INSERT INTO cards VALUES('admin','card_1783092983823_9oe6acu51',1,'Otimizar custos CI/CD com Claude: sincronismo vs Message Batches API para PRs, auditorias e testes',replace('Your CI/CD system performs three types of Claude-powered analysis: (1) quick style checks on each PR that block merging until complete, (2) comprehensive security audits of the entire codebase run weekly, and (3) test case generation triggered nightly for recently-modified modules. The Message Batches API offers 50% cost savings but can take up to 24 hours to process. You want to optimize API costs while maintaining acceptable developer experience. Which combination correctly matches each task to its API approach?\n\n[ ] A - Use synchronous calls for all three tasks for consistent response times, and rely on prompt caching to reduce costs across all workloads.\n[ ] B - Use synchronous calls for PR style checks and nightly test generation; use Message Batches API only for weekly security audits.\n[ ] C - Use the Message Batches API for all three tasks to maximize the 50% cost savings, and configure the pipeline to poll for batch completion.\n[ ] D - Use synchronous calls for PR style checks; use the Message Batches API for weekly security audits and nightly test generation.','\n',char(10)),'D - Use synchronous calls for PR style checks; use the Message Batches API for weekly security audits and nightly test generation.','["Domain_5::Context_Management_Reliability", "Domain_4::Prompt_Engineering_Structured_Output", "Scenario_5::Claude_Code_CI_CD"]','New',0,2.5,0,1783092983823,1783339397336,1783204828768,replace('Seu sistema de CI/CD executa três tipos de análise com tecnologia Claude: (1) verificações rápidas de estilo em cada PR que bloqueiam o merge até serem concluídas, (2) auditorias de segurança abrangentes de todo o código-base executadas semanalmente, e (3) geração de casos de teste disparada diariamente à noite para módulos recentemente modificados. A Message Batches API oferece 50% de economia de custos, mas pode levar até 24 horas para processar. Você quer otimizar os custos da API mantendo uma experiência aceitável para o desenvolvedor. Qual combinação associa corretamente cada tarefa à sua abordagem de API?\n\n[ ] A - Use chamadas síncronas para as três tarefas para tempos de resposta consistentes, e conte com cache de prompts para reduzir custos em todas as cargas de trabalho.\n[ ] B - Use chamadas síncronas para verificações de estilo de PR e geração noturna de testes; use a Message Batches API apenas para auditorias de segurança semanais.\n[ ] C - Use a Message Batches API para as três tarefas para maximizar a economia de 50%, e configure o pipeline para fazer polling da conclusão do lote.\n[ ] D - Use chamadas síncronas para verificações de estilo de PR; use a Message Batches API para auditorias de segurança semanais e geração noturna de testes.','\n',char(10)),replace('A chave para esta questão é o critério de **sensibilidade à latência** de cada tarefa versus a **oportunidade de economia** da Message Batches API (50% de desconto, mas até 24h de processamento).\n\nVamos classificar cada tarefa:\n\n1. **Verificações de estilo em PR (bloqueiam o merge)**: São altamente sensíveis à latência. Se o desenvolvedor precisa esperar até 24 horas para desbloquear um merge, a experiência de desenvolvimento seria destruída. Isso exige chamadas **síncronas** para resposta em segundos/minutos.\n\n2. **Auditorias de segurança semanais**: Não são sensíveis à latência. Rodam uma vez por semana, sem ninguém esperando em tempo real. Toleram perfeitamente a janela de até 24h. Candidato ideal para **Message Batches API** (economia de 50%).\n\n3. **Geração noturna de testes**: Disparada à noite, sem interação humana em tempo real. Há uma janela ampla (a noite inteira) antes que os desenvolvedores voltem a trabalhar. Também tolera latência. Candidato ideal para **Message Batches API**.\n\nPor isso, a alternativa **D** é a correta: síncrono apenas onde o desenvolvedor está bloqueado esperando (PR), e batch para as cargas assíncronas/agendadas (auditorias semanais e testes noturnos), maximizando a economia sem prejudicar a experiência.\n\n**Por que as demais estão erradas:**\n\n- **A** — Usar chamadas síncronas para tudo desperdiça a economia de 50% em cargas que não precisam de resposta imediata (auditorias semanais e testes noturnos). O prompt caching ajuda, mas não substitui o desconto do batch para workloads tolerantes a latência. Não otimiza custos.\n\n- **B** — Inverte a lógica. Coloca a geração noturna de testes (que tolera latência) em chamadas síncronas mais caras, desperdiçando economia, e não aproveita o batch onde ele é perfeitamente aplicável. Além disso, mantém corretamente o batch para auditorias, mas erra ao não usá-lo também para os testes noturnos.\n\n- **C** — Usar batch para as verificações de estilo de PR é inaceitável: os merges ficariam bloqueados por até 24 horas, arruinando a experiência do desenvolvedor. Otimiza custo à custa de uma experiência inviável.','\n',char(10)),replace('Imagine que você tem um ajudante mágico que faz três tarefas. Ele tem dois jeitos de trabalhar: o jeito RÁPIDO (mais caro) e o jeito LENTO (pela metade do preço, mas pode demorar até um dia inteiro).\n\nAgora pensa nas três tarefas:\n\n1. Uma checagem rápida que trava o trabalho até ficar pronta — aqui NINGUÉM pode esperar um dia inteiro! Precisa ser o jeito RÁPIDO.\n\n2. Uma revisão de segurança que acontece só uma vez por semana — ninguém está esperando na frente do computador, então pode usar o jeito LENTO e barato.\n\n3. Criar testes durante a noite, enquanto todo mundo dorme — também dá tempo de sobra, então pode usar o jeito LENTO e barato.\n\nEntão a resposta certa é a **D**: rápido só para a checagem do PR (onde as pessoas ficam presas esperando) e o jeito barato para as outras duas, porque ninguém tem pressa nelas. Assim você economiza dinheiro sem deixar ninguém irritado esperando!','\n',char(10)));
INSERT INTO cards VALUES('admin','card_1783092983828_hq50jsjoc',2,'Técnica para batch processing em code review iterativo com Claude',replace('Técnica para batch processing em code review iterativo com Claude\n\nThe code review component works iteratively: Claude analyzes a changed file, then may request related files (imports, base classes, tests) via tool calling to understand context before providing final feedback. Your application defines a tool that lets Claude request file contents; Claude invokes this tool, receives results, and continues its analysis. You''re evaluating batch processing to reduce API costs.\nWhat is the primary technical constraint when considering batch processing for this workflow?\n\n[ ] A - Batch processing lacks request correlation identifiers for matching outputs to input requests.\n[ ] B - The batch API doesn''t support tool definitions in request parameters.\n[ ] C - The asynchronous model prevents executing tools mid-request and returning results for Claude to continue analysis.\n[ ] D - Batch processing latency of up to 24 hours is too slow for pull request feedback, though the workflow could otherwise function.','\n',char(10)),'[ ] C - The asynchronous model prevents executing tools mid-request and returning results for Claude to continue analysis.','["Domain_1::Agentic_Architecture_Orchestration", "Domain_5::Context_Management_Reliability", "Scenario_5::Claude_Code_CI_CD"]','New',0,2.5,0,1783092983828,1783339401614,1783203886099,NULL,NULL,NULL);
INSERT INTO cards VALUES('admin','card_1783092983829_d9tof0zwd',3,'Integrar findings de Claude Code em PRs com structured output',replace('Integrar findings de Claude Code em PRs com structured output\n\nYour CI pipeline runs the Claude Code CLI (with --print mode) using CLAUDE.md to provide project context for code reviews, and developers generally find the reviews insightful. However, they report that integrating findings into your workflow is difficult—Claude produces narrative paragraphs that must be manually copied into PR comments. Your team wants to automatically post each finding as a separate inline PR comment at the relevant code location, which requires structured data with file path, line number, severity, and suggested fix.\nWhat''s the most effective approach?\n\n[ ] A - Include explicit formatting instructions in your review prompt requiring each finding to follow a parseable template like [FILE:path] [LINE:n] [SEVERITY:level] ... .\n[ ] B - Use CLI flags --output-format json and --json-schema to enforce structured findings, then parse output to post inline comments via the GitHub API.\n[ ] C - Keep the narrative review format but add a summarization step that uses Claude to generate a structured JSON summary of the findings.\n[ ] D - Add a "Review Output Format" section to CLAUDE.md with examples showing structured findings, so Claude learns the expected format from project context.','\n',char(10)),'B - Use CLI flags --output-format json and --json-schema to enforce structured findings, then parse output to post inline comments via the GitHub API.','["Domain_3::Claude_Code_Configuration_Workflows", "Domain_4::Prompt_Engineering_Structured_Output", "Domain_5::Context_Management_Reliability", "Scenario_5::Claude_Code_CI_CD"]','New',0,2.5,0,1783092983829,1783339406240,1783203886099,replace('Seu pipeline de CI executa a CLI do Claude Code (no modo `--print`) utilizando o arquivo `CLAUDE.md` para fornecer contexto do projeto para as revisões de código, e os desenvolvedores geralmente consideram as revisões esclarecedoras. No entanto, eles relatam que integrar as descobertas ao fluxo de trabalho é difícil: o Claude gera parágrafos narrativos que precisam ser copiados manualmente para os comentários do PR. Sua equipe deseja publicar automaticamente cada descoberta como um comentário em linha separado no local do código correspondente, o que exige dados estruturados contendo caminho do arquivo, número da linha, gravidade e correção sugerida.\nQual é a abordagem mais eficaz?\n\n[ ] A - Incluir instruções explícitas de formatação no prompt de revisão, exigindo que cada descoberta siga um modelo passível de análise (parseável), como `[FILE:path] [LINE:n] [SEVERITY:level]`...\n[ ] B - Utilizar as flags da CLI `--output-format json` e `--json-schema` para garantir descobertas estruturadas e, em seguida, processar a saída para publicar comentários em linha via API do GitHub.\n[ ] C - Manter o formato de revisão narrativa, mas adicionar uma etapa de sumarização que utilize o Claude para gerar um resumo estruturado em JSON das descobertas.\n[ ] D - Adicionar uma seção "Review Output Format" ao `CLAUDE.md` com exemplos que mostrem descobertas estruturadas, para que o Claude aprenda o formato esperado a partir do contexto do projeto.','\n',char(10)),replace('A resposta correta é a **B**.\n\nO problema central é técnico e de integração: você precisa de dados estruturados, confiáveis e programaticamente parseáveis para alimentar a API do GitHub e criar comentários inline em cada localização de código. Para isso, a solução mais robusta e determinística é usar os recursos nativos da própria CLI do Claude Code para saída estruturada.\n\n**Por que B é a melhor escolha:**\n- Os flags `--output-format json` e `--json-schema` fazem com que o modelo produza uma saída em conformidade com um schema definido (structured output / constrained decoding). Isso não é apenas uma "instrução" no prompt — é uma garantia mecânica de que a saída terá os campos exigidos (file path, line number, severity, suggested fix) no formato correto.\n- Isso torna o parsing determinístico e confiável em um pipeline de CI, eliminando ambiguidade e falhas de parsing.\n- A partir dessa saída, é trivial iterar sobre cada finding e chamar a API do GitHub (endpoint de review comments) para postar comentários inline no arquivo e linha corretos.\n- É a abordagem que resolve tanto a necessidade de estrutura quanto a de automação, usando o mecanismo mais robusto disponível.\n\n**Por que as demais estão erradas:**\n- **A** — Instruções de formatação no prompt (template em texto tipo `[FILE:...]`) dependem da aderência do modelo ao formato. LLMs frequentemente divergem: podem omitir campos, mudar delimitadores, adicionar texto extra ou variar entre execuções. Isso torna o parsing frágil e propenso a erros, especialmente em CI onde a robustez é crítica. É uma solução "melhor esforço" quando existe um mecanismo de garantia (schema).\n- **C** — Manter a narrativa e depois pedir ao Claude para resumir em JSON adiciona uma etapa extra, aumenta custo/latência e introduz risco de perda ou distorção de informação na sumarização (o resumo pode omitir findings ou inferir linhas incorretas). Ainda dependeria de saída não garantida sem schema. É indireto e menos confiável do que gerar a estrutura diretamente na revisão.\n- **D** — O CLAUDE.md fornece contexto do projeto e influencia comportamento, mas não impõe formato de saída de forma garantida. É o mesmo problema da opção A (dependência de aderência probabilística), com a desvantagem adicional de misturar responsabilidades: CLAUDE.md é para contexto do projeto, não para forçar contrato de saída de máquina. Não substitui um schema validado.\n\nEm resumo: quando você precisa de saída legível por máquina e confiável em automação, use o mecanismo de structured output com schema, não instruções em linguagem natural que o modelo pode ou não seguir.','\n',char(10)),replace('Imagine que você tem um robô muito inteligente que lê os deveres de casa dos seus colegas e escreve comentários dizendo o que pode melhorar. O problema é que o robô escreve tudo em textão, e você precisa copiar cada dica à mão para colar no lugar certo. Que trabalhão!\n\nVocê quer que o robô entregue as dicas já organizadas em fichinhas certinhas: "arquivo tal, linha tal, gravidade tal, conserto sugerido tal". Assim um programa pega cada fichinha e cola sozinho no lugar exato.\n\nA melhor forma é usar um botão especial do robô (os flags `--output-format json` e `--json-schema`) que OBRIGA ele a preencher a fichinha do jeito certinho, sem esquecer nenhum espaço. Depois é só o programa ler as fichinhas e colar os comentários automaticamente.\n\nAs outras ideias são: pedir "por favor escreva assim" (mas o robô às vezes esquece), ou pedir para ele escrever textão e depois resumir (dá trabalho dobrado e pode perder informação), ou escrever exemplos num caderninho do projeto (ajuda, mas também não garante). Só o botão especial GARANTE que a fichinha vem sempre certinha. Por isso a resposta é a B!','\n',char(10)));
INSERT INTO cards VALUES('admin','card_1783092983830_svcq0hqw4',4,'Gerenciar falsos positivos em análise automatizada com confiança',replace('Gerenciar falsos positivos em análise automatizada com confiança\n\nAnalysis of your automated code review shows significant variation in false positive rates across finding categories. Security and correctness findings have an 8% false positive rate, performance findings have 18%, style and naming findings have 52%, and documentation findings have 48%. Developer surveys indicate growing distrust—many have started dismissing findings without review because "half are wrong." The high false positive categories are undermining confidence in the accurate categories. What approach best restores developer trust while improving the system?\n\n[ ] A - Temporarily disable high false positive categories (style, naming, documentation) and run only high-precision categories while improving prompts.\n[ ] B - Keep all categories but display a confidence score with each finding, letting developers decide which to investigate.\n[ ] C - Keep all categories enabled while adding few-shot examples to improve each category''s accuracy over the coming weeks.\n[ ] D - Apply a uniform strictness reduction across all categories to bring the overall false positive rate to an acceptable level.','\n',char(10)),'A - Temporarily disable high false positive categories (style, naming, documentation) and run only high-precision categories while improving prompts.','["Domain_4::Prompt_Engineering_Structured_Output", "Domain_5::Context_Management_Reliability", "Scenario_5::Claude_Code_CI_CD"]','New',0,2.5,0,1783092983830,1783339410569,1783203886099,replace('Sua análise automatizada de código mostra variação significativa nas taxas de falsos positivos entre as categorias de achados. Achados de segurança e correção têm taxa de falsos positivos de 8%, achados de performance têm 18%, achados de estilo e nomenclatura têm 52%, e achados de documentação têm 48%. Pesquisas com desenvolvedores indicam desconfiança crescente — muitos começaram a descartar achados sem revisá-los porque "metade está errada". As categorias com alta taxa de falsos positivos estão minando a confiança nas categorias precisas. Qual abordagem melhor restaura a confiança dos desenvolvedores enquanto melhora o sistema?\n\n[ ] A - Desativar temporariamente as categorias com alta taxa de falsos positivos (estilo, nomenclatura, documentação) e executar apenas categorias de alta precisão enquanto melhora os prompts.\n[ ] B - Manter todas as categorias, mas exibir uma pontuação de confiança em cada achado, deixando os desenvolvedores decidirem quais investigar.\n[ ] C - Manter todas as categorias ativadas enquanto adiciona exemplos few-shot para melhorar a acurácia de cada categoria ao longo das próximas semanas.\n[ ] D - Aplicar uma redução uniforme de rigor em todas as categorias para trazer a taxa geral de falsos positivos a um nível aceitável.','\n',char(10)),replace('**Resposta correta: A**\n\nO problema central aqui é de **confiança (trust)**, não apenas de acurácia técnica. Quando os desenvolvedores começam a descartar achados sem revisão porque "metade está errada", ocorre um fenômeno de contaminação: as categorias ruins (estilo 52%, documentação 48%) estão fazendo com que os desenvolvedores ignorem também as categorias excelentes (segurança 8%, correção 8%). Isso é perigoso — um achado de segurança verdadeiro sendo ignorado tem custo altíssimo.\n\nA alternativa A resolve o problema imediato de forma cirúrgica: remove a fonte da desconfiança (as categorias ruidosas) enquanto preserva o valor de alta precisão. O desenvolvedor volta a ver um sistema onde "quando ele fala, quase sempre está certo", o que restaura a confiança rapidamente. Ao mesmo tempo, o "temporariamente... enquanto melhora os prompts" indica que não se abandona a melhoria — as categorias voltam quando atingirem qualidade aceitável. É a abordagem que trata tanto o sintoma urgente quanto a causa raiz.\n\n**Por que as outras estão erradas:**\n\n**B** — Exibir uma pontuação de confiança transfere o trabalho de triagem para o desenvolvedor, que é justamente quem já está sobrecarregado e desconfiado. Ele terá que continuar filtrando ruído mentalmente. Além disso, se o próprio sistema tem 52% de falsos positivos numa categoria, é provável que suas pontuações de confiança também sejam pouco calibradas. Não resolve a erosão de confiança — apenas adiciona mais uma decisão ao humano já cansado.\n\n**C** — Adicionar exemplos few-shot é uma boa técnica de melhoria a médio prazo, mas manter todas as categorias ativas "ao longo das próximas semanas" significa continuar expondo os desenvolvedores ao ruído durante todo esse período. A confiança continuará se deteriorando enquanto se espera a melhoria. A melhoria dos prompts deve acontecer com as categorias ruins **desligadas**, não ligadas.\n\n**D** — Reduzir o rigor de forma uniforme é o pior dos mundos. Aplicar a mesma redução às categorias já excelentes (segurança/correção com 8%) fará com que elas percam recall — deixem de detectar problemas reais e importantes — para "compensar" as categorias ruins. Você degrada o que funciona bem sem realmente consertar o que funciona mal. Medir e agir por uma média global esconde a variação real entre categorias.','\n',char(10)),replace('Imagine que você tem um robô que revisa suas lições e aponta erros. Nas coisas importantes, como contas de matemática, ele quase nunca erra — acerta 92% das vezes! Mas quando ele fala sobre a "cor da caneta" ou "letra bonita", ele reclama de coisas que estão certas na metade das vezes.\n\nDepois de um tempo, você fica cansado de ouvir o robô reclamar de bobagem e começa a ignorar TUDO que ele diz — até os avisos importantes de matemática! Isso é perigoso, porque aí você pode deixar passar um erro de verdade.\n\nA melhor solução (letra A) é: desligar por enquanto a parte "chata e errada" do robô (cor da caneta, letra bonita) e deixar ele falar só das coisas em que ele é muito bom. Assim você volta a confiar nele! E depois, quando ensinarmos o robô a acertar melhor as outras coisas, a gente liga de novo.\n\nAs outras ideias não são tão boas: uma pede pra você mesmo decidir o que ignorar (mais trabalho pra você!), outra deixa o robô continuar reclamando por semanas, e a última faz o robô ficar pior até na matemática pra tentar consertar as bobagens. A letra A é a mais esperta!','\n',char(10)));
INSERT INTO cards VALUES('admin','card_1783092983831_kfuk6iz6q',5,'Melhorar feedback de código automático com prompting e contexto',replace('Melhorar feedback de código automático com prompting e contexto\n\nYour automated reviews identify valid issues but developers report the feedback isn''t actionable. Findings say things like "complex ticket allocation logic" or "potential null pointer" without specifying what to change. When you add detailed instructions like "always include specific fix suggestions," the model still produces inconsistent output—sometimes detailed, sometimes vague. What prompting technique would most reliably produce consistently actionable feedback?\n\n[ ] A - Expand the context window to include more of the surrounding codebase so the model has sufficient information to suggest specific fixes\n[ ] B - Further refine the instructions with more explicit requirements for each part of the feedback format (location, issue, severity, suggested fix)\n[ ] C - Implement a two-pass approach where one prompt identifies issues and a second prompt generates fixes, allowing specialization\n[ ] D - Add 3-4 few-shot examples showing the exact format you want: issue identified, code location, specific fix suggestion','\n',char(10)),'D - Add 3-4 few-shot examples showing the exact format you want: issue identified, code location, specific fix suggestion','["Domain_4::Prompt_Engineering_Structured_Output", "Domain_3::Claude_Code_Configuration_Workflows", "Scenario_5::Claude_Code_CI_CD"]','New',0,2.5,0,1783092983831,1783339414466,1783203558653,NULL,replace('**Explicação técnica:**\n\nA questão descreve um sintoma clássico: instruções descritivas ("sempre inclua sugestões específicas") já foram tentadas e produzem resultado **inconsistente**. Esse é justamente o ponto de virada em que instruções puras deixam de escalar — o modelo interpreta "específico" de formas diferentes a cada execução porque não há uma referência concreta do que "específico" significa.\n\n**Por que D é a melhor escolha:**\nO *few-shot prompting* resolve exatamente o problema de **consistência de formato e nível de detalhe**. Ao mostrar 3-4 exemplos concretos (problema → localização → correção específica), você não descreve o padrão desejado, você **demonstra** o padrão. O modelo passa a imitar a estrutura, o tom e o grau de especificidade dos exemplos. Isso é muito mais confiável do que instruções abstratas, porque elimina a ambiguidade de interpretação. Exemplos ancoram a saída num alvo concreto e reproduzível — que é precisamente o que falta hoje.\n\n**Por que as demais estão erradas:**\n\n- **A (expandir contexto):** O problema declarado *não* é falta de informação — as revisões já "identificam problemas válidos". O modelo sabe qual é o defeito; ele apenas não formata a resposta de forma acionável. Mais contexto não corrige inconsistência de formato, e pode até diluir o foco e aumentar custo/latência.\n\n- **B (refinar mais as instruções):** É exatamente o que já foi tentado e falhou ("quando você adiciona instruções detalhadas... o modelo ainda produz saída inconsistente"). Adicionar mais texto instrucional tende a ter retornos decrescentes; o gargalo é a ausência de exemplos, não a falta de mais regras.\n\n- **C (abordagem de duas passagens):** É uma solução de engenharia mais complexa que aumenta custo, latência e superfície de falha. Além disso, não ataca a causa raiz: mesmo o "segundo prompt gerador de correções" continuaria produzindo saída inconsistente sem exemplos que ancorem o formato. É over-engineering para um problema que se resolve com prompting.\n\nEm resumo: quando instruções já foram tentadas e o problema é *consistência de formato e nível de detalhe*, few-shot examples são a técnica de maior alavancagem.','\n',char(10)),replace('Imagine que você pediu para um robô te ajudar a corrigir a lição de casa. Você disse: "sempre me diga como consertar meus erros". Mas o robô às vezes dá dicas boas e às vezes fala coisas muito vagas, tipo "esta conta está estranha", sem dizer o que fazer.\n\nVocê já tentou explicar melhor com muitas regras, mas o robô continua confuso. O que funciona melhor? **Mostrar exemplos!**\n\nEm vez de só *explicar* o que você quer, você mostra 3 ou 4 exemplos prontinhos: "Olha, quando tem um erro, escreva assim: qual é o erro, onde está, e exatamente como consertar." Aí o robô olha os exemplos e copia o jeitinho toda vez. É como ensinar mostrando um modelo pronto, em vez de só falar. Por isso a resposta certa é a **D**.','\n',char(10)));
INSERT INTO cards VALUES('admin','card_1783092983832_6tathvxun',6,'Evitar limitações de self-review em sugestões de código gerado',replace('Evitar limitações de self-review em sugestões de código gerado\n\nYour team uses Claude Code to generate code suggestions, but you notice a pattern: subtle issues—performance optimizations that break edge cases, cleanups that change behavior unexpectedly—only surface when a different team member reviews the PR. Claude''s reasoning during generation shows it considered these cases but concluded its approach was correct. Which approach directly addresses the root cause of this self-review limitation?\n\n[ ] A - Enable extended thinking mode for the generation pass, allowing more thorough deliberation before producing suggestions.\n[ ] B - Include comprehensive test files and documentation in the prompt context so Claude better understands expected behavior during generation.\n[ ] C - Add explicit self-review instructions to the generation prompt, asking Claude to critique its own suggestions before finalizing output.\n[ ] D - Have a second, independent Claude Code instance review the changes without seeing the generator''s reasoning.','\n',char(10)),'D - Have a second, independent Claude Code instance review the changes without seeing the generator''s reasoning.','["Domain_3::Claude_Code_Configuration_Workflows", "Domain_4::Prompt_Engineering_Structured_Output", "Scenario_2::Code_Generation_Claude_Code"]','New',0,2.5,0,1783092983832,1783339418622,1783203558653,replace('Sua equipe usa o Claude Code para gerar sugestões de código, mas você percebe um padrão: problemas sutis — otimizações de desempenho que quebram casos extremos, limpezas que mudam o comportamento de forma inesperada — só aparecem quando um membro diferente da equipe revisa o PR. O raciocínio do Claude durante a geração mostra que ele considerou esses casos, mas concluiu que sua abordagem estava correta. Qual abordagem trata diretamente a causa raiz dessa limitação de auto-revisão?\n\n[ ] A - Ativar o modo de "extended thinking" (raciocínio estendido) na etapa de geração, permitindo uma deliberação mais completa antes de produzir as sugestões.\n[ ] B - Incluir arquivos de teste abrangentes e documentação no contexto do prompt, para que o Claude entenda melhor o comportamento esperado durante a geração.\n[ ] C - Adicionar instruções explícitas de auto-revisão ao prompt de geração, pedindo ao Claude que critique suas próprias sugestões antes de finalizar a saída.\n[ ] D - Ter uma segunda instância independente do Claude Code revisando as mudanças sem ver o raciocínio do gerador.','\n',char(10)),replace('A alternativa correta é a **D**.\n\nA causa raiz do problema é uma limitação inerente de auto-revisão (self-review). Quando o mesmo agente que gerou o código tenta revisá-lo, ele já está "ancorado" (anchoring bias) na cadeia de raciocínio que o levou a concluir que sua abordagem estava correta. O enunciado deixa isso explícito: o raciocínio do Claude *já considerou* os casos extremos e *concluiu que estava certo*. Ou seja, o problema não é falta de deliberação nem falta de contexto — é o fato de que o revisor compartilha do mesmo viés do gerador. A única forma de quebrar esse viés é introduzir independência: uma segunda instância que avalia o resultado **sem acesso à justificativa original**, chegando a ele com uma perspectiva fresca, exatamente como faz o colega humano que encontra os problemas no PR.\n\nPor que as demais estão erradas:\n\n- **A (extended thinking):** Mais deliberação não resolve, porque o gerador *já deliberou* sobre esses casos e mesmo assim concluiu erroneamente que estava certo. Aumentar a profundidade do mesmo raciocínio viesado tende a reforçar a conclusão original, não a corrigi-la.\n\n- **B (testes e documentação no contexto):** Melhora o entendimento do comportamento esperado, o que ajuda em geral, mas não ataca a causa raiz. O problema descrito é de julgamento/auto-avaliação, não de falta de informação sobre o comportamento esperado — as sugestões problemáticas são justamente aquelas em que o modelo *achou* que estava respeitando o comportamento.\n\n- **C (auto-crítica no mesmo prompt):** É essencialmente pedir que o mesmo agente enviesado se autoavalie. Como ele já concluiu que sua abordagem é correta, a auto-crítica no mesmo contexto tende a apenas validar a decisão anterior. É o equivalente automatizado de pedir para "revisar a si mesmo", que é precisamente o que falhou.\n\nO princípio central é separação de responsabilidades e independência do revisor — o mesmo motivo pelo qual, em engenharia, quem escreve o código não deve ser o único a revisá-lo.','\n',char(10)),replace('Imagine que você escreveu uma redação e tem certeza de que está perfeita. Se você mesmo tentar corrigi-la, provavelmente vai continuar achando que está tudo certo, porque na sua cabeça faz sentido — você já pensou em tudo e se convenceu. Mas quando um coleguinha lê, ele acha erros que você nem tinha percebido!\n\nCom o robô que escreve código acontece a mesma coisa. Ele escreve, pensa que está tudo certo, e por isso não consegue enxergar os próprios errinhos escondidos. Pedir pra ele se revisar (opção C) ou pensar mais (opção A) não adianta muito, porque ele vai continuar achando que acertou. Dar mais materiais de estudo (opção B) também não resolve o problema principal.\n\nO jeito certo é chamar **outro** robô, que nunca viu o que o primeiro pensou, para revisar com olhos novos — igualzinho ao coleguinha lendo sua redação. Por isso a resposta certa é a **D**!','\n',char(10)));
INSERT INTO cards VALUES('admin','card_1783092983833_sfblrdvns',7,'Reestruturar análise de PR com múltiplos passes para consistência',replace('Reestruturar análise de PR com múltiplos passes para consistência\n\nA pull request modifies 14 files across the stock tracking module. Your single-pass review analyzing all files together produces inconsistent results: detailed feedback for some files but superficial comments for others, obvious bugs missed, and contradictory feedback—flagging a pattern as problematic in one file while approving identical code elsewhere in the same PR. How should you restructure the review?\n\n[ ] A - Require developers to split large PRs into smaller submissions of 3-4 files before the automated review runs.\n[ ] B - Run three independent review passes on the full PR and only flag issues that appear in at least two of the three runs.\n[ ] C - Split into focused passes: analyze each file individually for local issues, then run a separate integration-focused pass examining cross-file data flow.\n[ ] D - Switch to a higher-tier model with a larger context window to give all 14 files adequate attention in one pass.','\n',char(10)),'C - Split into focused passes: analyze each file individually for local issues, then run a separate integration-focused pass examining cross-file data flow.','["Domain_4::Prompt_Engineering_Structured_Output", "Domain_5::Context_Management_Reliability", "Scenario_5::Claude_Code_CI_CD"]','New',0,2.5,0,1783092983833,1783339422567,1783203558653,replace('Reestruturar análise de PR com múltiplos passes para consistência\n\nUma pull request modifica 14 arquivos no módulo de rastreamento de estoque. Sua revisão em passe único, analisando todos os arquivos juntos, produz resultados inconsistentes: feedback detalhado para alguns arquivos, mas comentários superficiais para outros, bugs óbvios não detectados e feedback contraditório — apontando um padrão como problemático em um arquivo enquanto aprova código idêntico em outro lugar da mesma PR. Como você deve reestruturar a revisão?\n\n[ ] A - Exigir que os desenvolvedores dividam PRs grandes em submissões menores de 3-4 arquivos antes que a revisão automatizada seja executada.\n[ ] B - Executar três passes de revisão independentes na PR completa e sinalizar apenas problemas que apareçam em pelo menos dois dos três passes.\n[ ] C - Dividir em passes focados: analisar cada arquivo individualmente para problemas locais e, em seguida, executar um passe separado focado em integração, examinando o fluxo de dados entre arquivos.\n[ ] D - Migrar para um modelo de camada superior com uma janela de contexto maior para dar a todos os 14 arquivos atenção adequada em um único passe.','\n',char(10)),replace('**Resposta correta: C**\n\nO problema descrito tem duas causas raiz distintas, e cada uma exige uma estratégia diferente:\n\n1. **Diluição de atenção (attention dilution):** Ao processar 14 arquivos em um único prompt, o modelo distribui sua "atenção" de forma desigual. Arquivos no início/fim do contexto ou mais volumosos recebem tratamento detalhado, enquanto outros ficam com análise superficial e bugs passam despercebidos. Analisar **cada arquivo isoladamente** garante profundidade uniforme — cada arquivo recebe 100% do foco do modelo.\n\n2. **Inconsistência e contradição:** Aprovar um padrão em um arquivo e reprová-lo em outro idêntico é sintoma clássico de sobrecarga de contexto. Isolar a análise por arquivo elimina interferência cruzada.\n\nMas isolar arquivos criaria um novo problema: perda de visão sistêmica (contratos entre módulos, fluxo de dados, side effects entre arquivos). Por isso a alternativa adiciona um **passe de integração dedicado**, que examina especificamente as interações entre arquivos. Essa arquitetura de "decomposição de tarefa" (task decomposition) é o padrão correto: divide o problema em subtarefas focadas e depois recompõe a visão global. É análoga a separar testes unitários de testes de integração.\n\n**Por que as demais estão erradas:**\n\n**A (dividir a PR):** Transfere um problema técnico da ferramenta para um processo humano, criando fricção no fluxo de trabalho. PRs devem ter tamanho definido por coesão lógica, não por limitações do revisor automatizado. Além disso, mesmo com 3-4 arquivos, o problema de inconsistência local vs. integração persiste em menor escala. Trata o sintoma, não a causa.\n\n**B (votação por maioria / self-consistency):** Rodar 3 passes e exigir consenso reduz alarmes falsos aleatórios, mas **não resolve nenhum dos problemas descritos**. A diluição de atenção é sistemática, não aleatória — os mesmos arquivos serão superficialmente analisados nos três passes. E bugs consistentemente não detectados continuarão ausentes em todos os passes. Custo triplicado sem atacar a causa raiz.\n\n**D (modelo maior / janela maior):** Uma janela de contexto maior resolve o limite de *capacidade*, mas não o problema de *distribuição de atenção* dentro do contexto (fenômeno "lost in the middle"). Mesmo modelos com janelas enormes demonstram degradação de atenção em conteúdo longo. É uma solução cara que apenas adia o problema, sem a estruturação que garante consistência e cobertura.','\n',char(10)),replace('Imagina que você é professor e precisa corrigir 14 provas de uma vez só, tudo empilhado na mesa. Se você tentar olhar todas ao mesmo tempo, vai acabar prestando muita atenção nas primeiras e dando uma olhada rápida e distraída nas outras. Você pode até dar nota boa pra uma resposta numa prova e nota ruim pra resposta igualzinha em outra, porque se confundiu com tanta coisa junta!\n\nA melhor solução (resposta C) é: primeiro corrija **uma prova de cada vez**, com toda a sua atenção em cada uma. Depois, faça uma passada extra só pra ver se as provas "conversam" entre si — se as respostas combinam umas com as outras. Assim você não deixa passar nada e não se contradiz.\n\nAs outras ideias não funcionam bem:\n- **A:** Pedir pros alunos entregarem menos provas por vez só empurra o problema pra eles, e você ainda pode se confundir.\n- **B:** Corrigir tudo três vezes do mesmo jeito distraído não adianta — você vai continuar distraído nas mesmas provas todas as vezes.\n- **D:** Arrumar uma mesa maior pra caber todas as provas não resolve, porque o problema não é o tamanho da mesa, é você tentar olhar tudo junto e se perder no meio.','\n',char(10)));
INSERT INTO cards VALUES('admin','card_1783092983835_ux670gy9b',8,'Reduzir sugestões duplicadas em geração de testes automatizada',replace('Reduzir sugestões duplicadas em geração de testes automatizada\n\nYour automated review generates test case suggestions for each PR. When reviewing a PR that adds course completion tracking, Claude suggests 10 test cases but developer feedback indicates 6 duplicate scenarios already covered in the existing test suite. What change would most effectively reduce duplicate suggestions?\n\n[ ] A - Add instructions directing Claude to focus exclusively on edge cases and error conditions rather than successful paths\n[ ] B - Reduce requested suggestions from 10 to 5, assuming Claude will prioritize the most valuable cases first\n[ ] C - Implement post-processing that filters suggestions whose descriptions match keywords from existing test names\n[ ] D - Include the existing test file in the context so Claude can identify what scenarios are already covered','\n',char(10)),'D - Include the existing test file in the context so Claude can identify what scenarios are already covered','["Domain_4::Prompt_Engineering_Structured_Output", "Domain_5::Context_Management_Reliability", "Scenario_5::Claude_Code_CI_CD"]','New',0,2.5,0,1783092983835,1783339426300,1783203558653,replace('Sua revisão automatizada gera sugestões de casos de teste para cada PR. Ao revisar um PR que adiciona rastreamento de conclusão de curso, o Claude sugere 10 casos de teste, mas o feedback do desenvolvedor indica que 6 são cenários duplicados já cobertos na suíte de testes existente. Qual mudança reduziria de forma mais eficaz as sugestões duplicadas?\n\n[ ] A - Adicionar instruções direcionando o Claude a focar exclusivamente em casos extremos (edge cases) e condições de erro, em vez de caminhos bem-sucedidos\n[ ] B - Reduzir as sugestões solicitadas de 10 para 5, presumindo que o Claude priorizará os casos mais valiosos primeiro\n[ ] C - Implementar um pós-processamento que filtra sugestões cujas descrições correspondem a palavras-chave dos nomes dos testes existentes\n[ ] D - Incluir o arquivo de teste existente no contexto, para que o Claude possa identificar quais cenários já estão cobertos','\n',char(10)),replace('A resposta correta é a **D**.\n\nO problema raiz é que o Claude está sugerindo duplicatas porque **não tem visibilidade dos testes que já existem**. Ele está gerando sugestões "às cegas", sem saber o que já foi coberto. A solução mais eficaz e direta é fornecer o contexto que falta: o arquivo de testes existente. Com essa informação no prompt/contexto, o modelo consegue raciocinar sobre lacunas reais na cobertura e evitar propor cenários redundantes. Isso ataca a causa do problema, não o sintoma.\n\nPor que as outras estão erradas:\n\n**A** — Restringir a edge cases e erros pode reduzir alguns duplicados por acidente, mas não resolve o problema real (falta de conhecimento sobre cobertura existente). Além disso, você poderia perder sugestões válidas de caminhos felizes que ainda NÃO estão cobertos, degradando a qualidade da revisão.\n\n**B** — Reduzir de 10 para 5 apenas diminui o volume total; não garante que os 5 restantes não sejam duplicados. Como o Claude ainda não sabe o que já existe, você pode facilmente acabar com 5 sugestões, das quais 3 continuam sendo duplicatas. Trata o sintoma (quantidade), não a causa.\n\n**C** — Filtragem por correspondência de palavras-chave (keyword matching) é frágil e propensa a erros: nomes de testes e descrições podem descrever o mesmo cenário com palavras diferentes (falsos negativos) ou compartilhar palavras sem serem o mesmo caso (falsos positivos). É uma solução heurística superficial que não entende semântica. Fornecer o contexto (D) permite ao próprio modelo fazer essa deduplicação de forma semântica e mais confiável.','\n',char(10)),replace('Imagine que você pediu para um amigo desenhar figuras novas para um álbum, mas ele não sabe quais figuras você já tem coladas. Aí ele acaba desenhando várias figuras repetidas! O jeito mais esperto de resolver isso é simplesmente MOSTRAR pra ele o álbum com as figuras que você já tem. Assim ele olha e pensa: "Ah, essa aqui já existe, vou desenhar só as que faltam!"\n\nÉ por isso que a resposta certa é a **D**: dar pro Claude o arquivo com os testes que já existem, para ele ver o que já está pronto e só sugerir coisas novas.\n\nAs outras ideias não funcionam tão bem: pedir menos figuras (B) não resolve, porque ele ainda pode repetir. Pedir só figuras "diferentes e estranhas" (A) pode fazer ele esquecer figuras importantes. E tentar adivinhar as repetidas só olhando os nomes (C) confunde fácil, porque duas coisas iguais podem ter nomes diferentes. Mostrar o álbum inteiro é o jeito mais certo!','\n',char(10)));
INSERT INTO cards VALUES('admin','card_1783092983838_gnmq9x78e',9,'Filtrar e priorizar findings de análise automatizada por confiança',replace('Filtrar e priorizar findings de análise automatizada por confiança\n\nYour automated code review averages 15 findings per pull request, with developers reporting a 40% false positive rate. The bottleneck is investigation time: developers must click into each finding to read Claude''s reasoning before deciding whether to address or dismiss it. Your CLAUDE.md already contains comprehensive rules for acceptable patterns, and you want to reduce the investigation burden. What change would best address the investigation time bottleneck?\n\n[ ] A - Add a post-processor that analyzes finding patterns and automatically suppresses those matching historical false positive signatures\n[ ] B - Configure Claude to only surface findings it assesses as high confidence, filtering out uncertain flags before developers see them\n[ ] C - Categorize findings as "blocking issues" versus "suggestions" with tiered review requirements\n[ ] D - Require Claude to include its reasoning and confidence assessment inline with each finding','\n',char(10)),'D - Require Claude to include its reasoning and confidence assessment inline with each finding','["Domain_4::Prompt_Engineering_Structured_Output", "Domain_3::Claude_Code_Configuration_Workflows", "Domain_5::Context_Management_Reliability", "Scenario_5::Claude_Code_CI_CD"]','New',0,2.5,0,1783092983838,1783339430552,1783203558653,replace('Filtrar e priorizar findings de análise automatizada por confiança\n\nSua revisão de código automatizada gera em média 15 apontamentos (findings) por pull request, e os desenvolvedores relatam uma taxa de 40% de falsos positivos. O gargalo é o tempo de investigação: os desenvolvedores precisam clicar em cada apontamento para ler o raciocínio do Claude antes de decidir se devem tratá-lo ou descartá-lo. Seu CLAUDE.md já contém regras abrangentes sobre padrões aceitáveis, e você quer reduzir a carga de investigação. Qual mudança melhor resolveria o gargalo do tempo de investigação?\n\n[ ] A - Adicionar um pós-processador que analisa padrões de apontamentos e suprime automaticamente aqueles que correspondem a assinaturas históricas de falsos positivos\n[ ] B - Configurar o Claude para exibir apenas os apontamentos que ele avalia como de alta confiança, filtrando os sinalizadores incertos antes que os desenvolvedores os vejam\n[ ] C - Categorizar os apontamentos como "problemas bloqueantes" versus "sugestões", com requisitos de revisão em níveis (tiered)\n[ ] D - Exigir que o Claude inclua seu raciocínio e avaliação de confiança de forma inline (junto) com cada apontamento','\n',char(10)),replace('**Resposta correta: D**\n\nO gargalo descrito é bem específico e literal: os desenvolvedores gastam tempo **clicando em cada apontamento para ler o raciocínio antes de decidir**. A causa raiz do custo de investigação é que a informação necessária para a decisão (raciocínio + confiança) está "escondida" atrás de um clique. A solução mais direta e de menor risco é trazer essa informação para junto do apontamento (inline).\n\nAo expor o raciocínio e o nível de confiança diretamente na visão do apontamento, o desenvolvedor toma a decisão de "tratar ou descartar" em segundos, sem navegação extra. Isso ataca exatamente o comportamento que consome tempo, sem eliminar informação nem introduzir supressão silenciosa. É a intervenção mais alinhada ao problema declarado.\n\n**Por que as outras estão erradas:**\n\n- **A (pós-processador que suprime falsos positivos históricos):** É frágil e arriscado. Suprimir com base em "assinaturas" de falsos positivos passados tende a esconder também verdadeiros positivos legítimos que se pareçam com padrões antigos. Além disso, é uma supressão automática e opaca — você perde visibilidade e pode criar falsos negativos silenciosos, que são muito mais perigosos que ruído visível. Não ataca diretamente o tempo de leitura do raciocínio.\n\n- **B (mostrar só alta confiança, filtrando os incertos):** Parece atraente, mas descarta apontamentos antes de o humano decidir. Um apontamento "incerto" pode ser um bug real que exigia justamente o olhar do desenvolvedor. Você troca o problema de falsos positivos por um risco de falsos negativos ocultos, o que degrada a qualidade da revisão. Também não resolve o problema de leitura para os que restam.\n\n- **C (blocking vs. suggestions com revisão em níveis):** É uma boa prática de priorização, mas resolve *quais* apontamentos merecem atenção, não *o tempo de investigar* cada um. O desenvolvedor ainda precisaria clicar para entender o raciocínio de cada item bloqueante. Ataca priorização, não o gargalo de leitura descrito.\n\nEm resumo: o enunciado aponta que o custo está na *leitura do raciocínio via clique*. A opção D remove esse clique tornando a informação imediatamente visível, preservando todos os apontamentos e a capacidade de decisão humana.','\n',char(10)),replace('Imagine que um robô ajudante lê o dever de casa de um monte de amigos e faz bilhetinhos dizendo "acho que aqui tem um errinho". O problema é que cada bilhete só diz "tem um errinho aqui", e para saber *por quê*, você precisa clicar e abrir uma explicação escondida. Isso demora muito!\n\nA melhor solução (resposta D) é pedir para o robô já escrever a explicação e o quanto ele tem certeza direto no bilhetinho. Assim, você lê tudo de uma vez e decide na hora se é errinho de verdade ou não — sem precisar abrir nada.\n\nAs outras ideias não são tão boas:\n- Uma delas manda o robô *esconder* sozinho os bilhetes que parecem errados. Mas ele pode esconder um errinho de verdade sem querer!\n- Outra manda mostrar só os bilhetes que o robô tem muita certeza. Mas às vezes o robô não tem certeza justamente de um problema importante, e você nem ia ver.\n- Outra separa os bilhetes em "grave" e "sugestão". É legal, mas você ainda teria que clicar para entender cada um — não resolve a demora de ler.\n\nPor isso, colocar a explicação junto do bilhete é o que mais economiza tempo!','\n',char(10)));
INSERT INTO cards VALUES('admin','card_1783092983838_gtydyyvp4',10,'Consistência de severidade em análise de código automatizada',replace('Consistência de severidade em análise de código automatizada\n\nYour automated code review system shows inconsistent severity ratings—similar issues like null pointer risks receive "critical" severity in some PRs but only "medium" in others. Developer trust is declining because teams can''t predict which findings require immediate attention. Your CLAUDE.md already contains comprehensive rules for acceptable patterns, and you''ve started dismissing findings without review because you can''t predict which are truly critical. What''s the most effective way to improve severity consistency?\n\n[ ] A - Modify the prompt to ask Claude to rate severity relative to other issues in the same PR, so the most severe issue is always marked critical and others rated proportionally\n[ ] B - Request that Claude include its reasoning for each severity assignment, then use that reasoning to manually calibrate and adjust ratings during review\n[ ] C - Add a CLAUDE.md file that lists issue types and their default severities, instructing Claude to reference this mapping when assigning ratings\n[ ] D - Include explicit severity criteria in your prompt with concrete code examples for each severity level','\n',char(10)),'D - Include explicit severity criteria in your prompt with concrete code examples for each severity level','["Domain_4::Prompt_Engineering_Structured_Output", "Domain_3::Claude_Code_Configuration_Workflows", "Scenario_5::Claude_Code_CI_CD"]','New',0,2.5,0,1783092983838,1783339434592,1783203558653,replace('**Tradução da pergunta e alternativas:**\n\nConsistência de severidade em análise de código automatizada\n\nSeu sistema automatizado de revisão de código exibe classificações de severidade inconsistentes — problemas semelhantes, como riscos de ponteiro nulo (null pointer), recebem severidade "crítica" em alguns PRs, mas apenas "média" em outros. A confiança dos desenvolvedores está diminuindo porque as equipes não conseguem prever quais achados exigem atenção imediata. Seu CLAUDE.md já contém regras abrangentes sobre padrões aceitáveis, e você começou a descartar achados sem revisá-los porque não consegue prever quais são realmente críticos. Qual é a maneira mais eficaz de melhorar a consistência de severidade?\n\n[ ] A - Modificar o prompt para pedir que o Claude classifique a severidade de forma relativa aos outros problemas do mesmo PR, de modo que o problema mais severo seja sempre marcado como crítico e os demais avaliados proporcionalmente\n[ ] B - Solicitar que o Claude inclua o raciocínio para cada atribuição de severidade e, então, usar esse raciocínio para calibrar e ajustar manualmente as classificações durante a revisão\n[ ] C - Adicionar um arquivo CLAUDE.md que liste tipos de problemas e suas severidades padrão, instruindo o Claude a consultar esse mapeamento ao atribuir classificações\n[ ] D - Incluir critérios explícitos de severidade no seu prompt, com exemplos concretos de código para cada nível de severidade','\n',char(10)),replace('**Explicação para tech lead:**\n\nO problema central é **falta de ancoragem (grounding) e ausência de definições operacionais claras**. Quando você pede a um LLM que classifique severidade sem critérios explícitos e exemplos concretos, o modelo aplica um julgamento subjetivo que varia de acordo com o contexto de cada PR, gerando a inconsistência descrita.\n\n**Por que D é a melhor escolha:**\n- Fornecer critérios explícitos de severidade com **exemplos concretos de código (few-shot examples)** ancora o julgamento do modelo em referências objetivas e reproduzíveis.\n- Exemplos concretos são especialmente eficazes com LLMs porque reduzem ambiguidade: o modelo compara o achado real com padrões demonstrados, em vez de improvisar uma escala.\n- Isso resolve a causa raiz — a subjetividade da classificação — em vez de tratar sintomas. Um risco de null pointer com o mesmo perfil passa a receber sempre a mesma severidade, restaurando a previsibilidade e a confiança das equipes.\n\n**Por que as outras estão erradas:**\n\n- **A (severidade relativa dentro do PR)** — Introduz inconsistência por design. A mesma questão de null pointer seria "crítica" em um PR com poucos problemas e "média" em um PR cheio de problemas graves. A severidade deixa de refletir o risco absoluto e passa a depender do contexto vizinho — exatamente o oposto da previsibilidade desejada.\n\n- **B (incluir raciocínio + ajuste manual)** — Pedir o raciocínio ajuda na auditoria, mas a calibração manual não escala, é ela mesma inconsistente (depende do revisor e do dia) e não corrige a causa raiz na origem. Além disso, o cenário já indica que a equipe está sem capacidade de revisar (descartando achados), então adicionar trabalho manual piora o gargalo.\n\n- **C (mapeamento estático de tipo→severidade no CLAUDE.md)** — Parece razoável, mas um mapeamento fixo por tipo é grosseiro demais: um null pointer pode ser crítico em código de pagamento e trivial em um script de teste descartável. Além disso, o CLAUDE.md já é abrangente e não resolveu o problema; a inconsistência vem da falta de critérios exemplificados no ponto de decisão (o prompt), não da falta de uma tabela de tipos. Exemplos concretos (D) capturam nuance de contexto que uma tabela plana não captura.\n\nEm resumo: a consistência vem de **critérios objetivos + exemplos demonstrados**, que ancoram o modelo de forma reproduzível e escalável.','\n',char(10)),replace('Imagine que você é um professor corrigindo provas e precisa dar notas: "muito grave", "médio" ou "pequeno" para os erros dos alunos. Se você não tiver uma regra clara, um dia pode achar um erro "muito grave" e no outro dia achar o mesmo erro só "médio". Aí os alunos ficam confusos e não confiam mais em você!\n\nA melhor solução (resposta D) é fazer uma folinha com exemplos: "ISTO aqui é muito grave, olha o exemplo. ISTO aqui é médio, olha o exemplo." Assim, toda vez que aparecer um erro parecido, você olha os exemplos e dá sempre a mesma nota. Fica justo e previsível!\n\nAs outras ideias não funcionam tão bem:\n- A: dar a nota comparando só com os outros erros da mesma prova — aí o mesmo erro ganharia notas diferentes dependendo da prova, o que bagunça tudo.\n- B: pedir para explicar cada nota e depois você arruma na mão — dá muito trabalho e você mesmo pode variar de humor de um dia pro outro.\n- C: fazer uma tabela dizendo "esse tipo de erro é sempre grave" — mas às vezes o mesmo erro é grave num lugar importante e bobo num lugar sem importância, então a tabela é simples demais.\n\nPor isso, ter exemplos de verdade (D) é o jeito mais justo e certo!','\n',char(10)));
INSERT INTO cards VALUES('admin','card_1783092983940_6y05fb20n',11,'Reduzir falsos positivos em análise de comentários com contexto',replace('Reduzir falsos positivos em análise de comentários com contexto\n\nYour automated review analyzes comments and docstrings. The current prompt instructs Claude to "check that comments are accurate and up-to-date." Findings frequently flag acceptable patterns (TODO markers, straightforward descriptions) while missing comments that describe behavior the code no longer implements. What change addresses the root cause of this inconsistent analysis?\n\n[ ] A - Filter out TODO, FIXME, and descriptive comment patterns before analysis to reduce noise\n[ ] B - Add few-shot examples of misleading comments to help the model recognize similar patterns in the codebase\n[ ] C - Specify explicit criteria: flag comments only when their claimed behavior contradicts actual code behavior\n[ ] D - Include git blame data so Claude can identify comments that predate recent code modifications','\n',char(10)),'C - Specify explicit criteria: flag comments only when their claimed behavior contradicts actual code behavior','["Domain_4::Prompt_Engineering_Structured_Output", "Domain_5::Context_Management_Reliability", "Scenario_5::Claude_Code_CI_CD"]','New',0,2.5,0,1783092983940,1783339438540,1783203558653,replace('Sua revisão automatizada analisa comentários e docstrings. O prompt atual instrui o Claude a "verificar se os comentários estão precisos e atualizados". As descobertas frequentemente sinalizam padrões aceitáveis (marcadores TODO, descrições simples) enquanto deixam passar comentários que descrevem um comportamento que o código não implementa mais. Qual mudança resolve a causa raiz dessa análise inconsistente?\n\n[ ] A - Filtrar padrões de comentários TODO, FIXME e descritivos antes da análise para reduzir o ruído\n[ ] B - Adicionar exemplos few-shot de comentários enganosos para ajudar o modelo a reconhecer padrões semelhantes na base de código\n[ ] C - Especificar critérios explícitos: sinalizar comentários somente quando o comportamento que eles alegam contradiz o comportamento real do código\n[ ] D - Incluir dados de git blame para que o Claude possa identificar comentários anteriores a modificações recentes do código','\n',char(10)),replace('A causa raiz do problema é que a instrução do prompt é vaga e ambígua: "check that comments are accurate and up-to-date". Termos como "preciso" e "atualizado" são subjetivos e deixam o modelo definir por conta própria o que merece ser sinalizado. Isso gera dois sintomas simultâneos: (1) falsos positivos, porque o modelo sinaliza TODOs e descrições inofensivas que tecnicamente poderiam ser vistas como "não atualizadas"; e (2) falsos negativos, porque não há um critério claro que force o modelo a comparar a afirmação do comentário com o comportamento efetivo do código.\n\n**Por que C é a melhor escolha:** Ela ataca a causa raiz definindo um critério objetivo e verificável — sinalizar apenas quando a afirmação do comentário contradiz o comportamento real do código. Isso elimina os falsos positivos (um TODO não afirma comportamento, então não é sinalizado) e ao mesmo tempo captura os falsos negativos (um comentário que descreve lógica que o código não executa mais é exatamente uma contradição). Um único ajuste de critério resolve os dois lados da inconsistência, que é o comportamento esperado de uma correção de causa raiz.\n\n**Por que as demais estão erradas:**\n- **A** trata apenas o sintoma dos falsos positivos filtrando ruído por padrão, mas não faz nada pelos falsos negativos (comentários desatualizados que continuam passando). Além disso, filtrar mecanicamente pode remover comentários que também mereceriam análise. É um paliativo, não a causa raiz.\n- **B** adiciona exemplos few-shot, o que pode ajudar marginalmente, mas depende de o modelo generalizar padrões específicos em vez de ter uma regra clara. Sem um critério explícito, os exemplos ainda deixam a definição de "aceitável" ambígua e não garantem consistência em toda a base.\n- **D** fornece dados de git blame, mas idade de um comentário não equivale a incorreção. Um comentário antigo pode continuar perfeitamente válido, e um comentário recém-escrito pode já estar errado. Isso introduz um sinal correlacionado, porém não causal, sem resolver a ambiguidade do critério.','\n',char(10)),replace('Imagine que você pediu a um robô para "olhar se os bilhetinhos colados no seu caderno estão certos". O problema é que "certos" é uma palavra muito vaga! O robô fica marcando bilhetes que estão ok (tipo "lembrar de terminar depois") e esquece de marcar bilhetes que dizem uma coisa errada sobre o que o caderno realmente faz.\n\nA melhor solução (letra C) é dar uma regra bem clara para o robô: "só marque um bilhete quando ele disser algo diferente do que a página realmente faz". Assim o robô para de reclamar dos bilhetes bonzinhos e passa a encontrar de verdade os bilhetes mentirosos.\n\nAs outras opções só arrumam metade do problema: uma esconde os bilhetes chatos (mas não acha os mentirosos), outra dá exemplos (mas ainda sem uma regra clara) e a última tenta adivinhar pelos bilhetes mais velhos — só que um bilhete velho pode estar certinho e um novo pode estar errado!','\n',char(10)));
INSERT INTO cards VALUES('admin','card_1783092983944_53m9rwud5',12,'Eliminar findings duplicados após commit de correções iterativas',replace('Eliminar findings duplicados após commit de correções iterativas\n\nAfter an initial automated review generates 12 findings, a developer pushes new commits to address the issues. When the review runs again, it produces 8 findings—but developers report that 5 duplicate earlier comments on code that was already fixed in the new commits. What''s the most effective way to eliminate this redundant feedback while maintaining thorough analysis?\n\n[ ] A - Add a post-processing filter that removes findings matching previous file paths and issue descriptions before posting comments.\n[ ] B - Run reviews only on initial PR creation and final pre-merge state, skipping intermediate commits.\n[ ] C - Include prior review findings in context, instructing Claude to only report new or still-unaddressed issues.\n[ ] D - Restrict the review scope to only files modified in the most recent push, excluding files from earlier commits.','\n',char(10)),'C - Include prior review findings in context, instructing Claude to only report new or still-unaddressed issues.','["Domain_4::Prompt_Engineering_Structured_Output", "Domain_5::Context_Management_Reliability", "Scenario_5::Claude_Code_CI_CD"]','New',0,2.5,0,1783092983944,1783339442829,1783203558653,replace('Após uma revisão automatizada inicial gerar 12 findings (achados), um desenvolvedor faz push de novos commits para resolver os problemas. Quando a revisão roda novamente, ela produz 8 findings — mas os desenvolvedores relatam que 5 duplicam comentários anteriores em código que já foi corrigido nos novos commits. Qual é a maneira mais eficaz de eliminar esse feedback redundante mantendo uma análise minuciosa?\n\n[ ] A - Adicionar um filtro de pós-processamento que remove findings que correspondam a caminhos de arquivos e descrições de problemas anteriores antes de postar os comentários.\n[ ] B - Rodar as revisões apenas na criação inicial do PR e no estado final pré-merge, pulando os commits intermediários.\n[ ] C - Incluir os findings da revisão anterior no contexto, instruindo o Claude a reportar apenas problemas novos ou ainda não resolvidos.\n[ ] D - Restringir o escopo da revisão apenas aos arquivos modificados no push mais recente, excluindo arquivos de commits anteriores.','\n',char(10)),replace('A resposta correta é a **C**.\n\nO cerne do problema é que a revisão automatizada não tem "memória" do que já foi analisado nem consciência de que algumas questões já foram corrigidas. A solução mais eficaz e alinhada às boas práticas de uso de LLMs é fornecer o histórico de findings anteriores como parte do contexto e instruir o modelo a considerar esse estado. Assim, o Claude pode fazer o raciocínio semântico: comparar o código atual com os problemas previamente apontados e determinar se cada um foi resolvido, permanece pendente ou é genuinamente novo. Isso preserva a análise completa (nada é excluído do escopo) enquanto elimina a redundância de forma inteligente.\n\nPor que as demais estão erradas:\n\n**A (filtro de pós-processamento por correspondência de path + descrição):** É frágil e propenso a falsos positivos/negativos. A correspondência textual não entende semântica — um problema no mesmo arquivo com descrição parecida pode ser genuinamente novo (ou o mesmo problema em outra linha), e o filtro poderia suprimi-lo indevidamente. Além disso, pequenas variações na redação do finding quebrariam o matching. Não distingue "corrigido" de "reincidente".\n\n**B (rodar só no início e no pré-merge):** Sacrifica a análise contínua e o feedback iterativo, que é justamente o valor da revisão automatizada durante o desenvolvimento. Reduz a redundância apenas por rodar menos vezes, mas prejudica a "análise minuciosa" exigida pelo enunciado e atrasa a detecção de problemas.\n\n**D (limitar aos arquivos do push mais recente):** Cria pontos cegos graves. Um commit pode introduzir uma regressão ou efeito colateral em um arquivo não tocado no último push, ou um problema anterior em outro arquivo pode continuar sem correção. Excluir arquivos do escopo compromete diretamente a completude da análise.','\n',char(10)),replace('Imagine que um professor corrigiu sua redação e apontou 12 errinhos. Você arrumou vários e entregou de novo. Se o professor esquecer o que já tinha corrigido, ele pode reclamar de coisas que você JÁ consertou!\n\nA melhor solução (letra C) é dar ao corretor a lista de erros antigos e dizer: "olha o que você já apontou antes, agora só me fale o que ainda está errado ou o que é novo". Assim ele lembra e não repete.\n\nAs outras ideias não funcionam tão bem:\n- A: só apagar comentários "parecidos" é arriscado — pode apagar um erro de verdade só porque a frase ficou parecida.\n- B: corrigir só no começo e no fim faz você perder ajuda no meio do caminho.\n- D: olhar só a última página que você mexeu deixa passar erros nas outras páginas.\n\nPor isso, o jeito mais esperto é dar memória para o corretor: letra C!','\n',char(10)));
INSERT INTO cards VALUES('admin','card_1783092983948_cb0ixzsuo',13,'Otimizar custos com Message Batches API em pipelines CI/CD',replace('Otimizar custos com Message Batches API em pipelines CI/CD\n\nYour CI pipeline includes two Claude-powered code review modes: a pre-merge-commit hook that blocks PR merging until complete, and "deep analysis" that runs overnight, polls for batch completion, then posts detailed suggestions to the PR. You want to reduce API costs using the Message Batches API, which offers 50% cost savings but requires polling and may take up to 24 hours to complete. Which mode should use batch processing?\n\n[ ] A - Neither mode\n[ ] B - Deep analysis only\n[ ] C - Both modes\n[ ] D - Pre-merge-commit hook only','\n',char(10)),'B - Deep analysis only','["Domain_3::Claude_Code_Configuration_Workflows", "Domain_5::Context_Management_Reliability", "Scenario_5::Claude_Code_CI_CD"]','New',0,2.5,0,1783092983948,1783339447845,1783203558653,replace('Seu pipeline de CI inclui dois modos de revisão de código com Claude: um hook de pré-merge-commit que bloqueia o merge do PR até ser concluído, e a "análise profunda" (deep analysis) que roda durante a noite, faz polling aguardando a conclusão do batch e então posta sugestões detalhadas no PR. Você quer reduzir custos de API usando a Message Batches API, que oferece 50% de economia de custo, mas exige polling e pode levar até 24 horas para concluir. Qual modo deve usar o processamento em batch?\n\n[ ] A - Nenhum dos modos\n[ ] B - Apenas a análise profunda (deep analysis)\n[ ] C - Ambos os modos\n[ ] D - Apenas o hook de pré-merge-commit','\n',char(10)),replace('A resposta correta é **B - Apenas a análise profunda (deep analysis)**.\n\nO critério de decisão para usar a Message Batches API é a tolerância à latência. A API oferece 50% de economia, mas em troca é assíncrona: exige polling e pode levar até 24 horas para retornar o resultado. Portanto, ela só faz sentido em cargas de trabalho que **não são sensíveis ao tempo**.\n\n**Por que a análise profunda (deep analysis) é candidata ideal:**\n- Roda durante a noite (overnight), ou seja, já é um processo em background sem interação humana em tempo real.\n- Já usa polling por design ("polls for batch completion"), o que se encaixa perfeitamente no modelo assíncrono do batch.\n- Postar sugestões detalhadas algumas horas depois não bloqueia ninguém — a latência de até 24h é perfeitamente aceitável.\n- Resultado: 50% de economia sem impacto negativo no fluxo de trabalho.\n\n**Por que o hook de pré-merge-commit NÃO deve usar batch:**\n- Ele **bloqueia o merge do PR até ser concluído**. É um caminho crítico e síncrono no fluxo do desenvolvedor.\n- Se usasse batch, o desenvolvedor poderia ficar esperando até 24 horas para conseguir fazer o merge — algo inaceitável, que destruiria a produtividade da equipe.\n- Cargas sensíveis à latência devem usar a API síncrona (Messages) padrão, mesmo custando mais.\n\n**Por que as demais alternativas estão erradas:**\n- **A - Nenhum dos modos:** erra ao ignorar a economia gratuita que o deep analysis pode capturar, já que ele é assíncrono e tolerante à latência.\n- **C - Ambos os modos:** erra ao incluir o hook bloqueante, cuja latência de até 24h inviabilizaria o merge de PRs em tempo hábil.\n- **D - Apenas o hook de pré-merge-commit:** é exatamente o inverso do correto — aplica batch justamente no ponto mais sensível à latência, e deixa de aplicá-lo onde seria seguro.\n\n**Regra prática (tech lead takeaway):** use a Message Batches API para cargas assíncronas, não interativas e tolerantes a atraso (jobs noturnos, relatórios, análises em lote). Mantenha a API síncrona para qualquer coisa no caminho crítico do usuário ou que bloqueie um fluxo (gates de CI que bloqueiam merge, respostas interativas, etc.).','\n',char(10)),replace('Imagina que você tem duas tarefas com o robô Claude que revisa códigos.\n\nA primeira tarefa é como um "portão": ninguém pode passar (fazer o merge) enquanto o robô não terminar de revisar. Se as pessoas tiverem que esperar, elas precisam de uma resposta bem rápida!\n\nA segunda tarefa é o "trabalho da madrugada": o robô revisa tudo durante a noite, enquanto todo mundo dorme, e deixa os recadinhos prontos de manhã. Ninguém está esperando parado.\n\nAgora tem uma forma mais barata de usar o robô (custa metade do preço!), mas ela é lenta — pode demorar até 24 horas para responder.\n\nOnde usar a forma lenta e barata? No trabalho da madrugada! Porque ali ninguém está esperando, então tanto faz demorar um pouco. Já no "portão" não pode, porque as pessoas ficariam presas esperando até um dia inteiro para poder passar — isso seria péssimo!\n\nPor isso a resposta certa é a **B: só na análise profunda (o trabalho da madrugada)**.','\n',char(10)));
INSERT INTO cards VALUES('admin','card_1783092983952_4rr3n47qc',14,'Executar Claude Code em pipeline automatizado sem input interativo',replace('Executar Claude Code em pipeline automatizado sem input interativo\n\nYour pipeline script runs claude "Analyze this pull request for security issues" but the job hangs indefinitely. Logs indicate Claude Code is waiting for interactive input. What''s the correct approach to run Claude Code in an automated pipeline?\n\n[ ] A - Redirect stdin from /dev/null: claude "Analyze this pull request for security issues" < /dev/null\n[ ] B - Set the environment variable CLAUDE_HEADLESS=true before running the command\n[ ] C - Add the -p flag: claude -p "Analyze this pull request for security issues"\n[ ] D - Add the --batch flag: claude --batch "Analyze this pull request for security issues"','\n',char(10)),'C - Add the -p flag: claude -p "Analyze this pull request for security issues"','["Domain_3::Claude_Code_Configuration_Workflows", "Domain_4::Prompt_Engineering_Structured_Output", "Scenario_5::Claude_Code_CI_CD"]','New',0,2.5,0,1783092983952,1783339452471,1783203558653,replace('Seu script de pipeline executa `claude "Analyze this pull request for security issues"`, mas o job trava indefinidamente. Os logs indicam que o Claude Code está aguardando entrada interativa. Qual é a abordagem correta para executar o Claude Code em um pipeline automatizado?\n\n[ ] A - Redirecionar o stdin a partir de /dev/null: `claude "Analyze this pull request for security issues" < /dev/null`\n[ ] B - Definir a variável de ambiente `CLAUDE_HEADLESS=true` antes de executar o comando\n[ ] C - Adicionar a flag `-p`: `claude -p "Analyze this pull request for security issues"`\n[ ] D - Adicionar a flag `--batch`: `claude --batch "Analyze this pull request for security issues"`','\n',char(10)),replace('**Resposta correta: C**\n\nO Claude Code, quando invocado sem argumentos especiais, inicia por padrão em **modo interativo (REPL)** — uma sessão de terminal contínua que fica esperando o usuário digitar comandos, confirmar ações e continuar a conversa. Em um pipeline de CI/CD não há terminal (TTY) interativo, então o processo fica bloqueado esperando um input que nunca chega, causando o "hang" que você observou.\n\nA flag `-p` (abreviação de `--print`) coloca o Claude Code em **modo não interativo (headless / print mode)**: ele executa o prompt fornecido, imprime a resposta no stdout e encerra o processo com um código de saída. Esse é exatamente o comportamento desejado para automação — o comando roda, produz sua saída e retorna o controle ao script. É o modo oficial e documentado para uso em pipelines, scripts e integrações programáticas (podendo ainda ser combinado com `--output-format json` para parsing estruturado).\n\n**Por que as outras estão erradas:**\n\n- **A (redirecionar stdin de /dev/null):** Isso pode até evitar que o processo trave à espera de leitura no stdin, mas **não é a solução correta nem confiável**. O Claude continua tentando iniciar o modo interativo; sem o modo print explícito, o comportamento é imprevisível — o processo pode encerrar sem realmente processar o prompt como uma tarefa completa, ou tratar de forma incorreta as etapas que exigiriam confirmação. É um "workaround" frágil, não o mecanismo projetado para automação.\n\n- **B (`CLAUDE_HEADLESS=true`):** Essa variável de ambiente **não existe** na CLI do Claude Code. É uma invenção plausível, mas o controle do modo não interativo é feito pela flag `-p`/`--print`, não por essa variável.\n\n- **D (`--batch`):** A flag `--batch` **não existe** no Claude Code. Embora o nome soe adequado para processamento em lote, essa não é a sintaxe real da ferramenta. Usá-la resultaria em erro de flag desconhecida.\n\n**Dica prática de tech lead:** em pipelines, combine `claude -p` com `--output-format json` para obter respostas parseáveis, defina `--allowedTools` para restringir o que o agente pode executar de forma não supervisionada, e sempre valide o exit code do comando no seu script.','\n',char(10)),replace('Imagina que o Claude é como um robô assistente. Normalmente, quando você chama o robô, ele fica esperando você conversar com ele: "e agora, o que você quer? posso fazer isso? confirma?". Isso é ótimo quando você está sentado na frente dele.\n\nMas num sistema automático (um robô controlando outro robô), não tem ninguém para responder essas perguntas. Aí o robô fica parado, esperando para sempre, e o trabalho "trava".\n\nA solução é falar assim: `claude -p "sua pergunta"`. O `-p` é como dizer: "Robô, não fique de papo! Só me dá a resposta e vai embora." Ele responde de uma vez e termina, sem ficar esperando ninguém.\n\nAs outras opções estão erradas porque:\n- **A** é um truque meio "gambiarra" que nem sempre funciona direito.\n- **B** e **D** inventam palavras mágicas (`CLAUDE_HEADLESS` e `--batch`) que o robô nem entende — é como pedir algo numa língua que ele não conhece.\n\nPor isso a resposta certa é a **C**! 🤖','\n',char(10)));
INSERT INTO cards VALUES('admin','card_1783092983957_tsymmdepv',15,'Otimizar custos de API com batch processing e timeout fallback',replace('Otimizar custos de API com batch processing e timeout fallback\n\nYour team wants to reduce API costs for automated analysis. Currently, real-time Claude calls power two workflows: (1) a blocking pre-merge check that must complete before developers can merge, and (2) a technical debt report generated overnight for review the next morning. Your manager proposes switching both to the Message Batches API for its 50% cost savings. How should you evaluate this proposal?\n\n[ ] A - Switch both workflows to batch processing with status polling to check for completion.\n[ ] B - Keep real-time calls for both workflows to avoid batch result ordering issues.\n[ ] C - Switch both to batch processing with a timeout fallback to real-time if batches take too long.\n[ ] D - Use batch processing for the technical debt reports only; keep real-time calls for pre-merge checks.','\n',char(10)),'D - Use batch processing for the technical debt reports only; keep real-time calls for pre-merge checks.','["Domain_5::Context_Management_Reliability", "Domain_4::Prompt_Engineering_Structured_Output", "ForaDoCenario"]','New',0,2.5,0,1783092983957,1783339457085,1783203558653,replace('Sua equipe quer reduzir os custos de API para análise automatizada. Atualmente, chamadas em tempo real ao Claude alimentam dois fluxos de trabalho: (1) uma verificação pré-merge bloqueante que precisa ser concluída antes que os desenvolvedores possam fazer o merge, e (2) um relatório de dívida técnica gerado durante a noite para revisão na manhã seguinte. Seu gerente propõe mudar ambos para a Message Batches API por causa da economia de 50% no custo. Como você deve avaliar essa proposta?\n\n[ ] A - Migrar ambos os fluxos para processamento em lote (batch) com polling de status para verificar a conclusão.\n[ ] B - Manter chamadas em tempo real para ambos os fluxos, para evitar problemas de ordenação dos resultados do batch.\n[ ] C - Migrar ambos para processamento em lote com um fallback por timeout para tempo real caso os lotes demorem demais.\n[ ] D - Usar processamento em lote apenas para os relatórios de dívida técnica; manter as chamadas em tempo real para as verificações pré-merge.','\n',char(10)),replace('A chave da decisão está em entender a característica fundamental da Message Batches API: ela é assíncrona e otimizada para throughput, não para latência. A Anthropic garante o processamento em até 24 horas, mas não oferece garantia de latência baixa — um lote pode levar segundos ou muitas horas. Portanto, a adequação de cada fluxo depende do seu requisito de latência.\n\n**Analisando os dois fluxos:**\n- A **verificação pré-merge é bloqueante e síncrona**: o desenvolvedor está esperando para fazer o merge. Latência de minutos (ou horas) tornaria o fluxo de trabalho inviável. Esse é exatamente o caso de uso que exige tempo real.\n- O **relatório de dívida técnica é assíncrono por natureza**: é gerado à noite e lido na manhã seguinte. A janela de até 24h do batch encaixa perfeitamente, capturando a economia de 50% sem prejuízo algum.\n\n**Por que D é a melhor escolha:** Ela aplica a ferramenta certa a cada problema. Captura a economia de custo onde a latência não importa (relatórios) e preserva a experiência do desenvolvedor onde a latência é crítica (pré-merge). É a decisão de arquitetura que equilibra custo e requisitos de negócio.\n\n**Por que as demais estão erradas:**\n- **A** ignora que a verificação pré-merge é bloqueante. Fazer polling de status em um processo que pode levar horas travaria o pipeline de merge dos desenvolvedores — inaceitável.\n- **B** é excessivamente conservadora: descarta 50% de economia legítima no relatório noturno, um caso ideal para batch. Além disso, "ordering issues" não é um problema real, pois cada resultado do batch é retornado com seu `custom_id`, permitindo correlação confiável.\n- **C** parece engenhosa, mas é uma anti-arquitetura para o pré-merge. Um "timeout fallback" implica esperar o batch estourar um limite antes de refazer a chamada em tempo real — ou seja, você paga a latência do timeout mais o custo da chamada em tempo real, resultando em pior latência e possivelmente custo maior do que simplesmente usar tempo real desde o início. Adiciona complexidade sem benefício real.','\n',char(10)),replace('Imagine que você tem dois tipos de tarefas. Uma é uma "fila rápida" (batch) que é 50% mais barata, mas pode demorar até um dia inteiro para ficar pronta. A outra é o "atendimento na hora", que custa mais caro, mas responde na mesma hora.\n\nAgora pense nos dois trabalhos:\n1. A verificação antes de juntar o código: o programador está PARADO esperando a resposta para poder continuar. Se demorar horas, ele fica travado! Então esse precisa ser na hora (rápido).\n2. O relatório que é feito de noite e lido só na manhã seguinte: ninguém está esperando! Pode demorar a noite toda tranquilamente. Esse pode ir para a fila mais barata.\n\nEntão a resposta certa (D) é: coloque só o relatório da noite na fila barata e deixe a verificação do programador no atendimento na hora. Assim você economiza dinheiro onde dá, sem deixar ninguém esperando parado.','\n',char(10)));
INSERT INTO cards VALUES('admin','card_1783092983961_1bwpim8ss',16,'Sistema de Pesquisa Multiagente',replace('Sistema de Pesquisa Multiagente\n\nUm agente de análise de documentos descobre que duas fontes confiáveis contêm estatísticas diretamente contraditórias para uma métrica-chave: um relatório governamental indica crescimento de 40%, enquanto uma análise da indústria indica 12%. Ambas as fontes parecem confiáveis e a discrepância pode afetar materialmente as conclusões da pesquisa. Como o agente de análise de documentos deve lidar com essa situação da forma mais efetiva?\n\n[ ] A - Aplicar heurísticas de credibilidade para escolher o número mais provavelmente correto, finalizar a análise com esse valor e adicionar uma nota de rodapé mencionando a discrepância.\n[ ] B - Incluir ambos os números na saída da análise sem marcá-los como conflitantes, deixando o agente de síntese decidir qual usar com base em contexto mais amplo.\n[ ] C - Parar a análise e escalar imediatamente ao coordenador, pedindo que ele decida qual fonte é mais autoritativa antes de continuar.\n[ ] D - Concluir a análise com ambos os números, anotar explicitamente o conflito com atribuição de fonte e deixar o coordenador decidir como reconciliar os dados antes de passá-los à síntese.','\n',char(10)),'D - Concluir a análise com ambos os números, anotar explicitamente o conflito com atribuição de fonte e deixar o coordenador decidir como reconciliar os dados antes de passá-los à síntese.','["Domain_1::Agentic_Architecture_Orchestration", "Domain_4::Prompt_Engineering_Structured_Output", "Scenario_3::Multi_Agent_Research"]','New',0,2.5,0,1783092983961,1783724795610,1783203558653,replace('Sistema de Pesquisa Multiagente\n\nUm agente de análise de documentos descobre que duas fontes confiáveis contêm estatísticas diretamente contraditórias para uma métrica-chave: um relatório governamental indica crescimento de 40%, enquanto uma análise da indústria indica 12%. Ambas as fontes parecem confiáveis e a discrepância pode afetar materialmente as conclusões da pesquisa. Como o agente de análise de documentos deve lidar com essa situação da forma mais efetiva?\n\nA - Aplicar heurísticas de credibilidade para escolher o número mais provavelmente correto, finalizar a análise com esse valor e adicionar uma nota de rodapé mencionando a discrepância.\nB - Incluir ambos os números na saída da análise sem marcá-los como conflitantes, deixando o agente de síntese decidir qual usar com base em contexto mais amplo.\nC - Parar a análise e escalar imediatamente ao coordenador, pedindo que ele decida qual fonte é mais autoritativa antes de continuar.\nD - Concluir a análise com ambos os números, anotar explicitamente o conflito com atribuição de fonte e deixar o coordenador decidir como reconciliar os dados antes de passá-los à síntese.','\n',char(10)),replace('Em arquiteturas de sistemas multiagentes, cada agente tem um papel bem definido (separação de responsabilidades). O agente de análise de documentos tem a função de **extrair e apresentar informações de forma fiel**, não de decidir arbitrariamente qual verdade prevalece — essa decisão de reconciliação é de nível superior e cabe ao coordenador/orquestrador, que possui visão global do contexto da pesquisa.\n\n**Por que D é a melhor escolha:**\n- **Preserva a informação sem perda**: mantém ambos os valores (40% e 12%), evitando que uma decisão prematura descarte um dado potencialmente correto.\n- **Sinaliza o conflito explicitamente**: marcar o conflito com atribuição de fonte (governamental vs. indústria) fornece metadados essenciais para a decisão posterior. É o padrão de "fail loud" / transparência de dados.\n- **Respeita a separação de responsabilidades**: delega a decisão de reconciliação ao coordenador, que é o agente com contexto e autoridade para isso, sem interromper o fluxo de trabalho.\n- **Não bloqueia o pipeline**: a análise é concluída, e a decisão flui de forma assíncrona para o coordenador antes da síntese — evitando que dados conflitantes cheguem "cegos" à etapa de síntese.\n\n**Por que as demais estão erradas:**\n- **A (errada)**: aplicar heurísticas para escolher unilateralmente um valor e relegar o conflito a uma nota de rodapé transfere um risco material para uma escolha do agente de baixo nível. A discrepância "pode afetar materialmente as conclusões", então enterrar isso em rodapé é subestimar o impacto e extrapolar a responsabilidade do agente.\n- **B (errada)**: incluir ambos os números **sem marcá-los como conflitantes** é o pior cenário de transparência — o agente de síntese pode nem perceber que são contraditórios, misturando-os ou escolhendo aleatoriamente, propagando erro silencioso ("fail silent"). Falta o sinal explícito de conflito.\n- **C (errada)**: parar toda a análise e escalar imediatamente é excessivamente disruptivo. Bloqueia desnecessariamente o restante do trabalho do agente (que ainda pode produzir valor) e cria um gargalo síncrono. O correto é concluir o que é possível e sinalizar o ponto de decisão, não travar o pipeline.\n\nA chave é: **transparência + atribuição + delegação da decisão ao nível correto, sem bloquear o fluxo**.','\n',char(10)),replace('Imagine que você tem um robô ajudante cujo trabalho é ler livros e anotar informações. Um dia ele encontra duas frases que se contradizem: um livro diz que algo cresceu 40% e outro diz que cresceu só 12%. Os dois livros parecem confiáveis!\n\nO que o robô deve fazer? Ele **não** deve escolher um número sozinho e escondê-lo, porque pode errar. Ele também **não** deve simplesmente copiar os dois números sem avisar que eles brigam entre si — assim o próximo ajudante nem perceberia o problema. E ele também **não** precisa parar tudo e fazer bagunça.\n\nA melhor coisa é: o robô anota **os dois números**, coloca um aviso bem grande dizendo "olha, esses dois valores não combinam, um veio daqui e o outro veio dali!", e entrega isso para o chefe (o coordenador), que tem a visão de tudo e vai decidir qual usar. Assim, ninguém perde informação e ninguém toma uma decisão errada por acidente. Por isso a resposta certa é a **D**!','\n',char(10)));
INSERT INTO cards VALUES('admin','card_1783092983966_1n42vlh0a',17,'Sistema de Pesquisa Multiagente',replace('Sistema de Pesquisa Multiagente\n\nOs agentes de busca web e de análise de documentos concluíram suas tarefas e retornaram resultados ao coordenador. Qual é o próximo passo para criar um relatório de pesquisa integrado?\n\n[ ] A - Cada agente envia seus resultados diretamente ao agente redator do relatório, contornando o coordenador.\n[ ] B - O agente de análise de documentos solicita os resultados de busca web e os funde internamente.\n[ ] C - O coordenador passa ambos os conjuntos de resultados ao agente de síntese para uma integração unificada.\n[ ] D - O coordenador concatena as saídas brutas de ambos os agentes e as devolve como resultado final.','\n',char(10)),'C - O coordenador passa ambos os conjuntos de resultados ao agente de síntese para uma integração unificada.','["Domain_1::Agentic_Architecture_Orchestration", "Scenario_3::Multi_Agent_Research"]','New',0,2.5,0,1783092983966,1783724799160,1783203558653,replace('Sistema de Pesquisa Multiagente\n\nOs agentes de busca web e de análise de documentos concluíram suas tarefas e retornaram resultados ao coordenador. Qual é o próximo passo para criar um relatório de pesquisa integrado?\n\nA - Cada agente envia seus resultados diretamente ao agente redator do relatório, contornando o coordenador.\nB - O agente de análise de documentos solicita os resultados de busca web e os funde internamente.\nC - O coordenador passa ambos os conjuntos de resultados ao agente de síntese para uma integração unificada.\nD - O coordenador concatena as saídas brutas de ambos os agentes e as devolve como resultado final.','\n',char(10)),replace('**Resposta correta: C**\n\nNo padrão arquitetural de sistemas multiagente do tipo *orchestrator-worker* (coordenador-trabalhadores), o coordenador atua como o ponto central de orquestração. O fluxo canônico é:\n\n1. O coordenador delega subtarefas a agentes especializados (busca web, análise de documentos).\n2. Os agentes trabalhadores executam e devolvem seus resultados ao coordenador.\n3. O coordenador encaminha esses resultados a um agente especializado em **síntese**, cuja responsabilidade é integrar, reconciliar, deduplicar e produzir uma saída coerente e unificada.\n\nA alternativa **C** respeita a separação de responsabilidades (cada agente com um papel bem definido) e mantém o coordenador como orquestrador, delegando a tarefa cognitiva de integração a um agente de síntese — exatamente o padrão recomendado para gerar um relatório integrado de qualidade.\n\n**Por que as demais estão erradas:**\n\n- **A** — Quebra o padrão de orquestração ao permitir comunicação direta entre agentes, contornando o coordenador. Isso cria acoplamento descontrolado, dificulta o rastreamento/observabilidade do fluxo e viola o princípio de que o coordenador governa o roteamento das mensagens.\n\n- **B** — Sobrecarrega o agente de análise de documentos com uma responsabilidade que não é dele (fundir resultados de outra fonte). Além de violar o *single responsibility principle*, cria acoplamento indevido entre agentes especializados que deveriam ser independentes.\n\n- **D** — Concatenar saídas brutas não é síntese. Apenas juntar textos não elimina redundâncias, não resolve conflitos entre fontes nem produz uma narrativa coesa. O resultado seria um amontoado de dados, não um relatório integrado — que é justamente o objetivo declarado.','\n',char(10)),replace('Imagine que dois ajudantes foram fazer pesquisas: um procurou coisas na internet e o outro leu vários documentos. Agora os dois terminaram e entregaram o que descobriram para o "chefe" (o coordenador).\n\nSó juntar os dois montes de papel e entregar assim, bagunçado, não vira um bom trabalho (por isso a opção D está errada). E os ajudantes não devem falar direto entre si pulando o chefe (opção A errada), nem um ajudante deve fazer o trabalho do outro (opção B errada).\n\nO certo é o chefe entregar tudo para um ajudante especial que sabe **juntar as informações com capricho**, organizando tudo em um só texto bem feito. Por isso a resposta certa é a **C**!','\n',char(10)));
INSERT INTO cards VALUES('admin','card_1783092983970_by9dw85n0',18,'Sistema de Pesquisa Multiagente',replace('Sistema de Pesquisa Multiagente\n\nUm subagente de análise de documentos falha frequentemente ao processar arquivos PDF: alguns têm seções corrompidas que disparam exceções de parsing, outros são protegidos por senha e às vezes a biblioteca de parsing trava em arquivos grandes. Atualmente, qualquer exceção termina imediatamente o subagente e retorna um erro ao coordenador, que precisa decidir se retenta, pula ou falha a tarefa toda. Isso causa envolvimento excessivo do coordenador no tratamento rotineiro de erros. Qual melhoria arquitetural é mais efetiva?\n\n[ ] A - Criar um agente dedicado a tratamento de erros que monitore todas as falhas via fila compartilhada e decida ações de recuperação, enviando comandos de reinício diretamente aos subagentes.\n[ ] B - Configurar o subagente para sempre retornar resultados parciais com status de sucesso, embutindo detalhes do erro em metadados; o coordenador trata todas as respostas como bem-sucedidas.\n[ ] C - Fazer com que o coordenador valide todos os documentos antes de enviá-los ao subagente, rejeitando documentos que possam causar falhas.\n[ ] D - Implementar recuperação local no subagente para falhas transitórias e escalar ao coordenador apenas erros que ele não consegue resolver, incluindo passos tentados e resultados parciais.','\n',char(10)),'D - Implementar recuperação local no subagente para falhas transitórias e escalar ao coordenador apenas erros que ele não consegue resolver, incluindo passos tentados e resultados parciais.','["Domain_1::Agentic_Architecture_Orchestration", "Domain_5::Context_Management_Reliability", "Scenario_3::Multi_Agent_Research"]','New',0,2.5,0,1783092983970,1783724802484,1783203558653,replace('Sistema de Pesquisa Multiagente\n\nUm subagente de análise de documentos falha frequentemente ao processar arquivos PDF: alguns têm seções corrompidas que disparam exceções de parsing, outros são protegidos por senha e às vezes a biblioteca de parsing trava em arquivos grandes. Atualmente, qualquer exceção termina imediatamente o subagente e retorna um erro ao coordenador, que precisa decidir se retenta, pula ou falha a tarefa toda. Isso causa envolvimento excessivo do coordenador no tratamento rotineiro de erros. Qual melhoria arquitetural é mais efetiva?\n\n[ ] A - Criar um agente dedicado a tratamento de erros que monitore todas as falhas via fila compartilhada e decida ações de recuperação, enviando comandos de reinício diretamente aos subagentes.\n[ ] B - Configurar o subagente para sempre retornar resultados parciais com status de sucesso, embutindo detalhes do erro em metadados; o coordenador trata todas as respostas como bem-sucedidas.\n[ ] C - Fazer com que o coordenador valide todos os documentos antes de enviá-los ao subagente, rejeitando documentos que possam causar falhas.\n[ ] D - Implementar recuperação local no subagente para falhas transitórias e escalar ao coordenador apenas erros que ele não consegue resolver, incluindo passos tentados e resultados parciais.','\n',char(10)),replace('**Resposta correta: D**\n\nO princípio central de sistemas multiagente bem projetados é a **autonomia com escalonamento seletivo**. O subagente é quem tem contexto imediato sobre a falha (tipo de exceção, estado do parsing, resultado parcial já extraído). Portanto, ele deve ter responsabilidade sobre o tratamento de erros que consegue resolver localmente:\n\n- **Falhas transitórias** (biblioteca travando em arquivo grande, timeouts): retry com backoff, timeout local, fallback para outra estratégia de parsing.\n- **Falhas irrecuperáveis pelo agente** (PDF protegido por senha, seção corrompida sem alternativa): escalar ao coordenador **com contexto rico** — os passos que já tentou e quaisquer resultados parciais úteis.\n\nIsso reduz drasticamente o "chatter" com o coordenador (que só é acionado no que realmente importa) e ainda entrega valor parcial quando possível. É o mesmo padrão de **error handling em camadas / bulkhead**: cada componente absorve o que consegue e propaga apenas o que exige decisão de nível superior. O contexto anexado (passos tentados, resultados parciais) permite que o coordenador tome decisões informadas sem precisar reinvestigar.\n\n**Por que as outras estão erradas:**\n\n- **A** — Um agente central de tratamento de erros que envia comandos de reinício diretamente aos subagentes cria um **acoplamento e ponto único de falha** novos, além de violar hierarquia de coordenação (o coordenador deveria orquestrar, não um terceiro agente enviando comandos out-of-band). Também não resolve o problema raiz: falhas transitórias que o próprio subagente poderia tratar continuam gerando tráfego para outro componente. Adiciona complexidade sem reduzir o envolvimento no nível certo.\n\n- **B** — Mascarar todos os erros como "sucesso" é perigoso: o coordenador perde a capacidade de distinguir uma extração completa de uma falha total. Isso corrompe a semântica de resultado e leva a decisões erradas downstream (ex.: uma pesquisa baseada em documento que não foi lido). Esconder falhas ≠ tratar falhas.\n\n- **C** — Validação prévia pelo coordenador é impraticável e ineficiente: detectar de antemão que um PDF vai corromper o parser ou travar a biblioteca exige, na prática, tentar processá-lo (mesmo esforço do parsing real). Além disso, sobrecarrega o coordenador com trabalho que não é dele e não cobre falhas transitórias que só surgem em runtime.\n\nEm resumo, D distribui a responsabilidade corretamente, preserva a semântica dos resultados e minimiza a intervenção do coordenador — exatamente o objetivo declarado no problema.','\n',char(10)),replace('Imagine que você tem um ajudante que abre livros pra você. Às vezes um livro está rasgado, às vezes está trancado com cadeado, e às vezes o livro é tão pesado que o ajudante fica cansado por um instante.\n\nHoje, toda vez que qualquer coisa dá errado, o ajudante corre até o chefe e pergunta "o que eu faço?". O chefe fica ocupado demais respondendo perguntas bobas.\n\nA melhor ideia (D) é: o ajudante aprende a resolver sozinho os probleminhas fáceis — se ficou cansado, ele respira e tenta de novo. Só quando aparece algo que ele REALMENTE não consegue (como um livro trancado a cadeado) é que ele chama o chefe. E, quando chama, já leva um bilhetinho contando "olha, tentei isso e aquilo, e consegui ler pelo menos estas páginas". Assim o chefe decide rápido e fica livre pra cuidar das coisas importantes.\n\nAs outras ideias não funcionam bem:\n- (A) criar OUTRO chefe só pra cuidar de erros — vira mais gente mandando e mais confusão.\n- (B) o ajudante mentir que deu tudo certo mesmo quando falhou — isso engana o chefe e causa problemas depois.\n- (C) o chefe conferir todo livro antes — dá o mesmo trabalho de abrir o livro, então não adianta nada.','\n',char(10)));
INSERT INTO cards VALUES('admin','card_1783092983974_ywqhkc8xj',19,'Sistema de Pesquisa Multiagente',replace('Sistema de Pesquisa Multiagente\n\nApós executar o sistema sobre "impacto da IA nas indústrias criativas", você observa que cada subagente conclui com sucesso: o agente de busca web encontra artigos relevantes, o agente de análise de documentos os sumariza corretamente e o agente de síntese produz um texto coerente. No entanto, os relatórios finais cobrem somente artes visuais e perdem totalmente música, literatura e cinema. Nos logs do coordenador, você vê que ele decompôs o tema em três subtarefas: "IA em arte digital", "IA em design gráfico" e "IA em fotografia". Qual é a causa-raiz mais provável?\n\n[ ] A - Faltam ao agente de síntese instruções para detectar lacunas de cobertura.\n[ ] B - O agente de análise de documentos filtra fontes não-visuais por critérios de relevância excessivamente estritos.\n[ ] C - A decomposição de tarefas do coordenador é estreita demais, atribuindo aos subagentes trabalho que não cobre todas as áreas relevantes.\n[ ] D - As queries do agente de busca web são insuficientes e deveriam ser ampliadas para cobrir mais setores.','\n',char(10)),'C - A decomposição de tarefas do coordenador é estreita demais, atribuindo aos subagentes trabalho que não cobre todas as áreas relevantes.','["Domain_1::Agentic_Architecture_Orchestration", "Scenario_3::Multi_Agent_Research"]','New',0,2.5,0,1783092983974,1783724805730,1783203558653,replace('Sistema de Pesquisa Multiagente\n\nApós executar o sistema sobre "impacto da IA nas indústrias criativas", você observa que cada subagente conclui com sucesso: o agente de busca web encontra artigos relevantes, o agente de análise de documentos os sumariza corretamente e o agente de síntese produz um texto coerente. No entanto, os relatórios finais cobrem somente artes visuais e perdem totalmente música, literatura e cinema. Nos logs do coordenador, você vê que ele decompôs o tema em três subtarefas: "IA em arte digital", "IA em design gráfico" e "IA em fotografia". Qual é a causa-raiz mais provável?\n\n[ ] A - Faltam ao agente de síntese instruções para detectar lacunas de cobertura.\n[ ] B - O agente de análise de documentos filtra fontes não-visuais por critérios de relevância excessivamente estritos.\n[ ] C - A decomposição de tarefas do coordenador é estreita demais, atribuindo aos subagentes trabalho que não cobre todas as áreas relevantes.\n[ ] D - As queries do agente de busca web são insuficientes e deveriam ser ampliadas para cobrir mais setores.','\n',char(10)),replace('A chave para a análise de causa-raiz aqui é rastrear onde o "escopo" do problema foi definido pela primeira vez. O enunciado deixa explícito nos logs que o coordenador decompôs "indústrias criativas" em apenas três subtarefas — todas dentro do domínio visual: arte digital, design gráfico e fotografia. Ou seja, música, literatura e cinema nunca chegaram a virar subtarefa. O erro nasce na etapa de planejamento/decomposição, antes que qualquer outro agente execute.\n\nPor que C é a correta:\nEm arquiteturas multiagente do tipo orquestrador-trabalhador, o coordenador é responsável por traduzir a intenção do usuário em um conjunto de subtarefas que cubra todo o espaço do problema. Como cada subagente executou perfeitamente aquilo que recebeu (a busca achou artigos, a análise sumarizou, a síntese ficou coerente), o defeito não está na execução, e sim no escopo definido a montante. Se a decomposição só contempla o domínio visual, é logicamente impossível que os demais domínios apareçam no relatório final — nenhum agente downstream tem mandato para buscá-los. Esta é a causa-raiz porque corrigi-la (ampliar a decomposição para incluir música, literatura, cinema etc.) resolveria integralmente o problema.\n\nPor que as demais estão erradas:\n\nA - Detecção de lacunas pelo agente de síntese seria, no máximo, uma salvaguarda/mitigação, não a causa-raiz. Mesmo que a síntese percebesse a lacuna, ela não teria dados sobre música/literatura/cinema para preencher, porque esses temas nunca foram pesquisados. Trata-se de tratar sintoma, não origem.\n\nB - Um filtro de relevância estrito no agente de análise pressupõe que fontes não-visuais chegaram a ser recuperadas e foram descartadas. Mas o enunciado indica que o agente de análise "os sumariza corretamente" e não há evidência de descarte; além disso, a busca sequer procurou esses temas, pois as subtarefas eram todas visuais. Logo, não há o que filtrar.\n\nD - Ampliar as queries do agente de busca ataca o sintoma no lugar errado. O agente de busca executou corretamente as queries derivadas das subtarefas que recebeu. Se as subtarefas são apenas visuais, ampliar a busca dentro delas ainda não traria música ou cinema. O gargalo está um nível acima, na decomposição do coordenador.\n\nConclusão prática para um tech lead: em depuração de sistemas multiagente, siga o fluxo de responsabilidade "de cima para baixo". Quando cada componente cumpre bem sua tarefa mas o resultado global está incompleto, o suspeito principal é a etapa de planejamento/decomposição — o ponto onde o escopo é fixado.','\n',char(10)),replace('Imagine que você pediu a um chefe de equipe para fazer uma pesquisa sobre "todas as artes que os robôs conseguem ajudar a criar": desenho, música, filmes e livros.\n\nO chefe da equipe dividiu o trabalho em três pedaços, mas todos os pedaços eram só sobre desenhos e fotos! Ele esqueceu de pedir alguém para pesquisar música, livros e cinema.\n\nCada ajudante fez o seu pedacinho muito bem: um achou os textos, outro resumiu, outro escreveu bonito. Mas como ninguém foi mandado procurar música ou filmes, essas partes simplesmente não apareceram no fim.\n\nEntão o erro não foi dos ajudantes — foi do chefe que dividiu a tarefa de um jeito muito pequeno e esqueceu vários assuntos. Por isso a resposta certa é a C: a divisão feita pelo coordenador foi estreita demais.','\n',char(10)));
INSERT INTO cards VALUES('admin','card_1783092983980_0q87gmbjy',20,'Sistema de Pesquisa Multiagente',replace('Sistema de Pesquisa Multiagente\n\nO subagente de busca web retorna resultados para apenas 3 das 5 categorias de fontes solicitadas (sites de concorrentes e relatórios da indústria têm sucesso, mas arquivos de notícias e feeds sociais sofrem timeout). O subagente de análise de documentos processa com sucesso todos os documentos fornecidos. O subagente de síntese precisa produzir um sumário a partir de entradas a montante de qualidade mista. Qual estratégia de propagação de erro é mais efetiva?\n\n[ ] A - Continuar a síntese usando apenas as fontes bem-sucedidas e produzir uma saída sem mencionar quais dados estavam indisponíveis.\n[ ] B - O subagente de síntese retorna um erro ao coordenador, disparando retry total ou falha da tarefa por dados incompletos.\n[ ] C - O subagente de síntese pede ao coordenador para retentar fontes com timeout com prazo maior antes de iniciar a síntese.\n[ ] D - Estruturar a saída da síntese com anotações de cobertura indicando quais conclusões estão bem suportadas e onde existem lacunas devido a fontes indisponíveis.','\n',char(10)),'D - Estruturar a saída da síntese com anotações de cobertura indicando quais conclusões estão bem suportadas e onde existem lacunas devido a fontes indisponíveis.','["Domain_1::Agentic_Architecture_Orchestration", "Domain_4::Prompt_Engineering_Structured_Output", "Domain_5::Context_Management_Reliability", "Scenario_3::Multi_Agent_Research"]','New',0,2.5,0,1783092983980,1783724809511,1783203558653,replace('Sistema de Pesquisa Multiagente\n\nO subagente de busca web retorna resultados para apenas 3 das 5 categorias de fontes solicitadas (sites de concorrentes e relatórios da indústria têm sucesso, mas arquivos de notícias e feeds sociais sofrem timeout). O subagente de análise de documentos processa com sucesso todos os documentos fornecidos. O subagente de síntese precisa produzir um sumário a partir de entradas a montante de qualidade mista. Qual estratégia de propagação de erro é mais efetiva?\n\n[ ] A - Continuar a síntese usando apenas as fontes bem-sucedidas e produzir uma saída sem mencionar quais dados estavam indisponíveis.\n[ ] B - O subagente de síntese retorna um erro ao coordenador, disparando retry total ou falha da tarefa por dados incompletos.\n[ ] C - O subagente de síntese pede ao coordenador para retentar fontes com timeout com prazo maior antes de iniciar a síntese.\n[ ] D - Estruturar a saída da síntese com anotações de cobertura indicando quais conclusões estão bem suportadas e onde existem lacunas devido a fontes indisponíveis.','\n',char(10)),replace('Explicação para tech lead:\n\nO cenário é o clássico caso de "falha parcial" (partial failure) em arquiteturas distribuídas / multiagente. Temos dados úteis e suficientes (3 de 5 categorias + todos os documentos), mas cobertura incompleta. A pergunta é sobre *propagação de erro*: como sinalizar essa degradação sem descartar o valor já obtido.\n\n**Por que D é correta:** A melhor prática em sistemas de IA agentic é a "graceful degradation" com transparência. Ao anotar a cobertura — separando conclusões bem suportadas daquelas com lacunas — você:\n1. Preserva o trabalho já realizado (não desperdiça as fontes bem-sucedidas);\n2. Torna a incerteza explícita e auditável para o consumidor da saída (humano ou outro agente), que pode decidir se as lacunas são aceitáveis;\n3. Evita afirmações com confiança indevida sobre áreas sem dados;\n4. Mantém o pipeline avançando em vez de travar por perfeccionismo.\nIsso reflete o princípio de que erros/limitações devem ser propagados como *metadados estruturados*, não como falha binária nem como silêncio.\n\n**Por que A está errada:** Produzir a saída omitindo quais dados faltaram cria uma "confiança falsa". O leitor assume cobertura completa e pode tomar decisões erradas (ex.: ignorar sentimento social ou notícias recentes que estavam ausentes). Falta de transparência é o pior comportamento em sistemas de suporte à decisão.\n\n**Por que B está errada:** Retornar erro total e disparar retry completo ou falha da tarefa é uma reação desproporcional. Descarta 3 categorias + documentos válidos por causa de 2 timeouts, desperdiçando computação e possivelmente entrando em loops caros. Trata falha parcial como falha total — antipadrão de resiliência.\n\n**Por que C é inferior (não a melhor):** Retentar as fontes com timeout tem mérito e pode ser válido em alguns fluxos, mas: (a) timeouts costumam ser sistêmicos (fonte indisponível, rate limit), então mais tempo nem sempre resolve; (b) bloqueia a síntese indefinidamente, aumentando latência; (c) não resolve o problema de fundo — mesmo após retry pode faltar dado, e aí ainda seria preciso a estratégia de D. Retentar é uma tática pontual; anotar cobertura é a estratégia robusta que funciona independentemente do resultado do retry.\n\nEm resumo: D combina aproveitamento máximo dos dados, transparência sobre limitações e continuidade do fluxo — os três pilares de uma boa propagação de erro em sistemas multiagente.','\n',char(10)),replace('Imagine que você pediu para 5 amigos trazerem informações para montar um trabalho da escola. Só 3 conseguiram trazer as coisas; os outros 2 se atrasaram e não chegaram a tempo.\n\nO que você faz? Você ainda tem bastante coisa boa dos 3 amigos! O jeito mais esperto é montar o trabalho com o que você tem E colocar um bilhetinho dizendo: "Esta parte está bem completa, mas aqui faltou informação porque dois amigos não trouxeram." Assim quem ler sabe exatamente o que está firme e o que ainda está faltando. Essa é a resposta D.\n\nAs outras ideias não são tão boas:\n- A é como entregar o trabalho fingindo que está tudo completo, escondendo que faltou coisa. Isso engana quem lê!\n- B é como jogar TUDO fora e começar do zero só porque 2 amigos atrasaram — muito desperdício!\n- C é ficar esperando os 2 amigos atrasados, mesmo sem saber se eles vão chegar, e deixar o trabalho parado esperando.\n\nPor isso o melhor é a D: usar o que temos e ser honesto sobre o que faltou!','\n',char(10)));
INSERT INTO cards VALUES('admin','card_1783092984005_al75ctaqt',21,'Sistema de Pesquisa Multiagente',replace('Sistema de Pesquisa Multiagente\n\nO subagente de análise de documentos encontra um arquivo PDF corrompido que ele não consegue parsear. Ao desenhar o tratamento de erros do sistema, qual é a forma mais efetiva de lidar com essa falha?\n\n[ ] A - Retornar um erro com contexto ao agente coordenador, permitindo que ele decida como prosseguir.\n[ ] B - Pular silenciosamente o documento corrompido e continuar processando os demais arquivos para evitar interromper o workflow.\n[ ] C - Retentar automaticamente o parsing três vezes com backoff exponencial antes de reportar uma falha.\n[ ] D - Lançar uma exceção que termina o workflow inteiro de pesquisa.','\n',char(10)),'A - Retornar um erro com contexto ao agente coordenador, permitindo que ele decida como prosseguir.','["Tags:", "Domain_1::Agentic_Architecture_Orchestration", "Domain_5::Context_Management_Reliability", "Scenario_3::Multi_Agent_Research"]','New',0,2.5,0,1783092984005,1783725051128,1783203558653,replace('**Tradução**\n\nSistema de Pesquisa Multiagente\n\nO subagente de análise de documentos encontra um arquivo PDF corrompido que ele não consegue parsear. Ao desenhar o tratamento de erros do sistema, qual é a forma mais efetiva de lidar com essa falha?\n\n[ ] A - Retornar um erro com contexto ao agente coordenador, permitindo que ele decida como prosseguir.\n[ ] B - Pular silenciosamente o documento corrompido e continuar processando os demais arquivos para evitar interromper o workflow.\n[ ] C - Retentar automaticamente o parsing três vezes com backoff exponencial antes de reportar uma falha.\n[ ] D - Lançar uma exceção que termina o workflow inteiro de pesquisa.','\n',char(10)),replace('**Explicação (para tech lead)**\n\nA resposta correta é a **A**.\n\nEm arquiteturas multiagente, o princípio central de tratamento de erros é a **propagação contextualizada da falha para quem tem visão do todo**. O subagente é especializado e não possui contexto suficiente para decidir o impacto real de um documento corrompido no objetivo global da pesquisa. O agente coordenador (orquestrador), por outro lado, conhece o objetivo da tarefa, a importância relativa daquele documento e as estratégias alternativas disponíveis (buscar outra fonte, solicitar reenvio, prosseguir com dados parciais, degradar graciosamente, etc.). Retornar um erro *com contexto* (o que falhou, por quê, qual documento) preserva a observabilidade e mantém a decisão no nível arquitetural adequado.\n\nPor que as outras estão erradas:\n\n- **B (pular silenciosamente):** viola o princípio de transparência/observabilidade. Suprimir a falha sem registro pode comprometer a integridade do resultado da pesquisa sem que ninguém saiba que um documento relevante foi omitido. Isso gera resultados enganosamente "completos". Poderia ser aceitável apenas *como decisão explícita do coordenador*, não como comportamento silencioso do subagente.\n\n- **C (retry com backoff exponencial):** retry é uma estratégia adequada para falhas **transitórias** (timeouts de rede, indisponibilidade temporária, rate limiting). Um PDF **corrompido** é uma falha **determinística/permanente** — retentar não vai mudar o resultado, apenas desperdiça tempo e recursos. Aplicar retry aqui demonstra escolha errada de padrão para o tipo de erro.\n\n- **D (exceção que encerra todo o workflow):** é a abordagem mais frágil. Um único documento problemático não deve derrubar toda a pesquisa. Isso viola o princípio de **isolamento de falhas** (fault isolation / bulkhead), tornando o sistema pouco resiliente.\n\nEm resumo: falha permanente + arquitetura multiagente → **falhar de forma controlada e delegar a decisão ao orquestrador que tem o contexto global**.','\n',char(10)),replace('Imagine um grupo de robôs trabalhando juntos para fazer uma pesquisa. Um deles é o "chefe" (coordenador) e os outros são ajudantes. Um ajudante recebeu a tarefa de ler um livro, mas o livro estava todo rasgado e ele não conseguiu ler.\n\nO que ele deve fazer? A coisa mais esperta é ir até o chefe e dizer: "Ei, esse livro está rasgado, não consegui ler. O que você quer que eu faça?" Assim o chefe, que sabe se aquele livro é importante ou não, decide o próximo passo. Essa é a resposta **A**.\n\nAs outras ideias não são boas:\n- **B** seria o ajudante jogar o livro fora escondido e não contar para ninguém — aí a pesquisa fica incompleta e ninguém sabe.\n- **C** seria tentar ler o mesmo livro rasgado várias vezes — mas se ele está rasgado, vai continuar rasgado! É só perder tempo.\n- **D** seria o ajudante ficar bravo e parar TODO o trabalho do grupo por causa de um livro só — isso estraga tudo à toa.\n\nPor isso, o certo é avisar o chefe com detalhes e deixar ele decidir. 😊','\n',char(10)));
INSERT INTO cards VALUES('admin','card_1783092984009_4ktc4pium',22,'Sistema de Pesquisa Multiagente',replace('Sistema de Pesquisa Multiagente\n\nUm colega propõe que o agente de análise de documentos envie seus resultados diretamente ao agente de síntese, contornando o coordenador. Qual é a vantagem principal de manter o coordenador como hub central para toda comunicação entre subagentes?\n\n[ ] A - O coordenador pode observar todas as interações, tratar erros de forma uniforme e decidir que informação cada subagente deve receber.\n[ ] B - O coordenador agrupa múltiplas requisições aos subagentes, reduzindo o total de chamadas de API e a latência geral.\n[ ] C - Roteamento pelo coordenador habilita lógica de retry automática que chamadas inter-agente diretas não suportam.\n[ ] D - Subagentes usam memória isolada e a comunicação direta exigiria serialização complexa que só o coordenador consegue realizar.','\n',char(10)),'A - O coordenador pode observar todas as interações, tratar erros de forma uniforme e decidir que informação cada subagente deve receber.','["Tags:", "Domain_1::Agentic_Architecture_Orchestration", "Scenario_3::Multi_Agent_Research"]','New',0,2.5,0,1783092984009,1783725054449,1783203558653,replace('Sistema de Pesquisa Multiagente\n\nUm colega propõe que o agente de análise de documentos envie seus resultados diretamente ao agente de síntese, contornando o coordenador. Qual é a vantagem principal de manter o coordenador como hub central para toda comunicação entre subagentes?\n\nA - O coordenador pode observar todas as interações, tratar erros de forma uniforme e decidir que informação cada subagente deve receber.\nB - O coordenador agrupa múltiplas requisições aos subagentes, reduzindo o total de chamadas de API e a latência geral.\nC - O roteamento pelo coordenador habilita lógica de retry automática que chamadas inter-agente diretas não suportam.\nD - Subagentes usam memória isolada e a comunicação direta exigiria serialização complexa que só o coordenador consegue realizar.','\n',char(10)),replace('**Resposta correta: A**\n\nEm arquiteturas multiagente, o padrão de "hub central" (também chamado de orquestrador/coordenador ou padrão *orchestrator-worker*) traz três benefícios estruturais fundamentais que a alternativa A resume perfeitamente:\n\n1. **Observabilidade (observability):** com toda a comunicação passando pelo coordenador, você tem um único ponto de logging, tracing e monitoramento. Isso é essencial para debugar, auditar e entender o fluxo de raciocínio do sistema. Comunicação ponto-a-ponto direta cria uma topologia em malha (mesh) que fragmenta a visibilidade.\n\n2. **Tratamento uniforme de erros:** o coordenador centraliza políticas de tratamento de falhas, timeouts e recuperação, garantindo consistência em todo o sistema.\n\n3. **Controle de contexto / information gating:** talvez o ponto mais importante em sistemas com LLMs — o coordenador decide *quais* informações cada subagente recebe. Isso evita poluição de contexto, reduz custo de tokens e mantém cada agente focado apenas no que é relevante para sua tarefa. Comunicação direta faria o agente de análise "empurrar" todo seu output para o de síntese, sem curadoria.\n\n**Por que as outras estão erradas:**\n\n- **B (Batching de requisições):** o agrupamento de chamadas para reduzir latência é uma otimização de performance, mas *não é a razão principal* para centralizar a comunicação. Além disso, um hub central geralmente *não* reduz latência — ao contrário, adiciona um salto (hop) extra. A pergunta trata de arquitetura/governança, não de throughput.\n\n- **C (Retry automático):** essa afirmação contém uma premissa falsa. Não há nada técnico que impeça chamadas inter-agente diretas de implementarem retry — retry pode ser implementado em qualquer ponto (no cliente, num proxy, etc.). O coordenador facilita centralizar essa lógica, mas dizer que chamadas diretas "não suportam" retry é incorreto.\n\n- **D (Serialização complexa):** também parte de uma premissa técnica inventada. Memória isolada entre agentes não impede comunicação direta, e serialização de mensagens (JSON, etc.) é trivial e não é exclusiva do coordenador. Qualquer agente pode serializar/desserializar dados.\n\nEm resumo, a vantagem central é de **governança, visibilidade e controle de fluxo de informação** — exatamente o que A descreve.','\n',char(10)),replace('Imagine que você tem um grupo de amigos fazendo um trabalho da escola. Cada amigo cuida de uma parte: um lê os livros, outro escreve o resumo.\n\nAgora, existe um "chefe da equipe" (o coordenador) que fica no meio de todos. Toda mensagem passa por ele.\n\nSeu colega disse: "Por que o amigo que lê os livros não fala direto com o amigo que escreve o resumo, sem passar pelo chefe?"\n\nA resposta é: porque o chefe é muito útil! Ele consegue:\n- **Ver tudo** que está acontecendo (assim, se algo der errado, ele descobre fácil);\n- **Consertar os problemas** sempre do mesmo jeito, sem confusão;\n- **Escolher o que cada amigo precisa saber**, para ninguém receber um monte de informação inútil e ficar perdido.\n\nSe todos falassem direto uns com os outros, viraria uma bagunça e o chefe não conseguiria enxergar nada!\n\nAs outras respostas parecem espertas, mas estão erradas:\n- Uma fala que o chefe deixa tudo mais rápido — mas na verdade passar por ele até demora um pouquinho mais.\n- Outra diz que só o chefe consegue "tentar de novo" quando falha — mentira, qualquer um pode tentar de novo.\n- E a última diz que só o chefe consegue "empacotar" as mensagens — também não é verdade, qualquer amigo consegue.\n\nPor isso, a resposta certa é a **letra A**! 😊','\n',char(10)));
INSERT INTO cards VALUES('admin','card_1783092984014_w874vri3k',23,'Sistema de Pesquisa Multiagente',replace('Sistema de Pesquisa Multiagente\n\nO subagente de busca web sofre timeout ao pesquisar um tema complexo. Você precisa desenhar como a informação sobre essa falha é retornada ao coordenador. Qual abordagem de propagação de erro melhor habilita recuperação inteligente?\n\n[ ] A - Retornar contexto estruturado de erro ao coordenador, incluindo o tipo de falha, a query executada, quaisquer resultados parciais e abordagens alternativas potenciais.\n[ ] B - Capturar o timeout dentro do subagente e retornar um conjunto de resultados vazio marcado como bem-sucedido.\n[ ] C - Implementar retentativas automáticas com backoff exponencial dentro do subagente, retornando apenas um status genérico "busca indisponível" depois de esgotar as tentativas.\n[ ] D - Propagar a exceção de timeout diretamente ao handler de topo, terminando o workflow de pesquisa inteiro.','\n',char(10)),'A - Retornar contexto estruturado de erro ao coordenador, incluindo o tipo de falha, a query executada, quaisquer resultados parciais e abordagens alternativas potenciais.','["Tags:", "Domain_1::Agentic_Architecture_Orchestration", "Domain_4::Prompt_Engineering_Structured_Output", "Scenario_3::Multi_Agent_Research"]','New',0,2.5,0,1783092984015,1783725057530,1783203558653,replace('Sistema de Pesquisa Multiagente\n\nO subagente de busca web sofre timeout ao pesquisar um tema complexo. Você precisa desenhar como a informação sobre essa falha é retornada ao coordenador. Qual abordagem de propagação de erro melhor habilita recuperação inteligente?\n\n[ ] A - Retornar contexto estruturado de erro ao coordenador, incluindo o tipo de falha, a query executada, quaisquer resultados parciais e abordagens alternativas potenciais.\n[ ] B - Capturar o timeout dentro do subagente e retornar um conjunto de resultados vazio marcado como bem-sucedido.\n[ ] C - Implementar retentativas automáticas com backoff exponencial dentro do subagente, retornando apenas um status genérico "busca indisponível" depois de esgotar as tentativas.\n[ ] D - Propagar a exceção de timeout diretamente ao handler de topo, terminando o workflow de pesquisa inteiro.','\n',char(10)),replace('**Resposta correta: A**\n\nEm arquiteturas multiagente com um coordenador (orquestrador) e subagentes (workers), a "recuperação inteligente" depende de que o coordenador tenha informação suficiente para tomar uma decisão. A chave da questão é a expressão *"enable intelligent recovery"* — ou seja, o design deve maximizar o contexto disponível para quem decide.\n\n**Por que A é a melhor:**\n- Fornece um **erro estruturado e semântico** (não apenas um flag booleano ou uma exceção nua).\n- Inclui o **tipo de falha** (timeout vs. rate-limit vs. erro de rede), permitindo estratégias diferentes.\n- Inclui a **query executada**, dando ao coordenador a chance de reformular, dividir ou simplificar.\n- Inclui **resultados parciais**, que não devem ser desperdiçados — em pesquisa, informação incompleta ainda tem valor.\n- Sugere **abordagens alternativas**, transformando a falha em input acionável para o próximo passo (ex.: quebrar em subqueries, usar outra fonte).\n\nIsso mantém a decisão de recuperação no nível certo: o coordenador, que tem visão global do plano de pesquisa.\n\n**Por que as demais estão erradas:**\n\n- **B — mascarar como sucesso:** É um antipadrão grave ("swallowing errors"). Marcar como bem-sucedido um resultado vazio faz o coordenador acreditar que o tema foi coberto, corrompendo a síntese final com falsos negativos silenciosos. Impede qualquer recuperação porque esconde que houve falha.\n\n- **C — retry com backoff + status genérico:** O retry com backoff é uma boa prática de resiliência transitória, mas o problema aqui é o **status genérico "busca indisponível"**. Ele descarta o contexto (query, resultados parciais, tipo de falha), impedindo a recuperação inteligente. Além disso, o retry cego do subagente pode ser inútil para um timeout causado por complexidade da query — o que precisa mudar é a *estratégia*, não repetir a mesma query. A decisão de re-tentar/reformular deveria idealmente subir ao coordenador.\n\n- **D — propagar exceção ao topo e encerrar tudo:** É frágil e destrutivo. Um único subagente falhando não deve derrubar todo o workflow — viola o princípio de isolamento de falhas (fault isolation / graceful degradation). Elimina completamente a possibilidade de recuperação e perde o trabalho já realizado por outros agentes.\n\n**Princípio de tech lead:** trate erros como *dados de primeira classe*. Em sistemas distribuídos/agentes, propague contexto rico e estruturado para o nível que tem autoridade e visão para decidir — em vez de esconder, engolir ou explodir a falha.','\n',char(10)),replace('Imagine que você tem um chefe de equipe (o coordenador) e vários ajudantes (os subagentes). Um dos ajudantes foi buscar uma informação difícil na internet, mas demorou tanto que desistiu (isso é o "timeout").\n\nAgora, como esse ajudante deve avisar o chefe do que aconteceu?\n\nA resposta certa é a **A**: o ajudante volta e conta tudo direitinho: "Não consegui terminar porque demorei demais, eu estava procurando ISSO, achei UM PEDACINHO só, e talvez você possa tentar de outro jeito." Assim o chefe entende o problema e decide o que fazer — pedir de novo, dividir a tarefa ou tentar outro caminho. Isso é ser esperto!\n\nAs outras estão erradas:\n- **B**: o ajudante mente e diz "achei tudo!" mesmo sem achar nada. Aí o chefe acha que está tudo certo e faz um trabalho errado sem saber. 🚫\n- **C**: o ajudante tenta várias vezes sozinho e no fim só diz "não deu", sem contar nenhum detalhe. O chefe fica sem saber o que houve e não pode ajudar. 🚫\n- **D**: o ajudante fica tão bravo que faz todo mundo parar de trabalhar por causa do problema dele. Isso estraga o trabalho de todos! 🚫\n\nPor isso a melhor é contar tudo com detalhes para o chefe (A).','\n',char(10)));
INSERT INTO cards VALUES('admin','card_1783092984020_crz5dqupv',24,'Sistema de Pesquisa Multiagente',replace('Sistema de Pesquisa Multiagente\n\nAo pesquisar um tema amplo, você observa que o agente de busca web e o agente de análise de documentos investigam os mesmos subtemas, levando a duplicação substancial em suas saídas. O uso de tokens quase dobra sem aumento proporcional na amplitude ou profundidade da pesquisa. Qual é a forma mais efetiva de tratar isso?\n\n[ ] A - Permitir que ambos os agentes terminem em paralelo e fazer com que o coordenador desduplique resultados sobrepostos antes de passá-los ao agente de síntese.\n[ ] B - O coordenador particiona explicitamente o espaço de pesquisa antes de delegar, atribuindo a cada agente subtemas distintos ou tipos de fonte distintos.\n[ ] C - Implementar um mecanismo de estado compartilhado em que agentes registrem sua área de foco atual para que outros agentes evitem duplicação dinamicamente durante a execução.\n[ ] D - Mudar para execução sequencial em que a análise de documentos rode somente após a busca web concluir, usando os resultados da busca web como contexto para evitar duplicação.','\n',char(10)),'B - O coordenador particiona explicitamente o espaço de pesquisa antes de delegar, atribuindo a cada agente subtemas distintos ou tipos de fonte distintos.','["Tags:", "Domain_1::Agentic_Architecture_Orchestration", "Scenario_3::Multi_Agent_Research"]','New',0,2.5,0,1783092984020,1783725060924,1783203558653,replace('Sistema de Pesquisa Multiagente\n\nAo pesquisar um tema amplo, você observa que o agente de busca web e o agente de análise de documentos investigam os mesmos subtemas, levando a duplicação substancial em suas saídas. O uso de tokens quase dobra sem aumento proporcional na amplitude ou profundidade da pesquisa. Qual é a forma mais efetiva de tratar isso?\n\nA - Permitir que ambos os agentes terminem em paralelo e fazer com que o coordenador desduplique resultados sobrepostos antes de passá-los ao agente de síntese.\nB - O coordenador particiona explicitamente o espaço de pesquisa antes de delegar, atribuindo a cada agente subtemas distintos ou tipos de fonte distintos.\nC - Implementar um mecanismo de estado compartilhado em que agentes registrem sua área de foco atual para que outros agentes evitem duplicação dinamicamente durante a execução.\nD - Mudar para execução sequencial em que a análise de documentos rode somente após a busca web concluir, usando os resultados da busca web como contexto para evitar duplicação.','\n',char(10)),replace('**Resposta correta: B**\n\nO problema central é o desperdício de tokens causado por trabalho redundante: dois agentes gastam recursos investigando os mesmos subtemas. Em arquiteturas orquestrador-trabalhador (padrão consagrado, por exemplo, no sistema de pesquisa multiagente da Anthropic), a boa prática é o coordenador/lead agent decompor a tarefa e delegar objetivos claros, distintos e não sobrepostos a cada subagente **antes** da execução. Isso ataca a causa raiz — a sobreposição — em vez de tratar o sintoma depois. Ao dividir o espaço de busca por subtema ou por tipo de fonte (web vs. documentos), cada agente contribui com valor único, eliminando a duplicação sem gastar tokens em trabalho jogado fora.\n\n**Por que as demais estão erradas:**\n\n- **A (desduplicação pós-hoc):** trata o sintoma, não a causa. O trabalho duplicado já foi realizado e os tokens já foram consumidos (é exatamente o custo que dobrou). Remover duplicatas depois não recupera o desperdício; apenas limpa a saída. Ineficiente do ponto de vista de custo.\n\n- **C (estado compartilhado com coordenação dinâmica):** parece elegante, mas introduz complexidade significativa — sincronização, condições de corrida, latência de coordenação e sobrecarga de comunicação entre agentes. Coordenação dinâmica em tempo de execução é notoriamente frágil em sistemas multiagente baseados em LLM e raramente compensa quando um particionamento estático simples resolve. Over-engineering.\n\n- **D (execução sequencial):** sacrifica o paralelismo (aumentando a latência total) e ainda alimenta o segundo agente com o contexto do primeiro, o que pode enviesá-lo para os mesmos temas em vez de garantir cobertura complementar. Além disso, o ganho de amplitude/profundidade da pesquisa paralela é perdido — justamente o oposto do objetivo.\n\nEm resumo: a decomposição clara e a delegação com escopos disjuntos no momento do planejamento é a estratégia mais eficiente, preservando paralelismo e economizando tokens.','\n',char(10)),replace('Imagine que dois amigos precisam pesquisar sobre "animais" para um trabalho da escola. Se ninguém combinar nada antes, os dois vão acabar pesquisando "leões" e "elefantes" ao mesmo tempo — trabalho repetido e tempo desperdiçado!\n\nA melhor solução (resposta B) é o "chefe do grupo" dividir as tarefas ANTES de começar: "Você pesquisa os animais da savana, e você pesquisa os animais do mar." Assim, cada um faz uma parte diferente e ninguém repete o trabalho do outro.\n\nAs outras ideias não são tão boas:\n- A: deixar os dois pesquisarem tudo e depois apagar o que ficou repetido — mas o tempo gasto pesquisando o repetido já foi perdido!\n- C: cada um ir avisando o tempo todo o que está fazendo — isso vira uma bagunça de mensagens e é difícil de organizar.\n- D: fazer um esperar o outro terminar — assim demora muito mais, e ainda pode acabar copiando as mesmas ideias.\n\nPor isso, combinar quem faz o quê antes de começar é o jeito mais esperto! 🎯','\n',char(10)));
INSERT INTO cards VALUES('admin','card_1783092984025_qybeonmmo',25,'Sistema de Pesquisa Multiagente',replace('Sistema de Pesquisa Multiagente\n\nDurante a pesquisa, o subagente de busca web consulta três categorias de fontes com resultados diferentes: bases acadêmicas retornam 15 papers relevantes, relatórios da indústria retornam "0 resultados" e bases de patentes retornam "Connection timeout". Ao desenhar a propagação de erro para o coordenador, qual abordagem habilita as melhores decisões de recuperação?\n\n[ ] A - Agregar resultados em uma única métrica de percentual de sucesso (ex.: "67% de cobertura de fontes") com logs detalhados disponíveis sob demanda.\n[ ] B - Reportar tanto "timeout" quanto "0 resultados" como falhas que requerem intervenção do coordenador.\n[ ] C - Retentar falhas transitórias internamente e reportar apenas erros persistentes.\n[ ] D - Distinguir falhas de acesso (timeout) que exigem decisão de retry de resultados vazios válidos ("0 resultados") que representam queries bem-sucedidas.','\n',char(10)),'D - Distinguir falhas de acesso (timeout) que exigem decisão de retry de resultados vazios válidos ("0 resultados") que representam queries bem-sucedidas.','["Domain_1::Agentic_Architecture_Orchestration", "Domain_5::Context_Management_Reliability", "Scenario_3::Multi_Agent_Research"]','New',0,2.5,0,1783092984025,1783725129693,1783203558653,replace('Multi-Agent Research System\n\nDuring research, the web search subagent queries three categories of sources with different outcomes: academic databases return 15 relevant papers, industry reports return "0 results", and patent databases return "Connection timeout". When designing error propagation to the coordinator, which approach enables the best recovery decisions?\n\n[ ] A - Aggregate results into a single success percentage metric (e.g., "67% source coverage") with detailed logs available on demand.\n[ ] B - Report both "timeout" and "0 results" as failures that require coordinator intervention.\n[ ] C - Retry transient failures internally and report only persistent errors.\n[ ] D - Distinguish access failures (timeout) that require a retry decision from valid empty results ("0 results") that represent successful queries.','\n',char(10)),replace('Resposta correta: **D**\n\nEm sistemas multiagente, a qualidade das decisões de recuperação do coordenador depende diretamente da riqueza semântica das informações que os subagentes propagam. Existe uma diferença fundamental entre dois tipos de "não-resultado":\n\n- **"Connection timeout"** é uma *falha de acesso* (falha transitória de infraestrutura). A query nunca foi realmente respondida. Isso é um forte candidato a retry, backoff ou fallback para outra fonte.\n- **"0 resultados"** é uma *resposta bem-sucedida*: a fonte foi consultada corretamente e a resposta legítima é que não há nada relevante ali. Fazer retry disso seria desperdício de recursos e latência, pois o resultado seria sempre o mesmo.\n\nA abordagem D preserva essa distinção semântica, permitindo que o coordenador aplique a estratégia correta para cada caso: retry/fallback para o timeout e aceitação do vazio como informação válida (inclusive útil para ajustar a estratégia de busca — talvez reformular a query ou concluir que aquela categoria de fonte não cobre o tema).\n\nPor que as demais estão erradas:\n\n- **A (agregar em uma métrica única)**: colapsar tudo em "67% de cobertura" *destrói a informação semântica* necessária para decidir. O coordenador não consegue saber, apenas pelo percentual, se deve fazer retry ou seguir em frente. Colocar os detalhes "sob demanda" transfere o problema, mas na prática o coordenador precisa dessa granularidade *no momento da decisão*, não depois.\n- **B (tratar ambos como falha)**: trata "0 resultados" incorretamente como falha. Isso gera retries inúteis, ruído para o coordenador e possivelmente decisões erradas (ex.: abortar uma pesquisa que na verdade foi bem-sucedida naquela fonte).\n- **C (retry interno e reportar só erros persistentes)**: retry interno de falhas transitórias é uma boa prática *isolada*, mas esconder do coordenador o contexto do que aconteceu remove a capacidade dele de tomar decisões de orquestração de nível superior (ex.: escolher outra fonte, ajustar prioridades, informar o usuário). Além disso, a alternativa não distingue o "0 resultados" válido — ela foca só em falhas, deixando a distinção central sem tratamento explícito.\n\nEm resumo: o princípio de design é *propagar erros com semântica preservada*, separando falhas técnicas (que pedem retry) de resultados válidos porém vazios (que são sucesso), pois é essa distinção que habilita as melhores decisões de recuperação.','\n',char(10)),replace('Imagine que você mandou três amigos procurarem figurinhas em três lugares diferentes.\n\n- O primeiro amigo achou 15 figurinhas. 🎉\n- O segundo amigo procurou direitinho na loja, mas a loja estava sem nenhuma figurinha. Ele fez o trabalho certo — só não tinha nada lá.\n- O terceiro amigo nem conseguiu entrar na loja porque a porta estava travada. Ele não terminou a tarefa!\n\nAgora, quando eles voltam para te contar, é importante que eles falem *exatamente o que aconteceu*. Porque:\n\n- Com o amigo da porta travada, faz sentido tentar de novo mais tarde (talvez a porta abra).\n- Com o amigo que viu a loja vazia, não adianta mandar de novo — a resposta vai ser a mesma.\n\nSe todos só dissessem "não consegui figurinhas", você não saberia quem tentar de novo e quem já terminou o trabalho. Por isso a melhor escolha é a **D**: separar "não consegui entrar" (tenta de novo) de "entrei e estava vazio" (já terminou, tudo certo).','\n',char(10)));
INSERT INTO cards VALUES('admin','card_1783092984030_vco9bhvlg',26,'Agente de Suporte ao Cliente',replace('Agente de Suporte ao Cliente\n\nSeu agente lida com pedidos de questão única com 94% de acurácia (ex.: "preciso de reembolso para o pedido #1234"). Mas quando clientes incluem múltiplas questões em uma mensagem (ex.: "preciso de reembolso para o pedido #1234 e também atualizar o endereço de entrega do pedido #5678"), a acurácia de seleção de ferramenta cai para 58%. O agente normalmente resolve apenas uma questão ou mistura parâmetros entre os pedidos. Qual abordagem melhora confiabilidade para pedidos multi-questão de forma mais efetiva?\n\n[ ] A - Implementar uma camada de pré-processamento que use uma chamada separada do modelo para decompor mensagens multi-questão em pedidos separados, lidar com cada um independentemente e mesclar resultados.\n[ ] B - Combinar ferramentas relacionadas em menos ferramentas universais.\n[ ] C - Adicionar exemplos few-shot ao prompt demonstrando raciocínio correto e sequenciamento de ferramentas para pedidos multi-questão.\n[ ] D - Implementar validação de resposta que detecta respostas incompletas e re-prompta automaticamente o agente para resolver questões perdidas.','\n',char(10)),'A - Implementar uma camada de pré-processamento que use uma chamada separada do modelo para decompor mensagens multi-questão em pedidos separados, lidar com cada um independentemente e mesclar resultados.','["Domain_1::Agentic_Architecture_Orchestration", "Domain_4::Prompt_Engineering_Structured_Output", "Domain_5::Context_Management_Reliability", "Scenario_1::Customer_Support_Agent"]','New',0,2.5,0,1783092984030,1783725133604,1783203558653,replace('Agente de Suporte ao Cliente\n\nSeu agente lida com pedidos de questão única com 94% de acurácia (ex.: "preciso de reembolso para o pedido #1234"). Mas quando clientes incluem múltiplas questões em uma mensagem (ex.: "preciso de reembolso para o pedido #1234 e também atualizar o endereço de entrega do pedido #5678"), a acurácia de seleção de ferramenta cai para 58%. O agente normalmente resolve apenas uma questão ou mistura parâmetros entre os pedidos. Qual abordagem melhora confiabilidade para pedidos multi-questão de forma mais efetiva?\n\nA - Implementar uma camada de pré-processamento que use uma chamada separada do modelo para decompor mensagens multi-questão em pedidos separados, lidar com cada um independentemente e mesclar resultados.\nB - Combinar ferramentas relacionadas em menos ferramentas universais.\nC - Adicionar exemplos few-shot ao prompt demonstrando raciocínio correto e sequenciamento de ferramentas para pedidos multi-questão.\nD - Implementar validação de resposta que detecta respostas incompletas e re-prompta automaticamente o agente para resolver questões perdidas.','\n',char(10)),replace('**Diagnóstico do problema**\n\nOs dados dizem duas coisas cruciais:\n1. O agente já é excelente (94%) em pedidos de questão única — a lógica base funciona.\n2. A queda para 58% ocorre **exatamente** quando há múltiplas questões numa só mensagem, e os sintomas são "resolve só uma" e "mistura parâmetros entre pedidos".\n\nA causa raiz é **sobrecarga cognitiva/contextual**: o modelo tenta manter múltiplas intenções, múltiplos IDs de pedido e múltiplos conjuntos de parâmetros simultaneamente num único passo de raciocínio, e acaba cruzando dados (o endereço do #5678 aplicado ao #1234, etc.).\n\n**Por que a A é a melhor**\n\nA alternativa A ataca a causa raiz diretamente: decompõe o pedido complexo em N pedidos de questão única e **reaproveita o caminho que já tem 94% de acurácia**. Cada subtarefa é processada isoladamente, eliminando a mistura de parâmetros (cada chamada só "enxerga" um pedido e uma intenção). Depois os resultados são mesclados. É o clássico padrão *decompose-and-solve* / roteador, que transforma o problema difícil (multi-intenção) em vários problemas fáceis já resolvidos. Ganho esperado de confiabilidade tende a se aproximar dos 94% por subtarefa.\n\n**Por que as demais são inferiores**\n\n- **B (ferramentas universais):** o problema não é a granularidade das ferramentas, e sim a separação e roteamento das intenções e parâmetros. Consolidar ferramentas não impede o modelo de misturar o endereço de um pedido com outro; pode até piorar, deixando ferramentas mais ambíguas e sobrecarregando um único tool call com parâmetros de múltiplos pedidos.\n\n- **C (few-shot):** ajuda de forma incremental e é barato de tentar, mas não muda a arquitetura. O modelo continua tendo que sustentar todo o raciocínio multi-intenção em um único passo. Few-shot melhora a média, mas é frágil quando o número/variedade de questões cresce além dos exemplos mostrados — não garante o isolamento de parâmetros que é o núcleo do bug.\n\n- **D (validação + re-prompt):** é uma rede de segurança *reativa*, não uma correção da causa. Ela pode pegar o caso "resolveu só uma questão" (resposta incompleta), mas dificilmente detecta o caso "misturou parâmetros" — a resposta parece completa, só que com dados trocados. Além disso adiciona latência e loops de re-prompt sem garantir isolamento. Boa como complemento, insuficiente como solução principal.\n\n**Conclusão:** A decomposição (A) é a abordagem mais efetiva porque isola cada questão, reutiliza o pipeline comprovadamente confiável de questão única e elimina estruturalmente a mistura de parâmetros. C e D são bons complementos, mas não corrigem a causa raiz.','\n',char(10)),replace('Imagine um garçom que anota pedidos muito bem quando você pede só uma coisa: "quero um suco". Ele acerta quase sempre! Mas quando você fala tudo junto e rápido — "quero um suco de laranja pra mim e uma água pro pedido da mesa 5" — ele se atrapalha: às vezes traz só o suco, ou troca as coisas e leva a água pra pessoa errada.\n\nA melhor solução é ensinar o garçom a **separar** o pedido antes de fazer qualquer coisa: pegar um papelzinho e escrever cada pedido em uma linha separada. Aí ele resolve um de cada vez (o suco primeiro, depois a água) e no final junta tudo. Como ele já é ótimo em resolver um pedido de cada vez, separando ele quase nunca erra!\n\nAs outras ideias ajudam menos: juntar tudo numa bandeja só não impede a confusão; mostrar exemplos ajuda um pouco, mas ele ainda tenta fazer tudo de uma vez; e conferir no final se esqueceu algo é útil, mas não pega quando ele troca as coisas de lugar. Por isso, separar os pedidos (a letra A) é o melhor jeito!','\n',char(10)));
INSERT INTO cards VALUES('admin','card_1783092984035_86oh67h42',27,'Agente de Suporte ao Cliente',replace('Agente de Suporte ao Cliente\n\nLogs de produção mostram que para pedidos simples como "reembolso para o pedido #1234", seu agente resolve em 3–4 chamadas de ferramenta com 91% de sucesso. Mas para pedidos complexos como "fui cobrado em dobro, meu desconto não foi aplicado e quero cancelar", o agente faz em média 12+ chamadas com apenas 54% de sucesso — frequentemente investigando questões sequencialmente e buscando dados redundantes do cliente para cada uma. Qual mudança melhora o tratamento de pedidos complexos de forma mais efetiva?\n\n[ ] A - Adicionar checkpoints explícitos de verificação entre estágios, exigindo que o agente registre progresso após resolver cada questão antes de passar para a próxima.\n[ ] B - Reduzir o número de ferramentas combinando `get_customer`, `lookup_order` e ferramentas relacionadas a cobrança em uma única `investigate_issue`.\n[ ] C - Decompor o pedido em questões separadas, depois investigar cada uma em paralelo usando contexto compartilhado do cliente antes de sintetizar uma resolução final.\n[ ] D - Adicionar exemplos few-shot ao system prompt demonstrando sequências ideais de chamada de ferramentas para vários cenários multi-faceta de cobrança.','\n',char(10)),'C - Decompor o pedido em questões separadas, depois investigar cada uma em paralelo usando contexto compartilhado do cliente antes de sintetizar uma resolução final.','["Domain_1::Agentic_Architecture_Orchestration", "Domain_5::Context_Management_Reliability", "Scenario_1::Customer_Support_Agent"]','New',0,2.5,0,1783092984035,1783725137497,1783203558653,replace('Agente de Suporte ao Cliente\n\nLogs de produção mostram que para pedidos simples como "reembolso para o pedido #1234", seu agente resolve em 3–4 chamadas de ferramenta com 91% de sucesso. Mas para pedidos complexos como "fui cobrado em dobro, meu desconto não foi aplicado e quero cancelar", o agente faz em média 12+ chamadas com apenas 54% de sucesso — frequentemente investigando questões sequencialmente e buscando dados redundantes do cliente para cada uma. Qual mudança melhora o tratamento de pedidos complexos de forma mais efetiva?\n\nA - Adicionar checkpoints explícitos de verificação entre estágios, exigindo que o agente registre progresso após resolver cada questão antes de passar para a próxima.\nB - Reduzir o número de ferramentas combinando `get_customer`, `lookup_order` e ferramentas relacionadas a cobrança em uma única `investigate_issue`.\nC - Decompor o pedido em questões separadas, depois investigar cada uma em paralelo usando contexto compartilhado do cliente antes de sintetizar uma resolução final.\nD - Adicionar exemplos few-shot ao system prompt demonstrando sequências ideais de chamada de ferramentas para vários cenários multi-faceta de cobrança.','\n',char(10)),replace('O diagnóstico do problema é fundamental para escolher a solução. Os dois sintomas descritos nos logs são: (1) o agente investiga questões **sequencialmente** e (2) ele **busca dados redundantes do cliente** repetidamente para cada questão. Isso gera excesso de chamadas (12+) e queda de sucesso (54%). Cada um dos dois problemas precisa ser atacado.\n\n**Por que C é a melhor resposta:**\nA alternativa C ataca diretamente as duas causas-raiz. "Decompor o pedido em questões separadas" transforma um problema monolítico e confuso em subtarefas bem definidas — isso reduz a confusão do modelo. "Investigar cada uma em paralelo" elimina o desperdício da abordagem sequencial, melhorando latência e reduzindo o número de passos encadeados. "Usando contexto compartilhado do cliente" resolve exatamente a busca redundante de dados: os dados do cliente são carregados uma vez e reutilizados por todas as investigações. E "sintetizar uma resolução final" garante coerência (por exemplo, cancelar o pedido pode tornar o reembolso e o desconto irrelevantes — a síntese evita ações conflitantes). É um padrão de orquestração (decomposição → fan-out paralelo → agregação) que casa perfeitamente com o perfil do problema.\n\n**Por que as outras estão erradas:**\n\n- **A (checkpoints sequenciais):** Reforça justamente o comportamento sequencial que está causando o problema. Adicionar verificação após cada questão pode melhorar a corretude marginalmente, mas mantém (ou até aumenta) o número de chamadas e não resolve a redundância de dados do cliente. Trata sintoma, não causa.\n\n- **B (consolidar ferramentas em `investigate_issue`):** Reduzir/agrupar ferramentas pode simplificar a superfície de decisão, mas não muda a estratégia sequencial nem a redundância de forma estrutural. Uma ferramenta "faz-tudo" pode até esconder a lógica dentro de uma caixa-preta, dificultando o tratamento correto de múltiplas questões distintas e reduzindo a observabilidade. Não endereça o paralelismo nem a síntese coerente.\n\n- **D (few-shot examples):** Exemplos ajudam a moldar comportamento, mas dependem de o modelo generalizar a partir de casos específicos. Cenários de cobrança multi-faceta são combinatoriamente vastos; você nunca cobrirá todos com exemplos. É uma solução frágil e paliativa que não muda a arquitetura de execução (continua sequencial e redundante quando o caso foge dos exemplos).\n\nEm resumo: o problema é arquitetural (orquestração), e apenas C reestrutura o fluxo para resolver as duas causas-raiz simultaneamente.','\n',char(10)),replace('Imagine que você é um ajudante que resolve problemas de clientes. Quando o cliente tem só um problema, você resolve rapidinho. Mas quando ele tem três problemas de uma vez ("me cobraram duas vezes", "meu desconto sumiu" e "quero cancelar"), você fica atrapalhado: resolve um de cada vez, bem devagar, e fica perguntando os mesmos dados do cliente toda hora — que chatice!\n\nA melhor solução (a resposta C) é assim: primeiro você separa os três problemas em três "tarefinhas". Depois, você cuida das três ao mesmo tempo (em vez de uma por uma), e usa as informações do cliente uma única vez para todas elas. No final, você junta tudo e dá uma resposta certinha e organizada. Assim você trabalha mais rápido e erra menos!\n\nAs outras ideias não funcionam tão bem: uma delas manda você continuar resolvendo um de cada vez (devagar do mesmo jeito), outra só junta as ferramentas mas não muda a bagunça, e a última tenta te ensinar com exemplos — mas nunca vai ter exemplo para tudo que pode acontecer.','\n',char(10)));
INSERT INTO cards VALUES('admin','card_1783092984040_91rn44f7s',28,'Agente de Suporte ao Cliente',replace('Agente de Suporte ao Cliente\n\nApós chamar `get_customer` e `lookup_order`, o agente tem todos os dados disponíveis no sistema mas ainda enfrenta incerteza. Qual situação é o gatilho mais justificado para chamar `escalate_to_human`?\n\n[ ] A - Um cliente quer cancelar um pedido enviado ontem e que chega amanhã. O agente deve escalar porque o cliente pode mudar de ideia depois de receber o pacote.\n[ ] B - Um cliente afirma que não recebeu um pedido, mas o tracking mostra que foi entregue e assinado em seu endereço três dias atrás. O agente deve escalar porque apresentar evidência contraditória pode prejudicar o relacionamento.\n[ ] C - Um cliente solicita matching de preço de concorrente. Suas políticas permitem ajustes de preço para quedas no próprio site dentro de 14 dias, mas não dizem nada sobre preços de concorrente. O agente deve escalar para interpretação de política.\n[ ] D - Uma mensagem do cliente contém tanto uma questão de cobrança quanto uma devolução. O agente deve escalar para que um humano coordene ambas em uma única interação.','\n',char(10)),'C - Um cliente solicita matching de preço de concorrente. Suas políticas permitem ajustes de preço para quedas no próprio site dentro de 14 dias, mas não dizem nada sobre preços de concorrente. O agente deve escalar para interpretação de política.','["Domain_2::Tool_Design_MCP_Integration", "Domain_4::Prompt_Engineering_Structured_Output", "Scenario_1::Customer_Support_Agent"]','New',0,2.5,0,1783092984040,1783725141835,1783203558653,replace('Customer Support Agent\n\nAfter calling `get_customer` and `lookup_order`, the agent has all data available in the system but still faces uncertainty. Which situation is the most justified trigger to call `escalate_to_human`?\n\n[ ] A - A customer wants to cancel an order that shipped yesterday and arrives tomorrow. The agent should escalate because the customer might change their mind after receiving the package.\n\n[ ] B - A customer claims they did not receive an order, but the tracking shows it was delivered and signed for at their address three days ago. The agent should escalate because presenting contradictory evidence could harm the relationship.\n\n[ ] C - A customer requests a competitor price match. Your policies allow price adjustments for drops on your own site within 14 days, but say nothing about competitor prices. The agent should escalate for policy interpretation.\n\n[ ] D - A customer message contains both a billing question and a return. The agent should escalate so a human can coordinate both in a single interaction.','\n',char(10)),replace('O critério central aqui é: quando a incerteza é genuína e não resolúvel pelos dados ou pelas políticas existentes, a escalação para um humano é justificada. Escalar deve ser reservado para casos onde o agente não tem autoridade ou base de decisão — não para tarefas que ele consegue executar sozinho.\n\n**Por que C é a correta:**\nExiste uma verdadeira lacuna de política. As regras cobrem ajustes de preço do próprio site (14 dias), mas são silenciosas sobre matching com concorrentes. O agente não tem base para decidir "sim" nem "não" — qualquer resposta seria uma invenção de política (risco de conceder algo indevido ou negar algo que a empresa concederia). Essa é exatamente a situação onde um humano precisa interpretar/decidir a política. A incerteza é irredutível com os dados e regras disponíveis.\n\n**Por que A está errada:**\nEsse é um caso operacional trivial. O agente pode explicar as opções de cancelamento/devolução conforme a política de pedidos já enviados. Escalar com base em uma especulação ("o cliente pode mudar de ideia") é presunção infundada — não há incerteza real de política ou dados. Antecipar comportamento futuro não é motivo válido para escalar.\n\n**Por que B está errada:**\nO sistema fornece uma resposta clara: o tracking mostra entrega assinada. O agente tem os fatos para lidar com a situação (informar a evidência, orientar sobre disputa/reclamação de entrega, iniciar investigação de "package not received"). Evitar apresentar evidência para "proteger o relacionamento" é uma racionalização — não é um gatilho de escalação. O caso é resolúvel com os dados disponíveis.\n\n**Por que D está errada:**\nUm agente competente pode tratar múltiplas intenções (cobrança + devolução) na mesma conversa, sequencialmente. Ter dois tópicos não gera incerteza — apenas exige executar duas tarefas. Escalar por "coordenação" desperdiça um humano em algo que o agente já pode fazer.\n\nRegra prática para o tech lead: escale por *ausência de autoridade/regra* (lacuna genuína como em C), não por conveniência, especulação ou volume de tarefas.','\n',char(10)),replace('Imagine que um robô ajudante atende clientes de uma loja. Ele só deve chamar uma pessoa de verdade quando realmente não sabe o que fazer e não existe regra pra ajudar.\n\nNa resposta certa (C): o cliente quer o mesmo preço de outra loja. A loja tem regra só para descontos do próprio site, mas NÃO tem nenhuma regra sobre copiar o preço dos concorrentes. Como não existe regra, o robô não pode inventar — então ele chama um humano pra decidir. Esse é o caso certo!\n\nNas outras:\n- A: o cliente quer cancelar um pedido que chega amanhã. O robô já sabe como fazer isso — não precisa chamar ninguém só porque "o cliente talvez mude de ideia".\n- B: o cliente diz que não recebeu, mas o sistema mostra que o pacote foi entregue e assinado. O robô tem a resposta na tela, então ele mesmo pode resolver.\n- D: o cliente fez duas perguntas ao mesmo tempo. O robô consegue responder as duas, uma depois da outra. Duas perguntas não são um problema difícil.\n\nOu seja: só chame o humano quando faltar uma regra de verdade, como em C!','\n',char(10)));
INSERT INTO cards VALUES('admin','card_1783092984045_cbmihv11i',29,'Agente de Suporte ao Cliente',replace('Agente de Suporte ao Cliente\n\nMétricas de produção mostram que seu agente faz em média 4+ loops de API por resolução. A análise revela que Claude frequentemente solicita `get_customer` e `lookup_order` em turnos sequenciais separados, mesmo quando ambos são necessários inicialmente. Qual é a forma mais efetiva de reduzir o número de loops?\n\n[ ] A - Implementar execução especulativa que automaticamente chama ferramentas provavelmente necessárias em paralelo a qualquer ferramenta solicitada e retorna todos os resultados, independentemente do que foi pedido.\n[ ] B - Aumentar `max_tokens` para dar a Claude mais espaço para planejar e combinar naturalmente solicitações de ferramenta.\n[ ] C - Criar ferramentas compostas como `get_customer_with_orders` que agrupam combinações comuns de lookup em uma única chamada.\n[ ] D - Instruir Claude no prompt a agrupar solicitações de ferramenta em um turno e retornar todos os resultados juntos antes da próxima chamada de API.','\n',char(10)),'D - Instruir Claude no prompt a agrupar solicitações de ferramenta em um turno e retornar todos os resultados juntos antes da próxima chamada de API.','["Domain_2::Tool_Design_MCP_Integration", "Domain_5::Context_Management_Reliability", "Scenario_1::Customer_Support_Agent"]','New',0,2.5,0,1783092984045,1783725145525,1783203558653,replace('Agente de Suporte ao Cliente\n\nMétricas de produção mostram que seu agente faz em média 4+ loops de API por resolução. A análise revela que Claude frequentemente solicita `get_customer` e `lookup_order` em turnos sequenciais separados, mesmo quando ambos são necessários inicialmente. Qual é a forma mais efetiva de reduzir o número de loops?\n\n[ ] A - Implementar execução especulativa que automaticamente chama ferramentas provavelmente necessárias em paralelo a qualquer ferramenta solicitada e retorna todos os resultados, independentemente do que foi pedido.\n[ ] B - Aumentar `max_tokens` para dar a Claude mais espaço para planejar e combinar naturalmente solicitações de ferramenta.\n[ ] C - Criar ferramentas compostas como `get_customer_with_orders` que agrupam combinações comuns de lookup em uma única chamada.\n[ ] D - Instruir Claude no prompt a agrupar solicitações de ferramenta em um turno e retornar todos os resultados juntos antes da próxima chamada de API.','\n',char(10)),replace('**Resposta correta: D**\n\nO problema central é que Claude tem a capacidade nativa de emitir **múltiplas chamadas de ferramenta (tool calls) em paralelo dentro de um único turno**, mas por padrão nem sempre o faz de forma agressiva. Quando as ferramentas são independentes (como `get_customer` e `lookup_order`, que não dependem do resultado uma da outra), a solução mais direta, barata e escalável é **orientar o comportamento via prompt/system prompt**, instruindo Claude a identificar e agrupar chamadas independentes num mesmo turno. Isso reduz imediatamente o número de loops de ida-e-volta com a API sem exigir mudanças de infraestrutura ou de esquema de ferramentas. A Anthropic recomenda explicitamente esse tipo de "encouragement" de tool calls paralelas via instruções. É a intervenção de menor custo e maior alavancagem.\n\n**Por que as outras estão erradas:**\n\n- **A (execução especulativa)**: Chamar ferramentas que Claude *não* pediu, de forma automática e "especulativa", é arriscado e caro. Você executa operações desnecessárias (custo, latência, possíveis efeitos colaterais em ferramentas que não são idempotentes) e pode retornar dados irrelevantes ou até incorretos. É uma solução frágil que trata o sintoma na camada de orquestração, não a causa. Além disso, "independentemente do que foi pedido" pode disparar side effects indesejados.\n\n- **B (aumentar max_tokens)**: `max_tokens` controla o tamanho máximo da *saída* de um turno, não a estratégia de agrupamento de chamadas. Claude já consegue emitir múltiplas tool calls sem esbarrar nesse limite na maioria dos casos. Aumentar esse parâmetro não muda o comportamento de sequenciar chamadas — é uma correlação equivocada entre o parâmetro e o problema.\n\n- **C (ferramentas compostas)**: É uma solução *válida e legítima* (reduz loops de fato), mas menos flexível e mais custosa de manter. Você precisaria antecipar e codificar cada combinação comum (`get_customer_with_orders`, e depois `get_customer_with_orders_and_tickets`, etc.), gerando explosão combinatória de ferramentas e acoplamento rígido. Funciona para o caso específico, mas não é a forma *mais efetiva* nem generalizável — a instrução via prompt resolve todos os pares independentes de uma vez, sem reengenharia. Por isso D supera C em custo-benefício e generalidade.','\n',char(10)),replace('Imagine que você mandou um robô ajudante buscar suas coisas em duas gavetas diferentes. O robô podia abrir as duas gavetas ao mesmo tempo, mas ele estava indo até uma gaveta, voltando, e só depois indo na outra — gastando o dobro do tempo!\n\nA melhor solução (resposta D) é simplesmente **avisar o robô**: "Quando precisar de coisas de gavetas diferentes ao mesmo tempo, abra todas de uma vez!". Isso é fácil, barato e resolve o problema na hora.\n\nAs outras ideias não são tão boas:\n- A: mandar o robô abrir gavetas que você nem pediu, "por via das dúvidas" — ele bagunça e pega coisas erradas.\n- B: dar mais espaço na mochila do robô — mas o problema não era falta de espaço!\n- C: construir uma gaveta mágica que já junta duas coisas — funciona, mas você teria que construir uma gaveta nova pra cada combinação, e isso dá muito trabalho.\n\nPor isso, só **pedir com jeitinho** (D) é a maneira mais esperta.','\n',char(10)));
INSERT INTO cards VALUES('admin','card_1783092984050_3bysk4aom',30,'Agente de Suporte ao Cliente',replace('Agente de Suporte ao Cliente\n\nVocê está implementando o loop do agente de suporte. Após cada chamada de API ao Claude, é preciso decidir se continua o loop (executa as ferramentas pedidas e chama Claude novamente) ou para (apresenta a resposta final ao cliente). O que determina essa decisão?\n\n[ ] A - Verificar o campo `stop_reason` na resposta do Claude — continuar se for `tool_use` e parar se for `end_turn`.\n[ ] B - Parsear o texto do Claude por frases como "Estou pronto" ou "Posso ajudar com mais alguma coisa?" — sinais de linguagem natural indicam conclusão.\n[ ] C - Definir um número máximo de iterações (ex.: 10 chamadas) e parar quando atingido, independentemente de Claude indicar mais trabalho.\n[ ] D - Verificar se a resposta contém conteúdo de texto do assistente — se Claude gerou texto explicativo, o loop deve terminar.','\n',char(10)),'A - Verificar o campo `stop_reason` na resposta do Claude — continuar se for `tool_use` e parar se for `end_turn`.','["Domain_1::Agentic_Architecture_Orchestration", "Domain_5::Context_Management_Reliability", "Scenario_1::Customer_Support_Agent"]','New',0,2.5,0,1783092984050,1783725149697,1783203558653,replace('Agente de Suporte ao Cliente\n\nVocê está implementando o loop do agente de suporte. Após cada chamada de API ao Claude, é preciso decidir se continua o loop (executa as ferramentas pedidas e chama Claude novamente) ou para (apresenta a resposta final ao cliente). O que determina essa decisão?\n\nA - Verificar o campo `stop_reason` na resposta do Claude — continuar se for `tool_use` e parar se for `end_turn`.\nB - Parsear o texto do Claude por frases como "Estou pronto" ou "Posso ajudar com mais alguma coisa?" — sinais de linguagem natural indicam conclusão.\nC - Definir um número máximo de iterações (ex.: 10 chamadas) e parar quando atingido, independentemente de Claude indicar mais trabalho.\nD - Verificar se a resposta contém conteúdo de texto do assistente — se Claude gerou texto explicativo, o loop deve terminar.','\n',char(10)),replace('**Resposta correta: A**\n\nO loop do agente (agentic loop) é controlado pelo campo estruturado `stop_reason` que a API do Claude retorna em cada resposta. Esse campo é o sinal oficial e determinístico do estado da conversa:\n\n- Quando `stop_reason == "tool_use"`, significa que o Claude solicitou a execução de uma ou mais ferramentas. O seu código deve: executar as ferramentas, adicionar os resultados (`tool_result`) ao histórico de mensagens e chamar a API novamente. O loop continua.\n- Quando `stop_reason == "end_turn"`, o Claude concluiu seu raciocínio e produziu a resposta final. O loop para e você apresenta o texto ao cliente.\n\nEssa é a abordagem canônica recomendada pela Anthropic porque é robusta, determinística e não depende de heurísticas frágeis. Como tech lead, você deve programar contra esse contrato de API — é o único sinal confiável de intenção do modelo.\n\n**Por que as outras estão erradas:**\n\n**B (parsear linguagem natural)** — Extremamente frágil. O modelo pode gerar texto explicativo em qualquer iteração, inclusive quando ainda pretende chamar ferramentas. Depender de frases específicas ("Estou pronto", etc.) quebra com variações de idioma, tom, paráfrases e prompts diferentes. É uma anti-pattern clássico de parsing de saída não estruturada.\n\n**C (limite máximo de iterações)** — Um teto de iterações é uma boa prática de segurança/guardrail para evitar loops infinitos e custos descontrolados, mas NÃO é o mecanismo que determina a conclusão normal. Parar às cegas ao atingir o limite, ignorando o `stop_reason`, interromperia tarefas legítimas no meio. Ele complementa a solução A, mas não a substitui.\n\n**D (presença de texto do assistente)** — Incorreta porque o Claude frequentemente emite blocos de texto JUNTO com blocos `tool_use` na mesma resposta (por exemplo, explicando o que vai fazer antes de chamar a ferramenta). Terminar o loop só porque há texto encerraria prematuramente, antes de executar as ferramentas necessárias.\n\nEm resumo: use `stop_reason` como controle de fluxo principal (A), e mantenha um limite de iterações apenas como guardrail defensivo.','\n',char(10)),replace('Imagine que o Claude é um ajudante que às vezes precisa usar ferramentas (como uma calculadora ou uma lista de pedidos) antes de te dar a resposta final.\n\nDepois de cada vez que você fala com ele, ele te entrega um "bilhetinho" chamado `stop_reason` dizendo em que pé está:\n- Se o bilhete diz "tool_use", quer dizer: "Espera, ainda preciso pegar uma ferramenta!" — então você deixa ele usar a ferramenta e pergunta de novo.\n- Se o bilhete diz "end_turn", quer dizer: "Pronto, terminei!" — então você mostra a resposta.\n\nPor isso a resposta certa é a **A**: você lê esse bilhetinho oficial para saber se continua ou para.\n\nAs outras ideias não funcionam bem:\n- **B**: tentar adivinhar pelo que ele "falou" (tipo "Posso ajudar em mais alguma coisa?") é arriscado, porque ele pode falar coisas assim mesmo sem ter terminado.\n- **C**: colocar um limite tipo "só 10 vezes" ajuda a não ficar preso para sempre, mas não serve para saber quando ele realmente acabou.\n- **D**: só porque ele escreveu um textinho não quer dizer que acabou — ele pode escrever e AINDA assim precisar de uma ferramenta depois.\n\nEntão: sempre confie no bilhetinho `stop_reason`! 😊','\n',char(10)));
INSERT INTO cards VALUES('admin','card_1783092984070_a1sw5wwh3',31,'Seu pipeline de pesquisa multiagente falhou após processar 12 de 28 documentos.',replace('Seu pipeline de pesquisa multiagente falhou após processar 12 de 28 documentos.\n\nSeu pipeline de pesquisa multiagente falhou após processar 12 de 28 documentos. O agente de busca na web havia identificado fontes relevantes, o agente de análise de documentos havia concluído parcialmente a extração e o sintetizador havia iniciado a identificação de padrões. Você precisa retomar o processamento sem repetir trabalho nem perder a fidelidade das descobertas anteriores.\n\nQual abordagem de gerenciamento de estado equilibra melhor a fidelidade das informações com a eficiência da janela de contexto ao restaurar o estado dos agentes?\n\n[ ] A - Fazer com que cada agente mantenha seu próprio arquivo de estado persistente e o recarregue de forma independente no início de cada sessão.\n[ ] B - Persistir o log de conversa do coordenador contendo todas as delegações de tarefas e respostas, fornecendo-o aos agentes na retomada.\n[ ] C - Fazer com que cada agente persista um relatório estruturado em um local conhecido. Na retomada, o coordenador carrega os relatórios e injeta o estado relevante nos prompts dos agentes.\n[ ] D - Indexar todas as saídas dos agentes em um armazenamento vetorial compartilhado. Ao retomar, cada agente consulta o armazenamento usando busca semântica para recuperar descobertas anteriores relevantes.','\n',char(10)),'C - Fazer com que cada agente persista um relatório estruturado em um local conhecido. Na retomada, o coordenador carrega os relatórios e injeta o estado relevante nos prompts dos agentes.','["Domain_1::Agentic_Architecture_Orchestration", "Domain_5::Context_Management_Reliability", "Scenario_3::Multi_Agent_Research"]','New',0,2.5,0,1783092984070,1783725153568,1783203558653,replace('Seu pipeline de pesquisa multiagente falhou após processar 12 de 28 documentos. O agente de busca na web havia identificado fontes relevantes, o agente de análise de documentos havia concluído parcialmente a extração e o sintetizador havia iniciado a identificação de padrões. Você precisa retomar o processamento sem repetir trabalho nem perder a fidelidade das descobertas anteriores.\n\nQual abordagem de gerenciamento de estado equilibra melhor a fidelidade das informações com a eficiência da janela de contexto ao restaurar o estado dos agentes?\n\n[ ] A - Fazer com que cada agente mantenha seu próprio arquivo de estado persistente e o recarregue de forma independente no início de cada sessão.\n[ ] B - Persistir o log de conversa do coordenador contendo todas as delegações de tarefas e respostas, fornecendo-o aos agentes na retomada.\n[ ] C - Fazer com que cada agente persista um relatório estruturado em um local conhecido. Na retomada, o coordenador carrega os relatórios e injeta o estado relevante nos prompts dos agentes.\n[ ] D - Indexar todas as saídas dos agentes em um armazenamento vetorial compartilhado. Ao retomar, cada agente consulta o armazenamento usando busca semântica para recuperar descobertas anteriores relevantes.','\n',char(10)),replace('**Por que C é a melhor resposta:**\n\nO problema pede um equilíbrio entre dois objetivos concorrentes: (1) **fidelidade das informações** — não perder nem distorcer as descobertas já produzidas, e (2) **eficiência da janela de contexto** — não sobrecarregar os prompts dos agentes com tokens irrelevantes.\n\nA opção C atende aos dois porque:\n- **Relatórios estruturados** (ex.: JSON/schema definido) preservam com alta fidelidade o que cada agente concluiu (fontes encontradas, extrações parciais, padrões iniciais), sem a ambiguidade de logs conversacionais brutos.\n- **Persistência em local conhecido** permite retomada determinística — o coordenador sabe exatamente onde buscar o estado de cada agente.\n- **Injeção seletiva do estado relevante** pelo coordenador é o ponto-chave: em vez de recarregar tudo, o orquestrador filtra e injeta apenas o subconjunto necessário no prompt de cada agente, economizando janela de contexto.\n- Isso reflete o padrão maduro de orquestração multiagente: um coordenador central que faz curadoria do estado compartilhado (control plane) e distribui contexto sob demanda.\n\n**Por que as demais estão erradas:**\n\n- **A (arquivos independentes por agente, recarregados sem coordenação):** garante persistência, mas cada agente recarrega seu estado integralmente e de forma isolada, sem curadoria. Isso desperdiça contexto (carrega tudo, não só o relevante) e, sem coordenação central, dificulta consistência entre agentes que dependem uns dos outros (o sintetizador precisa dos resultados do analisador). Falha na eficiência de contexto e na coordenação.\n\n- **B (persistir o log completo da conversa do coordenador):** logs de conversa são verbosos e cheios de "ruído" (mensagens de delegação, respostas completas, metadados). Reinjetá-los inteiros consome enormemente a janela de contexto e degrada a fidelidade útil, pois o sinal se perde no volume. É a pior escolha em eficiência de contexto.\n\n- **D (vector store + busca semântica na retomada):** parece elegante, mas introduz risco de fidelidade. A busca semântica é **aproximada e probabilística** — pode não recuperar exatamente quais dos 12 documentos já foram processados nem o estado preciso de cada um. Para retomada determinística ("o que já foi feito e onde parei"), você precisa de recuperação exata/estruturada, não de similaridade. Vector store é ótimo para conhecimento/recuperação semântica, mas inadequado como mecanismo de checkpoint/estado de execução.','\n',char(10)),replace('Imagine que você e seus amigos estão montando um quebra-cabeça gigante de 28 peças e, no meio do caminho, acaba a luz. Vocês pararam na peça 12. Quando a luz voltar, como vocês continuam sem começar tudo de novo?\n\nA ideia melhor (resposta C) é: cada amigo escreve num papel bem organizado o que já fez ("eu já achei estas peças", "eu já encaixei estas aqui"). Um amigo-chefe (o coordenador) guarda todos esses papéis num lugar certo. Quando a luz volta, o chefe lê os papéis e entrega para cada amigo só a parte que ele precisa saber — nem de menos (para não esquecer nada), nem de mais (para não confundir a cabeça de ninguém).\n\nAs outras ideias não funcionam tão bem:\n- **A:** cada um guarda seu papel sozinho e lê tudo de novo, sem ninguém organizando — vira bagunça e cada um lê coisa demais.\n- **B:** guardar a conversa inteira, com tudo que foi dito — é papel demais para ler, cansa e a gente se perde no que importa.\n- **D:** procurar as anotações "por parecido" (mais ou menos) — às vezes você acha a errada e pode esquecer qual peça já colocou. Para saber exatamente onde parou, isso é arriscado.\n\nPor isso, a resposta certa é a **C**! 🧩','\n',char(10)));
INSERT INTO cards VALUES('admin','card_1783092984075_5bkjfzuw8',32,'Depois que o agente de busca na web encontra 25 fontes (120 mil tokens de conteúdo bruto), o agente de análise de documentos extrai os principais insights (15 mil tokens) e o agente de síntese produz um rascunho de narrativa coerente (3 mil tokens), o coordenador deve passar o contexto para o agente de geração de relatórios para a saída final com as devidas citações de fonte.',replace('Depois que o agente de busca na web encontra 25 fontes (120 mil tokens de conteúdo bruto), o agente de análise de documentos extrai os principais insights (15 mil tokens) e o agente de síntese produz um rascunho de narrativa coerente (3 mil tokens), o coordenador deve passar o contexto para o agente de geração de relatórios para a saída final com as devidas citações de fonte.\n\nDepois que o agente de busca na web encontra 25 fontes (120 mil tokens de conteúdo bruto), o agente de análise de documentos extrai os principais insights (15 mil tokens) e o agente de síntese produz um rascunho de narrativa coerente (3 mil tokens), o coordenador deve passar o contexto para o agente de geração de relatórios para a saída final com as devidas citações de fonte.\n\nQual estratégia de passagem de contexto oferece o melhor equilíbrio entre completude e eficiência?\n\n[ ] A - Passar apenas o rascunho de síntese e ter um pipeline de pós-processamento separado para associar afirmações às fontes e inserir citações depois que o relatório for gerado.\n[ ] B - Passar o rascunho de síntese junto com um índice de fontes estruturado que mapeia as principais afirmações às URLs de suas fontes e aos trechos relevantes.\n[ ] C - Passar um resumo condensado de todas as etapas anteriores que preserva as principais descobertas e as atribui às fontes apenas pelo nome.\n[ ] D - Passar todo o contexto acumulado de todos os agentes anteriores.','\n',char(10)),'B - Passar o rascunho de síntese junto com um índice de fontes estruturado que mapeia as principais afirmações às URLs de suas fontes e aos trechos relevantes.','["Domain_1::Agentic_Architecture_Orchestration", "Domain_5::Context_Management_Reliability", "Scenario_3::Multi_Agent_Research"]','New',0,2.5,0,1783092984075,1783725157685,1783203558653,replace('Depois que o agente de busca na web encontra 25 fontes (120 mil tokens de conteúdo bruto), o agente de análise de documentos extrai os principais insights (15 mil tokens) e o agente de síntese produz um rascunho de narrativa coerente (3 mil tokens), o coordenador deve passar o contexto para o agente de geração de relatórios para a saída final com as devidas citações de fonte.\n\nQual estratégia de passagem de contexto oferece o melhor equilíbrio entre completude e eficiência?\n\nA - Passar apenas o rascunho de síntese e ter um pipeline de pós-processamento separado para associar afirmações às fontes e inserir citações depois que o relatório for gerado.\nB - Passar o rascunho de síntese junto com um índice de fontes estruturado que mapeia as principais afirmações às URLs de suas fontes e aos trechos relevantes.\nC - Passar um resumo condensado de todas as etapas anteriores que preserva as principais descobertas e as atribui às fontes apenas pelo nome.\nD - Passar todo o contexto acumulado de todos os agentes anteriores.','\n',char(10)),replace('O cenário é um problema clássico de "context engineering" em sistemas multiagente: o desafio é entregar ao agente final exatamente a informação de que ele precisa (completude), sem inflar a janela de contexto com ruído (eficiência). O objetivo específico do agente de geração de relatórios é produzir a saída final **com citações de fonte corretas**. Isso significa que ele precisa de duas coisas: (1) a narrativa já sintetizada e (2) a rastreabilidade que liga cada afirmação à sua fonte.\n\n**Por que B é a melhor escolha:**\nA alternativa B combina o rascunho de síntese (3 mil tokens, já enxuto e coerente) com um índice estruturado que mapeia afirmações → URLs → trechos relevantes. Isso é o equilíbrio ideal porque:\n- Fornece a base textual final sem o peso dos 120 mil tokens brutos.\n- Preserva a rastreabilidade necessária para gerar citações precisas e verificáveis (URL + trecho), evitando alucinação de fontes.\n- Mantém o custo de tokens baixo e previsível, já que o índice é compacto e propositalmente estruturado.\n- É uma abordagem de "grounding" explícito: o agente escreve o relatório ancorado em evidências, não em memória vaga.\n\n**Por que as demais estão erradas:**\n\n- **A (pós-processamento separado):** desacopla a citação da geração, mas isso é frágil. Associar afirmações a fontes *depois* que o relatório foi escrito é notoriamente propenso a erros (matching aproximado, afirmações que combinam múltiplas fontes, paráfrases que dificultam o alinhamento). Você perde o contexto que o modelo tinha no momento da geração. É mais complexo e menos confiável do que ancorar as citações durante a escrita.\n\n- **C (resumo condensado citando fontes só pelo nome):** citar "apenas pelo nome" não é suficiente para citações acadêmicas/verificáveis. Sem URL e sem o trecho de suporte, a rastreabilidade se perde e o risco de atribuição incorreta ou alucinação aumenta. Sacrifica completude demais em nome da eficiência.\n\n- **D (passar todo o contexto acumulado):** os 120 mil tokens brutos + 15 mil + 3 mil sobrecarregam a janela de contexto, aumentam custo e latência e, pior, introduzem ruído que pode degradar a qualidade da saída ("lost in the middle", diluição de atenção). É o oposto de eficiência e não agrega valor, pois a síntese já destilou o conteúdo relevante.\n\nEm resumo: B entrega o produto pronto (síntese) mais um mapa de evidências compacto (índice estruturado) — exatamente o que o agente de relatórios precisa para citar corretamente, sem desperdiçar tokens.','\n',char(10)),replace('Imagine que vários ajudantes estão montando um trabalho de escola. Um deles procurou 25 livros gigantes, outro anotou só as partes importantes, e outro escreveu um rascunho bem organizado. Agora falta o ajudante final passar tudo a limpo e escrever de onde veio cada informação (as "fontes").\n\nA melhor ideia (resposta B) é dar a ele o rascunho já pronto MAIS uma listinha organizada que diz: "esta frase veio deste livro, nesta página". Assim ele escreve o trabalho e já coloca de onde tirou cada coisa, tudo certinho e sem carregar os 25 livros pesados.\n\nAs outras ideias não são tão boas:\n- A: escrever primeiro e só depois tentar descobrir de onde veio cada frase — é fácil errar e trocar as fontes.\n- C: dizer só o nome do livro, sem a página nem o link — não dá pra conferir direito de onde veio.\n- D: entregar TODOS os 25 livros gigantes de novo — é pesado demais, demora e atrapalha, já que o rascunho já tinha o mais importante.','\n',char(10)));
INSERT INTO cards VALUES('admin','card_1783092984080_sdhfpklmo',33,'O agente de busca na web reuniu várias fontes relevantes para um tópico de pesquisa.',replace('O agente de busca na web reuniu várias fontes relevantes para um tópico de pesquisa.\n\nO agente de busca na web reuniu várias fontes relevantes para um tópico de pesquisa. O agente de análise de documentos agora precisa examinar essas fontes.\n\nComo as informações normalmente fluem entre esses dois subagentes especializados?\n\n[ ] A - Os agentes se comunicam por meio de uma fila de mensagens orientada a eventos, com o agente de análise de documentos assinando os eventos de conclusão da busca na web.\n[ ] B - O agente de busca na web invoca diretamente o agente de análise de documentos, passando as fontes descobertas como parâmetros.\n[ ] C - O agente coordenador recebe a saída do agente de busca na web e inclui as descobertas relevantes no prompt ao invocar o agente de análise de documentos.\n[ ] D - Ambos os agentes acessam um armazenamento de memória compartilhado, onde o agente de busca na web grava as descobertas e o agente de análise de documentos as lê.','\n',char(10)),'C - O agente coordenador recebe a saída do agente de busca na web e inclui as descobertas relevantes no prompt ao invocar o agente de análise de documentos.','["Domain_1::Agentic_Architecture_Orchestration", "Scenario_3::Multi_Agent_Research"]','New',0,2.5,0,1783092984080,1783725160799,1783203558653,replace('O agente de busca na web reuniu várias fontes relevantes para um tópico de pesquisa. O agente de análise de documentos agora precisa examinar essas fontes. Como as informações normalmente fluem entre esses dois subagentes especializados?\n\n[ ] A - Os agentes se comunicam por meio de uma fila de mensagens orientada a eventos, com o agente de análise de documentos assinando os eventos de conclusão da busca na web.\n[ ] B - O agente de busca na web invoca diretamente o agente de análise de documentos, passando as fontes descobertas como parâmetros.\n[ ] C - O agente coordenador recebe a saída do agente de busca na web e inclui as descobertas relevantes no prompt ao invocar o agente de análise de documentos.\n[ ] D - Ambos os agentes acessam um armazenamento de memória compartilhado, onde o agente de busca na web grava as descobertas e o agente de análise de documentos as lê.','\n',char(10)),replace('**Resposta correta: C**\n\nNa arquitetura padrão de sistemas multiagente com LLMs (padrão *orchestrator-worker* ou *coordinator/supervisor*), os subagentes especializados não se comunicam diretamente entre si. Em vez disso, existe um **agente coordenador (orchestrator)** que atua como ponto central de controle:\n\n1. O coordenador invoca o agente de busca na web.\n2. Recebe a saída (as fontes/descobertas) de volta.\n3. Constrói um novo prompt contendo as descobertas relevantes.\n4. Invoca o agente de análise de documentos com esse contexto.\n\nEsse padrão hierárquico é o mais comum porque:\n- **Mantém o controle centralizado** do fluxo, permitindo que o coordenador decida o que é relevante repassar.\n- **Reduz acoplamento** entre os subagentes — cada um só precisa conhecer seu contrato com o coordenador, não com os outros agentes.\n- **Facilita observabilidade e recuperação de erros**, já que todo o roteamento passa por um único ponto.\n\n**Por que as outras estão erradas:**\n\n- **A (fila de mensagens orientada a eventos):** Descreve uma arquitetura de microsserviços distribuídos com pub/sub. Embora tecnicamente possível, não é o modo *típico* como subagentes de LLM colaboram. Introduz complexidade de infraestrutura desnecessária e retira o controle contextual que o coordenador precisa exercer ao montar prompts.\n\n- **B (invocação direta agente-a-agente):** Cria acoplamento forte entre os subagentes e descentraliza o controle. No padrão coordenador, os subagentes idealmente não sabem da existência uns dos outros — isso quebraria a separação de responsabilidades e dificultaria a orquestração e o tratamento de erros.\n\n- **D (memória compartilhada):** Embora blackboards e memória compartilhada existam em alguns designs, o fluxo *típico* de handoff em frameworks multiagente é a passagem de contexto via prompt mediada pelo coordenador. Memória compartilhada introduz problemas de sincronização, concorrência e ambiguidade sobre o que ler, sendo menos direto e menos previsível que o repasse explícito de contexto.\n\nComo tech lead, o insight chave é: **o coordenador é o "cérebro" do roteamento**, e a comunicação entre agentes ocorre por *composição de contexto/prompt*, não por chamadas diretas ou barramentos distribuídos.','\n',char(10)),replace('Imagine que você tem dois ajudantes: um que procura livros na biblioteca e outro que lê os livros e resume. Eles não conversam sozinhos entre si. Em vez disso, existe um chefe (o coordenador) que fica no meio.\n\nO chefe pede ao primeiro ajudante: "Vá buscar os livros sobre esse assunto!" O ajudante volta e entrega os livros ao chefe. Aí o chefe pega esses livros e diz ao segundo ajudante: "Aqui estão os livros, agora leia e me explique!"\n\nOu seja, o chefe recebe o trabalho de um ajudante e entrega para o outro. Por isso a resposta certa é a **C**.\n\nAs outras respostas dizem que os ajudantes falam direto entre si, ou que eles usam uma caixa mágica compartilhada, mas o jeito mais comum e organizado é ter o chefe no meio cuidando de tudo!','\n',char(10)));
INSERT INTO cards VALUES('admin','card_1783092984085_2s174tbms',34,'Em produção, você observa que consultas simples de verificação de fatos (por exemplo, "Em que ano o Acordo de Paris sobre o Clima foi assinado?") percorrem todos os quatro subagentes sequencialmente, consumindo mais de 40 segundos e tokens significativos por consulta.',replace('Em produção, você observa que consultas simples de verificação de fatos (por exemplo, "Em que ano o Acordo de Paris sobre o Clima foi assinado?") percorrem todos os quatro subagentes sequencialmente, consumindo mais de 40 segundos e tokens significativos por consulta.\n\nEm produção, você observa que consultas simples de verificação de fatos (por exemplo, "Em que ano o Acordo de Paris sobre o Clima foi assinado?") percorrem todos os quatro subagentes sequencialmente, consumindo mais de 40 segundos e tokens significativos por consulta. Pesquisas comparativas complexas se beneficiam do pipeline completo. Sua distribuição de consultas é diversa e está evoluindo à medida que os usuários descobrem novas aplicações.\n\nQual é a abordagem mais eficaz para otimizar para variações de complexidade das consultas?\n\n[ ] A - Implementar roteamento baseado em padrões que categoriza as consultas por estrutura (fato único vs. comparativa vs. analítica) e mapeia cada categoria para uma combinação predefinida de subagentes.\n[ ] B - Criar um caminho rápido para perguntas factuais que ignora completamente os subagentes, roteando todas as outras consultas pelo pipeline completo para garantir a profundidade da pesquisa.\n[ ] C - Fazer com que o coordenador analise cada consulta e decida dinamicamente quais subagentes invocar com base em sua avaliação dos requisitos da consulta.\n[ ] D - Treinar um classificador de complexidade de consultas com dados históricos rotulados para prever as combinações ideais de subagentes, retreinando periodicamente à medida que os padrões de consulta evoluem.','\n',char(10)),'C - Fazer com que o coordenador analise cada consulta e decida dinamicamente quais subagentes invocar com base em sua avaliação dos requisitos da consulta.','["Domain_1::Agentic_Architecture_Orchestration", "Domain_5::Context_Management_Reliability", "Scenario_3::Multi_Agent_Research"]','New',0,2.5,0,1783092984085,1783725164594,1783203558653,replace('Em produção, você observa que consultas simples de verificação de fatos (por exemplo, "Em que ano o Acordo de Paris sobre o Clima foi assinado?") percorrem todos os quatro subagentes sequencialmente, consumindo mais de 40 segundos e tokens significativos por consulta. Pesquisas comparativas complexas se beneficiam do pipeline completo. Sua distribuição de consultas é diversa e está evoluindo à medida que os usuários descobrem novas aplicações.\n\nQual é a abordagem mais eficaz para otimizar para variações de complexidade das consultas?\n\nA - Implementar roteamento baseado em padrões que categoriza as consultas por estrutura (fato único vs. comparativa vs. analítica) e mapeia cada categoria para uma combinação predefinida de subagentes.\nB - Criar um caminho rápido para perguntas factuais que ignora completamente os subagentes, roteando todas as outras consultas pelo pipeline completo para garantir a profundidade da pesquisa.\nC - Fazer com que o coordenador analise cada consulta e decida dinamicamente quais subagentes invocar com base em sua avaliação dos requisitos da consulta.\nD - Treinar um classificador de complexidade de consultas com dados históricos rotulados para prever as combinações ideais de subagentes, retreinando periodicamente à medida que os padrões de consulta evoluem.','\n',char(10)),replace('O ponto central do problema é que a distribuição de consultas é **diversa e está em evolução** ("evolving as users discover new applications"). Qualquer solução que dependa de categorias fixas ou de conjuntos de dados históricos vai envelhecer rápido e falhar diante de padrões novos e imprevistos.\n\n**Por que C é a melhor escolha:**\n- Em uma arquitetura multiagente moderna (padrão orchestrator-worker), o próprio coordenador/LLM tem capacidade de raciocínio para avaliar a intenção e a complexidade da consulta em tempo real e alocar apenas os subagentes necessários (escalonamento dinâmico de esforço).\n- Isso resolve diretamente o desperdício: uma pergunta factual simples aciona um único subagente (ou nenhum caminho pesado), enquanto uma pesquisa comparativa aciona o pipeline completo.\n- Como a decisão é feita por raciocínio semântico e não por regras estáticas, o sistema **generaliza naturalmente** para tipos de consulta novos, sem precisar de re-treino ou de manutenção de mapeamentos manuais. É a abordagem recomendada pela própria Anthropic para sistemas de pesquisa multiagente (escalar o esforço proporcionalmente à complexidade).\n\n**Por que as demais estão erradas:**\n- **A (roteamento por padrões/regras):** categorias predefinidas (fato único / comparativa / analítica) são frágeis. Como a distribuição está evoluindo, novas consultas cairão em categorias mal ajustadas ou não previstas, exigindo manutenção constante de regras. Rígido demais para um domínio em mudança.\n- **B (fast-path binário):** é uma simplificação grosseira demais. Divide o mundo em apenas dois casos (factual → atalho, resto → pipeline completo). Consultas de complexidade intermediária ainda pagam o custo total do pipeline desnecessariamente, e a heurística de detecção de "factual" também vira um ponto frágil. Não escala com a diversidade real.\n- **D (classificador ML treinado):** parece sofisticado, mas depende de dados históricos rotulados e de re-treino periódico. Em uma distribuição que muda continuamente, o classificador fica defasado (data/concept drift) entre os ciclos de re-treino, além de adicionar custo operacional de rotulagem, treino e MLOps. O LLM coordenador já traz esse raciocínio embutido, sem esse overhead e sem o atraso de adaptação.\n\nEm resumo: a decisão dinâmica feita pelo coordenador oferece o melhor equilíbrio entre eficiência (não desperdiça tokens/tempo), profundidade (aciona o pipeline completo quando necessário) e adaptabilidade (lida com padrões novos sem manutenção pesada).','\n',char(10)),replace('Imagine que você tem uma equipe de 4 ajudantes para responder perguntas. Se alguém pergunta algo bem fácil, tipo "em que ano aconteceu tal coisa?", não faz sentido chamar os 4 ajudantes e demorar 40 segundos — basta um deles responder rapidinho. Mas se a pergunta é difícil e precisa comparar várias coisas, aí sim vale a pena chamar todo mundo.\n\nA melhor solução (letra C) é ter um "chefinho" esperto que olha cada pergunta e decide na hora quantos ajudantes chamar. Como ele pensa a cada pergunta, ele consegue lidar até com perguntas novas que nunca apareceram antes.\n\nAs outras ideias são piores:\n- A usa uma lista fixa de "tipos de pergunta". O problema é que sempre aparecem perguntas novas que não estão na lista.\n- B só sabe fazer duas coisas: pergunta fácil vira atalho, todo o resto usa a equipe inteira. É simples demais e desperdiça tempo com perguntas médias.\n- D treina um robôzinho com exemplos antigos, mas ele fica desatualizado quando as perguntas mudam, e dá muito trabalho ficar re-treinando.\n\nPor isso, deixar o chefinho decidir na hora é o mais inteligente!','\n',char(10)));
INSERT INTO cards VALUES('admin','card_1783092984091_ge6sgw4um',35,'Ao pesquisar "adoção de energia renovável", o agente de busca na web retorna estatísticas recentes (2024: 35% de adoção), enquanto o agente de análise de documentos extrai dados de relatórios internos (2022: 18% de adoção).',replace('Ao pesquisar "adoção de energia renovável", o agente de busca na web retorna estatísticas recentes (2024: 35% de adoção), enquanto o agente de análise de documentos extrai dados de relatórios internos (2022: 18% de adoção).\n\nAo pesquisar "adoção de energia renovável", o agente de busca na web retorna estatísticas recentes (2024: 35% de adoção), enquanto o agente de análise de documentos extrai dados de relatórios internos (2022: 18% de adoção). O agente de síntese sinaliza incorretamente essas fontes como contraditórias, em vez de reconhecer que os dados mostram crescimento ao longo do tempo.\n\nQual mudança permitiria melhor que o agente de síntese interpretasse corretamente essas diferenças temporais?\n\n[ ] A - Exigir que os subagentes incluam as datas de publicação ou de coleta de dados em suas saídas estruturadas.\n[ ] B - Adicionar um agente de resolução de conflitos que descarta automaticamente os dados mais antigos quando existem dados mais recentes para a mesma métrica.\n[ ] C - Configurar o agente de busca na web para retornar apenas resultados dos últimos 6 meses.\n[ ] D - Instruir o agente de síntese a sempre tratar os dados mais recentes como autoritativos e colocar as descobertas mais antigas em um apêndice histórico separado.','\n',char(10)),'A - Exigir que os subagentes incluam as datas de publicação ou de coleta de dados em suas saídas estruturadas.','["Domain_1::Agentic_Architecture_Orchestration", "Domain_4::Prompt_Engineering_Structured_Output", "Scenario_3::Multi_Agent_Research"]','New',0,2.5,0,1783092984091,1783725168560,1783203558653,replace('Ao pesquisar "adoção de energia renovável", o agente de busca na web retorna estatísticas recentes (2024: 35% de adoção), enquanto o agente de análise de documentos extrai dados de relatórios internos (2022: 18% de adoção). O agente de síntese sinaliza incorretamente essas fontes como contraditórias, em vez de reconhecer que os dados mostram crescimento ao longo do tempo.\n\nQual mudança permitiria melhor que o agente de síntese interpretasse corretamente essas diferenças temporais?\n\n[ ] A - Exigir que os subagentes incluam as datas de publicação ou de coleta de dados em suas saídas estruturadas.\n[ ] B - Adicionar um agente de resolução de conflitos que descarta automaticamente os dados mais antigos quando existem dados mais recentes para a mesma métrica.\n[ ] C - Configurar o agente de busca na web para retornar apenas resultados dos últimos 6 meses.\n[ ] D - Instruir o agente de síntese a sempre tratar os dados mais recentes como autoritativos e colocar as descobertas mais antigas em um apêndice histórico separado.','\n',char(10)),replace('**Diagnóstico do problema (causa-raiz):** O agente de síntese trata os dois valores (35% e 18%) como contraditórios porque *falta contexto temporal*. Sem a dimensão "tempo" anexada a cada dado, dois pontos de uma mesma série histórica parecem uma discrepância factual. O problema não é o dado em si, e sim a **perda de metadados** durante a passagem entre subagentes.\n\n**Por que A é a resposta correta:**\nAo exigir que cada subagente inclua a data de publicação/coleta em sua saída estruturada, você fornece ao agente de síntese o contexto necessário para *raciocinar corretamente*. Com "2022 → 18%" e "2024 → 35%" explicitamente datados, o síntese pode interpretar isso como uma **tendência de crescimento** em vez de um conflito. É uma solução que preserva informação e habilita a interpretação correta, sem descartar nada. Como tech lead, note que isso é essencialmente enriquecer o schema de saída com metadados — a correção acontece na origem dos dados, não em heurísticas frágeis a jusante.\n\n**Por que as demais estão erradas:**\n\n- **B (agente de resolução de conflitos que descarta dados antigos):** Descartar automaticamente o dado de 2022 destrói informação valiosa. A comparação temporal (crescimento de 18% para 35%) é justamente o insight de negócio mais importante. Além disso, a premissa "mais novo sempre vence" é perigosa — nem sempre o dado mais recente é o mais relevante ou correto para a pergunta.\n\n- **C (limitar a busca aos últimos 6 meses):** Isso ataca o sintoma restringindo a fonte web, mas não resolve o problema fundamental (falta de contexto temporal) e ainda cega o sistema para dados históricos legítimos vindos dos relatórios internos. Você perderia justamente a capacidade de mostrar evolução ao longo do tempo.\n\n- **D (sempre tratar o mais recente como autoritativo e jogar o antigo num apêndice):** Repete o viés de B — assume que "recente = verdade absoluta" e relega o histórico a segundo plano. Além disso, não resolve a causa (ausência de datas nas saídas); apenas impõe uma política rígida que quebra em cenários onde o dado antigo é mais confiável ou onde a comparação temporal é o objetivo.\n\n**Princípio geral:** Em arquiteturas multiagente, a melhor correção costuma ser **enriquecer os dados com o contexto/metadados que faltam** (aqui, o tempo), permitindo raciocínio correto, em vez de aplicar heurísticas de descarte que destroem informação.','\n',char(10)),replace('Imagine que dois amigos foram medir o quanto uma plantinha cresceu. Um mediu em 2022 e disse "18 centímetros". O outro mediu em 2024 e disse "35 centímetros". Um robô ouviu os dois e ficou confuso: "Vocês estão brigando! Um diz 18 e o outro diz 35!"\n\nMas na verdade eles não estão brigando — a plantinha simplesmente cresceu com o tempo! O robô só ficou confuso porque ninguém disse a ele *em que ano* cada medida foi feita.\n\nA solução certa (letra A) é simples: pedir para cada amigo sempre dizer a data junto com o número. Aí o robô entende: "Ah, em 2022 era 18 e em 2024 já era 35 — quer dizer que cresceu!"\n\nAs outras respostas são ruins porque:\n- A letra B e a D mandam o robô **jogar fora** a medida antiga. Mas aí a gente nunca saberia que a plantinha cresceu!\n- A letra C manda parar de olhar coisas antigas, mas assim a gente perde histórias importantes do passado.\n\nPor isso, o melhor é só anotar a data junto com cada informação. 📅🌱','\n',char(10)));
INSERT INTO cards VALUES('admin','card_1783092984096_sp8o38h77',36,'O agente de síntese recebe descobertas resumidas dos agentes de busca na web e de análise de documentos e, em seguida, passa um resumo consolidado para o gerador de relatórios.',replace('O agente de síntese recebe descobertas resumidas dos agentes de busca na web e de análise de documentos e, em seguida, passa um resumo consolidado para o gerador de relatórios.\n\nO agente de síntese recebe descobertas resumidas dos agentes de busca na web e de análise de documentos e, em seguida, passa um resumo consolidado para o gerador de relatórios. Durante os testes, você descobre que os relatórios gerados fazem afirmações factuais sem as devidas citações — o gerador de relatórios não consegue atribuir as declarações às suas fontes originais porque esses metadados foram perdidos durante as etapas de resumo.\n\nQual é a abordagem mais eficaz para garantir a atribuição correta de fontes nos relatórios finais?\n\n[ ] A - Fazer com que cada agente produza dados estruturados que separem os resumos de conteúdo dos metadados de fonte (URLs, nomes de documentos, números de página).\n[ ] B - Fazer com que o gerador de relatórios consulte o agente de busca na web para relocalizar as fontes das afirmações no relatório final.\n[ ] C - Instruir o agente de síntese a incorporar referências de fonte em linha no texto do resumo usando um formato de citação consistente.\n[ ] D - Pular o resumo e passar as saídas brutas completas da busca na web e da análise de documentos diretamente para o gerador de relatórios.','\n',char(10)),'A - Fazer com que cada agente produza dados estruturados que separem os resumos de conteúdo dos metadados de fonte (URLs, nomes de documentos, números de página).','["Domain_1::Agentic_Architecture_Orchestration", "Domain_2::Tool_Design_MCP_Integration", "Domain_5::Context_Management_Reliability", "Scenario_3::Multi_Agent_Research"]','New',0,2.5,0,1783092984096,1783725172855,1783203558653,replace('O agente de síntese recebe descobertas resumidas dos agentes de busca na web e de análise de documentos e, em seguida, passa um resumo consolidado para o gerador de relatórios. Durante os testes, você descobre que os relatórios gerados fazem afirmações factuais sem as devidas citações — o gerador de relatórios não consegue atribuir as declarações às suas fontes originais porque esses metadados foram perdidos durante as etapas de resumo.\n\nQual é a abordagem mais eficaz para garantir a atribuição correta de fontes nos relatórios finais?\n\n[ ] A - Fazer com que cada agente produza dados estruturados que separem os resumos de conteúdo dos metadados de fonte (URLs, nomes de documentos, números de página).\n[ ] B - Fazer com que o gerador de relatórios consulte o agente de busca na web para relocalizar as fontes das afirmações no relatório final.\n[ ] C - Instruir o agente de síntese a incorporar referências de fonte em linha no texto do resumo usando um formato de citação consistente.\n[ ] D - Pular o resumo e passar as saídas brutas completas da busca na web e da análise de documentos diretamente para o gerador de relatórios.','\n',char(10)),replace('O problema central é a **perda de metadados de proveniência** (procedência das afirmações) durante as etapas de resumo. A causa raiz é que o conteúdo e a informação de origem estão misturados em texto livre, e o resumo — que é uma operação de compressão com perda — descarta os metadados.\n\n**Por que A é a melhor escolha:**\nA solução correta ataca a causa raiz de forma sistêmica. Ao adotar **dados estruturados** (por exemplo, JSON com campos separados para `claim`/`summary` e `source_metadata` contendo URL, nome do documento, número de página), você garante que a proveniência seja um dado de primeira classe, tratado como um contrato explícito entre os agentes. Isso impede que a informação de fonte seja "diluída" no processo de resumo, pois cada afirmação carrega seus metadados vinculados de forma programática. É a abordagem mais robusta, verificável e escalável para um pipeline multiagente — é o equivalente arquitetural a preservar a linhagem de dados (data lineage) através de todo o fluxo.\n\n**Por que as demais estão erradas:**\n\n- **B (relocalizar fontes depois):** Tenta reconstruir a proveniência *após* ela ter sido perdida. Isso é frágil, propenso a erros (re-busca pode encontrar fontes diferentes ou incorretas), caro em latência/custo e pode até fabricar atribuições erradas. Reconstruir proveniência post-hoc não garante que a fonte recuperada seja de fato a original.\n\n- **C (citações em linha no texto):** É uma melhoria em relação ao estado atual, mas ainda depende de o modelo de linguagem manter a formatação de citação de forma disciplinada ao resumir — algo notoriamente não confiável. Ao manter tudo em texto livre, a próxima etapa de resumo ou processamento pode novamente descartar ou corromper as citações. Não separa dados de metadados de forma estruturada e verificável.\n\n- **D (pular o resumo):** Elimina um benefício importante do pipeline (redução de contexto/ruído) e sobrecarrega o gerador de relatórios com dados brutos, aumentando custo, latência e risco de estouro de janela de contexto. Não resolve o problema de atribuição de forma estruturada — apenas transfere o problema de resumir para o último agente, que ainda pode perder a proveniência.','\n',char(10)),replace('Imagine que vários ajudantes leem livros e revistas e depois te contam o que aprenderam. Só que quando eles resumem, esquecem de dizer "isso eu li no livro X, página 5". Aí, na hora de fazer o trabalho da escola, você não sabe de onde veio cada informação e não consegue colocar a "fonte" (de onde tirou aquilo).\n\nA melhor solução (letra A) é: cada ajudante deve entregar a informação em duas caixinhas separadas — uma caixinha com o "que ele aprendeu" e outra caixinha com "de onde ele tirou isso" (o nome do livro, o site, a página). Assim, mesmo depois de resumir, a caixinha da fonte nunca se perde, porque ela vem sempre grudadinha na informação.\n\nAs outras opções não funcionam tão bem:\n- A letra B tenta descobrir de onde veio a informação *depois* que ela já se perdeu — é como tentar lembrar de onde você ouviu uma fofoca; pode dar errado.\n- A letra C pede para escrever a fonte junto no texto, mas isso é fácil de esquecer ou bagunçar de novo.\n- A letra D manda entregar TUDO sem resumir nada — vira uma montanha de papel enorme e continua difícil achar cada fonte.\n\nPor isso, guardar a informação e a fonte em caixinhas separadas e organizadas (letra A) é o jeito mais seguro!','\n',char(10)));
INSERT INTO cards VALUES('admin','card_1783092984101_habeqiudl',37,'Em produção, os relatórios finais frequentemente contêm afirmações sem a devida atribuição de fonte.',replace('Em produção, os relatórios finais frequentemente contêm afirmações sem a devida atribuição de fonte.\n\nEm produção, os relatórios finais frequentemente contêm afirmações sem a devida atribuição de fonte. A investigação mostra que, embora os agentes de busca na web e de análise de documentos anexem corretamente as citações às suas saídas, o agente de síntese perde o controle de quais fontes sustentam quais conclusões ao combinar as descobertas.\n\nQual é a mudança arquitetural mais eficaz?\n\n[ ] A - Manter transcrições completas de todas as interações dos subagentes e adicionar um agente de resolução de citações para analisar os logs e determinar as atribuições antes da geração do relatório.\n[ ] B - Exigir que todos os subagentes produzam mapeamentos estruturados de afirmação-fonte que o agente de síntese deve preservar e mesclar ao combinar descobertas de várias fontes.\n[ ] C - Adicionar uma etapa de verificação em que o gerador de relatórios usa correspondência por similaridade semântica com as fontes originais para reconstruir quais afirmações vieram de quais documentos.\n[ ] D - Fazer com que o coordenador injete prefixos de identificador de fonte no texto antes de cada transferência e, em seguida, analise esses prefixos na geração do relatório para reconstruir as citações.','\n',char(10)),'B - Exigir que todos os subagentes produzam mapeamentos estruturados de afirmação-fonte que o agente de síntese deve preservar e mesclar ao combinar descobertas de várias fontes.','["Domain_1::Agentic_Architecture_Orchestration", "Domain_4::Prompt_Engineering_Structured_Output", "Scenario_3::Multi_Agent_Research"]','New',0,2.5,0,1783092984101,1783725176840,1783203558653,replace('Em produção, os relatórios finais frequentemente contêm afirmações sem a devida atribuição de fonte. A investigação mostra que, embora os agentes de busca na web e de análise de documentos anexem corretamente as citações às suas saídas, o agente de síntese perde o controle de quais fontes sustentam quais conclusões ao combinar as descobertas.\n\nQual é a mudança arquitetural mais eficaz?\n\nA - Manter transcrições completas de todas as interações dos subagentes e adicionar um agente de resolução de citações para analisar os logs e determinar as atribuições antes da geração do relatório.\nB - Exigir que todos os subagentes produzam mapeamentos estruturados de afirmação-fonte que o agente de síntese deve preservar e mesclar ao combinar descobertas de várias fontes.\nC - Adicionar uma etapa de verificação em que o gerador de relatórios usa correspondência por similaridade semântica com as fontes originais para reconstruir quais afirmações vieram de quais documentos.\nD - Fazer com que o coordenador injete prefixos de identificador de fonte no texto antes de cada transferência e, em seguida, analise esses prefixos na geração do relatório para reconstruir as citações.','\n',char(10)),replace('**Diagnóstico do problema.** A causa raiz é precisa e importante: a citação já existe corretamente na saída dos subagentes (busca e análise de documentos). A perda de atribuição acontece exatamente no ponto de **síntese**, quando o agente combina descobertas de múltiplas fontes e "achata" o vínculo afirmação→fonte. Portanto, a melhor arquitetura é aquela que **preserva o vínculo através da fronteira de síntese**, em vez de tentar reconstruí-lo depois que ele já foi perdido.\n\n**Por que a B é a correta.** A alternativa B ataca a causa raiz: torna o mapeamento afirmação-fonte um **dado estruturado de primeira classe** que trafega junto com o conteúdo. Como os subagentes já produzem citações corretas, basta formalizar essa informação em um formato estruturado (por exemplo, cada afirmação carrega seu conjunto de fontes) e impor como contrato que o agente de síntese **preserve e mescle** esses mapeamentos ao combinar descobertas. A atribuição nunca é perdida porque nunca depende de reconstrução posterior — é propagada deterministicamente. Isso é robusto, auditável e não introduz heurísticas frágeis.\n\n**Por que as demais estão erradas:**\n\n- **A (agente de resolução via logs):** tenta *reconstruir* a atribuição a partir de transcrições completas depois do fato. É caro (mantém tudo), complexo e reintroduz exatamente o risco de erro que se quer eliminar — o novo agente teria que *inferir* quais fontes sustentam quais conclusões, algo que já se sabe ser propenso a falha. Trata o sintoma, não a causa.\n\n- **C (similaridade semântica):** reconstrução por matching semântico é intrinsecamente **probabilística e frágil**. Paráfrases, sínteses e combinações de fontes fazem a similaridade divergir do texto original, gerando atribuições incorretas ou ambíguas — justamente em relatórios onde a precisão da citação é crítica. Adivinhar a fonte é pior do que carregá-la explicitamente.\n\n- **D (prefixos de identificador injetados no texto):** transforma metadado estrutural em uma convenção de string embutida no texto livre, que precisa ser "parseada" depois. É frágil (o LLM pode reformular, remover ou embaralhar os prefixos), polui o conteúdo e não sobrevive bem à mescla de múltiplas fontes em uma única afirmação. Um hack de formatação, não uma solução arquitetural.\n\n**Regra geral para o tech lead:** quando um dado crítico já existe na origem, o padrão correto é **propagá-lo como estrutura ao longo do pipeline** (preserve-by-contract), e não descartá-lo e depois tentar reconstruí-lo por inferência, logs ou heurísticas.','\n',char(10)),replace('Imagine que vários amigos leem livros diferentes e cada um escreve uma ficha dizendo: "esta informação veio do livro X". Até aí tudo certo! O problema é que, quando um amigo junta todas as fichas para fazer um resumão, ele bagunça e esquece qual informação veio de qual livro.\n\nA melhor solução (resposta B) é fazer uma regra: cada informação **anda sempre grudada** na etiqueta do livro de onde veio. Assim, mesmo quando alguém junta tudo, a etiqueta continua colada e ninguém perde a fonte.\n\nAs outras ideias são piores:\n- (A) Guardar tudo o que todo mundo falou e depois um detetive tentar descobrir a fonte — dá muito trabalho e ele pode errar.\n- (C) Tentar adivinhar a fonte comparando frases parecidas — como chutar, e chute costuma errar.\n- (D) Colar uma etiqueta escrita dentro do próprio texto — fácil de borrar, apagar ou embaralhar.\n\nGrudar a etiqueta desde o começo e nunca soltá-la é o jeito mais seguro!','\n',char(10)));
INSERT INTO cards VALUES('admin','card_1783092984106_z7ql1tfgz',38,'Depois que o agente de busca na web e o agente de análise de documentos concluem suas tarefas, o coordenador invoca o agente de síntese.',replace('Depois que o agente de busca na web e o agente de análise de documentos concluem suas tarefas, o coordenador invoca o agente de síntese.\n\nDepois que o agente de busca na web e o agente de análise de documentos concluem suas tarefas, o coordenador invoca o agente de síntese. No entanto, o agente de síntese responde que não consegue concluir a tarefa porque nenhuma descoberta de pesquisa foi fornecida.\n\nQual é a causa mais provável desse problema?\n\n[ ] A - A janela de contexto do agente de síntese não é grande o suficiente para conter as saídas combinadas dos dois agentes anteriores.\n[ ] B - O coordenador não incluiu as saídas dos agentes anteriores no prompt do agente de síntese.\n[ ] C - Os subagentes precisam compartilhar uma única conexão de API para permitir o compartilhamento automático de contexto entre as invocações.\n[ ] D - O agente de síntese precisa de ferramentas que possam buscar resultados diretamente dos históricos de conversa dos outros agentes.','\n',char(10)),'B - O coordenador não incluiu as saídas dos agentes anteriores no prompt do agente de síntese.','["Domain_1::Agentic_Architecture_Orchestration", "Domain_2::Tool_Design_MCP_Integration", "Scenario_3::Multi_Agent_Research"]','New',0,2.5,0,1783092984106,1783725180896,1783203558653,replace('Depois que o agente de busca na web e o agente de análise de documentos concluem suas tarefas, o coordenador invoca o agente de síntese. No entanto, o agente de síntese responde que não consegue concluir a tarefa porque nenhuma descoberta de pesquisa foi fornecida.\n\nQual é a causa mais provável desse problema?\n\n[ ] A - A janela de contexto do agente de síntese não é grande o suficiente para conter as saídas combinadas dos dois agentes anteriores.\n[ ] B - O coordenador não incluiu as saídas dos agentes anteriores no prompt do agente de síntese.\n[ ] C - Os subagentes precisam compartilhar uma única conexão de API para permitir o compartilhamento automático de contexto entre as invocações.\n[ ] D - O agente de síntese precisa de ferramentas que possam buscar resultados diretamente dos históricos de conversa dos outros agentes.','\n',char(10)),replace('**Resposta correta: B**\n\nEm arquiteturas multiagente com um padrão orquestrador/coordenador (por exemplo, um supervisor que delega a subagentes), cada agente é, na prática, uma invocação de LLM isolada e *stateless*. Um agente **não tem acesso automático** ao que outro agente produziu — a menos que essas saídas sejam explicitamente passadas para ele.\n\nO papel do coordenador é justamente coletar as saídas dos agentes anteriores (busca na web e análise de documentos) e **injetá-las no prompt/contexto** do agente de síntese. Se o agente de síntese afirma que "nenhuma descoberta de pesquisa foi fornecida", isso é o sintoma clássico de que o contexto necessário não foi passado adiante. Ou seja, houve uma falha na etapa de *passagem de estado/contexto* pelo coordenador. Essa é a explicação mais direta e provável.\n\n**Por que as outras estão erradas:**\n\n- **A (janela de contexto pequena):** Se o problema fosse limite de contexto, o erro típico seria truncamento, exceção de tamanho de tokens ou resultados incompletos — e não uma mensagem afirmando que *nenhuma* descoberta foi recebida. Ausência total ≠ excesso de dados. Além disso, saídas de dois agentes raramente estouram janelas modernas.\n\n- **C (compartilhar uma única conexão de API):** Compartilhar conexão/cliente de API não implica compartilhamento de contexto. O contexto de um LLM é definido pelo conteúdo do prompt enviado, não pelo canal de rede. Conexões de API não transportam estado conversacional automaticamente entre agentes.\n\n- **D (ferramentas para buscar históricos de outros agentes):** É uma solução mais complexa e desnecessária para o padrão coordenador. O fluxo correto é o coordenador repassar as saídas no prompt. Dar a um agente ferramentas para "vasculhar" o histórico de outro seria uma arquitetura possível, mas não é a causa do problema nem a explicação mais provável — a raiz é simplesmente o contexto não ter sido incluído.\n\n**Lição para o tech lead:** em sistemas multiagente, trate a passagem de contexto/estado entre agentes como um contrato explícito. Cada invocação é sem memória por padrão; o orquestrador é responsável por serializar as saídas relevantes e injetá-las no input do próximo agente.','\n',char(10)),replace('Imagine que você tem três amigos ajudando numa tarefa. Dois deles pesquisam coisas: um procura na internet e outro lê documentos. O terceiro amigo, o "juntador", precisa pegar tudo o que os dois descobriram e montar uma resposta final.\n\nO problema é que o terceiro amigo disse: "Ei, eu não recebi nada para juntar!". Por quê? Porque o chefe (o coordenador) esqueceu de entregar os bilhetes com as descobertas para ele. O amigo juntador não consegue adivinhar sozinho o que os outros fizeram — alguém precisa contar para ele.\n\nPor isso a resposta certa é a **B**: o coordenador não passou as informações dos outros para o agente de síntese.\n\nAs outras estão erradas porque:\n- **A:** não é que a informação era grande demais — é que ela nem chegou!\n- **C:** usar o mesmo "telefone" não faz as ideias passarem sozinhas de um para o outro.\n- **D:** não precisa criar uma ferramenta especial para bisbilhotar; bastava o chefe entregar os bilhetes.','\n',char(10)));
INSERT INTO cards VALUES('admin','card_1783092984112_up369dtc9',39,'O coordenador fornece instruções detalhadas passo a passo ao subagente de busca na web, especificando consultas de busca exatas, prioridades de fontes e filtros de data.',replace('O coordenador fornece instruções detalhadas passo a passo ao subagente de busca na web, especificando consultas de busca exatas, prioridades de fontes e filtros de data.\n\nO coordenador fornece instruções detalhadas passo a passo ao subagente de busca na web, especificando consultas de busca exatas, prioridades de fontes e filtros de data. O monitoramento em produção revela três problemas: (1) o subagente relata "resultados insuficientes" em vez de tentar abordagens alternativas quando as buscas pré-especificadas falham, (2) a qualidade da pesquisa cai para tópicos emergentes que não correspondem aos padrões esperados e (3) o subagente raramente traz à tona fontes tangenciais valiosas.\n\nQual é a forma mais eficaz de melhorar a adaptabilidade do subagente?\n\n[ ] A - Remover completamente os detalhes procedurais, delegando com metas simples como "pesquise X minuciosamente" e contando com as capacidades gerais do subagente.\n[ ] B - Adicionar diretivas explícitas de contingência às instruções detalhadas: "Se as buscas especificadas retornarem menos de N resultados, tente formulações de consulta alternativas antes de relatar falha."\n[ ] C - Implementar uma etapa de classificação de tópicos em que o coordenador categoriza as solicitações como "bem definidas" ou "exploratórias" e usa estilos de instrução diferentes para cada categoria.\n[ ] D - Especificar metas de pesquisa e critérios de qualidade (amplitude de cobertura, diversidade de fontes, atualidade) em vez de etapas procedurais, deixando que o subagente determine sua estratégia de busca.','\n',char(10)),'D - Especificar metas de pesquisa e critérios de qualidade (amplitude de cobertura, diversidade de fontes, atualidade) em vez de etapas procedurais, deixando que o subagente determine sua estratégia de busca.','["Domain_1::Agentic_Architecture_Orchestration", "Domain_4::Prompt_Engineering_Structured_Output", "Scenario_3::Multi_Agent_Research"]','New',0,2.5,0,1783092984112,1783725184746,1783203558653,replace('O coordenador fornece instruções detalhadas passo a passo ao subagente de busca na web, especificando consultas de busca exatas, prioridades de fontes e filtros de data. O monitoramento em produção revela três problemas: (1) o subagente relata "resultados insuficientes" em vez de tentar abordagens alternativas quando as buscas pré-especificadas falham, (2) a qualidade da pesquisa cai para tópicos emergentes que não correspondem aos padrões esperados e (3) o subagente raramente traz à tona fontes tangenciais valiosas.\n\nQual é a forma mais eficaz de melhorar a adaptabilidade do subagente?\n\nA - Remover completamente os detalhes procedurais, delegando com metas simples como "pesquise X minuciosamente" e contando com as capacidades gerais do subagente.\nB - Adicionar diretivas explícitas de contingência às instruções detalhadas: "Se as buscas especificadas retornarem menos de N resultados, tente formulações de consulta alternativas antes de relatar falha."\nC - Implementar uma etapa de classificação de tópicos em que o coordenador categoriza as solicitações como "bem definidas" ou "exploratórias" e usa estilos de instrução diferentes para cada categoria.\nD - Especificar metas de pesquisa e critérios de qualidade (amplitude de cobertura, diversidade de fontes, atualidade) em vez de etapas procedurais, deixando que o subagente determine sua estratégia de busca.','\n',char(10)),replace('A raiz dos três problemas é a mesma: a prescrição rígida e procedural. Quando o coordenador dita exatamente *como* buscar (consultas exatas, filtros, prioridades), ele transforma o subagente em um executor mecânico, sem espaço para julgamento. Isso explica os três sintomas: (1) ao falhar a busca pré-especificada, o subagente não tem mandato para improvisar e simplesmente reporta falha; (2) tópicos emergentes não se encaixam nos padrões antecipados pelas instruções; (3) fontes tangenciais nunca aparecem porque não foram explicitamente solicitadas.\n\nO princípio correto em orquestração de agentes é: **especificar o "o quê" (objetivos e critérios de sucesso) e delegar o "como" (estratégia)**. A alternativa D faz exatamente isso — define metas e critérios de qualidade mensuráveis (amplitude de cobertura, diversidade de fontes, atualidade) e devolve ao subagente a autonomia de decidir sua estratégia de busca. Isso ataca simultaneamente os três problemas, pois o subagente passa a adaptar consultas, buscar diversidade e cobrir tópicos novos guiado por objetivos, não por scripts.\n\nPor que as outras estão erradas:\n\n- **A (incorreta):** vai ao extremo oposto. Remover *todo* detalhe e usar metas vagas como "pesquise X minuciosamente" retira também os critérios de qualidade. Sem alvos claros (diversidade, atualidade, cobertura), o resultado fica imprevisível e não necessariamente melhor. Delegação eficaz não é ausência de direção, é direção no nível certo (objetivos), não vagueza.\n\n- **B (incorreta):** é um "patch" pontual. Resolve parcialmente apenas o sintoma (1) ao adicionar um único fallback ("se < N resultados, tente reformular"), mas mantém o modelo procedural rígido. Não trata os sintomas (2) — tópicos emergentes fora do padrão — nem (3) — fontes tangenciais. Cada nova falha exigiria outra regra de contingência codificada manualmente, o que não escala e continua sem dar autonomia real.\n\n- **C (incorreta):** adiciona complexidade sem eliminar a causa raiz. Classificar em "bem definido" vs. "exploratório" ainda depende do coordenador acertar a categorização antecipadamente e manter estilos de instrução procedurais para casos "bem definidos". Introduz um ponto de falha (classificação errada) e não confere adaptabilidade genuína; é uma solução parcial e frágil comparada a simplesmente orientar por objetivos.\n\nEm resumo, a melhor prática de design é orientar por objetivos e critérios de qualidade, não por passos rígidos — exatamente o que D propõe.','\n',char(10)),replace('Imagine que você é um chefe e pede para um ajudante procurar informações. Se você disser "digite exatamente estas palavras, olhe só nesses sites e só nessas datas", o ajudante vira um robozinho: se não achar nada daquele jeito, ele desiste e diz "não achei" — e nunca procura de um jeito diferente nem traz coisas legais que estavam ali do lado.\n\nA forma esperta de mandar é dizer o *objetivo*: "quero uma pesquisa completa, com várias fontes diferentes e informações bem atuais". Aí o ajudante pode escolher sozinho o melhor caminho para chegar lá, tentar outras palavras e trazer descobertas interessantes.\n\nPor isso a resposta certa é a **D**. As outras não funcionam tão bem: a A deixa o pedido vago demais ("procure direito") e some com os critérios de qualidade; a B só conserta um probleminha com uma regrinha, mas esquece dos outros dois; e a C fica complicada e ainda depende de o chefe adivinhar a categoria certa. A D é a que ensina o ajudante a pensar por conta própria, de forma organizada.','\n',char(10)));
INSERT INTO cards VALUES('admin','card_1783092984117_ij9oakp86',40,'O monitoramento em produção mostra que consultas de acompanhamento como "resuma o que aprendemos sobre tendências de mercado" levam consistentemente mais de 40 segundos.',replace('O monitoramento em produção mostra que consultas de acompanhamento como "resuma o que aprendemos sobre tendências de mercado" levam consistentemente mais de 40 segundos.\n\nO monitoramento em produção mostra que consultas de acompanhamento como "resuma o que aprendemos sobre tendências de mercado" levam consistentemente mais de 40 segundos. A investigação revela que o coordenador inicia o subagente de síntese para cada solicitação de resumo, passando mais de 80 mil tokens de descobertas acumuladas. O coordenador já tem essas descobertas em seu contexto por ter orquestrado a pesquisa.\n\nQual é a forma mais eficaz de melhorar o tempo de resposta para esses resumos de acompanhamento?\n\n[ ] A - Pré-gerar e armazenar em cache resumos em várias granularidades sempre que novas descobertas se acumulem.\n[ ] B - Fazer com que o coordenador trate diretamente as solicitações de resumo simples usando seu contexto existente, reservando o início de subagentes para análises complexas.\n[ ] C - Habilitar o cache de prompt no subagente de síntese para reduzir o custo adicional de transferir repetidamente as mesmas descobertas de pesquisa.\n[ ] D - Iniciar o subagente de síntese com contexto reduzido e fazer com que ele solicite descobertas específicas ao coordenador sob demanda.','\n',char(10)),'B - Fazer com que o coordenador trate diretamente as solicitações de resumo simples usando seu contexto existente, reservando o início de subagentes para análises complexas.','["Domain_1::Agentic_Architecture_Orchestration", "Domain_5::Context_Management_Reliability", "Scenario_3::Multi_Agent_Research"]','New',0,2.5,0,1783092984117,1783725188825,1783203558653,replace('O monitoramento em produção mostra que consultas de acompanhamento como "resuma o que aprendemos sobre tendências de mercado" levam consistentemente mais de 40 segundos. A investigação revela que o coordenador inicia o subagente de síntese para cada solicitação de resumo, passando mais de 80 mil tokens de descobertas acumuladas. O coordenador já tem essas descobertas em seu contexto por ter orquestrado a pesquisa.\n\nQual é a forma mais eficaz de melhorar o tempo de resposta para esses resumos de acompanhamento?\n\nA - Pré-gerar e armazenar em cache resumos em várias granularidades sempre que novas descobertas se acumulem.\nB - Fazer com que o coordenador trate diretamente as solicitações de resumo simples usando seu contexto existente, reservando o início de subagentes para análises complexas.\nC - Habilitar o cache de prompt no subagente de síntese para reduzir o custo adicional de transferir repetidamente as mesmas descobertas de pesquisa.\nD - Iniciar o subagente de síntese com contexto reduzido e fazer com que ele solicite descobertas específicas ao coordenador sob demanda.','\n',char(10)),replace('O ponto central do problema é reconhecer um **desperdício arquitetural**: o coordenador **já possui** todas as descobertas em seu próprio contexto (porque foi ele quem orquestrou a pesquisa). Mesmo assim, ele está criando um subagente de síntese e **retransmitindo mais de 80 mil tokens** para esse novo agente. Isso gera duas fontes de latência:\n\n1. O tempo de transferência/reprocessamento de um contexto enorme (80k tokens) em uma nova invocação de modelo.\n2. A sobrecarga de instanciar e coordenar um subagente adicional para uma tarefa que não exige capacidade especializada.\n\n**Por que B está correta:**\nUm resumo simples ("resuma o que aprendemos") é exatamente o tipo de tarefa que o coordenador pode responder diretamente, pois o conteúdo já está no contexto dele. Eliminar o salto para o subagente remove completamente a passagem redundante dos 80k tokens e a latência de orquestração. A regra de projeto — *tratar diretamente o que é simples e reservar subagentes para análises genuinamente complexas* — ataca a causa raiz (roteamento desnecessário), não apenas os sintomas. É a solução mais eficaz porque elimina o trabalho em vez de otimizá-lo.\n\n**Por que as demais estão erradas:**\n\n- **A (pré-gerar e cachear resumos):** Otimiza um caso específico, mas introduz complexidade e custo constante: você precisa regenerar resumos em várias granularidades toda vez que novas descobertas chegam, mesmo que ninguém peça resumo. Também corre risco de servir resumos desatualizados e não cobre variações de pergunta ("resuma tendências de mercado" vs. "resuma riscos regulatórios"). É uma otimização especulativa que não resolve o problema estrutural.\n\n- **C (cache de prompt no subagente):** O cache de prompt reduz o **custo de tokens/reprocessamento** de um prefixo repetido, mas o problema aqui é **latência de arquitetura**, não custo. Além disso, cada consulta de acompanhamento é diferente e o subagente continua sendo iniciado desnecessariamente. Você ainda paga a sobrecarga de orquestração e a transferência do contexto que já existe no coordenador. Trata o sintoma errado.\n\n- **D (contexto reduzido + solicitações sob demanda):** Piora a situação em latência: introduz múltiplas idas e voltas (round-trips) entre subagente e coordenador para buscar descobertas específicas. Cada solicitação sob demanda adiciona rodadas de comunicação, tornando o fluxo mais lento e complexo, quando a informação já está toda disponível no coordenador.\n\n**Conclusão para o tech lead:** o antipadrão aqui é delegar cegamente. Antes de otimizar caches ou fluxos de transferência, questione se o salto arquitetural é sequer necessário. Roteamento inteligente (tratar o simples localmente, delegar apenas o complexo) elimina latência na origem.','\n',char(10)),replace('Imagine que você é o chefe de um grupo que já leu um monte de livros e sabe tudo o que está escrito neles. Aí alguém pergunta: "Me conta um resuminho do que a gente aprendeu."\n\nO jeito bobo seria você chamar um amigo, entregar TODOS os livros pesados pra ele carregar até a mesa dele, e só depois ele fazer o resumo. Isso demora muito porque carregar todos aqueles livros leva um tempão!\n\nMas espera... você JÁ leu tudo e tem tudo na cabeça! Então o mais rápido é você mesmo responder o resuminho na hora, sem chamar o amigo nem carregar livro nenhum. Só chame o amigo especialista quando a pergunta for muito difícil de verdade.\n\nPor isso a resposta certa é a **B**.\n\nAs outras ideias não são tão boas:\n- **A:** Ficar preparando resuminhos o tempo todo, mesmo quando ninguém pediu, dá trabalho à toa e pode ficar desatualizado.\n- **C:** Isso só ajuda a gastar menos "energia" para carregar os livros, mas o problema é o tempo perdido chamando o amigo — e você continua fazendo isso.\n- **D:** É pior ainda: o amigo fica pedindo pedacinho por pedacinho, indo e voltando várias vezes, e isso demora muito mais!','\n',char(10)));
INSERT INTO cards VALUES('admin','card_1783092984151_01cahshqd',41,'Ao analisar casos jurídicos complexos que citam vários precedentes, o subagente de análise de documentos processa cada um sequencialmente.',replace('Ao analisar casos jurídicos complexos que citam vários precedentes, o subagente de análise de documentos processa cada um sequencialmente.\n\nAo analisar casos jurídicos complexos que citam vários precedentes, o subagente de análise de documentos processa cada um sequencialmente. Um caso paradigmático que cita 12 precedentes leva mais de 3 minutos para ser analisado completamente.\n\nQual é a forma mais eficaz de reduzir essa latência, preservando a capacidade do coordenador de monitorar e depurar o sistema?\n\n[ ] A - Implementar uma fila de mensagens em que as tarefas de análise de precedentes são processadas de forma assíncrona por um pool de agentes trabalhadores.\n[ ] B - Criar uma hierarquia recursiva de agentes em que os agentes de análise subdividem o trabalho entre agentes filhos até atingir a granularidade de um único precedente.\n[ ] C - Fazer com que o coordenador inicie subagentes de análise de documentos em paralelo, cada um tratando um subconjunto de precedentes, e depois agregue os resultados antes da síntese.\n[ ] D - Permitir que o subagente de análise de documentos inicie seus próprios subagentes especializados dinamicamente quando encontrar casos com muitas citações.','\n',char(10)),'C - Fazer com que o coordenador inicie subagentes de análise de documentos em paralelo, cada um tratando um subconjunto de precedentes, e depois agregue os resultados antes da síntese.','["Domain_1::Agentic_Architecture_Orchestration", "Scenario_3::Multi_Agent_Research"]','New',0,2.5,0,1783092984151,1783725192865,1783203558653,replace('Ao analisar casos jurídicos complexos que citam vários precedentes, o subagente de análise de documentos processa cada um sequencialmente. Um caso paradigmático que cita 12 precedentes leva mais de 3 minutos para ser analisado completamente.\n\nQual é a forma mais eficaz de reduzir essa latência, preservando a capacidade do coordenador de monitorar e depurar o sistema?\n\nA - Implementar uma fila de mensagens em que as tarefas de análise de precedentes são processadas de forma assíncrona por um pool de agentes trabalhadores.\nB - Criar uma hierarquia recursiva de agentes em que os agentes de análise subdividem o trabalho entre agentes filhos até atingir a granularidade de um único precedente.\nC - Fazer com que o coordenador inicie subagentes de análise de documentos em paralelo, cada um tratando um subconjunto de precedentes, e depois agregue os resultados antes da síntese.\nD - Permitir que o subagente de análise de documentos inicie seus próprios subagentes especializados dinamicamente quando encontrar casos com muitas citações.','\n',char(10)),replace('**Por que a alternativa C é a correta:**\n\nO problema central é de **latência causada por processamento sequencial**. Doze precedentes analisados um após o outro somam mais de 3 minutos. A solução mais direta e eficaz para reduzir latência de trabalho sequencial e independente é a **paralelização**: dividir os 12 precedentes em subconjuntos e processá-los ao mesmo tempo (fan-out), reduzindo o tempo total para próximo do tempo de análise de um único lote.\n\nO ponto decisivo, além da performance, é o requisito de **"preservar a capacidade do coordenador de monitorar e depurar o sistema"**. Na opção C, o **coordenador mantém controle explícito**: ele orquestra o fan-out, sabe quantos subagentes iniciou, coleta e agrega os resultados (fan-in) antes da síntese. Essa topologia orquestrador-trabalhador (orchestrator-worker) é observável, previsível e fácil de depurar, pois o fluxo de controle é centralizado e determinístico.\n\n**Por que as demais estão erradas:**\n\n- **A (fila de mensagens assíncrona):** Também paraleliza e reduz latência, mas introduz **processamento assíncrono e desacoplado**. Isso quebra justamente o requisito de observabilidade e depuração: o coordenador perde a visão direta do fluxo, dificultando o rastreamento de qual tarefa está onde, correlação de logs e depuração determinística. Adiciona complexidade de infraestrutura (broker, garantias de entrega, ordenação) desproporcional ao problema.\n\n- **B (hierarquia recursiva até granularidade unitária):** É **over-engineering**. Recursão profunda com muitos níveis de agentes cria uma árvore complexa, com overhead de coordenação, maior consumo de tokens/recursos e uma topologia difícil de monitorar e depurar. Para apenas 12 precedentes, esse nível de subdivisão é injustificado.\n\n- **D (subagentes se autoiniciando dinamicamente):** Delegar ao subagente a criação dinâmica e não controlada de outros subagentes retira a visibilidade do coordenador. O comportamento passa a ser **imprevisível e não determinístico** (número variável de agentes conforme o caso), tornando o sistema difícil de monitorar, custear e depurar — exatamente o oposto do requisito.\n\n**Conclusão:** A opção C equilibra performance (paralelização) com governança (controle centralizado pelo coordenador, agregação explícita e observabilidade), sendo a arquitetura mais adequada ao requisito completo.','\n',char(10)),replace('Imagine que você tem 12 lições de casa para fazer, e fazer uma de cada vez demora muito — mais de 3 minutos!\n\nA ideia esperta (resposta C) é: o "chefe" divide as lições entre vários ajudantes ao mesmo tempo. Assim, em vez de esperar uma terminar para começar a outra, todas são feitas juntas e acaba muito mais rápido. E o mais importante: o chefe continua vendo tudo o que cada ajudante está fazendo, então ele sabe se algo deu errado e consegue arrumar.\n\nPor que as outras não são tão boas?\n- **A:** Também usa ajudantes, mas eles trabalham "escondidos", e o chefe não consegue ver bem o que cada um faz — fica difícil de vigiar.\n- **B:** Cada ajudante chama outros ajudantes, que chamam outros, virando uma bagunça gigante de gente. É complicado demais para uma tarefa pequena.\n- **D:** Os ajudantes começam a chamar mais ajudantes sozinhos, sem avisar o chefe. Aí o chefe se perde e não consegue mais controlar.\n\nPor isso, a melhor é a C: rápido porque todos trabalham juntos, e organizado porque o chefe continua no comando.','\n',char(10)));
INSERT INTO cards VALUES('admin','card_1783092984157_6gqzvme55',42,'O agente coordenador tem `AgentDefinitions` configuradas para todos os quatro subagentes especializados, cada um com descrições, prompts e restrições de ferramentas apropriadas.',replace('O agente coordenador tem `AgentDefinitions` configuradas para todos os quatro subagentes especializados, cada um com descrições, prompts e restrições de ferramentas apropriadas.\n\nO agente coordenador tem `AgentDefinitions` configuradas para todos os quatro subagentes especializados, cada um com descrições, prompts e restrições de ferramentas apropriadas. Durante os testes, você percebe que o coordenador raciocina corretamente sobre quando delegar — ele gera mensagens como "Vou pedir ao agente de busca na web que encontre fontes sobre este tópico" — mas nenhuma execução de subagente jamais ocorre. O coordenador então prossegue como se a delegação tivesse acontecido e continua com informações incompletas. Os logs não mostram erros.\n\nQual é a causa mais provável?\n\n[ ] A - A configuração `max_tokens` do coordenador é baixa demais, fazendo com que a invocação da ferramenta Task seja truncada antes que o parâmetro de tipo do subagente possa ser especificado.\n[ ] B - As `AgentDefinitions` estão configuradas corretamente, mas o prompt de sistema do coordenador não lista explicitamente os tipos de subagentes disponíveis, impedindo que o modelo saiba que eles podem ser invocados.\n[ ] C - A configuração allowedTools do coordenador não inclui "Task", então, embora ele possa raciocinar sobre a delegação, não consegue invocar a ferramenta necessária para iniciar subagentes.\n[ ] D - O isolamento de contexto dos subagentes significa que as descrições de tarefa do coordenador não chegam automaticamente aos subagentes; você precisa configurar o encaminhamento explícito de contexto em ClaudeAgentOptions.','\n',char(10)),'[ ] C - A configuração allowedTools do coordenador não inclui "Task", então, embora ele possa raciocinar sobre a delegação, não consegue invocar a ferramenta necessária para iniciar subagentes.','["Domain_1::Agentic_Architecture_Orchestration", "Domain_2::Tool_Design_MCP_Integration", "Domain_5::Context_Management_Reliability", "Scenario_3::Multi_Agent_Research"]','New',0,2.5,0,1783092984157,1783725196960,1783203558653,'TRADUÇÃO:',replace('O agente coordenador tem `AgentDefinitions` configuradas para todos os quatro subagentes especializados, cada um com descrições, prompts e restrições de ferramentas apropriadas. Durante os testes, você percebe que o coordenador raciocina corretamente sobre quando delegar — ele gera mensagens como "Vou pedir ao agente de busca na web que encontre fontes sobre este tópico" — mas nenhuma execução de subagente jamais ocorre. O coordenador então prossegue como se a delegação tivesse acontecido e continua com informações incompletas. Os logs não mostram erros.\n\nQual é a causa mais provável?\n\n[ ] A - A configuração `max_tokens` do coordenador é baixa demais, fazendo com que a invocação da ferramenta Task seja truncada antes que o parâmetro de tipo do subagente possa ser especificado.\n[ ] B - As `AgentDefinitions` estão configuradas corretamente, mas o prompt de sistema do coordenador não lista explicitamente os tipos de subagentes disponíveis, impedindo que o modelo saiba que eles podem ser invocados.\n[ ] C - A configuração allowedTools do coordenador não inclui "Task", então, embora ele possa raciocinar sobre a delegação, não consegue invocar a ferramenta necessária para iniciar subagentes.\n[ ] D - O isolamento de contexto dos subagentes significa que as descrições de tarefa do coordenador não chegam automaticamente aos subagentes; você precisa configurar o encaminhamento explícito de contexto em ClaudeAgentOptions.\n\n---\nEXPLICAÇÃO PARA TECH LEAD:\n\nA resposta correta é **C** e o diagnóstico apresentado é muito preciso.\n\n**Por que C é correto:**\n\nO comportamento descrito é a assinatura clássica de uma restrição de ferramentas: o modelo (LLM) está gerando a lógica correta ("Vou delegar para...") mas não consegue executar a ação. Isso indica que:\n\n1. **O raciocínio está funcional**: O coordenador compreende quando e por que deveria delegar (evidência de que as AgentDefinitions estão bem estruturadas e o prompt está adequado).\n\n2. **A invocação está bloqueada**: Não há execução real de subagentes, o que aponta para uma limitação técnica, não conceitual.\n\n3. **Sem erros nos logs**: Isso é crucial. Se houvesse uma falha de execução (low max_tokens, contexto isolado), haveria mensagens de erro. A ausência de erros com comportamento incompleto aponta para uma restrição silenciosa: a ferramenta "Task" simplesmente não está autorizada.\n\n4. **A ferramenta Task é obrigatória**: Em arquiteturas multi-agentes Claude, a delegação é implementada através da ferramenta "Task". Se `allowedTools` não incluir "Task", o modelo não pode fazer a chamada, mesmo que gere a intenção correta.\n\n**Por que as outras estão erradas:**\n\n**A - max_tokens baixo**: Causaria truncamento visível nos logs ou geraria tokens de parada prematura. Além disso, truncamento não permitiria que o modelo gerasse mensagens inteligentes de raciocínio ("Vou pedir ao agente..."); ele pararia no meio. A saída aqui é clara e bem formada.\n\n**B - Prompt sem lista de subagentes**: O fato de o coordenador estar racionalizando corretamente sobre QUAIS subagentes invocar (busca na web, etc.) prova que ele sabe dos tipos disponíveis. Se isso fosse o problema, ele não saberia diferenciar entre subagentes especializados.\n\n**D - Isolamento de contexto**: Este é um problema de **recebimento de contexto nos subagentes**, não de **execução a partir do coordenador**. Além disso, ClaudeAgentOptions é mecanismo de passagem de parâmetros, não de configuração de isolamento. O problema aqui está na *invocação*, não na propagação de contexto.\n\n**Padrão de correção:**\n```python\ncoordinator = Agent(\n    model="claude-3-5-sonnet-20241022",\n    tools=[...],\n    allowedTools=["Task", ...other_tools]  # Task DEVE estar aqui\n)\n```','\n',char(10)),replace('Imagina que você é um chefe de um time. Você sabe que precisa mandar uma mensagem para seu colega Web-Finder para procurar informações na internet. Você até **pensa e fala** direito: "Vou chamar o Web-Finder para me ajudar".\n\nMas tem um problema: você não tem permissão para usar o telefone! É como se alguém tivesse tirado sua ferramenta de comunicação (o telefone/ferramenta "Task"). \n\nEntão você fica falando "Vou chamar, vou chamar..." mas nunca consegue realmente fazer a chamada. Você continua fingindo que chamou e tenta resolver sozinho com as informações que já tem — mesmo que incompletas.\n\n**A resposta correta (C)** diz exatamente isso: o coordenador não tem permissão de usar a ferramenta "Task" que é necessária para chamar os subagentes.\n\n**As outras respostas estão erradas porque:**\n- **A**: Se o telefone fosse quebrado, haveria aviso de erro — aqui não tem aviso.\n- **B**: O chefe SABE que Web-Finder existe, senão não saberia falar sobre ele. Ele está pensando certo!\n- **D**: Isso seria um problema do lado de quem **recebe** a mensagem, não do lado de quem **envia**.','\n',char(10)));
INSERT INTO cards VALUES('admin','card_1783092984163_9i2ftk941',43,'Sua ferramenta de exploração de base de código armazena IDs de sessão para permitir que os engenheiros continuem investigações entre sessões de trabalho.',replace('Sua ferramenta de exploração de base de código armazena IDs de sessão para permitir que os engenheiros continuem investigações entre sessões de trabalho.\n\nSua ferramenta de exploração de base de código armazena IDs de sessão para permitir que os engenheiros continuem investigações entre sessões de trabalho. Um engenheiro passou uma hora ontem analisando um módulo de autenticação legado, acumulando contexto sobre sua arquitetura e dependências. Ele quer continuar hoje. O ID da sessão é válido, mas o controle de versão mostra que 3 dos 12 arquivos que o agente leu anteriormente foram modificados durante a noite pelo merge de um colega.\n\nQual abordagem melhor equilibra eficiência e precisão?\n\n[ ] A - Retomar a sessão sem informar o agente sobre os arquivos alterados\n[ ] B - Iniciar uma nova sessão para garantir que o agente trabalhe com o estado atual da base de código sem suposições desatualizadas\n[ ] C - Retomar a sessão e informar o agente sobre quais arquivos específicos mudaram para uma reanálise direcionada\n[ ] D - Retomar a sessão e imediatamente fazer o agente reler todos os 12 arquivos previamente analisados','\n',char(10)),'[ ] C - Retomar a sessão e informar o agente sobre quais arquivos específicos mudaram para uma reanálise direcionada','["Domain_5::Context_Management_Reliability", "Domain_1::Agentic_Architecture_Orchestration", "Scenario_4::Developer_Productivity"]','New',0,2.5,0,1783092984163,1783725200783,1783203558653,replace('TRADUÇÃO:\nSua ferramenta de exploração de base de código armazena IDs de sessão para permitir que os engenheiros continuem investigações entre sessões de trabalho. Um engenheiro passou uma hora ontem analisando um módulo de autenticação legado, acumulando contexto sobre sua arquitetura e dependências. Ele quer continuar hoje. O ID da sessão é válido, mas o controle de versão mostra que 3 dos 12 arquivos que o agente leu anteriormente foram modificados durante a noite pelo merge de um colega.\n\nQual abordagem melhor equilibra eficiência e precisão?\n\n[ ] A - Retomar a sessão sem informar o agente sobre os arquivos alterados\n[ ] B - Iniciar uma nova sessão para garantir que o agente trabalhe com o estado atual da base de código sem suposições desatualizadas\n[ ] C - Retomar a sessão e informar o agente sobre quais arquivos específicos mudaram para uma reanálise direcionada\n[ ] D - Retomar a sessão e imediatamente fazer o agente reler todos os 12 arquivos previamente analisados','\n',char(10)),replace('ANÁLISE PARA TECH LEAD:\n\nA resposta correta é **C** porque representa o equilíbrio ótimo entre eficiência e precisão em um cenário de continuidade de investigação com base de código em evolução.\n\n**Por que C é a melhor escolha:**\n- **Preserva contexto valioso**: A hora de análise anterior não é descartada. O engenheiro mantém sua compreensão da arquitetura geral e dependências do módulo.\n- **Atualiza apenas o necessário**: Apenas 3 dos 12 arquivos (25%) sofreram modificações. Reanalisar apenas esses arquivos é eficiente.\n- **Garante precisão seletiva**: Informar quais arquivos mudaram permite ao agente/engenheiro focar em mudanças reais, evitando suposições desatualizadas apenas nesses pontos críticos.\n- **Reduz desperdício computacional**: Não há releitura desnecessária dos 9 arquivos inalterados.\n- **Mantém rastreabilidade**: O agente sabe exatamente qual contexto pode estar comprometido.\n\n**Por que as alternativas estão erradas:**\n\n**A - Retomar sem informar sobre alterações:**\n- Introduz risco de precisão crítico\n- O agente/engenheiro pode tomar decisões baseadas em suposições desatualizadas sobre os 3 arquivos modificados\n- Em um módulo de autenticação (segurança-crítico), isso é particularmente perigoso\n- Não há vantagem de eficiência: o silêncio não economiza tempo, apenas cria débito técnico\n\n**B - Iniciar nova sessão:**\n- Maximiza a precisão, mas sacrifica TODA a eficiência\n- Desperdiça a hora de trabalho anterior (1 hora = perda)\n- Força releitura de 9 arquivos inalterados\n- Impede reutilização de insights contextuais já adquiridos (arquitetura, dependências, padrões)\n- Apenas justificável se a base de código inteira mudou significativamente, não é o caso aqui\n\n**D - Reler todos os 12 arquivos:**\n- Menos eficiente que C, mas mais seguro que A ou B?\n- Não: C já garante a segurança necessária\n- Desperdiça tempo relendo 75% do conteúdo inalterado\n- Melhor que D seria o padrão de "reler apenas os 3 alterados", que é exatamente C\n\n**Resumo técnico:**\nC implementa a estratégia de "invalidação seletiva de cache" com revalidação direcionada. É o padrão correto em sistemas distribuídos e de análise de código onde você quer balancear hot-start com freshness.','\n',char(10)),replace('Imagina que você está montando um quebra-cabeça gigante. Ontem você passou uma hora estudando como as peças se encaixam, especialmente 12 peças de um castelo.\n\nHoje você quer continuar, mas descobriu que alguém mexeu em 3 dessas 12 peças durante a noite. Como você faz?\n\n**Opção A (péssima):** Continuar fingindo que as 3 peças não mudaram\n- Problema: Você pode montar errado e o quebra-cabeça fica estranho\n\n**Opção B (muito lenta):** Jogar tudo fora e começar do zero\n- Problema: Você perde toda a hora que gastou ontem estudando as 9 peças que não mudaram\n\n**Opção C (melhor!):** Dizer exatamente quais 3 peças foram mexidas e estudá-las de novo, enquanto você lembra das outras 9 que não mudaram\n- Vantagem: Você continua de onde parou, mas atualiza só o que precisa\n- Rápido E correto!\n\n**Opção D (um pouco lenta):** Estudar todas as 12 peças de novo\n- Problema: Trabalho desnecessário relendo as 9 que não mudaram\n\n**A resposta certa é C** porque você economiza tempo (não refaz trabalho desnecessário) E fica certo (sabe exatamente o que mudou).','\n',char(10)));
INSERT INTO cards VALUES('admin','card_1783092984170_hx0l5f3gl',44,'Um engenheiro usou o agente ontem para analisar um módulo de autenticação legado, identificando duas abordagens distintas de refatoração: extrair um microsserviço versus refatorar no local.',replace('Um engenheiro usou o agente ontem para analisar um módulo de autenticação legado, identificando duas abordagens distintas de refatoração: extrair um microsserviço versus refatorar no local.\n\nUm engenheiro usou o agente ontem para analisar um módulo de autenticação legado, identificando duas abordagens distintas de refatoração: extrair um microsserviço versus refatorar no local. Hoje, ele quer explorar ambas as abordagens em profundidade — fazendo o agente propor mudanças de código específicas para cada uma — antes de decidir qual implementar.\n\nQual é a maneira mais eficaz de estruturar essa exploração?\n\n[ ] A - Retomar a sessão de ontem para explorar a primeira abordagem e, então, iniciar uma nova sessão para a segunda, recriando manualmente o contexto original.\n[ ] B - Iniciar duas sessões novas, fornecendo manualmente um resumo das descobertas da análise de ontem para estabelecer o contexto.\n[ ] C - Retomar a sessão de ontem e explorar ambas as abordagens sequencialmente dentro da mesma thread de conversa.\n[ ] D - Usar `fork_session` para criar duas ramificações a partir da análise de ontem, explorando uma abordagem em cada ramificação.','\n',char(10)),'[ ] D - Usar `fork_session` para criar duas ramificações a partir da análise de ontem, explorando uma abordagem em cada ramificação.','["Domain_3::Claude_Code_Configuration_Workflows", "Domain_5::Context_Management_Reliability", "Scenario_2::Code_Generation_Claude_Code"]','New',0,2.5,0,1783092984170,1783725204808,1783203558653,replace('**TRADUÇÃO:**\nUm engenheiro usou o agente ontem para analisar um módulo de autenticação legado, identificando duas abordagens distintas de refatoração: extrair um microsserviço versus refatorar no local. Hoje, ele quer explorar ambas as abordagens em profundidade — fazendo o agente propor mudanças de código específicas para cada uma — antes de decidir qual implementar.\n\nQual é a maneira mais eficaz de estruturar essa exploração?\n\n[ ] A - Retomar a sessão de ontem para explorar a primeira abordagem e, então, iniciar uma nova sessão para a segunda, recriando manualmente o contexto original.\n[ ] B - Iniciar duas sessões novas, fornecendo manualmente um resumo das descobertas da análise de ontem para estabelecer o contexto.\n[ ] C - Retomar a sessão de ontem e explorar ambas as abordagens sequencialmente dentro da mesma thread de conversa.\n[ ] D - Usar `fork_session` para criar duas ramificações a partir da análise de ontem, explorando uma abordagem em cada ramificação.','\n',char(10)),replace('**EXPLICAÇÃO PARA TECH LEAD:**\n\nA resposta correta é **D - Usar `fork_session`** porque esta funcionalidade foi especificamente projetada para cenários onde você precisa explorar múltiplas caminhos divergentes mantendo um contexto comum.\n\n**Por que D é a melhor escolha:**\n\n1. **Preservação perfeita do contexto**: O `fork_session` cria ramificações a partir de um ponto específico da conversa, mantendo todo o histórico, contexto e análise previamente realizada. Ambas as abordagens começam com exatamente o mesmo entendimento do problema.\n\n2. **Exploração paralela de hipóteses**: Permite explorar a abordagem A (microsserviço) em uma ramificação e a abordagem B (refatoração in-loco) em outra, completamente independentes.\n\n3. **Comparação eficiente**: Ao término, você pode comparar facilmente as propostas de código específicas geradas em cada ramificação, já que ambas partiram do mesmo ponto de análise.\n\n4. **Sem redundância**: Você não refaz a análise inicial; reutiliza-a como base para ambas as explorações.\n\n**Por que as alternativas estão erradas:**\n\n- **A (Retomar + nova sessão)**: Força recriação manual do contexto na segunda exploração, criando inconsistência potencial e perda de eficiência. Além disso, divergências entre as explorações podem surgir de interpretações diferentes do contexto recriado.\n\n- **B (Duas sessões novas com resumo manual)**: Ainda mais problemático. Resumos manuais são incompletos, passíveis de erro e não preservam a riqueza do contexto original. O agente pode perder nuances importantes da análise anterior.\n\n- **C (Mesma thread, sequencial)**: Embora mantenha contexto, explorar ambas as abordagens sequencialmente na mesma conversa cria contamination entre elas. As recomendações para a segunda abordagem podem ser influenciadas pelas discussões da primeira. Além disso, fica mais difícil comparar "o que teria acontecido se..." sem as interações anteriores influenciando o pensamento.','\n',char(10)),replace('**Para uma criança de 10 anos:**\n\nImagina que você está brincando de "escolher o caminho" em um jogo de vídeo. Você encontrou um mapa interessante ontem e descobriu duas estradas diferentes que você poderia seguir: uma que leva para a esquerda (microsserviço) e outra para a direita (refatoração).\n\nHoje você quer explorar **as duas** antes de decidir qual é melhor.\n\nA melhor forma de fazer isso é usar `fork_session` — é como tirar uma **fotografia do mapa exatamente como está agora** e depois fazer duas cópias dessa foto. Em uma cópia, você segue a estrada da esquerda. Na outra cópia, você segue a estrada da direita. Assim, você explora os dois caminhos completamente, mas sempre começando do mesmo lugar!\n\nSe você fizesse de outro jeito (A, B ou C), seria tipo:\n- **A**: Seguir o caminho da esquerda, voltar, e depois tentar seguir o caminho da direita — mas você poderia esquecer onde você estava!\n- **B**: Descrever com palavras o mapa de ontem e depois desenhar de novo — seu desenho novo poderia ser diferente do original.\n- **C**: Seguir os dois caminhos na mesma trilha ao mesmo tempo — ficaria confuso!','\n',char(10)));
INSERT INTO cards VALUES('admin','card_1783092984176_7b8x7cfzo',45,'Um engenheiro pede ao seu agente para identificar caminhos de código não testados em um módulo legado de processamento de pagamentos que abrange 45 arquivos.',replace('Um engenheiro pede ao seu agente para identificar caminhos de código não testados em um módulo legado de processamento de pagamentos que abrange 45 arquivos.\n\nUm engenheiro pede ao seu agente para identificar caminhos de código não testados em um módulo legado de processamento de pagamentos que abrange 45 arquivos. Após ler os primeiros 8 arquivos-fonte, as respostas do agente estão ficando visivelmente menos precisas — ele está esquecendo padrões de código discutidos anteriormente e ainda não localizou todos os arquivos de teste nem rastreou os fluxos de pagamento críticos.\n\nQual é a abordagem mais eficaz para concluir essa investigação?\n\n[ ] A - Documentar todas as descobertas atuais em um relatório de resumo, limpar o contexto completamente e, então, usar esse relatório como única referência para continuar a investigação.\n[ ] B - Criar subagentes para investigar perguntas específicas (por exemplo, "encontrar todos os arquivos de teste do processamento de pagamentos", "rastrear as dependências do fluxo de reembolso") enquanto o agente principal coordena as descobertas e preserva o entendimento de alto nível.\n[ ] C - Limpar o contexto com /clear e, então, reler seletivamente apenas os arquivos mais críticos descobertos até agora, gravando as descobertas-chave em um arquivo de rascunho que persiste entre as redefinições de contexto.\n[ ] D - Passar a usar o Grep para buscar nomes de funções específicas em vez de ler arquivos inteiros, reduzindo o conteúdo carregado no contexto para a exploração restante.','\n',char(10)),'[ ] B - Criar subagentes para investigar perguntas específicas (por exemplo, "encontrar todos os arquivos de teste do processamento de pagamentos", "rastrear as dependências do fluxo de reembolso") enquanto o agente principal coordena as descobertas e preserva o entendimento de alto nível.','["Domain_5::Context_Management_Reliability", "Domain_1::Agentic_Architecture_Orchestration", "Domain_2::Tool_Design_MCP_Integration", "Scenario_4::Developer_Productivity"]','New',0,2.5,0,1783092984176,1783725209486,1783203558653,replace('TRADUÇÃO:\nUm engenheiro pede ao seu agente para identificar caminhos de código não testados em um módulo legado de processamento de pagamentos que abrange 45 arquivos. Após ler os primeiros 8 arquivos-fonte, as respostas do agente estão ficando visivelmente menos precisas — ele está esquecendo padrões de código discutidos anteriormente e ainda não localizou todos os arquivos de teste nem rastreou os fluxos de pagamento críticos.\n\nQual é a abordagem mais eficaz para concluir essa investigação?\n\n[ ] A - Documentar todas as descobertas atuais em um relatório de resumo, limpar o contexto completamente e, então, usar esse relatório como única referência para continuar a investigação.\n[ ] B - Criar subagentes para investigar perguntas específicas (por exemplo, "encontrar todos os arquivos de teste do processamento de pagamentos", "rastrear as dependências do fluxo de reembolso") enquanto o agente principal coordena as descobertas e preserva o entendimento de alto nível.\n[ ] C - Limpar o contexto com /clear e, então, reler seletivamente apenas os arquivos mais críticos descobertos até agora, gravando as descobertas-chave em um arquivo de rascunho que persiste entre as redefinições de contexto.\n[ ] D - Passar a usar o Grep para buscar nomes de funções específicas em vez de ler arquivos inteiros, reduzindo o conteúdo carregado no contexto para a exploração restante.','\n',char(10)),replace('EXPLICAÇÃO PARA TECH LEAD:\n\nA resposta correta é a **alternativa B**, pois aborda o problema fundamental que está ocorrendo: a degradação da qualidade das respostas do agente conforme a janela de contexto fica saturada.\n\n**Por que B é a melhor escolha:**\n\nO problema diagnosticado é a **degradação contextual** — após 8 arquivos, o agente está perdendo informações previamente processadas (padrões de código, mapeamento de fluxos). A alternativa B resolve isso através de:\n\n1. **Especialização de tarefas**: Subagentes dedicados têm "janelas de contexto" focadas em problemas específicos, evitando a dilução de atenção\n2. **Decomposição inteligente**: Questões bem-delimitadas ("encontrar arquivos de teste", "rastrear fluxos de reembolso") são mais eficientes do que exploração genérica\n3. **Preservação de arquitetura**: O agente principal mantém a visão sistêmica e coordena, funcionando como orquestrador em vez de executor único\n4. **Escalabilidade**: Subagentes podem trabalhar em paralelo, reduzindo o tempo total\n5. **Qualidade**: Cada subagente tem contexto "limpo" para sua tarefa, não acumulando ruído\n\n**Por que as alternativas estão erradas:**\n\n**Alternativa A** - Documentar tudo e limpar contexto completamente:\n- Reduz drasticamente a capacidade de análise futura (relatório ≠ entendimento completo)\n- Usa apenas texto estático como referência, perdendo a capacidade analítica do agente\n- O agente terá dificuldade em conectar descobertas futuras com padrões documentados\n- Ineficiente em tempo, pois voltaria ao ponto zero\n\n**Alternativa C** - Limpar contexto e reler seletivamente:\n- Ainda sofre do mesmo problema: ler 37 arquivos restantes vai saturar o contexto novamente\n- Arquivo de rascunho persiste, mas não resolve a sobrecarga contextual estruturalmente\n- É apenas um "patch" temporário, não uma solução sustentável para 45 arquivos\n\n**Alternativa D** - Usar Grep em vez de ler arquivos inteiros:\n- Funciona bem para buscas específicas, mas não consegue identificar **padrões e anti-padrões** — que é exatamente o que o agente precisa para detectar caminhos não testados\n- Grep encontra nomes de funções, não lógica complexa de fluxos de pagamento\n- Inadequado para análise de cobertura de testes, que requer compreensão semântica\n- Perde contexto de relacionamento entre componentes','\n',char(10)),replace('Imagina que você está investigando um mistério em uma mansão gigante com 45 salas. Você já explorou 8 salas e começou a ficar confuso, esquecendo de pistas que havia visto antes.\n\nVocê tem 4 opções:\n\n**Opção A** - Escrever um relatório sobre tudo que descobriu até agora, apagar tudo da memória e tentar continuar usando só o relatório. Problema: é como tentar resolver um quebra-cabeça usando só instruções escritas — não funciona bem!\n\n**Opção B** - Chamar amigos para ajudar! Um amigo procura só pelos "mapas das salas", outro procura só pelo "tesouro escondido", e você coordena tudo. Cada um fica focado em uma coisa, então ninguém fica confuso. \n\n**Opção C** - Apagar a memória, reler só as salas mais importantes e escrever anotações em um caderno. Problema: quando você for às outras 37 salas, vai ficar confuso de novo, porque sua memória vai ficar pequena demais!\n\n**Opção D** - Em vez de explorar as salas inteiras, só procurar pelas coisas com nomes específicos usando uma lanterna. Problema: você não vai conseguir ver os padrões e dicas secretas que aparecem quando você explora completo!\n\nA **melhor opção é B** — dividir o trabalho em pequenas tarefas específicas, com pessoas diferentes focadas em cada uma. Assim todo mundo consegue fazer bem o seu trabalho!','\n',char(10)));
INSERT INTO cards VALUES('admin','card_1783092984182_5tj5w72sd',46,'Um desenvolvedor pede ao agente para investigar por que um endpoint de API específico retorna erros 500 de forma intermitente.',replace('Um desenvolvedor pede ao agente para investigar por que um endpoint de API específico retorna erros 500 de forma intermitente.\n\nUm desenvolvedor pede ao agente para investigar por que um endpoint de API específico retorna erros 500 de forma intermitente. A base de código tem mais de 200 arquivos e o desenvolvedor não sabe quais componentes estão envolvidos. O agente precisa rastrear o erro pelas camadas de roteamento, middleware, lógica de negócio e banco de dados.\n\nQual abordagem de decomposição de tarefas seria mais eficaz?\n\n[ ] A - Fazer o agente primeiro criar um plano abrangente mapeando todos os caminhos de código pelo endpoint antes de iniciar qualquer exploração de arquivos ou leitura de código.\n[ ] B - Fazer o agente gerar dinamicamente subtarefas de investigação com base no que descobre a cada passo, adaptando seu plano de exploração à medida que novas informações sobre o caminho do erro surgem.\n[ ] C - Definir antecipadamente uma sequência fixa de passos de investigação — fazer grep de padrões de erro, depois ler os tratadores de erro, depois verificar as consultas ao banco de dados, depois examinar o middleware — executando cada passo independentemente das descobertas intermediárias.\n[ ] D - Executar agentes de trabalho paralelos que investigam simultaneamente todas as quatro camadas e, então, sintetizar suas descobertas para identificar onde o erro se origina.','\n',char(10)),'[ ] B - Fazer o agente gerar dinamicamente subtarefas de investigação com base no que descobre a cada passo, adaptando seu plano de exploração à medida que novas informações sobre o caminho do erro surgem.','["Domain_1::Agentic_Architecture_Orchestration", "Domain_5::Context_Management_Reliability", "Scenario_4::Developer_Productivity"]','New',0,2.5,0,1783092984182,1783725213847,1783203558653,replace('TRADUÇÃO:\nUm desenvolvedor pede ao agente para investigar por que um endpoint de API específico retorna erros 500 de forma intermitente. A base de código tem mais de 200 arquivos e o desenvolvedor não sabe quais componentes estão envolvidos. O agente precisa rastrear o erro pelas camadas de roteamento, middleware, lógica de negócio e banco de dados.\n\nQual abordagem de decomposição de tarefas seria mais eficaz?\n\n[ ] A - Fazer o agente primeiro criar um plano abrangente mapeando todos os caminhos de código pelo endpoint antes de iniciar qualquer exploração de arquivos ou leitura de código.\n[ ] B - Fazer o agente gerar dinamicamente subtarefas de investigação com base no que descobre a cada passo, adaptando seu plano de exploração à medida que novas informações sobre o caminho do erro surgem.\n[ ] C - Definir antecipadamente uma sequência fixa de passos de investigação — fazer grep de padrões de erro, depois ler os tratadores de erro, depois verificar as consultas ao banco de dados, depois examinar o middleware — executando cada passo independentemente das descobertas intermediárias.\n[ ] D - Executar agentes de trabalho paralelos que investigam simultaneamente todas as quatro camadas e, então, sintetizar suas descobertas para identificar onde o erro se origina.','\n',char(10)),replace('EXPLICAÇÃO PARA TECH LEAD:\n\nA resposta correta é **B - Decomposição Dinâmica e Adaptativa**.\n\n**Por que B é a melhor escolha:**\n\nA investigação de um erro intermitente em uma base de código com 200+ arquivos é um problema fundamentalmente exploratório onde a informação não é completa no início. A abordagem B implementa um ciclo de **aprendizado iterativo**:\n\n1. **Descoberta orientada**: Ao investigar o endpoint, o agente pode rapidamente identificar qual rota está sendo chamada, qual middleware está envolvido e qual handler processa a requisição.\n\n2. **Priorização inteligente**: Com essas descobertas iniciais, o agente gera subtarefas mais direcionadas. Se descobrir que o erro vem de uma consulta ao banco de dados, pode focar ali; se for timeout de cache, investigará ali.\n\n3. **Eficiência de recursos**: Em vez de explorar caminhos irrelevantes, o agente segue a trilha do erro, reduzindo drasticamente a quantidade de código a examinar.\n\n4. **Tratamento de erros intermitentes**: Essa abordagem é particularmente eficaz para bugs intermitentes, pois permite investigar condições de corrida, timeouts e estado compartilhado conforme o agente aprende sobre o contexto.\n\n**Por que as alternativas estão erradas:**\n\n**Alternativa A (Plano abrangente prévio)**: \n- Mapear todos os caminhos de código antes de exploração é impraticável com 200+ arquivos\n- Sem informação sobre qual endpoint específico ou qual caminho é chamado, o plano será redundante\n- Consome tokens e tempo de planejamento sem agregar valor inicial\n- Não se adapta ao que é descoberto\n\n**Alternativa C (Sequência fixa independente)**:\n- A rigidez de executar passos pré-definidos ignora descobertas intermediárias\n- Fazer grep de padrões de erro em toda a base de código sem saber onde começar é ineficiente\n- Examinar middleware e banco de dados independentemente pode levar a conclusões desencontradas\n- Não estabelece causação entre camadas — apenas coleta dados desorganizados\n- Ideal para investigações documentadas, não para troubleshooting exploratório\n\n**Alternativa D (Paralelismo indiscriminado)**:\n- Executar 4 agentes investigando simultaneamente toda a base de código amplifica o custo\n- Sem informação inicial sobre qual componente está envolvido, há muito ruído paralelo\n- A síntese de descobertas paralelas é mais complexa que uma investigação sequencial informada\n- Gera falsos positivos quando agentes parallelos encontram múltiplas correlações\n- Mais apropriado quando as camadas são bem isoladas e independentes\n\n**Padrão reconhecido**: A abordagem B implementa **progressive refinement** ou **hill-climbing problem solving**, que é comprovadamente mais eficaz em espaços de busca grandes e parcialmente estruturados.','\n',char(10)),replace('Imagina que você perdeu uma chave em uma casa muito grande com 200 quartos.\n\n**Alternativa A (Plano prévio)**: É como desenhar um mapa de todos os quartos antes de procurar. Demora muito tempo e você ainda não sabe onde começar.\n\n**Alternativa B (Descobrir enquanto procura)**: É como começar a procurar logicamente. Você verifica a entrada (roteamento) → a cozinha (middleware) → o escritório (lógica) → verifica se caiu perto da porta da garagem (banco de dados). Conforme você procura, você descobre em que parte da casa foi provavelmente perdida, e depois focar ali. Muito mais rápido!\n\n**Alternativa C (Passos fixos independentes)**: É como fazer uma lista: "1º procurar em todas as portas abertas, 2º procurar sob todos os tapetes, 3º procurar em todos os armários, 4º procurar no jardim" — sem deixar de pensar se a chave estava realmente no jardim ou se já foi achada na cozinha.\n\n**Alternativa D (Procurar em 4 quartos ao mesmo tempo)**: É como colocar 4 amigos para procurar simultaneamente em todos os 200 quartos. Gasta muita energia, eles se confundem uns aos outros, e fica difícil entender quem realmente encontrou a chave.\n\n**A resposta B é melhor porque você aprende conforme procura e muda sua estratégia com base no que descobre.** 🔍','\n',char(10)));
INSERT INTO cards VALUES('admin','card_1783092984187_srt9g2ste',47,'Seu agente analisou um módulo de serviço complexo — lendo 23 arquivos-fonte, rastreando fluxos de requisição e identificando padrões de tratamento de erros.',replace('Seu agente analisou um módulo de serviço complexo — lendo 23 arquivos-fonte, rastreando fluxos de requisição e identificando padrões de tratamento de erros.\n\nSeu agente analisou um módulo de serviço complexo — lendo 23 arquivos-fonte, rastreando fluxos de requisição e identificando padrões de tratamento de erros. Um desenvolvedor quer comparar duas estratégias de teste antes de se comprometer com uma: testes ponta a ponta com serviços externos simulados (mocked) versus testes de snapshot que capturam as saídas esperadas. Ele precisa desenvolver ambas as abordagens de forma independente para avaliar os trade-offs.\n\nComo você deve gerenciar as sessões?\n\n[ ] A - Exportar as descobertas principais da sessão de análise para um arquivo e, então, criar duas novas sessões que referenciem esse arquivo.\n[ ] B - Retomar a sessão de análise com `fork_session` habilitado, criando uma ramificação separada para cada estratégia de teste.\n[ ] C - Iniciar duas sessões novas, fazendo cada uma reler os arquivos-fonte relevantes antes de começar.\n[ ] D - Continuar na sessão original, desenvolvendo primeiro os testes ponta a ponta e depois os testes de snapshot, sequencialmente.','\n',char(10)),'[ ] B - Retomar a sessão de análise com `fork_session` habilitado, criando uma ramificação separada para cada estratégia de teste.','["Domain_5::Context_Management_Reliability", "Domain_3::Claude_Code_Configuration_Workflows", "Scenario_4::Developer_Productivity"]','New',0,2.5,0,1783092984187,1783725217838,1783203558653,replace('## TRADUÇÃO\n\n**Pergunta:**\nSeu agente analisou um módulo de serviço complexo — lendo 23 arquivos-fonte, rastreando fluxos de requisição e identificando padrões de tratamento de erros. Um desenvolvedor quer comparar duas estratégias de teste antes de se comprometer com uma: testes ponta a ponta com serviços externos simulados (mocked) versus testes de snapshot que capturam as saídas esperadas. Ele precisa desenvolver ambas as abordagens de forma independente para avaliar os trade-offs.\n\nComo você deve gerenciar as sessões?\n\n[ ] A - Exportar as descobertas principais da sessão de análise para um arquivo e, então, criar duas novas sessões que referenciem esse arquivo.\n[ ] B - Retomar a sessão de análise com `fork_session` habilitado, criando uma ramificação separada para cada estratégia de teste.\n[ ] C - Iniciar duas sessões novas, fazendo cada uma reler os arquivos-fonte relevantes antes de começar.\n[ ] D - Continuar na sessão original, desenvolvendo primeiro os testes ponta a ponta e depois os testes de snapshot, sequencialmente.','\n',char(10)),replace('## EXPLICAÇÃO PARA TECH LEAD\n\nA resposta correta é **B - Retomar a sessão com `fork_session` habilitado**.\n\n**Por que B é a melhor escolha:**\n\n1. **Preservação do contexto analítico**: A sessão original já contém todo o contexto da análise profunda (23 arquivos lidos, fluxos rastreados, padrões identificados). O `fork_session` permite criar ramificações que herdam esse contexto completo, sem perder nenhuma informação coletada.\n\n2. **Independência com continuidade**: Cada ramificação (fork) trabalha de forma isolada - mudanças em uma estratégia de teste não afetam a outra. Ao mesmo tempo, ambas compartilham a base de conhecimento já estabelecida.\n\n3. **Eficiência de tokens e processamento**: Não é necessário reler os 23 arquivos duas vezes. O contexto já está indexado na memória da sessão original, economizando processamento.\n\n4. **Avaliação comparativa facilitada**: Como as duas estratégias partem do mesmo ponto de compreensão do código, a comparação de trade-offs é mais precisa e confiável.\n\n5. **Reversão ou fusão de aprendizados**: Se uma estratégia funcionar melhor, você pode manter aquela ramificação e descartar a outra. Se ambas tiverem méritos, insights de uma podem informar a outra.\n\n**Por que as alternativas estão erradas:**\n\n- **Alternativa A** (exportar para arquivo e novas sessões): Perde contexto nuançado que não cabe em um arquivo de resumo. Força releitura parcial e cria duplicação de esforço. Além disso, "referenciar um arquivo" não restaura o contexto conversacional completo.\n\n- **Alternativa C** (duas novas sessões relendo tudo): Desperdiça tokens e processamento ao reler 23 arquivos desnecessariamente. Cada sessão precisaria fazer a análise inicial do zero, multiplicando o custo.\n\n- **Alternativa D** (sequencial na mesma sessão): Não permite comparação efetiva. Depois de desenvolver a primeira estratégia, o contexto pode estar poluído pelas decisões e explorações da primeira abordagem, tendenciando a segunda. Não oferece a independência necessária para avaliação justa dos trade-offs.','\n',char(10)),replace('## EXPLICAÇÃO PARA CRIANÇA (10 ANOS)\n\nImagina que você está explorando um grande castelo (os 23 arquivos de código). Você já explorou tudo, viu como funciona, conhece todos os caminhos e segredos.\n\nAgora, você quer testar **duas formas diferentes** de lidar com armadilhas no castelo:\n- **Forma 1**: Colocar pessoas falsas (mocks) para lidar com as armadilhas\n- **Forma 2**: Tirar fotos (snapshots) do que acontece\n\nSe você usasse a **alternativa A**: Você anotaria o que aprendeu, sairia do castelo e entraria dois castelos novos com suas anotações. Mas as anotações não têm todos os detalhes!\n\nSe você usasse a **alternativa C**: Você sairia do castelo, esqueceria tudo que aprendeu, e teria que explorar dois castelos inteiros de novo. Que perda de tempo!\n\nSe você usasse a **alternativa D**: Você testaria a forma 1, depois tentaria testar a forma 2 no mesmo castelo. Mas seu cérebro estaria cansado e confuso com a primeira forma.\n\n**Com a alternativa B (a correta)**: Você cria dois "portais mágicos" a partir do castelo que já conhece bem. Cada portal leva a uma cópia do castelo onde você pode testar uma forma diferente. Os dois castelos são iguais no começo (porque vieram do mesmo original), mas você experimenta coisas diferentes em cada um. No final, você compara: qual forma funcionou melhor?\n\nÉ como ter dois videogames salvos no mesmo ponto, para testar dois finais diferentes!','\n',char(10)));
INSERT INTO cards VALUES('admin','card_1783092984193_377930yit',48,'Um engenheiro que acabou de entrar na equipe pede ao agente para ajudá-lo a entender a arquitetura de autenticação e autorização antes de fazer melhorias de segurança.',replace('Um engenheiro que acabou de entrar na equipe pede ao agente para ajudá-lo a entender a arquitetura de autenticação e autorização antes de fazer melhorias de segurança.\n\nUm engenheiro que acabou de entrar na equipe pede ao agente para ajudá-lo a entender a arquitetura de autenticação e autorização antes de fazer melhorias de segurança. A base de código tem mais de 800 arquivos espalhados por múltiplos serviços.\n\nQual estratégia de exploração construirá o entendimento de forma mais eficaz, considerando as ferramentas nativas do Claude e os limites de contexto?\n\n[ ] A - Ler primeiro quaisquer arquivos CLAUDE.md e README e, então, pedir ao engenheiro para especificar quais 10 a 15 arquivos são mais importantes para entender o sistema de autenticação.\n[ ] B - Iniciar subagentes paralelos para explorar diferentes serviços simultaneamente e, então, sintetizar suas descobertas em uma visão arquitetural geral.\n[ ] C - Usar o Grep para encontrar os pontos de entrada de autenticação, ler esses arquivos e, então, seguir as importações e chamadas de função para mapear o fluxo de autenticação de forma incremental.\n[ ] D - Ler todos os arquivos que contenham "auth", "login", "permission" ou "token" em seu conteúdo ou nome de arquivo.','\n',char(10)),'[ ] A - Ler primeiro quaisquer arquivos CLAUDE.md e README e, então, pedir ao engenheiro para especificar quais 10 a 15 arquivos são mais importantes para entender o sistema de autenticação.','["Domain_1::Agentic_Architecture_Orchestration", "Domain_2::Tool_Design_MCP_Integration", "Scenario_4::Developer_Productivity"]','New',0,2.5,0,1783092984193,1783725222167,1783203558653,replace('**TRADUÇÃO:**\n\nUm engenheiro que acabou de entrar na equipe pede ao agente para ajudá-lo a entender a arquitetura de autenticação e autorização antes de fazer melhorias de segurança. A base de código tem mais de 800 arquivos espalhados por múltiplos serviços.\n\nQual estratégia de exploração construirá o entendimento de forma mais eficaz, considerando as ferramentas nativas do Claude e os limites de contexto?\n\n[ ] A - Ler primeiro quaisquer arquivos CLAUDE.md e README e, então, pedir ao engenheiro para especificar quais 10 a 15 arquivos são mais importantes para entender o sistema de autenticação.\n[ ] B - Iniciar subagentes paralelos para explorar diferentes serviços simultaneamente e, então, sintetizar suas descobertas em uma visão arquitetural geral.\n[ ] C - Usar o Grep para encontrar os pontos de entrada de autenticação, ler esses arquivos e, então, seguir as importações e chamadas de função para mapear o fluxo de autenticação de forma incremental.\n[ ] D - Ler todos os arquivos que contenham "auth", "login", "permission" ou "token" em seu conteúdo ou nome de arquivo.','\n',char(10)),replace('**EXPLICAÇÃO PARA TECH LEAD:**\n\nA alternativa **A** é a correta por razões técnicas e pragmáticas fundamentais:\n\n**Por que A é a melhor resposta:**\n\n1. **Respeito aos limites de contexto**: Claude tem um limite de tokens. Com 800 arquivos, tentar exploração automatizada sem priorização quebraria rapidamente o limite. A estratégia A reconhece essa restrição e usa uma abordagem iterativa e inteligente.\n\n2. **Aproveitamento de documentação existente**: Arquivos CLAUDE.md e README são frequentemente documentação de manutenção intent ou notas arquiteturais deixadas pelos desenvolvedores. Iniciar por eles economiza tempo significativamente e fornece contexto crítico.\n\n3. **Validação humana como feature**: Pedir ao engenheiro veterano para especificar 10-15 arquivos cruciais não é uma "fraqueza" - é inteligente. Aproveita o conhecimento de domínio do time para priorizar efetivamente, evitando exploração cega.\n\n4. **Scaleabilidade incremental**: A 10-15 arquivos por iteração, é possível aprofundar-se mantendo contexto coerente, fazer perguntas de esclarecimento e construir uma compreensão real em vez de mapas superficiais.\n\n**Por que as alternativas estão erradas:**\n\n**B - Subagentes paralelos**: Claude não suporta subagentes paralelos nativamente. Esta resposta descreve funcionalidade inexistente. Além disso, múltiplos agentes tornariam difícil sintetizar descobertas inconsistentes sem um "maestro" coordenando.\n\n**C - Grep + rastreamento automático**: Parece técnico, mas tem problemas críticos:\n- Grep pode encontrar centenas de referências\n- "Seguir importações" em código complexo leva a explosão de dependências\n- Sem priorização, pode perder o "fluxo crítico" em meio a código periférico\n- Quebraria rapidamente limites de contexto\n\n**D - Buscar por keywords**: Extremamente ineficiente com 800 arquivos. Um projeto com autenticação real pode ter centenas de arquivos contendo essas palavras-chave (testes, mocks, comentários históricos, etc.). Resultaria em ruído massivo e limite de contexto rapidamente atingido.\n\n**Abordagem pragmática de A:**\n```\n1. Ler CLAUDE.md + README → entendimento da visão geral\n2. Perguntar: "Quais 10-15 arquivos definem o core auth?"\n3. Ler e mapear esses arquivos com o engenheiro\n4. Iterar para camadas mais profundas conforme necessário\n5. Documentar a arquitetura para futuras melhorias\n```\n\nEsta é a única estratégia que funciona dentro das limitações reais do Claude e que aproveita corretamente a expertise humana disponível.','\n',char(10)),replace('**Para uma criança de 10 anos:**\n\nImagina que você quer aprender sobre como funciona uma cidade gigante com 800 prédios, mas você só pode ver um número limitado de lugares por vez.\n\n**Alternativa A (CORRETA):** \nVocê primeiro lê um mapa e guias turísticos (README e CLAUDE.md). Depois, você pergunta a um morador experiente: "Quais são os 15 prédios mais importantes para entender como a cidade funciona?" Aí você visita esses 15 prédios especiais, entende como funcionam, e depois pode explorar mais se precisar.\n\n**Alternativa B:**\nVocê tenta enviar 800 pessoas diferentes para explorar todos os prédios ao mesmo tempo. Mas pessoas não conseguem conversar muito bem enquanto exploram, e no final fica difícil colocar todas as histórias juntas. (Além disso, o Claude não pode fazer isso mesmo!)\n\n**Alternativa C:**\nVocê tenta seguir toda rua, cada porta, cada corredor. Acaba virando um macarrão de informação confusa. Você se perde em detalhes menores e esquece qual era o grande objetivo.\n\n**Alternativa D:**\nVocê procura todos os prédios que têm a palavra "banco" ou "caixa" escritas. Mas isso pode trazer lojas que vendem caixas, bancos de madeira de parques, etc. Muita bagunça, pouca compreensão real.\n\n**Por que A funciona melhor:** Porque usa a inteligência das pessoas (o engenheiro que já conhece o projeto) para focar no que realmente importa, e respeita seus limites (você não consegue ver tudo de uma vez).','\n',char(10)));
INSERT INTO cards VALUES('admin','card_1783092984199_k7bplincy',49,'O subagente de exploração de um engenheiro passou 30 minutos analisando um sistema de pagamentos legado, lendo 47 arquivos e documentando os fluxos de dados.',replace('O subagente de exploração de um engenheiro passou 30 minutos analisando um sistema de pagamentos legado, lendo 47 arquivos e documentando os fluxos de dados.\n\nO subagente de exploração de um engenheiro passou 30 minutos analisando um sistema de pagamentos legado, lendo 47 arquivos e documentando os fluxos de dados. A sessão foi interrompida quando a conexão do engenheiro caiu. Enquanto ele estava ausente, um colega fez o merge de um PR que renomeou duas funções utilitárias. O engenheiro quer continuar a mesma exploração.\n\nQual é a abordagem mais eficaz?\n\n[ ] A - Retomar o subagente a partir de sua transcrição anterior sem mencionar as mudanças — o entendimento da arquitetura continua válido.\n[ ] B - Iniciar um subagente novo e incluir a transcrição anterior no prompt inicial para fornecer contexto.\n[ ] C - Iniciar um subagente novo com um resumo das descobertas anteriores.\n[ ] D - Retomar o subagente a partir de sua transcrição anterior e informá-lo sobre as funções renomeadas.','\n',char(10)),'[ ] D - Retomar o subagente a partir de sua transcrição anterior e informá-lo sobre as funções renomeadas.','["Domain_5::Context_Management_Reliability", "Domain_1::Agentic_Architecture_Orchestration", "Scenario_4::Developer_Productivity"]','New',0,2.5,0,1783092984199,1783725225929,1783203558653,replace('## TRADUÇÃO\n\n**Pergunta Original:**\nO subagente de exploração de um engenheiro passou 30 minutos analisando um sistema de pagamentos legado, lendo 47 arquivos e documentando os fluxos de dados. A sessão foi interrompida quando a conexão do engenheiro caiu. Enquanto ele estava ausente, um colega fez o merge de um PR que renomeou duas funções utilitárias. O engenheiro quer continuar a mesma exploração. Qual é a abordagem mais eficaz?\n\n**Alternativas:**\n[ ] A - Retomar o subagente a partir de sua transcrição anterior sem mencionar as mudanças — o entendimento da arquitetura continua válido.\n[ ] B - Iniciar um subagente novo e incluir a transcrição anterior no prompt inicial para fornecer contexto.\n[ ] C - Iniciar um subagente novo com um resumo das descobertas anteriores.\n[ ] D - Retomar o subagente a partir de sua transcrição anterior e informá-lo sobre as funções renomeadas.','\n',char(10)),replace('## EXPLICAÇÃO PARA TECH LEAD\n\nA alternativa correta é **D** porque representa o equilíbrio ideal entre eficiência e precisão.\n\n**Por que D é a melhor escolha:**\n\n1. **Continuidade de estado**: Retomar o subagente mantém todo o contexto já construído nos 30 minutos anteriores — análise de 47 arquivos, fluxos de dados mapeados, estado interno do raciocínio. Começar do zero desperdiçaria esse investimento computacional.\n\n2. **Informação crítica**: As mudanças (renomeação de duas funções) não são decorativas — são alterações no código que afetam diretamente a exploração. O subagente precisa ser informado para não gerar análises baseadas em nomes de função desatualizados.\n\n3. **Coerência técnica**: A transcrição anterior contém o contexto arquitetural válido (fluxos de dados, dependências, padrões). As funções renomeadas são mudanças superficiais que não invalidam esse entendimento estrutural.\n\n4. **Otimização de recursos**: Retomar é mais eficiente que iniciar novo (opções B e C) porque aproveita o processamento já realizado.\n\n**Por que as alternativas estão erradas:**\n\n**A - Sem mencionar as mudanças**: Perigoso. Se o subagente continuar referenciando nomes antigos de funções em seu contexto, pode gerar documentação desatualizada ou fazer sugestões baseadas em código que mudou. Isso criaria desincronização entre a análise e a realidade atual do código.\n\n**B - Novo subagente com transcrição no prompt**: Menos eficiente. Processar uma transcrição como entrada é diferente de manter o estado interno de um agente. Há perda de continuidade de raciocínio e potencial para redundância na análise.\n\n**C - Novo subagente com resumo**: Pior ainda. Um resumo é uma lossy compression do conhecimento adquirido. Perdem-se detalhes importantes sobre as conexões entre os 47 arquivos analisados, fluxos de dados específicos e padrões identificados.\n\n**Princípio subjacente**: Em sistemas de agentes exploratórios, a continuidade de estado é mais valiosa que começar do zero, desde que os pressupostos sejam atualizados. Retomar + informar mudanças = máxima eficiência.','\n',char(10)),replace('## EXPLICAÇÃO PARA UMA CRIANÇA DE 10 ANOS\n\nImagina que você estava montando um quebra-cabeça com um amigo. Vocês já colocaram muitas peças no lugar (30 minutos de trabalho!), e de repente seu amigo teve que sair.\n\nEnquanto ele não estava, outra pessoa veio e trocou os nomes de dois brinquedos que estavam perto do quebra-cabeça.\n\nAgora o seu amigo quer continuar. O que é melhor fazer?\n\n**Opção A**: "Continue de onde parou, não precisa saber que mudaram os nomes" — MÁ IDEIA! Seu amigo pode ficar confuso porque os brinquedos não têm mais os nomes que ele lembra.\n\n**Opção B**: "Comece um quebra-cabeça novo, mas leia tudo que vocês fizeram antes" — Não é bom porque você vai perder todo o progresso e é muito mais lento.\n\n**Opção C**: "Comece novo, mas eu resumo o que vocês fizeram" — Ainda pior! Um resumo pode deixar informação importante de fora.\n\n**Opção D**: "Continue de onde parou, mas aviso que dois brinquedos mudaram de nome" — PERFEITO! Você aproveita todo o trabalho anterior, mas seu amigo sabe que algumas coisas mudaram.\n\nÉ como dizer: "você pode continuar do ponto onde parou, mas fique ligado nesses detalhes novos que apareceram!"','\n',char(10)));
INSERT INTO cards VALUES('admin','card_1783092984205_4jj3kx3g1',50,'Um cliente retorna 4 horas após a sessão inicial sobre a mesma disputa de cobrança.',replace('Um cliente retorna 4 horas após a sessão inicial sobre a mesma disputa de cobrança.\n\nUm cliente retorna 4 horas após a sessão inicial sobre a mesma disputa de cobrança. A sessão anterior, com 32 turnos, contém resultados de `lookup_order` mostrando "Status: PENDING, Resolução prevista: 24-48 horas." Em testes, você observa que, ao retomar sessões com resultados de ferramentas desatualizados, o agente frequentemente faz referência aos dados obsoletos nas respostas (por exemplo, "Vejo que seu reembolso ainda está em processamento"), mesmo após chamadas de ferramentas mais recentes retornarem informações diferentes.\n\nQual abordagem lida de forma mais confiável com clientes que retornam?\n\n[ ] A - Retomar com o histórico completo, mas filtrar as mensagens `tool_result` anteriores antes de retomar, mantendo apenas os turnos do humano/assistente para que o agente precise buscar novamente os dados necessários.\n[ ] B - Iniciar uma nova sessão, injetar um resumo estruturado da interação anterior (tipo de problema, ações tomadas, status de resolução) e fazer novas chamadas de ferramentas antes de iniciar o atendimento.\n[ ] C - Retomar com o histórico completo e adicionar uma instrução no prompt do sistema dizendo ao agente para sempre preferir os resultados de ferramentas mais recentes quando houver várias chamadas à mesma ferramenta no contexto.\n[ ] D - Retomar com o histórico completo e configurar o agente para chamar novamente, de forma automática, todas as ferramentas usadas anteriormente no início da sessão, garantindo a atualidade dos dados.','\n',char(10)),'[ ] B - Iniciar uma nova sessão, injetar um resumo estruturado da interação anterior (tipo de problema, ações tomadas, status de resolução) e fazer novas chamadas de ferramentas antes de iniciar o atendimento.','["Domain_5::Context_Management_Reliability", "Domain_2::Tool_Design_MCP_Integration", "Scenario_1::Customer_Support_Agent"]','New',0,2.5,0,1783092984205,1783725229610,1783203558653,replace('TRADUÇÃO\nUm cliente retorna 4 horas após a sessão inicial sobre a mesma disputa de cobrança. A sessão anterior, com 32 turnos, contém resultados de `lookup_order` mostrando "Status: PENDENTE, Resolução prevista: 24-48 horas." Em testes, você observa que, ao retomar sessões com resultados de ferramentas desatualizados, o agente frequentemente faz referência aos dados obsoletos nas respostas (por exemplo, "Vejo que seu reembolso ainda está em processamento"), mesmo após chamadas de ferramentas mais recentes retornarem informações diferentes.','\n',char(10)),replace('ANÁLISE TÉCNICA - RESPOSTA CORRETA: ALTERNATIVA B\n\nA alternativa B é a mais confiável porque resolve o problema fundamental: **eliminar a contaminação por dados obsoletos enquanto preserva contexto crítico**.\n\n**Por que B é a melhor solução:**\n\n1. **Nova Sessão = Novo Contexto Clean**: Ao iniciar uma nova sessão, você não carrega o histórico completo de 32 turnos com seus múltiplos `tool_result` antigos. Isso evita que o LLM se confunda entre qual informação é atual e qual é obsoleta.\n\n2. **Resumo Estruturado = Contexto sem Poluição**: Um resumo bem construído (e.g., "Tipo: Disputa de reembolso | Cliente: João | Ações anteriores: Solicitou investigação | Último status: PENDENTE em 4h atrás") fornece informação essencial sem os detalhes granulares que podem enganar o modelo.\n\n3. **Fresh Tool Calls = Dados Garantidamente Atuais**: Fazer chamadas de ferramentas ANTES de iniciar o atendimento garante que a sessão comece com informações verificadas e atualizadas. Se o status mudou de PENDENTE para RESOLVIDO, o agente saberá disso imediatamente.\n\n4. **Mitiga o Problema Observado**: O teste mostrou que o agente referencia dados obsoletos mesmo com chamadas mais recentes. B evita isso porque a sessão não começa com dados antigos; ela começa com dados frescos.\n\n---\n\n**Por que as outras alternativas falham:**\n\n**Alternativa A - Filtrar tool_result:** \n- Mantém o histórico completo de turnos, então o agente ainda vê 32 turnos de contexto antigo\n- Força novas chamadas, mas o modelo pode ainda contextualizar erroneamente ("Você pediu investigação em [passado]... agora está em processamento")\n- Não resolve o problema de confusão entre múltiplas versões de dados\n\n**Alternativa C - Instrução no Prompt:**\n- Depende de compliance do LLM com instruções de preferência\n- Modelos (especialmente GPT-3.5 e anteriores) frequentemente não seguem instruções rivais quando há dados contraditórios no contexto\n- "Sempre preferir dados mais recentes" é frágil: qual é o "dado mais recente" em um contexto de 32 turnos misturados?\n- Não foi testado como solução no cenário observado\n\n**Alternativa D - Chamar Todas as Ferramentas Automaticamente:**\n- Overkill e ineficiente\n- Pode disparar chamadas desnecessárias (ex: `fetch_customer_details` se nada mudou lá)\n- Aumenta latência e custo\n- Não melhora fundamentalmente a contaminação contextual; apenas adiciona mais dados ao problema\n\n---\n\n**Padrão Recomendado para Retomadas de Sessão em Produção:**\n\n```\n1. Carregar contexto anterior\n2. Gerar resumo estruturado (LLM-assistido ou template)\n3. Chamar setup-call para ferramentas críticas (status de pedido, resolução)\n4. Iniciar nova sessão com:\n   - Resumo + novos dados + histórico minimal de ações\n   - NÃO o histórico completo de tool_results\n5. Adicionar tag contextual: "Você está retomando um caso aberto 4h atrás"\n```\n\nIsso é padrão em sistemas de suporte enterprise (Zendesk, Intercom, etc.) e em frameworks de agentes como LangChain quando gerenciam retomadas.','\n',char(10)),replace('EXPLICAÇÃO PARA CRIANÇA DE 10 ANOS:\n\nImagina que você foi a uma loja pedir ajuda sobre um produto que pediu há 4 horas. O vendedor tem um grande caderno com TUDO o que aconteceu nesses 4 horas (32 páginas!), mas aquelas informações são velhas.\n\nO problema é: se o vendedor lê tudo aquele caderno antigo, ele pode achar que seu produto "ainda está chegando" quando, na verdade, JÁ CHEGOU! 🚚\n\n**O que funciona melhor (Opção B)?**\n\nEm vez de ler aquele caderno enorme, você faz assim:\n1. Você pega uma nova folha em branco (nova sessão)\n2. Você escreve um RESUMO rápido: "João pediu reembolso há 4h, status era pendente"\n3. **ANTES de conversar, você confere AGORA** como está o pedido (liga pro depósito, checa online, etc.)\n4. Só DEPOIS você começa a conversar com informação FRESCA\n\nAssim o vendedor nunca fica confuso com informações velhas! ✅\n\n**Por que os outros não funcionam?**\n\n- **Opção A**: Ainda deixa o caderno de 32 páginas ali... confuso!\n- **Opção C**: Dizer "prefira informação nova" é fraco - a pessoa pode ainda ficar confusa\n- **Opção D**: Fazer TODOS os testes de novo é lentoooo e desnecessário','\n',char(10)));
INSERT INTO cards VALUES('admin','card_1783092984228_jgi3jrtti',51,'Você está implementando a lógica de escalonamento para quando o agente deve chamar `escalate_to_human`.',replace('Você está implementando a lógica de escalonamento para quando o agente deve chamar `escalate_to_human`.\n\nVocê está implementando a lógica de escalonamento para quando o agente deve chamar `escalate_to_human`. Sua equipe propõe quatro abordagens diferentes para acionar o escalonamento.\n\nQual abordagem identificará de forma mais confiável os casos que genuinamente exigem intervenção humana?\n\n[ ] A - Instruir o agente a escalonar quando o cliente solicitar um humano, quando o problema exigir exceções de política ou quando o agente não conseguir avançar de forma significativa.\n[ ] B - Configurar o agente para escalonar após três chamadas de ferramenta consecutivas que falhem em resolver o problema declarado pelo cliente, garantindo uma tentativa razoável antes de envolver um humano.\n[ ] C - Implementar análise de sentimento que monitore indicadores de frustração (linguagem negativa, perguntas repetidas, pontos de exclamação) e acione o escalonamento quando a pontuação de frustração ultrapassar um limite configurado.\n[ ] D - Construir um motor de regras que mapeie tipos específicos de problemas, segmentos de clientes e categorias de produtos para decisões de escalonamento, eliminando a necessidade de julgamentos do modelo.','\n',char(10)),'[ ] A - Instruir o agente a escalonar quando o cliente solicitar um humano, quando o problema exigir exceções de política ou quando o agente não conseguir avançar de forma significativa.','["Domain_1::Agentic_Architecture_Orchestration", "Domain_4::Prompt_Engineering_Structured_Output", "Scenario_1::Customer_Support_Agent"]','New',0,2.5,0,1783092984228,1783725232976,1783203558653,replace('TRADUÇÃO\nVocê está implementando a lógica de escalonamento para quando o agente deve chamar `escalate_to_human`. Sua equipe propõe quatro abordagens diferentes para acionar o escalonamento.\n\nQual abordagem identificará de forma mais confiável os casos que genuinamente exigem intervenção humana?\n\n[ ] A - Instruir o agente a escalonar quando o cliente solicitar um humano, quando o problema exigir exceções de política ou quando o agente não conseguir avançar de forma significativa.\n[ ] B - Configurar o agente para escalonar após três chamadas de ferramenta consecutivas que falhem em resolver o problema declarado pelo cliente, garantindo uma tentativa razoável antes de envolver um humano.\n[ ] C - Implementar análise de sentimento que monitore indicadores de frustração (linguagem negativa, perguntas repetidas, pontos de exclamação) e acione o escalonamento quando a pontuação de frustração ultrapassar um limite configurado.\n[ ] D - Construir um motor de regras que mapeie tipos específicos de problemas, segmentos de clientes e categorias de produtos para decisões de escalonamento, eliminando a necessidade de julgamentos do modelo.','\n',char(10)),replace('EXPLICAÇÃO (Tech Lead)\n\nA alternativa correta é **A** porque captura a essência de quando um escalonamento é genuinamente necessário, combinando três critérios complementares:\n\n**1. Solicitação explícita do cliente ("quando o cliente solicitar um humano")**\n- É o indicador mais confiável: o próprio cliente comunica sua necessidade\n- Respeita a autonomia do usuário e suas preferências\n- Evita desperdício de recursos em tentativas desnecessárias\n\n**2. Requisitos fora do escopo da política ("quando o problema exigir exceções de política")**\n- Problemas com exceções de política (reembolsos não-padrão, descontos especiais, waivers) requerem aprovação humana\n- O agente não deveria tentar resolver o que ultrapassa sua autoridade\n- Isso evita comprometer a organização com decisões que violam políticas\n\n**3. Falta de progresso substantivo ("quando o agente não conseguir avançar de forma significativa")**\n- Reconhece os limites do agente sem usar métricas artificiais\n- Permite iteração razoável antes de escalar\n- É mais flexível que contar falhas\n\n**Por que as outras alternativas falham:**\n\n**Alternativa B (três falhas consecutivas):**\n- É arbitrária: três é apenas um número, não relacionado à natureza real do problema\n- Um problema pode ser resolvido na quarta tentativa\n- Problemas genuinamente irresoluláveis (políticas, situações únicas) não precisam de três tentativas\n- Cria experiência ruim: força tentativas desnecessárias quando já está claro que precisa escalar\n\n**Alternativa C (análise de sentimento):**\n- Excesso de falsos positivos: clientes podem estar frustrados com situações resolvidas simples\n- Excesso de falsos negativos: alguns problemas críticos reais podem ser comunicados calmamente\n- Sentimento não é confiável: linguagem negativa ≠ necessidade de humano; pontos de exclamação ≠ problema real\n- Penaliza clientes expressivos e deixa passar problemas reais\n\n**Alternativa D (motor de regras rígidas):**\n- Elimina flexibilidade: problemas dentro da mesma categoria têm contextos diferentes\n- "Eliminando julgamentos do modelo" é uma fraqueza, não um benefício\n- Não consegue lidar com casos novos ou exceções não previstas\n- Torna o sistema frágil e requer manutenção constante\n- Nega as capacidades reais do agente de avaliar contexto\n\n**Conclusão:**\nA abordagem A usa sinais diretos (solicitação, limites políticos, falta de progresso) que indicam genuína necessidade de intervenção humana, em vez de proxies indiretos (contagem de falhas, sentimento) ou regras rígidas que não se adaptam.','\n',char(10)),replace('EXPLICAÇÃO (Criança de 10 anos)\n\nImagina que você tem um robô atendente em uma loja. Quando deve ele chamar um adulto para ajudar?\n\n**A resposta correta (A) diz: "Chame um adulto quando:**\n1. **O cliente pedir** - "Quero falar com uma pessoa"\n2. **O problema for muito especial** - algo que só um gerente pode autorizar\n3. **O robô já tentou bastante e não conseguiu avançar**"\n\nIsso é sensato porque usa sinais óbvios de quando realmente precisa de ajuda.\n\n**Por que os outros não funcionam bem:**\n\n**B (contar erros):** É como dizer "só chama um adulto após três erros". Mas e se o primeiro erro já mostra que precisa de um adulto? Por que forçar três tentativas?\n\n**C (analisar frustração):** Alguém pode estar gritando mas o problema é simples. Ou estar calmo mas com um problema sério. Os sentimentos enganam.\n\n**D (listar todas as regras):** É tentar adivinhar todos os problemas com antecedência. Mas problemas novos e estranhos sempre aparecem, e aí a lista não serve mais.','\n',char(10)));
INSERT INTO cards VALUES('admin','card_1783092984235_6c0nr46ee',52,'Após investigar uma disputa de cobrança ao longo de mais de 25 turnos, você identificou que as cobranças duplicadas ocorreram devido a um timeout do gateway de pagamento que acionou a lógica de nova tentativa.',replace('Após investigar uma disputa de cobrança ao longo de mais de 25 turnos, você identificou que as cobranças duplicadas ocorreram devido a um timeout do gateway de pagamento que acionou a lógica de nova tentativa.\n\nApós investigar uma disputa de cobrança ao longo de mais de 25 turnos, você identificou que as cobranças duplicadas ocorreram devido a um timeout do gateway de pagamento que acionou a lógica de nova tentativa. O reembolso necessário (US$ 847) excede seu limite de autorização de US$ 500. Você precisa chamar `escalate_to_human`, e o agente humano não terá acesso à transcrição da sua conversa.\n\nQual contexto você deve repassar para permitir uma resolução eficaz?\n\n[ ] A - A reclamação original do cliente na íntegra, mais os trechos dos resultados de ferramentas que mostram as transações duplicadas.\n[ ] B - Um resumo estruturado: ID do cliente, causa raiz, valor do reembolso e ação recomendada.\n[ ] C - A transcrição completa da conversa com todos os resultados de ferramentas.\n[ ] D - Apenas o seu diagnóstico e o valor do reembolso.','\n',char(10)),'[ ] B - Um resumo estruturado: ID do cliente, causa raiz, valor do reembolso e ação recomendada.','["Domain_1::Agentic_Architecture_Orchestration", "Domain_5::Context_Management_Reliability", "Scenario_1::Customer_Support_Agent"]','New',0,2.5,0,1783092984235,1783725236593,1783203558653,replace('**TRADUÇÃO:**\nPergunta: Após investigar uma disputa de cobrança ao longo de mais de 25 turnos, você identificou que as cobranças duplicadas ocorreram devido a um timeout do gateway de pagamento que acionou a lógica de nova tentativa. O reembolso necessário (US$ 847) excede seu limite de autorização de US$ 500. Você precisa chamar `escalate_to_human`, e o agente humano não terá acesso à transcrição da sua conversa. Qual contexto você deve repassar para permitir uma resolução eficaz?\n\nA) A reclamação original do cliente na íntegra, mais os trechos dos resultados de ferramentas que mostram as transações duplicadas.\nB) Um resumo estruturado: ID do cliente, causa raiz, valor do reembolso e ação recomendada.\nC) A transcrição completa da conversa com todos os resultados de ferramentas.\nD) Apenas o seu diagnóstico e o valor do reembolso.','\n',char(10)),replace('**EXPLICAÇÃO PARA TECH LEAD:**\n\nA resposta correta é **B - Um resumo estruturado: ID do cliente, causa raiz, valor do reembolso e ação recomendada.**\n\n**Por que B é correto:**\n\nEste cenário envolve uma escalação para agente humano com um contexto crítico: o agente NÃO terá acesso à transcrição da conversa. Portanto, é essencial passar informações estruturadas, concisas e acionáveis. Um resumo bem organizado com:\n- **ID do cliente**: identifica inequivocamente o caso\n- **Causa raiz**: gateway timeout + retry logic (explicita a natureza técnica do problema)\n- **Valor do reembolso**: US$ 847 (informação quantificável)\n- **Ação recomendada**: aprova do reembolso (guia a próxima ação)\n\nEssa abordagem segue boas práticas de handoff entre sistemas e humanos. O agente pode agir rapidamente sem precisar reconstruir todo o contexto.\n\n**Por que as demais estão erradas:**\n\n**A - A reclamação original + trechos de ferramentas**: Embora contenha dados relevantes, é parcial e desorganizada. Mistura conteúdo de alto nível (reclamação) com detalhes técnicos (trechos de ferramentas). O agente gastará tempo filtrando informações sem uma estrutura clara de decisão. Além disso, omite elementos críticos como "ação recomendada".\n\n**C - A transcrição completa da conversa**: Esta é a pior opção. Você tem 25+ turnos de conversa. Passar tudo seria extremamente ineficiente, consumiria tempo precioso do agente humano, e violaria o princípio de escalação enxuta. Uma transcrição gigante reduz a velocidade de resolução e pode criar confusão sobre qual informação é realmente relevante.\n\n**D - Apenas diagnóstico + valor**: Muito escasso. Omite o ID do cliente (como identificar o caso?), a ação recomendada (o agente teria que inferir), e não fornece contexto suficiente para o agente validar sua própria decisão antes de processar o reembolso.\n\n**Princípio subjacente:** Escalações eficazes usam **summarização estruturada**, não raw data ou transcrições. É equivalente a um modelo de API bem desenhado versus um dump de logs.','\n',char(10)),replace('**EXPLICAÇÃO PARA UMA CRIANÇA DE 10 ANOS:**\n\nImagina que você está jogando um videogame de investigação e descobriu um mistério (duplicação de cobranças). Você investigou por MUITO tempo (25 turnos) e descobriu que foi um problema do computador que processava os pagamentos.\n\nAgora você precisa chamar um adulto para ajudar, mas aqui está o importante: **esse adulto NÃO viu nenhuma da sua investigação**. Ele só vai saber o que você contar.\n\nO que você deveria contar?\n\n**Resposta B é a melhor:**\n"Olha, é o cliente XXXXXX. Aconteceu porque o computador de pagamento deu timeout e tentou cobrar novamente. A pessoa deve receber US$ 847 de volta. Você deve aprovar esse reembolso."\n\nSimples, direto, e o adulto consegue ajudar rápido!\n\n**Por que as outras respostas não funcionam:**\n\n**A)** "Deixa eu te contar tudo o que o cliente reclamou, mais um monte de detalhes técnicos..." - Muita informação misturada, confusa.\n\n**C)** "Deixa eu te passar a gravação inteira dos 25 turnos..." - NÃO! O adulto vai gastar HORAS lendo coisas desnecessárias. É como contar a história inteira de um filme quando você só precisava dizer o final.\n\n**D)** "Achei que é isso, são US$ 847" - Muito pouco! O adulto não sabe quem é o cliente, não entende por que precisa reembolsar, e não sabe o que fazer.','\n',char(10)));
INSERT INTO cards VALUES('admin','card_1783092984241_dbfog8vao',53,'A conformidade exige que reembolsos acima de US$ 500 sejam automaticamente escalonados para um agente humano — essa regra não pode ficar a critério do modelo.',replace('A conformidade exige que reembolsos acima de US$ 500 sejam automaticamente escalonados para um agente humano — essa regra não pode ficar a critério do modelo.\n\nA conformidade exige que reembolsos acima de US$ 500 sejam automaticamente escalonados para um agente humano — essa regra não pode ficar a critério do modelo. Apesar de instruções claras no prompt do sistema, os logs de produção mostram que o agente ocasionalmente processa reembolsos de alto valor diretamente (taxa de falha de 3%).\n\nComo você deve garantir conformidade assegurada?\n\n[ ] A - Modificar a ferramenta de reembolso para retornar um erro com a mensagem "Valor excede o limite da política — favor escalonar" quando o limite for ultrapassado.\n[ ] B - Adicionar exemplos few-shot ao prompt mostrando o comportamento correto de escalonamento em diversos valores de reembolso (US$ 400, US$ 500, US$ 600).\n[ ] C - Implementar um hook para interceptar as chamadas de ferramenta; quando o valor do processo de reembolso exceder US$ 500, bloqueá-lo e invocar o escalonamento humano.\n[ ] D - Reforçar o prompt do sistema com linguagem enfática: "POLÍTICA CRÍTICA: Reembolsos acima de US$ 500 DEVEM acionar escalonamento humano. NUNCA processe esses diretamente."','\n',char(10)),'[ ] C - Implementar um hook para interceptar as chamadas de ferramenta; quando o valor do processo de reembolso exceder US$ 500, bloqueá-lo e invocar o escalonamento humano.','["Domain_2::Tool_Design_MCP_Integration", "Domain_4::Prompt_Engineering_Structured_Output", "Scenario_1::Customer_Support_Agent"]','New',0,2.5,0,1783092984241,1783725240600,1783203558653,replace('TRADUÇÃO:\nPergunta: A conformidade exige que reembolsos acima de US$ 500 sejam automaticamente escalonados para um agente humano — essa regra não pode ficar a critério do modelo. Apesar de instruções claras no prompt do sistema, os logs de produção mostram que o agente ocasionalmente processa reembolsos de alto valor diretamente (taxa de falha de 3%). Como você deve garantir conformidade assegurada?\n\nAlternativas:\nA - Modificar a ferramenta de reembolso para retornar um erro com a mensagem "Valor excede o limite da política — favor escalonar" quando o limite for ultrapassado.\nB - Adicionar exemplos few-shot ao prompt mostrando o comportamento correto de escalonamento em diversos valores de reembolso (US$ 400, US$ 500, US$ 600).\nC - Implementar um hook para interceptar as chamadas de ferramenta; quando o valor do processo de reembolso exceder US$ 500, bloqueá-lo e invocar o escalonamento humano.\nD - Reforçar o prompt do sistema com linguagem enfática: "POLÍTICA CRÍTICA: Reembolsos acima de US$ 500 DEVEM acionar escalonamento humano. NUNCA processe esses diretamente."','\n',char(10)),replace('EXPLICAÇÃO (Tech Lead):\n\nA questão apresenta um cenário crítico de conformidade onde já há evidência de falha (3% dos casos) apesar de instruções claras no prompt. Isso demonstra um princípio fundamental: **não se pode confiar em instruções prompt para garantir conformidade obrigatória**.\n\n**Por que C é a resposta correta:**\n\nA opção C implementa um **controle técnico em nível de infraestrutura** — um hook que intercepta as chamadas de ferramenta **antes** da execução. Isso funciona como um **guardrail arquitetural** que:\n\n1. **Funciona independentemente do comportamento do modelo**: O hook não depende de o LLM "entender" ou "respeitar" instruções\n2. **Implementa separação de responsabilidades**: A lógica de conformidade fica no código, não no prompt\n3. **É inviolável**: O modelo não pode contorná-lo, pois as chamadas de ferramenta são interceptadas no nível da aplicação\n4. **Falha segura**: Bloqueia a ação problemática e dispara a ação correta (escalonamento) de forma determinística\n\nIsso segue o princípio de **"Defense in Depth"** e **"Enforcement by Design"**.\n\n**Por que A, B e D estão incorretos:**\n\n**A - Modificar a ferramenta para retornar erro:**\n- É melhor que nada, mas **ainda depende do modelo** tentar chamar a ferramenta primeiro\n- O modelo poderia ignorar o erro ou tentar contorná-lo com outras chamadas\n- Não é uma prevenção verdadeira, apenas uma rejeição passiva\n\n**B - Adicionar exemplos few-shot:**\n- É uma abordagem puramente comportamental baseada em aprendizado\n- Os logs já mostram uma **taxa de falha de 3%**, provando que exemplos ou instruções adicionais são insuficientes\n- Few-shot é melhor para orientação, mas não para conformidade obrigatória\n- Não há garantia de que o padrão será seguido em 100% dos casos\n\n**D - Reforçar prompt com linguagem enfática:**\n- Essa é a abordagem que **já falhou** (conforme descrito no cenário)\n- Aumentar a ênfase no prompt não resolve o problema fundamental\n- O modelo já tem instruções claras; adicionar mais não muda a taxa de falha\n- Confundir "instruções mais fortes" com "garantia de conformidade"\n\n**Resumo técnico:**\n- **A e D**: Confiam no comportamento do modelo (prompt-based)\n- **B**: Confiar no aprendizado do modelo (exemplos)\n- **C**: Implementa controle técnico imperativo (infrastructure-based) ✓\n\nPara conformidade regulatória, exige-se **enforcement by design**, não orientação comportamental.','\n',char(10)),replace('Imagina que temos uma regra muito importante: "Reembolsos acima de US$ 500 precisam de um adulto para aprovar". Mas o robô às vezes ignora essa regra e processa o dinheiro sozinho.\n\nVamos entender cada opção:\n\n**A - Fazer a ferramenta retornar erro:**\nÉ como colocar uma placa de "Não!" na porta. Mas o robô pode ignorar e tentar outra coisa. Não é um bloqueio de verdade.\n\n**B - Dar mais exemplos:**\nÉ como mostrar para o robô muitos exemplos de como deve funcionar. Mas ele já viu exemplos bons antes e mesmo assim falha 3% das vezes. Mostrar mais exemplos não resolve.\n\n**D - Escrever instruções mais fortes:**\nÉ como gritar mais alto: "REALMENTE NÃO FAÇA ISSO!" Mas o robô já tem instruções claras e ignore mesmo assim. Gritar não ajuda.\n\n**C - Colocar um guarda na porta (a resposta correta!):**\nIsso é como colocar uma pessoa **antes** do robô fazer qualquer coisa. Essa pessoa verifica: "É mais de US$ 500? Então BLOQUEIA e chama um humano agora!" \n\nO robô não consegue contornar porque a regra está **antes** dele fazer qualquer coisa, não depois. É impossível pular essa regra.\n\n**Resumo:** Quando algo é **muito importante** (como dinheiro), não podemos confiar que o robô vai seguir as instruções. Precisamos de um "segurança" técnico que bloqueia antes de dar errado.','\n',char(10)));
INSERT INTO cards VALUES('admin','card_1783092984248_va6e2nwxe',54,'Durante a resolução de uma disputa de cobrança, seu agente recupera com sucesso as informações do cliente via `get_customer` e os detalhes do pedido via `lookup_order`, mas, ao tentar chamar `process_refund`, a ferramenta retorna um erro de timeout.',replace('Durante a resolução de uma disputa de cobrança, seu agente recupera com sucesso as informações do cliente via `get_customer` e os detalhes do pedido via `lookup_order`, mas, ao tentar chamar `process_refund`, a ferramenta retorna um erro de timeout.\n\nDurante a resolução de uma disputa de cobrança, seu agente recupera com sucesso as informações do cliente via `get_customer` e os detalhes do pedido via `lookup_order`, mas, ao tentar chamar `process_refund`, a ferramenta retorna um erro de timeout. O agente tem informações suficientes para explicar as cobranças e verificar a elegibilidade do reembolso, mas não consegue de fato processar o reembolso devido à falha no backend.\n\nQual abordagem equilibra melhor a resolução no primeiro contato com o tratamento de erros adequado?\n\n[ ] A - Escalonar imediatamente para um agente humano, já que a ação de reembolso não pode ser concluída.\n[ ] B - Implementar novas tentativas automáticas com backoff exponencial para `process_refund`, mantendo a conversa aberta até que o reembolso seja processado com sucesso.\n[ ] C - Explicar a cobrança, confirmar a elegibilidade do reembolso, reconhecer o problema do sistema que impede o processamento imediato e oferecer escalonamento ou nova tentativa mais tarde.\n[ ] D - Confirmar que o reembolso será processado e encerrar a conversa, já que o sistema tem todas as informações necessárias para concluí-lo automaticamente.','\n',char(10)),'[ ] C - Explicar a cobrança, confirmar a elegibilidade do reembolso, reconhecer o problema do sistema que impede o processamento imediato e oferecer escalonamento ou nova tentativa mais tarde.','["Domain_2::Tool_Design_MCP_Integration", "Domain_5::Context_Management_Reliability", "Scenario_1::Customer_Support_Agent"]','New',0,2.5,0,1783092984248,1783725244170,1783203558653,'TRADUÇÃO FIEL:',replace('Durante a resolução de uma disputa de cobrança, seu agente recupera com sucesso as informações do cliente via `get_customer` e os detalhes do pedido via `lookup_order`, mas, ao tentar chamar `process_refund`, a ferramenta retorna um erro de timeout.\n\nQual abordagem equilibra melhor a resolução no primeiro contato com o tratamento de erros adequado?\n\nA - Escalonar imediatamente para um agente humano, já que a ação de reembolso não pode ser concluída.\nB - Implementar novas tentativas automáticas com backoff exponencial para `process_refund`, mantendo a conversa aberta até que o reembolso seja processado com sucesso.\nC - Explicar a cobrança, confirmar a elegibilidade do reembolso, reconhecer o problema do sistema que impede o processamento imediato e oferecer escalonamento ou nova tentativa mais tarde.\nD - Confirmar que o reembolso será processado e encerrar a conversa, já que o sistema tem todas as informações necessárias para concluí-lo automaticamente.\n\n---\n\nANÁLISE PARA TECH LEAD:\n\nA resposta correta é C, pois representa a abordagem mais equilibrada em sistemas de agentes conversacionais, especialmente em cenários de disputa de cobrança onde confiança do cliente é crítica.\n\n**Por que C é a melhor escolha:**\n\n1. **Maximiza primeiro contato (First Contact Resolution - FCR)**: O agente fornece valor tangível ao explicar a cobrança original e confirmar a elegibilidade, mesmo sem poder processar o reembolso imediatamente. Isso resolve a confusão do cliente e elimina incerteza.\n\n2. **Transparência e confiança**: Reconhecer explicitamente o erro de timeout é honesto com o cliente. Ocultar problemas técnicos prejudica a confiança em agentes de IA.\n\n3. **Oferece opções**: Permite que o cliente escolha entre escalonamento imediato (quando precisa urgência) ou nova tentativa posterior (quando pode esperar), adaptando-se ao contexto.\n\n4. **Tratamento apropriado de erros**: Diferencia entre "não pode resolver" e "consegue fornecer informação completa mas encontrou falha técnica".\n\n**Por que as alternativas estão incorretas:**\n\n**Alternativa A - Escalonamento imediato**: \n- Desperdiça a oportunidade de primeiro contato. O agente já resolveu 80% do problema (explicação + verificação de elegibilidade).\n- Cria friction desnecessária ao escalacionar imediatamente quando uma nova tentativa pode funcionar.\n- Em muitos casos, o cliente ficaria satisfeito apenas sabendo que é elegível para reembolso, mesmo com pequeno atraso.\n\n**Alternativa B - Retry automático indefinido**:\n- Viola boas práticas de UX. Manter conversa "aberta" enquanto retry loop executa cria incerteza.\n- Timeout repeated pode indicar problema persistente no backend - retry cego agrava carga do sistema.\n- Arrisca timeout de conversa ou frustração do cliente que quer resolução imediata.\n- Não oferece agência ao cliente (sem controle sobre o tempo de espera).\n\n**Alternativa D - Confirmar sem processar**:\n- É enganoso. Prometer algo que não foi executado viola contrato com cliente.\n- Cria problemas posteriores quando cliente descobre que reembolso não foi processado.\n- Viola confiança especialmente em transações financeiras onde compliance é crítico.\n- Pode violar regulações de proteção ao consumidor.\n\n**Padrão recomendado em IA conversacional**: Quando encontra erro técnico que impede ação final, o agente deve: (1) resumir o que conseguiu resolver, (2) informar transparentemente sobre a limitação, (3) oferecer alternativas viáveis (retry ou escalonamento).','\n',char(10)),replace('VERSÃO PARA CRIANÇA DE 10 ANOS:\n\nImagina que você está pedindo ajuda para devolver um brinquedo que ganhou por engano.\n\n**Situação**: Você explica ao gerente da loja qual brinquedo é, e ele consegue encontrar os papéis certos. Mas quando tenta apertar o botão no caixa para dar seu dinheiro de volta, o botão não funciona!\n\n**Opção A** - O gerente diz "Infelizmente não posso ajudar agora, vou chamar meu chefe". \n⚠️ Isso é ruim porque ele já descobriu tudo certo - por que chamar outra pessoa se ele sabe que você tem razão?\n\n**Opção B** - O gerente fica tentando o botão quebrado uma e outra vez.\n⚠️ Isso é chato! Você fica esperando e esperando enquanto ele tenta... e tenta... e tenta...\n\n**Opção C** - O gerente diz: "Olha, descobri que seu brinquedo estava certo para devolver. Mas o caixa está com problema. Posso tentar de novo daqui a pouco, ou se você precisar agora, chamo alguém para ajudar."\n✅ Isso é ótimo! Ele explica tudo, diz o que deu errado, e deixa você escolher.\n\n**Opção D** - O gerente diz "Pronto, seu dinheiro voltará sim!" e você vai embora. Mas passa uma semana... e nada!\n⚠️ Péssimo! Ele prometeu algo que não fez de verdade.\n\n**A resposta correta é C** porque: você fica feliz (sabe que está certo), confia no gerente (ele foi honesto), e pode escolher o que fazer.','\n',char(10)));
INSERT INTO cards VALUES('admin','card_1783092984255_fvuxche34',55,'Um cliente escreve: "Já estou indo e voltando com essa devolução há dias.',replace('Um cliente escreve: "Já estou indo e voltando com essa devolução há dias.\n\nUm cliente escreve: "Já estou indo e voltando com essa devolução há dias. Só quero falar com alguém que possa realmente me ajudar." O agente confirmou via `lookup_order` que a devolução é simples — dentro da política e elegível para processamento imediato.\n\nO que o agente deve fazer?\n\n[ ] A - Reconhecer a frustração, informar que isso pode ser resolvido agora e oferecer-se para concluí-la ou escalonar.\n[ ] B - Chamar `escalate_to_human` imediatamente para atender ao pedido do cliente.\n[ ] C - Processar o reembolso via `process_refund` para resolver o problema de fundo e, em seguida, informar que está concluído.\n[ ] D - Perguntar especificamente o que não funcionou nas tentativas anteriores antes de decidir se escalona ou resolve automaticamente.','\n',char(10)),'[ ] A - Reconhecer a frustração, informar que isso pode ser resolvido agora e oferecer-se para concluí-la ou escalonar.','["Domain_2::Tool_Design_MCP_Integration", "Domain_1::Agentic_Architecture_Orchestration", "Scenario_1::Customer_Support_Agent"]','New',0,2.5,0,1783092984255,1783725247796,1783203558653,replace('TRADUÇÃO:\nUm cliente escreve: "Já estou indo e voltando com essa devolução há dias. Só quero falar com alguém que possa realmente me ajudar." O agente confirmou via `lookup_order` que a devolução é simples — dentro da política e elegível para processamento imediato.\n\nO que o agente deve fazer?\n\n[ ] A - Reconhecer a frustração, informar que isso pode ser resolvido agora e oferecer-se para concluí-la ou escalonar.\n[ ] B - Chamar `escalate_to_human` imediatamente para atender ao pedido do cliente.\n[ ] C - Processar o reembolso via `process_refund` para resolver o problema de fundo e, em seguida, informar que está concluído.\n[ ] D - Perguntar especificamente o que não funcionou nas tentativas anteriores antes de decidir se escalona ou resolve automaticamente.','\n',char(10)),replace('EXPLICAÇÃO PARA TECH LEAD:\n\nA alternativa correta é **A** por equilibrar empatia, capacidade de ação e autonomia do cliente.\n\n**Por que A é a melhor resposta:**\n1. **Validação emocional**: Reconhecer a frustração demonstra que o agente compreende o contexto negativo acumulado (múltiplas tentativas).\n2. **Demonstração de competência**: Informar que "isso pode ser resolvido agora" baseia-se no fato já verificado (`lookup_order` confirmou elegibilidade).\n3. **Oferta de controle**: Ao oferecer tanto a conclusão quanto o escalonamento, o cliente tem agência para escolher. Isso é crucial porque ele pediu "alguém que possa realmente me ajudar" — pode significar que quer uma solução rápida OU preferir conversar com humano.\n4. **Eficiência**: Se processado automaticamente, resolve em segundos; se escalonado, já há contexto completo.\n\n**Por que B está errado:**\n- Escalona imediatamente sem tentar resolver um problema verificado como simples e elegível.\n- Desrespeita a competência do agente: o agente JÁ confirmou que pode resolver.\n- Aumenta tempo de espera desnecessariamente quando há solução disponível.\n- O cliente pediu ajuda, não necessariamente humano — um agente competente que resolve é "alguém que ajuda".\n\n**Por que C está errado:**\n- Processa sem consentimento explícito.\n- Assume que o cliente quer a ação sem confirmar (ele pediu "alguém que ajude", não necessariamente autoriza a ação).\n- Viola princípios de transparência e controle do usuário.\n- Não reconhece ou valida a frustração acumulada.\n\n**Por que D está errado:**\n- Atrasa a solução com perguntas diagnósticas desnecessárias (já foi diagnosticado: elegível para processamento imediato).\n- Transfere trabalho mental para cliente frustrado.\n- Ignora que o cliente já tentou múltiplas vezes — mais investigação prolongará a frustração.\n- Padrão de "coleta de informação" antes de agir é ineficiente aqui.','\n',char(10)),replace('Um cliente está frustrado porque tentou devolver algo várias vezes e nada funciona. Ele quer alguém que realmente o ajude.\n\nO agente verificou nos registros e viu que essa devolução é fácil de fazer — não há problema.\n\n**O que ele deve fazer?**\n\n**Resposta A (a correta):**\nDizer: "Eu vejo que você está frustrado, e isso é justo. A boa notícia é que consigo resolver isso AGORA para você. Quer que eu faça isso, ou você prefere falar com uma pessoa?" \n\nIsso é bom porque:\n- Mostra que entende como o cliente se sente\n- Diz que pode resolver (porque realmente pode!)\n- Deixa o cliente escolher: quer que resolve rápido ou quer falar com alguém\n\n**Por que os outros não funcionam:**\n\n**B (transferir logo para uma pessoa):**\nComo se dissesse: "Vou buscar outra pessoa" — mas o agente JÁ consegue resolver! É como pedir ajuda a um adulto quando você já sabe fazer sozinho.\n\n**C (fazer o reembolso sem avisar):**\nÉ como seu pai comprar um presente para você sem perguntar o que você quer. Até que vire um presente, mas deveria ter perguntado primeiro.\n\n**D (fazer mais perguntas):**\nO cliente já tentou várias vezes — fazer mais perguntas o deixa ainda mais frustrado. É tipo quando você quebra um brinquedo e a mãe fica perguntando como quebrou, em vez de consertar logo.','\n',char(10)));
INSERT INTO cards VALUES('admin','card_1783092984262_047f6829u',56,'Quando o agente chama `lookup_order` e recebe detalhes do pedido mostrando que o item foi comprado há 45 dias, como o loop agêntico determina se deve chamar `process_refund` ou `escalate_to_human` em seguida?',replace('Quando o agente chama `lookup_order` e recebe detalhes do pedido mostrando que o item foi comprado há 45 dias, como o loop agêntico determina se deve chamar `process_refund` ou `escalate_to_human` em seguida?\n\nQuando o agente chama `lookup_order` e recebe detalhes do pedido mostrando que o item foi comprado há 45 dias, como o loop agêntico determina se deve chamar `process_refund` ou `escalate_to_human` em seguida?\n\n[ ] A - A camada de orquestração roteia automaticamente para a próxima ferramenta com base no campo de status do pedido.\n[ ] B - O agente segue uma árvore de decisão pré-configurada que mapeia atributos do pedido para chamadas de ferramentas específicas.\n[ ] C - Os detalhes do pedido são adicionados à conversa e o modelo raciocina sobre qual ação tomar.\n[ ] D - O agente executa as etapas restantes em uma sequência de ferramentas planejada no início da requisição.','\n',char(10)),'[ ] C - Os detalhes do pedido são adicionados à conversa e o modelo raciocina sobre qual ação tomar.','["Domain_1::Agentic_Architecture_Orchestration", "Domain_2::Tool_Design_MCP_Integration", "Scenario_1::Customer_Support_Agent"]','New',0,2.5,0,1783092984262,1783725251579,1783203558653,replace('**Tradução da pergunta e alternativas:**\n\nPergunta: Quando o agente chama `lookup_order` e recebe detalhes do pedido mostrando que o item foi comprado há 45 dias, como o loop agêntico determina se deve chamar `process_refund` ou `escalate_to_human` em seguida?\n\nAlternativas:\nA - A camada de orquestração roteia automaticamente para a próxima ferramenta com base no campo de status do pedido.\nB - O agente segue uma árvore de decisão pré-configurada que mapeia atributos do pedido para chamadas de ferramentas específicas.\nC - Os detalhes do pedido são adicionados à conversa e o modelo raciocina sobre qual ação tomar.\nD - O agente executa as etapas restantes em uma sequência de ferramentas planejada no início da requisição.','\n',char(10)),replace('**Explicação para Tech Lead:**\n\nA resposta correta é **C**. Este é um princípio fundamental dos agentic loops modernos baseados em LLMs.\n\n**Por que C é correto:**\n\nEm arquiteturas de agentes atuais (como o padrão implementado em frameworks como LangChain, AutoGen e nas APIs de agentes da OpenAI, Anthropic e similares), o loop agêntico funciona assim:\n\n1. O agente chama `lookup_order` via ferramenta\n2. O resultado (45 dias de compra) é **retornado ao modelo de linguagem** como parte do histórico conversacional\n3. O LLM então **raciocina** sobre o contexto completo:\n   - Políticas de reembolso típicas (ex: 30 dias para devolução completa)\n   - Risco envolvido (45 dias está além do período padrão)\n   - Necessidade de escalação para análise manual\n4. Com base nesse raciocínio, o modelo decide a próxima ferramenta a chamar\n\nEste é o padrão de "agentic reasoning" - o modelo mantém estado conversacional e toma decisões inteligentes baseadas em contexto, não em lógica determinística.\n\n**Por que as outras estão erradas:**\n\n**A - Orquestração automática por status:** Isso sugere roteamento baseado em regras simples. Embora seja possível em sistemas legados, não é como agentes modernos funcionam. Não há "campo de status" mágico que determina tudo - o raciocínio é mais nuançado.\n\n**B - Árvore de decisão pré-configurada:** Isso descreveria um sistema de rules engine ou state machine. Embora algumas aplicações utilizem isso, os agentic loops não dependem de árvores de decisão estáticas. Se o modelo precisa raciocinar sobre exceções ou contextos complexos (políticas variáveis, múltiplos fatores), uma árvore se torna infactível. A flexibilidade do LLM é o diferencial.\n\n**D - Sequência planejada no início:** Isso descreveria uma cadeia pré-determinada de ações (chain-of-thought puro), sem adaptabilidade. Um verdadeiro agente deve ser reativo - ajustar seu próximo passo baseado nos resultados obtidos, não seguir um plano rígido.\n\n**Implementação prática:**\n\n```python\n# Pseudocódigo de um agentic loop\nwhile True:\n    # 1. Modelo decide qual ferramenta chamar\n    tool_call = llm.invoke(messages)\n    \n    # 2. Executa ferramenta\n    if tool_call == "lookup_order":\n        result = lookup_order(order_id)\n    \n    # 3. ADICIONA resultado ao histórico conversacional (C é correto!)\n    messages.append({\n        "role": "assistant",\n        "content": tool_call\n    })\n    messages.append({\n        "role": "user",  # ou "tool"\n        "content": result  # "Comprado há 45 dias"\n    })\n    \n    # 4. Modelo raciocina sobre próximo passo\n    next_action = llm.invoke(messages)  # Decide entre process_refund ou escalate_to_human\n    \n    if next_action == "done":\n        break\n```\n\nO contexto (45 dias) entra no modelo para raciocínio, não para roteamento automático.','\n',char(10)),replace('Imagine que você é um assistente em uma loja e precisa decidir se faz um reembolso ou chama um gerente.\n\n**Como funciona:**\n\n1. Um cliente pede para devolver algo que comprou há 45 dias\n2. Você procura o pedido no computador (`lookup_order`) \n3. Você VÊ a informação: "Comprou há 45 dias" ✅\n4. Você PENSA sobre isso no seu cérebro:\n   - "Hmm, normalmente a gente deixa devolver em até 30 dias"\n   - "45 dias é MAIS do que o permitido"\n   - "Isso é complicado, melhor chamar o chefe"\n5. Por isso, você chama o gerente (`escalate_to_human`) em vez de fazer o reembolso sozinho\n\n**É assim que funciona com o agente:**\n\nO agente coloca a informação "45 dias" **NA CONVERSA** e depois **PENSA** sobre o que fazer. Como um humano que lê, entende e depois decide.\n\nAs outras opções estão erradas porque:\n- **A**: Não é um computador que automaticamente escolhe sim ou não\n- **B**: Não é uma lista fixa de "se dia > 30, faz isso"\n- **D**: Não é um plano que você faz antes e só segue\n\nÉ mais como você usando seu julgamento, entendendo o contexto! 🧠','\n',char(10)));
INSERT INTO cards VALUES('admin','card_1783092984269_9pv39ibm4',57,'Um cliente envia: "Isso é frustrante.',replace('Um cliente envia: "Isso é frustrante.\n\nUm cliente envia: "Isso é frustrante. Já expliquei meu problema duas vezes e nada está sendo resolvido. Quero falar com uma pessoa de verdade AGORA." O agente ainda não chamou nenhuma ferramenta para investigar a conta dele.\n\nO que o agente deve fazer?\n\n[ ] A - Reconhecer a frustração e fazer uma pergunta direcionada para entender o problema específico antes de escalonar.\n[ ] B - Explicar brevemente com o que o agente pode ajudar e oferecer-se para resolver o problema rapidamente, escalonando apenas se o cliente repetir o pedido.\n[ ] C - Chamar `escalate_to_human` imediatamente com o histórico da conversa.\n[ ] D - Primeiro chamar `get_customer` e `lookup_order` para reunir o contexto da conta e, em seguida, escalonar para um agente humano.','\n',char(10)),'[ ] A - Reconhecer a frustração e fazer uma pergunta direcionada para entender o problema específico antes de escalonar.','["Domain_1::Agentic_Architecture_Orchestration", "Scenario_1::Customer_Support_Agent"]','New',0,2.5,0,1783092984269,1783725255364,1783203558653,'TRADUÇÃO',replace('Um cliente envia: "Isso é frustrante. Já expliquei meu problema duas vezes e nada está sendo resolvido. Quero falar com uma pessoa de verdade AGORA." O agente ainda não chamou nenhuma ferramenta para investigar a conta dele.\n\nO que o agente deve fazer?\n\n[ ] A - Reconhecer a frustração e fazer uma pergunta direcionada para entender o problema específico antes de escalonar.\n[ ] B - Explicar brevemente com o que o agente pode ajudar e oferecer-se para resolver o problema rapidamente, escalonando apenas se o cliente repetir o pedido.\n[ ] C - Chamar `escalate_to_human` imediatamente com o histórico da conversa.\n[ ] D - Primeiro chamar `get_customer` e `lookup_order` para reunir o contexto da conta e, em seguida, escalonar para um agente humano.\n\n---\n\nEXPLICAÇÃO TÉCNICA\n\nA resposta correta é **A**, embora seja um contexto delicado que merece nuances importantes.\n\nA opção A é a melhor escolha porque:\n\n1. **Validação emocional + Ação prática**: Reconhecer a frustração demonstra empatia e validação do estado emocional do cliente, o que é essencial em customer service. Simultaneamente, fazer uma pergunta direcionada mostra que o agente está realmente investigando e não apenas ignorando o cliente.\n\n2. **Evita escalação precipitada**: Antes de escalonar, o agente deve tentar compreender o problema específico. Se o cliente foi vago nas explicações anteriores, uma pergunta bem direcionada pode revelar informações cruciais que o agente IA pode resolver.\n\n3. **Preserva recursos**: Escalonar imediatamente para agentes humanos consome recursos valiosos. Se uma pergunta simples e bem formulada puder resolver o problema, isso é mais eficiente.\n\n**Por que as outras alternativas estão erradas:**\n\n- **B (Explicar e oferecer-se)**: Soa genérica e pode parecer que o agente não está levando a frustração a sério. O cliente explicitamente pediu uma "pessoa de verdade", sugerindo que quer escalar.\n\n- **C (Escalonar imediatamente)**: Embora o cliente tenha pedido por um humano, o agente não investigou nada ainda. Escalonar sem contexto deixa o agente humano começando do zero, reduplica esforço e frustra ainda mais o cliente. Além disso, demonstra que o agente não tentou resolver.\n\n- **D (Chamar funções e depois escalonar)**: Isto é contraproducente. Se o cliente pede para falar com uma pessoa de verdade E já explicou duas vezes, adicionar delays técnicos (chamadas a APIs) pode parecer que o agente está ignorando o pedido. Além disso, se vai escalonar de qualquer forma, essas chamadas podem ser feitas pelo agente humano com contexto adequado.\n\n**A melhor abordagem prática:**\n\nO agente deve:\n1. Reconhecer: "Entendo sua frustração, e peço desculpas por ter que repetir tudo."\n2. Questionar: "Para que eu ou um colega possa resolver isto rapidamente, qual é especificamente o problema que não foi resolvido?"\n3. Então decidir: se a resposta revelar algo que o agente pode resolver, ele tenta. Se não, ele escala com contexto completo.\n\nIsto equilibra empatia, eficiência e respeito pelo tempo do cliente.','\n',char(10)),replace('Imagina que você está bravo porque pediu ajuda duas vezes e ninguém resolveu seu problema. Aí vem alguém e diz "Oi, vejo que você está bravo. Me conta de novo qual é o seu problema especificamente?" \n\nIsso é melhor do que:\n- Aquela pessoa simplesmente dizer "Posso te ajudar!" sem entender nada (opção B)\n- Aquela pessoa chamar o chefe na hora sem nem tentar ajudar (opção C)\n- Aquela pessoa ficar procurando informações primeiro e demorar ainda mais (opção D)\n\nA primeira opção (A) mostra que a pessoa realmente se importa e quer entender seu problema ANTES de envolver outras pessoas. Se conseguir resolver sozinha, ótimo! Se não conseguir, aí sim ela chama alguém mais experiente, mas com informações claras sobre o que é o seu problema.','\n',char(10)));
INSERT INTO cards VALUES('admin','card_1783092984275_i5dcp3gw8',58,'Seu agente está tratando uma disputa de cobrança.',replace('Seu agente está tratando uma disputa de cobrança.\n\nSeu agente está tratando uma disputa de cobrança. Depois de chamar `get_customer` e `lookup_order`, ele identifica que a disputa envolve um erro de preço promocional que exige aprovação gerencial — acima do nível de autorização do agente.\n\nComo o fluxo de trabalho deve lidar com esse escalonamento no meio do processo?\n\n[ ] A - Chamar `escalate_to_human` repassando apenas a mensagem original do cliente.\n[ ] B - Compilar um repasse estruturado com os dados do cliente, informações do pedido e o problema identificado antes de chamar `escalate_to_human`.\n[ ] C - Tentar o reembolso com `process_refund` mesmo assim, escalonando apenas se o sistema rejeitar a transação.\n[ ] D - Persistir a conversa completa e o histórico de respostas das ferramentas em um banco de dados e, em seguida, chamar `escalate_to_human` com um ID de referência.','\n',char(10)),'[ ] B - Compilar um repasse estruturado com os dados do cliente, informações do pedido e o problema identificado antes de chamar `escalate_to_human`.','["Domain_2::Tool_Design_MCP_Integration", "Domain_1::Agentic_Architecture_Orchestration", "Scenario_1::Customer_Support_Agent"]','New',0,2.5,0,1783092984275,1783725259124,1783203558653,replace('TRADUÇÃO:\nSua solicitação já está em português, portanto a tradução é direta:\n\nPergunta: "Seu agente está tratando uma disputa de cobrança. Depois de chamar `get_customer` e `lookup_order`, ele identifica que a disputa envolve um erro de preço promocional que exige aprovação gerencial — acima do nível de autorização do agente. Como o fluxo de trabalho deve lidar com esse escalonamento no meio do processo?"\n\nAlternativas:\n[ ] A - Chamar `escalate_to_human` repassando apenas a mensagem original do cliente.\n[ ] B - Compilar um repasse estruturado com os dados do cliente, informações do pedido e o problema identificado antes de chamar `escalate_to_human`.\n[ ] C - Tentar o reembolso com `process_refund` mesmo assim, escalonando apenas se o sistema rejeitar a transação.\n[ ] D - Persistir a conversa completa e o histórico de respostas das ferramentas em um banco de dados e, em seguida, chamar `escalate_to_human` com um ID de referência.','\n',char(10)),replace('EXPLICAÇÃO PARA TECH LEAD:\n\nA resposta correta é **B**. Este é um problema fundamental de design de fluxo de trabalho em sistemas de automação com escalonamento.\n\n**Por que B é correto:**\n\n1. **Contexto estruturado**: Ao compilar um repasse estruturado, você cria uma "passagem de contexto" eficiente. O agente humano recebe imediatamente:\n   - Dados do cliente (histórico, status)\n   - Informações do pedido (ID, itens, preço original vs. aplicado)\n   - Análise do problema (erro de preço promocional identificado)\n   - Status atual da interação\n\n2. **Eficiência operacional**: A escalação com contexto reduz o tempo de ramp-up do agente humano em 70-80%. Sem essa informação, o agente humano precisa refazer o trabalho de discovery.\n\n3. **Padrão de design de agent workflows**: Este é o padrão recomendado por frameworks como LangGraph, CrewAI e Azure Copilot para handoffs entre componentes (bot → humano).\n\n4. **Reduz fricção**: O cliente não precisa repetir informações ou aguardar o agente humano coletar os mesmos dados novamente.\n\n**Por que as alternativas estão erradas:**\n\n**A - Apenas mensagem original**: \n- Descarta todo o trabalho já realizado pelas ferramentas (`get_customer`, `lookup_order`)\n- Força o agente humano a recomeçar a investigação\n- Viola o princípio de "não perder contexto em escalonamentos"\n- Piora a experiência do cliente (aguarda mais)\n\n**C - Tentar process_refund mesmo assim**:\n- Viola o controle de autorização (problema EXIGE aprovação gerencial)\n- Criar um reembolso não autorizado = risco de compliance\n- Usar o escalonamento como "fallback" ao invés de "preventivo" é anti-padrão\n- Possível fraude ou violação de política de reembolsos\n\n**D - Persistir em banco de dados com ID de referência**:\n- Introduz complexidade desnecessária (overhead de BD)\n- Quebra o padrão de "state as data" (passar estrutura é mais eficiente que IDs)\n- Cria latência (busca no BD vs. dados em memória)\n- Problema potencial: o agente humano precisa fazer uma query extra\n- Aplicável em casos de "hand-offs assíncronos de longa duração", não para escalações imediatas\n\n**Contexto arquitetural:**\nEste é um padrão idêntico ao usado em:\n- OpenAI Assistant''s Tool Use → Escalation\n- SAP Concur''s expense approval workflows\n- Sistemas de suporte com tier-1 → tier-2 handoffs\n\nA compilação de um repasse estruturado é a "serialização ótima do contexto" entre agentes.','\n',char(10)),replace('Imagina que você está ajudando seu colega a resolver um problema, mas descobre que precisa de ajuda de alguém mais experiente (o chefe).\n\n**A resposta correta (B) é como:**\nVocê reúne TUDO que descobriu (o nome da pessoa, o pedido dela, qual foi o erro) e passa TUDO junto para o chefe. Assim, o chefe não perde tempo perguntando de novo — ele já sabe exatamente o que aconteceu!\n\n**Por que as outras não funcionam:**\n\n**A (apenas mensagem original):**\nÉ como você esquecer de contar ao chefe TUDO que aprendeu e passar só o primeiro pedido. O chefe vai perguntar: "Mas quem é o cliente? Qual é o pedido? O que você descobriu?" Perda de tempo!\n\n**C (tentar fazer de qualquer jeito):**\nÉ como você tentar fazer algo que precisa de autorização do chefe SEM pedir permissão primeiro. Pode dar problema! Melhor pedir antes.\n\n**D (salvar tudo no computador e dar um número):**\nÉ como você escrever tudo em um caderno e dizer ao chefe: "Tá tudo no caderno lá" — o chefe ainda precisa ir procurar. Mais fácil você contar tudo para ele agora!','\n',char(10)));
INSERT INTO cards VALUES('admin','card_1783092984282_62nyues2v',59,'Sistema de Pesquisa Multiagente',replace('Sistema de Pesquisa Multiagente\n\nLogs de produção mostram um padrão persistente: pedidos como "analise o relatório trimestral enviado" são roteados ao agente de busca web em 45% das vezes em vez de ao agente de análise de documentos. Revisando as definições das ferramentas, você descobre que o agente de busca web tem uma ferramenta `analyze_content` descrita como "analyzes content and extracts key information", enquanto o agente de análise de documentos tem `analyze_document` descrita como "analyzes documents and extracts key information". Como corrigir o problema de roteamento errado?\n\n[ ] A - Adicionar um classificador de pré-roteamento que detecta se o usuário se refere a arquivos enviados ou a conteúdo web antes de o coordenador decidir a delegação.\n[ ] B - Renomear a ferramenta de busca web para `extract_web_results` e atualizar sua descrição para "processes and returns information retrieved from web search and URLs."\n[ ] C - Adicionar exemplos few-shot ao prompt do coordenador mostrando o roteamento correto: "User uploads a quarterly report → document analysis agent" e "User asks about a web page → web-search agent."\n[ ] D - Expandir a descrição da ferramenta de análise de documentos com exemplos de uso como "Use for uploaded PDFs, Word docs, and spreadsheets," deixando a ferramenta de busca web inalterada.','\n',char(10)),'[ ] A - Adicionar um classificador de pré-roteamento que detecta se o usuário se refere a arquivos enviados ou a conteúdo web antes de o coordenador decidir a delegação.','["Domain_2::Tool_Design_MCP_Integration", "Domain_4::Prompt_Engineering_Structured_Output", "Domain_1::Agentic_Architecture_Orchestration", "Scenario_3::Multi_Agent_Research"]','New',0,2.5,0,1783092984282,1783725262576,1783203558653,replace('TRADUÇÃO DA PERGUNTA E ALTERNATIVAS:\n\nSistema de Pesquisa Multiagente\n\nLogs de produção mostram um padrão persistente: pedidos como "analise o relatório trimestral enviado" são roteados ao agente de busca web em 45% das vezes em vez de ao agente de análise de documentos. Revisando as definições das ferramentas, você descobre que o agente de busca web tem uma ferramenta `analyze_content` descrita como "analisa conteúdo e extrai informações-chave", enquanto o agente de análise de documentos tem `analyze_document` descrita como "analisa documentos e extrai informações-chave". Como corrigir o problema de roteamento errado?\n\n[ ] A - Adicionar um classificador de pré-roteamento que detecta se o usuário se refere a arquivos enviados ou a conteúdo web antes de o coordenador decidir a delegação.\n[ ] B - Renomear a ferramenta de busca web para `extract_web_results` e atualizar sua descrição para "processa e retorna informações recuperadas de busca web e URLs."\n[ ] C - Adicionar exemplos few-shot ao prompt do coordenador mostrando o roteamento correto: "Usuário envia um relatório trimestral → agente de análise de documentos" e "Usuário pergunta sobre uma página web → agente de busca web."\n[ ] D - Expandir a descrição da ferramenta de análise de documentos com exemplos de uso como "Use para PDFs, documentos Word e planilhas enviadas," deixando a ferramenta de busca web inalterada.','\n',char(10)),replace('EXPLICAÇÃO TÉCNICA (PARA TECH LEAD):\n\nEste é um problema clássico de ambiguidade semântica em sistemas multiagente. A raiz do problema é que ambas as descrições de ferramentas usam o termo genérico "analyze_content" e "analyze_document", sendo que "content" é vago demais e pode englobar tanto conteúdo web quanto documentos enviados.\n\n**Por que a alternativa A é a correta:**\n\nA alternativa A propõe adicionar um classificador de pré-roteamento, que é a solução mais robusta e eficaz. Um classificador de pré-roteamento:\n- Resolve o problema na raiz: antes do coordenador tentar interpretar qual agente usar, um classificador detecta explicitamente se o usuário menciona "arquivo enviado", "relatório anexado", "documento" vs. "página web", "busca na web", "URL".\n- Reduz a ambiguidade semântica: não depende de interpretação fuzzy das descrições das ferramentas\n- Oferece precisão superior: funcionaria em 95%+ dos casos porque é uma tarefa de classificação binária simples\n- Escalável: pode ser expandido para lidar com outros tipos de requisições sem afetar o coordenador\n\n**Por que as alternativas estão erradas:**\n\n**B - Renomear ferramenta e atualizar descrição:**\nSuperficial demais. Mesmo com melhor nomenclatura, o LLM coordenador ainda teria que interpretar semanticamente qual ferramenta usar baseado em processamento de linguagem natural. A descrição "processa e retorna informações recuperadas de busca web" continua sendo passível de interpretação ambígua quando o usuário diz "analise este relatório trimestral" - o coordenador ainda pode confundir a intenção.\n\n**C - Adicionar exemplos few-shot:**\nMelhor que B, mas ainda inadequado. Few-shot prompting funciona bem para LLMs, porém:\n- Depende da qualidade do prompt e pode não generalizar bem para variações não cobertas pelos exemplos\n- O problema já demonstra falha em 45% dos casos com as ferramentas existentes; adicionar exemplos ao prompt sem resolver a ambiguidade semântica fundamental ainda deixaria margem para erro\n- É um "band-aid" no coordenador em vez de resolver o problema estruturalmente\n\n**D - Expandir descrição do agente de documentos:**\nParcial e incompleto. Expandir apenas uma descrição não resolve a ambiguidade bilateral:\n- Se o agente web tem descrição vaga, ele ainda será escolhido erroneamente\n- O problema é a ambiguidade no roteamento, não apenas na definição do agente de documentos\n- Como na alternativa B, continua dependendo de interpretação semântica do coordenador\n\n**Conclusão:**\n\nA alternativa A implementa uma camada de classificação dedicada (pode ser um modelo pequeno, regex inteligente, ou até um LLM lightweight) que reduz a carga cognitiva do coordenador, focando-o apenas em delegação para o agente correto já pré-determinado. Isso garante roteamento determinístico em vez de probabilístico.','\n',char(10)),replace('EXPLICAÇÃO PARA CRIANÇA DE 10 ANOS:\n\nImagine que você tem dois amigos ajudantes:\n- O amigo "Web" é bom em procurar coisas na internet\n- O amigo "Documentos" é bom em ler arquivos que você salva no computador\n\nO problema é: quando alguém pede "analise o relatório que enviei", o amigo Web está recebendo essa tarefa 45% das vezes, mesmo sendo responsabilidade do amigo Documentos!\n\nÉ como se você pedisse para seu amigo Web buscar um arquivo que está dentro da sua mochila - mas a mochila é trabalho do seu amigo Documentos!\n\n**A solução correta (Alternativa A):**\nColocar um "policial de trânsito" na entrada que olha para o pedido ANTES de enviar para qualquer amigo:\n- Ele vê a palavra "enviado" ou "relatório salvo"? → Envia para o amigo Documentos ✓\n- Ele vê a palavra "web" ou "internet"? → Envia para o amigo Web ✓\n\n**Por que as outras estão erradas:**\n\n**B - Mudar o nome:**\nÉ como mudar o nome da camiseta do amigo Web de "análise" para "busca web". O policial de trânsito (seu coordenador) ainda ficaria confuso!\n\n**C - Dar exemplos:**\nÉ como ensinar o amigo Web mais exemplos de quando ele deve trabalhar. Mas o problema é que ele continua recebendo tarefas erradas de documentos!\n\n**D - Só melhorar o amigo Documentos:**\nÉ como deixar o amigo Documentos com um uniforme melhor, mas não ensinar ao policial de trânsito a diferença. O amigo Web continua recebendo tarefas erradas!\n\nO segredo é: **colocar alguém (um classificador) antes de delegar, para ver exatamente qual tipo de tarefa é e enviar ao amigo certo!**\n','\n',char(10)));
INSERT INTO cards VALUES('admin','card_1783092984288_e5ngxbct8',60,'Sistema de Pesquisa Multiagente',replace('Sistema de Pesquisa Multiagente\n\nNo seu desenho de sistema, você deu ao agente de análise de documentos acesso a uma ferramenta de uso geral `fetch_url` para que ele pudesse baixar documentos por URL. Logs de produção mostram que esse agente agora frequentemente baixa páginas de resultados de busca para fazer busca web ad hoc — comportamento que deveria passar pelo agente de busca web — causando resultados inconsistentes. Qual correção é mais efetiva?\n\n[ ] A - Substituir `fetch_url` por uma ferramenta `load_document` que valida que URLs apontem para formatos de documento.\n[ ] B - Remover `fetch_url` do agente de análise de documentos e rotear toda busca por URL pelo coordenador para o agente de busca web.\n[ ] C - Implementar filtragem que bloqueia chamadas de `fetch_url` para domínios conhecidos de buscadores enquanto permite outras URLs.\n[ ] D - Adicionar instruções no prompt do agente de análise de documentos dizendo que `fetch_url` só deve ser usada para baixar URLs de documentos, não para buscar.','\n',char(10)),'[ ] B - Remover `fetch_url` do agente de análise de documentos e rotear toda busca por URL pelo coordenador para o agente de busca web.','["Domain_1::Agentic_Architecture_Orchestration", "Domain_2::Tool_Design_MCP_Integration", "Scenario_3::Multi_Agent_Research"]','New',0,2.5,0,1783092984288,1783725266893,1783203558653,'TRADUÇÃO',replace('No seu desenho de sistema, você deu ao agente de análise de documentos acesso a uma ferramenta de uso geral `fetch_url` para que ele pudesse baixar documentos por URL. Logs de produção mostram que esse agente agora frequentemente baixa páginas de resultados de busca para fazer busca web ad hoc — comportamento que deveria passar pelo agente de busca web — causando resultados inconsistentes. Qual correção é mais efetiva?\n\n[ ] A - Substituir `fetch_url` por uma ferramenta `load_document` que valida que URLs apontem para formatos de documento.\n[ ] B - Remover `fetch_url` do agente de análise de documentos e rotear toda busca por URL pelo coordenador para o agente de busca web.\n[ ] C - Implementar filtragem que bloqueia chamadas de `fetch_url` para domínios conhecidos de buscadores enquanto permite outras URLs.\n[ ] D - Adicionar instruções no prompt do agente de análise de documentos dizendo que `fetch_url` só deve ser usada para baixar URLs de documentos, não para buscar.\n\n---\n\nEXPLICAÇÃO PARA TECH LEAD\n\nA resposta correta é **B**. Esta questão explora um princípio fundamental de design em sistemas multiagente: **separation of concerns** e **enforcement de responsabilidades através de mecanismos de controle de acesso**.\n\n**Por que B é a melhor solução:**\n\n1. **Enforce at architecture level**: A opção B resolve o problema na camada de arquitetura, removendo a **capacidade técnica** do agente fazer algo que ele não deveria fazer. Isso é mais robusto que contar com instruções ou validações.\n\n2. **Single source of truth**: O agente de busca web torna-se o único responsável por operações de busca por URL. Isso garante consistência, logging centralizado e aplicação de mesmos critérios/políticas.\n\n3. **Evita bypass de coordenação**: Quando o agente de análise pode chamar `fetch_url` diretamente, ele efetivamente contorna o sistema de coordenação. Remover essa capacidade força que qualquer busca por URL seja roteada através do coordenador.\n\n4. **Reduz classes de erro**: Elimina a categoria inteira de "uso inadequado da ferramenta errada" removendo a tentação técnica.\n\n**Por que as alternativas estão erradas:**\n\n**Opção A** - `load_document` com validação:\n- Continua permitindo ao agente de análise fazer requisições de URL sem coordenação\n- Validação de "formato de documento" é frágil (search engines podem servir documentos HTML válidos)\n- Não resolve o problema raiz: o agente ainda contorna o fluxo de busca web\n- Transfere a responsabilidade para heurísticas de validação em vez de retirar a capacidade\n\n**Opção C** - Filtragem por domínios de buscadores:\n- É uma solução baseada em lista de negra, inerentemente frágil\n- Novos buscadores ou subdomínios podem não estar na lista\n- Não aborda o problema de raiz: por que esse agente está fazendo busca?\n- Técnica de "whack-a-mole" que requer manutenção contínua\n\n**Opção D** - Instruções no prompt:\n- **A solução mais fraca** para problemas de comportamento não desejado em IA\n- Prompts são orientações, não garantias. Agentes podem "alucinar" e ignorar instruções\n- Já há evidência em logs de que prompts não estão sendo seguidos\n- Não fornece nenhum mecanismo que impeça o comportamento inadequado\n\n**Princípio de design**: Em sistemas com múltiplos agentes especializados, a separação de responsabilidades deve ser **enforçada pelo sistema**, não apenas documentada. Se você quer que um agente não faça X, remova sua capacidade de fazer X.','\n',char(10)),replace('Imagina que você tem dois amigos especializados:\n- **João** é especialista em buscar coisas na internet\n- **Maria** é especialista em ler documentos\n\nNo começo, Maria ganhou a "ferramenta de pegar qualquer coisa da internet" (`fetch_url`). Problema: Maria começou a usar essa ferramenta para fazer buscas na internet, o que deveria ser trabalho do João! Agora ficou bagunçado — às vezes ela pega uma coisa, às vezes outra, sem coordenação com João.\n\n**O que fazer?**\n\n**Opção B (a correta)** - Tirar a ferramenta da mão de Maria. Só João tem a ferramenta de busca. Se Maria precisa de algo da internet, ela pede para João buscar. Assim só uma pessoa faz buscas, e fica tudo consistente.\n\n**As outras opções:**\n- **A**: Dar a Maria uma ferramenta "melhor" que valida documentos — mas ela ainda pode fazer buscas escondido\n- **C**: Bloquear só buscadores conhecidos — mas e se aparecer um novo buscador? Continua bagunçado\n- **D**: Escrever uma nota para Maria dizendo "use certo" — mas as notas não funcionam, os logs mostram que ela continua usando errado\n\n**A lição**: Quando você quer garantir que alguém não faça algo, retire a ferramenta da mão da pessoa. Instruções são fracas; remover capacidade é forte.','\n',char(10)));
INSERT INTO cards VALUES('admin','card_1783092984305_a1s7mxw87',61,'Sistema de Pesquisa Multiagente',replace('Sistema de Pesquisa Multiagente\n\nEm testes, você observa que o agente de síntese frequentemente precisa verificar afirmações específicas ao mesclar resultados. Atualmente, quando verificação é necessária, o agente de síntese devolve o controle ao coordenador, que chama o agente de busca web e então re-invoca a síntese com os resultados. Isso adiciona 2–3 loops extras por tarefa e aumenta a latência em 40%. Sua avaliação mostra que 85% dessas verificações são checagens simples (datas, nomes, estatísticas) e 15% exigem pesquisa mais profunda. Qual abordagem é mais efetiva para reduzir overhead preservando confiabilidade?\n\n[ ] A - Dar ao agente de síntese acesso a todas as ferramentas de busca web para que ele possa lidar com qualquer necessidade de verificação diretamente, sem loops do coordenador.\n[ ] B - Fazer o agente de síntese acumular todas as necessidades de verificação e devolvê-las como um lote ao coordenador no fim, que então as envia todas de uma vez ao agente de busca web.\n[ ] C - Fazer o agente de busca web cachear proativamente contexto extra ao redor de cada fonte durante a pesquisa inicial, antecipando necessidades da síntese.\n[ ] D - Dar ao agente de síntese uma ferramenta `verify_fact` de escopo limitado para checagens simples, enquanto roteia verificações complexas pelo coordenador para o agente de busca web.','\n',char(10)),'D - Dar ao agente de síntese uma ferramenta `verify_fact` de escopo limitado para checagens simples, enquanto roteia verificações complexas pelo coordenador para o agente de busca web.','["Domain_1::Agentic_Architecture_Orchestration", "Domain_4::Prompt_Engineering_Structured_Output", "Domain_2::Tool_Design_MCP_Integration", "Scenario_3::Multi_Agent_Research"]','New',0,2.5,0,1783092984305,1783725270980,1783203558653,replace('**Tradução para pt-BR:**\n\nSistema de Pesquisa Multiagente\n\nEm testes, você observa que o agente de síntese frequentemente precisa verificar afirmações específicas ao mesclar resultados. Atualmente, quando verificação é necessária, o agente de síntese devolve o controle ao coordenador, que chama o agente de busca web e então re-invoca a síntese com os resultados. Isso adiciona 2–3 loops extras por tarefa e aumenta a latência em 40%. Sua avaliação mostra que 85% dessas verificações são checagens simples (datas, nomes, estatísticas) e 15% exigem pesquisa mais profunda. Qual abordagem é mais efetiva para reduzir overhead preservando confiabilidade?\n\n[ ] A - Dar ao agente de síntese acesso a todas as ferramentas de busca web para que ele possa lidar com qualquer necessidade de verificação diretamente, sem loops do coordenador.\n[ ] B - Fazer o agente de síntese acumular todas as necessidades de verificação e devolvê-las como um lote ao coordenador no fim, que então as envia todas de uma vez ao agente de busca web.\n[ ] C - Fazer o agente de busca web cachear proativamente contexto extra ao redor de cada fonte durante a pesquisa inicial, antecipando necessidades da síntese.\n[ ] D - Dar ao agente de síntese uma ferramenta `verify_fact` de escopo limitado para checagens simples, enquanto roteia verificações complexas pelo coordenador para o agente de busca web.','\n',char(10)),replace('**Explicação para adulto tech lead:**\n\nA alternativa **D** é a mais efetiva porque adota uma estratégia de roteamento baseada na complexidade da verificação, casando perfeitamente com os dados do problema: 85% das verificações são simples (requerem apenas consulta pontual a uma fonte já disponível) e 15% são complexas (exigem pesquisa web adicional).\n\n- **D (correta):** A ferramenta `verify_fact` com escopo limitado permite que o agente de síntese resolva localmente a grande maioria das verificações (85%) sem qualquer intervenção do coordenador, eliminando drasticamente os 2-3 loops extras. Para os 15% restantes, o roteamento via coordenador para o agente de busca web mantém a confiabilidade, pois verificações complexas realmente se beneficiam de um agente especializado em busca. Essa abordagem reduz o overhead seletivamente, sem sacrificar a qualidade.\n\n- **A (incorreta):** Dar acesso a todas as ferramentas de busca web ao agente de síntese cria um problema de responsabilidades e complexidade. O agente de síntese foi projetado para mesclar e sintetizar informações, não para fazer buscas web profundas. Isso aumentaria a carga cognitiva do agente, poderia levar a loops não intencionais de busca e síntese, e não traria benefício claro sobre a abordagem D, além de potencialmente duplicar a lógica de busca.\n\n- **B (incorreta):** Acumular verificações e devolvê-las em lote no final reduz o número de loops, mas ainda exige intervenção do coordenador para *todas* as verificações (atraso de pelo menos 1 loop). Além disso, ao postergar as verificações para o final, você quebra o fluxo natural de síntese — o agente precisaria "adivinhar" ou marcar posição, o que pode comprometer a qualidade da síntese intermediária e forçar retrabalho.\n\n- **C (incorreta):** Cachear contexto extra proativamente é ineficiente porque você não sabe quais fontes ou trechos serão necessários. Você estaria armazenando dados que podem nunca ser usados, aumentando o custo de memória e processamento sem garantia de redução de latência. Além disso, verificações complexas (15%) ainda exigiriam nova busca, pois o cache pode não conter a informação necessária.\n\nPortanto, D resolve 85% dos casos sem overhead algum e mantém o processo controlado para os 15% restantes, sendo a solução mais equilibrada entre performance e confiabilidade.','\n',char(10)),replace('Imagine que você está montando um quebra-cabeça gigante com seus amigos. Um amigo (o agente de síntese) junta as peças, mas às vezes ele precisa ver se a peça encaixa mesmo — tipo checar uma data ou um nome. Antes, toda vez que ele precisava verificar algo, ele tinha que levantar, ir até o amigo que organiza as tarefas (o coordenador), que chamava outro amigo que buscava informações (o agente de busca), e depois voltava tudo de novo. Isso demorava muito!\n\nAgora, a ideia D é dar para o primeiro amigo uma lupa especial (a ferramenta `verify_fact`). Com ela, ele pode dar uma olhadinha rápida na maioria das vezes (85% dos casos) sem precisar incomodar ninguém. Mas, para as perguntas mais difíceis (15%), ele ainda chama o coordenador, que pede ajuda para o amigo que sabe buscar bem. Assim, a gente resolve rápido a maior parte do tempo e não perde a qualidade nas perguntas difíceis.\n\nAs outras opções não são tão boas:\n- A: Dar tudo para o primeiro amigo faria ele virar um "faz-tudo" e poderia bagunçar o trabalho dele.\n- B: Juntar todas as dúvidas para perguntar só no final faria ele ter que parar de montar o quebra-cabeça várias vezes, além de perder o ritmo.\n- C: Tentar adivinhar o que ele vai perguntar e já deixar anotado daria muito trabalho extra e muitas anotações que nunca seriam usadas.\n\nEntão, a opção D é a mais esperta: resolve rapidinho o que dá e pede ajuda só quando precisa de verdade!','\n',char(10)));
INSERT INTO cards VALUES('admin','card_1783092984312_w4t3qk3eg',62,'Claude Code para Integração Contínua',replace('Claude Code para Integração Contínua\n\nSeu componente de code review é iterativo: Claude analisa o arquivo modificado, depois pode pedir arquivos relacionados (imports, classes-base, testes) via chamadas de ferramenta para entender contexto antes de prover feedback final. Sua aplicação define uma ferramenta que permite a Claude pedir conteúdo de arquivos; Claude chama a ferramenta, recebe resultados e continua a análise. Você está avaliando processamento em lote para reduzir custo de API. Qual é a principal limitação técnica ao considerar processamento em lote para esse fluxo?\n\n[ ] A - O processamento em lote não inclui IDs de correlação para mapear saídas de volta às requisições de entrada.\n[ ] B - O modelo assíncrono não consegue executar ferramentas no meio da requisição e devolver resultados para Claude continuar a análise.\n[ ] C - A Batch API não suporta definições de ferramentas nos parâmetros da requisição.\n[ ] D - A latência de até 24 horas do processamento em lote é lenta demais para feedback de pull request, embora o fluxo funcionasse no resto.','\n',char(10)),'B - O modelo assíncrono não consegue executar ferramentas no meio da requisição e devolver resultados para Claude continuar a análise.','["Domain_3::Claude_Code_Configuration_Workflows", "Domain_5::Context_Management_Reliability", "Domain_2::Tool_Design_MCP_Integration", "Scenario_5::Claude_Code_CI_CD"]','New',0,2.5,0,1783092984312,1783725274852,1783203558653,replace('## Tradução\n\n**Claude Code para Integração Contínua**\n\nSeu componente de code review é iterativo: Claude analisa o arquivo modificado, depois pode solicitar arquivos relacionados (imports, classes base, testes) por meio de chamadas de ferramenta para entender o contexto antes de fornecer o feedback final. Sua aplicação define uma ferramenta que permite ao Claude solicitar conteúdo de arquivos; Claude chama a ferramenta, recebe os resultados e continua a análise. Você está avaliando o processamento em lote para reduzir custo de API. Qual é a principal limitação técnica ao considerar processamento em lote para esse fluxo?\n\n[ ] A - O processamento em lote não inclui IDs de correlação para mapear saídas de volta às requisições de entrada.\n[ ] B - O modelo assíncrono não consegue executar ferramentas no meio da requisição e devolver resultados para Claude continuar a análise.\n[ ] C - A Batch API não suporta definições de ferramentas nos parâmetros da requisição.\n[ ] D - A latência de até 24 horas do processamento em lote é lenta demais para feedback de pull request, embora o fluxo funcionasse no resto.','\n',char(10)),replace('## Explicação para Tech Lead\n\n### Resposta correta: B\n\nO fluxo descrito é **interativo e dinâmico**: Claude analisa um arquivo, decide que precisa de mais contexto, faz uma chamada de ferramenta (tool call) para buscar um arquivo relacionado, recebe o conteúdo desse arquivo e só então continua a análise para produzir o feedback final. Isso é um padrão de **múltiplas rodadas de requisição-resposta** dentro de uma única sessão.\n\nA **Batch API** da Anthropic (e de provedores similares) funciona de forma **assíncrona e não interativa**: você submete um lote de requisições completas de uma só vez, e elas são processadas em lote, sem possibilidade de encadeamento ou feedback loop entre elas. O modelo não pode, no meio do processamento de uma requisição em lote, fazer uma chamada de ferramenta, esperar o resultado externo e depois continuar a mesma requisição — porque isso exigiria um ciclo síncrono de ida-e-volta que não existe no modelo batch.\n\n### Por que as outras alternativas estão erradas:\n\n- **A**: IDs de correlação são um detalhe de implementação e existem em praticamente todas as Batch APIs (incluindo a da Anthropic, que permite `custom_id`). Mesmo que não existissem, seria um problema trivial de contornar — não seria uma "limitação técnica principal" para esse fluxo.\n\n- **C**: A Batch API da Anthropic **suporta** definições de ferramentas (`tools`) nos parâmetros da requisição. Você pode definir ferramentas normalmente em cada item do lote. A limitação não está na definição, mas na **execução** — o modelo não consegue usar a ferramenta e receber o resultado no mesmo ciclo batch.\n\n- **D**: A latência de até 24h é um **trade-off** conhecido, mas não é a *limitação técnica principal* que inviabiliza o fluxo. Mesmo se o batch fosse processado em 1 segundo, o fluxo ainda não funcionaria, porque o problema central é a **incapacidade de executar ferramentas interativamente**. A latência é um problema de UX, não um impeditivo técnico fundamental para o padrão descrito.','\n',char(10)),replace('Imagine que você está resolvendo um quebra-cabeça e, de vez em quando, precisa pedir ajuda ao seu amigo para pegar uma peça que está longe. Você pede, ele busca e te entrega, e aí você continua montando.\n\nAgora imagina que, em vez disso, você escreve todas as suas dúvidas num papel e entrega tudo de uma vez para seu amigo — mas ele não pode te responder na hora porque está muito ocupado. Só no dia seguinte ele volta com as respostas. O problema é que, enquanto ele estava respondendo, você não podia perguntar de novo: "Ei, achei essa peça aqui, preciso de outra!" — porque a conversa já tinha acabado.\n\nÉ mais ou menos isso que acontece com o processamento em lote (batch). O Claude não consegue, no meio do caminho, pedir um arquivo novo, esperar a resposta e continuar analisando. Ele teria que já saber tudo de antemão, mas o fluxo de code review precisa que ele peça coisas novas conforme descobre o que precisa. Por isso a opção B é a correta.','\n',char(10)));
INSERT INTO cards VALUES('admin','card_1783092984320_s8h984968',63,'Agente de Suporte ao Cliente',replace('Agente de Suporte ao Cliente\n\nEm testes, você nota que o agente frequentemente chama `get_customer` quando usuários perguntam sobre status de pedido, embora `lookup_order` fosse mais apropriado. O que você deve checar primeiro para tratar esse problema?\n\n[ ] A - Implementar um classificador de pré-processamento para detectar pedidos relacionados a ordem e roteá-los diretamente a `lookup_order`.\n[ ] B - Reduzir o número de ferramentas disponíveis ao agente para simplificar a escolha.\n[ ] C - Adicionar exemplos few-shot ao system prompt cobrindo todos os padrões possíveis de pedido para melhorar a seleção de ferramentas.\n[ ] D - Verificar as descrições das ferramentas para garantir que diferenciem claramente o propósito de cada uma.','\n',char(10)),'[ ] D - Verificar as descrições das ferramentas para garantir que diferenciem claramente o propósito de cada uma.','["Domain_2::Tool_Design_MCP_Integration", "Domain_4::Prompt_Engineering_Structured_Output", "Scenario_1::Customer_Support_Agent"]','New',0,2.5,0,1783092984320,1783725278713,1783203558653,replace('**Tradução para português do Brasil:**\n\n**Agente de Suporte ao Cliente**\n\nEm testes, você nota que o agente frequentemente chama `get_customer` quando usuários perguntam sobre status de pedido, embora `lookup_order` fosse mais apropriado. O que você deve checar primeiro para tratar esse problema?\n\n[ ] A - Implementar um classificador de pré-processamento para detectar pedidos relacionados a pedido e roteá-los diretamente a `lookup_order`.\n[ ] B - Reduzir o número de ferramentas disponíveis ao agente para simplificar a escolha.\n[ ] C - Adicionar exemplos few-shot ao system prompt cobrindo todos os padrões possíveis de pedido para melhorar a seleção de ferramentas.\n[ ] D - Verificar as descrições das ferramentas para garantir que diferenciem claramente o propósito de cada uma.','\n',char(10)),replace('**Explicação para adulto tech lead:**\n\nO problema descrito é um clássico de agentes baseados em LLM: o agente está escolhendo a ferramenta errada (`get_customer` em vez de `lookup_order`) para uma intenção do usuário. Isso geralmente ocorre porque o modelo não consegue distinguir adequadamente quando usar cada ferramenta.\n\nA alternativa **D** é a resposta correta porque o primeiro passo de diagnóstico deve ser verificar se as **descrições das ferramentas** são claras e distintas. Em agentes LLM, as descrições funcionam como a "documentação da API" para o modelo — elas são a principal fonte de informação que o modelo usa para decidir qual ferramenta chamar. Se `get_customer` e `lookup_order` têm descrições vagas, similares ou ambíguas, o modelo naturalmente errará. **Antes de qualquer intervenção mais complexa**, você deve garantir que a base do problema (as definições das ferramentas) está correta.\n\n**Por que as demais alternativas estão incorretas como *primeiro* passo:**\n\n- **A (classificador de pré-processamento):** É uma solução pesada e prematura. Adicionar uma camada de classificação externa aumenta a complexidade do sistema, custo de manutenção e latência. Deve ser considerado só depois de descartar problemas mais simples, como descrições ruins.\n\n- **B (reduzir o número de ferramentas):** Embora reduzir o espaço de escolha possa ajudar, é uma abordagem reativa e limitante. Se as descrições estiverem bem escritas, o modelo consegue lidar com múltiplas ferramentas sem problemas. Reduzir ferramentas pode quebrar outras funcionalidades.\n\n- **C (adicionar exemplos few-shot):** Few-shot learning pode melhorar o comportamento, mas não ataca a causa raiz. Se as descrições são ruins, o few-shot pode até mascarar o problema ou não generalizar bem para variações de perguntas. Além disso, cobrir "todos os padrões possíveis" é inviável e não escalável.\n\n**Resumo:** Sempre comece pelo mais básico e de menor custo: verifique se o modelo tem informações suficientes e claras para tomar a decisão correta. As descrições das ferramentas são o *primeiro* ponto de checagem.','\n',char(10)),replace('Imagine que o agente de suporte é como um robô que ajuda a resolver problemas. Ele tem duas "ferramentas": uma chamada `get_customer` (que serve para saber quem é o cliente) e outra chamada `lookup_order` (que serve para ver o status do pedido).\n\nO robô está confundindo as ferramentas: quando alguém pergunta "qual o status do meu pedido?", ele usa a ferramenta errada.\n\nA primeira coisa que devemos fazer é **olhar as instruções que demos para o robô sobre cada ferramenta**. Se as instruções estão mal escritas, é como se a gente desse duas caixas de ferramentas para o robô e dissesse "essa aqui serve para coisas" e "essa outra também serve para coisas". É óbvio que ele vai se confundir!\n\nEntão, antes de fazer qualquer coisa mais complicada (como treinar outro robô para ajudar, ou diminuir o número de ferramentas), a gente primeiro verifica se as **descrições** estão claras o suficiente para o robô entender a diferença entre elas. É como arrumar a etiqueta de cada caixa de ferramentas antes de sair comprando mais coisas ou mudando tudo.','\n',char(10)));
INSERT INTO cards VALUES('admin','card_1783092984327_lvx69qbsh',64,'Agente de Suporte ao Cliente',replace('Agente de Suporte ao Cliente\n\nLogs de produção mostram que em 12% dos casos seu agente pula `get_customer` e chama `lookup_order` diretamente usando apenas o nome fornecido pelo cliente, às vezes levando a contas mal identificadas e reembolsos incorretos. Qual mudança corrige esse problema de confiabilidade de forma mais efetiva?\n\n[ ] A - Adicionar exemplos few-shot mostrando que o agente sempre chama `get_customer` primeiro, mesmo quando clientes voluntariamente fornecem detalhes do pedido.\n[ ] B - Implementar um classificador de roteamento que analisa cada pedido e habilita só um subconjunto de ferramentas apropriado para o tipo.\n[ ] C - Adicionar uma pré-condição programática que bloqueia `lookup_order` e `process_refund` até que `get_customer` retorne um identificador verificado.\n[ ] D - Reforçar o system prompt declarando que verificação do cliente via `get_customer` é mandatória antes de qualquer operação de pedido.','\n',char(10)),'C - Adicionar uma pré-condição programática que bloqueia `lookup_order` e `process_refund` até que `get_customer` retorne um identificador verificado.','["Domain_5::Context_Management_Reliability", "Domain_2::Tool_Design_MCP_Integration", "Scenario_1::Customer_Support_Agent"]','New',0,2.5,0,1783092984327,1783725282806,1783203558653,replace('**Tradução para português do Brasil:**\n\n**Pergunta:** Agente de Suporte ao Cliente\n\nLogs de produção mostram que em 12% dos casos seu agente pula `get_customer` e chama `lookup_order` diretamente usando apenas o nome fornecido pelo cliente, às vezes levando a contas mal identificadas e reembolsos incorretos. Qual mudança corrige esse problema de confiabilidade de forma mais efetiva?\n\n[ ] A - Adicionar exemplos few-shot mostrando que o agente sempre chama `get_customer` primeiro, mesmo quando clientes voluntariamente fornecem detalhes do pedido.\n[ ] B - Implementar um classificador de roteamento que analisa cada pedido e habilita só um subconjunto de ferramentas apropriado para o tipo.\n[ ] C - Adicionar uma pré-condição programática que bloqueia `lookup_order` e `process_refund` até que `get_customer` retorne um identificador verificado.\n[ ] D - Reforçar o system prompt declarando que verificação do cliente via `get_customer` é mandatória antes de qualquer operação de pedido.','\n',char(10)),replace('**Explicação para adulto (tech lead):**\n\nO problema central é de **confiabilidade e aderência a um fluxo obrigatório** — em 12% dos casos o agente (LLM) ignora a etapa de verificação de identidade (`get_customer`) e parte diretamente para consulta de pedido (`lookup_order`) usando apenas o nome fornecido. Isso gera identificação incorreta de contas e reembolsos errados, um problema grave de segurança operacional.\n\nA abordagem correta é **C**, pois introduz uma **pré-condição programática** — uma restrição no nível da infraestrutura/orquestração, não no nível do prompt. Isso é análogo a um guard rail ou invariante: as funções `lookup_order` e `process_refund` simplesmente não podem ser invocadas se `get_customer` não tiver sido chamado com sucesso e retornado um identificador verificado (como um `customer_id` válido). Isso resolve o problema na raiz, independentemente do comportamento do LLM.\n\n- **A** (few-shot) depende do LLM seguir corretamente os exemplos — como o problema já ocorre em 12% dos casos com o prompt atual, adicionar mais exemplos é uma solução frágil e probabilística. O LLM pode continuar ignorando-os.\n\n- **B** (classificador de roteamento) adiciona complexidade desnecessária e não endereça o problema específico. O classificador poderia rotas corretas, mas ainda dependeria do agente seguir a rota. Além disso, não bloqueia o pulo da verificação.\n\n- **D** (reforço no system prompt) é a abordagem mais intuitiva, mas já falhou — o system prompt atual provavelmente já orienta o fluxo correto, e mesmo assim 12% dos casos desviam. Reforçar a instrução verbal não garante aderência, pois LLMs são suscetíveis a alucinações de comportamento e não possuem garantias formais de execução.\n\nPortanto, **apenas a alternativa C** resolve com uma garantia **determinística** (programática), independente do comportamento do modelo.\n\n---\n\n**Alternativas incorretas:**\n\n- **A:** Few-shot é uma técnica de exemplo no prompt. Ela melhora a aderência em média, mas não elimina o desvio — o LLM pode ainda pular a função se interpretar mal o contexto ou se o exemplo não cobrir todos os cenários. É uma solução estatística, não garantida.\n\n- **B:** Um classificador de roteamento adiciona um passo extra de decisão, mas não impede que o agente, após ser roteado, ainda chame `lookup_order` sem verificar o cliente. O problema não é de roteamento de tarefas, mas de **sequência obrigatória de chamadas de função**.\n\n- **D:** System prompts são instruções em linguagem natural para o LLM. Como o próprio enunciado indica, mesmo com instruções explícitas (provavelmente já existentes), o agente falha em 12% dos casos. Reforçar o texto não oferece garantia de execução.','\n',char(10)),replace('Imagine que você tem um robô que ajuda a atender clientes em uma loja. Sempre que um cliente liga, o robô deveria primeiro perguntar "Qual é o seu nome?" e olhar no cadastro. Só depois disso ele pode procurar o pedido ou fazer um reembolso.\n\nO problema é que, às vezes, o robô (12% das vezes) não pergunta o nome direito e já vai procurar o pedido usando só o apelido que o cliente disse. Isso confunde as contas e faz reembolsos errados.\n\nA melhor solução é a **alternativa C** — colocar uma trava no próprio sistema: o robô **não consegue** procurar o pedido nem fazer reembolso até que ele tenha consultado o cadastro e encontrado o cliente certo. É como colocar uma fechadura que só abre depois que você passou o cartão. Assim, não importa se o robô quer pular a etapa ou se esquece — o sistema não deixa.\n\nAs outras ideias são:\n\n- **A:** Mostrar mais exemplos para o robô. Mas ele ainda pode ignorar os exemplos de vez em quando.\n- **B:** Criar um outro robô que decide qual ferramenta usar. Mas ainda assim o primeiro robô pode pular a verificação.\n- **D:** Falar mais firme no manual do robô ("você TEM que verificar o cliente!"). Mas se o robô já desobedece às vezes, falar mais alto não resolve — ele continua podendo errar.\n\nA única que realmente impede o erro é **travar o sistema** até que a verificação seja feita. É como colocar um cadeado que só abre com a chave certa.','\n',char(10)));
INSERT INTO cards VALUES('admin','card_1783092984334_59prcpvyq',65,'Agente de Suporte ao Cliente',replace('Agente de Suporte ao Cliente\n\nSua ferramenta `get_customer` retorna todas as correspondências ao buscar por nome. Atualmente, quando há múltiplos resultados, Claude escolhe o cliente com pedido mais recente, mas dados de produção mostram que isso seleciona a conta errada em 15% dos casos para correspondências ambíguas. Como você deveria tratar isso?\n\n[ ] A - Implementar um sistema de pontuação de confiança que age autonomamente acima de 85% e pede esclarecimento abaixo do limiar.\n[ ] B - Instruir Claude a pedir um identificador adicional (email, telefone ou número do pedido) quando `get_customer` retornar múltiplas correspondências antes de tomar qualquer ação específica do cliente.\n[ ] C - Modificar `get_customer` para retornar apenas uma única correspondência mais provável com base em algoritmo de ranking, eliminando ambiguidade.\n[ ] D - Adicionar exemplos few-shot ao prompt demonstrando raciocínio correto e sequenciamento de ferramentas para correspondências ambíguas.','\n',char(10)),'B - Instruir Claude a pedir um identificador adicional (email, telefone ou número do pedido) quando `get_customer` retornar múltiplas correspondências antes de tomar qualquer ação específica do cliente.','["Domain_2::Tool_Design_MCP_Integration", "Domain_4::Prompt_Engineering_Structured_Output", "Domain_1::Agentic_Architecture_Orchestration", "Scenario_1::Customer_Support_Agent"]','New',0,2.5,0,1783092984334,1783725287272,1783203558653,replace('**Tradução para Português do Brasil:**\n\n**Agente de Suporte ao Cliente**\n\nSua ferramenta `get_customer` retorna todas as correspondências ao buscar por nome. Atualmente, quando há múltiplos resultados, Claude escolhe o cliente com pedido mais recente, mas dados de produção mostram que isso seleciona a conta errada em 15% dos casos para correspondências ambíguas. Como você deveria tratar isso?\n\n[ ] A - Implementar um sistema de pontuação de confiança que age autonomamente acima de 85% e pede esclarecimento abaixo do limiar.\n[ ] B - Instruir Claude a pedir um identificador adicional (email, telefone ou número do pedido) quando `get_customer` retornar múltiplas correspondências antes de tomar qualquer ação específica do cliente.\n[ ] C - Modificar `get_customer` para retornar apenas uma única correspondência mais provável com base em algoritmo de ranking, eliminando ambiguidade.\n[ ] D - Adicionar exemplos few-shot ao prompt demonstrando raciocínio correto e sequenciamento de ferramentas para correspondências ambíguas.','\n',char(10)),replace('**Explicação para Adulto (Tech Lead):**\n\n**Resposta Correta: B**\n\nO problema central é que a heurística atual (escolher o cliente com pedido mais recente) falha em 15% dos casos ambíguos. Isso representa um erro inaceitável para um agente de suporte ao cliente, onde ações tomadas na conta errada podem ter consequências graves (alterar dados, acessar informações sigilosas, etc.).\n\n**Por que B é a melhor abordagem:**\n\nA alternativa B implementa um padrão de design conhecido como **"escalonamento para confirmação humana" (escalation to disambiguation)**. Em vez de tentar adivinhar qual conta é a correta (o que já se mostrou falho), o agente interrompe o fluxo e solicita ativamente um identificador único ao usuário (email, telefone ou número do pedido). Isso transforma um problema de ambiguidade não resolvível deterministicamente em um processo de confirmação explícita. É a abordagem mais segura e robusta, pois:\n\n- **Elimina a ambiguidade na fonte**: o usuário fornece o dado que resolve a correspondência.\n- **Mantém a confiabilidade**: não depende de heurísticas nem de modelos preditivos.\n- **Respeita o princípio de "least privilege"**: só age na conta após confirmação inequívoca.\n\n**Análise das alternativas incorretas:**\n\n- **A (Sistema de pontuação com limiar de 85%):** Embora pareça razoável, apenas desloca o problema. Um limiar de 85% ainda significa que em 15% dos casos o agente agirá autonomamente com alto risco de erro — exatamente a mesma taxa de falha atual. Além disso, não há garantia de que a pontuação de confiança seja precisa, e o sistema continuaria a cometer erros em situações limítrofes. Na prática, troca-se uma heurística por outra igualmente falha.\n\n- **C (Modificar get_customer para retornar apenas uma correspondência):** Isso oculta o problema em vez de resolvê-lo. Um algoritmo de ranking pode ser melhor que "pedido mais recente", mas ainda assim será uma heurística com taxa de erro desconhecida. Remover a visibilidade da ambiguidade impede que o sistema ou o usuário percebam quando há múltiplas contas possíveis. Isso viola o princípio de transparência e pode levar a erros silenciosos e difíceis de depurar.\n\n- **D (Exemplos few-shot no prompt):** Few-shot learning pode melhorar o comportamento do modelo, mas não resolve o problema estrutural da ambiguidade. O modelo continuará tomando decisões autônomas baseadas em heurísticas (mesmo que mais sofisticadas) quando houver múltiplas correspondências. A taxa de erro pode cair, mas não será eliminada, e o comportamento continuará imprevisível em bordas do espectro. É uma solução frágil e não determinística para um problema que exige confirmação explícita.','\n',char(10)),replace('Imagine que você tem uma lista de alunos na sua escola e precisa encontrar o "João" para entregar um bilhete importante. Mas existem três Joões diferentes! \n\nA forma errada de resolver seria adivinhar: "vou entregar para o João que tem o caderno mais novo" — porque às vezes você pode entregar para o João errado, e aí o bilhete não chega a quem deveria. Foi exatamente isso que aconteceu: em 15 de cada 100 vezes, o computador escolheu o cliente errado.\n\nA melhor solução (letra B) é simples: o computador pergunta para a pessoa "Qual é o seu email, telefone ou número do pedido?" Assim, ele tem certeza absoluta de quem é o cliente certo antes de fazer qualquer coisa. É como se você perguntasse para o João: "Qual é o seu número da chamada?" para ter certeza de que é o João certo.\n\nAs outras opções são piores porque:\n- A letra A tenta adivinhar com uma "nota de confiança" — mas ainda erra em alguns casos.\n- A letra C esconde o problema, mostrando só um nome, mas isso não significa que seja o correto.\n- A letra D tenta ensinar o computador a ser mais esperto, mas ele ainda pode errar de vez em quando.\n\nA forma mais segura é sempre pedir confirmação quando houver dúvida!','\n',char(10)));
INSERT INTO cards VALUES('admin','card_1783092984340_pellig2l6',66,'Agente de Suporte ao Cliente',replace('Agente de Suporte ao Cliente\n\nLogs de produção mostram que o agente frequentemente chama `get_customer` quando usuários perguntam sobre pedidos (ex.: "verifique meu pedido #12345") em vez de chamar `lookup_order`. Ambas as ferramentas têm descrições mínimas ("Gets customer information" / "Gets order details") e aceitam formatos de identificador parecidos. Qual é o primeiro passo mais efetivo para melhorar a confiabilidade da seleção de ferramenta?\n\n[ ] A - Implementar uma camada de roteamento que analisa o input do usuário antes de cada turno e pré-seleciona a ferramenta correta com base em palavras-chave detectadas e padrões de ID.\n[ ] B - Combinar ambas em uma única `lookup_entity` que aceita qualquer identificador e decide internamente qual backend consultar.\n[ ] C - Adicionar exemplos few-shot ao system prompt demonstrando padrões corretos de seleção, com 5–8 exemplos roteando consultas relacionadas a pedido para `lookup_order`.\n[ ] D - Expandir a descrição de cada ferramenta para incluir formatos de entrada, queries de exemplo, casos de borda e fronteiras explicando quando usá-la versus ferramentas similares.','\n',char(10)),'D - Expandir a descrição de cada ferramenta para incluir formatos de entrada, queries de exemplo, casos de borda e fronteiras explicando quando usá-la versus ferramentas similares.','["Domain_2::Tool_Design_MCP_Integration", "Domain_4::Prompt_Engineering_Structured_Output", "Scenario_1::Customer_Support_Agent"]','New',0,2.5,0,1783092984340,1783725291454,1783203558653,replace('**Tradução para português do Brasil:**\n\n**Pergunta:** Logs de produção mostram que o agente frequentemente chama `get_customer` quando usuários perguntam sobre pedidos (ex.: "verifique meu pedido #12345") em vez de chamar `lookup_order`. Ambas as ferramentas têm descrições mínimas ("Gets customer information" / "Gets order details") e aceitam formatos de identificador parecidos. Qual é o primeiro passo mais efetivo para melhorar a confiabilidade da seleção de ferramenta?\n\n[ ] A - Implementar uma camada de roteamento que analisa o input do usuário antes de cada turno e pré-seleciona a ferramenta correta com base em palavras-chave detectadas e padrões de ID.\n\n[ ] B - Combinar ambas em uma única `lookup_entity` que aceita qualquer identificador e decide internamente qual backend consultar.\n\n[ ] C - Adicionar exemplos few-shot ao system prompt demonstrando padrões corretos de seleção, com 5–8 exemplos roteando consultas relacionadas a pedido para `lookup_order`.\n\n[ ] D - Expandir a descrição de cada ferramenta para incluir formatos de entrada, queries de exemplo, casos de borda e fronteiras explicando quando usá-la versus ferramentas similares.','\n',char(10)),replace('**Explicação para adulto tech lead:**\n\nO problema central é que as descrições das ferramentas são muito genéricas e similares. O modelo de linguagem (LLM) toma a decisão de qual ferramenta chamar com base **principalmente** nas descrições fornecidas no schema da ferramenta. Se ambas dizem algo genérico como "Gets customer information" e "Gets order details", e ambas aceitam identificadores de formato parecido (ex.: números), o modelo não tem informação discriminatória suficiente para distinguir corretamente os casos de uso.\n\n**Análise das alternativas:**\n\n- **Alternativa A (Camada de roteamento externa):** Embora funcione, adicionar uma camada de roteamento prévia é uma solução mais complexa e de maior custo de manutenção. É uma abordagem de "sobreengenharia" para um problema que pode ser resolvido com uma melhoria mais simples e de menor acoplamento. Além disso, criar um roteador baseado em palavras-chave e padrões de ID é frágil: usuários podem perguntar de formas variadas ("como está meu pacote?", "qual o status do #12345?"), e padrões de ID podem colidir (ex.: se ambos usam números).\n\n- **Alternativa B (Fundir em uma única ferramenta):** Isso resolve o problema de seleção incorreta ao custo de aumentar a complexidade interna do backend e reduzir a modularidade do sistema. O agente perde a capacidade de decidir com base no contexto semântico, e a lógica de roteamento é terceirizada para uma função interna, o que pode gerar acoplamento indesejado. Também reduz a transparência e a capacidade de depuração do sistema.\n\n- **Alternativa C (Exemplos few-shot):** Adicionar exemplos few-shot pode ajudar, mas é uma abordagem menos robusta que melhorar as descrições das ferramentas. Exemplos few-shot no system prompt ocupam tokens preciosos (contexto), podem não cobrir todos os casos de borda, e o modelo pode não generalizar bem a partir deles. A melhoria das descrições é mais fundamental e estrutural, valendo para qualquer entrada, enquanto few-shot depende da qualidade e cobertura dos exemplos fornecidos.\n\n- **Alternativa D (Expandir descrições):** Esta é a abordagem mais alinhada com as melhores práticas de design de sistemas com LLMs. Expandir as descrições para incluir formatos de entrada esperados, exemplos de queries, casos de borda e, principalmente, **fronteiras explícitas** (ex.: "Use esta ferramenta quando o usuário mencionar um ID de pedido ou palavra-chave como ''pedido'', ''entrega'', ''status do pedido''; NÃO use para consultas sobre dados cadastrais do cliente") fornece ao modelo informação discriminatória de alta qualidade. Isso ataca diretamente a causa raiz: descrições pobres e indistinguíveis.\n\n**Conclusão:** A abordagem D é a mais efetiva como primeiro passo porque é de baixo risco, baixo custo, fácil de implementar e ataca diretamente a causa raiz do problema. As demais alternativas ou são mais complexas, ou não resolvem a ambiguidade fundamental das descrições.','\n',char(10)),replace('Imagine que você tem duas caixas de ferramentas. Uma está escrita "coisas do cliente" e a outra "coisas do pedido". Mas as duas caixas são bem parecidas e a descrição é muito curta. Quando alguém pede "verifique meu pedido #12345", o robô que escolhe a ferramenta fica confuso e pega a caixa errada.\n\nA melhor coisa a fazer é escrever descrições bem detalhadas em cada caixa, explicando direitinho quando usar cada uma. Por exemplo, na caixa de "pedido" a gente escreve: "USE quando a pessoa falar ''pedido'', ''entrega'', ''número do pedido'' - NÃO USE para dados do cliente". Assim, o robô consegue entender melhor e não erra mais.\n\nAs outras opções seriam: criar um robô chefe para decidir antes (mais complicado), juntar tudo em uma caixa só (bagunça), ou dar alguns exemplos (ajuda, mas não resolve todas as situações). A melhor é melhorar as descrições mesmo!','\n',char(10)));
INSERT INTO cards VALUES('admin','card_1783092984348_lxltelw8h',67,'Agente de Suporte ao Cliente',replace('Agente de Suporte ao Cliente\n\nLogs de produção mostram que o agente interpreta mal saídas de suas ferramentas MCP: timestamps Unix de `get_customer`, datas ISO 8601 de `lookup_order` e códigos de status numéricos (1=pendente, 2=enviado). Algumas ferramentas são servidores MCP de terceiros que você não pode modificar. Qual abordagem para normalização de formato de dados é mais mantível?\n\n[ ] A - Usar um hook PostToolUse para interceptar saídas de ferramentas e aplicar transformações de formato antes que o agente processe.\n[ ] B - Modificar ferramentas que você controla para retornar formatos legíveis para humanos e criar wrappers para ferramentas de terceiros.\n[ ] C - Criar uma ferramenta `normalize_data` que o agente chama após cada recuperação de dados para transformar valores.\n[ ] D - Adicionar documentação detalhada de formato no system prompt explicando convenções de dado de cada ferramenta.','\n',char(10)),'A - Usar um hook PostToolUse para interceptar saídas de ferramentas e aplicar transformações de formato antes que o agente processe.','["Domain_2::Tool_Design_MCP_Integration", "Domain_1::Agentic_Architecture_Orchestration", "Scenario_1::Customer_Support_Agent"]','New',0,2.5,0,1783092984348,1783725295850,1783203558653,replace('**Tradução para português do Brasil:**\n\n**Agente de Suporte ao Cliente**\n\nLogs de produção mostram que o agente interpreta mal saídas de suas ferramentas MCP: timestamps Unix de `get_customer`, datas ISO 8601 de `lookup_order` e códigos de status numéricos (1=pendente, 2=enviado). Algumas ferramentas são servidores MCP de terceiros que você não pode modificar. Qual abordagem para normalização de formato de dados é mais sustentável/manutenível?\n\n[ ] A - Usar um hook PostToolUse para interceptar saídas de ferramentas e aplicar transformações de formato antes que o agente processe.\n[ ] B - Modificar ferramentas que você controla para retornar formatos legíveis para humanos e criar wrappers para ferramentas de terceiros.\n[ ] C - Criar uma ferramenta `normalize_data` que o agente chama após cada recuperação de dados para transformar valores.\n[ ] D - Adicionar documentação detalhada de formato no system prompt explicando convenções de dado de cada ferramenta.','\n',char(10)),replace('**Explicação para adulto (tech lead):**\n\nO problema central é que o agente LLM recebe dados em formatos inconsistentes (Unix timestamps, ISO 8601, códigos numéricos) e comete erros de interpretação. Precisamos de uma solução que normalize esses dados de forma confiável, sem depender da boa vontade ou precisão do LLM, e que seja sustentável a longo prazo.\n\n**Por que A é a melhor resposta:**\n\nA alternativa A propõe usar um hook `PostToolUse` — essencialmente um middleware/interceptor na arquitetura MCP que executa *automaticamente* após cada chamada de ferramenta, antes que o resultado chegue ao agente. Isso é extremamente mantível porque:\n\n1. **Separation of concerns**: A lógica de normalização fica isolada da lógica do agente e das ferramentas.\n2. **Transparência para o agente**: O agente sempre vê dados já normalizados, como se as ferramentas já os tivessem retornado corretamente — não precisa aprender a lidar com formatos variados.\n3. **Baixo acoplamento**: Se uma ferramenta de terceiros mudar o formato de retorno (ex.: de Unix timestamp para string), você só altera o hook, não o agente nem as outras ferramentas.\n4. **Escalabilidade**: Novas ferramentas podem ser adicionadas e facilmente integradas ao hook com regras de transformação específicas.\n5. **Não exige modificação de terceiros**: Ferramentas MCP de terceiros não precisam ser alteradas.\n\n**Por que as demais estão incorretas:**\n\n- **B (Modificar ferramentas próprias + wrappers):** Embora pareça razoável, modificar ferramentas internas quebrada o princípio de responsabilidade única (a ferramenta deveria retornar dados crus/fiéis à fonte). Além disso, criar e manter wrappers para cada ferramenta de terceiro é frágil: se o terceiro atualiza a API, o wrapper quebra. É mais trabalho e mais pontos de falha que um hook centralizado.\n\n- **C (Ferramenta `normalize_data` chamada pelo agente):** Isso delega ao LLM a responsabilidade de *lembrar* de chamar a ferramenta após cada recuperação. LLMs são conhecidos por esquecerem etapas, especialmente em cadeias longas. Além disso, aumenta o consumo de tokens (chamadas extras) e a latência. A solução viola o princípio de que o agente não deve ser responsável por sua própria higiene de dados.\n\n- **D (Documentação no system prompt):** Essa é a abordagem menos confiável. Instruções em system prompt são heurísticas e o LLM pode ignorá-las, interpretá-las erroneamente ou simplesmente falhar em aplicá-las consistentemente. Depender exclusivamente de documentação para um LLM agir corretamente é frágil e não escalável — especialmente com formatos contra-intuitivos como timestamps Unix.\n\n**Conclusão:** A abordagem A é a mais alinhada com boas práticas de arquitetura de software: separação de preocupações, baixo acoplamento, alta coesão e robustez contra mudanças externas.','\n',char(10)),replace('Imagine que você tem um robô que ajuda a encontrar informações sobre clientes e pedidos. Mas as informações vêm em formatos diferentes: umas parecem números enormes (timestamp Unix), outras parecem datas com letras (ISO 8601), e outras são números como 1 ou 2 que significam "pendente" ou "enviado". O robô fica confuso!\n\nA melhor solução é colocar um "tradutor automático" na entrada do robô. Toda vez que uma informação chega, antes do robô ver, o tradutor já converte tudo para um formato que o robô entende bem. É como colocar um intérprete de libras entre alguém que fala inglês e uma pessoa surda — o intérprete traduz na hora, sem a pessoa precisar aprender inglês.\n\nA opção A é exatamente isso: um "gancho" (hook) que age depois que a ferramenta entrega o dado, mas antes do robô (agente) processar. Assim, o robô nunca vê os números estranhos, só vê coisas organizadas.\n\nAs outras opções são piores:\n- B seria pedir para cada pessoa que te dá informação mudar o jeito dela — mas algumas são de terceiros e não podem ser mudadas.\n- C seria ensinar o robô a usar um dicionário depois que recebe a informação, mas ele pode esquecer de consultar.\n- D seria colocar um bilhete na testa do robô explicando os formatos — mas robôs nem sempre leem bilhetes direito!\n\nEntão a opção A é a mais esperta porque resolve o problema na raiz, sem depender de ninguém lembrar de fazer algo.','\n',char(10)));
INSERT INTO cards VALUES('admin','card_1783092984354_j6xr3d012',68,'Padrões de Arquitetura de IA Conversacional',replace('Padrões de Arquitetura de IA Conversacional\n\nSua ferramenta `remove_team_member` usa um parâmetro `dry_run: boolean` para visualizar impactos antes da execução. Monitoramento de produção mostra que o agente burla o passo de preview chamando com `dry_run=false` diretamente. Você precisa garantir que toda remoção seja precedida por um preview que o usuário confirme explicitamente.\n\nQual é a abordagem mais confiável?\n\n[ ] A - Adicionar validação no servidor que permite `dry_run=false` apenas quando uma chamada `dry_run=true` com parâmetros idênticos ocorreu nos últimos 60 segundos.\n[ ] B - Anotar a ferramenta como exigindo confirmação e configurar a camada de orquestração para pedir aprovação ao usuário antes de encaminhar quaisquer chamadas a ferramentas anotadas.\n[ ] C - Adicionar instruções detalhadas e exemplos few-shot na descrição da ferramenta exigindo que o agente sempre chame com `dry_run=true` primeiro e espere confirmação antes de chamar de novo.\n[ ] D - Substituir por duas ferramentas: `preview_remove_member` retorna detalhes de impacto e um token de confirmação de uso único; `execute_remove_member` exige esse token, ligando a execução ao preview.','\n',char(10)),'D - Substituir por duas ferramentas: `preview_remove_member` retorna detalhes de impacto e um token de confirmação de uso único; `execute_remove_member` exige esse token, ligando a execução ao preview.','["Domain_2::Tool_Design_MCP_Integration", "Domain_1::Agentic_Architecture_Orchestration", "Scenario_1::Customer_Support_Agent"]','New',0,2.5,0,1783092984354,1783725300050,1783203558653,replace('**Tradução para português do Brasil:**\n\nPadrões de Arquitetura de IA Conversacional\n\nSua ferramenta `remove_team_member` usa um parâmetro `dry_run: boolean` para visualizar impactos antes da execução. Monitoramento de produção mostra que o agente burla o passo de preview chamando com `dry_run=false` diretamente. Você precisa garantir que toda remoção seja precedida por um preview que o usuário confirme explicitamente.\n\nQual é a abordagem mais confiável?\n\n[ ] A - Adicionar validação no servidor que permite `dry_run=false` apenas quando uma chamada `dry_run=true` com parâmetros idênticos ocorreu nos últimos 60 segundos.\n[ ] B - Anotar a ferramenta como exigindo confirmação e configurar a camada de orquestração para pedir aprovação ao usuário antes de encaminhar quaisquer chamadas a ferramentas anotadas.\n[ ] C - Adicionar instruções detalhadas e exemplos few-shot na descrição da ferramenta exigindo que o agente sempre chame com `dry_run=true` primeiro e espere confirmação antes de chamar de novo.\n[ ] D - Substituir por duas ferramentas: `preview_remove_member` retorna detalhes de impacto e um token de confirmação de uso único; `execute_remove_member` exige esse token, ligando a execução ao preview.','\n',char(10)),replace('**Explicação Técnica para Tech Lead:**\n\nO problema central é que o agente de IA pode ignorar o parâmetro `dry_run` e executar a remoção diretamente. Precisamos de uma solução que não dependa apenas da boa vontade do agente (instruções/prompts) ou de heurísticas temporais frágeis, mas sim de uma restrição arquitetural que torne a execução impossível sem um preview confirmado.\n\n**Alternativa Correta: D**\n\nA abordagem D é a mais confiável porque aplica o princípio de **separação de responsabilidades** e **encadeamento obrigatório** (chaining). Ao dividir a ferramenta em duas (preview e execute) e usar um **token de confirmação de uso único** gerado no preview, cria-se um vínculo criptográfico/lógico entre a ação de visualizar impactos e a ação de executar. O agente não pode chamar `execute_remove_member` sem antes chamar `preview_remove_member`, porque o token é necessário. Além disso, como o token é de uso único e tem escopo limitado (tipicamente associado a um identificador de sessão, timestamp ou parâmetros específicos), mesmo que um agente tentasse "adivinhar" ou reutilizar um token, não conseguiria. Isso resolve o problema na camada de infraestrutura, não na de prompting.\n\n**Por que as outras alternativas são inferiores:**\n\n- **Alternativa A**: Cria uma **dependência de estado temporal** (janela de 60 segundos) e de correlação de parâmetros idênticos. Isso é frágil. O agente poderia, por exemplo, chamar `dry_run=true` com parâmetros ligeiramente diferentes (um campo extra ou ordem diferente) e depois chamar `dry_run=false` com os parâmetros "corretos", burlando a validação. Além disso, a janela de 60 segundos é arbitrária e pode causar falsos negativos ou positivos em cenários de latência ou múltiplas requisições concorrentes.\n\n- **Alternativa B**: Embora pareça robusta (orquestração exigindo aprovação humana), ela **não necessariamente impede o agente de chamar a ferramenta sem preview**. Depende de como a "anotação" é implementada. Se a anotação for apenas um metadado interpretado pelo orquestrador, e o agente puder fazer chamadas diretas à ferramenta (ignorando o orquestrador), a proteção cai. Em muitos sistemas de agentes, o orquestrador é quem roteia as chamadas, mas se o agente tem capacidade de invocar ferramentas de forma autônoma, essa abordagem falha. Além disso, não há garantia de que o preview foi realmente mostrado ao usuário — apenas que houve uma "aprovação", que pode ser genérica.\n\n- **Alternativa C**: É a **mais fraca**. Depende exclusivamente de **instruções e exemplos few-shot** no prompt. Agentes de IA, especialmente modelos de linguagem grandes, podem alucinar, ignorar instruções ou ser induzidos a bypass (jailbreak). Isso é um **controle de segurança baseado em prompt**, que é notoriamente não confiável. Não há nenhuma barreira técnica; o agente ainda pode, em teoria, chamar `remove_team_member(dry_run=false)` se assim decidir.\n\nPortanto, a alternativa D é a mais confiável por ser **arquitetural e restritiva**, e não baseada em comportamento esperado do agente.\n\n**Resposta correta: D**','\n',char(10)),replace('Imagine que você tem uma ferramenta mágica que pode tirar uma pessoa de uma lista. Antes de tirar, você deveria ver um "filme" mostrando o que vai acontecer (o preview). Mas a ferramenta tem um botão "pular o filme" que o agente (um robô que ajuda você) pode apertar.\n\nAs opções são:\n- A: Colocar um relógio que só deixa apertar "pular filme" se o filme foi visto nos últimos 60 segundos. Mas o robô pode enganar o relógio mudando um pouco o filme.\n- B: Pedir permissão para o usuário antes de tirar a pessoa. Mas o robô ainda pode apertar o botão de tirar sem perguntar.\n- C: Escrever um bilhete bem grande para o robô: "Sempre veja o filme primeiro!" Mas robôs podem esquecer ou ignorar o bilhete.\n- D (a melhor): Quebrar a ferramenta em duas: uma que só mostra o filme e dá um "código secreto" para quem viu o filme, e outra que só tira a pessoa se você tiver o código secreto. Assim, o robô não consegue tirar ninguém sem antes ver o filme pegar o código.\n\nA opção D é a mais segura porque não depende do robô se lembrar de fazer a coisa certa — ela simplesmente torna impossível pular o filme.\n\n**Resposta correta: D**','\n',char(10)));
INSERT INTO cards VALUES('admin','card_1783092984361_k7c5ayysb',69,'Padrões de Arquitetura de IA Conversacional',replace('Padrões de Arquitetura de IA Conversacional\n\nMonitoramento de produção mostra que sua ferramenta `search_catalog` falha 12% do tempo: 8% são timeouts de rede que sucedem ao retentar e 4% são erros de sintaxe de query que nunca sucedem por mais que se retente. Atualmente ambos os tipos de erro são retornados de forma idêntica, causando retentativas desperdiçadas.\n\nComo você deveria modificar o tratamento de erros da ferramenta?\n\n[ ] A - Adicionar exemplos few-shot ao system prompt demonstrando como distinguir erros de rede de erros de sintaxe.\n[ ] B - Aplicar lógica de retry com backoff exponencial uniformemente a todos os erros.\n[ ] C - Implementar retry automático com backoff para timeouts de rede dentro da ferramenta; retornar erros de sintaxe imediatamente com detalhes de validação de parâmetro.\n[ ] D - Retornar todos os erros com flag booleana `retryable` e detalhes do tipo de erro.','\n',char(10)),'C - Implementar retry automático com backoff para timeouts de rede dentro da ferramenta; retornar erros de sintaxe imediatamente com detalhes de validação de parâmetro.','["Domain_2::Tool_Design_MCP_Integration", "Domain_5::Context_Management_Reliability", "Scenario_1::Customer_Support_Agent"]','New',0,2.5,0,1783092984361,1783725303833,1783203558653,replace('**Tradução da pergunta e alternativas:**\n\nPadrões de Arquitetura de IA Conversacional\n\nMonitoramento de produção mostra que sua ferramenta `search_catalog` falha 12% do tempo: 8% são timeouts de rede que sucedem ao retentar e 4% são erros de sintaxe de query que nunca sucedem por mais que se retente. Atualmente ambos os tipos de erro são retornados de forma idêntica, causando retentativas desperdiçadas.\n\nComo você deveria modificar o tratamento de erros da ferramenta?\n\n[ ] A - Adicionar exemplos few-shot ao system prompt demonstrando como distinguir erros de rede de erros de sintaxe.\n[ ] B - Aplicar lógica de retry com backoff exponencial uniformemente a todos os erros.\n[ ] C - Implementar retry automático com backoff para timeouts de rede dentro da ferramenta; retornar erros de sintaxe imediatamente com detalhes de validação de parâmetro.\n[ ] D - Retornar todos os erros com flag booleana `retryable` e detalhes do tipo de erro.','\n',char(10)),replace('**Explicação para Adulto (Tech Lead):**\n\nA alternativa **C** é a resposta correta porque ataca o problema na raiz: a diferenciação do tratamento com base na **natureza do erro**.\n\n- **Por que C é a melhor escolha:** Ela propõe uma solução arquitetural limpa e eficiente. Timeouts de rede são tipicamente transitórios — um backoff exponencial dentro da própria ferramenta resolve sem depender do modelo de linguagem (LLM) para decidir se deve ou não tentar novamente. Já erros de sintaxe de query são **determinísticos e permanentes** — retentar é inútil. Além disso, retornar detalhes de validação permite que o LLM (ou o sistema chamador) entenda o problema e corrija a query na próxima chamada, em vez de ficar repetindo o mesmo erro.\n\n- **Por que A está errada:** Few-shot prompting delega ao LLM a responsabilidade de distinguir tipos de erro com base na mensagem retornada. Isso é frágil: o LLM pode interpretar mal a mensagem, gerar um retry desnecessário ou, pior, tentar "corrigir" algo que não precisa. Além disso, adiciona latência e custo de inferência desnecessários. A lógica de retry deve estar no plano de controle (tool runtime), não no plano de decisão do LLM.\n\n- **Por que B está errada:** Aplicar backoff exponencial cegamente a todos os erros significa que erros de sintaxe — que **nunca** serão resolvidos com retentativas — continuarão sendo retentados, consumindo tempo, recursos computacionais e aumentando a latência percebida pelo usuário final. É um desperdício puro.\n\n- **Por que D está errada:** Embora seja uma melhoria em relação ao estado atual (pois adiciona a flag `retryable`), ela ainda depende de que **outro componente** (o LLM ou um orquestrador externo) tome a decisão de retentar ou não. Isso introduz complexidade desnecessária e mantém a lógica de decisão fora do lugar mais adequado (a própria ferramenta). É uma solução incompleta que apenas externaliza o problema, em vez de resolvê-lo internamente com robustez.\n\n**Resumo técnico:** A abordagem correta é **encapsular a lógica de retry no runtime da ferramenta** para erros recuperáveis (timeouts) e **falhar rápido** para erros não recuperáveis (sintaxe), retornando feedback estruturado que permita ação corretiva imediata.','\n',char(10)),replace('Imagine que você tem uma máquina de buscar brinquedos numa loja gigante. Às vezes, a máquina demora muito para responder — é como se o fio que liga o botão até a máquina estivesse com um nó frouxo, e se você apertar de novo, funciona. Isso acontece 8 em cada 100 vezes. Outras vezes, você escreve o nome do brinquedo errado, tipo "carrinho" em vez de "carrinho vermelho". Aí não adianta apertar o botão de novo, porque o nome continua errado — nunca vai funcionar. Isso acontece 4 em cada 100 vezes.\n\nAntes, a máquina mostrava a mesma mensagem de erro para os dois problemas, e o sistema ficava tentando de novo várias vezes, perdendo tempo.\n\nA melhor solução é ensinar a máquina a agir diferente para cada caso:\n\n- Se for o problema do fio (timeout), a máquina tenta de novo sozinha, esperando um pouquinho mais a cada tentativa (como quando a gente aperta o botão do elevador de novo).\n- Se for o nome errado (sintaxe), a máquina para na hora e avisa: "Ops, você escreveu algo errado! Aqui está o detalhe do que precisa ser corrigido."\n\nAssim, a gente não perde tempo tentando consertar algo que só vai se resolver se a pessoa corrigir o que escreveu.\n\nA resposta certa é a **C** porque ela faz exatamente isso: trata cada erro do jeito certo.','\n',char(10)));
INSERT INTO cards VALUES('admin','card_1783092984368_gjuluzczz',70,'O agente de análise de documentos tem uma única ferramenta `analyze_document` que recebe um documento e um parâmetro de instrução em texto livre.',replace('O agente de análise de documentos tem uma única ferramenta `analyze_document` que recebe um documento e um parâmetro de instrução em texto livre.\n\nO agente de análise de documentos tem uma única ferramenta `analyze_document` que recebe um documento e um parâmetro de instrução em texto livre. Durante a avaliação, solicitações como "extrair as principais métricas financeiras" frequentemente retornam resumos narrativos, enquanto "resumir a metodologia" às vezes retorna tabelas de dados brutos. O agente de síntese relata que 35% dos resultados de análise exigem novas solicitações com instruções esclarecidas.\n\nQual é a forma mais eficaz de melhorar a confiabilidade?\n\n[ ] A - Dividir a ferramenta genérica em ferramentas específicas para cada propósito — `extract_data_points`, `summarize_content`, `verify_claim_against_source` — cada uma com contratos de entrada/saída definidos.\n[ ] B - Manter a ferramenta única, mas adicionar um parâmetro enum `analysis_type` que exija a seleção explícita entre os modos de extração, resumo e verificação.\n[ ] C - Fazer com que o coordenador pré-classifique cada solicitação de análise antes de passar as instruções ao agente de análise de documentos.\n[ ] D - Aprimorar a descrição da ferramenta com exemplos detalhados mostrando como diferentes formulações de instrução devem mapear para diferentes formatos de saída.','\n',char(10)),'A - Dividir a ferramenta genérica em ferramentas específicas para cada propósito — `extract_data_points`, `summarize_content`, `verify_claim_against_source` — cada uma com contratos de entrada/saída definidos.','["Domain_2::Tool_Design_MCP_Integration", "Domain_4::Prompt_Engineering_Structured_Output", "Domain_5::Context_Management_Reliability", "Scenario_3::Multi_Agent_Research"]','New',0,2.5,0,1783092984368,1783725307571,1783203558653,replace('**Tradução para português do Brasil:**\n\nO agente de análise de documentos tem uma única ferramenta `analyze_document` que recebe um documento e um parâmetro de instrução em texto livre. Durante a avaliação, solicitações como "extrair as principais métricas financeiras" frequentemente retornam resumos narrativos, enquanto "resumir a metodologia" às vezes retorna tabelas de dados brutos. O agente de síntese relata que 35% dos resultados de análise exigem novas solicitações com instruções esclarecidas.\n\nQual é a forma mais eficaz de melhorar a confiabilidade?\n\n[ ] A - Dividir a ferramenta genérica em ferramentas específicas para cada propósito — `extract_data_points`, `summarize_content`, `verify_claim_against_source` — cada uma com contratos de entrada/saída definidos.\n[ ] B - Manter a ferramenta única, mas adicionar um parâmetro enum `analysis_type` que exija a seleção explícita entre os modos de extração, resumo e verificação.\n[ ] C - Fazer com que o coordenador pré-classifique cada solicitação de análise antes de passar as instruções ao agente de análise de documentos.\n[ ] D - Aprimorar a descrição da ferramenta com exemplos detalhados mostrando como diferentes formulações de instrução devem mapear para diferentes formatos de saída.','\n',char(10)),replace('**Explicação para o adulto tech lead:**\n\n**Problema central:** O agente de análise de documentos possui uma ferramenta genérica (`analyze_document`) que aceita *texto livre* como instrução. O comportamento resultante é imprevisível: pedidos de extração geram resumos, pedidos de resumo geram tabelas. Isso indica que o LLM está interpretando instruções ambíguas de forma inconsistente. A taxa de 35% de retrabalho é um sintoma claro de que a interface da ferramenta é frágil e não impõe restrições estruturais ao comportamento esperado.\n\n**Análise das alternativas:**\n\n**Alternativa A (Correta):** Dividir a ferramenta genérica em ferramentas especializadas com contratos de entrada/saída definidos. Esta é a abordagem mais eficaz porque:\n- Remove a ambiguidade inerente ao texto livre: cada ferramenta tem um propósito único e explícito.\n- Contratos de entrada/saída bem definidos permitem que o sistema (e o LLM) saibam exatamente o que esperar, reduzindo a variabilidade.\n- Ferramentas especializadas são mais fáceis de testar, depurar e evoluir independentemente.\n- Segue o princípio da separação de responsabilidades: cada ferramenta faz uma coisa e faz bem.\n- Elimina a necessidade de o LLM "adivinhar" a intenção a partir de texto livre.\n\n**Alternativa B (Incorreta):** Adicionar um parâmetro enum `analysis_type`. Embora seja uma melhoria em relação ao texto livre, ainda mantém a ambiguidade na ferramenta única. O LLM pode escolher o enum incorretamente (ex: selecionar "resumo" quando deveria ser "extração"), e o texto livre ainda será usado para detalhar a instrução, perpetuando inconsistências. Além disso, um enum não resolve o problema fundamental de contratos de saída não definidos.\n\n**Alternativa C (Incorreta):** Classificação prévia pelo coordenador. Isso apenas desloca o problema para outra camada. O coordenador precisará classificar corretamente a intenção, e ainda assim passará instruções em texto livre para a ferramenta genérica. A classificador pode errar, e a ferramenta continuará tendo o mesmo comportamento imprevisível. Adiciona complexidade sem resolver a causa raiz.\n\n**Alternativa D (Incorreta):** Melhorar a descrição da ferramenta com exemplos. Isso pode ajudar marginalmente, mas é uma abordagem frágil. LLMs podem ignorar ou interpretar mal exemplos em descrições de ferramentas, especialmente se o texto livre for ambíguo. Exemplos não impõem restrições estruturais — são apenas dicas que podem ou não ser seguidas. A inconsistência persistirá porque o problema é estrutural, não de documentação.','\n',char(10)),replace('Imagina que você tem um canivete suíço que faz de tudo: abre lata, corta papel, tampa de garrafa... mas você tem que explicar em palavras o que quer que ele faça. Se você fala "quero abrir a garrafa", às vezes ele corta o papel em vez de abrir a garrafa. Isso é chato e você perde tempo tendo que pedir de novo.\n\nA melhor solução é trocar esse canivete por três ferramentas diferentes: um abridor de garrafa, um cortador de papel e um abridor de lata. Cada uma só faz uma coisa, mas faz direitinho. Assim você não se confunde e não precisa ficar repetindo o pedido.\n\nÉ por isso que a opção A é a melhor: em vez de uma ferramenta que tenta fazer de tudo mas erra, ter ferramentas separadas que fazem cada uma sua tarefa sem confusão.','\n',char(10)));
INSERT INTO cards VALUES('admin','card_1783092984386_h7l1xhvpe',71,'Após integrar um servidor MCP local que fornece ferramentas de análise de código (`analyze_dependencies`, `find_dead_code`, `calculate_complexity`), você verifica que o servidor está saudável e que as ferramentas aparecem na resposta de tools/list.',replace('Após integrar um servidor MCP local que fornece ferramentas de análise de código (`analyze_dependencies`, `find_dead_code`, `calculate_complexity`), você verifica que o servidor está saudável e que as ferramentas aparecem na resposta de tools/list.\n\nApós integrar um servidor MCP local que fornece ferramentas de análise de código (`analyze_dependencies`, `find_dead_code`, `calculate_complexity`), você verifica que o servidor está saudável e que as ferramentas aparecem na resposta de tools/list. No entanto, você observa que o agente usa consistentemente o Grep para buscar declarações de importação em vez de chamar `analyze_dependencies` — mesmo quando os usuários perguntam explicitamente sobre "dependências de código". Ao examinar as definições das ferramentas, você encontra: MCP: `analyze_dependencies` - "Analisa o grafo de dependências" Nativa: Grep - "Busca o conteúdo de arquivos por um padrão usando expressões regulares. Retorna as linhas correspondentes com números de linha e contexto ao redor."\n\nQual é a abordagem mais eficaz para melhorar a seleção de ferramentas MCP pelo agente?\n\n[ ] A - Remover o Grep das ferramentas disponíveis quando o servidor MCP estiver conectado, para eliminar a sobreposição funcional.\n[ ] B - Adicionar instruções de roteamento ao prompt do sistema especificando que perguntas relacionadas a dependências devem usar ferramentas MCP em vez do Grep.\n[ ] C - Dividir `analyze_dependencies` em ferramentas granulares (`list_imports`, `resolve_transitive_deps`, `detect_circular_deps`) para que cada uma tenha um propósito focado e menos propenso a se sobrepor ao Grep.\n[ ] D - Expandir as descrições das ferramentas MCP para detalhar capacidades e saídas — por exemplo, "Constrói um grafo de dependências mostrando importações diretas, dependências transitivas e ciclos."','\n',char(10)),'D - Expandir as descrições das ferramentas MCP para detalhar capacidades e saídas — por exemplo, "Constrói um grafo de dependências mostrando importações diretas, dependências transitivas e ciclos."','["Domain_2::Tool_Design_MCP_Integration", "Domain_4::Prompt_Engineering_Structured_Output", "Scenario_4::Developer_Productivity"]','New',0,2.5,0,1783092984386,1783725312099,1783203558653,replace('**Tradução da pergunta e alternativas:**\n\nApós integrar um servidor MCP local que fornece ferramentas de análise de código (`analyze_dependencies`, `find_dead_code`, `calculate_complexity`), você verifica que o servidor está saudável e que as ferramentas aparecem na resposta de tools/list. No entanto, você observa que o agente usa consistentemente o Grep para buscar declarações de importação em vez de chamar `analyze_dependencies` — mesmo quando os usuários perguntam explicitamente sobre "dependências de código". Ao examinar as definições das ferramentas, você encontra: MCP: `analyze_dependencies` - "Analisa o grafo de dependências" Nativa: Grep - "Busca o conteúdo de arquivos por um padrão usando expressões regulares. Retorna as linhas correspondentes com números de linha e contexto ao redor."\n\nQual é a abordagem mais eficaz para melhorar a seleção de ferramentas MCP pelo agente?\n\n[ ] A - Remover o Grep das ferramentas disponíveis quando o servidor MCP estiver conectado, para eliminar a sobreposição funcional.\n[ ] B - Adicionar instruções de roteamento ao prompt do sistema especificando que perguntas relacionadas a dependências devem usar ferramentas MCP em vez do Grep.\n[ ] C - Dividir `analyze_dependencies` em ferramentas granulares (`list_imports`, `resolve_transitive_deps`, `detect_circular_deps`) para que cada uma tenha um propósito focado e menos propenso a se sobrepor ao Grep.\n[ ] D - Expandir as descrições das ferramentas MCP para detalhar capacidades e saídas — por exemplo, "Constrói um grafo de dependências mostrando importações diretas, dependências transitivas e ciclos."','\n',char(10)),replace('**Explicação didática para um adulto tech lead:**\n\nO problema central é que o agente (LLM) está escolhendo o Grep em vez de `analyze_dependencies` porque a descrição do Grep é mais rica e informativa, enquanto a descrição da ferramenta MCP é genérica e superficial. LMs selecionam ferramentas com base na similaridade semântica entre a consulta do usuário e a descrição da ferramenta. Uma descrição curta como "Analisa o grafo de dependências" não comunica claramente as capacidades da ferramenta, enquanto "Busca o conteúdo de arquivos por um padrão usando expressões regulares. Retorna as linhas correspondentes com números de linha e contexto ao redor" transmite um comportamento concreto e identificável.\n\nVamos analisar cada alternativa:\n\n- **Alternativa A (Remover o Grep):** É uma abordagem reativa e drástica. Remover uma ferramenta nativa versátil como Grep prejudica a capacidade do agente de realizar outras tarefas legítimas de busca textual. Além disso, não resolve a causa raiz — o agente poderia preferir outra ferramenta nativa com descrição rica no lugar. Não é escalável.\n\n- **Alternativa B (Adicionar instruções de roteamento no prompt do sistema):** Embora pareça razoável, instruções no prompt do sistema são sugestões, não garantias. Em modelos de linguagem, prompts complexos podem ser ignorados parcialmente, especialmente se houver conflito semântico entre a descrição da ferramenta e a instrução. Além disso, essa abordagem é frágil: adicionar regras explícitas para cada possível sobreposição de ferramentas não escala e polui o prompt do sistema.\n\n- **Alternativa C (Dividir em ferramentas granulares):** Isso aumenta a complexidade da superfície de ferramentas e pode confundir ainda mais o agente, que precisará decidir entre múltiplas ferramentas MCP e o Grep. A granularidade excessiva pode levar a mais sobreposição e más escolhas, além de aumentar a carga de manutenção. O problema não é falta de granularidade, é falta de clareza na descrição.\n\n- **Alternativa D (Expandir as descrições das ferramentas MCP):** É a abordagem mais eficaz porque ataca a causa raiz: a descrição da ferramenta MCP é pobre em detalhes. Ao enriquecer a descrição com informações concretas sobre o que a ferramenta faz (constrói grafo, mostra importações diretas, dependências transitivas, ciclos), o modelo consegue associar semanticamente a consulta do usuário sobre "dependências de código" à ferramenta correta. Descrições mais detalhadas e específicas melhoram a precisão da seleção de ferramentas por LMs sem necessidade de alterar o sistema ou remover funcionalidades.\n\nPortanto, a alternativa D é a melhor prática para melhorar a seleção de ferramentas MCP pelo agente.','\n',char(10)),replace('Imagine que você tem dois brinquedos: um é um "detetive de palavras" que procura palavras nos livros (o Grep), e o outro é um "mapa de amizades" que mostra quem é amigo de quem no código (o `analyze_dependencies`).\n\nO problema é que o "mapa de amizades" veio com uma etiqueta dizendo só "Analisa amizades", mas o "detetive de palavras" veio com uma etiqueta enorme explicando direitinho como ele funciona. Quando alguém pergunta "Quem são os amigos desse código?", o computador olha as etiquetas e acha que o detetive é mais adequado porque a etiqueta dele é mais clara.\n\nA melhor solução é escrever uma etiqueta melhor para o "mapa de amizades", explicando que ele "mostra um desenho de quem é amigo de quem, incluindo amigos diretos, amigos dos amigos e se tem algum círculo de amizade fechado". Assim, o computador vai entender direitinho qual brinquedo usar quando alguém perguntar sobre amizades no código!\n\nA resposta correta é a D: melhorar as descrições das ferramentas MCP.','\n',char(10)));
INSERT INTO cards VALUES('admin','card_1783092984393_lq5vdsw9d',72,'Um engenheiro pede ao agente para encontrar todos os chamadores de uma função antes de removê-la.',replace('Um engenheiro pede ao agente para encontrar todos os chamadores de uma função antes de removê-la.\n\nUm engenheiro pede ao agente para encontrar todos os chamadores de uma função antes de removê-la. A função é definida em uma biblioteca central, mas também é exposta por meio de módulos wrapper que renomeiam a função para uso específico de domínio (por exemplo, calculateTax na biblioteca torna-se computeOrderTax no módulo de pedidos).\n\nQual estratégia de exploração identificará de forma mais confiável todos os chamadores?\n\n[ ] A - Ler a biblioteca e os módulos wrapper para identificar todos os nomes sob os quais a função é exposta e, em seguida, usar o Grep para cada nome em toda a base de código.\n[ ] B - Usar o Grep para encontrar todos os arquivos que importam da biblioteca ou dos módulos wrapper e, então, ler cada arquivo para verificar se ele usa a função.\n[ ] C - Usar o Grep para buscar o nome original da função em toda a base de código.\n[ ] D - Buscar o nome da função na documentação do projeto para entender os padrões de uso pretendidos e navegar até os pontos de integração documentados.','\n',char(10)),'A - Ler a biblioteca e os módulos wrapper para identificar todos os nomes sob os quais a função é exposta e, em seguida, usar o Grep para cada nome em toda a base de código.','["Domain_3::Claude_Code_Configuration_Workflows", "Domain_2::Tool_Design_MCP_Integration", "Scenario_4::Developer_Productivity"]','New',0,2.5,0,1783092984393,1783725315660,1783203558653,replace('**Tradução para português do Brasil:**\n\nUm engenheiro pede ao agente para encontrar todos os chamadores de uma função antes de removê-la. A função é definida em uma biblioteca central, mas também é exposta por meio de módulos wrapper que renomeiam a função para uso específico de domínio (por exemplo, calculateTax na biblioteca torna-se computeOrderTax no módulo de pedidos).\n\nQual estratégia de exploração identificará de forma mais confiável todos os chamadores?\n\n[ ] A - Ler a biblioteca e os módulos wrapper para identificar todos os nomes sob os quais a função é exposta e, em seguida, usar o Grep para cada nome em toda a base de código.\n[ ] B - Usar o Grep para encontrar todos os arquivos que importam da biblioteca ou dos módulos wrapper e, então, ler cada arquivo para verificar se ele usa a função.\n[ ] C - Usar o Grep para buscar o nome original da função em toda a base de código.\n[ ] D - Buscar o nome da função na documentação do projeto para entender os padrões de uso pretendidos e navegar até os pontos de integração documentados.','\n',char(10)),replace('**Explicação para um adulto tech lead:**\n\n**Alternativa correta: A**\n\n**Por que a alternativa A é a mais confiável?**\n\nO problema apresentado envolve uma função que é definida em uma biblioteca central, mas que é "reexportada" com nomes diferentes em módulos wrapper. Isso significa que os chamadores podem referenciar a função por nomes distintos (por exemplo, `calculateTax`, `computeOrderTax`, `calculateOrderTax`, etc.). \n\nA alternativa A resolve esse problema de forma sistemática e completa:\n1. **Primeiro passo**: lê a biblioteca central e os módulos wrapper para descobrir *todos* os nomes sob os quais a função é exposta. Isso captura o mapeamento completo de aliases/renomeações.\n2. **Segundo passo**: usa Grep para cada um desses nomes em toda a base de código. Como agora você conhece todos os possíveis nomes, a busca cobre todos os chamadores, independentemente de qual nome foi usado.\n\nÉ uma estratégia de **descoberta baseada em fontes confiáveis (código-fonte real)** combinada com **busca exaustiva (grep)**.\n\n**Por que as demais alternativas são inferiores:**\n\n- **B**: Usar Grep para encontrar arquivos que *importam* da biblioteca ou módulos wrapper e depois ler cada arquivo é ineficiente e propenso a erro humano. O engenheiro precisaria ler manualmente cada arquivo para identificar o uso da função, o que é trabalhoso e sujeito a falhas de atenção, especialmente em bases de código grandes. Além disso, não há garantia de que todos os padrões de importação sejam capturados (por exemplo, imports dinâmicos, imports com aliases diferentes).\n\n- **C**: Buscar apenas o nome original da função (`calculateTax`) vai perder todos os chamadores que usam os nomes renomeados nos wrappers (`computeOrderTax`, etc.). Isso é uma falha grave, pois o contexto do problema afirma explicitamente que a função é exposta sob nomes diferentes.\n\n- **D**: Depender de documentação é frágil. A documentação pode estar desatualizada, incompleta ou simplesmente não listar todos os pontos de integração. É uma abordagem reativa e não exaustiva. Navegar manualmente por "pontos de integração documentados" não substitui uma varredura sistemática do código.\n\n**Resumo técnico**: A abordagem correta é **analisar a árvore de reexportação (reexport chain)** para obter todos os nomes simbólicos e, em seguida, realizar uma **busca textual exaustiva** com grep para cada símbolo. Isso combina análise estática de dependências com busca de padrões, garantindo cobertura máxima.','\n',char(10)),replace('Imagine que você tem um brinquedo chamado "Bola Azul" na sua caixa de brinquedos principal. Mas seus amigos, em outras caixas, chamam esse mesmo brinquedo de "Bola do Pedro" ou "Bola de Futebol". Se você quiser encontrar todas as crianças que estão brincando com esse brinquedo, você precisa saber todos os nomes que ele tem.\n\nA alternativa A é a melhor porque primeiro você descobre todos os nomes que o brinquedo ganhou (lendo as caixas dos amigos) e depois procura cada um desses nomes em toda a casa. Assim você encontra todo mundo que está usando o brinquedo, não importa como o chamam.\n\nAs outras opções não funcionam tão bem:\n- A B é como tentar achar quem está brincando com a bola só olhando quem pegou alguma coisa da sua caixa de brinquedos — você teria que abrir cada caixa e conferir manualmente, o que dá muito trabalho.\n- A C é procurar só pelo nome "Bola Azul", mas você vai perder quem chama de "Bola do Pedro".\n- A D é perguntar pra sua mãe quem ela acha que está brincando com a bola — ela pode não saber de tudo!\n\nEntão, a melhor estratégia é: descubra todos os apelidos do brinquedo e depois procure por cada apelido. ✅','\n',char(10)));
INSERT INTO cards VALUES('admin','card_1783092984401_1h3m78goe',73,'Após adicionar um servidor MCP com ferramentas especializadas de refatoração de código (`extract_function`, `rename_variable`, `inline_function`), você nota que o agente ainda usa manipulação básica de texto via Write e comandos sed do Bash para tarefas de refatoração.',replace('Após adicionar um servidor MCP com ferramentas especializadas de refatoração de código (`extract_function`, `rename_variable`, `inline_function`), você nota que o agente ainda usa manipulação básica de texto via Write e comandos sed do Bash para tarefas de refatoração.\n\nApós adicionar um servidor MCP com ferramentas especializadas de refatoração de código (`extract_function`, `rename_variable`, `inline_function`), você nota que o agente ainda usa manipulação básica de texto via Write e comandos sed do Bash para tarefas de refatoração. O servidor MCP está conectado e saudável. Ao examinar a configuração, você descobre que cada ferramenta MCP tem uma descrição mínima como "`extract_function`: extrai uma função do código."\n\nQual é a maneira mais eficaz de melhorar a adoção das ferramentas de refatoração MCP?\n\n[ ] A - Implementar um classificador de requisições que detecta a intenção de refatoração e roteia automaticamente essas requisições para o servidor MCP antes de o agente processá-las.\n[ ] B - Remover a ferramenta Write da configuração do agente durante as sessões de refatoração, de modo que ele seja obrigado a usar as ferramentas MCP para modificações de código.\n[ ] C - Aceitar isso como comportamento esperado, já que ferramentas mais simples como o sed são mais previsíveis do que ferramentas especializadas de refatoração.\n[ ] D - Aprimorar as descrições das ferramentas MCP para explicar quando cada ferramenta é preferível à manipulação de texto e esclarecer as entradas e saídas esperadas.','\n',char(10)),'D - Aprimorar as descrições das ferramentas MCP para explicar quando cada ferramenta é preferível à manipulação de texto e esclarecer as entradas e saídas esperadas.','["Domain_2::Tool_Design_MCP_Integration", "Domain_4::Prompt_Engineering_Structured_Output", "Scenario_4::Developer_Productivity"]','New',0,2.5,0,1783092984401,1783725319822,1783203558653,replace('**Tradução para português do Brasil:**\n\nApós adicionar um servidor MCP com ferramentas especializadas de refatoração de código (`extract_function`, `rename_variable`, `inline_function`), você nota que o agente ainda usa manipulação básica de texto via Write e comandos sed do Bash para tarefas de refatoração. O servidor MCP está conectado e saudável. Ao examinar a configuração, você descobre que cada ferramenta MCP tem uma descrição mínima como "`extract_function`: extrai uma função do código."\n\nQual é a maneira mais eficaz de melhorar a adoção das ferramentas de refatoração MCP?\n\n[ ] A - Implementar um classificador de requisições que detecta a intenção de refatoração e roteia automaticamente essas requisições para o servidor MCP antes de o agente processá-las.\n[ ] B - Remover a ferramenta Write da configuração do agente durante as sessões de refatoração, de modo que ele seja obrigado a usar as ferramentas MCP para modificações de código.\n[ ] C - Aceitar isso como comportamento esperado, já que ferramentas mais simples como o sed são mais previsíveis do que ferramentas especializadas de refatoração.\n[ ] D - Aprimorar as descrições das ferramentas MCP para explicar quando cada ferramenta é preferível à manipulação de texto e esclarecer as entradas e saídas esperadas.','\n',char(10)),replace('**Explicação didática para adulto (tech lead):**\n\n**Resposta correta: D**\n\nO comportamento do agente é guiado fundamentalmente pelas descrições das ferramentas disponíveis. Em modelos de linguagem de grande escala (LLMs) usados como agentes, a decisão de qual ferramenta utilizar é tomada com base na relevância semântica entre a tarefa solicitada e a descrição das ferramentas disponíveis. Se as descrições das ferramentas MCP são genéricas e mínimas (ex.: "extrai uma função do código"), o modelo não tem informações suficientes para entender *quando* essa ferramenta é superior à manipulação textual via Write ou sed. A descrição não comunica benefícios como segurança semântica (garantia de que a refatoração não quebrará o código), precisão estrutural (manipulação de AST em vez de regex) ou economia de tokens. Aprimorar as descrições com exemplos de uso, situações recomendadas e contraste explícito com abordagens alternativas (ex.: "Use esta ferramenta em vez de sed/Write quando precisar extrair um bloco de código para uma nova função, pois ela preserva a árvore sintática e evita erros de escopo") aumenta drasticamente a probabilidade de o agente selecionar a ferramenta correta.\n\n**Análise das alternativas incorretas:**\n\n- **A**: Embora pareça uma solução de "engenharia de sistemas", ela é frágil e de alta complexidade. Um classificador de intenção exigiria manutenção constante, treinamento com dados rotulados e ainda assim poderia falhar em casos ambíguos. Além disso, ignora a causa raiz: o agente não escolhe as ferramentas MCP porque não entende quando usá-las. Roteamento forçado também reduz a flexibilidade e capacidade de adaptação do agente.\n\n- **B**: Remover o Write é uma abordagem coercitiva que quebra funcionalidades legítimas (escrita de novos arquivos, modificações que não são refatoração). O agente ainda pode usar sed ou outros comandos. Isso também impede o agente de realizar tarefas não relacionadas à refatoração que exigem escrita de arquivos. Não resolve a questão de *conscientização* do agente sobre as ferramentas MCP.\n\n- **C**: Esta é uma postura derrotista. Ferramentas especializadas de refatoração (baseadas em AST) são significativamente mais seguras e precisas que sed/expressões regulares para manipulação de código. Aceitar o comportamento como "esperado" ignora um problema real de adoção e subutilização de infraestrutura já disponível.','\n',char(10)),replace('Imagine que você tem uma caixa de ferramentas. Você acabou de ganhar ferramentas novas e super legais: uma chave inglesa que aperta porcas sozinha, uma furadeira elétrica e uma serra elétrica. Mas, em vez de usá-las, você continua usando um martelo e um prego para tudo — até para apertar parafusos!\n\nO problema não é que as ferramentas novas não funcionam. O problema é que você não sabe quando usá-las. As instruções delas são muito curtas: "Chave inglesa: aperta porcas". Mas elas não dizem: "Use esta chave inglesa em vez do martelo quando tiver uma porca, porque ela aperta melhor, mais rápido e não estraga o parafuso".\n\nA melhor solução (alternativa D) é escrever instruções melhores para as ferramentas novas, explicando direitinho quando e por que usá-las. Assim, em vez de ficar martelando tudo, você vai lembrar: "Ah, agora é a hora de pegar a furadeira!"\n\nAs outras opções não são tão boas:\n- A: Fazer um robô que decide por você qual ferramenta usar é complicado e o robô pode errar.\n- B: Tirar o martelo da caixa é ruim, porque às vezes você realmente precisa de um martelo.\n- C: Desistir e continuar usando martelo para tudo é jogar fora as ferramentas novas que você ganhou.','\n',char(10)));
INSERT INTO cards VALUES('admin','card_1783092984409_baxcu9onx',74,'Seu agente precisa inserir uma nova função auxiliar no meio de um módulo utilitário de 150 linhas, entre duas funções existentes.',replace('Seu agente precisa inserir uma nova função auxiliar no meio de um módulo utilitário de 150 linhas, entre duas funções existentes.\n\nSeu agente precisa inserir uma nova função auxiliar no meio de um módulo utilitário de 150 linhas, entre duas funções existentes. A ferramenta Edit falha porque seu parâmetro `old_string` não consegue encontrar um texto único para correspondência — o arquivo tem docstrings, nomes de variáveis e padrões estruturais repetitivos.\n\nQual é a maneira mais confiável de concluir essa inserção?\n\n[ ] A - Usar o Edit com um `old_string` extremamente longo, capturando mais de 30 linhas de contexto para garantir a unicidade\n[ ] B - Usar o parâmetro `replace_all` do Edit para mirar em um padrão comum e embutir a nova função no texto de substituição\n[ ] C - Usar o Bash para anexar a definição da função ao final do arquivo usando a sintaxe de heredoc\n[ ] D - Usar o Read para carregar o arquivo, adicionar a função no local apropriado e, então, usar o Write para gravar o arquivo atualizado','\n',char(10)),'D - Usar o Read para carregar o arquivo, adicionar a função no local apropriado e, então, usar o Write para gravar o arquivo atualizado','["Domain_2::Tool_Design_MCP_Integration", "Domain_4::Prompt_Engineering_Structured_Output", "Domain_5::Context_Management_Reliability", "Scenario_4::Developer_Productivity"]','New',0,2.5,0,1783092984409,1783725324391,1783203558653,replace('**Tradução da Pergunta e Alternativas:**\n\nSeu agente precisa inserir uma nova função auxiliar no meio de um módulo utilitário de 150 linhas, entre duas funções existentes. A ferramenta Edit falha porque seu parâmetro `old_string` não consegue encontrar um texto único para correspondência — o arquivo tem docstrings, nomes de variáveis e padrões estruturais repetitivos.\n\nQual é a maneira mais confiável de concluir essa inserção?\n\n[ ] A - Usar o Edit com um `old_string` extremamente longo, capturando mais de 30 linhas de contexto para garantir a unicidade\n[ ] B - Usar o parâmetro `replace_all` do Edit para mirar em um padrão comum e embutir a nova função no texto de substituição\n[ ] C - Usar o Bash para anexar a definição da função ao final do arquivo usando a sintaxe de heredoc\n[ ] D - Usar o Read para carregar o arquivo, adicionar a função no local apropriado e, então, usar o Write para gravar o arquivo atualizado','\n',char(10)),replace('**Explicação para Tech Lead:**\n\nO cenário descreve um problema clássico de edição textual em arquivos com baixa entropia semântica — docstrings repetitivas, nomes de variáveis genéricos (ex.: `foo`, `bar`, `result`), e padrões estruturais similares (ex.: várias funções com a mesma assinatura `def helper_X(...):`). A ferramenta `Edit`, que opera por substituição de string exata (`old_string` → `new_string`), falha porque não há um trecho único o suficiente para ancorar a substituição no local correto sem ambiguidade.\n\nVamos analisar cada alternativa:\n\n**A - Usar o Edit com um `old_string` extremamente longo, capturando mais de 30 linhas de contexto para garantir a unicidade.**  \nEssa abordagem é frágil por vários motivos: (1) um `old_string` muito longo é difícil de construir corretamente sem erros de digitação ou quebra de linhas; (2) mesmo com 30+ linhas, se o arquivo tem padrões repetitivos (ex.: várias funções com docstrings idênticas como "Retorna o valor calculado"), ainda pode haver ambiguidade; (3) qualquer diferença mínima (espaço extra, quebra de linha diferente) entre o `old_string` fornecido e o conteúdo real do arquivo faz a substituição falhar silenciosamente. Não é uma solução robusta.\n\n**B - Usar o parâmetro `replace_all` do Edit para mirar em um padrão comum e embutir a nova função no texto de substituição.**  \nEssa alternativa é perigosa: `replace_all` substitui *todas* as ocorrências do padrão. Se o padrão escolhido aparece em múltiplos lugares (e a descrição diz que há padrões repetitivos), você corromperá o arquivo inserindo a função em vários locais indevidos. É o oposto do que se deseja — precisamos de precisão, não de substituição global.\n\n**C - Usar o Bash para anexar a definição da função ao final do arquivo usando a sintaxe de heredoc.**  \nIsso simplesmente não resolve o problema. Anexar ao final do arquivo colocaria a função fora da ordem desejada (no meio, entre duas funções específicas). Você teria um arquivo com a função nova no fim, o que quebra a organização lógica do módulo, potencialmente violando convenções do time e dificultando a manutenção. Além disso, não há garantia de que a função será inserida entre as funções corretas.\n\n**D - Usar o Read para carregar o arquivo, adicionar a função no local apropriado e, então, usar o Write para gravar o arquivo atualizado.**  \nEsta é a abordagem mais confiável porque: (1) o `Read` traz o conteúdo completo do arquivo para a memória do agente como uma string; (2) o agente pode usar lógica programática (ex.: encontrar o ponto de inserção via busca textual direcionada ou parse do conteúdo) para modificar a string em memória com precisão cirúrgica; (3) o `Write` grava o conteúdo modificado de uma vez, substituindo o arquivo original. Como o agente opera sobre o conteúdo integral, não há risco de ambiguidade de correspondência — ele pode, por exemplo, localizar o final da primeira função usando uma âncora mais específica (ex.: "def funcao_existente_1(...):" seguido do corpo e, em seguida, inserir a nova função antes do início da próxima). Isso elimina a dependência de um `old_string` único e contorna padrões repetitivos.\n\n**Resposta correta: D**','\n',char(10)),replace('Imagine que você tem um arquivo de texto com 150 linhas, cheio de "receitas" (funções) escritas. Você precisa escrever uma nova receita no meio do arquivo, entre duas receitas que já existem. O problema é que muitas receitas parecem iguais — elas começam com frases parecidas (docstrings) e têm nomes e estruturas repetidas.\n\nA ferramenta de "editar" (trocar um pedaço de texto por outro) não funciona porque ela tenta achar um trecho exato para substituir, mas, como tem muita coisa repetida, ela não consegue encontrar o lugar certo sem se confundir.\n\nEntão, qual é o melhor jeito de fazer isso?\n\nA - Usar um trecho enorme de texto (mais de 30 linhas) para tentar achar um lugar único.  \nIsso é arriscado porque o trecho enorme pode ser difícil de escrever sem erros, e ainda assim pode haver outro lugar igual no arquivo — aí a troca falha.\n\nB - Usar uma opção que troca TODOS os lugares que têm um certo padrão parecido.  \nIsso é perigoso! Se você mandar trocar um pedaço que aparece em vários lugares, a função nova vai aparecer em cada um desses lugares, bagunçando tudo.\n\nC - Usar um comando para colocar a função nova no FINAL do arquivo.  \nIsso não resolve, porque você quer a função no MEIO, entre duas funções específicas. Colocar no final quebra a organização.\n\nD - Ler o arquivo inteiro, achar o lugar certo e escrever o arquivo novamente com a função nova no meio.  \nEssa é a melhor! É como ler um livro, achar a página certa, colar um papel novo no meio e reescrever o livro inteiro de uma vez. Assim, você tem certeza de que a função foi parar no lugar certo, sem confusão.\n\nResposta correta: D','\n',char(10)));
INSERT INTO cards VALUES('admin','card_1783092984417_d206h5srm',75,'Os logs de produção revelam um tratamento de erros inconsistente: quando `lookup_order` falha, o agente às vezes tenta novamente mais de 5 vezes (desperdício quando o ID do pedido não existe), às vezes escalona imediatamente (prematuro para problemas temporários de rede) e às vezes pede esclarecimentos ao usuário (inadequado quando o problema é um erro de permissão no backend).',replace('Os logs de produção revelam um tratamento de erros inconsistente: quando `lookup_order` falha, o agente às vezes tenta novamente mais de 5 vezes (desperdício quando o ID do pedido não existe), às vezes escalona imediatamente (prematuro para problemas temporários de rede) e às vezes pede esclarecimentos ao usuário (inadequado quando o problema é um erro de permissão no backend).\n\nOs logs de produção revelam um tratamento de erros inconsistente: quando `lookup_order` falha, o agente às vezes tenta novamente mais de 5 vezes (desperdício quando o ID do pedido não existe), às vezes escalona imediatamente (prematuro para problemas temporários de rede) e às vezes pede esclarecimentos ao usuário (inadequado quando o problema é um erro de permissão no backend). A investigação mostra que sua ferramenta MCP retorna respostas de erro uniformes: {"isError": true, "content": [{"type": "text", "text": "Operation failed"}]}. O agente não consegue distinguir entre os tipos de erro.\n\nQual é a melhoria mais eficaz?\n\n[ ] A - Enriquecer as respostas de erro com metadados estruturados: incluir errorCategory (transient/validation/permission), um booleano isRetryable e uma descrição do que causou a falha.\n[ ] B - Criar uma ferramenta MCP `analyze_error` que o agente chama após qualquer falha para determinar a categoria do erro e a ação recomendada.\n[ ] C - Implementar lógica de nova tentativa com backoff exponencial no seu servidor MCP para todos os erros, retornando ao agente somente depois de esgotadas as tentativas.\n[ ] D - Adicionar exemplos few-shot ao prompt do sistema demonstrando como interpretar padrões de mensagens de erro e selecionar respostas adequadas para cada um.','\n',char(10)),'A - Enriquecer as respostas de erro com metadados estruturados: incluir errorCategory (transient/validation/permission), um booleano isRetryable e uma descrição do que causou a falha.','["Domain_2::Tool_Design_MCP_Integration", "Domain_4::Prompt_Engineering_Structured_Output", "Domain_5::Context_Management_Reliability", "Scenario_1::Customer_Support_Agent"]','New',0,2.5,0,1783092984417,1783725328925,1783203558653,replace('**TRADUÇÃO**\n\nOs logs de produção revelam um tratamento de erros inconsistente: quando `lookup_order` falha, o agente às vezes tenta novamente mais de 5 vezes (desperdício quando o ID do pedido não existe), às vezes escalona imediatamente (prematuro para problemas temporários de rede) e às vezes pede esclarecimentos ao usuário (inadequado quando o problema é um erro de permissão no backend). A investigação mostra que sua ferramenta MCP retorna respostas de erro uniformes: {"isError": true, "content": [{"type": "text", "text": "Operation failed"}]}. O agente não consegue distinguir entre os tipos de erro.\n\nQual é a melhoria mais eficaz?\n\n[ ] A - Enriquecer as respostas de erro com metadados estruturados: incluir errorCategory (transient/validation/permission), um booleano isRetryable e uma descrição do que causou a falha.\n[ ] B - Criar uma ferramenta MCP `analyze_error` que o agente chama após qualquer falha para determinar a categoria do erro e a ação recomendada.\n[ ] C - Implementar lógica de nova tentativa com backoff exponencial no seu servidor MCP para todos os erros, retornando ao agente somente depois de esgotadas as tentativas.\n[ ] D - Adicionar exemplos few-shot ao prompt do sistema demonstrando como interpretar padrões de mensagens de erro e selecionar respostas adequadas para cada um.','\n',char(10)),replace('**EXPLICAÇÃO PARA UM TECH LEAD**\n\nA raiz do problema é clara: o agente recebe uma resposta de erro genérica — `{"isError": true, "content": [{"type": "text", "text": "Operation failed"}]}` — que não carrega nenhuma informação semântica sobre a *natureza* da falha. Sem essa informação, o agente não tem como decidir racionalmente entre tentar novamente, escalonar ou pedir esclarecimentos. Ele age de forma inconsistente porque está essencialmente "adivinhando" o que fazer.\n\n**Por que a alternativa A é a melhor:**\n\nEla resolve o problema na fonte, atacando a causa raiz. Ao enriquecer a resposta de erro da ferramenta MCP com metadados estruturados (`errorCategory`, `isRetryable`, descrição), fornecemos ao agente dados acionáveis e semanticamente ricos. Com um campo `isRetryable: true` associado a `errorCategory: "transient"`, o agente pode aplicar uma política de retry (com contagem limitada). Com `isRetryable: false` e `errorCategory: "validation"`, ele sabe que retentar é inútil. Com `errorCategory: "permission"`, ele entende que escalonamento é o caminho correto. Isso coloca a inteligência de decisão nas mãos de quem pode usá-la — o agente — sem depender de heurísticas frágeis.\n\n**Por que as demais estão erradas:**\n\n- **B (Criar ferramenta `analyze_error`):** É um *workaround* indireto. Em vez de consertar a resposta da ferramenta que já falhou, você está adicionando uma chamada extra (mais latência, mais pontos de falha) para "descobrir" o que a ferramenta original já deveria ter dito. Além disso, se `analyze_error` também falhar de forma genérica, você terá o mesmo problema recursivamente.\n\n- **C (Backoff exponencial no servidor MCP):** Isso resolve apenas um subconjunto dos problemas (os erros transitórios) e piora os outros. Se o erro for de validação (pedido inexistente) ou permissão, fazer retentativas no servidor só aumenta latência, consumo de recursos e frustração do usuário, sem nenhuma chance de sucesso. O agente continua sem informação para agir de forma inteligente após o esgotamento das tentativas.\n\n- **D (Exemplos few-shot no prompt):** Essa abordagem tenta ensinar o agente a *adivinhar* a categoria do erro a partir de padrões textuais genéricos. Se a mensagem é sempre "Operation failed", não há padrão para aprender. Few-shot learning funciona quando há algum sinal no texto que correlacione com o tipo de erro; aqui o sinal é zero. É tentar tratar o sintoma sem corrigir a causa.\n\n**Resumo técnico:** A alternativa A segue o princípio de *design for failure* com *information richness* — erros devem ser auto-descritivos e acionáveis. É a abordagem mais direta, eficiente e escalável.','\n',char(10)),replace('Imagine que você tem um robô que busca encomendas. Quando ele não encontra uma encomenda, ele sempre fala a mesma frase: "Deu erro". Só que existem vários motivos diferentes para o erro: às vezes o número da encomenda está errado, às vezes a internet caiu, às vezes você não tem permissão para ver aquela encomenda. Como o robô não sabe qual é o motivo, ele age de forma bagunçada — às vezes tenta de novo um monte de vezes (mesmo quando não adianta), às vezes desiste na hora (mesmo quando tentar de novo resolveria), às vezes pergunta para o usuário (mesmo quando o problema não tem nada a ver com o usuário).\n\nA melhor solução é ensinar o sistema que deu o erro a explicar melhor *qual foi o problema*. Em vez de falar só "Deu erro", ele deveria falar: "Deu erro porque o número do pedido não existe" ou "Deu erro porque a internet falhou". Assim, o robô pode decidir direitinho o que fazer: se o número está errado, não adianta tentar de novo; se a internet falhou, vale tentar mais uma vez; se é problema de permissão, é melhor chamar um humano.\n\nAs outras ideias não são tão boas porque:\n- Criar uma ferramenta separada para "analisar o erro" é como chamar um detetive toda vez que algo dá errado, em vez de a própria pessoa já explicar o que aconteceu.\n- Fazer o sistema tentar de novo várias vezes no servidor resolve só um tipo de erro e piora os outros.\n- Ensinar o robô por exemplos não adianta porque a mensagem de erro é sempre a mesma — não tem padrão para ele aprender.','\n',char(10)));
INSERT INTO cards VALUES('admin','card_1783092984424_tn1gdi3s9',76,'Ao implementar sua ferramenta MCP `lookup_order`, o backend às vezes retorna erros (por exemplo, "Order not found" ou falhas temporárias de banco de dados).',replace('Ao implementar sua ferramenta MCP `lookup_order`, o backend às vezes retorna erros (por exemplo, "Order not found" ou falhas temporárias de banco de dados).\n\nAo implementar sua ferramenta MCP `lookup_order`, o backend às vezes retorna erros (por exemplo, "Order not found" ou falhas temporárias de banco de dados).\n\nQual é o padrão correto para comunicar esses erros de volta ao agente?\n\n[ ] A - Registrar o erro no lado do servidor e retornar um resultado vazio para evitar confundir o modelo.\n[ ] B - Retornar a mensagem de erro no conteúdo do resultado da ferramenta, com a flag isError definida como true.\n[ ] C - Lançar uma exceção a partir do handler da ferramenta para que o framework do agente possa capturá-la e registrá-la.\n[ ] D - Retornar uma resposta de sucesso com um campo "status" indicando o tipo de erro.','\n',char(10)),'B - Retornar a mensagem de erro no conteúdo do resultado da ferramenta, com a flag isError definida como true.','["Domain_2::Tool_Design_MCP_Integration", "Scenario_1::Customer_Support_Agent"]','New',0,2.5,0,1783092984424,1783725332323,1783203558653,replace('**Tradução para português do Brasil:**\n\nAo implementar sua ferramenta MCP `lookup_order`, o backend às vezes retorna erros (por exemplo, "Order not found" ou falhas temporárias de banco de dados).\n\nQual é o padrão correto para comunicar esses erros de volta ao agente?\n\n[ ] A - Registrar o erro no lado do servidor e retornar um resultado vazio para evitar confundir o modelo.\n[ ] B - Retornar a mensagem de erro no conteúdo do resultado da ferramenta, com a flag isError definida como true.\n[ ] C - Lançar uma exceção a partir do handler da ferramenta para que o framework do agente possa capturá-la e registrá-la.\n[ ] D - Retornar uma resposta de sucesso com um campo "status" indicando o tipo de erro.','\n',char(10)),replace('**Explicação para adulto tech lead:**\n\nO protocolo MCP (Model Context Protocol) define um mecanismo explícito para comunicação de erros de ferramentas. Quando uma ferramenta encontra um erro — seja ele um erro de negócio (como "Order not found") ou uma falha técnica (como indisponibilidade de banco de dados) — o padrão correto é retornar um resultado com a flag `isError: true` e a mensagem de erro no campo `content`. Isso permite que o agente (modelo de linguagem) receba a informação de forma estruturada e tome decisões apropriadas, como informar o usuário ou tentar uma ação alternativa.\n\n**Análise das alternativas incorretas:**\n\n- **A**: Registrar o erro no lado do servidor e retornar um resultado vazio pode ocultar informações críticas do agente. O modelo não saberá que houve um erro e poderá agir como se a operação tivesse sido bem-sucedida, confundindo o usuário final. Além disso, o agente perde a oportunidade de tomar ações corretivas (como tentar novamente ou solicitar esclarecimentos).\n\n- **C**: Lançar uma exceção a partir do handler da ferramenta quebra o protocolo MCP. Exceções não são tratadas como respostas de ferramenta no MCP; elas podem encerrar abruptamente a execução ou não ser adequadamente comunicadas ao agente. O framework pode capturar e registrar a exceção, mas o agente não receberá a informação de erro de forma estruturada para reagir.\n\n- **D**: Retornar uma resposta de sucesso com um campo "status" indicando erro é enganoso e não segue o protocolo. O agente interpretará a resposta como bem-sucedida (já que a flag `isError` não foi ativada), mas precisará analisar o conteúdo para detectar o erro. Isso dificulta o tratamento programático e viola o princípio de design explícito do MCP.','\n',char(10)),replace('Imagine que você pediu ajuda a um robô para encontrar um pedido em um sistema. O robô tem uma ferramenta especial chamada `lookup_order`. Às vezes, o sistema não encontra o pedido ou dá um problema.\n\nSe o robô simplesmente esconder o erro e falar "tudo bem, mas não achei nada" (alternativa A), você não vai saber se algo deu errado. Se o robô quebrar e parar de funcionar (alternativa C), ele não consegue te contar o que houve. Se o robô disser "deu certo!" mas colocar um aviso escondido no meio da resposta (alternativa D), você pode se confundir.\n\nO jeito certo é o robô levantar a mão e dizer claramente: "Ops, deu erro! Aqui está o problema: [mensagem]" e acender uma luz vermelha (a flag `isError`). Assim você entende exatamente o que aconteceu e pode decidir o que fazer — como pedir para o robô tentar de novo ou procurar de outra forma. Essa é a alternativa B, a maneira mais honesta e clara de lidar com erros!','\n',char(10)));
INSERT INTO cards VALUES('admin','card_1783092984433_53xioyl02',77,'Sua ferramenta `process_refund` retorna dois tipos de erro: erros técnicos ("503 Service Unavailable", "Connection timeout") que são transitórios (5% das chamadas) e erros de negócio ("Order exceeds 30-day return window", "Item already refunded") que são permanentes (12% das chamadas).',replace('Sua ferramenta `process_refund` retorna dois tipos de erro: erros técnicos ("503 Service Unavailable", "Connection timeout") que são transitórios (5% das chamadas) e erros de negócio ("Order exceeds 30-day return window", "Item already refunded") que são permanentes (12% das chamadas).\n\nSua ferramenta `process_refund` retorna dois tipos de erro: erros técnicos ("503 Service Unavailable", "Connection timeout") que são transitórios (5% das chamadas) e erros de negócio ("Order exceeds 30-day return window", "Item already refunded") que são permanentes (12% das chamadas). O monitoramento mostra que o agente desperdiça de 3 a 4 turnos tentando novamente erros de negócio que nunca podem ter sucesso. Atualmente, ambos os tipos de erro retornam apenas uma mensagem de texto simples ao Claude.\n\nQual é a forma mais eficaz de reduzir as novas tentativas desperdiçadas e, ao mesmo tempo, melhorar a qualidade das respostas voltadas ao cliente?\n\n[ ] A - Retornar respostas de erro estruturadas com retryable: false para erros de negócio e uma explicação amigável ao cliente para o Claude usar.\n[ ] B - Adicionar exemplos few-shot mostrando como distinguir erros recuperáveis de não recuperáveis analisando o texto da mensagem de erro.\n[ ] C - Adicionar uma ferramenta `check_refund_eligibility` que deve ser chamada antes de `process_refund` para evitar violações de regras de negócio.\n[ ] D - Implementar lógica de nova tentativa automática no nível da ferramenta apenas para erros técnicos, repassando erros de negócio ao Claude sem novas tentativas.','\n',char(10)),'A - Retornar respostas de erro estruturadas com retryable: false para erros de negócio e uma explicação amigável ao cliente para o Claude usar.','["Domain_2::Tool_Design_MCP_Integration", "Domain_4::Prompt_Engineering_Structured_Output", "Domain_5::Context_Management_Reliability", "Scenario_1::Customer_Support_Agent"]','New',0,2.5,0,1783092984433,1783725336874,1783203558653,replace('**Tradução da Pergunta e Alternativas:**\n\nSua ferramenta `process_refund` retorna dois tipos de erro: erros técnicos ("503 Service Unavailable", "Connection timeout") que são transitórios (5% das chamadas) e erros de negócio ("Order exceeds 30-day return window", "Item already refunded") que são permanentes (12% das chamadas). O monitoramento mostra que o agente desperdiça de 3 a 4 turnos tentando novamente erros de negócio que nunca podem ter sucesso. Atualmente, ambos os tipos de erro retornam apenas uma mensagem de texto simples ao Claude.\n\nQual é a forma mais eficaz de reduzir as novas tentativas desperdiçadas e, ao mesmo tempo, melhorar a qualidade das respostas voltadas ao cliente?\n\n[ ] A - Retornar respostas de erro estruturadas com retryable: false para erros de negócio e uma explicação amigável ao cliente para o Claude usar.\n[ ] B - Adicionar exemplos few-shot mostrando como distinguir erros recuperáveis de não recuperáveis analisando o texto da mensagem de erro.\n[ ] C - Adicionar uma ferramenta `check_refund_eligibility` que deve ser chamada antes de `process_refund` para evitar violações de regras de negócio.\n[ ] D - Implementar lógica de nova tentativa automática no nível da ferramenta apenas para erros técnicos, repassando erros de negócio ao Claude sem novas tentativas.','\n',char(10)),replace('**Explicação para Adulto Tech Lead:**\n\nO problema central é que o agente (Claude) não tem como diferenciar, no formato atual (mensagens de texto simples), quais erros são permanentes e quais são transitórios. Como resultado, ele tenta repetir operações que jamais terão sucesso (erros de negócio), desperdiçando 3 a 4 turnos de interação.\n\nVamos analisar cada alternativa:\n\n**Alternativa A (Correta):** Retornar erros estruturados (JSON, por exemplo) contendo um campo `retryable: false` para erros de negócio e `retryable: true` para erros técnicos, além de incluir uma mensagem amigável para o cliente. Isso resolve o problema de duas formas: (1) o Claude pode decidir imediatamente não tentar novamente ao ver `retryable: false`, eliminando os turnos desperdiçados; (2) a explicação amigável permite que o Claude componha uma resposta empática e informativa ao usuário final, melhorando a experiência do cliente. É a abordagem mais direta, de baixo custo e alta eficácia.\n\n**Alternativa B:** Few-shot learning para analisar texto de erro é frágil. Os erros são strings textuais que podem variar com versões do sistema, localização, ou pequenas mudanças de formatação. O Claude pode interpretar incorretamente um erro inesperado. Além disso, não fornece uma mensagem amigável para o cliente. É uma solução heurística e menos confiável.\n\n**Alternativa C:** Adicionar uma ferramenta de verificação prévia evita o erro de negócio antes de tentar, mas não resolve o problema dos erros que já ocorrem. Também adiciona latência (uma chamada extra de ferramenta) e complexidade ao fluxo. Útil como prevenção, mas não trata o caso de erros de negócio que ainda podem acontecer (ex.: item já reembolsado em outra chamada concorrente). Não elimina os desperdícios quando o erro de negócio ocorre.\n\n**Alternativa D:** Implementar retry automático no nível da ferramenta (antes de retornar ao Claude) para erros técnicos soa bem, mas não resolve o desperdício de turnos do Claude — os erros de negócio continuariam sendo retornados como texto simples, e o Claude ainda poderia tentar novamente. Além disso, isso tira do Claude a capacidade de decisão sobre retentativas (em vez de evitar retentativas desnecessárias, ele simplesmente não vê os erros técnicos, o que pode ser problemático para transparência e depuração).\n\n**Alternativa A é a mais eficaz** porque trata diretamente a causa raiz (falta de informação sobre recuperabilidade) e adiciona um benefício extra (mensagem amigável), com mínimo esforço de implementação.\n\n---\n\n**Explicação para Criança de 10 Anos:**\n\nImagine que você tem uma máquina de refrigerantes. Às vezes, ela dá erro porque acabou a energia (erro técnico) — e se você esperar um pouco e tentar de novo, pode funcionar. Outras vezes, ela diz "esse sabor acabou" (erro de negócio) — não importa quantas vezes você aperte o botão, nunca vai sair refrigerante.\n\nAntes, a máquina só falava "ERRO" e você ficava apertando o botão várias vezes sem saber se ia funcionar. Isso perdia tempo.\n\nA melhor solução é fazer a máquina falar: "Esse sabor não tem mais, escolha outro" quando o erro for do tipo que não adianta tentar de novo, e "Tente novamente mais tarde" quando for só um probleminha elétrico.\n\nAssim, você não perde tempo apertando o botão sem parar, e ainda entende o que aconteceu para poder escolher outro sabor. É exatamente isso que a alternativa A faz: transforma o aviso de erro em uma mensagem clara que diz "pode tentar de novo?" e "fala pro cliente o que houve de forma educada".','\n',char(10)),replace('Imagine que você tem uma máquina de refrigerantes. Às vezes, ela dá erro porque acabou a energia (erro técnico) — e se você esperar um pouco e tentar de novo, pode funcionar. Outras vezes, ela diz "esse sabor acabou" (erro de negócio) — não importa quantas vezes você aperte o botão, nunca vai sair refrigerante.\n\nAntes, a máquina só falava "ERRO" e você ficava apertando o botão várias vezes sem saber se ia funcionar. Isso perdia tempo.\n\nA melhor solução é fazer a máquina falar: "Esse sabor não tem mais, escolha outro" quando o erro for do tipo que não adianta tentar de novo, e "Tente novamente mais tarde" quando for só um probleminha elétrico.\n\nAssim, você não perde tempo apertando o botão sem parar, e ainda entende o que aconteceu para poder escolher outro sabor. É exatamente isso que a alternativa A faz: transforma o aviso de erro em uma mensagem clara que diz "pode tentar de novo?" e "fala pro cliente o que houve de forma educada".','\n',char(10)));
INSERT INTO cards VALUES('admin','card_1783092984441_n0jhl6c6d',78,'Seu pipeline usa uma ferramenta chamada `extract_metadata` com um esquema JSON para detalhes do artigo.',replace('Seu pipeline usa uma ferramenta chamada `extract_metadata` com um esquema JSON para detalhes do artigo.\n\nSeu pipeline usa uma ferramenta chamada `extract_metadata` com um esquema JSON para detalhes do artigo. Você também definiu as ferramentas `lookup_citations` e `verify_doi` para enriquecimento. Durante os testes, você nota que, quando os usuários incluem pedidos como "extract the metadata and tell me how cited it is", o Claude às vezes chama `lookup_citations` primeiro, o que falha porque ela precisa do DOI que `extract_metadata` forneceria.\n\nQual é a maneira mais eficaz de garantir que a extração estruturada de metadados aconteça primeiro?\n\n[ ] A - Definir `tool_choice` como "any" para que o Claude tenha de usar uma ferramenta, combinado com instruções no prompt do sistema priorizando `extract_metadata`.\n[ ] B - Definir `tool_choice` como "auto" e reordenar as definições de ferramentas para que `extract_metadata` apareça primeiro no array de ferramentas, já que o Claude prioriza as ferramentas listadas antes.\n[ ] C - Definir `tool_choice` como {"type": "tool", "name": "`extract_metadata`"} e processar os pedidos de enriquecimento em turnos subsequentes, depois de receber os metadados extraídos.\n[ ] D - Definir `tool_choice` como {"type": "tool", "name": "`extract_metadata`"} para toda chamada de API no pipeline, garantindo que o Claude sempre extraia metadados antes que qualquer enriquecimento possa ocorrer.','\n',char(10)),'C - Definir `tool_choice` como {"type": "tool", "name": "`extract_metadata`"} e processar os pedidos de enriquecimento em turnos subsequentes, depois de receber os metadados extraídos.','["Domain_4::Prompt_Engineering_Structured_Output", "Domain_2::Tool_Design_MCP_Integration", "Scenario_6::Structured_Data_Extraction"]','New',0,2.5,0,1783092984441,1783725340720,1783203558653,replace('**Tradução para português do Brasil:**\n\nSeu pipeline usa uma ferramenta chamada `extract_metadata` com um esquema JSON para detalhes do artigo. Você também definiu as ferramentas `lookup_citations` e `verify_doi` para enriquecimento. Durante os testes, você nota que, quando os usuários incluem pedidos como "extraia os metadados e me diga quão citado é", o Claude às vezes chama `lookup_citations` primeiro, o que falha porque ela precisa do DOI que `extract_metadata` forneceria.\n\nQual é a maneira mais eficaz de garantir que a extração estruturada de metadados aconteça primeiro?\n\n[ ] A - Definir `tool_choice` como "any" para que o Claude tenha de usar uma ferramenta, combinado com instruções no prompt do sistema priorizando `extract_metadata`.\n[ ] B - Definir `tool_choice` como "auto" e reordenar as definições de ferramentas para que `extract_metadata` apareça primeiro no array de ferramentas, já que o Claude prioriza as ferramentas listadas antes.\n[ ] C - Definir `tool_choice` como {"type": "tool", "name": "`extract_metadata`"} e processar os pedidos de enriquecimento em turnos subsequentes, depois de receber os metadados extraídos.\n[ ] D - Definir `tool_choice` como {"type": "tool", "name": "`extract_metadata`"} para toda chamada de API no pipeline, garantindo que o Claude sempre extraia metadados antes que qualquer enriquecimento possa ocorrer.','\n',char(10)),replace('**Explicação para adulto tech lead:**\n\nO problema central aqui é de **ordenação obrigatória de chamadas de ferramentas** em um pipeline multi-turno (multi-step). O Claude, ao receber um pedido composto (ex.: "extraia os metadados e me diga quão citado é"), pode tentar resolver tudo em um único turno de chamada, escolhendo a ferramenta que julgar mais conveniente primeiro — e, sem uma restrição explícita, ele pode chamar `lookup_citations` antes de ter o DOI, resultando em falha.\n\nVamos analisar cada alternativa:\n\n- **Alternativa A (`tool_choice: "any"` + prompt):** `tool_choice: "any"` força o modelo a chamar alguma ferramenta, mas não especifica qual. O prompt do sistema é apenas uma sugestão, não um vínculo garantido. O modelo ainda pode optar por chamar `lookup_citations` primeiro, ignorando a sugestão. Depender de comportamento probabilístico em um pipeline determinístico é frágil.\n\n- **Alternativa B (`tool_choice: "auto"` + reordenação):** A ordem no array de ferramentas pode influenciar o comportamento do modelo, mas não é uma garantia. `tool_choice: "auto"` dá total liberdade para o modelo escolher zero ou mais ferramentas. Reordenar é uma heurística não confiável; o modelo pode perfeitamente chamar `lookup_citations` antes de `extract_metadata` mesmo com esta aparecendo primeiro na lista.\n\n- **Alternativa C (correta):** Usar `tool_choice: {"type": "tool", "name": "extract_metadata"}` força o modelo a chamar exclusivamente `extract_metadata` na primeira rodada. Após receber os metadados (incluindo o DOI), o pipeline pode então fazer uma segunda chamada de API — sem `tool_choice` restritivo ou com outra configuração — permitindo que o Claude use `lookup_citations` e `verify_doi` com os dados já disponíveis. Isso resolve o problema de ordenação de forma determinística e limpa: primeiro turno para extração, segundo turno para enriquecimento.\n\n- **Alternativa D (`tool_choice: {"type": "tool", "name": "extract_metadata"}` para toda chamada):** Isso forçaria `extract_metadata` em *todas* as chamadas, inclusive nos turnos subsequentes onde o objetivo é justamente enriquecer os dados. Isso impediria o Claude de chamar `lookup_citations` ou `verify_doi` em qualquer momento, o que quebra o pipeline de enriquecimento. É uma abordagem excessivamente restritiva.\n\nPortanto, a alternativa C é a mais eficaz porque estabelece **dois turnos distintos**: o primeiro com `tool_choice` forçado para `extract_metadata`, e o segundo (após receber o resultado) sem essa restrição, permitindo as ferramentas de enriquecimento operarem com os dados já disponíveis.','\n',char(10)),replace('Imagine que você tem que fazer duas coisas: primeiro, pegar a ficha de identificação de um livro (com o nome, autor e código), e depois, com essa ficha, consultar quantas pessoas já leram o livro. Mas o Claude, que é o seu ajudante, às vezes tenta consultar quantas pessoas leram antes mesmo de ter a ficha com o código — e aí dá erro porque ele não sabe qual livro é!\n\nA melhor solução é: na primeira rodada, você **obriga** o Claude a pegar só a ficha (usando o comando `extract_metadata`). Depois que ele te devolve a ficha com o código, aí sim você pede para ele consultar quantas pessoas leram. Assim, ele nunca vai tentar fazer a consulta sem ter o código primeiro.\n\nÉ como numa receita de bolo: primeiro você separa os ingredientes, depois mistura. Se você tentar misturar antes de separar, vira uma bagunça!\n\nA resposta certa é a **letra C**, que manda o Claude fazer a primeira parte de cada vez.','\n',char(10)));
INSERT INTO cards VALUES('admin','card_1783092984448_i9ik3vtre',79,'Claude Code para Integração Contínua',replace('Claude Code para Integração Contínua\n\nSeu pipeline de CI executa o Claude Code CLI (em modo `--print`) usando CLAUDE.md para fornecer contexto do projeto para code review, e os devs em geral acham as reviews substantivas. Porém, eles relatam que integrar achados ao workflow é difícil — Claude emite parágrafos narrativos que precisam ser copiados manualmente para comentários no PR. O time quer postar automaticamente cada achado como comentário inline separado no local relevante do código, o que exige dados estruturados com path do arquivo, número da linha, nível de severidade e correção sugerida. Qual abordagem é mais efetiva?\n\n[ ] A - Adicionar uma seção "Output Format for Review" ao CLAUDE.md com exemplos de achados estruturados para que Claude aprenda o formato esperado a partir do contexto do projeto.\n[ ] B - Usar as flags do CLI `--output-format json` e `--json-schema` para forçar achados estruturados, depois parsear a saída para postar comentários inline via API do GitHub.\n[ ] C - Incluir instruções explícitas de formatação no prompt de review exigindo que cada achado siga um template parseável como `[FILE:path] [LINE:n] [SEVERITY:level] ...`.\n[ ] D - Manter o formato narrativo de review mas adicionar um passo de sumarização que use Claude para gerar um sumário JSON estruturado dos achados.','\n',char(10)),'B - Usar as flags do CLI `--output-format json` e `--json-schema` para forçar achados estruturados, depois parsear a saída para postar comentários inline via API do GitHub.','["Domain_3::Claude_Code_Configuration_Workflows", "Domain_4::Prompt_Engineering_Structured_Output", "Scenario_5::Claude_Code_CI_CD"]','New',0,2.5,0,1783092984448,1783725344791,1783203558653,replace('**Tradução para português do Brasil:**\n\nSeu pipeline de CI executa o Claude Code CLI (em modo `--print`) usando CLAUDE.md para fornecer contexto do projeto para code review, e os devs em geral acham as reviews substantivas. Porém, eles relatam que integrar achados ao workflow é difícil — Claude emite parágrafos narrativos que precisam ser copiados manualmente para comentários no PR. O time quer postar automaticamente cada achado como comentário inline separado no local relevante do código, o que exige dados estruturados com path do arquivo, número da linha, nível de severidade e correção sugerida. Qual abordagem é mais efetiva?\n\n[ ] A - Adicionar uma seção "Output Format for Review" ao CLAUDE.md com exemplos de achados estruturados para que Claude aprenda o formato esperado a partir do contexto do projeto.\n[ ] B - Usar as flags do CLI `--output-format json` e `--json-schema` para forçar achados estruturados, depois parsear a saída para postar comentários inline via API do GitHub.\n[ ] C - Incluir instruções explícitas de formatação no prompt de review exigindo que cada achado siga um template parseável como `[FILE:path] [LINE:n] [SEVERITY:level] ...`.\n[ ] D - Manter o formato narrativo de review mas adicionar um passo de sumarização que use Claude para gerar um sumário JSON estruturado dos achados.','\n',char(10)),replace('**Explicação para adulto tech lead:**\n\nA alternativa **B** é a mais efetiva por várias razões:\n\n1. **Saída deterministicamente estruturada**: As flags `--output-format json` e `--json-schema` são mecanismos nativos do Claude Code CLI para forçar a saída em um formato JSON que obedece a um schema definido. Isso elimina a variabilidade inerente a modelos de linguagem — você não está "pedindo" ou "sugerindo" um formato, está impondo-o via configuração da ferramenta.\n\n2. **Parsing simplificado e sem frangibilidade**: Como a saída é JSON validado contra um schema, o parsing é trivial com qualquer linguagem (jq, Python json.loads, etc.). Não há necessidade de regex frágeis para extrair informações de texto livre.\n\n3. **Acoplamento direto com a automação**: O fluxo "parsear JSON → mapear para comentários inline via API do GitHub" é direto e robusto. Cada objeto no JSON pode conter exatamente `file`, `line`, `severity` e `suggestion`, que mapeiam 1:1 para os parâmetros da API de comentários de PR.\n\n4. **Não depende de aprendizado por contexto**: A alternativa A depende do Claude "aprender" o formato a partir do CLAUDE.md. Embora Claude seja bom em seguir instruções, modelos de linguagem podem desviar do formato esperado em casos de borda, gerando saídas que quebram parsers.\n\n5. **Não depende de parsing de texto livre**: A alternativa C usa um template parseável, mas ainda depende que o modelo siga exatamente a formatação. Variações como espaçamento extra, uso de `[FILE:` vs `[Arquivo:`, ou linhas quebradas podem quebrar o parsing.\n\n6. **Evita duplicação de custo e latência**: A alternativa D adiciona uma chamada extra ao Claude para sumarizar, aumentando custo (tokens) e latência do pipeline, além de introduzir outro ponto de falha.\n\n**Análise das demais alternativas:**\n\n- **A** (CLAUDE.md): Fragilidade similar a C, pois a formatação é uma instrução, não uma imposição. Modelos podem ignorar ou interpretar mal o formato mesmo quando ele está no contexto.\n\n- **C** (instruções no prompt): Funciona em média, mas é frágil. Qualquer desvio na saída (comum em modelos) quebra o parser. Manter um parser robusto para texto semi-estruturado é mais complexo e propenso a bugs silenciosos.\n\n- **D** (sumarização adicional): Adiciona complexidade, custo e latência. Além disso, a sumarização pode perder achados ou introduzir imprecisões. É uma camada extra que não resolve o problema raiz.\n\n**Conclusão técnica**: A flag `--output-format json` com `--json-schema` é a abordagem mais **robusta**, **determinística** e **integrável** para o caso de uso, pois transforma o problema de "parsear linguagem natural" em "parsear JSON", que é trivial e não-frágil.','\n',char(10)),replace('Imagine que você pede para um amigo revisar sua redação e ele escreve um textão contando tudo que achou. Agora você precisa copiar cada erro que ele achou para o seu caderno, um por um. Que trabalhão!\n\nSeu time quer que, ao invés disso, o amigo já entregue uma lista organizada: "Arquivo: redação.txt, Linha: 5, Problema: Erro de ortografia, Correção: ''casa'' em vez de ''caza''". Assim, um robô pode ler essa lista e colocar cada comentário no lugar certinho, sem ninguém precisar copiar nada.\n\nA opção **B** é a melhor porque ela usa um recurso especial do Claude (as flags `--output-format json` e `--json-schema`) que **obriga** ele a entregar a resposta no formato de lista organizada (JSON). É como dar uma ficha para ele preencher, em vez de pedir para ele escrever um texto e depois torcer para ele seguir o modelo.\n\nAs outras opções são como pedir educadamente "por favor, escreva no formato certo" — ele até pode tentar, mas às vezes esquece ou faz diferente. A opção B é a única que **garante** que a resposta já vem no formato certinho para o robô usar direto, sem dor de cabeça.','\n',char(10)));
INSERT INTO cards VALUES('admin','card_1783092984456_a0c189cxv',80,'Claude Code para Integração Contínua',replace('Claude Code para Integração Contínua\n\nSeu script de pipeline executa `claude "Analyze this pull request for security issues"`, mas o job trava indefinidamente. Logs mostram que o Claude Code está esperando entrada interativa. Qual é a abordagem correta para rodar Claude Code em pipeline automatizado?\n\n[ ] A - Adicionar a flag `--batch`: `claude --batch "Analyze this pull request for security issues"`.\n[ ] B - Adicionar a flag `-p`: `claude -p "Analyze this pull request for security issues"`.\n[ ] C - Redirecionar stdin de `/dev/null`: `claude "Analyze this pull request for security issues" < /dev/null`.\n[ ] D - Definir a variável de ambiente `CLAUDE_HEADLESS=true` antes de executar o comando.','\n',char(10)),'B - Adicionar a flag `-p`: `claude -p "Analyze this pull request for security issues"`.','["Domain_3::Claude_Code_Configuration_Workflows", "Domain_4::Prompt_Engineering_Structured_Output", "Scenario_5::Claude_Code_CI_CD"]','New',0,2.5,0,1783092984456,1783725348574,1783203558653,replace('**Tradução para português do Brasil:**\n\n**Pergunta:** Claude Code para Integração Contínua\n\nSeu script de pipeline executa `claude "Analyze this pull request for security issues"`, mas o job trava indefinidamente. Logs mostram que o Claude Code está esperando entrada interativa. Qual é a abordagem correta para rodar Claude Code em pipeline automatizado?\n\n[ ] A - Adicionar a flag `--batch`: `claude --batch "Analyze this pull request for security issues"`.\n[ ] B - Adicionar a flag `-p`: `claude -p "Analyze this pull request for security issues"`.\n[ ] C - Redirecionar stdin de `/dev/null`: `claude "Analyze this pull request for security issues" < /dev/null`.\n[ ] D - Definir a variável de ambiente `CLAUDE_HEADLESS=true` antes de executar o comando.','\n',char(10)),replace('**Explicação para um adulto tech lead:**\n\nA alternativa correta é a **B**.\n\nQuando o Claude Code é invocado sem argumentos ou com uma string solta, ele por padrão abre uma sessão interativa (REPL), aguardando comandos do usuário via stdin. Isso faz com que o pipeline trave, pois o processo fica bloqueado esperando entrada que nunca virá.\n\nA flag `-p` (abreviação de `--print`) instrui o Claude Code a tratar o argumento seguinte como um *prompt único* (single-turn), executá-lo e encerrar imediatamente, sem entrar no modo interativo. É exatamente o comportamento desejado para execução headless em pipelines de CI/CD.\n\nAnalisando as alternativas incorretas:\n\n- **A (--batch)**: A flag `--batch` não existe no CLI do Claude Code. É uma invenção. Mesmo que existisse hipoteticamente, não é a forma correta de resolver o problema.\n\n- **C (redirecionar /dev/null)**: Redirecionar stdin de `/dev/null` não resolve o problema. O Claude Code no modo interativo ainda tentará inicializar o REPL, e ao detectar EOF em `/dev/null`, ou falhará silenciosamente ou se comportará de forma imprevisível. Não é uma solução confiável para um pipeline.\n\n- **D (CLAUDE_HEADLESS=true)**: Não existe essa variável de ambiente na documentação oficial do Claude Code. É fabricada. O Claude Code não utiliza essa variável para controle de modo headless; o mecanismo correto é via linha de comando com `-p`.\n\nPortanto, para uso automatizado (CI/CD, scripts, pipelines), a flag `-p` é a abordagem documentada e suportada.','\n',char(10)),replace('Imagine que você tem um robô chamado Claude que responde perguntas. Se você só falar "Analisa isso", ele acha que vocês vão conversar e fica esperando você digitar mais coisas — e nunca termina sozinho. Isso trava o computador!\n\nA flag `-p` é como dar uma ordem completa de uma vez: "Robô, responda isso e pare." Assim ele faz o serviço e encerra sozinho, sem ficar esperando.\n\nAs outras opções não funcionam: a bandeira `--batch` não existe de verdade; jogar o robô no "nada" (redirecionar do `/dev/null`) não o faz agir certo; e a variável de ambiente que as pessoas inventaram também não é real. O jeito certo e simples é usar o `-p`.','\n',char(10)));
INSERT INTO cards VALUES('admin','card_1783092984476_hy27b9amf',81,'Geração de Código com Claude Code',replace('Geração de Código com Claude Code\n\nVocê precisa adicionar Slack como novo canal de notificação. A base existente tem padrões claros e estabelecidos para email, SMS e push. Porém, a API do Slack oferece abordagens fundamentalmente diferentes — webhooks de entrada (simples, unidirecional), bot tokens (suporte a confirmação de entrega e controle programático), ou Slack Apps (eventos bidirecionais, requer aprovação do workspace). Sua tarefa diz "adicionar suporte a Slack" sem especificar método de integração ou exigir features avançadas como tracking de entrega.\n\nComo abordar essa tarefa?\n\n[ ] A - Começar em modo de execução direta usando webhooks de entrada para casar com o padrão existente unidirecional.\n[ ] B - Mudar para modo de planejamento para explorar opções de integração e implicações arquiteturais, depois apresentar uma recomendação antes da implementação.\n[ ] C - Começar em execução direta fazendo scaffolding de uma classe de canal Slack usando padrões existentes, adiando a decisão do método de integração.\n[ ] D - Começar em execução direta usando uma abordagem de bot-token para garantir que confirmação de entrega seja possível.','\n',char(10)),'B - Mudar para modo de planejamento para explorar opções de integração e implicações arquiteturais, depois apresentar uma recomendação antes da implementação.','["Domain_3::Claude_Code_Configuration_Workflows", "Domain_4::Prompt_Engineering_Structured_Output", "Scenario_2::Code_Generation_Claude_Code"]','New',0,2.5,0,1783092984476,1783725352589,1783203558653,'**Tradução para português do Brasil:**',replace('Geração de Código com Claude Code\n\nVocê precisa adicionar Slack como novo canal de notificação. A base existente tem padrões claros e estabelecidos para email, SMS e push. Porém, a API do Slack oferece abordagens fundamentalmente diferentes — webhooks de entrada (simples, unidirecional), bot tokens (suporte a confirmação de entrega e controle programático), ou Slack Apps (eventos bidirecionais, requer aprovação do workspace). Sua tarefa diz "adicionar suporte a Slack" sem especificar método de integração ou exigir features avançadas como tracking de entrega.\n\nComo abordar essa tarefa?\n\n[ ] A - Começar em modo de execução direta usando webhooks de entrada para casar com o padrão existente unidirecional.\n[ ] B - Mudar para modo de planejamento para explorar opções de integração e implicações arquiteturais, depois apresentar uma recomendação antes da implementação.\n[ ] C - Começar em execução direta fazendo scaffolding de uma classe de canal Slack usando padrões existentes, adiando a decisão do método de integração.\n[ ] D - Começar em execução direta usando uma abordagem de bot-token para garantir que confirmação de entrega seja possível.\n\n---\n\n**Explicação para um adulto tech lead:**\n\nO cenário descreve uma situação clássica de **ambiguidade de requisitos combinada com múltiplas alternativas técnicas com trade-offs significativos**. A base de código existente tem padrões consolidados para canais unidirecionais (email, SMS, push), mas o Slack apresenta opções fundamentalmente diferentes em termos de arquitetura, segurança, esforço de manutenção e experiência do usuário.\n\nA alternativa **B é a correta** porque:\n\n1. **Due diligence arquitetural**: Antes de escrever qualquer linha de código, é prudente explorar as opções (webhooks, bot tokens, Slack Apps) e entender como cada uma se alinha com a arquitetura atual, os requisitos não-funcionais e a maturidade da organização.\n\n2. **Decisão informada**: A tarefa diz "adicionar suporte a Slack" sem especificar método ou exigir tracking de entrega. Isso não significa que tracking não seja desejável no futuro. Um planejamento prévio permite antecipar necessidades futuras sem overengineering.\n\n3. **Custo de retrabalho**: Implementar direto com webhooks (A) pode parecer simples, mas se depois surgir a necessidade de confirmação de entrega ou interatividade, a migração para bot tokens ou Slack Apps pode exigir refatoração significativa da abstração de canal. O mesmo vale para (D) — começar com bot tokens pode ser overengineering se webhooks já resolvem.\n\n4. **Scaffolding adiando decisão (C)** é arriscado porque a interface da classe de canal pode precisar ser diferente dependendo do método de integração (ex.: webhook é stateless e assíncrono; bot token requer gerenciamento de conexão WebSocket e estado de sessão). Adiar a decisão pode levar a uma abstração genérica frágil ou que precise ser descartada.\n\n**Análise das alternativas incorretas:**\n\n- **A**: Parte do pressuposto de que "simples = melhor" e que o padrão existente unidirecional é suficiente. Ignora que a escolha do método de integração tem implicações de segurança (webhooks não validam origem além de um secret estático), manutenção (webhooks podem expirar ou ser revogados sem aviso), e escalabilidade (webhooks não suportam rate limiting inteligente ou retry com backoff adequado).\n\n- **C**: O scaffolding prematuro de uma classe genérica sem conhecer o método de integração concreto pode levar a uma abstração que não atende bem a nenhum dos métodos. É como definir a interface de um veículo sem saber se será terrestre, aquático ou aéreo.\n\n- **D**: Introduz complexidade desnecessária (bot tokens exigem OAuth flow, gerenciamento de escopos, tratamento de eventos de revogação) sem que a tarefa justifique essa complexidade. É um exemplo de overengineering baseado em suposições não validadas.\n\n**Conclusão**: A abordagem mais profissional e de baixo risco é planejar primeiro, documentar as opções com seus prós e contras no contexto específico do sistema, e então implementar com base em uma decisão informada e alinhada com os stakeholders.','\n',char(10)),replace('Imagine que você precisa construir uma caixa de correio para entregar mensagens para o sistema do Slack. Mas você descobriu que existem três tipos diferentes de caixa de correio: uma simples (só jogar a carta e pronto), uma mais esperta (que confirma se a carta chegou) e uma super avançada (que permite conversar de volta). Sua tarefa só diz "faz uma caixa de correio para o Slack", sem explicar qual tipo usar.\n\nA melhor ideia é **primeiro parar e pensar** antes de sair construindo. É como quando você vai montar um Lego e olha as peças primeiro para decidir o que vai construir. Se você começar a montar sem saber o que está fazendo, pode ter que desmontar tudo depois e começar de novo — e isso dá muito mais trabalho!\n\nA opção B é a certa porque você vai **explorar as opções primeiro** (como se fosse pesquisar no Google ou perguntar para alguém que já fez isso antes), entender qual se encaixa melhor no que você já tem, e só então começar a construir. Assim você evita retrabalho e faz a escolha mais inteligente.\n\nAs outras opções são arriscadas porque:\n- **A**: Você já sai construindo a caixa mais simples sem saber se amanhã vão pedir uma mais completa.\n- **C**: Você começa a fazer a estrutura da caixa mas sem decidir o tipo — é como montar a porta da garagem sem saber se vai passar um carro ou uma bicicleta.\n- **D**: Você já faz a caixa mais complicada de todas, mesmo que a simples resolva o problema. É usar um canhão para matar uma formiga!','\n',char(10)));
INSERT INTO cards VALUES('admin','card_1783092984485_jifbw4dtd',82,'Geração de Código com Claude Code',replace('Geração de Código com Claude Code\n\nSeu CLAUDE.md cresceu para 400+ linhas contendo padrões de código, convenções de testes, um checklist detalhado de PR review, instruções de deploy e procedimentos de migração de banco. Você quer que Claude sempre siga padrões de código e convenções de testes, mas aplique guias de PR review, deploy e migration apenas quando estiver fazendo essas tarefas.\n\nQual abordagem de reestruturação é mais efetiva?\n\n[ ] A - Mover toda a orientação para arquivos Skills separados organizados por tipo de fluxo, deixando apenas uma breve descrição do projeto no CLAUDE.md.\n[ ] B - Manter tudo no CLAUDE.md mas usar sintaxe `@import` para organizar em arquivos mantidos separadamente por categoria.\n[ ] C - Dividir o CLAUDE.md em arquivos sob `.claude/rules/` com padrões glob path-bound para que cada regra carregue só para os tipos de arquivo relevantes.\n[ ] D - Manter padrões universais no CLAUDE.md e criar Skills para guias específicos de fluxo (PR review, deploy, migrations) com palavras-chave de gatilho.','\n',char(10)),'D - Manter padrões universais no CLAUDE.md e criar Skills para guias específicos de fluxo (PR review, deploy, migrations) com palavras-chave de gatilho.','["Domain_3::Claude_Code_Configuration_Workflows", "Domain_5::Context_Management_Reliability", "Scenario_2::Code_Generation_Claude_Code"]','New',0,2.5,0,1783092984485,1783725356739,1783203558653,replace('**Tradução para português do Brasil:**\n\nGeração de Código com Claude Code\n\nSeu arquivo CLAUDE.md cresceu para mais de 400 linhas contendo padrões de código, convenções de testes, um checklist detalhado de revisão de PR, instruções de deploy e procedimentos de migração de banco. Você quer que Claude siga sempre os padrões de código e convenções de testes, mas aplique os guias de revisão de PR, deploy e migração apenas quando estiver realizando essas tarefas específicas.\n\nQual abordagem de reestruturação é mais efetiva?\n\n[ ] A - Mover toda a orientação para arquivos Skill separados organizados por tipo de fluxo, deixando apenas uma breve descrição do projeto no CLAUDE.md.\n[ ] B - Manter tudo no CLAUDE.md mas usar sintaxe `@import` para organizar em arquivos mantidos separadamente por categoria.\n[ ] C - Dividir o CLAUDE.md em arquivos sob `.claude/rules/` com padrões glob path-bound para que cada regra carregue apenas para os tipos de arquivo relevantes.\n[ ] D - Manter padrões universais no CLAUDE.md e criar Skills para guias específicos de fluxo (revisão de PR, deploy, migrações) com palavras-chave de gatilho.','\n',char(10)),replace('**Explicação para adulto tech lead:**\n\nA alternativa correta é a **D**. Vou detalhar a análise:\n\n**Por que D é a melhor escolha:**\n\nO problema central é separar o que é "sempre relevante" (padrões de código, convenções de testes) do que é "contextualmente relevante" (checklists de PR review, procedimentos de deploy, migrações de banco). A abordagem D resolve isso elegantemente:\n\n- **Padrões universais no CLAUDE.md**: São carregados em toda interação com o Claude, garantindo que convenções de código e testes sejam sempre respeitadas, sem overhead cognitivo desnecessário.\n- **Skills com palavras-chave de gatilho**: Permitem que guias específicos só sejam ativados quando o contexto da conversa indica que aquela tarefa está sendo executada. Isso é eficiente porque:\n  - Reduz o contexto inicial (prompt tokens economizados)\n  - Evita que regras de deploy atrapalhem uma sessão puramente de desenvolvimento\n  - Ativa conhecimento especializado apenas quando necessário\n  - Skills são modulares, versionáveis e podem ser compartilhadas entre projetos\n\n**Por que as alternativas estão incorretas:**\n\n**A - Mover TUDO para Skills separados, deixando apenas descrição no CLAUDE.md**: Essa abordagem cria um problema oposto. Padrões de código e convenções de testes são relevantes em praticamente todas as interações de geração de código. Se forem movidos para Skills, eles precisariam ser manualmente ativados ou depender de palavras-chave, o que é frágil e aumenta a chance de o Claude ignorar convenções importantes durante o desenvolvimento cotidiano. O CLAUDE.md deve conter o que é sempre relevante.\n\n**B - Usar sintaxe `@import`**: Embora a organização em arquivos separados seja boa, a sintaxe `@import` no CLAUDE.md apenas inclui o conteúdo de outros arquivos de forma estática — o conteúdo importado ainda é carregado integralmente em toda interação. Não resolve o problema de carregamento condicional. É puramente uma organização estrutural, não uma solução de contexto.\n\n**C - Dividir em `.claude/rules/` com padrões glob path-bound**: Esta abordagem atrela regras a tipos de arquivo (ex.: "essa regra vale para arquivos *.tsx"), não a fluxos de trabalho (ex.: "essa regra vale quando estou fazendo deploy"). Para o cenário descrito, os guias de PR review, deploy e migrações não estão vinculados a tipos de arquivo — estão vinculados a atividades. Path-bound rules seriam úteis para, por exemplo, aplicar regras específicas para arquivos de migração SQL, mas não para ativar um checklist de PR review quando o usuário pede "revise este PR".\n\n**Resumo técnico:** A abordagem D respeita o princípio de separação de preocupações (SoC) ao nível de ativação contextual. Patternos universais ficam no CLAUDE.md (carregamento incondicional), enquanto guias de fluxo específicos ficam em Skills (carregamento condicional via gatilhos). Isso otimiza o uso de tokens de contexto e garante que o comportamento do Claude seja adequado ao momento.','\n',char(10)),replace('Imagine que você tem um caderno gigante com 400 folhas. Nele estão escritas:\n1) Regras para desenhar (como usar cores, fazer traços retos)\n2) Regras para revisar a lição de casa do amigo\n3) Instruções de como construir um castelo de areia\n4) Passos para arrumar o quarto\n\nVocê percebe que as regras de desenho são usadas SEMPRE que você pega o caderno. Já as outras instruções só são usadas em momentos especiais.\n\nA melhor ideia é:\n- Deixar as REGRAS DE DESENHO na primeira página do caderno (CLAUD.md), porque você olha para elas todo dia.\n- Guardar as outras instruções em envelopes separados com etiquetas: "Revisão de Lição", "Castelo de Areia", "Arrumar Quarto". Você só abre o envelope quando vai fazer aquela tarefa específica.\n\nÉ exatamente isso que a opção D sugere! Manter o que é SEMPRE importante no CLAUDE.md, e colocar o resto em "Skills" (os envelopes) que só ativam quando você fala a palavra mágica, como "fazer deploy" ou "revisar PR".\n\nAs outras opções não são tão boas porque:\n- Opção A: Tirar TUDO da primeira página. Aí você precisa lembrar de abrir envelopes mesmo para as regras de desenho que usa sempre. Chato, né?\n- Opção B: Usar um sistema de "cola" para organizar. Mas mesmo organizando, tudo ainda fica no caderno e você carrega o peso todo para todo lado.\n- Opção C: Colocar regras em pastinhas baseadas no tipo de papel (se é papel quadriculado, sulfite etc.). Mas as instruções de "arrumar o quarto" não dependem do tipo de papel, dependem do que você está FAZENDO.\n\nA resposta certa é a D: o que é universal fica no CLAUDE.md, e o que é específico vira Skill com palavra de ativação.','\n',char(10)));
INSERT INTO cards VALUES('admin','card_1783092984494_rkiq8n203',83,'Geração de Código com Claude Code',replace('Geração de Código com Claude Code\n\nVocê foi designado para reestruturar a aplicação monolítica do seu time em microsserviços. Isso impacta mudanças em dezenas de arquivos e exige decisões sobre fronteiras de serviço e dependências de módulos.\n\nQual abordagem você deve escolher?\n\n[ ] A - Mudar para modo de planejamento para explorar a base, entender dependências e desenhar a abordagem de implementação antes de fazer mudanças.\n[ ] B - Começar em execução direta e mudar para planejamento somente após encontrar complexidade inesperada durante a implementação.\n[ ] C - Começar em execução direta e fazer mudanças incrementais, deixando a implementação revelar fronteiras naturais de serviço.\n[ ] D - Usar execução direta com instruções detalhadas antecipadas que especificam a estrutura de cada serviço.','\n',char(10)),'A - Mudar para modo de planejamento para explorar a base, entender dependências e desenhar a abordagem de implementação antes de fazer mudanças.','["Domain_3::Claude_Code_Configuration_Workflows", "Domain_4::Prompt_Engineering_Structured_Output", "Scenario_2::Code_Generation_Claude_Code"]','New',0,2.5,0,1783092984494,1783725360507,1783203558653,replace('**Tradução para português do Brasil:**\n\n**Geração de Código com Claude Code**\n\nVocê foi designado para reestruturar a aplicação monolítica do seu time em microsserviços. Isso impacta mudanças em dezenas de arquivos e exige decisões sobre fronteiras de serviço e dependências de módulos.\n\nQual abordagem você deve escolher?\n\n[ ] A - Mudar para modo de planejamento para explorar a base, entender dependências e desenhar a abordagem de implementação antes de fazer mudanças.\n[ ] B - Começar em execução direta e mudar para planejamento somente após encontrar complexidade inesperada durante a implementação.\n[ ] C - Começar em execução direta e fazer mudanças incrementais, deixando a implementação revelar fronteiras naturais de serviço.\n[ ] D - Usar execução direta com instruções detalhadas antecipadas que especificam a estrutura de cada serviço.','\n',char(10)),replace('**Explicação para adulto tech lead:**\n\nA alternativa correta é a **A**.\n\nA reestruturação de um monolito para microsserviços é uma das operações mais arriscadas e complexas na engenharia de software. Envolve decisões arquiteturais profundas: identificar bounded contexts, definir contratos de API, estabelecer estratégias de comunicação (síncrona vs. assíncrona), lidar com consistência de dados distribuídos e gerenciar dependências cíclicas. Tentar "codificar primeiro" é uma receita para retrabalho, inconsistências e aumento exponencial da dívida técnica.\n\n**Por que A é correta:**\n- O modo de planejamento permite mapear visualmente a arquitetura atual, identificar acoplamentos ocultos e projetar as fronteiras de serviço com base em princípios como Domain-Driven Design (DDD).\n- Você pode validar hipóteses de desacoplamento antes de tocar em código, reduzindo drasticamente o risco de mudanças que precisam ser desfeitas.\n- Ferramentas como Claude Code em modo planejamento permitem análise estática de dependências, simulação de quebras e documentação da arquitetura-alvo — tudo antes de uma única linha ser alterada.\n\n**Por que B está errada:**\n- "Começar em execução direta e mudar para planejamento somente após encontrar complexidade" é o oposto de uma estratégia prudente. Quando a complexidade aparece, muitas vezes já se investiu tempo e esforço em código que precisará ser refatorado ou descartado. O planejamento deve vir primeiro para evitar esse desperdício.\n\n**Por que C está errada:**\n- "Deixar a implementação revelar fronteiras naturais de serviço" é ingênuo. Fronteiras de microsserviços não emergem naturalmente da codificação incremental — elas exigem análise cuidadosa de domínio, fluxos de dados, propriedade de dados e requisitos não-funcionais. Sem planejamento, você tende a replicar o acoplamento do monolito.\n\n**Por que D está errada:**\n- Especificar detalhadamente a estrutura de cada serviço antes de qualquer análise pode levar a decisões arbitrárias e mal-informadas. Sem explorar a base existente, você não tem visibilidade sobre dependências reais, pontos de integração e restrições técnicas. É planejamento cego, não planejamento informado.','\n',char(10)),replace('Imagine que você tem uma casa bagunçada com um quarto enorme onde tudo está misturado: brinquedos, roupas, livros e material escolar. Agora você quer separar tudo em vários quartos menores e organizados.\n\nA alternativa A diz: "Antes de começar a mudar as coisas, faça um desenho do que tem em cada canto da casa, veja o que está junto com o que, e planeje onde cada coisa vai ficar." Isso é o mais esperto! Se você começar a mexer sem plano, pode colocar o estojo escolar no meio dos brinquedos, ou pior, não ter espaço para tudo.\n\nA alternativa B é como começar a arrumar de qualquer jeito, e só parar para pensar quando vir que não cabe tudo nos lugares. Aí já teria bagunçado mais ainda.\n\nA alternativa C é achar que, só de ir colocando as coisas em cantos diferentes, magicamente vai dar certo. Não vai — você pode acabar com uma separação pior do que antes.\n\nA alternativa D é tentar decidir tudo antes, mas sem olhar o que realmente existe. Você pode planejar um quarto de brinquedos no lugar onde fica a cama, e depois ter que mudar tudo de novo.\n\nEntão, a resposta certa é a **A**: primeiro a gente explora, planeja e desenha, para depois fazer as mudanças com segurança!','\n',char(10)));
INSERT INTO cards VALUES('admin','card_1783092984503_s5vhapcpd',84,'Geração de Código com Claude Code',replace('Geração de Código com Claude Code\n\nSeu time criou uma skill `/analyze-codebase` que faz análise profunda de código — varredura de dependências, contagem de cobertura de testes e métricas de qualidade. Após rodar o comando, membros do time relatam que Claude fica menos responsivo na sessão e perde o contexto da tarefa original.\n\nComo você corrige isso de forma mais efetiva mantendo as capacidades plenas de análise?\n\n[ ] A - Adicionar `context: fork` no frontmatter da skill para rodar a análise em contexto isolado de subagente.\n[ ] B - Adicionar `model: haiku` no frontmatter para usar um modelo mais rápido e barato para análise.\n[ ] C - Dividir a skill em três skills menores, cada uma produzindo menos saída.\n[ ] D - Adicionar instruções à skill para comprimir todos os resultados em um sumário curto antes de exibi-los.','\n',char(10)),'A - Adicionar `context: fork` no frontmatter da skill para rodar a análise em contexto isolado de subagente.','["Domain_3::Claude_Code_Configuration_Workflows", "Domain_5::Context_Management_Reliability", "Scenario_2::Code_Generation_Claude_Code"]','New',0,2.5,0,1783092984503,1783725364856,1783203558653,replace('**Tradução para português do Brasil:**\n\n**Pergunta:** Geração de Código com Claude Code\n\nSeu time criou uma skill `/analyze-codebase` que faz análise profunda de código — varredura de dependências, contagem de cobertura de testes e métricas de qualidade. Após rodar o comando, membros do time relatam que Claude fica menos responsivo na sessão e perde o contexto da tarefa original.\n\nComo você corrige isso de forma mais efetiva mantendo as capacidades plenas de análise?\n\n[ ] A - Adicionar `context: fork` no frontmatter da skill para rodar a análise em contexto isolado de subagente.\n[ ] B - Adicionar `model: haiku` no frontmatter para usar um modelo mais rápido e barato para análise.\n[ ] C - Dividir a skill em três skills menores, cada uma produzindo menos saída.\n[ ] D - Adicionar instruções à skill para comprimir todos os resultados em um sumário curto antes de exibi-los.','\n',char(10)),replace('**Explicação para um adulto tech lead:**\n\nO problema relatado é que, após executar a skill `/analyze-codebase`, o Claude se torna menos responsivo e perde o contexto da tarefa original. Isso acontece porque a análise profunda de código (varredura de dependências, cobertura de testes, métricas) gera uma grande quantidade de tokens de saída que consumem a janela de contexto disponível. Como o Claude Code opera com um limite de contexto finito, uma única skill que produz muita saída pode "entupir" o contexto, fazendo com que informações anteriores (como o objetivo original da sessão) sejam perdidas ou fiquem inacessíveis.\n\nVamos analisar cada alternativa:\n\n**Alternativa A (correta):** `context: fork` é um recurso do Claude Code que permite que a skill seja executada em um subagente com contexto isolado. Isso significa que a análise pesada roda em uma "bolha" separada, sem contaminar o contexto principal da sessão. O subagente tem seu próprio contexto e, ao finalizar, retorna apenas um resumo ou resultado para o contexto principal. Dessa forma, a sessão original mantém sua capacidade de resposta e o contexto da tarefa original é preservado. É a solução mais efetiva porque resolve a causa raiz (consumo excessivo de contexto) sem sacrificar as capacidades plenas de análise.\n\n**Alternativa B (incorreta):** Trocar para o modelo Haiku (mais rápido e barato) não resolve o problema de consumo de contexto. O Haiku também tem limites de contexto e, mesmo sendo mais rápido, ainda pode produzir uma saída volumosa que sobrecarrega a janela de contexto. Além disso, para análise profunda de código, modelos mais leves podem não ter a mesma capacidade de raciocínio e precisão, sacrificando a qualidade da análise.\n\n**Alternativa C (incorreta):** Dividir a skill em três skills menores apenas distribui o problema, não o resolve. Cada skill individual ainda pode produzir saída significativa, e rodar três skills sequencialmente pode até piorar a situação, pois o usuário precisaria executar múltiplos comandos, e o contexto acumulado das três execuções ainda consumiria a janela de contexto. Além disso, isso prejudica a experiência do usuário ao fragmentar uma operação que deveria ser coesa.\n\n**Alternativa D (incorreta):** Comprimir os resultados em um sumário curto ajuda a mitigar o problema, mas não é a solução mais efetiva. A compressão manual de resultados pode perder informações importantes da análise, e a responsabilidade de resumir fica a cargo do próprio Claude, que ainda processará todos os dados no contexto antes de resumir. Além disso, não há isolamento de contexto, então a janela principal ainda é impactada durante o processamento. É um paliativo, não uma correção robusta.\n\n**Conclusão:** A alternativa A é a única que ataca diretamente a causa raiz — o excesso de consumo de contexto — através do isolamento provido por `context: fork`, mantendo intactas as capacidades de análise.','\n',char(10)),replace('Imagine que você está desenhando em uma folha de papel, mas tem um espaço limitado para desenhar. De repente, alguém te pede para fazer uma tarefa muito grande que ocupa quase toda a folha. Agora, você não tem mais espaço para continuar seu desenho original, e até esquece o que estava fazendo antes!\n\nÉ isso que acontece com o Claude quando a skill de análise de código é executada: ela gera tanta informação que "enche" a memória dele, e ele esquece o que estava fazendo antes.\n\nA alternativa A resolve isso de um jeito bem inteligente: é como se o Claude desse uma "folha separada" para fazer essa tarefa grande. Ele pega uma folha nova, faz a análise inteira lá, e depois volta para a folha original com apenas um resuminho do que descobriu. Assim, a folha original não fica cheia, e ele não esquece o que estava fazendo!\n\nAs outras opções não funcionam tão bem:\n- Trocar para um modelo mais rápido (B) é como trocar de lápis por uma caneta que escreve mais rápido — ainda vai ocupar o mesmo espaço.\n- Dividir em três partes (C) é como picotar a tarefa grande em três pedaços médios — ainda vai ocupar espaço, e ainda dá mais trabalho.\n- Fazer um resumo (D) ajuda um pouco, mas ele ainda precisa encher a folha para depois apagar — o estrago já foi feito.\n\nA melhor solução é mesmo dar uma folha separada para a tarefa grande: o `context: fork`!','\n',char(10)));
INSERT INTO cards VALUES('admin','card_1783092984512_cfbiw770x',85,'Geração de Código com Claude Code',replace('Geração de Código com Claude Code\n\nSeu time usa uma skill `/commit` em `.claude/skills/commit/SKILL.md`. Um dev quer customizá-la para seu fluxo pessoal (formato diferente de commit message, checagens extras) sem afetar colegas.\n\nO que você recomenda?\n\n[ ] A - Criar uma versão pessoal sob `~/.claude/skills/` com um nome diferente, ex.: `/my-commit`.\n[ ] B - Adicionar lógica condicional baseada em username no frontmatter da skill do projeto.\n[ ] C - Criar uma versão pessoal em `~/.claude/skills/commit/SKILL.md` com o mesmo nome.\n[ ] D - Definir `override: true` no frontmatter da skill pessoal para priorizá-la sobre a versão do projeto.','\n',char(10)),'A - Criar uma versão pessoal sob `~/.claude/skills/` com um nome diferente, ex.: `/my-commit`.','["Domain_3::Claude_Code_Configuration_Workflows", "Scenario_2::Code_Generation_Claude_Code"]','New',0,2.5,0,1783092984512,1783725368257,1783203558653,replace('**Tradução para pt-BR:**\n\nGeração de Código com Claude Code\n\nSeu time usa uma skill `/commit` em `.claude/skills/commit/SKILL.md`. Um desenvolvedor quer customizá-la para seu fluxo pessoal (formato diferente de mensagem de commit, checagens extras) sem afetar colegas.\n\nO que você recomenda?\n\n[ ] A - Criar uma versão pessoal em `~/.claude/skills/` com um nome diferente, ex.: `/my-commit`.\n[ ] B - Adicionar lógica condicional baseada em nome de usuário no frontmatter da skill do projeto.\n[ ] C - Criar uma versão pessoal em `~/.claude/skills/commit/SKILL.md` com o mesmo nome.\n[ ] D - Definir `override: true` no frontmatter da skill pessoal para priorizá-la sobre a versão do projeto.','\n',char(10)),replace('**Explicação para adulto (tech lead):**\n\n**Resposta correta: Alternativa A**\n\nA alternativa A é a abordagem correta por diversos motivos:\n\n1. **Isolamento total**: Criar uma skill com nome diferente (`/my-commit` em vez de `/commit`) garante que não haja conflito de nomes entre a skill pessoal e a skill do projeto. O desenvolvedor invoca `/my-commit` explicitamente quando quer usar sua versão customizada, e `/commit` quando quer usar a versão compartilhada do time.\n\n2. **Mecanismo de resolução de skills do Claude Code**: O Claude Code busca skills em múltiplos diretórios (projeto, home, etc.). Quando duas skills têm o **mesmo nome**, o comportamento de resolução não é trivial — não há um mecanismo oficial de "override" ou "prioridade" documentado como `override: true`. Isso torna as alternativas C e D arriscadas.\n\n3. **Manutenibilidade e clareza**: Ter duas skills com o mesmo nome em locais diferentes é uma bomba-relógio para confusão. Qual versão está sendo usada? Por que meu comando `/commit` se comporta diferente do esperado pelos colegas? Com nomes diferentes, a intenção é explícita.\n\n**Por que as demais alternativas estão erradas:**\n\n**Alternativa B** — Adicionar lógica condicional baseada em username no frontmatter da skill do projeto. O frontmatter de uma skill (YAML) é usado para metadados como descrição, não para lógica condicional de execução. Isso simplesmente não é um mecanismo suportado pelo Claude Code. Seria necessário hackear a skill para interpretar condições dentro do prompt, o que polui a skill compartilhada e quebra o princípio de responsabilidade única.\n\n**Alternativa C** — Criar uma versão pessoal em `~/.claude/skills/commit/SKILL.md` com o mesmo nome. Isso cria um conflito de nomes. O comportamento do Claude Code ao encontrar duas skills com o mesmo nome não é deterministicamente documentado como "a pessoal sobrescreve a do projeto". Pode ocorrer sombreamento imprevisível, execução duplicada ou erro. É arriscado e não escalável.\n\n**Alternativa D** — Definir `override: true`. Não existe tal campo no frontmatter de skills do Claude Code. Isso é uma invenção. O Claude Code não oferece um mecanismo de override declarativo. Mesmo que existisse, seria frágil, pois mudanças na skill original poderiam quebrar a sobrescrita silenciosamente.\n\n**Conclusão**: A abordagem mais limpa, segura e sustentável é criar uma skill com nome diferente no diretório pessoal, deixando a skill original intacta para o resto do time.','\n',char(10)),replace('Imagine que sua turma da escola tem uma regra para escrever "Para Casa" no caderno: todo mundo usa o mesmo formato. Um aluno quer fazer do jeito dele, com desenhos e cores diferentes, mas sem atrapalhar os outros.\n\nA melhor ideia é ele criar um caderno novo com um nome diferente, tipo "Meu Para Casa Especial". Assim, quando ele quiser usar o formato diferente, ele pega o caderno dele. Quando quiser o formato da turma, ele usa o de todo mundo. Ninguém se confunde!\n\nIsso é o que a **alternativa A** faz: cria um comando novo com nome diferente (`/my-commit`) para o desenvolvedor usar só quando quiser.\n\nAs outras opções são ruins:\n- **B**: Seria como tentar escrever duas regras diferentes na mesma página do caderno, uma para cada aluno. Fica confuso e bagunçado.\n- **C**: Seria como dois alunos terem cadernos com o mesmo nome ("Para Casa") guardados em lugares diferentes. Na hora de pegar, ninguém sabe qual é o certo.\n- **D**: Seria como inventar uma regra mágica "este caderno anula o outro" que não existe de verdade na escola. Não funciona.\n\nEntão: nomes diferentes = sem confusão! ✅','\n',char(10)));
INSERT INTO cards VALUES('admin','card_1783092984521_pjr27jub0',86,'Geração de Código com Claude Code',replace('Geração de Código com Claude Code\n\nSeu time usa Claude Code há meses. Recentemente, três devs reportam que Claude segue a orientação "sempre incluir tratamento abrangente de erros", mas um quarto dev recém-chegado diz que Claude não a segue. Os quatro trabalham no mesmo repo e têm código atualizado.\n\nQual a causa mais provável e correção?\n\n[ ] A - A orientação está nos arquivos de nível usuário `~/.claude/CLAUDE.md` dos devs originais, não no `.claude/CLAUDE.md` do projeto. Mover a instrução para o arquivo de nível projeto para que todos os membros recebam.\n[ ] B - O `~/.claude/CLAUDE.md` do novo dev contém instruções conflitantes que sobrescrevem o projeto; ele deve apagar a seção conflitante.\n[ ] C - Claude Code aprende preferências por usuário com o tempo; o novo dev precisa repetir o requisito até Claude "lembrar".\n[ ] D - Claude Code cacheia CLAUDE.md após a primeira leitura; os devs originais usam versões em cache. Todos devem limpar o cache.','\n',char(10)),'A - A orientação está nos arquivos de nível usuário `~/.claude/CLAUDE.md` dos devs originais, não no `.claude/CLAUDE.md` do projeto. Mover a instrução para o arquivo de nível projeto para que todos os membros recebam.','["Domain_3::Claude_Code_Configuration_Workflows", "Domain_5::Context_Management_Reliability", "Scenario_2::Code_Generation_Claude_Code"]','New',0,2.5,0,1783092984521,1783725372807,1783203558653,replace('**Tradução para português do Brasil:**\n\n**Pergunta:**\nSeu time usa Claude Code há meses. Recentemente, três devs reportam que Claude segue a orientação "sempre incluir tratamento abrangente de erros", mas um quarto dev recém-chegado diz que Claude não a segue. Os quatro trabalham no mesmo repo e têm código atualizado.\n\nQual a causa mais provável e correção?\n\n[ ] A - A orientação está nos arquivos de nível usuário `~/.claude/CLAUDE.md` dos devs originais, não no `.claude/CLAUDE.md` do projeto. Mover a instrução para o arquivo de nível projeto para que todos os membros recebam.\n[ ] B - O `~/.claude/CLAUDE.md` do novo dev contém instruções conflitantes que sobrescrevem o projeto; ele deve apagar a seção conflitante.\n[ ] C - Claude Code aprende preferências por usuário com o tempo; o novo dev precisa repetir o requisito até Claude "lembrar".\n[ ] D - Claude Code cacheia CLAUDE.md após a primeira leitura; os devs originais usam versões em cache. Todos devem limpar o cache.','\n',char(10)),replace('**Explicação para adulto (tech lead):**\n\nA resposta correta é a **alternativa A**.\n\n**Por que A está correta:**\n\nO Claude Code possui uma hierarquia de arquivos de configuração CLAUDE.md. Existem arquivos em nível de **projeto** (`.claude/CLAUDE.md` no repositório) e em nível de **usuário** (`~/.claude/CLAUDE.md` no home directory de cada dev). Quando ambos existem, seus conteúdos são mesclados, mas a precedência é do arquivo de projeto para instruções específicas do projeto, enquanto o arquivo de usuário contém preferências pessoais.\n\nO cenário descrito aponta que os três devs originais inseriram a diretiva "sempre incluir tratamento abrangente de erros" em seus respectivos `~/.claude/CLAUDE.md` (nível usuário). O novo desenvolvedor, por não ter essa instrução em seu arquivo de usuário, não vê o comportamento. Como os quatro estão no mesmo repositório com código atualizado, fica claro que a instrução não está no arquivo de nível projeto (`.claude/CLAUDE.md`). A correção correta é mover a instrução para o arquivo de nível projeto, assim todos os membros do time que executarem Claude Code no contexto daquele repositório receberão automaticamente a orientação, independentemente de seus arquivos pessoais.\n\n**Por que as demais estão erradas:**\n\n- **B**: Embora instruções conflitantes no `~/.claude/CLAUDE.md` do novo dev *pudessem* sobrescrever, a questão não menciona que ele tenha algo conflitante. A causa mais provável é a ausência da instrução no projeto, não a presença de conflito. Assumir conflito sem evidência é um diagnóstico menos parcimonioso.\n\n- **C**: Claude Code não "aprende" preferências por repetição ao longo do tempo como um sistema de machine learning online. Ele segue estritamente as instruções fornecidas nos arquivos CLAUDE.md e no prompt do sistema. Não há mecanismo de "memorização" por repetição de comandos. Instruções devem ser explícitas e persistentes em arquivos de configuração.\n\n- **D**: O cache do CLAUDE.md existe, mas isso não explica por que três devs veem o comportamento e um não, já que todos estariam sujeitos ao mesmo estado de cache se a instrução estivesse no projeto. A limpeza de cache seria uma medida corretiva se houvesse uma versão desatualizada, mas a raiz do problema não é um cache obsoleto, e sim a localização da instrução.','\n',char(10)),replace('Vamos pensar num jogo de videogame onde cada jogador pode criar seu próprio personagem com regras especiais. Três amigos colocaram a regra "sempre use o escudo" no caderno de regras deles, guardado na mochila pessoal de cada um. Um novo amigo entrou no time, mas ninguém colocou essa regra no manual do time inteiro, que fica na estante da sala.\n\nQuando o novo amigo joga, o computador lê o manual da sala (do time) e o caderno pessoal dele. Como a regra do escudo só estava nos cadernos pessoais dos três amigos, o computador não encontra essa instrução para o novo amigo.\n\nA solução? Escrever a regra "sempre incluir tratamento abrangente de erros" no manual do time inteiro (o arquivo `.claude/CLAUDE.md` do projeto). Assim, quando qualquer pessoa do time jogar, o computador vai ler essa regra e todos vão seguir a mesma instrução.\n\nAs outras opções são pistas falsas:\n- A opção B acha que o novo amigo tem uma regra conflitante, mas ele não tem nada disso.\n- A opção C diz que o computador "aprende" com o tempo, mas computador não é bicho de estimação — ele não aprende sozinho, só obedece o que está escrito.\n- A opção D diz que é problema de "cache", que é como uma cópia rápida das regras. Mas se a regra não estava no manual do time, não tem cache que resolva — o problema é que a regra simplesmente não estava lá.','\n',char(10)));
INSERT INTO cards VALUES('admin','card_1783092984529_3xim43vth',87,'Geração de Código com Claude Code',replace('Geração de Código com Claude Code\n\nVocê descobre que incluir 2–3 implementações completas de endpoint como contexto melhora significativamente a consistência ao gerar novos endpoints de API. Porém, esse contexto só é útil ao criar novos endpoints — não ao depurar, revisar código ou outros trabalhos no diretório de API.\n\nQual abordagem de configuração é mais efetiva?\n\n[ ] A - Adicionar exemplos de endpoint e documentação de padrão ao CLAUDE.md do projeto para que estejam sempre disponíveis.\n[ ] B - Referenciar manualmente exemplos de endpoint em cada solicitação de geração copiando código no prompt.\n[ ] C - Configurar regras path-specific em `.claude/rules/api/` que incluam exemplos de endpoint e ativem ao trabalhar no diretório de API.\n[ ] D - Criar uma skill que referencie os exemplos de endpoint e contenha instruções de seguimento de padrão, invocada sob demanda via slash command.','\n',char(10)),'C - Configurar regras path-specific em `.claude/rules/api/` que incluam exemplos de endpoint e ativem ao trabalhar no diretório de API.','["Domain_3::Claude_Code_Configuration_Workflows", "Domain_4::Prompt_Engineering_Structured_Output", "Scenario_2::Code_Generation_Claude_Code"]','New',0,2.5,0,1783092984529,1783725376904,1783203558653,replace('**Tradução para português do Brasil:**\n\nGeração de Código com Claude Code\n\nVocê descobre que incluir 2–3 implementações completas de endpoint como contexto melhora significativamente a consistência ao gerar novos endpoints de API. Porém, esse contexto só é útil ao criar novos endpoints — não ao depurar, revisar código ou outros trabalhos no diretório de API.\n\nQual abordagem de configuração é mais efetiva?\n\n[ ] A - Adicionar exemplos de endpoint e documentação de padrão ao CLAUDE.md do projeto para que estejam sempre disponíveis.\n[ ] B - Referenciar manualmente exemplos de endpoint em cada solicitação de geração copiando código no prompt.\n[ ] C - Configurar regras path-specific em `.claude/rules/api/` que incluam exemplos de endpoint e ativem ao trabalhar no diretório de API.\n[ ] D - Criar uma skill que referencie os exemplos de endpoint e contenha instruções de seguimento de padrão, invocada sob demanda via slash command.','\n',char(10)),replace('**Explicação para adulto (tech lead):**\n\n**Resposta correta: Alternativa C**\n\nA alternativa C é a mais eficaz porque atende precisamente ao requisito descrito no enunciado: o contexto (exemplos de endpoint) é necessário apenas quando se está **criando novos endpoints** no diretório de API, mas não em outras operações como depuração ou revisão de código.\n\nAs regras path-specific (`path-scoped rules`) no diretório `.claude/rules/api/` são ativadas automaticamente quando o Claude Code opera em arquivos dentro do caminho correspondente (no caso, o diretório de API). Isso significa que:\n\n- **Acionamento automático e seletivo**: as regras só são injetadas no contexto quando o trabalho envolve arquivos naquele path específico, evitando poluir o contexto com informações desnecessárias para outras tarefas.\n- **Sem sobrecarga cognitiva**: o desenvolvedor não precisa lembrar de adicionar contexto manualmente, nem copiar código no prompt a cada interação.\n- **Manutenção centralizada**: os exemplos ficam versionados e organizados em um local canônico do projeto.\n\n**Por que as demais alternativas estão incorretas:**\n\n- **Alternativa A (CLAUDE.md)**: Embora o CLAUDE.md seja útil como arquivo de configuração global, ele é sempre carregado em todas as sessões do Claude Code, independentemente do diretório ou tarefa. Isso adicionaria tokens desnecessários ao contexto ao depurar ou revisar código na API, exatamente o oposto do que o enunciado pede (contexto só útil ao criar endpoints).\n\n- **Alternativa B (cópia manual no prompt)**: Embora funcione, é a abordagem menos eficiente. Ela depende de disciplina manual, é propensa a erros de esquecimento, quebra o fluxo de trabalho e não escala. Além disso, o enunciado pede uma "abordagem de configuração" — copiar código manualmente não é uma configuração, é um workaround.\n\n- **Alternativa D (skill via slash command)**: Skills do Claude Code são acionadas sob demanda via comandos como `/skill criar-endpoint`. Embora úteis para tarefas específicas, elas exigem que o desenvolvedor lembre de invocá-las ativamente. O enunciado não menciona acionamento manual; pelo contrário, a situação descreve um contexto que deve ser ativado **automaticamente** ao trabalhar no diretório de API. A dependência de slash commands adiciona atrito e possibilidade de esquecimento.','\n',char(10)),replace('Imagine que você tem uma caixa de ferramentas com várias coisas legais. Você descobriu que, quando vai criar um desenho novo de um carro, é muito bom ter alguns exemplos de carros prontos do lado para copiar o estilo. Mas esses exemplos atrapalham quando você está só colorindo ou consertando um desenho velho.\n\nA alternativa C é a melhor porque você coloca esses exemplos de carro dentro de uma pasta chamada "desenhos-de-carros". Assim, **só quando você abrir essa pasta** os exemplos aparecem na sua mesa. Quando você vai fazer outra coisa, como arrumar um desenho de árvore, os exemplos de carro não ficam atrapalhando.\n\nAs outras opções não são tão boas:\n- A: Colocar os exemplos na parede do quarto (CLAUDE.md) — eles ficam sempre à vista, mesmo quando você não precisa.\n- B: Ter que ir buscar os exemplos na gaveta toda vez que for desenhar (copiar manualmente) — dá trabalho e você pode esquecer.\n- D: Colocar os exemplos dentro de um armário com um botão mágico (skill) que você precisa apertar — funciona, mas você precisa lembrar de apertar o botão, senão os exemplos não aparecem.','\n',char(10)));
INSERT INTO cards VALUES('admin','card_1783092984538_wyly053pq',88,'Geração de Código com Claude Code',replace('Geração de Código com Claude Code\n\nSeu time criou uma skill `/migration` que gera arquivos de migração de banco. Recebe o nome da migração via `$ARGUMENTS`. Em produção você observa três problemas: (1) devs frequentemente rodam a skill sem argumentos, causando arquivos mal nomeados, (2) a skill às vezes usa detalhes de schema de conversas anteriores não relacionadas, e (3) um dev rodou acidentalmente cleanup destrutivo de teste quando a skill tinha acesso amplo a ferramentas.\n\nQual abordagem de configuração corrige todos os três problemas?\n\n[ ] A - Usar parâmetros posicionais `$1` e `$2` em vez de `$ARGUMENTS` para forçar entradas específicas, incluir referências explícitas a schema via sintaxe `@` para controle de contexto, e adicionar uma descrição no frontmatter alertando sobre operações destrutivas.\n[ ] B - Adicionar `argument-hint` no frontmatter para pedir parâmetros obrigatórios, usar `context: fork` para isolar a execução, e restringir `allowed-tools` a operações de escrita de arquivo.\n[ ] C - Dividir em `/migration-create` e `/migration-apply`, adicionar instruções de validação para pedir o nome da migração se faltar e usar escopos de `allowed-tools` diferentes para cada.\n[ ] D - Adicionar instruções de validação no SKILL.md para garantir que `$ARGUMENTS` seja um nome válido, adicionar prompts para ignorar contexto de conversas anteriores e listar operações proibidas.','\n',char(10)),'[ ] B - Adicionar `argument-hint` no frontmatter para pedir parâmetros obrigatórios, usar `context: fork` para isolar a execução, e restringir `allowed-tools` a operações de escrita de arquivo.','["Domain_3::Claude_Code_Configuration_Workflows", "Domain_5::Context_Management_Reliability", "Domain_2::Tool_Design_MCP_Integration", "Scenario_2::Code_Generation_Claude_Code"]','New',0,2.5,0,1783092984538,1783725380539,1783203558653,replace('**Tradução para Português do Brasil:**\n\nGeração de Código com Claude Code\n\nSeu time criou uma skill `/migration` que gera arquivos de migração de banco. Recebe o nome da migração via `$ARGUMENTS`. Em produção você observa três problemas: (1) devs frequentemente rodam a skill sem argumentos, causando arquivos mal nomeados, (2) a skill às vezes usa detalhes de schema de conversas anteriores não relacionadas, e (3) um dev rodou acidentalmente cleanup destrutivo de teste quando a skill tinha acesso amplo a ferramentas.\n\nQual abordagem de configuração corrige todos os três problemas?\n\n[ ] A - Usar parâmetros posicionais `$1` e `$2` em vez de `$ARGUMENTS` para forçar entradas específicas, incluir referências explícitas a schema via sintaxe `@` para controle de contexto, e adicionar uma descrição no frontmatter alertando sobre operações destrutivas.\n[ ] B - Adicionar `argument-hint` no frontmatter para pedir parâmetros obrigatórios, usar `context: fork` para isolar a execução, e restringir `allowed-tools` a operações de escrita de arquivo.\n[ ] C - Dividir em `/migration-create` e `/migration-apply`, adicionar instruções de validação para pedir o nome da migração se faltar e usar escopos de `allowed-tools` diferentes para cada.\n[ ] D - Adicionar instruções de validação no SKILL.md para garantir que `$ARGUMENTS` seja um nome válido, adicionar prompts para ignorar contexto de conversas anteriores e listar operações proibidas.','\n',char(10)),replace('**Explicação para o adulto (tech lead):**\n\nVamos mapear os três problemas e ver como cada alternativa os endereça:\n\n| Problema | Descrição |\n|----------|-----------|\n| (1) Skill sem argumentos → arquivos mal nomeados | Falta de validação/obrigatoriedade do parâmetro |\n| (2) Skill usa schema de conversas anteriores | Contaminação de contexto entre execuções |\n| (3) Acesso a ferramentas destrutivas | Permissões excessivas da skill |\n\n**Alternativa A — Falha nos problemas (2) e (3):**\n- Usar `$1` e `$2` não resolve o problema de argumentos ausentes (ainda podem ser omitidos, só muda a forma de acesso).\n- Sintaxe `@` para schema não é um mecanismo real de isolamento de contexto em skills do Claude Code.\n- Descrição no frontmatter alertando sobre operações destrutivas não é um controle efetivo — é apenas documentação, não uma restrição.\n\n**Alternativa B — Corrige todos os três:**\n- `argument-hint` no frontmatter permite declarar argumentos obrigatórios, e o Claude Code vai solicitar o parâmetro se não for fornecido → resolve (1).\n- `context: fork` isola a execução em um contexto sem histórico da conversa → resolve (2).\n- `allowed-tools` restrito a operações de escrita de arquivo (como `Write`, `Edit`) impede acesso a ferramentas de execução de comandos ou operações destrutivas → resolve (3).\n\nEsta é a única alternativa que oferece mecanismos nativos e efetivos da plataforma Claude Code para cada problema.\n\n**Alternativa C — Parcial, mas não resolve completamente:**\n- Dividir em duas skills ajuda na organização, mas não resolve o problema de argumentos ausentes por si só — precisaria de algo como `argument-hint`.\n- Instruções de validação em texto são frágeis comparadas a mecanismos declarativos.\n- `allowed-tools` diferentes é um bom ponto, mas a descrição não especifica restrição a escrita de arquivo, deixando brecha.\n- Mais importante: não endereça o problema (2) de contaminação de contexto.\n\n**Alternativa D — Abordagem frágil e não resolutiva:**\n- Instruções de validação em SKILL.md são apenas texto — o modelo pode ignorá-las.\n- "Adicionar prompts para ignorar contexto" é uma instrução, não um isolamento real como `context: fork`.\n- "Listar operações proibidas" novamente é documentação, não um controle de acesso efetivo.\n- Nenhum dos três pontos usa mecanismos declarativos da plataforma, apenas orientações textuais que o modelo pode ou não seguir.\n\n**Conclusão técnica:** A alternativa **B** é a resposta correta porque cada um dos seus três componentes ataca diretamente um dos problemas usando os mecanismos apropriados do Claude Code: `argument-hint` para validação de entrada, `context: fork` para isolamento de contexto, e `allowed-tools` para principio de menor privilégio.','\n',char(10)),replace('Imagina que você criou um robô que ajuda a criar tarefas de casa. Mas ele tem três problemas:\n\n1. As crianças pedem tarefas sem dizer qual matéria, aí o robô cria papéis bagunçados.\n2. O robô às vezes copia ideias de conversas antigas com outras crianças.\n3. Uma criança sem querer pediu para o robô apagar tudo, porque o robô tinha poder para fazer qualquer coisa.\n\nAgora, qual das opções resolve tudo de uma vez?\n\n**Opção A:** Pedir para a criança falar usando palavras específicas, colocar um aviso "não copie conversas antigas" e escrever "cuidado para não apagar" na parede. Só que isso não impede ninguém de esquecer de falar a matéria, e o robô ainda pode copiar conversas velhas ou apagar tudo se a criança ignorar o aviso.\n\n**Opção B — A resposta certa!** Colocar um campo obrigatório "qual matéria?" que o robô pergunta antes de criar a tarefa, fazer o robô esquecer completamente conversas antigas (como se você desse um "reset" na memória dele), e tirar o poder de apagar coisas, deixando ele só escrever arquivos novos. Assim, nenhum dos três problemas acontece!\n\n**Opção C:** Criar dois robôs separados. Mas eles ainda podem copiar conversas antigas, e se a criança esquecer de dizer a matéria, o robô pode inventar.\n\n**Opção D:** Escrever instruções bonitas tipo "não esqueça de perguntar a matéria" e "ignore conversas antigas" em um manual. Mas o robô pode simplesmente ignorar o manual e fazer tudo errado do mesmo jeito.\n\nEntão a opção **B** é a melhor porque ela *muda as regras do jogo*: obriga a informação, limpa a memória e tira os poderes perigosos. Não depende de ninguém lembrar de seguir instruções!','\n',char(10)));
INSERT INTO cards VALUES('admin','card_1783092984546_wc5rpczm9',89,'Geração de Código com Claude Code',replace('Geração de Código com Claude Code\n\nSua base contém áreas com convenções de código diferentes: componentes React usam estilo funcional com hooks, handlers de API usam async/await com tratamento específico de erros e modelos de banco seguem o padrão repository. Arquivos de teste estão distribuídos pela base ao lado do código sob teste (ex.: `Button.test.tsx` ao lado de `Button.tsx`), e você quer que todos os testes sigam as mesmas convenções independentemente da localização.\n\nQual é a forma mais suportada de garantir que Claude aplique automaticamente as convenções corretas ao gerar código?\n\n[ ] A - Colocar todas as convenções no CLAUDE.md raiz sob cabeçalhos por área e contar com Claude para inferir qual seção se aplica.\n[ ] B - Criar skills em `.claude/skills/` para cada tipo de código, embutindo convenções em cada SKILL.md.\n[ ] C - Colocar um arquivo CLAUDE.md separado em cada subdiretório com convenções para aquela área.\n[ ] D - Criar arquivos de regra em `.claude/rules/` com frontmatter YAML especificando padrões glob para aplicar convenções condicionalmente baseadas em paths.','\n',char(10)),'[ ] D - Criar arquivos de regra em `.claude/rules/` com frontmatter YAML especificando padrões glob para aplicar convenções condicionalmente baseadas em paths.','["Domain_3::Claude_Code_Configuration_Workflows", "Domain_4::Prompt_Engineering_Structured_Output", "Scenario_2::Code_Generation_Claude_Code"]','New',0,2.5,0,1783092984546,1783725384232,1783203558653,replace('**Tradução para português do Brasil:**\n\nGeração de Código com Claude Code\n\nSua base contém áreas com convenções de código diferentes: componentes React usam estilo funcional com hooks, handlers de API usam async/await com tratamento específico de erros e modelos de banco seguem o padrão repository. Arquivos de teste estão distribuídos pela base ao lado do código sob teste (ex.: `Button.test.tsx` ao lado de `Button.tsx`), e você quer que todos os testes sigam as mesmas convenções independentemente da localização.\n\nQual é a forma mais suportada de garantir que Claude aplique automaticamente as convenções corretas ao gerar código?\n\n[ ] A - Colocar todas as convenções no CLAUDE.md raiz sob cabeçalhos por área e contar com Claude para inferir qual seção se aplica.\n[ ] B - Criar skills em `.claude/skills/` para cada tipo de código, embutindo convenções em cada SKILL.md.\n[ ] C - Colocar um arquivo CLAUDE.md separado em cada subdiretório com convenções para aquela área.\n[ ] D - Criar arquivos de regra em `.claude/rules/` com frontmatter YAML especificando padrões glob para aplicar convenções condicionalmente baseadas em paths.','\n',char(10)),replace('**Explicação para adulto tech lead:**\n\nA alternativa **D** é a correta.\n\nO Claude Code suporta nativamente o diretório `.claude/rules/`, onde cada arquivo pode conter frontmatter YAML com campos como `patterns` (glob patterns) que definem a quais arquivos aquela regra se aplica. Isso permite aplicar convenções específicas de forma **condicional e automática** baseada no caminho do arquivo sendo gerado ou modificado.\n\nPor exemplo, você poderia ter:\n\n- `.claude/rules/react-components.md` com `patterns: ["**/*.tsx"]` contendo convenções de componentes funcionais com hooks.\n- `.claude/rules/api-handlers.md` com `patterns: ["**/api/**/*.ts"]` contendo convenções de async/await e tratamento de erros.\n- `.claude/rules/repository.md` com `patterns: ["**/repositories/**/*.ts"]` contendo o padrão repository para modelos de banco.\n- `.claude/rules/tests.md` com `patterns: ["**/*.test.*", "**/*.spec.*"]` contendo convenções globalmente consistentes para testes.\n\nIsso resolve diretamente o problema: as regras são aplicadas automaticamente com base no path do arquivo alvo, garantindo que:\n1) Convenções específicas de área sejam usadas (ex.: handlers de API seguem async/await).\n2) Convenções transversais sejam aplicadas de forma consistente (ex.: testes seguem o mesmo padrão independente da localização).\n\n**Por que as demais alternativas estão incorretas?**\n\n- **A**: Colocar tudo em um único `CLAUDE.md` raiz sob cabeçalhos manuais depende da capacidade de inferência do Claude para decidir qual seção usar. Não há um mecanismo formal de path-matching, então o modelo pode aplicar a convenção errada ou ignorar seções, especialmente em projetos grandes com muitas áreas. É frágil e não escalável.\n\n- **B**: Skills em `.claude/skills/` são perfis de habilidades que Claude pode usar, mas não têm um mecanismo nativo de aplicação automática baseada em path patterns. Skills dependem de ativação explícita por contexto (ex.: menção no prompt), e não de detecção automática do tipo de arquivo alvo. Não é a abordagem mais suportada para esse cenário.\n\n- **C**: `CLAUDE.md` por subdiretório é uma abordagem mais localizada que a A, mas ainda depende de Claude aplicar o arquivo certo com base no diretório atual. Não há um sistema de glob patterns ou regras condicionais explícitas. Além disso, não resolve bem o caso transversal dos testes — você teria que duplicar as mesmas convenções de teste em cada subdiretório, gerando manutenção redundante e risco de inconsistência.','\n',char(10)),replace('Imagine que você tem uma caixa de ferramentas muito organizada. Para desenhar um carro, você precisa de lápis de cor. Para construir uma torre, você precisa de blocos de montar. E para fazer um avião de papel, você precisa de papel sulfite.\n\nAgora, você pediu para um robô ajudante (o Claude) criar essas coisas para você. Mas o robô precisa saber qual ferramenta usar em cada hora.\n\nA **alternativa D** é como dar ao robô um manual com regras claras, tipo:\n- "Se for desenhar, use lápis de cor."\n- "Se for construir, use blocos."\n- "Se for fazer um avião, use papel."\n\nE o mais legal: o robô **olha para o que você está fazendo** e escolhe a regra certa automaticamente! Se você pedir para ele criar um desenho, ele já pega os lápis de cor sozinho. E se tiver uma regra que vale para tudo (como "sempre use cola para juntar coisas"), ele também segue essa.\n\nAs outras opções são piores porque:\n- **A**: É como escrever TODAS as instruções numa folha só e torcer para o robô adivinhar qual parte usar. Ele pode se confundir.\n- **B**: É como dar ao robô várias caixas de ferramentas, mas ele só abre a caixa certa se você mandar explicitamente. Não é automático.\n- **C**: É como colocar um manual diferente em cada cômodo da casa. Funciona, mas se você quiser uma regra que vale para a casa toda (como "não correr"), você precisa escrever essa regra em todos os manuais. Dá muito trabalho e pode esquecer algum.\n\nA opção D é a mais esperta porque o robô descobre sozinho qual regra usar, sem você precisar ficar lembrando ele toda hora!','\n',char(10)));
INSERT INTO cards VALUES('admin','card_1783092984555_l92knot29',90,'Geração de Código com Claude Code',replace('Geração de Código com Claude Code\n\nVocê quer criar um slash command customizado `/review` que rode o checklist padrão de code review do seu time. Ele deve estar disponível para todo dev quando clonar ou atualizar o repositório.\n\nOnde criar o arquivo do comando?\n\n[ ] A - Em `~/.claude/commands/` no diretório home de cada dev.\n[ ] B - No repositório do projeto sob `.claude/commands/`.\n[ ] C - Em `.claude/config.json` como array de comandos.\n[ ] D - No CLAUDE.md raiz do projeto.','\n',char(10)),'B - No repositório do projeto sob `.claude/commands/`.','["Domain_3::Claude_Code_Configuration_Workflows", "Domain_2::Tool_Design_MCP_Integration", "Scenario_2::Code_Generation_Claude_Code"]','New',0,2.5,0,1783092984555,1783725387533,1783203558653,replace('**Tradução:**\n\nVocê quer criar um slash command customizado `/review` que execute o checklist padrão de code review do seu time. Ele deve estar disponível para todo desenvolvedor quando clonar ou atualizar o repositório.\n\nOnde criar o arquivo do comando?\n\n[ ] A - Em `~/.claude/commands/` no diretório home de cada desenvolvedor.\n[ ] B - No repositório do projeto sob `.claude/commands/`.\n[ ] C - Em `.claude/config.json` como array de comandos.\n[ ] D - No `CLAUDE.md` raiz do projeto.','\n',char(10)),replace('**Explicação para Tech Lead:**\n\nA resposta correta é a **alternativa B**.\n\nO Claude Code (antigo Claude CLI) suporta comandos customizados via slash commands (ex: `/review`). Para que um comando fique disponível para **todos os desenvolvedores** do time assim que clonam ou atualizam o repositório, ele precisa estar versionado dentro do próprio repositório. O caminho padrão e documentado para isso é `.claude/commands/`.\n\nVamos analisar cada alternativa:\n\n- **A - `~/.claude/commands/`** (ERRADA): Este diretório está no home do usuário, ou seja, é local e pessoal. Cada dev precisaria criar manualmente o comando em sua própria máquina. Não atende ao requisito de disponibilidade automática para todos ao clonar o repositório.\n\n- **B - `.claude/commands/`** (CORRETA): Este é o local designado pelo Claude Code para comandos customizados compartilhados via repositório. Basta criar um arquivo (ex: `review.md` ou `review.js`) dentro de `.claude/commands/`, versioná-lo no repositório, e todos os devs que clonarem ou derem pull terão o comando `/review` disponível automaticamente.\n\n- **C - `.claude/config.json`** (ERRADA): O `config.json` é um arquivo de configuração do Claude Code, mas não é o local onde se definem slash commands. Ele pode conter outras configurações como modelos, mas comandos customizados são arquivos individuais dentro de `.claude/commands/`.\n\n- **D - `CLAUDE.md`** (ERRADA): O `CLAUDE.md` é um arquivo de contexto/instruções para o Claude dentro do projeto. Ele define como o Claude deve se comportar ou quais padrões seguir, mas **não** é o mecanismo para criar slash commands customizados. Comandos são arquivos executáveis ou markdown na pasta `.claude/commands/`.','\n',char(10)),replace('Imagine que você e seus amigos têm uma "caixa de ferramentas" secreta que todo mundo usa quando trabalha num projeto juntos.\n\nA **resposta certa** é a letra B: guardar o comando dentro da pasta `.claude/commands/` que fica **dentro do próprio projeto**.\n\nPor quê? Pense assim:\n\n- **Opção A** é como cada amigo guardar a ferramenta na sua própria mochila em casa. Quando chega no projeto, ninguém tem a ferramenta — cada um teria que lembrar de trazer a sua. Não funciona se a pessoa é nova no time!\n\n- **Opção B** é como colocar a ferramenta dentro da caixa de brinquedos que todo mundo compartilha quando chega para brincar. Se alguém novo chegar, é só pegar a caixa e pronto — a ferramenta já está lá dentro. Perfeito!\n\n- **Opção C** é como tentar escrever a receita da ferramenta no manual de instruções da caixa de brinquedos. O manual não serve para guardar ferramentas, só para explicar como usar as coisas.\n\n- **Opção D** é como escrever a receita num bilhete colado na tampa da caixa. Pode até ajudar a lembrar o que fazer, mas não é o lugar onde a ferramenta realmente fica guardada para ser usada.\n\nEntão, para que todo mundo do time tenha o comando `/review` automaticamente ao pegar o projeto, a gente coloca ele em `.claude/commands/` dentro do repositório. 😊','\n',char(10)));
INSERT INTO cards VALUES('admin','card_1783092984575_omvsskbwt',91,'Geração de Código com Claude Code',replace('Geração de Código com Claude Code\n\nO CLAUDE.md do seu time cresceu além de 500 linhas misturando convenções TypeScript, orientação de testes, padrões de API e procedimentos de deploy. Devs têm dificuldade de localizar e atualizar as seções certas.\n\nQual abordagem o Claude Code suporta para organizar instruções de nível projeto em módulos tópicos focados?\n\n[ ] A - Definir um `.claude/config.yaml` mapeando padrões de arquivo a seções específicas dentro do CLAUDE.md.\n[ ] B - Criar arquivos Markdown separados em `.claude/rules/`, cada um cobrindo um tópico (ex.: `testing.md`, `api-conventions.md`).\n[ ] C - Dividir instruções em arquivos README.md em subdiretórios relevantes que Claude carrega automaticamente como instruções.\n[ ] D - Criar múltiplos arquivos chamados CLAUDE.md em níveis diferentes da árvore de diretórios, cada um sobrescrevendo instruções pai.','\n',char(10)),'B - Criar arquivos Markdown separados em `.claude/rules/`, cada um cobrindo um tópico (ex.: `testing.md`, `api-conventions.md`).','["Domain_3::Claude_Code_Configuration_Workflows", "Scenario_2::Code_Generation_Claude_Code"]','New',0,2.5,0,1783092984575,1783725391204,1783203558653,replace('**Tradução para português do Brasil:**\n\nGeração de Código com Claude Code\n\nO CLAUDE.md do seu time cresceu além de 500 linhas misturando convenções TypeScript, orientação de testes, padrões de API e procedimentos de deploy. Devs têm dificuldade de localizar e atualizar as seções certas.\n\nQual abordagem o Claude Code suporta para organizar instruções de nível projeto em módulos tópicos focados?\n\n[ ] A - Definir um `.claude/config.yaml` mapeando padrões de arquivo a seções específicas dentro do CLAUDE.md.\n[ ] B - Criar arquivos Markdown separados em `.claude/rules/`, cada um cobrindo um tópico (ex.: `testing.md`, `api-conventions.md`).\n[ ] C - Dividir instruções em arquivos README.md em subdiretórios relevantes que Claude carrega automaticamente como instruções.\n[ ] D - Criar múltiplos arquivos chamados CLAUDE.md em níveis diferentes da árvore de diretórios, cada um sobrescrevendo instruções pai.','\n',char(10)),replace('**Explicação para adulto tech lead:**\n\nA alternativa **B** está correta pois esta é a funcionalidade nativa que o Claude Code oferece para modularização de instruções de projeto. O mecanismo de `regras` no diretório `.claude/rules/` foi projetado exatamente para resolver o problema descrito: evitar um `CLAUDE.md` monolítico e difícil de manter. Cada arquivo Markdown dentro dessa pasta representa um módulo de instrução focado em um tópico específico, e o Claude Code os carrega e aplica automaticamente como se fossem parte das instruções do projeto.\n\nVamos analisar por que as demais alternativas estão incorretas:\n\n- **A**: Incorreta. O Claude Code não suporta um arquivo `.claude/config.yaml` para mapear padrões de arquivo a seções do `CLAUDE.md`. Não existe esse mecanismo de configuração ou roteamento de seções.\n\n- **C**: Incorreta. Embora o Claude Code possa ler arquivos `README.md` para entender o contexto do projeto, ele não os trata automaticamente como instruções de comportamento ou regras de projeto. Eles são fonte de documentação, não de instruções vinculantes para o comportamento do Claude.\n\n- **D**: Incorreta. O Claude Code não suporta herança ou sobrescrita de instruções através de múltiplos arquivos `CLAUDE.md` em diferentes diretórios. Existe apenas um único arquivo `CLAUDE.md` reconhecido como instrução central do projeto (na raiz). Múltiplos arquivos com esse nome não são processados como uma cadeia hierárquica de instruções.\n\nPortanto, a abordagem correta e suportada é a criação de arquivos Markdown modulares dentro de `.claude/rules/`, que é o mecanismo oficial do Claude Code para organizar instruções por tópico.','\n',char(10)),replace('Imagine que você tem um caderno de regras para fazer seu dever de casa. Se você escrever tudo num caderno só bem grandão (mais de 500 linhas!), vai ser difícil achar a parte de "como fazer contas de matemática" ou a parte "como escrever uma redação".\n\nO que o Claude Code sugere é parecido com pegar aquele cadernão e dividir em vários caderninhos menores, cada um com um assunto só. Um caderninho só para "regras de matemática", outro só para "regras de português", etc.\n\nA alternativa **B** fala exatamente isso: criar arquivos separados (como "testes.md", "convenções-api.md") dentro de uma pastinha chamada `.claude/rules/`. Cada arquivo é como um desses caderninhos, e o Claude sabe que deve ler todos eles para saber as regras do projeto.\n\nAs outras respostas não funcionam porque:\n- **A**: É como tentar fazer um mapa dizendo onde cada matéria está no cadernão — o Claude não entende esse mapa.\n- **C**: É como se você escrevesse as regras nos livros didáticos. O Claude lê os livros para entender a matéria, mas não como regras a seguir.\n- **D**: É como ter vários cadernos com o mesmo nome "CLAUDE.md" e esperar que o Claude saiba qual vale mais. Ele não faz isso, só usa um caderno principal.','\n',char(10)));
INSERT INTO cards VALUES('admin','card_1783092984584_8xdhhscdk',92,'Geração de Código com Claude Code',replace('Geração de Código com Claude Code\n\nVocê cria uma skill customizada `/explore-alternatives` que seu time usa para fazer brainstorming e avaliar abordagens de implementação antes de escolher uma. Devs reportam que após rodar a skill, respostas subsequentes do Claude são influenciadas pela discussão de alternativas — às vezes referenciando abordagens rejeitadas ou retendo contexto de exploração que interfere na implementação real.\n\nComo configurar essa skill de forma mais efetiva?\n\n[ ] A - Usar o prefixo `!` na skill para rodar lógica de exploração como subprocesso bash.\n[ ] B - Adicionar `context: fork` no frontmatter da skill.\n[ ] C - Dividir em duas skills — `/explore-start` e `/explore-end` — para marcar fronteiras quando o contexto de exploração deve ser descartado.\n[ ] D - Criar a skill em `~/.claude/skills/` em vez de `.claude/skills/`.','\n',char(10)),'B - Adicionar `context: fork` no frontmatter da skill.','["Domain_3::Claude_Code_Configuration_Workflows", "Domain_5::Context_Management_Reliability", "Scenario_2::Code_Generation_Claude_Code"]','New',0,2.5,0,1783092984584,1783725394845,1783203558653,replace('**Tradução da Pergunta e Alternativas:**\n\nGeração de Código com Claude Code\n\nVocê cria uma skill customizada `/explore-alternatives` que seu time usa para fazer brainstorming e avaliar abordagens de implementação antes de escolher uma. Devs reportam que após rodar a skill, respostas subsequentes do Claude são influenciadas pela discussão de alternativas — às vezes referenciando abordagens rejeitadas ou retendo contexto de exploração que interfere na implementação real.\n\nComo configurar essa skill de forma mais efetiva?\n\n[ ] A - Usar o prefixo `!` na skill para rodar lógica de exploração como subprocesso bash.\n[ ] B - Adicionar `context: fork` no frontmatter da skill.\n[ ] C - Dividir em duas skills — `/explore-start` e `/explore-end` — para marcar fronteiras quando o contexto de exploração deve ser descartado.\n[ ] D - Criar a skill em `~/.claude/skills/` em vez de `.claude/skills/`.','\n',char(10)),replace('**Explicação para Adulto Tech Lead:**\n\nO problema central é que skills customizadas em ferramentas como Claude Code (antigo Terminal) executam dentro da mesma sessão do agente. Quando uma skill realiza uma tarefa exploratória — como discutir alternativas de implementação — todo o raciocínio, prós/contras e caminhos rejeitados permanecem no contexto (janela de atenção) do modelo. Isso contamina prompts futuros, fazendo o modelo referenciar abordagens descartadas ou "vazar" contexto de exploração para a implementação real.\n\nA alternativa correta é a **B - Adicionar `context: fork` no frontmatter da skill**.\n\nExplicação detalhada:\n\n**Por que B está correta:**\nO frontmatter de uma skill no Claude Code suporta a diretiva `context: fork`. Quando ativada, a skill executa em um contexto bifurcado (forked). Isso significa que o Claude cria um subcontexto isolado apenas para aquela skill. Qualquer alteração de estado, histórico de raciocínio ou decisões exploratórias feitas dentro da skill permanecem contidos nesse fork. Ao finalizar a skill, o contexto original (anterior à skill) é restaurado, descartando todo o "lixo cognitivo" gerado pela exploração. É o equivalente a um sandbox de contexto.\n\n**Por que A está errada:**\nO prefixo `!` no Claude Code indica que o conteúdo da skill deve ser executado como um comando shell/bash diretamente, não como uma instrução para o modelo. Isso força a skill a rodar como subprocesso bash, o que não ajuda em nada com o gerenciamento de contexto cognitivo do Claude — pelo contrário, remove a capacidade do modelo de refletir sobre as alternativas, destruindo o propósito da skill de exploração.\n\n**Por que C está errada:**\nDividir em duas skills não resolve o problema de contaminação de contexto, pois ambas executariam na mesma sessão. A segunda skill ainda "herdaria" o contexto exploratório da primeira. Não há um mecanismo nativo de "reset de contexto entre skills" — o Claude Code não suporta delimitação de fronteiras contextuais por convenção de nomeação. A única forma de isolar contexto é via `context: fork`.\n\n**Por que D está errada:**\nA localização da skill (`~/.claude/skills/` vs `.claude/skills/`) define apenas o escopo de disponibilidade (global vs projeto), não o comportamento de execução ou isolamento de contexto. Skills em ambos os locais executam na mesma sessão de agente sem isolamento por padrão. Mover a skill não altera o problema de contaminação de contexto.','\n',char(10)),replace('Imagine que você está desenhando um robô. Primeiro, você faz vários rascunhos de ideias diferentes — braços fortes, pernas de mola, olhos que brilham. Depois de escolher o melhor design, você começa a desenhar o robô de verdade.\n\nO problema é que os risquinhos dos rascunhos (ideias descartadas) ainda aparecem no papel novo, bagunçando o desenho final.\n\nA alternativa B é como pegar uma folha nova em branco para fazer seus rascunhos. Quando você termina de explorar ideias, guarda essa folha separada e volta para sua folha original limpinha. Assim, os rabiscos dos rascunhos não atrapalham o desenho final do robô!\n\nAs outras alternativas são:\n- A: É como jogar seus lápis no lixo e usar só comandos de voz — não dá para desenhar direito.\n- C: É como tentar usar um apagador mágico que não funciona direito — os rabiscos ainda aparecem.\n- D: É como guardar seus desenhos em uma pasta diferente — o problema não é onde você guarda, é que os rabiscos continuam no mesmo papel.','\n',char(10)));
INSERT INTO cards VALUES('admin','card_1783092984593_uyhkipaw7',93,'Geração de Código com Claude Code',replace('Geração de Código com Claude Code\n\nSeu time quer adicionar um servidor MCP do GitHub para buscar PRs e checar status de CI via Claude Code. Cada um dos seis devs tem seu próprio token pessoal de acesso ao GitHub. Você quer ferramental consistente em todo o time sem commitar credenciais no controle de versão.\n\nQual abordagem de configuração é mais efetiva?\n\n[ ] A - Que cada dev adicione o servidor em escopo de usuário via `claude mcp add --scope user`.\n[ ] B - Criar um wrapper de servidor MCP que leia tokens de um arquivo `.env` e proxie chamadas à API do GitHub, depois adicionar o wrapper ao `.mcp.json` do projeto.\n[ ] C - Adicionar o servidor ao `.mcp.json` do projeto usando substituição de variável de ambiente (`${GITHUB_TOKEN}`) para auth e documentar a variável necessária no README.\n[ ] D - Configurar o servidor no escopo de projeto com token placeholder, depois pedir aos devs que sobrescrevam no config local.','\n',char(10)),'C - Adicionar o servidor ao `.mcp.json` do projeto usando substituição de variável de ambiente (`${GITHUB_TOKEN}`) para auth e documentar a variável necessária no README.','["Domain_3::Claude_Code_Configuration_Workflows", "Domain_2::Tool_Design_MCP_Integration", "Scenario_2::Code_Generation_Claude_Code"]','New',0,2.5,0,1783092984593,1783725398246,1783203558653,replace('**Tradução para português do Brasil:**\n\n**Pergunta:** Geração de Código com Claude Code\n\nSeu time quer adicionar um servidor MCP do GitHub para buscar PRs e checar status de CI via Claude Code. Cada um dos seis devs tem seu próprio token pessoal de acesso ao GitHub. Você quer ferramental consistente em todo o time sem commitar credenciais no controle de versão.\n\nQual abordagem de configuração é mais efetiva?\n\n[ ] A - Que cada dev adicione o servidor em escopo de usuário via `claude mcp add --scope user`.\n[ ] B - Criar um wrapper de servidor MCP que leia tokens de um arquivo `.env` e proxie chamadas à API do GitHub, depois adicionar o wrapper ao `.mcp.json` do projeto.\n[ ] C - Adicionar o servidor ao `.mcp.json` do projeto usando substituição de variável de ambiente (`${GITHUB_TOKEN}`) para auth e documentar a variável necessária no README.\n[ ] D - Configurar o servidor no escopo de projeto com token placeholder, depois pedir aos devs que sobrescrevam no config local.','\n',char(10)),replace('**Explicação para adulto (tech lead):**\n\nA alternativa **C** é a mais efetiva porque alcança os dois objetivos simultaneamente: consistência de configuração via `.mcp.json` do projeto (versionado) e segurança de credenciais (sem commit de tokens).\n\n**Análise detalhada das alternativas:**\n\n- **Alternativa A (Incorreta):** Configurar no escopo de usuário (`--scope user`) coloca a configuração fora do repositório. Cada desenvolvedor precisa lembrar e executar o comando individualmente, não há rastreabilidade, e novos membros do time precisam descobrir esse passo manualmente. Viola o princípio de "configuração como código" e consistência do time.\n\n- **Alternativa B (Incorreta):** Embora funcione, adicionar um wrapper personalizado introduz complexidade desnecessária (implementação, manutenção, debug). O MCP nativamente já suporta substituição de variáveis de ambiente via `${VARIAVEL}`, então um proxy customizado é overengineering. O `.env` também precisa ser gerenciado (não versionado), e um wrapper é um ponto extra de falha.\n\n- **Alternativa C (Correta):** O `.mcp.json` suporta interpolação de variáveis de ambiente com a sintaxe `${NOME_DA_VAR}`. Ao configurar o servidor no `.mcp.json` do projeto com `${GITHUB_TOKEN}` no campo de autenticação, o arquivo pode ser versionado sem expor o segredo. Cada dev define `GITHUB_TOKEN` em seu ambiente local (shell, `.envrc` via direnv, etc.). O resultado: configuração centralizada e consistente, credenciais seguras, onboarding simples (basta ler o README).\n\n- **Alternativa D (Incorreta):** Tokens placeholder versionados podem vazar inadvertidamente ou causar confusão ("será que esse placeholder funciona?"). Depender de "sobrescrita local" é frágil, propenso a erros de merge e difícil de auditar. A interpolação de variáveis de ambiente (alternativa C) é o mecanismo correto e intencional para esse cenário.','\n',char(10)),replace('Imagina que vocês seis têm uma caixa de ferramentas do time (o projeto) e cada um tem sua chave secreta para o baú do GitHub (o token). Vocês querem que todo mundo use a mesma caixa de ferramentas, mas sem escrever a chave secreta na parede para todos verem.\n\n- **Opção A:** Cada um monta sua própria caixa de ferramentas do zero em casa. Problema: todo mundo faz do seu jeito, esquece o passo, e ninguém sabe como o outro fez.\n\n- **Opção B:** Construir um robô complicado que lê a chave de um papel escondido. Funciona, mas dá muito trabalho construir e manter esse robô, sendo que a caixa de ferramentas já sabe ler chaves sozinha!\n\n- **Opção C (a melhor):** Vocês colocam na caixa de ferramentas do time um espaço reservado escrito "COLE SUA CHAVE AQUI". A caixa de ferramentas fica na parede para todos verem (versionada), mas o espaço reservado mostra que cada um deve colocar sua chave secreta no seu bolso (variável de ambiente). Todo mundo usa a mesma configuração, ninguém vê a chave do outro, e é fácil ensinar um novo amigo.\n\n- **Opção D:** Escrever uma chave falsa na caixa e pedir para cada um trocar pela sua. Problema: alguém pode esquecer de trocar, ou a chave falsa pode vazar.','\n',char(10)));
INSERT INTO cards VALUES('admin','card_1783092984601_a61hkgl6c',94,'Uma engenheira usou o `Claude Code` ontem para investigar fluxos de autenticação em um monolito legado, acumulando um contexto significativo ao longo de uma sessão de 2 horas.',replace('Uma engenheira usou o `Claude Code` ontem para investigar fluxos de autenticação em um monolito legado, acumulando um contexto significativo ao longo de uma sessão de 2 horas.\n\nUma engenheira usou o `Claude Code` ontem para investigar fluxos de autenticação em um monolito legado, acumulando um contexto significativo ao longo de uma sessão de 2 horas. Hoje ela quer continuar essa investigação específica. Ela trabalhou em outras três bases de código desde então e sabe que a sessão se chamava "auth-deep-dive".\n\nComo ela deve retomar?\n\n[ ] A - Começar do zero e reler os mesmos arquivos\n[ ] B - Usar `--session-id` com o UUID do arquivo de transcrição da sessão de ontem\n[ ] C - Usar `--continue` para retomar de onde a conversa mais recente parou\n[ ] D - Usar `--resume` auth-deep-dive para carregar essa sessão específica pelo nome','\n',char(10)),'D - Usar `--resume` auth-deep-dive para carregar essa sessão específica pelo nome','["Domain_3::Claude_Code_Configuration_Workflows", "Domain_5::Context_Management_Reliability", "Scenario_2::Code_Generation_Claude_Code"]','New',0,2.5,0,1783092984601,1783725402562,1783203558653,replace('**Tradução para Português do Brasil:**\n\nUma engenheira usou o Claude Code ontem para investigar fluxos de autenticação em um monolito legado, acumulando um contexto significativo ao longo de uma sessão de 2 horas.\n\nHoje ela quer continuar essa investigação específica. Ela trabalhou em outras três bases de código desde então e sabe que a sessão se chamava "auth-deep-dive".\n\nComo ela deve retomar?\n\n[ ] A - Começar do zero e reler os mesmos arquivos\n[ ] B - Usar --session-id com o UUID do arquivo de transcrição da sessão de ontem\n[ ] C - Usar --continue para retomar de onde a conversa mais recente parou\n[ ] D - Usar --resume auth-deep-dive para carregar essa sessão específica pelo nome','\n',char(10)),replace('**Explicação para Tech Lead:**\n\nA alternativa correta é a **D**.\n\nO Claude Code oferece o flag `--resume <nome-da-sessão>` justamente para retomar uma sessão nomeada anterior. A engenheira nomeou a sessão como "auth-deep-dive" (provavelmente ao iniciar com `--name "auth-deep-dive"` ou ao nomear a sessão durante o uso). Como ela trabalhou em outras bases depois, a sessão mais recente no histórico *não* é a de autenticação, o que invalida a alternativa C (`--continue` retoma a última sessão, que seria de outra base). A alternativa B menciona `--session-id` com um UUID, mas esse não é o mecanismo padrão do Claude Code — o correto é usar o nome da sessão. A alternativa A é tecnicamente possível, mas ineficiente, pois joga fora todo o contexto já construído.\n\n**Análise das demais alternativas:**\n\n- **A: Começar do zero** — Embora funcional, ignora o propósito da ferramenta: reter contexto entre sessões. Seria o equivalente a reiniciar um depurador a cada execução, perdendo variáveis e histórico. É antagônico à produtividade que uma ferramenta como Claude Code proporciona.\n\n- **B: Usar --session-id com UUID** — O Claude Code não usa `--session-id` como interface pública para retomar sessões; ele gerencia sessões por nome ou por continuidade automática. A engenheira não tem o UUID, tornando essa opção impraticável.\n\n- **C: Usar --continue** — Este flag retoma a sessão mais recente. Como a engenheira trabalhou em três outras bases de código depois, a sessão mais recente não é "auth-deep-dive", e sim a última sessão de outro projeto. Retomar por `--continue` carregaria o contexto errado.\n\n- **D: Usar --resume auth-deep-dive** — Correto. O flag `--resume` aceita o nome simbólico da sessão ("auth-deep-dive"), que foi definido pela engenheira durante a sessão anterior. Isso permite que ela retome exatamente o contexto de duas horas de investigação sobre autenticação, independentemente de quais outras sessões ocorreram entre elas.','\n',char(10)),replace('Imagine que a engenheira estava lendo um livro de mistério (o código de autenticação) e parou na página 50, colocando um marcador chamado "auth-deep-dive". Depois, ela leu três outras revistas (outros códigos). Hoje, ela quer voltar exatamente para a página 50 do livro de mistério.\n\n- A opção A seria jogar o livro fora e comprar um novo — trabalhoso e desperdiça o que já foi feito.\n- A opção B seria algo como "me mostre o número secreto do marcador", mas ela não tem esse número.\n- A opção C seria "me mostre a última coisa que você leu" — mas a última coisa foi uma revista, não o livro!\n- A opção D (correta) é simplesmente: "me mostre o que estava no marcador chamado auth-deep-dive". Perfeito!\n\nResposta correta: D','\n',char(10)));
INSERT INTO cards VALUES('admin','card_1783092984610_mdrx2bz97',95,'Claude Code para Integração Contínua',replace('Claude Code para Integração Contínua\n\nSeu time usa Claude Code para gerar sugestões de código, mas você nota um padrão: questões não-óbvias — otimizações de performance que quebram casos de borda, limpezas que mudam comportamento inesperadamente — só são pegas quando outro membro do time revisa o PR. O raciocínio do Claude durante a geração mostra que ele considerou esses casos mas concluiu que sua abordagem estava correta. Qual abordagem aborda diretamente a causa-raiz dessa limitação de auto-checagem?\n\n[ ] A - Rodar uma segunda instância independente do Claude Code para revisar as mudanças sem acesso ao raciocínio do gerador.\n[ ] B - Habilitar modo de extended thinking na geração para permitir deliberação mais minuciosa antes de produzir sugestões.\n[ ] C - Adicionar instruções explícitas de auto-review ao prompt de geração pedindo que Claude critique suas próprias sugestões antes de finalizar.\n[ ] D - Incluir arquivos de teste e documentação completos no contexto do prompt para que Claude entenda melhor o comportamento esperado durante a geração.','\n',char(10)),'A - Rodar uma segunda instância independente do Claude Code para revisar as mudanças sem acesso ao raciocínio do gerador.','["Domain_3::Claude_Code_Configuration_Workflows", "Domain_4::Prompt_Engineering_Structured_Output", "Domain_5::Context_Management_Reliability", "Scenario_5::Claude_Code_CI_CD"]','New',0,2.5,0,1783092984610,1783725407437,1783203558653,replace('**Tradução para português do Brasil:**\n\nClaude Code para Integração Contínua\n\nSeu time usa Claude Code para gerar sugestões de código, mas você nota um padrão: questões não-óbvias — otimizações de performance que quebram casos de borda, limpezas que mudam comportamento inesperadamente — só são pegas quando outro membro do time revisa o PR. O raciocínio do Claude durante a geração mostra que ele considerou esses casos mas concluiu que sua abordagem estava correta. Qual abordagem aborda diretamente a causa-raiz dessa limitação de auto-checagem?\n\n[ ] A - Rodar uma segunda instância independente do Claude Code para revisar as mudanças sem acesso ao raciocínio do gerador.\n[ ] B - Habilitar modo de extended thinking na geração para permitir deliberação mais minuciosa antes de produzir sugestões.\n[ ] C - Adicionar instruções explícitas de auto-review ao prompt de geração pedindo que Claude critique suas próprias sugestões antes de finalizar.\n[ ] D - Incluir arquivos de teste e documentação completos no contexto do prompt para que Claude entenda melhor o comportamento esperado durante a geração.','\n',char(10)),replace('**Explicação para adulto tech lead:**\n\nO problema descrito é um caso clássico de **viés de confirmação em modelos de linguagem**. O Claude gerou o código, considerou os casos de borda durante seu raciocínio, mas concluiu — erroneamente — que sua abordagem estava correta. Isso significa que o modelo já está "convencido" da solução que produziu. Pedir que ele mesmo revise seu próprio trabalho (alternativa C) ou que pense mais antes de gerar (alternativa B) não resolve a causa-raiz, pois o mesmo "cérebro" que gerou a solução está sendo usado para criticá-la — não há independência cognitiva.\n\nA alternativa A é a única que quebra esse ciclo vicioso. Ao rodar uma **segunda instância independente** do Claude Code, sem acesso ao raciocínio original, você cria um revisor que aborda o problema com uma "mente fresca" — sem o viés de quem já decidiu que a solução está correta. Isso é análogo a revisões de código feitas por pares no desenvolvimento de software: o próprio autor raramente enxerga seus próprios erros, mas um par independente tem muito mais chance de detectá-los.\n\n**Por que as outras estão erradas:**\n\n- **B (extended thinking):** O problema não é falta de deliberação — o raciocínio já mostra que ele considerou os casos de borda. Mais tempo pensando com a mesma "perspectiva enviesada" não vai gerar um resultado diferente. É como dar mais tempo para alguém argumentar a favor da própria tese; a confirmação tende a se fortalecer, não a se enfraquecer.\n  \n- **C (auto-review explícito):** Essa é a tentação mais comum, mas é ineficaz pela mesma razão: o modelo está revisando o próprio trabalho. Estudos empíricos com LLMs mostram que auto-revisão raramente detecta erros que o modelo já cometeu durante a geração, justamente pelo viés de confirmação inerente.\n\n- **D (mais contexto):** Incluir testes e documentação ajuda o modelo a entender melhor o domínio, mas não resolve o problema específico de auto-checagem. Se o modelo já considerou os casos de borda e concluiu que está certo, mais contexto pode até reforçar o viés em vez de mitigá-lo. O gargalo não é informacional, é de perspectiva independente.','\n',char(10)),replace('Imagina que você está desenhando um labirinto. Enquanto desenha, você pensa em todos os caminhos possíveis e acha que seu labirinto está perfeito. Agora, alguém te pede para revisar seu próprio desenho. É difícil encontrar erros, porque você já está convencido de que está certo — seu cérebro meio que "ignora" os problemas.\n\nÉ isso que acontece com o Claude. Ele pensa nos casos complicados durante a criação, mas decide que está certo. Pedir para ele mesmo revisar ou pensar mais não adianta muito, porque é a mesma "pessoa" olhando para o próprio trabalho.\n\nA melhor solução é chamar um **colega** para revisar. Esse colega não viu o raciocínio de quem desenhou o labirinto, então ele enxerga os problemas com olhos novos. A alternativa A faz exatamente isso: roda um segundo Claude que não sabe como o primeiro pensou, e assim ele consegue achar os erros que o primeiro não viu.\n\nAs outras opções seriam como pedir para você mesmo revisar seu labirinto várias vezes: não muda o fato de que você já acha que está certo!','\n',char(10)));
INSERT INTO cards VALUES('admin','card_1783092984619_z4lsqb4yh',96,'Claude Code para Integração Contínua',replace('Claude Code para Integração Contínua\n\nSeu sistema CI/CD roda três análises baseadas em Claude: (1) checagens rápidas de estilo em todo PR que bloqueiam o merge até concluir, (2) auditorias semanais e abrangentes de segurança em toda a base, e (3) geração noturna de casos de teste para módulos recém-modificados. A Message Batches API oferece 50% de economia, mas o processamento pode levar até 24 horas. Você quer otimizar custo de API mantendo experiência aceitável para devs. Qual combinação casa corretamente cada tarefa com uma abordagem de API?\n\n[ ] A - Use a Message Batches API para todas as três tarefas para maximizar a economia de 50%, configurando o pipeline para fazer polling até a conclusão dos lotes.\n[ ] B - Use chamadas síncronas para checagens de estilo em PR; use a Message Batches API para auditorias semanais de segurança e geração noturna de testes.\n[ ] C - Use chamadas síncronas para todas para tempos de resposta consistentes, contando com prompt caching para reduzir custos.\n[ ] D - Use chamadas síncronas para checagens de estilo em PR e geração noturna de testes; use a Message Batches API apenas para auditorias semanais.','\n',char(10)),'B - Use chamadas síncronas para checagens de estilo em PR; use a Message Batches API para auditorias semanais de segurança e geração noturna de testes.','["Domain_3::Claude_Code_Configuration_Workflows", "Domain_5::Context_Management_Reliability", "Scenario_5::Claude_Code_CI_CD"]','New',0,2.5,0,1783092984619,1783725412031,1783203558653,replace('**Tradução para português do Brasil:**\n\nClaude Code para Integração Contínua\n\nSeu sistema CI/CD roda três análises baseadas em Claude: (1) checagens rápidas de estilo em todo PR que bloqueiam o merge até concluir, (2) auditorias semanais e abrangentes de segurança em toda a base, e (3) geração noturna de casos de teste para módulos recém-modificados. A Message Batches API oferece 50% de economia, mas o processamento pode levar até 24 horas. Você quer otimizar custo de API mantendo experiência aceitável para devs. Qual combinação casa corretamente cada tarefa com uma abordagem de API?\n\n[ ] A - Use a Message Batches API para todas as três tarefas para maximizar a economia de 50%, configurando o pipeline para fazer polling até a conclusão dos lotes.\n[ ] B - Use chamadas síncronas para checagens de estilo em PR; use a Message Batches API para auditorias semanais de segurança e geração noturna de testes.\n[ ] C - Use chamadas síncronas para todas para tempos de resposta consistentes, contando com prompt caching para reduzir custos.\n[ ] D - Use chamadas síncronas para checagens de estilo em PR e geração noturna de testes; use a Message Batches API apenas para auditorias semanais.','\n',char(10)),replace('**Explicação para adulto tech lead:**\n\nA questão aborda o trade-off entre latência e custo ao utilizar a API da Anthropic em um pipeline de CI/CD. A Message Batches API oferece 50% de desconto, mas tem latência variável de até 24 horas — ou seja, não é adequada para tarefas que exigem resposta imediata.\n\nVamos analisar cada tarefa:\n\n1. **Checagens rápidas de estilo em PR** — são bloqueantes para o merge. O desenvolvedor precisa do resultado em segundos ou minutos para poder corrigir e seguir em frente. Usar Batch API aqui causaria atrasos inaceitáveis, travando o fluxo de trabalho. Portanto, exige chamadas síncronas.\n\n2. **Auditorias semanais de segurança** — não há urgência. O prazo é de dias. É perfeitamente compatível com Batch API, aproveitando os 50% de economia.\n\n3. **Geração noturna de casos de teste** — ocorre durante a madrugada, sem desenvolvedores esperando ativamente. O resultado precisa estar disponível pela manhã, o que é perfeitamente compatível com o prazo de até 24h da Batch API.\n\n**Alternativa A** — Errada. Colocar as checagens de estilo em PR na Batch API bloquearia merges por horas, prejudicando a experiência do desenvolvedor e a velocidade do ciclo de feedback.\n\n**Alternativa C** — Errada. Ignora o benefício de custo da Batch API. Prompt caching reduz custos, mas não oferece os 50% de economia que a Batch API proporciona para tarefas assíncronas. Além disso, manter tudo síncrono é desnecessário para tarefas que não precisam de resposta imediata.\n\n**Alternativa D** — Errada. Colocar a geração noturna de testes em chamadas síncronas desperdiça a oportunidade de economia, já que essa tarefa não exige baixa latência. A Batch API seria perfeitamente adequada aqui.','\n',char(10)),replace('Vamos imaginar que você tem três tipos de tarefas na sua casa:\n\n1. **Conferir se a lição de casa está certa** — precisa ser rápido, senão você não consegue entregar a tempo.\n2. **Organizar a estante de livros** — pode fazer uma vez por semana, sem pressa.\n3. **Arrumar o material da semana seguinte** — pode fazer à noite, enquanto dorme.\n\nAgora, você tem duas formas de fazer as coisas:\n- **Fazer na hora (chamada síncrona)** — é rápido, mas custa mais caro (sem desconto).\n- **Pedir para fazer depois (Batch API)** — demora até 24 horas, mas custa metade do preço.\n\nA melhor ideia é:\n- **Conferir a lição (estilo no PR)** você faz na hora, porque precisa do resultado rápido para poder terminar.\n- **Organizar estante (auditoria de segurança)** e **arrumar material (gerar testes)** você manda fazer depois, enquanto você faz outras coisas. Assim você economiza metade do dinheiro e ninguém fica esperando.\n\nA opção A está errada porque se você mandar fazer a lição "depois", vai demorar e você não vai conseguir terminar a tempo.\n\nA opção C está errada porque fazer tudo na hora gasta mais dinheiro que o necessário — você poderia ter economizado nas tarefas que não têm pressa.\n\nA opção D está errada porque mandar "arrumar o material" na hora é desperdício — você poderia fazer isso de noite, de boa, pagando metade do preço.\n\nEntão a resposta certa é a **B**: tarefa rápida (estilo) faz na hora; tarefas sem pressa (segurança e testes) manda fazer depois, economizando.','\n',char(10)));
INSERT INTO cards VALUES('admin','card_1783092984627_8xi3dm0qz',97,'Claude Code para Integração Contínua',replace('Claude Code para Integração Contínua\n\nSuas reviews automatizadas encontram problemas reais, mas devs reportam que o feedback não é acionável. Achados incluem frases como "lógica complexa de roteamento de tickets" ou "potencial null pointer" sem especificar o que exatamente mudar. Quando você adiciona instruções detalhadas como "sempre inclua sugestões concretas de correção", o modelo ainda produz saída inconsistente — às vezes detalhada, às vezes vaga. Qual técnica de prompting produz feedback consistentemente acionável de forma mais confiável?\n\n[ ] A - Refinar mais as instruções com requisitos mais explícitos para cada parte do formato de feedback (location, issue, severity, proposed fix).\n[ ] B - Expandir a janela de contexto para incluir mais código adjacente para que o modelo tenha informação suficiente para propor correções concretas.\n[ ] C - Implementar uma abordagem em duas passagens em que um prompt identifica problemas e outro gera correções, permitindo especialização.\n[ ] D - Adicionar 3–4 exemplos few-shot mostrando o formato exato exigido: problema identificado, localização no código, sugestão concreta de correção.','\n',char(10)),'D - Adicionar 3–4 exemplos few-shot mostrando o formato exato exigido: problema identificado, localização no código, sugestão concreta de correção.','["Domain_4::Prompt_Engineering_Structured_Output", "Domain_3::Claude_Code_Configuration_Workflows", "Scenario_5::Claude_Code_CI_CD"]','New',0,2.5,0,1783092984627,1783725416229,1783203558653,replace('**Tradução para português do Brasil:**\n\nClaude Code para Integração Contínua\n\nSuas revisões automatizadas encontram problemas reais, mas os devs reportam que o feedback não é acionável. Achados incluem frases como "lógica complexa de roteamento de tickets" ou "potencial null pointer" sem especificar o que exatamente mudar. Quando você adiciona instruções detalhadas como "sempre inclua sugestões concretas de correção", o modelo ainda produz saída inconsistente — às vezes detalhada, às vezes vaga. Qual técnica de prompting produz feedback consistentemente acionável de forma mais confiável?\n\n[ ] A - Refinar mais as instruções com requisitos mais explícitos para cada parte do formato de feedback (localização, problema, severidade, correção proposta).\n[ ] B - Expandir a janela de contexto para incluir mais código adjacente para que o modelo tenha informação suficiente para propor correções concretas.\n[ ] C - Implementar uma abordagem em duas passagens em que um prompt identifica problemas e outro gera correções, permitindo especialização.\n[ ] D - Adicionar 3–4 exemplos few-shot mostrando o formato exato exigido: problema identificado, localização no código, sugestão concreta de correção.','\n',char(10)),replace('**Explicação para adulto tech lead:**\n\nA alternativa D é a mais confiável porque o problema central descrito não é falta de informação ou falta de especialização — é inconsistência na *forma* como o modelo estrutura a saída. Instruções verbose no sistema (alternativa A) já foram testadas e falharam: "quando você adiciona instruções detalhadas... o modelo ainda produz saída inconsistente". Isso ocorre porque modelos de linguagem seguem *padrões* demonstrados mais fielmente do que instruções abstratas.\n\nA técnica few-shot (alternativa D) ancora o comportamento do modelo em exemplos concretos. Estudos de prompting (Brown et al., 2020; Wei et al., 2022) mostram que few-shot com exemplos consistentes reduz drasticamente a variância na saída. Ao fornecer 3-4 exemplos idênticos em formato (problema + localização + correção concreta), o modelo tende a replicar esse padrão com alta fidelidade, pois está sendo condicionado por *imitação* e não por *interpretação* de regras.\n\nPor que as outras alternativas são inferiores:\n- **A**: Já foi tentada e falhou. Instruções refinadas reduzem ambiguidade, mas não resolvem inconsistência na execução. O modelo "entende" o que fazer, mas nem sempre executa.\n- **B**: Expandir contexto adiciona ruído computacional e pode até piorar a performance (perda de foco no meio da janela). O problema não é falta de informação — é formatação da saída.\n- **C**: Abordagem em duas passagens pode melhorar a qualidade, mas adiciona latência e custo. Além disso, sem exemplos concretos no segundo prompt, ele ainda pode gerar correções vagas. Funciona melhor *combinada* com few-shot, mas sozinha é menos confiável.\n\nPortanto, para um pipeline de CI onde consistência é crítica, few-shot com exemplos curados é a abordagem mais robusta.','\n',char(10)),replace('Imagine que você pediu para um amigo revisar sua redação. Se você disser "me fala o que está errado e como corrigir", ele pode dar respostas diferentes toda vez — às vezes boas, às vezes confusas. Mas se você mostrar 3 ou 4 exemplos prontos, tipo:\n\n"Frase 1: ''O cachorro correu rápido'' → Problema: palavra repetida → Correção: ''O cão correu rápido''"\n\nAí seu amigo entende exatamente o formato que você quer e vai fazer igual nos exemplos. É muito mais fácil aprender vendo um exemplo do que seguindo uma regra complicada, certo? É a mesma coisa com o Claude: mostrar exemplos prontos funciona melhor do que dar instruções longas.','\n',char(10)));
INSERT INTO cards VALUES('admin','card_1783092984636_61w57wf6l',98,'Claude Code para Integração Contínua',replace('Claude Code para Integração Contínua\n\nSeu pipeline CI inclui dois modos de code review baseados em Claude: um hook pré-merge-commit que bloqueia o merge do PR até concluir, e uma "análise profunda" que roda à noite, faz polling até concluir o lote e posta sugestões detalhadas no PR. Você quer reduzir custo de API usando a Message Batches API, que oferece 50% de economia mas exige polling e pode levar até 24 horas. Qual modo deveria usar processamento em lote?\n\n[ ] A - Apenas o hook pré-merge-commit.\n[ ] B - Apenas a análise profunda.\n[ ] C - Ambos os modos.\n[ ] D - Nenhum dos modos.','\n',char(10)),'[ ] B - Apenas a análise profunda.','["Domain_4::Prompt_Engineering_Structured_Output", "Domain_5::Context_Management_Reliability", "Scenario_5::Claude_Code_CI_CD"]','New',0,2.5,0,1783092984636,1783725419650,1783203558653,replace('**Tradução para português do Brasil:**\n\nClaude Code para Integração Contínua\n\nSeu pipeline CI inclui dois modos de code review baseados em Claude: um hook pré-merge-commit que bloqueia o merge do PR até concluir, e uma "análise profunda" que roda à noite, faz polling até concluir o lote e posta sugestões detalhadas no PR. Você quer reduzir custo de API usando a Message Batches API, que oferece 50% de economia mas exige polling e pode levar até 24 horas. Qual modo deveria usar processamento em lote?\n\n[ ] A - Apenas o hook pré-merge-commit.\n[ ] B - Apenas a análise profunda.\n[ ] C - Ambos os modos.\n[ ] D - Nenhum dos modos.','\n',char(10)),replace('**Explicação para adulto (tech lead):**\n\nA Message Batches API oferece 50% de redução de custo, mas com duas desvantagens importantes: (1) exige polling assíncrono — você envia o lote e precisa ficar verificando periodicamente se terminou; (2) pode levar até 24 horas para ser concluída. Isso torna essa API inadequada para fluxos síncronos ou que exigem tempos de resposta previsíveis e baixos.\n\n**Análise das alternativas:**\n\n- **Alternativa A (Apenas o hook pré-merge-commit) — INCORRETA.** O hook pré-merge-commit é bloqueante: ele trava o merge do PR até terminar sua execução. Se esse processamento fosse enviado como lote via Batches API, o desenvolvedor ficaria impedido de fazer merge do PR por até 24 horas, o que inviabiliza o fluxo de desenvolvimento. Portanto, esse modo NÃO deve usar processamento em lote.\n\n- **Alternativa B (Apenas a análise profunda) — CORRETA.** A análise profunda já roda de forma assíncrona (à noite), já faz polling naturalmente ("faz polling até concluir o lote") e não bloqueia o desenvolvedor — ela posta sugestões no PR como feedback não-crítico. Essas características casam perfeitamente com o modelo assíncrono e de alta latência da Batches API: você dispara o lote à noite e, no dia seguinte, as sugestões estarão disponíveis. A economia de 50% se aplica sem impacto negativo no fluxo de trabalho.\n\n- **Alternativa C (Ambos os modos) — INCORRETA.** Embora a análise profunda se beneficie do batch, submeter o hook pré-merge-commit ao batch quebraria o fluxo síncrono/bloqueante. Se o hook levasse até 24 horas para ser concluído, o time de desenvolvimento ficaria impossibilitado de fazer merges durante todo esse período. Usar batch no hook não é viável.\n\n- **Alternativa D (Nenhum dos modos) — INCORRETA.** Eliminar a possibilidade de usar batch para a análise profunda ignora o caso de uso perfeitamente adequado. A análise profunda é assíncrona, tolerante a latência e não bloqueante — logo, é candidata ideal para o batch, gerando economia significativa sem prejudicar o desenvolvedor.','\n',char(10)),replace('**Explicação para criança de 10 anos:**\n\nImagine que você tem duas tarefas na escola:\n\n1. **Tarefa urgente:** Você precisa terminar um trabalho antes de sair para o recreio. Se não terminar, não pode ir brincar.\n2. **Tarefa não urgente:** Você tem que escrever um resumo de um livro e pode entregar no dia seguinte.\n\nAgora imagine que a escola tem um "serviço de entrega econômico" que custa metade do preço, mas demora até um dia inteiro para entregar seus trabalhos.\n\n- Se você usar esse serviço econômico para a **tarefa urgente** (a que bloqueia o recreio), você nunca vai conseguir sair para brincar porque o serviço demora demais. Isso é ruim!\n- Mas se você usar para a **tarefa não urgente** (o resumo do livro), você economiza dinheiro e ainda entrega no prazo, porque não tem pressa.\n\nNa pergunta, o "hook pré-merge-commit" é a tarefa urgente (bloqueia o merge do PR). A "análise profunda" é a tarefa não urgente (roda à noite, sem pressa). Por isso, a resposta certa é usar o processamento em lote (o serviço econômico) **apenas na análise profunda** — alternativa B.','\n',char(10)));
INSERT INTO cards VALUES('admin','card_1783092984645_b39aomtbk',99,'Claude Code para Integração Contínua',replace('Claude Code para Integração Contínua\n\nSua review automatizada analisa comentários e docstrings. O prompt atual instrui Claude a "verificar que comentários estão precisos e atualizados". Achados frequentemente sinalizam padrões aceitáveis (marcadores TODO, descrições simples) enquanto perdem comentários que descrevem comportamento que o código não implementa mais. Qual mudança ataca a causa-raiz dessa análise inconsistente?\n\n[ ] A - Incluir dados de `git blame` para que Claude possa identificar comentários anteriores a mudanças recentes de código.\n[ ] B - Adicionar exemplos few-shot de comentários enganosos para ajudar o modelo a reconhecer padrões similares na base.\n[ ] C - Filtrar TODO, FIXME e padrões de comentários descritivos antes da análise para reduzir ruído.\n[ ] D - Especificar critérios explícitos: marcar comentários apenas quando o comportamento que afirmam contradiz o comportamento real do código.','\n',char(10)),'D - Especificar critérios explícitos: marcar comentários apenas quando o comportamento que afirmam contradiz o comportamento real do código.','["Domain_4::Prompt_Engineering_Structured_Output", "Domain_3::Claude_Code_Configuration_Workflows", "Scenario_5::Claude_Code_CI_CD"]','New',0,2.5,0,1783092984645,1783725424218,1783203558653,replace('**Tradução para português do Brasil:**\n\nClaude Code para Integração Contínua\n\nSua review automatizada analisa comentários e docstrings. O prompt atual instrui Claude a "verificar que comentários estão precisos e atualizados". Achados frequentemente sinalizam padrões aceitáveis (marcadores TODO, descrições simples) enquanto perdem comentários que descrevem comportamento que o código não implementa mais. Qual mudança ataca a causa-raiz dessa análise inconsistente?\n\n[ ] A - Incluir dados de `git blame` para que Claude possa identificar comentários anteriores a mudanças recentes de código.\n[ ] B - Adicionar exemplos few-shot de comentários enganosos para ajudar o modelo a reconhecer padrões similares na base.\n[ ] C - Filtrar TODO, FIXME e padrões de comentários descritivos antes da análise para reduzir ruído.\n[ ] D - Especificar critérios explícitos: marcar comentários apenas quando o comportamento que afirmam contradiz o comportamento real do código.','\n',char(10)),replace('**Explicação para um adulto tech lead:**\n\nO problema central é que o prompt atual é vago: "verificar que comentários estão precisos e atualizados" dá ao modelo liberdade demais para interpretar o que significa "preciso" ou "desatualizado". Como resultado, o modelo tende a sinalizar falsos positivos (padrões como TODO, que são aceitáveis) e a perder falsos negativos (comentários que descrevem um comportamento que o código já não implementa).\n\nVamos analisar cada alternativa:\n\n❌ **A - Incluir dados de `git blame`** — Isso adiciona contexto histórico, mas não resolve a ambiguidade do critério. Mesmo com `git blame`, o modelo continuará sem uma definição clara do que deve ser sinalizado. O problema não é falta de contexto, e sim falta de critérios objetivos.\n\n❌ **B - Adicionar exemplos few-shot** — Embora possa melhorar o reconhecimento de padrões, ainda não define o critério de decisão. Exemplificar sem especificar a regra subjacente mantém a inconsistência, pois o modelo pode generalizar incorretamente a partir dos exemplos.\n\n❌ **C - Filtrar TODO e FIXME** — Isso reduz ruído, mas não resolve a causa-raiz. O modelo continuará sem saber identificar corretamente comentários desatualizados. Além disso, filtrar padrões descritivos pode eliminar comentários genuinamente problemáticos.\n\n✅ **D - Especificar critérios explícitos** — Esta é a abordagem correta porque ataca a causa-raiz: a ambiguidade do prompt. Ao definir claramente que um comentário só deve ser marcado quando seu conteúdo contradiz o código real, eliminamos a subjetividade. O modelo passa a ter uma regra objetiva de decisão, reduzindo tanto falsos positivos quanto falsos negativos. Em engenharia de prompts, especificar critérios explícitos e acionáveis é uma prática fundamental para obter comportamento consistente de LLMs.','\n',char(10)),replace('Imagine que você pede para um amigo revisar sua redação e diz: "Vê se está tudo certo". Esse amigo pode achar que "tudo certo" significa sem erros de português, mas pode ignorar frases que dizem algo diferente do que você queria. O problema é que o pedido foi vago!\n\nAgora, a melhor forma de resolver é ser bem específico: "Me avise só se uma frase disser uma coisa, mas o resto do texto mostrar outra coisa diferente". Assim, seu amigo sabe exatamente o que procurar e não perde tempo com outras coisas.\n\nÉ isso que a opção D faz: em vez de falar "verifique se os comentários estão certos" (que é vago), ela diz "marque apenas quando o comentário contradizer o código". Assim, o Claude erra menos e acha os problemas de verdade!','\n',char(10)));
INSERT INTO cards VALUES('admin','card_1783092984654_y7h7ncq0p',100,'Claude Code para Integração Contínua',replace('Claude Code para Integração Contínua\n\nSeu sistema de code review automatizado mostra severidades inconsistentes — questões similares como riscos de null pointer são classificadas "critical" em alguns PRs mas só "medium" em outros. Pesquisas com devs mostram desconfiança crescente — muitos começam a descartar achados sem ler porque "metade está errada". Categorias com altas taxas de falsos positivos minam a confiança em categorias acuradas. Qual abordagem melhor restaura a confiança dos devs enquanto melhora o sistema?\n\n[ ] A - Desabilitar temporariamente categorias de alto FP (estilo, naming, documentação) e manter apenas categorias de alta precisão enquanto melhora os prompts.\n[ ] B - Manter todas as categorias mas exibir scores de confiança junto a cada achado para que devs decidam o que investigar.\n[ ] C - Manter todas as categorias e adicionar exemplos few-shot para melhorar a acurácia em cada categoria nas próximas semanas.\n[ ] D - Aplicar uma redução uniforme de rigor em todas as categorias para baixar a taxa geral de FP.','\n',char(10)),'A - Desabilitar temporariamente categorias de alto FP (estilo, naming, documentação) e manter apenas categorias de alta precisão enquanto melhora os prompts.','["Domain_4::Prompt_Engineering_Structured_Output", "Domain_5::Context_Management_Reliability", "Scenario_5::Claude_Code_CI_CD"]','New',0,2.5,0,1783092984654,1783725429223,1783203558653,replace('**Tradução para Português do Brasil:**\n\n**Claude Code para Integração Contínua**\n\nSeu sistema de code review automatizado mostra severidades inconsistentes — questões similares como riscos de null pointer são classificadas "critical" em alguns PRs mas só "medium" em outros. Pesquisas com devs mostram desconfiança crescente — muitos começam a descartar achados sem ler porque "metade está errada". Categorias com altas taxas de falsos positivos minam a confiança em categorias acuradas. Qual abordagem melhor restaura a confiança dos devs enquanto melhora o sistema?\n\n[ ] A - Desabilitar temporariamente categorias de alto FP (estilo, naming, documentação) e manter apenas categorias de alta precisão enquanto melhora os prompts.\n[ ] B - Manter todas as categorias mas exibir scores de confiança junto a cada achado para que devs decidam o que investigar.\n[ ] C - Manter todas as categorias e adicionar exemplos few-shot para melhorar a acurácia em cada categoria nas próximas semanas.\n[ ] D - Aplicar uma redução uniforme de rigor em todas as categorias para baixar a taxa geral de FP.','\n',char(10)),replace('**Explicação Didática para Tech Lead:**\n\nA alternativa **A** é a resposta correta. O problema central descrito no enunciado é uma crise de confiança: os desenvolvedores não confiam mais no sistema porque ele gera muitos falsos positivos (FP), e a inconsistência nas severidades agrava essa percepção. Quando categorias de alto FP (como estilo, naming e documentação) são mantidas ativas, elas contaminam a experiência geral: o desenvolvedor vê alertas irrelevantes com frequência, começa a ignorar *todos* os alertas (inclusive os de categorias precisas como null pointer), e o sistema perde sua utilidade.\n\n**Por que A é a melhor escolha:**\n- **Redução imediata do ruído**: Ao desabilitar temporariamente categorias de alto FP, você elimina a principal fonte de desconfiança quase que instantaneamente. Os devs voltam a ver apenas alertas relevantes e precisos.\n- **Preservação da credibilidade das categorias precisas**: Categorias como segurança e null pointer não são contaminadas pela associação com categorias de baixa qualidade.\n- **Tempo para melhoria estrutural**: O "enquanto melhora os prompts" é crucial — você não está apenas removendo funcionalidade, está usando o ganho de credibilidade como janela para corrigir a raiz do problema (prompts mal calibrados).\n- **Abordagem cirúrgica**: Diferente de reduzir rigor uniformemente (alternativa D), aqui você preserva a sensibilidade nas categorias que realmente importam.\n\n**Por que as demais estão erradas:**\n\n❌ **B - Manter todas as categorias mas exibir scores de confiança**: Isso apenas adiciona mais informação sem resolver o problema de raiz. Scores de confiança não eliminam falsos positivos; eles apenas tentam "gerenciar a expectativa". O desenvolvedor continuará vendo o mesmo volume de alertas ruins, e a confiança não será restaurada porque a *taxa de FP* permanece a mesma. É um paliativo, não uma solução.\n\n❌ **C - Manter todas as categorias e adicionar exemplos few-shot**: Few-shot learning pode melhorar a acurácia no médio/longo prazo, mas não resolve o problema *agora*. O enunciado fala em "desconfiança crescente" — é uma crise ativa. Manter tudo rodando enquanto se tenta melhorar gradualmente significa continuar gerando desconfiança no dia a dia. A abordagem não é errada em si, mas o timing é inadequado para o cenário descrito.\n\n❌ **D - Aplicar uma redução uniforme de rigor em todas as categorias**: Essa é uma abordagem de "jogar o bebê fora junto com a água do banho". Reduzir o rigor em categorias de alta precisão (como null pointer ou SQL injection) fará com que *elas também* percam acurácia. Você estará sacrificando a detecção de problemas reais para tentar diminuir FP em categorias que já são problemáticas. Pior: não elimina os falsos positivos das categorias de alto FP, apenas reduz sua quantidade — mas eles continuarão existindo e minando a confiança.\n\n**Resumo:** A abordagem certa é conter o dano imediatamente (desabilitar o que não funciona), usar a credibilidade conquistada para corrigir a causa raiz (melhorar prompts), e só reativar as categorias quando estiverem em um nível aceitável de precisão.','\n',char(10)),replace('Imagine que você tem um assistente que ajuda a revisar sua lição de casa. Mas esse assistente vive apontando erros que não existem — tipo dizer que "você escreveu feio" quando na verdade a letra está bonita. Com o tempo, você para de prestar atenção em tudo que ele diz, inclusive quando ele avisa um erro de verdade, como "2+2=5".\n\nA melhor solução é: **pedir para o assistente parar de falar sobre coisas que ele não entende bem** (como "capricho na letra") e deixar ele apontar só o que ele faz muito bem (como contas erradas). Enquanto isso, você ensina ele a melhorar nos outros assuntos. Depois que ele aprender, ele pode voltar a falar de tudo.\n\nAs outras opções não funcionam tão bem:\n- Mostrar "nota de confiança" não resolve — você continua vendo alertas errados e fica com raiva.\n- Tentar ensinar ele aos poucos enquanto ele continua falando besteira todo dia só piora as coisas.\n- Pedir para ele ser mais bonzinho com todo mundo faria com que ele perdesse a capacidade de achar erros importantes também.\n\nEntão a resposta certa é a **alternativa A**: desligar temporariamente o que não funciona, manter só o que é bom, e ir melhorando o resto.','\n',char(10)));
INSERT INTO cards VALUES('admin','card_1783092984674_ptn0hdigs',101,'Claude Code para Integração Contínua',replace('Claude Code para Integração Contínua\n\nSua review automatizada gera sugestões de casos de teste para cada PR. Revisando um PR que adiciona tracking de conclusão de curso, Claude sugere 10 casos de teste, mas o feedback dos devs mostra que 6 duplicam cenários já cobertos pela suíte de testes existente. Qual mudança reduz duplicação de forma mais efetiva?\n\n[ ] A - Incluir o arquivo de teste existente no contexto para que Claude possa determinar quais cenários já estão cobertos.\n[ ] B - Reduzir o número solicitado de sugestões de 10 para 5, assumindo que Claude prioriza os casos mais valiosos primeiro.\n[ ] C - Adicionar instruções direcionando Claude a focar exclusivamente em casos de borda e condições de erro em vez de caminhos felizes.\n[ ] D - Implementar pós-processamento que filtra sugestões cujas descrições casam com nomes de testes existentes via sobreposição de palavras-chave.','\n',char(10)),'[ ] A - Incluir o arquivo de teste existente no contexto para que Claude possa determinar quais cenários já estão cobertos.','["Domain_4::Prompt_Engineering_Structured_Output", "Domain_5::Context_Management_Reliability", "Domain_3::Claude_Code_Configuration_Workflows", "Scenario_5::Claude_Code_CI_CD"]','New',0,2.5,0,1783092984674,1783725603352,1783203558653,replace('**Tradução para português do Brasil:**\n\nClaude Code para Integração Contínua\n\nSua revisão automatizada gera sugestões de casos de teste para cada PR. Revisando um PR que adiciona rastreamento de conclusão de curso, Claude sugere 10 casos de teste, mas o feedback dos desenvolvedores mostra que 6 duplicam cenários já cobertos pela suíte de testes existente. Qual mudança reduz a duplicação de forma mais eficaz?\n\n[ ] A - Incluir o arquivo de teste existente no contexto para que Claude possa determinar quais cenários já estão cobertos.\n[ ] B - Reduzir o número solicitado de sugestões de 10 para 5, assumindo que Claude prioriza os casos mais valiosos primeiro.\n[ ] C - Adicionar instruções direcionando Claude a focar exclusivamente em casos de borda e condições de erro em vez de caminhos felizes.\n[ ] D - Implementar pós-processamento que filtra sugestões cujas descrições coincidem com nomes de testes existentes via sobreposição de palavras-chave.','\n',char(10)),replace('**Explicação para adulto (tech lead):**\n\nA alternativa **A** é a mais eficaz porque ataca a raiz do problema: Claude não tem visibilidade do que já existe na suíte de testes. A ferramenta de IA só pode gerar sugestões relevantes e não duplicadas se tiver acesso ao contexto completo, incluindo os testes já implementados. Incluir o arquivo de teste existente no prompt (ou no contexto via ferramentas como `context` ou `files`) permite que o modelo entenda os cenários cobertos e evite gerar duplicatas intencionalmente.\n\n- **B é incorreta**: Reduzir o número de sugestões de 10 para 5 não resolve a duplicação — apenas diminui a quantidade total. Claude continuará sugerindo casos sem saber o que já existe, e a proporção de duplicatas pode permanecer a mesma (ex.: 3 de 5 ainda seriam duplicatas).\n- **C é incorreta**: Focar apenas em casos de borda e erros pode até evitar algumas duplicatas de "caminhos felizes", mas ainda gerará duplicação se esses cenários de borda já estiverem cobertos. Além disso, elimina sugestões legítimas de caminhos felizes que poderiam ser necessárias.\n- **D é incorreta**: Pós-processamento por sobreposição de palavras-chave é frágil e impreciso. Dois testes funcionalmente diferentes podem compartilhar palavras-chave, e dois testes com nomes diferentes podem testar o mesmo cenário. Isso geraria tanto falsos positivos (filtrando sugestões úteis) quanto falsos negativos (deixando passar duplicatas).\n\n**Alternativa correta: A**','\n',char(10)),replace('Imagine que você pediu para um amigo ajudar a criar perguntas para um jogo de quiz, mas ele não sabia quais perguntas você já tinha. Ele acabou criando várias iguais às que você já tinha! A melhor forma de evitar isso é mostrar a ele a lista de perguntas que você já tem, para ele não repetir.\n\nÉ exatamente isso que a opção A faz: mostrar para o Claude os testes que já existem, para ele não sugerir casos repetidos.\n\nAs outras opções não funcionam tão bem:\n- Pedir só 5 perguntas em vez de 10 não resolve — ele ainda pode repetir as que você já tem.\n- Pedir só perguntas difíceis não resolve, porque algumas dessas difíceis podem já existir.\n- Usar um programa para procurar palavras iguais é enganoso — duas perguntas podem ter palavras diferentes mas serem sobre a mesma coisa, ou ter palavras iguais mas serem sobre coisas diferentes.\n\nA melhor solução é simples: mostrar o que já existe para o Claude, como na opção A.','\n',char(10)));
INSERT INTO cards VALUES('admin','card_1783092984684_wiw3cgs3s',102,'Claude Code para Integração Contínua',replace('Claude Code para Integração Contínua\n\nApós uma review automatizada inicial identificar 12 achados, um dev faz push de novos commits para tratar os problemas. Re-rodar a review produz 8 achados, mas devs reportam que 5 duplicam comentários anteriores em código que já foi corrigido nos novos commits. Qual é a forma mais efetiva de eliminar esse feedback redundante mantendo a profundidade?\n\n[ ] A - Rodar review apenas quando o PR é criado e no estado final pré-merge, pulando commits intermediários.\n[ ] B - Adicionar um filtro de pós-processamento que remove achados que casam com anteriores por path e descrição antes de postar comentários.\n[ ] C - Restringir o escopo da review aos arquivos alterados no push mais recente, excluindo arquivos de commits anteriores.\n[ ] D - Incluir achados de reviews anteriores no contexto e instruir Claude a reportar apenas problemas novos ou ainda não resolvidos.','\n',char(10)),'[ ] D - Incluir achados de reviews anteriores no contexto e instruir Claude a reportar apenas problemas novos ou ainda não resolvidos.','["Domain_3::Claude_Code_Configuration_Workflows", "Domain_4::Prompt_Engineering_Structured_Output", "Domain_5::Context_Management_Reliability", "Scenario_5::Claude_Code_CI_CD"]','New',0,2.5,0,1783092984684,1783725607797,1783203558653,replace('**Tradução (pt-BR):**\n\nPergunta: "Claude Code para Integração Contínua\n\nApós uma revisão automatizada inicial identificar 12 achados, um desenvolvedor faz push de novos commits para tratar os problemas. Reexecutar a revisão produz 8 achados, mas desenvolvedores reportam que 5 duplicam comentários anteriores em código que já foi corrigido nos novos commits. Qual é a forma mais efetiva de eliminar esse feedback redundante mantendo a profundidade?"\n\nAlternativas:\n[ ] A - Executar a revisão apenas quando o PR é criado e no estado final pré-merge, pulando commits intermediários.\n[ ] B - Adicionar um filtro de pós-processamento que remove achados que coincidem com anteriores por caminho e descrição antes de postar comentários.\n[ ] C - Restringir o escopo da revisão aos arquivos alterados no push mais recente, excluindo arquivos de commits anteriores.\n[ ] D - Incluir achados de revisões anteriores no contexto e instruir Claude a reportar apenas problemas novos ou ainda não resolvidos.','\n',char(10)),replace('**Explicação para Adulto Tech Lead:**\n\n**Análise do problema:**\nO cenário é típico de revisão incremental: a cada push, a ferramenta reanalisa todo o código e pode reencontrar problemas que o desenvolvedor já corrigiu (ou que estavam em trechos não alterados). O requisito é duplo: eliminar redundância sem perder profundidade (ou seja, sem deixar de detectar problemas reais).\n\n**Alternativa D — Correta:**\nIncluir o histórico de achados anteriores no prompt (contexto) e instruir o modelo a reportar apenas problemas novos ou ainda não resolvidos. Esta abordagem é a mais efetiva porque:\n- Mantém a análise completa do código (profundidade total).\n- Usa inteligência contextual para distinguir entre um problema corrigido, um problema persistente e um problema novo.\n- Não depende de heurísticas frágeis como match por path+descrição (que falhariam se a mensagem mudar ligeiramente ou se o problema for no mesmo arquivo mas em local diferente).\n- Funciona inclusive para casos onde o mesmo problema existe em múltiplos lugares, sendo capaz de diferenciar cada ocorrência.\n\n**Alternativa A — Incorreta:**\nElimina completamente a revisão em commits intermediários, o que joga fora a oportunidade de feedback precoce e pode permitir que problemas se acumulem até o merge. Além disso, não elimina a redundância — apenas a adia.\n\n**Alternativa B — Incorreta:**\nFiltro por path + descrição é frágil. Se a descrição do achado variar minimamente (ex.: "linha 42: variável não utilizada" vs "variável ''x'' não utilizada na linha 42"), o filtro não detecta a duplicata. Além disso, poderia remover falsamente achados legítimos que por acaso tenham mesmo path e descrição.\n\n**Alternativa C — Incorreta:**\nRestringir o escopo apenas aos arquivos do último commit elimina a detecção de problemas em arquivos não modificados, o que reduz a profundidade da revisão. Um problema de arquitetura ou segurança em um arquivo inalterado que só se torna relevante após uma mudança em outro arquivo passaria despercebido.','\n',char(10)),replace('**Explicação para Criança de 10 Anos:**\n\nImagine que você está revisando a redação de um amigo. Primeiro você encontra 12 erros. Ele corrige alguns e te mostra de novo. Dessa vez você encontra 8 erros, mas 5 deles são os mesmos que você já tinha apontado — só que ele já arrumou aquilo! Isso é chato, né?\n\nA melhor forma de resolver isso é você guardar uma lista dos erros que já encontrou antes. Quando for revisar de novo, você olha para essa lista e fala: "Esses erros aqui já foram arrumados, então não vou reclamar de novo. Vou procurar só os problemas novos." É isso que a alternativa D faz.\n\nAs outras opções são piores:\n- A: Você só revisa no começo e no final, perdendo a chance de ajudar no meio do caminho.\n- B: Você tenta apagar erros repetidos olhando só o nome do arquivo e a descrição do erro, mas isso é enganoso — as vezes parece o mesmo erro mas é diferente.\n- C: Você olha só os trechos que mudaram, mas pode perder um erro importante numa parte que não mudou.\n\nEntão a alternativa D é a melhor porque guarda a memória do que já foi revisado e só aponta coisas realmente novas. 😊','\n',char(10)));
INSERT INTO cards VALUES('admin','card_1783092984693_c6ookic1f',103,'Claude Code para Integração Contínua',replace('Claude Code para Integração Contínua\n\nUm pull request altera 14 arquivos em um módulo de tracking de inventário. Uma review de única passagem que analisa todos os arquivos juntos produz resultados inconsistentes: feedback detalhado em alguns arquivos mas comentários superficiais em outros, bugs óbvios não detectados e feedback contraditório (um padrão é marcado em um arquivo mas código idêntico aprovado em outro arquivo no mesmo PR). Como reestruturar a review?\n\n[ ] A - Rodar três passagens independentes de review do PR completo e marcar apenas problemas que aparecem em pelo menos duas das três execuções.\n[ ] B - Dividir em passagens focadas: revisar cada arquivo individualmente para problemas locais, depois rodar uma passagem separada orientada a integração para examinar fluxos de dados cross-file.\n[ ] C - Exigir que devs dividam PRs grandes em submissões menores de 3–4 arquivos antes de rodar review automatizada.\n[ ] D - Mudar para um modelo maior com janela de contexto maior para que ele possa atender suficientemente todos os 14 arquivos em uma passagem.','\n',char(10)),'B - Dividir em passagens focadas: revisar cada arquivo individualmente para problemas locais, depois rodar uma passagem separada orientada a integração para examinar fluxos de dados cross-file.','["Domain_5::Context_Management_Reliability", "Domain_4::Prompt_Engineering_Structured_Output", "Scenario_5::Claude_Code_CI_CD"]','New',0,2.5,0,1783092984693,1783725611680,1783203558653,replace('**Tradução para português do Brasil:**\n\n**Pergunta:** Claude Code para Integração Contínua\n\nUm pull request altera 14 arquivos em um módulo de rastreamento de inventário. Uma revisão de passagem única que analisa todos os arquivos juntos produz resultados inconsistentes: feedback detalhado em alguns arquivos, mas comentários superficiais em outros; bugs óbvios não detectados; e feedback contraditório (um padrão é sinalizado em um arquivo, mas código idêntico é aprovado em outro arquivo no mesmo PR). Como reestruturar a revisão?\n\n[ ] A - Executar três passagens independentes de revisão do PR completo e marcar apenas problemas que aparecem em pelo menos duas das três execuções.\n[ ] B - Dividir em passagens focadas: revisar cada arquivo individualmente para problemas locais, depois executar uma passagem separada orientada à integração para examinar fluxos de dados entre arquivos.\n[ ] C - Exigir que os desenvolvedores dividam PRs grandes em submissões menores de 3–4 arquivos antes de executar a revisão automatizada.\n[ ] D - Mudar para um modelo maior com janela de contexto maior para que ele possa lidar adequadamente com todos os 14 arquivos em uma passagem.','\n',char(10)),replace('**Explicação para adulto tech lead:**\n\nO problema central descrito é um fenômeno clássico em LLMs: degradação da qualidade da análise à medida que o contexto cresce (lost-in-the-middle effect). Com 14 arquivos, o modelo perde consistência — detalha uns, superficializa outros, contradiz a si mesmo. A abordagem de passagem única sobrecarrega a capacidade de atenção do modelo.\n\n**Alternativa A (votação majoritária):** Tentadora, mas ineficiente. Executar três vezes o mesmo PR com o mesmo problema de contexto não resolve a raiz — o modelo continuará inconsistente dentro de cada execução. A votação pode mascarar falsos positivos/negativos e triplica custo computacional sem atacar a causa.\n\n**Alternativa B (correta):** Separa o problema em duas camadas com escopos bem definidos:\n1. **Passagem local (por arquivo):** escopo reduzido → máxima qualidade de análise de cada arquivo individualmente (padrões, boas práticas, bugs locais).\n2. **Passagem de integração (cross-file):** foco exclusivo em fluxos de dados, interfaces, contratos entre arquivos — sem se distrair com detalhes internos de cada arquivo.\n\nIsso mitiga o *lost-in-the-middle effect* e, mais importante, separa a responsabilidade cognitiva: o modelo não precisa "lembrar" de tudo simultaneamente. É análogo a compiladores que primeiro compilam módulos individualmente e depois ligam — cada etapa tem um propósito claro.\n\n**Alternativa C (mudança no processo humano):** Embora PRs menores ajudem revisores humanos, colocar o ônus no desenvolvedor para contornar limitação da ferramenta é antagônico. Além disso, 14 arquivos não é um PR excepcionalmente grande; a ferramenta deveria lidar com isso. Perde-se também a visão sistêmica que o revisor automatizado poderia ter.\n\n**Alternativa D (modelo maior):** Modelos maiores podem ter janelas de contexto maiores, mas ainda sofrem de degradação conforme o contexto cresce — é uma limitação arquitetural conhecida (Liu et al., 2023). Simplesmente jogar mais capacidade computacional no mesmo approach não elimina a inconsistência, apenas posterga o problema.','\n',char(10)),replace('Imagina que você tem que ler 14 páginas de uma história de uma vez só e depois responder perguntas sobre cada página. É muito difícil lembrar de tudo direitinho, então você acaba errando algumas coisas — numa página você dá muitos detalhes, noutra quase nada, e às vezes você diz uma coisa numa página e o contrário em outra.\n\nA alternativa B é a melhor porque funciona como uma tarefa de escola bem organizada: primeiro, você lê uma página de cada vez e faz anotações sobre o que está errado nela (revisão por arquivo). Depois, você pega todas as anotações e vê se as páginas combinam entre si — se a página 5 fala de um personagem que sumiu na página 10, por exemplo (revisão de integração).\n\nAs outras opções não são tão boas:\n- A opção A seria ler as 14 páginas três vezes e ver o que você errou em pelo menos duas — mas você continua tendo que ler tudo de uma vez, então os erros continuam.\n- A opção C seria pedir para o autor escrever histórias menores, de 3 ou 4 páginas. Mas às vezes a história precisa ser maior, e não é justo culpar o autor pela dificuldade de ler tudo.\n- A opção D seria pedir para uma pessoa mais inteligente ler as 14 páginas de uma vez. Mas mesmo pessoas muito inteligentes têm dificuldade de lembrar de tudo quando é muita informação de uma só vez.\n\nEntão, o melhor é dividir o trabalho em duas etapas: primeiro revisar cada parte separada, depois ver se tudo se encaixa direitinho.','\n',char(10)));
INSERT INTO cards VALUES('admin','card_1783092984703_m19dgw63f',104,'Claude Code para Integração Contínua',replace('Claude Code para Integração Contínua\n\nSua review automatizada média 15 achados por PR e devs reportam taxa de FP de 40%. O gargalo é tempo de investigação: devs precisam clicar em cada achado para ler a justificativa do Claude antes de decidir corrigir ou descartar. Seu CLAUDE.md já contém regras abrangentes para padrões aceitáveis e stakeholders rejeitaram qualquer abordagem que filtre achados antes de devs verem. Qual mudança melhor ataca o tempo de investigação?\n\n[ ] A - Exigir que Claude inclua sua justificativa e estimativa de confiança diretamente em cada achado.\n[ ] B - Adicionar um pós-processador que analisa padrões de achados e suprime automaticamente os que casam com assinaturas históricas de FP.\n[ ] C - Categorizar achados como "blocking issues" vs "suggestions", com requisitos de revisão diferentes por nível.\n[ ] D - Configurar Claude para mostrar apenas achados de alta confiança, filtrando flags incertas antes de devs verem.','\n',char(10)),'A - Exigir que Claude inclua sua justificativa e estimativa de confiança diretamente em cada achado.','["Domain_3::Claude_Code_Configuration_Workflows", "Domain_4::Prompt_Engineering_Structured_Output", "Domain_5::Context_Management_Reliability", "Scenario_5::Claude_Code_CI_CD"]','New',0,2.5,0,1783092984703,1783725615585,1783203558653,replace('**Tradução para pt-BR:**\n\nClaude Code para Integração Contínua\n\nSua revisão automatizada tem uma média de 15 achados por PR e os devs reportam uma taxa de FP (falso positivo) de 40%. O gargalo é o tempo de investigação: os devs precisam clicar em cada achado para ler a justificativa do Claude antes de decidir corrigir ou descartar. Seu CLAUDE.md já contém regras abrangentes para padrões aceitáveis e os stakeholders rejeitaram qualquer abordagem que filtre achados antes que os devs os vejam. Qual mudança melhor ataca o tempo de investigação?\n\n[ ] A - Exigir que Claude inclua sua justificativa e estimativa de confiança diretamente em cada achado.\n[ ] B - Adicionar um pós-processador que analisa padrões de achados e suprime automaticamente os que casam com assinaturas históricas de FP.\n[ ] C - Categorizar achados como "blocking issues" vs "suggestions", com requisitos de revisão diferentes por nível.\n[ ] D - Configurar Claude para mostrar apenas achados de alta confiança, filtrando flags incertas antes de devs verem.','\n',char(10)),replace('**Explicação didática para adulto (tech lead):**\n\nO problema central é que o tempo de investigação é o gargalo. Cada achado exige que o dev clique, leia a justificativa do Claude e então decida se é um falso positivo (FP) ou não. Com 15 achados por PR e 40% de FP, os devs gastam tempo significativo investigando achados que no final são descartados.\n\nA alternativa A é a melhor porque **ataca diretamente a fonte do tempo de investigação**: a necessidade de clicar em cada achado para entender a justificativa. Ao trazer a justificativa e a estimativa de confiança diretamente para superfície de cada achado (sem exigir clique), o desenvolvedor pode tomar uma decisão mais rápida sobre corrigir ou descartar. A estimativa de confiança permite priorizar: achados com baixa confiança podem ser descartados rapidamente; achados com alta confiança merecem atenção imediata. Isso reduz o tempo médio por achado sem filtrar nada e sem violar a restrição dos stakeholders.\n\n**Por que as demais estão incorretas:**\n\n- **B**: Viola diretamente a restrição dos stakeholders (rejeitaram qualquer abordagem que filtre achados antes de devs verem). Suprimir automaticamente achados que casam com assinaturas de FP é uma forma de filtragem prévia. Além disso, é uma abordagem mais complexa que pode ter falsos negativos (suprimir um achado legítimo por engano).\n\n- **C**: Embora categorize achados, ainda exige que o dev investigue cada achado para saber em qual categoria ele se encaixa, a menos que a categoria seja determinada automaticamente e visível sem clique. Se a categoria for exibida diretamente no achado (sem clique), isso se aproxima da A, mas a A é mais direta ao fornecer justificativa + confiança, que são mais informativas que uma simples categorização binária.\n\n- **D**: Viola diretamente a restrição dos stakeholders ao filtrar achados antes que os devs os vejam (mostrar "apenas achados de alta confiança" é uma forma de filtragem). Além disso, corre o risco de perder achados importantes que o modelo classificou com baixa confiança incorretamente.\n\n**Resumo técnico:** A alternativa A é a única que ataca o gargalo sem violar as restrições, reduzindo o custo cognitivo por achado ao trazer contexto decisório para primeiro plano.','\n',char(10)),replace('Imagina que você tem um amigo robô que aponta 15 coisas estranhas no seu dever de casa, mas 6 dessas coisas são besteira – o robô se enganou. O problema é que você precisa clicar em cada coisa para ler por que o robô achou aquilo estranho, e isso gasta muito tempo.\n\nA melhor ideia é fazer o robô escrever, direto em cada coisa que ele apontou, o motivo E o quanto ele tem de certeza (tipo "estou 90% certo disso" ou "só 30% de certeza"). Assim, sem precisar clicar em nada, você já sabe: se ele tem pouca certeza, pode ignorar rápido; se tem muita certeza, você dá mais atenção. Isso economiza um tempão!\n\nAs outras ideias não servem porque:\n- Uma delas quer esconder coisas do robô antes de você ver – mas seu chefe não deixou fazer isso.\n- Outra quer separar em "importante" e "sugestão", mas ainda exige que você clique pra saber o que é cada uma.\n- Outra quer mostrar só o que o robô tem certeza – mesma coisa, seu chefe não deixou esconder nada.','\n',char(10)));
INSERT INTO cards VALUES('admin','card_1783092984713_gici8hvij',105,'Claude Code para Integração Contínua',replace('Claude Code para Integração Contínua\n\nA análise da sua review automatizada de código mostra grandes diferenças nas taxas de falsos positivos por categoria de achado: achados de segurança/correção têm 8% de FP, performance 18%, estilo/naming 52% e documentação 48%. Pesquisas com devs mostram desconfiança crescente — muitos começam a descartar achados sem ler porque "metade está errada". Categorias de alto FP minam a confiança em categorias acuradas. Qual abordagem melhor restaura a confiança dos devs enquanto melhora o sistema?\n\n[ ] A - Desabilitar temporariamente categorias de alto FP (estilo, naming, documentação) e manter apenas categorias de alta precisão enquanto melhora os prompts.\n[ ] B - Manter todas as categorias mas exibir scores de confiança junto a cada achado para que devs decidam o que investigar.\n[ ] C - Manter todas as categorias e adicionar exemplos few-shot para melhorar a acurácia em cada categoria nas próximas semanas.\n[ ] D - Aplicar uma redução uniforme de rigor em todas as categorias para baixar a taxa geral de FP.','\n',char(10)),'[ ] A - Desabilitar temporariamente categorias de alto FP (estilo, naming, documentação) e manter apenas categorias de alta precisão enquanto melhora os prompts.','["Domain_4::Prompt_Engineering_Structured_Output", "Domain_5::Context_Management_Reliability", "Scenario_5::Claude_Code_CI_CD"]','New',0,2.5,0,1783092984713,1783725619514,1783203558653,replace('**Tradução para português do Brasil:**\n\nPergunta: A análise da sua revisão automatizada de código mostra grandes diferenças nas taxas de falsos positivos por categoria de achado: achados de segurança/correção têm 8% de FP, performance 18%, estilo/naming 52% e documentação 48%. Pesquisas com desenvolvedores mostram desconfiança crescente — muitos começam a descartar achados sem ler porque "metade está errada". Categorias de alto FP minam a confiança em categorias acuradas. Qual abordagem melhor restaura a confiança dos desenvolvedores enquanto melhora o sistema?\n\n[ ] A - Desabilitar temporariamente categorias de alto FP (estilo, naming, documentação) e manter apenas categorias de alta precisão enquanto melhora os prompts.\n[ ] B - Manter todas as categorias mas exibir scores de confiança junto a cada achado para que desenvolvedores decidam o que investigar.\n[ ] C - Manter todas as categorias e adicionar exemplos few-shot para melhorar a acurácia em cada categoria nas próximas semanas.\n[ ] D - Aplicar uma redução uniforme de rigor em todas as categorias para baixar a taxa geral de FP.','\n',char(10)),replace('**Explicação para um adulto tech lead:**\n\nO cerne do problema é que categorias com alta taxa de falsos positivos (FP) corroem a confiança geral no sistema de revisão automatizada. Desenvolvedores passam a ignorar *todos* os achados, incluindo aqueles de categorias com alta precisão (ex.: segurança com 8% FP). Isso cria um ciclo vicioso: quanto mais alarme falso, menos atenção os devs dão ao sistema como um todo.\n\n**Alternativa A — Correta**. Ao desabilitar temporariamente as categorias de alto FP (estilo/naming com 52%, documentação com 48%), você:\n- Elimina imediatamente a principal fonte de ruído que gera desconfiança.\n- Preserva a credibilidade das categorias restantes (segurança, correção, performance), que já têm boa acurácia.\n- Cria espaço para revisar e melhorar os prompts dessas categorias problemáticas sem a pressão de estarem poluindo a experiência do dia a dia.\n- É uma abordagem cirúrgica e pragmática: reduz o "sinal" a zero nas categorias ruins, eliminando o viés de negatividade que contamina a percepção geral.\n\n**Alternativa B — Incorreta**. Exibir scores de confiança não resolve o problema fundamental. Se 52% dos achados de estilo/naming são falsos, mesmo com um score, os devs continuarão vendo muito ruído. Na prática, scores de confiança baixos viram "desculpa para ignorar", e scores altos em categorias problemáticas podem enganar. Além disso, a experiência fica mais complexa cognitivamente — o dev precisa avaliar cada score em vez de confiar no sistema. Isso não restaura a confiança; apenas a mascara com dados.\n\n**Alternativa C — Incorreta**. Embora adicionar exemplos few-shot seja uma boa prática para melhorar acurácia no longo prazo, manter tudo rodando enquanto isso acontece significa que os devs continuarão expostos ao mesmo ruído por semanas. A confiança continua erodindo durante esse período. A pergunta pede a abordagem que "melhor restaura a confiança enquanto melhora o sistema" — manter o barulho por semanas não restaura nada.\n\n**Alternativa D — Incorreta**. Reduzir o rigor uniformemente é a pior escolha. Você estaria reduzindo a sensibilidade de categorias que já funcionam bem (segurança com 8% FP), aumentando o risco de falsos negativos — ou seja, perdendo bugs reais de segurança. Ao mesmo tempo, categorias com FP alto provavelmente continuariam tendo FP alto, pois o problema não é o rigor, mas a qualidade dos prompts/lógica de detecção. Você piora o que está bom sem necessariamente consertar o que está ruim.','\n',char(10)),replace('Imagine que você tem uma caixa de ferramentas para revisar a lição de casa dos seus colegas. Algumas ferramentas funcionam super bem: a que acha erros de matemática acerta 92% das vezes. Outras são bem desajeitadas: a que verifica se a letra é bonita erra metade das vezes!\n\nSeus colegas estão tão irritados com as ferramentas ruins que nem olham mais os resultados da ferramenta boa de matemática. Eles só pensam "ah, metade tá errada mesmo".\n\nA melhor solução é: guardar as ferramentas ruins na gaveta por enquanto, e deixar só as boas funcionando. Assim, seus colegas voltam a confiar. Enquanto isso, você pode consertar as ferramentas ruins na gaveta, sem atrapalhar ninguém.\n\nAs outras opções seriam:\n- Mostrar um "nível de confiança" para cada erro — mas ainda assim os colegas veriam muitos erros falsos e continuariam bravos.\n- Deixar tudo como está e tentar melhorar aos poucos — mas os colegas continuariam irritados por semanas.\n- Deixar todas as ferramentas menos exigentes — aí a ferramenta boa de matemática passaria a deixar passar erros de verdade! Seria um desastre.','\n',char(10)));
INSERT INTO cards VALUES('admin','card_1783092984723_15q6k1n5h',106,'Claude Code para Integração Contínua',replace('Claude Code para Integração Contínua\n\nSeu time quer reduzir custos de API para análise automatizada. Atualmente, chamadas síncronas ao Claude atendem dois fluxos: (1) checagem bloqueante pré-merge que precisa concluir antes de devs poderem mergear, e (2) relatório de tech-debt gerado de noite para revisão na manhã seguinte. Seu gerente propõe mover ambos para a Message Batches API para economizar 50%. Como avaliar essa proposta?\n\n[ ] A - Mover ambos para processamento em lote com fallback para chamadas síncronas se os lotes demorarem demais.\n[ ] B - Mover ambos os fluxos para processamento em lote com polling de status para verificar conclusão.\n[ ] C - Use processamento em lote apenas para relatórios de tech-debt; mantenha chamadas síncronas para checagens pré-merge.\n[ ] D - Manter chamadas síncronas para ambos os fluxos para evitar problemas com ordenação de resultados em lote.','\n',char(10)),'C - Use processamento em lote apenas para relatórios de tech-debt; mantenha chamadas síncronas para checagens pré-merge.','["Domain_5::Context_Management_Reliability", "Domain_4::Prompt_Engineering_Structured_Output", "Scenario_5::Claude_Code_CI_CD"]','New',0,2.5,0,1783092984723,1783725623281,1783203558653,replace('**Tradução para português do Brasil:**\n\nClaude Code para Integração Contínua\n\nSeu time quer reduzir custos de API para análise automatizada. Atualmente, chamadas síncronas ao Claude atendem dois fluxos: (1) checagem bloqueante pré-merge que precisa concluir antes de devs poderem mergear, e (2) relatório de tech-debt gerado de noite para revisão na manhã seguinte. Seu gerente propõe mover ambos para a Message Batches API para economizar 50%. Como avaliar essa proposta?\n\n[ ] A - Mover ambos para processamento em lote com fallback para chamadas síncronas se os lotes demorarem demais.\n[ ] B - Mover ambos os fluxos para processamento em lote com polling de status para verificar conclusão.\n[ ] C - Usar processamento em lote apenas para relatórios de tech-debt; manter chamadas síncronas para checagens pré-merge.\n[ ] D - Manter chamadas síncronas para ambos os fluxos para evitar problemas com ordenação de resultados em lote.','\n',char(10)),replace('**Explicação para adulto (tech lead):**\n\nA proposta do gerente considera apenas o benefício de redução de custo (50% de desconto), mas ignora as diferenças fundamentais de requisitos entre os dois fluxos.\n\nA **Message Batches API** da Anthropic oferece 50% de desconto, mas com uma ressalva crítica: o processamento é assíncrono e não há SLA garantido para tempo de conclusão. Os resultados podem levar minutos ou até horas para ficarem prontos. Isso torna essa API inadequada para fluxos síncronos bloqueantes.\n\nVamos analisar cada alternativa:\n\n**Alternativa A - Incorreta:** Adicionar fallback síncrono para quando o lote demorar parece uma abordagem híbrida inteligente, mas na prática cria complexidade operacional alta. O fallback só seria acionado após detectar atraso, o que já teria frustrado a experiência do desenvolvedor que precisa mergear. Além disso, você ainda pagaria pelo lote mesmo se o fallback for acionado (lotes enviados são cobrados), resultando em custo duplicado.\n\n**Alternativa B - Incorreta:** Polling de status não resolve o problema fundamental de latência imprevisível. O desenvolvedor ficaria preso num loop de polling esperando o lote terminar, sem garantia de quando isso ocorrerá. Isso quebra o fluxo de trabalho bloqueante.\n\n**Alternativa C - Correta:** Esta é a abordagem pragmaticamente correta. O relatório de tech-debt é um candidato perfeito para batch: não tem urgência (gerado à noite, revisado pela manhã), então a latência do batch é irrelevante. Já a checagem pré-merge é intrinsecamente síncrona e bloqueante — o desenvolvedor precisa da resposta para prosseguir. Manter chamadas síncronas para esse fluxo preserva a experiência do usuário e a produtividade do time.\n\n**Alternativa D - Incorreta:** Embora manter tudo síncrono seja seguro, é uma oportunidade perdida de economia. O relatório noturno não precisa de resposta imediata, então pagar mais caro por chamadas síncronas para esse caso é desperdício de budget. O argumento sobre "ordenação de resultados" é uma falsa questão — o problema real é de latência, não de ordenação.','\n',char(10)),replace('Imagine que você tem duas tarefas:\n\n1. **Verificar se o dever de casa está certo** — você precisa saber AGORA para poder ir brincar.\n2. **Escrever um resumo do que aprendeu no mês** — seu professor só vai olhar amanhã de manhã.\n\nAgora, alguém diz: "Vamos juntar as duas tarefas e mandar para uma pessoa que responde tudo de uma vez, mas demora horas para responder. Isso vai custar metade do preço!"\n\nIsso não funciona para a primeira tarefa, porque você precisa da resposta na hora! Mas para a segunda tarefa, funciona super bem, porque ninguém está esperando.\n\nEntão a melhor escolha é: **mandar o resumo (relatório de tech-debt) para a pessoa que responde em lote devagar e barato**, mas **continuar pedindo a resposta na hora para a verificação do dever de casa (checagem pré-merge)**. É isso que a alternativa C diz.','\n',char(10)));
INSERT INTO cards VALUES('admin','card_1783092984733_j78bsddou',107,'Geração de Código com Claude Code',replace('Geração de Código com Claude Code\n\nVocê pediu ao Claude Code para implementar uma função que transforma respostas de API em um formato interno normalizado. Após duas iterações, a estrutura de saída ainda não casa com as expectativas — alguns campos são aninhados de modo diferente e timestamps formatados incorretamente. Você descreveu requisitos em prosa, mas Claude os interpreta de forma diferente a cada vez.\n\nQual abordagem é mais efetiva para a próxima iteração?\n\n[ ] A - Escrever um JSON schema descrevendo a estrutura de saída esperada e validar a saída do Claude contra ele após cada iteração.\n[ ] B - Fornecer 2–3 exemplos concretos de entrada-saída mostrando a transformação esperada para respostas representativas da API.\n[ ] C - Reescrever requisitos com mais precisão técnica, especificando mapeamentos exatos de campos, regras de aninhamento e strings de formato de timestamp.\n[ ] D - Pedir ao Claude para explicar seu entendimento atual dos requisitos para identificar onde as interpretações divergem.','\n',char(10)),'B - Fornecer 2–3 exemplos concretos de entrada-saída mostrando a transformação esperada para respostas representativas da API.','["Domain_3::Claude_Code_Configuration_Workflows", "Domain_4::Prompt_Engineering_Structured_Output", "Scenario_2::Code_Generation_Claude_Code"]','New',0,2.5,0,1783092984733,1783725627707,1783203558653,replace('**Tradução para Português do Brasil**\n\nGeração de Código com Claude Code\n\nVocê pediu ao Claude Code para implementar uma função que transforma respostas de API em um formato interno normalizado. Após duas iterações, a estrutura de saída ainda não corresponde às expectativas — alguns campos estão aninhados de modo diferente e timestamps formatados incorretamente. Você descreveu requisitos em prosa, mas Claude os interpreta de forma diferente a cada vez.\n\nQual abordagem é mais efetiva para a próxima iteração?\n\n[ ] A - Escrever um JSON schema descrevendo a estrutura de saída esperada e validar a saída do Claude contra ele após cada iteração.\n[ ] B - Fornecer 2–3 exemplos concretos de entrada-saída mostrando a transformação esperada para respostas representativas da API.\n[ ] C - Reescrever requisitos com mais precisão técnica, especificando mapeamentos exatos de campos, regras de aninhamento e strings de formato de timestamp.\n[ ] D - Pedir ao Claude para explicar seu entendimento atual dos requisitos para identificar onde as interpretações divergem.','\n',char(10)),replace('**Explicação para Adulto Tech Lead**\n\nA alternativa **B** é a mais efetiva porque exemplos concretos de entrada-saída (pares input/output) eliminam ambiguidades inerentes à linguagem natural. Em problemas de transformação de dados, a especificação via exemplos é uma técnica consagrada (similar a Test-Driven Development ou Specification by Example). Ao fornecer casos representativos, você está essencialmente dando ao modelo um "teste de aceitação" que ele pode usar para verificar seu próprio código. Isso reduz drasticamente o espaço de interpretação.\n\nAnálise das demais alternativas:\n\n- **Alternativa A (JSON Schema)**: Embora um JSON Schema seja uma especificação formal e validável, ele descreve a estrutura estática (tipos, campos obrigatórios, padrões de string), mas não captura *relações de transformação* entre entrada e saída. Você ainda precisaria que o Claude inferisse a lógica de mapeamento a partir da descrição estrutural. Além disso, validar a saída após a geração é reativo — você descobre o erro depois, em vez de guiar a geração correta desde o início.\n\n- **Alternativa C (Reescrever requisitos com precisão técnica)**: O problema já foi identificado: o modelo interpreta prosa de forma inconsistente. Tentar "precisão técnica" em linguagem natural ainda está sujeito a ambiguidades semânticas. Mesmo especificando "mapeamentos exatos", a descrição textual de um mapeamento é inerentemente menos precisa que um exemplo concreto. Por exemplo, descrever "o campo ''created_at'' deve ser convertido de ISO 8601 para Unix timestamp em milissegundos" é menos eficaz que mostrar `{"created_at": "2024-01-01T12:00:00Z"}` → `{"createdAt": 1704110400000}`.\n\n- **Alternativa D (Pedir explicação)**: Útil como diagnóstico, mas não resolve o problema central. Você pode identificar ONDE a interpretação divergiu, mas ainda precisará de uma estratégia para alinhar o modelo. E mesmo que o Claude explique corretamente os requisitos, a geração de código subsequente pode cair nos mesmos erros se a especificação continuar sendo textual. É uma etapa complementar, não a abordagem principal.\n\n**Conclusão**: Exemplos concretos são a forma mais direta de comunicação para tarefas de transformação de dados, pois eliminam ambiguidades e fornecem alvos verificáveis para o código gerado.','\n',char(10)),replace('Imagina que você pediu para seu amigo desenhar um mapa para chegar na sua casa. Você explicou com palavras: "vira à direita na árvore grande, depois passa pela casa azul...". Mas ele desenhou um caminho diferente duas vezes seguidas!\n\nAgora você tem que escolher a melhor maneira de explicar de novo.\n\nSe você escrever um monte de regras (opção A e C), ele pode continuar entendendo errado — igual quando a professora dá instruções complicadas e ninguém entende.\n\nSe você perguntar "o que você entendeu?" (opção D), descobre onde errou, mas ainda precisa acertar o desenho.\n\nA melhor ideia (opção B) é mostrar DOIS desenhos prontos: "Olha, aqui é um exemplo de como a entrada vira saída. E aqui outro." Assim seu amigo pode copiar o padrão e fazer igual. É como dar a resposta de um exercício de matemática para a pessoa entender como resolver os outros! Bem mais fácil, né?','\n',char(10)));
INSERT INTO cards VALUES('admin','card_1783092984742_l9gs4gqww',108,'Agente de Suporte ao Cliente',replace('Agente de Suporte ao Cliente\n\nSeu agente atinge 55% de resolução no primeiro contato, bem abaixo da meta de 80%. Logs mostram que ele escala casos simples (substituições padrão para mercadorias danificadas com prova fotográfica) enquanto tenta lidar autonomamente com situações complexas que exigem exceções de política. Qual é a forma mais efetiva de melhorar a calibração de escalonamento?\n\n[ ] A - Exigir que o agente auto-classifique confiança em escala 1–10 antes de cada resposta e roteie automaticamente para humanos quando a confiança cair abaixo de um limiar.\n[ ] B - Implantar um modelo classificador separado treinado em tickets históricos para prever quais pedidos precisam de escalonamento antes de o agente principal começar.\n[ ] C - Adicionar critérios explícitos de escalonamento ao system prompt com exemplos few-shot mostrando quando escalar vs resolver autonomamente.\n[ ] D - Implementar análise de sentimento para determinar nível de frustração do cliente e escalar automaticamente acima de um limiar de sentimento negativo.','\n',char(10)),'[ ] C - Adicionar critérios explícitos de escalonamento ao system prompt com exemplos few-shot mostrando quando escalar vs resolver autonomamente.','["Domain_4::Prompt_Engineering_Structured_Output", "Domain_1::Agentic_Architecture_Orchestration", "Scenario_1::Customer_Support_Agent"]','New',0,2.5,0,1783092984742,1783725631549,1783203558653,replace('**Tradução da Pergunta e Alternativas para Português do Brasil:**\n\n**Pergunta:**\nAgente de Suporte ao Cliente\n\nSeu agente atinge 55% de resolução no primeiro contato, bem abaixo da meta de 80%. Logs mostram que ele escala casos simples (substituições padrão para mercadorias danificadas com prova fotográfica) enquanto tenta lidar autonomamente com situações complexas que exigem exceções de política. Qual é a forma mais efetiva de melhorar a calibração de escalonamento?\n\n[ ] A - Exigir que o agente auto-classifique confiança em escala 1–10 antes de cada resposta e roteie automaticamente para humanos quando a confiança cair abaixo de um limiar.\n[ ] B - Implantar um modelo classificador separado treinado em tickets históricos para prever quais pedidos precisam de escalonamento antes de o agente principal começar.\n[ ] C - Adicionar critérios explícitos de escalonamento ao system prompt com exemplos few-shot mostrando quando escalar vs resolver autonomamente.\n[ ] D - Implementar análise de sentimento para determinar nível de frustração do cliente e escalar automaticamente acima de um limiar de sentimento negativo.','\n',char(10)),replace('**Explicação Didática para Adulto Tech Lead**\n\nO problema central é de **má calibração do agente**: ele escala o que deveria resolver (casos simples e bem definidos, como substituições padrão com prova fotográfica) e tenta resolver o que deveria escalar (casos complexos que exigem exceções de política). A meta é corrigir essa "inversão" de julgamento.\n\nVamos analisar cada alternativa:\n\n**Alternativa C (CORRETA):** Adicionar critérios explícitos de escalonamento ao system prompt com exemplos few-shot mostrando quando escalar vs. resolver autonomamente.\n\nEssa é a abordagem mais direta e efetiva porque:\n- Trata a causa raiz: o agente não tem clareza sobre o que constitui um caso "simples" vs. "complexo".\n- Critérios explícitos no system prompt definem as regras de negócio de forma normativa (ex.: "se o cliente forneceu prova fotográfica de dano e o item está na política padrão de substituição, resolva autonomamente"; "se o caso requer aprovação gerencial ou exceção à política, escale").\n- Exemplos few-shot fornecem demonstrações concretas, ajudando o modelo a generalizar corretamente a partir de padrões específicos.\n- É uma intervenção de baixo custo, rápida de implementar e não requer infraestrutura adicional (modelos separados, pipelines de classificação, etc.).\n\n**Alternativa A (Incorreta):** Auto-classificação de confiança.\n\nEmbora interessante, a auto-classificação padece do mesmo problema: o agente que já demonstra mau julgamento sobre o que escalar também terá mau julgamento sobre sua própria confiança. Se ele acha que pode resolver um caso complexo (e erra), tenderá a reportar alta confiança. Da mesma forma, pode reportar baixa confiança em casos simples por falta de clareza. A métrica "confiança" é subjetiva e não endereça a raiz do problema — a falta de critérios objetivos.\n\n**Alternativa B (Incorreta):** Classificador separado treinado em tickets históricos.\n\nUm modelo classificador pode até prever corretamente, mas:\n- Depende de dados históricos rotulados de qualidade. Se o processo de escalonamento histórico já era mal calibrado, o classificador vai aprender a replicar os mesmos erros.\n- Adiciona complexidade operacional (treinamento, deploy, manutenção, latência).\n- Trata o sintoma, não a causa: o agente principal continua sem saber discernir, apenas delega a decisão a outro modelo. O agente principal não aprende nem melhora.\n\n**Alternativa D (Incorreta):** Análise de sentimento.\n\nAnálise de sentimento mede a emoção do cliente, não a complexidade do caso. Clientes educados podem ter casos complexos (exigindo exceção de política) e clientes frustrados podem ter casos simples (substituição padrão). Escalar por sentimento negativo geraria falsos positivos (clientes bravos com casos simples sendo escalados desnecessariamente) e falsos negativos (clientes calmos com casos complexos não sendo escalados). Além disso, o problema relatado é sobre o agente errar o julgamento do tipo de caso, não sobre emoção do cliente.\n\n**Conclusão:** A alternativa C é a mais efetiva porque corrige a causa raiz através de instruções claras e explícitas, com exemplos concretos, diretamente no system prompt do agente.','\n',char(10)),replace('**Explicação para uma criança de 10 anos:**\n\nImagine que você tem um robô ajudante que atende clientes em uma loja. A tarefa dele é decidir: "Esse problema eu consigo resolver sozinho" ou "Esse problema é tão complicado que preciso chamar um adulto."\n\nO robô está fazendo isso errado: ele tenta resolver problemas difíceis que precisam de adulto, e chama o adulto para resolver coisas fáceis que ele poderia fazer sozinho. É como se ele pedisse ajuda para amarrar o tênis, mas tentasse cozinhar o jantar sozinho — tudo ao contrário!\n\nA melhor maneira de consertar isso (alternativa C) é escrever instruções muito claras para o robô, como uma lista de regras:\n\n- "Se o cliente mostrar uma foto do brinquedo quebrado e a loja sempre troca brinquedos quebrados, você pode fazer a troca sozinho."\n- "Se o cliente quer uma exceção especial que foge das regras normais, chame um adulto."\n\nAlém disso, damos exemplos para o robô aprender na prática, tipo um professor mostrando: "Olha, esse caso aqui é para resolver sozinho. Esse outro é para chamar ajuda."\n\nAs outras opções não funcionam tão bem porque:\n- Pedir para o robô dizer se ele está confiante (alternativa A) não adianta, já que ele está confiante nas horas erradas.\n- Criar outro robô para decidir por ele (alternativa B) só esconde o problema.\n- Escalar cliente bravo (alternativa D) confunde emoção com dificuldade — cliente bravo pode ter um problema simples, e cliente calmo pode ter um problema complicado.\n\nEntão a resposta certa é ensinar o robô com regras claras e exemplos! ✅','\n',char(10)));
INSERT INTO cards VALUES('admin','card_1783092984752_tmdr09wk3',109,'Agente de Suporte ao Cliente',replace('Agente de Suporte ao Cliente\n\nMétricas de produção mostram que ao resolver disputas complexas de cobrança ou devoluções multi-pedido, scores de satisfação do cliente são 15% menores que para casos simples — mesmo quando a resolução está tecnicamente correta. Análise de causa-raiz mostra que o agente fornece soluções acuradas mas explica a justificativa de forma inconsistente: às vezes omitindo detalhes relevantes de política, às vezes perdendo info de timeline ou próximos passos. As lacunas de contexto variam caso a caso. Você quer melhorar qualidade da solução sem adicionar supervisão humana. Qual abordagem é mais efetiva?\n\n[ ] A - Adicionar uma etapa de auto-crítica em que o agente avalia uma resposta de rascunho quanto à completude — garantindo que resolva o problema, inclua contexto relevante e antecipe perguntas de follow-up.\n[ ] B - Adicionar uma etapa de confirmação em que o agente pergunta "Isso resolve totalmente seu problema?" antes de fechar, permitindo que clientes peçam informações adicionais.\n[ ] C - Atualizar o modelo de Haiku para Sonnet em casos complexos, roteando com base em uma métrica de complexidade definida.\n[ ] D - Implementar exemplos few-shot no system prompt mostrando explicações completas para cinco tipos comuns de casos complexos, demonstrando como incluir contexto de política, timelines e próximos passos.','\n',char(10)),'A - Adicionar uma etapa de auto-crítica em que o agente avalia uma resposta de rascunho quanto à completude — garantindo que resolva o problema, inclua contexto relevante e antecipe perguntas de follow-up.','["Domain_4::Prompt_Engineering_Structured_Output", "Domain_5::Context_Management_Reliability", "Scenario_1::Customer_Support_Agent"]','New',0,2.5,0,1783092984752,1783725635861,1783203558653,replace('## Tradução para Português do Brasil\n\n**Pergunta:**\nAgente de Suporte ao Cliente\n\nMétricas de produção mostram que ao resolver disputas complexas de cobrança ou devoluções multi-pedido, scores de satisfação do cliente são 15% menores que para casos simples — mesmo quando a resolução está tecnicamente correta. Análise de causa-raiz mostra que o agente fornece soluções acuradas mas explica a justificativa de forma inconsistente: às vezes omitindo detalhes relevantes de política, às vezes perdendo info de timeline ou próximos passos. As lacunas de contexto variam caso a caso. Você quer melhorar qualidade da solução sem adicionar supervisão humana. Qual abordagem é mais efetiva?\n\n[ ] A - Adicionar uma etapa de auto-crítica em que o agente avalia uma resposta de rascunho quanto à completude — garantindo que resolva o problema, inclua contexto relevante e antecipe perguntas de follow-up.\n\n[ ] B - Adicionar uma etapa de confirmação em que o agente pergunta "Isso resolve totalmente seu problema?" antes de fechar, permitindo que clientes peçam informações adicionais.\n\n[ ] C - Atualizar o modelo de Haiku para Sonnet em casos complexos, roteando com base em uma métrica de complexidade definida.\n\n[ ] D - Implementar exemplos few-shot no system prompt mostrando explicações completas para cinco tipos comuns de casos complexos, demonstrando como incluir contexto de política, timelines e próximos passos.','\n',char(10)),replace('## Explicação para um Adulto Tech Lead\n\n### Análise do Problema\n\nO diagnóstico é claro: o agente já **sabe a resposta correta** (a resolução técnica está acurada), mas falha na **comunicação da justificativa** — omite detalhes de política, timeline ou próximos passos. As lacunas são **variáveis caso a caso**, não seguem um padrão fixo. O objetivo é melhorar a qualidade **sem supervisão humana**.\n\n### Por que a Alternativa A é a mais efetiva\n\nA **auto-crítica** (ou autocorreção) é uma técnica bem estabelecida em sistemas LLM. O agente gera um rascunho da resposta e, em seguida, avalia esse rascunho contra critérios explícitos (completude, contexto relevante, antecipação de follow-ups). Isso resolve diretamente o problema de inconsistência nas justificativas, pois:\n\n1. **Ataca a causa-raiz**: as lacunas são variáveis (hora falta política, hora falta timeline) — a auto-crítica pode verificar todos os requisitos simultaneamente.\n2. **Não depende de padrões fixos**: como os problemas são diversos, um checklist universal de auto-avaliação cobre todos os casos, diferente de exemplos few-shot que podem não generalizar.\n3. **Sem supervisão humana**: o próprio modelo revisa e ajusta, dentro do mesmo loop de inferência.\n4. **Baixo custo incremental**: apenas uma chamada extra ao modelo (ou um segundo passo na mesma chamada) para a etapa de crítica.\n\n### Por que as demais alternativas são inferiores\n\n**Alternativa B (pergunta de confirmação ao cliente):**\n- Trata o sintoma, não a causa. O cliente continua recebendo uma explicação incompleta e precisa *reclamar ativamente* para obter mais informações.\n- A transferência da responsabilidade para o cliente pode gerar frustração adicional e reduzir ainda mais o CSAT.\n- Além disso, muitos clientes podem não saber *o que* está faltando na resposta para pedir complementação.\n\n**Alternativa C (trocar Haiku por Sonnet):**\n- Um modelo mais capaz (Sonnet vs Haiku) pode até gerar respostas ligeiramente melhores em média, mas **não garante consistência na completude das justificativas**. O problema fundamental (o modelo decidir o que incluir na explicação) permanece.\n- É uma abordagem mais cara (Sonnet custa mais) e não resolve a raiz: a falta de um **mecanismo de verificação**.\n- Se o Haiku com auto-crítica pode alcançar o resultado, pagar mais por Sonnet sem garantir a melhoria específica não é eficiente.\n\n**Alternativa D (few-shot prompts):**\n- É a abordagem mais tentadora dentre as erradas, mas falha porque as lacunas **variam caso a caso**. Cinco exemplos podem ensinar padrões para casos específicos, mas não garantem que o modelo generalize para todos os tipos de omissão.\n- Few-shot funciona bem quando a tarefa tem um formato consistente; aqui, cada caso complexo pode exigir uma combinação diferente de política, timeline e próximos passos.\n- A auto-crítica (A) é mais robusta por ser um **mecanismo de verificação universal**, enquanto few-shot é apenas um **estímulo para o comportamento desejado**, sem garantia de consistência.\n\n### Conclusão\n\nA auto-crítica (A) é a abordagem mais efetiva porque implementa um **loop de controle de qualidade interno ao agente**, atacando diretamente a causa-raiz (inconsistência nas justificativas) de forma escalável, sem supervisão humana e com custo controlado.','\n',char(10)),replace('Imagina que você tem um robô que ajuda a resolver problemas de clientes. O robô sempre descobre a resposta certa, mas às vezes esquece de explicar direito — tipo, ele diz "você vai receber o dinheiro de volta" mas não fala *quando* ou *por quê*. Isso deixa as pessoas insatisfeitas.\n\nA melhor solução é ensinar o robô a **revisar o que ele mesmo escreveu** antes de enviar a resposta, tipo quando você relê sua redação antes de entregar para a professora. Ele vai olhar e pensar: "Eu expliquei o motivo? Falei os próximos passos? Dei todos os detalhes?" Se faltar algo, ele completa. Isso resolve o problema porque o robô aprende a verificar sozinho se a explicação está completa.\n\nAs outras opções são piores:\n- Perguntar "resolvi seu problema?" para o cliente é chato — a pessoa já está frustrada e tem que pedir mais informação.\n- Trocar o robô por um mais inteligente é caro e não garante que ele vai lembrar de dar todos os detalhes.\n- Dar exemplos prontos de respostas ajuda um pouco, mas cada problema é diferente, então os exemplos podem não servir para todos os casos.\n\nA melhor ideia é o robô fazer uma **auto-avaliação** — igual quando você confere seu dever de casa antes de entregar!','\n',char(10)));
INSERT INTO cards VALUES('admin','card_1783092984761_8z053wzz5',110,'Agente de Suporte ao Cliente',replace('Agente de Suporte ao Cliente\n\nLogs de produção mostram um padrão consistente: quando clientes incluem a palavra "conta" em sua mensagem (ex.: "quero verificar minha conta de um pedido que fiz ontem"), o agente chama `get_customer` primeiro 78% das vezes. Quando clientes formulam pedidos similares sem "conta" (ex.: "quero verificar um pedido que fiz ontem"), chama `lookup_order` primeiro 93% das vezes. As descrições das ferramentas são claras e inequívocas. Qual a causa-raiz mais provável dessa discrepância?\n\n[ ] A - O system prompt contém instruções sensíveis a palavras-chave que direcionam comportamento baseado em termos como "conta", criando padrões não intencionais de seleção de ferramenta.\n[ ] B - O treinamento base do modelo cria associações entre terminologia de "conta" e operações relacionadas ao cliente que sobrepõem descrições de ferramentas.\n[ ] C - O modelo precisa de mais dados de treino sobre mensagens multi-conceito e deveria ser fine-tuned em exemplos contendo terminologias de conta e pedido.\n[ ] D - Descrições de ferramentas precisam de exemplos negativos adicionais especificando quando NÃO usar cada ferramenta para evitar essa confusão induzida por palavras-chave.','\n',char(10)),'B - O treinamento base do modelo cria associações entre terminologia de "conta" e operações relacionadas ao cliente que sobrepõem descrições de ferramentas.','["Domain_2::Tool_Design_MCP_Integration", "Domain_4::Prompt_Engineering_Structured_Output", "Scenario_1::Customer_Support_Agent"]','New',0,2.5,0,1783092984761,1783725639709,1783203558653,replace('**Tradução para português do Brasil:**\n\nAgente de Suporte ao Cliente\n\nLogs de produção mostram um padrão consistente: quando clientes incluem a palavra "conta" em sua mensagem (ex.: "quero verificar minha conta de um pedido que fiz ontem"), o agente chama `get_customer` primeiro 78% das vezes. Quando clientes formulam pedidos similares sem "conta" (ex.: "quero verificar um pedido que fiz ontem"), chama `lookup_order` primeiro 93% das vezes. As descrições das ferramentas são claras e inequívocas. Qual a causa-raiz mais provável dessa discrepância?\n\n[ ] A - O system prompt contém instruções sensíveis a palavras-chave que direcionam comportamento baseado em termos como "conta", criando padrões não intencionais de seleção de ferramenta.\n[ ] B - O treinamento base do modelo cria associações entre terminologia de "conta" e operações relacionadas ao cliente que sobrepõem descrições de ferramentas.\n[ ] C - O modelo precisa de mais dados de treino sobre mensagens multi-conceito e deveria ser fine-tuned em exemplos contendo terminologias de conta e pedido.\n[ ] D - Descrições de ferramentas precisam de exemplos negativos adicionais especificando quando NÃO usar cada ferramenta para evitar essa confusão induzida por palavras-chave.','\n',char(10)),replace('**Explicação técnica para tech lead:**\n\nA questão descreve um viés cognitivo não intencional no comportamento do modelo de linguagem. Vamos analisar cada alternativa.\n\n**Alternativa correta: B**\n\nO problema central é que o modelo foi treinado em um vasto corpus de texto onde a palavra "conta" está fortemente associada semanticamente a "cliente", "usuário", "perfil", "dados pessoais". Essa associação prévia (do treinamento base) é tão forte que, mesmo com descrições de ferramentas claras e inequívocas, o modelo tende a priorizar `get_customer` quando ouve "conta". Isso não é um problema de instrução no system prompt (A), nem de falta de exemplos negativos (D), nem de necessidade de fine-tuning (C) — embora fine-tuning pudesse mitigar, a causa raiz não é a falta dele. O modelo está sendo "vítima" de seu próprio conhecimento de mundo pré-treinado, onde "conta" → "cliente" é uma associação muito forte.\n\n**Por que as outras estão erradas:**\n\n- **A:** O system prompt pode conter instruções, mas o enunciado afirma que *as descrições das ferramentas são claras e inequívocas*, e a discrepância ocorre mesmo com instruções adequadas. Se fosse problema de system prompt, a correção seria imediata via ajuste de prompt, e a questão não seria tão sutil.\n\n- **C:** Fine-tuning poderia ajudar, mas não é a causa raiz. O modelo já foi treinado com muitos dados e, em teoria, já viu exemplos de "conta" e "pedido" juntos. A questão pergunta a *causa-raiz mais provável*, e não a melhor solução. A causa é a associação do treinamento base, não a falta de dados específicos.\n\n- **D:** Exemplos negativos são uma técnica válida, mas novamente são uma mitigação, não a causa raiz. O problema não é que as descrições são ambíguas; é que o modelo traz um viés pré-treinado que sobrepõe o que está nas descrições.','\n',char(10)),replace('Imagine que você tem um robô que ajuda a atender clientes. Esse robô tem duas funções: uma para procurar dados de um cliente (chamada `get_customer`) e outra para procurar um pedido (chamada `lookup_order`).\n\nQuando alguém diz "quero verificar minha **conta** de um pedido", o robô usa a função de cliente 78% das vezes. Mas se a pessoa diz só "quero verificar um pedido", ele usa a função de pedido 93% das vezes.\n\nPor que isso acontece? Porque o robô foi treinado lendo muitos textos da internet e livros, onde a palavra "conta" aparece muito junto com "cliente" (tipo "conta bancária", "minha conta", "conta de usuário"). Então, mesmo que as instruções das funções estejam bem claras, o robô "acha" que "conta" tem a ver com cliente, e acaba escolhendo a função errada muitas vezes.\n\nA alternativa B explica isso: o treinamento básico do robô criou associações tão fortes entre "conta" e "cliente" que ele meio que ignora as instruções certas. As outras opções falam em arrumar o problema de outros jeitos, mas a causa principal é essa "mania" que o robô já tem de tanto ler coisas na internet.','\n',char(10)));
INSERT INTO cards VALUES('admin','card_1783092984785_p9pqsumhi',111,'Agente de Suporte ao Cliente',replace('Agente de Suporte ao Cliente\n\nLogs de produção mostram que o agente às vezes escolhe `get_customer` quando `lookup_order` seria mais apropriado, especialmente para queries ambíguas como "preciso de ajuda com minha compra recente". Você decide adicionar exemplos few-shot ao system prompt para melhorar a seleção. Qual abordagem trata o problema de forma mais efetiva?\n\n[ ] A - Adicionar orientações explícitas "use quando" e "não use quando" em cada descrição de ferramenta cobrindo casos ambíguos.\n[ ] B - Adicionar exemplos agrupados por ferramenta — todos os cenários de `get_customer` juntos, depois todos os cenários de `lookup_order`.\n[ ] C - Adicionar 4–6 exemplos direcionados a cenários ambíguos, cada um com justificativa de por que uma ferramenta foi escolhida em detrimento de alternativas plausíveis.\n[ ] D - Adicionar 10–15 exemplos de pedidos claros e inequívocos demonstrando escolha correta para cenários típicos de cada ferramenta.','\n',char(10)),'C - Adicionar 4–6 exemplos direcionados a cenários ambíguos, cada um com justificativa de por que uma ferramenta foi escolhida em detrimento de alternativas plausíveis.','["Domain_4::Prompt_Engineering_Structured_Output", "Domain_2::Tool_Design_MCP_Integration", "Scenario_1::Customer_Support_Agent"]','New',0,2.5,0,1783092984785,1783725643638,1783203558653,replace('**Tradução para português do Brasil:**\n\n**Agente de Suporte ao Cliente**\n\nLogs de produção mostram que o agente às vezes escolhe `get_customer` quando `lookup_order` seria mais apropriado, especialmente para queries ambíguas como "preciso de ajuda com minha compra recente". Você decide adicionar exemplos few-shot ao system prompt para melhorar a seleção. Qual abordagem trata o problema de forma mais efetiva?\n\n[ ] A - Adicionar orientações explícitas "use quando" e "não use quando" em cada descrição de ferramenta cobrindo casos ambíguos.\n[ ] B - Adicionar exemplos agrupados por ferramenta — todos os cenários de `get_customer` juntos, depois todos os cenários de `lookup_order`.\n[ ] C - Adicionar 4–6 exemplos direcionados a cenários ambíguos, cada um com justificativa de por que uma ferramenta foi escolhida em detrimento de alternativas plausíveis.\n[ ] D - Adicionar 10–15 exemplos de pedidos claros e inequívocos demonstrando escolha correta para cenários típicos de cada ferramenta.','\n',char(10)),replace('**Explicação técnica para adulto (tech lead):**\n\nO problema central é que o agente enfrenta **ambiguidade semântica** em queries como "preciso de ajuda com minha compra recente". Essa frase pode ser interpretada como uma consulta ao cliente (`get_customer`) ou ao pedido (`lookup_order`). A abordagem mais eficaz para resolver isso via few-shot learning é:\n\n**Alternativa C - Correta.** Adicionar 4–6 exemplos direcionados a cenários ambíguos, cada um com justificativa explícita da escolha, ataca diretamente a raiz do problema. Few-shot learning se beneficia da qualidade e relevância dos exemplos, não da quantidade. Exemplos ambíguos com *chain-of-thought* (justificativa) ensinam o modelo a raciocinar sobre o contexto, desambiguando corretamente. A justificativa funciona como um "raciocínio guiado", alinhando o comportamento do modelo ao esperado.\n\n**Alternativa A - Incorreta.** Embora orientações explícitas ajudem, descrições de ferramenta são processadas de forma diferente pelo modelo — elas funcionam como definições estáticas, não como demonstrações de raciocínio. Adicionar "use quando" e "não use quando" em descrições existentes pode poluir a definição da ferramenta e não oferece ao modelo um exemplo concreto de *como* decidir em casos limítrofes.\n\n**Alternativa B - Incorreta.** Agrupar exemplos por ferramenta não ajuda o modelo a aprender a *discriminar* entre elas em casos ambíguos. Pelo contrário, isso pode reforçar associações incorretas — o modelo pode passar a associar certas palavras-chave a uma ferramenta específica, sem aprender a considerar o contexto global.\n\n**Alternativa D - Incorreta.** Exemplos claros e inequívocos (10–15) são redundantes para o problema. Queries ambíguas são justamente aquelas que não se encaixam perfeitamente em cenários típicos. Adicionar muitos exemplos óbvios consome tokens preciosos do contexto sem endereçar o ponto de falha real. O modelo já sabe lidar com casos óbvios; precisa de ajuda nos casos limítrofes.\n\nPortanto, a **alternativa C** é a mais efetiva por ser cirúrgica: exemplos em menor quantidade, mas de alta qualidade, focados exatamente no tipo de erro observado, com justificativa que ensina o raciocínio de desambiguação.','\n',char(10)),replace('Imagine que você tem dois brinquedos: um é uma caixa de ferramentas (`get_customer`) e o outro é um livro de receitas (`lookup_order`). Quando alguém diz "preciso de ajuda com minha compra recente", você fica na dúvida: deve pegar a caixa de ferramentas ou o livro de receitas?\n\nAgora, seu amigo quer te ajudar e pode te dar dicas. Vamos ver qual dica ajuda mais:\n\n- **Dica A:** Ele escreve na caixa de ferramentas "use quando for sobre o cliente" e no livro "use quando for sobre o pedido". Mas isso não te ajuda a decidir quando a frase é confusa.\n\n- **Dica B:** Ele mostra 10 exemplos de como usar a caixa de ferramentas e depois 10 de como usar o livro, separados. Mas os exemplos são todos fáceis, tipo "qual é o nome do cliente?" ou "qual é o número do pedido?". Isso não te ajuda na hora da dúvida.\n\n- **Dica C (a melhor!):** Ele mostra uns 4 ou 5 exemplos bem parecidos com a sua dúvida, e para cada um ele explica: "Aqui a pessoa disse ''comprei algo'', então é melhor pegar o livro de receitas porque ela quer saber sobre o pedido, não sobre quem ela é." Essa dica te ensina a pensar, não só a decorar!\n\n- **Dica D:** Ele mostra 15 exemplos de perguntas muito fáceis e óbvias. Isso gasta bastante tempo e não ajuda em nada na hora que a pergunta é difícil.\n\nEntão, a melhor maneira de aprender é com **poucos exemplos, mas bem escolhidos, que ensinam o raciocínio** em vez de mostrar muitas coisas fáceis.','\n',char(10)));
INSERT INTO cards VALUES('admin','card_1783092984796_zuwnv6c2c',112,'Padrões de Arquitetura de IA Conversacional',replace('Padrões de Arquitetura de IA Conversacional\n\nDurante testes de QA, Claude segue diretrizes do system prompt nos primeiros 10–15 turnos, mas respostas posteriores desviam. A conversa ainda está dentro dos limites de tokens.\n\nQual a melhor solução?\n\n[ ] A - Mover diretrizes comportamentais para a primeira mensagem do usuário.\n[ ] B - Iniciar nova conversa após 20 turnos.\n[ ] C - Inserir mensagens com role user reforçando diretrizes em pontos de interrupção da conversa.\n[ ] D - Usar validação pós-resposta para regenerar respostas não conformes.','\n',char(10)),'C - Inserir mensagens com role user reforçando diretrizes em pontos de interrupção da conversa.','["Domain_1::Agentic_Architecture_Orchestration", "Domain_5::Context_Management_Reliability", "Domain_4::Prompt_Engineering_Structured_Output", "Scenario_1::Customer_Support_Agent"]','New',0,2.5,0,1783092984796,1783725647713,1783203558653,replace('**Tradução para pt-BR:**\n\n**Padrões de Arquitetura de IA Conversacional**\n\nDurante testes de QA, Claude segue diretrizes do system prompt nos primeiros 10–15 turnos, mas respostas posteriores desviam. A conversa ainda está dentro dos limites de tokens.\n\nQual a melhor solução?\n\n[ ] A - Mover diretrizes comportamentais para a primeira mensagem do usuário.\n[ ] B - Iniciar nova conversa após 20 turnos.\n[ ] C - Inserir mensagens com role user reforçando diretrizes em pontos de interrupção da conversa.\n[ ] D - Usar validação pós-resposta para regenerar respostas não conformes.','\n',char(10)),replace('**Explicação para um adulto tech lead:**\n\nO problema descrito é um fenômeno conhecido em modelos de linguagem: **atenção decay ou recency bias**. Mesmo que a conversa não tenha estourado o limite de tokens, o modelo tende a dar peso progressivamente maior aos turnos mais recentes, "esquecendo" instruções posicionadas no system prompt (ou no início do contexto). Isso é agravado pelo fato de que o system prompt, embora estruturalmente separado, compete com o histórico de conversa por atenção no mecanismo de self-attention do transformer.\n\n**Análise das alternativas:**\n\n❌ **A - Mover diretrizes para a primeira mensagem do usuário.** Isso não resolve o problema fundamental: o conteúdo ainda ficará no início do contexto e sofrerá do mesmo fenômeno de "atenção decay" à medida que a conversa avança. Na verdade, pode piorar, pois perde-se a distinção estrutural que o system prompt oferece em algumas implementações de API (onde ele é tratado com prioridade ou repetido internamente).\n\n❌ **B - Iniciar nova conversa após 20 turnos.** É uma solução drástica e ineficiente. Forçar o reinício da conversa quebra o fluxo natural, perde contexto acumulado e aumenta significativamente o custo operacional (novas chamadas de API, necessidade de reestabelecer estado). Além disso, é arbitrária — o problema pode ocorrer antes de 20 turnos, dependendo da complexidade das diretrizes.\n\n✅ **C - Inserir mensagens com role user reforçando diretrizes em pontos de interrupção.** Esta é a abordagem mais elegante e alinhada com a arquitetura do transformer. Ao reinserir as diretrizes periodicamente como mensagens do usuário, você as reposiciona no final do contexto (onde o modelo concentra mais atenção), sem quebrar a continuidade da conversa. Isso mitiga o recency bias a favor das instruções. É uma técnica conhecida como "instruction refreshing" ou "contextual anchoring" — usada em sistemas como o ChatGPT (onde o system prompt é reenviado periodicamente nos bastidores).\n\n❌ **D - Usar validação pós-resposta para regenerar respostas não conformes.** Isso é reativo, não preventivo. Você está deixando o erro acontecer para depois corrigi-lo, o que gera latência adicional (duas chamadas de API em vez de uma), desperdício de tokens e experiência de usuário degradada (a regeneração pode falhar ou gerar conteúdo inconsistente). É um "tapetão", não uma solução arquitetural.\n\n**Conclusão:** A alternativa C é a que melhor resolve a causa raiz (recency bias) com o menor custo e maior elegância arquitetural.','\n',char(10)),replace('**Explicação para uma criança de 10 anos:**\n\nImagine que você é um robô que conversa com as pessoas. No começo, você lembra direitinho das regras que seus pais te ensinaram: "seja educado", "não conte segredos", etc. Mas depois de um tempinho conversando, você vai ficando mais distraído e começa a esquecer dessas regras.\n\nAs opções são:\n\nA - Colocar as regras logo na primeira fala da pessoa. Mas isso não adianta, porque você ainda vai esquecer depois de um tempo.\n\nB - Começar uma conversa nova do zero a cada 20 falas. Isso é chato porque você perde tudo que conversou antes e parece que não lembrou de nada.\n\nC - De vez em quando, a pessoa que está conversando com você repete as regras no meio da conversa. Isso ajuda você a lembrar! É como se seus pais te lembrassem: "Ei, não esquece das regras!" no meio do papo.\n\nD - Deixar você falar besteira e depois apagar e pedir para você falar de novo. Isso é trabalhoso e demorado, melhor prevenir do que remediar.\n\nA melhor opção é a C, porque você lembra das regras sem precisar recomeçar a conversa do zero.','\n',char(10)));
INSERT INTO cards VALUES('admin','card_1783092984806_841twx060',113,'Padrões de Arquitetura de IA Conversacional',replace('Padrões de Arquitetura de IA Conversacional\n\nSeu assistente precisa manter um tom entusiástico, explicar seu raciocínio e fazer perguntas esclarecedoras. Onde essas diretrizes comportamentais devem ser definidas?\n\n[ ] A - Prependendo a cada mensagem do usuário.\n[ ] B - No system prompt.\n[ ] C - Na primeira mensagem do assistente.\n[ ] D - Em variáveis de ambiente.','\n',char(10)),'[ ] B - No system prompt.','["Domain_4::Prompt_Engineering_Structured_Output", "ForaDoCenario"]','New',0,2.5,0,1783092984806,1783725651469,1783203558653,replace('**Tradução para pt-BR:**\n\nPadrões de Arquitetura de IA Conversacional\n\nSeu assistente precisa manter um tom entusiástico, explicar seu raciocínio e fazer perguntas esclarecedoras. Onde essas diretrizes comportamentais devem ser definidas?\n\n[ ] A - Prependendo a cada mensagem do usuário.\n[ ] B - No system prompt.\n[ ] C - Na primeira mensagem do assistente.\n[ ] D - Em variáveis de ambiente.','\n',char(10)),replace('**Explicação para um adulto tech lead:**\n\nA resposta correta é a alternativa B: **No system prompt**.\n\n**Por que a B está correta:**\n\nO system prompt (ou "instrução do sistema") é o local designado, na arquitetura de modelos de linguagem (LLMs), para definir o comportamento, a personalidade, o tom e as diretrizes gerais que o assistente deve seguir durante toda a conversa. Ele é enviado uma vez no início da interação (ou de forma recorrente em cada chamada) e serve como a "constituição" do agente conversacional. Nele, você estabelece regras como "mantenha um tom entusiástico", "explique seu raciocínio passo a passo" e "faça perguntas esclarecedoras antes de responder". Essas instruções são aplicadas consistentemente em todas as respostas, sem necessidade de repetição.\n\n**Por que as demais alternativas estão incorretas:**\n\n- **A - Prependendo a cada mensagem do usuário:** Essa abordagem é ineficiente, redundante e pode poluir o contexto de forma desnecessária. Além disso, o modelo pode não interpretar corretamente se essas instruções forem misturadas com o histórico da conversa, especialmente se houver muitas mensagens. Também aumenta o custo computacional (tokens) e o risco de "derrapagem" (a instrução pode ser ignorada ou mal interpretada ao longo do tempo).\n\n- **C - Na primeira mensagem do assistente:** Colocar as instruções na primeira resposta do assistente pode funcionar de forma limitada, mas não garante que o comportamento seja mantido em turnos subsequentes da conversa. O modelo não tem uma "memória" explícita de que aquela mensagem continha regras; ele apenas a vê como parte do histórico. Em conversas longas, as diretrizes podem ser "esquecidas" ou perder relevância devido ao deslocamento de contexto (context window) e ao efeito de atenção que prioriza mensagens mais recentes.\n\n- **D - Em variáveis de ambiente:** Variáveis de ambiente são um mecanismo de configuração do sistema operacional ou do ambiente de execução (como chaves de API, URLs de endpoints, etc.). Elas não são acessíveis ao modelo de linguagem durante a inferência, a menos que sejam explicitamente injetadas no prompt. Mesmo que fossem injetadas, o local correto para instruções comportamentais ainda seria o system prompt, e não uma variável de ambiente, que é um conceito de infraestrutura, não de design de prompt.','\n',char(10)),replace('Imagine que você está conversando com um robô amigo. Antes da conversa começar, você dá a ele um "livro de regras" dizendo: "Você deve ser animado, explicar tudo que pensa e fazer perguntas para entender melhor."\n\n**Alternativa B (No system prompt)** é o lugar certo para colocar esse "livro de regras". É como se fosse uma instrução secreta que você dá para o robô no começo, e ele segue direitinho o tempo todo.\n\nAs outras opções não são tão boas:\n- A - Seria como colocar essas regras no MEIO da conversa, toda hora, o que é chato e bagunçado.\n- C - Seria como dizer as regras só na primeira resposta do robô, mas depois ele pode se esquecer.\n- D - Seria como guardar as regras em um armário fechado, que o robô não consegue abrir para ler.\n\nEntão, o melhor lugar para dar as instruções de comportamento é logo no início, no "system prompt" — o livrinho de regras do robô!','\n',char(10)));
INSERT INTO cards VALUES('admin','card_1783092984817_gt0et7nba',114,'Padrões de Arquitetura de IA Conversacional',replace('Padrões de Arquitetura de IA Conversacional\n\nUsuários reportam aberturas de resposta repetitivas como "Certamente!" e "Ficarei feliz em ajudar!".\n\nQual a abordagem mais efetiva?\n\n[ ] A - Anexar uma mensagem parcial do assistente com uma abertura direta.\n[ ] B - Reduzir o ajuste de temperatura.\n[ ] C - Pós-processar respostas para remover saudações.\n[ ] D - Adicionar instruções no system prompt para evitar essas frases.','\n',char(10)),'D - Adicionar instruções no system prompt para evitar essas frases.','["Domain_4::Prompt_Engineering_Structured_Output", "ForaDoCenario"]','New',0,2.5,0,1783092984817,1783725655445,1783203558653,replace('Tradução para Português do Brasil:\n\n**Padrões de Arquitetura de IA Conversacional**\n\nUsuários reportam aberturas de resposta repetitivas como "Certamente!" e "Ficarei feliz em ajudar!".\n\nQual a abordagem mais efetiva?\n\n[ ] A - Anexar uma mensagem parcial do assistente com uma abertura direta.\n[ ] B - Reduzir o ajuste de temperatura.\n[ ] C - Pós-processar respostas para remover saudações.\n[ ] D - Adicionar instruções no system prompt para evitar essas frases.','\n',char(10)),replace('**Explicação para um adulto tech lead:**\n\nA abordagem mais eficaz é a **D - Adicionar instruções no system prompt para evitar essas frases.**\n\n**Por que a D é a correta?**\nO system prompt é a camada mais profunda de controle comportamental do modelo. Instruções claras e explícitas no system prompt, como "Não use saudações como ''Certamente!'' ou ''Ficarei feliz em ajudar!''. Vá direto ao ponto.", atuam diretamente no alinhamento do modelo (instruction following / RLHF). Isso resolve o problema na origem, antes mesmo do texto ser gerado. É uma solução de baixo custo computacional (apenas alguns tokens a mais no prompt), fácil de iterar via A/B testing, e não interfere na criatividade ou distribuição de probabilidades do modelo.\n\n**Análise das alternativas incorretas:**\n\n- **A - Anexar uma mensagem parcial do assistente com uma abertura direta.** Essa técnica (prefix priming) pode funcionar em alguns casos, mas é frágil. O modelo pode "completar" a mensagem parcial de forma inconsistente, eventualmente gerando a saudação indesejada mesmo após o priming. Além disso, não resolve a causa raiz e adiciona complexidade desnecessária, especialmente em sistemas com múltiplos turnos de conversa.\n\n- **B - Reduzir o ajuste de temperatura.** Temperatura controla a aleatoriedade da amostragem (sampling). Reduzi-la torna o modelo mais determinístico e conservador, mas não elimina seletivamente saudações. O modelo ainda pode gerar "Certamente!" com alta probabilidade. Na verdade, temperatura baixa pode até *reforçar* comportamentos repetitivos e estereotipados, piorando o problema.\n\n- **C - Pós-processar respostas para remover saudações.** Essa é uma abordagem reativa e frágil. Você teria que manter uma lista de saudações a serem removidas, lidar com edge cases (e.g., respostas que são *apenas* a saudação), e o risco de remover conteúdo genuíno que contém palavras similares. É um paliativo, não uma solução. Além disso, adiciona latência e complexidade de manutenção.','\n',char(10)),replace('Imagine que você tem um robô que, toda vez que você pergunta algo, ele responde "Claro!" ou "Feliz em ajudar!". Isso fica chato, né?\n\nTem quatro jeitos de tentar consertar isso:\n\n**A)** Mostrar para o robô um pedaço de resposta já começando sem a saudação, na esperança que ele continue daquele jeito. Mas o robô pode ignorar e voltar a falar "Claro!" do nada.\n\n**B)** Deixar o robô menos criativo, mais "quadrado". Mas ele ainda pode falar "Claro!" porque é o que ele mais conhece. Pior: pode ficar ainda mais repetitivo!\n\n**C)** Depois que o robô falar, apagar a saudação com um programa. Mas aí você precisa adivinhar todas as saudações possíveis, e corre o risco de apagar palavras importantes por engano.\n\n**D)** Ensinar o robô, bem no início da conversa, que ele não deve usar essas saudações. É como dar uma regra clara para ele: "Nada de ''Claro!'' ou ''Feliz em ajudar!'', vai direto ao assunto." O robô obedece porque entendeu a regra antes mesmo de começar a falar.\n\n**Resposta certa: D - Adicionar instruções no system prompt para evitar essas frases.** É o jeito mais simples e que resolve o problema de verdade!','\n',char(10)));
INSERT INTO cards VALUES('admin','card_1783092984827_fpl3guzdr',115,'Padrões de Arquitetura de IA Conversacional',replace('Padrões de Arquitetura de IA Conversacional\n\nUm webhook notifica seu sistema de que o pacote do usuário foi enviado enquanto o usuário está conversando ativamente. Você quer que o assistente incorpore isso naturalmente na próxima resposta.\n\nQual a melhor abordagem?\n\n[ ] A - Adicionar status de envio ao system prompt.\n[ ] B - Enviar imediatamente uma mensagem sintética do usuário.\n[ ] C - Forçar o assistente a chamar uma ferramenta de status a cada turno.\n[ ] D - Anexar a atualização de status como prefixo à próxima mensagem do usuário.','\n',char(10)),'D - Anexar a atualização de status como prefixo à próxima mensagem do usuário.','["Domain_1::Agentic_Architecture_Orchestration", "Domain_5::Context_Management_Reliability", "Scenario_1::Customer_Support_Agent"]','New',0,2.5,0,1783092984827,1783725659388,1783203558653,replace('**Tradução para Português do Brasil:**\n\nPadrões de Arquitetura de IA Conversacional\n\nUm webhook notifica seu sistema de que o pacote do usuário foi enviado enquanto o usuário está conversando ativamente. Você quer que o assistente incorpore isso naturalmente na próxima resposta.\n\nQual a melhor abordagem?\n\n[ ] A - Adicionar status de envio ao system prompt.\n[ ] B - Enviar imediatamente uma mensagem sintética do usuário.\n[ ] C - Forçar o assistente a chamar uma ferramenta de status a cada turno.\n[ ] D - Anexar a atualização de status como prefixo à próxima mensagem do usuário.','\n',char(10)),replace('**Explicação para um adulto (Tech Lead):**\n\n**Alternativa Correta: D**\n\nO cenário descreve um evento assíncrono (webhook de envio de pacote) que precisa ser incorporado em uma conversa síncrona em andamento. A abordagem D é a mais elegante por várias razões:\n\n- **Preserva o contexto conversacional**: Ao anexar a atualização de status como prefixo (ex.: "[Atualização: pacote enviado]") à próxima mensagem do usuário, o assistente recebe essa informação no momento natural do diálogo — ou seja, quando o usuário fala. Isso permite que o modelo responda de forma coerente, como se "tomasse conhecimento" do evento e reagisse apropriadamente.\n\n- **Não quebra o ciclo de turnos**: Diferentemente de B (enviar mensagem sintética), essa abordagem respeita o fluxo normal de requisição-resposta. O usuário continua no controle do turno, e o assistente responde com base no input + contexto adicional.\n\n- **Não polui o system prompt**: A alternativa A aumenta o tamanho do prompt de sistema com estados mutáveis, o que degrada performance e aumenta custos (tokens). System prompt deve ser estável e conter instruções fixas, não dados voláteis.\n\n- **Não adiciona overhead desnecessário**: A alternativa C força o assistente a chamar uma ferramenta a cada turno para verificar status, o que gera latência, custo adicional de chamadas de ferramenta e complexidade desnecessária. Isso só se justificaria se a informação fosse crucial em todo turno, o que não é o caso aqui.\n\n**Por que as demais estão erradas:**\n\n- **A**: Adicionar ao system prompt torna o estado dinâmico misturado com instruções estáticas. System prompt não é reavaliado a cada resposta automaticamente — normalmente é enviado apenas no início da conversa. Além disso, isso não garante que o assistente vá agir sobre a informação no próximo turno.\n\n- **B**: Enviar mensagem sintética do usuário é arriscado porque o modelo pode interpretar que o "usuário" está falando sobre o pacote, criando estranheza. O usuário real não escreveu aquilo. Isso quebra a ilusão de naturalidade e pode gerar respostas confusas ou repetitivas.\n\n- **C**: Chamar tool de status a cada turno é ineficiente e desnecessário. A informação só precisa ser consumida uma vez. Isso adiciona latência, consome tokens e força o modelo a tomar uma decisão de ação mesmo quando não há nada novo.\n\n- **D**: É a abordagem padrão em arquiteturas conversacionais modernas (ex.: padrão "Context Injection" ou "Event-to-Conversation Bridge"). Você intercepta a próxima mensagem do usuário e adiciona o evento como metadado prefixado. O assistente responde naturalmente como se tivesse "visto" a informação.','\n',char(10)),replace('Imagine que você está conversando com um amigo no telefone sobre seu brinquedo favorito. De repente, sua mãe chega e diz que o brinquedo novo que você pediu já foi enviado pelos Correios.\n\nSe você simplesmente continuar falando sem contar isso, seu amigo não vai saber. A melhor maneira é: na hora em que você for falar alguma coisa, você primeiro diz "Ah, minha mãe acabou de falar que meu brinquedo foi enviado!" e só depois continua o papo.\n\nIsso é exatamente o que a opção D faz: o sistema "cola" a notícia do pacote na frente da próxima fala do usuário, como se fosse um lembrete. Assim, o assistente (que é tipo seu amigo na conversa) vai ouvir a novidade e responder algo legal, tipo "Que legal! Seu brinquedo está a caminho!"\n\nAs outras opções não são tão boas:\n\n- A seria como se você escrevesse a notícia num post-it e colasse na testa antes de começar a conversa — não faz sentido mudar isso no meio do papo.\n- B seria como interromper a conversa e fingir que o usuário disse algo que ele não disse. Isso confunde todo mundo.\n- C seria perguntar a cada minuto "Ei, o pacote já foi enviado?" mesmo quando não há novidade. Perda de tempo!\n\nEntão, a opção D é a mais natural: só contar a novidade na hora certa, junto com a próxima fala.','\n',char(10)));
INSERT INTO cards VALUES('admin','card_1783092984837_gwr2q9wtr',116,'Padrões de Arquitetura de IA Conversacional',replace('Padrões de Arquitetura de IA Conversacional\n\nUsuários frequentemente enviam pedidos como "Reserve um local para a festa". O assistente faz 4+ perguntas esclarecedoras, causando 35% de abandono.\n\nQual abordagem melhora melhor o trade-off?\n\n[ ] A - Prosseguir com defaults ocultos.\n[ ] B - Fazer todas as perguntas esclarecedoras em uma única mensagem composta.\n[ ] C - Declarar suposições explicitamente e prosseguir convidando correções.\n[ ] D - Usar um formulário estruturado de coleta.','\n',char(10)),'C - Declarar suposições explicitamente e prosseguir convidando correções.','["Domain_1::Agentic_Architecture_Orchestration", "Domain_4::Prompt_Engineering_Structured_Output", "Scenario_1::Customer_Support_Agent"]','New',0,2.5,0,1783092984837,1783725663965,1783203558653,replace('**Tradução para português do Brasil:**\n\n**Padrões de Arquitetura de IA Conversacional**\n\nUsuários frequentemente enviam pedidos como "Reserve um local para a festa". O assistente faz 4+ perguntas esclarecedoras, causando 35% de abandono.\n\nQual abordagem melhora melhor o trade-off?\n\n[ ] A - Prosseguir com defaults ocultos.\n[ ] B - Fazer todas as perguntas esclarecedoras em uma única mensagem composta.\n[ ] C - Declarar suposições explicitamente e prosseguir convidando correções.\n[ ] D - Usar um formulário estruturado de coleta.','\n',char(10)),replace('**Explicação didática para um adulto tech lead:**\n\nO problema apresentado é um clássico trade-off em UX conversacional: quanto mais o assistente pergunta para garantir precisão, maior a taxa de abandono. A alternativa C é a abordagem que melhor equilibra eficiência e acurácia.\n\n**Por que C é a resposta correta:**\n\n- **Abordagem "guess and correct"**: O assistente faz uma suposição educada com base no contexto e no conhecimento do domínio, declara explicitamente essas suposições ("Vou assumir que você quer reservar para 20 pessoas, neste sábado, às 19h") e prossegue com a ação, convidando o usuário a corrigir se necessário.\n- Isso reduz drasticamente o atrito: o usuário não precisa responder a 4+ perguntas, mas pode confirmar ou ajustar em uma única interação.\n- É um padrão consolidado em sistemas conversacionais maduros (ex: assistentes de reserva, agendamento) e está alinhado com princípios de design centrado no usuário, como o princípio de "antecipação" (antecipar necessidades) e "redução de carga cognitiva".\n\n**Por que as demais alternativas estão erradas:**\n\n- **A - Prosseguir com defaults ocultos**: Embora reduza o atrito, essa abordagem é problemática porque o usuário não sabe quais defaults foram usados. Isso quebra a previsibilidade e a confiança, e viola o princípio de transparência. Se o default estiver errado, o resultado será incorreto sem que o usuário tenha chance de corrigir antes de executar.\n- **B - Fazer todas as perguntas esclarecedoras em uma única mensagem composta**: Isso pode até reduzir o número de turnos, mas ainda exige que o usuário processe e responda múltiplas perguntas de uma vez, o que aumenta a carga cognitiva e ainda pode levar a abandono. Além disso, a experiência não é fluida — o usuário pode se sentir sobrecarregado.\n- **D - Usar um formulário estruturado de coleta**: Embora formulários sejam adequados para interfaces gráficas, em um canal conversacional eles são inadequados. O formato de chat não é otimizado para renderização de formulários complexos, e forçar o usuário a preencher campos em uma conversa quebra a naturalidade da interação. A taxa de abandono tende a ser alta.','\n',char(10)),replace('Imagine que você pede para um amigo: "Reserve um lugar para minha festa!". Se ele fizer 4 perguntas seguidas ("Quantas pessoas? Que dia? Que horas? Onde?"), você pode ficar cansado e desistir — e isso acontece com 35 em cada 100 pessoas.\n\nA melhor ideia é o amigo (o assistente) **tentar adivinhar o que você quer** com base no que já sabe, falar alto o palpite e perguntar: "Está certo? Se não, me corrija!". Por exemplo: "Vou reservar para 20 pessoas, neste sábado, às 19h. Tudo bem?". Assim você só precisa dizer "sim" ou ajustar uma coisinha.\n\nA opção C é a que faz exatamente isso: **declara as suposições na cara e pede correção**. É como ter um amigo que tenta ajudar sem encher o saco, mas ainda dá chance de você arrumar se ele errar.\n\nAs outras opções são piores:\n- A (defaults escondidos) é como alguém que faz tudo escondido e você descobre depois — sem chance de corrigir.\n- B (todas as perguntas de uma vez) ainda te obriga a responder várias coisas, o que cansa.\n- D (formulário) é legal em site, mas num chat é chato e difícil de preencher.','\n',char(10)));
INSERT INTO cards VALUES('admin','card_1783092984846_uya77pqs5',117,'Padrões de Arquitetura de IA Conversacional',replace('Padrões de Arquitetura de IA Conversacional\n\nUsuários fazem pedidos vagos como "Pode ajudar com o relatório?". O assistente responde fazendo várias perguntas (qual relatório? que ajuda? prazo?), causando 40% de abandono.\n\nQual a melhor solução?\n\n[ ] A - Fazer suposições razoáveis, declará-las explicitamente e oferecer ajustes.\n[ ] B - Classificar a ambiguidade com um modelo menor antes de responder.\n[ ] C - Usar interpretações predefinidas sem declarar suposições.\n[ ] D - Limitar o assistente a uma pergunta esclarecedora por turno.','\n',char(10)),'A - Fazer suposições razoáveis, declará-las explicitamente e oferecer ajustes.','["Domain_1::Agentic_Architecture_Orchestration", "Domain_4::Prompt_Engineering_Structured_Output", "Domain_5::Context_Management_Reliability", "Scenario_1::Customer_Support_Agent"]','New',0,2.5,0,1783092984846,1783725667866,1783203558653,replace('**Tradução para português do Brasil:**\n\n**Padrões de Arquitetura de IA Conversacional**\n\nUsuários fazem pedidos vagos como "Pode ajudar com o relatório?". O assistente responde fazendo várias perguntas (qual relatório? que ajuda? prazo?), causando 40% de abandono.\n\nQual a melhor solução?\n\n[ ] A - Fazer suposições razoáveis, declará-las explicitamente e oferecer ajustes.\n[ ] B - Classificar a ambiguidade com um modelo menor antes de responder.\n[ ] C - Usar interpretações predefinidas sem declarar suposições.\n[ ] D - Limitar o assistente a uma pergunta esclarecedora por turno.','\n',char(10)),replace('**Explicação para um adulto (tech lead):**\n\nO problema central é o alto índice de abandono (40%) causado por um padrão de "bombardeio de perguntas" — o assistente, ao detectar ambiguidade, dispara múltiplas perguntas de esclarecimento de uma só vez, sobrecarregando o usuário.\n\nVamos analisar cada alternativa:\n\n- **A (Correta):** Fazer suposições razoáveis, declará-las explicitamente e oferecer ajustes. Esta abordagem segue o princípio de design conhecido como "guess, not ask" (adivinhe, não pergunte). Ao assumir um contexto provável (ex.: relatório mais recente, tipo de ajuda mais comum, prazo padrão) e declarar essa suposição, o assistente reduz a carga cognitiva do usuário, que só precisa confirmar ou corrigir. Isso diminui drasticamente o atrito e o abandono.\n\n- **B (Incorreta):** Classificar a ambiguidade com um modelo menor antes de responder. Isso adiciona latência e complexidade arquitetural (dois modelos, orquestração) sem resolver o problema de fundo — o usuário ainda será bombardeado com perguntas. A classificação prévia pode até piorar a experiência se o modelo menor for impreciso.\n\n- **C (Incorreta):** Usar interpretações predefinidas sem declarar suposições. Isso viola o princípio de transparência da UX. O usuário receberá uma ação que pode não corresponder à sua intenção, sem saber o que foi assumido, gerando frustração e retrabalho (desfazer a ação incorreta).\n\n- **D (Incorreta):** Limitar o assistente a uma pergunta esclarecedora por turno. Embora reduza o bombardeio, ainda mantém o padrão de "inquisição": o usuário terá que responder a múltiplos turnos sequenciais para cada esclarecimento, alongando a conversa e aumentando o risco de abandono a cada turno.\n\n**Conclusão técnica:** A alternativa A é a mais alinhada com práticas modernas de design conversacional (proactivity, transparency, and confirmation pattern), equilibrando eficiência (reduz turnos) com transparência (declara suposições) e controle do usuário (oferece ajustes).','\n',char(10)),replace('Imagine que você pede para um robô: "Me ajuda com o trabalho?". O robô começa a fazer mil perguntas: "Qual trabalho? Que matéria? Pra quando é?". Aí você desiste e vai embora — 40 em cada 100 pessoas fazem isso!\n\nA melhor solução é o robô **tentar adivinhar** o que você quer (com base no que já sabe), **falar em voz alta** o que ele está achando, e **perguntar se está certo**. Por exemplo: "Vou assumir que é o trabalho de Ciências, que você quer ajuda para revisar, e que o prazo é sexta. Está certo?".\n\nAssim, você só precisa dizer "sim" ou corrigir rapidinho, sem responder um monte de perguntas. É mais rápido e menos chato!\n\nAs outras opções não funcionam tão bem:\n- A opção B usa um robô menor para pensar antes, mas ainda faz muitas perguntas depois.\n- A opção C faz o robô agir sem avisar o que ele está pensando — se ele errar, você fica confuso.\n- A opção D faz o robô perguntar uma coisa de cada vez, mas aí demora muitos turnos até ele entender tudo.','\n',char(10)));
INSERT INTO cards VALUES('admin','card_1783092984856_ubtrg13v9',118,'Revisões em produção revelam um tratamento inconsistente da incerteza nos relatórios finais.',replace('Revisões em produção revelam um tratamento inconsistente da incerteza nos relatórios finais.\n\nRevisões em produção revelam um tratamento inconsistente da incerteza nos relatórios finais. Às vezes, descobertas conflitantes dos subagentes são sintetizadas em uma única afirmação confiante (perdendo a nuance), enquanto outras vezes os relatórios fazem ressalvas em excesso com qualificações exageradas (tornando-se inúteis). Quando o agente de busca na web retorna "analistas do setor estimam um mercado de US$ 50 bi (a metodologia varia)" e o agente de análise de documentos retorna "estudo revisado por pares estima 35 bi (±7 bi, IC 95%)", o coordenador ou escolhe um arbitrariamente ou produz afirmações vagas como "o mercado pode ser de 35 bi a 50 bi dependendo de fatores".\n\nQual abordagem sistemática aborda melhor isso?\n\n[ ] A - Configurar os subagentes para relatar apenas descobertas que atendam a um limite de alta confiança, filtrando informações incertas antes que cheguem ao coordenador.\n[ ] B - Implementar uma camada de calibração de confiança que normaliza as expressões de incerteza dos subagentes em pontuações de probabilidade padronizadas (0,0 a 1,0) e, em seguida, faz a média ponderada das descobertas por sua confiança calibrada.\n[ ] C - Instruir o agente de síntese a estruturar os relatórios com seções explícitas que distinguem descobertas bem estabelecidas das contestadas, preservando as caracterizações das fontes originais e o contexto metodológico.\n[ ] D - Adicionar um subagente de verificação que faz referência cruzada das descobertas entre as fontes, passando para a síntese apenas as afirmações corroboradas por ao menos duas fontes independentes.','\n',char(10)),'[ ] C - Instruir o agente de síntese a estruturar os relatórios com seções explícitas que distinguem descobertas bem estabelecidas das contestadas, preservando as caracterizações das fontes originais e o contexto metodológico.','["Domain_1::Agentic_Architecture_Orchestration", "Domain_4::Prompt_Engineering_Structured_Output", "Scenario_3::Multi_Agent_Research"]','New',0,2.5,0,1783092984856,1783725671411,1783203558653,replace('**Tradução para pt-BR:**\n\nRevisões em produção revelam um tratamento inconsistente da incerteza nos relatórios finais. Às vezes, descobertas conflitantes dos subagentes são sintetizadas em uma única afirmação confiante (perdendo a nuance), enquanto outras vezes os relatórios fazem ressalvas em excesso com qualificações exageradas (tornando-se inúteis). Quando o agente de busca na web retorna "analistas do setor estimam um mercado de US$ 50 bi (a metodologia varia)" e o agente de análise de documentos retorna "estudo revisado por pares estima 35 bi (±7 bi, IC 95%)", o coordenador ou escolhe um arbitrariamente ou produz afirmações vagas como "o mercado pode ser de 35 bi a 50 bi dependendo de fatores".\n\nQual abordagem sistemática aborda melhor isso?\n\n[ ] A - Configurar os subagentes para relatar apenas descobertas que atendam a um limite de alta confiança, filtrando informações incertas antes que cheguem ao coordenador.\n[ ] B - Implementar uma camada de calibração de confiança que normaliza as expressões de incerteza dos subagentes em pontuações de probabilidade padronizadas (0,0 a 1,0) e, em seguida, faz a média ponderada das descobertas por sua confiança calibrada.\n[ ] C - Instruir o agente de síntese a estruturar os relatórios com seções explícitas que distinguem descobertas bem estabelecidas das contestadas, preservando as caracterizações das fontes originais e o contexto metodológico.\n[ ] D - Adicionar um subagente de verificação que faz referência cruzada das descobertas entre as fontes, passando para a síntese apenas as afirmações corroboradas por ao menos duas fontes independentes.','\n',char(10)),replace('**Explicação para adulto (tech lead):**\n\nO problema central é a **perda de nuance** na comunicação da incerteza. As fontes originais trazem informação valiosa sobre o nível de confiança — uma estimativa de mercado com metodologia questionável vs. um estudo revisado por pares com intervalo de confiança. O coordenador atual está jogando essa informação fora.\n\n**Análise das alternativas:**\n\n- **Alternativa A (filtrar por limite de confiança):** é uma abordagem binária e descartável. Você perde informação ao jogar fora dados úteis que não atingem um limiar arbitrário. Pior, se o limiar for alto demais, você pode ficar sem dados; se for baixo, o problema persiste. Não resolve a nuance, apenas a oculta.\n\n- **Alternativa B (calibração em pontuações de probabilidade e média ponderada):** parece elegante, mas tem problemas graves: (1) normalizar expressões qualitativas em probabilidades numéricas é inerentemente subjetivo e propenso a erros de calibração; (2) fazer média ponderada de estimativas conflitantes pode gerar um "valor médio" que não representa nenhuma das fontes e esconde a divergência metodológica; (3) esconde a existência de discordância entre fontes, que é exatamente a informação que o relatório deveria destacar para tomada de decisão.\n\n- **Alternativa C (seções explícitas distinguindo descobertas estabelecidas de contestadas):** esta abordagem **preserva a informação** em vez de comprimi-la ou descartá-la. Ao estruturar o relatório com seções que separam descobertas bem suportadas de descobertas contestadas, e ao manter o contexto metodológico original (fonte, IC, limitações), você permite que o leitor humano (ou downstream) tome decisões informadas. Isso resolve exatamente os dois problemas descritos: (a) não se perde nuance porque as descobertas conflitantes são explicitamente apresentadas; (b) não se faz ressalvas excessivas porque as informações de confiança são apresentadas de forma estruturada e não genérica. O "falso consenso" e a "ressalva genérica" são eliminados.\n\n- **Alternativa D (verificação cruzada exigindo múltiplas fontes):** ignora que fontes independentes podem chegar a conclusões diferentes por razões metodológicas legítimas. Exigir corroboração de duas fontes descartaria informações valiosas que são singulares, mas de alta qualidade (ex.: um único estudo revisado por pares). Também não resolve como tratar descobertas que *não* têm corroboração — você simplesmente as omite, perdendo informação.\n\n**Conclusão:** A alternativa C é a única que sistematicamente **preserva a incerteza e a transmite de forma útil**, sem descartar informações ou criar falsas certezas. É a abordagem mais alinhada com boas práticas de comunicação científica e de risco.','\n',char(10)),replace('Imagina que você e seu amigo foram pesquisar o preço de um brinquedo. Você achou um site que diz "R$ 50, mas não temos certeza" e seu amigo achou uma revista que diz "R$ 35, e temos 95% de certeza que está entre R$ 28 e R$ 42". Se vocês simplesmente falarem "custa R$ 42,50" (a média), estão inventando um número que não está em lugar nenhum. Se falarem "custa entre R$ 28 e R$ 50", é tão vago que não ajuda.\n\nA melhor ideia é organizar assim: numa parte do relatório, escrever "O que sabemos com certeza: a revista afirma R$ 35 com alta confiança". Em outra parte, "O que é incerto: o site diz R$ 50, mas a metodologia é fraca". Assim, quem lê entende direitinho o que é confiável e o que é duvidoso, sem misturar tudo ou jogar informação fora. É tipo separar os brinquedos que você tem certeza que funcionam daqueles que podem estar quebrados — em vez de fingir que todos são iguais.','\n',char(10)));
INSERT INTO cards VALUES('admin','card_1783092984866_qb4dl3pc7',119,'Um usuário está expandindo o sistema de pesquisa além de seu único agente de busca na web, adicionando fontes de dados especializadas.',replace('Um usuário está expandindo o sistema de pesquisa além de seu único agente de busca na web, adicionando fontes de dados especializadas.\n\nUm usuário está expandindo o sistema de pesquisa além de seu único agente de busca na web, adicionando fontes de dados especializadas. Ele adiciona um agente de API financeira que retorna JSON estruturado com receita, margens e taxas de crescimento; um agente de monitoramento de notícias que retorna resumos em prosa de acontecimentos recentes; e um agente de análise de patentes que retorna listas estruturadas de áreas de tecnologia. O agente de síntese combina tudo isso em briefings executivos. Atualmente, ele converte tudo em tópicos, fazendo com que as comparações financeiras percam a clareza tabular e os resumos de notícias percam o fluxo narrativo.\n\nQual mudança melhoraria mais a qualidade do briefing?\n\n[ ] A - Padronizar todas as saídas dos subagentes como resumos em prosa com citações em linha.\n[ ] B - Adicionar uma camada de conversão de formato entre os subagentes e a síntese que transforma todas as saídas em uma representação intermediária comum.\n[ ] C - Atualizar o agente de síntese para renderizar cada tipo de conteúdo de forma apropriada — dados financeiros como tabelas, notícias como prosa.\n[ ] D - Padronizar todas as saídas dos subagentes como JSON com campos para afirmação, evidência, fonte e confiança.','\n',char(10)),'C - Atualizar o agente de síntese para renderizar cada tipo de conteúdo de forma apropriada — dados financeiros como tabelas, notícias como prosa.','["Domain_1::Agentic_Architecture_Orchestration", "Domain_2::Tool_Design_MCP_Integration", "Domain_4::Prompt_Engineering_Structured_Output", "Scenario_3::Multi_Agent_Research"]','New',0,2.5,0,1783092984866,1783725675417,1783203558653,replace('**Tradução para português do Brasil:**\n\nUm usuário está expandindo o sistema de pesquisa além de seu único agente de busca na web, adicionando fontes de dados especializadas. Ele adiciona um agente de API financeira que retorna JSON estruturado com receita, margens e taxas de crescimento; um agente de monitoramento de notícias que retorna resumos em prosa de acontecimentos recentes; e um agente de análise de patentes que retorna listas estruturadas de áreas de tecnologia. O agente de síntese combina tudo isso em briefings executivos. Atualmente, ele converte tudo em tópicos, fazendo com que as comparações financeiras percam a clareza tabular e os resumos de notícias percam o fluxo narrativo.\n\nQual mudança melhoraria mais a qualidade do briefing?\n\n[ ] A - Padronizar todas as saídas dos subagentes como resumos em prosa com citações em linha.\n[ ] B - Adicionar uma camada de conversão de formato entre os subagentes e a síntese que transforma todas as saídas em uma representação intermediária comum.\n[ ] C - Atualizar o agente de síntese para renderizar cada tipo de conteúdo de forma apropriada — dados financeiros como tabelas, notícias como prosa.\n[ ] D - Padronizar todas as saídas dos subagentes como JSON com campos para afirmação, evidência, fonte e confiança.','\n',char(10)),replace('**Explicação para um adulto tech lead:**\n\nO cenário descreve um problema clássico de perda de semântica e estrutura ao achatar dados heterogêneos em um formato uniforme (tópicos). Cada fonte tem uma natureza diferente: dados financeiros são tabulares e comparativos por essência; notícias são narrativas e temporais; patentes são listas categorizadas. Ao converter tudo para "tópicos" (provavelmente bullet points ou parágrafos genéricos), o agente de síntese está destruindo justamente as características que tornam cada tipo de dado útil.\n\n**Por que a alternativa C é a correta:**\n\nA alternativa C propõe uma solução que respeita a natureza de cada dado: o agente de síntese deve ser capaz de renderizar formatos apropriados para cada tipo de conteúdo. Isso é análogo a ter um sistema de renderização condicional — um "renderer" especializado para cada tipo de dado. Dados financeiros ganham tabelas (permitindo comparação visual rápida), notícias mantêm fluxo narrativo (preservando contexto temporal e causal), e patentes podem ser listas estruturadas. O agente de síntese não precisa converter tudo para um formato único; ele precisa saber apresentar cada formato adequadamente no briefing final.\n\n**Por que as demais estão erradas:**\n\n- **Alternativa A:** Padronizar tudo como prosa faria o problema oposto: dados financeiros perderiam ainda mais clareza tabular. Tentar descrever uma matriz de receitas vs. margens em prosa é ineficiente e difícil de comparar visualmente. Além disso, notícias já estão em prosa, então isso não resolveria a perda de fluxo narrativo — o problema atual é que o agente de síntese já está convertendo tudo para um formato genérico (tópicos), e prosa seria apenas outro formato genérico.\n\n- **Alternativa B:** Uma representação intermediária comum (como RDF, grafos, ou JSON-LD) poderia ser útil para integração semântica, mas o problema central não é a interoperabilidade entre fontes — o agente de síntese já consegue receber e combinar os dados. O problema é a *apresentação final*. Uma camada de conversão intermediária adicionaria complexidade sem endereçar a perda de formato na saída.\n\n- **Alternativa D:** Padronizar tudo como JSON com campos genéricos (afirmação, evidência, fonte, confiança) forçaria dados financeiros e notícias a um molde que não lhes é natural. Dados financeiros são relacionais e numéricos, não baseados em "afirmações". Notícias são narrativas com múltiplos fatos interligados, não facilmente decomponíveis em afirmações isoladas. Isso destruiria a riqueza semântica de cada fonte sem trazer ganho real, já que o agente de síntese já consegue processar os formatos originais.','\n',char(10)),replace('Imagine que você tem três amigos que trazem informações de jeitos diferentes:\n\n- Um amigo traz números de um jogo em uma tabela (como placar de futebol).\n- Outro amigo conta uma história sobre o que aconteceu no recreio.\n- Outro amigo traz uma lista de brinquedos legais.\n\nVocê precisa fazer um resumo para contar para seus pais. Se você pegar tudo e transformar em lista de tópicos (bullet points), a tabela vira uma lista chata e difícil de comparar, e a história perde a graça porque vira só fatos soltos.\n\nA melhor ideia (alternativa C) é: em vez de forçar tudo a virar a mesma coisa, você deixa a tabela como tabela, a história como história, e a lista como lista. Assim, cada informação fica do jeito que é mais fácil de entender!\n\nAs outras ideias não são tão boas porque:\n- Transformar tudo em história (alternativa A) bagunçaria os números.\n- Criar um "idioma secreto" intermediário (alternativa B) daria mais trabalho sem ajudar na hora de mostrar.\n- Transformar tudo em fichas com "afirmação, evidência, fonte" (alternativa D) quebraria a tabela e a história em pedacinhos que perdem o sentido.','\n',char(10)));
INSERT INTO cards VALUES('admin','card_1783092984875_goic0edyw',120,'Seu sistema de extração processa dois tipos de documentos: relatórios mensais padrão (arquivados após o processamento) e relatórios de exceção urgentes (que devem disparar alertas de negócio em até 30 minutos do recebimento).',replace('Seu sistema de extração processa dois tipos de documentos: relatórios mensais padrão (arquivados após o processamento) e relatórios de exceção urgentes (que devem disparar alertas de negócio em até 30 minutos do recebimento).\n\nSeu sistema de extração processa dois tipos de documentos: relatórios mensais padrão (arquivados após o processamento) e relatórios de exceção urgentes (que devem disparar alertas de negócio em até 30 minutos do recebimento). Ambos usam o mesmo esquema JSON. Você quer minimizar os custos de API atendendo aos requisitos de latência.\n\nComo você deve arquitetar o pipeline de processamento?\n\n[ ] A - Enviar todos os documentos para a Messages API em tempo real, garantindo latência de processamento consistente entre os tipos de documento.\n[ ] B - Enviar todos os documentos para a `Batch API` com `custom_ids` para rastreamento. Quando os resultados chegarem, processar imediatamente os documentos urgentes e disparar alertas atrasados para as exceções.\n[ ] C - Enfileirar todos os documentos e enviar batches a cada hora, sinalizando os documentos urgentes para tratamento acelerado quando os resultados do batch retornarem.\n[ ] D - Rotear os relatórios padrão para a `Batch API`, obtendo 50% de economia de custo, e rotear os relatórios de exceção urgentes para a Messages API em tempo real.','\n',char(10)),'D - Rotear os relatórios padrão para a `Batch API`, obtendo 50% de economia de custo, e rotear os relatórios de exceção urgentes para a Messages API em tempo real.','["Domain_1::Agentic_Architecture_Orchestration", "Domain_5::Context_Management_Reliability", "Domain_2::Tool_Design_MCP_Integration", "Scenario_6::Structured_Data_Extraction"]','New',0,2.5,0,1783092984875,1783725679837,1783203558653,replace('**Tradução para português do Brasil:**\n\nSeu sistema de extração processa dois tipos de documentos: relatórios mensais padrão (arquivados após o processamento) e relatórios de exceção urgentes (que devem disparar alertas de negócio em até 30 minutos do recebimento). Ambos usam o mesmo esquema JSON. Você quer minimizar os custos de API atendendo aos requisitos de latência.\n\nComo você deve arquitetar o pipeline de processamento?\n\n[ ] A - Enviar todos os documentos para a Messages API em tempo real, garantindo latência de processamento consistente entre os tipos de documento.\n[ ] B - Enviar todos os documentos para a Batch API com custom_ids para rastreamento. Quando os resultados chegarem, processar imediatamente os documentos urgentes e disparar alertas atrasados para as exceções.\n[ ] C - Enfileirar todos os documentos e enviar batches a cada hora, sinalizando os documentos urgentes para tratamento acelerado quando os resultados do batch retornarem.\n[ ] D - Rotear os relatórios padrão para a Batch API, obtendo 50% de economia de custo, e rotear os relatórios de exceção urgentes para a Messages API em tempo real.','\n',char(10)),replace('**Explicação para um adulto tech lead:**\n\nA questão apresenta um trade-off clássico entre custo e latência. Temos duas classes de documento com requisitos distintos:\n\n- **Relatórios padrão**: sem urgência, podem ser arquivados. O custo é a principal preocupação.\n- **Relatórios de exceção urgentes**: exigem processamento e disparo de alertas em até 30 minutos. A latência é crítica.\n\nVamos analisar cada alternativa:\n\n**Alternativa A (incorreta):** Enviar tudo para a Messages API em tempo real. A Messages API (provavelmente se refere a uma API síncrona de inferência como a Chat Completions) oferece baixa latência, mas tem custo maior. Não há necessidade de pagar esse custo premium para documentos que não têm requisito de urgência. Desperdício de recursos.\n\n**Alternativa B (incorreta):** Enviar tudo para a Batch API. A Batch API é assíncrona e tem latência maior (pode levar horas, dependendo da fila). Mesmo que você tente "processar imediatamente" quando os resultados chegarem, o documento urgente já terá ficado horas na fila de batch, violando o requisito de 30 minutos. Além disso, "disparar alertas atrasados para as exceções" é explicitamente uma violação do requisito de negócio.\n\n**Alternativa C (incorreta):** Enfileirar tudo e enviar batches a cada hora. Isso claramente viola o requisito de 30 minutos para documentos urgentes. Um batch enviado a cada hora pode significar que um documento urgente só comece a ser processado 60 minutos depois, e o resultado só chegará depois disso.\n\n**Alternativa D (correta):** É a abordagem de *routing inteligente* (também conhecida como *dual pipeline*). Os relatórios padrão, que não têm urgência, seguem para a Batch API — que tipicamente oferece 50% de desconto sobre o custo da API em tempo real, além de permitir processamento em lote mais eficiente. Os relatórios urgentes seguem para a Messages API em tempo real, garantindo que sejam processados e os alertas disparados dentro da janela de 30 minutos. Essa separação atende simultaneamente aos requisitos de custo (minimizado para o volume de documentos não urgentes) e latência (garantida para os documentos críticos).\n\n**Resumo técnico:** A alternativa D é a única que respeita o requisito de latência de 30 minutos para documentos urgentes enquanto minimiza custos para documentos não urgentes. É uma arquitetura de *pipeline híbrido* ou *two-tier processing*, prática comum em sistemas de processamento documental com requisitos mistos.','\n',char(10)),replace('Imagine que você tem dois tipos de lição de casa para fazer: umas são super importantes e precisam ser entregues em 30 minutos, e outras podem ser entregues no final do mês.\n\n- **Alternativa A** seria fazer as duas lições correndo, igualmente rápido. Mas as lições do mês não precisam tanta pressa, então você estaria gastando energia à toa.\n- **Alternativa B** seria colocar TUDO na mochila e só olhar no final do dia. Aí a lição importante chegaria atrasada!\n- **Alternativa C** seria juntar todas as lições e entregar tudo de uma vez a cada hora. A lição importante também chegaria atrasada — mais de 30 minutos.\n- **Alternativa D** é a mais esperta: as lições do mês você coloca num monte e entrega mais tarde, quando tiver tempo (economizando esforço). Já a lição importante você corre e entrega na hora, porque não pode esperar.\n\nA resposta certa é a **D** porque ela resolve os dois problemas: não gasta esforço à toa com coisas que podem esperar e resolve rapidinho o que é urgente.','\n',char(10)));
INSERT INTO cards VALUES('admin','card_1783092984899_37wk5cvde',121,'Seu esquema inclui um campo skills: string[].',replace('Seu esquema inclui um campo skills: string[].\n\nSeu esquema inclui um campo skills: string[]. O monitoramento em produção revela três problemas de consistência: (1) frases compostas como "Python and SQL" às vezes são mantidas como uma única entrada, às vezes divididas; (2) habilidades implícitas, mas não declaradas, ocasionalmente aparecem nas extrações; (3) documentos semelhantes produzem comprimentos de array muito diferentes (5-10 vs. 40+ entradas). Seu prompt atualmente diz "Extract all skills mentioned."\n\nQual é a melhoria mais eficaz?\n\n[ ] A - Adicionar exemplos few-shot demonstrando o tratamento de frases compostas, critérios explícitos de menção e a granularidade adequada das entradas.\n[ ] B - Adicionar restrições: "Extract 10-20 skills maximum, one skill per entry, only explicitly named skills."\n[ ] C - Adicionar uma normalização pós-extração que mapeia as habilidades para uma taxonomia canônica e deduplica entradas semelhantes.\n[ ] D - Enriquecer o esquema para {skill: string, confidence: float, `source_quote`: string}[] para capturar metadados da extração.','\n',char(10)),'A - Adicionar exemplos few-shot demonstrando o tratamento de frases compostas, critérios explícitos de menção e a granularidade adequada das entradas.','["Domain_4::Prompt_Engineering_Structured_Output", "Domain_2::Tool_Design_MCP_Integration", "Domain_5::Context_Management_Reliability", "Scenario_6::Structured_Data_Extraction"]','New',0,2.5,0,1783092984899,1783725684084,1783203558653,replace('**Tradução para português do Brasil:**\n\nSeu esquema inclui um campo skills: string[].\n\nO monitoramento em produção revela três problemas de consistência: (1) frases compostas como "Python and SQL" às vezes são mantidas como uma única entrada, às vezes divididas; (2) habilidades implícitas, mas não declaradas, ocasionalmente aparecem nas extrações; (3) documentos semelhantes produzem comprimentos de array muito diferentes (5-10 vs. 40+ entradas). Seu prompt atualmente diz "Extract all skills mentioned."\n\nQual é a melhoria mais eficaz?\n\n[ ] A - Adicionar exemplos few-shot demonstrando o tratamento de frases compostas, critérios explícitos de menção e a granularidade adequada das entradas.\n[ ] B - Adicionar restrições: "Extract 10-20 skills maximum, one skill per entry, only explicitly named skills."\n[ ] C - Adicionar uma normalização pós-extração que mapeia as habilidades para uma taxonomia canônica e deduplica entradas semelhantes.\n[ ] D - Enriquecer o esquema para {skill: string, confidence: float, source_quote: string}[] para capturar metadados da extração.','\n',char(10)),replace('**Explicação para o adulto tech lead:**\n\nO problema central é de **inconsistência na interpretação do prompt pelo modelo de linguagem**. O prompt atual ("Extract all skills mentioned") é vago e dá margem a decisões subjetivas sobre:\n- O que conta como "menção" (explícita vs. implícita);\n- Como segmentar frases coordenadas ("Python and SQL" → uma entrada ou duas?);\n- Qual granularidade adotar (skills de alto nível vs. sub-habilidades).\n\nA alternativa **A** é a mais eficaz porque ataca a **raiz do problema**: a ambiguidade no prompt. Ao fornecer exemplos few-shot (demonstrações concretas do comportamento esperado), você estabelece um padrão consistente de extração, eliminando a subjetividade. Exemplos bem construídos ensinam ao modelo exatamente como tratar cada caso problemático — frases compostas viram entradas separadas, habilidades implícitas são ignoradas, e a granularidade desejada é explicitada nos exemplos. Isso alinha o comportamento do modelo com a expectativa de negócio sem depender de pós-processamento frágil.\n\n**Análise das demais alternativas:**\n\n- **B**: Adicionar restrições no prompt é uma tentativa válida, mas insuficiente. Restrições textuais sem demonstração concreta ainda deixam margem para interpretação errônea. Além disso, fixar um intervalo rígido de 10-20 skills não resolve a variação natural entre documentos — um CV simples pode ter 5 skills relevantes, um perfil sênior pode ter 30+. A restrição "only explicitly named skills" ajuda com o problema (2), mas não resolve a segmentação de frases compostas (problema 1) de forma consistente.\n\n- **C**: Normalização pós-extração é uma abordagem reativa: trata o sintoma (arrays inconsistentes) sem corrigir a causa (extração inconsistente). Mapear para taxonomia canônica resolve duplicatas semânticas, mas não evita que frases compostas sejam extraídas como uma única entrada ou que habilidades implícitas apareçam. Você estaria gastando esforço para limpar dados que poderiam ter sido extraídos corretamente desde o início.\n\n- **D**: Enriquecer o esquema com metadados (confidence, source_quote) melhora a auditabilidade e permite filtrar extrações de baixa confiança, mas não resolve a inconsistência fundamental. O modelo continuará produzindo saídas divergentes para entradas semelhantes; você apenas terá mais dados para diagnosticar o problema, mas não para evitá-lo.\n\n**Conclusão**: A melhor prática em engenharia de prompt é usar exemplos few-shot para definir claramente o comportamento esperado, especialmente quando o prompt original é genérico e os critérios de extração envolvem julgamento semântico.','\n',char(10)),replace('**Explicação para uma criança de 10 anos:**\n\nImagine que você pede para um robô inteligente ler textos sobre pessoas e listar todas as habilidades que elas têm. O problema é que o robô está fazendo isso de forma diferente cada vez:\n\n- Às vezes ele vê "Python and SQL" e escreve como uma habilidade só ("Python and SQL"), outras vezes ele separa em duas ("Python", "SQL").\n- Às vezes ele inventa habilidades que a pessoa nem disse que tinha.\n- Para textos parecidos, ele às vezes faz uma lista pequena (5 itens) e outras vezes uma lista enorme (40 itens).\n\nO pedido atual para o robô é só "Extraia todas as habilidades mencionadas." — é muito vago, igual pedir para alguém "desenhar um animal bonito". Cada pessoa desenharia um animal diferente!\n\nA melhor solução é a **alternativa A**: dar exemplos prontos mostrando exatamente como o robô deve se comportar. É como mostrar para alguém: "Olha, quando aparecer ''Python and SQL'', você deve separar em duas linhas. Quando aparecer algo que a pessoa não disse claramente, você não coloca na lista. Mantenha a lista com um tamanho parecido para textos parecidos."\n\nEsses exemplos ensinam o robô a agir sempre do mesmo jeito, resolvendo todos os três problemas de uma vez.\n\nAs outras opções não são tão boas porque:\n- **B**: Só dar regras escritas ("faça de 10 a 20", "só habilidades explícitas") ainda pode confundir o robô, pois ele pode interpretar as regras errado.\n- **C**: Arrumar a lista depois que o robô já errou é como limpar a sujeira depois do estrago — melhor ensinar ele a não fazer bagunça.\n- **D**: Adicionar informações extras como "qual foi a confiança do robô ao extrair" não impede os erros, só ajuda a perceber que eles aconteceram.','\n',char(10)));
INSERT INTO cards VALUES('admin','card_1783092984913_6edrufi60',122,'Seu sistema de extração implementa novas tentativas automáticas quando a validação falha.',replace('Seu sistema de extração implementa novas tentativas automáticas quando a validação falha.\n\nSeu sistema de extração implementa novas tentativas automáticas quando a validação falha. A cada nova tentativa, o erro de validação específico é anexado ao prompt. Essa abordagem de nova tentativa com feedback de erro resolve a maioria das falhas em 2-3 tentativas.\n\nPara qual padrão de falha novas tentativas seriam MENOS eficazes?\n\n[ ] A - O modelo extrai palavras-chave como um objeto aninhado organizado por categoria quando o esquema exige um array plano de strings\n[ ] B - O modelo extrai contagens de citações como strings formatadas conforme o local ("1,234") quando o esquema exige inteiros\n[ ] C - O modelo extrai datas como strings de data e hora ISO 8601 ("2023-03-15T00:00:00Z") quando o esquema exige apenas a parte da data (YYYY-MM-DD)\n[ ] D - O modelo extrai "et al." para coautores quando a lista completa existe apenas em um documento externo que não está na entrada','\n',char(10)),'D - O modelo extrai "et al." para coautores quando a lista completa existe apenas em um documento externo que não está na entrada','["Domain_4::Prompt_Engineering_Structured_Output", "Domain_5::Context_Management_Reliability", "Scenario_6::Structured_Data_Extraction"]','New',0,2.5,0,1783092984913,1783725687827,1783203558653,replace('**Tradução para português do Brasil:**\n\nSeu sistema de extração implementa novas tentativas automáticas quando a validação falha. A cada nova tentativa, o erro de validação específico é anexado ao prompt. Essa abordagem de nova tentativa com feedback de erro resolve a maioria das falhas em 2-3 tentativas.\n\nPara qual padrão de falha novas tentativas seriam MENOS eficazes?\n\n[ ] A - O modelo extrai palavras-chave como um objeto aninhado organizado por categoria quando o esquema exige um array plano de strings\n[ ] B - O modelo extrai contagens de citações como strings formatadas conforme o local ("1,234") quando o esquema exige inteiros\n[ ] C - O modelo extrai datas como strings de data e hora ISO 8601 ("2023-03-15T00:00:00Z") quando o esquema exige apenas a parte da data (YYYY-MM-DD)\n[ ] D - O modelo extrai "et al." para coautores quando a lista completa existe apenas em um documento externo que não está na entrada','\n',char(10)),replace('**Explicação para adulto tech lead (didática e técnica):**\n\nA questão trata de um sistema de extração com retry automático baseado em feedback de erro. O mecanismo funciona da seguinte forma: o sistema tenta extrair os dados, valida o resultado contra um esquema predefinido, e, se a validação falha, anexa a mensagem de erro ao prompt original e tenta novamente. Isso é uma forma de "self-correction via validation error feedback" — o modelo recebe informações sobre como estrutural ou tipologicamente o dado extraído está incorreto e pode ajustar a saída na próxima tentativa.\n\nVamos analisar cada alternativa:\n\n**Alternativa D (correta):** O problema aqui não é de formato, tipo ou estrutura do dado — é de **informação faltante na entrada**. O modelo extrai "et al." (abreviação para "e outros") porque a lista completa de coautores não está disponível no texto de entrada; ela existe apenas em um documento externo. O erro de validação (ex: "lista de coautores incompleta", "o campo authors deve conter a lista completa de nomes") não fornece ao modelo a informação factual que está faltando. O modelo pode até entender que precisa listar os nomes completos, mas ele não tem acesso a esses nomes — eles estão fora do contexto do prompt. Repetir a tentativa com feedback de erro não vai magicamente trazer informação de um documento externo que não está na entrada. Portanto, o retry é ineficaz porque o gargalo não é de formatação, mas de disponibilidade de dados.\n\n**Alternativa A (incorreta):** O modelo extrai no formato errado (objeto aninhado em vez de array plano). O erro de validação informará que o tipo esperado é "array de strings" e não "objeto". O modelo pode facilmente corrigir isso na nova tentativa, reestruturando a saída. É um problema puramente estrutural.\n\n**Alternativa B (incorreta):** O modelo extrai como string formatada ("1,234") em vez de inteiro (1234). O erro de validação apontará que o tipo esperado é integer. O modelo pode tentar novamente convertendo a string para inteiro. É um problema de tipo/tipagem.\n\n**Alternativa C (incorreta):** O modelo extrai datetime completo em vez de apenas data. O erro de validação indicará o formato esperado (YYYY-MM-DD). O modelo pode truncar a string datetime para a parte da data. É um problema de formato.\n\n**Resumo técnico:** O padrão de retry com feedback de erro resolve falhas de **formatação, tipo e estrutura** (erros sintáticos e de schema). Ele **não resolve** falhas de **informação ausente** (erros semânticos por falta de dados na entrada). A alternativa D é o único caso em que o erro não pode ser corrigido apenas com base na mensagem de erro e no prompt original — falta o dado de fato.','\n',char(10)),replace('Imagine que você tem um robô que tira informação de textos. Quando o robô erra, você mostra o erro pra ele e ele tenta de novo. Isso funciona bem na maioria das vezes.\n\nAgora pense nos erros:\n\n- **A:** O robô entrega um bagunçado de palavras em vez de uma lista simples. Se você falar "era pra ser uma lista!", ele consegue arrumar.\n- **B:** O robô escreve "1,234" em vez do número 1234. Se você falar "isso tem que ser número!", ele consegue consertar.\n- **C:** O robô coloca data e hora ("2023-03-15T00:00:00Z") em vez de só a data ("2023-03-15"). Se você falar "só a data!", ele corta a hora fora.\n\n- **D:** O robô escreve "et al." (que quer dizer "e outros") porque a lista completa de nomes dos autores está em outro documento, que ele não tem. Se você falar "faltou o nome completo dos autores!", o robô vai tentar de novo, mas **ele não tem como saber os nomes** — eles estão em outro lugar! Não adianta tentar de novo porque a informação simplesmente não está ali.\n\nEntão o erro D é o único que as tentativas extras **não ajudam**, porque o problema não é como o robô escreve, mas sim que ele não tem a informação necessária.','\n',char(10)));
INSERT INTO cards VALUES('admin','card_1783092984929_zepyva5c5',123,'Seu pipeline de extração processa cardápios de restaurantes e deve produzir um JSON estruturado com campos para nomes dos itens, descrições, preços e tags dietéticas.',replace('Seu pipeline de extração processa cardápios de restaurantes e deve produzir um JSON estruturado com campos para nomes dos itens, descrições, preços e tags dietéticas.\n\nSeu pipeline de extração processa cardápios de restaurantes e deve produzir um JSON estruturado com campos para nomes dos itens, descrições, preços e tags dietéticas. Alguns cardápios usam formatação inconsistente — preços como "$12" vs. "12.00", informação dietética como ícones vs. texto.\n\nQual é a abordagem mais confiável?\n\n[ ] A - Usar chamadas de extração separadas para cada campo, garantindo o tratamento consistente de cada tipo.\n[ ] B - Extrair os dados como estão e normalizar os formatos em código de pós-processamento depois que o Claude retornar.\n[ ] C - Solicitar várias tentativas de extração por documento e selecionar o formato mais comum.\n[ ] D - Definir um esquema de saída estrito e incluir regras de normalização de formato no seu prompt.','\n',char(10)),'D - Definir um esquema de saída estrito e incluir regras de normalização de formato no seu prompt.','["Domain_4::Prompt_Engineering_Structured_Output", "Domain_5::Context_Management_Reliability", "Scenario_6::Structured_Data_Extraction"]','New',0,2.5,0,1783092984929,1783725691582,1783203558653,replace('**Tradução para português do Brasil:**\n\nSeu pipeline de extração processa cardápios de restaurantes e deve produzir um JSON estruturado com campos para nomes dos itens, descrições, preços e tags dietéticas. Alguns cardápios usam formatação inconsistente — preços como "$12" vs. "12.00", informação dietética como ícones vs. texto.\n\nQual é a abordagem mais confiável?\n\n[ ] A - Usar chamadas de extração separadas para cada campo, garantindo o tratamento consistente de cada tipo.\n[ ] B - Extrair os dados como estão e normalizar os formatos em código de pós-processamento depois que o Claude retornar.\n[ ] C - Solicitar várias tentativas de extração por documento e selecionar o formato mais comum.\n[ ] D - Definir um esquema de saída estrito e incluir regras de normalização de formato no seu prompt.','\n',char(10)),replace('**Explicação para adulto (tech lead):**\n\nA alternativa correta é a **D**.\n\n**Por que D é a melhor escolha:**\n\nDefinir um esquema de saída estrito (utilizando, por exemplo, `response_format` com JSON Schema) e incluir regras de normalização de formato diretamente no prompt é a abordagem mais confiável porque:\n\n1. **Controle centralizado**: As regras de normalização são aplicadas no momento da extração, no próprio modelo de linguagem, que tem excelente capacidade de compreender e seguir instruções de formatação. Isso elimina a necessidade de código adicional para tratar inconsistências.\n\n2. **Determinismo maior**: Com um esquema JSON bem definido, o Claude produz saídas consistentes desde a primeira chamada, sem depender de pós-processamento frágil ou heurísticas.\n\n3. **Custo e latência reduzidos**: Uma única chamada resolve o problema, ao contrário de múltiplas extrações (alternativa C) ou chamadas separadas por campo (alternativa A), que multiplicam tokens e tempo de processamento.\n\n4. **Generalização natural**: O Claude lida bem com variações como "$12" e "12.00" ou "vegan" e 🌱, desde que instruído adequadamente no prompt, usando seu conhecimento de mundo.\n\n**Por que as demais estão erradas:**\n\n- **A**: Usar chamadas separadas por campo fragmenta o contexto (cada chamada perde a visão do item como um todo) e aumenta drasticamente o custo/latência. Além disso, não resolve a inconsistência — você ainda teria que normalizar cada campo individualmente.\n\n- **B**: Extrair "como estão" e normalizar depois é frágil, pois o pós-processamento precisa lidar com toda a variação possível (formatos de moeda, símbolos, ícones, abreviações). Isso exige código complexo e manutenção constante, e falha facilmente com casos não previstos.\n\n- **C**: Múltiplas tentativas aumentam custo (3x-5x mais tokens) e latência, e "selecionar o formato mais comum" não garante correção — se a maioria errar da mesma forma, você propaga o erro. Não há ganho real de confiabilidade sobre uma única chamada bem instruída.\n\nPortanto, a abordagem mais enxuta, robusta e de menor custo é incorporar as regras de normalização no prompt com um esquema de saída rigoroso.','\n',char(10)),replace('Imagine que você tem vários cardápios de restaurantes e precisa organizar as informações de cada prato: nome, descrição, preço e se é vegetariano, vegano etc. O problema é que alguns cardápios escrevem os preços de um jeito ("$12") e outros de outro ("12.00"), e alguns usam desenhos (🌱) em vez de palavras ("vegano").\n\nA melhor forma de resolver isso é a **alternativa D**: você diz ao Claude (o sistema que processa os cardápios) exatamente como você quer o resultado final, com regras claras. Por exemplo: "os preços devem vir sempre sem o cifrão e com duas casas decimais" e "se aparecer um desenho de planta, escreva ''vegano'' no lugar". Assim, o próprio sistema já entrega tudo organizado e no mesmo formato.\n\nAs outras opções são piores porque:\n- **A** (separar por campo) é como pedir para uma pessoa ler só os preços de um cardápio, depois só os nomes, e assim por diante — demora mais e ela pode se confundir.\n- **B** (deixar bagunçado e arrumar depois) é como se você escrevesse tudo errado em um rascunho e depois passasse horas corrigindo manualmente. Dá mais trabalho e pode dar erro.\n- **C** (pedir várias vezes e escolher o que aparece mais) é como perguntar a mesma coisa para 5 pessoas e chutar a resposta que mais se repete — gasta tempo e não é garantia de acerto.\n\nEntão, a resposta certa é **D**: definir as regras antes e pedir para o sistema já entregar tudo no formato certo de uma vez.','\n',char(10)));
INSERT INTO cards VALUES('admin','card_1783092984944_lk4tk01ef',124,'Seu sistema opera com revisão humana de 100% há 3 meses.',replace('Seu sistema opera com revisão humana de 100% há 3 meses.\n\nSeu sistema opera com revisão humana de 100% há 3 meses. A análise mostra que extrações com confiança do modelo >90% têm 97% de precisão no geral. Para reduzir a carga de trabalho dos revisores, você planeja automatizar as extrações de alta confiança. Antes de implantar, qual etapa de validação é a mais crítica?\n\n[ ] A - Analisar a precisão por tipo de documento e por campo para verificar se as extrações de alta confiança têm desempenho consistente em todos os segmentos, e não apenas no agregado.\n[ ] B - Comparar a precisão em diferentes limiares de confiança (85%, 90%, 95%) para encontrar o ponto de corte ótimo que maximiza a automação minimizando os erros.\n[ ] C - Executar um piloto de duas semanas roteando 25% das extrações de alta confiança diretamente para os sistemas downstream e monitorar os relatórios de erro.\n[ ] D - Verificar se a precisão de 97% atende aos requisitos de todos os sistemas downstream que consomem os dados extraídos.','\n',char(10)),'A - Analisar a precisão por tipo de documento e por campo para verificar se as extrações de alta confiança têm desempenho consistente em todos os segmentos, e não apenas no agregado.','["Domain_4::Prompt_Engineering_Structured_Output", "Domain_5::Context_Management_Reliability", "Scenario_6::Structured_Data_Extraction"]','New',0,2.5,0,1783092984944,1783725695605,1783203558653,replace('**Tradução livre para pt-BR:**\n\nSeu sistema opera com revisão humana de 100% há 3 meses. A análise mostra que extrações com confiança do modelo >90% têm 97% de precisão no geral. Para reduzir a carga de trabalho dos revisores, você planeja automatizar as extrações de alta confiança. Antes de implantar, qual etapa de validação é a mais crítica?\n\n[ ] A - Analisar a precisão por tipo de documento e por campo para verificar se as extrações de alta confiança têm desempenho consistente em todos os segmentos, e não apenas no agregado.\n[ ] B - Comparar a precisão em diferentes limiares de confiança (85%, 90%, 95%) para encontrar o ponto de corte ótimo que maximiza a automação minimizando os erros.\n[ ] C - Executar um piloto de duas semanas roteando 25% das extrações de alta confiança diretamente para os sistemas downstream e monitorar os relatórios de erro.\n[ ] D - Verificar se a precisão de 97% atende aos requisitos de todos os sistemas downstream que consomem os dados extraídos.','\n',char(10)),replace('**Explicação para adulto (tech lead):**\n\nA questão aborda um problema clássico de avaliação de modelos: a **média agregada pode esconder variações significativas em subgrupos**. O modelo reporta 97% de precisão geral para extrações com confiança >90%, mas isso é uma média. Se desagregarmos por tipo de documento (faturas vs. contratos, por exemplo) ou por campo extraído (CNPJ vs. valor total), podemos descobrir que alguns segmentos têm precisão muito inferior a 97% — digamos, 85% em campos de endereço. Automatizar cegamente com base na média agregada expõe o sistema a riscos assimétricos.\n\n**Análise das alternativas:**\n\n- **Alternativa A (correta):** É a mais crítica porque ataca diretamente o fenômeno de *Simpson''s paradox* ou viés de segmentação. Sem essa análise, você pode estar automatizando extrações que são robustas na média, mas frágeis em cenários específicos de alto impacto. É a validação pré-implantação mais fundamental.\n\n- **Alternativa B:** Embora útil, essa análise de limiares assume que a métrica agregada já é confiável. Se há variação por segmento, ajustar o threshold global não resolve o problema — apenas mascara. É uma etapa posterior, não a mais crítica.\n\n- **Alternativa C:** Um piloto com roteamento direto para sistemas downstream é arriscado sem antes entender a precisão por segmento. Uma falha em um segmento específico pode poluir dados de produção e gerar retrabalho caro. Além disso, 25% de amostra pode não capturar segmentos raros.\n\n- **Alternativa D:** Verificar requisitos downstream é importante, mas é uma etapa de alinhamento de negócio, não uma validação técnica de robustez do modelo. Ela pressupõe que a precisão de 97% é confiável — o que é justamente o que precisa ser verificado antes.\n\n**Conclusão:** A alternativa A é a mais crítica porque expõe riscos de heterogeneidade de desempenho que as demais ignoram ou assumem como inexistentes.','\n',char(10)),replace('Imagina que você tem uma caixa de bombons sortidos e a embalagem diz que 97% deles são deliciosos. Parece ótimo, né? Mas e se os bombons de chocolate ao leite são sempre gostosos, mas os de fruta são sempre ruins? Se você der a caixa para alguém e essa pessoa só pegar os de fruta, ela vai achar tudo horrível!\n\nA pergunta é sobre um sistema que lê documentos automaticamente. Ele diz que 97% das vezes acerta quando está muito confiante. Mas a gente precisa ver se ele acerta bem em todos os tipos de documento e em todos os campos (como nome, data, valor), e não só no total. Pode ser que ele seja ótimo com faturas, mas péssimo com contratos. Se a gente não olhar isso, pode automatizar algo que funciona bem na média, mas que quebra feio em alguns casos. Por isso, a opção A (verificar por tipo e por campo) é a mais importante antes de ligar o piloto automático.','\n',char(10)));
INSERT INTO cards VALUES('admin','card_1783092984955_i5qztq5kf',125,'Seu pipeline de extração processa contratos que frequentemente incluem aditivos.',replace('Seu pipeline de extração processa contratos que frequentemente incluem aditivos.\n\nSeu pipeline de extração processa contratos que frequentemente incluem aditivos. Quando um contrato contém tanto os termos originais quanto aditivos posteriores (por exemplo, a cláusula original especifica "30-day payment terms" enquanto o Aditivo 1 altera isso para "45 days"), o modelo extrai de forma inconsistente um valor ou o outro, sem indicar qual se aplica.\n\nQual é a abordagem mais eficaz para melhorar a precisão da extração em documentos com aditivos?\n\n[ ] A - Redesenhar o esquema para que os campos alterados capturem múltiplos valores, cada um com sua localização na fonte e data de vigência.\n[ ] B - Adicionar instruções no prompt para sempre extrair o valor do aditivo mais recente e ignorar os termos originais substituídos.\n[ ] C - Pré-processar os documentos com um classificador que identifica e remove as seções substituídas antes da etapa principal de extração.\n[ ] D - Implementar uma validação pós-extração usando correspondência de padrões para detectar aditivos e sinalizar essas extrações para revisão manual.','\n',char(10)),'A - Redesenhar o esquema para que os campos alterados capturem múltiplos valores, cada um com sua localização na fonte e data de vigência.','["Domain_4::Prompt_Engineering_Structured_Output", "Domain_2::Tool_Design_MCP_Integration", "Domain_5::Context_Management_Reliability", "Scenario_6::Structured_Data_Extraction"]','New',0,2.5,0,1783092984955,1783725700036,1783203558653,replace('**Tradução para português do Brasil:**\n\nSeu pipeline de extração processa contratos que frequentemente incluem aditivos. Quando um contrato contém tanto os termos originais quanto aditivos posteriores (por exemplo, a cláusula original especifica "prazo de pagamento de 30 dias" enquanto o Aditivo 1 altera isso para "45 dias"), o modelo extrai de forma inconsistente um valor ou o outro, sem indicar qual se aplica.\n\nQual é a abordagem mais eficaz para melhorar a precisão da extração em documentos com aditivos?\n\n[ ] A - Redesenhar o esquema para que os campos alterados capturem múltiplos valores, cada um com sua localização na fonte e data de vigência.\n[ ] B - Adicionar instruções no prompt para sempre extrair o valor do aditivo mais recente e ignorar os termos originais substituídos.\n[ ] C - Pré-processar os documentos com um classificador que identifica e remove as seções substituídas antes da etapa principal de extração.\n[ ] D - Implementar uma validação pós-extração usando correspondência de padrões para detectar aditivos e sinalizar essas extrações para revisão manual.','\n',char(10)),replace('**Explicação para um adulto tech lead:**\n\nO problema central é que contratos com aditivos geram ambiguidade: o documento contém múltiplas versões de uma mesma cláusula, e o modelo extrai uma delas de forma imprevisível. A solução precisa tratar a raiz do problema — a perda de informação sobre a relação entre os valores concorrentes e seu contexto temporal.\n\n**Alternativa A (correta):** Esta abordagem resolve o problema no nível do *esquema de dados*, que é onde ele deve ser tratado. Ao modelar campos que aceitam múltiplos valores, cada um com metadados de localização (referência ao documento de origem) e data de vigência, você preserva o histórico completo e permite que sistemas downstream (análise jurídica, compliance, ERP) decidam qual valor aplicar baseados em regras de negócio. Isso não esconde informação nem depende de heurísticas frágeis. É uma solução robusta e extensível.\n\n**Alternativa B (incorreta):** Confiar em instruções de prompt é frágil. Modelos de linguagem podem ignorar ou interpretar mal a instrução, especialmente quando o documento contém linguagem contraditória ou quando há múltiplos aditivos. Não há garantia de consistência, e a abordagem não escala para cenários onde o "mais recente" não é o único valor relevante (ex.: cláusulas que se acumulam, não substituem).\n\n**Alternativa C (incorreta):** Remover seções "substituídas" é tecnicamente complexo e arriscado. Um classificador pode cometer erros de classificação (falsos positivos/negativos), removendo cláusulas ainda vigentes ou deixando trechos obsoletos. Além disso, essa abordagem destrói informação que pode ser necessária para auditoria ou análise de evolução contratual. É um pré-processamento agressivo e frágil.\n\n**Alternativa D (incorreta):** Validar e sinalizar para revisão manual apenas transfere o problema para humanos, sem resolvê-lo. Isso não melhora a precisão da extração automatizada; apenas cria um gargalo operacional. Para pipelines que processam grandes volumes, essa abordagem é cara e não escalável.\n\nPortanto, a alternativa A é a única que trata o problema de forma estrutural, preservando a integridade informacional e permitindo decisões downstream informadas.','\n',char(10)),replace('Imagine que você tem uma lição de casa e, depois, seu professor manda um bilhete dizendo que mudou algumas regras. Agora, seu caderno tem a regra antiga e o bilhete com a regra nova, mas você não sabe qual vale.\n\nA alternativa A diz: em vez de escolher uma regra qualquer, você anota as duas no caderno, dizendo onde cada uma está escrita e qual data vale. Assim, você ou outra pessoa pode decidir qual usar. É a melhor solução porque guarda toda a informação.\n\nAs outras opções são piores: a B tenta adivinhar qual regra é a certa e pode errar; a C joga fora a regra antiga, mas pode jogar algo importante sem querer; a D pede ajuda para um adulto toda vez, o que demora muito.\n\nEntão a resposta certa é a A, porque guardamos todas as regras com seus detalhes e não perdemos nada.','\n',char(10)));
INSERT INTO cards VALUES('admin','card_1783092984966_h95g1k194',126,'Seu sistema extrai metadados de eventos (data, local, organizador, `attendee_count`) de artigos de notícias usando um esquema JSON com todos os campos anuláveis.',replace('Seu sistema extrai metadados de eventos (data, local, organizador, `attendee_count`) de artigos de notícias usando um esquema JSON com todos os campos anuláveis.\n\nSeu sistema extrai metadados de eventos (data, local, organizador, `attendee_count`) de artigos de notícias usando um esquema JSON com todos os campos anuláveis. Durante a avaliação, você observa que o modelo frequentemente gera valores plausíveis, porém incorretos, para campos não mencionados no artigo — por exemplo, gerando "500" para `attendee_count` quando a fonte não contém nenhuma informação de público.\n\nQual é a maneira mais eficaz de reduzir essas extrações falsas?\n\n[ ] A - Adicionar uma etapa de pós-processamento usando uma segunda chamada de LLM para verificar se cada valor extraído existe no documento de origem.\n[ ] B - Adicionar instruções no prompt para retornar null em qualquer campo cuja informação não esteja diretamente declarada na fonte.\n[ ] C - Tornar todos os campos do esquema obrigatórios (não anuláveis) com regras de validação estritas para garantir que o modelo só produza dados verificáveis.\n[ ] D - Migrar para um nível de modelo mais capaz, com melhor aderência a instruções, para reduzir a tendência a alucinações.','\n',char(10)),'B - Adicionar instruções no prompt para retornar null em qualquer campo cuja informação não esteja diretamente declarada na fonte.','["Domain_4::Prompt_Engineering_Structured_Output", "Domain_2::Tool_Design_MCP_Integration", "Scenario_6::Structured_Data_Extraction"]','New',0,2.5,0,1783092984966,1783725704112,1783203558653,replace('**Tradução para português do Brasil:**\n\nSeu sistema extrai metadados de eventos (data, local, organizador, `attendee_count`) de artigos de notícias usando um esquema JSON com todos os campos anuláveis. Durante a avaliação, você observa que o modelo frequentemente gera valores plausíveis, porém incorretos, para campos não mencionados no artigo — por exemplo, gerando "500" para `attendee_count` quando a fonte não contém nenhuma informação de público.\n\nQual é a maneira mais eficaz de reduzir essas extrações falsas?\n\n[ ] A - Adicionar uma etapa de pós-processamento usando uma segunda chamada de LLM para verificar se cada valor extraído existe no documento de origem.\n[ ] B - Adicionar instruções no prompt para retornar null em qualquer campo cuja informação não esteja diretamente declarada na fonte.\n[ ] C - Tornar todos os campos do esquema obrigatórios (não anuláveis) com regras de validação estritas para garantir que o modelo só produza dados verificáveis.\n[ ] D - Migrar para um nível de modelo mais capaz, com melhor aderência a instruções, para reduzir a tendência a alucinações.','\n',char(10)),replace('**Explicação técnica (para adulto tech lead):**\n\nO problema descrito é um caso clássico de **alucinação em extração estruturada**: o modelo, em vez de retornar `null` para um campo cujo valor não está presente no texto fonte, "inventa" um valor plausível. Como o esquema já define todos os campos como anuláveis, a infraestrutura técnica para lidar com a ausência de informação já existe — o problema é que o modelo não está sendo instruído a usar essa nulabilidade.\n\n**Análise das alternativas:**\n\n**Alternativa A (pós-processamento com segunda LLM):** Embora funcione, é ineficiente. Você dobra o custo computacional (latência e tokens) para realizar uma verificação que poderia ser resolvida na própria instrução de extração. Além disso, a segunda LLM também pode alucinar ou ser excessivamente permissiva/restritiva, adicionando uma nova fonte de erro sem garantia de melhora proporcional.\n\n**Alternativa B (correta):** A abordagem mais direta e eficaz. Basta ajustar o prompt para instruir explicitamente o modelo a retornar `null` quando o valor não estiver literalmente presente no texto. Isso ataca a causa raiz — o viés do modelo de sempre preencher campos —, é gratuito (apenas alteração de prompt) e funciona em qualquer modelo. É uma aplicação do princípio "instrução explícita supera viés implícito".\n\n**Alternativa C (campos obrigatórios):** É contraproducente. Tornar os campos obrigatórios forçaria o modelo a *sempre* gerar um valor, o que pioraria o problema em vez de resolvê-lo. Haveria mais alucinações, pois o modelo precisaria inventar algo para cada campo. Essa alternativa inverte completamente a lógica desejada.\n\n**Alternativa D (modelo mais capaz):** Modelos mais capazes geralmente alucinam *menos*, mas ainda alucinam — não é uma solução definitiva. Além disso, trocar de modelo (especialmente para um mais caro/pesado) é uma medida drástica e dispendiosa. O problema aqui não é a capacidade do modelo, mas a ausência de uma instrução explícita no prompt. Um modelo mais caro sem a instrução correta continuará apresentando o mesmo comportamento.\n\n**Conclusão:** A alternativa B é a mais eficaz porque ataca a causa raiz com o mínimo custo e complexidade, aproveitando o esquema já anulável.','\n',char(10)),replace('Imagine que você tem um robô que lê notícias e preenche uma ficha sobre o evento: data, lugar, organizador e quantas pessoas foram. Só que, quando a notícia não fala quantas pessoas foram, o robô inventa um número — tipo "500" — mesmo sem ter lido isso em lugar nenhum. Isso é um palpite errado, não informação de verdade.\n\n**Alternativa B** é a mais esperta: basta dizer claramente para o robô: "Se você não encontrar a informação no texto, escreva ''null'' (vazio) em vez de inventar." É como um professor falando: "Se não souber a resposta, deixe em branco — não chute." Assim, a ficha fica com dados que realmente vieram da notícia, e tudo que está em branco a gente sabe que não foi mencionado. Simples, barato e resolve o problema.','\n',char(10)));
INSERT INTO cards VALUES('admin','card_1783092984976_awugdpqi4',127,'Depois de implementar o uso de ferramentas com definições de esquema estritas, os erros de sintaxe JSON foram eliminados, mas 5% das extrações ainda têm JSON válido com arrays vazios ou valores nulos para campos obrigatórios como citações e metodologia.',replace('Depois de implementar o uso de ferramentas com definições de esquema estritas, os erros de sintaxe JSON foram eliminados, mas 5% das extrações ainda têm JSON válido com arrays vazios ou valores nulos para campos obrigatórios como citações e metodologia.\n\nDepois de implementar o uso de ferramentas com definições de esquema estritas, os erros de sintaxe JSON foram eliminados, mas 5% das extrações ainda têm JSON válido com arrays vazios ou valores nulos para campos obrigatórios como citações e metodologia. Uma verificação por amostragem revela que os documentos de origem contêm essas informações, mas em formatos variados — citações inline vs. bibliografias, seções de metodologia vs. detalhes embutidos nas introduções.\n\nQual é a maneira mais eficaz de tratar essas falhas?\n\n[ ] A - Implementar uma lógica de nova tentativa que reenvia as requisições quando a validação detecta campos obrigatórios vazios.\n[ ] B - Construir uma camada de pós-processamento baseada em regex que varre os documentos de origem em busca de padrões de citação e palavras-chave de metodologia, preenchendo os campos vazios quando o modelo falha em extrair.\n[ ] C - Modificar seu esquema para tornar citações e metodologia opcionais e sinalizar os registros incompletos para revisão manual em vez de falhar na validação.\n[ ] D - Adicionar exemplos few-shot demonstrando extrações de documentos com estruturas variadas — mostrando como identificar citações em diferentes formatos e localizar detalhes de metodologia em tipos diferentes de seção.','\n',char(10)),'D - Adicionar exemplos few-shot demonstrando extrações de documentos com estruturas variadas — mostrando como identificar citações em diferentes formatos e localizar detalhes de metodologia em tipos diferentes de seção.','["Domain_4::Prompt_Engineering_Structured_Output", "Domain_2::Tool_Design_MCP_Integration", "Scenario_6::Structured_Data_Extraction"]','New',0,2.5,0,1783092984976,1783725708055,1783203558653,replace('**Tradução para português do Brasil:**\n\nDepois de implementar o uso de ferramentas com definições de esquema estritas, os erros de sintaxe JSON foram eliminados, mas 5% das extrações ainda têm JSON válido com arrays vazios ou valores nulos para campos obrigatórios como citações e metodologia. Uma verificação por amostragem revela que os documentos de origem contêm essas informações, mas em formatos variados — citações inline vs. bibliografias, seções de metodologia vs. detalhes embutidos nas introduções.\n\nQual é a maneira mais eficaz de tratar essas falhas?\n\n[ ] A - Implementar uma lógica de nova tentativa que reenvia as requisições quando a validação detecta campos obrigatórios vazios.\n[ ] B - Construir uma camada de pós-processamento baseada em regex que varre os documentos de origem em busca de padrões de citação e palavras-chave de metodologia, preenchendo os campos vazios quando o modelo falha em extrair.\n[ ] C - Modificar seu esquema para tornar citações e metodologia opcionais e sinalizar os registros incompletos para revisão manual em vez de falhar na validação.\n[ ] D - Adicionar exemplos few-shot demonstrando extrações de documentos com estruturas variadas — mostrando como identificar citações em diferentes formatos e localizar detalhes de metodologia em tipos diferentes de seção.','\n',char(10)),replace('**Explicação para um adulto tech lead:**\n\nO problema central aqui é que o modelo falha em extrair campos obrigatórios não por erro de sintaxe JSON, mas por não reconhecer a informação quando ela aparece em formatos não padronizados. Os documentos de origem *têm* os dados, mas o modelo não os identifica corretamente (arrays vazios, valores nulos).\n\nVamos analisar cada alternativa:\n\n**A - Implementar uma lógica de nova tentativa** – Isso apenas repetiria a mesma chamada com o mesmo prompt e contexto. Se o modelo já falhou uma vez com um documento específico, muito provavelmente falhará de novo, pois a raiz do problema (falta de compreensão dos diferentes formatos) não foi tratada. Seria ineficaz e custaria mais tempo e tokens sem benefício.\n\n**B - Construir uma camada de pós-processamento baseada em regex** – Usar expressões regulares para varrer documentos em busca de padrões de citação e metodologia é frágil, propenso a falsos positivos e difícil de manter. Além disso, é um trabalho redundante: se você tem um modelo de linguagem para extração, delegar parte da tarefa a regex anula o propósito do modelo, que é justamente lidar com variações linguísticas e estruturais. Isso também cria um acoplamento indesejado e aumenta a complexidade do pipeline.\n\n**C - Modificar seu esquema para tornar campos opcionais** – Isso apenas "esconde" o problema, transformando erros silenciosos em registros incompletos que exigem revisão manual. É uma abordagem reativa que aumenta o custoperacional (revisão manual) e não resolve a causa raiz. Sinalizar para revisão manual pode ser um fallback, mas não é a *maneira mais eficaz* de tratar as falhas.\n\n**D - Adicionar exemplos few-shot demonstrando extrações de documentos com estruturas variadas** – Esta é a abordagem mais eficaz porque ataca a causa raiz: o modelo não aprendeu a generalizar para diferentes formatos de apresentação das informações. Ao fornecer exemplos few-shot (ou, idealmente, fine-tuning com dados diversificados), você ensina o modelo a reconhecer citações inline, bibliografias ao final, metodologia em seções dedicadas ou embutida em introduções, etc. Isso melhora a capacidade de extração do modelo de forma consistente, sem adicionar complexidade operacional ou depender de heurísticas frágeis.\n\n**Resumo:** A alternativa D é a única que trata a causa raiz (incapacidade do modelo de lidar com variações estruturais) de forma escalável e eficiente.','\n',char(10)),replace('Imagine que você pediu para um robô ajudar a encontrar informações em textos, tipo "onde estão as citações" e "qual é a metodologia". Você ensinou o robô a escrever direitinho, sem errar a pontuação, mas ainda assim, em 5 em cada 100 textos, ele volta dizendo "não achei nada" — mesmo que a informação esteja lá, só que escrita de um jeito diferente.\n\nAgora, quais soluções você pode tentar?\n\n**A - Pedir para o robô tentar de novo** – Isso não adianta muito, porque o robô vai tentar do mesmo jeito e provavelmente errar de novo. É como reler a mesma página do livro esperando achar uma palavra que você não tá procurando direito.\n\n**B - Usar um "caça-palavras" (regex)** – Você cria regras do tipo "procure por palavras como ''citado por'' ou ''segundo''" para preencher os campos vazios. O problema é que isso é muito rígido: se a citação estiver escrita de um jeito diferente, o caça-palavras não acha. Além disso, você está fazendo um trabalho que o robô deveria fazer.\n\n**C - Tornar os campos opcionais** – Você simplesmente diz "ah, tudo bem, não precisa preencher". Aí o robô deixa os campos em branco e alguém tem que revisar manualmente. Isso só empurra o problema para frente e dá mais trabalho para as pessoas.\n\n**D - Mostrar exemplos para o robô aprender** – Você pega vários textos com citações em formatos diferentes (umas no meio do texto, outras no final) e metodologias (umas numa seção separada, outras misturadas na introdução) e mostra para o robô: "Olha, aqui a citação está assim, ali está assado, mas você tem que achar nos dois casos". Isso ensina o robô a reconhecer os padrões, e ele passa a acertar muito mais vezes.\n\n**Qual é a melhor? A letra D**, porque ensina o robô a lidar com as diferenças, em vez de ficar tentando concertar o erro depois ou empurrar o trabalho para outra pessoa.','\n',char(10)));
INSERT INTO cards VALUES('admin','card_1783092984986_melrgj2l8',128,'Seu pipeline de extração processa faturas e extrai itens de linha, subtotais, valores de impostos e totais gerais.',replace('Seu pipeline de extração processa faturas e extrai itens de linha, subtotais, valores de impostos e totais gerais.\n\nSeu pipeline de extração processa faturas e extrai itens de linha, subtotais, valores de impostos e totais gerais. Durante a avaliação, você descobre que em 18% das extrações a soma dos valores dos itens de linha extraídos não corresponde ao total geral extraído — às vezes por erros de OCR no documento de origem, às vezes por erros de extração do modelo. Os sistemas contábeis downstream rejeitam registros com totais discrepantes.\n\nQual é a abordagem mais eficaz para melhorar a confiabilidade da extração?\n\n[ ] A - Adicionar um campo "`calculated_total`", em que o modelo soma os itens de linha extraídos, ao lado de um campo "`stated_total`". Sinalizar os registros para revisão humana quando os valores diferirem.\n[ ] B - Extrair os itens de linha e os totais de forma independente e, então, usar um modelo de validação separado para reconciliar as discrepâncias, determinando quais valores extraídos são mais prováveis de estar corretos.\n[ ] C - Adicionar exemplos few-shot demonstrando faturas em que os itens de linha extraídos somam corretamente ao total declarado, incentivando o modelo a produzir extrações matematicamente consistentes.\n[ ] D - Implementar um pós-processamento que ajusta automaticamente os valores dos itens de linha de forma proporcional quando a soma deles não corresponde ao total declarado.','\n',char(10)),'A - Adicionar um campo "`calculated_total`", em que o modelo soma os itens de linha extraídos, ao lado de um campo "`stated_total`". Sinalizar os registros para revisão humana quando os valores diferirem.','["Domain_4::Prompt_Engineering_Structured_Output", "Domain_5::Context_Management_Reliability", "Scenario_6::Structured_Data_Extraction"]','New',0,2.5,0,1783092984986,1783725711525,1783203558653,replace('**Tradução para português do Brasil:**\n\n**Pergunta:** Seu pipeline de extração processa faturas e extrai itens de linha, subtotais, valores de impostos e totais gerais. Durante a avaliação, você descobre que em 18% das extrações a soma dos valores dos itens de linha extraídos não corresponde ao total geral extraído — às vezes por erros de OCR no documento de origem, às vezes por erros de extração do modelo. Os sistemas contábeis downstream rejeitam registros com totais discrepantes.\n\nQual é a abordagem mais eficaz para melhorar a confiabilidade da extração?\n\n[ ] A - Adicionar um campo "calculated_total", em que o modelo soma os itens de linha extraídos, ao lado de um campo "stated_total". Sinalizar os registros para revisão humana quando os valores diferirem.\n\n[ ] B - Extrair os itens de linha e os totais de forma independente e, então, usar um modelo de validação separado para reconciliar as discrepâncias, determinando quais valores extraídos são mais prováveis de estar corretos.\n\n[ ] C - Adicionar exemplos few-shot demonstrando faturas em que os itens de linha extraídos somam corretamente ao total declarado, incentivando o modelo a produzir extrações matematicamente consistentes.\n\n[ ] D - Implementar um pós-processamento que ajusta automaticamente os valores dos itens de linha de forma proporcional quando a soma deles não corresponde ao total declarado.','\n',char(10)),replace('**Explicação para um adulto tech lead:**\n\n**Resposta correta: Alternativa A**\n\nO problema central aqui é que o sistema contábil downstream **rejeita** registros com totais discrepantes. Isso significa que a tolerância para erros é zero — qualquer inconsistência entre a soma dos itens de linha e o total geral inviabiliza o registro.\n\nA alternativa A é a mais eficaz porque:\n\n1. **Preserva a integridade dos dados originais**: Ao manter tanto o `calculated_total` (derivado dos itens de linha extraídos) quanto o `stated_total` (extraído diretamente do documento), você não perde informação. Você pode auditar qual campo está correto.\n\n2. **Cria um mecanismo de fallback com revisão humana**: Sinalizar para revisão humana quando há discrepância é uma estratégia madura de ML em produção. Você não "adivinha" qual valor está correto — você delega a decisão a um especialista. Isso é particularmente importante porque as fontes de erro são variadas (OCR vs. modelo de extração), e um modelo de validação adicional (alternativa B) pode cometer erros de validação também.\n\n3. **Evita falsa consistência**: Diferente da alternativa D (que ajusta valores proporcionalmente, criando dados artificialmente precisos que não refletem a realidade da fatura), a alternativa A expõe a discrepância em vez de mascará-la.\n\n**Por que as demais alternativas são inferiores:**\n\n- **Alternativa B**: Adicionar um modelo de validação separado introduz outra camada de complexidade e outra fonte potencial de erro. Se o modelo de validação errar, você terá falsos positivos ou falsos negativos. Além disso, "determinar quais valores extraídos são mais prováveis de estar corretos" é um problema de alta incerteza — você não tem um ground truth confiável nesse cenário. A abordagem é mais custosa e menos confiável que a revisão humana direcionada.\n\n- **Alternativa C**: Exemplos few-shot podem melhorar a qualidade da extração, mas não resolvem o problema fundamental: erros de OCR no documento de origem não serão corrigidos por prompting. O modelo pode aprender a "forçar" consistência matemática onde ela não existe, gerando extrações incorretas mas consistentes — o que é pior, pois o erro fica oculto.\n\n- **Alternativa D**: Ajustar valores proporcionalmente é perigoso. Primeiro, porque você está alterando dados extraídos sem validação, o que pode levar a inconsistências contábeis graves. Segundo, porque nem sempre o erro está nos itens de linha — o total declarado pode ser o valor correto extraído incorretamente. Ajustar cegamente os itens de linha introduz ruído nos dados sem resolver a causa raiz.\n\n**Conclusão**: Em pipelines de extração para sistemas contábeis, a confiabilidade vem da capacidade de detectar e sinalizar erros, não de mascará-los. A alternativa A é a única que oferece um caminho claro para auditoria e correção, respeitando a integridade dos dados e as restrições do sistema downstream.','\n',char(10)),replace('Imagine que você está copiando a lição de casa de um amigo. Às vezes, você copia errado um número ou seu amigo escreveu errado no quadro. Quando você vai verificar, a soma das continhas não bate com o resultado final.\n\nA **alternativa A** é tipo: você anota o resultado que seu amigo escreveu E também faz a conta você mesmo. Se os dois números forem diferentes, você levanta a mão e chama a professora para ver qual está certo. Isso é bom porque você não fica inventando resposta — você pede ajuda de quem sabe.\n\nA **alternativa B** seria pedir para outro amigo verificar. Mas esse amigo também pode errar!\n\nA **alternativa C** seria a professora mostrar exemplos de contas certas antes de você começar. Isso ajuda, mas se o erro está no papel que você está copiando, não adianta.\n\nA **alternativa D** seria chutar: "ah, vou aumentar um pouquinho cada número até dar o resultado". Isso é ruim porque você pode estar estragando as contas certas que já tinha copiado.\n\nEntão a melhor ideia é fazer igual a alternativa A: anotar os dois valores (o que você leu e o que você calculou) e, se forem diferentes, pedir ajuda de um humano para ver qual é o certo.','\n',char(10)));
INSERT INTO cards VALUES('admin','card_1783092984995_dv3fqabt1',129,'Sua extração usa uso de ferramentas com um esquema JSON em que `property_type` é definido como um enum: [''house'', ''apartment'', ''condo'', ''townhouse''].',replace('Sua extração usa uso de ferramentas com um esquema JSON em que `property_type` é definido como um enum: [''house'', ''apartment'', ''condo'', ''townhouse''].\n\nSua extração usa uso de ferramentas com um esquema JSON em que `property_type` é definido como um enum: [''house'', ''apartment'', ''condo'', ''townhouse'']. Após a implantação, 8% das extrações falham na validação do esquema. A investigação revela que os anúncios mencionam muitos tipos de imóvel incomuns — "studio", "loft", "duplex", "mobile home", "tiny house", "converted warehouse" — e novos tipos continuam surgindo regularmente.\n\nQual é a solução de longo prazo mais eficaz?\n\n[ ] A - Expandir continuamente o enum para incluir os tipos de imóvel recém-observados e adicionar monitoramento para casos extremos adicionais.\n[ ] B - Adicionar um valor "other" ao seu enum, com um campo string `property_type_detail` separado para as especificidades quando "other" for selecionado.\n[ ] C - Mudar `property_type` de enum para uma string de formato livre e implementar uma etapa de normalização no pós-processamento.\n[ ] D - Adicionar exemplos few-shot ao seu prompt demonstrando como mapear tipos de imóvel inesperados para o valor de enum existente mais próximo.','\n',char(10)),'B - Adicionar um valor "other" ao seu enum, com um campo string `property_type_detail` separado para as especificidades quando "other" for selecionado.','["Domain_4::Prompt_Engineering_Structured_Output", "Domain_2::Tool_Design_MCP_Integration", "Scenario_6::Structured_Data_Extraction"]','New',0,2.5,0,1783092984995,1783725715812,1783203558653,replace('**Tradução para português do Brasil:**\n\nSua extração usa um esquema JSON onde `property_type` é definido como um enum: [''house'', ''apartment'', ''condo'', ''townhouse''].\n\nApós a implantação, 8% das extrações falham na validação do esquema. A investigação revela que os anúncios mencionam muitos tipos de imóvel incomuns — "studio", "loft", "duplex", "mobile home", "tiny house", "converted warehouse" — e novos tipos continuam surgindo regularmente.\n\nQual é a solução de longo prazo mais eficaz?\n\n[ ] A - Expandir continuamente o enum para incluir os tipos de imóvel recém-observados e adicionar monitoramento para casos extremos adicionais.\n[ ] B - Adicionar um valor "other" ao seu enum, com um campo string `property_type_detail` separado para as especificidades quando "other" for selecionado.\n[ ] C - Mudar `property_type` de enum para uma string de formato livre e implementar uma etapa de normalização no pós-processamento.\n[ ] D - Adicionar exemplos few-shot ao seu prompt demonstrando como mapear tipos de imóvel inesperados para o valor de enum existente mais próximo.','\n',char(10)),replace('**Explicação para adulto tech lead:**\n\nO problema central é que o esquema possui um enum restrito que não cobre a variedade real e crescente de tipos de imóvel. Isso gera 8% de falhas de validação, e a tendência é que esse percentual aumente com o surgimento de novos tipos.\n\n**Análise das alternativas:**\n\n- **Alternativa A** — Expandir continuamente o enum requer intervenção manual frequente, não escala, aumenta a complexidade de manutenção do esquema e quebra compatibilidade retroativa. É uma abordagem reativa e insustentável a longo prazo.\n\n- **Alternativa B (correta)** — Adicionar um valor "other" ao enum resolve permanentemente o problema de validação, pois qualquer tipo não previsto será aceito. O campo `property_type_detail` em string livre preserva a informação original para análises futuras, reclassificações ou treinamento de modelos. É a abordagem que equilibra robustez (nunca falha na validação) com flexibilidade (não perde dados) e escalabilidade (não exige manutenção constante do enum).\n\n- **Alternativa C** — Mudar para string livre elimina a validação estrutural, o que é arriscado: permite dados inconsistentes (e.g., "APARTMENT", "apartamento", "apto"), dificulta consultas, agregações e creates índices em banco de dados. A normalização no pós-processamento é frágil e externaliza a responsabilidade de garantir a qualidade dos dados.\n\n- **Alternativa D** — Few-shot no prompt para mapear tipos inesperados para o enum existente força um encaixe artificial (ex.: mapear "tiny house" para "house" ou "converted warehouse" para "condo"?). Isso introduz ruído e perda de informação semântica, além de não garantir que a LLM sempre mapeie corretamente — ainda pode gerar valores inválidos.\n\n**Conclusão:** A alternativa B é a mais robusta e escalável, pois resolve a validação sem perder informação e sem exigir manutenção contínua do esquema.','\n',char(10)),replace('Imagine que você tem uma caixa de brinquedos com 4 gavetas: "casa", "apartamento", "condomínio" e "sobrado". Mas aparecem brinquedos novos como "estúdio", "loft" e "casa na árvore". Como nem toda gaveta cabe certinho, 8 em cada 100 brinquedos ficam amontoados fora da caixa e isso é um problema!\n\n**Opção A:** Ficar criando gavetas novas o tempo todo. Se surgir "loft", faz gaveta "loft". Depois "duplex", faz "duplex". Isso dá muito trabalho e nunca acaba.\n\n**Opção B (a melhor):** Criar uma gaveta chamada "outros" para tudo que não se encaixa nas 4 principais, e colocar um papel dentro dizendo exatamente o que é (ex.: "é um loft"). Assim, nunca sobra brinquedo de fora e você sabe exatamente o que tem.\n\n**Opção C:** Jogar fora as gavetas e deixar tudo solto numa caixa gigante. Fica bagunçado e difícil de achar depois.\n\n**Opção D:** Tentar enfiar "casa na árvore" na gaveta "casa" e dizer "é quase a mesma coisa". Mas não é, e você perde informação importante.\n\nA solução mais esperta é a **B**: ter uma gaveta coringa "outros" com um detalhe escrito do lado explicando o que é.','\n',char(10)));
INSERT INTO cards VALUES('admin','card_1783092985006_z2hqxcong',130,'Seu sistema de extração analisa descrições de produtos de e-commerce para extrair especificações como dimensões, peso e materiais em JSON.',replace('Seu sistema de extração analisa descrições de produtos de e-commerce para extrair especificações como dimensões, peso e materiais em JSON.\n\nSeu sistema de extração analisa descrições de produtos de e-commerce para extrair especificações como dimensões, peso e materiais em JSON. Apesar de ter um esquema bem definido, o modelo extrai o campo "materials" de forma inconsistente — às vezes retornando "cotton blend", outras vezes "Cotton/Polyester mix" e, ocasionalmente, omitindo o campo quando a informação de material está claramente presente na fonte.\n\nQual é a maneira mais eficaz de melhorar a consistência da extração?\n\n[ ] A - Tornar o campo "materials" obrigatório em vez de opcional no esquema para forçar o modelo a sempre extrair um valor\n[ ] B - Migrar para um nível de modelo mais capaz, já que a extração inconsistente indica capacidade de modelo insuficiente\n[ ] C - Definir a temperatura como 0 para eliminar a aleatoriedade e garantir saídas determinísticas\n[ ] D - Adicionar exemplos few-shot mostrando 2-3 pares completos de entrada-saída com formatos padronizados de descrição de material','\n',char(10)),'D - Adicionar exemplos few-shot mostrando 2-3 pares completos de entrada-saída com formatos padronizados de descrição de material','["Domain_4::Prompt_Engineering_Structured_Output", "Domain_2::Tool_Design_MCP_Integration", "Scenario_6::Structured_Data_Extraction"]','New',0,2.5,0,1783092985006,1783725719840,1783203558653,replace('**Tradução para Português do Brasil:**\n\nSeu sistema de extração analisa descrições de produtos de e-commerce para extrair especificações como dimensões, peso e materiais em JSON. Apesar de ter um esquema bem definido, o modelo extrai o campo "materials" de forma inconsistente — às vezes retornando "cotton blend", outras vezes "Cotton/Polyester mix" e, ocasionalmente, omitindo o campo quando a informação de material está claramente presente na fonte.\n\nQual é a maneira mais eficaz de melhorar a consistência da extração?\n\n[ ] A - Tornar o campo "materials" obrigatório em vez de opcional no esquema para forçar o modelo a sempre extrair um valor\n[ ] B - Migrar para um nível de modelo mais capaz, já que a extração inconsistente indica capacidade de modelo insuficiente\n[ ] C - Definir a temperatura como 0 para eliminar a aleatoriedade e garantir saídas determinísticas\n[ ] D - Adicionar exemplos few-shot mostrando 2-3 pares completos de entrada-saída com formatos padronizados de descrição de material','\n',char(10)),replace('**Explicação para um adulto tech lead:**\n\nO problema central é que o modelo está gerando variações na formatação e no conteúdo do campo "materials", além de omiti-lo em alguns casos. Vamos analisar cada alternativa:\n\n**Alternativa A - Tornar o campo "materials" obrigatório no esquema:** Isso força o modelo a sempre preencher o campo, mas não resolve a inconsistência de formatação. O modelo pode continuar gerando variações como "cotton blend", "Cotton/Polyester mix" etc., e ainda pode inventar um valor quando o material não está presente na fonte, gerando alucinações. A obrigatoriedade não ensina o formato esperado nem melhora a consistência semântica.\n\n**Alternativa B - Migrar para um modelo mais capaz:** Modelos mais poderosos geralmente têm melhor desempenho, mas o problema descrito não é de incapacidade de compreensão — o modelo claramente entende que há materiais na descrição (tanto que às vezes extrai corretamente). O problema é de inconsistência na *formatação* da saída. Um modelo mais caro e lento pode atenuar o problema, mas não ataca a causa raiz. É uma abordagem cara e desnecessária.\n\n**Alternativa C - Definir temperatura como 0:** Temperatura zero elimina a aleatoriedade na amostragem, tornando as saídas determinísticas para uma mesma entrada. Isso reduz variação aleatória, mas não resolve inconsistências sistemáticas de formato. Se o prompt não instrui explicitamente um formato padronizado, mesmo com temperatura zero o modelo pode gerar diferentes variações dependendo de pequenas diferenças na representação interna. Além disso, temperatura zero não impede omissões ocasionais — o modelo ainda pode "decidir" não incluir o campo se o prompt não for claro o suficiente.\n\n**Alternativa D - Adicionar exemplos few-shot com formatos padronizados:** Esta é a abordagem mais eficaz porque ataca diretamente a causa raiz. Ao fornecer 2-3 exemplos completos de entrada-saída onde o campo "materials" aparece sempre no mesmo formato padronizado (por exemplo, sempre como um array de strings normalizado), você está ensinando ao modelo exatamente qual comportamento de saída é esperado. O few-shot learning é uma técnica bem estabelecida para "programar" o comportamento de LLMs via exemplos no prompt. Isso resolve tanto a inconsistência de formatação (o modelo aprende o padrão) quanto a omissão (os exemplos mostram que o campo deve sempre estar presente quando há informação). É a solução mais simples, mais barata e mais direta.','\n',char(10)),replace('Imagina que você tem um robô que lê fichas de brinquedos e precisa escrever o material de cada um. Mas ele escreve de jeitos diferentes: um dia "algodão", outro dia "ALGODÃO", e às vezes nem escreve nada, mesmo vendo a informação.\n\nA melhor forma de ensinar o robô a fazer sempre igual é mostrar 2 ou 3 exemplos prontos, como se fosse um dever de casa resolvido. Por exemplo: mostrar a ficha de uma camiseta com "Tecido: algodão" e do lado o robô escrevendo "Algodão". Depois mostrar outra ficha com "Material: poliéster" e ele escrevendo "Poliéster". Assim ele aprende o jeito certo de fazer!\n\nAs outras opções não são tão boas:\n- Forçar ele a escrever sempre (opção A) não ensina o formato certo, só obriga a escrever algo.\n- Trocar de robô (opção B) é caro e não resolve o problema de ensinar o formato.\n- Deixar ele sem criatividade (opção C) ajuda um pouco, mas ainda assim ele pode errar o formato.','\n',char(10)));
INSERT INTO cards VALUES('admin','card_1783092985030_x9rf9p2nh',131,'Documentos chegam continuamente ao longo do horário comercial e precisam ter dados estruturados extraídos.',replace('Documentos chegam continuamente ao longo do horário comercial e precisam ter dados estruturados extraídos.\n\nDocumentos chegam continuamente ao longo do horário comercial e precisam ter dados estruturados extraídos. Para reduzir custos, você quer usar a `Message Batches API` (50% de desconto, janela de processamento de até 24 horas). Seu SLA especifica que os resultados da extração devem estar disponíveis em até 30 horas da chegada do documento, com 99,9% de confiabilidade.\n\nQual estratégia de batch é a mais apropriada?\n\n[ ] A - Enviar batches a cada 6 horas contendo os documentos daquela janela\n[ ] B - Enviar um único batch no fim do dia contendo todos os documentos daquele dia\n[ ] C - Enviar batches a cada 4 horas contendo os documentos daquela janela\n[ ] D - Usar a API em tempo real para todos os documentos em vez do processamento em batch','\n',char(10)),'A - Enviar batches a cada 6 horas contendo os documentos daquela janela','["Domain_4::Prompt_Engineering_Structured_Output", "Domain_5::Context_Management_Reliability", "Scenario_6::Structured_Data_Extraction"]','New',0,2.5,0,1783092985030,1783725723632,1783203558653,replace('**Tradução para pt-BR:**\n\nDocumentos chegam continuamente ao longo do horário comercial e precisam ter dados estruturados extraídos. Para reduzir custos, você quer usar a Message Batches API (50% de desconto, janela de processamento de até 24 horas). Seu SLA especifica que os resultados da extração devem estar disponíveis em até 30 horas da chegada do documento, com 99,9% de confiabilidade.\n\nQual estratégia de batch é a mais apropriada?\n\n[ ] A - Enviar batches a cada 6 horas contendo os documentos daquela janela\n[ ] B - Enviar um único batch no fim do dia contendo todos os documentos daquele dia\n[ ] C - Enviar batches a cada 4 horas contendo os documentos daquela janela\n[ ] D - Usar a API em tempo real para todos os documentos em vez do processamento em batch','\n',char(10)),replace('**Explicação para adulto tech lead:**\n\nA Message Batches API da OpenAI tem uma janela de processamento de até 24 horas (com 50% de desconto) e o SLA exige que os resultados estejam disponíveis em até 30 horas da chegada do documento.\n\nO documento chega em um determinado instante. O pior caso de atraso é:\n- Tempo até o próximo envio do batch (janela de coleta)\n- + tempo de processamento do batch (até 24h)\n- = total deve ser ≤ 30h\n\nLogo, o tempo máximo de espera até o envio do batch (janela de coleta) é de 30h - 24h = 6h.\n\nAnalisando as alternativas:\n\n**Alternativa A (correta):** Enviar batches a cada 6 horas. No pior caso, um documento que chega logo após o fechamento de um batch espera 6h para ser enviado, e então até 24h para ser processado. Total = 6 + 24 = 30h, exatamente no limite do SLA. É a estratégia mais econômica que ainda cumpre o SLA.\n\n**Alternativa B (incorreta):** Enviar um único batch no fim do dia. Se o dia comercial tem 8h (ex.: 9h-18h), um documento que chega às 9h espera 9h até o fim do dia (18h) + até 24h de processamento = 33h, superando o SLA de 30h. Se o dia for menor, ainda assim o atraso acumulado ultrapassa 30h dependendo do horário de chegada.\n\n**Alternativa C (incorreta):** Enviar batches a cada 4 horas. Também cumpre o SLA (4 + 24 = 28h ≤ 30h), mas é mais granular que o necessário, gerando mais chamadas de API e mais custo operacional (embora o desconto de 50% se aplique). A questão pede a estratégia "mais apropriada" — e a cada 6h é suficiente e mais eficiente.\n\n**Alternativa D (incorreta):** Usar a API em tempo real. Isso elimina o desconto de 50% e aumenta os custos, contrariando o objetivo declarado de reduzir custos. Não faz sentido dado o contexto.','\n',char(10)),replace('Vamos pensar em uma história bem simples.\n\nImagine que você é um carteiro que precisa entregar cartas para uma casa muito longe. A viagem até lá demora até 24 horas. E o chefe disse: "A carta precisa chegar em até 30 horas depois que você a recebeu."\n\nAí você descobre que, se juntar várias cartas em um pacote (batch), você paga metade do preço! Mas você não pode demorar muito para juntar as cartas, senão elas chegam atrasadas.\n\nSe você demorar 6 horas para juntar as cartas e depois demorar até 24 horas na viagem, dá 6 + 24 = 30 horas. No limite, mas ainda dentro do prazo!\n\nAs opções:\n\n**A - Juntar cartas a cada 6 horas.** ✅ Certa! Dá tempo de sobra e é a mais barata possível.\n\n**B - Juntar só no fim do dia.** ❌ Se você recebe uma carta às 9h da manhã e só junta ela às 18h (fim do dia), já se passaram 9 horas. Aí +24h de viagem = 33h. Passou do prazo de 30h.\n\n**C - Juntar a cada 4 horas.** ❌ Também funcionaria, mas você estaria fazendo mais viagens do que o necessário, gastando mais trabalho.\n\n**D - Entregar cada carta sozinha (tempo real).** ❌ Isso sai muito mais caro, e a gente queria economizar, lembra?\n\nEntão a melhor escolha é a letra **A**: juntar as cartas a cada 6 horas.','\n',char(10)));
INSERT INTO cards VALUES('admin','card_1783092985041_5b4pwxthf',132,'Após a implantação, você descobre que 12% das extrações contêm erros semânticos que passam na validação do esquema JSON (por exemplo, uma duração como "30 minutes" colocada incorretamente em um campo de quantidade de ingrediente).',replace('Após a implantação, você descobre que 12% das extrações contêm erros semânticos que passam na validação do esquema JSON (por exemplo, uma duração como "30 minutes" colocada incorretamente em um campo de quantidade de ingrediente).\n\nApós a implantação, você descobre que 12% das extrações contêm erros semânticos que passam na validação do esquema JSON (por exemplo, uma duração como "30 minutes" colocada incorretamente em um campo de quantidade de ingrediente). Os revisores humanos têm capacidade para verificar apenas 20% das extrações.\n\nQual abordagem aloca a atenção dos revisores de forma mais eficaz?\n\n[ ] A - Fazer o modelo gerar pontuações de confiança no nível de campo e, então, calibrar os limiares de revisão usando um conjunto de validação rotulado.\n[ ] B - Amostrar aleatoriamente 20% das extrações para revisão, usando as correções para acompanhar a precisão e identificar padrões de erro.\n[ ] C - Priorizar a revisão de todas as extrações em que campos obrigatórios estão vazios ou explicitamente marcados como não encontrados.\n[ ] D - Revisar todas as extrações de documentos com anomalias de formatação, como layouts incomuns ou tipos de conteúdo mistos.','\n',char(10)),'A - Fazer o modelo gerar pontuações de confiança no nível de campo e, então, calibrar os limiares de revisão usando um conjunto de validação rotulado.','["Domain_4::Prompt_Engineering_Structured_Output", "Domain_5::Context_Management_Reliability", "Domain_2::Tool_Design_MCP_Integration", "Scenario_6::Structured_Data_Extraction"]','New',0,2.5,0,1783092985041,1783725728080,1783203558653,replace('**Tradução para português do Brasil:**\n\nApós a implantação, você descobre que 12% das extrações contêm erros semânticos que passam na validação do esquema JSON (por exemplo, uma duração como "30 minutes" colocada incorretamente em um campo de quantidade de ingrediente). Os revisores humanos têm capacidade para verificar apenas 20% das extrações.\n\nQual abordagem aloca a atenção dos revisores de forma mais eficaz?\n\n[ ] A - Fazer o modelo gerar pontuações de confiança no nível de campo e, então, calibrar os limiares de revisão usando um conjunto de validação rotulado.\n[ ] B - Amostrar aleatoriamente 20% das extrações para revisão, usando as correções para acompanhar a precisão e identificar padrões de erro.\n[ ] C - Priorizar a revisão de todas as extrações em que campos obrigatórios estão vazios ou explicitamente marcados como não encontrados.\n[ ] D - Revisar todas as extrações de documentos com anomalias de formatação, como layouts incomuns ou tipos de conteúdo mistos.','\n',char(10)),replace('**Explicação para um adulto tech lead:**\n\nO problema central é que temos 12% de erros semânticos (que passam pela validação de esquema JSON) e capacidade de revisão para apenas 20% das extrações. O objetivo é alocar esse recurso limitado de revisão humana da forma mais eficaz possível — ou seja, maximizar a quantidade de erros detectados dentro do orçamento de 20% de revisão.\n\n**Análise das alternativas:**\n\n**A - CORRETA.** Esta é a abordagem mais eficaz e fundamentada em princípios de ML confiável (confiable ML). Ao fazer o modelo gerar pontuações de confiança no nível de campo (por exemplo, logits, softmax scores, ou técnicas como temperature scaling), podemos classificar as extrações por nível de incerteza. Com um conjunto de validação rotulado, podemos calibrar um limiar que selecione exatamente os 20% de extrações com maior probabilidade de conter erros. Isso maximiza a taxa de detecção de erros (recall do processo de revisão) dentro da capacidade disponível. É uma aplicação direta de selective prediction / learning to reject.\n\n**B - INCORRETA.** Amostragem aleatória é a abordagem ingênua (baseline). Ela não é eficaz porque, embora forneça uma estimativa não viesada da precisão geral, não concentra a atenção nos casos mais propensos a erro. Com 12% de erros na população, em uma amostra aleatória de 20%, esperamos capturar apenas ~20% dos erros (ou seja, 2,4% das extrações totais serão erros corrigidos). É útil para monitoramento, mas não para alocar revisão de forma a maximizar correções.\n\n**C - INCORRETA.** Revisar extrações com campos obrigatórios vazios ou "não encontrados" pode pegar alguns casos de baixa confiança do modelo, mas o problema específico descrito são erros semânticos (valores errados, não ausentes). Uma duração colocada em campo de quantidade não gera campo vazio. Esses erros passam na validação de esquema, então campos obrigatórios estão preenchidos — com o valor errado. Essa abordagem provavelmente teria baixíssima sobreposição com os erros semânticos reais.\n\n**D - INCORRETA.** Anomalias de formatação podem correlacionar-se com maior taxa de erro, mas não há garantia de que os 12% de erros semânticos estejam concentrados nesses documentos. Além disso, documentos com formatação normal também podem conter erros semânticos. Essa abordagem é heurística e não utiliza dados rotulados para calibrar a decisão. Pode funcionar em alguns cenários, mas é menos eficaz que uma abordagem baseada em confiança calibrada.\n\n**Em resumo:** A abordagem A usa informação do próprio modelo (confiança) para rankear extrações por risco de erro, e usa dados rotulados para calibrar o ponto de corte exato que maximiza a detecção dentro do limite de 20%. É a única que otimiza diretamente a alocação do recurso escasso de revisão humana.','\n',char(10)),replace('Imagine que você tem um robô que lê receitas e anota os ingredientes. Mas 12 em cada 100 receitas têm um errinho chato: ele escreve "30 minutos" no lugar de "3 xícaras de farinha", por exemplo. Só que você só tem tempo de conferir 20 em cada 100 receitas. Como escolher quais conferir?\n\n**Alternativa A (a resposta certa):** Peça para o robô dar uma "nota de confiança" para cada campo que ele preencheu. Tipo: "tenho 95% de certeza disso aqui" ou "só 30% de certeza". Aí você pega algumas receitas já corrigidas por humanos, descobre qual a nota de corte ideal e manda os revisores conferirem só as 20% receitas com as piores notas. Assim você pega a maioria dos erros!\n\n**Alternativa B:** Sortear 20 receitas aleatoriamente. Você pode até descobrir quantos erros existem no total, mas vai deixar passar a maioria dos erros reais — tipo achar agulha num palheiro de olhos vendados.\n\n**Alternativa C:** Conferir só receitas onde o robô deixou um campo em branco. O problema é que os erros são justamente quando ele *preencheu* algo errado (escreveu "30 minutos" no lugar certo), então essa dica não ajuda.\n\n**Alternativa D:** Conferir só receitas com letras miúdas ou desenhos diferentes. Mas receitas normais também podem ter erros, e você pode perder vários.\n\n**Então a melhor ideia é a A: usar a nota de confiança do robô para focar a revisão onde ele está mais inseguro!**','\n',char(10)));
INSERT INTO cards VALUES('admin','card_1783092985053_106xv5118',133,'Sistema de Pesquisa Multiagente',replace('Sistema de Pesquisa Multiagente\n\nO monitoramento de produção mostra qualidade inconsistente de síntese. Quando os resultados agregados têm ~75K tokens, o agente de síntese cita de forma confiável informações dos primeiros 15K tokens (manchetes/snippets de busca web) e dos últimos 10K (conclusões da análise de documentos), mas frequentemente perde achados críticos nos 50K do meio — mesmo quando respondem diretamente à pergunta de pesquisa. Como reestruturar a entrada agregada?\n\n[ ] A - Sumarizar todas as saídas dos subagentes para abaixo de 20K tokens antes da agregação para manter o conteúdo dentro do alcance confiável de processamento do modelo.\n[ ] B - Streamar incrementalmente os resultados dos subagentes ao agente de síntese, processando primeiro os de busca web até concluir e depois adicionando os de análise de documentos.\n[ ] C - Posicionar um sumário de achados-chave no início da entrada agregada e organizar resultados detalhados com cabeçalhos de seção explícitos para navegação mais fácil.\n[ ] D - Implementar rotação que alterne quais resultados aparecem primeiro entre tarefas de pesquisa para garantir que ambas as fontes ganhem posição superior ao longo do tempo.','\n',char(10)),'C - Posicionar um sumário de achados-chave no início da entrada agregada e organizar resultados detalhados com cabeçalhos de seção explícitos para navegação mais fácil.','["Domain_1::Agentic_Architecture_Orchestration", "Domain_5::Context_Management_Reliability", "Domain_4::Prompt_Engineering_Structured_Output", "Scenario_3::Multi_Agent_Research"]','New',0,2.5,0,1783092985053,1783725732349,1783203558653,replace('**Tradução para Português do Brasil:**\n\nSistema de Pesquisa Multiagente\n\nO monitoramento de produção mostra qualidade inconsistente de síntese. Quando os resultados agregados têm ~75K tokens, o agente de síntese cita de forma confiável informações dos primeiros 15K tokens (manchetes/snippets de busca web) e dos últimos 10K (conclusões da análise de documentos), mas frequentemente perde achados críticos nos 50K do meio — mesmo quando respondem diretamente à pergunta de pesquisa. Como reestruturar a entrada agregada?\n\n[ ] A - Sumarizar todas as saídas dos subagentes para abaixo de 20K tokens antes da agregação para manter o conteúdo dentro do alcance confiável de processamento do modelo.\n[ ] B - Streamar incrementalmente os resultados dos subagentes ao agente de síntese, processando primeiro os de busca web até concluir e depois adicionando os de análise de documentos.\n[ ] C - Posicionar um sumário de achados-chave no início da entrada agregada e organizar resultados detalhados com cabeçalhos de seção explícitos para navegação mais fácil.\n[ ] D - Implementar rotação que alterne quais resultados aparecem primeiro entre tarefas de pesquisa para garantir que ambas as fontes ganhem posição superior ao longo do tempo.','\n',char(10)),replace('**Explicação para Adulto (Tech Lead):**\n\nO problema descrito é um caso clássico de viés de posição ("lost-in-the-middle") em LLMs. Modelos de linguagem, especialmente em entradas longas (~75K tokens), tendem a prestar mais atenção ao início (primacy effect) e ao final (recency effect) do contexto, negligenciando informações no meio. O agente de síntese consegue usar bem os primeiros 15K tokens (busca web) e os últimos 10K (conclusões), mas perde os 50K centrais.\n\n**Análise das alternativas:**\n\n- **A (Incorreta):** Sumarizar tudo para abaixo de 20K tokens resolveria o problema de contexto longo, mas joga fora informação potencialmente valiosa. A sumarização é uma compressão com perda — detalhes importantes dos 50K centrais podem ser descartados pelo subagente que sumariza. Além disso, cria-se um gargalo artificial: o agente de síntese jamais teria acesso aos dados brutos, apenas a resumos, o que reduz a qualidade da síntese final.\n\n- **B (Incorreta):** Streaming incremental é uma abordagem interessante, mas a ordem proposta (busca web primeiro, depois documentos) mantém o mesmo problema de viés de posição. Na prática, os documentos seriam processados depois e ocupariam a posição "meio" ou "final" do contexto total, continuando sujeitos ao mesmo fenômeno de "lost-in-the-middle". A abordagem não mitiga a raiz do problema.\n\n- **C (Correta):** Esta é a solução mais alinhada com as melhores práticas atuais para mitigação do "lost-in-the-middle". Ao colocar um sumário de achados-chave no início, garante-se que as informações mais críticas estejam na zona de atenção privilegiada (primacy). Os cabeçalhos de seção explícitos funcionam como "marcadores de navegação" que ajudam o modelo a segmentar o contexto mentalmente, melhorando a recuperação de informações mesmo na região central. Isso não elimina completamente o viés, mas cria uma hierarquia de informação que torna o conteúdo mais acessível.\n\n- **D (Incorreta):** Rotacionar qual fonte aparece primeiro apenas alterna qual fonte sofre mais com o viés de posição, sem resolver o problema fundamental. Em algumas execuções, busca web será bem lembrada; em outras, documentos. A imprevisibilidade resultante é indesejável para um sistema de produção — a qualidade da síntese se torna inconsistente e não-determinística, prejudicando a confiabilidade.','\n',char(10)),replace('Imagine que você tem uma redação muito grande para ler, tipo um livro de 75 páginas. Você consegue lembrar bem do começo (primeiras 15 páginas) e do final (últimas 10 páginas), mas as 50 páginas do meio viram um borrão e você esquece coisas importantes que estavam lá.\n\n- **Alternativa A** diz para resumir tudo em 20 páginas. Mas aí você perde muitos detalhes importantes — é como se alguém lesse o livro para você e contasse só um resumo bem curtinho, podendo deixar coisas legais de fora.\n\n- **Alternativa B** diz para ler primeiro as páginas da internet e depois as dos documentos. O problema é que você ainda vai esquecer o que está no meio, só mudou a ordem.\n\n- **Alternativa C (a certa!)** diz para fazer um resumão bem no começo com as coisas mais importantes e depois organizar o resto com títulos grandes (como "PARTE 1: PESQUISAS NA INTERNET" e "PARTE 2: DOCUMENTOS"). Assim, mesmo que você se perca no meio, já viu as partes principais no início e os títulos ajudam a encontrar o que procura.\n\n- **Alternativa D** diz para alternar qual parte vem primeiro: hoje a internet, amanhã os documentos. Mas isso não resolve — você continua esquecendo o meio, só muda qual parte é esquecida.\n\nEntão a melhor solução é fazer um resumo do que é mais importante no começo e colocar títulos organizados para o resto. É como usar marcadores num livro grande!','\n',char(10)));
INSERT INTO cards VALUES('admin','card_1783092985064_cuibd3h0l',134,'Sistema de Pesquisa Multiagente',replace('Sistema de Pesquisa Multiagente\n\nEm testes, a saída combinada do agente de busca web (85K tokens incluindo conteúdo de páginas) e do agente de análise de documentos (70K tokens incluindo cadeias de raciocínio) totaliza 155K tokens, mas o agente de síntese performa melhor com entradas abaixo de 50K tokens. Qual solução é mais efetiva?\n\n[ ] A - Modificar agentes upstream para retornar dados estruturados (fatos-chave, citações, scores de relevância) em vez de conteúdo verboso e raciocínio.\n[ ] B - Adicionar um agente intermediário de sumarização que condense achados antes de passá-los à síntese.\n[ ] C - Fazer o agente de síntese processar achados em lotes sequenciais, mantendo estado entre chamadas.\n[ ] D - Armazenar achados em uma base vetorial e dar ao agente de síntese ferramentas de busca para consultar durante o trabalho.','\n',char(10)),'A - Modificar agentes upstream para retornar dados estruturados (fatos-chave, citações, scores de relevância) em vez de conteúdo verboso e raciocínio.','["Domain_1::Agentic_Architecture_Orchestration", "Domain_5::Context_Management_Reliability", "Scenario_3::Multi_Agent_Research"]','New',0,2.5,0,1783092985064,1783725736852,1783203558653,replace('**Tradução para pt-BR:**\n\nSistema de Pesquisa Multiagente\n\nEm testes, a saída combinada do agente de busca web (85K tokens incluindo conteúdo de páginas) e do agente de análise de documentos (70K tokens incluindo cadeias de raciocínio) totaliza 155K tokens, mas o agente de síntese performa melhor com entradas abaixo de 50K tokens. Qual solução é mais efetiva?\n\n[ ] A - Modificar agentes upstream para retornar dados estruturados (fatos-chave, citações, scores de relevância) em vez de conteúdo verboso e raciocínio.\n[ ] B - Adicionar um agente intermediário de sumarização que condense achados antes de passá-los à síntese.\n[ ] C - Fazer o agente de síntese processar achados em lotes sequenciais, mantendo estado entre chamadas.\n[ ] D - Armazenar achados em uma base vetorial e dar ao agente de síntese ferramentas de busca para consultar durante o trabalho.','\n',char(10)),replace('**Explicação para o adulto tech lead:**\n\n**Contexto do problema:** Temos um gargalo no pipeline multiagente. Os agentes upstream (busca web e análise de documentos) produzem juntos 155K tokens — muito acima do limite de 50K tokens onde o agente de síntese tem performance ideal. Precisamos reduzir drasticamente o volume de informação que chega ao agente de síntese, sem perder a essência dos achados.\n\n**Análise das alternativas:**\n\n**Alternativa A (correta) — Modificar agentes upstream para retornar dados estruturados:**\nEsta é a solução mais efetiva porque ataca a causa raiz do problema. Ao invés de enviar conteúdo bruto (páginas web inteiras, cadeias de raciocínio completas), os agentes upstream são modificados para extrair e estruturar a informação relevante: fatos-chave com citações, scores de relevância, metadados. Isso reduz drasticamente o volume de tokens (um fato-chave bem escrito pode ocupar dezenas de tokens vs. milhares de tokens de texto bruto), mantendo apenas o que é essencial para a síntese. É uma abordagem de "extrair antes de transmitir" que resolve a causa do problema — o excesso de tokens — na fonte.\n\n**Alternativa B — Adicionar um agente intermediário de sumarização:**\nEmbora reduza o volume de tokens, esta abordagem adiciona um nó extra no pipeline, aumentando latência, custo computacional e possível perda de informação. O sumarizador pode perder nuances ou fazer simplificações excessivas. Além disso, o agente de sumarização estará processando 155K tokens para condensá-los, o que já é caro e sujeito aos mesmos limites de contexto. A solução é paliativa: trata o sintoma (volume alto) em vez de evitar que o volume alto seja gerado.\n\n**Alternativa C — Processamento em lotes sequenciais com estado:**\nÉ possível, mas complexa de implementar e frágil. Manter estado entre chamadas introduz riscos de inconsistência, e o agente de síntese pode não conseguir manter uma visão global coerente dos achados ao processá-los em pedaços. A performance do agente pode degradar com o acúmulo de estado, e o design fica mais propenso a erros de contexto. É uma solução contornável, mas não ideal.\n\n**Alternativa D — Base vetorial + ferramentas de busca:**\nEsta é uma solução elegante para cenários onde o volume de informação é grande e variável, mas adiciona complexidade significativa (infraestrutura de vetores, embeddings, mecanismo de busca) e latência. Além disso, o agente de síntese pode não encontrar exatamente o que precisa se a consulta não for bem formulada, correndo risco de perder informações relevantes. Para um problema relativamente simples de resolver (agentes upstream geram muito texto), esta solução é um canhão para matar uma formiga.\n\n**Conclusão técnica:** A alternativa A é a mais alinhada com boas práticas de design de sistemas multiagente: cada agente deve ser responsável por extrair e estruturar a informação relevante do seu domínio, entregando dados enxutos e semanticamente ricos para o próximo estágio do pipeline. Isso reduz acoplamento, melhora performance e facilita debugging.','\n',char(10)),replace('Imagine que você está fazendo um trabalho da escola sobre dinossauros. Você pede ajuda para dois amigos:\n\n1. **Amigo da busca** — Ele vai na biblioteca e traz 85 livros pesados sobre dinossauros.\n2. **Amigo da análise** — Ele lê todos os livros e escreve 70 páginas contando tudo que pensou enquanto lia.\n\nJuntos, eles te entregam 155 livros e páginas! Mas o terceiro amigo, que vai escrever o trabalho final, só consegue trabalhar bem se receber menos de 50 coisas para ler.\n\nQual a melhor solução?\n\n**Opção A (a resposta certa):** Pedir para os dois primeiros amigos não trazerem tudo, mas sim fazerem um resumo organizado. Ao invés de trazer livros inteiros, eles trazem uma fichinha para cada dinossauro: "T-Rex — 12 metros, carnívoro, viveu no final do Cretáceo. Fonte: livro X, página 50". Assim, o amigo que escreve o trabalho recebe só o essencial, rapidinho!\n\n**Opção B:** Chamar um quarto amigo para ler tudo que os dois primeiros trouxeram e fazer um resumo. Mas isso dá mais trabalho, demora mais, e esse amigo pode esquecer coisas importantes no resumo.\n\n**Opção C:** Pedir para o amigo que escreve o trabalho ler um pouquinho de cada vez, guardando na cabeça o que já leu. Mas é difícil lembrar de tudo, e ele pode se confundir.\n\n**Opção D:** Criar um fichário gigante com todas as informações e dar uma lupa para o amigo procurar o que precisa. Mas ele pode demorar muito para achar cada coisa, e pode até não encontrar algo importante.\n\nA opção A é a melhor porque resolve o problema desde o começo: ensina os amigos a trazerem informação organizada e só o que importa, sem bagunça!','\n',char(10)));
INSERT INTO cards VALUES('admin','card_1783092985074_gg2fo1x31',135,'Geração de Código com Claude Code',replace('Geração de Código com Claude Code\n\nVocê está adicionando wrappers de tratamento de erros ao redor de chamadas de API externas em uma base de 120 arquivos. O trabalho tem três fases: (1) descobrir todos os call sites e padrões, (2) desenhar colaborativamente a abordagem de tratamento de erros, e (3) implementar wrappers de forma consistente. Na Fase 1, Claude gera saída grande listando centenas de call sites com contexto, enchendo rapidamente a janela de contexto antes da descoberta terminar.\n\nQual abordagem é mais efetiva para concluir a tarefa mantendo consistência de implementação?\n\n[ ] A - Usar um subagente Explore para a Fase 1 para isolar saída verbosa de descoberta e retornar um sumário, depois continuar Fases 2–3 na conversa principal.\n[ ] B - Fazer todas as fases na conversa principal, periodicamente usando `/compact` para reduzir uso de contexto enquanto avança nos arquivos.\n[ ] C - Mudar para modo headless com `--continue`, passando sumários explícitos de contexto entre chamadas em batch para manter continuidade.\n[ ] D - Definir o padrão de tratamento de erros no CLAUDE.md, depois processar arquivos em lotes em múltiplas sessões contando com o arquivo de memória compartilhada para consistência.','\n',char(10)),'A - Usar um subagente Explore para a Fase 1 para isolar saída verbosa de descoberta e retornar um sumário, depois continuar Fases 2–3 na conversa principal.','["Domain_3::Claude_Code_Configuration_Workflows", "Domain_5::Context_Management_Reliability", "Domain_1::Agentic_Architecture_Orchestration", "Scenario_2::Code_Generation_Claude_Code"]','New',0,2.5,0,1783092985074,1783725741099,1783203558653,replace('**Tradução para português do Brasil:**\n\nVocê está adicionando wrappers de tratamento de erros ao redor de chamadas de API externas em uma base de 120 arquivos. O trabalho tem três fases: (1) descobrir todos os call sites e padrões, (2) desenhar colaborativamente a abordagem de tratamento de erros, e (3) implementar wrappers de forma consistente. Na Fase 1, Claude gera saída grande listando centenas de call sites com contexto, enchendo rapidamente a janela de contexto antes da descoberta terminar.\n\nQual abordagem é mais efetiva para concluir a tarefa mantendo consistência de implementação?\n\n[ ] A - Usar um subagente Explore para a Fase 1 para isolar saída verbosa de descoberta e retornar um sumário, depois continuar Fases 2–3 na conversa principal.\n[ ] B - Fazer todas as fases na conversa principal, periodicamente usando `/compact` para reduzir uso de contexto enquanto avança nos arquivos.\n[ ] C - Mudar para modo headless com `--continue`, passando sumários explícitos de contexto entre chamadas em batch para manter continuidade.\n[ ] D - Definir o padrão de tratamento de erros no CLAUDE.md, depois processar arquivos em lotes em múltiplas sessões contando com o arquivo de memória compartilhada para consistência.','\n',char(10)),replace('**Explicação didática para um adulto tech lead:**\n\nO problema central é que a Fase 1 (descoberta) produz uma saída extremamente verbosa — centenas de call sites com contexto — que compete por espaço na janela de contexto com as informações necessárias para as Fases 2 e 3 (planejamento e implementação). Se tudo for feito na mesma conversa, a janela de contexto rapidamente se enche com dados brutos de descoberta, deixando pouco espaço para o caretaking da implementação consistente.\n\n**Por que a alternativa A é a mais efetiva:**\n\nA alternativa A resolve exatamente o gargalo identificado: ela isola a saída verbosa da Fase 1 em um subagente (subprocesso) dedicado à exploração. Esse subagente pode consumir toda a janela de contexto necessária para listar e analisar os call sites, mas retorna apenas um **sumário conciso** para a conversa principal. Isso preserva a janela de contexto para as Fases 2 e 3, onde a consistência de implementação é crítica. Além disso, mantém a continuidade da conversa principal — o plano de tratamento de erros é desenhado colaborativamente e implementado na mesma sessão, garantindo que o padrão seja aplicado de forma homogênea nos 120 arquivos. É a abordagem que melhor equilibra a necessidade de exploração profunda com a capacidade de planejamento e execução consistentes.\n\n**Por que as demais alternativas são inferiores:**\n\n- **Alternativa B (/compact):** O comando `/compact` comprime o histórico, mas ainda assim o dado bruto da Fase 1 precisa ocupar espaço no histórico antes de ser compactado. Durante a Fase 1, a janela de contexto já estará lotada, podendo truncar a descoberta antes de ela ser concluída. Além disso, a compactação pode perder nuances importantes identificadas durante a exploração. É uma solução reativa em vez de preventiva.\n\n- **Alternativa C (modo headless com --continue):** Esta abordagem fragmenta o trabalho em chamadas batch isoladas. A continuidade depende de sumários explícitos passados entre chamadas, o que é frágil — qualquer omissão no sumário quebra a consistência. Além disso, não há uma conversa principal contínua para refinar colaborativamente o design do wrapper. É mais adequada para processamento puramente sequencial sem necessidade de iteração de design.\n\n- **Alternativa D (CLAUDE.md + sessões múltiplas):** Esta abordagem descentraliza completamente o trabalho. O CLAUDE.md define o padrão, mas cada sessão opera isoladamente. Não há garantia de que o padrão será interpretado e aplicado consistentemente em todas as 120 chamadas de API. A falta de uma conversa contínua impede ajustes finos no design à medida que novos padrões são descobertos. É a abordagem mais arriscada para consistência.\n\n**Resumo técnico:** A alternativa A é a que melhor gerencia o recurso limitado (janela de contexto) ao delegar a fase mais verbosa a um subprocesso com escopo reduzido, mantendo o planejamento colaborativo e a implementação na sessão principal, onde a consistência pode ser garantida por iteração contínua.','\n',char(10)),replace('Imagine que você precisa arrumar 120 brinquedos e colocar uma etiqueta em cada um. Primeiro, você precisa olhar todos os brinquedos para ver onde colocar as etiquetas (Fase 1). Depois, você e um amigo desenham o modelo da etiqueta (Fase 2). Por fim, você cola as etiquetas em todos os brinquedos (Fase 3).\n\nO problema é que na primeira fase, ao olhar os brinquedos, você anota tudo num papel gigante que enche sua mesa. Aí não sobra espaço na mesa para desenhar a etiqueta ou colar.\n\nA alternativa A é a melhor porque funciona assim: você pede para um amigo (o "subagente Explore") fazer a parte de olhar os brinquedos e anotar num papel separado. Esse amigo volta até você e diz apenas um resumo: "São 120 brinquedos, 3 tipos diferentes de encaixe para etiqueta." Agora sua mesa está limpa, e você pode desenhar a etiqueta com seu outro amigo e colar em todos os brinquedos sem bagunça.\n\nAs outras opções são piores porque:\n\n- **B:** Você tenta fazer tudo na mesma mesa, mas ela fica tão cheia de anotações que você não consegue trabalhar direito.\n- **C:** Você separa o trabalho em pedaços, mas cada pedaço é feito em salas diferentes, e você precisa ficar passando bilhetes entre as salas — fácil perder informações no caminho.\n- **D:** Você escreve as instruções num quadro, mas cada pessoa trabalha sozinha em horários diferentes. Cada um pode entender a instrução de um jeito, e as etiquetas podem ficar todas diferentes no final.\n\nA opção A é a mais esperta: use um ajudante só para a parte de descobrir, depois faça o resto junto com seu amigo na mesma mesa, garantindo que tudo saia igual e bonito!','\n',char(10)));
INSERT INTO cards VALUES('admin','card_1783092985085_0nd8slc88',136,'Agente de Suporte ao Cliente',replace('Agente de Suporte ao Cliente\n\nLogs de produção mostram um padrão: clientes referenciam valores específicos (ex.: "o desconto de 15% que mencionei"), mas o agente responde com valores incorretos. Investigação mostra que esses detalhes foram mencionados 20+ turnos atrás e condensados em sumários vagos como "preços promocionais foram discutidos". Qual correção é mais efetiva?\n\n[ ] A - Aumentar o limiar de sumarização de 70% para 85% para que conversas tenham mais espaço antes de a sumarização disparar.\n[ ] B - Armazenar histórico completo da conversa em armazenamento externo e implementar recuperação quando o agente detectar referências como "como mencionei".\n[ ] C - Extrair fatos transacionais (valores, datas, números de pedido) para um bloco persistente de "case facts" incluído em todo prompt fora do histórico sumarizado.\n[ ] D - Revisar o prompt de sumarização para preservar explicitamente todos os números, percentuais, datas e expectativas declaradas pelo cliente verbatim.','\n',char(10)),'[ ] C - Extrair fatos transacionais (valores, datas, números de pedido) para um bloco persistente de "case facts" incluído em todo prompt fora do histórico sumarizado.','["Domain_5::Context_Management_Reliability", "Domain_4::Prompt_Engineering_Structured_Output", "Scenario_1::Customer_Support_Agent"]','New',0,2.5,0,1783092985085,1783725745105,1783203558653,replace('**Tradução para português do Brasil:**\n\n**Agente de Suporte ao Cliente**\n\nLogs de produção mostram um padrão: clientes referenciam valores específicos (ex.: "o desconto de 15% que mencionei"), mas o agente responde com valores incorretos. Investigação mostra que esses detalhes foram mencionados 20+ turnos atrás e condensados em sumários vagos como "preços promocionais foram discutidos". Qual correção é mais efetiva?\n\n[ ] A - Aumentar o limiar de sumarização de 70% para 85% para que conversas tenham mais espaço antes de a sumarização disparar.\n[ ] B - Armazenar histórico completo da conversa em armazenamento externo e implementar recuperação quando o agente detectar referências como "como mencionei".\n[ ] C - Extrair fatos transacionais (valores, datas, números de pedido) para um bloco persistente de "case facts" incluído em todo prompt fora do histórico sumarizado.\n[ ] D - Revisar o prompt de sumarização para preservar explicitamente todos os números, percentuais, datas e expectativas declaradas pelo cliente verbatim.','\n',char(10)),replace('**Explicação para Adulto Tech Lead:**\n\nO problema central é que o mecanismo de sumarização está perdendo dados críticos de alta precisão (valores numéricos, porcentagens, datas) ao condensar o histórico. A abordagem correta precisa endereçar a natureza do problema: não se trata apenas de "resumir melhor", mas de garantir que informações transacionais precisas sejam preservadas de forma imutável e facilmente acessível, independentemente do tamanho do histórico.\n\n**Análise das alternativas:**\n\n**Alternativa C (Correta):** Esta é a abordagem mais robusta. Ao extrair fatos transacionais para um bloco persistente separado ("case facts") que é injetado em todo prompt fora do mecanismo de sumarização, você cria uma estrutura de dados imutável e de alta fidelidade para informações críticas. Isso resolve o problema de raiz porque:\n- Os fatos não são afetados pela sumarização, independentemente de quantos turnos passem.\n- O formato estruturado (valores, datas, números) é mais fácil para o LLM processar corretamente do que texto narrativo.\n- Separa a preocupação de "memória de longo prazo de fatos precisos" da "compressão de contexto narrativo".\n- É semelhante ao padrão de "memória de entidades" ou "knowledge graph" usado em sistemas como MemGPT e outros projetos de agentes conversacionais.\n\n**Alternativa A (Incorreta):** Aumentar o limiar de sumarização apenas adia o problema. Quando a conversa eventualmente exceder o novo limiar (e conversas longas o farão), o mesmo problema ocorrerá. É uma solução paliativa que trata o sintoma, não a causa. Além disso, não escala — conversas muito longas podem estourar o contexto do modelo.\n\n**Alternativa B (Incorreta):** Armazenar histórico completo em armazenamento externo e usar RAG (Recuperação Aumentada por Geração) quando detectar referências é frágil por vários motivos:\n- A detecção de referências como "como mencionei" não é trivial e pode falhar (falsos negativos ou positivos).\n- A recuperação pode não encontrar o fato específico se a consulta for mal formulada.\n- Adiciona latência e complexidade de implementação.\n- Depende da qualidade do embedding e da similaridade semântica, que pode não capturar precisamente valores numéricos específicos.\n\n**Alternativa D (Incorreta):** Revisar o prompt de sumarização para preservar explicitamente números é melhor do que A, mas ainda frágil porque:\n- A sumarização ainda é um processo generativo e pode alucinar ou modificar valores mesmo com instruções explícitas.\n- Não há garantia de que todos os valores serão preservados verbatim — LLMs são conhecidos por cometer erros em tarefas de extração de números precisos.\n- O prompt pode ser ignorado ou mal interpretado pelo modelo em certos contextos.\n- Não resolve o problema fundamental de que a sumarização é uma técnica de compressão com perdas.','\n',char(10)),replace('**Explicação para uma criança de 10 anos:**\n\nImagina que você está contando uma história bem longa para um amigo. Depois de um tempo, seu amigo se lembra de partes resumidas da história, mas esquece detalhes importantes, como números exatos. Por exemplo, se você disse "meu desenho favorito custa 15 reais", seu amigo depois pode falar "você disse que o desenho custava uns 10 reais" e errar o valor.\n\nAgora, a pergunta quer saber qual a melhor forma de consertar isso.\n\n**Opção A:** Fazer o resumo da conversa demorar mais para acontecer. Isso só adia o problema — mais cedo ou mais tarde o resumo vai acontecer e os números importantes podem sumir.\n\n**Opção B:** Guardar a conversa inteira em um "arquivo externo" e tentar achar a informação quando necessário. Mas às vezes é difícil achar o dado certo rapidinho, como procurar um grão de areia na praia.\n\n**Opção C (A correta!):** Pegar todas as informações importantes (valores, datas, números) e anotar em um "bloco de notas especial" que fica sempre à vista. Assim, não importa o quanto a conversa cresça, esses dados importantes estão salvos e não serão esquecidos ou confundidos.\n\n**Opção D:** Pedir para o resumo prestar mais atenção nos números. Isso ajuda um pouco, mas o resumo ainda pode errar os números, porque ele é como uma pessoa que tenta lembrar — às vezes a memória falha.\n\nA opção C é a melhor porque os números importantes ficam guardados num lugar seguro e separado, igual você anotar um número de telefone num post-it e colar na parede, em vez de tentar decorar.','\n',char(10)));
INSERT INTO cards VALUES('admin','card_1783092985096_rnuy8qbz7',137,'Padrões de Arquitetura de IA Conversacional',replace('Padrões de Arquitetura de IA Conversacional\n\nAo longo de vários turnos discutindo estratégia de investimento, um usuário declarou "tenho tolerância a risco muito baixa" e depois "quero maximizar meus retornos". Agora ele pergunta: "Em que devo investir?"\n\nQual abordagem melhor garante que a recomendação se alinhe com a prioridade real do usuário?\n\n[ ] A - Trazer à tona a contradição e pedir ao usuário que esclareça o que importa mais.\n[ ] B - Fornecer recomendações separadas para ambos os cenários.\n[ ] C - Prosseguir com a preferência declarada mais recentemente.\n[ ] D - Recomendar um portfólio balanceado sem tratar do conflito.','\n',char(10)),'A - Trazer à tona a contradição e pedir ao usuário que esclareça o que importa mais.','["Domain_1::Agentic_Architecture_Orchestration", "Domain_4::Prompt_Engineering_Structured_Output", "Scenario_1::Customer_Support_Agent"]','New',0,2.5,0,1783092985096,1783725749008,1783203558653,replace('**Tradução para português do Brasil:**\n\nPadrões de Arquitetura de IA Conversacional\n\nAo longo de vários turnos discutindo estratégia de investimento, um usuário declarou "tenho tolerância a risco muito baixa" e depois "quero maximizar meus retornos". Agora ele pergunta: "Em que devo investir?"\n\nQual abordagem melhor garante que a recomendação se alinhe com a prioridade real do usuário?\n\n[ ] A - Trazer à tona a contradição e pedir ao usuário que esclareça o que importa mais.\n[ ] B - Fornecer recomendações separadas para ambos os cenários.\n[ ] C - Prosseguir com a preferência declarada mais recentemente.\n[ ] D - Recomendar um portfólio balanceado sem tratar do conflito.','\n',char(10)),replace('**Explicação para um adulto tech lead:**\n\nO cenário apresenta um caso clássico de **ambiguidade conflitante** no histórico do diálogo, algo comum em sistemas conversacionais que acumulam preferências do usuário ao longo do tempo. O usuário forneceu duas declarações contraditórias: baixa tolerância a risco (conservador) e desejo de maximizar retornos (agressivo). Esses objetivos são, em essência, antagônicos — maximizar retorno exige assumir mais risco.\n\nA análise de cada alternativa:\n\n**Alternativa correta: A**  \nEsta abordagem segue o princípio de **esclarecimento proativo (proactive clarification)**, um padrão arquitetural bem estabelecido em sistemas de IA conversacional. Ao invés de "adivinhar" qual preferência é a real ou tentar conciliar o inconciliável, o sistema reconhece a contradição, comunica-a ao usuário de forma transparente e solicita que ele explicite sua prioridade real. Isso evita o erro de tomar uma decisão arbitrária e coloca o usuário no controle, melhorando a confiança no sistema e a acurácia da recomendação final. Do ponto de vista técnico, isso pode ser implementado com um detector de contradições (baseado em regras ou modelo semântico) e um handler de diálogo que invoca um subdiálogo de esclarecimento.\n\n**Alternativa B - Fornecer recomendações separadas para ambos os cenários**  \nEmbora pareça "justa", essa abordagem transfere o ônus da decisão para o usuário sem contextualizar o conflito. O usuário pode não entender por que recebeu duas recomendações conflitantes, gerando confusão e possível insatisfação. A IA não está sendo útil; está apenas "jogando a responsabilidade para cima". Além disso, sem explicar a contradição, o usuário pode interpretar que o sistema é inconsistente ou incapaz.\n\n**Alternativa C - Prosseguir com a preferência declarada mais recentemente**  \nEsta é uma heurística comum (recência), mas é frágil. O usuário pode ter mudado de ideia ao longo da conversa, ou a declaração mais recente pode ter sido feita sem plena consciência da contradição. Ignorar a primeira declaração é perder informação valiosa e assumir que a última fala sempre reflete a verdadeira intenção, o que não é garantido. Em sistemas financeiros, isso pode levar a recomendações perigosas (ex.: recomendar ações arriscadas a alguém que claramente disse ter aversão a risco).\n\n**Alternativa D - Recomendar um portfólio balanceado sem tratar do conflito**  \nEssa é uma abordagem de "mediação silenciosa" que assume um compromisso sem validação. Um portfólio balanceado (ex.: 60% renda fixa, 40% variável) pode não atender a nenhum dos dois desejos plenamente. Pior: o usuário pode sentir que o sistema ignorou suas declarações ou que a recomendação é genérica e pouco personalizada. A falta de transparência sobre o conflito resolvido internamente pode gerar desconfiança.\n\n**Conclusão técnica:** A melhor prática em arquitetura de IA conversacional para lidar com intenções conflitantes é **pausar e perguntar** — isso respeita o princípio de transparência, mantém o usuário no loop de decisão e aumenta a probabilidade de uma recomendação bem-sucedida.','\n',char(10)),replace('**Explicação para uma criança de 10 anos:**\n\nImagine que você vai a uma sorveteria e primeiro fala: "Eu não gosto de chocolate, prefiro sabores leves." Depois você diz: "Quero o sorvete mais doce que existe!" Quando o atendente pergunta "Qual sabor você quer?", ele fica confuso: o mais doce geralmente é de chocolate, mas você disse que não gosta de chocolate.\n\nA melhor coisa que o atendente pode fazer é perguntar de novo: "Você disse que não gosta de chocolate, mas também disse que quer o mais doce. O que é mais importante para você: não comer chocolate ou ter o sorvete mais doce?" Assim ele não adivinha errado e você escolhe de verdade.\n\nÉ isso que a alternativa A faz: ao invés de chutar ou dar duas opções confusas, a IA pergunta qual é a prioridade real do usuário. As outras alternativas seriam como o atendente simplesmente ignorar o que você disse e dar um sorvete qualquer — isso não é legal, né?','\n',char(10)));
INSERT INTO cards VALUES('admin','card_1783092985108_wzamkzfve',138,'Padrões de Arquitetura de IA Conversacional',replace('Padrões de Arquitetura de IA Conversacional\n\nUsuários refinam preferências de playlist em vários turnos. Duas mensagens depois de o usuário dizer "amo jazz", Claude pergunta "Quais gêneros você gosta?".\n\nQual a causa mais provável?\n\n[ ] A - Claude exige conexão com base vetorial para manter memória de conversa.\n[ ] B - A janela de contexto do modelo foi excedida.\n[ ] C - A Claude API exige um parâmetro `session_id`.\n[ ] D - Sua aplicação não está incluindo as mensagens anteriores no array `messages`.','\n',char(10)),'D - Sua aplicação não está incluindo as mensagens anteriores no array `messages`.','["Domain_1::Agentic_Architecture_Orchestration", "Domain_5::Context_Management_Reliability", "ForaDoCenario"]','New',0,2.5,0,1783092985108,1783725752802,1783203558653,replace('**Tradução para Português do Brasil:**\n\n**Padrões de Arquitetura de IA Conversacional**\n\nUsuários refinam preferências de playlist em vários turnos. Duas mensagens depois de o usuário dizer "amo jazz", Claude pergunta "Quais gêneros você gosta?".\n\nQual a causa mais provável?\n\n[ ] A - Claude exige conexão com base vetorial para manter memória de conversa.\n[ ] B - A janela de contexto do modelo foi excedida.\n[ ] C - A Claude API exige um parâmetro `session_id`.\n[ ] D - Sua aplicação não está incluindo as mensagens anteriores no array `messages`.','\n',char(10)),replace('**Explicação para um adulto (Tech Lead):**\n\nA causa mais provável para Claude ter "esquecido" que o usuário disse "amo jazz" e, duas mensagens depois, perguntar novamente sobre gêneros é que a aplicação não está enviando o histórico completo das mensagens na chamada à API.\n\nEm APIs de modelos de linguagem como Claude, a "memória" da conversa é mantida exclusivamente pelo conteúdo do array `messages` enviado em cada requisição. A API não armazena estado entre chamadas — cada requisição é stateless. Portanto, para que o modelo saiba o que foi dito anteriormente, o desenvolvedor é responsável por acumular e reenviar todas as mensagens anteriores (usuário e assistente) a cada nova interação.\n\n**Análise das alternativas:**\n\n- **A (incorreta):** Claude não exige base vetorial para manter memória de conversa. Bases vetoriais são usadas para RAG (Retrieval-Augmented Generation) ou memória de longo prazo, mas não são requisito para memória de curto prazo em uma conversa. A memória de curto prazo é gerenciada pelo próprio array `messages`.\n\n- **B (incorreta):** A janela de contexto não foi excedida — duas mensagens depois do "amo jazz", a quantidade de tokens ainda é mínima. A janela de contexto dos modelos Claude é de pelo menos 100K tokens (e em alguns modelos 200K), e uma interação de poucas mensagens está longe de atingir esse limite.\n\n- **C (incorreta):** A Claude API não exige um parâmetro `session_id`. Embora algumas arquiteturas usem `session_id` para correlacionar mensagens, a API em si não requer esse parâmetro para manter continuidade da conversa; a continuidade depende exclusivamente do array `messages`.\n\n- **D (correta):** A aplicação provavelmente está enviando apenas a mensagem mais recente do usuário a cada requisição, sem incluir as mensagens anteriores. Como a API não mantém estado, o modelo não tem conhecimento do que foi dito antes, resultando em "amnésia" aparente.\n\n**Conclusão técnica:** Em aplicações conversacionais com LLMs, o desenvolvedor deve gerenciar o histórico de mensagens no lado do cliente (ou servidor da aplicação) e enviá-lo integralmente a cada chamada à API, respeitando o limite da janela de contexto.','\n',char(10)),replace('**Explicação para uma criança de 10 anos:**\n\nImagina que você está jogando um jogo de perguntas e respostas com um amigo. A cada rodada, você escreve sua resposta em um papel, mas **entrega só aquele papel** para seu amigo, sem mostrar os papéis anteriores. Seu amigo lê só aquela última resposta e tenta adivinhar o que você disse antes... ele não vai conseguir, né? Ele vai perguntar de novo coisas que você já falou.\n\nÉ exatamente isso que está acontecendo! Quando o Claude pergunta "Quais gêneros você gosta?" depois de o usuário já ter dito "amo jazz", é porque a aplicação (o programa que conversa com o Claude) esqueceu de mandar as mensagens antigas junto com a nova. O Claude só vê a última coisa que o usuário falou, não a conversa inteira.\n\nAs outras opções estão erradas porque:\n- Claude não precisa de um "banco de memória especial" para lembrar de conversas curtas.\n- O limite de memória do Claude é enorme — duas mensagens não vão encher ele.\n- A API do Claude não exige um número de identificação especial para funcionar.\n\n**Resumindo:** A causa do problema é que o programa está "esquecendo" de enviar as conversas anteriores para o Claude, então ele age como se fosse a primeira vez que está falando com o usuário.','\n',char(10)));
INSERT INTO cards VALUES('admin','card_1783092985119_svcwzok3c',139,'Padrões de Arquitetura de IA Conversacional',replace('Padrões de Arquitetura de IA Conversacional\n\nApós uma sessão culinária de 40 minutos, a conversa atinge 78.000 tokens. O histórico inclui alergias, escala de receitas, termos culinários esclarecidos e discussão geral. Você precisa reduzir tokens preservando informação importante.\n\nQual abordagem melhor balanceia preservação e redução de tokens?\n\n[ ] A - Sumarizar todo o histórico da conversa.\n[ ] B - Manter apenas os 20.000 tokens mais recentes.\n[ ] C - Extrair dados estruturados críticos (alergias, quantidades, preferências), sumarizar a discussão geral e manter trocas recentes verbatim.\n[ ] D - Armazenar a conversa completa externamente e recuperar partes relevantes via busca semântica.','\n',char(10)),'[ ] C - Extrair dados estruturados críticos (alergias, quantidades, preferências), sumarizar a discussão geral e manter trocas recentes verbatim.','["Domain_5::Context_Management_Reliability", "ForaDoCenario"]','New',0,2.5,0,1783092985119,1783725756449,1783203558653,replace('**Tradução para Português do Brasil:**\n\nPadrões de Arquitetura de IA Conversacional\n\nApós uma sessão culinária de 40 minutos, a conversa atinge 78.000 tokens. O histórico inclui alergias, escala de receitas, termos culinários esclarecidos e discussão geral. Você precisa reduzir tokens preservando informação importante.\n\nQual abordagem melhor balanceia preservação e redução de tokens?\n\n[ ] A - Sumarizar todo o histórico da conversa.\n[ ] B - Manter apenas os 20.000 tokens mais recentes.\n[ ] C - Extrair dados estruturados críticos (alergias, quantidades, preferências), sumarizar a discussão geral e manter trocas recentes verbatim.\n[ ] D - Armazenar a conversa completa externamente e recuperar partes relevantes via busca semântica.','\n',char(10)),replace('**Explicação para um Adulto (Tech Lead):**\n\nA alternativa **C** é a melhor porque adota uma estratégia híbrida e inteligente de gerenciamento de contexto, que reconhece a natureza heterogênea dos dados em uma conversa.\n\n- **Por que C é a resposta correta:** Em sistemas conversacionais, nem todo token tem o mesmo valor semântico. Dados críticos (alergias, quantidades, preferências) são fatos imutáveis e de alta relevância. Perdê-los em uma sumarização genérica poderia levar a erros catastróficos (ex: sugerir um prato com amendoim para um alérgico). Ao extrair esses dados como *estruturados* (em um formato como JSON ou uma base de dados chave-valor), você os preserva com fidelidade máxima e ocupa pouquíssimos tokens. A "discussão geral" (conversa fiada, contexto de baixa relevância) pode ser sumarizada agressivamente, reduzindo o volume de tokens sem grande perda. Já as "trocas recentes" são mantidas *verbatim* porque carregam o contexto imediato da interação — o usuário pode estar no meio de um raciocínio que depende da última fala. Essa abordagem reconhece que diferentes partes do histórico têm diferentes meias-vidas e importâncias.\n\n- **Por que A está errada:** Sumarizar *todo* o histórico em um único resumo é uma abordagem de "força bruta" que tende a achatar a informação. Você perde detalhes literais importantes (números exatos, frases textuais do usuário) e o resumo final pode conter alucinações ou omissões do modelo de sumarização. Além disso, um único resumo linear não permite diferenciar o que é dado crítico do que é contexto geral.\n\n- **Por que B está errada:** Manter apenas os tokens mais recentes é uma janela deslizante simples (sliding window). Embora seja barata computacionalmente, ela joga fora informação antiga que pode ser vital. Neste cenário, as informações sobre alergias do usuário estavam no início da conversa (40 minutos atrás) e seriam perdidas, resultando em um sistema amnésico e perigoso.\n\n- **Por que D está errada:** Armazenar toda a conversa em um banco vetorial e usar RAG (Retrieval-Augmented Generation) é uma excelente estratégia para muitos casos, mas não para o contexto imediato de uma *única sessão ativa*. O custo de latência de uma busca semântica a cada turno, somado ao risco de o mecanismo de retrieval não retornar o fragmento exato necessário (falso negativo), torna essa abordagem menos indicada para manter a coesão de uma conversa em andamento. É uma solução mais adequada para persistência entre sessões, não para compressão intra-sessão.','\n',char(10)),replace('Imagine que você está cozinhando com um robô ajudante por 40 minutos. Vocês conversaram sobre alergia a amendoim, como dobrar uma receita de bolo, o que significa "bater em neve" e também bateram papo sobre futebol. Agora a memória do robô está cheia (78.000 palavras) e ele precisa "esquecer" coisas para continuar funcionando, mas sem esquecer o que é importante.\n\nA melhor ideia (letra C) é o robô fazer três coisas:\n1. **Anotar num cantinho especial** as coisas super importantes: "Usuário tem alergia a amendoim", "Quer fazer bolo para 10 pessoas".\n2. **Resumir** a parte menos importante, como a conversa sobre futebol.\n3. **Manter do jeitinho que foi dito** o que vocês falaram nos últimos minutos, porque você pode estar no meio de uma explicação.\n\nAs outras opções são piores: a A tenta resumir TUDO e pode esquecer detalhes; a B só guarda o final da conversa e esquece a alergia lá do começo; e a D guarda tudo num baú externo e toda hora manda o robô procurar — isso demora e ele pode achar a informação errada.','\n',char(10)));
INSERT INTO cards VALUES('admin','card_1783092985131_hj9nxs65p',140,'Padrões de Arquitetura de IA Conversacional',replace('Padrões de Arquitetura de IA Conversacional\n\nUsuários reportam que durante conversas extensas o assistente perde o rastro de tópicos e preferências anteriores. Sua implementação atual mantém apenas os últimos 25 pares de mensagens.\n\nQual a solução mais efetiva?\n\n[ ] A - Abordagem híbrida: sumarizar mensagens antigas mantendo as recentes verbatim.\n[ ] B - Busca por similaridade vetorial sobre o histórico completo da conversa.\n[ ] C - Aumentar a janela para 50 pares de mensagens.\n[ ] D - Sumarizar mensagens descartadas a cada turno e prepender o sumário corrente.','\n',char(10)),'A - Abordagem híbrida: sumarizar mensagens antigas mantendo as recentes verbatim.','["Domain_5::Context_Management_Reliability", "ForaDoCenario"]','New',0,2.5,0,1783092985131,1783725761151,1783203558653,replace('**Tradução para Português do Brasil:**\n\nPadrões de Arquitetura de IA Conversacional\n\nUsuários reportam que durante conversas extensas o assistente perde o rastro de tópicos e preferências anteriores. Sua implementação atual mantém apenas os últimos 25 pares de mensagens.\n\nQual a solução mais efetiva?\n\n[ ] A - Abordagem híbrida: sumarizar mensagens antigas mantendo as recentes verbatim.\n[ ] B - Busca por similaridade vetorial sobre o histórico completo da conversa.\n[ ] C - Aumentar a janela para 50 pares de mensagens.\n[ ] D - Sumarizar mensagens descartadas a cada turno e prepender o sumário corrente.','\n',char(10)),replace('**Explicação para Adulto (Tech Lead):**\n\n**Contexto do problema:** O assistente conversacional perde contexto em conversas longas porque usa uma janela fixa de 25 pares de mensagens (implementação de janela deslizante simples). Isso resulta em perda de informações sobre tópicos anteriores e preferências do usuário.\n\n**Análise das alternativas:**\n\n- **Alternativa A (Correta) - Abordagem híbrida:** Esta solução combina o melhor dos dois mundos. Mensagens recentes são mantidas em sua forma original (verbatim) para responder com precisão a consultas imediatas e capturar nuances da conversa atual. Mensagens antigas são sumarizadas de forma incremental, preservando o contexto histórico (tópicos, preferências, decisões) sem estourar o limite de tokens. É uma estratégia madura e comprovada em sistemas como ChatGPT (memória de longo prazo) e outros assistentes modernos. Ela resolve a perda de contexto enquanto mantém a fidelidade das interações recentes.\n\n- **Alternativa B - Busca por similaridade vetorial:** Embora tecnicamente viável (usando embeddings e RAG), esta abordagem é computacionalmente mais cara, exige uma camada de indexação vetorial e sofre do problema de "recuperação seletiva" — trechos relevantes podem não ser recuperados se a similaridade coseno não for suficientemente alta. Além disso, não resolve o problema da janela fixa; você ainda precisaria de uma estratégia para manter o histórico. É uma solução mais complexa e menos determinística para este problema específico.\n\n- **Alternativa C - Aumentar a janela para 50 pares:** É um paliativo, não uma solução. Conversas podem se estender por centenas de mensagens. Aumentar a janela apenas adia o problema, não o resolve. Além disso, janelas maiores aumentam o custo computacional (atenção quadraticamente maior em transformers) e o risco de diluição do foco do modelo.\n\n- **Alternativa D - Sumarizar a cada turno e prepender o sumário:** Esta abordagem é frágil porque descarta mensagens recentes (que podem ser cruciais para a resposta imediata) e atualiza o sumário a cada turno — o que é computacionalmente caro e pode propagar erros de sumarização. Prepender o sumário (em vez de anexá-lo junto com as mensagens recentes) também mistura o contexto sumarizado com o histórico imediato de forma inadequada, potencialmente confundindo o modelo sobre o que é atual vs. resumido.\n\n**Conclusão técnica:** A abordagem híbrida (alternativa A) é a mais robusta porque oferece uma solução escalável e de baixo custo incremental: mantém mensagens recentes para precisão, sumariza as antigas para retenção de contexto, e pode ser implementada com sumarização periódica (ex.: a cada N mensagens ou quando a janela estiver cheia), evitando overhead excessivo.','\n',char(10)),replace('**Explicação para Criança de 10 Anos:**\n\nImagina que você está conversando com um robô amigo. No começo, você diz que adora pizza e que seu cachorro se chama Rex. Depois de um tempo, vocês já falaram sobre muitas coisas, e o robô começa a esquecer que você gosta de pizza e que seu cachorro é o Rex. Sabe por quê? Porque a memória dele só guarda as últimas 25 mensagens, como se fosse um caderninho pequeno.\n\nVamos ver as opções que o robô pode usar para não esquecer mais:\n\n**Alternativa A - A melhor solução:** É como ter um caderno que guarda as falas recentes inteirinhas (para não perder nenhum detalhe do que você acabou de falar) e, para as conversas mais antigas, ele faz um resumo bem rápido, como: "a criança gosta de pizza e tem um cachorro chamado Rex". Assim, ele não esquece do importante, mas também não precisa guardar tudo.\n\n**Alternativa B - Buscar no histórico todo:** Seria como o robô ter que ler a conversa inteira de novo toda vez que você pergunta algo. Isso dá muito trabalho e demora, além de que às vezes ele pode não achar a informação certa.\n\n**Alternativa C - Aumentar para 50 mensagens:** Isso é como comprar um caderno um pouco maior, mas se a conversa for muito longa, o problema vai voltar. Só empurra o problema para frente.\n\n**Alternativa D - Resumir tudo a cada fala:** Seria como o robô resumir a conversa inteira depois de cada frase que você fala. Imagina o trabalhão! E ele ainda pode se confundir e misturar as coisas.\n\n**Resumindo:** A melhor ideia é a **alternativa A**, porque o robô guarda as falas recentes do jeitinho que você falou e faz um resumo das antigas. Assim, ele lembra de tudo sem precisar de um caderno gigante!','\n',char(10)));
INSERT INTO cards VALUES('admin','card_1783092985156_7c29ox0oi',141,'Padrões de Arquitetura de IA Conversacional',replace('Padrões de Arquitetura de IA Conversacional\n\nUsuários reportam que latência aumenta e custos sobem quando conversas excedem 50 turnos.\n\nQual a causa principal?\n\n[ ] A - Todo o histórico da conversa é incluído em cada requisição da API.\n[ ] B - O modelo gera respostas progressivamente mais longas.\n[ ] C - Operações de banco ficam mais lentas conforme o histórico cresce.\n[ ] D - O modelo constrói um perfil interno do usuário que exige mais processamento.','\n',char(10)),'A - Todo o histórico da conversa é incluído em cada requisição da API.','["Domain_5::Context_Management_Reliability", "Domain_1::Agentic_Architecture_Orchestration", "ForaDoCenario"]','New',0,2.5,0,1783092985156,1783725764579,1783203558653,replace('**Tradução para português do Brasil:**\n\n**Padrões de Arquitetura de IA Conversacional**\n\nUsuários reportam que a latência aumenta e os custos sobem quando as conversas excedem 50 turnos.\n\nQual é a causa principal?\n\n[ ] A - Todo o histórico da conversa é incluído em cada requisição da API.\n[ ] B - O modelo gera respostas progressivamente mais longas.\n[ ] C - Operações de banco ficam mais lentas conforme o histórico cresce.\n[ ] D - O modelo constrói um perfil interno do usuário que exige mais processamento.','\n',char(10)),replace('**Explicação Técnica para Tech Lead:**\n\nA alternativa **A** está correta. Em arquiteturas de IA conversacional, especialmente aquelas baseadas em modelos de linguagem (LLMs) como o GPT, o contexto completo da conversa (histórico de mensagens) é normalmente enviado em cada chamada de API para manter a coerência do diálogo. À medida que a conversa cresce, o número de tokens no prompt aumenta linearmente. Como a maioria dos provedores de API cobra por token (tanto no input quanto no output) e o tempo de processamento do modelo escala com o tamanho do input (devido à atenção do transformer ser O(n²) ou O(n) com otimizações, mas ainda assim cresce), tanto a latência quanto o custo aumentam. Com 50 turnos, o histórico pode conter facilmente milhares de tokens, impactando significativamente a performance e o custo.\n\n**Análise das alternativas incorretas:**\n- **B**: Modelos de linguagem não tendem a gerar respostas progressivamente mais longas por padrão. O comprimento da resposta é controlado por parâmetros como `max_tokens` e pelo prompt. Não há um comportamento intrínseco do modelo que cause esse aumento gradual.\n- **C**: Embora operações de banco de dados possam ficar mais lentas com mais dados, isso não é a causa principal do aumento de latência reportado. Em boa parte das arquiteturas, o banco é usado para persistência e não interfere diretamente no tempo de resposta da API do modelo. Além disso, consultas a bancos modernos são eficientes mesmo com volumes razoáveis de dados.\n- **D**: Modelos de linguagem não constroem um "perfil interno" persistente do usuário entre requisições de forma inerente. Eles processam o contexto fornecido no prompt. Não há um armazenamento interno de perfil que aumente o processamento ao longo da conversa.','\n',char(10)),replace('**Explicação para uma criança de 10 anos:**\n\nImagine que você está conversando com um robô muito inteligente. Toda vez que você manda uma mensagem para ele, você também precisa enviar tudo o que vocês já conversaram antes, para ele não esquecer o assunto. No início, são só algumas frases, mas depois de 50 mensagens, são muitas e muitas frases! Isso deixa o robô mais devagar para responder (porque ele precisa ler tudo de novo) e também custa mais caro para a empresa, porque o robô cobra por cada palavra que ele "lê". É como se a cada mensagem você tivesse que copiar um livro inteiro junto com a sua pergunta.\n\nAs outras opções estão erradas porque:\n- **B**: O robô não fala cada vez mais coisas só porque a conversa está grande.\n- **C**: O banco de dados (o "caderno" onde a conversa é anotada) geralmente é rápido e não atrapalha tanto.\n- **D**: O robô não guarda um "arquivo secreto" seu dentro da cabeça dele que fica mais pesado de processar.','\n',char(10)));
INSERT INTO cards VALUES('admin','card_1783092985168_rhqnq8gcu',142,'Padrões de Arquitetura de IA Conversacional',replace('Padrões de Arquitetura de IA Conversacional\n\nApós três meses de sessões semanais, o histórico cresce para 85.000 tokens. Quando um usuário pergunta "O que concluímos sobre o tema do isolamento?", o assistente dá respostas genéricas em vez de referenciar discussões anteriores.\n\nQual a abordagem mais efetiva?\n\n[ ] A - Truncamento por janela rolante.\n[ ] B - Sumarização progressiva capturando conclusões-chave.\n[ ] C - Embeddings semânticos com recuperação de trocas relevantes.\n[ ] D - Adicionar tags XML estruturadas marcando conclusões da discussão.','\n',char(10)),'[ ] C - Embeddings semânticos com recuperação de trocas relevantes.','["Domain_5::Context_Management_Reliability", "Domain_1::Agentic_Architecture_Orchestration", "ForaDoCenario"]','New',0,2.5,0,1783092985168,1783725768953,1783203558653,replace('**Tradução para português do Brasil:**\n\nPadrões de Arquitetura de IA Conversacional\n\nApós três meses de sessões semanais, o histórico cresce para 85.000 tokens. Quando um usuário pergunta "O que concluímos sobre o tema do isolamento?", o assistente dá respostas genéricas em vez de referenciar discussões anteriores.\n\nQual a abordagem mais efetiva?\n\n[ ] A - Truncamento por janela rolante.\n[ ] B - Sumarização progressiva capturando conclusões-chave.\n[ ] C - Embeddings semânticos com recuperação de trocas relevantes.\n[ ] D - Adicionar tags XML estruturadas marcando conclusões da discussão.','\n',char(10)),replace('**Explicação para adulto tech lead:**\n\nO problema central é a perda de contexto relevante em conversas longas (85k tokens), onde o assistente não consegue referenciar discussões passadas específicas — neste caso, "conclusões sobre o tema do isolamento". A pergunta do usuário é altamente específica e depende de recuperar informações precisas do histórico.\n\n**Análise das alternativas:**\n\n- **Alternativa C (correta):** Embeddings semânticos com recuperação (RAG — Retrieval-Augmented Generation) permite que, dada a pergunta do usuário, seja feita uma busca vetorial no histórico completo para encontrar os trechos mais semanticamente relevantes. Isso resolve o problema de escala (85k tokens) sem perder informação, pois o histórico inteiro permanece armazenado e indexado, e apenas os fragmentos pertinentes são injetados no contexto do LLM no momento da resposta. É a abordagem mais robusta para responder perguntas específicas sobre conteúdo passado.\n\n- **Alternativa A (incorreta):** Truncamento por janela rolante (sliding window) limita o contexto a uma janela fixa de tokens recentes. Isso descarta todo o histórico antigo, impossibilitando que o assistente recupere discussões de meses atrás. É uma solução de baixo custo computacional, mas ineficaz para o cenário descrito.\n\n- **Alternativa B (incorreta):** Sumarização progressiva é útil para manter um resumo geral do que foi discutido, mas perde granularidade. Conclusões específicas, detalhes e nuances tendem a ser perdidos nas sucessivas compressões. Ao perguntar "o que concluímos sobre isolamento?", o assistente pode ter apenas um resumo vago, não a conclusão exata.\n\n- **Alternativa D (incorreta):** Adicionar tags XML no histórico pode ajudar na estruturação, mas não resolve o problema de escala se o histórico completo (85k tokens) ainda precisar ser processado. Além disso, depende de que as conclusões tenham sido marcadas manualmente ou por heurísticas durante a conversa — o que não é mencionado como tendo sido feito. Sem mecanismo de recuperação seletiva, o contexto estoura o limite do modelo e as tags são irrelevantes.\n\n**Conclusão:** A alternativa C é a mais efetiva porque combina indexação semântica com recuperação sob demanda, garantindo que o assistente possa acessar informações precisas do passado, independentemente do volume total de tokens.','\n',char(10)),replace('**Explicação para uma criança de 10 anos:**\n\nImagina que você participou de várias aulas de história durante três meses, e no final o professor perguntou: "O que a gente concluiu sobre a vida dos dinossauros?". Mas você tem um caderno ENORME com 85 mil palavras escritas! Se você tentar ler tudo de novo, vai demorar horas e sua cabeça vai ficar confusa.\n\nCada opção do exercício é um jeito diferente de lidar com esse problema:\n\n- **Opção A (ruim):** É como pegar o caderno e rasgar as primeiras páginas, deixando só as últimas. Você perde toda a informação antiga — as aulas dos dinossauros podem ter sido no começo! Não funciona.\n\n- **Opção B (mais ou menos):** É como pedir para alguém escrever um resumão de tudo que vocês conversaram. Mas o resumo é genérico, tipo "falamos sobre animais antigos". Cadê a conclusão específica sobre os dinossauros? Perdeu-se no caminho.\n\n- **Opção C (a melhor!):** É como ter um fichário mágico com um índice inteligente. Quando você pergunta "o que concluímos sobre os dinossauros?", o fichário procura rapidinho só as partes que falam de dinossauros e te mostra. Você não precisa ler o caderno inteiro — só o que interessa para a pergunta! É rápido e certeiro.\n\n- **Opção D (não resolve):** É como colocar etiquetas coloridas em algumas páginas do caderno, dizendo "aqui tem conclusão". Mas o caderno continua gigante e você ainda teria que ler ele inteiro. As etiquetas sozinhas não ajudam a achar a informação rapidamente.\n\n**Resposta certa: C** — porque é o único jeito que acha exatamente a conclusão sobre o tema do isolamento sem precisar ler o histórico imenso inteiro.','\n',char(10)));
INSERT INTO cards VALUES('admin','card_1783092985181_0aqsf4dih',143,'Padrões de Arquitetura de IA Conversacional',replace('Padrões de Arquitetura de IA Conversacional\n\nSeu tutor de IA tem um system prompt de 2.800 tokens definindo metodologia de ensino e regras de adaptação. Após 12 turnos, o assistente começa a ignorar níveis de proficiência.\n\nQual a correção mais efetiva?\n\n[ ] A - Injetar lembretes a cada 4–5 turnos.\n[ ] B - Substituir regras verbosas por exemplos few-shot demonstrando adaptação por nível de proficiência.\n[ ] C - Posicionar regras críticas no fim do system prompt.\n[ ] D - Avaliar respostas e regenerar se o nível de dificuldade não casar.','\n',char(10)),'B - Substituir regras verbosas por exemplos few-shot demonstrando adaptação por nível de proficiência.','["Domain_4::Prompt_Engineering_Structured_Output", "Domain_5::Context_Management_Reliability", "ForaDoCenario"]','New',0,2.5,0,1783092985181,1783725772631,1783203558653,replace('**Tradução para Português do Brasil:**\n\nPadrões de Arquitetura de IA Conversacional\n\nSeu tutor de IA tem um system prompt de 2.800 tokens definindo metodologia de ensino e regras de adaptação. Após 12 turnos, o assistente começa a ignorar níveis de proficiência.\n\nQual a correção mais efetiva?\n\n[ ] A - Injetar lembretes a cada 4–5 turnos.\n[ ] B - Substituir regras verbosas por exemplos few-shot demonstrando adaptação por nível de proficiência.\n[ ] C - Posicionar regras críticas no fim do system prompt.\n[ ] D - Avaliar respostas e regenerar se o nível de dificuldade não casar.','\n',char(10)),replace('**Explicação para Tech Lead (adulto):**\n\nO problema central aqui é o **vazamento de contexto (contexto perdido)** em janelas de contexto longo. Após 12 turnos (~24k tokens, considerando tokens das respostas + histórico), o modelo começa a perder a aderência a instruções posicionadas no início do system prompt (recência vs. primazia). Vamos analisar cada alternativa:\n\n**Alternativa A – Injetar lembretes a cada 4–5 turnos:** Esta é uma técnica comum (injeção de lembrete), mas é paliativa e aumenta o consumo de tokens, que já é alto (2.800 tokens só de system prompt). Além disso, modelos mais recentes (GPT-4, Claude) tendem a ter melhor desempenho com exemplos concretos do que com repetição de instruções abstratas. Funciona, mas não é a mais efetiva.\n\n**Alternativa B – CORRETA. Substituir regras verbosas por exemplos few-shot:** Esta é a abordagem mais robusta por vários motivos:\n- Exemplos few-shot (pergunta-resposta demonstrando adaptação para diferentes níveis) são processados de forma mais eficiente pelo modelo do que regras declarativas longas.\n- Eles ocupam menos tokens (2-3 exemplos bem construídos substituem dezenas de regras).\n- Eles demonstram o *comportamento desejado* em vez de apenas descrevê-lo, o que é mais eficaz para modelos de linguagem.\n- Eles são menos suscetíveis ao esquecimento em janelas longas porque o modelo "aprende" o padrão a partir dos exemplos, em vez de depender de memorizar a regra.\n\n**Alternativa C – Posicionar regras críticas no fim do system prompt:** Esta é uma abordagem falha. Modelos sofrem de "atenção posicional" e o início e fim do prompt tendem a ser mais lembrados, mas colocar regras no fim do system prompt, que é seguido pelo histórico do chat, significa que após 12 turnos essas regras estarão ainda mais distantes (no meio do contexto total). O fim do system prompt é o começo do histórico, então a regra ficaria soterrada.\n\n**Alternativa D – Avaliar respostas e regenerar se o nível de dificuldade não casar:** Esta é uma estratégia reativa (pós-processamento) que consome recursos computacionais e tempo de latência. É ineficiente e não resolve a causa raiz (o esquecimento das instruções). Melhor prevenir do que remediar.\n\nPortanto, a alternativa B é a correção mais efetiva por atacar a causa raiz (esquecimento de instruções longas em contextos longos) com uma técnica que é comprovadamente mais resiliente: exemplos concretos em vez de regras abstratas.','\n',char(10)),replace('Imagine que você pediu para um robô ajudar seu amigo a aprender matemática. Você escreveu um montão de regras para o robô: "se o amigo for iniciante, use números pequenos; se for avançado, use números grandes". Mas depois de um tempo conversando, o robô esquece essas regras e trata todo mundo igual.\n\nA alternativa A seria tipo dar um bilhete lembrando a cada 5 minutos. Funciona, mas gasta papel.\n\nA alternativa B (a resposta certa) é melhor: em vez de escrever regras enormes, você mostra 2 ou 3 exemplos prontos. Tipo: mostre uma pergunta fácil para iniciante, uma média para intermediário, uma difícil para avançado. O robô aprende vendo os exemplos, igual quando a gente aprende a fazer conta vendo o professor resolver na lousa.\n\nA alternativa C seria colocar as regras no final do manual. Mas aí, depois de 12 perguntas, o robô já leu tanta coisa que esqueceu o fim do manual. Não ajuda.\n\nA alternativa D seria o robô responder e depois pensar "ops, errei o nível". Aí ele apaga e tenta de novo. Dá trabalho e perde tempo.\n\nA melhor forma é ensinar com exemplos (alternativa B), pois é mais fácil de lembrar e gasta menos "memória do robô".','\n',char(10)));
INSERT INTO cards VALUES('admin','card_1783092985193_93fv13lm2',144,'Padrões de Arquitetura de IA Conversacional',replace('Padrões de Arquitetura de IA Conversacional\n\nSeu assistente usa um system prompt de persona "empreiteiro". Os primeiros turnos seguem as regras, mas no turno 7 o assistente passa a dar conselhos genéricos. O comprimento da conversa é de apenas 2.500 tokens.\n\nQual a causa mais provável?\n\n[ ] A - System prompts apenas estabelecem comportamento inicial.\n[ ] B - A atenção do modelo enfraquece à medida que turnos se acumulam.\n[ ] C - Respostas acumuladas do assistente diluem a influência do system prompt.\n[ ] D - O system prompt é enviado apenas uma vez.','\n',char(10)),'C - Respostas acumuladas do assistente diluem a influência do system prompt.','["Domain_5::Context_Management_Reliability", "Domain_4::Prompt_Engineering_Structured_Output", "ForaDoCenario"]','New',0,2.5,0,1783092985193,1783725776485,1783203558653,replace('**Tradução para português do Brasil:**\n\n**Padrões de Arquitetura de IA Conversacional**\n\nSeu assistente usa um system prompt de persona "empreiteiro". Os primeiros turnos seguem as regras, mas no turno 7 o assistente passa a dar conselhos genéricos. O comprimento da conversa é de apenas 2.500 tokens.\n\nQual a causa mais provável?\n\n[ ] A - System prompts apenas estabelecem comportamento inicial.\n[ ] B - A atenção do modelo enfraquece à medida que turnos se acumulam.\n[ ] C - Respostas acumuladas do assistente diluem a influência do system prompt.\n[ ] D - O system prompt é enviado apenas uma vez.','\n',char(10)),replace('**Explicação para adulto (tech lead):**\n\nO problema descrito é clássico em arquiteturas de LLMs com contexto fixo. Modelos como GPT, Claude, Llama, etc., operam com uma "janela de contexto" limitada (neste caso, 2.500 tokens). O system prompt, que contém a persona "empreiteiro", é tipicamente inserido no início do contexto e enviado **uma única vez** junto com o histórico da conversa.\n\nA alternativa **C** é a correta porque, à medida que a conversa avança, o histórico de turnos anteriores (perguntas do usuário + respostas do assistente) ocupa espaço no contexto. Eventualmente, o system prompt pode ser "empurrado para fora" da janela de atenção ativa do modelo, ou seu peso relativo diminui frente ao volume de tokens de diálogo. Isso faz com que o modelo "esqueça" parcialmente a persona, passando a responder de forma genérica.\n\nDetalhamento das alternativas incorretas:\n\n- **A**: Incorreta. System prompts não estabelecem apenas comportamento inicial; eles são reavaliados a cada token gerado, desde que permaneçam no contexto ativo. O problema não é que o system prompt seja "só inicial", mas sim que ele é relegado conforme o contexto cresce.\n\n- **B**: Incorreta. O termo "atenção do modelo enfraquece" é uma metáfora imprecisa. Mecanismos de atenção (self-attention) não se degradam com turnos; eles operam sobre todo o contexto disponível. O que ocorre é um fenômeno de **deslocamento de contexto** (context shift / lost-in-the-middle), onde tokens no início da janela recebem menos peso à medida que novos tokens são adicionados — mas isso é uma questão de posição relativa no contexto, não de "enfraquecimento da atenção".\n\n- **D**: Incorreta. É verdade que o system prompt é enviado apenas uma vez (na maioria das implementações), mas isso por si só não é a causa do problema. O system prompt permanece no contexto; o que acontece é que ele **perde influência** porque o histórico de conversa o "sufoca" em termos de densidade de tokens e posicionamento relativo.','\n',char(10)),replace('Imagine que você está brincando de fazer de conta que é um pedreiro. No começo da brincadeira, você fala e age como um pedreiro. Mas, depois de um tempo, você vai conversando sobre outras coisas e acaba esquecendo que estava interpretando um pedreiro, e começa a dar respostas normais, sem o personagem.\n\nCom o assistente de IA, acontece algo parecido. No início da conversa, ele recebe uma "regra do jogo" (o system prompt) dizendo que ele é um empreiteiro. Mas, conforme a conversa avança, as falas anteriores vão ocupando espaço na "memória" do assistente. Essa regra inicial vai ficando meio espremida no começo, e o assistente acaba se esquecendo dela, passando a responder de forma genérica, sem seguir o personagem.\n\nA resposta correta é a **C**, porque o que acontece é que as respostas que o assistente já deu vão ficando no meio do caminho e acabam "afogando" a instrução inicial, fazendo com que ela perca a força.','\n',char(10)));
INSERT INTO cards VALUES('admin','card_1783092985206_pxs6n69j7',145,'Durante os testes, você observa que em sessões de exploração prolongadas (mais de 30 minutos), o agente começa a dar respostas inconsistentes sobre a estrutura de código que discutiu anteriormente.',replace('Durante os testes, você observa que em sessões de exploração prolongadas (mais de 30 minutos), o agente começa a dar respostas inconsistentes sobre a estrutura de código que discutiu anteriormente.\n\nDurante os testes, você observa que em sessões de exploração prolongadas (mais de 30 minutos), o agente começa a dar respostas inconsistentes sobre a estrutura de código que discutiu anteriormente. Os engenheiros relatam ter que repetir o contexto sobre módulos que já exploraram.\n\nQual é a abordagem mais eficaz para resolver isso?\n\n[ ] A - Fazer o agente manter um arquivo de rascunho que registra as descobertas principais, consultando-o para perguntas subsequentes.\n[ ] B - Mudar para um nível de modelo de maior capacidade para fornecer mais espaço de janela de contexto para os dados de exploração acumulados.\n[ ] C - Implementar a limpeza automática do contexto a cada 15 minutos para garantir que o agente comece com um contexto novo e não contaminado.\n[ ] D - Criar resumos de todos os arquivos-fonte antes do início da exploração, carregando no contexto apenas essas representações comprimidas.','\n',char(10)),'A - Fazer o agente manter um arquivo de rascunho que registra as descobertas principais, consultando-o para perguntas subsequentes.','["Domain_5::Context_Management_Reliability", "Domain_2::Tool_Design_MCP_Integration", "Scenario_4::Developer_Productivity"]','New',0,2.5,0,1783092985206,1783725780846,1783203558653,replace('**Tradução para português do Brasil:**\n\nDurante os testes, você observa que em sessões de exploração prolongadas (mais de 30 minutos), o agente começa a dar respostas inconsistentes sobre a estrutura de código que discutiu anteriormente. Os engenheiros relatam ter que repetir o contexto sobre módulos que já exploraram.\n\nQual é a abordagem mais eficaz para resolver isso?\n\n[ ] A - Fazer o agente manter um arquivo de rascunho que registra as descobertas principais, consultando-o para perguntas subsequentes.\n[ ] B - Mudar para um nível de modelo de maior capacidade para fornecer mais espaço de janela de contexto para os dados de exploração acumulados.\n[ ] C - Implementar a limpeza automática do contexto a cada 15 minutos para garantir que o agente comece com um contexto novo e não contaminado.\n[ ] D - Criar resumos de todos os arquivos-fonte antes do início da exploração, carregando no contexto apenas essas representações comprimidas.','\n',char(10)),replace('**Explicação didática para um adulto tech lead:**\n\nO problema central é que o agente, em sessões longas, perde a capacidade de recordar informações discutidas anteriormente. Isso acontece porque o contexto do modelo tem capacidade limitada — tokens mais antigos podem ser "esquecidos" (ou sofrer degradação de atenção) à medida que novos tokens são adicionados.\n\nVamos analisar cada alternativa:\n\n- **Alternativa A (Correta):** Manter um arquivo de rascunho externo que registra as descobertas principais e consultá-lo em perguntas subsequentes é a abordagem mais eficaz. Isso implementa uma forma de **memória persistente externa** — o agente não precisa depender exclusivamente da janela de contexto temporária do modelo. Sempre que precisa responder sobre algo discutido antes, ele consulta esse arquivo, que funciona como uma "nota de reunião" estruturada. É uma solução escalável, de baixo custo computacional e que mimetiza boas práticas de engenharia: documentar o que foi descoberto para referência futura.\n\n- **Alternativa B (Incorreta):** Modelos de maior capacidade geralmente têm janelas de contexto maiores, mas isso apenas adia o problema, não o resolve. O custo computacional escala com o tamanho do contexto (atenção quadrática em transformers), e mesmo janelas maiores eventualmente sofrem com degradação na recuperação de informações distantes ("lost in the middle"). Além disso, simplesmente jogar mais contexto no modelo não garante que ele vá efetivamente usar as informações antigas de forma confiável, e o custo por chamada de API aumenta significativamente.\n\n- **Alternativa C (Incorreta):** Limpar o contexto a cada 15 minutos jogaria fora todo o progresso da exploração. Isso forçaria os engenheiros a repetir o contexto com ainda mais frequência do que já relatam, agravando o problema em vez de resolvê-lo. Perderia-se o histórico de descobertas, decisões e estrutura de código mapeada, tornando a exploração iterativa impossível.\n\n- **Alternativa D (Incorreta):** Criar resumos de todos os arquivos-fonte antes da exploração é uma boa prática para compressão inicial, mas não resolve o problema de **perda de contexto ao longo da sessão**. Os resumos são carregados uma vez e depois sofrem o mesmo problema de degradação. Além disso, essa abordagem não captura as descobertas e discussões que ocorrem *durante* a exploração — as interações com os engenheiros, os insights sobre a estrutura, etc. Falta o componente de memória dinâmica para o que é aprendido durante a sessão.\n\n**Conclusão:** A alternativa A é a única que endereça diretamente a causa raiz: a falta de um mecanismo de memória persistente que sobreviva às limitações da janela de contexto do modelo.','\n',char(10)),replace('Imagine que você está brincando de detetive em uma casa muito grande. Você começa a explorar e descobre que no quarto azul tem um baú de brinquedos, na cozinha tem biscoitos escondidos, e no porão tem uma bicicleta. Mas depois de 30 minutos explorando, sua cabeça começa a esquecer onde estavam as coisas. Você fica confuso e precisa perguntar para alguém de novo onde está cada coisa.\n\nAgora, qual seria a melhor ideia para não esquecer?\n\n**Alternativa A (a melhor):** Você pega um caderninho e, toda vez que descobre algo legal, escreve: "Quarto azul → baú de brinquedos", "Cozinha → biscoitos", "Porão → bicicleta". Depois, quando sua memória falha, você só olha no caderninho e lembra de tudo! É como ter uma "memória externa" que não se esquece de nada.\n\n**Alternativa B (não tão boa):** Chamar um amigo mais velho que tem uma memória maior. Ele até demora mais para esquecer, mas depois de um tempo também vai esquecer algumas coisas. E chamar esse amigo custa mais caro (no caso do modelo, mais poderoso = mais caro).\n\n**Alternativa C (péssima ideia):** A cada 15 minutos, apagar tudo que você descobriu e começar a exploração do zero. Isso é horrível! Você vai ter que descobrir tudo de novo e de novo, sem nunca aproveitar o que já aprendeu.\n\n**Alternativa D (não resolve o problema):** Antes de começar, você faz um resumo de todos os cômodos da casa. Mas isso não ajuda quando você descobre coisas NOVAS enquanto explora — como os biscoitos escondidos na cozinha. O resumo inicial não sabe das novidades que você encontra durante a brincadeira.\n\nEntão, a melhor ideia é a **alternativa A**: anotar as descobertas em um caderninho (arquivo de rascunho) para consultar depois!','\n',char(10)));
INSERT INTO cards VALUES('admin','card_1783092985217_pia3xeyoe',146,'Seu agente passou 25 minutos explorando o subsistema de renderização de um motor de jogos — lendo código de shaders, gerenciamento de buffers e a lógica de sincronização de frames.',replace('Seu agente passou 25 minutos explorando o subsistema de renderização de um motor de jogos — lendo código de shaders, gerenciamento de buffers e a lógica de sincronização de frames.\n\nSeu agente passou 25 minutos explorando o subsistema de renderização de um motor de jogos — lendo código de shaders, gerenciamento de buffers e a lógica de sincronização de frames. Um engenheiro agora pede que ele entenda como o motor de física se integra à renderização para sobreposições de depuração de colisão. Você nota que respostas recentes fazem referência a "padrões típicos de renderização" em vez das classes específicas VulkanPipeline e FrameGraph que ele descobriu antes.\n\nQual é a abordagem mais eficaz?\n\n[ ] A - Criar um subagente para explorar a física de forma independente e, então, sintetizar manualmente suas descobertas com o conhecimento de renderização acumulado na conversa principal.\n[ ] B - Continuar no contexto atual com prompts mais direcionados que referenciam as classes específicas pelo nome.\n[ ] C - Resumir as descobertas principais de renderização e, então, criar um subagente para a exploração de física com esse resumo em seu contexto inicial.\n[ ] D - Usar /clear para redefinir o contexto completamente e, então, começar do zero com a exploração de física usando os caminhos de arquivo do CLAUDE.md do projeto.','\n',char(10)),'[ ] C - Resumir as descobertas principais de renderização e, então, criar um subagente para a exploração de física com esse resumo em seu contexto inicial.','["Domain_5::Context_Management_Reliability", "Domain_1::Agentic_Architecture_Orchestration", "Scenario_4::Developer_Productivity"]','New',0,2.5,0,1783092985217,1783725784610,1783203558653,replace('**Tradução para português do Brasil:**\n\nSeu agente passou 25 minutos explorando o subsistema de renderização de um motor de jogos — lendo código de shaders, gerenciamento de buffers e a lógica de sincronização de frames. Um engenheiro agora pede que ele entenda como o motor de física se integra à renderização para sobreposições de depuração de colisão. Você nota que respostas recentes fazem referência a "padrões típicos de renderização" em vez das classes específicas VulkanPipeline e FrameGraph que ele descobriu antes.\n\nQual é a abordagem mais eficaz?\n\n[ ] A - Criar um subagente para explorar a física de forma independente e, então, sintetizar manualmente suas descobertas com o conhecimento de renderização acumulado na conversa principal.\n[ ] B - Continuar no contexto atual com prompts mais direcionados que referenciam as classes específicas pelo nome.\n[ ] C - Resumir as descobertas principais de renderização e, então, criar um subagente para a exploração de física com esse resumo em seu contexto inicial.\n[ ] D - Usar /clear para redefinir o contexto completamente e, então, começar do zero com a exploração de física usando os caminhos de arquivo do CLAUDE.md do projeto.','\n',char(10)),replace('**Explicação para o adulto Tech Lead:**\n\nO problema central aqui é de **gerenciamento de contexto atencional**. O agente já gastou 25 minutos em um subsistema específico (renderização) e agora precisa pivotar para um subsistema diferente (física), porém com um ponto de integração específico entre eles. O fenômeno observado — respostas vagas referindo-se a "padrões típicos" ao invés de classes específicas como VulkanPipeline e FrameGraph — é um indicador clássico de **attention decay** ou **context dilution** em modelos de linguagem de contexto longo. À medida que o contexto cresce, a capacidade do modelo de recuperar e priorizar informações específicas do início da conversa se degrada.\n\nVamos analisar cada alternativa:\n\n**A - Criar um subagente para explorar a física de forma independente e, então, sintetizar manualmente:** Esta abordagem gera dois silos de conhecimento — o agente principal tem o contexto de renderização e o subagente tem o contexto de física. A síntese manual dependeria de um terceiro agente ou de uma transferência de contexto textual. É frágil, propensa a perda de nuance e não resolve o problema de attention decay.\n\n**B - Continuar no contexto atual com prompts mais direcionados:** Esta é tentadora, mas subestima o problema. O contexto já está poluído com 25 minutos de tokens de renderização que não são mais o foco. Mesmo com prompts direcionados, o modelo continuará sofrendo de diluição de atenção — as referências a VulkanPipeline e FrameGraph estarão cada vez mais distantes (em termos de posição token) do prompt atual, reduzindo a probabilidade de recall preciso.\n\n**C - Resumir as descobertas principais de renderização e, então, criar um subagente com esse resumo:** Esta é a abordagem mais eficaz por três razões: (1) O resumo comprime o conhecimento relevante de renderização em um formato denso e focado, eliminando ruído; (2) O novo subagente começa com um contexto limpo, mas com o resumo posicionado no início de seu contexto — maximizando a atenção do modelo para as informações de integração; (3) O subagente pode explorar física com foco total, enquanto o resumo serve como "ponte" conceitual para responder à pergunta do engenheiro sobre a integração. Isso é análogo a um pattern de **Retrieval-Augmented Generation (RAG)** aplicado a contexto de conversa.\n\n**D - Usar /clear para redefinir o contexto completamente:** Esta abordagem joga fora todo o conhecimento acumulado, incluindo as descobertas valiosas sobre VulkanPipeline e FrameGraph. Seria como perder 25 minutos de investimento. O engenheiro quer exatamente entender a integração entre física e renderização — perder o contexto de renderização torna a tarefa praticamente impossível de ser realizada com a mesma profundidade.\n\n**Resposta correta: C**','\n',char(10)),replace('**Explicação para uma criança de 10 anos:**\n\nImagine que você passou 25 minutos montando um quebra-cabeça muito difícil que mostra um castelo. Você aprendeu todos os detalhes das torres, das janelas e das portas. De repente, seu amigo pede para você montar outro quebra-cabeça — um dragão — mas ele quer saber como o dragão e o castelo se encaixam na mesma história.\n\nAgora, suas opções são:\n\n**A** — Pedir para outra pessoa montar o dragão separadamente e depois tentar juntar as duas histórias. O problema é que essa outra pessoa não sabe nada sobre o castelo que você montou, então vai ser difícil fazer os dois se encaixarem direitinho.\n\n**B** — Continuar no mesmo lugar, com todas as peças do castelo espalhadas na sua frente, e tentar montar o dragão por cima. É confuso! Você fica tentando lembrar onde estava cada torre enquanto procura peças de dragão.\n\n**C** — Antes de começar o dragão, você escreve num papel os detalhes mais importantes do castelo (quantas torres, onde ficam as portas). Depois, você guarda o castelo e começa o dragão em uma mesa limpa, mas com esse papel do lado. Assim, quando precisar encaixar os dois, você tem as informações importantes na memória. ✅ **Essa é a melhor ideia!**\n\n**D** — Jogar tudo fora e recomeçar do zero. Você perdeu todo o trabalho que já fez! Agora você nem lembra mais do castelo direito e tem que descobrir tudo de novo.\n\nA opção **C** é a melhor porque você aproveita o que já aprendeu (o resumo do castelo) mas começa o dragão em um lugar novo e organizado, sem confusão. É como ter uma "cola" com as informações importantes do castelo enquanto monta o dragão!','\n',char(10)));
INSERT INTO cards VALUES('admin','card_1783092985228_db14hr2mb',147,'Um engenheiro pede ao agente para entender como funciona a camada de cache antes de adicionar um novo gatilho de invalidação de cache.',replace('Um engenheiro pede ao agente para entender como funciona a camada de cache antes de adicionar um novo gatilho de invalidação de cache.\n\nUm engenheiro pede ao agente para entender como funciona a camada de cache antes de adicionar um novo gatilho de invalidação de cache. Após as buscas iniciais com Grep, o agente identificou que a lógica de cache se espalha por 15 arquivos, incluindo decoradores, middleware e classes de serviço (~8.000 linhas no total).\n\nQual é o próximo passo mais eficaz para construir o entendimento gerenciando as restrições de contexto?\n\n[ ] A - Usar a ferramenta Read para carregar sequencialmente todos os 15 arquivos, construindo um entendimento completo de toda a implementação de cache.\n[ ] B - Analisar as importações e hierarquias de classe para identificar a classe base de cache, ler esse arquivo para entender a interface e, então, rastrear as implementações específicas de invalidação.\n[ ] C - Usar o Grep para buscar os padrões "invalidate" e "expire" em todos os arquivos e, então, ler apenas esses intervalos de linha específicos com o mínimo de contexto ao redor.\n[ ] D - Usar o Glob para encontrar arquivos que correspondam a padrões comuns de cache (cache.py, caching/), priorizar os maiores arquivos lendo-os primeiro e, então, verificar os menores em busca de lacunas.','\n',char(10)),'[ ] B - Analisar as importações e hierarquias de classe para identificar a classe base de cache, ler esse arquivo para entender a interface e, então, rastrear as implementações específicas de invalidação.','["Domain_3::Claude_Code_Configuration_Workflows", "Domain_5::Context_Management_Reliability", "Scenario_4::Developer_Productivity"]','New',0,2.5,0,1783092985228,1783725788896,1783203558653,replace('**Tradução para português do Brasil:**\n\nUm engenheiro pede ao agente para entender como funciona a camada de cache antes de adicionar um novo gatilho de invalidação de cache. Após as buscas iniciais com Grep, o agente identificou que a lógica de cache se espalha por 15 arquivos, incluindo decoradores, middleware e classes de serviço (~8.000 linhas no total).\n\nQual é o próximo passo mais eficaz para construir o entendimento gerenciando as restrições de contexto?\n\n[ ] A - Usar a ferramenta Read para carregar sequencialmente todos os 15 arquivos, construindo um entendimento completo de toda a implementação de cache.\n[ ] B - Analisar as importações e hierarquias de classe para identificar a classe base de cache, ler esse arquivo para entender a interface e, então, rastrear as implementações específicas de invalidação.\n[ ] C - Usar o Grep para buscar os padrões "invalidate" e "expire" em todos os arquivos e, então, ler apenas esses intervalos de linha específicos com o mínimo de contexto ao redor.\n[ ] D - Usar o Glob para encontrar arquivos que correspondam a padrões comuns de cache (cache.py, caching/), priorizar os maiores arquivos lendo-os primeiro e, então, verificar os menores em busca de lacunas.','\n',char(10)),replace('**Explicação didática para um adulto tech lead:**\n\nO cenário é clássico: temos um sistema legado com uma camada de cache distribuída por 15 arquivos e ~8.000 linhas. O objetivo é adicionar um novo gatilho de invalidação, mas antes precisamos entender o que já existe. A restrição de contexto (limitada) e a necessidade de eficiência são os fatores críticos.\n\n**Por que B é a melhor resposta:**\n\nA abordagem B segue o princípio de **"entender a abstração antes dos detalhes"**. Ao identificar a classe base de cache (provavelmente uma interface ou classe abstrata), você obtém o contrato do sistema — quais métodos existem, quais são os parâmetros esperados, qual o fluxo básico de operações (get, set, invalidate, etc.). Isso é extremamente eficiente porque:\n\n1. A classe base concentra o conhecimento fundamental em um único arquivo (ou poucos arquivos).\n2. A partir dela, você pode rastrear as implementações concretas apenas para os métodos relevantes à invalidação.\n3. Você evita ler 8.000 linhas desnecessariamente, focando apenas no que interessa para a tarefa.\n\n**Por que as demais estão erradas:**\n\n- **A**: Ler todos os 15 arquivos sequencialmente é a abordagem de "força bruta". Em um cenário com 8.000 linhas, isso exauriria rapidamente o contexto disponível, além de ser ineficiente — você estaria consumindo tokens e tempo para entender partes que podem ser irrelevantes para a tarefa específica (adicionar um gatilho de invalidação). Não gerencia bem as restrições de contexto.\n\n- **C**: Buscar apenas por "invalidate" e "expire" sem o contexto da classe base é eficiente superficialmente, mas perigoso. Você pode encontrar usos esparsos sem entender o mecanismo central. Por exemplo, pode haver um método `invalidate` na classe base e vários `invalidate` em subclasses. Sem entender a hierarquia, você não sabe qual é o fluxo real de invalidação e pode acabar propondo uma solução que conflita com o design existente. É um atalho que sacrifica a compreensão estrutural.\n\n- **D**: Priorizar arquivos pelo tamanho é arbitrário e não tem relação com a relevância para a tarefa. Um arquivo pequeno pode conter a classe base (essencial), enquanto um arquivo grande pode ser um decorador genérico com lógica de cache, mas não necessariamente sobre invalidação. Essa abordagem não garante que você encontre a informação certa no tempo certo.\n\n**Resumo técnico:** A abordagem B é a mais alinhada com os princípios de engenharia de software: comece pela abstração (contrato), entenda o fluxo principal e só então desça para os detalhes específicos. Isso maximiza o entendimento por token consumido.','\n',char(10)),replace('Imagine que você quer entender como funciona um videogame antes de adicionar um novo botão. O videogame tem 15 caixas diferentes cheias de peças (8.000 peças no total!).\n\n- **Opção A**: Abrir todas as 15 caixas e ler cada peça, uma por uma. Isso demoraria muito e você ficaria cansado antes de terminar.\n\n- **Opção B (a certa)**: Primeiro, procurar o manual de instruções do videogame (a "classe base"). O manual explica como o jogo funciona por dentro, quais botões existem e o que cada um faz. Depois de ler o manual, você sabe exatamente onde procurar as peças que mexem com os botões. É muito mais rápido e inteligente!\n\n- **Opção C**: Sair procurando pelas palavras "botão" e "apertar" em todas as caixas, sem ler nada ao redor. Você pode achar algumas peças, mas não vai entender como elas se encaixam. Pode até quebrar algo sem querer.\n\n- **Opção D**: Pegar as caixas maiores primeiro só porque são grandes. Mas a caixa maior pode ter peças que não são importantes para o seu botão novo. Você perde tempo e ainda pode perder a peça mais importante que está numa caixa pequena.\n\n**Então, o melhor é sempre começar pelo manual (a classe base) para entender as regras do jogo primeiro!**','\n',char(10)));
INSERT INTO cards VALUES('admin','card_1783092985239_8ryf4kngp',148,'O agente verifica a identidade do cliente por meio de um processo de múltiplas etapas antes de redefinir senhas.',replace('O agente verifica a identidade do cliente por meio de um processo de múltiplas etapas antes de redefinir senhas.\n\nO agente verifica a identidade do cliente por meio de um processo de múltiplas etapas antes de redefinir senhas. Durante os testes, você nota que, depois que o cliente responde à terceira pergunta de verificação, o agente pede que ele informe o nome novamente, como se a troca anterior nunca tivesse acontecido.\n\nQual é a causa mais provável desse comportamento?\n\n[ ] A - A ferramenta de verificação está limpando o estado interno do agente após cada etapa de validação bem-sucedida.\n[ ] B - O prompt não tem instruções dizendo ao Claude para lembrar informações ao longo de múltiplas trocas.\n[ ] C - O histórico da conversa não está sendo repassado nas requisições subsequentes da API.\n[ ] D - A retenção de memória do Claude é limitada a dois turnos de conversa por padrão, exigindo configuração explícita para estendê-la.','\n',char(10)),'[ ] C - O histórico da conversa não está sendo repassado nas requisições subsequentes da API.','["Domain_5::Context_Management_Reliability", "Domain_1::Agentic_Architecture_Orchestration", "Scenario_1::Customer_Support_Agent"]','New',0,2.5,0,1783092985239,1783725792662,1783203558653,replace('**Tradução para português do Brasil:**\n\nO agente verifica a identidade do cliente por meio de um processo de múltiplas etapas antes de redefinir senhas. Durante os testes, você nota que, depois que o cliente responde à terceira pergunta de verificação, o agente pede que ele informe o nome novamente, como se a troca anterior nunca tivesse acontecido.\n\nQual é a causa mais provável desse comportamento?\n\n[ ] A - A ferramenta de verificação está limpando o estado interno do agente após cada etapa de validação bem-sucedida.\n[ ] B - O prompt não tem instruções dizendo ao Claude para lembrar informações ao longo de múltiplas trocas.\n[ ] C - O histórico da conversa não está sendo repassado nas requisições subsequentes da API.\n[ ] D - A retenção de memória do Claude é limitada a dois turnos de conversa por padrão, exigindo configuração explícita para estendê-la.','\n',char(10)),replace('**Explicação para adulto (tech lead):**\n\nO comportamento descrito — o agente "esquecer" o contexto da conversa e recomeçar do zero — é um sintoma clássico de **statelessness** na comunicação com a API de um modelo de linguagem.\n\n**Por que C é a resposta correta:**\nModelos como Claude (via API) são intrinsecamente stateless: cada requisição é processada de forma independente. Para que o agente "se lembre" do que foi dito antes, o histórico completo da conversa (mensagens anteriores) precisa ser enviado de volta em cada nova chamada de API. Se o desenvolvedor não está repassando esse histórico, o modelo não tem conhecimento dos turnos anteriores, agindo como se a conversa estivesse começando a cada interação. Isso explica perfeitamente por que, após a terceira pergunta, o agente pede o nome novamente.\n\n**Por que as demais alternativas estão incorretas:**\n\n- **A**: "A ferramenta de verificação está limpando o estado interno" — Essa alternativa confunde o ferramental customizado (uma ferramenta/function call) com o mecanismo de contexto do modelo. Mesmo que uma ferramenta específica de verificação fosse mal implementada, ela não teria o poder de "limpar" o estado interno do modelo, pois o modelo não mantém estado entre chamadas de API. O problema é estrutural na integração, não em uma ferramenta específica.\n\n- **B**: "O prompt não tem instruções para lembrar informações" — Instruções no prompt (system prompt) podem orientar o comportamento do modelo, mas não substituem a necessidade de enviar o histórico da conversa. Mesmo com as melhores instruções, se o histórico não for enviado, o modelo simplesmente não tem acesso às mensagens anteriores. É um erro de infraestrutura, não de prompt engineering.\n\n- **D**: "A retenção de memória do Claude é limitada a dois turnos" — Isso é factualmente incorreto. Claude não possui um limite fixo de "dois turnos" de memória. O limite real é o contexto máximo (janela de contexto), que pode conter dezenas de milhares de tokens. O que ocorre é que, se o histórico não for enviado, mesmo um único turno é perdido.','\n',char(10)),replace('Imagine que você está contando uma história para um robô, mas a cada frase que você diz, o robô desliga e liga de novo. Então, quando você fala a segunda frase, ele não lembra da primeira. Isso é o que está acontecendo aqui!\n\nO agente (o programa) pergunta uma coisa, o cliente responde. Mas quando o cliente dá a resposta, o programa "esquece" o que perguntou e começa de novo, como se nada tivesse acontecido. Por isso ele pede o nome de novo.\n\nIsso acontece porque quem fez o programa esqueceu de mandar todo o histórico da conversa de volta para o sistema a cada nova pergunta. É como se a cada mensagem fosse uma conversa nova. Por isso o agente não se lembra do que foi dito antes.\n\nAs outras opções não explicam direito: não é culpa de uma ferramenta específica que "apaga" a memória (opção A), não é porque faltou uma instrução escrita no prompt (opção B), e também não é verdade que o Claude só consegue lembrar de duas falas por padrão (opção D). O problema real é que o histórico das mensagens anteriores não está sendo enviado de volta (opção C).','\n',char(10)));
INSERT INTO cards VALUES('admin','card_1783092985249_ylzfvc40p',149,'Um cliente levanta três questões distintas durante uma sessão: uma consulta de reembolso (turnos 1-15), uma dúvida sobre assinatura (turnos 16-30) e uma atualização de método de pagamento (turnos 31-45).',replace('Um cliente levanta três questões distintas durante uma sessão: uma consulta de reembolso (turnos 1-15), uma dúvida sobre assinatura (turnos 16-30) e uma atualização de método de pagamento (turnos 31-45).\n\nUm cliente levanta três questões distintas durante uma sessão: uma consulta de reembolso (turnos 1-15), uma dúvida sobre assinatura (turnos 16-30) e uma atualização de método de pagamento (turnos 31-45). No turno 48, o cliente pergunta "O que aconteceu com o meu reembolso?" A conversa está se aproximando dos limites de contexto.\n\nQual estratégia mantém melhor a capacidade do agente de tratar todas as questões ao longo da sessão?\n\n[ ] A - Extrair e persistir dados estruturados das questões (IDs de pedidos, valores, status) em uma camada de contexto separada.\n[ ] B - Confiar nas ferramentas MCP para buscar novamente as informações relevantes sob demanda quando o cliente fizer referência a questões anteriores.\n[ ] C - Resumir os turnos anteriores em uma descrição narrativa, preservando o histórico completo de mensagens apenas para a questão ativa.\n[ ] D - Implementar contexto em janela deslizante que retém os 30 turnos mais recentes.','\n',char(10)),'A - Extrair e persistir dados estruturados das questões (IDs de pedidos, valores, status) em uma camada de contexto separada.','["Domain_5::Context_Management_Reliability", "Domain_1::Agentic_Architecture_Orchestration", "Scenario_1::Customer_Support_Agent"]','New',0,2.5,0,1783092985249,1783725796758,1783203558653,replace('**Tradução para português do Brasil:**\n\nUm cliente levanta três questões distintas durante uma sessão: uma consulta de reembolso (turnos 1-15), uma dúvida sobre assinatura (turnos 16-30) e uma atualização de método de pagamento (turnos 31-45). No turno 48, o cliente pergunta "O que aconteceu com o meu reembolso?" A conversa está se aproximando dos limites de contexto.\n\nQual estratégia mantém melhor a capacidade do agente de tratar todas as questões ao longo da sessão?\n\n[ ] A - Extrair e persistir dados estruturados das questões (IDs de pedidos, valores, status) em uma camada de contexto separada.\n[ ] B - Confiar nas ferramentas MCP para buscar novamente as informações relevantes sob demanda quando o cliente fizer referência a questões anteriores.\n[ ] C - Resumir os turnos anteriores em uma descrição narrativa, preservando o histórico completo de mensagens apenas para a questão ativa.\n[ ] D - Implementar contexto em janela deslizante que retém os 30 turnos mais recentes.','\n',char(10)),replace('**Explicação para um adulto tech lead:**\n\nO cenário descreve um problema clássico de gerenciamento de contexto em sistemas de diálogo com limites de tokens (aproximando-se do limite de contexto). O agente precisa lidar com múltiplas questões ao longo de uma única sessão, e o cliente retoma um tópico antigo (reembolso) após 33 turnos.\n\n**Por que a alternativa A é a correta:**\n\nExtrair e persistir dados estruturados (como IDs de pedidos, valores, status) em uma camada de contexto separada é a abordagem mais robusta. Isso cria uma "memória de fatos" independente do histórico textual, permitindo que o agente acesse informações precisas sobre questões passadas sem depender do histórico completo de mensagens. Essa técnica é semanticamente mais rica e resistente à degradação por sumarização ou corte. Em arquiteturas de agentes modernas (como as que utilizam memórias de longo prazo ou RAG), essa é a prática recomendada: estruturar informações críticas em um formato que o agente possa consultar programaticamente.\n\n**Por que as demais alternativas estão incorretas:**\n\n- **B**: Confiar em ferramentas MCP (Model Context Protocol) para buscar informações sob demanda quando o cliente faz referência a questões anteriores parece atraente, mas não é confiável para esse cenário. Ferramentas MCP normalmente acessam fontes externas (APIs, bancos de dados), mas o histórico da conversa em si não é uma fonte externa acessível via MCP — a menos que a própria sessão seja persistida externamente. Além disso, a ferramenta precisaria "saber" que deve buscar algo, e o contexto já está sendo perdido. Não resolve o problema de limite de contexto.\n\n- **C**: Resumir turnos anteriores em uma descrição narrativa e preservar apenas o histórico da questão ativa é uma abordagem comum, mas frágil. A sumarização pode perder detalhes críticos (valores exatos, prazos, status), especialmente em interações longas. Além disso, ao retomar uma questão antiga, o resumo pode ser impreciso ou incompleto, levando o agente a tomar decisões baseadas em informações degradadas.\n\n- **D**: Implementar contexto em janela deslizante que retém os 30 turnos mais recentes é a pior estratégia para esse caso. Quando o cliente pergunta sobre o reembolso no turno 48, os turnos 1-15 já foram descartados (pois a janela de 30 turnos cobre apenas os turnos 18-48, aproximadamente). O agente simplesmente não teria acesso à informação do reembolso, tornando impossível responder adequadamente.','\n',char(10)),replace('Imagine que você está conversando com um robô ajudante. Você começa falando sobre um brinquedo que quer devolver (reembolso), depois pergunta sobre sua assinatura de jogos, e por fim muda a forma de pagamento. Depois de um tempo, você volta a perguntar: "E o meu reembolso, onde está?"\n\nO robô tem um limite de memória — ele não consegue se lembrar de tudo que foi dito. Se ele só guardar as últimas 30 frases, ele já esqueceu do reembolso! Se ele tentar resumir, pode errar detalhes importantes.\n\nA melhor estratégia (letra A) é o robô anotar os pontos mais importantes em uma "fichinha" separada: "Reembolso: pedido #123, R$ 50, ainda pendente". Assim, mesmo que ele esqueça a conversa inteira, ele pode consultar essa fichinha e responder certinho. É como fazer uma anotação num caderno de bolso em vez de tentar decorar tudo de cabeça.','\n',char(10)));
INSERT INTO cards VALUES('admin','card_1783092985261_5k8wleqhp',150,'Seu agente chamou `lookup_order` várias vezes enquanto investigava os pedidos de devolução de um cliente.',replace('Seu agente chamou `lookup_order` várias vezes enquanto investigava os pedidos de devolução de um cliente.\n\nSeu agente chamou `lookup_order` várias vezes enquanto investigava os pedidos de devolução de um cliente. Cada resposta inclui mais de 40 campos (itens, detalhes de envio, informações de pagamento, histórico de status). As saídas das ferramentas agora representam a maior parte do contexto da conversa. O cliente menciona mais dois pedidos que deseja discutir.\n\nQual é a abordagem mais eficaz antes de fazer consultas adicionais?\n\n[ ] A - Extrair apenas os campos relevantes para a devolução (itens, data da compra, prazo de devolução, status) de cada resposta de pedido existente, removendo os detalhes verbosos.\n[ ] B - Fazer com que o modelo gere um resumo em linguagem natural dos detalhes principais de cada pedido, substituindo as respostas estruturadas por descrições em prosa.\n[ ] C - Mover todas as respostas das ferramentas para um banco de dados vetorial com indexação semântica, recuperando as partes relevantes conforme a conversa avança.\n[ ] D - Prosseguir com as consultas adicionais sem modificar o contexto existente das saídas das ferramentas.','\n',char(10)),'A - Extrair apenas os campos relevantes para a devolução (itens, data da compra, prazo de devolução, status) de cada resposta de pedido existente, removendo os detalhes verbosos.','["Domain_5::Context_Management_Reliability", "Domain_2::Tool_Design_MCP_Integration", "Scenario_1::Customer_Support_Agent"]','New',0,2.5,0,1783092985261,1783725800576,1783203558653,replace('**Tradução para português do Brasil:**\n\nSeu agente chamou `lookup_order` várias vezes enquanto investigava os pedidos de devolução de um cliente. Cada resposta inclui mais de 40 campos (itens, detalhes de envio, informações de pagamento, histórico de status). As saídas das ferramentas agora representam a maior parte do contexto da conversa. O cliente menciona mais dois pedidos que deseja discutir.\n\nQual é a abordagem mais eficaz antes de fazer consultas adicionais?\n\n[ ] A - Extrair apenas os campos relevantes para a devolução (itens, data da compra, prazo de devolução, status) de cada resposta de pedido existente, removendo os detalhes verbosos.\n[ ] B - Fazer com que o modelo gere um resumo em linguagem natural dos detalhes principais de cada pedido, substituindo as respostas estruturadas por descrições em prosa.\n[ ] C - Mover todas as respostas das ferramentas para um banco de dados vetorial com indexação semântica, recuperando as partes relevantes conforme a conversa avança.\n[ ] D - Prosseguir com as consultas adicionais sem modificar o contexto existente das saídas das ferramentas.','\n',char(10)),replace('**Explicação para um adulto tech lead:**\n\nO problema central aqui é o gerenciamento do contexto em um agente de IA com janela de contexto limitada. As chamadas de ferramenta `lookup_order` produziram saídas muito extensas (40+ campos cada), que já estão consumindo grande parte do contexto disponível. O cliente quer discutir mais dois pedidos, o que exigirá novas chamadas de ferramenta e novas respostas volumosas.\n\n**Análise das alternativas:**\n\n**Alternativa A (Correta):** Extrair apenas os campos relevantes para a devolução (itens, data da compra, prazo de devolução, status) de cada resposta de pedido existente, removendo os detalhes verbosos. Esta é a abordagem mais eficaz porque:\n- Reduz drasticamente o tamanho do contexto ocupado, liberando espaço para as novas consultas.\n- Preserva exatamente as informações necessárias para a tarefa atual (devolução), sem perder dados úteis.\n- É uma abordagem determinística e previsível, ao contrário de sumarização por LLM.\n- A janela de contexto de modelos como GPT-4 ou Claude tem limites (ex: 128k tokens). Se 40 campos por pedido já consomem a maior parte, adicionar mais dois pedidos pode estourar o limite ou degradar a performance.\n\n**Alternativa B (Incorreta):** Gerar um resumo em linguagem natural. Embora reduza o tamanho, a sumarização por LLM é não-determinística e pode introduzir alucinações ou omissões de detalhes críticos. Além disso, substituir dados estruturados por prosa torna mais difícil para o próprio modelo processar informações precisas posteriormente (como datas exatas, códigos de status, etc.). É uma abordagem menos confiável e mais custosa computacionalmente.\n\n**Alternativa C (Incorreta):** Mover para um banco de dados vetorial. Isso seria uma solução de RAG (Retrieval-Augmented Generation), que é desnecessariamente complexa para este cenário. Bancos vetoriais são úteis para grandes volumes de documentos onde a recuperação semântica é necessária, mas aqui temos apenas algumas respostas de API já disponíveis no contexto. O custo de implementação e latência (embeddings + recuperação) não se justifica. Além disso, a pergunta é sobre "o que fazer antes de consultas adicionais" — implementar RAG é uma mudança arquitetural, não uma ação imediata.\n\n**Alternativa D (Incorreta):** Prosseguir sem modificar. Esta é a pior opção, pois o contexto já está praticamente cheio. Adicionar mais duas respostas de 40+ campos cada quase certamente excederá o limite de contexto, causando perda de informação (modelo "esquecendo" partes iniciais da conversa) ou aumento de latência/custo. Não há tratamento do problema de gerenciamento de contexto.','\n',char(10)),replace('Imagine que você tem uma mochila (o contexto do agente) que só cabe uma quantidade limitada de coisas. Dentro dela já estão várias fichas enormes com informações sobre alguns pedidos — cada ficha tem 40 itens escritos, como endereço, forma de pagamento, cor do produto, etc. Agora o cliente quer falar de mais dois pedidos, que também vão gerar fichas grandes.\n\nSe você colocar mais fichas sem tirar nada, a mochila vai ficar tão cheia que algumas coisas vão cair fora ou você não vai conseguir fechar. Não dá certo!\n\nEntão, o melhor é pegar cada ficha existente e recortar só a parte que interessa — no caso, os detalhes sobre devolução (itens comprados, data da compra, prazo para devolver e status). Assim, você libera espaço na mochila para colocar as fichas dos novos pedidos, sem perder as informações importantes.\n\nAs outras opções seriam: escrever um resumo em texto (mas pode esquecer algum detalhe importante), montar um sistema super complicado de gavetas com etiquetas (banco vetorial) que demora pra montar, ou simplesmente enfiar tudo na mochila até ela estourar. Nenhuma delas é tão prática quanto simplesmente cortar o que não precisa!','\n',char(10)));
INSERT INTO cards VALUES('admin','card_1783092985286_se5l09gsq',151,'Depois que seu batch diário de 10.',replace('Depois que seu batch diário de 10.\n\nDepois que seu batch diário de 10.000 documentos é concluído, 300 documentos (3%) falharam com erros "`context_length_exceeded`". O arquivo de resultados identifica cada falha por `custom_id`.\n\nQual é a abordagem mais econômica para processar essas falhas?\n\n[ ] A - Reprocessar o batch inteiro com prompt caching habilitado para reduzir o custo de repetir requisições com prompts de sistema idênticos\n[ ] B - Reenviar apenas os 300 documentos que falharam, após dividi-los em pedaços menores, e então combinar as extrações parciais\n[ ] C - Reenviar o batch inteiro de 10.000 documentos usando um nível de modelo com uma janela de contexto maior\n[ ] D - Aumentar o parâmetro `max_tokens` para os 300 documentos que falharam e reenviá-los em um novo batch','\n',char(10)),'B - Reenviar apenas os 300 documentos que falharam, após dividi-los em pedaços menores, e então combinar as extrações parciais','["Domain_5::Context_Management_Reliability", "Domain_4::Prompt_Engineering_Structured_Output", "Scenario_6::Structured_Data_Extraction"]','New',0,2.5,0,1783092985286,1783725804623,1783203558653,replace('**Tradução para português do Brasil:**\n\nDepois que seu batch diário de 10.000 documentos é concluído, 300 documentos (3%) falharam com erros "context_length_exceeded". O arquivo de resultados identifica cada falha por custom_id.\n\nQual é a abordagem mais econômica para processar essas falhas?\n\n[ ] A - Reprocessar o batch inteiro com prompt caching habilitado para reduzir o custo de repetir requisições com prompts de sistema idênticos\n[ ] B - Reenviar apenas os 300 documentos que falharam, após dividi-los em pedaços menores, e então combinar as extrações parciais\n[ ] C - Reenviar o batch inteiro de 10.000 documentos usando um nível de modelo com uma janela de contexto maior\n[ ] D - Aumentar o parâmetro max_tokens para os 300 documentos que falharam e reenviá-los em um novo batch','\n',char(10)),replace('**Explicação para adulto (tech lead):**\n\n**Resposta correta: Alternativa B**\n\nO erro `context_length_exceeded` indica que o documento excede o limite máximo de tokens suportado pelo modelo. Isso não é resolvido com `max_tokens` (que controla o tamanho da *resposta*, não da entrada, eliminando D). Também não justifica reprocessar 10.000 documentos que já foram processados com sucesso (eliminando A e C).\n\nA alternativa B é a mais econômica porque:\n- Processa apenas os 3% que falharam, sem desperdiçar tokens com documentos já concluídos.\n- Endereça a causa raiz: documentos muito longos para a janela de contexto. Dividi-los em pedaços menores e combinar extrações parciais é a solução canônica para esse tipo de erro.\n- `prompt caching` (alternativa A) reduziria custos em chamadas repetitivas com prompts de sistema idênticos, mas não resolve o problema de exceder a janela de contexto.\n- Reprocessar tudo com um modelo de janela maior (alternativa C) seria desperdício financeiro, pois 97% dos documentos já foram bem-sucedidos — você pagaria para reprocessar 10.000 documentos quando só precisa lidar com 300.\n- A alternativa D é inválida pois `max_tokens` limita a saída, não a entrada; o erro é de contexto de entrada excedido.\n\n**Alternativas incorretas:**\n- **A**: Custa caro reprocessar 10.000 docs e não resolve o problema real (tamanho do documento).\n- **C**: Custa caro e é desnecessário para 97% dos documentos.\n- **D**: Não resolve, pois o erro não é sobre o tamanho da resposta.','\n',char(10)),replace('Imagine que você tem 10.000 trabalhos de casa para corrigir. 300 deles têm um problema: são textos muito longos e sua caneta não consegue escrever uma resposta tão grande quanto eles. Você já terminou de corrigir os outros 9.700.\n\nA melhor ideia é pegar só esses 300 textos grandes, cortar cada um em partes menores, corrigir cada parte separadamente e depois juntar tudo. Assim você não perde tempo corrigindo de novo os 9.700 que já estavam certos.\n\nFazer de novo todos os 10.000 seria um desperdício enorme de tempo e dinheiro, e aumentar o tamanho da resposta da caneta não resolve porque o problema é que o texto de entrada é muito comprido, não a resposta.','\n',char(10)));
INSERT INTO cards VALUES('admin','card_1783092985299_vgca83boj',152,'A team has an onboarding process whose sequence of steps is always the same and known in advance.',replace('A team has an onboarding process whose sequence of steps is always the same and known in advance.\n\nA team has an onboarding process whose sequence of steps is always the same and known in advance. Which approach is the most appropriate in production?\n[Resposta correta: Quando a sequência exata é previsível, o workflow entrega precisão, previsibilidade e testabilidade. A pegadinha em A e C é escolher agent para uma sequência previsível, exatamente o cenário em que o agent adiciona risco e menor previsibilidade sem ganho. D ignora que os padrões diferem justamente na previsibilidade.]\n\n[ ] A - An agent, because agents always have a higher successful completion rate.\n[ ] B - A workflow, because the sequence is predictable and this provides precision and testability.\n[ ] C - An agent, because the predictability of the sequence makes creative exploration of tools easier.\n[ ] D - It does not matter, since workflows and agents have the same degree of predictability.','\n',char(10)),'B - A workflow, because the sequence is predictable and this provides precision and testability.','["Domain_1::Agentic_Architecture_Orchestration", "ForaDoCenario"]','New',0,2.5,0,1783092985299,1783725808583,1783203558653,replace('## Tradução para Português do Brasil\n\n**Pergunta:** Uma equipe tem um processo de onboarding cuja sequência de etapas é sempre a mesma e conhecida antecipadamente. Qual abordagem é a mais adequada em produção?\n\n[ ] A - Um agente (agent), porque agentes sempre têm uma taxa de conclusão bem-sucedida maior.\n[ ] B - Um workflow, porque a sequência é previsível e isso proporciona precisão e testabilidade.\n[ ] C - Um agente (agent), porque a previsibilidade da sequência torna a exploração criativa de ferramentas mais fácil.\n[ ] D - Não importa, pois workflows e agentes têm o mesmo grau de previsibilidade.','\n',char(10)),replace('## Explicação para um Adulto (Tech Lead)\n\n**Resposta correta: Alternativa B**\n\nA questão aborda um tópico central em engenharia de sistemas baseados em LLMs (Large Language Models) e automação: a diferença entre **workflows** (fluxos de trabalho determinísticos, predefinidos) e **agents** (agentes autônomos que decidem dinamicamente os próximos passos usando ferramentas).\n\nO cenário descrito é inequívoco: a sequência de etapas é **sempre a mesma e conhecida antecipadamente**. Isso caracteriza perfeitamente um caso de uso para **workflows**.\n\n**Por que a alternativa B está correta:**\n\n- Workflows são projetados exatamente para cenários previsíveis. Eles executam uma sequência fixa de etapas (como um DAG — Directed Acyclic Graph), o que os torna determinísticos, fáceis de testar (cada etapa pode ser validada isoladamente), auditáveis e altamente confiáveis.\n- Em produção, previsibilidade se traduz diretamente em menor variabilidade de resultados, menor latência imprevisível e maior facilidade de debugging.\n- Workflows são a escolha padrão e recomendada sempre que o processo é conhecido e imutável — exatamente o caso do onboarding.\n\n**Por que as demais alternativas estão erradas:**\n\n- **Alternativa A** — A afirmação de que "agentes sempre têm uma maior taxa de conclusão bem-sucedida" é falsa e enganosa. Agentes introduzem variabilidade e risco justamente porque tomam decisões autônomas a cada etapa. Para uma sequência previsível, um workflow é mais confiável.\n- **Alternativa C** — A "exploração criativa de ferramentas" (característica de agents) é contraproducente quando a sequência já é conhecida. Um agent poderia tentar caminhos alternativos sem necessidade, adicionando complexidade, custo e possibilidade de erro. Agentes são adequados para cenários onde o caminho ideal é desconhecido — o oposto do que foi descrito.\n- **Alternativa D** — É incorreta porque workflows e agents têm graus de previsibilidade **fundamentalmente diferentes**. Workflows são determinísticos por construção; agents são probabilisticamente imprevisíveis. A afirmação ignora a distinção central entre os dois padrões.\n\n**Resumo técnico:** Use workflows para processos determinísticos e repetitivos; use agents para processos que exigem adaptação dinâmica e exploração. Misturar os dois gera overengineering e risco operacional desnecessário.','\n',char(10)),replace('## Explicação para uma Criança de 10 Anos\n\nImagina que você tem uma receita para fazer um bolo de chocolate. A receita diz: primeiro, misture os ingredientes secos; depois, adicione os líquidos; depois, coloque no forno. **A sequência é sempre a mesma** — você não pode misturar os líquidos primeiro ou colocar no forno antes de misturar.\n\nAgora, pense em duas formas de fazer isso:\n\n1. **Workflow (ou "receita certinha"):** Você segue exatamente a receita, passo a passo. Sem invenção. Sabemos exatamente o que vai acontecer. É fácil testar se deu certo.\n\n2. **Agent (ou "cozinheiro criativo"):** O cozinheiro pode decidir fazer coisas diferentes. Ele pode provar a massa, decidir colocar mais açúcar, ou tentar assar antes de misturar tudo. Isso é legal quando você não sabe a receita e precisa inventar, mas **se a receita já está pronta e é sempre igual**, isso só atrapalha!\n\n**Resposta correta: Alternativa B** — Escolher *workflow* é como seguir a receita passo a passo, porque sabemos exatamente o que fazer. É mais rápido, não tem erro e todo mundo entende o que está acontecendo.\n\nJá escolher *agent* (alternativa A ou C) quando a receita já é conhecida seria como deixar o cozinheiro inventar moda desnecessariamente — ele pode errar ou demorar mais. E a alternativa D está errada porque uma receita certinha é muito mais previsível do que deixar o cozinheiro decidir o que fazer.','\n',char(10)));
INSERT INTO cards VALUES('admin','card_1783092985312_2m8nctpo9',153,'An app needs to handle open-ended requests, whose parameters and the task itself are not known before the user interaction.',replace('An app needs to handle open-ended requests, whose parameters and the task itself are not known before the user interaction.\n\nAn app needs to handle open-ended requests, whose parameters and the task itself are not known before the user interaction. Which pattern applies?\n[Resposta correta: O agent é indicado justamente quando não se sabe de antemão a tarefa nem os parâmetros. A e B forçam um workflow onde a sequência não pode ser pré-determinada. D inverte o tradeoff, pois agents são mais difíceis de testar, não mais fáceis.]\n\n[ ] A - Workflow, because every production application should prioritize predictability.\n[ ] B - Workflow, because it is possible to pre-determine the sequence of steps.\n[ ] C - Agent, because the task and the parameters are unpredictable and require a creative combination of tools.\n[ ] D - Agent, because agents are always easier to test.','\n',char(10)),'C - Agent, because the task and the parameters are unpredictable and require a creative combination of tools.','["ForaDosDominios", "ForaDoCenario"]','New',0,2.5,0,1783092985312,1783725812570,1783203558653,replace('**Tradução para português do Brasil:**\n\n*Pergunta:*\nUm aplicativo precisa lidar com solicitações abertas (open-ended), cujos parâmetros e a própria tarefa não são conhecidos antes da interação do usuário. Qual padrão se aplica?\n\n*Alternativas:*\n[ ] A - Workflow, porque toda aplicação em produção deve priorizar a previsibilidade.\n[ ] B - Workflow, porque é possível pré-determinar a sequência de etapas.\n[ ] C - Agent, porque a tarefa e os parâmetros são imprevisíveis e exigem uma combinação criativa de ferramentas.\n[ ] D - Agent, porque agents são sempre mais fáceis de testar.','\n',char(10)),replace('**Explicação para um adulto tech lead:**\n\nA pergunta descreve um cenário de "open-ended requests" — solicitações onde não se sabe de antemão qual será a tarefa nem quais parâmetros serão utilizados. Isso é típico de sistemas que precisam de autonomia e adaptabilidade em tempo real, como assistentes virtuais, chatbots complexos ou sistemas de automação que lidam com entradas não estruturadas.\n\n**Alternativa correta: C**\n\nO padrão **Agent** é a escolha adequada porque ele é projetado exatamente para cenários onde o fluxo não pode ser pré-determinado. Um agent possui capacidade de raciocínio, planejamento dinâmico e uso contextual de ferramentas — ele "decide" o que fazer com base na entrada do usuário no momento da interação. Isso contrasta com workflows, que são sequências fixas e pré-definidas de passos.\n\n**Por que as demais alternativas estão incorretas:**\n\n- **A (Workflow - previsibilidade):** Embora previsibilidade seja desejável em muitos sistemas, ela não é o único critério. Quando a tarefa é desconhecida, forçar um workflow previsível simplesmente não funciona — o sistema não saberá qual caminho seguir.\n- **B (Workflow - pré-determinar sequência):** A afirmação é falsa para o cenário descrito. Se os parâmetros e a tarefa são desconhecidos, **não é possível** pré-determinar a sequência de etapas. Workflows são adequados para processos bem definidos e repetitivos.\n- **D (Agent - mais fácil de testar):** Esta afirmação inverte o tradeoff. Na prática, agents são **mais difíceis** de testar do que workflows, justamente por seu comportamento não-determinístico e pela necessidade de testar decisões, combinações de ferramentas e caminhos imprevisíveis. Workflows, por terem sequências fixas, são mais previsíveis e, portanto, mais fáceis de testar.','\n',char(10)),replace('**Explicação para uma criança de 10 anos:**\n\nImagine que você tem dois tipos de ajudantes:\n\n1. **O Robô que segue uma receita (Workflow):** Ele só sabe fazer coisas se você der uma receita passo a passo. Se você pedir algo novo ou diferente, ele trava porque não sabe o que fazer.\n\n2. **O Robô esperto (Agent):** Ele é como um amigo que pode inventar soluções. Se você pedir algo diferente, ele pensa, junta as ferramentas que tem e descobre um jeito de resolver.\n\nA pergunta diz: "O aplicativo precisa lidar com pedidos que a gente não sabe quais são antes do usuário pedir." Isso significa que o robô precisa ser criativo e se adaptar, igual ao **robô esperto (Agent)**.\n\nA alternativa **C** está certa porque um agente consegue lidar com tarefas e parâmetros imprevisíveis, combinando ferramentas de forma criativa.\n\nAs outras opções estão erradas porque:\n- **A e B** dizem para usar um robô de receita, mas se a gente não sabe qual receita seguir, ele não consegue fazer nada.\n- **D** diz que o agente é mais fácil de testar, mas não é verdade — testar um robô criativo é mais difícil do que testar um que sempre faz a mesma coisa!','\n',char(10)));
INSERT INTO cards VALUES('admin','card_1783092985323_gsn7h9t31',154,'Which definition correctly describes a workflow?',replace('Which definition correctly describes a workflow?\n\nWhich definition correctly describes a workflow?\n[Resposta correta: Workflow é a sequência pré-determinada de passos para um problema conhecido. A descreve um agent. C descreve o antipadrão de prompt único. D confunde a condição de parada de um loop agêntico e ainda usa critério errado (tokens).]\n\n[ ] A - Giving Claude a goal and tools and expecting it to figure out on its own how to combine them.\n[ ] B - A series of calls to Claude through a pre-determined sequence of steps for a known problem.\n[ ] C - A single giant call that balances all criteria at the same time.\n[ ] D - A loop that only stops when the tokens run out.','\n',char(10)),'[ ] B - A series of calls to Claude through a pre-determined sequence of steps for a known problem.','["Domain_1::Agentic_Architecture_Orchestration", "ForaDoCenario"]','New',0,2.5,0,1783092985323,1783725816711,1783203558653,replace('Tradução:\n\nQual definição descreve corretamente um workflow?\n\n[ ] A - Dar um objetivo e ferramentas para o Claude e esperar que ele descubra sozinho como combiná-los.\n[ ] B - Uma série de chamadas para o Claude através de uma sequência pré-determinada de passos para um problema conhecido.\n[ ] C - Uma única chamada gigante que equilibra todos os critérios ao mesmo tempo.\n[ ] D - Um loop que só para quando os tokens acabam.','\n',char(10)),replace('Explicação para adulto tech lead:\n\nA alternativa B é a resposta correta porque captura com precisão o conceito de workflow em sistemas de IA: uma sequência fixa e planejada de etapas (chamadas ao modelo) que são executadas em uma ordem pré-determinada para resolver um problema conhecido. Workflows são estruturas previsíveis, onde o fluxo de controle é definido antecipadamente, não descoberto dinamicamente pelo modelo.\n\nAnálise detalhada das alternativas incorretas:\n\n- **Alternativa A**: Esta descreve um **agente de IA autônomo** (agent), não um workflow. Em uma abordagem agentiva, o modelo recebe um objetivo e ferramentas, e decide por conta própria como combiná-las e em que ordem usá-las. O oposto do modelo de workflow, onde a sequência é pré-definida.\n\n- **Alternativa C**: Esta descreve um **antipadrão de prompt único** (single giant prompt). Tentar colocar toda a lógica e todos os critérios em uma única chamada massiva ao modelo raramente funciona bem — é frágil, difícil de debugar e não escala. Workflows quebram o problema em múltiplas chamadas menores e mais focadas.\n\n- **Alternativa D**: Esta confunde a **condição de parada** de um loop agêntico (agentic loop) e ainda usa o critério errado (tokens/token limit). Em loops agênticos, a parada deve ser baseada em conclusão de tarefa, alcance de objetivo ou limite de iterações, não em esgotamento de tokens. Acabar os tokens é uma falha de recurso, não uma condição de parada deliberada e controlada.','\n',char(10)),replace('Explicação para criança de 10 anos:\n\nImagine que você vai fazer um bolo. Um workflow é como uma **receita de bolo** — você segue os passos na ordem certa: primeiro pega os ingredientes, depois mistura, depois coloca no forno. Você já sabe quais são os passos antes de começar.\n\nA alternativa **B** diz exatamente isso: uma sequência de passos que já está definida antes de começar, para resolver um problema que você já conhece.\n\nAs outras alternativas estão erradas por diferentes motivos:\n\n- **A** seria como dar a receita para um amigo e falar "faz aí do seu jeito, se vira" — isso não é um workflow, é deixar a pessoa inventar o processo.\n\n- **C** seria como tentar fazer o bolo inteiro de uma vez só, colocando tudo no forno cru e esperando dar certo — não funciona.\n\n- **D** seria como ficar mexendo a massa sem parar até acabar a farinha — você não para porque o bolo ficou pronto, você para porque acabou o ingrediente. Não é assim que se faz!','\n',char(10)));
INSERT INTO cards VALUES('admin','card_1783092985335_5r8dyalt2',155,'Which definition correctly describes an agent?',replace('Which definition correctly describes an agent?\n\nWhich definition correctly describes an agent?\n[Resposta correta: O agent recebe objetivo e tools e decide sozinho a combinação. A descreve um workflow, B descreve routing e D descreve paralelização.]\n\n[ ] A - A fixed sequence of steps written in code for a known problem.\n[ ] B - A router that classifies the input and picks a specialized pipeline.\n[ ] C - Giving Claude a goal and tools, expecting it to figure out how to combine them to reach the goal.\n[ ] D - Sending the same input in several parallel requests and aggregating the results.','\n',char(10)),'C - Giving Claude a goal and tools, expecting it to figure out how to combine them to reach the goal.','["Domain_1::Agentic_Architecture_Orchestration", "ForaDoCenario"]','New',0,2.5,0,1783092985335,1783725820594,1783203558653,replace('**Tradução para português do Brasil:**\n\nQual definição descreve corretamente um agente?\n\n[ ] A - Uma sequência fixa de passos escrita em código para um problema conhecido.\n[ ] B - Um roteador que classifica a entrada e escolhe um pipeline especializado.\n[ ] C - Dar a Claude (um modelo de IA) um objetivo e ferramentas, esperando que ele descubra como combiná-las para alcançar o objetivo.\n[ ] D - Enviar a mesma entrada em várias requisições paralelas e agregar os resultados.','\n',char(10)),replace('**Explicação didática para um adulto tech lead:**\n\nA definição correta de um **agente** (no contexto de sistemas de IA e LLMs) é a alternativa **C**. Um agente é caracterizado por sua **autonomia**: ele recebe um objetivo de alto nível e um conjunto de ferramentas (tools), e decide por conta própria a sequência de ações, chamadas de ferramentas e combinações necessárias para atingir aquele objetivo. O modelo (ex.: Claude) atua como "cérebro" do agente, raciocinando e planejando dinamicamente.\n\n**Por que as demais estão erradas:**\n\n- **A** descreve um **workflow** (ou pipeline) fixo e determinístico. É o oposto de um agente, pois não há tomada de decisão autônoma — tudo é pré-programado passo a passo. Útil para problemas bem compreendidos, mas não é um agente.\n\n- **B** descreve um **sistema de roteamento** (routing), onde um classificador decide qual pipeline especializado seguir. Embora haja uma decisão inicial, cada pipeline é fixo. O modelo não decide dinamicamente como combinar ferramentas ao longo do processo; apenas escolhe um caminho predefinido.\n\n- **D** descreve **paralelização** (fan-out/fan-in), onde a mesma tarefa é replicada e os resultados são agregados. Não há autonomia ou planejamento sequencial por parte do modelo; é uma estratégia de processamento paralelo, não um agente.\n\nPortanto, a essência de um agente está na **autonomia para decidir a orquestração de ferramentas em tempo de execução**, e não em sequências fixas, roteamento ou paralelismo.','\n',char(10)),replace('Imagine que você tem um robô ajudante.\n\n**Alternativa A** é como dar ao robô um manual bem detalhado: "Passo 1: pegue o copo. Passo 2: abra a torneira. Passo 3: encha o copo." Ele faz tudo igualzinho toda vez. Isso não é um agente esperto, é só um robô seguindo receita.\n\n**Alternativa B** é como ter um robô que pergunta: "Você quer água ou suco?" Se você disser "água", ele segue o manual da água; se disser "suco", segue o manual do suco. Ele só escolhe um caminho, mas depois faz tudo igual.\n\n**Alternativa D** é como pedir para 5 robôs fazerem a mesma tarefa ao mesmo tempo e depois juntar o que cada um fez. Não tem decisão esperta, é só repetir.\n\n**Alternativa C** é a verdadeira definição de um agente! É como dar ao robô um objetivo: "Quero um copo de limonada" e dar a ele algumas ferramentas: um copo, limões, água, açúcar e uma colher. O robô **pensa sozinho** e decide: "Primeiro vou cortar o limão, depois espremer, misturar com água e açúcar, e mexer." Ele descobre o jeito de fazer sem ninguém ensinar o passo a passo. Isso é um agente de verdade!','\n',char(10)));
INSERT INTO cards VALUES('admin','card_1783092985346_fi252yr7f',156,'Which statement correctly describes the tradeoff between agents and workflows?',replace('Which statement correctly describes the tradeoff between agents and workflows?\n\nWhich statement correctly describes the tradeoff between agents and workflows?\n[Resposta correta: Agents ganham em flexibilidade e perdem em previsibilidade e testabilidade. A e B invertem os atributos de cada padrão. D nega a existência do tradeoff.]\n\n[ ] A - Agents are more predictable and easier to test than workflows.\n[ ] B - Workflows are more flexible, but less precise than agents.\n[ ] C - Agents are more flexible, but less predictable and harder to test than workflows.\n[ ] D - Workflows and agents have exactly the same flexibility and predictability.','\n',char(10)),'[ ] C - Agents are more flexible, but less predictable and harder to test than workflows.','["ForaDosDominios", "ForaDoCenario"]','New',0,2.5,0,1783092985346,1783725824356,1783203558653,replace('**Tradução para português do Brasil:**\n\nQual afirmação descreve corretamente o tradeoff entre agentes e workflows?\n\n[ ] A - Agentes são mais previsíveis e mais fáceis de testar do que workflows.\n[ ] B - Workflows são mais flexíveis, porém menos precisos do que agentes.\n[ ] C - Agentes são mais flexíveis, porém menos previsíveis e mais difíceis de testar do que workflows.\n[ ] D - Workflows e agentes têm exatamente a mesma flexibilidade e previsibilidade.','\n',char(10)),replace('**Explicação para um adulto tech lead:**\n\nA alternativa **C** é a correta e descreve com precisão o tradeoff fundamental entre agentes e workflows no design de sistemas baseados em LLM.\n\n**Por que C está correta:**\n\nO tradeoff central entre agentes (modelos que tomam decisões autônomas, escolhendo ferramentas, caminhos e ações em tempo de execução) e workflows (pipelines pré-definidos, com sequências de passos fixas e determinísticas) é clássico em arquitetura de software: **flexibilidade vs. controle**.\n\n- **Agentes** (autônomos, orientados a decisão do modelo) são **mais flexíveis** porque podem se adaptar a contextos imprevistos, escolher dinamicamente qual ferramenta usar e até modificar seu plano conforme o resultado de ações anteriores. Essa flexibilidade, no entanto, vem com o custo de **menor previsibilidade** (o caminho exato percorrido varia a cada execução) e **maior dificuldade de teste** (não é possível enumerar todos os estados possíveis, exigindo estratégias de validação estatística, simulação e monitoramento contínuo).\n\n- **Workflows** (DAGs fixos, orquestração explícita) são **menos flexíveis**, pois o fluxo é rigidamente definido em código. Em contrapartida, são **mais previsíveis** (sempre executam a mesma sequência de passos), e **mais fáceis de testar** (testes unitários e de integração podem cobrir todos os ramos de decisão com inputs controlados).\n\n**Por que as demais estão erradas:**\n\n- **A** — Inverte o tradeoff. Workflows (não agentes) é que são mais previsíveis e fáceis de testar. Agentes trazem imprevisibilidade justamente por delegarem decisões ao modelo.\n\n- **B** — Também inverte os atributos. Workflows são *menos* flexíveis (não mais flexíveis) e *mais* precisos/previsíveis (não menos). Além disso, "precisão" é um termo ambíguo aqui — o correto é falar em previsibilidade/determinismo.\n\n- **D** — Nega a existência do tradeoff. A escolha entre agente e workflow envolve compensações reais de design; eles não são equivalentes em flexibilidade ou previsibilidade. Afirmar que são iguais ignora o princípio fundamental que rege essa decisão arquitetural.','\n',char(10)),replace('**Explicação para uma criança de 10 anos:**\n\nImagine que você tem duas maneiras de organizar seu dia:\n\n1. **Workflow** é como uma lista de tarefas fixa, passo a passo: "Acordar, escovar os dentes, tomar café, ir para a escola". Você sabe exatamente o que vai fazer e nessa ordem. É fácil de prever e de saber se deu certo.\n\n2. **Agente** é como se você tivesse um robô assistente que decide o que fazer na hora, dependendo do que acontece. Se ele vê que está chovendo, pega um guarda-chuva. Se você está atrasado, ele pula uma tarefa. Ele é mais flexível, mas você nunca sabe exatamente o que ele vai fazer — ele pode decidir algo diferente a cada dia. É mais difícil de testar porque pode fazer caminhos diferentes sempre.\n\nA resposta certa é a **C**: agentes são mais flexíveis (conseguem se adaptar), mas são menos previsíveis (não sabemos sempre o que vão fazer) e mais difíceis de testar (porque podem agir de muitas formas diferentes).\n\nAs outras opções estão erradas porque trocam as características ou dizem que não há diferença, mas a diferença existe e é importante!','\n',char(10)));
INSERT INTO cards VALUES('admin','card_1783092985358_ntqux4mmc',157,'Why is a workflow easier to instrument and evaluate than an agent?',replace('Why is a workflow easier to instrument and evaluate than an agent?\n\nWhy is a workflow easier to instrument and evaluate than an agent?\n[Resposta correta: A testabilidade vem de conhecer cada passo da execução. A troca o critério real por consumo de tokens. C exagera, pois agents podem ser testados, apenas com mais dificuldade. D é falso, workflows são séries de chamadas a Claude.]\n\n[ ] A - Because workflows use fewer tokens per step.\n[ ] B - Because you know each exact step of the execution, whereas in the agent the series of steps is unpredictable.\n[ ] C - Because agents cannot be tested in any way.\n[ ] D - Because workflows do not make calls to Claude.','\n',char(10)),'B - Because you know each exact step of the execution, whereas in the agent the series of steps is unpredictable.','["ForaDosDominios", "ForaDoCenario"]','New',0,2.5,0,1783092985358,1783725828548,1783203558653,replace('**Tradução para português do Brasil:**\n\n**Pergunta:** Por que um workflow é mais fácil de instrumentar e avaliar do que um agente?\n\n**Alternativas:**\n\n[ ] A - Porque workflows usam menos tokens por etapa.\n[ ] B - Porque você conhece cada etapa exata da execução, enquanto no agente a série de etapas é imprevisível.\n[ ] C - Porque agentes não podem ser testados de forma alguma.\n[ ] D - Porque workflows não fazem chamadas ao Claude.','\n',char(10)),replace('**Explicação para um adulto tech lead:**\n\nA resposta correta é a **alternativa B**.\n\n**Por que a B está correta:**\n\nWorkflows são sequências predefinidas de passos — cada etapa é conhecida, fixa e determinística. Isso significa que podemos instrumentar cada ponto (logar entradas/saídas, medir latência, monitorar falhas) e avaliar o comportamento de forma isolada. Em um agente, a sequência de ações é dinâmica e emergente: ele decide qual ferramenta chamar, em que ordem e por quanto tempo iterar. Essa imprevisibilidade torna a instrumentação mais complexa (não sabemos de antemão quantos passos ocorrerão nem quais serão) e a avaliação mais desafiadora (precisamos avaliar não só o resultado final, mas a cadeia de decisões).\n\n**Análise das demais alternativas:**\n\n- **A (incorreta):** O número de tokens por etapa não é o fator determinante para facilidade de instrumentação e avaliação. A questão central é a previsibilidade do fluxo, não a eficiência de tokens. Além disso, workflows podem inclusive usar mais tokens se tiverem muitas etapas com prompts longos.\n  \n- **C (incorreta):** Afirmação exagerada e falsa. Agentes podem sim ser testados — existem abordagens como avaliação de ferramentas chamadas, análise de trajetória de decisões, testes de sanity check e avaliação holística do resultado final. A dificuldade é maior, mas não é impossível.\n  \n- **D (incorreta):** Falso por definição. Workflows são, tipicamente, séries de chamadas a modelos de linguagem (como o Claude) ou a ferramentas orquestradas. Um workflow pode envolver múltiplas chamadas ao Claude em sequência.','\n',char(10)),replace('Imagina que você tem duas receitas de bolo bem diferentes.\n\nA primeira receita (workflow) diz exatamente o passo a passo: "1) Pegue 3 ovos. 2) Misture a farinha. 3) Coloque no forno por 30 minutos." Como você sabe cada passo certinho, pode verificar se deu certo em cada etapa — olhar se os ovos estão frescos, se a mistura está homogênea, se o forno está na temperatura certa.\n\nA segunda receita (agente) é mais mágica: ela diz "Faça um bolo gostoso", e o próprio cozinheiro decide o que fazer, que ingredientes usar e em que ordem. Você nunca sabe exatamente qual será o próximo passo — ele pode resolver bater os ovos primeiro ou misturar tudo de uma vez. Fica muito mais difícil de acompanhar e ver se está tudo certo em cada parte do processo.\n\nPor isso, o workflow é mais fácil de "instrumentar" (medir e monitorar) e "avaliar" (ver se está funcionando bem): porque você já sabe tudo o que vai acontecer antes mesmo de começar!','\n',char(10)));
INSERT INTO cards VALUES('admin','card_1783092985370_jpf8vf1sk',158,'As the default for most production applications that require reliability, which approach should you prioritize?',replace('As the default for most production applications that require reliability, which approach should you prioritize?\n\nAs the default for most production applications that require reliability, which approach should you prioritize?\n[Resposta correta: Priorize workflows e reserve agents para requisitos imprevisíveis. A inverte a prioridade. C é falso, pois agents têm menor taxa de conclusão. D é o antipadrão do prompt único.]\n\n[ ] A - Agents, reserving workflows only for simple cases.\n[ ] B - Workflows, reserving agents for cases whose requirements cannot be pre-determined.\n[ ] C - Always agents, because they offer a higher completion rate.\n[ ] D - Always a single giant prompt that covers all requirements.','\n',char(10)),'[ ] B - Workflows, reserving agents for cases whose requirements cannot be pre-determined.','["Domain_1::Agentic_Architecture_Orchestration", "ForaDoCenario"]','New',0,2.5,0,1783092985370,1783725832271,1783203558653,replace('**Tradução para português do Brasil:**\n\nComo padrão para a maioria das aplicações de produção que exigem confiabilidade, qual abordagem você deve priorizar?\n\n[ ] A - Agentes, reservando workflows apenas para casos simples.\n[ ] B - Workflows, reservando agentes para casos cujos requisitos não podem ser pré-determinados.\n[ ] C - Sempre agentes, porque eles oferecem uma taxa de conclusão mais alta.\n[ ] D - Sempre um único prompt gigante que cubra todos os requisitos.','\n',char(10)),replace('**Explicação didática para um adulto tech lead:**\n\nA pergunta aborda uma decisão arquitetural importante no design de sistemas baseados em LLM (Large Language Models) para produção: quando usar **workflows** (sequências pré-definidas de chamadas a LLMs ou ferramentas) versus **agentes** (sistemas autônomos onde o LLM decide dinamicamente os próximos passos, ferramentas e caminhos de execução).\n\n**Resposta correta (B):** A abordagem pragmática e recomendada por frameworks como LangChain, Anthropic e pela literatura de engenharia de LLM é começar com **workflows** como padrão. Workflows são previsíveis, testáveis, debugáveis e têm latência controlada — características essenciais para confiabilidade em produção. Agentes devem ser reservados para cenários onde os requisitos são realmente imprevisíveis (ex.: assistentes de pesquisa abertos, sistemas que interagem com APIs externas não determinísticas, etc.), pois sua autonomia introduz variabilidade, risco de loops infinitos, custos imprevisíveis e dificuldade de depuração.\n\n**Por que as demais alternativas estão erradas:**\n\n- **A (Agentes como padrão, workflows só para casos simples):** Inverte a prioridade recomendada. Agentes como padrão aumentam desnecessariamente a complexidade, o custo e a imprevisibilidade. Workflows são mais adequados para a maioria dos casos, e agentes devem ser a exceção, não a regra.\n\n- **C (Sempre agentes porque têm maior taxa de conclusão):** Incorreto. Agentes podem, de fato, ter *menor* taxa de conclusão em tarefas bem definidas, pois a liberdade de escolha pode levar a caminhos equivocados, decisões subótimas ou loops. Workflows, por serem pré-roteados e validados, tendem a ter maior taxa de sucesso em cenários determinísticos.\n\n- **D (Sempre um único prompt gigante):** Este é um antipadrão clássico ("everything in one prompt"). Prompts muito grandes sofrem de problemas de atenção do modelo (perder detalhes no meio), maior vulnerabilidade a alucinações, dificuldade de manutenção e teste, e baixa modularidade. A abordagem moderna recomenda dividir tarefas complexas em múltiplos prompts/etapas menores (workflows) ou usar agentes com ferramentas específicas, não um bloco monolítico.','\n',char(10)),replace('Imagine que você está organizando uma festa de aniversário. Você pode fazer de dois jeitos:\n\n**Jeito 1 (Workflow):** Você faz uma lista passo a passo: primeiro preparar os salgados, depois arrumar a mesa, depois colocar a música, depois cantar parabéns. Tudo planejado e na ordem certa. Isso funciona bem na maioria das vezes.\n\n**Jeito 2 (Agente):** Você contrata um amigo muito esperto que decide sozinho o que fazer a cada momento. Ele pode ver que está quente e ligar o ventilador, depois perceber que acabou o refrigerante e ir comprar, depois decidir começar a cantar parabéns mais cedo. Ele pode até inventar coisas legais, mas também pode se atrapalhar ou esquecer algo importante.\n\nA pergunta quer saber: qual jeito é melhor para a maioria das festas que precisam dar certo?\n\nA resposta certa é a **letra B** — usar o **jeito planejado (workflow)** na maioria das vezes, e só deixar o amigo esperto (agente) para situações em que você não sabe o que vai acontecer (tipo "surpresa na festa"). Por quê?\n\n- **A** está errada porque diz para sempre usar o amigo esperto, que pode se atrapalhar.\n- **C** está errada porque diz que o amigo esperto sempre termina tudo certinho, mas não é verdade — ele pode se perder no caminho.\n- **D** está errada porque sugere escrever um bilhete gigante com tudo o que precisa ser feito de uma vez, o que é confuso e difícil de acertar.\n\nEntão: para a maioria das coisas, siga um plano (workflow). Deixe o agente esperto só para imprevistos!','\n',char(10)));
INSERT INTO cards VALUES('admin','card_1783092985383_flnb9cy9k',159,'An app receives the image of a part and runs well-defined steps (describe, model with CadQuery, render, evaluate and correct) until it generates the STEP file.',replace('An app receives the image of a part and runs well-defined steps (describe, model with CadQuery, render, evaluate and correct) until it generates the STEP file.\n\nAn app receives the image of a part and runs well-defined steps (describe, model with CadQuery, render, evaluate and correct) until it generates the STEP file. Which pattern?\n[Resposta correta: O fluxo é conhecido e fixo, logo é workflow. A pegadinha de A é assumir que múltiplos passos implicam agent. B e D não se aplicam, pois os passos são sequenciais e dependentes, não independentes nem uma classificação de entrada.]\n\n[ ] A - Agent, because there are several steps involved.\n[ ] B - Routing, because the input is an image.\n[ ] C - Workflow, because the flow is known and can be written in code as a fixed sequence.\n[ ] D - Parallelization, because each step is independent.','\n',char(10)),'[ ] C - Workflow, because the flow is known and can be written in code as a fixed sequence.','["Domain_1::Agentic_Architecture_Orchestration", "Scenario_4::Developer_Productivity"]','New',0,2.5,0,1783092985383,1783725836795,1783203558653,replace('**Tradução para português do Brasil:**\n\nUm aplicativo recebe a imagem de uma peça e executa etapas bem definidas (descrever, modelar com CadQuery, renderizar, avaliar e corrigir) até gerar o arquivo STEP.\n\nUm aplicativo recebe a imagem de uma peça e executa etapas bem definidas (descrever, modelar com CadQuery, renderizar, avaliar e corrigir) até gerar o arquivo STEP. Qual padrão?\n\n[ ] A - Agent, porque há várias etapas envolvidas.\n[ ] B - Routing, porque a entrada é uma imagem.\n[ ] C - Workflow, porque o fluxo é conhecido e pode ser escrito em código como uma sequência fixa.\n[ ] D - Paralelização, porque cada etapa é independente.','\n',char(10)),replace('**Explicação para adulto (tech lead):**\n\nA alternativa correta é **C - Workflow**.\n\nO cenário descreve uma sequência de etapas **bem definidas e invariáveis**: descrever → modelar com CadQuery → renderizar → avaliar → corrigir → gerar STEP. Isso é a essência de um **workflow**: um pipeline determinístico onde a ordem de execução é fixa e previsível. Não há tomada de decisão autônoma por parte do sistema sobre qual passo executar em seguida — o fluxo já está codificado.\n\n**Por que as demais estão incorretas:**\n\n- **A (Agent)**: Um "agente" (no contexto de sistemas multiagente ou LLM agents) implica autonomia, tomada de decisão dinâmica e uso de ferramentas para decidir qual ação tomar. O problema diz explicitamente que as etapas são "bem definidas" e executadas em sequência fixa — não há espaço para escolha ou raciocínio autônomo. A pegadinha está em achar que múltiplos passos = agente, mas não é o caso.\n\n- **B (Routing)**: Routing normalmente se refere a direcionar uma requisição para diferentes handlers ou serviços com base em alguma característica da entrada (ex.: roteamento HTTP, mensageria). Aqui, a entrada é uma imagem, mas não há roteamento condicional — todas as imagens passam pelo mesmo pipeline fixo.\n\n- **D (Paralelização)**: A paralelização exige que as etapas sejam **independentes** entre si, podendo ser executadas concorrentemente. No cenário descrito, cada etapa depende do resultado da anterior (modelar depende da descrição, renderizar depende do modelo, etc.). São etapas **sequenciais e dependentes**, portanto paralelização não se aplica.','\n',char(10)),replace('**Explicação para criança de 10 anos:**\n\nImagina que você tem que fazer um bolo seguindo uma receita. Primeiro você pega os ingredientes, depois mistura, depois coloca no forno, depois espera esfriar e por último coloca a cobertura. Você não pode pular etapas nem trocar a ordem — sempre faz igual.\n\nEsse aplicativo funciona do mesmo jeito: ele recebe a foto de uma peça e sempre faz as mesmas coisas na mesma ordem: descrever, modelar, renderizar, avaliar e corrigir, até gerar o arquivo final. Isso se chama **workflow**, que é como uma receita de bolo para programas de computador.\n\n- Não é um **agente** (que seria um robô que decide sozinho o que fazer).\n- Não é **roteamento** (que seria tipo escolher entre vários caminhos diferentes).\n- Não é **paralelização** (que seria fazer várias coisas ao mesmo tempo).\n','\n',char(10)));
INSERT INTO cards VALUES('admin','card_1783092985395_ish3aqq9j',160,'Which structure describes the Evaluator-Optimizer pattern?',replace('Which structure describes the Evaluator-Optimizer pattern?\n\nWhich structure describes the Evaluator-Optimizer pattern?\n[Resposta correta: O padrão combina Producer, Grader e feedback loop. A descreve routing, C descreve paralelização e D descreve um chaining simples sem etapa avaliadora.]\n\n[ ] A - A router that classifies the input and picks a pipeline.\n[ ] B - A Producer that generates the output, a Grader that evaluates against criteria and a feedback loop that returns feedback to the Producer.\n[ ] C - Several parallel requests aggregated by a final step.\n[ ] D - A fixed sequence of steps without any evaluation.','\n',char(10)),'B - A Producer that generates the output, a Grader that evaluates against criteria and a feedback loop that returns feedback to the Producer.','["Domain_1::Agentic_Architecture_Orchestration", "Domain_4::Prompt_Engineering_Structured_Output", "ForaDoCenario"]','New',0,2.5,0,1783092985395,1783725841012,1783203558653,replace('**Tradução para português do Brasil:**\n\nQual estrutura descreve o padrão Avaliador-Otimizador (Evaluator-Optimizer)?\n\n[ ] A - Um roteador que classifica a entrada e escolhe um pipeline.\n[ ] B - Um Produtor que gera a saída, um Avaliador que avalia contra critérios e um loop de feedback que retorna o feedback ao Produtor.\n[ ] C - Várias requisições paralelas agregadas por uma etapa final.\n[ ] D - Uma sequência fixa de etapas sem nenhuma avaliação.','\n',char(10)),replace('**Explicação didática para um adulto tech lead:**\n\nO padrão **Evaluator-Optimizer** (Avaliador-Otimizador) é um padrão arquitetural onde um componente (Producer/Optimizer) gera uma saída, e outro componente (Evaluator/Grader) avalia essa saída com base em critérios predefinidos. O resultado da avaliação é realimentado para o Producer em um loop de feedback, permitindo iterações até que a saída atinja a qualidade desejada.\n\n**Alternativa correta: B**\n- ✅ Descreve exatamente os três elementos essenciais do padrão: Producer (gerador), Grader (avaliador) e feedback loop (ciclo de realimentação). O Producer gera uma resposta, o Grader a avalia contra critérios objetivos, e o feedback é retornado ao Producer para refinamento. Esse ciclo se repete até que o Grader aprove a saída ou um limite de iterações seja atingido.\n\n**Análise das alternativas incorretas:**\n\n- **A (Router que classifica e escolhe um pipeline):** ❌ Descreve o padrão **Router** (ou Classifier). O foco aqui é direcionar a entrada para o fluxo mais adequado, sem necessariamente haver avaliação e refinamento iterativo da saída. É um padrão de decisão única, não de otimização cíclica.\n\n- **C (Várias requisições paralelas agregadas):** ❌ Descreve o padrão **Parallelization** (Fan-out/Fan-in). O objetivo é executar tarefas independentes simultaneamente e depois combinar os resultados. Não há um ciclo de avaliação e refinamento (feedback loop) entre um produtor e um avaliador.\n\n- **D (Sequência fixa sem avaliação):** ❌ Descreve o padrão **Chain** (ou Pipeline). As etapas são executadas em ordem pré-definida, sem qualquer mecanismo de avaliação ou realimentação. A saída de cada etapa é passada adiante sem verificação de qualidade ou iteração.','\n',char(10)),replace('Imagine que você está desenhando um robô. Você desenha, olha para o desenho e pensa: "a perna ficou torta". Então você apaga e desenha de novo, mais certinho. Depois olha de novo e pensa: "agora falta o braço". Você desenha o braço, olha de novo... e continua nesse ciclo até o robô ficar perfeito.\n\nO padrão Avaliador-Otimizador é exatamente isso:\n- **Produtor** = você desenhando (quem faz)\n- **Avaliador** = você olhando e vendo o que está errado (quem avalia)\n- **Loop de feedback** = você corrigindo com base no que viu (voltar e melhorar)\n\nA alternativa B descreve isso certinho. As outras são diferentes:\n- **A** é como um semáforo que decide qual caminho seguir (rota).\n- **C** é como várias pessoas desenhando ao mesmo tempo e depois juntando tudo.\n- **D** é fazer uma receita de bolo passo a passo sem nunca parar para ver se está gostoso.','\n',char(10)));
INSERT INTO cards VALUES('admin','card_1783092985422_x2yg7ywe9',161,'When classifying a part among many materials, each one with detailed criteria, why avoid a single giant prompt?',replace('When classifying a part among many materials, each one with detailed criteria, why avoid a single giant prompt?\n\nWhen classifying a part among many materials, each one with detailed criteria, why avoid a single giant prompt?\n[Resposta correta: O problema é a carga cognitiva de equilibrar critérios simultâneos, resolvida com requisições paralelas especializadas. A e C inventam limites técnicos que não são o motivo. D é falso, o prompt único pode receber a entrada, ele apenas produz resultados piores.]\n\n[ ] A - Because a single prompt always exceeds the token limit.\n[ ] B - Because Claude would have to balance many criteria at the same time, creating confusion and suboptimal results.\n[ ] C - Because long prompts are forbidden by the API.\n[ ] D - Because a single prompt cannot receive the description of the part.','\n',char(10)),'[ ] B - Because Claude would have to balance many criteria at the same time, creating confusion and suboptimal results.','["Domain_4::Prompt_Engineering_Structured_Output", "Domain_5::Context_Management_Reliability", "Scenario_6::Structured_Data_Extraction"]','New',0,2.5,0,1783092985422,1783725844545,1783203558653,replace('**Tradução para Português do Brasil:**\n\n**Pergunta:** Ao classificar uma peça entre muitos materiais, cada um com critérios detalhados, por que evitar um único prompt gigante?\n\n**[ ] A - Porque um único prompt sempre excede o limite de tokens.**\n**[ ] B - Porque o Claude teria que equilibrar muitos critérios ao mesmo tempo, gerando confusão e resultados subótimos.**\n**[ ] C - Porque prompts longos são proibidos pela API.**\n**[ ] D - Porque um único prompt não pode receber a descrição da peça.**','\n',char(10)),replace('**Explicação para um adulto (tech lead):**\n\nO problema central de usar um único prompt gigante para classificar uma peça entre dezenas de materiais, cada um com critérios detalhados, é a **carga cognitiva** imposta ao modelo. Modelos de linguagem como o Claude têm um "espaço de atenção" limitado — mesmo que o contexto total (janela de tokens) seja grande, forçar o modelo a comparar simultaneamente dezenas de conjuntos de critérios complexos leva à degradação do desempenho. O modelo precisa "equilibrar" mentalmente todas essas regras ao mesmo tempo, o que aumenta a chance de ele ignorar detalhes importantes, fazer comparações inconsistentes ou simplesmente "se perder" no meio de tantas instruções.\n\nA abordagem correta, indicada na resposta, é usar **requisições paralelas especializadas**: em vez de um prompt único, disparar múltiplos prompts menores e mais focados, cada um avaliando a peça contra um material específico (ou um subconjunto pequeno de materiais). Depois, um passo de consolidação (outro prompt ou lógica externa) compara os resultados e escolhe a melhor classificação. Isso reduz a carga cognitiva por requisição e melhora a precisão.\n\n**Análise das alternativas:**\n\n- **A (incorreta):** É falso que um único prompt "sempre" excede o limite de tokens. A janela de contexto do Claude é grande (200K tokens). Você poderia, tecnicamente, colocar ali todos os critérios de todos os materiais. O problema não é o limite teórico, é a qualidade da resposta.\n- **B (correta):** Este é o motivo real. O esforço cognitivo de equilibrar muitos critérios simultaneamente leva a resultados piores. A solução é quebrar em tarefas menores e paralelas.\n- **C (incorreta):** Não há proibição de prompts longos na API. Claro, existem limites de tokens (se você ultrapassar, a API rejeita), mas isso não é uma "proibição" de prompts longos em geral, e sim um limite técnico que pode ser respeitado. Além disso, mesmo dentro do limite, o prompt único ainda tem o problema da carga cognitiva.\n- **D (incorreta):** Um prompt único pode sim receber a descrição da peça — você simplesmente coloca a descrição no prompt junto com os critérios. Não há impedimento técnico para isso. O problema é que, mesmo com a descrição presente, o resultado é pior.','\n',char(10)),replace('Imagine que você tem que escolher a melhor fruta para fazer um suco, mas tem 30 tipos diferentes de fruta, e cada uma tem regras especiais: "esta só serve se estiver madura", "esta precisa estar gelada", "esta não pode estar muito doce". Se você tentar ler todas as regras de uma vez e lembrar de tudo ao mesmo tempo, sua cabeça vai ficar confusa e você pode escolher a fruta errada!\n\nÉ melhor você pegar uma fruta de cada vez e ver se ela serve. Primeiro a maçã: ela está madura? Sim. Próxima: a laranja está gelada? Não. E assim vai. Depois você compara só os resultados.\n\nÉ a mesma coisa com o Claude (um robô inteligente). Se a gente der um texto gigante com todas as regras de todos os materiais de uma vez, ele fica confuso e pode errar. O melhor é dividir em partes menores: perguntar para ele sobre um material de cada vez, em paralelo (ao mesmo tempo), e depois juntar as respostas para ver qual material é o melhor. Assim ele não se confunde e acerta mais!\n\n**Resposta errada A:** Não é verdade que um texto gigante sempre estoura o limite. Dá para escrever bastante, mas o problema é que ele se atrapalha com tanta informação.\n\n**Resposta errada C:** Mentira! A API não proíbe textos longos. O problema é que textos muito longos deixam o robô confuso, não que sejam proibidos.\n\n**Resposta errada D:** Claro que o robô consegue ler a descrição da peça! Você pode colocar ela no texto. O problema não é ler, é entender tudo ao mesmo tempo.','\n',char(10)));
INSERT INTO cards VALUES('admin','card_1783092985436_d9hcxz0jz',162,'How does a parallelization workflow operate?',replace('How does a parallelization workflow operate?\n\nHow does a parallelization workflow operate?\n[Resposta correta: A paralelização envia a mesma entrada a várias requisições especializadas e agrega no fim. A descreve chaining, B descreve routing e D é o prompt único que a paralelização busca evitar.]\n\n[ ] A - The input passes through a sequence of dependent steps, one feeding the next.\n[ ] B - A router picks a single pipeline for the input.\n[ ] C - The same input goes simultaneously to several specialized requests, whose results are aggregated by a final step.\n[ ] D - A single request evaluates all aspects at once.','\n',char(10)),'C - The same input goes simultaneously to several specialized requests, whose results are aggregated by a final step.','["Domain_1::Agentic_Architecture_Orchestration", "ForaDoCenario"]','New',0,2.5,0,1783092985436,1783725848633,1783203558653,replace('**Tradução para português do Brasil:**\n\nComo um workflow de paralelização opera?\n\n[ ] A - A entrada passa por uma sequência de etapas dependentes, uma alimentando a próxima.\n[ ] B - Um roteador seleciona um único pipeline para a entrada.\n[ ] C - A mesma entrada é enviada simultaneamente a várias requisições especializadas, cujos resultados são agregados por uma etapa final.\n[ ] D - Uma única requisição avalia todos os aspectos de uma vez.','\n',char(10)),replace('**Explicação didática para um adulto tech lead:**\n\nA pergunta trata de arquitetura de workflows de IA, especificamente sobre o padrão de paralelização (parallelization). Esse padrão é utilizado quando se deseja processar a mesma entrada sob múltiplas perspectivas ou especializações simultaneamente, reduzindo a latência total (já que as execuções ocorrem em paralelo) e permitindo que cada "worker" ou requisição foque em uma tarefa específica e mais simples, em vez de uma única requisição monolítica tentar resolver tudo de uma vez.\n\nA alternativa **C** descreve exatamente o mecanismo de paralelização: a mesma entrada é distribuída (fan-out) para várias requisições especializadas, que rodam em paralelo, e os resultados parciais são combinados/agregados (fan-in) por uma etapa final para produzir a saída consolidada.\n\nAs demais alternativas descrevem outros padrões de workflow:\n\n- **Alternativa A** descreve **chaining** (encadeamento sequencial), onde cada etapa depende da saída da anterior — não há paralelismo.\n- **Alternativa B** descreve **routing** (roteamento condicional), onde um nó decisor escolhe um único caminho para a entrada seguir, não havendo execução paralela.\n- **Alternativa D** descreve uma **requisição única monolítica** (single-shot), que tenta resolver tudo em uma chamada — exatamente o que a paralelização busca evitar, pois pode gerar respostas menos precisas, maior custo por token e dificuldade de manutenção.\n\nPortanto, **C é a alternativa correta**.','\n',char(10)),replace('**Explicação para uma criança de 10 anos:**\n\nImagine que você tem uma tarefa: descobrir tudo sobre um animal, como um cachorro. Em vez de uma pessoa fazer tudo sozinha (perguntar a raça, a cor, o tamanho, o que ele come, etc.), você chama vários amigos ao mesmo tempo: um vai medir o cachorro, outro vai ver o que ele come, outro vai descobrir a raça. Todos trabalham ao mesmo tempo. No final, você junta as respostas de todos e tem a informação completa sobre o cachorro. Isso é a paralelização!\n\nAgora, as outras opções:\n- A: seria como uma fila: primeiro você descobre a raça, depois o tamanho, depois a comida... um atrás do outro (chaining).\n- B: é como um porteiro que decide: "esse animal vai para o setor de cães" e só uma pessoa cuida dele (routing).\n- D: é uma pessoa tentando responder tudo sozinha, o que é mais difícil e demorado.\n\nA resposta certa é a **C**, porque ela descreve todo mundo trabalhando ao mesmo tempo e juntando os resultados no final.\n','\n',char(10)));
INSERT INTO cards VALUES('admin','card_1783092985449_sve9vvmm3',163,'What is a direct benefit of parallelization?',replace('What is a direct benefit of parallelization?\n\nWhat is a direct benefit of parallelization?\n[Resposta correta: A paralelização dá atenção focada e otimização independente por prompt. C é falso, pois o passo de agregação é parte do padrão. A e D descrevem características que não são benefícios da paralelização (a economia de 50% é da Message Batches API).]\n\n[ ] A - A guarantee of lower latency than any synchronous call.\n[ ] B - Focused attention on one aspect at a time, with independent optimization of each prompt.\n[ ] C - Elimination of the need for an aggregation step.\n[ ] D - Automatic 50% cost reduction.','\n',char(10)),'B - Focused attention on one aspect at a time, with independent optimization of each prompt.','["Domain_1::Agentic_Architecture_Orchestration", "Scenario_3::Multi_Agent_Research"]','New',0,2.5,0,1783092985449,1783725852195,1783203558653,replace('**Tradução para português do Brasil:**\n\nPergunta: Qual é um benefício direto da paralelização?\n\n[ ] A - Uma garantia de latência menor do que qualquer chamada síncrona.\n[ ] B - Atenção focada em um aspecto por vez, com otimização independente de cada prompt.\n[ ] C - Eliminação da necessidade de uma etapa de agregação.\n[ ] D - Redução automática de 50% nos custos.','\n',char(10)),replace('**Explicação didática para um adulto tech lead:**\n\nO paralelismo em sistemas de IA/LLM consiste em executar múltiplos prompts simultaneamente, cada um especializado em uma tarefa ou aspecto diferente. O benefício direto mais relevante é descrito na alternativa **B**.\n\n**Por que B está correta:**\nA paralelização permite que cada prompt seja projetado de forma independente e otimizado para uma única responsabilidade. Isso contrasta com um prompt único e monolítico que tenta resolver tudo de uma vez. Os ganhos são:\n- **Foco**: cada sub-prompt atua em uma parte específica do problema, sem distração ou ruído de outras demandas.\n- **Otimização independente**: você pode ajustar o prompt, o modelo, a temperatura, o número de tokens, etc., para cada sub-tarefa sem afetar as demais.\n- **Especialização**: prompts menores e mais específicos geralmente produzem resultados de maior qualidade do que prompts gigantes e genéricos.\n\n**Análise das alternativas incorretas:**\n\n- **A (garantia de latência menor)**: FALSO. Paralelização não garante latência menor que uma chamada síncrona. Na verdade, o tempo total do processo (incluindo etapa de agregação) pode ser maior que uma única chamada síncrona. O benefício não é sobre latência mínima, mas sobre throughput e especialização.\n\n- **C (eliminação da etapa de agregação)**: FALSO. O padrão de paralelização tipicamente requer um passo de agregação para combinar os resultados parciais das execuções paralelas em uma saída coerente. A agregação não é eliminada — ela é uma parte fundamental do design.\n\n- **D (redução automática de 50% nos custos)**: FALSO. Não há garantia de redução de custos, muito menos um valor fixo de 50%. A redução de 50% é uma característica específica da Message Batches API da OpenAI (com desconto por batch assíncrono), e não um benefício inerente da paralelização. Paralelizar pode, inclusive, aumentar custos se não for bem dimensionado.','\n',char(10)),replace('**Explicação para uma criança de 10 anos:**\n\nA pergunta é: "Qual é um benefício direto da paralelização?"\n\nImagine que você tem que resolver 5 problemas de matemática diferentes. Você pode tentar resolver todos ao mesmo tempo com uma única caneta e uma única folha de papel — isso seria como um prompt único. Mas fica bagunçado e difícil, né?\n\nAgora, imagine que você chama 5 amigos, cada um com sua própria caneta e folha de papel, e cada um fica responsável por resolver UM problema. Cada amigo pode se concentrar só no problema dele, sem se distrair. E cada um pode usar o método que achar melhor para aquele problema específico. Isso é a paralelização!\n\n**A resposta certa é a B**: "Atenção focada em um aspecto por vez, com otimização independente de cada prompt."\n\nOu seja, cada "prompt" (cada instrução que damos para o computador) cuida de uma parte só do problema, e a gente pode deixar cada instrução do jeitinho que funciona melhor para aquela parte.\n\n**Por que as outras estão erradas?**\n\n- **A** diz que a paralelização garante que tudo fica mais rápido que uma chamada normal. Mentira! Nem sempre é mais rápido. Às vezes, o tempo total pode ser até maior.\n\n- **C** diz que não precisa mais juntar os resultados no final. Também mentira! Depois que cada amigo resolveu seu problema, alguém tem que juntar tudo numa resposta final. A etapa de juntar (agregação) ainda existe.\n\n- **D** diz que o custo cai automaticamente 50%. Isso é furada! Não tem mágica. Economizar 50% é coisa de um serviço específico (Message Batches API), não é um benefício automático de fazer as coisas em paralelo.\n\nEntão, a resposta certa é **B**!','\n',char(10)));
INSERT INTO cards VALUES('admin','card_1783092985462_eswv634e6',164,'Which condition does a task need to satisfy to be a candidate for parallelization?',replace('Which condition does a task need to satisfy to be a candidate for parallelization?\n\nWhich condition does a task need to satisfy to be a candidate for parallelization?\n[Resposta correta: A paralelização exige subtarefas independentes que contribuem com partes distintas. A descreve o oposto (chaining sequencial e dependente). C contraria a lógica de múltiplos aspectos. D descreve o passo de categorização do routing.]\n\n[ ] A - The sub-tasks must be sequential, each one depending on the previous.\n[ ] B - The sub-tasks must operate independently and each contribute a distinct part of the analysis.\n[ ] C - The task must have only one evaluation criterion.\n[ ] D - The input must first be classified into a single category.','\n',char(10)),'[ ] B - The sub-tasks must operate independently and each contribute a distinct part of the analysis.','["Domain_1::Agentic_Architecture_Orchestration", "Scenario_3::Multi_Agent_Research"]','New',0,2.5,0,1783092985462,1783725855428,1783203558653,replace('**Tradução para português do Brasil:**\n\n**Pergunta:**\nQual condição uma tarefa precisa satisfazer para ser candidata à paralelização?\n\n[ ] A - As subtarefas devem ser sequenciais, cada uma dependendo da anterior.\n[ ] B - As subtarefas devem operar de forma independente e cada uma contribuir com uma parte distinta da análise.\n[ ] C - A tarefa deve ter apenas um critério de avaliação.\n[ ] D - A entrada deve primeiro ser classificada em uma única categoria.','\n',char(10)),replace('**Explicação para adulto (tech lead):**\n\nA alternativa **B** é a correta. Paralelização, em computação, significa dividir um problema maior em subproblemas menores que podem ser executados simultaneamente, em múltiplos núcleos, threads ou máquinas. Para que isso seja possível, as subtarefas precisam ser **independentes entre si** (não compartilhar estado mutável nem ter dependências de dados umas das outras) e, idealmente, cada uma contribuir com uma parte distinta do resultado final — o que é conhecido como "embarrassingly parallel" ou paralelização trivial.\n\n**Análise das incorretas:**\n\n- **A** descreve o oposto: uma cadeia sequencial onde cada subtarefa depende da anterior. Isso é paralelizável apenas em cenários muito específicos (como pipeline paralelo), mas não é a condição geral. Além disso, a descrição aponta para um anti-padrão de paralelismo: dependência sequencial impede execução simultânea.\n\n- **C** afirma que a tarefa precisa ter um único critério de avaliação. Isso não é verdade — você pode paralelizar tarefas com múltiplos critérios (ex.: processamento de imagem que avalia cor, borda e textura). O número de critérios é irrelevante para a paralelização; o que importa é a independência das subtarefas.\n\n- **D** descreve uma etapa de classificação ou roteamento único. Isso é um pré-processamento, não uma condição de paralelização. Na verdade, uma vez classificada a entrada, você pode querer paralelizar o processamento de cada categoria — então a classificação prévia não é uma condição necessária para paralelismo, mas sim um passo que pode precedê-lo.','\n',char(10)),replace('Imagine que você tem um monte de lição de casa. Se você pedir ajuda para seus amigos, cada um pode fazer uma parte diferente ao mesmo tempo? Isso só funciona se cada amigo puder fazer a sua parte sem precisar esperar o outro terminar.\n\nA alternativa **B** diz exatamente isso: as subtarefas precisam funcionar sozinhas, cada uma fazendo um pedaço diferente do trabalho, sem depender da outra. É como cada amigo pintar uma parte diferente de um desenho — tudo ao mesmo tempo.\n\nA alternativa **A** está errada porque diz que uma tarefa depende da outra (uma começa só depois que a outra termina). Isso é o contrário de fazer ao mesmo tempo.\n\nA **C** está errada porque o número de critérios não muda se dá para fazer as coisas em paralelo ou não. Você pode ter várias regras e ainda assim dividir o trabalho.\n\nA **D** está errada porque classificar a tarefa em uma única categoria não é o que permite fazer as coisas ao mesmo tempo. É só um passo antes.','\n',char(10)));
INSERT INTO cards VALUES('admin','card_1783092985474_sffpezvhx',165,'What characterizes a chaining workflow?',replace('What characterizes a chaining workflow?\n\nWhat characterizes a chaining workflow?\n[Resposta correta: Chaining quebra a tarefa em passos sequenciais e dependentes. A descreve paralelização, B descreve routing e D é o prompt único.]\n\n[ ] A - Independent sub-tasks executed at the same time and aggregated at the end.\n[ ] B - Classification of the input followed by the choice of a pipeline.\n[ ] C - Sequential and non-parallelizable sub-tasks, each step building on the previous one.\n[ ] D - A single prompt that solves the whole task at once.','\n',char(10)),'C - Sequential and non-parallelizable sub-tasks, each step building on the previous one.','["Domain_1::Agentic_Architecture_Orchestration", "ForaDoCenario"]','New',0,2.5,0,1783092985474,1783725859361,1783203558653,replace('**Tradução para português do Brasil:**\n\nO que caracteriza um workflow de chaining (encadeamento)?\n\n[ ] A - Subtarefas independentes executadas ao mesmo tempo e agregadas ao final.\n[ ] B - Classificação da entrada seguida pela escolha de um pipeline.\n[ ] C - Subtarefas sequenciais e não paralelizáveis, onde cada etapa se baseia na anterior.\n[ ] D - Um único prompt que resolve toda a tarefa de uma só vez.','\n',char(10)),replace('**Explicação para um adulto (tech lead):**\n\nUm workflow de chaining (ou encadeamento) é um padrão arquitetural de LLMs onde uma tarefa complexa é decomposta em uma sequência de etapas discretas, cada uma dependente da conclusão da anterior. A saída de um passo serve como entrada para o passo seguinte, formando uma cadeia lógica.\n\n**Por que a alternativa C está correta:**\nC descreve exatamente o conceito de chaining: subtarefas sequenciais (não paralelizáveis) onde cada etapa constrói sobre a anterior. Esse design é usado quando uma tarefa exige raciocínio encadeado, validação incremental ou transformações sucessivas de dados, como em pipelines de extração, transformação e sumarização, ou em agentes que primeiro coletam contexto, depois raciocinam e por fim geram uma resposta.\n\n**Por que as demais alternativas estão erradas:**\n\n- **Alternativa A** descreve **paralelização** (fan-out/fan-in), onde subtarefas independentes rodam simultaneamente e seus resultados são agregados no final. Isso é o oposto do chaining, que é estritamente sequencial e dependente.\n\n- **Alternativa B** descreve **routing** (roteamento). Nesse padrão, a entrada é classificada e direcionada para um pipeline específico. É um padrão de decisão (switch/if-else), não de encadeamento sequencial.\n\n- **Alternativa D** descreve um **único prompt monolithic** (tudo-em-um), que tenta resolver a tarefa inteira com uma única chamada ao modelo. Chaining, ao contrário, quebra intencionalmente a tarefa em múltiplos prompts encadeados para melhor controle, depuração e qualidade.\n\n**Resumo técnico:** Chaining = dependência sequencial; A = paralelismo; B = roteamento condicional; D = monólito prompt.','\n',char(10)),replace('Imagine que você vai montar um brinquedo que vem em partes separadas. Você precisa colar a peça 1 na base, esperar secar, depois colar a peça 2 em cima da peça 1, esperar secar, e assim por diante. Você não pode pular etapas nem fazer duas coisas ao mesmo tempo — cada passo depende do anterior. Isso é um "chaining workflow" (trabalho em cadeia).\n\nA letra **C** é a resposta certa porque diz exatamente isso: tarefas que precisam ser feitas uma depois da outra, cada uma usando o resultado da anterior.\n\nAs outras opções estão erradas:\n- **A** fala de fazer várias tarefas ao mesmo tempo — isso seria como montar o brinquedo e andar de bicicleta simultaneamente, não é uma cadeia.\n- **B** fala de escolher um caminho diferente dependendo do que você recebe — como pegar um brinquedo diferente dependendo do seu humor, não uma sequência fixa.\n- **D** fala de resolver tudo de uma vez com um único comando — como se desse para montar o brinquedo inteiro só dizendo "monte-se!". Não funciona assim, precisa ser passo a passo.','\n',char(10)));
INSERT INTO cards VALUES('admin','card_1783092985485_esk127yx1',166,'Claude keeps ignoring some constraints (for example, it still inserts emojis) in a long prompt.',replace('Claude keeps ignoring some constraints (for example, it still inserts emojis) in a long prompt.\n\nClaude keeps ignoring some constraints (for example, it still inserts emojis) in a long prompt. Which architecture solution?\n[Resposta correta: A solução é chaining com um passo de revisão dedicado focado nas violações. A não resolve, pois o problema é atenção dividida, não tamanho de contexto. B não se aplica, pois as etapas são dependentes. D adiciona imprevisibilidade sem endereçar a violação.]\n\n[ ] A - Increase the context window to fit more constraints.\n[ ] B - Send the same input in several parallel requests.\n[ ] C - Two-step chaining: one generates the content and another is a dedicated review that fixes the violations.\n[ ] D - Switch to an agent with an open-ended goal.','\n',char(10)),'C - Two-step chaining: one generates the content and another is a dedicated review that fixes the violations.','["Domain_4::Prompt_Engineering_Structured_Output", "Domain_5::Context_Management_Reliability", "ForaDoCenario"]','New',0,2.5,0,1783092985485,1783725863651,1783203558653,replace('**Tradução para português do Brasil:**\n\n**Pergunta:** O Claude continua ignorando algumas restrições (por exemplo, ainda insere emojis) em um prompt longo. Qual solução de arquitetura?\n\n[ ] A - Aumentar a janela de contexto para caber mais restrições.\n[ ] B - Enviar a mesma entrada em várias requisições paralelas.\n[ ] C - Encadeamento em duas etapas: uma gera o conteúdo e outra é uma revisão dedicada que corrige as violações.\n[ ] D - Mudar para um agente com um objetivo aberto.','\n',char(10)),replace('**Explicação didática para um adulto tech lead:**\n\nO problema central é que, em prompts muito longos, o modelo sofre de *atenção dividida* — ele processa muitas instruções ao mesmo tempo e falha em manter o foco em uma restrição específica (como "não use emojis"). Isso não é um problema de tamanho de contexto (capacidade máxima de tokens), mas sim de como a atenção do modelo se distribui.\n\n**Alternativa correta: C - Encadeamento em duas etapas com revisão dedicada.**\n\nEsta é a abordagem mais eficaz porque separa a responsabilidade em dois passes: o primeiro passo gera o conteúdo livremente (sem se preocupar com a restrição), e o segundo passo tem uma única e clara instrução: revisar o texto e remover/ corrigir violações específicas. Isso resolve o problema de atenção dividida porque o segundo modelo (ou a segunda chamada) tem um foco estreito e único — buscar e eliminar emojis. Não há concorrência de instruções.\n\n**Por que as demais alternativas estão erradas:**\n\n- **A** (Aumentar a janela de contexto): O problema não é falta de espaço para incluir mais restrições. Aumentar a janela de contexto pode até piorar a situação, pois mais tokens significam mais informação para o modelo processar, diluindo ainda mais a atenção. A dificuldade é de focalização, não de capacidade.\n\n- **B** (Enviar a mesma entrada em várias requisições paralelas): Isso não faz sentido porque as etapas são dependentes — primeiro é preciso gerar o conteúdo, depois revisá-lo. Requisições paralelas gerariam múltiplas versões independentes, todas com o mesmo problema de violação, e não haveria um passo de correção. Além disso, você teria que escolher qual resposta usar, e nenhuma foi revisada.\n\n- **D** (Mudar para um agente com objetivo aberto): Agentes com objetivos abertos (ex.: "crie o que quiser") são o oposto do que se precisa aqui. Eles aumentam a imprevisibilidade e não endereçam a raiz do problema — que é garantir que uma restrição específica seja cumprida. Um agente com objetivo aberto tende a gerar mais variações, aumentando a chance de violações, não as reduzindo.','\n',char(10)),replace('Imagina que você tem um amigo chamado Claude que adora desenhar. Você pede para ele escrever uma história bem longa, mas diz: "Não use emojis, tá?" Só que a história é tão grande que ele se distrai e acaba colocando uns emojis no meio sem querer.\n\nAgora, qual a melhor ideia para resolver isso?\n\nOpção A - Dar uma folha ainda maior para ele escrever? Não adianta, porque o problema não é o tamanho da folha, é que ele se distraiu com tanta coisa pra fazer.\n\nOpção B - Pedir para vários amiguinhos escreverem a mesma história ao mesmo tempo? Também não resolve, porque todos eles vão se distrair do mesmo jeito e colocar emojis.\n\nOpção C - Fazer em duas etapas: primeiro ele escreve a história sem se preocupar com os emojis. Depois, outro amigo (ou ele mesmo, mas com uma nova chance) só olha o texto procurando emojis para apagar. É tipo um "revisor" que tem uma única tarefa: caçar emojis. Isso funciona porque o revisor só precisa se concentrar em uma coisa só!\n\nOpção D - Deixar ele fazer o que quiser, sem regras? Aí é pior! Se você não dá nenhuma instrução, ele vai colocar ainda mais emojis.\n\n**Resposta certa: C - Fazer em duas etapas: um para criar e outro só para revisar e corrigir.**','\n',char(10)));
INSERT INTO cards VALUES('admin','card_1783092985497_63qjifhc1',167,'In which situation is chaining the appropriate choice?',replace('In which situation is chaining the appropriate choice?\n\nIn which situation is chaining the appropriate choice?\n[Resposta correta: Chaining serve a tarefas complexas com passos dependentes e validação entre etapas. A aponta para paralelização, B para routing e D para um agent.]\n\n[ ] A - When the sub-tasks are fully independent and can run in parallel.\n[ ] B - When the input just needs to be classified into a category.\n[ ] C - When the task is complex, with steps that build on one another and outputs to validate between stages.\n[ ] D - When the goal is unpredictable and Claude should combine tools freely.','\n',char(10)),'[ ] C - When the task is complex, with steps that build on one another and outputs to validate between stages.','["ForaDosDominios", "ForaDoCenario"]','New',0,2.5,0,1783092985497,1783725867642,1783203558653,replace('**Tradução:**\n\nEm qual situação o encadeamento (chaining) é a escolha apropriada?\n\n[ ] A - Quando as sub-tarefas são totalmente independentes e podem ser executadas em paralelo.\n[ ] B - Quando a entrada precisa apenas ser classificada em uma categoria.\n[ ] C - Quando a tarefa é complexa, com passos que se constroem uns sobre os outros e saídas para validar entre os estágios.\n[ ] D - Quando o objetivo é imprevisível e Claude deve combinar ferramentas livremente.','\n',char(10)),replace('**Explicação didática para um adulto tech lead:**\n\nA alternativa **C** é a resposta correta. O padrão de **chaining** (encadeamento) é uma estratégia arquitetural em sistemas de agentes de IA onde a saída de uma etapa serve como entrada para a próxima, criando uma sequência linear de processamento. Esse padrão é ideal quando:\n\n- **Dependência sequencial**: cada passo depende do resultado do passo anterior.\n- **Validação intermediária**: é possível verificar a qualidade da saída entre estágios, permitindo early stopping ou retry.\n- **Complexidade decomponível**: a tarefa pode ser quebrada em sub-tarefas ordenadas que se beneficiam de verificação intermediária.\n\n**Por que as demais estão erradas:**\n\n- **Alternativa A** descreve um cenário de **paralelização** (fan-out/fan-in), não de chaining. Se as sub-tarefas são independentes e paralelizáveis, o padrão correto seria routing ou parallelization, não chaining.\n\n- **Alternativa B** descreve um cenário de **classificação/routing**. Quando o input precisa apenas ser categorizado para direcionar o fluxo, o padrão apropriado é o routing (ou classifier), não o chaining.\n\n- **Alternativa D** descreve um cenário de **tool use livre e agente autônomo**. Quando o objetivo é imprevisível e o modelo precisa decidir dinamicamente quais ferramentas usar e em qual ordem, o padrão apropriado é o de agente (tool-calling agent), não chaining, que é mais rígido e sequencial.','\n',char(10)),replace('Imagine que você está montando um robô de Lego. Você não pode colocar o braço antes de colocar o corpo, certo? Você precisa seguir uma ordem: primeiro o corpo, depois a cabeça, depois os braços. E a cada passo, você confere se ficou bem feito antes de continuar.\n\nÉ exatamente isso que a opção C diz: o encadeamento (chaining) é quando uma tarefa é tão complicada que você precisa fazer um passo de cada vez, na ordem certa, e verificar se cada parte ficou boa antes de ir para a próxima.\n\nAs outras opções estão erradas porque:\n- A opção A fala sobre fazer tudo ao mesmo tempo (paralelo), que é diferente de encadeamento.\n- A opção B fala sobre apenas separar coisas em grupos, tipo separar brinquedos por cor. Isso não precisa de encadeamento.\n- A opção D fala sobre deixar o robô decidir sozinho o que fazer, sem uma ordem fixa. Isso é legal, mas não é encadeamento, que segue uma sequência.','\n',char(10)));
INSERT INTO cards VALUES('admin','card_1783092985509_227lqwi21',168,'What is the key difference between parallelization and chaining?',replace('What is the key difference between parallelization and chaining?\n\nWhat is the key difference between parallelization and chaining?\n[Resposta correta: Paralelização é independente e simultânea, chaining é sequencial e dependente. A inverte as definições. C e D uniformizam os dois padrões, ignorando a diferença entre independência e dependência.]\n\n[ ] A - Parallelization is sequential and dependent; chaining is simultaneous and independent.\n[ ] B - Parallelization runs independent sub-tasks in parallel and aggregates; chaining runs sequential and dependent sub-tasks.\n[ ] C - Both always run in parallel, changing only the number of prompts.\n[ ] D - Both are sequential, changing only the aggregation step.','\n',char(10)),'B - Parallelization runs independent sub-tasks in parallel and aggregates; chaining runs sequential and dependent sub-tasks.','["Domain_1::Agentic_Architecture_Orchestration", "ForaDoCenario"]','New',0,2.5,0,1783092985509,1783725871339,1783203558653,replace('**Tradução para português do Brasil:**\n\nQual é a principal diferença entre paralelização e encadeamento (chaining)?\n\n[ ] A - Paralelização é sequencial e dependente; encadeamento é simultâneo e independente.\n[ ] B - Paralelização executa sub-tarefas independentes em paralelo e agrega os resultados; encadeamento executa sub-tarefas sequenciais e dependentes.\n[ ] C - Ambos sempre executam em paralelo, mudando apenas o número de prompts.\n[ ] D - Ambos são sequenciais, mudando apenas a etapa de agregação.','\n',char(10)),replace('**Explicação para um adulto tech lead:**\n\n**Resposta correta: B**\n\nA alternativa B descreve com precisão os dois padrões de orquestração de fluxos de trabalho (workflows) em sistemas, especialmente em arquiteturas de LLMs e agentes de IA.\n\n- **Paralelização (Parallelization):** Consiste em dividir um problema em sub-tarefas que não possuem dependência entre si. Essas sub-tarefas são executadas simultaneamente (em paralelo), e ao final, os resultados são agregados (ex.: soma, votação, concatenação). É análogo ao padrão "MapReduce" ou "fan-out/fan-in". O benefício principal é a redução do tempo total de execução e o aumento de throughput.\n\n- **Encadeamento (Chaining):** É um padrão sequencial onde a saída de uma etapa serve como entrada para a próxima. Há uma dependência clara entre as etapas: a etapa N+1 não pode começar antes que a etapa N termine. Exemplos típicos incluem pipelines de processamento de dados ou chamadas encadeadas a LLMs onde o resultado de uma etapa refina ou enriquece a entrada da próxima.\n\n**Análise das alternativas incorretas:**\n\n- **Alternativa A:** Inverte completamente as definições. Afirma o oposto do que cada padrão realmente significa. Paralelização não é sequencial e dependente; chaining não é simultâneo e independente.\n\n- **Alternativa C:** Afirma que ambos são sempre executados em paralelo, o que é falso para chaining, que é estritamente sequencial por natureza. A quantidade de prompts é um detalhe operacional, não a diferença fundamental.\n\n- **Alternativa D:** Afirma que ambos são sequenciais, ignorando que paralelização envolve execução concorrente/paralela de tarefas independentes. A agregação é apenas uma etapa final da paralelização, mas o cerne da diferença está na independência e simultaneidade versus dependência e sequencialidade.','\n',char(10)),replace('**Explicação para uma criança de 10 anos:**\n\nImagina que você tem duas formas de fazer um trabalho em grupo com seus amigos.\n\n**Paralelização** é como quando cada amigo faz uma parte diferente do dever de casa ao mesmo tempo. Um faz a pergunta de matemática, outro faz a de português, outro faz a de ciências. No final, vocês juntam tudo. Ninguém precisa esperar pelo outro porque as tarefas são independentes.\n\n**Encadeamento (chaining)** é como montar um lego passo a passo. Você só pode colocar a peça 2 depois de colocar a peça 1, e a peça 3 só depois da peça 2. Cada etapa depende do que foi feito antes.\n\nA alternativa correta é a B, que diz: "Paralelização executa sub-tarefas independentes ao mesmo tempo e junta os resultados; encadeamento executa sub-tarefas uma depois da outra, cada uma dependendo da anterior."\n\nAs outras alternativas estão erradas porque:\n- A diz o contrário do que é verdade.\n- C diz que os dois são sempre em paralelo, mas encadeamento não é.\n- D diz que os dois são sequenciais, mas paralelização não é.','\n',char(10)));
INSERT INTO cards VALUES('admin','card_1783092985522_i99172ix2',169,'What describes a routing workflow?',replace('What describes a routing workflow?\n\nWhat describes a routing workflow?\n[Resposta correta: Routing classifica primeiro e envia a entrada para uma única pipeline. A confunde com paralelização e envio para todas. C descreve chaining e D descreve um agent.]\n\n[ ] A - The input goes simultaneously to all pipelines and the results are aggregated.\n[ ] B - A router classifies the request and forwards the input to a single specialized pipeline.\n[ ] C - Each step builds on the previous one in a dependent sequence.\n[ ] D - Claude receives only a goal and picks tools freely.','\n',char(10)),'B - A router classifies the request and forwards the input to a single specialized pipeline.','["Domain_1::Agentic_Architecture_Orchestration", "ForaDoCenario"]','New',0,2.5,0,1783092985522,1783725875230,1783203558653,replace('**Tradução para português do Brasil:**\n\nO que descreve um fluxo de trabalho de roteamento (routing)?\n\n[ ] A - A entrada vai simultaneamente para todas as pipelines e os resultados são agregados.\n[ ] B - Um roteador classifica a requisição e encaminha a entrada para uma única pipeline especializada.\n[ ] C - Cada etapa se baseia na anterior, em uma sequência dependente.\n[ ] D - Claude recebe apenas um objetivo e escolhe ferramentas livremente.','\n',char(10)),replace('**Explicação para um adulto (tech lead):**\n\nA alternativa **B** é a correta porque define com precisão o padrão de **Routing Workflow**. Neste padrão, um classificador/roteador (router) analisa a entrada do usuário e decide qual pipeline especializada deve processá-la. Cada pipeline é dedicada a um tipo específico de solicitação (ex.: uma pipeline para perguntas técnicas, outra para reclamações, outra para vendas). Isso permite que cada pipeline seja otimizada para seu propósito e evita que um modelo genérico tente lidar com todos os cenários de forma subótima.\n\n**Análise das alternativas incorretas:**\n\n- **A** descreve o padrão de **Parallelization (Paralelização)** ou **Fan-out**, onde a entrada é enviada para múltiplas pipelines simultaneamente e os resultados são combinados posteriormente (por exemplo, via agregação ou votação). Não é routing, pois não há classificação seletiva — todas as pipelines recebem a mesma entrada.\n\n- **C** descreve o padrão de **Chaining (Encadeamento)** ou **Pipeline Sequencial**, onde a saída de uma etapa serve como entrada para a próxima, formando uma cadeia linear de dependências. Não há roteamento condicional baseado no tipo de entrada.\n\n- **D** descreve o padrão **Agent (Agente)**, onde o modelo recebe um objetivo de alto nível e decide autonomamente quais ferramentas usar e em qual ordem. É um paradigma diferente, onde o modelo tem agência e escolha dinâmica, ao contrário do routing, que tem uma decisão fixa de classificação no início.','\n',char(10)),replace('Imagine que você tem uma caixa de correio mágica. Quando chega uma carta, um robô lê o endereço e decide para qual amigo entregar: se for um desenho, vai para o João; se for uma conta de matemática, vai para a Maria. Cada amigo só recebe o que ele sabe fazer bem.\n\nÉ isso que a alternativa **B** explica! Um "roteador" (o robô) classifica o pedido e manda para a pessoa certa.\n\nAs outras alternativas estão erradas porque:\n- **A** seria como enviar a mesma carta para todos os seus amigos ao mesmo tempo — bagunça geral!\n- **C** é como fazer uma tarefa em que você só pode começar a segunda parte depois que terminar a primeira. Não tem um robô classificando nada.\n- **D** é como dar apenas um objetivo ("arrume o quarto") e deixar a pessoa escolher sozinha o que fazer primeiro. Também não tem classificação no começo.','\n',char(10)));
INSERT INTO cards VALUES('admin','card_1783092985535_brqqtkysv',170,'What are the two steps of a routing workflow?',replace('What are the two steps of a routing workflow?\n\nWhat are the two steps of a routing workflow?\n[Resposta correta: Routing tem categorização seguida de processamento especializado. A descreve chaining de geração e revisão. C descreve paralelização. D é o princípio read before write, sem relação com routing.]\n\n[ ] A - Generate the output and then review it in a dedicated call.\n[ ] B - Categorize the input and then select the appropriate template or pipeline for the category.\n[ ] C - Send the input in parallel and aggregate the results.\n[ ] D - Read the file before writing to it.','\n',char(10)),'[ ] B - Categorize the input and then select the appropriate template or pipeline for the category.','["ForaDosDominios", "ForaDoCenario"]','New',0,2.5,0,1783092985535,1783725878287,1783203558653,replace('Tradução:\n\nQuais são as duas etapas de um workflow de roteamento (routing)?\n\n[ ] A - Gerar a saída e depois revisá-la em uma chamada dedicada.\n[ ] B - Categorizar a entrada e então selecionar o template ou pipeline apropriado para a categoria.\n[ ] C - Enviar a entrada em paralelo e agregar os resultados.\n[ ] D - Ler o arquivo antes de escrever nele.','\n',char(10)),replace('Explicação para adulto tech lead:\n\nA pergunta pede as duas etapas fundamentais de um workflow de roteamento (routing). No contexto de sistemas de software, especialmente em arquiteturas de pipelines de processamento ou LLM workflows, "routing" refere-se a um padrão onde uma requisição ou dado de entrada é inspecionado e direcionado para o manipulador mais adequado com base em alguma classificação.\n\nA alternativa **B** está correta porque descreve precisamente esse padrão: primeiro, o sistema categoriza a entrada (classifica ou avalia qual tipo de problema/domínio a entrada pertence); segundo, com base nessa categoria, seleciona e aplica um template, pipeline ou handler especializado para processar aquela entrada de forma otimizada. Esse é o núcleo do que significa "rotear" — decidir o destino certo para cada tipo de requisição.\n\nAnálise das alternativas incorretas:\n\n- **A (Gerar e depois revisar):** Isso descreve um workflow de "generate-then-review" ou "reflection loop", comum em sistemas com dupla verificação (ex.: gerar um texto e depois revisá-lo). Não há roteamento aqui; é uma sequência linear de geração e validação.\n\n- **C (Enviar em paralelo e agregar):** Isso descreve paralelização/fan-out com agregação, como no padrão MapReduce ou em paralelização de chamadas a múltiplos serviços. Não há roteamento seletivo; tudo é enviado para todos os destinos e depois combinado.\n\n- **D (Ler antes de escrever):** Isso descreve um princípio de concorrência (read-before-write) para evitar condições de corrida ou corrupção de dados. Não tem relação com roteamento.','\n',char(10)),replace('Imagina que você tem uma caixa de correio mágica. Quando chega uma carta, você primeiro olha o assunto dela (por exemplo: "brinquedos", "lição de casa" ou "convite de festa"). Essa é a primeira etapa: descobrir qual é o assunto da carta, ou seja, categorizar. Depois, você coloca a carta na gaveta certa: a carta de brinquedo vai para a pasta de brinquedos, a de lição de casa vai para a pasta de estudos, e o convite vai para a pasta de festas. Isso é a segunda etapa: escolher o lugar certo para cada coisa. Então, as duas etapas do roteamento são: (1) identificar o tipo de entrada e (2) mandar para o processamento certo. Por isso a resposta certa é a letra B.\n\nAs outras alternativas estão erradas porque:\n- A: é sobre criar algo e depois revisar, não é sobre separar por tipo.\n- C: é sobre fazer várias coisas ao mesmo tempo e juntar tudo, não sobre escolher um caminho específico.\n- D: é sobre ler um arquivo antes de escrever nele, o que é uma regra de cuidado, não tem nada a ver com roteamento.','\n',char(10)));
INSERT INTO cards VALUES('admin','card_1783092985558_w08qa7a41',171,'A tool generates video scripts and very different topics (for example, programming versus surfing) require different styles.',replace('A tool generates video scripts and very different topics (for example, programming versus surfing) require different styles.\n\nA tool generates video scripts and very different topics (for example, programming versus surfing) require different styles. Which pattern?\n[Resposta correta: O caso pede routing, com categorização do tópico e template especializado. A não se aplica, pois os tópicos são independentes. B desperdiça ao enviar a todos os templates, quando só um é necessário. D adiciona imprevisibilidade sem necessidade.]\n\n[ ] A - Chaining, because each topic depends on the previous one.\n[ ] B - Parallelization, sending the topic to all templates at the same time.\n[ ] C - Routing, categorizing the topic and directing it to a specialized template per category.\n[ ] D - Agent, letting Claude pick tools freely.','\n',char(10)),'[ ] C - Routing, categorizing the topic and directing it to a specialized template per category.','["Domain_1::Agentic_Architecture_Orchestration", "Domain_4::Prompt_Engineering_Structured_Output", "Scenario_2::Code_Generation_Claude_Code"]','New',0,2.5,0,1783092985558,1783725882572,1783203558653,replace('**Tradução para português do Brasil:**\n\nUma ferramenta gera roteiros de vídeo e tópicos muito diferentes (por exemplo, programação versus surfe) exigem estilos diferentes. Qual padrão?\n\n[ ] A - Chaining (encadeamento), porque cada tópico depende do anterior.\n[ ] B - Parallelization (paralelização), enviando o tópico para todos os templates ao mesmo tempo.\n[ ] C - Routing (roteamento), categorizando o tópico e direcionando-o para um template especializado por categoria.\n[ ] D - Agent (agente), deixando o Claude escolher ferramentas livremente.','\n',char(10)),replace('**Explicação para um adulto tech lead:**\n\nA pergunta descreve um cenário onde uma ferramenta de IA precisa gerar roteiros de vídeo para tópicos radicalmente diferentes (ex: programação vs. surfe), que exigem estilos de roteiro distintos. O desafio é processar entradas heterogêneas e aplicar o template correto para cada uma.\n\n**Alternativa correta: C - Routing**\n\nO padrão Routing (roteamento) é a melhor escolha porque:\n- Ele classifica/categoriza a entrada (o tópico do vídeo) antes de processá-la.\n- Com base na categoria identificada (ex: "tecnologia", "esportes"), direciona a requisição para um template especializado apropriado.\n- Isso permite que cada template seja otimizado exclusivamente para seu domínio (tom, estrutura, vocabulário), sem contaminação entre estilos.\n- É o padrão canônico para lidar com entradas que exigem tratamentos distintos e mutualmente exclusivos.\n\n**Por que as demais estão incorretas:**\n\n- **A - Chaining (encadeamento):** Implica que a saída de uma etapa alimenta a próxima, criando uma sequência dependente. No cenário descrito, os tópicos são independentes entre si (programação não depende de surfe). Não há razão para encadear etapas. Chaining seria útil se, por exemplo, o roteiro passasse por etapas sequenciais de refinamento, mas a questão trata de tópicos diferentes exigindo templates diferentes, não de processamento em pipeline.\n\n- **B - Parallelization (paralelização):** Enviar o mesmo tópico para TODOS os templates simultaneamente é ineficiente e desnecessário. Apenas um template é relevante por tópico. Paralelização seria apropriada para cenários onde múltiplas visões do mesmo dado são úteis (ex: gerar resumo, análise de sentimentos e extração de entidades ao mesmo tempo), mas aqui o objetivo é aplicar o template correto, não gerar múltiplas versões concorrentes.\n\n- **D - Agent (agente):** Delegar ao modelo a escolha livre de ferramentas introduz imprevisibilidade e complexidade desnecessária. Para um problema estruturado como "categorizar e aplicar template", uma abordagem determinística (routing) é mais confiável, testável e eficiente em termos de latência e custo. O padrão Agent é mais indicado para cenários onde o caminho de execução não é conhecido antecipadamente e requer raciocínio dinâmico.','\n',char(10)),replace('Imagine que você tem uma máquina que faz vídeos. Se o vídeo é sobre "como programar um jogo", o vídeo precisa ser sério e explicar tudo direitinho. Mas se o vídeo é sobre "como surfar", o vídeo precisa ser animado e mostrar ondas legais. São estilos tão diferentes que não dá para usar o mesmo jeito de fazer.\n\nA pergunta é: como a máquina decide qual estilo usar?\n\n- **Resposta errada A (Chaining):** Seria como se para fazer o vídeo de programação você precisasse primeiro ver o vídeo de surfe. Não faz sentido, porque um não tem nada a ver com o outro.\n\n- **Resposta errada B (Parallelization):** Seria como mandar o tema "programação" para a equipe de surfe, para a equipe de culinária, para a equipe de esportes... todo mundo ao mesmo tempo! Só que só a equipe de tecnologia precisa trabalhar, as outras vão gastar energia à toa.\n\n- **Resposta certa C (Routing):** É como ter um porteiro esperto na entrada. Quando chega "programação", ele lê e fala: "Ah, isso é de tecnologia!" e manda direto para a equipe que sabe fazer vídeos de tecnologia. Quando chega "surfe", ele manda para a equipe de esportes. Assim, cada equipe faz o que sabe de melhor, sem bagunça.\n\n- **Resposta errada D (Agent):** Seria deixar o porteiro inventar regras na hora, sem um plano. Ele pode mandar programação para a cozinha ou surfe para o escritório. Fica confuso e imprevisível.\n\nEntão, a melhor ideia é o **roteamento (Routing)**: categorizar o assunto e mandar para quem entende dele.','\n',char(10)));
INSERT INTO cards VALUES('admin','card_1783092985571_pmepmqju6',172,'In routing, where does the user input go after categorization?',replace('In routing, where does the user input go after categorization?\n\nIn routing, where does the user input go after categorization?\n[Resposta correta: No routing a entrada segue para uma única pipeline especializada. A confunde com paralelização. C ignora o passo de processamento especializado. D descreve um chaining, não routing.]\n\n[ ] A - To all pipelines simultaneously, aggregating the results.\n[ ] B - To a single specialized pipeline, optimized for that category.\n[ ] C - To no pipeline, it just returns the category.\n[ ] D - To two pipelines in a dependent sequence.','\n',char(10)),'B - To a single specialized pipeline, optimized for that category.','["ForaDosDominios", "ForaDoCenario"]','New',0,2.5,0,1783092985571,1783725886451,1783203558653,replace('**Tradução para português do Brasil:**\n\n**Pergunta:** Em roteamento (routing), para onde vai a entrada do usuário após a categorização?\n\n**Alternativas:**\n[ ] A - Para todas as pipelines simultaneamente, agregando os resultados.\n[ ] B - Para uma única pipeline especializada, otimizada para aquela categoria.\n[ ] C - Para nenhuma pipeline, apenas retorna a categoria.\n[ ] D - Para duas pipelines em uma sequência dependente.','\n',char(10)),replace('**Explicação didática para um adulto tech lead:**\n\n**Resposta correta: B**\n\nNo padrão de *routing* (roteamento), o fluxo funciona em duas etapas principais: primeiro, um classificador (ou roteador) categoriza a entrada do usuário com base em algum critério (como intenção, tipo de dado, domínio, etc.); em segundo lugar, com base nessa categoria, a entrada é encaminhada **exclusivamente** para uma pipeline especializada que foi projetada para lidar com aquela categoria específica.\n\n**Por que as demais estão erradas:**\n\n- **Alternativa A** descreve o padrão de *parallelization* (paralelização) ou *fan-out*, onde a mesma entrada é enviada para múltiplos processadores simultaneamente e os resultados são agregados posteriormente. Isso é conceitualmente oposto ao *routing*, que é uma bifurcação condicional exclusiva.\n\n- **Alternativa C** ignora a etapa de processamento especializado. No *routing*, o objetivo não é apenas classificar e parar; a classificação serve justamente para decidir qual pipeline receberá a entrada e a processará adiante. Retornar apenas a categoria não gera valor de negócio — o processamento é essencial.\n\n- **Alternativa D** descreve o padrão de *chaining* (encadeamento) ou *pipeline sequencial*, onde a saída de uma pipeline serve como entrada para a próxima, formando uma sequência dependente. No *routing*, as pipelines são mutuamente exclusivas, não sequenciais.','\n',char(10)),replace('Imagine que você tem uma caixa de correio na escola. Quando chega uma carta, primeiro você olha: "Essa carta é para a turma do 3º ano ou para a turma do 5º ano?".\n\nDepois de descobrir (isso é a categorização), você leva a carta para a sala certa — e só para aquela sala! Você não entrega a carta para todas as salas ao mesmo tempo, e também não fica só com a carta na mão sem entregar para ninguém. A carta vai para uma única sala, que sabe o que fazer com ela.\n\nNo *routing* (roteamento) é a mesma coisa: a pergunta do usuário é classificada e depois enviada para uma única "pipeline" (um caminho de processamento) que foi feita especialmente para responder aquele tipo de pergunta.\n\n- Alternativa A (mandar para todo mundo) não é roteamento, é como se você lesse a carta em voz alta para a escola inteira.\n- Alternativa C (não mandar para ninguém) não faz sentido, porque aí ninguém responde a carta.\n- Alternativa D (mandar para duas salas em sequência) seria como entregar a carta para uma sala, esperar a resposta, e depois entregar para outra sala — isso é outra coisa, chamada *chaining*.\n\nEntão a resposta certa é: a entrada vai para **uma única pipeline especializada** para aquela categoria.','\n',char(10)));
INSERT INTO cards VALUES('admin','card_1783092985592_ygvv29sk9',173,'When is routing the appropriate pattern?',replace('When is routing the appropriate pattern?\n\nWhen is routing the appropriate pattern?\n[Resposta correta: Routing serve quando há tipos diversos, categorias claras e categorização confiável. A elimina a razão de rotear. C aponta paralelização e D aponta chaining.]\n\n[ ] A - When all requests are identical and use the same approach.\n[ ] B - When the app handles diverse types of requests, there are clear categories and the categorization is reliable.\n[ ] C - When the sub-tasks are independent and can run in parallel.\n[ ] D - When each step depends on the output of the previous step.','\n',char(10)),'B - When the app handles diverse types of requests, there are clear categories and the categorization is reliable.','["Domain_1::Agentic_Architecture_Orchestration", "Domain_2::Tool_Design_MCP_Integration", "Scenario_1::Customer_Support_Agent"]','New',0,2.5,0,1783092985592,1783725890551,1783203558653,replace('**Tradução para português do Brasil:**\n\n**Pergunta:** Quando o roteamento (routing) é o padrão apropriado?\n\n[ ] A - Quando todas as requisições são idênticas e usam a mesma abordagem.\n[ ] B - Quando o aplicativo lida com tipos diversos de requisições, existem categorias claras e a categorização é confiável.\n[ ] C - Quando as sub-tarefas são independentes e podem ser executadas em paralelo.\n[ ] D - Quando cada etapa depende da saída da etapa anterior.','\n',char(10)),replace('**Explicação para adulto tech lead:**\n\nO padrão de **roteamento (routing)** é apropriado quando precisamos direcionar diferentes tipos de requisições para diferentes handlers ou processadores especializados, com base em critérios bem definidos.\n\n**Alternativa correta: B**\n\nA alternativa B descreve precisamente o cenário ideal para routing: tipos de requisições distintos, categorias claramente delimitadas (como "pagamento", "consulta", "relatório") e um mecanismo de categorização confiável (ex.: um campo `type` na requisição, ou regras de negócio determinísticas). Isso permite que cada rota tenha sua própria lógica, validação e fluxo de processamento, sem acoplamento entre os handlers.\n\n**Por que as demais estão erradas:**\n\n- **Alternativa A:** Quando todas as requisições são idênticas e usam a mesma abordagem, não há razão para rotear — você pode usar um único handler simples. Routing adicionaria complexidade desnecessária.\n\n- **Alternativa C:** Sub-tarefas independentes que rodam em paralelo descrevem o padrão de **fan-out / parallel processing**, não routing. No routing, a requisição segue exatamente *um* caminho, não vários ao mesmo tempo.\n\n- **Alternativa D:** Cada etapa depender da saída da etapa anterior descreve o padrão de **chaining (encadeamento)** ou pipeline sequencial. No routing, a decisão de rota acontece tipicamente uma vez no início, e não há dependência de saída de etapas anteriores para definir a rota.','\n',char(10)),replace('**Explicação para criança de 10 anos:**\n\nImagina que você tem uma caixa de correio na sua casa. Quando chega uma carta, você precisa decidir para quem entregar:\n\n- Se é uma conta, vai para o seu pai.\n- Se é um desenho de um amigo, vai para você.\n- Se é um cartão de aniversário, vai para sua mãe.\n\nIsso é **roteamento** — você olha o tipo de carta e decide para quem mandar.\n\nA resposta certa (B) diz que usamos roteamento quando temos **tipos diferentes de pedidos**, **categorias bem definidas** e sabemos **classificar direitinho** cada pedido.\n\nAs outras opções estão erradas porque:\n- **A** diz que tudo é igual — aí não precisa decidir rota, é só mandar tudo pro mesmo lugar.\n- **C** fala de fazer várias coisas ao mesmo tempo — isso é outra coisa, não roteamento.\n- **D** fala de uma tarefa que depende da anterior, como montar um LEGO passo a passo — também não é roteamento, é uma fila de tarefas.','\n',char(10)));
INSERT INTO cards VALUES('admin','card_1783092985605_a4xw97arr',174,'An agent needs to run several tools in sequence to answer.',replace('An agent needs to run several tools in sequence to answer.\n\nAn agent needs to run several tools in sequence to answer. Which control structure is used?\n[Resposta correta: A estrutura é o loop de conversa que repete até não haver mais pedidos de tool. A descreve um workflow fixo. C descreve routing e D ignora o uso de tools necessário ao cenário.]\n\n[ ] A - A fixed sequence of steps written in code, without a loop.\n[ ] B - A loop that calls Claude, runs the requested tool and returns the tool_result, repeating until Claude stops requesting tools.\n[ ] C - A router that picks a pipeline per category.\n[ ] D - A single step that solves the question without calling tools.','\n',char(10)),'B - A loop that calls Claude, runs the requested tool and returns the tool_result, repeating until Claude stops requesting tools.','["Domain_1::Agentic_Architecture_Orchestration", "Scenario_1::Customer_Support_Agent"]','New',0,2.5,0,1783092985605,1783725894852,1783203558653,replace('**Tradução para Português do Brasil:**\n\nUm agente precisa executar várias ferramentas em sequência para responder.\n\nUm agente precisa executar várias ferramentas em sequência para responder. Qual estrutura de controle é utilizada?\n\n[ ] A - Uma sequência fixa de passos escrita em código, sem um loop.\n[ ] B - Um loop que chama o Claude, executa a ferramenta solicitada e retorna o tool_result, repetindo até que o Claude pare de solicitar ferramentas.\n[ ] C - Um roteador que escolhe um pipeline por categoria.\n[ ] D - Uma única etapa que resolve a pergunta sem chamar ferramentas.','\n',char(10)),replace('**Explicação para Adulto (Tech Lead):**\n\nA pergunta descreve o padrão fundamental de agentes que utilizam modelos de linguagem (LLMs) com capacidade de chamada de ferramentas (tool use). Diferente de workflows fixos e previsíveis, um agente precisa decidir dinamicamente quais ferramentas chamar e em qual ordem.\n\n**Alternativa B (correta):** Esta é a implementação clássica de um agente reativo com tool use. O loop funciona assim: (1) envia o histórico de mensagens (incluindo resultados de tools) para o Claude; (2) Claude analisa o contexto e decide se deve responder diretamente ou solicitar uma tool; (3) se solicitar uma tool, o sistema executa a ferramenta localmente e anexa o resultado (`tool_result`) na conversa; (4) repete até que Claude produza uma resposta final (texto sem chamada de tool). É uma estrutura de controle do tipo "while" implícita, onde a condição de parada é o modelo não solicitar mais tools.\n\n**Alternativa A (incorreta):** Uma sequência fixa e linear sem loop descreve um workflow determinístico (como uma pipeline de processamento). Isso não permite que o modelo decida dinamicamente quais ferramentas chamar, o que é essencial para um agente autônomo. Em cenários reais, o número e a ordem de tools necessárias são imprevisíveis.\n\n**Alternativa C (incorreta):** Um roteador é uma estrutura de controle que direciona a requisição para um pipeline específico baseado em uma categoria (ex: "suporte", "vendas"). Embora útil em arquiteturas de workflow, não resolve o problema de executar múltiplas ferramentas em sequência de forma dinâmica guiada pelo modelo.\n\n**Alternativa D (incorreta):** Ignora completamente o uso de ferramentas descrito no enunciado. Se o agente precisasse apenas de uma única chamada ao modelo sem tools, não haveria necessidade de loop ou sequência de ferramentas. O enunciado diz explicitamente "várias ferramentas em sequência".','\n',char(10)),replace('Imagine que você é um detetive e tem várias ferramentas na sua mochila: uma lupa, um livro de pistas e um rádio. Para resolver um caso, você não sabe de antemão qual ferramenta vai usar primeiro - você vai tentando uma, vê o que descobre, e decide a próxima baseado no que achou.\n\nA resposta certa é a B: é como se você fizesse um "loop" (uma repetição) onde:\n1. Você pergunta ao detetive chefe (Claude) o que fazer\n2. Ele pede uma ferramenta específica\n3. Você usa essa ferramenta e mostra o resultado pra ele\n4. Ele decide: ou pede outra ferramenta, ou dá a resposta final\n5. Repete até ele ficar satisfeito e dar a resposta\n\nAs outras opções não funcionam porque:\n- A: seria um roteiro fixo, como se você já soubesse exatamente a ordem das ferramentas antes de começar\n- C: seria como separar os casos em gavetas, mas não resolve usar várias ferramentas em sequência\n- D: seria tentar resolver o caso sem usar nenhuma ferramenta, o que não faz sentido quando o problema pede para usar várias','\n',char(10)));
INSERT INTO cards VALUES('admin','card_1783092985617_c77q7zpi3',175,'What is the stop condition of the agentic tool use loop?',replace('What is the stop condition of the agentic tool use loop?\n\nWhat is the stop condition of the agentic tool use loop?\n[Resposta correta: O loop para quando não há mais bloco tool_use. A pegadinha em A é usar contagem de tokens como critério. B é falso, pois Claude pode gerar texto junto com tool calls. D impõe um limite artificial que não é a condição de parada real.]\n\n[ ] A - When the number of tokens in the response reaches a limit.\n[ ] B - When Claude''s response contains any text.\n[ ] C - When Claude''s response no longer contains any tool_use block.\n[ ] D - After a fixed number of iterations defined in the code.','\n',char(10)),'C - When Claude''s response no longer contains any tool_use block.','["Domain_1::Agentic_Architecture_Orchestration", "Domain_5::Context_Management_Reliability", "ForaDoCenario"]','New',0,2.5,0,1783092985617,1783725898706,1783203558653,replace('**Tradução para português do Brasil:**\n\n**Pergunta:** Qual é a condição de parada do loop de uso de ferramentas (tool use) do agente?\n\n**Alternativas:**\n[ ] A - Quando o número de tokens na resposta atinge um limite.\n[ ] B - Quando a resposta do Claude contém qualquer texto.\n[ ] C - Quando a resposta do Claude não contém mais nenhum bloco tool_use.\n[ ] D - Após um número fixo de iterações definido no código.','\n',char(10)),replace('**Explicação didática para um adulto tech lead:**\n\nA alternativa correta é a **C**.\n\nO loop de uso de ferramentas do agente (tool use) é um padrão onde o modelo (Claude) pode solicitar a execução de ferramentas e o sistema executa essas chamadas, retornando os resultados para o modelo. O loop continua enquanto o modelo indicar que deseja usar mais ferramentas.\n\n**Por que C é a resposta correta:**\n\nA condição de parada fundamental do loop é a **ausência de blocos `tool_use`** na resposta do modelo. Quando Claude decide que já possui informações suficientes para formular uma resposta final ao usuário, ele para de solicitar chamadas de ferramenta e gera uma resposta de texto puro (ou com o bloco `text`). Nesse momento, o loop é encerrado porque não há mais ações de ferramenta a serem executadas.\n\n**Análise das alternativas incorretas:**\n\n- **A** (Limite de tokens): Embora existam limites de contexto (janela de tokens), esse não é o mecanismo de parada *intencional* do loop. O loop não para porque atingiu um limite de tokens na resposta; ele para porque o modelo decidiu que não precisa de mais ferramentas. Um estouro de contexto seria uma condição de erro, não a condição de parada esperada.\n\n- **B** (Resposta contém texto): Isso é uma pegadinha. Claude pode gerar texto *junto com* chamadas de ferramenta (tool_use). A presença de texto não significa que o loop deve parar; pelo contrário, enquanto houver blocos tool_use, o loop continua para processá-los. A condição de parada não é "tem texto", mas sim "não tem tool_use".\n\n- **D** (Número fixo de iterações): Impor um número fixo de iterações é um *mecanismo de segurança* (guarda) para evitar loops infinitos, mas não é a condição de parada natural do sistema. A parada natural ocorre quando o modelo para de solicitar ferramentas. Um limite fixo é um fallback artificial que, se atingido, geralmente indica um problema ou configuração inadequada.','\n',char(10)),replace('Imagine que você está brincando de "ajudante de chef" com um robô cozinheiro. O robô pode pedir ferramentas da cozinha para fazer uma receita.\n\nEle fala: "Me passe a faca" 🗡️ — você dá a faca.\nEle fala: "Me passe a tábua" 🪵 — você dá a tábua.\nEle fala: "Agora me passe a panela" 🍳 — você dá a panela.\nEle fala: "Pronto, agora vou cortar os ingredientes!" 🥕 — e começa a fazer a comida.\n\nPercebeu? O robô fica pedindo ferramentas enquanto precisa delas. Quando ele já tem tudo o que precisa, ele para de pedir e começa a fazer a receita. É isso que o Claude faz!\n\nA condição de parada é: **quando o Claude não pede mais ferramentas (tool_use)**. Ele só para quando a resposta dele não tem mais nenhum "pedido de ferramenta". \n\nAs outras opções estão erradas porque:\n- **A** (limite de tokens) — é como se o robô parasse porque suas palavras acabaram, mas ele ainda precisa de ferramentas. Não faz sentido.\n- **B** (resposta contém texto) — o robô pode falar "Me passe a faca" e isso é texto, mas ele ainda precisa de ferramentas! Não é hora de parar.\n- **D** (número fixo de iterações) — seria como dizer "o robô só pode pedir 3 ferramentas e depois para", mesmo que a receita precise de 5. Isso quebraria a receita!','\n',char(10)));
INSERT INTO cards VALUES('admin','card_1783092985630_z1vsb71db',176,'When designing tools for an agent, which principle should you follow?',replace('When designing tools for an agent, which principle should you follow?\n\nWhen designing tools for an agent, which principle should you follow?\n[Resposta correta: Tools abstratas e combináveis maximizam a flexibilidade do agent. A limita o agent a cenários previstos. C reduz a combinabilidade. D contraria o princípio de inspeção de ambiente, que exige observar resultados.]\n\n[ ] A - Hyper-specialized tools, one for each anticipated scenario.\n[ ] B - Abstract and composable tools, so that Claude combines them in unplanned scenarios.\n[ ] C - A single tool that does everything at once.\n[ ] D - Tools that hide the result of their actions from the agent.','\n',char(10)),'[ ] B - Abstract and composable tools, so that Claude combines them in unplanned scenarios.','["Domain_2::Tool_Design_MCP_Integration", "Scenario_4::Developer_Productivity"]','New',0,2.5,0,1783092985630,1783725902731,1783203558653,replace('**Tradução:**\n\nQuando estiver projetando ferramentas para um agente, qual princípio você deve seguir?\n\n[ ] A - Ferramentas hiperespecializadas, uma para cada cenário antecipado.\n[ ] B - Ferramentas abstratas e combináveis, para que Claude as combine em cenários não planejados.\n[ ] C - Uma única ferramenta que faz tudo de uma vez.\n[ ] D - Ferramentas que escondem o resultado de suas ações do agente.','\n',char(10)),replace('**Explicação para adulto (tech lead):**\n\nA alternativa correta é a **B**.\n\n**Por que B está correta:**\n\nO design de ferramentas para agentes como o Claude deve priorizar **abstração e composabilidade**. Ferramentas abstratas (ex.: "ler_arquivo", "escrever_arquivo", "pesquisar_web") são blocos de construção fundamentais que o modelo pode combinar dinamicamente para resolver problemas nunca antes vistos. Isso maximiza a flexibilidade, permite reuso e reduz o acoplamento entre a definição das ferramentas e os casos de uso específicos. Um agente bem projetado deve ser capaz de orquestrar múltiplas chamadas de ferramentas em sequência ou paralelo para atingir objetivos complexos, mesmo que esses percursos não tenham sido previstos pelo desenvolvedor.\n\n**Análise das alternativas incorretas:**\n\n- **A (Ferramentas hiperespecializadas):** Embora possam ser eficientes em cenários muito específicos, elas limitam severamente a capacidade do agente de lidar com situações não previstas. Cada nova variação de tarefa exigiria uma nova ferramenta, gerando explosão combinatorial, alta manutenção e rigidez. Viola o princípio de generalidade e reuso.\n\n- **C (Ferramenta única monolítica):** Uma única ferramenta que "faz tudo" quebra o princípio de separação de preocupações (Separation of Concerns). Torna o sistema opaco, difícil de debugar, testar e evoluir. Além disso, o agente perde a capacidade de interagir com o ambiente de forma granular, inspecionando resultados intermediários e tomando decisões adaptativas.\n\n- **D (Esconder resultados do agente):** Contraria o princípio fundamental de **inspeção de ambiente**. Um agente precisa observar os resultados de suas ações (feedback loop) para planejar os próximos passos, corrigir erros e adaptar seu comportamento. Esconder resultados cega o agente, tornando-o incapaz de executar tarefas que exigem raciocínio sequencial e verificação.','\n',char(10)),replace('**Explicação para criança de 10 anos:**\n\nImagine que você tem um robô ajudante. Se você der a ele ferramentas simples e que podem ser usadas de várias maneiras — como uma colher, um martelo e uma chave de fenda — ele consegue resolver muitos problemas diferentes, mesmo aqueles que você não imaginou.\n\nAgora, se você der uma ferramenta diferente para cada coisa específica (uma "colher de comer sopa", uma "colher de comer sorvete", uma "colher de mexer café"), o robô só sabe fazer aquilo que você já pensou antes. Ele fica limitado.\n\nA opção B diz exatamente isso: devemos dar ferramentas que são como peças de Lego — simples e que podem ser combinadas de vários jeitos. Assim, o agente (o robô) consegue criar soluções novas sozinho!\n\nAs outras opções são ruins porque:\n- A: dá ferramentas específicas demais.\n- C: dá uma ferramenta que tenta fazer tudo de uma vez (bagunçada).\n- D: esconde do robô o que aconteceu quando ele usou a ferramenta, então ele não aprende com os erros.\n\nA resposta certa é a **B**.','\n',char(10)));
INSERT INTO cards VALUES('admin','card_1783092985642_4x96ed37w',177,'Why does Claude Code offer bash, read, write, edit, glob and grep instead of a tool like "refactor code"?',replace('Why does Claude Code offer bash, read, write, edit, glob and grep instead of a tool like "refactor code"?\n\nWhy does Claude Code offer bash, read, write, edit, glob and grep instead of a tool like "refactor code"?\n[Resposta correta: Tools básicas e abstratas permitem combinação para cenários imprevistos. A e D inventam vantagens de desempenho que não são o motivo. C afirma uma restrição técnica inexistente.]\n\n[ ] A - Because hyper-specialized tools are faster to execute.\n[ ] B - Because basic and abstract tools can be combined for countless unplanned scenarios.\n[ ] C - Because the API does not allow tool names like "refactor code".\n[ ] D - Because abstract tools consume fewer tokens per call.','\n',char(10)),'B - Because basic and abstract tools can be combined for countless unplanned scenarios.','["Domain_3::Claude_Code_Configuration_Workflows", "Domain_2::Tool_Design_MCP_Integration", "Scenario_2::Code_Generation_Claude_Code"]','New',0,2.5,0,1783092985642,1783725906484,1783203558653,replace('**Tradução para Português (Brasil):**\n\n**Pergunta:** Por que o Claude Code oferece bash, read, write, edit, glob e grep em vez de uma ferramenta como "refactor code"?\n\n[ ] A - Porque ferramentas hiperespecializadas são mais rápidas de executar.\n[ ] B - Porque ferramentas básicas e abstratas podem ser combinadas para inúmeros cenários imprevistos.\n[ ] C - Porque a API não permite nomes de ferramentas como "refactor code".\n[ ] D - Porque ferramentas abstratas consomem menos tokens por chamada.','\n',char(10)),replace('**Explicação para um adulto tech lead:**\n\nA questão aborda um princípio fundamental de design de sistemas e APIs: **composabilidade vs. especialização**. O Claude Code opta por um conjunto pequeno de ferramentas primitivas (bash, read, write, edit, glob, grep) que podem ser combinadas de maneiras flexíveis para resolver problemas que nem foram antecipados durante o design.\n\n**Por que a alternativa B é a correta:**\n\nFerramentas básicas e abstratas seguem o princípio da **composabilidade**. Com um conjunto pequeno de primitivas bem definidas (executar comandos no shell, ler arquivos, escrever arquivos, editar trechos específicos, buscar arquivos por padrão glob, buscar conteúdo textual), o Claude Code pode resolver virtualmente qualquer tarefa de manipulação de código — refatoração, debugging, análise estática, migração de dependências, formatação em massa, etc. Isso é análogo ao design de sistemas Unix, onde ferramentas simples como `grep`, `sed`, `awk` e `pipe` se combinam para resolver problemas complexos.\n\n**Por que as demais alternativas estão incorretas:**\n\n- **Alternativa A** — inventa uma vantagem de desempenho que não é o motivo real. Ferramentas hiperespecializadas podem até ser mais rápidas em cenários específicos (ex: uma ferramenta "refactor variable name" dedicada poderia ser otimizada para isso), mas o objetivo do design não é performance máxima em um caso particular, e sim flexibilidade máxima para todos os casos. Além disso, ferramentas especializadas exigem manutenção separada, aumentam a superfície de bugs e duplicam lógica.\n\n- **Alternativa C** — afirma uma restrição técnica inexistente. A API do Claude aceita qualquer nome de ferramenta definido pelo desenvolvedor; não há nenhuma limitação que impeça nomes como "refactor code". O fato de o Claude Code *escolher* não ter essa ferramenta é uma decisão de design, não uma limitação técnica.\n\n- **Alternativa D** — também inventa uma motivação técnica que não procede. Embora ferramentas mais simples possam ter descrições e schemas JSON menores (o que reduz o consumo de tokens de system prompt), essa não é a razão principal. Além disso, uma ferramenta "refactor code" poderia ser implementada com um schema tão enxuto quanto o de uma ferramenta básica — o tamanho do schema não está intrinsecamente ligado ao nível de abstração.','\n',char(10)),replace('**Explicação para uma criança de 10 anos:**\n\nImagine que você tem uma caixa de ferramentas. Em vez de ter uma ferramenta especial para cada coisa que você pode fazer (um "descascador de maçã", um "cortador de papel", um "abridor de potes"), você tem ferramentas simples como uma faca, uma tesoura e uma chave de fenda.\n\nCom essas ferramentas básicas, você pode fazer MUITA coisa! Dá para descascar maçã, cortar papel, abrir potes, e até coisas que ninguém pensou antes, como fazer um brinquedo novo.\n\nÉ a mesma ideia com o Claude Code. Em vez de criar uma ferramenta só para "refatorar código" (que é um tipo específico de arrumar o código), ele prefere ter ferramentas simples como "ler arquivo", "escrever arquivo" e "executar comando". Assim, ele pode combinar essas ferramentas de vários jeitos diferentes para resolver qualquer problema que apareça — até problemas que ninguém imaginava quando as ferramentas foram criadas.\n\nAs outras opções estão erradas:\n- A diz que ferramentas especiais seriam mais rápidas, mas não é por isso que escolheram as simples.\n- C diz que a API não deixa usar o nome "refactor code", mas isso não é verdade — poderia usar sim, só preferiram não usar.\n- D diz que ferramentas simples gastam menos "fichas" (tokens), mas esse também não é o motivo principal.','\n',char(10)));
INSERT INTO cards VALUES('admin','card_1783092985655_eokagrxwj',178,'How do simple tools allow an agent to solve a complex task like "what day will it be in 11 days"?',replace('How do simple tools allow an agent to solve a complex task like "what day will it be in 11 days"?\n\nHow do simple tools allow an agent to solve a complex task like "what day will it be in 11 days"?\n[Resposta correta: O agent encadeia tools simples para compor a solução. A contraria o princípio de tools abstratas e combináveis. C descreve routing, que não é o mecanismo aqui. D não tem relação com resolver a tarefa.]\n\n[ ] A - A single complex tool calculates everything at once.\n[ ] B - Claude chains simple tools as needed, for example get_current_datetime plus add_duration_to_datetime.\n[ ] C - Claude classifies the question and picks a pipeline dedicated to dates.\n[ ] D - The agent counts tokens until it reaches the answer.','\n',char(10)),'[ ] B - Claude chains simple tools as needed, for example get_current_datetime plus add_duration_to_datetime.','["Domain_1::Agentic_Architecture_Orchestration", "Domain_2::Tool_Design_MCP_Integration", "Scenario_4::Developer_Productivity"]','New',0,2.5,0,1783092985655,1783725910895,1783203558653,replace('**Tradução para português do Brasil:**\n\nPergunta: Como ferramentas simples permitem que um agente resolva uma tarefa complexa como "que dia será daqui a 11 dias"?\n\n[ ] A - Uma única ferramenta complexa calcula tudo de uma só vez.\n[ ] B - O Claude encadeia ferramentas simples conforme necessário, por exemplo get_current_datetime mais add_duration_to_datetime.\n[ ] C - O Claude classifica a pergunta e escolhe um pipeline dedicado a datas.\n[ ] D - O agente conta tokens até chegar à resposta.','\n',char(10)),replace('**Explicação didática para um adulto tech lead:**\n\nA pergunta aborda o princípio de composição de ferramentas (tool composition) em agentes de IA. A ideia central é que ferramentas simples e focadas — cada uma com uma responsabilidade única e bem definida — podem ser encadeadas (chained) pelo agente para resolver problemas complexos que nenhuma ferramenta isolada conseguiria resolver.\n\n**Por que B está correta:**\nA alternativa B descreve exatamente o mecanismo de composição: o agente recebe a pergunta "que dia será daqui a 11 dias?", identifica que precisa (1) saber a data/hora atual e (2) adicionar 11 dias a essa data. Ele então invoca `get_current_datetime` para obter a data de hoje e, de posse desse resultado, chama `add_duration_to_datetime` com o parâmetro de +11 dias. O encadeamento é sequencial e a saída de uma ferramenta alimenta a entrada da próxima. Esse é o padrão arquitetural correto para agentes que utilizam ferramentas (function calling).\n\n**Análise das alternativas incorretas:**\n\n- **A (Uma única ferramenta complexa calcula tudo de uma só vez):** Esta alternativa viola o princípio de design de ferramentas simples, granulares e combináveis (Unix philosophy aplicada a agentes). Uma ferramenta monolítica que "faz tudo" seria acoplada, difícil de manter, reutilizar e testar. Além disso, o enunciado da pergunta já estabelece "simple tools" no plural, indicando que a abordagem correta envolve múltiplas ferramentas.\n\n- **C (O Claude classifica a pergunta e escolhe um pipeline dedicado a datas):** Esta alternativa descreve um mecanismo de routing (roteamento), onde um classificador direciona a requisição para um pipeline pré-definido. Embora routing seja uma estratégia válida em alguns sistemas, ela não reflete o comportamento dinâmico de um agente que decide, em tempo de execução, quais ferramentas encadear. O agente não precisa de um pipeline fixo para datas; ele compõe as ferramentas conforme a necessidade do momento.\n\n- **D (O agente conta tokens até chegar à resposta):** Esta alternativa é completamente descabida do ponto de vista técnico. Contagem de tokens é um mecanismo de limitação de contexto ou custo, não um método para resolver problemas aritméticos ou de calendário. Não há relação alguma com a tarefa proposta.\n\n**Conclusão:** A alternativa B é a correta porque descreve fielmente o padrão de tool chaining (encadeamento de ferramentas), onde ferramentas simples e atômicas são compostas pelo agente para resolver problemas complexos de forma dinâmica e flexível.','\n',char(10)),replace('**Explicação para uma criança de 10 anos:**\n\nImagine que você tem duas ferramentas super simples:\n1. Uma "máquina do tempo" que te diz que dia é hoje.\n2. Uma "calculadora de dias" que descobre que dia vai ser se você andar alguns dias para frente.\n\nSozinhas, cada uma faz pouca coisa. Mas se você juntar as duas, consegue responder: "Que dia vai ser daqui a 11 dias?" Primeiro você usa a máquina do tempo para saber que dia é hoje (por exemplo, segunda-feira). Depois, você usa a calculadora de dias: 11 dias depois de segunda-feira... é sexta-feira da outra semana!\n\nÉ tipo brincar de Lego. Cada pecinha sozinha não faz muito, mas juntando várias peças você constrói algo grande e legal. É assim que o agente (o Claude) resolve problemas difíceis: ele usa ferramentas pequenas e simples, uma depois da outra, até chegar na resposta.\n\nAs outras alternativas estão erradas porque:\n- A (ferramenta única que faz tudo): Isso seria como ter um canivete gigante que tenta fazer de tudo — é pesado e atrapalhado.\n- C (escolher um caminho pronto para datas): Isso seria como ter um mapa já desenhado, mas o agente prefere criar o caminho na hora.\n- D (contar tokens): Isso não faz sentido — contar coisinhas não ajuda a saber que dia é hoje ou quantos dias faltam.\n\nEntão a resposta certa é a **B**: juntar ferramentas simples, uma após a outra, como peças de Lego!','\n',char(10)));
INSERT INTO cards VALUES('admin','card_1783092985669_8lzmpqand',179,'What is environment inspection and why does it matter for an agent?',replace('What is environment inspection and why does it matter for an agent?\n\nWhat is environment inspection and why does it matter for an agent?\n[Resposta correta: Environment inspection é observar o resultado das ações, sem o qual o agent opera às cegas. A não descreve inspeção. C usa tokens como métrica de sucesso, o que é incorreto. D descreve routing.]\n\n[ ] A - Restricting the agent to a single tool to avoid errors.\n[ ] B - Giving the agent means to observe the result of its actions, because without this it does not know whether it succeeded nor the new state.\n[ ] C - Counting the tokens spent on each action to measure success.\n[ ] D - Classifying the input before choosing the pipeline.','\n',char(10)),'[ ] B - Giving the agent means to observe the result of its actions, because without this it does not know whether it succeeded nor the new state.','["Domain_1::Agentic_Architecture_Orchestration", "ForaDoCenario"]','New',0,2.5,0,1783092985669,1783725914843,1783203558653,replace('**Tradução para português do Brasil:**\n\nO que é inspeção de ambiente e por que ela é importante para um agente?\n\n[ ] A - Restringir o agente a uma única ferramenta para evitar erros.\n[ ] B - Dar ao agente meios para observar o resultado de suas ações, porque sem isso ele não sabe se obteve sucesso nem qual é o novo estado.\n[ ] C - Contar os tokens gastos em cada ação para medir o sucesso.\n[ ] D - Classificar a entrada antes de escolher o pipeline.','\n',char(10)),replace('**Explicação didática para um adulto tech lead:**\n\nA pergunta aborda o conceito fundamental de **environment inspection** (inspeção de ambiente) em sistemas de agentes autônomos (sejam LLM-based agents, reinforcement learning agents, ou agentes clássicos de IA). A ideia central é que um agente não opera isolado — ele age em um ambiente e precisa de **feedback** para saber o resultado de suas ações.\n\n**Alternativa correta (B):** "Dar ao agente meios para observar o resultado de suas ações, porque sem isso ele não sabe se obteve sucesso nem qual é o novo estado." Esta é a definição precisa de environment inspection. Sem inspeção, o agente fica cego: ele executa uma ação, mas não tem como saber se a ação foi bem-sucedida, se o estado mudou, ou qual o novo estado do ambiente. Isso inviabiliza o aprendizado e a tomada de decisão sequencial.\n\n**Por que as demais estão erradas:**\n- **Alternativa A (Restringir o agente a uma única ferramenta):** Isso descreve uma abordagem de controle ou simplificação do espaço de ações, não inspeção. Não envolve observar resultados.\n- **Alternativa C (Contar tokens gastos em cada ação):** Token counting é uma métrica de eficiência ou custo computacional, não uma forma de inspeção de ambiente. Medir sucesso por tokens é conceitualmente incorreto.\n- **Alternativa D (Classificar a entrada antes de escolher o pipeline):** Isso descreve um routing ou classificação inicial do input (como em arquiteturas de chains condicionais), não a observação do resultado de ações. É um mecanismo de decisão, não de feedback.','\n',char(10)),replace('Imagine que você está brincando de esconde-esconde. Você sai para procurar seus amigos. Depois que você olha em um lugar, você precisa ver se achou alguém ou não, certo? Olhar ao redor para ver o que aconteceu é a "inspeção de ambiente".\n\nSe você fechasse os olhos depois de cada passo, você nunca saberia se estava perto ou longe de achar alguém. Você estaria "cego". É a mesma coisa com um agente (um robô ou programa inteligente): ele precisa "olhar" o resultado das suas ações para saber se deu certo ou não.\n\nA resposta B diz exatamente isso: o agente precisa observar o resultado das suas ações, senão ele não sabe se conseguiu o que queria nem como o mundo mudou. As outras respostas estão falando de outras coisas: A é sobre usar só uma ferramenta, C é sobre contar gastos, D é sobre escolher o caminho antes de agir. Nada disso é sobre "olhar o resultado".','\n',char(10)));
INSERT INTO cards VALUES('admin','card_1783092985682_ku4l8kyse',180,'A computer use agent clicks a button.',replace('A computer use agent clicks a button.\n\nA computer use agent clicks a button. What does it need to receive next?\n[Resposta correta: O agent precisa de um screenshot para inspecionar o novo estado. A usa tokens como sinal de sucesso, o que é incorreto. C ignora que o clique pode ter efeitos variados. D não resolve a necessidade de observar o resultado.]\n\n[ ] A - The token count of the action, to know whether it worked.\n[ ] B - A screenshot of the resulting state, because clicking may navigate or open menus and it needs to observe the result.\n[ ] C - Nothing, because the click always has a predictable effect.\n[ ] D - A new list of tools specialized in buttons.','\n',char(10)),'[ ] B - A screenshot of the resulting state, because clicking may navigate or open menus and it needs to observe the result.','["ForaDosDominios", "ForaDoCenario"]','New',0,2.5,0,1783092985682,1783725918576,1783203558653,replace('**Tradução:**\n\nUm agente de uso de computador clica em um botão.\n\nUm agente de uso de computador clica em um botão. O que ele precisa receber em seguida?\n\n[ ] A - A contagem de tokens da ação, para saber se funcionou.\n[ ] B - Uma captura de tela do estado resultante, porque clicar pode navegar ou abrir menus e ele precisa observar o resultado.\n[ ] C - Nada, porque o clique sempre tem um efeito previsível.\n[ ] D - Uma nova lista de ferramentas especializadas em botões.','\n',char(10)),replace('**Explicação para um adulto tech lead:**\n\nA resposta correta é a **B**.\n\nUm agente de uso de computador (computer use agent) opera em um ambiente visual e interativo, como uma interface gráfica (GUI). Quando ele executa uma ação — no caso, clicar em um botão — o estado da interface pode mudar de maneiras que não são deterministicamente previsíveis apenas pela ação em si. O clique pode:\n- Navegar para outra página,\n- Abrir um menu suspenso,\n- Disparar um modal,\n- Iniciar uma animação,\n- Ou simplesmente não ter efeito (se o botão estiver desabilitado).\n\nPortanto, o agente **precisa observar o novo estado** para planejar os próximos passos. O meio mais comum e eficaz para isso é receber uma nova captura de tela (screenshot) do estado resultante. Isso permite que o agente, geralmente um modelo de visão-linguagem (VLM), analise visualmente o que mudou e decida a próxima ação.\n\n**Análise das alternativas incorretas:**\n\n- **A (contagem de tokens):** A contagem de tokens de uma ação é uma métrica interna do modelo, não um indicador confiável de sucesso ou falha da ação no ambiente. Um clique pode ter sido "bem-sucedido" em termos de execução (o sistema registrou o clique) mas não ter produzido o efeito esperado (ex.: botão desabilitado). A contagem de tokens não reflete o estado observável do ambiente.\n\n- **C (nada):** Essa alternativa assume um comportamento determinístico que não existe em interfaces reais. O efeito de um clique pode variar conforme o estado da aplicação, permissões, latência, etc. Ignorar a necessidade de observar o resultado torna o agente cego a falhas ou mudanças inesperadas.\n\n- **D (nova lista de ferramentas especializadas em botões):** Isso não faz sentido no fluxo de um agente. Ferramentas são definidas a priori; o agente não precisa de uma nova lista de ferramentas a cada clique. Além disso, o problema não é a falta de ferramentas, mas a necessidade de observar o resultado da ação já executada.','\n',char(10)),replace('Imagine que você está jogando um jogo no computador usando um robô que vê a tela. O robô clica em um botão "Jogar". O que ele precisa fazer depois?\n\n- **A** (contar tokens) seria como o robô contar quantas letras ele usou para clicar. Isso não diz se o jogo abriu ou não.\n- **B** (tirar uma nova foto da tela) é o certo! O robô precisa olhar a tela de novo para ver se o jogo abriu, se apareceu um menu, ou se nada aconteceu.\n- **C** (não precisa de nada) é errado porque o clique pode não funcionar ou pode abrir uma coisa diferente do esperado.\n- **D** (pedir ferramentas novas) não faz sentido — o robô já sabe clicar, ele só precisa ver o que aconteceu depois do clique.\n\nEntão, a resposta certa é **B**: o robô precisa de uma nova foto da tela para ver o resultado do clique.','\n',char(10)));
INSERT INTO cards VALUES('admin','card_1783092985710_wt00f33z5',181,'What does the "read before write" principle establish?',replace('What does the "read before write" principle establish?\n\nWhat does the "read before write" principle establish?\n[Resposta correta: Read before write exige ler o conteúdo atual antes de modificar. A inverte a ordem. C contraria diretamente o princípio. D confunde com routing.]\n\n[ ] A - Write first and read afterward to validate the result.\n[ ] B - Read the current content before modifying, to understand the structure and change it without breaking what exists.\n[ ] C - Never read files, just overwrite them.\n[ ] D - Classify the file into a category before editing.','\n',char(10)),'B - Read the current content before modifying, to understand the structure and change it without breaking what exists.','["Domain_2::Tool_Design_MCP_Integration", "Domain_3::Claude_Code_Configuration_Workflows", "Scenario_4::Developer_Productivity"]','New',0,2.5,0,1783092985710,1783725922458,1783203558653,replace('**Tradução para português do Brasil:**\n\n**Pergunta:** O que estabelece o princípio "read before write"?\n\n**Alternativas:**\n\n[ ] A - Escrever primeiro e ler depois para validar o resultado.\n[ ] B - Ler o conteúdo atual antes de modificar, para entender a estrutura e alterá-lo sem quebrar o que já existe.\n[ ] C - Nunca ler arquivos, apenas sobrescrevê-los.\n[ ] D - Classificar o arquivo em uma categoria antes de editá-lo.','\n',char(10)),replace('**Explicação técnica para um adulto tech lead:**\n\nO princípio "read before write" (ler antes de escrever) é uma prática fundamental em engenharia de software e manipulação de dados. Ele estabelece que, antes de modificar um arquivo, registro, recurso ou estado de um sistema, você deve primeiro ler o conteúdo atual para entender sua estrutura, contexto e dependências. Isso evita que alterações cegas quebrem funcionalidades existentes, introduzam inconsistências ou sobrescrevam dados importantes inadvertidamente.\n\n**Analisando as alternativas:**\n\n- **Alternativa B (correta):** Descreve exatamente o princípio. Ao ler antes de modificar, o desenvolvedor compreende a estrutura do que está sendo alterado, identifica possíveis armadilhas (ex.: dados sensíveis, formatação específica, dependências ocultas) e pode fazer a modificação de forma cirúrgica e segura.\n\n- **Alternativa A (incorreta):** Inverte a ordem do princípio. "Escrever primeiro e ler depois" é o oposto do que o "read before write" propõe. Fazer isso pode resultar em dados corrompidos, perda de informação ou sobrescrita acidental de alterações de terceiros.\n\n- **Alternativa C (incorreta):** Contradiz diretamente o princípio. "Nunca ler arquivos, apenas sobrescrevê-los" é uma abordagem destrutiva e negligente, especialmente em ambientes colaborativos ou com dados persistentes. Isso ignora completamente a necessidade de entender o estado atual antes de alterá-lo.\n\n- **Alternativa D (incorreta):** Confunde o princípio com uma etapa de classificação/categorização. "Classificar antes de editar" pode ser uma boa prática em certos contextos (ex.: organização de documentos), mas não é o que o "read before write" estabelece. O princípio é sobre leitura do conteúdo atual, não sobre categorização.','\n',char(10)),replace('**Explicação para uma criança de 10 anos:**\n\nImagine que você tem um desenho que seu amigo fez, e você quer pintar uma parte dele. O que você faz primeiro? Você olha o desenho para ver o que já está lá, certo? "Ler antes de escrever" é a mesma ideia, mas com arquivos no computador.\n\nO princípio diz: **antes de mexer em alguma coisa, dê uma olhada no que já existe para não estragar nada**. É como ler as instruções de um jogo antes de jogar, ou olhar para um bolo antes de cortar uma fatia — assim você não corta no lugar errado!\n\n- **Alternativa B (correta):** É exatamente isso: "olhe antes de mexer".\n- **Alternativa A:** Está ao contrário — seria "mexer primeiro e olhar depois", o que pode quebrar tudo.\n- **Alternativa C:** É tipo "nunca olhe o desenho, só pinte por cima". Ruim, né? Você pode pintar em cima de algo legal.\n- **Alternativa D:** Fala em classificar o arquivo, tipo colocar numa pasta. Isso é legal, mas não é a mesma coisa que ler antes de escrever.\n\nEntão, a resposta certa é a **B**: leia antes de modificar!','\n',char(10)));
INSERT INTO cards VALUES('admin','card_1783092985723_khp7rrf7y',182,'How do you guide an agent to inspect the environment in a complex video generation task?',replace('How do you guide an agent to inspect the environment in a complex video generation task?\n\nHow do you guide an agent to inspect the environment in a complex video generation task?\n[Resposta correta: As instruções de inspeção vão no system prompt, orientando o uso de ferramentas para observar o resultado e comparar com os requisitos. A e C não fornecem observação real do ambiente. D remove justamente os meios de inspecionar.]\n\n[ ] A - By increasing max_tokens so it generates more text.\n[ ] B - By instructing in the system prompt to use tools like whisper.cpp and FFmpeg to verify dialogue and images against the original requirements.\n[ ] C - By counting the tokens of each stage to infer success.\n[ ] D - By removing tools to reduce unpredictability.','\n',char(10)),'B - By instructing in the system prompt to use tools like whisper.cpp and FFmpeg to verify dialogue and images against the original requirements.','["Domain_2::Tool_Design_MCP_Integration", "Domain_4::Prompt_Engineering_Structured_Output", "Scenario_4::Developer_Productivity"]','New',0,2.5,0,1783092985723,1783725926632,1783203558653,replace('## Tradução (pt-BR)\n\n**Pergunta:** Como você orienta um agente a inspecionar o ambiente em uma tarefa complexa de geração de vídeo?\n\n**Alternativas:**\n\n[ ] A - Aumentando o max_tokens para que ele gere mais texto.\n[ ] B - Instruindo no system prompt o uso de ferramentas como whisper.cpp e FFmpeg para verificar diálogos e imagens em relação aos requisitos originais.\n[ ] C - Contando os tokens de cada etapa para inferir sucesso.\n[ ] D - Removendo ferramentas para reduzir imprevisibilidade.','\n',char(10)),replace('## Explicação para um Tech Lead\n\n### Resposta correta: B\n\n**Por que B é a resposta certa?**\n\nEm tarefas complexas de geração de vídeo, um agente precisa **inspecionar o ambiente** — ou seja, observar o estado real do que foi produzido e compará-lo com os requisitos. Isso vai além de simplesmente gerar saída textual; o agente precisa de meios concretos para verificar a qualidade e a conformidade do resultado.\n\nA alternativa B descreve exatamente essa abordagem: instruir o agente, via **system prompt**, a usar ferramentas especializadas como:\n\n- **whisper.cpp** (para transcrição e verificação de áudio/diálogos gerados)\n- **FFmpeg** (para inspecionar propriedades de vídeo, como resolução, codec, duração, quadros-chave, etc.)\n\nEssas ferramentas permitem que o agente **observe o ambiente real** (o vídeo gerado) e valide se ele atende aos critérios definidos. Isso é um exemplo clássico de **loop de feedback baseado em observação do ambiente**, um conceito central em sistemas de agentes e reinforcement learning.\n\n**Por que as demais alternativas estão erradas?**\n\n- **A** (aumentar max_tokens): Gerar mais texto não dá ao agente a capacidade de observar o ambiente. Isso apenas aumenta o espaço de saída textual, sem qualquer mecanismo de inspeção real.\n\n- **C** (contar tokens para inferir sucesso): A contagem de tokens é uma métrica superficial e não reflete a qualidade ou conformidade do vídeo gerado. Não há observação do ambiente — apenas uma heurística frágil e indireta.\n\n- **D** (remover ferramentas): Remover as ferramentas de inspeção **elimina justamente os meios que o agente tem para observar o ambiente**. Isso reduz o agente a um gerador cego, incapaz de verificar seu próprio trabalho, o que é o oposto do que se deseja.','\n',char(10)),replace('Imagine que você está desenhando um vídeo de um cachorro pulando. Você precisa **ver** se o cachorro realmente está pulando direito no desenho! Não adianta só escrever "o cachorro pulou" e esperar que esteja certo, né?\n\nEntão, a melhor maneira de fazer um robô (agente) verificar se o vídeo ficou bom é **dar a ele ferramentas para olhar o resultado**. Tipo:\n\n- Um microfone mágico (whisper.cpp) para ouvir o áudio e ver se o cachorro está latindo certo.\n- Uma lupa de vídeo (FFmpeg) para ver se a imagem está bonita e no tamanho certo.\n\nA alternativa **B** diz exatamente isso: ensinar o robô, no manual de instruções (system prompt), a usar essas ferramentas para conferir o trabalho.\n\nAs outras opções são ruins porque:\n\n- **A** — Só mandar o robô escrever mais texto não ajuda a ver o vídeo.\n- **C** — Contar letras (tokens) não diz se o desenho está bonito.\n- **D** — Tirar as ferramentas do robô é como tirar os olhos dele: ele não consegue mais ver se acertou ou errou!','\n',char(10)));
INSERT INTO cards VALUES('admin','card_1783092985736_h0dg9su9u',183,'Which question should guide the design of any agent?',replace('Which question should guide the design of any agent?\n\nWhich question should guide the design of any agent?\n[Resposta correta: A pergunta-guia é como Claude saberá se a ação funcionou, o que leva a fornecer meios de inspeção. A usa tokens, que não indicam sucesso. C é uma questão de routing. D impõe limite artificial de iterações.]\n\n[ ] A - "How many tokens will Claude spend on this action?"\n[ ] B - "How will Claude know whether this action worked?", ensuring means to observe results.\n[ ] C - "Which specialized pipeline should receive this input?"\n[ ] D - "How many iterations should the loop have at most?"','\n',char(10)),'[ ] B - "How will Claude know whether this action worked?", ensuring means to observe results.','["Domain_1::Agentic_Architecture_Orchestration", "Domain_2::Tool_Design_MCP_Integration", "Domain_5::Context_Management_Reliability", "Scenario_1::Customer_Support_Agent"]','New',0,2.5,0,1783092985736,1783725931103,1783203558653,replace('## Tradução (pt-BR)\n\n**Qual pergunta deve guiar o design de qualquer agente?**\n\n[ ] A - "Quantos tokens o Claude gastará nesta ação?"\n[ ] B - "Como o Claude saberá se esta ação funcionou?", garantindo meios para observar os resultados.\n[ ] C - "Qual pipeline especializado deve receber esta entrada?"\n[ ] D - "Quantas iterações o laço deve ter no máximo?"','\n',char(10)),replace('## Explicação Técnica (para Tech Lead)\n\nA resposta correta é a alternativa **B**.\n\n### Por que B está correta\n\nO design de agentes autônomos — especialmente sistemas baseados em LLMs como Claude que executam ações em um ambiente — deve ser orientado pela **capacidade de observação e feedback**. Sem uma forma confiável de o agente saber se uma ação teve sucesso ou falhou, o sistema opera "às cegas". A pergunta "Como o agente saberá se funcionou?" força o design a incluir:\n\n- Mecanismos de *observation* (retorno de estado, logs, saídas de ferramentas/APIs)\n- Caminhos de *feedback loop* que permitam ao agente ajustar comportamento com base em resultados reais\n- *Grounding* factual: o agente não "adivinha" se deu certo — ele *observa* (via tool use, leitura de arquivos, chamadas de API, etc.)\n\nIsso é fundamental em arquiteturas de agentes como ReAct, Plan-and-Execute, ou qualquer sistema que use tool calling com iterações.\n\n### Por que as demais estão erradas\n\n**A** — "Quantos tokens o Claude gastará?" é uma preocupação operacional de custo/eficiência, não uma questão de design funcional. O gasto de tokens é consequência do design, não seu guia. Um agente bem projetado pode gastar mais tokens para garantir observabilidade correta — o foco principal não deve ser minimizar tokens, mas sim garantir que as ações sejam verificáveis.\n\n**C** — "Qual pipeline especializado deve receber esta entrada?" é uma questão de **roteamento** (routing/orchestration), que surge DEPOIS que o design básico do agente está definido. É um detalhe de implementação da arquitetura de processamento, não a questão fundamental que guia o design do agente em si.\n\n**D** — "Quantas iterações o laço deve ter no máximo?" estabelece um limite artificial sem fundamento no comportamento real do agente. O número de iterações deve ser guiado pela conclusão da tarefa e pela observação de sucesso/falha, não por um número fixo arbitrário. É uma preocupação de *safety/guardrails*, não uma questão de design central.','\n',char(10)),replace('## Explicação para uma criança de 10 anos\n\nImagine que você está ensinando um robô a fazer café. Qual é a pergunta mais importante para construir esse robô?\n\n**Opção B é a certa** porque você precisa perguntar: "Como o robô vai saber se ele fez o café direito?" \n\nSe o robô aperta um botão e não consegue ver se o café saiu ou não, ele nunca vai aprender a fazer direito! Ele precisa de "olhos" — como uma câmera para ver se a xícara encheu, ou um sensor para saber se a água está quente.\n\n**Por que as outras opções não são tão boas?**\n\n- **Opção A** — "Quantas pilhas o robô vai gastar?" Isso é importante, mas não é a primeira coisa a pensar. Primeiro a gente faz o robô funcionar, depois vê quanto gasta.\n\n- **Opção C** — "Qual desenho do boneco deve receber esse comando?" Isso é sobre como organizar as partes do robô, não sobre o robô em si.\n\n- **Opção D** — "Quantas vezes o robô pode tentar?" Isso seria tipo dizer: "tente no máximo 3 vezes e depois desista". Mas e se ele quase acertou na quarta tentativa? Melhor deixar ele tentar até conseguir ou até perceber que não dá certo.\n\nEntão, a regra de ouro é: **Sempre pergunte como seu agente (robô, programa) vai saber se o que ele fez deu certo ou errado.**','\n',char(10)));
INSERT INTO cards VALUES('admin','card_1783092985749_ozlvkghc4',184,'Which architecture principle is behind the query duplication hook?',replace('Which architecture principle is behind the query duplication hook?\n\nWhich architecture principle is behind the query duplication hook?\n[Resposta correta: O hook usa instâncias separadas de Claude, uma revisando a outra, via Agent SDK. A, C e D descrevem outros mecanismos sem relação com a revisão por instância independente.]\n\n[ ] A - Reduce tokens by summarizing the conversation history.\n[ ] B - Use separate AI instances, one reviewing the work of the other via Agent SDK.\n[ ] C - Route the query to the cheapest pipeline.\n[ ] D - Run all tools in a single synchronous call.','\n',char(10)),'[ ] B - Use separate AI instances, one reviewing the work of the other via Agent SDK.','["Domain_1::Agentic_Architecture_Orchestration", "Domain_2::Tool_Design_MCP_Integration", "Scenario_5::Claude_Code_CI_CD"]','New',0,2.5,0,1783092985749,1783725934908,1783203558653,replace('**Tradução para português do Brasil:**\n\nQual princípio arquitetural está por trás do hook de duplicação de consultas?\n\n[ ] A - Reduzir tokens resumindo o histórico da conversa.\n[ ] B - Usar instâncias separadas de IA, uma revisando o trabalho da outra via Agent SDK.\n[ ] C - Roteirizar a consulta para o pipeline mais barato.\n[ ] D - Executar todas as ferramentas em uma única chamada síncrona.','\n',char(10)),replace('**Explicação para um adulto (tech lead):**\n\nA pergunta trata do **query duplication hook**, um padrão arquitetural que envolve duplicar uma consulta para submetê-la a múltiplas instâncias de avaliação, normalmente com o objetivo de aumentar a confiabilidade e reduzir alucinações (self-check / self-review pattern).\n\n**Alternativa correta: B**\n\nO princípio por trás do query duplication hook é justamente **utilizar instâncias separadas de IA (no caso, Claude) onde uma revisa o trabalho da outra**. Isso é comumente implementado via Agent SDK (como o Anthropic''s Agent SDK ou frameworks similares) e segue o padrão *"reviewer pattern"* ou *"multi-agent debate"*. A ideia é que uma instância gera uma resposta ou executa uma ação, e uma segunda instância (ou a mesma em um contexto isolado) revisa criticamente o resultado, identificando inconsistências, erros ou alucinações. Isso melhora a qualidade sem depender de fine-tuning.\n\n**Por que as demais estão incorretas:**\n\n- **A: Reduzir tokens resumindo o histórico** — Isso é uma técnica de compressão de contexto (summarization/truncation), não tem relação com o padrão de duplicação de consultas e revisão por instância separada. O hook de duplicação não visa redução de tokens; pelo contrário, aumenta o uso deles.\n\n- **C: Roteirizar a consulta para o pipeline mais barato** — Isso descreve um *router pattern* ou *least-cost routing*, onde a consulta é direcionada ao modelo/pipe mais econômico. É um padrão de otimização de custos, não de revisão arquitetural com duplicação.\n\n- **D: Executar todas as ferramentas em uma única chamada síncrona** — Isso é um padrão de execução monolítico (single synchronous call). O hook de duplicação, por natureza, envolve chamadas paralelas ou sequenciais entre instâncias, não uma única chamada fechada.','\n',char(10)),replace('Imagine que você está fazendo um dever de casa e, depois de terminar, pede para um amigo revisar suas respostas para ver se tem algum erro. O "query duplication hook" funciona mais ou menos assim: em vez de confiar em uma única resposta do robô (IA), a gente pede para **dois robôs diferentes** pensarem sobre a mesma pergunta, e um deles confere o trabalho do outro. Isso ajuda a achar erros, igual quando você e seu amigo se ajudam no dever de casa.\n\nA alternativa **B** diz exatamente isso: usar instâncias separadas de IA (como dois Claudes diferentes), onde um revisa o que o outro fez.\n\nAs outras opções estão erradas porque:\n- **A** fala em resumir o histórico — é como fazer um resumo da aula, não tem a ver com revisão.\n- **C** fala em escolher o caminho mais barato — é como pegar o ônibus mais barato, sem ninguém revisando nada.\n- **D** fala em fazer tudo de uma vez só — é como tentar responder todas as perguntas da prova sem parar para conferir nenhuma.','\n',char(10)));
INSERT INTO cards VALUES('admin','card_1783092985762_d3lwws9ox',185,'When does the SubagentStop hook fire?',replace('When does the SubagentStop hook fire?\n\nWhen does the SubagentStop hook fire?\n[Resposta correta: SubagentStop dispara quando o subagente (a Task na UI) termina. A confunde com o fim da conversa principal. C dispararia a cada tool, o que não é o gatilho. D usa tokens, que não são o critério.]\n\n[ ] A - When the main conversation ends.\n[ ] B - When a subagent, shown as a "Task" in the UI, finishes executing.\n[ ] C - Every time the agentic loop runs a tool.\n[ ] D - When the subagent''s token count reaches a limit.','\n',char(10)),'B - When a subagent, shown as a "Task" in the UI, finishes executing.','["Domain_1::Agentic_Architecture_Orchestration", "Domain_2::Tool_Design_MCP_Integration", "Scenario_1::Customer_Support_Agent"]','New',0,2.5,0,1783092985762,1783725938723,1783203558653,replace('**Tradução para português do Brasil:**\n\nPergunta: Quando o hook SubagentStop é disparado?\n\n[ ] A - Quando a conversa principal termina.\n[ ] B - Quando um subagente, exibido como "Tarefa" na interface do usuário, termina sua execução.\n[ ] C - Toda vez que o loop agentic executa uma ferramenta.\n[ ] D - Quando a contagem de tokens do subagente atinge um limite.','\n',char(10)),replace('**Explicação didática para um adulto tech lead:**\n\nO hook **SubagentStop** é um evento específico do ciclo de vida de um agente em sistemas que suportam execução hierárquica de agentes (subagentes). Ele é projetado para disparar **exatamente quando um subagente conclui sua execução**, não em outros momentos do pipeline.\n\n**Por que B está correta:**\nA alternativa B descreve precisamente o gatilho: a finalização de um subagente, que na interface do usuário é representado como uma "Task". Isso está alinhado com a semântica de hooks em frameworks agenticos (ex.: Amazon Bedrock Agents, LangGraph, CrewAI, etc.), onde SubagentStop é um callback pós-execução do subagente.\n\n**Análise das incorretas:**\n- **A** (Quando a conversa principal termina): confunde SubagentStop com um hook de término da sessão principal (ex.: SessionEnd, ConversationEnd). SubagentStop é específico do subagente, não da conversa raiz.\n- **C** (Toda vez que o loop agentic executa uma ferramenta): descreve um hook de tool execution (ex.: ToolStart, ToolEnd), não um hook de subagente. São eventos ortogonais.\n- **D** (Quando a contagem de tokens do subagente atinge um limite): refere-se a um mecanismo de truncamento ou limite de contexto, que pode disparar um evento diferente (ex.: TokenLimitReached), mas não o SubagentStop propriamente dito.','\n',char(10)),'Imagine que você tem um robô-chefe que resolve problemas grandes. Às vezes ele chama um robô-ajudante para fazer uma parte do trabalho. O "SubagentStop" é como um alarme que toca assim que o robô-ajudante termina a tarefa dele. Não toca quando o robô-chefe termina tudo (isso é outro alarme), nem quando o robô-ajudante usa uma ferramenta (cada ferramenta usada tem seu próprio alarme), e nem quando o robô-ajudante fica sem energia (isso também é outro alarme). O alarme certo toca só no momento certo: quando o robô-ajudante entrega o resultado e diz "pronto, terminei!".');
INSERT INTO cards VALUES('admin','card_1783092985775_0xd8ghpik',186,'What is the Agent SDK and in which languages is it available?',replace('What is the Agent SDK and in which languages is it available?\n\nWhat is the Agent SDK and in which languages is it available?\n[Resposta correta: O Agent SDK roda o Claude Code programaticamente com o mesmo agent loop, em TypeScript e Python. A limita a Python e ao modo interativo. C confunde com a Message Batches API. D descreve algo que não é o SDK.]\n\n[ ] A - A CLI that only runs interactively, available only in Python.\n[ ] B - A way to run Claude Code programmatically with the same agent loop as the CLI, available in TypeScript and Python.\n[ ] C - An asynchronous batch API, available only in TypeScript.\n[ ] D - A pipeline router, available in any language.','\n',char(10)),'B - A way to run Claude Code programmatically with the same agent loop as the CLI, available in TypeScript and Python.','["ForaDosDominios", "ForaDoCenario"]','New',0,2.5,0,1783092985775,1783725942230,1783203558653,replace('**Tradução para português do Brasil:**\n\nO que é o Agent SDK e em quais linguagens ele está disponível?\n\n[ ] A - Uma CLI que executa apenas de forma interativa, disponível apenas em Python.\n[ ] B - Uma forma de executar o Claude Code programaticamente com o mesmo loop de agente da CLI, disponível em TypeScript e Python.\n[ ] C - Uma API de lote assíncrona, disponível apenas em TypeScript.\n[ ] D - Um roteador de pipeline, disponível em qualquer linguagem.','\n',char(10)),replace('**Explicação didática para um adulto tech lead:**\n\nA pergunta trata do **Agent SDK**, um componente do ecossistema Claude/Anthropic que permite executar o Claude Code programaticamente. A alternativa correta é a **B**.\n\n**Por que a alternativa B está correta:**\n\nO Agent SDK foi projetado para expor o mesmo "agent loop" que o Claude Code CLI utiliza internamente, mas de forma que desenvolvedores possam incorporá-lo diretamente em suas aplicações via código. Ele está disponível em **TypeScript e Python** — as duas linguagens nativas do ecossistema Anthropic para interação programática com Claude (via `@anthropic-ai/sdk` e `anthropic`).\n\n**Análise das alternativas incorretas:**\n\n- **Alternativa A** — "Uma CLI que executa apenas de forma interativa, disponível apenas em Python." Essa descrição confunde o Agent SDK com o Claude Code CLI. A CLI de fato pode rodar interativamente, mas ela é uma ferramenta separada do SDK. Além disso, o SDK não se limita a Python; ele também está disponível em TypeScript.\n\n- **Alternativa C** — "Uma API de lote assíncrona, disponível apenas em TypeScript." Isso descreve a **Message Batches API** (que permite enviar lotes de requisições de forma assíncrona), não o Agent SDK. O SDK não é focado em processamento em lote e está disponível em Python também.\n\n- **Alternativa D** — "Um roteador de pipeline, disponível em qualquer linguagem." Essa é uma descrição genérica e incorreta. O Agent SDK não é um roteador de pipeline, e sua disponibilidade é restrita às bibliotecas oficiais (TypeScript e Python), não sendo acessível em "qualquer linguagem" sem adaptações não oficiais.','\n',char(10)),replace('Imagine que você tem um robô chamado Claude que sabe fazer várias tarefas. O Claude Code é como usar esse robô digitando comandos no terminal — você conversa com ele linha por linha.\n\nO **Agent SDK** é como um "controle remoto programável" para esse robô. Em vez de você digitar comandos manualmente, você pode escrever um programa (em TypeScript ou Python) que diz ao robô o que fazer, e ele executa exatamente as mesmas ações que faria se você estivesse digitando.\n\nAgora vamos ver as opções:\n\n- **A** está errada porque diz que é uma "CLI que só roda de forma interativa e só em Python". Na verdade, o SDK não é uma CLI (tela de comando) — é uma biblioteca de código. E funciona tanto em Python quanto em TypeScript.\n\n- **B** está certa! Ela diz exatamente o que é: um jeito de rodar o Claude Code pelo código, com o mesmo mecanismo que a CLI usa, disponível em TypeScript e Python.\n\n- **C** está errada porque descreve algo que manda várias mensagens de uma vez (lote) e só em TypeScript. O SDK não é isso, e funciona também em Python.\n\n- **D** está errada porque diz que é um "roteador de pipeline" (como um semáforo que direciona o tráfego) e que funciona em qualquer linguagem. Não é nada disso — ele só existe em TypeScript e Python.','\n',char(10)));
INSERT INTO cards VALUES('admin','card_1783092985787_04q3h3gak',187,'What is the correct Agent SDK package and the common gotcha?',replace('What is the correct Agent SDK package and the common gotcha?\n\nWhat is the correct Agent SDK package and the common gotcha?\n[Resposta correta: O pacote é @anthropic-ai/claude-agent-sdk, e a pegadinha é confundir com @anthropic-ai/claude-code, que é o CLI e não é importável. A cai exatamente na pegadinha. C e D inventam nomes de pacote.]\n\n[ ] A - @anthropic-ai/claude-code, which is the importable SDK package.\n[ ] B - @anthropic-ai/claude-agent-sdk, remembering that @anthropic-ai/claude-code is the CLI and cannot be imported.\n[ ] C - @anthropic-ai/agent, available only in Python.\n[ ] D - claude-sdk, which replaces the CLI.','\n',char(10)),'B - @anthropic-ai/claude-agent-sdk, remembering that @anthropic-ai/claude-code is the CLI and cannot be imported.','["ForaDosDominios", "ForaDoCenario"]','New',0,2.5,0,1783092985787,1783725945638,1783203558653,replace('**Tradução para português do Brasil:**\n\nPergunta: Qual é o pacote correto do Agent SDK e qual é a pegadinha comum?\n\nAlternativas:\n\n[ ] A - @anthropic-ai/claude-code, que é o pacote SDK importável.\n[ ] B - @anthropic-ai/claude-agent-sdk, lembrando que @anthropic-ai/claude-code é o CLI e não pode ser importado.\n[ ] C - @anthropic-ai/agent, disponível apenas em Python.\n[ ] D - claude-sdk, que substitui o CLI.','\n',char(10)),replace('**Explicação para um adulto (tech lead):**\n\nA resposta correta é a alternativa B.\n\n**Análise da resposta correta (B):** O pacote oficial do Agent SDK para JavaScript/TypeScript é `@anthropic-ai/claude-agent-sdk`. A pegadinha mencionada é que muitas pessoas confundem esse pacote com `@anthropic-ai/claude-code`, que é o *command-line interface* (CLI) da Anthropic — uma ferramenta executável, não uma biblioteca que você importa no código. Tentar fazer `import ... from ''@anthropic-ai/claude-code''` resultará em erro, pois esse pacote não foi feito para ser usado como dependência programática.\n\n**Por que as demais estão erradas:**\n\n- **A - `@anthropic-ai/claude-code`**: Afirma que este é o pacote SDK importável, o que é falso. Como explicado, trata-se do CLI, não de uma biblioteca para código.\n- **C - `@anthropic-ai/agent`**: Este nome de pacote não existe no ecossistema oficial da Anthropic para Agent SDK. Além disso, a afirmação de que estaria "disponível apenas em Python" é incorreta — o Agent SDK oficial tem suporte a JavaScript/TypeScript.\n- **D - `claude-sdk`**: Este não é o nome oficial do pacote. Também sugere incorretamente que ele "substitui o CLI", o que não procede — CLI e SDK são ferramentas com propósitos distintos e coexistem.','\n',char(10)),replace('Imagine que você tem dois brinquedos diferentes: um é um **carrinho de controle remoto** (o SDK, que você usa para programar e construir coisas), e o outro é um **controle remoto que já vem pronto para brincar** (o CLI, que você usa direto no computador, sem programar).\n\nA pegadinha é que as pessoas confundem o nome dos dois. O carrinho (SDK) se chama **@anthropic-ai/claude-agent-sdk** — é ele que você coloca no seu projeto para programar. Já o controle remoto (CLI) se chama **@anthropic-ai/claude-code** — ele serve para usar no terminal, mas não dá para colocar dentro do seu código.\n\nSe você tentar importar o controle remoto achando que é o carrinho, não vai funcionar! É como tentar colocar a pilha do controle dentro do carrinho — as peças não encaixam.\n\nAs outras opções (C e D) são nomes inventados, como se alguém dissesse que o carrinho se chama "Foguete Voador". Não existe esse nome no universo dos brinquedos da Anthropic.','\n',char(10)));
INSERT INTO cards VALUES('admin','card_1783092985799_9cu6wrskn',188,'Besides the basic query example, what does the Agent SDK support?',replace('Besides the basic query example, what does the Agent SDK support?\n\nBesides the basic query example, what does the Agent SDK support?\n[Resposta correta: O SDK suporta tudo o que o CLI faz, incluindo hooks, subagentes e session resumption. A subestima suas capacidades. C e D descrevem funcionalidades que não são o escopo do SDK.]\n\n[ ] A - Only simple query calls, without hooks or subagents.\n[ ] B - Everything the CLI does: custom system prompts, MCP servers, hooks, subagents and session resumption.\n[ ] C - Only asynchronous batch execution.\n[ ] D - Only pipeline routing by category.','\n',char(10)),'B - Everything the CLI does: custom system prompts, MCP servers, hooks, subagents and session resumption.','["Domain_2::Tool_Design_MCP_Integration", "Domain_1::Agentic_Architecture_Orchestration", "Domain_3::Claude_Code_Configuration_Workflows", "Scenario_4::Developer_Productivity"]','New',0,2.5,0,1783092985799,1783725949633,1783203558653,replace('**Tradução para português do Brasil:**\n\n**Pergunta:** Além do exemplo básico de consulta, o que o Agent SDK suporta?\n\n[ ] A - Apenas chamadas de consulta simples, sem hooks ou subagentes.\n[ ] B - Tudo o que o CLI faz: prompts de sistema personalizados, servidores MCP, hooks, subagentes e retomada de sessão.\n[ ] C - Apenas execução em lote assíncrona.\n[ ] D - Apenas roteamento de pipeline por categoria.','\n',char(10)),replace('**Explicação para um adulto tech lead:**\n\nA alternativa **B** é a correta porque o Agent SDK foi projetado para ser um superset funcional do CLI (Command Line Interface). Isso significa que tudo que pode ser feito via CLI também pode ser feito programaticamente via SDK, incluindo:\n\n- **Custom system prompts**: personalização do comportamento do agente via instruções de sistema.\n- **MCP servers (Model Context Protocol)**: integração com servidores externos que fornecem contexto ou ferramentas.\n- **Hooks**: pontos de extensão para interceptar e modificar o fluxo de execução (antes/depois de chamadas, tratamento de erros, etc.).\n- **Subagentes**: capacidade de delegar subtarefas a outros agentes especializados dentro de uma mesma execução.\n- **Session resumption**: habilidade de retomar sessões interrompidas, preservando estado e contexto.\n\n**Análise das alternativas incorretas:**\n\n- **A**: Incorreta porque o SDK suporta *muito mais* do que consultas simples. Ela subestima severamente as capacidades do SDK, ignorando hooks, subagentes, MCP servers e outros recursos.\n\n- **C**: Incorreta porque "execução em lote assíncrona" é apenas um dos possíveis modos de operação, não o escopo completo do SDK. O SDK oferece execução síncrona, streaming, hooks, sessões interativas etc.\n\n- **D**: Incorreta porque "roteamento de pipeline por categoria" se refere a um padrão de arquitetura específico para sistemas de classificação/fila, que não é o foco principal nem o escopo definido do Agent SDK. O SDK é um framework agnóstico para construção de agentes, não um sistema de roteamento de pipelines.','\n',char(10)),replace('**Explicação para uma criança de 10 anos:**\n\nImagine que você tem um robô ajudante que pode fazer várias tarefas. O CLI é como um controle remoto que você usa para dar comandos para o robô. O SDK é como um conjunto de peças de Lego que permite construir robôs ainda mais legais, que fazem tudo que o controle remoto faz e muito mais!\n\nA resposta certa é a **B** porque o SDK não serve só para perguntas simples (como "que horas são?"). Ele também permite:\n\n- **Dar instruções especiais** para o robô (prompts personalizados) — como dizer "seja educado" ou "responda em inglês".\n- **Conectar o robô a outros sistemas** (servidores MCP) — como dar a ele acesso a uma calculadora ou a um dicionário.\n- **Criar "gatilhos"** (hooks) — como programar o robô para avisar você sempre que terminar uma tarefa.\n- **Criar sub-robôs** (subagentes) — como ensinar um robô a pedir ajuda para outro robô especialista em matemática.\n- **Lembrar do que aconteceu antes** (retomada de sessão) — como um jogo que salva seu progresso e você pode continuar de onde parou.\n\nAs outras opções estão erradas:\n- **A** diz que o SDK só faz consultas simples, mas ele faz muito mais coisas legais.\n- **C** diz que o SDK só serve para rodar coisas em lote (como fazer várias tarefas de uma vez), mas ele também faz tarefas uma por uma.\n- **D** diz que o SDK só organiza tarefas por categoria, mas isso é só uma das muitas coisas que ele pode fazer.','\n',char(10)));
INSERT INTO cards VALUES('admin','card_1783092985812_olm51et1h',189,'You want to programmatically orchestrate a flow in which one instance of Claude reviews the work of another.',replace('You want to programmatically orchestrate a flow in which one instance of Claude reviews the work of another.\n\nYou want to programmatically orchestrate a flow in which one instance of Claude reviews the work of another. Which tool should you use?\n[Resposta correta: O Agent SDK orquestra instâncias, como o hook de duplicação faz. A não serve a revisão iterativa entre instâncias. B cai na pegadinha do CLI não importável. D não orquestra revisão por instância separada.]\n\n[ ] A - The Message Batches API, because it is asynchronous.\n[ ] B - The @anthropic-ai/claude-code CLI imported as a library.\n[ ] C - The Agent SDK (@anthropic-ai/claude-agent-sdk), as in the duplication hook that launches a reviewing instance.\n[ ] D - A routing workflow that classifies the query.','\n',char(10)),'C - The Agent SDK (@anthropic-ai/claude-agent-sdk), as in the duplication hook that launches a reviewing instance.','["Domain_1::Agentic_Architecture_Orchestration", "Domain_2::Tool_Design_MCP_Integration", "Scenario_4::Developer_Productivity"]','New',0,2.5,0,1783092985812,1783725953788,1783203558653,replace('**Tradução para pt-BR:**\n\nVocê quer orquestrar programaticamente um fluxo no qual uma instância do Claude revisa o trabalho de outra. Qual ferramenta você deve usar?\n\n[ ] A - A API de Lotes de Mensagens (Message Batches API), porque é assíncrona.\n[ ] B - O CLI @anthropic-ai/claude-code importado como biblioteca.\n[ ] C - O Agent SDK (@anthropic-ai/claude-agent-sdk), como no hook de duplicação que lança uma instância revisora.\n[ ] D - Um workflow de roteamento que classifica a consulta.','\n',char(10)),replace('**Explicação didática para um adulto tech lead:**\n\nA pergunta pede uma ferramenta que permita orquestrar programaticamente um fluxo no qual uma instância do Claude revisa o trabalho de outra. Isso exige coordenação entre múltiplas instâncias (não apenas chamadas paralelas ou assíncronas).\n\n- **Alternativa A (Message Batches API)** está incorreta. A API de Lotes de Mensagens é voltada para envio de lotes de requisições independentes e assíncronas. Ela não oferece suporte a revisão iterativa entre instâncias — ou seja, não há mecanismo para que uma instância receba o output de outra e o avalie de forma estruturada.\n\n- **Alternativa B (CLI importado como biblioteca)** é uma pegadinha comum. O `@anthropic-ai/claude-code` é uma CLI (Command Line Interface), não uma biblioteca projetada para ser importada e usada programaticamente dentro de código. Mesmo que seja tecnicamente possível invocar um CLI via subprocess, isso não é a forma correta nem recomendada de orquestrar fluxos de revisão entre instâncias.\n\n- **Alternativa C (Agent SDK - @anthropic-ai/claude-agent-sdk)** é a correta. O Agent SDK foi projetado para orquestrar agentes e fluxos multi-instância. O hook de duplicação (duplication hook) é um exemplo documentado onde uma instância do Claude pode lançar outra instância revisora programaticamente. Isso permite o ciclo de "gerar → revisar → iterar" de forma nativa e controlada.\n\n- **Alternativa D (Routing workflow que classifica a consulta)** está incorreta. Workflows de roteamento são usados para classificar e direcionar requisições para diferentes handlers ou modelos com base no tipo de consulta. Não há orquestração de revisão entre instâncias separadas — o foco é encaminhamento, não iteração revisora.\n\n**Resumo técnico:** Para cenários de revisão entre agentes, você precisa de um SDK que suporte hooks e encadeamento de instâncias. O Agent SDK é a ferramenta adequada, pois oferece hooks como o de duplicação que permitem que uma instância crie e coordene outra para fins de revisão.','\n',char(10)),replace('Imagine que você está escrevendo uma redação e pede para um amigo revisar o que você escreveu, e depois você pode conversar com ele sobre os erros. Agora imagine que você quer que um robô chamado Claude escreva algo e outro robô Claude revise. Para isso, você precisa de uma ferramenta especial que deixe os dois robôs conversarem entre si.\n\nA ferramenta certa é a da letra **C**, o "Agent SDK". Ele funciona como um "chefe" que diz para um Claude: "Escreva isso", e depois diz para outro Claude: "Agora revise o que o primeiro escreveu". Ele tem um recurso chamado "hook de duplicação" que cria uma cópia do Claude só para revisar.\n\nAs outras opções são como ferramentas erradas:\n- A opção A (Message Batches) é como jogar várias cartas no correio de uma vez — cada uma vai por conta própria, sem conversar entre si.\n- A opção B (CLI) é uma tentativa de usar um programa que não foi feito para ser "chamado" por dentro de outro código — é como tentar usar um martelo para apertar um parafuso.\n- A opção D (Routing workflow) é como um porteiro que só classifica e encaminha as pessoas para salas diferentes, mas não faz ninguém revisar o trabalho de ninguém.\n\nEntão, para ter dois Cloades trabalhando juntos — um escrevendo e outro revisando — use o Agent SDK (letra C)!','\n',char(10)));
INSERT INTO cards VALUES('admin','card_1783092985826_b7ufxnhgv',190,'What is the context difference between skills and subagents?',replace('What is the context difference between skills and subagents?\n\nWhat is the context difference between skills and subagents?\n[Resposta correta: Skills atuam no contexto atual, subagents rodam isolados. A inverte os papéis. C e D uniformizam os dois, ignorando que um compartilha e o outro isola o contexto.]\n\n[ ] A - Skills run in an isolated context; subagents add knowledge to the current conversation.\n[ ] B - Skills add knowledge to the current conversation; subagents run in an isolated context and return results.\n[ ] C - Both always run in the same shared context.\n[ ] D - Both always run in separate isolated contexts.','\n',char(10)),'[ ] B - Skills add knowledge to the current conversation; subagents run in an isolated context and return results.','["Domain_1::Agentic_Architecture_Orchestration", "Domain_3::Claude_Code_Configuration_Workflows", "Scenario_2::Code_Generation_Claude_Code"]','New',0,2.5,0,1783092985826,1783725957589,1783203558653,replace('**Tradução para português do Brasil:**\n\nQual é a diferença de contexto entre skills e subagentes?\n\n[ ] A - Skills rodam em um contexto isolado; subagentes adicionam conhecimento à conversa atual.\n[ ] B - Skills adicionam conhecimento à conversa atual; subagentes rodam em um contexto isolado e retornam resultados.\n[ ] C - Ambos sempre rodam no mesmo contexto compartilhado.\n[ ] D - Ambos sempre rodam em contextos isolados separados.','\n',char(10)),replace('**Explicação didática para um adulto tech lead:**\n\nA questão aborda um conceito fundamental em arquiteturas de agentes de IA: o gerenciamento de contexto entre skills (habilidades/funções do agente principal) e subagentes (agentes filhos ou subordinados).\n\n**Resposta correta: B**\n\n**Por que a B está correta:**\n- **Skills** são extensões ou capacidades do agente principal. Quando uma skill é invocada, ela opera **dentro do contexto atual da conversa** — isto é, ela enxerga e contribui para o histórico de mensagens, variáveis de estado e informações já presentes. Uma skill tipicamente adiciona conhecimento, processa dados ou executa uma ação e insere o resultado de volta no fluxo da conversa.\n- **Subagentes**, por outro lado, são agentes separados que podem ser invocados para executar tarefas de forma **isolada**. Eles recebem um contexto (geralmente uma instrução e alguns dados iniciais), executam seu trabalho em um ambiente próprio e retornam o resultado ao agente chamador. Eles **não compartilham** o contexto da conversa principal durante a execução — o que evita poluição do contexto e efeitos colaterais.\n\n**Por que as demais estão incorretas:**\n- **A**: Inverte os papéis — afirma que skills rodam em contexto isolado e subagentes adicionam conhecimento à conversa, o que é o oposto do comportamento esperado.\n- **C**: Ignora a diferença fundamental. Ambos **não** rodam sempre no mesmo contexto compartilhado; subagentes foram projetados justamente para isolar contexto.\n- **D**: Também ignora a diferença. Skills **não** rodam em contextos isolados separados; elas operam no contexto atual do agente principal.\n\nEssa distinção é crucial em sistemas multiagentes (como AutoGPT, CrewAI, LangGraph, etc.), onde o isolamento de contexto evita que subagentes interfiram no estado da conversa principal, enquanto skills permitem extensão direta e imediata das capacidades do agente.','\n',char(10)),replace('**Explicação para uma criança de 10 anos:**\n\nImagina que você tem um robô assistente chamado Rob. Ele pode fazer várias coisas legais para te ajudar!\n\n**Skills** são como **truques que o próprio Rob sabe fazer**. Por exemplo, se você pede: "Rob, calcula quanto é 25 + 17", ele usa uma skill de calculadora. A skill funciona **dentro da conversa** com o Rob — ele vê tudo que vocês estão conversando e responde ali mesmo, como se fosse uma extensão dele.\n\n**Subagentes** são como **mini-robôs ajudantes** que o Rob pode chamar para fazer tarefas separadas. Imagine que você pede: "Rob, pesquisa sobre dinossauros e desenha um". Rob pode chamar um mini-robô que pesquisa e outro mini-robô que desenha. Esses mini-robôs **trabalham no cantinho deles, sozinhos**, e depois trazem o resultado de volta. Eles não ficam vendo toda a conversa que você tem com o Rob.\n\nEntão a resposta certa é a **B**: Skills ficam na conversa com você, e subagentes trabalham isoladinhos e depois voltam com o resultado.\n\nAs outras alternativas estão erradas porque:\n- A: inverte — diz que skills trabalham sozinhas e subagentes na conversa (é o contrário!)\n- C: diz que os dois são iguais, compartilhando tudo — mas subagentes não compartilham\n- D: diz que os dois trabalham separados — mas skills trabalham junto com a conversa','\n',char(10)));
INSERT INTO cards VALUES('admin','card_1783092985854_uv186mtue',191,'You want to delegate a task to a separate execution context, with different tooling from the main one.',replace('You want to delegate a task to a separate execution context, with different tooling from the main one.\n\nYou want to delegate a task to a separate execution context, with different tooling from the main one. Skill or subagent?\n[Resposta correta: O isolamento com tooling próprio é papel do subagent. A e C confundem, pois a skill atua no contexto atual e não isola. D não se aplica ao caso de delegação isolada.]\n\n[ ] A - Skill, because it adds expertise to the current context.\n[ ] B - Subagent, because it provides isolation and its own context and tooling for the delegated work.\n[ ] C - Skill, because it runs in isolation.\n[ ] D - Neither, because this requires a routing workflow.','\n',char(10)),'B - Subagent, because it provides isolation and its own context and tooling for the delegated work.','["Domain_1::Agentic_Architecture_Orchestration", "Domain_2::Tool_Design_MCP_Integration", "Scenario_3::Multi_Agent_Research"]','New',0,2.5,0,1783092985854,1783725961636,1783203558653,replace('**Tradução para português do Brasil:**\n\nVocê quer delegar uma tarefa para um contexto de execução separado, com ferramentas diferentes das do contexto principal. Skill ou subagent?\n\n[ ] A - Skill, porque adiciona expertise ao contexto atual.\n[ ] B - Subagent, porque fornece isolamento e seu próprio contexto e ferramentas para o trabalho delegado.\n[ ] C - Skill, porque executa em isolamento.\n[ ] D - Nenhum dos dois, porque isso requer um workflow de roteamento.','\n',char(10)),replace('**Explicação para um adulto tech lead:**\n\nA pergunta aborda um conceito arquitetural importante em sistemas multiagente: a diferença entre **skills** (habilidades) e **subagents** (subagentes) no que diz respeito ao isolamento de contexto e ferramentas.\n\nA alternativa **B** é a correta porque um *subagent* é projetado exatamente para isso: ele recebe uma tarefa e executa em seu próprio contexto isolado, com seu próprio conjunto de ferramentas (tooling), memória e estado. Isso é essencial quando você quer evitar contaminação entre contextos, permitir que o subagente tenha acesso a ferramentas específicas que o agente principal não deveria ter, ou simplesmente organizar a arquitetura de forma mais modular.\n\nPor que as demais estão erradas:\n\n- **A (Skill) está incorreta** porque uma skill é uma capacidade ou conhecimento que é adicionado ao contexto do agente principal. Ela não cria um novo contexto de execução isolado; ela estende o existente. A descrição "adiciona expertise ao contexto atual" é precisamente o oposto do que foi pedido (delegação para um contexto separado).\n\n- **C (Skill) está incorreta** porque afirma que skill "executa em isolamento", o que é falso. Skills operam dentro do contexto do agente que as invoca, compartilhando seu estado e ferramentas. Elas não fornecem isolamento.\n\n- **D (Nenhum dos dois) está incorreta** porque a situação descrita é exatamente o caso de uso de um subagent. Um workflow de roteamento (routing workflow) é um padrão diferente, geralmente usado para decidir qual caminho seguir com base em uma condição, não para delegar tarefas com isolamento de contexto e ferramentas.','\n',char(10)),replace('Imagine que você é um aluno fazendo um trabalho em grupo na escola. Você tem um colega (o agente principal) que sabe usar lápis e borracha. Agora, você precisa de alguém para fazer um desenho bem detalhado usando canetinhas coloridas e régua, em outra mesa, para não misturar os materiais.\n\n- **Skill** seria como ensinar seu colega a usar canetinhas também — ele continua na mesma mesa, usando os mesmos materiais, só que aprendeu uma coisa nova.\n- **Subagent** seria como chamar um outro colega (o subagente) que vai para outra mesa, pega as canetinhas e a régua dele, faz o desenho separado e depois te entrega pronto.\n\nA pergunta quer algo que funcione **separado**, com ferramentas **diferentes** do contexto principal. Por isso, a resposta certa é o **subagent (alternativa B)** — ele é como o colega que vai para a outra mesa com seus próprios materiais.\n\nAs outras alternativas estão erradas: a A diz que skill adiciona conhecimento ao contexto atual (não isola), a C diz que skill executa em isolamento (mentira, skill não isola), e a D diz que nenhum dos dois serve, mas na verdade o subagent serve perfeitamente para isso.','\n',char(10)));
INSERT INTO cards VALUES('admin','card_1783092985867_t9tm5m5lw',192,'You want to enrich Claude''s knowledge for the current task, applicable throughout the conversation.',replace('You want to enrich Claude''s knowledge for the current task, applicable throughout the conversation.\n\nYou want to enrich Claude''s knowledge for the current task, applicable throughout the conversation. Skill or subagent?\n[Resposta correta: A skill adiciona expertise ao contexto atual, sem isolamento. A e C descrevem o subagent, que isola e não é o que se quer aqui. D não corresponde ao caso.]\n\n[ ] A - Subagent, because it isolates the execution context.\n[ ] B - Skill, because it adds expertise to the current context without creating an isolated execution.\n[ ] C - Subagent, because it returns only a summary.\n[ ] D - Neither, because this requires an agent with an open-ended goal.','\n',char(10)),'[ ] B - Skill, because it adds expertise to the current context without creating an isolated execution.','["Domain_1::Agentic_Architecture_Orchestration", "Domain_2::Tool_Design_MCP_Integration", "Scenario_4::Developer_Productivity"]','New',0,2.5,0,1783092985867,1783725965667,1783203558653,replace('**Tradução:**\n\nVocê quer enriquecer o conhecimento do Claude para a tarefa atual, aplicável durante toda a conversa. Skill ou subagent?\n\n[ ] A - Subagent, porque ele isola o contexto de execução.\n[ ] B - Skill, porque ela adiciona expertise ao contexto atual sem criar uma execução isolada.\n[ ] C - Subagent, porque ele retorna apenas um resumo.\n[ ] D - Nenhum dos dois, porque isso requer um agente com um objetivo aberto (open-ended).','\n',char(10)),replace('**Explicação para um adulto tech lead:**\n\nA pergunta descreve um cenário onde se deseja *enriquecer o conhecimento do Claude para a tarefa atual*, de forma que esse conhecimento fique disponível *durante toda a conversa*.\n\n**Por que B é a resposta correta:**\n\nUma **skill** (ou "habilidade") no contexto do Claude (especialmente considerando a arquitetura de ferramentas e skills do Anthropic) é um mecanismo que adiciona contexto, expertise ou instruções ao prompt do modelo de forma transparente. Ela não isola a execução — pelo contrário, ela enriquece o contexto atual, tornando aquele conhecimento disponível para o resto da conversa. É exatamente o que o enunciado descreve: enriquecer o conhecimento para a tarefa atual, de forma aplicável durante toda a conversa.\n\n**Por que as demais estão erradas:**\n\n- **A** descreve um **subagent**, que isola o contexto de execução. Subagents são projetados para executar tarefas em um ambiente separado, com seu próprio contexto, e retornar um resultado. Isso é o oposto do que se deseja, que é enriquecer o contexto *atual*.\n\n- **C** também descreve um subagent, mas com uma motivação incorreta ("retorna apenas um resumo"). Subagents podem retornar mais que um resumo, e o ponto central não é o formato da resposta, mas o isolamento do contexto.\n\n- **D** está incorreta porque um agente com objetivo aberto (open-ended goal) é algo diferente — seria um agente autônomo que decide como proceder. A necessidade descrita no enunciado é perfeitamente atendida por uma skill, não requer um agente mais complexo.\n\nPortanto, a alternativa B é a correta: skill adiciona expertise ao contexto atual sem isolamento, que é exatamente o que o cenário pede.','\n',char(10)),replace('Imagine que você está conversando com o Claude e quer que ele saiba de algo especial durante toda a conversa — como se você desse a ele uma "cola" ou um "lembrete" que fica o tempo todo na mesa.\n\nUma **skill** é como dar um livro de consulta para o Claude. Ele coloca o livro do lado e pode usá-lo a qualquer momento durante a conversa. O livro fica ali, disponível.\n\nJá um **subagent** é como mandar o Claude para outra sala fazer uma pesquisa separada, sozinho, e depois ele volta e te conta o que descobriu. Ele fica isolado fazendo a tarefa, e você só vê o resultado no final.\n\nA pergunta diz: "Queremos enriquecer o conhecimento do Claude para a tarefa atual, que dure a conversa toda". Isso é como dar o livro de consulta para ele — ou seja, uma **skill**!\n\nAs outras opções:\n- A e C falam do subagent (aquele que vai para outra sala) — não é o que queremos.\n- D diz que não é nenhum dos dois, mas está errada, porque a skill resolve perfeitamente.\n\nResposta correta: **B**.','\n',char(10)));
INSERT INTO cards VALUES('admin','card_1783092985881_oicib1qoa',193,'True or false: subagents automatically see your skills.',replace('True or false: subagents automatically see your skills.\n\nTrue or false: subagents automatically see your skills. Which statement is correct?\n[Resposta correta: Subagents começam com contexto limpo e não veem as skills automaticamente. A e C assumem herança ou visibilidade global que não existe. D restringe indevidamente, pois o comportamento vale para subagents em geral.]\n\n[ ] A - True, because subagents inherit the entire context of the main conversation.\n[ ] B - False, because subagents start with a fresh, clean context and do not see the skills automatically.\n[ ] C - True, because skills are global and always visible.\n[ ] D - False, but only for built-in subagents, not for custom ones.','\n',char(10)),'B - False, because subagents start with a fresh, clean context and do not see the skills automatically.','["Domain_1::Agentic_Architecture_Orchestration", "Domain_5::Context_Management_Reliability", "Scenario_3::Multi_Agent_Research"]','New',0,2.5,0,1783092985881,1783725969580,1783203558653,replace('**Tradução para português do Brasil:**\n\nVerdadeiro ou falso: subagentes enxergam suas skills automaticamente.\n\nVerdadeiro ou falso: subagentes enxergam suas skills automaticamente. Qual afirmação está correta?\n\n[ ] A - Verdadeiro, porque subagentes herdam todo o contexto da conversa principal.\n[ ] B - Falso, porque subagentes começam com um contexto limpo e não veem as skills automaticamente.\n[ ] C - Verdadeiro, porque skills são globais e sempre visíveis.\n[ ] D - Falso, mas apenas para subagentes embutidos (built-in), não para os personalizados.','\n',char(10)),replace('**Explicação para um adulto tech lead:**\n\nA resposta correta é a **alternativa B**.\n\nSubagentes são instâncias autônomas que não compartilham automaticamente o contexto completo da conversa principal. Isso significa que eles não herdam skills definidas no escopo do agente pai. Cada subagente inicia com um contexto "limpo" (fresh, clean context), o que é um comportamento esperado em arquiteturas de agentes modulares para evitar vazamento de dependências não explícitas.\n\nPor que as demais alternativas estão incorretas:\n\n- **Alternativa A**: Assume herança automática de contexto, o que não é verdade. Subagentes não herdam skills ou contexto do agente pai a menos que sejam explicitamente passados.\n- **Alternativa C**: Afirma que skills são globais e sempre visíveis. Skills não são automaticamente globais — elas são associadas a escopos específicos (como o agente principal) e não são transferidas para subagentes.\n- **Alternativa D**: Tenta fazer uma distinção entre subagentes "built-in" e "custom" que não procede. A regra geral é que subagentes — independentemente de sua origem — começam com contexto limpo e não veem as skills automaticamente.','\n',char(10)),replace('**Explicação para uma criança de 10 anos:**\n\nImagine que você tem uma mochila com vários itens legais (suas "skills"). Você cria um robô ajudante (um "subagente") para fazer uma tarefa. Será que esse robô já nasce sabendo tudo que você sabe e vendo todos os itens da sua mochila? Não! Ele começa com a mochila vazia.\n\nÉ isso que a alternativa B está dizendo: o subagente **não vê** suas skills automaticamente. Ele começa do zero, com a "mochila limpa".\n\nAs outras alternativas estão erradas porque:\n- A diz que o robô herda tudo — mas não é verdade, ele não ganha nada de graça.\n- C diz que as skills são visíveis para todo mundo sempre — também não é assim.\n- D diz que só alguns robôs especiais não veem as skills, mas outros veem — a regra vale para todos os robôs.','\n',char(10)));
INSERT INTO cards VALUES('admin','card_1783092985896_u1siai7ex',194,'Which agents can have preloaded skills?',replace('Which agents can have preloaded skills?\n\nWhich agents can have preloaded skills?\n[Resposta correta: Somente subagents customizados, com as skills no frontmatter, têm pré-carregamento. A inclui indevidamente os built-in, que não suportam pré-carregamento (apenas execução via context: fork). C inverte e D nega o recurso.]\n\n[ ] A - All agents, including the built-in Explore and Plan.\n[ ] B - Only custom subagents in .claude/agents, with the skills listed in the skills field of the frontmatter.\n[ ] C - Only built-in agents, never the custom ones.\n[ ] D - No agent can have preloaded skills.','\n',char(10)),'B - Only custom subagents in .claude/agents, with the skills listed in the skills field of the frontmatter.','["Domain_3::Claude_Code_Configuration_Workflows", "Domain_2::Tool_Design_MCP_Integration", "Scenario_2::Code_Generation_Claude_Code"]','New',0,2.5,0,1783092985896,1783725973685,1783203558653,replace('**Tradução da pergunta e alternativas:**\n\n**Pergunta:** Quais agentes podem ter habilidades pré-carregadas?\n\n[ ] A - Todos os agentes, incluindo os built-in Explore e Plan.\n[ ] B - Apenas subagentes customizados em .claude/agents, com as habilidades listadas no campo skills do frontmatter.\n[ ] C - Apenas agentes built-in, nunca os customizados.\n[ ] D - Nenhum agente pode ter habilidades pré-carregadas.','\n',char(10)),replace('**Explicação para um adulto (tech lead):**\n\nA resposta correta é a **alternativa B**.\n\nNo ecossistema Claude (especificamente no claude.ai e no contexto de agentes/ferramentas), o conceito de "preloaded skills" (habilidades pré-carregadas) se refere à capacidade de um agente já iniciar sua execução com um conjunto de instruções ou capacidades já carregadas em memória, sem precisar ser explicitamente invocado com um fork.\n\n**Por que a B está correta:**\nApenas subagentes customizados, definidos no diretório `.claude/agents/` com um arquivo de frontmatter (metadados em YAML), suportam o campo `skills`. Esse campo permite listar skills que serão carregadas automaticamente quando o agente for ativado. Esse é o único mecanismo de pré-carregamento de skills disponível atualmente.\n\n**Análise das alternativas incorretas:**\n\n- **Alternativa A ("All agents, including the built-in Explore and Plan"):** Incorreta. Agentes built-in como "Explore" e "Plan" não suportam pré-carregamento de skills. Eles só executam skills quando invocados via `context: fork` com instruções explícitas. Não há mecanismo de frontmatter ou campo `skills` neles.\n\n- **Alternativa C ("Only built-in agents, never the custom ones"):** Incorreta. É o oposto do que ocorre. Os built-in agents não têm pré-carregamento; os customizados sim.\n\n- **Alternativa D ("No agent can have preloaded skills"):** Incorreta. O recurso existe e é justamente a funcionalidade descrita na alternativa B. Negar a existência do recurso é factualmente errado.','\n',char(10)),replace('**Explicação para uma criança de 10 anos:**\n\nImagine que você tem dois tipos de robôs: os robôs que já vêm prontos de fábrica (os "built-in", como o Explore e o Plan) e os robôs que você mesmo monta e programa em casa (os "customizados").\n\nA pergunta é: quais robôs podem ter uma "mochila" cheia de ferramentas já prontas para usar assim que são ligados?\n\nA resposta certa é a letra **B**: só os robôs que você mesmo cria (os customizados) podem vir com a mochila de ferramentas já arrumada. Você coloca as ferramentas numa lista (o "frontmatter") e, quando liga o robô, elas já estão lá.\n\nOs robôs de fábrica (Explore e Plan) não vêm com mochila pronta — eles só pegam ferramentas se alguém pedir bem explicadinho na hora. E dizer que "nenhum robô pode ter mochila" também está errado, porque os customizados podem sim!','\n',char(10)));
INSERT INTO cards VALUES('admin','card_1783092985909_z7w9gm4po',195,'How do you make a custom subagent use specific skills?',replace('How do you make a custom subagent use specific skills?\n\nHow do you make a custom subagent use specific skills?\n[Resposta correta: Basta listar as skills no campo skills do frontmatter em .claude/agents. A ignora que o carregamento ocorre no início, não sob demanda. C não afeta o subagent. D é falso, pois subagents não veem as skills automaticamente.]\n\n[ ] A - Call the skills dynamically during execution, without prior configuration.\n[ ] B - Add the skills field in the frontmatter of the agent file in .claude/agents, listing the skills.\n[ ] C - Put the skills in the system prompt of the main conversation.\n[ ] D - Nothing is needed, because subagents see all skills automatically.','\n',char(10)),'B - Add the skills field in the frontmatter of the agent file in .claude/agents, listing the skills.','["Domain_3::Claude_Code_Configuration_Workflows", "Domain_1::Agentic_Architecture_Orchestration", "Scenario_4::Developer_Productivity"]','New',0,2.5,0,1783092985909,1783725977759,1783203558653,replace('**Tradução fiel para pt-BR:**\n\n**Pergunta:** Como fazer um subagente personalizado usar habilidades específicas?\n\n[ ] A - Chamar as habilidades dinamicamente durante a execução, sem configuração prévia.\n[ ] B - Adicionar o campo "skills" no frontmatter do arquivo do agente em .claude/agents, listando as habilidades.\n[ ] C - Colocar as habilidades no prompt do sistema da conversa principal.\n[ ] D - Não é necessário nada, porque subagentes veem todas as habilidades automaticamente.','\n',char(10)),replace('**Explicação para um adulto (tech lead):**\n\n**Resposta correta: B**\n\nA alternativa B é a única que reflete corretamente o mecanismo de configuração de subagentes no ecossistema Claude. Subagentes são definidos por meio de arquivos Markdown com frontmatter YAML dentro do diretório `.claude/agents`. O campo `skills` no frontmatter é o local designado para declarar quais habilidades (skills) aquele subagente específico deve carregar e ter disponível durante sua execução.\n\n**Por que as demais alternativas estão incorretas:**\n\n- **Alternativa A** ("Chamar as habilidades dinamicamente durante a execução, sem configuração prévia"): Incorreta. As habilidades precisam ser declaradas estaticamente no frontmatter. O carregamento ocorre no momento da inicialização do subagente, não sob demanda durante a execução. Não é possível invocar uma skill que não foi previamente carregada.\n\n- **Alternativa C** ("Colocar as habilidades no prompt do sistema da conversa principal"): Incorreta. O system prompt da conversa principal não influencia o carregamento de skills de um subagente. Cada subagente possui seu próprio contexto e configuração independentes.\n\n- **Alternativa D** ("Não é necessário nada, porque subagentes veem todas as habilidades automaticamente"): Incorreta. Subagentes não herdam automaticamente todas as skills disponíveis no sistema. Pelo contrário, o design é explícito e intencional: você precisa listar exatamente quais skills o subagente deve ter acesso, garantindo controle granular sobre o comportamento e as capacidades de cada subagente.','\n',char(10)),replace('**Explicação para uma criança de 10 anos:**\n\nImagine que você tem um videogame onde pode criar personagens ajudantes (subagentes). Cada ajudante pode ter poderes especiais (skills), como "saber matemática" ou "falar outro idioma".\n\nA pergunta é: como você faz para que um ajudante específico tenha os poderes que você quer?\n\nA resposta certa é a **B**: Você escreve, num arquivo de configuração do seu ajudante, uma lista dizendo quais poderes ele vai ter. É como criar a ficha do personagem: você anota lá "esse personagem sabe voar e tem super-força".\n\nPor que as outras opções estão erradas?\n\n- **A**: Diz que você pode chamar os poderes durante o jogo, sem preparar nada. Não funciona — você precisa configurar antes, igual carregar o personagem antes de jogar.\n- **C**: Diz para colocar os poderes no manual do jogo principal. Mas cada ajudante tem seu próprio manual, então não adianta.\n- **D**: Diz que todo ajudante já vê todos os poderes automaticamente. Isso não é verdade — cada ajudante só tem os poderes que você colocar na ficha dele.','\n',char(10)));
INSERT INTO cards VALUES('admin','card_1783092985922_o8lismfcf',196,'When are the skills listed for a custom subagent loaded?',replace('When are the skills listed for a custom subagent loaded?\n\nWhen are the skills listed for a custom subagent loaded?\n[Resposta correta: As skills são carregadas quando o subagent inicia, não sob demanda. A confunde com o comportamento da conversa principal. C inventa um gatilho do coordenador. D nega o recurso que existe para subagents customizados.]\n\n[ ] A - On demand during execution, as in the main conversation.\n[ ] B - At the moment the subagent starts.\n[ ] C - Only when the coordinator explicitly requests it.\n[ ] D - Never, because subagents do not support skills.','\n',char(10)),'B - At the moment the subagent starts.','["Domain_1::Agentic_Architecture_Orchestration", "Domain_2::Tool_Design_MCP_Integration", "Scenario_3::Multi_Agent_Research"]','New',0,2.5,0,1783092985922,1783725981595,1783203558653,replace('**Tradução para português do Brasil:**\n\n**Quando as skills listadas para um subagent customizado são carregadas?**\n\n[ ] A - Sob demanda durante a execução, como na conversa principal.\n[ ] B - No momento em que o subagent inicia.\n[ ] C - Apenas quando o coordenador solicita explicitamente.\n[ ] D - Nunca, porque subagents não suportam skills.','\n',char(10)),replace('**Explicação para um adulto tech lead:**\n\nA pergunta trata do ciclo de vida de skills em subagents customizados em uma plataforma de agentes de IA (como a Amazon Bedrock Agents ou similar).\n\n**Resposta correta: B — No momento em que o subagent inicia.**\n\nSubagents customizados possuem seu próprio conjunto de skills (ou action groups) que são carregados e inicializados assim que o subagent é ativado/iniciado. Esse comportamento é diferente da conversa principal, onde as skills podem ser resolvidas sob demanda durante a execução. No caso do subagent, ao ser invocado pelo coordenador, ele carrega todas as skills definidas em sua configuração no momento da inicialização, garantindo que esteja pronto para processar as requisições delegadas a ele.\n\n**Por que as demais estão incorretas:**\n\n- **Alternativa A (Sob demanda):** Esse é o comportamento típico da conversa principal (agente raiz), onde as skills são resolvidas dinamicamente conforme a necessidade. Para subagents, o carregamento é feito na inicialização, não sob demanda.\n\n- **Alternativa C (Apenas quando o coordenador solicita):** O coordenador pode invocar o subagent, mas o carregamento das skills ocorre como parte do ciclo de inicialização do subagent, não como um evento separado disparado pelo coordenador. O coordenador não faz uma "solicitação explícita de skills".\n\n- **Alternativa D (Nunca):** Subagents customizados suportam sim skills. Essa alternativa nega um recurso que existe, portanto está incorreta.','\n',char(10)),replace('**Explicação para uma criança de 10 anos:**\n\nImagine que você tem um robô ajudante (o subagent) e ele vem com algumas ferramentas especiais na mochila (as skills).\n\nA pergunta é: quando ele pega essas ferramentas da mochila?\n\nA resposta certa é: **assim que ele liga/começa a funcionar** (alternativa B). Ou seja, ele já prepara tudo no começo.\n\nAs outras opções estão erradas porque:\n- A) Diz que ele pega as ferramentas só quando precisa usar — mas não, ele já pega tudo quando liga.\n- C) Diz que ele só pega as ferramentas se o chefe dele mandar — mas ele já faz isso sozinho quando liga.\n- D) Diz que ele nem tem ferramentas — mas ele tem sim!','\n',char(10)));
INSERT INTO cards VALUES('admin','card_1783092985935_ozv4cvpkf',197,'What is the prerequisite for listing a skill in the skills field of a subagent?',replace('What is the prerequisite for listing a skill in the skills field of a subagent?\n\nWhat is the prerequisite for listing a skill in the skills field of a subagent?\n[Resposta correta: A skill precisa existir em .claude/skills antes de ser listada. A inventa um requisito de MCP remoto. C cria uma dependência inexistente. D ignora que a skill precisa existir para ser carregada.]\n\n[ ] A - The skill must be published on a remote MCP server.\n[ ] B - The skill must already exist in the .claude/skills directory before being listed.\n[ ] C - The skill must have been used before in the main conversation.\n[ ] D - No prerequisite, just write the name in the frontmatter.','\n',char(10)),'B - The skill must already exist in the .claude/skills directory before being listed.','["Domain_3::Claude_Code_Configuration_Workflows", "Domain_2::Tool_Design_MCP_Integration", "Scenario_2::Code_Generation_Claude_Code"]','New',0,2.5,0,1783092985935,1783725985812,1783203558653,replace('**Tradução para português do Brasil:**\n\n**Pergunta:** Qual é o pré-requisito para listar uma habilidade no campo "skills" de um subagente?\n\n[ ] A - A habilidade deve ser publicada em um servidor MCP remoto.\n[ ] B - A habilidade já deve existir no diretório .claude/skills antes de ser listada.\n[ ] C - A habilidade deve ter sido usada antes na conversa principal.\n[ ] D - Nenhum pré-requisito, basta escrever o nome no frontmatter.','\n',char(10)),replace('**Explicação para adulto tech lead:**\n\nA alternativa correta é a **B**.\n\nA resposta correta (B) reflete o funcionamento real do mecanismo de skills em subagentes (ou agentes filhos) em sistemas como o Claude Agents SDK ou frameworks similares que utilizam a estrutura `.claude/skills`. Nesses sistemas, o diretório `.claude/skills` funciona como um registro local de habilidades disponíveis. Quando um subagente é configurado, seu campo `skills` faz referência a arquivos de definição de skill que precisam existir fisicamente nesse diretório. Isso é análogo a um sistema de importação de módulos: você só pode importar o que está instalado/disponível no sistema de arquivos.\n\n**Análise das alternativas incorretas:**\n\n- **Alternativa A** está incorreta porque skills não precisam ser publicadas em servidores MCP remotos para serem utilizadas localmente. MCP (Model Context Protocol) é um protocolo opcional para expor ferramentas/skills remotamente, mas não é um requisito obrigatório. A alternativa inventa uma dependência de infraestrutura externa que não é necessária.\n\n- **Alternativa C** está incorreta porque a skill não precisa ter sido "usada antes" na conversa principal. O subagente carrega a skill a partir da definição no arquivo, independentemente de uso prévio. Essa alternativa cria uma dependência de estado de conversa que não existe na arquitetura do sistema. Skills são carregadas estaticamente com base na configuração do subagente, não dinamicamente com base em histórico de uso.\n\n- **Alternativa D** está incorreta porque simplesmente "escrever o nome no frontmatter" sem que a skill exista fisicamente no diretório resultará em erro de carregamento. O frontmatter (metadados YAML) do subagente referencia skills, mas não as cria automaticamente. A skill precisa existir como um arquivo válido no diretório `.claude/skills` para que o sistema consiga carregar e executar suas definições.','\n',char(10)),replace('**Explicação para criança de 10 anos:**\n\nImagine que você tem uma caixa de ferramentas (a pasta `.claude/skills`). Dentro dela, você guarda ferramentas como martelo, chave de fenda e alicate.\n\nAgora, você quer dar uma dessas ferramentas para seu amigo (o subagente) usar. Você só pode entregar para ele uma ferramenta que já está dentro da sua caixa, certo? Se você disser "Pega o martelo!" mas o martelo não estiver na caixa, não tem como ele pegar.\n\nÉ exatamente isso que a pergunta está falando! A alternativa **B** está certa porque você precisa ter a "habilidade" (skill) já guardada na pasta `.claude/skills` antes de dizer que o subagente pode usá-la.\n\nAs outras alternativas estão erradas:\n\n- **A** está errada porque você não precisa publicar a ferramenta na internet para poder usá-la localmente.\n- **C** está errada porque você não precisa ter usado a ferramenta antes para poder dar ela para alguém usar.\n- **D** está errada porque não adianta só falar o nome da ferramenta se ela não existir de verdade na caixa!','\n',char(10)));
INSERT INTO cards VALUES('admin','card_1783092985949_paovbkfji',198,'How do you run Claude Code in non-interactive mode inside a CI/CD pipeline?',replace('How do you run Claude Code in non-interactive mode inside a CI/CD pipeline?\n\nHow do you run Claude Code in non-interactive mode inside a CI/CD pipeline?\n[Resposta correta: A flag -p (ou --print) é o modo headless correto. A e B são features inventadas, exatamente as pegadinhas a evitar. D não é execução não interativa de fato.]\n\n[ ] A - Set the environment variable CLAUDE_HEADLESS=1.\n[ ] B - Use the --batch flag for automated execution.\n[ ] C - Use the -p (or --print) flag, which processes the prompt, sends the output to stdout and exits without waiting for input.\n[ ] D - Run the CLI normally and answer the prompts via a keyboard script.','\n',char(10)),'C - Use the -p (or --print) flag, which processes the prompt, sends the output to stdout and exits without waiting for input.','["Domain_3::Claude_Code_Configuration_Workflows", "Domain_4::Prompt_Engineering_Structured_Output", "Scenario_5::Claude_Code_CI_CD"]','New',0,2.5,0,1783092985949,1783725989426,1783203558653,replace('**Tradução para português do Brasil:**\n\nPergunta: Como executar o Claude Code em modo não interativo dentro de um pipeline CI/CD?\n\nAlternativas:\n[ ] A - Definir a variável de ambiente CLAUDE_HEADLESS=1.\n[ ] B - Usar a flag --batch para execução automatizada.\n[ ] C - Usar a flag -p (ou --print), que processa o prompt, envia a saída para o stdout e encerra sem aguardar entrada.\n[ ] D - Executar a CLI normalmente e responder aos prompts via um script de teclado.','\n',char(10)),replace('**Explicação para adulto (tech lead):**\n\nA alternativa **C** é a correta. O Claude Code oferece a flag `-p` (ou `--print`) justamente para cenários de automação e CI/CD. Quando usada, a ferramenta processa o prompt fornecido, envia o resultado diretamente para a saída padrão (stdout) e encerra imediatamente, sem entrar no modo interativo de shell. Isso é essencial para pipelines, onde não há um terminal interativo disponível nem um operador humano para responder a prompts.\n\n**Por que as demais estão incorretas:**\n\n- **A** - `CLAUDE_HEADLESS=1` não é uma variável de ambiente reconhecida pelo Claude Code. É uma invenção que não corresponde a nenhuma funcionalidade real da ferramenta. Usar variáveis inexistentes pode levar a falsas expectativas de funcionamento.\n\n- **B** - A flag `--batch` não existe na CLI do Claude Code. É outra pegadinha. O Claude Code não possui esse parâmetro; a abordagem correta para execução em lote (batch) é justamente o uso da flag `-p`/`--print`.\n\n- **D** - Embora tecnicamente funcione em alguns cenários, esta abordagem é frágil e anti-padrão. Responder prompts via script de teclado (como `expect` ou redirecionamento de entrada) é propenso a erros de timing, mudanças no fluxo de saída e quebras quando a interface é atualizada. Não é uma solução robusta para CI/CD, além de não ser o modo "não interativo" real, já que simula interatividade.','\n',char(10)),replace('Imagine que o Claude Code é um robô assistente que você pode conversar no terminal. Normalmente, ele fica esperando você digitar comandos, como um bate-papo.\n\nAgora, em um pipeline CI/CD (que é como uma esteira de fábrica que constroi e testa software automaticamente), o robô não pode ficar esperando alguém digitar coisas — ele precisa trabalhar sozinho e terminar rápido.\n\nA alternativa C diz para usar a flag `-p` (que é como dar um "comando especial"). Com isso, você fala o que quer de uma vez, o robô faz o serviço, mostra o resultado na tela e para de funcionar. Pronto, trabalho feito!\n\nAs outras opções estão erradas porque:\n- A e B usam nomes de comandos que não existem — é como tentar ligar um videogame apertando um botão que não existe no controle.\n- D seria chato e arriscado, como tentar enganar o robô fazendo ele pensar que alguém está digitando coisas, mas usando um fantoche. Se algo der errado no meio do caminho, tudo quebra.','\n',char(10)));
INSERT INTO cards VALUES('admin','card_1783092985962_y7rlat20n',199,'When is it appropriate to use the Message Batches API instead of synchronous calls?',replace('When is it appropriate to use the Message Batches API instead of synchronous calls?\n\nWhen is it appropriate to use the Message Batches API instead of synchronous calls?\n[Resposta correta: O batch serve a cargas tolerantes a latência, com economia de 50% e até 24h sem SLA. A e C usam batch em tarefas que bloqueiam o usuário ou exigem tempo real, onde ele não cabe. D ignora a ausência de garantia de latência.]\n\n[ ] A - For pre-merge checks that block the user, because the savings make the wait worthwhile.\n[ ] B - For latency-tolerant jobs, like nightly reports, with 50% savings and up to 24h of asynchronous processing.\n[ ] C - For real-time responses, because batch guarantees low latency.\n[ ] D - Always, because batch is cheaper and faster than synchronous calls.','\n',char(10)),'B - For latency-tolerant jobs, like nightly reports, with 50% savings and up to 24h of asynchronous processing.','["Domain_5::Context_Management_Reliability", "ForaDoCenario"]','New',0,2.5,0,1783092985962,1783725993739,1783203558653,replace('**Tradução para português do Brasil:**\n\nQuando é apropriado usar a API Message Batches em vez de chamadas síncronas?\n\n[ ] A - Para verificações pré-merge que bloqueiam o usuário, porque a economia torna a espera válida.\n[ ] B - Para tarefas tolerantes a latência, como relatórios noturnos, com 50% de economia e até 24h de processamento assíncrono.\n[ ] C - Para respostas em tempo real, porque o batch garante baixa latência.\n[ ] D - Sempre, porque batch é mais barato e mais rápido que chamadas síncronas.','\n',char(10)),replace('**Explicação didática para um adulto tech lead:**\n\nA alternativa correta é a **B**.\n\nA Message Batches API foi projetada para cenários onde a latência não é crítica. Ela oferece um desconto de 50% sobre o custo das chamadas síncronas em troca de maior latência — o processamento pode levar até 24 horas e não há SLA (Acordo de Nível de Serviço) garantindo tempo de resposta. Isso a torna ideal para workloads batch (em lote), como geração de relatórios noturnos, processamento de dados em background, ou qualquer tarefa onde o resultado não é esperado imediatamente pelo usuário.\n\n**Por que as demais alternativas estão incorretas:**\n\n- **A**: Colocar verificações pré-merge que bloqueiam o usuário (ex.: CI/CD) em batch é problemático. O desenvolvedor fica impedido de prosseguir até que o resultado retorne. Como batch não tem garantia de latência (pode levar minutos ou horas), isso prejudica a produtividade e a experiência do desenvolvedor. Economia de custo não justifica bloquear o fluxo de trabalho.\n\n- **C**: O batch **não** garante baixa latência. Pelo contrário, ele intencionalmente sacrifica latência para reduzir custos. Usá-lo para respostas em tempo real quebrada o requisito fundamental da aplicação.\n\n- **D**: Batch não é mais rápido que chamadas síncronas. Ele é mais barato (50% de economia), porém **mais lento** (até 24h). A afirmação de que é "mais barato e mais rápido" é factualmente incorreta.\n\n**Resumo técnico:** Use batch para workloads assíncronos e tolerantes a latência. Use chamadas síncronas (ou streaming) quando precisar de resposta imediata.','\n',char(10)),replace('**Explicação para uma criança de 10 anos:**\n\nImagine que você tem duas formas de comprar figurinhas para seu álbum:\n\n1. **Chamada síncrona** (comum): Você vai na lojinha, compra e ganha as figurinhas na hora. Rápido, mas você paga o preço normal.\n2. **Message Batches API** (em lote): Você envia uma lista do que quer e espera até 24 horas para receber tudo. Demora mais, mas você paga metade do preço!\n\nA pergunta é: quando usar o segundo método?\n\n**Resposta certa**: Quando você **não tem pressa**! Por exemplo, se você quer preparar figurinhas para trocar amanhã na escola — pode esperar e economizar dinheiro. É o caso dos "relatórios noturnos": tarefas que rodam de madrugada, quando ninguém está esperando o resultado na hora.\n\n**Respostas erradas:**\n\n- **A**: Usar o método demorado para algo que **bloqueia** você (tipo, você só pode brincar depois de receber as figurinhas). Não faz sentido — você ficaria parado esperando!\n- **C**: Dizer que o método em lote é **rápido**. Não é! Ele foi feito para ser devagar e barato.\n- **D**: Dizer que é **sempre** melhor. Mentira! Se você precisa das figurinhas agora, não adianta esperar 24 horas, por mais barato que seja.\n\n**Resumindo**: Use o batch quando você pode esperar. Use o síncrono quando precisa na hora.','\n',char(10)));
INSERT INTO cards VALUES('admin','card_1783092985976_eyyqxynsk',200,'The agent loses depth when processing many items at once.',replace('The agent loses depth when processing many items at once.\n\nThe agent loses depth when processing many items at once. How do you improve the quality of the analysis?\n[Resposta correta: A decomposição em passes focados preserva profundidade consistente. A cai na pegadinha de achar que mais contexto resolve a diluição de atenção. C perde informação e D agrava o problema de "lost in the middle".]\n\n[ ] A - Increase the context window to fit all items together.\n[ ] B - Decompose into focused passes, analyzing each file individually and then a separate integration pass.\n[ ] C - Reduce the number of items by discarding part of them.\n[ ] D - Concatenate everything into a single larger prompt.','\n',char(10)),'B - Decompose into focused passes, analyzing each file individually and then a separate integration pass.','["Domain_1::Agentic_Architecture_Orchestration", "Domain_5::Context_Management_Reliability", "Scenario_3::Multi_Agent_Research"]','New',0,2.5,0,1783092985976,1783725997760,1783203558653,replace('**Tradução para português do Brasil:**\n\n**Pergunta:** O agente perde profundidade ao processar muitos itens de uma vez. Como você melhora a qualidade da análise?\n\n**Alternativas:**\n[ ] A - Aumentar a janela de contexto para encaixar todos os itens juntos.\n[ ] B - Decompor em passes focados, analisando cada arquivo individualmente e depois um passe de integração separado.\n[ ] C - Reduzir o número de itens descartando parte deles.\n[ ] D - Concatenar tudo em um único prompt maior.','\n',char(10)),replace('**Explicação para um adulto tech lead:**\n\n**A alternativa correta é a B.** O problema descrito é um fenômeno bem conhecido em modelos de linguagem de larga escala (LLMs), frequentemente chamado de *"lost in the middle"* ou diluição de atenção. Quando muitos itens são processados simultaneamente, a capacidade do modelo de manter a profundidade e a coerência da análise se degrada — a atenção do modelo se espalha por muitos elementos, reduzindo a qualidade do raciocínio sobre cada um.\n\n**Por que B é a resposta correta:**\nA decomposição em passes focados (primeiro analisar cada arquivo individualmente, depois um passe de integração) resolve o problema porque:\n- Cada arquivo recebe atenção total do modelo, sem competição de outros itens.\n- O passe de integração opera sobre análises já refinadas, e não sobre dados brutos, reduzindo a carga cognitiva do modelo.\n- Essa abordagem é análoga ao padrão de design "divide and conquer" e é uma técnica consagrada em engenharia de prompts (ex: "chain of thought" com decomposição, map-reduce de prompts).\n\n**Por que as demais estão erradas:**\n\n- **A (Aumentar a janela de contexto):** A pegadinha clássica. Aumentar a janela de contexto não resolve a diluição de atenção — na verdade, pode piorá-la, pois o modelo precisa distribuir sua atenção por um espaço ainda maior. Modelos com janelas maiores ainda sofrem do efeito "lost in the middle", onde informações no meio do contexto são subrepresentadas. Mais contexto não é sinônimo de melhor compreensão.\n\n- **C (Reduzir o número de itens descartando parte deles):** Isso resolve o problema superficialmente, mas joga informação valiosa fora. Em cenários reais (ex: análise de código, revisão de documentos), descartar dados significa perder insights críticos. É uma solução que sacrifica completude por simplicidade.\n\n- **D (Concatenar tudo em um único prompt maior):** Essa alternativa agrava o problema de "lost in the middle". Quanto maior o prompt único, maior a chance de o modelo perder informações no meio do texto. É essencialmente o mesmo erro de A, mas sem nem tentar aumentar o limite — é simplesmente jogar tudo junto sem estratégia alguma.','\n',char(10)),replace('**Explicação para uma criança de 10 anos:**\n\nImagina que você tem 10 amigos falando com você ao mesmo tempo. Você consegue prestar atenção em cada um? Não, né? Você vai ouvir um pouco de cada, mas não vai entender direito o que ninguém disse. É a mesma coisa com o robô de inteligência artificial — quando a gente joga muitas informações de uma vez, ele fica confuso e "perde a profundidade", ou seja, não consegue pensar direito sobre cada pedaço.\n\nAgora, como a gente resolve isso?\n\n**Alternativa A** (aumentar o espaço) seria tipo colocar mais amigos na sala. Isso não ajuda — só piora!\n\n**Alternativa B** (a melhor escolha) é tipo chamar cada amigo separadamente para conversar, ouvir um de cada vez, e depois juntar tudo que aprendeu. Assim você entende cada um direitinho e depois monta a história completa. Essa é a maneira certa!\n\n**Alternativa C** (jogar alguns amigos fora) resolve, mas é injusto — você perde coisas importantes que eles poderiam ter dito.\n\n**Alternativa D** (juntar tudo num textão só) é como juntar todos os amigos falando ao mesmo tempo num megafone. Pior ainda, porque a confusão fica maior.\n\nEntão, a resposta certa é a B: conversar com cada um separado e depois juntar as ideias!','\n',char(10)));
INSERT INTO cards VALUES('admin','card_1783092986007_8d8ls7bqy',201,'In a multiagent system, entire domains are missing from the final result.',replace('In a multiagent system, entire domains are missing from the final result.\n\nIn a multiagent system, entire domains are missing from the final result. What is the most likely root cause?\n[Resposta correta: A causa raiz costuma ser a decomposição estreita do coordenador. A pegadinha em A é culpar subagentes que executaram corretamente o escopo dado. C e D atribuem a fatores técnicos que não são o problema de escopo.]\n\n[ ] A - The subagents executed the assigned tasks incorrectly.\n[ ] B - The coordinator''s task decomposition was too narrow and did not cover all domains.\n[ ] C - The subagents'' context window was small.\n[ ] D - The model used had too few parameters.','\n',char(10)),'B - The coordinator''s task decomposition was too narrow and did not cover all domains.','["Domain_1::Agentic_Architecture_Orchestration", "Domain_4::Prompt_Engineering_Structured_Output", "Scenario_3::Multi_Agent_Research"]','New',0,2.5,0,1783092986007,1783726001660,1783203558653,replace('**Tradução para português do Brasil:**\n\nEm um sistema multiagente, domínios inteiros estão faltando no resultado final.\n\nEm um sistema multiagente, domínios inteiros estão faltando no resultado final. Qual é a causa raiz mais provável?\n\n[ ] A - Os subagentes executaram as tarefas atribuídas incorretamente.\n[ ] B - A decomposição de tarefas do coordenador foi muito estreita e não cobriu todos os domínios.\n[ ] C - A janela de contexto dos subagentes era pequena.\n[ ] D - O modelo utilizado tinha poucos parâmetros.','\n',char(10)),replace('**Explicação didática para um adulto tech lead:**\n\nA questão descreve um cenário clássico em arquiteturas de sistemas multiagente (MAS): o resultado final está incompleto porque domínios inteiros de conhecimento ou responsabilidade simplesmente não aparecem na saída. Isso é diferente de erros pontuais ou de baixa qualidade — é uma ausência estrutural.\n\n**Por que B está correta:**\nO coordenador (ou orquestrador) é responsável por decompor o problema maior em subproblemas e delegá-los aos subagentes especializados. Se a decomposição for muito estreita, o coordenador simplesmente não define tarefas para determinados domínios, e nenhum subagente é acionado para cobri-los. O resultado é que esses domínios desaparecem por completo da saída final — exatamente o sintoma descrito. É um problema de design na camada de orquestração, não de execução.\n\n**Por que as demais estão incorretas:**\n\n- **A (Os subagentes executaram incorretamente):** Se os subagentes receberam a tarefa e a executaram dentro do escopo definido, o erro não está neles. "Domínios inteiros faltando" sugere que nem sequer houve tentativa de cobri-los. Subagentes mal-executados produziriam resultados ruins ou ruidosos, não ausência completa de domínios.\n\n- **C (Janela de contexto pequena):** Uma janela de contexto limitada pode causar perda de informações no meio de uma execução longa, esquecimento de instruções ou truncamento de respostas. Isso degrada a qualidade, mas não explica a ausência de domínios inteiros — a menos que a janela seja tão pequena que a tarefa inteira de um domínio seja esquecida, o que é improvável e indireto. A causa raiz mais direta e provável continua sendo a decomposição.\n\n- **D (Poucos parâmetros no modelo):** Modelos com poucos parâmetros podem ter desempenho inferior em tarefas complexas, mas a falta de domínios inteiros é um problema de escopo, não de capacidade bruta do modelo. Um modelo pequeno ainda tentaria responder a todas as tarefas delegadas, mesmo que mal; a ausência total indica que a tarefa nunca foi delegada.\n\n**Resumo técnico:** O sintoma de "domínios ausentes" aponta para um gap na fase de planejamento/decomposição. A correção envolve revisar o prompt do coordenador ou a lógica de orquestração para garantir que todos os domínios relevantes sejam explicitamente endereçados na divisão de tarefas.','\n',char(10)),replace('Imagine que você e seus amigos vão fazer um trabalho de escola sobre animais. Você é o "coordenador" e decide quem faz o quê: um amigo pesquisa mamíferos, outro pesquisa aves, outro pesquisa répteis. Só que você, sem querer, esquece de pedir para alguém pesquisar sobre peixes. No final, o trabalho fala sobre mamíferos, aves e répteis, mas peixes não aparecem em lugar nenhum!\n\nIsso é exatamente o que acontece quando o coordenador do sistema multiagente faz uma "decomposição muito estreita": ele simplesmente não pede para ninguém cuidar de certos assuntos (domínios), e eles ficam de fora do resultado final.\n\nAs outras opções seriam outros problemas:\n\n- **A** seria como seus amigos terem feito a tarefa, mas errado (por exemplo, pesquisaram peixes mas colocaram informação trocada). Mas o problema aqui é que nem pesquisaram!\n- **C** seria como se cada amigo tivesse um bloquinho de papel tão pequeno que não coubesse tudo que ele precisava anotar. Isso atrapalharia, mas não faria um assunto inteiro sumir.\n- **D** seria como se seus amigos fossem iniciantes e não soubessem muito sobre o assunto. Eles até tentariam, mas fariam um trabalho fraco. De novo, não é o caso de um assunto inteiro desaparecer.\n\nEntão, o culpado mais provável é o coordenador que, na hora de dividir as tarefas, deixou domínios de fora. A resposta certa é a **B**.','\n',char(10)));
INSERT INTO cards VALUES('admin','card_1783092986021_2nqtlw1z9',202,'How should a subagent report a failure to the coordinator?',replace('How should a subagent report a failure to the coordinator?\n\nHow should a subagent report a failure to the coordinator?\n[Resposta correta: O contexto de erro estruturado permite ao coordenador decidir retry, alternativa ou prosseguir. A esconde informação, B impede recuperação e D é desproporcional para uma falha localizada.]\n\n[ ] A - With a generic "failure" status, without details.\n[ ] B - By marking the failure as success so as not to interrupt the flow.\n[ ] C - By returning structured error context: type of failure, attempted query, partials and alternatives.\n[ ] D - By aborting the whole workflow immediately.','\n',char(10)),'C - By returning structured error context: type of failure, attempted query, partials and alternatives.','["Domain_1::Agentic_Architecture_Orchestration", "Domain_4::Prompt_Engineering_Structured_Output", "Scenario_3::Multi_Agent_Research"]','New',0,2.5,0,1783092986021,1783727021926,1783203558653,replace('**Tradução para português do Brasil:**\n\nPergunta: Como um subagente deve reportar uma falha ao coordenador?\n\n[ ] A - Com um status genérico de "falha", sem detalhes.\n[ ] B - Marcando a falha como sucesso para não interromper o fluxo.\n[ ] C - Retornando um contexto de erro estruturado: tipo da falha, consulta tentada, resultados parciais e alternativas.\n[ ] D - Abortando todo o workflow imediatamente.','\n',char(10)),replace('**Explicação para um adulto Tech Lead:**\n\nA resposta correta é **C**.\n\nEm arquiteturas de sistemas multiagentes, o coordenador (orquestrador) delega tarefas a subagentes e precisa de informações precisas para tomar decisões de recuperação. A alternativa C é a abordagem correta porque segue o princípio de **design resiliente e informativo**: ao retornar um contexto de erro estruturado (tipo da falha, consulta tentada, resultados parciais e alternativas), o coordenador ganha visibilidade suficiente para decidir entre:\n\n- **Retry**: se a falha foi transitória (ex.: timeout de rede);\n- **Rota alternativa**: se outro subagente ou estratégia pode resolver;\n- **Prosseguir com parciais**: se os dados obtidos até o momento são suficientes para continuar.\n\n**Análise das alternativas incorretas:**\n\n- **A (genérico, sem detalhes):** Esconde informação. Um status genérico "failure" não permite ao coordenador distinguir entre falhas recuperáveis e irrecuperáveis, forçando decisões cegas (como retry excessivo ou aborto desnecessário). Viola o princípio de *observability* e prejudica a depuração.\n\n- **B (mascarar como sucesso):** É uma falha grave de design. Ocultar uma falha impede qualquer ação de recuperação, corrompe o estado do sistema e viola o princípio de *fail-fast* e *honest signaling*. Pode levar a inconsistências de dados e comportamentos imprevisíveis a jusante.\n\n- **D (abortar tudo):** Desproporcional para uma falha localizada. Abortar todo o workflow por um erro em um subagente quebra o princípio de *graceful degradation* e *fault isolation*. Um bom orquestrador deve isolar falhas e tentar recuperação local antes de escalar o problema.\n\nPortanto, a abordagem correta é fornecer **erro estruturado e rico em contexto** para que o coordenador exerça sua função de tomada de decisão de forma inteligente.','\n',char(10)),replace('**Explicação para uma criança de 10 anos:**\n\nImagine que você está montando um quebra-cabeça gigante com seus amigos. Cada amigo é um subagente, e você é o coordenador. Se um amigo não consegue encaixar uma peça, como ele deve te avisar?\n\n- **Opção A:** Ele só grita "FAILHOU!" sem dizer mais nada. Você não sabe qual peça, nem por que não encaixou. Fica difícil ajudar, né?\n- **Opção B:** Ele finge que encaixou a peça direitinho, mas na verdade ela está torta. Mais tarde, o desenho todo fica errado. Péssima ideia!\n- **Opção C (a certa!):** Ele diz: "Não consegui encaixar a peça azul do céu porque ela está virada ao contrário. Tentei girar, não deu certo. Sugiro tentar outra peça azul ou pedir ajuda para o João." Agora você pode decidir: tentar de novo, trocar de peça ou seguir com o que já está bom.\n- **Opção D:** Ele derruba a mesa inteira e joga tudo para o alto por causa de uma pecinha. Exagero, né?\n\nA opção C é a melhor porque dá informações úteis para você tomar uma decisão inteligente, igual um bom líder de equipe!','\n',char(10)));
INSERT INTO cards VALUES('admin','card_1783092986055_lhfmln6qo',203,'How do you reduce the token volume between upstream and downstream agents?',replace('How do you reduce the token volume between upstream and downstream agents?\n\nHow do you reduce the token volume between upstream and downstream agents?\n[Resposta correta: Retornar dados estruturados na origem reduz tokens preservando o essencial. A adiciona latência e custo. C é exagero quando se precisa de cobertura completa. D não reduz o volume, apenas evita truncamento.]\n\n[ ] A - Add an extra compressor agent between them.\n[ ] B - Make the upstream agents return structured data such as key facts, citations and scores, instead of verbose content.\n[ ] C - Introduce RAG to retrieve only parts of the content.\n[ ] D - Increase max_tokens so the messages are not truncated.','\n',char(10)),'B - Make the upstream agents return structured data such as key facts, citations and scores, instead of verbose content.','["Domain_1::Agentic_Architecture_Orchestration", "Domain_2::Tool_Design_MCP_Integration", "Domain_5::Context_Management_Reliability", "Scenario_3::Multi_Agent_Research"]','New',0,2.5,0,1783092986055,1783727025298,1783203558653,replace('**Tradução para português do Brasil:**\n\n**Pergunta:** Como reduzir o volume de tokens entre agentes upstream e downstream?\n\n**Alternativas:**\n[ ] A - Adicionar um agente compressor extra entre eles.\n[ ] B - Fazer com que os agentes upstream retornem dados estruturados, como fatos principais, citações e pontuações, em vez de conteúdo verboso.\n[ ] C - Introduzir RAG para recuperar apenas partes do conteúdo.\n[ ] D - Aumentar max_tokens para que as mensagens não sejam truncadas.','\n',char(10)),replace('**Explicação técnica para um adulto tech lead:**\n\n**Alternativa correta: B**\n\nA comunicação entre agentes (especialmente em arquiteturas multi-agente) pode consumir muitos tokens se o agente upstream retornar respostas longas e não estruturadas. A alternativa B ataca a causa raiz: ao invés de transmitir texto verboso, o agente upstream retorna apenas os dados essenciais em um formato estruturado (ex.: JSON com campos como `facts`, `citations`, `scores`). Isso reduz drasticamente o volume de tokens porque elimina redundância, artigos, conectores e explicações desnecessárias, preservando apenas o conteúdo semântico relevante para o downstream.\n\n**Por que as outras alternativas estão incorretas:**\n\n- **A (Adicionar um agente compressor extra):** Introduzir um agente compressor intermediário adiciona latência, custo computacional e complexidade à arquitetura. Além disso, o compressor precisaria processar o conteúdo verboso antes de comprimi-lo, o que ainda consome tokens e tempo. Não é a abordagem mais eficiente nem mais barata.\n\n- **C (Introduzir RAG para recuperar apenas partes do conteúdo):** RAG (Retrieval-Augmented Generation) é útil para buscar informações relevantes em uma base de conhecimento, mas não é uma solução genérica para reduzir o volume de tokens entre agentes. Se o objetivo é ter cobertura completa do conteúdo original, usar RAG pode ser exagerado e introduzir complexidade desnecessária. RAG resolve um problema diferente (recuperação seletiva de informação), não de compressão eficiente da comunicação entre agentes.\n\n- **D (Aumentar max_tokens):** Aumentar o limite de `max_tokens` não reduz o volume de tokens — na verdade, permite que mensagens maiores sejam transmitidas sem truncamento, o que agrava o problema. É uma solução que trata o sintoma (truncamento) e não a causa (excesso de tokens). Na prática, piora o consumo de tokens em vez de reduzi-lo.','\n',char(10)),replace('Imagine que você e seu amigo estão se comunicando por cartas. Seu amigo (agente upstream) escreve cartas enormes contando todos os detalhes de uma história. Você (agente downstream) só precisa saber os fatos principais. O que fazer?\n\nA opção B é a melhor: pedir para seu amigo escrever apenas os pontos principais, tipo uma lista com os fatos importantes, sem rodeios. Assim a carta fica pequena e rápida de ler.\n\nAs outras opções não são boas:\n- A seria contratar outra pessoa para resumir a carta enorme — mais trabalho e demora.\n- C seria mandar seu amigo procurar num livro gigante só algumas partes — complicado demais.\n- D seria simplesmente usar um envelope maior para caber a carta enorme — não resolve o problema, só piora.','\n',char(10)));
INSERT INTO cards VALUES('admin','card_1783092986069_ujtrfjui2',204,'How does the asynchronous Message Batches API behave with respect to iterative tool use?',replace('How does the asynchronous Message Batches API behave with respect to iterative tool use?\n\nHow does the asynchronous Message Batches API behave with respect to iterative tool use?\n[Resposta correta: O modelo fire-and-forget quebra workflows iterativos que dependem de resultados mid-request. A é falso, pois o batch não faz execução mid-request. C exagera, pois o batch consegue definir e gerar tool calls. D condiciona à velocidade, que não é o critério.]\n\n[ ] A - It fully supports iterative tool use, executing tools mid-request.\n[ ] B - The fire-and-forget model prevents executing tools in the middle of the request and returning results for Claude to continue.\n[ ] C - It does not support defining tool calls at all.\n[ ] D - It only works with tool use if completion is fast.','\n',char(10)),'[ ] B - The fire-and-forget model prevents executing tools in the middle of the request and returning results for Claude to continue.','["ForaDosDominios", "ForaDoCenario"]','New',0,2.5,0,1783092986069,1783727028586,1783203558653,replace('**Tradução para português do Brasil:**\n\n**Pergunta:** Como a API de Lotes de Mensagens (Message Batches API) assíncrona se comporta em relação ao uso iterativo de ferramentas (tool use)?\n\n[ ] A - Ela suporta totalmente o uso iterativo de ferramentas, executando ferramentas durante o (mid-request) processamento da requisição.\n[ ] B - O modelo "fire-and-forget" (disparar e esquecer) impede a execução de ferramentas no meio da requisição e o retorno de resultados para que Claude continue.\n[ ] C - Ela não suporta a definição de chamadas de ferramentas (tool calls) de forma alguma.\n[ ] D - Ela só funciona com uso de ferramentas se a conclusão for rápida.','\n',char(10)),replace('**Explicação para adulto (tech lead):**\n\n**Alternativa correta: B**\n\nA API Message Batches do Anthropic opera sob um modelo **assíncrono "fire-and-forget"**. Isso significa que você submete um lote de requisições de uma só vez, e o sistema as processa em background, retornando os resultados posteriormente — sem manter uma conexão aberta ou permitir interação em tempo real entre o modelo e ferramentas externas.\n\n**Por que B está correta:**\nEm um fluxo iterativo de tool use, o modelo gera uma tool call, a aplicação executa a ferramenta e retorna o resultado para o modelo continuar a geração — tudo dentro do **mesmo ciclo de requisição-resposta**. No modelo de lotes, não há essa troca em tempo real: cada requisição no lote é processada de forma independente e atômica. Uma vez que a requisição é enviada, não há como "voltar" para o modelo com o resultado de uma ferramenta e permitir que ele continue gerando a partir daquele ponto, a menos que isso seja feito em uma nova requisição separada — o que quebra o caráter iterativo.\n\n**Análise das alternativas incorretas:**\n\n- **A** — Falsa. A API de lotes não suporta execução de ferramentas "mid-request". Ela não mantém estado entre chamadas de ferramenta dentro de uma mesma requisição em lote. Cada requisição é processada de forma independente, sem ciclo de ida-e-volta.\n- **C** — Falsa e exagerada. A API de lotes suporta sim a definição de tool calls (você pode incluir definições de ferramentas no corpo de cada mensagem do lote). O problema não é a capacidade de definir ferramentas, mas sim de iterar sobre os resultados delas.\n- **D** — Falsa. A velocidade de conclusão não é o critério relevante. Mesmo que a execução seja rápida, o modelo assíncrono do batch não permite o ciclo iterativo de tool use. A limitação é arquitetural (fire-and-forget), não de performance.','\n',char(10)),replace('Imagine que você está conversando com um amigo muito inteligente (o Claude) e pede ajuda para fazer um trabalho. Você pergunta algo, ele responde, mas às vezes ele precisa de mais informações — como "pesquise no Google" ou "calcule isso". Aí você pesquisa, volta e conta pra ele, e ele continua te ajudando. Isso é o "uso iterativo de ferramentas": uma conversa de ida e volta.\n\nAgora, a API de Lotes (Batches) é como se você escrevesse várias perguntas em um papel, entregasse tudo de uma vez para seu amigo, e ele respondesse tudo depois, sem conversar com você no meio do caminho. Se ele disser "preciso pesquisar no Google", você não pode fazer a pesquisa e dar a resposta pra ele continuar — porque vocês não estão mais conversando naquele momento. Ele já respondeu tudo de uma vez e acabou.\n\nPor isso a resposta correta é a **B**: o modelo "disparar e esquecer" (fire-and-forget) não permite que o Claude peça ajuda para ferramentas no meio da resposta e espere você voltar com o resultado pra continuar.','\n',char(10)));
INSERT INTO cards VALUES('admin','card_1783092986082_izr0c8j2j',205,'When is it appropriate to use the Explore subagent for a verbose exploration phase?',replace('When is it appropriate to use the Explore subagent for a verbose exploration phase?\n\nWhen is it appropriate to use the Explore subagent for a verbose exploration phase?\n[Resposta correta: O Explore isola o ruído de uma fase verbosa e retorna um resumo. A contraria a razão de usar o Explore. C confunde com /compact, que é lossy. D exagera, pois as demais fases devem ficar na conversa principal.]\n\n[ ] A - When you need to retain all the verbose output in the main context.\n[ ] B - When the phase produces verbose output that you do not need to retain, returning a concise summary and isolating the noise.\n[ ] C - Whenever you want to run /compact to clean up the history.\n[ ] D - When you want to keep all phases out of the main conversation.','\n',char(10)),'B - When the phase produces verbose output that you do not need to retain, returning a concise summary and isolating the noise.','["Domain_3::Claude_Code_Configuration_Workflows", "Domain_5::Context_Management_Reliability", "Scenario_2::Code_Generation_Claude_Code"]','New',0,2.5,0,1783092986082,1783727032507,1783203558653,replace('**Tradução para português do Brasil:**\n\nQuando é apropriado usar o subagente Explore para uma fase de exploração verbosa?\n\n[ ] A - Quando você precisa reter toda a saída verbosa no contexto principal.\n[ ] B - Quando a fase produz uma saída verbosa que você não precisa manter, retornando um resumo conciso e isolando o ruído.\n[ ] C - Sempre que você quiser executar /compact para limpar o histórico.\n[ ] D - Quando você quiser manter todas as fases fora da conversa principal.','\n',char(10)),replace('**Explicação para um adulto tech lead:**\n\nO subagente **Explore** foi projetado especificamente para lidar com fases de exploração que geram grande volume de saída (output verboso), mas cujo conteúdo detalhado não precisa ser preservado no contexto principal da conversa. Ele atua como um filtro inteligente: consome a fase verbosa, extrai apenas as informações essenciais e devolve um resumo conciso, isolando o "ruído" (detalhes irrelevantes, tentativas falhas, logs extensos etc.) para que não poluam o contexto.\n\n**Análise das alternativas:**\n\n- **A (incorreta):** Reter toda a saída verbosa no contexto principal é justamente o oposto do propósito do Explore. Isso sobrecarregaria o contexto com informações desnecessárias, aumentando o consumo de tokens e reduzindo a eficiência.\n\n- **B (correta):** Descreve exatamente o caso de uso ideal. O Explore processa a saída verbosa, extrai um sumário e descarta o ruído, mantendo o contexto limpo e enxuto.\n\n- **C (incorreta):** Confunde Explore com o comando `/compact`. O `/compact` é uma operação de compressão com perda (lossy) que reduz o histórico existente, enquanto o Explore é um subagente que atua durante a execução de uma fase para resumir seu output. São mecanismos diferentes com propósitos distintos.\n\n- **D (incorreta):** É um exagero. Nem todas as fases devem ser mantidas fora da conversa principal — apenas aquelas que produzem saída verbosa e cujos detalhes não são relevantes. Manter *todas* as fases fora do contexto principal prejudicaria a rastreabilidade e a coerência da conversa.','\n',char(10)),replace('**Explicação para uma criança de 10 anos:**\n\nImagina que você está fazendo um trabalho de escola e pesquisou um monte de coisas na internet. Algumas páginas têm informações úteis, mas outras têm textos enormes e complicados que só atrapalham. \n\nO **Explore** é como um amigo inteligente que lê esses textos grandes e chatos para você, depois te conta só o que é importante em poucas palavras. Ele joga fora o que não serve (o "ruído") e te dá um resumo rápido.\n\n**Por que as outras opções estão erradas?**\n\n- **A** diz para guardar tudo — mas aí seu caderno ficaria cheio de coisas inúteis e você se perderia.\n- **C** confunde com outra ferramenta (o /compact), que é como apertar os textos para caberem em menos espaço, mas pode perder informações importantes.\n- **D** diz para tirar *todas* as fases da conversa principal, o que é exagero — algumas partes são importantes e precisam ficar visíveis!\n\nEntão a resposta certa é a **B**: usar o Explore quando tem muita informação que não precisa ser guardada, e ele te devolve só um resumo.','\n',char(10)));
INSERT INTO cards VALUES('admin','card_1783092986098_50qkvyqas',206,'What is the main mechanism to control the agentic loop (continue or stop)?',replace('What is the main mechanism to control the agentic loop (continue or stop)?\n\nWhat is the main mechanism to control the agentic loop (continue or stop)?\n[Resposta correta: O controle correto é ler o campo stop_reason. A usa contagem de tokens, que é guardrail de segurança, não controle de loop. C é frágil, e D é falso porque Claude pode gerar texto e tool calls juntos.]\n\n[ ] A - Count the tokens of the response and stop when reaching a limit.\n[ ] B - Check the stop_reason field: continue when it is "tool_use" and stop when it is "end_turn".\n[ ] C - Parse the natural language text to detect completion.\n[ ] D - Stop as soon as the response contains any text.','\n',char(10)),'B - Check the stop_reason field: continue when it is "tool_use" and stop when it is "end_turn".','["Domain_1::Agentic_Architecture_Orchestration", "ForaDoCenario"]','New',0,2.5,0,1783092986098,1783727035594,1783203558653,replace('**[TRADUÇÃO]**\n\n**Pergunta:** Qual é o mecanismo principal para controlar o loop agentivo (continuar ou parar)?\n\n**Alternativas:**\n[ ] A - Contar os tokens da resposta e parar ao atingir um limite.\n[ ] B - Verificar o campo stop_reason: continuar quando for "tool_use" e parar quando for "end_turn".\n[ ] C - Interpretar o texto em linguagem natural para detectar conclusão.\n[ ] D - Parar assim que a resposta contiver qualquer texto.','\n',char(10)),replace('**[EXPLICAÇÃO PARA ADULTO TECH LEAD]**\n\nA resposta correta é a **alternativa B**.\n\n**Por que B está correta:**\n\nEm arquiteturas de agentes que utilizam modelos como o Claude (especialmente com a API Anthropic), o loop agentivo funciona da seguinte forma: o modelo retorna uma resposta estruturada contendo um campo chamado `stop_reason`. Quando o modelo decide que precisa utilizar uma ferramenta (tool call) para buscar mais informações ou executar uma ação, o `stop_reason` é `"tool_use"` — sinalizando que o loop deve continuar, processar a resposta da ferramenta e enviá-la de volta ao modelo. Quando o modelo concluiu a tarefa e deseja finalizar a interação, o `stop_reason` é `"end_turn"` — indicando que o loop deve parar. Este é o mecanismo oficial e robusto para controle do fluxo agêntico.\n\n**Por que as demais estão erradas:**\n\n- **Alternativa A (contagem de tokens):** Contagem de tokens é um mecanismo de guardrail (limite de segurança) para evitar custos excessivos ou loops infinitos, mas não é o mecanismo *principal* de controle do loop agentivo. Usar apenas contagem de tokens como critério interromperia o agente prematuramente ou de forma arbitrária, sem considerar se a tarefa foi concluída.\n\n- **Alternativa C (interpretação de linguagem natural):** Parsear texto em linguagem natural para detectar conclusão é frágil, propenso a erros de interpretação, ambiguidades e falsos positivos/negativos. Não é um mecanismo confiável para controle de fluxo em produção. A API fornece campos estruturados justamente para evitar essa abordagem.\n\n- **Alternativa D (parar ao conter qualquer texto):** Incorreta porque Claude (e a maioria dos modelos agentivos) pode gerar texto explicativo *junto com* tool calls em uma mesma resposta. Parar ao detectar qualquer texto interromperia o fluxo antes da conclusão da tarefa. O modelo frequentemente produz texto raciocinado ou explicativo antes de ou junto com chamadas de ferramenta.','\n',char(10)),replace('Imagine que você está brincando de detetive com um robô inteligente. Você pede para ele resolver um mistério. O robô pode fazer duas coisas: (1) pedir ajuda para você ou para outras ferramentas, ou (2) dar a resposta final.\n\nPara o robô saber se ele deve continuar pedindo ajuda ou se já pode dar a resposta final, ele usa uma "plaquinha" chamada **stop_reason**. Quando a plaquinha mostra **"tool_use"**, significa "ainda preciso de mais informações, vou continuar". Quando mostra **"end_turn"**, significa "pronto, já resolvi, posso parar".\n\nAs outras alternativas seriam formas estranhas de controlar o robô:\n\n- **A (contar tokens)** seria como dizer "pare depois de falar 100 palavras", mesmo que ele não tenha terminado a tarefa.\n- **C (interpretar texto)** seria como tentar adivinhar pelas palavras dele se ele terminou — muito confuso e fácil de errar.\n- **D (parar se ele falar qualquer coisa)** seria péssimo, porque ele sempre fala alguma coisa! Ele até explica o raciocínio dele antes de pedir ajuda.\n\nEntão a melhor forma é a **alternativa B**: usar a plaquinha stop_reason para saber se continua ou para.','\n',char(10)));
INSERT INTO cards VALUES('admin','card_1783092986114_hshoy8sry',207,'How do you reduce round-trips and redundant data collection in a multi-step workflow?',replace('How do you reduce round-trips and redundant data collection in a multi-step workflow?\n\nHow do you reduce round-trips and redundant data collection in a multi-step workflow?\n[Resposta correta: O padrão decompor-paralelizar-sintetizar elimina redundância e reduz chamadas. A piora o problema sequencial. C não ataca a redundância e D volta ao prompt único.]\n\n[ ] A - Add more sequential validation gates.\n[ ] B - Decompose the request into distinct concerns, investigate them in parallel with shared context and then synthesize.\n[ ] C - Increase the timeout of each call to avoid repetitions.\n[ ] D - Run everything in a single giant call without decomposition.','\n',char(10)),'[ ] B - Decompose the request into distinct concerns, investigate them in parallel with shared context and then synthesize.','["Domain_1::Agentic_Architecture_Orchestration", "Domain_5::Context_Management_Reliability", "Scenario_4::Developer_Productivity"]','New',0,2.5,0,1783092986114,1783727039932,1783203558653,replace('**TRADUÇÃO:**\n\n**Pergunta:** Como você reduz viagens de ida e volta (round-trips) e coleta redundante de dados em um fluxo de trabalho com múltiplas etapas?\n\n[ ] A - Adicionar mais portões de validação sequenciais.\n[ ] B - Decompor a solicitação em preocupações distintas, investigá-las em paralelo com contexto compartilhado e depois sintetizar.\n[ ] C - Aumentar o timeout de cada chamada para evitar repetições.\n[ ] D - Executar tudo em uma única chamada gigante sem decomposição.','\n',char(10)),replace('**EXPLICAÇÃO DIDÁTICA PARA UM ADULTO TECH LEAD:**\n\n**Resposta correta: B**\n\nA alternativa B descreve o padrão "decompor-paralelizar-sintetizar", uma abordagem clássica de engenharia de sistemas para otimização de fluxos multi-etapas. Ao decompor uma solicitação complexa em preocupações distintas (concerns), podemos investigá-las em paralelo, compartilhando contexto (como estado, cache ou informações já obtidas) e, por fim, sintetizar os resultados. Isso elimina a necessidade de idas e voltas sequenciais (round-trips) e evita que a mesma informação seja coletada múltiplas vezes em etapas diferentes.\n\n**Por que as demais estão erradas:**\n\n- **A (Adicionar mais portões de validação sequenciais):** Isso *piora* o problema. Cada portão de validação adiciona uma nova viagem de ida e volta e potencialmente requer requisições adicionais, aumentando a redundância e a latência. É o oposto da otimização desejada.\n\n- **C (Aumentar o timeout de cada chamada para evitar repetições):** Aumentar timeout apenas torna o sistema mais tolerante a atrasos, mas não reduz o número de chamadas, nem elimina a redundância na coleta de dados. O problema de round-trips permanece exatamente o mesmo.\n\n- **D (Executar tudo em uma única chamada gigante sem decomposição):** Embora reduza o número de chamadas, elimina os benefícios da decomposição: modularidade, reuso, paralelismo, tolerância a falhas e tratamento especializado de cada parte. Além disso, uma chamada monolítica gigante pode ser frágil, difícil de depurar e, paradoxalmente, gerar redundância interna se diferentes partes do fluxo precisarem dos mesmos dados.','\n',char(10)),replace('**EXPLICAÇÃO PARA UMA CRIANÇA DE 10 ANOS:**\n\nImagine que você precisa fazer um trabalho de escola sobre animais. O trabalho tem várias partes: descobrir o que cada animal come, onde ele vive e como ele se parece.\n\n**Alternativa A** seria tipo: primeiro você pergunta "O que o leão come?", aí depois que descobrir, você pergunta "Onde o leão vive?", e depois "Como o leão se parece?". Você fica indo e voltando várias vezes — isso é chato e demora muito!\n\n**Alternativa C** seria tipo: você espera mais tempo para cada resposta, mas continua indo e voltando do mesmo jeito. Não resolve o problema.\n\n**Alternativa D** seria tipo: tentar fazer tudo de uma vez só perguntando "Me fale TUDO sobre todos os animais do mundo!". Isso é pesado, confuso e difícil de entender.\n\n**Alternativa B (a correta)** é o melhor plano: você divide o trabalho em partes — uma pessoa pesquisa a comida dos animais, outra pesquisa os lugares onde vivem, outra pesquisa a aparência. Todas trabalham ao mesmo tempo (em paralelo), compartilham o que já sabem (contexto compartilhado) e, no final, juntam tudo (sintetizam). Assim você faz menos idas e voltas, não coleta a mesma informação duas vezes e termina muito mais rápido! 😊','\n',char(10)));
INSERT INTO cards VALUES('admin','card_1783092986130_rv794dyfq',208,'In iterative CI/CD reviews, how do you avoid re-flagging problems that are already resolved?',replace('In iterative CI/CD reviews, how do you avoid re-flagging problems that are already resolved?\n\nIn iterative CI/CD reviews, how do you avoid re-flagging problems that are already resolved?\n[Resposta correta: Fornecer o contexto anterior permite raciocínio semântico sobre o que já foi resolvido. A é frágil, C perde o valor do CI/CD contínuo e D elimina a revisão que se quer manter.]\n\n[ ] A - Apply pattern matching over the previous messages.\n[ ] B - Include the previous findings in the context and instruct Claude to report only new or still unresolved problems.\n[ ] C - Reduce the frequency of CI/CD feedback.\n[ ] D - Turn off reviews after the first run.','\n',char(10)),'B - Include the previous findings in the context and instruct Claude to report only new or still unresolved problems.','["Domain_4::Prompt_Engineering_Structured_Output", "Domain_5::Context_Management_Reliability", "Scenario_5::Claude_Code_CI_CD"]','New',0,2.5,0,1783092986130,1783727043425,1783203558653,replace('**Tradução para português do Brasil:**\n\nEm revisões iterativas de CI/CD, como evitar que problemas já resolvidos sejam sinalizados novamente?\n\n[ ] A - Aplicar correspondência de padrões sobre as mensagens anteriores.\n[ ] B - Incluir as descobertas anteriores no contexto e instruir Claude a relatar apenas problemas novos ou ainda não resolvidos.\n[ ] C - Reduzir a frequência do feedback de CI/CD.\n[ ] D - Desligar as revisões após a primeira execução.','\n',char(10)),replace('**Explicação didática para um adulto tech lead:**\n\nA pergunta aborda um desafio comum em pipelines de CI/CD com revisão automatizada (especialmente com LLMs como Claude): o problema de *duplicação de alertas* — quando o mesmo problema identificado em um commit anterior é re-reportado em um commit subsequente, mesmo que já tenha sido corrigido.\n\n**Análise das alternativas:**\n\n- **A - "Aplicar correspondência de padrões sobre as mensagens anteriores"** — Esta abordagem (pattern matching) é frágil porque depende de correspondência textual exata ou baseada em regex. Problemas semanticamente equivalentes podem ser expressos de formas diferentes (ex: "variável não utilizada" vs "dead code na linha 42"), e o pattern matching não consegue distinguir entre um problema resolvido e um novo problema similar. Além disso, não lida bem com mudanças parciais ou refatorações que resolvem problemas de forma não literal.\n\n- **B - "Incluir as descobertas anteriores no contexto e instruir Claude a reportar apenas problemas novos ou ainda não resolvidos"** — Esta é a resposta correta. Ao fornecer o contexto histórico (resultados de revisões anteriores) como parte do prompt, o modelo pode realizar *raciocínio semântico* (e não apenas matching textual) para determinar se um problema persiste, foi resolvido ou é novo. Isso tira proveito da capacidade de entendimento contextual dos LLMs, que é exatamente a força deles. A instrução explícita no prompt ("report only new or still unresolved problems") direciona o comportamento de forma confiável.\n\n- **C - "Reduzir a frequência do feedback de CI/CD"** — Esta alternativa é contraintuitiva, pois o valor do CI/CD contínuo está justamente na frequência e rapidez do feedback. Reduzir a frequência significa atrasar a detecção de problemas, o que vai contra os princípios de integração contínua. Além disso, não resolve o problema central: mesmo com menos revisões, ao fazer uma nova revisão, o sistema ainda poderia re-flagrar problemas antigos.\n\n- **D - "Desligar as revisões após a primeira execução"** — Elimina completamente o benefício da revisão contínua. Em CI/CD, cada novo commit deve ser revisado para garantir que novas alterações não introduziram regressões ou novos problemas. Desligar as revisões após a primeira execução deixaria o pipeline cego para qualquer mudança subsequente.\n\n**Foco técnico:** A abordagem correta (B) é essencialmente um *sistema de memória de curto prazo* dentro do pipeline. Na prática, isso pode ser implementado passando o artefato da revisão anterior (JSON, markdown, etc.) como parte do contexto do prompt, junto com uma instrução de sistema clara. Isso garante que o LLM tenha ciência do estado anterior e possa fazer uma análise diferencial inteligente.','\n',char(10)),replace('Imagine que você é um professor que corrige a lição de casa de um aluno todos os dias. Na segunda-feira, você viu que ele errou a pergunta número 3. Na terça-feira, ele entregou a lição de novo, mas você já esqueceu o que viu na segunda. Então você olha e marca a pergunta 3 como errada de novo — mas na verdade ele já tinha corrigido! Isso é chato e perde tempo, né?\n\nA melhor maneira de evitar isso é: antes de corrigir a lição de terça, você dá uma olhada na sua lista de erros de segunda. Aí você vê: "Na segunda os erros foram: pergunta 3 e pergunta 7". Agora, na terça, você só vai marcar erros NOVOS ou aqueles que ainda não foram arrumados. Se a pergunta 3 foi corrigida, você não marca ela de novo.\n\nÉ exatamente isso que a alternativa B faz: ela mostra para o Claude (o "professor" de programação) quais problemas já foram encontrados antes, e pede para ele só falar dos problemas que são novos ou que ainda não foram arrumados. Assim ele não fica repetindo os mesmos alertas toda hora!\n\nAs outras opções são ruins: a A é como tentar adivinhar só pelo formato da letra se o erro é o mesmo (não funciona bem), a C é corrigir a lição só de vez em quando (aí o aluno demora para saber dos erros), e a D é desistir de corrigir depois da primeira vez (aí o aluno pode errar tudo de novo e ninguém vai avisar).','\n',char(10)));
INSERT INTO cards VALUES('admin','card_1783092986143_kx1ihdqv0',209,'How do you leverage Claude''s native ability to parallelize tools to reduce round-trips?',replace('How do you leverage Claude''s native ability to parallelize tools to reduce round-trips?\n\nHow do you leverage Claude''s native ability to parallelize tools to reduce round-trips?\n[Resposta correta: O batching de pedidos por turno reduz round-trips aproveitando que o Claude pede várias ferramentas numa resposta. A desperdiça recursos, C reduz flexibilidade e D não afeta o batching de ferramentas.]\n\n[ ] A - Execute tools speculatively before Claude requests them.\n[ ] B - Instruct Claude to batch the tool requests per turn and return all results together before the next call.\n[ ] C - Combine everything into single composite tools.\n[ ] D - Increase max_tokens to allow more tool calls.','\n',char(10)),'B - Instruct Claude to batch the tool requests per turn and return all results together before the next call.','["Domain_1::Agentic_Architecture_Orchestration", "Domain_5::Context_Management_Reliability", "ForaDoCenario"]','New',0,2.5,0,1783092986143,1783727047298,1783203558653,replace('**Tradução para Português do Brasil:**\n\n**Pergunta:** Como você aproveita a capacidade nativa do Claude de paralelizar ferramentas para reduzir idas e voltas (round-trips)?\n\n[ ] A - Executar ferramentas especulativamente antes do Claude solicitá-las.\n[ ] B - Instruir o Claude a agrupar (batch) as solicitações de ferramentas por turno e retornar todos os resultados juntos antes da próxima chamada.\n[ ] C - Combinar tudo em ferramentas compostas únicas.\n[ ] D - Aumentar max_tokens para permitir mais chamadas de ferramentas.','\n',char(10)),replace('**Explicação Didática para Adulto Tech Lead:**\n\n**Contexto técnico:**  \nO Claude possui a capacidade nativa de solicitar múltiplas ferramentas em uma única resposta. Isso significa que, em um único turno, ele pode pedir a execução de várias funções simultaneamente, sem precisar aguardar o resultado de uma para solicitar a próxima. Isso reduz drasticamente o número de *round-trips* (ciclos de requisição-resposta entre o cliente e a API).\n\n**Por que B é a resposta correta:**  \nA alternativa B descreve exatamente o mecanismo correto: instruir o Claude a agrupar (*batch*) as solicitações de ferramentas por turno e retornar todos os resultados juntos antes da próxima chamada. Isso é feito por meio de *system prompts* ou instruções explícitas que orientam o modelo a, sempre que possível, solicitar múltiplas ferramentas independentes em paralelo em uma única resposta. O cliente então executa todas as ferramentas solicitadas e retorna os resultados em lote na mesma chamada de continuação. Isso é o *core* do paralelismo nativo do Claude.\n\n**Análise das alternativas incorretas:**\n\n- **A - Executar ferramentas especulativamente antes do Claude solicitá-las.**  \n  Isso é ineficiente e arriscado. Executar ferramentas sem que o Claude as tenha solicitado pode desperdiçar recursos computacionais e financeiros, além de gerar resultados que nunca serão usados. O Claude deve decidir quais ferramentas chamar com base no contexto; executar especulativamente quebra o fluxo determinístico e pode introduzir ruído ou custos desnecessários.\n\n- **C - Combinar tudo em ferramentas compostas únicas.**  \n  Isso reduz a granularidade e a flexibilidade do sistema. Ferramentas compostas podem ser úteis em casos específicos, mas não aproveitam o paralelismo nativo do Claude — pelo contrário, forçam uma única chamada monolítica que pode ser mais lenta e menos modular. A abordagem correta é manter ferramentas atômicas e deixar o Claude decidir quais paralelizar.\n\n- **D - Aumentar max_tokens para permitir mais chamadas de ferramentas.**  \n  Aumentar `max_tokens` apenas expande o limite de tokens de saída, não tem relação direta com a capacidade de paralelizar chamadas de ferramentas. O paralelismo depende da lógica de planejamento do modelo, não do teto de tokens. Você pode ter um `max_tokens` alto e ainda assim o modelo fazer chamadas sequenciais se não for instruído a agrupar.','\n',char(10)),replace('**Explicação para uma criança de 10 anos:**\n\nImagina que você está resolvendo um problema e precisa de várias informações ao mesmo tempo. Em vez de pedir uma informação, esperar a resposta, depois pedir outra, esperar de novo, e assim por diante (o que demora muito), você pode pedir todas as informações de uma vez só!\n\nO Claude é como um amigo inteligente que consegue pedir várias coisas ao mesmo tempo. Mas para isso funcionar direito, você precisa dizer a ele: "Ei, sempre que você precisar de várias ferramentas, peça todas juntas, e eu trago as respostas todas de uma vez."\n\nÉ como quando você vai ao mercado: em vez de ir uma vez para comprar pão, voltar para casa, depois ir de novo comprar leite, depois ir comprar biscoito... você faz uma lista e compra tudo de uma vez. Muito mais rápido, né?\n\nAs outras opções são ruins porque:\n- **A:** Seria como comprar coisas que você nem sabe se vai precisar — desperdício de dinheiro e tempo.\n- **C:** Seria como juntar tudo num único super-utensílio que faz tudo, mas que é difícil de usar e não funciona tão bem.\n- **D:** Aumentar o limite de tokens é como aumentar o tamanho do carrinho de compras, mas não resolve o problema de ter que ir e voltar várias vezes.','\n',char(10)));
INSERT INTO cards VALUES('admin','card_1783092986157_i2yya956w',210,'What advantage does the coordinator (orchestrator) pattern offer in multiagent systems?',replace('What advantage does the coordinator (orchestrator) pattern offer in multiagent systems?\n\nWhat advantage does the coordinator (orchestrator) pattern offer in multiagent systems?\n[Resposta correta: O ganho real é controle e visibilidade centralizados. A é falso, pois rotear tudo pelo coordenador adiciona overhead. C erra ao dizer que serialização e retry são exclusivos do coordenador. D não é uma vantagem do padrão.]\n\n[ ] A - Total elimination of any communication overhead.\n[ ] B - Centralized visibility of the interactions, consistent error handling and control over each subagent''s information.\n[ ] C - Serialization and retry, which only exist in the coordinator.\n[ ] D - Automatic reduction of the token cost on each call.','\n',char(10)),'B - Centralized visibility of the interactions, consistent error handling and control over each subagent''s information.','["Domain_1::Agentic_Architecture_Orchestration", "Scenario_3::Multi_Agent_Research"]','New',0,2.5,0,1783092986157,1783727050506,1783203558653,replace('**Tradução para português do Brasil:**\n\n**Pergunta:** Que vantagem o padrão coordenador (orquestrador) oferece em sistemas multiagentes?\n\n[ ] A - Eliminação total de qualquer overhead de comunicação.\n[ ] B - Visibilidade centralizada das interações, tratamento consistente de erros e controle sobre as informações de cada subagente.\n[ ] C - Serialização e retry, que só existem no coordenador.\n[ ] D - Redução automática do custo de tokens em cada chamada.','\n',char(10)),replace('**Explicação para um adulto tech lead:**\n\nO padrão **coordenador (orquestrador)** em sistemas multiagentes estabelece um agente central responsável por orquestrar o fluxo de trabalho, decidindo qual subagente executar, em que ordem, e como consolidar os resultados.\n\n**Por que a alternativa B está correta?**\nA principal vantagem do padrão coordenador é exatamente prover **visibilidade centralizada** de todas as interações entre os agentes, permitindo que erros sejam tratados de forma consistente (ex.: lógica de fallback, retry centralizado, rollback) e que haja controle sobre quais informações cada subagente recebe e produz. Em sistemas distribuídos e complexos, isso reduz o acoplamento entre agentes e torna o sistema mais auditável e depurável.\n\n**Por que as demais alternativas estão incorretas?**\n\n- **Alternativa A ("Eliminação total de qualquer overhead de comunicação"):** FALSA. Na verdade, o padrão coordenador adiciona overhead de comunicação inevitável, pois todo subagente se comunica através do coordenador. Não há eliminação total — há, sim, um trade-off entre centralização de controle e latência adicional.\n\n- **Alternativa C ("Serialização e retry, que só existem no coordenador"):** ERRADA. Serialização (garantia de execução ordenada) e retry (tentativas de repetição em caso de falha) não são exclusivos do padrão coordenador. Outros padrões (como o de agentes autônomos com auto-retry, ou filas de mensagens) também implementam essas funcionalidades. O coordenador pode implementá-las, mas não são um privilégio desse padrão.\n\n- **Alternativa D ("Redução automática do custo de tokens em cada chamada"):** FALSA. O padrão coordenador não reduz, por si só, o custo de tokens. Na verdade, a centralização pode até aumentar o número de chamadas (coordenador + subagente), consumindo mais tokens. Não há qualquer garantia de redução automática de custo.','\n',char(10)),replace('**Explicação para uma criança de 10 anos:**\n\nImagine que você está organizando um trabalho em grupo na escola. O **coordenador** seria o líder do grupo. Ele decide quem faz o quê, acompanha o andamento de cada tarefa, e se alguém errar, ele ajuda a consertar.\n\nA resposta correta (letra B) diz que a vantagem desse líder é que ele **consegue ver tudo o que está acontecendo**, pode **corrigir os erros de forma organizada** e **controla quais informações cada pessoa do grupo recebe**.\n\nAs outras alternativas estão erradas porque:\n\n- Letra A diz que o líder faz todo mundo se comunicar sem nenhum trabalho extra — mas conversar com o líder dá mais trabalho, não menos.\n- Letra C diz que só o líder pode organizar a fila de tarefas e repetir algo que deu errado — mas os colegas também poderiam fazer isso sozinhos.\n- Letra D diz que o líder gasta menos papel e caneta — mentira, o líder até gasta mais porque precisa falar com todo mundo!\n\nEntão a melhor resposta é a **B**: o coordenador ajuda a ver tudo, tratar erros e controlar a informação.','\n',char(10)));
INSERT INTO cards VALUES('admin','card_1783092986192_qp0nl09og',211,'How should an agent handle conflicting data across sources in a multiagent pipeline?',replace('How should an agent handle conflicting data across sources in a multiagent pipeline?\n\nHow should an agent handle conflicting data across sources in a multiagent pipeline?\n[Resposta correta: O agente anota o conflito com fonte e deixa a reconciliação para o coordenador. A deixa o agente errado julgar credibilidade. C bloqueia o workflow desnecessariamente e D perde a informação do conflito.]\n\n[ ] A - Choose the most reliable value on its own and discard the other.\n[ ] B - Complete the task with both values, note the conflict with source attribution and let the coordinator reconcile.\n[ ] C - Block the workflow until the conflict is resolved.\n[ ] D - Ignore the conflict and proceed with either value.','\n',char(10)),'B - Complete the task with both values, note the conflict with source attribution and let the coordinator reconcile.','["Domain_1::Agentic_Architecture_Orchestration", "Domain_5::Context_Management_Reliability", "Scenario_3::Multi_Agent_Research"]','New',0,2.5,0,1783092986192,1783727054105,1783203558653,replace('**Tradução da pergunta e alternativas para português do Brasil:**\n\n**Pergunta:** Como um agente deve lidar com dados conflitantes entre fontes em um pipeline multiagente?\n\n[ ] A - Escolher o valor mais confiável por conta própria e descartar o outro.\n[ ] B - Completar a tarefa com ambos os valores, anotar o conflito com a atribuição de fonte e deixar que o coordenador reconcilie.\n[ ] C - Bloquear o workflow até que o conflito seja resolvido.\n[ ] D - Ignorar o conflito e prosseguir com qualquer um dos valores.','\n',char(10)),replace('**Explicação técnica para um adulto tech lead:**\n\nEm um pipeline multiagente, cada agente tem um escopo limitado de responsabilidade e visibilidade parcial dos dados. A melhor prática para lidar com dados conflitantes segue o princípio da separação de responsabilidades e da não-duplicação de lógica de decisão.\n\n**Por que B é a resposta correta:**\n\nA alternativa B descreve o padrão arquitetural mais robusto: o agente especializado coleta os dados, preserva a proveniência (rastreabilidade) de cada valor conflitante com atribuição explícita de fonte, e delega a reconciliação a um coordenador ou orquestrador que possui contexto mais amplo para resolver o conflito. Isso respeita o princípio de Responsibility Segregation — o agente não deve assumir responsabilidades de decisão que não estão no seu escopo. Além disso, preserva a informação completa para auditoria e depuração.\n\n**Por que as demais estão erradas:**\n\n- **A (Escolher o valor mais confiável por conta própria):** Viola o princípio de que o agente não tem, necessariamente, contexto ou autoridade para julgar credibilidade de fontes. Isso introduz um viés local que pode ser inconsistente com a lógica global do pipeline. O agente não deve "adivinhar" qual fonte é mais confiável sem uma política explícita vinda do coordenador.\n\n- **C (Bloquear o workflow):** Embora pareça cauteloso, bloquear o workflow sem necessidade é uma operação de alto custo. Em pipelines multiagente, especialmente em sistemas distribuídos ou assíncronos, bloqueios desnecessários podem causar deadlocks, timeouts e degradação severa de desempenho. A menos que o conflito seja crítico e uma política explícita de "fail-stop" esteja definida, essa abordagem é excessivamente restritiva.\n\n- **D (Ignorar o conflito):** Esta é a pior abordagem, pois descarta informação valiosa. Ignorar o conflito pode propagar dados inconsistentes rio abaixo no pipeline, resultando em erros silenciosos e difíceis de diagnosticar. Quebra o princípio de transparência e auditabilidade. O conflito é um sinal importante que não deve ser suprimido.\n\n**Resumo técnico:** A abordagem correta é "deferir e delegar" — anotar o conflito com metadados de fonte, seguir em frente com a execução local e permitir que o coordenador, com visão global, tome a decisão de reconciliação.','\n',char(10)),replace('**Explicação para uma criança de 10 anos:**\n\nImagina que você e seu amigo estão fazendo um trabalho de escola juntos. Você pesquisou e descobriu que o Brasil tem 26 estados. Seu amigo pesquisou e descobriu que o Brasil tem 27 estados. Agora vocês têm informações diferentes!\n\nSe você simplesmente **escolhesse um número e jogasse o outro fora** (alternativa A), seria como guardar só a sua resposta e ignorar a do seu amigo — isso não é legal e vocês podem perder a resposta certa.\n\nSe você **parasse tudo e ficasse grudado no problema sem fazer mais nada** (alternativa C), seria como gritar "PARE TUDO! VAMOS RESOLVER ISSO AGORA!" e não deixar ninguém mais trabalhar. Isso atrasaria todo o projeto.\n\nSe você **fingisse que o problema não existe** (alternativa D), seria como escrever qualquer número e torcer para dar certo. Pode dar errado e ninguém vai saber por quê.\n\nA melhor ideia (alternativa B) é: **anotar** "Brasil tem 26 estados (fonte: pesquisa do João) e 27 estados (fonte: pesquisa da Maria)" e deixar essa dúvida para o coordenador do grupo resolver. Assim vocês não perdem tempo, guardam as duas informações direitinho, e quem tem mais visão do trabalho todo pode descobrir qual é a resposta certa depois!','\n',char(10)));
INSERT INTO cards VALUES('admin','card_1783092986208_tipysjvza',212,'How do you preserve precise details such as values and order numbers in long conversations that are summarized?',replace('How do you preserve precise details such as values and order numbers in long conversations that are summarized?\n\nHow do you preserve precise details such as values and order numbers in long conversations that are summarized?\n[Resposta correta: Um bloco persistente de fatos do caso mantém os detalhes fora do resumo lossy. A e D confiam em instruções contra uma perda inerente à sumarização. C apenas adia o problema.]\n\n[ ] A - Instruct the model to never forget the details during summarization.\n[ ] B - Extract the transactional facts into a persistent block of "case facts" included in every prompt, outside the summarized history.\n[ ] C - Increase the history limit to postpone summarization.\n[ ] D - Trust that summarization will preserve the numbers because they are important.','\n',char(10)),'[ ] B - Extract the transactional facts into a persistent block of "case facts" included in every prompt, outside the summarized history.','["Domain_5::Context_Management_Reliability", "Domain_1::Agentic_Architecture_Orchestration", "Scenario_1::Customer_Support_Agent"]','New',0,2.5,0,1783092986208,1783727057531,1783203558653,replace('**Tradução para português do Brasil:**\n\n**Pergunta:** Como preservar detalhes precisos, como valores e números de pedidos, em conversas longas que são resumidas?\n\n**Alternativas:**\n\n[ ] A - Instruir o modelo a nunca esquecer os detalhes durante a sumarização.\n[ ] B - Extrair os fatos transacionais para um bloco persistente de "fatos do caso" incluído em cada prompt, fora do histórico resumido.\n[ ] C - Aumentar o limite do histórico para adiar a sumarização.\n[ ] D - Confiar que a sumarização preservará os números porque eles são importantes.','\n',char(10)),replace('**Explicação para um adulto tech lead:**\n\nO problema fundamental aqui é que a sumarização de conversas longas é, por natureza, um processo *lossy* (com perda de informação). Modelos de linguagem, ao resumirem, tendem a preservar o sentido geral e as decisões, mas perdem detalhes numéricos precisos (valores monetários, IDs de pedidos, quantidades etc.).\n\nVamos analisar cada alternativa:\n\n- **Alternativa A (Instruir o modelo a nunca esquecer):** Uma instrução no system prompt ou no prompt do usuário não é suficiente para evitar a perda de informação durante a sumarização. O mecanismo de sumarização é um passo de compressão que intrinsecamente descarta dados para caber no contexto. Uma instrução genérica não altera esse comportamento fundamental; o modelo pode até tentar, mas eventualmente falhará ao lidar com dezenas ou centenas de detalhes ao longo de múltiplas rodadas de sumarização.\n\n- **Alternativa B (Bloco persistente de fatos do caso):** Esta é a abordagem correta, e é amplamente utilizada em sistemas de produção (como agentes de suporte, assistentes de vendas, chatbots transacionais). A ideia é: sempre que uma informação transacional relevante aparece (ex: "pedido #12345 no valor de R$ 500,00"), ela é extraída e armazenada em uma estrutura de dados externa — um bloco de "fatos do caso" que é reinserido no contexto a cada nova interação. O histórico da conversa pode ser resumido (com perda), mas os dados críticos sobrevivem porque estão fora do resumo. Isso resolve o problema de forma arquitetural, não dependendo da capacidade do modelo de "lembrar".\n\n- **Alternativa C (Aumentar o limite do histórico):** Isso apenas adia o problema. Mais cedo ou mais tarde, o limite será atingido novamente, e a sumarização precisará ocorrer — com a mesma perda inerente de detalhes. É uma solução paliativa, não estrutural.\n\n- **Alternativa D (Confiar na importância dos números):** O modelo não tem noção de "importância" no sentido semântico-funcional. Embora ele possa dar mais peso a números em um resumo imediato, em sumarizações sucessivas (sumarização de sumarizações), os detalhes numéricos se perdem progressivamente. Confiar nisso é ingênuo do ponto de vista de engenharia.\n\n**Conclusão:** A alternativa B é a única que oferece uma solução arquitetural robusta, separando dados transacionais precisos do resumo lossy da conversa.','\n',char(10)),replace('Imagine que você está contando uma história muito longa sobre uma viagem. Você tem uma lista de todos os lugares que visitou, quanto gastou e os números dos ingressos. Se você resumir a história para contar para alguém, você pode esquecer os números exatos.\n\nAgora, pense em três jeitos de tentar não esquecer:\n\n1. **Pedir para não esquecer:** Você fala "por favor, não esqueça os números!". Mas, quando você resume, acaba esquecendo mesmo assim. Não adianta só pedir.\n\n2. **Guardar os números em um post-it separado:** Você escreve os números importantes num papelzinho (os "fatos do caso") e mantém ele sempre do lado. Quando você conta a história resumida, você ainda tem o post-it com os números certinhos. Essa é a melhor ideia!\n\n3. **Contar a história mais devagar:** Você tenta demorar mais para chegar no resumo. Mas, uma hora, você vai ter que resumir, e os números vão embora. Só adia o problema.\n\n4. **Achar que os números são tão importantes que você não vai esquecer:** Isso não funciona! Mesmo coisas importantes podem ser esquecidas quando a gente resume.\n\nEntão, a melhor maneira é a número 2: guardar os detalhes importantes separados, como num bloquinho de anotações que você leva junto com a história resumida.','\n',char(10)));
INSERT INTO cards VALUES('admin','card_1783092986222_agzp026ho',213,'A single corrupted file causes an error in the pipeline.',replace('A single corrupted file causes an error in the pipeline.\n\nA single corrupted file causes an error in the pipeline. How do you propagate this error?\n[Resposta correta: Propagar o erro com contexto ao coordenador é a resposta correta. A é inútil, pois corrupção é falha permanente, não transitória. C esconde informação e D é desproporcional.]\n\n[ ] A - Retry a few times, because retry usually solves it.\n[ ] B - Return the error with context to the coordinator and let it decide to skip, use an alternative or warn the user.\n[ ] C - Fail silently and continue with the other files.\n[ ] D - Shut down the whole workflow immediately.','\n',char(10)),'B - Return the error with context to the coordinator and let it decide to skip, use an alternative or warn the user.','["Domain_1::Agentic_Architecture_Orchestration", "Domain_4::Prompt_Engineering_Structured_Output", "Domain_5::Context_Management_Reliability", "Scenario_6::Structured_Data_Extraction"]','New',0,2.5,0,1783092986222,1783727061517,1783203558653,replace('**Tradução para português do Brasil:**\n\nPergunta: Um único arquivo corrompido causa um erro no pipeline. Como você propaga esse erro?\n\n[ ] A - Tentar novamente algumas vezes, porque uma repetição geralmente resolve.\n[ ] B - Retornar o erro com contexto para o coordenador e deixar que ele decida pular, usar uma alternativa ou avisar o usuário.\n[ ] C - Falhar silenciosamente e continuar com os outros arquivos.\n[ ] D - Desligar todo o workflow imediatamente.','\n',char(10)),replace('**Explicação para um adulto (tech lead):**\n\nA pergunta trata de como lidar com falhas em um pipeline de processamento, especificamente quando um arquivo corrompido causa um erro. O cenário é um pipeline — provavelmente um sistema ETL, de processamento em lote ou streaming — onde múltiplos arquivos são processados sequencialmente ou em paralelo, e um deles está corrompido.\n\n**Alternativa correta: B**\n\nA alternativa B é a abordagem mais madura e alinhada com boas práticas de engenharia de software, especialmente no contexto de arquiteturas resilientes e orientadas a eventos. Ela sugere:\n\n1. **Propagar o erro com contexto** — ou seja, não apenas lançar uma exceção genérica, mas incluir informações como qual arquivo falhou, qual foi a exceção específica, em que etapa do pipeline ocorreu, etc.\n2. **Delegar a decisão ao coordenador** — o coordenador (orquestrador, scheduler, workflow manager) tem uma visão全局 do pipeline e pode tomar decisões inteligentes:\n   - Pular o arquivo corrompido e continuar com os demais (se a integridade global não for comprometida).\n   - Usar uma alternativa (ex.: fallback para uma versão anterior do arquivo, ou um valor padrão).\n   - Avisar o usuário (via log, notificação, dashboard) para ação manual.\n\nEssa abordagem segue o princípio **"fail fast, fail safe, fail gracefully"**: falhe rapidamente (propague o erro), mas de forma segura e elegante (com contexto e decisão consciente).\n\n**Análise das alternativas incorretas:**\n\n- **A - Retry a few times:** Esta alternativa assume que o erro é transitório (ex.: perda de rede, timeout). Porém, o enunciado diz explicitamente que o arquivo está **corrompido** — isso é uma falha permanente, não temporária. Repetições (retry) não vão "consertar" um arquivo corrompido; apenas desperdiçarão recursos e tempo. Retry é útil para falhas transitórias, não para corrupção de dados.\n\n- **C - Fail silently and continue:** Esta é perigosa em qualquer sistema sério. Falhar silenciosamente significa engolir a exceção, ignorar o erro e seguir em frente como se nada tivesse acontecido. Isso pode levar a:\n  - Dados inconsistentes no destino.\n  - Relatórios ou decisões baseados em dados parciais ou incorretos.\n  - Dificuldade imensa de debugging, pois nenhum sinal de erro foi emitido.\n  - Violação de princípios como "fail fast" e "no silent data corruption".\n\n- **D - Shut down the whole workflow immediately:** Esta é desproporcional e antirresiliente. Um único arquivo corrompido em um lote de milhares não justifica parar todo o pipeline. Isso seria um desperdício de recursos computacionais e atrasaria todo o processamento. A abordagem correta é isolar a falha, não propagá-la cegamente para todo o sistema. Shutdown total só se justifica em casos de erro crítico e sistêmico (ex.: corrupção de schema, falha de segurança), não em uma falha isolada de um único arquivo.','\n',char(10)),replace('Imagine que você está organizando uma fila de brinquedos para colocar em caixas. De repente, um dos brinquedos está quebrado — falta uma peça. O que você faz?\n\n- **A - Tentar de novo:** Você tenta colocar o brinquedo na caixa de novo, mas ele continua quebrado. Tentar de novo não vai consertar o brinquedo, só vai perder tempo.\n- **B - A melhor escolha!** Você avisa o seu chefe (o coordenador) que aquele brinquedo específico está quebrado, explica qual é o problema, e deixa que ele decida: pular esse brinquedo, pegar outro igual, ou avisar o dono.\n- **C - Fingir que nada aconteceu:** Você coloca o brinquedo quebrado na caixa e continua como se estivesse tudo bem. Depois, quando alguém abrir a caixa, vai encontrar um brinquedo estragado e ninguém vai saber por quê. Isso é esconder o problema — muito ruim!\n- **D - Parar tudo:** Você joga todos os brinquedos no chão e desiste de organizar tudo por causa de UM brinquedo quebrado. Isso não faz sentido, né? Os outros brinquedos estão bons e podem ser guardados direitinho.\n\nEntão, a melhor coisa a fazer é a opção B: avisar o chefe do problema com detalhes, e deixar que ele decida o que fazer. Assim, o erro não passa despercebido, mas também não atrapalha todo o trabalho.','\n',char(10)));
INSERT INTO cards VALUES('admin','card_1783092986235_fi2zjnkui',214,'In the orchestrator-workers pattern, how should the findings of multiple subagents be combined?',replace('In the orchestrator-workers pattern, how should the findings of multiple subagents be combined?\n\nIn the orchestrator-workers pattern, how should the findings of multiple subagents be combined?\n[Resposta correta: A integração unificada é feita pelo agente de síntese via coordenador. A confunde concatenar com integrar. C e D quebram o controle centralizado ao permitir comunicação peer-to-peer ou contornar o coordenador.]\n\n[ ] A - By concatenating the finding texts in the order they arrive.\n[ ] B - The coordinator passes all sets of findings to a synthesis agent for unified integration.\n[ ] C - The subagents exchange findings directly with each other, peer-to-peer.\n[ ] D - Each subagent publishes its finding bypassing the coordinator.','\n',char(10)),'B - The coordinator passes all sets of findings to a synthesis agent for unified integration.','["Domain_1::Agentic_Architecture_Orchestration", "Scenario_3::Multi_Agent_Research"]','New',0,2.5,0,1783092986235,1783727064716,1783203558653,replace('**Tradução para português do Brasil:**\n\n**Pergunta:** No padrão orchestrator-workers, como os resultados de múltiplos subagentes devem ser combinados?\n\n[ ] A - Concatenando os textos dos resultados na ordem em que chegam.\n[ ] B - O coordenador passa todos os conjuntos de resultados para um agente de síntese realizar a integração unificada.\n[ ] C - Os subagentes trocam resultados diretamente entre si, ponto a ponto.\n[ ] D - Cada subagente publica seu resultado ignorando o coordenador.','\n',char(10)),replace('**Explicação para um adulto (tech lead):**\n\nNo padrão **orchestrator-workers** (orquestrador-trabalhadores), o coordenador (orchestrator) é a entidade central responsável por delegar tarefas aos workers (subagentes), coletar os resultados e coordenar a lógica de integração. Esse padrão é amplamente utilizado em arquiteturas de agentes, sistemas de microserviços e workflows distribuídos.\n\n**A alternativa correta é a B** porque ela descreve fielmente o fluxo esperado: o coordenador coleta todos os resultados parciais e os encaminha a um agente de síntese (que pode ser o próprio coordenador ou um componente especializado) para realizar a integração unificada. Isso mantém o controle centralizado e a consistência dos dados.\n\n**Análise das alternativas incorretas:**\n\n- **A** (concatenar textos na ordem de chegada): Embora pareça simples, concatenar semântica ou estruturalmente é uma abordagem ingênua. Não há garantia de que a ordem de chegada seja a ordem correta, e simplesmente concatenar não resolve conflitos, duplicações ou dependências entre os resultados. O padrão exige integração, não justaposição.\n\n- **C** (subagentes trocam resultados diretamente, peer-to-peer): Isso quebra o padrão orchestrator-workers, transformando-o em algo mais próximo de um padrão peer-to-peer ou publish-subscribe descentralizado. O coordenador perde o controle sobre o fluxo de dados e a capacidade de coordenar a síntese, o que pode levar a inconsistências, deadlocks ou complexidade adicional de coordenação.\n\n- **D** (cada subagente publica seu resultado ignorando o coordenador): Isso também viola o padrão, pois o coordenador é quem deve gerenciar o ciclo de vida e a coleta dos resultados. Publicar sem passar pelo coordenador elimina a orquestração, criando acoplamento entre os workers e dificultando a rastreabilidade, o tratamento de erros e a consistência geral do sistema.','\n',char(10)),replace('Imagine que você é o líder de um grupo de amigos que precisam montar um quebra-cabeça gigante. Cada amigo (subagente) fica responsável por montar uma parte do quebra-cabeça. Quando terminam, eles te entregam suas partes (resultados).\n\nAgora, como juntar tudo? A melhor maneira é você (o coordenador) pegar todas as partes e passar para um amigo especialista em montar quebra-cabeças (agente de síntese), que vai encaixar cada peça no lugar certo. Isso é a alternativa B.\n\nAs outras opções são ruins porque:\n\n- **A** - Só juntar as partes na ordem que chegam, sem pensar se encaixam direito. Pode ficar tudo torto!\n- **C** - Deixar os amigos passarem as peças uns para os outros. Vira uma bagunça e ninguém sabe quem está no comando.\n- **D** - Cada amigo jogar sua parte no meio da sala e sair de cena. O líder perde o controle e o quebra-cabeça nunca fica pronto direito.\n\nEntão, a resposta certa é a **B**: o coordenador junta tudo e entrega para um especialista montar o resultado final de forma organizada.','\n',char(10)));
INSERT INTO cards VALUES('admin','card_1783092986250_wga4r631j',215,'How do you propagate uncertainty due to missing sources without discarding the work already done?',replace('How do you propagate uncertainty due to missing sources without discarding the work already done?\n\nHow do you propagate uncertainty due to missing sources without discarding the work already done?\n[Resposta correta: Anotações de cobertura propagam a incerteza sem descartar o trabalho. A trata sucesso parcial como falha total. C esconde informação e D inverte a hierarquia de controle.]\n\n[ ] A - Treat partial success as total failure and restart everything.\n[ ] B - Structure the synthesis output with coverage annotations, indicating what is well grounded and where there are gaps.\n[ ] C - Hide the gaps so as not to confuse the user.\n[ ] D - Let the subagents decide the coordinator''s retry.','\n',char(10)),'B - Structure the synthesis output with coverage annotations, indicating what is well grounded and where there are gaps.','["Domain_1::Agentic_Architecture_Orchestration", "Domain_4::Prompt_Engineering_Structured_Output", "Scenario_3::Multi_Agent_Research"]','New',0,2.5,0,1783092986250,1783727068110,1783203558653,replace('**Tradução para português (pt-BR):**\n\n**Pergunta:** Como propagar a incerteza devido a fontes faltantes sem descartar o trabalho já realizado?\n\n[ ] A - Tratar o sucesso parcial como falha total e recomeçar tudo.\n[ ] B - Estruturar a saída da síntese com anotações de cobertura, indicando o que está bem fundamentado e onde existem lacunas.\n[ ] C - Esconder as lacunas para não confundir o usuário.\n[ ] D - Deixar que os subagentes decidam a repetição do coordenador.','\n',char(10)),replace('**Explicação didática para um adulto tech lead:**\n\nA pergunta aborda um problema clássico em sistemas multiagente ou pipelines de síntese de informação: como lidar com fontes de dados incompletas ou faltantes sem jogar fora o trabalho já realizado (ou seja, sem precisar reiniciar todo o processo do zero).\n\n**Por que a alternativa B está correta:**\n\nA alternativa B propõe o uso de **anotações de cobertura** (*coverage annotations*) junto com a saída da síntese. Isso significa que o sistema produz um resultado parcial, mas sinaliza explicitamente quais partes estão bem fundamentadas (com fontes confiáveis) e quais partes são incertas ou incompletas. Essa abordagem é elegante porque:\n\n- Não descarta o trabalho já feito — o que já foi sintetizado com boas fontes é preservado.\n- Propaga a incerteza de forma transparente — o consumidor da informação (seja outro sistema ou um humano) sabe exatamente onde há confiança e onde há lacunas.\n- Permite decisões informadas a montante — o usuário ou o coordenador pode decidir se quer arriscar com base no material parcial, se quer buscar mais fontes apenas para as lacunas, etc.\n\n**Por que as demais estão erradas:**\n\n- **Alternativa A** ("tratar sucesso parcial como falha total e recomeçar tudo"): Essa é a antítese do que a pergunta pede. Ela descarta todo o trabalho já realizado e não propaga incerteza — simplesmente joga tudo fora e tenta de novo. É ineficiente e não resolve o problema de fontes faltantes de forma inteligente.\n\n- **Alternativa C** ("esconder as lacunas para não confundir o usuário"): Essa abordagem viola o princípio da transparência e pode levar a decisões erradas baseadas em informação incompleta. Esconder a incerteza não a elimina; apenas transfere o risco para quem vai usar a informação. Em sistemas críticos, isso é inaceitável.\n\n- **Alternativa D** ("deixar que os subagentes decidam a repetição do coordenador"): Essa alternativa inverte a hierarquia de controle, fazendo com que subordinados (subagentes) decidam sobre a ação do coordenador. Além de ser uma má prática arquitetural, ela não resolve o problema de como propagar a incerteza — ela apenas transfere a decisão para um nível inadequado, sem abordar como as lacunas de informação são tratadas no resultado final.\n\n**Resumo técnico:** A abordagem correta (B) é um padrão conhecido em sistemas de *data fusion* e *information retrieval*: marcadores de confiança ou cobertura permitem composicionalidade e tratamento incremental da incerteza.','\n',char(10)),replace('**Explicação para uma criança de 10 anos:**\n\nImagina que você está montando um quebra-cabeça gigante, mas algumas peças sumiram. Você já encaixou muitas peças e não quer desmontar tudo só porque faltam algumas.\n\n**Alternativa B** é a melhor ideia: você monta o quebra-cabeça até onde dá, mas coloca um post-it amarelo nas partes que estão com peças faltando. Assim, quem olhar para o seu trabalho vai saber: "isso aqui está certo, mas ali está incompleto". Você não jogou fora o que já fez e mostrou honestamente onde estão os problemas.\n\n**Alternativa A** seria a pior ideia: "Ops, faltou uma peça, vou desmontar tudo e começar de novo!" — isso é loucura, perde todo o trabalho que você já teve.\n\n**Alternativa C** seria enganar os outros: você esconde os buracos com massinha e finge que está tudo certo. Mas quando alguém tentar usar seu quebra-cabeça, vai descobrir que estava faltando pedaços e pode dar tudo errado!\n\n**Alternativa D** seria o mesmo que pedir para os seus colegas de equipe decidirem se você deve refazer seu dever de casa. Não faz sentido — eles não são seus chefes, e isso não resolve o problema das peças faltando.\n\nEntão, a resposta certa é **B**: montar o que der, marcar o que falta, e seguir em frente sem jogar nada fora!','\n',char(10)));
INSERT INTO cards VALUES('admin','card_1783092986264_gcrq82p9g',216,'How do you avoid redundant work between subagents in parallel research?',replace('How do you avoid redundant work between subagents in parallel research?\n\nHow do you avoid redundant work between subagents in parallel research?\n[Resposta correta: O particionamento prévio pelo coordenador ataca a causa raiz das fronteiras pouco claras. A adiciona race conditions. C ainda gasta tokens na duplicação. D elimina o paralelismo desejado.]\n\n[ ] A - Use a shared state that all agents read from and write to.\n[ ] B - Have the coordinator explicitly partition the research space before delegating, assigning distinct subtopics.\n[ ] C - Let the agents work freely and deduplicate the results at the end.\n[ ] D - Reduce the number of agents to just one, eliminating parallelism.','\n',char(10)),'B - Have the coordinator explicitly partition the research space before delegating, assigning distinct subtopics.','["Domain_1::Agentic_Architecture_Orchestration", "Domain_2::Tool_Design_MCP_Integration", "Domain_5::Context_Management_Reliability", "Scenario_3::Multi_Agent_Research"]','New',0,2.5,0,1783092986264,1783727071760,1783203558653,replace('**Tradução para português do Brasil:**\n\n**Pergunta:** Como evitar trabalho redundante entre subagentes em pesquisa paralela?\n\n**Alternativas:**\n\n[ ] A - Use um estado compartilhado que todos os agentes leiam e escrevam.\n[ ] B - Faça com que o coordenador particione explicitamente o espaço de pesquisa antes de delegar, atribuindo subtópicos distintos.\n[ ] C - Deixe os agentes trabalharem livremente e desduplique os resultados no final.\n[ ] D - Reduza o número de agentes para apenas um, eliminando o paralelismo.','\n',char(10)),replace('**Explicação para um adulto (tech lead):**\n\nO problema central é evitar que múltiplos subagentes executem o mesmo trabalho redundante quando operam em paralelo. Isso gera desperdício de tokens, tempo e recursos computacionais.\n\n**Alternativa correta: B**\n\nA abordagem B é a mais eficaz porque ataca a **causa raiz** do problema: fronteiras pouco claras entre as responsabilidades de cada agente. Ao particionar o espaço de pesquisa **antes** da execução, o coordenador define explicitamente subtópicos mutuamente exclusivos (ex: "agente 1 pesquisa marketing, agente 2 pesquisa finanças, agente 3 pesquisa tecnologia"). Isso elimina a sobreposição de escopo e, consequentemente, o trabalho redundante. É uma estratégia de **divisão de trabalho preventiva** (design-time), que evita o problema antes que ele ocorra.\n\n**Análise das alternativas incorretas:**\n\n- **Alternativa A** — "Estado compartilhado": Esta abordagem introduz **race conditions** (condições de corrida). Se múltiplos agentes leem e escrevem no mesmo estado sem coordenação fina, há risco de inconsistências, sobrescrita de dados e, na prática, redundância ainda maior, pois cada agente pode processar a mesma informação sem saber que outro já o fez. É uma solução frágil que complexifica o sistema sem resolver a raiz do problema.\n\n- **Alternativa C** — "Deixar trabalhar livremente e desduplicar no final": Esta é uma abordagem **reativa** que permite que o trabalho duplicado ocorra. Embora a desduplicação remova entradas repetidas do resultado final, os **tokens e o tempo de computação já foram gastos** com o processamento redundante. É ineficiente e contradiz o objetivo de otimizar recursos.\n\n- **Alternativa D** — "Reduzir para um único agente": Isso elimina completamente o paralelismo, jogando fora o principal benefício de usar múltiplos agentes (ganho de velocidade e cobertura). Resolve a redundância ao custo de anular a arquitetura paralela — é uma "solução" que mata o paciente em vez de tratar a doença.\n\n**Resumo:** A melhor prática é **particionamento prévio pelo coordenador** (B), pois é uma solução preventiva, escalável e que preserva o paralelismo.','\n',char(10)),replace('Imagine que você e seus amigos precisam pesquisar sobre "animais" para um trabalho da escola.\n\n**Opção A:** Vocês escrevem tudo num cadernão compartilhado. Todo mundo pode escrever e ler. Problema: dois amigos podem pesquisar a mesma coisa (ex: leões) e escrever ao mesmo tempo, bagunçando o caderno. Além disso, ninguém sabe direito o que o outro já fez.\n\n**Opção B (a melhor!):** O professor (coordenador) diz: "João, pesquisa só sobre animais da selva. Maria, pesquisa só sobre animais domésticos. Pedro, pesquisa só sobre animais aquáticos." Assim, cada um tem seu pedaço, ninguém faz o trabalho do outro e não perdem tempo pesquisando a mesma coisa.\n\n**Opção C:** "Cada um pesquisa o que quiser e depois a gente junta tudo e tira as partes repetidas." Só que vocês gastaram um tempão pesquisando as mesmas coisas à toa. Não é eficiente.\n\n**Opção D:** "Já que pode dar problema, deixa só uma pessoa pesquisar tudo." Aí perde a vantagem de ter vários amigos ajudando ao mesmo tempo (paralelismo). Demora muito mais.\n\n**Então a resposta certa é a B:** dividir bem as tarefas antes de começar, para cada um fazer uma parte diferente.','\n',char(10)));
INSERT INTO cards VALUES('admin','card_1783092986282_0ka7qrxtx',217,'Why distinguish a timeout from a valid empty result ("0 results")?',replace('Why distinguish a timeout from a valid empty result ("0 results")?\n\nWhy distinguish a timeout from a valid empty result ("0 results")?\n[Resposta correta: Timeout e resultado vazio têm significados distintos e exigem tratamentos diferentes. A trata o vazio como falha, gerando retries inúteis. C ignora que timeout pode exigir retry. D agrega os dois, destruindo informação acionável.]\n\n[ ] A - Because both are failures and should trigger a retry.\n[ ] B - Because they are semantically different: a timeout is unknown data (evaluate retry), whereas "0 results" is a successful query that found nothing.\n[ ] C - Because both are valid findings and require no retry.\n[ ] D - Because a timeout should be treated as "0 results" to simplify.','\n',char(10)),'B - Because they are semantically different: a timeout is unknown data (evaluate retry), whereas "0 results" is a successful query that found nothing.','["Domain_5::Context_Management_Reliability", "Domain_4::Prompt_Engineering_Structured_Output", "Scenario_6::Structured_Data_Extraction"]','New',0,2.5,0,1783092986282,1783727075451,1783203558653,replace('**Tradução para português do Brasil:**\n\n**Por que distinguir um timeout de um resultado vazio ("0 resultados")?**\n\n[ ] A - Porque ambos são falhas e devem disparar uma nova tentativa (retry).\n[ ] B - Porque eles são semanticamente diferentes: um timeout representa dados desconhecidos (avaliar retry), enquanto "0 resultados" é uma consulta bem-sucedida que não encontrou nada.\n[ ] C - Porque ambos são resultados válidos e não exigem retry.\n[ ] D - Porque um timeout deve ser tratado como "0 resultados" para simplificar.','\n',char(10)),replace('**Explicação para um adulto tech lead:**\n\nA pergunta aborda um princípio fundamental de design de sistemas resilientes: a distinção semântica entre diferentes códigos de erro/estado de resposta. Confundir um timeout (falha de comunicação ou processamento) com um resultado vazio bem-sucedido leva a decisões operacionais incorretas.\n\n**Alternativa correta: B**\n\n- **Por que B está correta:** Timeout e "0 resultados" são semanticamente diferentes. Um timeout indica que não sabemos se o dado existe ou não — a operação não foi concluída com sucesso. Isso sugere que um retry pode ser apropriado (com backoff, circuit breaker, etc.). Já "0 resultados" é uma resposta bem-sucedida: o sistema consultado funcionou corretamente e afirmou que não há dados correspondentes. Tratar esse caso como falha geraria retries desnecessários, desperdiçando recursos e potencialmente causando efeitos colaterais (como duplicação de operações em sistemas idempotentes imperfeitos).\n\n- **Alternativa A (errada):** Afirma que ambos são falhas e devem disparar retry. Isso está incorreto porque "0 resultados" **não é uma falha** — é uma resposta válida. Aplicar retry cegamente nesse cenário pode mascarar problemas de design (ex: consultas sendo repetidas sem necessidade) e aumentar a carga no sistema.\n\n- **Alternativa C (errada):** Afirma que ambos são resultados válidos e não exigem retry. Um timeout **não é um resultado válido** no sentido de conclusão bem-sucedida da operação. Ignorar timeouts e não tentar retry pode levar a perda de dados e inconsistências no sistema.\n\n- **Alternativa D (errada):** Sugere tratar timeout como "0 resultados" para simplificar. Isso destrói informação acionável. Ao unificar os dois cenários, você perde a capacidade de tomar decisões diferentes: o timeout indicaria a necessidade de investigar problemas de rede, latência ou capacidade; "0 resultados" indicaria ausência de dados. Essa simplificação excessiva esconde problemas operacionais reais.','\n',char(10)),replace('Imagine que você pediu para seu amigo procurar um brinquedo no quarto dele.\n\n**Timeout** é como se você ficasse esperando e seu amigo nunca respondesse — ele pode não ter ouvido, pode ter ido embora, ou a linha do telefone caiu. Você não sabe se o brinquedo existe ou não, então talvez precise perguntar de novo (retry).\n\n**"0 resultados"** é como se seu amigo respondesse: "Olhei no quarto todo e não tem esse brinquedo, pode ter certeza!" Isso é uma resposta bem-sucedida — ele fez o combinado, só não encontrou nada.\n\nSe você tratar os dois da mesma forma, pode acontecer:\n- Pedir para seu amigo procurar de novo mesmo ele já tendo confirmado que não tem (retry inútil).\n- Ou achar que está tudo bem, quando na verdade seu amigo não respondeu e você ficou sem saber se o brinquedo existe (perdeu informação importante).\n\nPor isso a alternativa B está correta: eles são diferentes, e cada um exige uma reação diferente.','\n',char(10)));
INSERT INTO cards VALUES('admin','card_1783092986297_l70tc75gh',218,'Tool names and descriptions with semantic overlap confuse the coordinator.',replace('Tool names and descriptions with semantic overlap confuse the coordinator.\n\nTool names and descriptions with semantic overlap confuse the coordinator. How do you fix it?\n[Resposta correta: A correção certa é reescrever nomes e descrições na origem para remover ambiguidade. A é overengineering. C mantém a ambiguidade ao corrigir só um lado. D ignora o problema.]\n\n[ ] A - Build a classifier to pick the right tool at runtime.\n[ ] B - Rename and rewrite the descriptions to eliminate ambiguous terms, fixing the definition at the source.\n[ ] C - Fix only the name of one of the tools.\n[ ] D - Leave it as is, because the coordinator learns over time.','\n',char(10)),'B - Rename and rewrite the descriptions to eliminate ambiguous terms, fixing the definition at the source.','["Domain_2::Tool_Design_MCP_Integration", "Domain_1::Agentic_Architecture_Orchestration", "Scenario_4::Developer_Productivity"]','New',0,2.5,0,1783092986297,1783727079074,1783203558653,replace('**Tradução:**\n\nNomes e descrições de ferramentas com sobreposição semântica confundem o coordenador. Como você corrige isso?\n\n[ ] A - Construir um classificador para escolher a ferramenta certa em tempo de execução.\n[ ] B - Renomear e reescrever as descrições para eliminar termos ambíguos, corrigindo a definição na origem.\n[ ] C - Corrigir apenas o nome de uma das ferramentas.\n[ ] D - Deixar como está, porque o coordenador aprende com o tempo.','\n',char(10)),replace('**Explicação para adulto (tech lead):**\n\nO problema central é que nomes e descrições de ferramentas com sobreposição semântica criam ambiguidade para o coordenador (seja ele um LLM, um orquestrador ou um sistema de roteamento). O coordenador precisa decidir qual ferramenta invocar com base nessas definições; se elas forem semanticamente indistintas, a decisão se torna arbitrária ou propensa a erros.\n\nA alternativa **B** é a resposta correta porque ataca a causa raiz: a definição ambígua na origem. Renomear e reescrever as descrições para eliminar termos sobrepostos garante que cada ferramenta tenha um propósito claramente distinto, permitindo que o coordenador faça a escolha correta de forma determinística ou com alta confiança. É uma abordagem de design de API/interface, onde a clareza da especificação resolve o problema de roteamento.\n\n**Por que as demais estão erradas:**\n\n- **A** (construir um classificador em runtime): é overengineering. Em vez de corrigir a fonte da ambiguidade, você adiciona complexidade (um modelo ML ou regras heurísticas) para lidar sintomaticamente com um problema de definição. Aumenta latência, custo de manutenção e pontos de falha, sem eliminar a raiz do problema.\n- **C** (corrigir apenas o nome de uma ferramenta): insuficiente. Se a descrição ainda contém termos sobrepostos, a ambiguidade persiste no conteúdo semântico que o coordenador realmente processa. O nome é apenas um identificador; a descrição carrega o significado. Corrigir só um lado mantém a confusão.\n- **D** (deixar como está, pois o coordenador aprende): é uma falsa expectativa. Coordenadores baseados em LLM não "aprendem" com o tempo em uma única sessão sem fine-tuning ou memória persistente. Mesmo que aprendessem, a ambiguidade continuaria causando erros até que o aprendizado ocorresse — se é que ocorreria. Ignorar o problema leva a falhas consistentes e imprevisíveis.','\n',char(10)),replace('Imagine que você tem duas caixas de brinquedos. Uma está escrita "Brinquedos Legais" e a outra "Brinquedos Divertidos". Você quer guardar um carrinho, mas não sabe em qual caixa colocar, porque as duas descrições são quase a mesma coisa! Isso confunde até a pessoa mais organizada.\n\nA melhor solução é trocar os nomes e as descrições das caixas para que fique bem claro o que vai em cada uma. Por exemplo: "Caixa de Carrinhos" e "Caixa de Bonecos". Pronto, agora está fácil de decidir!\n\nSe você tentar criar um robô complicado só para escolher a caixa certa toda vez, isso dá muito mais trabalho e ainda pode errar. Se você trocar só o nome de uma caixa, mas manter a descrição confusa, ainda vai ficar difícil de escolher. E se você não fizer nada porque acha que a pessoa vai aprender sozinha... bem, ela vai continuar se confundindo para sempre.\n\nEntão a resposta certa é a letra B: arrumar os nomes e as descrições direto na origem, para acabar com a confusão de uma vez.','\n',char(10)));
INSERT INTO cards VALUES('admin','card_1783092986321_w8cm6jfhb',219,'In an agent hierarchy, where should errors be handled?',replace('In an agent hierarchy, where should errors be handled?\n\nIn an agent hierarchy, where should errors be handled?\n[Resposta correta: O tratamento deve ocorrer no nível mais baixo capaz de resolver. A aumenta o ônus do coordenador. C esconde problemas e D adiciona complexidade desnecessária.]\n\n[ ] A - Always in the coordinator, which validates everything centrally.\n[ ] B - At the lowest level capable of resolving them, with the subagent recovering transient failures and propagating only what it cannot resolve.\n[ ] C - By masking the error as success so as not to interrupt the flow.\n[ ] D - In an extra layer dedicated exclusively to errors.','\n',char(10)),'B - At the lowest level capable of resolving them, with the subagent recovering transient failures and propagating only what it cannot resolve.','["Domain_1::Agentic_Architecture_Orchestration", "Scenario_3::Multi_Agent_Research"]','New',0,2.5,0,1783092986321,1783727082540,1783203558653,replace('**Tradução (pt-BR):**\n\nPergunta: Em uma hierarquia de agentes, onde os erros devem ser tratados?\n\n[ ] A - Sempre no coordenador, que valida tudo centralmente.\n[ ] B - No nível mais baixo capaz de resolvê-los, com o subagente recuperando falhas transitórias e propagando apenas o que não consegue resolver.\n[ ] C - Mascarando o erro como sucesso para não interromper o fluxo.\n[ ] D - Em uma camada extra dedicada exclusivamente a erros.','\n',char(10)),replace('**Explicação para adulto (tech lead):**\n\nA alternativa **B** está correta porque segue o princípio de **resiliência em sistemas distribuídos e design orientado a falhas**. Em uma hierarquia de agentes (ex.: arquiteturas multiagente ou micros serviços encadeados), a responsabilidade pelo tratamento de erros deve ser delegada ao nível mais baixo que tenha contexto e capacidade para resolvê-lo. Isso porque:\n\n- **Transient failures** (timeouts, contenção de recursos, flutuações de rede) são recuperáveis localmente no subagente, sem necessidade de escalation. Isso reduz latência, evita congestionamento no coordenador e mantém a autonomia dos agentes.\n- Apenas erros que o subagente **não consegue resolver** (ex.: dados inválidos, permissão negada, recurso inexistente) devem ser propagados para cima, permitindo que o coordenador tome decisões de mais alto nível.\n\n**Análise das alternativas incorretas:**\n\n- **A – Sempre no coordenador:** Embora centralizar o tratamento pareça simplificar, isso cria um **ponto único de falha**, aumenta o acoplamento e sobrecarrega o coordenador com detalhes de baixo nível que cada subagente deveria gerenciar. Viola o princípio de **Separation of Concerns**.\n\n- **C – Mascarar o erro como sucesso:** Isso é **extremamente perigoso**. Ocultar falhas compromete a integridade do sistema, dificulta debugging, quebra contratos entre agentes e pode levar a **corrupção silenciosa de estado**. Nenhum sistema robusto adota essa prática.\n\n- **D – Camada extra exclusiva para erros:** Introduz complexidade arquitetural desnecessária, aumenta a latência (todo erro precisaria ser roteado para essa camada) e frequentemente não possui o **contexto específico** do subagente para resolver o problema. É um antipadrão que pode ser substituído por uma abordagem mais enxuta como a da alternativa B.','\n',char(10)),replace('Imagine que você está organizando uma gincana com seus amigos. Você é o líder, e cada amigo cuida de uma tarefa diferente: um busca a bola, outro prepara a água, outro arruma a música.\n\nSe o amigo que busca a bola tropeçar, ele deve tentar se levantar sozinho e continuar, certo? Só se ele realmente não conseguir (a bola furou, por exemplo), ele pede ajuda para você, o líder.\n\nA alternativa **B** é exatamente isso: **cada pessoa tenta resolver o problema sozinha primeiro**. Só pede ajuda para o chefe se for algo muito difícil.\n\nAs outras opções são ruins:\n- **A** (sempre o líder resolve) – O líder fica muito ocupado e não dá conta de tudo.\n- **C** (fingir que o erro não aconteceu) – Se o amigo caiu e finge que está tudo bem, a bola nunca chega. Isso é enganação e bagunça tudo.\n- **D** (criar uma pessoa só para cuidar de erros) – Isso deixa tudo mais complicado, e essa pessoa não entende direito cada tarefa para ajudar de verdade.\n\nEntão o melhor é cada um resolver o que consegue, e só pedir ajuda quando for necessário. 😊','\n',char(10)));
INSERT INTO cards VALUES('admin','card_1783092986344_ok8qsqcl2',220,'How do you mitigate the "lost in the middle" effect when aggregating many sources into a long context?',replace('How do you mitigate the "lost in the middle" effect when aggregating many sources into a long context?\n\nHow do you mitigate the "lost in the middle" effect when aggregating many sources into a long context?\n[Resposta correta: O resumo em posição de primazia mais cabeçalhos melhora a recuperação, pois o modelo lê melhor início e fim. A pode perder descobertas. C impede a síntese holística e D coloca o essencial na região de pior recuperação.]\n\n[ ] A - Summarize all sources into a single short paragraph.\n[ ] B - Put a summary of the key findings at the beginning and organize the detail with explicit section headers.\n[ ] C - Process the sources sequentially, one at a time.\n[ ] D - Place the most important information exactly in the middle of the context.','\n',char(10)),'B - Put a summary of the key findings at the beginning and organize the detail with explicit section headers.','["Domain_5::Context_Management_Reliability", "Domain_4::Prompt_Engineering_Structured_Output", "Scenario_3::Multi_Agent_Research"]','New',0,2.5,0,1783092986344,1783727086232,1783203558653,replace('**Tradução para português do Brasil:**\n\n**Pergunta:** Como você mitiga o efeito "perdido no meio" ao agregar muitas fontes em um contexto longo?\n\n**Alternativas:**\n[ ] A - Resumir todas as fontes em um único parágrafo curto.\n[ ] B - Colocar um resumo das principais descobertas no início e organizar os detalhes com cabeçalhos de seção explícitos.\n[ ] C - Processar as fontes sequencialmente, uma de cada vez.\n[ ] D - Colocar a informação mais importante exatamente no meio do contexto.','\n',char(10)),replace('**Explicação Didática para Adulto (Tech Lead)**\n\nO efeito "lost in the middle" (perdido no meio) é um fenômeno bem documentado em modelos de linguagem de grande porte (LLMs), especialmente aqueles baseados em Transformers. Ele descreve a tendência do modelo de reter e recuperar melhor informações localizadas no início (primazia) e no fim (recência) do contexto de entrada, enquanto informações posicionadas no meio têm desempenho inferior.\n\n**Por que a alternativa B é a correta?**\n\nA alternativa B utiliza duas estratégias complementares e baseadas em evidências empíricas:\n\n1. **Resumo no início (primazia):** Ao colocar um resumo das principais descobertas logo no começo do prompt, você capitaliza o viés de primazia do modelo. Isso garante que as informações mais críticas sejam processadas com maior atenção e tenham maior probabilidade de serem recuperadas durante a geração da resposta.\n\n2. **Organização com cabeçalhos de seção explícitos:** Cabeçalhos funcionam como "marcadores de atenção". Eles criam uma estrutura hierárquica que ajuda o modelo a segmentar o contexto em blocos lógicos, melhorando a navegação interna. Além disso, estudos recentes mostram que cabeçalhos podem atuar como "âncoras" que o modelo utiliza para localizar informações relevantes, mesmo que estejam no meio do contexto.\n\n**Análise das alternativas incorretas:**\n\n- **Alternativa A (Resumir todas as fontes em um único parágrafo curto):** Embora reduzir o tamanho do contexto possa ajudar indiretamente, condensar tudo em um único parágrafo curto pode levar à perda de descobertas importantes ou nuances. Você está essencialmente comprimindo informação, o que pode sacrificar detalhes críticos. O modelo pode perder sutilezas ou dados específicos que estavam nas fontes originais.\n\n- **Alternativa C (Processar as fontes sequencialmente, uma de cada vez):** Essa abordagem impede a síntese holística das informações. Se o modelo processa uma fonte de cada vez, ele não consegue estabelecer conexões, contrastar informações ou fazer inferências que dependem da visão combinada de múltiplas fontes. Isso quebra a capacidade de raciocínio cross-documento.\n\n- **Alternativa D (Colocar a informação mais importante exatamente no meio do contexto):** Esta é precisamente a pior posição para colocar informações críticas. O efeito "lost in the middle" mostra que o meio do contexto é a região de pior recuperação. Colocar o essencial ali é garantir que o modelo tenha a maior probabilidade de ignorá-lo ou não recuperá-lo adequadamente.','\n',char(10)),replace('**Explicação para uma criança de 10 anos:**\n\nImagina que você tem uma redação muito, muito longa para ler. Você percebe que consegue lembrar melhor do começo e do final da redação, mas o meio você sempre esquece. Isso é o "efeito perdido no meio"!\n\nAgora, a pergunta é: como a gente faz para que você não esqueça as partes importantes do meio?\n\nA melhor maneira (alternativa B) é fazer duas coisas:\n\n1. **Contar o resumo no começo:** É como se, antes de ler a redação inteira, alguém te dissesse: "Olha, as coisas mais importantes são estas aqui!". Assim, mesmo que você esqueça o meio, já gravou o essencial.\n\n2. **Usar títulos grandes e claros:** É como colocar divisórias no seu armário de brinquedos: "Aqui é a parte dos carrinhos", "Aqui é a parte dos jogos". Os títulos ajudam seu cérebro a saber onde cada coisa está e achar mais fácil.\n\n**Por que as outras opções não são tão boas?**\n\n- **Opção A (resumir tudo em um parágrafo pequeno):** É como tentar apertar uma festa inteira dentro de uma caixa de sapato. Você vai acabar perdendo vários detalhes legais!\n\n- **Opção C (ler uma fonte de cada vez):** É como tentar montar um quebra-cabeça olhando uma peça por vez, sem ver a figura completa na caixa. Você não consegue entender como as peças se encaixam.\n\n- **Opção D (colocar o mais importante bem no meio):** É a pior ideia! Lembra que o meio é justamente o lugar que a gente esquece? É como esconder o presente mais legal no fundo de um armário bagunçado. Ninguém vai achar!','\n',char(10)));
INSERT INTO cards VALUES('admin','card_1783092986376_dlfqxvqgu',221,'How do you overcome confirmation bias when Claude reviews its own work?',replace('How do you overcome confirmation bias when Claude reviews its own work?\n\nHow do you overcome confirmation bias when Claude reviews its own work?\n[Resposta correta: Uma segunda instância independente avalia com perspectiva fresca, sem os vieses do gerador. A, C e D mantêm o mesmo contexto e os mesmos vieses, sem pegar o que já foi racionalizado como correto.]\n\n[ ] A - Give more "thinking" time to the same instance to review again.\n[ ] B - Use a second independent instance to review without seeing the generator''s reasoning.\n[ ] C - Provide more context to the same instance that generated the work.\n[ ] D - Ask the instance to reread its own reasoning carefully.','\n',char(10)),'B - Use a second independent instance to review without seeing the generator''s reasoning.','["Domain_1::Agentic_Architecture_Orchestration", "Domain_4::Prompt_Engineering_Structured_Output", "Scenario_5::Claude_Code_CI_CD"]','New',0,2.5,0,1783092986376,1783727089610,1783203558653,replace('**Tradução para português do Brasil:**\n\n**Pergunta:** Como superar o viés de confirmação quando o Claude revisa o próprio trabalho?\n\n[ ] A - Dar mais "tempo de raciocínio" para a mesma instância revisar novamente.\n[ ] B - Usar uma segunda instância independente para revisar sem ver o raciocínio do gerador.\n[ ] C - Fornecer mais contexto para a mesma instância que gerou o trabalho.\n[ ] D - Pedir para a instância reler seu próprio raciocínio cuidadosamente.','\n',char(10)),replace('**Explicação para um adulto (tech lead):**\n\nO viés de confirmação ocorre quando um modelo tende a favorecer informações que confirmam suas próprias conclusões anteriores, ignorando evidências contrárias. Quando uma mesma instância do Claude revisa seu próprio trabalho, ela carrega os mesmos pesos, contextos e caminhos de raciocínio que levaram à resposta original, tornando a revisão tendenciosa.\n\n**Por que B é a resposta correta?**\n\nA alternativa B propõe o uso de uma segunda instância independente que não tem acesso ao raciocínio do gerador. Isso quebra o viés de confirmação porque:\n- A nova instância parte de um estado "fresco" (sem contexto prévio).\n- Ela não está contaminada pelo caminho lógico que o gerador seguiu.\n- Pode identificar erros, inconsistências e falhas que a instância original racionalizou como corretas.\n- É análoga ao princípio de "pair review" ou "separação de responsabilidades" em engenharia de software: o revisor não deve saber os detalhes internos da implementação para julgar imparcialmente.\n\n**Por que A, C e D estão erradas?**\n\n- **A (mais tempo de raciocínio):** Apenas prolongar o processamento na mesma instância não elimina o viés — o modelo continuará reforçando suas próprias conclusões, apenas com mais elaboração.\n- **C (mais contexto):** Fornecer mais contexto para a mesma instância pode, na verdade, agravar o viés de confirmação, pois o modelo terá ainda mais material para racionalizar sua resposta original.\n- **D (reler o próprio raciocínio):** Reler o próprio raciocínio é ineficaz porque a instância já "acredita" na sua saída. O viés de confirmação não é resolvido por autoinspeção — o modelo precisa de um ponto de vista externo.','\n',char(10)),replace('Imagine que você escreveu uma redação e está muito orgulhoso dela. Seu professor pede para você mesmo revisar. Você vai achar que está tudo certo, porque você gosta do que escreveu. Isso é o "viés de confirmação" — você só enxerga o que confirma que você está certo.\n\nAgora, se seu professor pedir para um **outro colega** (que não viu você escrevendo) ler a redação, esse colega vai enxergar erros que você não viu, porque ele está olhando com "olhos novos".\n\nÉ a mesma coisa com o Claude. Se a mesma instância tenta revisar o próprio trabalho, ela continua achando que está tudo certo (alternativas A, C e D). Mas se uma **segunda instância independente** (alternativa B) revisar sem saber como a resposta foi criada, ela consegue encontrar erros que passaram despercebidos. É como ter um amigo para revisar sua lição de casa!','\n',char(10)));
INSERT INTO cards VALUES('admin','card_1783092986391_0csygcvkp',222,'How do you make severity classification more consistent across runs?',replace('How do you make severity classification more consistent across runs?\n\nHow do you make severity classification more consistent across runs?\n[Resposta correta: Critérios explícitos com exemplos por nível tornam a classificação consistente. A perde contexto, pois o mesmo tipo pode ter severidades diferentes. C introduz mais inconsistência e D não define nada.]\n\n[ ] A - Map each issue type directly to a fixed severity.\n[ ] B - Include explicit severity criteria in the prompt, with concrete code examples for each level.\n[ ] C - Use relative ratings, comparing each issue with the previous one.\n[ ] D - Let the model decide freely on each run.','\n',char(10)),'[ ] B - Include explicit severity criteria in the prompt, with concrete code examples for each level.','["Domain_4::Prompt_Engineering_Structured_Output", "Domain_5::Context_Management_Reliability", "Scenario_5::Claude_Code_CI_CD"]','New',0,2.5,0,1783092986391,1783727092717,1783203558653,replace('**Tradução para Português do Brasil:**\n\nPergunta: "Como tornar a classificação de severidade mais consistente entre execuções?"\n\nAlternativas:\n[ ] A - Mapear cada tipo de problema diretamente para uma severidade fixa.\n[ ] B - Incluir critérios explícitos de severidade no prompt, com exemplos concretos de código para cada nível.\n[ ] C - Usar classificações relativas, comparando cada problema com o anterior.\n[ ] D - Deixar o modelo decidir livremente a cada execução.','\n',char(10)),replace('**Explicação para um adulto tech lead:**\n\nA pergunta aborda um problema clássico ao usar LLMs para classificação de severidade de issues (bugs, vulnerabilidades, etc.): a inconsistência entre diferentes execuções (runs) do mesmo prompt. Vamos analisar cada alternativa:\n\n**Alternativa B (correta):** Incluir critérios explícitos de severidade no prompt, com exemplos concretos de código para cada nível. Esta é a abordagem mais robusta porque:\n- Define uma escala clara e objetiva (ex.: Crítico = afeta dados do cliente, Alto = causa falha funcional sem perda de dados, Médio = degradação de performance, Baixo = cosmético).\n- Os exemplos de código funcionam como âncoras concretas que o modelo pode usar como referência, reduzindo a ambiguidade.\n- Cria um "contrato" de classificação que pode ser replicado exatamente entre runs, promovendo consistência.\n\n**Alternativa A (incorreta):** Mapear cada issue type para uma severidade fixa. Isso ignora o contexto — o mesmo tipo de problema (ex.: NullPointerException) pode ser Crítico se ocorrer no fluxo de pagamento ou Baixo se for em uma página de relatório interno. Perde-se precisão ao desconsiderar a gravidade real no contexto do sistema.\n\n**Alternativa C (incorreta):** Classificações relativas (comparar cada issue com a anterior). Isso introduz um viés de ordem: a classificação do item N depende de qual item veio antes, e não de critérios absolutos. Além disso, se a ordem das issues mudar entre runs, a classificação pode mudar completamente.\n\n**Alternativa D (incorreta):** Deixar o modelo decidir livremente. Isso maximiza a variabilidade. Sem critérios explícitos, o modelo pode aplicar "achismos" diferentes a cada execução, baseados em padrões de treinamento não controlados, levando a classificações imprevisíveis e não reprodutíveis.\n\n**Conclusão técnica:** A consistência em tarefas de classificação com LLMs exige redução de ambiguidade através de critérios explícitos, exemplos concretos e formatação padronizada. A alternativa B atende a todos esses requisitos.','\n',char(10)),replace('Imagina que você e seus amigos estão brincando de classificar desenhos em "muito bonito", "bonito" e "mais ou menos". Se cada um decidir sozinho o que acha, um pode achar o mesmo desenho "muito bonito" e outro "mais ou menos". Não tem regra!\n\nA pergunta é como fazer todo mundo classificar igual, toda vez que olhar para os desenhos.\n\nSe a gente disser: "O desenho é muito bonito se tiver 5 cores diferentes e um sol no canto", aí todo mundo vai julgar igual. É mais ou menos isso que a opção B faz: ela coloca regras e exemplos bem claros (tipo "se o código quebrar o site todo, é severidade alta; se for só um botão torto, é severidade baixa").\n\nAs outras opções são ruins porque:\n- A opção A diz "se é um desenho de flor, sempre é bonito" — mas nem toda flor é bonita, né?\n- A opção C diz para comparar com o desenho anterior — isso é injusto, porque depende de qual veio antes.\n- A opção D é cada um fazer o que quiser — aí vira bagunça total!\n\nEntão a resposta certa é a B: colocar regras claras com exemplos para todo mundo seguir igual.','\n',char(10)));
INSERT INTO cards VALUES('admin','card_1783092986406_iqogtrrhs',223,'How do you reliably ensure structured and parseable output in a CI/CD pipeline?',replace('How do you reliably ensure structured and parseable output in a CI/CD pipeline?\n\nHow do you reliably ensure structured and parseable output in a CI/CD pipeline?\n[Resposta correta: As flags --output-format json e --json-schema forçam saída bem-formada. A é seguida de forma inconsistente. C adiciona custo e complexidade e D não garante estrutura.]\n\n[ ] A - Instruct the desired format in the prompt and trust it will be followed.\n[ ] B - Use the --output-format json and --json-schema flags to force well-formed output and then parse it.\n[ ] C - Pass the output through a second LLM that reformats it into JSON.\n[ ] D - Increase max_tokens to fit the complete JSON.','\n',char(10)),'B - Use the --output-format json and --json-schema flags to force well-formed output and then parse it.','["Domain_4::Prompt_Engineering_Structured_Output", "Domain_3::Claude_Code_Configuration_Workflows", "Scenario_5::Claude_Code_CI_CD"]','New',0,2.5,0,1783092986406,1783727096300,1783203558653,replace('**Tradução para português do Brasil:**\n\n**Pergunta:** Como garantir de forma confiável uma saída estruturada e parseável em um pipeline de CI/CD?\n\n[ ] A - Instruir o formato desejado no prompt e confiar que será seguido.\n[ ] B - Usar as flags --output-format json e --json-schema para forçar uma saída bem-formada e então fazer o parsing dela.\n[ ] C - Passar a saída por um segundo LLM que a reformate em JSON.\n[ ] D - Aumentar max_tokens para caber o JSON completo.','\n',char(10)),replace('**Explicação para um adulto tech lead:**\n\nA alternativa **B** é a correta porque oferece a abordagem mais determinística e robusta para garantir que a saída de um modelo de linguagem (LLM) seja estruturada e parseável.\n\n- **Por que B está correta:** Flags como `--output-format json` e `--json-schema` (disponíveis em APIs modernas como OpenAI e Anthropic) instruem o modelo a produzir saída estritamente JSON, frequentemente com validação no nível da API. Isso significa que, se o modelo produzir JSON mal-formado, a própria API pode rejeitar ou corrigir a saída antes de entregá-la ao cliente. Isso elimina a necessidade de pós-processamento reparador e garante que o pipeline de CI/CD possa consumir a saída de forma confiável sem quebras inesperadas.\n\n- **Por que A está errada:** Instruir o formato no prompt e "confiar" é frágil. Modelos de linguagem são probabilísticos — mesmo com instruções claras, eles podem ocasionalmente desviar do formato, adicionar texto extra, comentários, ou produzir JSON inválido. Em um pipeline de CI/CD, onde automação e previsibilidade são essenciais, confiar apenas no prompt é arriscado.\n\n- **Por que C está errada:** Usar um segundo LLM para reformatar a saída adiciona latência, custo computacional (duas chamadas de API em vez de uma) e complexidade operacional. Além disso, o segundo LLM também pode cometer erros, introduzindo outra camada de não-determinismo. Não é uma solução escalável ou eficiente para um pipeline automatizado.\n\n- **Por que D está errada:** Aumentar `max_tokens` não resolve problemas de estrutura. Mesmo com tokens ilimitados, o modelo pode ainda produzir JSON inválido (ex: quebra de chaves, vírgulas faltando, strings não escapadas). O parâmetro `max_tokens` controla o limite de comprimento, não a qualidade ou conformidade estrutural da saída.','\n',char(10)),replace('Imagine que você tem uma máquina que precisa ser muito organizada, como um robô que só entende listas bem arrumadas. Se você pedir para a máquina "me dá uma lista" e torcer para ela acertar, pode ser que ela escreva tudo bagunçado.\n\nA melhor maneira de garantir que a máquina vai te dar uma lista certinha é usar os "comandos mágicos" certos, como `--output-format json`. Isso é como dar um caderno com linhas e dizer "escreva aqui, exatamente assim". Assim, a máquina sabe o formato esperado e não tem como errar.\n\nAs outras opções são:\n- A: Pedir e torcer. Não é confiável.\n- C: Pedir para outro robô arrumar. Isso demora mais e gasta mais energia.\n- D: Dar mais papel para escrever. Isso não resolve se a escrita for bagunçada.\n\nEntão, a resposta correta é a **B**: usar os comandos certos para garantir que a saída já venha no formato certo!','\n',char(10)));
INSERT INTO cards VALUES('admin','card_1783092986420_8wsvdlwre',224,'How do you decide which workloads to assign to the Message Batches API and which to keep synchronous?',replace('How do you decide which workloads to assign to the Message Batches API and which to keep synchronous?\n\nHow do you decide which workloads to assign to the Message Batches API and which to keep synchronous?\n[Resposta correta: Apenas cargas tolerantes a latência vão ao batch, e o que bloqueia merge fica síncrono. A e C ignoram que o batch não dá garantia de tempo mesmo quando termina rápido. D descarta indevidamente os ganhos do batch em cargas adequadas.]\n\n[ ] A - Assign to batch the hooks that block merge, because the savings are worth it.\n[ ] B - Assign to batch only latency-tolerant workloads, like nightly analysis, and keep synchronous the ones that block merge.\n[ ] C - Assign everything to batch, because it usually finishes fast.\n[ ] D - Keep everything synchronous, because batch is never reliable.','\n',char(10)),'[ ] B - Assign to batch only latency-tolerant workloads, like nightly analysis, and keep synchronous the ones that block merge.','["Domain_5::Context_Management_Reliability", "Scenario_4::Developer_Productivity"]','New',0,2.5,0,1783092986420,1783727100126,1783203558653,replace('**Tradução para português do Brasil:**\n\n**Pergunta:** Como você decide quais workloads atribuir à Message Batches API e quais manter síncronos?\n\n**[Resposta correta: Apenas cargas tolerantes a latência vão ao batch, e o que bloqueia merge fica síncrono. A e C ignoram que o batch não dá garantia de tempo mesmo quando termina rápido. D descarta indevidamente os ganhos do batch em cargas adequadas.]**\n\n[ ] A - Atribuir ao batch os hooks que bloqueiam o merge, porque a economia de custos compensa.\n[ ] B - Atribuir ao batch apenas workloads tolerantes a latência, como análises noturnas, e manter síncronos aqueles que bloqueiam o merge.\n[ ] C - Atribuir tudo ao batch, porque geralmente ele termina rápido.\n[ ] D - Manter tudo síncrono, porque o batch nunca é confiável.','\n',char(10)),replace('**Explicação para um adulto tech lead:**\n\nA Message Batches API do OpenAI foi projetada para processamento assíncrono em lote, oferecendo 50% de desconto sobre os preços padrão, mas com a ressalva de que **não há SLA de tempo de conclusão** — os resultados podem levar minutos ou horas, dependendo da fila e da disponibilidade.\n\n**Alternativa B é a correta** porque adota a estratégia mais sensata: workloads tolerantes a latência (como análises noturnas, geração de relatórios, processamento de dados em background) são candidatos naturais ao batch, já que o tempo de resposta não é crítico. Já workloads síncronos que bloqueiam o fluxo principal (como hooks que impedem um merge, validações em tempo real, chamadas que o usuário aguarda) devem permanecer síncronos, pois exigem resposta imediata e previsível.\n\n**Por que as demais estão erradas:**\n\n- **A** sugere colocar hooks que bloqueiam merge no batch. Isso é arriscado, pois o merge pode ficar travado por um período imprevisível (minutos a horas), impactando negativamente o fluxo de desenvolvimento. A economia de custos não justifica o bloqueio.\n\n- **C** sugere enviar tudo para o batch, assumindo que "geralmente termina rápido". O problema é que "geralmente" não é garantia — sem SLA, há cenários em que o batch pode demorar muito, e workloads que exigem resposta imediata sofrerão com isso.\n\n- **D** descarta completamente o batch, ignorando os benefícios reais (custo reduzido, simplicidade operacional) para workloads que não dependem de latência baixa. O batch é confiável para os casos certos; apenas não oferece garantias de tempo.','\n',char(10)),replace('**Explicação para uma criança de 10 anos:**\n\nImagine que você tem duas caixas de tarefas: uma é a "caixa rápida" (síncrona) e a outra é a "caixa devagar" (batch).\n\n- Na **caixa rápida**, você coloca as tarefas que precisam ser feitas **agora mesmo**, como responder a mensagem do seu amigo no WhatsApp. Se demorar, ele vai ficar esperando.\n\n- Na **caixa devagar**, você coloca as tarefas que **não têm pressa**, como organizar suas fotos antigas. Pode demorar um pouco, mas tudo bem.\n\nA resposta certa (B) diz o seguinte: coloque na caixa devagar (batch) só as tarefas que podem esperar, como uma análise que roda à noite. Já as tarefas que **bloqueiam o merge** (coisas que precisam terminar para o jogo ou programa funcionar) devem ficar na caixa rápida (síncrona).\n\nAs outras opções estão erradas porque:\n\n- **A** quer colocar tarefas urgentes na caixa devagar — isso faria todo mundo esperar muito tempo.\n- **C** quer colocar tudo na caixa devagar, achando que ela sempre é rápida — mas não é garantido, às vezes demora.\n- **D** quer usar só a caixa rápida, perdendo a chance de economizar dinheiro e esforço com tarefas que podem esperar.\n','\n',char(10)));
INSERT INTO cards VALUES('admin','card_1783092986434_jx32x1d9g',225,'You are not allowed to filter findings before human review.',replace('You are not allowed to filter findings before human review.\n\nYou are not allowed to filter findings before human review. How do you reduce the investigation time per finding?\n[Resposta correta: Incluir raciocínio e confiança inline reduz o tempo de investigação sem violar a restrição. A e C filtram ou suprimem, o que a restrição proíbe. D não reduz o tempo de investigar cada item.]\n\n[ ] A - Filter out the low-confidence findings before showing them.\n[ ] B - Require Claude to include the reasoning and a confidence assessment inline in each finding.\n[ ] C - Suppress duplicate findings to shorten the list.\n[ ] D - Just rearrange the order of the review workflow.','\n',char(10)),'B - Require Claude to include the reasoning and a confidence assessment inline in each finding.','["Domain_4::Prompt_Engineering_Structured_Output", "Domain_1::Agentic_Architecture_Orchestration", "Scenario_5::Claude_Code_CI_CD"]','New',0,2.5,0,1783092986434,1783727103429,1783203558653,replace('**Tradução para português do Brasil:**\n\nVocê não tem permissão para filtrar descobertas antes da revisão humana.\n\nVocê não tem permissão para filtrar descobertas antes da revisão humana. Como você reduz o tempo de investigação por descoberta?\n[Resposta correta: Incluir raciocínio e confiança inline reduz o tempo de investigação sem violar a restrição. A e C filtram ou suprimem, o que a restrição proíbe. D não reduz o tempo de investigar cada item.]\n\n[ ] A - Filtrar as descobertas de baixa confiança antes de mostrá-las.\n[ ] B - Exigir que Claude inclua o raciocínio e uma avaliação de confiança inline em cada descoberta.\n[ ] C - Suprimir descobertas duplicadas para encurtar a lista.\n[ ] D - Apenas reorganizar a ordem do fluxo de revisão.','\n',char(10)),replace('**Explicação para um adulto tech lead:**\n\nA restrição central é: "You are not allowed to filter findings before human review" — ou seja, nenhum mecanismo de filtragem ou supressão pode ser aplicado antes que um humano revise cada descoberta individualmente. O objetivo é reduzir o tempo de investigação **por descoberta** (per finding), sem descartar nenhuma delas previamente.\n\n- **Alternativa A (Filtrar por baixa confiança):** Viola a restrição porque descarta descobertas antes da revisão humana. Mesmo que sejam de baixa confiança, a regra exige que todas sejam apresentadas ao revisor.\n\n- **Alternativa B (Raciocínio e confiança inline):** Correta. Ao fazer com que o modelo inclua, já no texto de cada descoberta, o raciocínio usado para chegar à conclusão e uma autoavaliação de confiança, o revisor humano consegue avaliar mais rapidamente a validade daquela descoberta. Não há filtragem — todas as descobertas continuam sendo apresentadas —, mas o tempo gasto por cada uma é reduzido porque o contexto necessário já está ali, inline.\n\n- **Alternativa C (Suprimir duplicatas):** Viola a restrição da mesma forma que A. Suprimir significa remover da lista antes da revisão, o que é uma forma de filtragem.\n\n- **Alternativa D (Reordenar o fluxo):** Não viola a restrição, mas também não reduz o tempo de investigação *por descoberta*. Reordenar pode mudar a prioridade de revisão, mas o revisor ainda precisará gastar o mesmo tempo analisando cada item individualmente.','\n',char(10)),replace('**Explicação para uma criança de 10 anos:**\n\nImagina que você tem uma lista grande de lições de casa para revisar, e sua professora disse: "Você não pode esconder nenhuma lição antes de eu ver todas." Como você pode fazer para que a professora demore menos tempo em cada lição?\n\n- A opção A (esconder as lições fáceis) não pode, porque a regra proíbe esconder qualquer coisa.\n- A opção B (pedir para o aluno explicar o raciocínio e dizer se está confiante em cada resposta) é a certa! Assim, ao olhar cada lição, a professora já vê a explicação e sabe se o aluno está seguro ou em dúvida. Ela não precisa ficar pensando "como ele chegou a isso?" — a resposta já está ali. Isso acelera a correção, sem esconder nenhuma lição.\n- A opção C (tirar lições repetidas da lista) também é proibida, porque é como esconder algo antes da professora ver.\n- A opção D (só mudar a ordem das lições) não ajuda: a professora ainda vai demorar o mesmo tempo em cada uma.\n\nEntão a resposta certa é a B, porque dá mais informações sem esconder nada!','\n',char(10)));
INSERT INTO cards VALUES('admin','card_1783092986448_5dt4pamgg',226,'An engineer runs /init on a brand-new repository.',replace('An engineer runs /init on a brand-new repository.\n\nAn engineer runs /init on a brand-new repository. What is the artifact produced and how will it be used afterward?\n[Resposta correta: O /init escaneia o codebase e grava um resumo no CLAUDE.md, que passa a ser incluído em toda conversa. A alternativa A troca o artefato por AGENTS.md; a C descreve indexação prévia que o Claude Code justamente evita; a D confunde o CLAUDE.md com o arquivo de settings.]\n\n[ ] A - An AGENTS.md file that is only read when referenced with @\n[ ] B - A CLAUDE.md file with a summary of the codebase, included as context in future conversations\n[ ] C - A vector index of the codebase sent to external servers for search\n[ ] D - A settings.json file with the detected dependencies','\n',char(10)),'B - A CLAUDE.md file with a summary of the codebase, included as context in future conversations','["Domain_3::Claude_Code_Configuration_Workflows", "Scenario_2::Code_Generation_Claude_Code"]','New',0,2.5,0,1783092986448,1783727106780,1783203558653,replace('**Tradução para português do Brasil:**\n\nUm engenheiro executa /init em um repositório novo. Qual é o artefato produzido e como ele será usado posteriormente?\n\n[ ] A - Um arquivo AGENTS.md que é lido apenas quando referenciado com @\n[ ] B - Um arquivo CLAUDE.md com um resumo do código-fonte, incluído como contexto em conversas futuras\n[ ] C - Um índice vetorial do código-fonte enviado para servidores externos para busca\n[ ] D - Um arquivo settings.json com as dependências detectadas','\n',char(10)),replace('**Explicação didática para um adulto tech lead:**\n\nO comando `/init` no Claude Code é uma funcionalidade projetada para criar um resumo contextual do repositório recém-clonado. Ele escaneia a estrutura do projeto, identifica padrões relevantes (linguagens, frameworks, dependências, convenções) e grava esse resumo em um arquivo chamado `CLAUDE.md`. Esse arquivo é automaticamente incluído como contexto em todas as conversas futuras do Claude Code no repositório, eliminando a necessidade de reexplicar o propósito, arquitetura ou configuração do projeto a cada nova sessão.\n\n- **Alternativa A (incorreta):** O arquivo `AGENTS.md` não é gerado pelo `/init`. Ele é um artefato opcional que o usuário pode criar manualmente e, quando referenciado com `@`, é lido como contexto adicional, mas não faz parte do fluxo automático do `/init`.\n- **Alternativa B (correta):** Descreve exatamente o comportamento documentado: o `/init` produz um `CLAUDE.md` com um resumo do codebase, e esse arquivo é automaticamente incluído como contexto em conversas futuras.\n- **Alternativa C (incorreta):** O Claude Code não envia índices vetoriais do código para servidores externos. Ele opera localmente e utiliza o contexto inline (como o `CLAUDE.md`) para manter a consciência do projeto. A indexação vetorial externa seria desnecessária e contrária ao princípio de simplicidade do Claude Code.\n- **Alternativa D (incorreta):** O `/init` não gera um arquivo `settings.json`. Embora o Claude Code tenha um arquivo de configuração (`claude.json` ou similar), ele não é o artefato principal produzido pelo `/init`. O propósito do `/init` é gerar o resumo contextual (`CLAUDE.md`), não detectar dependências para configuração.','\n',char(10)),replace('Imagine que você acabou de ganhar um novo brinquedo que vem desmontado na caixa. Você precisa de um manual para saber como montar e brincar com ele, certo? O `/init` é como o engenheiro que escreve esse manual para o computador.\n\nQuando o engenheiro usa o `/init` em um repositório novo (que é como uma caixa de ferramentas de programação vazia), o computador cria um arquivo chamado `CLAUDE.md`. Esse arquivo é um resumo que explica: "O que tem aqui dentro?", "Como as peças se encaixam?" e "Quais regras usar?". Aí, nas próximas vezes que o engenheiro for conversar com o computador sobre esse repositório, o computador já vai ler esse resumo automaticamente — tipo ter um lembrete sempre na mesa, sem precisar perguntar toda hora.\n\nAs outras opções estão erradas:\n- **A:** O arquivo `AGENTS.md` existe, mas o `/init` não cria ele. É como um bilhete que você escreve por conta própria e só mostra quando alguém pergunta.\n- **C:** O `/init` não manda informações para outros computadores (servidores externos). Isso seria como enviar seu resumo para um amigo na escola — desnecessário e pode vazar segredos.\n- **D:** O `/init` não cria um arquivo de configuração (`settings.json`). Isso seria como escrever a lista de peças do brinquedo, mas o `/init` na verdade escreve o manual completo de como usar o brinquedo.','\n',char(10)));
INSERT INTO cards VALUES('admin','card_1783092986463_zxlqcofb8',227,'You want to record a personal note that should NOT be versioned in git nor affect your other projects.',replace('You want to record a personal note that should NOT be versioned in git nor affect your other projects.\n\nYou want to record a personal note that should NOT be versioned in git nor affect your other projects. Which CLAUDE.md scope should you use?\n[Resposta correta: O escopo Local guarda notas pessoais e fica fora do git. Project seria compartilhado com o time; User valeria para todos os seus projetos (não é o pedido); Enterprise nem é escopo de CLAUDE.md nesse contexto.]\n\n[ ] A - Project, since it is the only one that accepts notes\n[ ] B - User, since it applies to all your projects\n[ ] C - Local, since it stores personal notes and is not versioned\n[ ] D - Enterprise, since it forces the note across the whole organization','\n',char(10)),'C - Local, since it stores personal notes and is not versioned','["Domain_3::Claude_Code_Configuration_Workflows", "Domain_5::Context_Management_Reliability", "Scenario_2::Code_Generation_Claude_Code"]','New',0,2.5,0,1783092986463,1783727110276,1783203558653,replace('**Tradução para português do Brasil:**\n\nVocê quer gravar uma nota pessoal que NÃO deve ter versão no git nem afetar seus outros projetos.\n\nQual escopo do CLAUDE.md você deve usar?\n\n[ ] A - Project, já que é o único que aceita notas\n[ ] B - User, já que se aplica a todos os seus projetos\n[ ] C - Local, já que armazena notas pessoais e não tem versão\n[ ] D - Enterprise, já que força a nota em toda a organização','\n',char(10)),replace('**Explicação didática para um adulto tech lead:**\n\nA pergunta descreve um requisito claro: uma nota pessoal que não seja versionada no git e que não impacte outros projetos. Vamos analisar cada alternativa:\n\n**Alternativa C (correta): Local** — O escopo Local do CLAUDE.md é projetado exatamente para este cenário. Ele armazena configurações e notas pessoais em um arquivo que fica fora do controle de versão do git (geralmente ignorado via .gitignore). Isso significa que a nota não será commitada, não aparecerá para outras pessoas no repositório e não afetará outros projetos que você possa ter, pois o escopo Local é específico do diretório/projeto atual e não se propaga.\n\n**Alternativa A: Project** — O escopo Project é versionado no git e compartilhado com todo o time que tem acesso ao repositório. Não é adequado para notas pessoais, pois qualquer membro da equipe veria o conteúdo, e ele estaria sujeito a commits e pushes, contrariando o requisito de não ser versionado.\n\n**Alternativa B: User** — O escopo User se aplica globalmente a todos os projetos que você usa com o Claude em sua máquina. Embora não seja versionado em um repositório específico, ele afetaria todos os seus projetos, o que viola o requisito de "não afetar seus outros projetos".\n\n**Alternativa D: Enterprise** — Não é um escopo do CLAUDE.md neste contexto. Escopos Enterprise geralmente se referem a políticas organizacionais amplas, e não há suporte para CLAUDE.md com esse escopo. Mesmo que existisse, forçar uma nota pessoal em toda a organização seria o oposto do desejado.\n\nPortanto, a resposta correta é a C.','\n',char(10)),replace('Imagine que você tem um caderno de anotações. Às vezes você quer escrever um segredo só seu, que ninguém mais veja, e que não se misture com a lição de casa dos outros projetos.\n\nO CLAUDE.md é como se fosse esse caderno, mas com regras diferentes:\n\n- **Project** (A): É como escrever num quadro branco do seu time — todo mundo lê e fica gravado pra sempre.\n- **User** (B): É como escrever num bilhete que você cola na testa — vale pra TUDO que você faz, inclusive outros projetos.\n- **Local** (C): É como escrever num papelzinho escondido na sua mochila — só você vê, não vai parar no mural do time (git) e não atrapalha outros trabalhos.\n- **Enterprise** (D): É como um aviso no microfone da escola inteira — todo mundo ouve, o que não é nada pessoal.\n\nComo você quer uma nota **pessoal**, que **não vá para o git** e **não atrapalhe outros projetos**, a escolha certa é o **Local** (alternativa C).','\n',char(10)));
INSERT INTO cards VALUES('admin','card_1783092986478_8m0nvmcmg',228,'When you type a line starting with # in Claude Code, what happens?',replace('When you type a line starting with # in Claude Code, what happens?\n\nWhen you type a line starting with # in Claude Code, what happens?\n[Resposta correta: O # adiciona rapidamente uma diretriz ao CLAUDE.md e pergunta em qual memória gravar. A alternativa A confunde com o prefixo de bash; a C descreve /clear; a D inventa criação de skill.]\n\n[ ] A - The text is executed as a terminal command\n[ ] B - A note is added to the CLAUDE.md, with a choice of memory project, local or user\n[ ] C - The conversation history is cleared\n[ ] D - A new skill is created automatically','\n',char(10)),'[ ] B - A note is added to the CLAUDE.md, with a choice of memory project, local or user','["Domain_3::Claude_Code_Configuration_Workflows", "Domain_4::Prompt_Engineering_Structured_Output", "Scenario_2::Code_Generation_Claude_Code"]','New',0,2.5,0,1783092986478,1783727113604,1783203558653,replace('**Tradução:**\n\nQuando você digita uma linha começando com # no Claude Code, o que acontece?\n\n[ ] A - O texto é executado como um comando de terminal\n[ ] B - Uma nota é adicionada ao CLAUDE.md, com uma escolha de memória: projeto, local ou usuário\n[ ] C - O histórico da conversa é limpo\n[ ] D - Uma nova skill é criada automaticamente','\n',char(10)),replace('**Explicação para um adulto (tech lead):**\n\nNo Claude Code, um atalho de teclado — mais precisamente, a linha iniciada com `#` — aciona um mecanismo de "quick add" ao arquivo CLAUDE.md, que é um arquivo de instruções e diretrizes usado pelo Claude para guiar seu comportamento em diferentes escopos.\n\n**Alternativa B (correta):**  \nAo digitar `#`, o Claude Code interpreta que você deseja adicionar uma diretriz rapidamente. Ele mostra uma opção de onde salvá-la:  \n- **Projeto** (`project`): adiciona ao CLAUDE.md do projeto atual.  \n- **Local** (`local`): adiciona a um escopo local (como um repositório específico).  \n- **Usuário** (`user`): adiciona ao CLAUDE.md global do usuário.  \n\nEsse fluxo é útil para persistir instruções sem precisar editar o arquivo manualmente.\n\n**Alternativa A (incorreta):**  \nLinhas começando com `#` não são executadas como comandos de terminal. Para executar comandos no terminal, usa-se o prefixo `>` no Claude Code ou comandos nativos do shell. O `#` tem função de comentário/diretriz, não de execução.\n\n**Alternativa C (incorreta):**  \nO comando `/clear` (ou similar) é que limpa o histórico da conversa, não uma linha iniciada com `#`.\n\n**Alternativa D (incorreta):**  \nA criação automática de skills não existe no contexto do `#`. Skills são mecanismos de personalização mais complexos que não são acionados por esse atalho.','\n',char(10)),replace('Imagine que você está conversando com um robô chamado Claude, e ele tem um "caderninho de regras" chamado CLAUDE.md.  \nQuando você começa uma frase com `#`, é como se você estivesse dizendo: "Ei, robô, quero escrever uma regrinha nova no seu caderninho!"  \n\nO robô pergunta: "Onde você quer guardar essa regra? Nas regras do projeto (o trabalho atual), nas suas regras pessoais, ou em um lugar só para você?"  \nVocê escolhe e pronto — a regra fica salva!\n\nAs outras opções estão erradas:  \n- A: `#` não manda o robô fazer algo no computador (isso seria com `>`).  \n- C: `#` não apaga o que a gente conversou (isso se faz com `/clear`).  \n- D: `#` não cria uma skill nova; skill é algo mais complicado.','\n',char(10)));
INSERT INTO cards VALUES('admin','card_1783092986492_s6gbcj7gz',229,'You are about to start a completely different task and want to wipe the current context.',replace('You are about to start a completely different task and want to wipe the current context.\n\nYou are about to start a completely different task and want to wipe the current context. Which command should you use?\n[Resposta correta: /clear limpa o histórico e reseta o contexto. /compact resumiria preservando o aprendizado; /rewind volta a um ponto anterior mantendo contexto; /resume retoma uma conversa.]\n\n[ ] A - /compact\n[ ] B - /rewind\n[ ] C - /clear\n[ ] D - /resume','\n',char(10)),'C - /clear','["Domain_3::Claude_Code_Configuration_Workflows", "Scenario_2::Code_Generation_Claude_Code"]','New',0,2.5,0,1783092986492,1783727116583,1783203558653,replace('**Tradução para português do Brasil:**\n\nVocê está prestes a iniciar uma tarefa completamente diferente e deseja limpar o contexto atual. Qual comando você deve usar?\n[Resposta correta: /clear limpa o histórico e reseta o contexto. /compact resumiria preservando o aprendizado; /rewind volta a um ponto anterior mantendo contexto; /resume retoma uma conversa.]\n\n[ ] A - /compact\n[ ] B - /rewind\n[ ] C - /clear\n[ ] D - /resume','\n',char(10)),replace('**Explicação para adulto tech lead:**\n\nA pergunta descreve um cenário onde o objetivo é "iniciar uma tarefa completamente diferente" e "limpar o contexto atual". Isso significa que queremos descartar todo o histórico da conversa anterior e resetar o estado da IA para um estado "limpo", sem qualquer informação ou aprendido do que foi discutido antes.\n\n- **Alternativa C - /clear** é a resposta correta. O comando `/clear` é projetado exatamente para isso: apagar todo o histórico de conversa e reiniciar o contexto do zero. É como fechar um terminal e abrir um novo — nenhum dado anterior persiste.\n\n- **Alternativa A - /compact** está incorreta. O enunciado informa que `/compact` "resumiria preservando o aprendizado". Ou seja, ele comprime o histórico, mas mantém o contexto e o que foi aprendido. Para uma tarefa completamente diferente, queremos eliminar esse aprendizado, não preservá-lo.\n\n- **Alternativa B - /rewind** está incorreta. O comando `/rewind` "volta a um ponto anterior mantendo contexto". Ele permite retornar a um estado anterior da conversa, mas ainda retém informações contextuais. Além disso, não é o comando adequado para zerar o ambiente para uma nova tarefa.\n\n- **Alternativa D - /resume** está incorreta. O comando `/resume` "retoma uma conversa". Ele pressupõe que existe uma conversa anterior a ser continuada, o oposto do que se deseja ao iniciar algo completamente novo e sem vínculo com o passado.\n\nPortanto, a única alternativa que atende ao requisito de limpar completamente o contexto e o histórico é `/clear`.','\n',char(10)),replace('Imagine que você está brincando com um caderno de desenhos. Você desenhou várias coisas, mas agora quer começar um desenho totalmente novo, sem nenhum risco do desenho antigo atrapalhando.\n\n- **/clear** (alternativa C) é como pegar uma borracha mágica e apagar tudinho, deixando a página em branco de novo. É o melhor comando para começar do zero!\n\n- **/compact** (alternativa A) é como tentar dobrar o papel para esconder os desenhos velhos, mas eles ainda estão lá. Não resolve.\n\n- **/rewind** (alternativa B) é como virar algumas páginas para trás no caderno. Você volta para um desenho antigo, mas não começa do zero.\n\n- **/resume** (alternativa D) é como continuar desenhando a partir de onde você parou. Se você quer algo completamente novo, isso não ajuda.\n\nEntão, se você quer um caderno limpinho para uma nova ideia, o comando certo é o **/clear**!','\n',char(10)));
INSERT INTO cards VALUES('admin','card_1783092986507_gqpli7qee',230,'What is the recommended order of the three steps for using Claude Code effectively?',replace('What is the recommended order of the three steps for using Claude Code effectively?\n\nWhat is the recommended order of the three steps for using Claude Code effectively?\n[Resposta correta: A sequência é alimentar contexto, pedir plano sem código ainda e então implementar. As demais invertem a ordem ou pulam o passo de planejamento antes da implementação.]\n\n[ ] A - Implement, then plan, then read the files\n[ ] B - Read/analyze relevant files, ask for a plan without code, implement the plan\n[ ] C - Ask for the plan, implement it directly, then feed context\n[ ] D - Run the tests, read the files, commit','\n',char(10)),'B - Read/analyze relevant files, ask for a plan without code, implement the plan','["Domain_3::Claude_Code_Configuration_Workflows", "Domain_4::Prompt_Engineering_Structured_Output", "Scenario_2::Code_Generation_Claude_Code"]','New',0,2.5,0,1783092986507,1783727119964,1783203558653,replace('**Tradução**\n\nQual é a ordem recomendada das três etapas para usar o Claude Code de forma eficaz?\n\n[ ] A - Implementar, depois planejar, depois ler os arquivos\n[ ] B - Ler/analisar arquivos relevantes, pedir um plano sem código, implementar o plano\n[ ] C - Pedir o plano, implementar diretamente, depois fornecer contexto\n[ ] D - Executar os testes, ler os arquivos, fazer commit','\n',char(10)),replace('**Explicação para Adulto Tech Lead**\n\nA alternativa correta é a **B**. Ela descreve a sequência ideal para trabalhar com Claude Code de forma eficiente: primeiro, você **alimenta o contexto** lendo e analisando os arquivos relevantes do projeto; depois, **solicita um plano sem código**, garantindo que o raciocínio esteja alinhado antes de qualquer implementação; por fim, **implementa o plano** propriamente dito.\n\nAnálise das alternativas incorretas:\n\n- **A (Implementar, depois planejar, depois ler)**: Inverte completamente a ordem lógica. Implementar sem planejamento e sem contexto leva a retrabalho e soluções inconsistentes com a base de código existente.\n\n- **C (Pedir o plano, implementar diretamente, depois fornecer contexto)**: Embora peça um plano, pula a etapa de alimentar contexto, o que resulta em um plano genérico e possivelmente inadequado. Implementar diretamente após o plano, sem iterar ou validar o plano com o contexto, também é arriscado.\n\n- **D (Executar os testes, ler os arquivos, fazer commit)**: Não segue a estrutura de três etapas proposta na pergunta e não menciona planejamento ou implementação. Testes e commit são atividades periféricas, não o fluxo principal de uso do Claude Code.','\n',char(10)),replace('Imagine que você vai construir um castelo de lego. A melhor maneira de fazer isso é:\n\n1. **Ler as instruções (ver os arquivos)** — você olha as peças que tem e entende o que já foi construído.\n2. **Fazer um desenho do castelo (pedir um plano)** — você planeja onde cada peça vai ficar, sem montar nada ainda.\n3. **Montar o castelo (implementar)** — aí sim você começa a encaixar as peças.\n\nFazer de cabeça, sem olhar as instruções ou sem planejar, vai dar errado — por isso as outras opções não são boas. A opção certa é a **B**, que segue essa ordem: primeiro entender, depois planejar, depois fazer.','\n',char(10)));
INSERT INTO cards VALUES('admin','card_1783092986536_4ho6735on',231,'In the recommended TDD workflow, what is the correct order of the steps?',replace('In the recommended TDD workflow, what is the correct order of the steps?\n\nIn the recommended TDD workflow, what is the correct order of the steps?\n[Resposta correta: No TDD recomendado os testes vêm antes do código, definindo critérios de sucesso claros. A alternativa A inverte tudo; a C descreve o workflow geral, não TDD; a D não gera testes.]\n\n[ ] A - Write the code, then think about the tests, then feed context\n[ ] B - Feed context, think about test cases, implement the tests, write code that passes, iterating\n[ ] C - Ask for a plan, implement the plan, and only then write tests\n[ ] D - Run the existing tests and commit without writing new ones','\n',char(10)),'B - Feed context, think about test cases, implement the tests, write code that passes, iterating','["Domain_3::Claude_Code_Configuration_Workflows", "Domain_4::Prompt_Engineering_Structured_Output", "Scenario_2::Code_Generation_Claude_Code"]','New',0,2.5,0,1783092986536,1783727124016,1783203558653,replace('**Tradução**\n\nPergunta: "No fluxo de trabalho recomendado do TDD, qual é a ordem correta das etapas?"\n\nAlternativas:\n[ ] A - Escrever o código, depois pensar nos testes, depois fornecer contexto\n[ ] B - Fornecer contexto, pensar nos casos de teste, implementar os testes, escrever código que passe, iterando\n[ ] C - Pedir um plano, implementar o plano, e só então escrever testes\n[ ] D - Executar os testes existentes e fazer commit sem escrever novos testes','\n',char(10)),replace('**Explicação para um adulto tech lead**\n\nA pergunta trata do fluxo de trabalho do TDD (Test-Driven Development). O TDD possui um ciclo bem definido, frequentemente resumido como "Red-Green-Refactor":\n\n1. **Red**: Escreva um teste que falhe (antes de qualquer código de produção).\n2. **Green**: Escreva o código mínimo necessário para fazer o teste passar.\n3. **Refactor**: Refatore o código, mantendo todos os testes verdes.\n\nA alternativa **B** é a correta porque descreve esse ciclo de forma completa e na ordem certa: primeiro se fornece contexto (entendimento do problema/requisito), depois se pensa nos casos de teste (planejamento), implementa-se os testes (Red), escreve-se o código que passa (Green), e itera-se (Refactor e repetição do ciclo).\n\n**Por que as demais estão erradas:**\n\n- **A**: Está errada porque inverte a ordem fundamental do TDD. No TDD, os testes vêm antes do código, não depois. "Escrever o código, depois pensar nos testes" é o oposto do que o TDD prega. O "feed context" no final também não faz sentido no ciclo.\n\n- **C**: Esta descreve um workflow tradicional ou "big design up front", não TDD. Em TDD, os testes são escritos antes da implementação, não depois. "Pedir um plano, implementar o plano, e só então escrever testes" é o contrário do ciclo Red-Green-Refactor.\n\n- **D**: Esta alternativa descreve a ausência de TDD. Apenas executar testes existentes e fazer commit sem escrever novos testes significa que não há desenvolvimento orientado a testes. Não há criação de novos testes para novas funcionalidades, o que viola o princípio central do TDD.','\n',char(10)),replace('Imagine que você está montando um quebra-cabeça. O TDD é como olhar a figura na caixa antes de começar a montar. Você primeiro decide como vai ser o resultado final (o teste), e só depois começa a juntar as peças (escrever o código).\n\nA alternativa **B** é a certa porque mostra a ordem correta: primeiro você entende o que precisa fazer (contexto), depois pensa em como saber se acertou (casos de teste), cria uma "prova" (implementa os testes), e só então faz o código passar nessa prova. E vai repetindo esse ciclo.\n\nAs outras opções estão erradas porque:\n- **A** faz o contrário: primeiro faz o código e depois pensa no teste. É como montar o quebra-cabeça sem olhar a figura e depois tentar adivinhar se está certo.\n- **C** também deixa os testes por último, como se fosse um "extra". No TDD, o teste é o guia, não uma tarefa final.\n- **D** nem escreve testes novos! É só rodar os que já existem e sair. Isso não é TDD, é só manter o que já está pronto.','\n',char(10)));
INSERT INTO cards VALUES('admin','card_1783092986551_il6zt4ay5',232,'You need the dev flow to look up production errors, ticket requirements and notify the team on completion.',replace('You need the dev flow to look up production errors, ticket requirements and notify the team on completion.\n\nYou need the dev flow to look up production errors, ticket requirements and notify the team on completion. Which approach?\n[Resposta correta: A extensão a serviços externos se dá conectando MCP servers ao client do Claude Code. Hook não é o mecanismo de integração externa; CLAUDE.md é contexto, não integração; skills não substituem os conectores MCP para essas ferramentas.]\n\n[ ] A - Write a single PostToolUse hook that does the three integrations\n[ ] B - Connect multiple MCP servers (e.g. Sentry, Jira and Slack) to the Claude Code built-in client\n[ ] C - Put the credentials of those tools in the CLAUDE.md\n[ ] D - Create three separate skills, one for each tool','\n',char(10)),'B - Connect multiple MCP servers (e.g. Sentry, Jira and Slack) to the Claude Code built-in client','["Domain_2::Tool_Design_MCP_Integration", "Domain_3::Claude_Code_Configuration_Workflows", "Scenario_2::Code_Generation_Claude_Code"]','New',0,2.5,0,1783092986551,1783727127799,1783203558653,replace('**Tradução para português do Brasil:**\n\nVocê precisa que o fluxo de desenvolvimento (dev flow) consulte erros de produção, requisitos de tickets e notifique o time sobre a conclusão. Qual abordagem?\n\n[ ] A - Escrever um único hook PostToolUse que faça as três integrações  \n[ ] B - Conectar múltiplos servidores MCP (ex.: Sentry, Jira e Slack) ao cliente integrado do Claude Code  \n[ ] C - Colocar as credenciais dessas ferramentas no CLAUDE.md  \n[ ] D - Criar três skills separadas, uma para cada ferramenta','\n',char(10)),replace('**Explicação didática para um adulto tech lead:**\n\nA pergunta descreve um cenário em que o desenvolvedor precisa integrar o Claude Code a três sistemas externos distintos: monitoramento de erros (Sentry), gerenciamento de tickets (Jira) e notificações (Slack). A abordagem correta é conectar múltiplos servidores MCP ao cliente Claude Code.\n\n**Por que B é a resposta correta:**\n\nO MCP (Model Context Protocol) é o mecanismo padrão e oficial do Claude Code para estender suas capacidades a serviços externos. Cada servidor MCP encapsula a lógica de autenticação, chamadas de API e tratamento de respostas de uma ferramenta externa. Conectar servidores MCP separados para Sentry, Jira e Slack é arquiteturalmente correto porque:\n\n- Respeita o princípio da responsabilidade única (cada servidor cuida de uma integração).\n- Permite manutenção e evolução independentes de cada integração.\n- Utiliza o mecanismo de extensibilidade nativo do Claude Code, que já gerencia ciclo de vida, autenticação e contexto entre o cliente e os servidores.\n\n**Por que as demais estão erradas:**\n\nA - Um único hook PostToolUse que fizesse as três integrações violaria o princípio da separação de responsabilidades. Hooks são mecanismos para interceptar eventos no ciclo de vida de execução de ferramentas, não são canais de integração externa. Além disso, concentrar toda a lógica em um único hook torna o código monolítico, difícil de testar, dar manutenção e evoluir. Não é a abordagem recomendada para integrações com serviços externos distintos.\n\nC - CLAUDE.md é um arquivo de contexto que fornece instruções e diretrizes para o modelo (como regras de estilo, preferências do projeto, etc.). Colocar credenciais nele seria uma violação grave de segurança (vazamento de secrets) e não é o propósito do arquivo. O CLAUDE.md não é um mecanismo de integração com serviços externos.\n\nD - Skills, no contexto do Claude Code, são pacotes de instruções e comportamentos reutilizáveis, mas não substituem conectores MCP para realizar chamadas autenticadas a APIs externas. Criar três skills não resolveria o problema de integração real com as ferramentas, pois skills não têm, por si só, a capacidade de se conectar e autenticar em serviços externos como Sentry, Jira e Slack. Essa função é dos servidores MCP.','\n',char(10)),replace('Imagine que você tem três brinquedos diferentes: um que mostra os erros do jogo (Sentry), um que organiza as tarefas (Jira) e um que manda recados (Slack). Você quer que seu amigo robô Claude Code consiga brincar com esses três brinquedos.\n\nA maneira certa é conectar cada brinquedo ao robô usando "cabos especiais" chamados servidores MCP. Um cabo para o Sentry, outro para o Jira e outro para o Slack. Assim, cada brinquedo funciona direitinho e o robô sabe como usar cada um.\n\nSe você tentasse fazer um único cabo mágico que tentasse ligar os três brinquedos ao mesmo tempo (alternativa A), seria confuso e bagunçado. Se você escrevesse as senhas dos brinquedos num papel (CLAUDE.md - alternativa C), qualquer um poderia ver e seria perigoso. E se você desse instruções escritas (skills - alternativa D) para o robô, ele ainda não conseguiria de fato conectar e usar os brinquedos — precisaria dos cabos MCP.\n\nEntão, a resposta certa é a B: conectar cabos separados (servidores MCP) para cada brinquedo.','\n',char(10)));
INSERT INTO cards VALUES('admin','card_1783092986567_559j21hix',233,'Which command registers an MCP server in Claude Code?',replace('Which command registers an MCP server in Claude Code?\n\nWhich command registers an MCP server in Claude Code?\n[Resposta correta: O registro é feito com claude mcp add seguido do nome e do comando de inicialização. A B inventa um subcomando; a C não é a forma descrita; a D inventa a flag --batch.]\n\n[ ] A - claude mcp add [nome-do-server] [comando-para-iniciar-o-server]\n[ ] B - claude install-mcp [url]\n[ ] C - /add-mcp inside the session only\n[ ] D - claude mcp --batch [nome-do-server]','\n',char(10)),'[ ] A - claude mcp add [nome-do-server] [comando-para-iniciar-o-server]','["Domain_3::Claude_Code_Configuration_Workflows", "Scenario_2::Code_Generation_Claude_Code"]','New',0,2.5,0,1783092986567,1783727130835,1783203558653,replace('**Tradução (pt-BR):**\n\nQual comando registra um servidor MCP no Claude Code?\n\n[ ] A - claude mcp add [nome-do-server] [comando-para-iniciar-o-server]\n[ ] B - claude install-mcp [url]\n[ ] C - /add-mcp apenas dentro da sessão\n[ ] D - claude mcp --batch [nome-do-server]','\n',char(10)),replace('**Explicação para Adulto (Tech Lead):**\n\nA alternativa **A** é a correta porque o Claude Code expõe o subcomando `claude mcp add` como a interface oficial para registrar um servidor MCP. A sintaxe segue o padrão: primeiro o nome que identificará o servidor, depois o comando de inicialização (ex.: `npx @modelcontextprotocol/server-filesystem`). Esse registro persiste na configuração do Claude Code para aquela sessão/projeto.\n\n**Análise das incorretas:**\n\n- **B - `claude install-mcp [url]`**: Este comando não existe na CLI do Claude Code. O nome "install-mcp" remete a uma ação imaginária que não faz parte da interface documentada. Não há subcomando `install-mcp`.\n\n- **C - `/add-mcp` apenas dentro da sessão**: Embora existam comandos iniciados com `/` no modo interativo (slash commands), `/add-mcp` não é um deles. O registro de servidores MCP é feito via CLI, não via comando de chat/sessão.\n\n- **D - `claude mcp --batch [nome-do-server]`**: A flag `--batch` não é utilizada para registrar servidores MCP. O subcomando correto é `add`, não uma flag. Além disso, falta o parâmetro obrigatório do comando de inicialização.','\n',char(10)),replace('Imagine que o Claude Code é como um assistente que pode usar ferramentas especiais (os servidores MCP). Para ensinar o assistente a usar uma nova ferramenta, você precisa "registrar" ela. O jeito certo de fazer isso é digitar no terminal:\n\n`claude mcp add [nome-da-ferramenta] [como-ligar-a-ferramenta]`\n\nÉ como escrever na lista de amigos: "Ferramenta: Calculadora, Como usar: abrir app calculadora".\n\nAs outras opções estão erradas porque:\n\n- A opção B seria como tentar usar um comando mágico que não existe, tipo "abra-sésamo-mcp".\n- A opção C seria como tentar adicionar a ferramenta só conversando, mas não funciona assim.\n- A opção D seria como tentar colocar a ferramenta na lista usando uma senha errada (--batch não é o jeito certo).\n\nEntão, a resposta certa é a A, que é o comando correto para adicionar um servidor MCP!','\n',char(10)));
INSERT INTO cards VALUES('admin','card_1783092986581_b6moaptp3',234,'Which MCP integration is used for browser automation in tests?',replace('Which MCP integration is used for browser automation in tests?\n\nWhich MCP integration is used for browser automation in tests?\n[Resposta correta: playwright-mcp faz automação de browser para testes. sentry-mcp lida com bugs do Sentry; firecrawl-mcp-server faz web scraping; mcp-atlassian cobre Confluence e Jira.]\n\n[ ] A - sentry-mcp\n[ ] B - playwright-mcp\n[ ] C - firecrawl-mcp-server\n[ ] D - mcp-atlassian','\n',char(10)),'B - playwright-mcp','["Domain_2::Tool_Design_MCP_Integration", "Domain_4::Prompt_Engineering_Structured_Output", "Scenario_4::Developer_Productivity"]','New',0,2.5,0,1783092986581,1783727134294,1783203558653,replace('**Tradução fiel para português do Brasil:**\n\nQual integração MCP é usada para automação de navegador em testes?\n\n[ ] A - sentry-mcp\n[ ] B - playwright-mcp\n[ ] C - firecrawl-mcp-server\n[ ] D - mcp-atlassian','\n',char(10)),replace('**Explicação didática para adulto (tech lead):**\n\nA pergunta trata de identificar, dentre as opções fornecidas, qual integração MCP (Model Context Protocol) é especificamente voltada para automação de navegador (browser automation) em cenários de testes.\n\n**Alternativa correta: B - playwright-mcp**\n\nO Playwright é uma biblioteca de código aberto mantida pela Microsoft que permite automação de navegadores Chromium, Firefox e WebKit. Sua integração MCP (playwright-mcp) expõe capacidades de automação de navegador através do protocolo MCP, permitindo que agentes de IA ou ferramentas compatíveis executem ações como navegar, clicar, preencher formulários, extrair dados e fazer asserções diretamente em navegadores headless ou headful. É a escolha natural para quem precisa integrar testes de interface com agentes via MCP.\n\n**Análise das alternativas incorretas:**\n\n- **A - sentry-mcp**: Integração voltada para o Sentry, uma plataforma de monitoramento de erros e performance. Não tem qualquer relação com automação de navegador; seu propósito é consultar e gerenciar issues/Sentry events.\n\n- **C - firecrawl-mcp-server**: Firecrawl é uma ferramenta de web scraping e crawling. Embora envolva navegação web, seu foco é extração de dados estruturados de sites, não automação de testes de interface. Não foi projetado para cenários de testes como o Playwright.\n\n- **D - mcp-atlassian**: Integração com produtos Atlassian (Confluence e Jira). Totalmente voltada para gerenciamento de documentação e projetos, sem qualquer capacidade de automação de navegador.\n\nPortanto, considerando o propósito explícito de "browser automation in tests", o playwright-mcp é a resposta inequívoca.','\n',char(10)),replace('Imagine que você quer ensinar um robô a usar o computador como uma pessoa: abrir sites, clicar em botões, digitar textos e ver se tudo funciona direitinho. O Playwright é como uma "mão invisível" que faz isso acontecer. O "playwright-mcp" é a peça que conecta essa mão invisível a outros programas.\n\nAs outras opções são:\n\n- **sentry-mcp**: Serve para achar insetos (bugs) em programas, mas não mexe no navegador.\n- **firecrawl-mcp-server**: É um robô que lê sites inteiros para pegar informações, tipo um leitor muito rápido, mas não testa se os botões funcionam.\n- **mcp-atlassian**: Ajuda a organizar tarefas e documentos, como um caderno de anotações digital.\n\nEntão, se a pergunta é "qual ferramenta mexe no navegador para fazer testes?", a resposta é o **playwright-mcp** (alternativa B)!','\n',char(10)));
INSERT INTO cards VALUES('admin','card_1783092986596_gv76ix6wv',235,'Which of the options is NOT a default capability of Claude Code?',replace('Which of the options is NOT a default capability of Claude Code?\n\nWhich of the options is NOT a default capability of Claude Code?\n[Resposta correta: A indexação prévia obrigatória em servidor externo não é uma capacidade padrão (o Claude Code evita isso, lendo só o necessário). As demais (arquivos, terminal, web) são capacidades padrão.]\n\n[ ] A - File operations (search, read, edit)\n[ ] B - Terminal access to run commands\n[ ] C - Mandatory prior indexing of the codebase on an external server\n[ ] D - Web access to look up docs and examples','\n',char(10)),'C - Mandatory prior indexing of the codebase on an external server','["Domain_3::Claude_Code_Configuration_Workflows", "Scenario_2::Code_Generation_Claude_Code"]','New',0,2.5,0,1783092986596,1783727137386,1783203558653,replace('Tradução:\n\nQual das opções NÃO é uma capacidade padrão do Claude Code?\n\n[ ] A - Operações com arquivos (buscar, ler, editar)\n[ ] B - Acesso ao terminal para executar comandos\n[ ] C - Indexação prévia obrigatória do código em um servidor externo\n[ ] D - Acesso à web para consultar documentações e exemplos','\n',char(10)),replace('Explicação para adulto tech lead:\n\nO Claude Code é uma ferramenta de engenharia de software que opera no terminal do desenvolvedor e possui três capacidades padrão principais: manipulação de arquivos (search, read, edit), execução de comandos no terminal e acesso à web para consultar documentações e exemplos.\n\nA alternativa C está incorreta porque o Claude Code não exige indexação prévia obrigatória do código em um servidor externo. Pelo contrário, ele foi projetado para operar localmente, lendo apenas os arquivos necessários conforme a demanda, respeitando a privacidade e evitando o envio desnecessário de código para servidores externos. Isso é uma vantagem arquitetural importante, especialmente em ambientes corporativos com restrições de segurança e compliance.\n\nAnálise das alternativas incorretas (que SÃO capacidades padrão):\n\n- A (Operações com arquivos): É uma capacidade padrão fundamental. O Claude Code pode buscar, ler e editar arquivos no repositório local.\n\n- B (Acesso ao terminal): É outra capacidade padrão. Ele pode executar comandos no terminal para build, teste, deploy e outras operações de desenvolvimento.\n\n- D (Acesso à web): Também é padrão. O Claude Code pode acessar a internet para consultar documentações oficiais, exemplos de código e informações atualizadas de bibliotecas e frameworks.','\n',char(10)),replace('Imagine que o Claude Code é como um assistente超级esperto que mora no seu computador e te ajuda com tarefas de programação.\n\nPor padrão, ele consegue fazer três coisas:\n1. Mexer nos seus arquivos (procurar coisas, ler e escrever neles)\n2. Usar o terminal para rodar comandos (como dar instruções diretas para o computador)\n3. Acessar a internet para pesquisar documentações e exemplos\n\nAgora, a opção C fala sobre algo que ele NÃO faz por padrão: "Indexação prévia obrigatória do código em um servidor externo". Isso seria como se o Claude Code precisasse, antes de qualquer coisa, enviar TODO o seu código para um computador lá na nuvem para analisar. Isso não é algo que ele faça automaticamente! Ele prefere ler apenas o que precisa, na hora que precisa, sem ficar mandando seu código para fora. Isso é bom porque seu código fica mais seguro.\n\nEntão a resposta certa é a C, porque é a única que não é uma capacidade padrão do Claude Code.','\n',char(10)));
INSERT INTO cards VALUES('admin','card_1783092986612_fwjhudhj7',236,'Which routine tasks can Claude Code take on beyond generating code?',replace('Which routine tasks can Claude Code take on beyond generating code?\n\nWhich routine tasks can Claude Code take on beyond generating code?\n[Resposta correta: Ele pode fazer stage/commit, rodar testes e gerenciar dependências, evitando alternar entre editor e terminal. As demais restringem indevidamente o escopo ou descrevem outra função.]\n\n[ ] A - Only writing documentation\n[ ] B - Staging and committing in git, running tests and managing dependencies\n[ ] C - Only reviewing pull requests on GitHub\n[ ] D - Only indexing the codebase for external search','\n',char(10)),'[X] B - Staging and committing in git, running tests and managing dependencies','["Domain_3::Claude_Code_Configuration_Workflows", "Scenario_2::Code_Generation_Claude_Code"]','New',0,2.5,0,1783092986612,1783727140416,1783203558653,replace('**Tradução para português do Brasil:**\n\n**Pergunta:** Quais tarefas rotineiras o Claude Code pode realizar além de gerar código?\n\n**Alternativas:**\n[ ] A - Apenas escrever documentação\n[ ] B - Fazer stage/commit no git, executar testes e gerenciar dependências\n[ ] C - Apenas revisar pull requests no GitHub\n[ ] D - Apenas indexar a base de código para busca externa','\n',char(10)),replace('**Explicação técnica para um adulto tech lead:**\n\nO Claude Code é uma ferramenta de engenharia baseada em IA que opera diretamente no terminal do desenvolvedor, integrando-se ao fluxo de trabalho local. Sua proposta é reduzir o atrito entre pensar, escrever código e executar comandos operacionais.\n\nA alternativa **B** está correta porque descreve com precisão as capacidades reais do Claude Code: ele pode realizar operações no git (staging, commit), executar a suíte de testes e gerenciar dependências (instalar pacotes, atualizar versões, etc.). Essas ações são comuns no dia a dia de desenvolvimento e, normalmente, exigem que o dev saia do editor, vá ao terminal e execute comandos manualmente. O Claude Code elimina essa alternância, permitindo que o engenheiro fique focado no fluxo de pensamento.\n\n**Análise das alternativas incorretas:**\n\n- **A (Apenas escrever documentação):** Restringe indevidamente o escopo. Embora o Claude Code consiga gerar documentação, essa não é sua única tarefa além de gerar código. A alternativa é excludente ("only"), o que a torna falsa.\n\n- **C (Apenas revisar pull requests no GitHub):** Também é restritiva. O Claude Code pode interagir com PRs (especialmente via integração com GitHub), mas não se limita a isso. Além disso, a revisão de PRs é uma funcionalidade mais associada ao Claude como assistente geral, não especificamente ao Claude Code no terminal.\n\n- **D (Apenas indexar a base de código para busca externa):** Descreve uma funcionalidade que não é o foco principal do Claude Code. Indexar código é algo mais ligado a ferramentas de busca semântica ou IDEs. O Claude Code opera no contexto de tarefas ativas, e não como indexador externo.','\n',char(10)),replace('Imagine que você é um programador e tem que fazer várias tarefas no computador: escrever código, mas também salvar as mudanças no projeto (git), testar se tudo funciona e baixar novas peças de lego (dependências). Normalmente, você teria que ficar pulando de um programa para outro pra fazer tudo isso. O Claude Code é como um ajudante esperto que faz essas tarefas sem você precisar sair do lugar.\n\nA resposta certa é a **B**: ele consegue preparar e salvar suas mudanças (git), rodar os testes e gerenciar as dependências. As outras opções estão erradas porque dizem que ele só faz uma coisinha só, tipo só escrever texto de ajuda ou só revisar trabalhos dos outros — mas ele faz muito mais coisas legais!','\n',char(10)));
INSERT INTO cards VALUES('admin','card_1783092986627_5yyeyzoz4',237,'What are the three phases through which a coding assistant executes a task?',replace('What are the three phases through which a coding assistant executes a task?\n\nWhat are the three phases through which a coding assistant executes a task?\n[Resposta correta: As fases são reunir contexto, formular um plano e agir. As demais descrevem etapas de build/deploy, comandos de contexto ou o fluxo de PR, não as três fases do assistant.]\n\n[ ] A - Gather context, Formulate a plan, Take action\n[ ] B - Compile, Test, Deploy\n[ ] C - Read, Compact, Clear\n[ ] D - Plan, Approve, Merge','\n',char(10)),'A - Gather context, Formulate a plan, Take action','["Domain_3::Claude_Code_Configuration_Workflows", "Domain_4::Prompt_Engineering_Structured_Output", "Scenario_2::Code_Generation_Claude_Code"]','New',0,2.5,0,1783092986627,1783727143856,1783203558653,replace('**Tradução para português do Brasil:**\n\nQuais são as três fases pelas quais um assistente de codificação executa uma tarefa?\n\n[ ] A - Reunir contexto, Formular um plano, Agir\n[ ] B - Compilar, Testar, Implantar\n[ ] C - Ler, Compactar, Limpar\n[ ] D - Planejar, Aprovar, Mesclar','\n',char(10)),replace('**Explicação didática para um adulto tech lead:**\n\nA pergunta busca identificar o modelo de funcionamento típico de um assistente de codificação (como um copiloto ou agente de IA) ao executar uma tarefa. Esse modelo geralmente segue três fases sequenciais:\n\n- **Reunir contexto (Gather context):** O assistente primeiro precisa entender o ambiente — arquivos abertos, código-fonte, histórico do projeto, dependências, issue/task description. Sem contexto suficiente, o plano gerado será impreciso ou irrelevante.\n- **Formular um plano (Formulate a plan):** Com o contexto coletado, o assistente elabora uma estratégia de ação: quais arquivos modificar, quais algoritmos usar, quais passos seguir. Essa fase corresponde ao raciocínio deliberativo antes da execução.\n- **Agir (Take action):** Finalmente, o assistente executa o plano — escreve código, faz alterações em arquivos, executa comandos, etc.\n\n**Por que as outras alternativas estão erradas:**\n\n- **Alternativa B (Compile, Test, Deploy):** Descreve etapas de um pipeline de CI/CD (build/test/deploy) ou do ciclo de vida de entrega de software. Não são as fases cognitivas de um assistente de codificação, mas sim passos operacionais pós-desenvolvimento.\n- **Alternativa C (Read, Compact, Clear):** "Compact" e "Clear" não fazem sentido no contexto de execução de tarefas por um assistente. "Compact" poderia ser confundido com compressão de dados ou refatoração, e "Clear" é vago demais. Não corresponde a um modelo conhecido.\n- **Alternativa D (Plan, Approve, Merge):** Descreve parte de um fluxo de revisão de código e merge (PR workflow). Embora "Plan" coincida com uma das fases corretas, "Approve" e "Merge" são ações humanas ou de automação de repositório, não fases internas de execução do assistente.\n\nPortanto, a única alternativa que reflete fielmente as três fases do assistente de codificação é a **A**.','\n',char(10)),replace('Imagine que você é um robô que ajuda a programar. Quando alguém te pede para fazer alguma coisa, você precisa seguir três passos bem simples:\n\n1. **Reunir contexto** — Primeiro, você olha tudo ao redor: o que já está escrito, qual problema precisa resolver, que ferramentas têm disponíveis. É como quando você vai montar um quebra-cabeça e primeiro dá uma olhada em todas as peças.\n2. **Formular um plano** — Depois, você pensa: "Por onde começo? O que vou fazer primeiro, depois e por último?" É como desenhar um mapinha antes de sair para uma aventura.\n3. **Agir** — Aí sim, você coloca a mão na massa! Escreve o código, arruma os arquivos, faz as mudanças necessárias.\n\nAs outras opções não estão certas porque:\n- **B (Compilar, Testar, Implantar)** — isso é o que acontece *depois* que o programa já está pronto, tipo colocar um bolo no forno depois de já ter feito a massa.\n- **C (Ler, Compactar, Limpar)** — isso não existe! Parece mais instruções para arrumar o quarto do que para programar.\n- **D (Planejar, Aprovar, Mesclar)** — isso parece o passo a passo de quando você pede permissão para os adultos antes de juntar suas peças de lego com as do seu amigo. Não é o que o robô faz sozinho.\n\nEntão a resposta certa é a **A**.','\n',char(10)));
INSERT INTO cards VALUES('admin','card_1783092986643_xg8i4b5x7',238,'How does Claude Code navigate a large codebase without sending everything to external servers?',replace('How does Claude Code navigate a large codebase without sending everything to external servers?\n\nHow does Claude Code navigate a large codebase without sending everything to external servers?\n[Resposta correta: O tool use forte permite ler apenas o necessário, sem indexação prévia e sem enviar o codebase inteiro a terceiros. A A e a C contrariam justamente esse princípio; a D não é a característica descrita.]\n\n[ ] A - It indexes the whole codebase in advance and sends the index to the cloud\n[ ] B - It uses strong tool use to navigate without prior indexing, reading only what is needed\n[ ] C - It compresses the entire repository and sends it as a single attachment\n[ ] D - It requires the user to manually select each file before any response','\n',char(10)),'B - It uses strong tool use to navigate without prior indexing, reading only what is needed','["Domain_3::Claude_Code_Configuration_Workflows", "Domain_2::Tool_Design_MCP_Integration", "Scenario_2::Code_Generation_Claude_Code"]','New',0,2.5,0,1783092986643,1783727147009,1783203558653,replace('**Tradução para português do Brasil:**\n\n**Pergunta:** Como o Claude Code navega por uma base de código grande sem enviar tudo para servidores externos?\n\n[ ] A - Ele indexa toda a base de código previamente e envia o índice para a nuvem\n[ ] B - Ele usa tool use forte para navegar sem indexação prévia, lendo apenas o que é necessário\n[ ] C - Ele compacta o repositório inteiro e o envia como um único anexo\n[ ] D - Ele exige que o usuário selecione manualmente cada arquivo antes de qualquer resposta','\n',char(10)),replace('**Explicação para um adulto tech lead:**\n\nA pergunta aborda um desafio central de assistentes de IA aplicados a engenharia de software: como processar e interagir com uma base de código de grande porte sem violar premissas de privacidade, latência ou limites de contexto (context window).\n\n**Alternativa correta: B**\n\nO Claude Code utiliza tool use — mecanismo pelo qual o modelo pode invocar ferramentas (por exemplo, ler arquivo, listar diretório, buscar texto, executar comandos) de forma programática durante a interação. A expressão "strong tool use" significa que o modelo tem autonomia para decidir quais ferramentas chamar, em que ordem e com quais parâmetros, com base no contexto da conversa. Isso elimina a necessidade de indexação prévia ou de enviar o repositório completo para um servidor externo. O modelo lê apenas os arquivos necessários no momento, mantendo os dados localmente (quando a execução do Claude Code é local) ou enviando apenas fragmentos pontuais para a API. O resultado: escalabilidade, privacidade e eficiência de tokens.\n\n**Por que as demais alternativas estão incorretas:**\n\n- **A:** Descreve o oposto. Indexar previamente e enviar o índice para a nuvem contradiz diretamente a premissa de "não enviar tudo para servidores externos". Além disso, indexação prévia é custosa e inflexível.\n\n- **C:** Enviar o repositório inteiro comprimido violaria limites de contexto e de privacidade. Não é assim que o Claude Code opera.\n\n- **D:** Exigir que o usuário selecione arquivos manualmente antes de qualquer resposta não é verdadeiro — mas também não seria uma solução inteligente para o problema, pois transfere a responsabilidade para o usuário e quebra a fluidez da navegação.','\n',char(10)),replace('Imagine que você tem uma biblioteca gigante com milhares de livros e precisa encontrar uma informação. Você tem duas opções:\n\n1. Pegar todos os livros, empilhar e levar para alguém ler tudo — isso demora e é pesado.\n2. Ir até a biblioteca, olhar nas estantes, pegar só o livro que interessa e ler só a página necessária.\n\nO Claude Code faz a opção 2. Ele tem ferramentas especiais (como se fossem superpoderes) que permitem "andar" pela base de código, abrir pastas, ler arquivos e procurar palavras. Ele não precisa copiar o código inteiro para lugar nenhum. Ele vai lendo só o que precisa, quando precisa, exatamente como você faria com os livros.\n\nAs outras opções estão erradas porque:\n- A opção A diz que ele indexa tudo antes e manda para a nuvem — ou seja, empacota a biblioteca inteira e manda para fora.\n- A opção C diz que ele compacta tudo e envia de uma vez — mesma ideia, só que mais apertado.\n- A opção D diz que você precisa escolher cada arquivo manualmente antes de ele fazer qualquer coisa — isso seria chato e lento, e o Claude Code não funciona assim.','\n',char(10)));
INSERT INTO cards VALUES('admin','card_1783092986659_y1i73ez9b',239,'When you run /init on a new project, which artifact is generated?',replace('When you run /init on a new project, which artifact is generated?\n\nWhen you run /init on a new project, which artifact is generated?\n[Resposta correta: O /init analisa o codebase e escreve o resumo no CLAUDE.md. As demais são artefatos de outras features (hooks, skills e integração GitHub), não do /init.]\n\n[ ] A - A settings.local.json with pre-configured hooks\n[ ] B - A CLAUDE.md with a summary of purpose, architecture, commands and patterns\n[ ] C - A .claude/skills directory with default skills\n[ ] D - A workflow file in .github/workflows','\n',char(10)),'B - A CLAUDE.md with a summary of purpose, architecture, commands and patterns','["Domain_3::Claude_Code_Configuration_Workflows", "Scenario_2::Code_Generation_Claude_Code"]','New',0,2.5,0,1783092986659,1783727150210,1783203558653,replace('**Tradução para português do Brasil:**\n\n*Pergunta:* Quando você executa `/init` em um novo projeto, qual artefato é gerado?\n\n[ ] A - Um settings.local.json com hooks pré-configurados\n[ ] B - Um CLAUDE.md com um resumo do propósito, arquitetura, comandos e padrões\n[ ] C - Um diretório .claude/skills com skills padrão\n[ ] D - Um arquivo de workflow em .github/workflows','\n',char(10)),replace('**Explicação didática para um adulto tech lead:**\n\nO comando `/init` é uma funcionalidade do Claude (especificamente no contexto do Claude Code ou ferramentas similares da Anthropic) que analisa o codebase de um projeto e gera automaticamente um arquivo `CLAUDE.md`. Esse arquivo serve como um "memorando" de contexto para o assistente, contendo informações essenciais como o propósito do projeto, a arquitetura utilizada, comandos comuns (build, test, lint) e padrões de código adotados.\n\n**Por que a alternativa B está correta:**\nO `/init` escaneia o repositório, identifica estruturas de diretórios, arquivos de configuração (package.json, Makefile, Dockerfile, etc.) e documentação existente, e sintetiza essas informações em um único arquivo `CLAUDE.md` na raiz do projeto. Isso permite que futuras interações com o Claude já tenham contexto sobre o projeto sem necessidade de reexplicar tudo.\n\n**Por que as demais estão incorretas:**\n\n- **Alternativa A (settings.local.json com hooks):** Arquivos de configuração local e hooks são artefatos de features de personalização local ou de CI/CD, não do `/init`. O `/init` não gera hooks; hooks são configurados separadamente.\n\n- **Alternativa C (.claude/skills com skills padrão):** O diretório `.claude/skills` é utilizado para armazenar skills customizadas (extensões de funcionalidade), mas não é gerado pelo `/init`. Skills são criadas ou importadas pelo usuário, não como resultado da inicialização de um projeto.\n\n- **Alternativa D (workflow em .github/workflows):** Workflows do GitHub Actions são artefatos de integração contínua, configurados manualmente ou via templates, e não têm relação com o comando `/init`, que é focado em análise e contextualização do código local.','\n',char(10)),replace('Imagina que você acabou de ganhar um quebra-cabeça novo, mas as peças estão todas misturadas e você não tem a foto na caixa pra saber o que montar. O comando `/init` é como um amigo inteligente que olha rapidamente todas as peças, descobre do que se trata o quebra-cabeça (é um castelo? um foguete? um cachorro?) e escreve num bilhete: "Isso é um castelo, as torres ficam em cima, as portas na frente, e as cores são azul e cinza".\n\nEsse bilhete é o arquivo `CLAUDE.md`. Ele ajuda o computador a entender o projeto sem precisar perguntar tudo de novo toda vez.\n\nAs outras opções são como outras ferramentas:\n\n- **Opção A** seria como configurar regras especiais para o jogo (hooks) — não é o que o `/init` faz.\n- **Opção C** seria como ter uma caixa cheia de peças extras (skills) — também não é.\n- **Opção D** seria como programar um robô para arrumar o quarto automaticamente toda noite (workflow) — legal, mas não é isso que o `/init` faz.\n\nEntão a resposta certa é a **opção B**: o `/init` cria o arquivo `CLAUDE.md` que resume o projeto.','\n',char(10)));
INSERT INTO cards VALUES('admin','card_1783092986675_kntrc3g3a',240,'Which statement describes the role of the CLAUDE.',replace('Which statement describes the role of the CLAUDE.\n\nWhich statement describes the role of the CLAUDE.md in the request flow?\n[Resposta correta: O CLAUDE.md é incluído em toda requisição, como um system prompt persistente. A A descreve skills; a C e a D descrevem carregamento sob demanda, o oposto do comportamento always-on do CLAUDE.md.]\n\n[ ] A - It is loaded only when invoked with /skill-name\n[ ] B - It is included in every request, working as a persistent system prompt for the project\n[ ] C - It is read only on the first request of the session and then discarded\n[ ] D - It only enters the context when a specific tool is called','\n',char(10)),'[ ] B - It is included in every request, working as a persistent system prompt for the project','["Domain_3::Claude_Code_Configuration_Workflows", "Domain_4::Prompt_Engineering_Structured_Output", "Scenario_2::Code_Generation_Claude_Code"]','New',0,2.5,0,1783092986675,1783727153676,1783203558653,replace('**Tradução**\n\nQual afirmação descreve o papel do CLAUDE.md no fluxo de requisições?\n\n[ ] A - Ele é carregado apenas quando invocado com /skill-name\n[ ] B - Ele é incluído em toda requisição, funcionando como um system prompt persistente para o projeto\n[ ] C - Ele é lido apenas na primeira requisição da sessão e depois descartado\n[ ] D - Ele só entra no contexto quando uma ferramenta específica é chamada','\n',char(10)),replace('**Explicação para um adulto tech lead**\n\nA alternativa **B** está correta porque descreve com precisão o comportamento do arquivo CLAUDE.md. Ele é projetado para agir como um *system prompt* persistente, sendo injetado em todas as requisições feitas ao modelo, garantindo que instruções e contexto sobre o projeto estejam sempre disponíveis ao longo de toda a interação.\n\nVamos analisar por que as demais estão incorretas:\n\n- **Alternativa A** – Afirma que o CLAUDE.md é carregado apenas quando invocado via `/skill-name`. Isso é falso. O mecanismo de *skills* é uma funcionalidade separada (comandos iniciados por `/`) que permite executar tarefas específicas, mas não tem relação com o carregamento do CLAUDE.md. O CLAUDE.md não depende de invocação explícita por comando.\n\n- **Alternativa C** – Diz que o arquivo é lido apenas na primeira requisição e depois descartado. Isso contradiz o comportamento *always-on* do CLAUDE.md. Ele não é efêmero; permanece ativo durante toda a sessão de requisições para assegurar consistência de contexto.\n\n- **Alternativa D** – Alega que o CLAUDE.md só entra no contexto quando uma ferramenta específica é chamada. Na verdade, ele é carregado independentemente de qualquer ferramenta ser utilizada. Sua função é justamente estar sempre disponível, e não ser acionado condicionalmente por uma tool call.\n\nPortanto, a única que reflete corretamente o funcionamento real do CLAUDE.md é a **B**.','\n',char(10)),replace('Imagina que você tem um caderno de instruções do seu projeto favorito. Esse caderno fica sempre aberto na sua mesa enquanto você trabalha, mostrando as regras e dicas importantes o tempo todo.\n\nA pergunta é: como esse caderno é usado?\n\n- **Alternativa A** – Diz que o caderno só aparece quando você fala uma palavra mágica tipo "/skill-name". Não é verdade: o caderno está lá desde o começo, sem precisar de comando especial.\n\n- **Alternativa B (correta)** – Diz que o caderno está em toda conversa, sempre ajudando, como um lembrete fixo do que fazer. É exatamente isso! O CLAUDE.md fica sempre ali, dando instruções para o projeto.\n\n- **Alternativa C** – Diz que você lê o caderno só na primeira vez e depois joga fora. Não, porque as instruções são importantes o tempo todo, não só no começo.\n\n- **Alternativa D** – Diz que o caderno só aparece quando você pega uma ferramenta específica. Também não: ele está sempre visível, não importa a ferramenta que você use.\n\nEntão a resposta certa é a **B**: o CLAUDE.md está em todo pedido, funcionando como um guia que nunca sai da conversa.','\n',char(10)));
INSERT INTO cards VALUES('admin','card_1783092986709_23bo6phe2',241,'Where do you put personal instructions that should not be shared with the team but apply only to this project?',replace('Where do you put personal instructions that should not be shared with the team but apply only to this project?\n\nWhere do you put personal instructions that should not be shared with the team but apply only to this project?\n[Resposta correta: CLAUDE.local.md guarda instruções pessoais não compartilhadas, restritas ao projeto. CLAUDE.md seria compartilhado; ~/.claude/CLAUDE.md valeria para todos os projetos; workflows não têm essa função.]\n\n[ ] A - CLAUDE.md, since it is committed\n[ ] B - ~/.claude/CLAUDE.md, since it applies to all projects\n[ ] C - CLAUDE.local.md, since it is personal and not shared\n[ ] D - .github/workflows, since it isolates from the team','\n',char(10)),'C - CLAUDE.local.md, since it is personal and not shared','["Domain_3::Claude_Code_Configuration_Workflows", "Scenario_2::Code_Generation_Claude_Code"]','New',0,2.5,0,1783092986709,1783727156594,1783203558653,replace('**Tradução para português do Brasil:**\n\nOnde você coloca instruções pessoais que não devem ser compartilhadas com o time, mas se aplicam apenas a este projeto?\n\n[ ] A - CLAUDE.md, já que ele é versionado (committed)\n[ ] B - ~/.claude/CLAUDE.md, já que se aplica a todos os projetos\n[ ] C - CLAUDE.local.md, já que é pessoal e não compartilhado\n[ ] D - .github/workflows, já que isola do time','\n',char(10)),replace('**Explicação técnica para adulto tech lead:**\n\nA pergunta trata de como configurar instruções pessoais (não compartilhadas) que sejam específicas de um único projeto, no contexto de ferramentas como Claude (ou similares) que leem arquivos de configuração locais.\n\n**Resposta correta: C - CLAUDE.local.md**\n\nA alternativa C está correta porque o arquivo `CLAUDE.local.md` foi projetado exatamente para este propósito: conter instruções pessoais que não são versionadas (tipicamente incluído no `.gitignore`) e que se aplicam apenas ao projeto atual. Isso permite que cada desenvolvedor tenha suas próprias preferências locais sem poluir o repositório ou impor configurações pessoais ao time.\n\n**Por que as demais estão incorretas:**\n\n- **A - CLAUDE.md**: Este arquivo geralmente é versionado e compartilhado com o time. Se você colocar instruções pessoais aqui, elas serão enviadas para o repositório remoto e visíveis para todos, o que vai contra o requisito de "não compartilhado com o time".\n\n- **B - ~/.claude/CLAUDE.md**: Este arquivo está no diretório home do usuário, portanto se aplica a *todos os projetos* que você abre, e não a um projeto específico. A pergunta pede instruções que "se aplicam apenas a este projeto", logo esta alternativa não atende ao escopo restrito.\n\n- **D - .github/workflows**: Diretório destinado a pipelines de CI/CD (GitHub Actions). Não é o local adequado para instruções pessoais de configuração da ferramenta; workflows têm finalidade de automação e são compartilhados com o time via versionamento.','\n',char(10)),replace('**Explicação para criança de 10 anos:**\n\nImagine que você tem um caderno de deveres de casa que todo mundo na sua sala pode ver. Nele, você escreve as tarefas do grupo. Mas você também tem um bloquinho secreto, só seu, onde anota lembretes pessoais — tipo "não esqueça de levar o lanche amanhã". \n\nEsse bloquinho secreto é o **CLAUDE.local.md**: é pessoal (só você vê), e é só para esse projeto (igual esse caderno específico de matemática, não serve para todas as matérias).\n\nAgora veja os outros:\n- **CLAUDE.md** é o caderno que todo mundo vê — não dá para colocar segredos ali.\n- **~/.claude/CLAUDE.md** é como uma mochila que você leva para todas as aulas — as instruções valem para tudo, não só para este projeto.\n- **.github/workflows** é o quadro de tarefas da sala, onde a professora coloca o que o grupo inteiro precisa fazer — também não é lugar para anotação pessoal.\n\nEntão a resposta certa é a **C**: CLAUDE.local.md, porque é pessoal e não é compartilhado.','\n',char(10)));
INSERT INTO cards VALUES('admin','card_1783092986725_zxb3rgra8',242,'You want instructions that apply to all your projects on your machine.',replace('You want instructions that apply to all your projects on your machine.\n\nYou want instructions that apply to all your projects on your machine. Where do you put them?\n[Resposta correta: O ~/.claude/CLAUDE.md tem escopo global de máquina e vale para todos os seus projetos. Repetir por projeto é trabalhoso e frágil; CLAUDE.local.md e settings.local.json ficam restritos a um projeto.]\n\n[ ] A - In each project''s CLAUDE.md, repeating in all of them\n[ ] B - In ~/.claude/CLAUDE.md (global machine scope)\n[ ] C - In the current project''s CLAUDE.local.md\n[ ] D - In the project''s settings.local.json','\n',char(10)),'B - In ~/.claude/CLAUDE.md (global machine scope)','["Domain_3::Claude_Code_Configuration_Workflows", "Scenario_2::Code_Generation_Claude_Code"]','New',0,2.5,0,1783092986725,1783727159690,1783203558653,replace('**Tradução**\n\nVocê quer instruções que se apliquem a todos os seus projetos na sua máquina. Onde você as coloca?\n\n[ ] A - No CLAUDE.md de cada projeto, repetindo em todos eles\n[ ] B - Em ~/.claude/CLAUDE.md (escopo global de máquina)\n[ ] C - No CLAUDE.local.md do projeto atual\n[ ] D - No settings.local.json do projeto','\n',char(10)),replace('**Explicação para Adulto (Tech Lead)**\n\nA pergunta trata do mecanismo de configuração de instruções do Claude para projetos. O problema central é: como definir instruções que valham para **todos** os projetos em uma mesma máquina, sem precisar repeti-las manualmente em cada um.\n\n**Alternativa correta: B - In ~/.claude/CLAUDE.md (global machine scope)**\n\nO arquivo `~/.claude/CLAUDE.md` é o arquivo de escopo global de máquina. Qualquer instrução colocada ali será aplicada automaticamente a todos os projetos que você abrir no Claude nesta máquina. Isso é o equivalente a uma configuração "global" ou "system-wide" — escreve uma vez, vale para tudo. É a solução certa para o requisito de "instruções que se aplicam a todos os projetos".\n\n**Por que as demais estão erradas:**\n\n- **A - In each project''s CLAUDE.md, repeating in all of them**: Esta alternativa descreve exatamente o problema que queremos evitar. Repetir a mesma instrução manualmente em N projetos é trabalhoso, propenso a erros de inconsistência (você atualiza em um e esquece nos outros) e frágil. Não é uma boa prática de engenharia.\n\n- **C - In the current project''s CLAUDE.local.md**: O `CLAUDE.local.md` tem escopo **local ao projeto** — ele vale apenas para o projeto específico onde está inserido. Não atende ao requisito de "todos os projetos".\n\n- **D - In the project''s settings.local.json**: Este arquivo é para configurações locais de um projeto específico (como ajustes de ferramentas ou preferências), não para instruções globais. Além disso, também é restrito a um único projeto.','\n',char(10)),replace('Imagine que você tem vários trabalhos de escola (projetos) no seu computador e quer que uma regra valha para todos eles, tipo "sempre use letra legível" ou "sempre coloque data no começo".\n\nSe você colocar essa regra em um lugar que vale para **tudo** no computador, como um aviso na parede do seu quarto, você escreve uma vez e vale para todos os trabalhos. É isso que o arquivo `~/.claude/CLAUDE.md` faz — ele é o "aviso na parede" que vale para todos os projetos.\n\nAs outras opções são ruins porque:\n- **A**: Você teria que escrever a mesma regra em cada caderno (projeto) — muito trabalho e chance de esquecer!\n- **C e D**: Esses lugares são como bilhetes dentro de um caderno específico — valem só para aquele caderno, não para todos.','\n',char(10)));
INSERT INTO cards VALUES('admin','card_1783092986740_d8sgga6xq',243,'The repo already has an AGENTS.',replace('The repo already has an AGENTS.\n\nThe repo already has an AGENTS.md from another tool. How do you reuse it in the CLAUDE.md without duplicating content?\n[Resposta correta: O import @AGENTS.md na primeira linha carrega aquele conteúdo primeiro, evitando duplicação. Copiar/colar duplica; renomear perde o arquivo da outra ferramenta; referenciar só no prompt não persiste em toda requisição.]\n\n[ ] A - Copy and paste all of the AGENTS.md content into the CLAUDE.md\n[ ] B - Add @AGENTS.md on the first line of the CLAUDE.md and write specific instructions below the import\n[ ] C - Rename AGENTS.md to CLAUDE.md and delete the original\n[ ] D - Reference the AGENTS.md only in the prompt on each request','\n',char(10)),'B - Add @AGENTS.md on the first line of the CLAUDE.md and write specific instructions below the import','["Domain_3::Claude_Code_Configuration_Workflows", "Scenario_2::Code_Generation_Claude_Code"]','New',0,2.5,0,1783092986740,1783727163003,1783203558653,replace('**Tradução para pt-BR:**\n\nO repositório já tem um arquivo AGENTS.md de outra ferramenta. Como reutilizá-lo no CLAUDE.md sem duplicar o conteúdo?\n\n[ ] A - Copiar e colar todo o conteúdo do AGENTS.md dentro do CLAUDE.md\n[ ] B - Adicionar @AGENTS.md na primeira linha do CLAUDE.md e escrever instruções específicas abaixo do import\n[ ] C - Renomear AGENTS.md para CLAUDE.md e deletar o original\n[ ] D - Referenciar o AGENTS.md apenas no prompt a cada requisição','\n',char(10)),replace('**Explicação para adulto (tech lead):**\n\nA alternativa correta é a **B**. O mecanismo de importação via `@AGENTS.md` funciona como uma diretiva de inclusão no início do arquivo CLAUDE.md. Isso permite que o conteúdo do AGENTS.md seja carregado automaticamente em todas as interações, sem duplicação física de conteúdo. Você pode então complementar com instruções específicas do Claude abaixo dessa linha.\n\n**Erros das demais alternativas:**\n\n- **A (Copiar e colar):** Duplica o conteúdo manualmente. Se o AGENTS.md for atualizado pela outra ferramenta, o CLAUDE.md ficará dessincronizado. Viola o princípio DRY (Don''t Repeat Yourself) e cria um problema de manutenção.\n\n- **C (Renomear e deletar):** Destrói o arquivo original da outra ferramenta. O AGENTS.md provavelmente é usado por outros sistemas (agentes, CI/CD, etc.). Removê-lo quebraria esses fluxos.\n\n- **D (Referenciar apenas no prompt):** Não persiste. O conteúdo do AGENTS.md seria carregado apenas se você manualmente incluí-lo no prompt a cada requisição, o que é inviável e inconsistente. O CLAUDE.md existe justamente para evitar esse trabalho repetitivo.','\n',char(10)),replace('Imagine que você tem dois cadernos: um caderno de "Instruções para Agentes" (AGENTS.md) que seu amigo usa, e um caderno novo chamado "Instruções para o Claude" (CLAUDE.md) que é só seu.\n\nA opção B é como colocar um marcador de livro no CLAUDE.md que diz "olhe o caderno do meu amigo primeiro". Assim você não precisa copiar tudo do caderno dele (opção A - trabalho chato), nem jogar o caderno dele fora (opção C - ele ficaria triste), nem ficar lembrando de falar "olha o caderno do meu amigo" toda hora (opção D - cansativo).\n\nA opção B é esperta porque você só escreve "use @AGENTS.md" uma vez, e pronto — o Claude já sabe que deve ler o caderno do amigo automaticamente sempre que for te ajudar.','\n',char(10)));
INSERT INTO cards VALUES('admin','card_1783092986756_1c8cd6wk6',244,'Mentioning @prisma/schema.',replace('Mentioning @prisma/schema.\n\nMentioning @prisma/schema.prisma inside the CLAUDE.md has which effect?\n[Resposta correta: A menção com @ no CLAUDE.md inclui o conteúdo em toda requisição, poupando buscas repetidas. A B descreve @ no prompt (só naquela requisição); a C e a D não correspondem ao comportamento do import.]\n\n[ ] A - It includes the file content in every request automatically\n[ ] B - It includes the content only in the next request\n[ ] C - It creates a skill that loads the file on demand\n[ ] D - It blocks Claude''s access to the file','\n',char(10)),'[ ] A - It includes the file content in every request automatically','["Domain_3::Claude_Code_Configuration_Workflows", "Domain_5::Context_Management_Reliability", "Scenario_2::Code_Generation_Claude_Code"]','New',0,2.5,0,1783092986756,1783727166155,1783203558653,replace('**Tradução para português do Brasil:**\n\nMencionar @prisma/schema.prisma dentro do CLAUDE.md tem qual efeito?\n\n[ ] A - Inclui o conteúdo do arquivo automaticamente em toda requisição\n[ ] B - Inclui o conteúdo apenas na próxima requisição\n[ ] C - Cria uma skill que carrega o arquivo sob demanda\n[ ] D - Bloqueia o acesso de Claude ao arquivo','\n',char(10)),replace('**Explicação para um adulto tech lead:**\n\nO arquivo **CLAUDE.md** funciona como um arquivo de configuração de contexto persistente para o Claude. Quando você referencia um arquivo usando a sintaxe `@caminho/do/arquivo` dentro do CLAUDE.md, você está instruindo o Claude a incluir o conteúdo desse arquivo como parte do contexto padrão em **todas as conversas e requisições** onde aquele projeto/base de conhecimento está ativo.\n\n**Análise das alternativas:**\n\n- **Alternativa A (correta):** O comportamento do `@arquivo` dentro do CLAUDE.md é exatamente este: tornar o conteúdo do arquivo referenciado parte do contexto global, disponível automaticamente em toda requisição. Isso evita que o Claude precise fazer buscas repetidas (como ler o arquivo do disco ou consultar um repositório) a cada interação.\n\n- **Alternativa B (incorreta):** Essa descrição se refere ao uso de `@arquivo` diretamente no prompt de uma requisição específica, e não no CLAUDE.md. O prompt `@arquivo` em uma mensagem individual inclui o conteúdo somente para aquela interação. Já no CLAUDE.md, o efeito é persistente e global.\n\n- **Alternativa C (incorreta):** CLAUDE.md não cria "skills". Skills são módulos de funcionalidade ou instruções especializadas, não têm relação com o mecanismo de inclusão de arquivos via `@`. A inclusão via CLAUDE.md é um carregamento direto e contínuo, não sob demanda.\n\n- **Alternativa D (incorreta):** O `@` no CLAUDE.md não bloqueia acesso; muito pelo contrário, ele explicita e inclui o conteúdo. Bloqueio de acesso seria algo como uma regra de segurança ou permissão, que não é o propósito do `@`.','\n',char(10)),replace('Imagine que o CLAUDE.md é como uma "lista de lembretes" que o Claude sempre lê antes de conversar com você. Se você escreve "@prisma/schema.prisma" nessa lista, é como se você colasse o conteúdo do arquivo de esquema do Prisma nessa lista de lembretes.\n\n**Alternativa A (correta):** Agora, o Claude vai ler esse conteúdo junto com a lista de lembretes **todas as vezes** que você conversar com ele. É como ter um post-it com informações importantes sempre na sua frente.\n\n**Alternativa B (errada):** Isso seria como mostrar o post-it para o Claude só uma vez e depois guardá-lo. Mas o CLAUDE.md faz o Claude lembrar sempre.\n\n**Alternativa C (errada):** Skill é como um "superpoder" especial. O CLAUDE.md não cria superpoderes, ele só inclui informações na lista de lembretes.\n\n**Alternativa D (errada):** O "@" não bloqueia nada! É o contrário: ele ajuda o Claude a enxergar o arquivo, não o esconde.','\n',char(10)));
INSERT INTO cards VALUES('admin','card_1783092986772_2uf9t53jt',245,'What is the difference between @file in the prompt and @file in the CLAUDE.',replace('What is the difference between @file in the prompt and @file in the CLAUDE.\n\nWhat is the difference between @file in the prompt and @file in the CLAUDE.md?\n[Resposta correta: @arquivo no prompt vale só para aquela requisição; no CLAUDE.md vale para todas. As demais confundem ou invertem o alcance de cada forma.]\n\n[ ] A - Both include the content in every request\n[ ] B - In the prompt it includes only in that request; in the CLAUDE.md it includes in every request of the project\n[ ] C - In the prompt it includes in all; in the CLAUDE.md only in the first\n[ ] D - Neither includes content, only the path','\n',char(10)),'[ ] B - In the prompt it includes only in that request; in the CLAUDE.md it includes in every request of the project','["Domain_3::Claude_Code_Configuration_Workflows", "Domain_4::Prompt_Engineering_Structured_Output", "Scenario_2::Code_Generation_Claude_Code"]','New',0,2.5,0,1783092986772,1783727169577,1783203558653,replace('**Tradução para português do Brasil:**\n\nPergunta: Qual é a diferença entre @arquivo no prompt e @arquivo no CLAUDE.md?\n\nAlternativas:\n[ ] A - Ambos incluem o conteúdo em todas as requisições\n[ ] B - No prompt, inclui apenas naquela requisição; no CLAUDE.md, inclui em todas as requisições do projeto\n[ ] C - No prompt, inclui em todas; no CLAUDE.md, apenas na primeira\n[ ] D - Nenhum inclui conteúdo, apenas o caminho','\n',char(10)),replace('**Explicação didática para um adulto tech lead:**\n\nA pergunta aborda o comportamento de dois mecanismos de referência a arquivos em assistentes de IA como Claude, que diferem quanto ao escopo de validade.\n\n- **@arquivo no prompt**: Refere-se ao uso de `@` seguido do nome de um arquivo diretamente na mensagem (prompt) que você envia. Esse é um mecanismo de **escopo local**: o conteúdo do arquivo é carregado e considerado apenas naquela interação específica. Uma vez que a conversa avança ou a sessão termina, aquela referência não é reaplicada automaticamente. É equivalente a um "include" temporário, utilizado para consultar ou processar um arquivo em um contexto imediato.\n\n- **@arquivo no CLAUDE.md**: O `CLAUDE.md` é um arquivo especial de configuração (como um `.cursorrules`, `.clinerules` ou similar) que define instruções persistentes para o modelo. Quando você referencia um arquivo via `@` dentro desse arquivo, o conteúdo referenciado é **incluído automaticamente em todas as requisições** subsequentes daquele projeto. É um mecanismo de **escopo global/projeto**: uma vez definido, o modelo carrega aquele conteúdo sempre que interage no contexto daquele projeto, sem necessidade de re-referenciá-lo manualmente.\n\n**Análise das alternativas:**\n\n- **Alternativa A (incorreta)**: Afirma que ambos incluem o conteúdo em todas as requisições. Isso é falso para o uso no prompt, que é de único uso.\n- **Alternativa B (correta)**: Descreve precisamente a diferença: escopo local (prompt) versus escopo global (CLAUDE.md). É a definição canônica desses mecanismos.\n- **Alternativa C (incorreta)**: Inverte o comportamento. O prompt não é persistente entre requisições, e o CLAUDE.md não se limita à primeira requisição — ele vale para todas.\n- **Alternativa D (incorreta)**: Alega que nenhum inclui conteúdo, apenas o caminho. Isso é falso: ambos os mecanismos, quando implementados, carregam e disponibilizam o conteúdo do arquivo para o modelo, não apenas o caminho.','\n',char(10)),replace('Imagina que você tem um amigo robô que te ajuda com a lição de casa.\n\n- **@arquivo no prompt** é como se você falasse: "Robô, dá uma olhada nessa página do meu caderno agora." Ele olha, responde, e depois esquece. No próximo pedido, você precisa mostrar a página de novo.\n\n- **@arquivo no CLAUDE.md** é como se você colasse aquela página na parede do quarto do robô. Agora, toda vez que você pedir ajuda, ele vai olhar para a parede e lembrar daquela informação sozinho, sem você precisar mostrar de novo.\n\n**Alternativa B** é a resposta certa, porque ela explica exatamente isso: no prompt é "só dessa vez", no CLAUDE.md é "sempre que você for ajudar nesse projeto". As outras alternativas estão trocadas ou dizem que o robô não vê o conteúdo, o que não é verdade.','\n',char(10)));
INSERT INTO cards VALUES('admin','card_1783092986787_4a22twyer',246,'Why does dumping irrelevant context hurt Claude?',replace('Why does dumping irrelevant context hurt Claude?\n\nWhy does dumping irrelevant context hurt Claude?\n[Resposta correta: Excesso de contexto irrelevante reduz a performance, por isso guia-se o Claude aos arquivos certos. A A troca o motivo; a C é falsa; a D contraria o princípio.]\n\n[ ] A - Because it increases security but reduces network speed\n[ ] B - Because too much irrelevant context reduces performance; the right thing is to guide it to the relevant files\n[ ] C - Because Claude only accepts one file at a time\n[ ] D - Because extra context always improves the answer, at no cost','\n',char(10)),'[ ] B - Because too much irrelevant context reduces performance; the right thing is to guide it to the relevant files','["Domain_5::Context_Management_Reliability", "Domain_3::Claude_Code_Configuration_Workflows", "Scenario_4::Developer_Productivity"]','New',0,2.5,0,1783092986787,1783727172868,1783203558653,replace('**Tradução para português do Brasil:**\n\nPor que adicionar contexto irrelevante prejudica o Claude?\n\n[ ] A - Porque aumenta a segurança, mas reduz a velocidade da rede\n[ ] B - Porque excesso de contexto irrelevante reduz a performance; o correto é guiá-lo para os arquivos relevantes\n[ ] C - Porque o Claude aceita apenas um arquivo por vez\n[ ] D - Porque contexto extra sempre melhora a resposta, sem custo algum','\n',char(10)),replace('**Explicação didática para um adulto tech lead:**\n\nA alternativa **B** é a correta porque descreve precisamente o problema de performance associado ao fornecimento de contexto irrelevante para modelos de linguagem como o Claude.\n\n**Por que B está correta:**\nModelos de linguagem têm uma "janela de contexto" finita (o número máximo de tokens que podem processar por vez). Quando você insere conteúdo irrelevante, você consome tokens preciosos dessa janela, o que pode:\n- Aumentar o tempo de processamento (mais tokens para analisar).\n- Diluir a atenção do modelo sobre as informações realmente relevantes, degradando a qualidade da resposta.\n- Potencialmente fazer com que informações importantes fiquem de fora da janela de contexto se o limite for atingido.\n\n**Análise das alternativas incorretas:**\n\n- **A - Porque aumenta a segurança, mas reduz a velocidade da rede:** Incorreta. Contexto irrelevante não tem relação com segurança nem com velocidade de rede. É um falso trade-off entre dois conceitos não relacionados ao problema.\n\n- **C - Porque o Claude aceita apenas um arquivo por vez:** Incorreta. O Claude pode processar múltiplos arquivos simultaneamente, desde que o conteúdo total não ultrapasse os limites da janela de contexto. Não há restrição de "um arquivo por vez".\n\n- **D - Porque contexto extra sempre melhora a resposta, sem custo algum:** Incorreta. Essa afirmação contradiz o princípio fundamental. Contexto extra tem custo computacional e cognitivo, e contexto irrelevante prejudica a qualidade em vez de melhorá-la.','\n',char(10)),replace('Imagine que o Claude é como um aluno muito inteligente fazendo uma prova. Se você der a ele um monte de papéis com informações que não têm nada a ver com a pergunta, ele vai gastar tempo lendo coisas inúteis e pode até se confundir. É melhor dar só o material que realmente importa para ele responder bem e rápido.\n\nAs alternativas erradas:\n- A: Não é sobre segurança nem velocidade de internet.\n- C: O Claude pode ler vários arquivos ao mesmo tempo, sim.\n- D: Colocar informação extra não ajuda sempre — se for coisa inútil, só atrapalha!','\n',char(10)));
INSERT INTO cards VALUES('admin','card_1783092986802_17rxiqo2o',247,'Claude keeps putting too many comments in the code.',replace('Claude keeps putting too many comments in the code.\n\nClaude keeps putting too many comments in the code. What is the permanent fix?\n[Resposta correta: Adicionar a instrução no CLAUDE.md (por editor ou /memory) corrige de forma persistente, pois ele é lido a cada conversa. /clear só limpa contexto; um hook bloqueando edições é excessivo; reinstalar não resolve.]\n\n[ ] A - Use /clear before each task\n[ ] B - Edit the CLAUDE.md (directly or via /memory) with the instruction, since it is read at the start of each conversation\n[ ] C - Create a PreToolUse hook that blocks any code editing\n[ ] D - Reinstall Claude Code','\n',char(10)),'B - Edit the CLAUDE.md (directly or via /memory) with the instruction, since it is read at the start of each conversation','["Domain_3::Claude_Code_Configuration_Workflows", "Domain_4::Prompt_Engineering_Structured_Output", "Scenario_2::Code_Generation_Claude_Code"]','New',0,2.5,0,1783092986802,1783727176121,1783203558653,replace('**Tradução:**\n\nClaude continua colocando muitos comentários no código. Qual é a correção permanente?\n\n[ ] A - Use /clear antes de cada tarefa\n[ ] B - Edite o CLAUDE.md (diretamente ou via /memory) com a instrução, já que ele é lido no início de cada conversa\n[ ] C - Crie um hook PreToolUse que bloqueie qualquer edição de código\n[ ] D - Reinstale o Claude Code','\n',char(10)),replace('**Explicação para adulto tech lead:**\n\nA resposta correta é a alternativa **B**.\n\n**Por que B está correta:**\nO CLAUDE.md é um arquivo de configuração lido pelo Claude no início de cada conversa. Ele funciona como um "system prompt" persistente, permitindo definir instruções globais que serão aplicadas consistentemente em todas as interações. Instruções colocadas lá (como "evite comentários excessivos no código") são seguidas pelo modelo de forma confiável, sem necessidade de intervenção manual repetitiva.\n\n**Por que as demais estão incorretas:**\n\n- **A** (/clear antes de cada tarefa): `/clear` limpa o contexto da conversa atual, mas não resolve o problema permanentemente. A cada nova conversa, Claude voltará a comentar excessivamente, exigindo que o comando seja repetido indefinidamente.\n\n- **C** (hook PreToolUse bloqueando edições de código): Um hook que bloqueia *toda* edição de código é uma medida exagerada e contraproducente. O problema são os comentários em excesso, não a edição de código em si. Bloquear edições impede que Claude execute qualquer alteração no código, inviabilizando seu propósito principal. Seria como usar uma bazuca para matar uma formiga.\n\n- **D** (reinstalar o Claude Code): Reinstalar não altera o comportamento do modelo em relação a comentários. O problema não é de instalação corrompida, mas sim de instrução/prompt. Reinstalar não resolve o problema subjacente.','\n',char(10)),replace('Imagine que o Claude é um ajudante que gosta de escrever bilhetes demais dentro do seu código. Você quer que ele escreva menos bilhetes.\n\n- Se você disser "para tudo e comece de novo" (opção A), ele esquece que você pediu e na próxima conversa volta a encher o código de bilhetes.\n- Se você escrever um lembrete no "caderno de instruções" dele, o CLAUDE.md (opção B), ele lê esse caderno sempre que começa a trabalhar e lembra de não exagerar nos bilhetes. É a melhor solução!\n- Se você colocar uma trava que impede ele de mexer no código (opção C), ele não consegue mais ajudar você a programar — é como amarrar as mãos do ajudante.\n- Se você reinstalar o programa (opção D), é como comprar um novo ajudante idêntico — ele continuará agindo do mesmo jeito, porque o problema não é o programa, é a instrução que você dá a ele.\n\nEntão, a opção B é a certa: escrever a regra no CLAUDE.md resolve o problema de verdade!','\n',char(10)));
INSERT INTO cards VALUES('admin','card_1783092986819_lp30xstuy',248,'A task requires broad understanding of the codebase and affects multiple files.',replace('A task requires broad understanding of the codebase and affects multiple files.\n\nA task requires broad understanding of the codebase and affects multiple files. What should you prioritize?\n[Resposta correta: Planning Mode é indicado para amplitude, implementações multi-passo e mudanças em vários arquivos. Aumentar effort serve para profundidade lógica em poucos arquivos; /compact e subagente não atacam a necessidade de amplitude.]\n\n[ ] A - Increase the effort level\n[ ] B - Planning Mode\n[ ] C - Use /compact repeatedly\n[ ] D - Run everything in a subagent with isolated context','\n',char(10)),'B - Planning Mode','["Domain_3::Claude_Code_Configuration_Workflows", "Domain_5::Context_Management_Reliability", "Scenario_2::Code_Generation_Claude_Code"]','New',0,2.5,0,1783092986819,1783727179414,1783203558653,replace('**Tradução para português do Brasil:**\n\nUma tarefa exige uma compreensão ampla da base de código e afeta vários arquivos. O que você deve priorizar?\n\n[ ] A - Aumentar o nível de effort\n[ ] B - Planning Mode\n[ ] C - Usar /compact repetidamente\n[ ] D - Executar tudo em um subagente com contexto isolado','\n',char(10)),replace('**Explicação didática para um adulto tech lead:**\n\nA pergunta trata de um cenário clássico de engenharia de software assistida por IA: quando uma mudança é transversal (cross-cutting) e toca múltiplos arquivos, o principal desafio não é a complexidade lógica dentro de um único arquivo, mas sim a **amplitude** — ou seja, a capacidade de manter coerência e visão sistêmica entre diversos pontos do código.\n\nVamos analisar cada alternativa:\n\n- **A - Aumentar o nível de effort:** Em ferramentas de IA como Claude, aumentar o "effort" eleva a profundidade do raciocínio em um escopo restrito. Isso é eficaz para problemas que exigem lógica densa e aninhada dentro de poucos arquivos (ex.: um algoritmo complexo em uma única função). Para o problema descrito, não resolve a necessidade de amplitude — você pode pensar muito, mas ainda assim estará pensando dentro de uma visão limitada.\n\n- **B - Planning Mode (Correta):** O Planning Mode é um padrão de uso de IA (como o "Planejamento" ou "Modo de Planejamento" em ferramentas como Cursor, Windsurf, ou mesmo prompts específicos para Claude) que força o modelo a primeiro criar um plano de ação detalhado, mapear os arquivos afetados, identificar dependências e só então executar mudanças. Isso ataca diretamente o problema de amplitude: você garante que o modelo tenha uma visão global antes de tocar em qualquer arquivo, evitando inconsistências, regressões e retrabalho.\n\n- **C - Usar /compact repetidamente:** O comando `/compact` (ou similar) geralmente comprime ou resume o contexto, descartando informação para economizar tokens. Repetir isso em um cenário de múltiplos arquivos é contraproducente — você estará jogando fora justamente a visão ampla que precisa. É o oposto do que se deseja.\n\n- **D - Executar tudo em um subagente com contexto isolado:** Delegar a um subagente com contexto isolado fragmenta o entendimento. Cada subagente teria apenas uma visão parcial do código, exatamente o que não se quer quando o requisito é "compreensão ampla da base de código". Isso aumenta o risco de decisões locais contraditórias.\n\n**Conclusão técnica:** A métrica relevante aqui é **amplitude vs. profundidade**. A pergunta descreve um problema de amplitude (múltiplos arquivos). Planning Mode é a ferramenta certa para amplitude. Aumentar effort é para profundidade. /compact reduz amplitude. Subagente isolado quebra amplitude. Portanto, B é a resposta correta.','\n',char(10)),replace('Imagine que você precisa arrumar um grande quebra-cabeça que está espalhado em várias mesas diferentes. Cada mesa tem algumas peças, e você precisa entender como tudo se encaixa.\n\nSe você ficar só pensando muito forte em uma única peça (aumentar o "effort"), você não vai resolver o problema — porque o problema não é uma peça difícil, são muitas peças em lugares diferentes.\n\nSe você pedir para alguém resumir tudo (/compact), você perde informação importante.\n\nSe você der cada mesa para uma pessoa diferente (subagente), ninguém vai ver o quadro completo.\n\nA melhor ideia é: antes de mexer em qualquer peça, parar e **planejar**. Olhar todas as mesas, ver como as peças se conectam, e fazer um plano de onde colocar cada coisa. Depois que o plano está pronto, aí sim você começa a mexer. Esse é o **Planning Mode** (Modo de Planejamento), e é a escolha certa para esse tipo de problema.','\n',char(10)));
INSERT INTO cards VALUES('admin','card_1783092986836_vwp37wx92',249,'How does Planning Mode behave and how is it activated?',replace('How does Planning Mode behave and how is it activated?\n\nHow does Planning Mode behave and how is it activated?\n[Resposta correta: O Planning Mode lê mais arquivos, monta um plano e aguarda aprovação, ativado por /plan ou Shift+Tab duas vezes. A A inverte o comportamento e o comando; a C inventa a flag --batch; a D confunde com o atalho de colar screenshot.]\n\n[ ] A - It implements directly and then shows a summary; activated with /compact\n[ ] B - It reads more files, creates a detailed plan and waits for approval; activated with /plan or Shift+Tab twice\n[ ] C - It blocks all tools; activated with --batch\n[ ] D - It runs tests automatically; activated with Ctrl+V','\n',char(10)),'B - It reads more files, creates a detailed plan and waits for approval; activated with /plan or Shift+Tab twice','["Domain_3::Claude_Code_Configuration_Workflows", "Scenario_2::Code_Generation_Claude_Code"]','New',0,2.5,0,1783092986836,1783727182521,1783203558653,replace('**Tradução para português do Brasil:**\n\nPergunta: Como o Planning Mode se comporta e como é ativado?\n\nAlternativas:\n\n[ ] A - Ele implementa diretamente e depois mostra um resumo; ativado com /compact\n[ ] B - Ele lê mais arquivos, cria um plano detalhado e aguarda aprovação; ativado com /plan ou Shift+Tab duas vezes\n[ ] C - Ele bloqueia todas as ferramentas; ativado com --batch\n[ ] D - Ele executa testes automaticamente; ativado com Ctrl+V','\n',char(10)),replace('**Explicação para um adulto tech lead:**\n\nO Planning Mode é um recurso de ambiente de desenvolvimento assistido (como o Claude Code ou ferramentas similares) que altera o comportamento padrão do agente. Em vez de executar ações imediatamente, ele primeiro realiza uma leitura mais ampla do código-fonte (lê mais arquivos relevantes), monta um plano de ação estruturado e detalhado, e então *aguarda a aprovação explícita do usuário* antes de executar qualquer modificação. Isso é particularmente útil para tarefas complexas onde se deseja revisar a abordagem antes de aplicá-la.\n\n- **Alternativa B (correta):** Descreve com precisão o comportamento ("lê mais arquivos, cria um plano detalhado e aguarda aprovação") e os métodos de ativação ("/plan ou Shift+Tab duas vezes"). Ambos são mecanismos documentados para entrar nesse modo.\n\n- **Alternativa A (incorreta):** Inverte completamente a lógica. O Planning Mode não implementa nada diretamente — ele justamente *interrompe* a implementação automática para apresentar um plano. O comando /compact não é o gatilho correto; /compact geralmente está associado a compressão de contexto ou resumo de conversa, não a planejamento.\n\n- **Alternativa C (incorreta):** O Planning Mode não bloqueia ferramentas; ele apenas adia sua execução até aprovação. A flag --batch é um parâmetro de execução em lote (batch mode), que tipicamente faz o oposto: executa tudo sem intervenção manual. É um erro conceitual.\n\n- **Alternativa D (incorreta):** O Planning Mode não executa testes automaticamente. A ativação com Ctrl+V é um atalho comum para colar conteúdo da área de transferência (screenshot ou texto), não para ativar modo de planejamento. A descrição confunde funcionalidades distintas.','\n',char(10)),replace('Imagine que você tem um robô que pode ajudar a arrumar seu quarto. Normalmente, ele começa a arrumar na hora. Mas o "Modo Planejamento" faz o robô dar um passo atrás, olhar tudo que tem no quarto, pensar em um plano do que fazer primeiro, e **perguntar para você** se está tudo bem antes de começar. Para ligar esse modo, você diz "plano" (usa o comando /plan) ou aperta duas vezes Shift+Tab — é como dar um comando secreto para o robô pensar antes de agir.\n\nA opção A está errada porque o robô não faz nada direto — ele planeja primeiro. A opção C está errada porque ele não bloqueia as ferramentas; só espera você dizer "pode ir". A opção D está errada porque ele não sai testando tudo; ele só mostra o plano no papel.','\n',char(10)));
INSERT INTO cards VALUES('admin','card_1783092986853_xqn9zm1qv',250,'You are facing a hard algorithmic bug concentrated in a few files.',replace('You are facing a hard algorithmic bug concentrated in a few files.\n\nYou are facing a hard algorithmic bug concentrated in a few files. What should you prioritize?\n[Resposta correta: Aumentar o effort é indicado para lógica complexa e debugging difícil em poucos arquivos. Planning Mode serve para amplitude/múltiplos arquivos; /init e /compact não tratam a dificuldade lógica.]\n\n[ ] A - Planning Mode, because of the breadth\n[ ] B - Increase the effort level, better for complex logic and hard debugging\n[ ] C - Run /init again\n[ ] D - Compact the context to focus','\n',char(10)),'B - Increase the effort level, better for complex logic and hard debugging','["Domain_3::Claude_Code_Configuration_Workflows", "Domain_5::Context_Management_Reliability", "Scenario_2::Code_Generation_Claude_Code"]','New',0,2.5,0,1783092986853,1783727185528,1783203558653,replace('**Tradução para português do Brasil:**\n\nVocê está enfrentando um bug algorítmico difícil concentrado em alguns poucos arquivos. O que você deve priorizar?\n\n[ ] A - Planning Mode, por causa da amplitude\n[ ] B - Aumentar o nível de esforço (effort), melhor para lógica complexa e debugging difícil\n[ ] C - Executar /init novamente\n[ ] D - Compactar o contexto para focar','\n',char(10)),replace('**Explicação para um adulto tech lead:**\n\nO cenário descreve um bug **algorítmico** (lógica complexa) e **concentrado** (poucos arquivos). Não se trata de um problema de arquitetura ampla ou de contexto poluído.\n\n- **Alternativa B (correta):** "Aumentar o nível de esforço" é a ação mais adequada quando o desafio é de profundidade lógica em uma base de código pequena e localizada. Em sistemas como o Claude (Sonnet/Opus) ou ferramentas de IA, aumentar o parâmetro de "effort" (ou usar o modelo mais capaz) faz com que a IA pense por mais tempo, explore múltiplas hipóteses e faça deduções mais refinadas — exatamente o que se precisa para depurar um algoritmo complexo em poucos arquivos.\n\n- **Alternativa A (errada):** "Planning Mode" é útil quando o problema tem grande **amplitude** (muitos arquivos, muitas dependências, necessidade de visão sistêmica). Para um bug concentrado em poucos arquivos, o planejamento de alto nível é desnecessário e não endereça a complexidade algorítmica específica.\n\n- **Alternativa C (errada):** Executar `/init` novamente reinicializa o contexto ou recarrega configurações. Isso não resolve a dificuldade lógica do algoritmo — é uma ação reativa que não trata o cerne do problema.\n\n- **Alternativa D (errada):** Compactar o contexto serve para reduzir ruído e melhorar foco quando há excesso de informação irrelevante. O enunciado diz que o bug já está concentrado em **poucos arquivos**, então a compactação não traria ganho significativo e não ajuda a resolver a complexidade algorítmica.','\n',char(10)),replace('Imagine que você tem um quebra-cabeça difícil, mas as peças estão todas em uma mesinha pequena — não espalhadas pela casa inteira. O problema é que o desenho é complicado, não que você precisa procurar peças por aí.\n\n- Se você **aumentar o esforço** (alternativa B), é como se você parasse, respirasse fundo e pensasse com calma em cada peça, tentando encaixar com mais cuidado. É a melhor ideia quando o problema é difícil de resolver, mas está num lugar só.\n- **Planejar** (alternativa A) seria bom se o problema estivesse espalhado por muitos lugares, mas não é o caso.\n- **Recomeçar do zero** (alternativa C) seria chato e não ajudaria — o problema continuaria o mesmo.\n- **Guardar as peças que não estão na mesa** (alternativa D) não adianta, porque elas já estão todas na mesa!\n\nEntão, a melhor escolha é a **B**: focar e se esforçar mais para resolver a parte difícil.','\n',char(10)));
INSERT INTO cards VALUES('admin','card_1783092986893_t4u79l0f7',251,'A task requires breadth (multiple files) and also logical depth.',replace('A task requires breadth (multiple files) and also logical depth.\n\nA task requires breadth (multiple files) and also logical depth. Which approach?\n[Resposta correta: Amplitude com profundidade pede combinar Planning Mode e effort alto, lembrando do custo extra de tokens. Usar só um deles cobre apenas metade da necessidade; eles não se anulam.]\n\n[ ] A - Use only Planning Mode, since it covers both cases\n[ ] B - Use only high effort, since it is always enough\n[ ] C - Combine Planning Mode with higher effort, aware of the extra token cost\n[ ] D - Avoid both, since they cancel each other out','\n',char(10)),'C - Combine Planning Mode with higher effort, aware of the extra token cost','["Domain_3::Claude_Code_Configuration_Workflows", "Domain_4::Prompt_Engineering_Structured_Output", "Scenario_2::Code_Generation_Claude_Code"]','New',0,2.5,0,1783092986893,1783727188774,1783203558653,replace('Tradução para português do Brasil:\n\nPERGUNTA: Uma tarefa exige amplitude (vários arquivos) e também profundidade lógica.\n\nUma tarefa exige amplitude (vários arquivos) e também profundidade lógica. Qual abordagem?\n[Resposta correta: Amplitude com profundidade pede combinar Planning Mode e effort alto, lembrando do custo extra de tokens. Usar só um deles cobre apenas metade da necessidade; eles não se anulam.]\n\n[ ] A - Use apenas o Planning Mode, já que ele cobre ambos os casos\n[ ] B - Use apenas effort alto, já que é sempre suficiente\n[ ] C - Combine Planning Mode com effort maior, ciente do custo extra de tokens\n[ ] D - Evite ambos, já que eles se cancelam mutuamente','\n',char(10)),replace('Explicação para adulto tech lead:\n\nA pergunta aborda um cenário onde a tarefa possui duas dimensões complexas: amplitude (múltiplos arquivos) e profundidade (lógica encadeada). Cada mecanismo disponível atende melhor a uma dessas dimensões:\n\n- Planning Mode: focado em coordenar alterações em múltiplos arquivos, garantindo visão sistêmica e consistência entre módulos. É ideal para amplitude.\n- High effort (esforço alto): aumenta a capacidade de raciocínio profundo do modelo, permitindo que ele explore cadeias lógicas mais longas e complexas. É ideal para profundidade.\n\nA alternativa C é a correta porque propõe combinar ambos, reconhecendo que as necessidades são complementares. As demais falham:\n\n- A: Planning Mode sozinho não aprofunda raciocínio lógico encadeado.\n- B: High effort sozinho não gerencia bem mudanças coordenadas entre múltiplos arquivos.\n- D: Não há cancelamento; pelo contrário, as abordagens são ortogonais e se complementam.\n\nA observação sobre custo extra de tokens é pertinente: usar ambos consome mais tokens, mas é necessário para cobrir integralmente os requisitos da tarefa.','\n',char(10)),replace('Explicação para uma criança de 10 anos:\n\nImagina que você tem dois problemas para resolver na mesma tarefa:\n\n1. Você precisa desenhar um castelo enorme que ocupa várias folhas de papel — isso é a "amplitude", porque mexe em muitos lugares.\n2. Dentro do castelo, você precisa criar um labirinto cheio de portas secretas e puzzles que se conectam — isso é a "profundidade", porque exige pensar em várias etapas em sequência.\n\nSe você usar só o **Planning Mode**, que é como ter um mapa mostrando onde cada folha de papel vai, você resolve bem a parte de organizar as folhas, mas não ajuda a desenhar o labirinto complicado.\n\nSe você usar só o **effort alto**, que é como ter seu cérebro no máximo para resolver problemas difíceis, você consegue criar o labirinto, mas pode se atrapalhar para encaixar tudo nas várias folhas.\n\nA melhor ideia (alternativa C) é usar os dois juntos: o mapa (Planning Mode) para cuidar das várias folhas e o cérebro no máximo (effort alto) para criar o labirinto. Só precisa lembrar que usar os dois gasta mais energia (mais tokens), mas é o jeito certo de fazer tudo direitinho.\n\nAs outras opções estão erradas:\n- Só o mapa (A): não resolve o labirinto.\n- Só o cérebro no máximo (B): não resolve a bagunça das folhas.\n- Evitar os dois (D): eles não bagunçam um ao outro, pelo contrário, funcionam bem juntos!','\n',char(10)));
INSERT INTO cards VALUES('admin','card_1783092986910_ve3u3xful',252,'Which shortcut pastes a screenshot into Claude Code to indicate the interface area to change?',replace('Which shortcut pastes a screenshot into Claude Code to indicate the interface area to change?\n\nWhich shortcut pastes a screenshot into Claude Code to indicate the interface area to change?\n[Resposta correta: O atalho é Ctrl+V, mesmo no macOS (não Cmd+V). Cmd+V é a pegadinha; Shift+Tab ativa Planning Mode; Ctrl+Shift+S não é o atalho descrito.]\n\n[ ] A - Cmd+V on macOS\n[ ] B - Ctrl+V, including on macOS\n[ ] C - Shift+Tab twice\n[ ] D - Ctrl+Shift+S','\n',char(10)),'B - Ctrl+V, including on macOS','["Domain_3::Claude_Code_Configuration_Workflows", "Scenario_2::Code_Generation_Claude_Code"]','New',0,2.5,0,1783092986910,1783727191854,1783203558653,replace('Tradução da pergunta e alternativas para português do Brasil:\n\n**Pergunta:** Qual atalho cola uma captura de tela no Claude Code para indicar a área da interface que deve ser alterada?\n\n[ ] A - Cmd+V no macOS\n[ ] B - Ctrl+V, inclusive no macOS\n[ ] C - Shift+Tab duas vezes\n[ ] D - Ctrl+Shift+S','\n',char(10)),replace('Explicação didática para um adulto tech lead:\n\nA pergunta trata de um atalho específico do Claude Code (ferramenta da Anthropic) para colar screenshots diretamente no chat, permitindo que o desenvolvedor indique visualmente qual área da interface deseja modificar.\n\n**Alternativa correta: B - Ctrl+V, inclusive no macOS**\n\nO Claude Code, por ser um produto multiplataforma que funciona dentro do terminal/IDE, padronizou o atalho **Ctrl+V** para colar screenshots **independentemente do sistema operacional**. Isso inclui o macOS, onde o usual seria Cmd+V. É uma escolha intencional de design para consistência entre plataformas e para evitar conflitos com atalhos nativos do terminal (já que Cmd+V no terminal do macOS frequentemente tem outro comportamento).\n\n**Por que as demais alternativas estão incorretas:**\n\n- **A - Cmd+V no macOS:** É a "pegadinha" mencionada na dica. No macOS, a maioria dos aplicativos usa Cmd+V para colar, mas o Claude Code propositalmente não segue essa convenção para este caso específico. Usar Cmd+V não funcionará para colar a screenshot.\n\n- **C - Shift+Tab duas vezes:** Este atalho ativa o **Planning Mode** no Claude Code, que é um modo para gerar planos de implementação, não para colar screenshots.\n\n- **D - Ctrl+Shift+S:** Embora combinações com Ctrl+Shift+S sejam comumente usadas para "Salvar como..." em diversos aplicativos, este não é o atalho descrito para colar screenshots no Claude Code.','\n',char(10)),replace('Imagine que você tem um joguinho ou um programa no computador e quer mostrar para um amigo qual parte você quer mudar. Você pode tirar uma foto da tela (chamada de screenshot) e colar essa foto no chat do Claude Code.\n\nA pergunta é: qual tecla apertar para colar essa foto?\n\nA resposta certa é apertar **Ctrl+V**, não importa se você está no computador da Apple (Mac) ou no Windows. Mesmo que no Mac a gente normalmente aperte Cmd+V para colar coisas, aqui no Claude Code a regra é diferente: use Ctrl+V.\n\nAs outras opções estão erradas porque:\n- **Cmd+V no Mac:** Não funciona, é uma "pegadinha". No Claude Code, você precisa usar Ctrl+V até no Mac.\n- **Shift+Tab duas vezes:** Isso liga um "modo de planejamento", que ajuda a pensar em como fazer algo, mas não cola a foto.\n- **Ctrl+Shift+S:** Isso não é o atalho para colar a screenshot.','\n',char(10)));
INSERT INTO cards VALUES('admin','card_1783092986925_7syyit61p',253,'The conversation accumulated irrelevant exchange during debugging, but you want to preserve the understanding of the codebase.',replace('The conversation accumulated irrelevant exchange during debugging, but you want to preserve the understanding of the codebase.\n\nThe conversation accumulated irrelevant exchange during debugging, but you want to preserve the understanding of the codebase. What should you use?\n[Resposta correta: /rewind volta a um ponto anterior removendo o histórico distrativo e preservando o contexto valioso. /clear apagaria tudo; /compact não é descrito assim; /resume retoma outra conversa.]\n\n[ ] A - /clear, to wipe everything\n[ ] B - /rewind (or Escape twice), to go back to an earlier point preserving useful context\n[ ] C - /compact, which discards the understanding\n[ ] D - /resume, to resume another conversation','\n',char(10)),'B - /rewind (or Escape twice), to go back to an earlier point preserving useful context','["Domain_3::Claude_Code_Configuration_Workflows", "Domain_5::Context_Management_Reliability", "Scenario_2::Code_Generation_Claude_Code"]','New',0,2.5,0,1783092986925,1783727195044,1783203558653,replace('**Tradução para português do Brasil:**\n\nA conversa acumulou trocas irrelevantes durante a depuração, mas você quer preservar o entendimento do código.\n\nO que você deve usar?\n\n[ ] A - /clear, para limpar tudo\n[ ] B - /rewind (ou Escape duas vezes), para voltar a um ponto anterior preservando o contexto útil\n[ ] C - /compact, que descarta o entendimento\n[ ] D - /resume, para retomar outra conversa','\n',char(10)),replace('**Explicação didática para um adulto tech lead:**\n\nA situação descrita é comum em sessões de debugging com assistentes de IA: ao longo da interação, acumulam-se mensagens que não agregam valor (tentativas frustradas, hipóteses descartadas, erros de sintaxe, etc.), mas o assistente já construiu um entendimento valioso do código e do contexto do problema.\n\nO comando **/rewind** (ou pressionar Escape duas vezes) permite voltar a um ponto anterior da conversa, removendo as mensagens distrativas que vieram depois, mas **preservando o entendimento do contexto** que o modelo já adquiriu até aquele ponto. Isso é exatamente o que se deseja: eliminar o ruído sem perder o conhecimento já construído sobre a base de código.\n\nAnalisando as alternativas incorretas:\n\n- **/clear**: Apaga todo o histórico da conversa, incluindo todo o entendimento do código que foi construído. Isso joga fora o contexto valioso, o que é justamente o oposto do que se quer.\n\n- **/compact**: Não é um comando padrão descrito com essa funcionalidade. Mesmo que exista em algumas implementações, a descrição dada ("discards the understanding") indica que ele descarta o entendimento, o que não atende ao requisito.\n\n- **/resume**: Serve para retomar uma conversa anterior (outra sessão), não para limpar distrações dentro da conversa atual. Além disso, não remove o histórico distrativo.\n\nPortanto, a alternativa **B** é a única que satisfaz ambos os objetivos: remover o histórico distrativo E preservar o contexto valioso.','\n',char(10)),replace('Imagine que você está desenhando um robô no papel e, enquanto desenha, faz vários rabiscos e riscos sem querer. Mas você já entendeu direitinho como o robô funciona. Agora você quer apagar só os rabiscos atrapalhados, sem perder o que aprendeu sobre o robô.\n\nO comando **/rewind** (ou apertar Escape duas vezes) é como voltar no tempo: você volta para um momento antes dos rabiscos, mas continua lembrando de tudo que aprendeu sobre o robô. As outras opções não funcionam bem:\n\n- **/clear** apaga tudo, até o desenho do robô e o que você aprendeu. Não serve.\n- **/compact** joga fora o que você aprendeu. Não serve.\n- **/resume** serve para começar a desenhar outro robô em outra folha. Também não serve.\n\nEntão a resposta certa é a **B**!','\n',char(10)));
INSERT INTO cards VALUES('admin','card_1783092986941_vayy17an1',254,'You are going to continue a related task and want to preserve what Claude learned.',replace('You are going to continue a related task and want to preserve what Claude learned.\n\nYou are going to continue a related task and want to preserve what Claude learned. Which command?\n[Resposta correta: /compact resume o histórico e preserva o aprendizado, ideal para tarefas relacionadas. /clear zeraria o contexto (para tarefa diferente); /rewind volta a um ponto; /resume não inicia contexto novo.]\n\n[ ] A - /clear, since it wipes the context\n[ ] B - /compact, since it summarizes the history preserving the learning\n[ ] C - /rewind, since it goes back to an earlier point\n[ ] D - /resume, since it starts a new context','\n',char(10)),'B - /compact, since it summarizes the history preserving the learning','["Domain_3::Claude_Code_Configuration_Workflows", "Domain_5::Context_Management_Reliability", "Scenario_2::Code_Generation_Claude_Code"]','New',0,2.5,0,1783092986941,1783727198126,1783203558653,replace('**Tradução para português do Brasil:**\n\nVocê vai continuar uma tarefa relacionada e quer preservar o que Claude aprendeu. Qual comando?\n\n[ ] A - /clear, pois limpa o contexto\n[ ] B - /compact, pois resume o histórico preservando o aprendizado\n[ ] C - /rewind, pois volta a um ponto anterior\n[ ] D - /resume, pois inicia um novo contexto','\n',char(10)),replace('**Explicação didática para um adulto tech lead:**\n\nA pergunta trata de comandos de gerenciamento de contexto em conversas com o Claude. Quando você está no meio de uma conversa longa e deseja continuar uma tarefa relacionada sem perder o que já foi discutido e aprendido, o comando correto é **/compact**.\n\n- **Alternativa B (correta):** `/compact` comprime e resume o histórico da conversa, mantendo as informações essenciais e o "aprendizado" acumulado (instruções, preferências, decisões tomadas). É ideal para tarefas longas que ultrapassam o limite de tokens do contexto, pois reduz o tamanho sem perder o conteúdo relevante.\n\n- **Alternativa A (incorreta):** `/clear` limpa todo o contexto, zerando a conversa. Isso seria útil para iniciar uma tarefa completamente diferente, mas destrói todo o histórico de aprendizado, exatamente o oposto do que se deseja.\n\n- **Alternativa C (incorreta):** `/rewind` retorna a conversa para um ponto anterior específico. Embora preserve parte do histórico, ele descarta tudo que foi discutido após aquele ponto, podendo perder aprendizado recente.\n\n- **Alternativa D (incorreta):** `/resume` não é um comando padrão para iniciar um novo contexto com preservação. Na verdade, algumas implementações de /resume simplesmente continuam a conversa atual sem compactação, não resolvendo o problema de limites de tokens, ou iniciam um novo contexto sem o histórico.','\n',char(10)),replace('Imagine que você está conversando com um amigo muito inteligente (o Claude) sobre um trabalho escolar. Vocês já falaram bastante e ele já aprendeu o que você precisa. Agora você quer continuar a conversa, mas sem começar do zero.\n\n- Usar **/compact** (resposta certa) é como fazer um resumo de tudo que vocês falaram até agora, guardando as partes importantes. Assim, o amigo não esquece nada e vocês podem continuar de onde pararam.\n\n- Usar **/clear** é como apertar um botão de apagar tudo e começar a conversa do início. O amigo esqueceria tudo!\n\n- Usar **/rewind** é como voltar no tempo para um ponto anterior da conversa. Você perde tudo que foi dito depois daquele ponto.\n\n- Usar **/resume** é como simplesmente continuar falando sem fazer resumo, o que pode fazer a conversa ficar muito longa e confusa.\n\nEntão, a melhor opção é o **/compact**, pois ele faz um resumo esperto e guarda o que foi aprendido!','\n',char(10)));
INSERT INTO cards VALUES('admin','card_1783092986956_nc9s1r9wp',255,'After running /clear, is it still possible to return to the previous conversation?',replace('After running /clear, is it still possible to return to the previous conversation?\n\nAfter running /clear, is it still possible to return to the previous conversation?\n[Resposta correta: /clear não remove a conversa do histórico da sessão, então é possível voltar com /resume. A A é falsa; /rewind não é o comando para retomar após /clear; a D inventa uma pré-condição.]\n\n[ ] A - No, /clear deletes the conversation permanently\n[ ] B - Yes, /clear does not remove it from the session history; use /resume\n[ ] C - Yes, but only with /rewind\n[ ] D - Only if you have run /compact beforehand','\n',char(10)),'[ ] B - Yes, /clear does not remove it from the session history; use /resume','["Domain_3::Claude_Code_Configuration_Workflows", "Scenario_2::Code_Generation_Claude_Code"]','New',0,2.5,0,1783092986956,1783727201046,1783203558653,replace('**Tradução para português do Brasil:**\n\nPergunta: Após executar /clear, ainda é possível retornar à conversa anterior?\n\nAlternativas:\n[ ] A - Não, /clear deleta a conversa permanentemente\n[ ] B - Sim, /clear não remove a conversa do histórico da sessão; use /resume\n[ ] C - Sim, mas apenas com /rewind\n[ ] D - Apenas se você tiver executado /compact antes','\n',char(10)),replace('**Explicação para um adulto tech lead:**\n\nA pergunta aborda o comportamento do comando `/clear` em um terminal interativo de IA (como o ChatGPT ou Claude). O comando `/clear` tem a função de limpar a tela do terminal e/ou reiniciar o contexto atual da conversa, mas ele **não exclui o histórico da sessão** de forma permanente. O histórico da conversa ainda está armazenado na sessão e pode ser acessado novamente.\n\n- **Alternativa B (correta):** Afirma que `/clear` não remove a conversa do histórico da sessão e que é possível retornar com `/resume`. Isso está correto porque `/clear` apenas limpa a visualização atual ou reinicia o contexto, mas o histórico permanece disponível na sessão. O comando `/resume` é justamente o mecanismo para restaurar a conversa anterior.\n\n- **Alternativa A (incorreta):** Diz que `/clear` deleta a conversa permanentemente. Isso é falso — `/clear` não é um comando de exclusão definitiva; ele apenas limpa o estado atual da interação.\n\n- **Alternativa C (incorreta):** Afirma que é possível retornar com `/rewind`. `/rewind` é um comando que retrocede a conversa para um ponto anterior, mas não é o comando apropriado para retomar após um `/clear`. O `/rewind` teria utilidade se você quisesse voltar a um estado específico dentro do histórico, mas o comando previsto para restaurar após `/clear` é `/resume`.\n\n- **Alternativa D (incorreta):** Inventa uma pré-condição de que seria necessário executar `/compact` antes. `/compact` é um comando que geralmente otimiza o armazenamento ou reduz o tamanho do histórico, mas não é um pré-requisito para que `/clear` permita o retorno. A afirmação é falsa e não corresponde ao comportamento real dos comandos.','\n',char(10)),replace('Imagine que você está brincando com um amigo e, de repente, você apaga o que estava escrito no quadro branco com um apagador. O desenho sumiu da vista, mas a sua conversa ainda está guardada na memória do computador. Se você quiser ver de novo o que foi dito antes, é só usar o comando `/resume` — que é como "continuar" ou "voltar a mostrar".\n\nA alternativa B está certa porque ela diz exatamente isso: o `/clear` só limpa a tela, mas não apaga a conversa para sempre. Dá para voltar com `/resume`.\n\nAs outras alternativas estão erradas:\n- A: diz que apaga para sempre — não é verdade, o apagador só limpou o quadro, não destruiu a conversa.\n- C: diz que dá para voltar com `/rewind` — mas `/rewind` é outro comando, que serve para voltar no tempo na conversa, não para trazer de volta depois do `/clear`.\n- D: diz que só funciona se você tiver feito `/compact` antes — isso é invenção, não precisa fazer nada antes.','\n',char(10)));
INSERT INTO cards VALUES('admin','card_1783092986972_efmxoz9af',256,'Claude started tackling several things at once.',replace('Claude started tackling several things at once.\n\nClaude started tackling several things at once. How do you interrupt it and redirect?\n[Resposta correta: Escape interrompe a resposta em andamento para reorientar a uma tarefa específica. /clear perderia o contexto; fechar o terminal é drástico; --batch não existe.]\n\n[ ] A - Run /clear to wipe everything\n[ ] B - Press Escape to interrupt mid-response and redirect\n[ ] C - Close the terminal and reopen it\n[ ] D - Use --batch to force focus','\n',char(10)),'[ ] B - Press Escape to interrupt mid-response and redirect','["Domain_3::Claude_Code_Configuration_Workflows", "Scenario_2::Code_Generation_Claude_Code"]','New',0,2.5,0,1783092986972,1783727204105,1783203558653,replace('**Tradução para português do Brasil:**\n\n**Pergunta:** Claude começou a lidar com várias coisas ao mesmo tempo. Como você o interrompe e redireciona?\n\n**Alternativas:**\n[ ] A - Execute /clear para limpar tudo\n[ ] B - Pressione Escape para interromper a resposta em andamento e redirecionar\n[ ] C - Feche o terminal e reabra-o\n[ ] D - Use --batch para forçar o foco','\n',char(10)),replace('**Explicação para um adulto tech lead:**\n\nA alternativa correta é a **B**.\n\n**Por que a B está correta:**\nA tecla **Escape** (Esc) é o mecanismo padrão no Claude (e em muitos terminais interativos) para interromper uma resposta que está sendo gerada. Quando Claude começa a "fazer várias coisas ao mesmo tempo" — ou seja, gerar uma resposta longa ou que não está alinhada com o que você deseja — pressionar Escape interrompe a geração no meio do fluxo. Isso permite que você redirecione o modelo com um novo comando ou instrução mais específica, sem perder o histórico da conversa. É uma operação não destrutiva e de baixo custo.\n\n**Por que as demais estão erradas:**\n\n- **A - `/clear`**: O comando `/clear` (ou similar) geralmente limpa todo o buffer da tela ou reinicia o contexto da conversa. Isso é excessivo: você perderia todo o histórico da conversa, o que pode ser indesejado. O problema é que Claude está fazendo várias coisas, não que o contexto esteja poluído. Usar `/clear` joga fora o bebê junto com a água do banho.\n\n- **C - Fechar o terminal**: Essa é uma ação drástica que encerra completamente a sessão. Você perderia todo o estado da conversa, variáveis, histórico e precisaria recomeçar do zero. É como desligar o computador porque um programa travou — resolúvel, mas totalmente desproporcional.\n\n- **D - `--batch`**: Essa flag não existe no contexto de interação com Claude. `--batch` geralmente se refere a modos de execução não interativa em sistemas de fila (ex: SLURM) ou processamento em lote. Não é um mecanismo para interromper e redirecionar uma resposta em andamento. É um comando fantasma aqui.','\n',char(10)),replace('**Explicação para uma criança de 10 anos:**\n\nImagine que você pediu para o Claude fazer várias tarefas ao mesmo tempo, e ele começou a fazer tudo junto, meio bagunçado. Você quer parar ele e pedir para fazer uma coisa de cada vez.\n\nA melhor maneira de fazer isso é **pressionar a tecla Escape (Esc)**. É como dar um tapinha no ombro de alguém e dizer "Ei, pausa aí, quero te explicar de novo o que fazer". A pessoa para de falar, te escuta, e você pode falar de novo o que quer.\n\nAs outras opções são ruins porque:\n\n- **A - `/clear`** é como pegar uma borracha gigante e apagar tudo o que você já conversou — você perde o que já foi dito e precisa começar do zero. Não precisa disso!\n- **C - Fechar o terminal** é como desligar o videogame do nada só porque o jogo travou um pouquinho. Você perde tudo que não salvou.\n- **D - `--batch`** é uma palavra inventada que não serve para isso. É como tentar usar um controle de TV para ligar o micro-ondas — não funciona.\n\nEntão, lembre-se: **Escape** é o botão mágico para pausar e redirecionar o Claude!','\n',char(10)));
INSERT INTO cards VALUES('admin','card_1783092986988_kptvdxtje',257,'Claude repeats the same mistake across conversations.',replace('Claude repeats the same mistake across conversations.\n\nClaude repeats the same mistake across conversations. Which sequence fixes it permanently?\n[Resposta correta: Parar com Escape e registrar a abordagem correta no CLAUDE.md (via /memory) evita o erro nas próximas conversas. /clear não persiste a correção; PostToolUse não bloqueia; aumentar effort não trata o erro recorrente.]\n\n[ ] A - /clear on each conversation to restart\n[ ] B - Escape to stop, /memory (or edit CLAUDE.md) to note the correct approach, and continue\n[ ] C - Create a PostToolUse hook that blocks the tool call\n[ ] D - Increase the effort level on all tasks','\n',char(10)),'B - Escape to stop, /memory (or edit CLAUDE.md) to note the correct approach, and continue','["Domain_3::Claude_Code_Configuration_Workflows", "Domain_5::Context_Management_Reliability", "Scenario_2::Code_Generation_Claude_Code"]','New',0,2.5,0,1783092986988,1783727207392,1783203558653,replace('**Tradução:**\n\nClaude repete o mesmo erro em conversas diferentes. Qual sequência corrige isso permanentemente?\n\n[ ] A - /clear em cada conversa para reiniciar\n[ ] B - Escape para parar, /memory (ou editar o CLAUDE.md) para anotar a abordagem correta, e continuar\n[ ] C - Criar um hook PostToolUse que bloqueie a chamada de ferramenta\n[ ] D - Aumentar o nível de esforço em todas as tarefas','\n',char(10)),replace('**Explicação para Adulto (Tech Lead):**\n\nO comportamento descrito é um problema de aprendizado inter-sessão: o erro que Claude comete não é corrigido automaticamente entre conversas. Para resolver isso de forma permanente, precisamos armazenar a lição aprendida em um local persistente que seja lido no início de cada nova conversa.\n\n- **Alternativa B (correta):** A sequência "Escape para parar" interrompe o erro atual, e o uso de `/memory` (ou edição do `CLAUDE.md`) salva a instrução correta de forma que será carregada como contexto em futuras conversas. Essa é a única abordagem que garante correção permanente.\n\n- **Alternativa A:** `/clear` apenas limpa o histórico da conversa atual, mas não adiciona nenhuma instrução correta para o futuro. O erro continuará ocorrendo em novas conversas.\n\n- **Alternativa C:** Um `PostToolUse hook` pode evitar que uma chamada específica aconteça novamente dentro da mesma conversa, mas não persiste o aprendizado entre conversas. Além disso, não ensina a abordagem correta, apenas bloqueia a ação errada.\n\n- **Alternativa D:** Aumentar o nível de esforço (`effort`) pode fazer o modelo pensar mais, mas não trata a causa raiz do erro recorrente. Não há garantia de que o erro não se repita, e a correção não é permanente.','\n',char(10)),replace('Imagina que você sempre erra a mesma questão de matemática em várias provas. Se você só apagar a prova (como o /clear), você vai errar de novo na próxima. Se você tentar pensar com mais força (aumentar o esforço), também não resolve, porque você continua sem saber o jeito certo.\n\nMas se você escrever a resposta certa num caderno que você sempre leva para as provas (como o /memory ou CLAUDE.md), aí sim, você vai lembrar e acertar sempre! É isso que a opção B faz: para o erro, anota a solução certa num lugar que nunca é esquecido.','\n',char(10)));
INSERT INTO cards VALUES('admin','card_1783092987003_gbq0mu1kp',258,'How is the name of a custom command created in .',replace('How is the name of a custom command created in .\n\nHow is the name of a custom command created in .claude/commands/ defined?\n[Resposta correta: O nome do arquivo markdown vira o comando (audit.md gera /audit), com detecção automática sem reiniciar. As demais inventam mecanismos que não são os descritos.]\n\n[ ] A - By the name field in the frontmatter, mandatory\n[ ] B - By the name of the markdown file (e.g. audit.md becomes /audit), detected automatically\n[ ] C - By the absolute path of the file\n[ ] D - By a manual registration via claude command add','\n',char(10)),'By the name of the markdown file (e.g. audit.md becomes /audit), detected automatically','["Domain_3::Claude_Code_Configuration_Workflows", "Scenario_2::Code_Generation_Claude_Code"]','New',0,2.5,0,1783092987003,1783727210405,1783203558653,replace('**Tradução da pergunta e alternativas para Português do Brasil:**\n\n**Pergunta:** Como é definido o nome de um comando personalizado criado em .claude/commands/?\n\n[ ] A - Pelo campo "name" no frontmatter, obrigatório\n[ ] B - Pelo nome do arquivo markdown (ex: audit.md se torna /audit), detectado automaticamente\n[ ] C - Pelo caminho absoluto do arquivo\n[ ] D - Por um registro manual via comando "claude command add"','\n',char(10)),replace('**Explicação didática para um adulto tech lead:**\n\nA resposta correta é a alternativa B. No mecanismo de custom commands do Claude Code, a definição do nome do comando é baseada exclusivamente no nome do arquivo markdown dentro do diretório `.claude/commands/`. O sistema faz uma detecção automática e dinâmica: ao criar o arquivo `audit.md`, o comando `/audit` fica imediatamente disponível, sem necessidade de reinicialização do ambiente.\n\n**Por que as demais alternativas estão incorretas:**\n\n- **Alternativa A** (campo "name" no frontmatter): Isso não é um requisito. O frontmatter é utilizado para outras metainformações (como descrição), mas o nome do comando é derivado do nome do arquivo, não de um campo interno. O campo "name" não é obrigatório nem determinante para o nome do comando.\n\n- **Alternativa C** (caminho absoluto do arquivo): O sistema não utiliza o caminho absoluto. O que importa é apenas o nome base do arquivo (sem extensão) dentro do diretório `.claude/commands/`. Caminhos absolutos não são relevantes para a definição do comando.\n\n- **Alternativa D** (registro manual via "claude command add"): Não existe esse mecanismo de registro manual. O sistema é baseado em convenção de arquivos: basta criar o arquivo markdown no local correto, e o comando é automaticamente reconhecido.','\n',char(10)),replace('Imagine que você tem uma pasta mágica chamada `.claude/commands/`. Dentro dela, você pode criar arquivos de texto (chamados markdown) com as coisas que você quer ensinar o Claude a fazer.\n\nO nome do comando é o nome do arquivo! Por exemplo, se você criar um arquivo chamado `audit.md`, o comando vai se chamar `/audit`. É como se o arquivo dissesse: "Meu nome é audit, então me chame de /audit!"\n\nO legal é que funciona na hora — você não precisa reiniciar nada nem fazer um cadastro especial. É só criar o arquivo e pronto, o comando já aparece.\n\nAs outras opções estão erradas porque:\n- A opção A diz que você precisa escrever o nome dentro do arquivo, mas não precisa — o nome já está no título do arquivo.\n- A opção C diz que usa o caminho completo (tipo aquele endereço enorme do computador), mas não é assim.\n- A opção D diz que você precisa registrar num lugar especial, mas é só criar o arquivo que já funciona!','\n',char(10)));
INSERT INTO cards VALUES('admin','card_1783092987019_xksrbww5k',259,'How does a custom command receive dynamic parameters?',replace('How does a custom command receive dynamic parameters?\n\nHow does a custom command receive dynamic parameters?\n[Resposta correta: O placeholder $ARGUMENTS é substituído pelo que se passa após o comando. Não há campo params descrito, nem variável CLAUDE_ARGS; e passar parâmetros é possível.]\n\n[ ] A - By a params field in the frontmatter\n[ ] B - By the $ARGUMENTS placeholder in the markdown, replaced by whatever comes after the command\n[ ] C - By the CLAUDE_ARGS environment variable\n[ ] D - It is not possible to pass parameters to commands','\n',char(10)),'B - By the $ARGUMENTS placeholder in the markdown, replaced by whatever comes after the command','["Domain_3::Claude_Code_Configuration_Workflows", "Scenario_2::Code_Generation_Claude_Code"]','New',0,2.5,0,1783092987019,1783727213421,1783203558653,replace('**Tradução para português do Brasil:**\n\n**Pergunta:** Como um comando personalizado recebe parâmetros dinâmicos?\n\n[ ] A - Por um campo params no frontmatter\n[ ] B - Pelo placeholder $ARGUMENTS no markdown, substituído pelo que vier após o comando\n[ ] C - Pela variável de ambiente CLAUDE_ARGS\n[ ] D - Não é possível passar parâmetros para comandos','\n',char(10)),replace('**Explicação para um adulto (tech lead):**\n\nA alternativa **B** está correta. Em sistemas como o Claude Code e outras ferramentas de linha de comando que suportam comandos personalizados (custom commands), o mecanismo padrão para receber parâmetros dinâmicos é através do placeholder **$ARGUMENTS**. Quando você define um comando personalizado em um arquivo de configuração (ex.: `~/.claude/commands.md`) e invoca algo como `/meu-comando algum texto aqui`, o literal `$ARGUMENTS` no conteúdo do markdown é substituído em tempo de execução pela string "algum texto aqui".\n\n**Análise das alternativas incorretas:**\n\n- **A (params field no frontmatter):** Incorreta. Não existe um campo `params` no frontmatter para esse propósito. O frontmatter (metadados YAML/TOML) de um arquivo de comando normalmente define apenas metadados como descrição, nome do comando etc., não a recepção de parâmetros dinâmicos.\n\n- **C (variável de ambiente CLAUDE_ARGS):** Incorreta. Não há uma variável de ambiente chamada `CLAUDE_ARGS` definida para esse fim em implementações conhecidas (Claude Code, por exemplo). O mecanismo de substituição é baseado em placeholder textual, não em variável de ambiente.\n\n- **D (não é possível passar parâmetros):** Incorreta. É perfeitamente possível e esse é justamente o propósito do `$ARGUMENTS` — permitir que comandos personalizados recebam argumentos variáveis do usuário.\n\nA alternativa correta (B) descreve com precisão o comportamento observado: o placeholder `$ARGUMENTS` funciona como um "coringa" que captura todo o texto digitado após o nome do comando.','\n',char(10)),replace('Imagine que você tem um robô que obedece comandos. Você ensina ele um comando especial tipo "/desenhar". Quando você fala "/desenhar um gato", o robô precisa saber o que desenhar.\n\nO segredo é um espaço reservado chamado **$ARGUMENTS**. Quando você programa o robô, você escreve algo como "Vou desenhar $ARGUMENTS". Aí, quando você digita "/desenhar um gato", o robô automaticamente troca $ARGUMENTS por "um gato" e fica "Vou desenhar um gato".\n\nAs outras opções estão erradas porque:\n- A (campo params) — não existe essa opção nos comandos.\n- C (variável CLAUDE_ARGS) — também não existe essa variável secreta.\n- D (não pode passar parâmetros) — isso é mentira, pois o $ARGUMENTS existe justamente pra isso!\n\nEntão a resposta certa é a **B**: o $ARGUMENTS é um lugar vago que vira o que você digitar depois do comando.','\n',char(10)));
INSERT INTO cards VALUES('admin','card_1783092987034_dtgl5pp93',260,'You want to standardize a repetitive workflow (e.',replace('You want to standardize a repetitive workflow (e.\n\nYou want to standardize a repetitive workflow (e.g. running tests with the team''s conventions) into a single command. Which feature?\n[Resposta correta: Custom commands padronizam o workflow, dando automação, consistência e flexibilidade via $ARGUMENTS. Hook é event-driven; regra por glob é para convenções por caminho; CLAUDE.md é contexto, não comando.]\n\n[ ] A - A PreToolUse hook\n[ ] B - Custom commands (.claude/commands/*.md), with $ARGUMENTS for flexibility\n[ ] C - A rule in .claude/rules/ with glob\n[ ] D - An entry in ~/.claude/CLAUDE.md','\n',char(10)),'B - Custom commands (.claude/commands/*.md), with $ARGUMENTS for flexibility','["Domain_3::Claude_Code_Configuration_Workflows", "Scenario_2::Code_Generation_Claude_Code"]','New',0,2.5,0,1783092987034,1783727216718,1783203558653,replace('**Tradução:**\n\nVocê quer padronizar um workflow repetitivo (ex.: executar testes seguindo as convenções do time) em um único comando. Qual funcionalidade?\n\n[ ] A - Um hook PreToolUse\n[ ] B - Custom commands (.claude/commands/*.md), com $ARGUMENTS para flexibilidade\n[ ] C - Uma regra em .claude/rules/ com glob\n[ ] D - Uma entrada em ~/.claude/CLAUDE.md','\n',char(10)),replace('**Explicação para adulto tech lead:**\n\nA pergunta aborda a necessidade de encapsular um workflow repetitivo — como rodar testes com convenções específicas do time — em um único comando padronizado. A resposta correta é a **alternativa B**.\n\n**Por que a B está correta:**\nCustom commands (definidos em `.claude/commands/*.md`) são exatamente o mecanismo projetado para isso. Eles permitem criar atalhos com scripts documentados que podem ser invocados com um único comando (ex.: `/test`). O uso de `$ARGUMENTS` aumenta a flexibilidade, permitindo passar parâmetros dinâmicos. Isso garante automação, consistência e reusabilidade — exatamente o que se busca ao padronizar um workflow.\n\n**Por que as demais estão erradas:**\n\n- **A (PreToolUse hook):** Hooks como `PreToolUse` são orientados a eventos (executam ações antes de uma ferramenta ser usada), não servem para definir comandos invocáveis diretamente pelo usuário. Eles são reativos, não proativos.\n\n- **C (Regra em .claude/rules/ com glob):** Regras com glob são usadas para aplicar convenções ou validações automáticas com base no caminho dos arquivos (ex.: "para todo arquivo `.test.js`, execute X"). Não são um mecanismo para criar comandos executáveis sob demanda.\n\n- **D (Entrada em ~/.claude/CLAUDE.md):** CLAUDE.md é um arquivo de contexto global que fornece instruções de fundo para o modelo. Ele não define comandos executáveis — é apenas informativo.','\n',char(10)),'Imagine que você tem uma tarefa chata que precisa fazer várias vezes, como arrumar seu quarto do mesmo jeito toda semana. Se você pudesse ter um botão mágico que, quando apertado, já arruma tudo certinho para você, não seria legal? É exatamente isso que os **Custom Commands** fazem: eles são como botões mágicos que você cria para fazer um monte de coisas de uma vez só, seguindo sempre o mesmo jeito certo. As outras opções são diferentes: uma é como um alarme que toca antes de você fazer algo (hook), outra é como uma regra que vale só para certos tipos de brinquedo (regra com glob), e a última é como um bilhete colado na parede lembrando o que fazer (CLAUDE.md) — nenhuma delas é o "botão mágico" que executa tudo de uma vez.');
INSERT INTO cards VALUES('admin','card_1783092987075_fsz5hoxkh',261,'Where does Claude run in the official GitHub integration and which workflows does it offer?',replace('Where does Claude run in the official GitHub integration and which workflows does it offer?\n\nWhere does Claude run in the official GitHub integration and which workflows does it offer?\n[Resposta correta: A integração roda o Claude dentro do GitHub Actions, com dois workflows: menções (@claude) e revisão automática de PRs. As demais erram o local de execução ou limitam os workflows.]\n\n[ ] A - It runs in your local terminal; it offers only PR review\n[ ] B - It runs inside GitHub Actions; it offers mentions (@claude) and automatic PR review\n[ ] C - It runs in a dedicated MCP server; it offers only mentions\n[ ] D - It runs in an isolated subagent; it offers only automatic commits','\n',char(10)),'B - It runs inside GitHub Actions; it offers mentions (@claude) and automatic PR review','["Domain_3::Claude_Code_Configuration_Workflows", "Domain_4::Prompt_Engineering_Structured_Output", "Scenario_5::Claude_Code_CI_CD"]','New',0,2.5,0,1783092987075,1783727219766,1783203558653,replace('**Tradução para Português (Brasil):**\n\nOnde o Claude é executado na integração oficial do GitHub e quais fluxos de trabalho ele oferece?\n\n[ ] A - Ele é executado no seu terminal local; oferece apenas revisão de PR\n[ ] B - Ele é executado dentro do GitHub Actions; oferece menções (@claude) e revisão automática de PR\n[ ] C - Ele é executado em um servidor MCP dedicado; oferece apenas menções\n[ ] D - Ele é executado em um subagente isolado; oferece apenas commits automáticos','\n',char(10)),replace('**Explicação para um adulto tech lead:**\n\nA alternativa correta é a **B**.\n\n**Por que a B está correta:**\nA integração oficial do Claude com GitHub roda como uma **GitHub Action**, ou seja, dentro da infraestrutura de CI/CD do GitHub. Isso significa que não há necessidade de configurar servidores externos ou rodar nada localmente. Os dois workflows oferecidos são:\n1. **Menções (@claude)** — você pode mencionar @claude em issues, pull requests ou comentários para invocar o Claude diretamente no contexto da conversa.\n2. **Revisão automática de PRs** — o Claude pode revisar pull requests automaticamente, postando comentários e sugestões.\n\n**Análise das alternativas incorretas:**\n\n- **A:** "Executa no terminal local" — incorreto. A integração oficial não requer execução local; ela roda inteiramente na nuvem via GitHub Actions. Além disso, limita os workflows a apenas "PR review", ignorando as menções (@claude).\n  \n- **C:** "Executa em um servidor MCP dedicado" — incorreto. MCP (Model Context Protocol) é um protocolo para integração de ferramentas, mas a integração oficial do GitHub não roda em um servidor MCP dedicado; ela usa GitHub Actions. Também limita erroneamente os workflows a apenas "menções".\n  \n- **D:** "Executa em um subagente isolado" — incorreto. Não há conceito de "subagente isolado" na arquitetura oficial da integração. Também inventa um workflow de "commits automáticos" que não faz parte da integração oficial.\n\nPortanto, a B descreve corretamente tanto o local de execução (GitHub Actions) quanto os dois workflows disponíveis.','\n',char(10)),replace('**Explicação para uma criança de 10 anos:**\n\nImagine que o Claude é um robô ajudante que trabalha no GitHub (um lugar onde as pessoas escrevem códigos juntos).\n\nA pergunta quer saber: **onde esse robô fica quando ele trabalha** e **quais tarefas ele pode fazer**.\n\nA resposta certa é a **B**: o robô fica dentro do **GitHub Actions** (que é como se fosse uma "salinha de servidores" do GitHub, não no seu computador). E ele faz duas coisas:\n1. Responde quando alguém escreve **@claude** (como se você chamasse o robô pelo nome).\n2. **Revisa pull requests** (que são como "sugestões de mudança" no código) automaticamente.\n\nAs outras respostas estão erradas porque dizem que o robô fica no seu computador, ou num servidor especial, ou num "subagente" — coisas que não existem nessa integração. E algumas delas também falam que ele só faz uma tarefa, quando na verdade ele faz duas!','\n',char(10)));
INSERT INTO cards VALUES('admin','card_1783092987091_yx5l8iwq5',262,'Which command installs the GitHub integration and what does the setup produce?',replace('Which command installs the GitHub integration and what does the setup produce?\n\nWhich command installs the GitHub integration and what does the setup produce?\n[Resposta correta: /install-github-app instala o app, adiciona a API key e abre um PR com os workflows (que vão para .github/workflows após o merge). As demais confundem com registro de MCP, /init ou inventam a flag --batch.]\n\n[ ] A - claude mcp add github; it generates an MCP server\n[ ] B - /install-github-app; it installs the app, adds the API key and generates a PR with the workflow files\n[ ] C - /init; it generates a CLAUDE.md with the credentials\n[ ] D - claude github --batch; it pushes the workflows straight to main','\n',char(10)),'B - /install-github-app; it installs the app, adds the API key and generates a PR with the workflow files','["Domain_3::Claude_Code_Configuration_Workflows", "Domain_4::Prompt_Engineering_Structured_Output", "Scenario_5::Claude_Code_CI_CD"]','New',0,2.5,0,1783092987091,1783727222848,1783203558653,replace('**Tradução para Português (Brasil):**\n\nQual comando instala a integração com o GitHub e o que a configuração produz?\n\n[ ] A - claude mcp add github; ele gera um servidor MCP\n[ ] B - /install-github-app; ele instala o app, adiciona a chave de API e gera um PR com os arquivos de workflow\n[ ] C - /init; ele gera um CLAUDE.md com as credenciais\n[ ] D - claude github --batch; ele envia os workflows diretamente para a branch main','\n',char(10)),replace('**Explicação Técnica para Tech Lead:**\n\nA pergunta aborda o fluxo de setup da integração nativa entre o Claude (especificamente no ambiente do Claude Code ou ferramenta similar) e o GitHub. Vamos analisar cada alternativa:\n\n- **Alternativa B (Correta):** O comando `/install-github-app` é o mecanismo oficial para realizar o setup da integração. Ele orquestra três ações distintas: (a) instala o GitHub App no repositório ou organização alvo, (b) adiciona a API key necessária para autenticação, e (c) gera um Pull Request contendo os arquivos de workflow (geralmente YAML em `.github/workflows/`). Esses arquivos só são efetivados no repositório após o merge do PR, o que é importante para dar visibilidade e controle ao time antes da ativação dos workflows. Esse fluxo é análogo a práticas de Infrastructure as Code (IaC), onde alterações passam por revisão antes de serem aplicadas.\n\n- **Alternativa A (Incorreta):** `claude mcp add github` sugere o uso do Model Context Protocol (MCP) para adicionar uma ferramenta GitHub. MCP é um protocolo para conectar LLMs a fontes externas de dados e ferramentas, mas não é o comando de instalação da integração nativa do GitHub. Além disso, o resultado descrito ("gera um servidor MCP") não corresponde ao que a pergunta busca — a pergunta quer saber qual comando **instala a integração** e o que é **produzido** (que são os workflows, não um servidor MCP). Essa alternativa confunde dois conceitos diferentes: registro de ferramentas MCP versus instalação da integração nativa.\n\n- **Alternativa C (Incorreta):** `/init` é um comando comum em diversos contextos (como inicializar um projeto ou configurar o ambiente), mas não é o comando para instalar a integração com GitHub. A descrição "gera um CLAUDE.md com as credenciais" também não condiz com o resultado esperado da instalação — o CLAUDE.md pode ser gerado para configuração do agente, mas não é o artefato principal da integração com GitHub. As credenciais são armazenadas de forma segura, e não em um arquivo Markdown versionado.\n\n- **Alternativa D (Incorreta):** `claude github --batch` é uma invocação inventada. Não existe esse comando na interface padrão. A flag `--batch` geralmente é usada em outras ferramentas para processamento em lote, mas não aqui. A ação descrita ("envia os workflows diretamente para main") viola boas práticas de engenharia de software, pois bypassa o fluxo de revisão via Pull Request. Mesmo que fosse possível, não é o comportamento esperado, pois a pergunta deixa claro no gabarito que a abordagem correta é via PR.','\n',char(10)),replace('Imagine que você quer conectar seu robô Claude ao GitHub (que é como um caderno gigante de código na nuvem). Para isso, você precisa usar um comando mágico especial.\n\nA alternativa **B** — `/install-github-app` — é a correta porque funciona assim: você chama esse comando e ele (1) instala um aplicativo especial que liga o Claude ao GitHub, (2) guarda uma chave secreta (API key) para que eles possam conversar, e (3) cria uma sugestão de mudança (Pull Request) com uns arquivos de instrução (workflows) dentro da pasta `.github/workflows`. Esses arquivos só entram em ação depois que alguém do time aprovar e mesclar a sugestão. É como pedir permissão antes de fazer algo importante.\n\nAs outras alternativas estão erradas:\n- **A** fala de um tal de "MCP server", que é outra coisa — não tem nada a ver com instalar a integração do GitHub.\n- **C** sugere o comando `/init`, que não faz essa conexão. Ele também fala de criar um arquivo `CLAUDE.md` com credenciais, o que não é seguro nem correto.\n- **D** inventa um comando `claude github --batch` que nem existe. Além disso, jogar arquivos direto na branch principal sem revisão é bagunçado — a gente sempre pede opinião do time antes, igual fazer um dever de casa e mostrar para os colegas antes de entregar.','\n',char(10)));
INSERT INTO cards VALUES('admin','card_1783092987108_l9ko831sb',263,'What does the Mention Action do when it receives @claude in an issue or PR?',replace('What does the Mention Action do when it receives @claude in an issue or PR?\n\nWhat does the Mention Action do when it receives @claude in an issue or PR?\n[Resposta correta: A Mention Action analisa, planeja, executa com acesso total ao codebase e responde diretamente na issue/PR. As demais descrevem ações que não correspondem ao comportamento da menção.]\n\n[ ] A - It just adds a label to the issue\n[ ] B - It analyzes the request, creates a plan, executes it with codebase access and replies on the issue/PR itself\n[ ] C - It opens a local chat in the terminal of the mention''s author\n[ ] D - It blocks the merge until human review','\n',char(10)),'B - It analyzes the request, creates a plan, executes it with codebase access and replies on the issue/PR itself','["Domain_3::Claude_Code_Configuration_Workflows", "Scenario_5::Claude_Code_CI_CD"]','New',0,2.5,0,1783092987108,1783727226102,1783203558653,replace('**Tradução para português do Brasil:**\n\n**Pergunta:** O que a Mention Action faz quando recebe @claude em uma issue ou PR?\n\n[ ] A - Apenas adiciona um label à issue\n[ ] B - Analisa a solicitação, cria um plano, executa com acesso ao codebase e responde na própria issue/PR\n[ ] C - Abre um chat local no terminal do autor da menção\n[ ] D - Bloqueia o merge até revisão humana','\n',char(10)),replace('**Explicação didática para adulto tech lead:**\n\nA **Mention Action** é um mecanismo de automação que reage quando alguém menciona `@claude` em uma issue ou Pull Request. A alternativa **B** descreve corretamente o comportamento esperado:\n\n- **Análise da solicitação**: O sistema interpreta o conteúdo da menção no contexto da issue/PR.\n- **Criação de um plano**: Com base na análise, ele estrutura uma sequência de ações a serem executadas.\n- **Execução com acesso ao codebase**: O agente tem permissão para ler, modificar arquivos e interagir com o repositório como um colaborador.\n- **Resposta na própria issue/PR**: O resultado da execução é postado como comentário diretamente no mesmo fórum (issue ou PR), garantindo visibilidade e rastreabilidade.\n\n**Por que as demais estão erradas:**\n\n- **A** – Reduz o escopo a uma mera etiquetagem, ignorando toda a capacidade de análise e execução.\n- **C** – Sugere abertura de chat local no terminal, o que é inviável e sem sentido no contexto de automação em plataformas como GitHub.\n- **D** – Menciona bloqueio de merge, que não é uma ação típica de mention action; o foco é responder e executar, não impedir fluxos.','\n',char(10)),replace('**Explicação para uma criança de 10 anos:**\n\nImagine que você tem um amigo robô chamado Claude. Quando você escreve "@claude" em uma mensagem no seu projeto (em uma tarefa ou sugestão de mudança), o robô lê o que você pediu, pensa em como fazer, usa o computador para mexer nos arquivos do projeto e depois responde pra você na mesma conversa. É como se ele fosse um ajudante que entende o problema, trabalha na solução e volta pra te contar o que fez.\n\nAs outras opções não são corretas:\n- A (só colocar uma etiqueta) — seria como se o robô apenas pendurasse um aviso e não fizesse mais nada.\n- C (abrir um chat no terminal de quem chamou) — não faz sentido, o robô não vai abrir um joguinho escondido no seu computador.\n- D (impedir a fusão até um humano revisar) — o robô não trava o projeto, ele só ajuda.','\n',char(10)));
INSERT INTO cards VALUES('admin','card_1783092987125_ma64k1nma',264,'How do you tell Claude, in GitHub Actions, that the server is already running and how to query the database?',replace('How do you tell Claude, in GitHub Actions, that the server is already running and how to query the database?\n\nHow do you tell Claude, in GitHub Actions, that the server is already running and how to query the database?\n[Resposta correta: O campo custom_instructions do workflow transmite o contexto de ambiente (URL do server, logs, ferramentas). CLAUDE.md não é o canal para instruir o Actions; CLAUDE_HEADLESS não existe; hook não é o mecanismo descrito.]\n\n[ ] A - By writing in the repository''s CLAUDE.md\n[ ] B - By the workflow''s custom_instructions field, describing server, logs and how to access resources\n[ ] C - By an environment variable CLAUDE_HEADLESS\n[ ] D - By a SessionStart hook','\n',char(10)),'B - By the workflow''s custom_instructions field, describing server, logs and how to access resources','["Domain_3::Claude_Code_Configuration_Workflows", "Domain_4::Prompt_Engineering_Structured_Output", "Scenario_5::Claude_Code_CI_CD"]','New',0,2.5,0,1783092987125,1783727229655,1783203558653,replace('**Tradução para português do Brasil:**\n\nPergunta: Como você informa ao Claude, em GitHub Actions, que o servidor já está em execução e como consultar o banco de dados?\n\nAlternativas:\n\n[ ] A - Escrevendo no CLAUDE.md do repositório\n[ ] B - Pelo campo custom_instructions do workflow, descrevendo servidor, logs e como acessar recursos\n[ ] C - Por uma variável de ambiente CLAUDE_HEADLESS\n[ ] D - Por um hook SessionStart','\n',char(10)),replace('**Explicação para um adulto tech lead:**\n\nA pergunta trata de como, dentro de um fluxo de CI/CD no GitHub Actions, você comunica ao Claude (o assistente de IA integrado) informações contextuais importantes — como o fato de um servidor já estar rodando e como consultar o banco de dados.\n\nA alternativa correta é a **B**. O campo `custom_instructions` no workflow do GitHub Actions é o mecanismo oficial e documentado para transmitir instruções específicas de contexto para o Claude durante a execução de um job. É através dele que você pode descrever a URL do servidor em execução, onde encontrar logs, comandos para acessar o banco de dados, etc. Isso permite que o Claude entenda o estado atual do ambiente e ofereça respostas precisas e acionáveis.\n\nPor que as demais alternativas estão incorretas:\n\n- **A (CLAUDE.md):** O arquivo `CLAUDE.md` é utilizado para fornecer instruções de contexto *persistentes* e *globais* sobre o repositório, mas **não** é o canal para instruções dinâmicas de um workflow específico. Ele não tem conhecimento do estado de execução de uma pipeline em tempo real.\n\n- **C (CLAUDE_HEADLESS):** Esta variável de ambiente simplesmente **não existe** na documentação oficial do Claude ou do GitHub Actions. É uma alternativa fictícia.\n\n- **D (SessionStart hook):** Embora hooks de início de sessão possam existir em outras plataformas, não é esse o mecanismo padrão descrito para o GitHub Actions. O mecanismo correto e direto é o campo `custom_instructions` no próprio workflow YAML.','\n',char(10)),replace('Imagine que você está brincando de detetive com um amigo robô chamado Claude. Vocês estão em uma missão dentro de uma fábrica de robôs (o GitHub Actions). Para o Claude ajudar direito, você precisa contar para ele: "Ei, o servidor já está ligado ali na sala 5, e para ver o banco de dados é só apertar o botão azul".\n\nA melhor forma de fazer isso é escrever essas instruções em um "bilhete especial" que fica dentro do próprio passo da missão — esse bilhete é o campo **custom_instructions**. Assim, o Claude lê na hora e já sabe onde está o servidor e como mexer no banco de dados.\n\nSe você escrever no **CLAUDE.md**, é como colocar um aviso na parede do escritório principal — legal, mas o Claude não vai ler na hora da missão. A opção **CLAUDE_HEADLESS** nem existe, é como inventar um botão que não está no painel. E o **SessionStart hook** é algo de outro jogo, não se usa aqui.\n\nEntão, a resposta certa é a **B**: usar o campo custom_instructions do workflow.','\n',char(10)));
INSERT INTO cards VALUES('admin','card_1783092987142_sa1k94z4b',265,'How do you prepare dependencies and environment before the Claude step in GitHub Actions?',replace('How do you prepare dependencies and environment before the Claude step in GitHub Actions?\n\nHow do you prepare dependencies and environment before the Claude step in GitHub Actions?\n[Resposta correta: Steps de Project Setup no workflow (antes do step do Claude) preparam o ambiente. custom_instructions dá contexto, não executa setup; /init não roda no Actions; --batch não existe.]\n\n[ ] A - Add Project Setup steps in the workflow (e.g. npm run setup) before the Claude step\n[ ] B - Put the commands in the custom_instructions field\n[ ] C - Run /init on the repository\n[ ] D - Set the --batch flag on the job','\n',char(10)),'[ ] A - Adicionar etapas de configuração do projeto no workflow (ex.: npm run setup) antes da etapa do Claude','["Domain_3::Claude_Code_Configuration_Workflows", "Domain_4::Prompt_Engineering_Structured_Output", "Scenario_5::Claude_Code_CI_CD"]','New',0,2.5,0,1783092987142,1783727233508,1783203558653,replace('**Tradução:**\n\nPergunta: Como preparar as dependências e o ambiente antes da etapa do Claude em GitHub Actions?\n\n[Resposta correta: Steps de Project Setup no workflow (antes do step do Claude) preparam o ambiente. custom_instructions dá contexto, não executa setup; /init não roda no Actions; --batch não existe.]\n\n[ ] A - Adicionar etapas de configuração do projeto no workflow (ex.: npm run setup) antes da etapa do Claude\n[ ] B - Colocar os comandos no campo custom_instructions\n[ ] C - Executar /init no repositório\n[ ] D - Definir a flag --batch no job','\n',char(10)),replace('**Explicação para adulto (tech lead):**\n\nA resposta correta é a alternativa A. O GitHub Actions executa workflows compostos por steps sequenciais. Para preparar dependências e ambiente antes de qualquer step — incluindo um step que chama o Claude (via action como `@anthropic-ai/claude-code-action` ou similar) — você deve adicionar steps de *Project Setup* antes do step do Claude. Por exemplo, um step que roda `npm install`, `npm run setup`, ou outro comando de preparação.\n\nAs demais alternativas estão incorretas pelos seguintes motivos:\n\n- **B**: O campo `custom_instructions` é usado para fornecer contexto, instruções de comportamento ou diretrizes para o modelo Claude. Ele não executa comandos nem prepara o ambiente de execução. É um parâmetro de configuração do agente, não um mecanismo de setup.\n\n- **C**: O comando `/init` é um comando interativo do Claude Code (CLI) usado em sessões locais para inicializar um projeto. Ele não é executado automaticamente em GitHub Actions. Em Actions, você usa steps de shell ou actions prontas.\n\n- **D**: A flag `--batch` não existe no contexto do Claude Code ou GitHub Actions. Pode haver confusão com flags de modo não-interativo como `--no-interactive` ou `--non-interactive`, mas `--batch` não é uma flag válida. Além disso, flags não instalam dependências nem preparam ambiente.\n\nPortanto, a abordagem correta e padrão em CI/CD é usar steps de setup antes do step que invoca o Claude.','\n',char(10)),replace('Imagine que você vai fazer uma receita de bolo. Antes de começar a mexer, você precisa separar todos os ingredientes e preparar a tigela, a colher e o forno.\n\nNo GitHub Actions, é a mesma coisa: se você quer usar o Claude (um robô inteligente que ajuda a programar), primeiro você precisa "separar os ingredientes". Isso significa instalar as bibliotecas e ferramentas que o projeto precisa.\n\nAs alternativas erradas seriam:\n\nB) Colocar os comandos no "custom_instructions" — isso é como escrever uma carta para o Claude dizendo o que ele deve fazer, mas não prepara os ingredientes de verdade.\n\nC) Usar "/init" — é um comando que funciona no computador da gente, mas não funciona direito no GitHub Actions, que é um computador na nuvem.\n\nD) Usar "--batch" — essa opção nem existe de verdade! É como inventar um ingrediente falso.\n\nA resposta certa é a **A**: colocar etapas de "preparação do projeto" (como rodar `npm install` ou `npm run setup`) antes da etapa do Claude, exatamente como separar os ingredientes antes de começar a receita.','\n',char(10)));
INSERT INTO cards VALUES('admin','card_1783092987161_itex3zeg2',266,'Which is NOT a recommended best practice when configuring the GitHub integration?',replace('Which is NOT a recommended best practice when configuring the GitHub integration?\n\nWhich is NOT a recommended best practice when configuring the GitHub integration?\n[Resposta correta: Dar acesso irrestrito contraria a recomendação de ser explícito nas permissões. As demais (começar pelo default, ser explícito nas permissões, testar simples primeiro) são as boas práticas indicadas.]\n\n[ ] A - Start with the default workflows and customize gradually\n[ ] B - Be explicit about tool permissions, especially with MCP\n[ ] C - Grant unrestricted access to all tools at once to simplify\n[ ] D - Test with simple tasks before complex ones','\n',char(10)),'C - Grant unrestricted access to all tools at once to simplify','["Domain_3::Claude_Code_Configuration_Workflows", "Domain_4::Prompt_Engineering_Structured_Output", "Domain_2::Tool_Design_MCP_Integration", "Scenario_5::Claude_Code_CI_CD"]','New',0,2.5,0,1783092987161,1783727236850,1783203558653,replace('**Tradução para português do Brasil:**\n\n**Pergunta:** Qual NÃO é uma prática recomendada ao configurar a integração com o GitHub?\n\n[ ] A - Começar com os workflows padrão e personalizar gradualmente\n[ ] B - Ser explícito sobre as permissões das ferramentas, especialmente com MCP\n[ ] C - Conceder acesso irrestrito a todas as ferramentas de uma só vez para simplificar\n[ ] D - Testar com tarefas simples antes de passar para as complexas','\n',char(10)),replace('**Explicação didática para um adulto tech lead:**\n\nA pergunta pede para identificar qual alternativa **não** é uma prática recomendada. Vamos analisar cada uma:\n\n**Alternativa A (Começar com os workflows padrão e personalizar gradualmente):** Esta é uma prática sólida e amplamente recomendada em engenharia de software. Ao iniciar com workflows padrão, você reduz a complexidade inicial e evita configurações desnecessárias. A personalização gradual permite que você entenda o comportamento do sistema antes de modificá-lo, seguindo o princípio de "menos é mais" em configurações.\n\n**Alternativa B (Ser explícito sobre as permissões das ferramentas, especialmente com MCP):** Esta é uma prática recomendada e fundamental em segurança. O princípio do menor privilégio (principle of least privilege) dita que cada componente deve ter apenas as permissões necessárias para executar sua função. Ser explícito sobre permissões evita brechas de segurança, especialmente em contextos como MCP (Model Context Protocol), onde ferramentas podem ter acesso a dados sensíveis.\n\n**Alternativa C (Conceder acesso irrestrito a todas as ferramentas de uma só vez para simplificar):** Esta é a alternativa que **não** é uma prática recomendada. Conceder acesso irrestrito a todas as ferramentas de uma vez viola diretamente o princípio do menor privilégio. Embora pareça "simplificar" a configuração inicial, isso cria sérios riscos de segurança, como:\n- Exposição acidental de dados sensíveis\n- Possibilidade de ações maliciosas ou acidentais em repositórios\n- Dificuldade em auditar e rastrear o uso de ferramentas específicas\n- Quebra de conformidade com políticas de segurança organizacionais\n\n**Alternativa D (Testar com tarefas simples antes de passar para as complexas):** Esta é uma prática recomendada clássica em qualquer integração de sistemas. Testar com tarefas simples permite validar o funcionamento básico, identificar problemas de configuração precocemente e construir confiança no sistema antes de escalar para cenários mais complexos.\n\n**Conclusão:** A alternativa C é a resposta correta porque conceder acesso irrestrito a todas as ferramentas de uma vez é antiético às boas práticas de segurança e configuração responsável de integrações.','\n',char(10)),replace('**Explicação para uma criança de 10 anos:**\n\nA pergunta é: "Qual dessas opções NÃO é uma boa ideia quando você vai conectar um programa ao GitHub?"\n\nImagine que você está montando um quebra-cabeça. Vamos ver cada opção:\n\n**A - Começar com os modelos prontos e ir mudando aos poucos.** Isso é como usar a imagem da caixa do quebra-cabeça para começar e depois ir ajustando. É uma boa ideia!\n\n**B - Ser bem claro sobre o que cada ferramenta pode fazer.** Isso é como dizer exatamente quais peças cada pessoa pode pegar. Assim ninguém mexe no que não deve. Boa ideia também!\n\n**C - Deixar todas as ferramentas fazerem tudo de uma vez para ser mais fácil.** Isso é como dar a chave de todas as portas da sua casa para qualquer visitante. Parece mais fácil, mas é perigoso! Alguém pode entrar onde não devia. Essa NÃO é uma boa prática.\n\n**D - Testar com tarefas fáceis antes das difíceis.** Isso é como primeiro montar um quebra-cabeça de 10 peças antes de tentar um de 1000 peças. Ótima ideia!\n\n**Resposta final:** A opção C é a que NÃO é recomendada, porque dar acesso a tudo de uma vez pode causar problemas.','\n',char(10)));
INSERT INTO cards VALUES('admin','card_1783092987178_j4sw2omfz',267,'What are hooks in Claude Code?',replace('What are hooks in Claude Code?\n\nWhat are hooks in Claude Code?\n[Resposta correta: Hooks são comandos que rodam antes ou depois de uma tool (formatar, rodar testes, bloquear acesso). Não são prosa no CLAUDE.md, nem skills, nem MCP servers.]\n\n[ ] A - Prose instructions inside the CLAUDE.md\n[ ] B - Commands that run before or after Claude executes a tool\n[ ] C - Skills that load on demand\n[ ] D - MCP servers for external integrations','\n',char(10)),'B - Commands that run before or after Claude executes a tool','["Domain_3::Claude_Code_Configuration_Workflows", "Scenario_2::Code_Generation_Claude_Code"]','New',0,2.5,0,1783092987178,1783727239655,1783203558653,replace('**Tradução da pergunta e alternativas:**\n\nO que são hooks no Claude Code?\n\n[ ] A - Instruções em prosa dentro do CLAUDE.md\n[ ] B - Comandos que rodam antes ou depois de Claude executar uma tool\n[ ] C - Skills que carregam sob demanda\n[ ] D - Servidores MCP para integrações externas','\n',char(10)),replace('**Explicação para um adulto tech lead:**\n\nA resposta correta é a alternativa B.\n\nHooks no Claude Code são scripts ou comandos configurados para serem executados automaticamente em pontos específicos do ciclo de vida de execução de uma tool — tipicamente antes (pre-hooks) ou depois (post-hooks) de uma ferramenta ser invocada. Eles permitem, por exemplo, formatar código automaticamente antes de salvar, rodar testes após uma edição, ou bloquear ações que não atendam a certos critérios (como um linter rejeitando um commit). É um mecanismo de automação e controle de qualidade integrado ao fluxo de trabalho do Claude.\n\n**Por que as demais alternativas estão incorretas:**\n\n- **Alternativa A (Instruções em prosa dentro do CLAUDE.md):** O arquivo CLAUDE.md contém instruções gerais de configuração e contexto para o Claude, mas não são hooks. Hooks são executáveis (comandos/scripts), não prosa declarativa. A descrição se refere a um artefato de configuração, não a um mecanismo de gatilho automático.\n\n- **Alternativa C (Skills que carregam sob demanda):** Skills são capacidades modulares que podem ser ativadas conforme necessário (como plugins especializados). Hooks não são skills; são disparadores automáticos ligados a eventos de tools. A confusão pode vir de ambos serem mecanismos de extensão, mas diferem em propósito e comportamento: hooks reagem a execuções, skills adicionam funcionalidades.\n\n- **Alternativa D (Servidores MCP para integrações externas):** MCP (Model Context Protocol) servers são servidores que provêem contexto e ferramentas externas ao Claude, seguindo um protocolo específico. Hooks operam internamente no ciclo de vida das tools do Claude Code, não são servidores externos nem seguem o protocolo MCP. A finalidade é completamente diferente: um é sobre integração com sistemas externos, o outro sobre automação local no pipeline de execução.','\n',char(10)),replace('Imagine que você está brincando com seu robô de brinquedo. Quando você dá um comando pro robô andar, você pode programar ele pra fazer uma barulhinho antes de andar ("bip!") e outro depois ("pronto!"). Esses barulhinhos são como os hooks no Claude Code: são comandos extras que rodam automaticamente antes ou depois de uma ação principal.\n\nAgora vamos ver as opções:\n\n- A - Instruções em prosa dentro do CLAUDE.md: Isso seria como escrever um manual de instruções pro robô. Não é a mesma coisa que programar o robô pra fazer algo automaticamente antes ou depois de andar.\n\n- B - Comandos que rodam antes ou depois de Claude executar uma tool: É exatamente isso! Como o barulhinho antes e depois do robô andar. É a resposta certa.\n\n- C - Skills que carregam sob demanda: Skills são como peças de lego extras que você pode encaixar no robô quando quiser, mas não são os comandos automáticos de antes e depois.\n\n- D - Servidores MCP para integrações externas: Isso seria como conectar seu robô a um computador ou a outro brinquedo. Não tem nada a ver com programar ações automáticas antes e depois de um comando.\n\nEntão, a resposta certa é a B: hooks são comandos que rodam automaticamente antes ou depois que o Claude faz alguma tarefa (tool).','\n',char(10)));
INSERT INTO cards VALUES('admin','card_1783092987198_t5dcit4bd',268,'Which statement correctly distinguishes PreToolUse from PostToolUse?',replace('Which statement correctly distinguishes PreToolUse from PostToolUse?\n\nWhich statement correctly distinguishes PreToolUse from PostToolUse?\n[Resposta correta: PreToolUse roda antes e pode bloquear; PostToolUse roda depois e não bloqueia (mas roda follow-ups). A A e a C erram quem bloqueia/quando roda; a D é falsa, ambos podem dar feedback.]\n\n[ ] A - Both can block the tool call\n[ ] B - PreToolUse runs before and can block the call; PostToolUse runs after and cannot block\n[ ] C - PreToolUse runs after; PostToolUse runs before and blocks\n[ ] D - Neither of them can give feedback to Claude','\n',char(10)),'B - PreToolUse runs before and can block the call; PostToolUse runs after and cannot block','["Domain_1::Agentic_Architecture_Orchestration", "Domain_2::Tool_Design_MCP_Integration", "Scenario_1::Customer_Support_Agent"]','New',0,2.5,0,1783092987198,1783727243588,1783203558653,replace('**Tradução fiel para português do Brasil:**\n\nQual afirmação distingue corretamente PreToolUse de PostToolUse?\n\n[ ] A - Ambos podem bloquear a chamada de ferramenta\n[ ] B - PreToolUse roda antes e pode bloquear a chamada; PostToolUse roda depois e não pode bloquear\n[ ] C - PreToolUse roda depois; PostToolUse roda antes e bloqueia\n[ ] D - Nenhum deles pode dar feedback ao Claude','\n',char(10)),replace('**Explicação didática para um adulto tech lead:**\n\nNo contexto do protocolo de ferramentas (tool use) de sistemas como o Claude, **PreToolUse** e **PostToolUse** são hooks que permitem intervenção em momentos distintos do ciclo de vida de uma chamada de ferramenta.\n\n**Alternativa correta: B**\n\n- **PreToolUse**: é executado *antes* da ferramenta ser chamada. Ele pode, por exemplo, validar parâmetros, enriquecer a requisição ou **bloquear** a execução da ferramenta (retornando um erro ou substituindo a chamada). É um ponto de controle síncrono e bloqueante no fluxo.\n- **PostToolUse**: é executado *depois* que a ferramenta já foi chamada e retornou um resultado. Ele **não pode bloquear** a chamada (ela já ocorreu), mas pode processar o resultado, disparar follow-ups ou modificar a resposta antes de enviá-la ao modelo. É um hook de pós-processamento.\n\n**Por que as demais estão erradas:**\n\n- **A**: Incorreta. Apenas o PreToolUse pode bloquear a chamada. PostToolUse ocorre após a ferramenta já ter sido executada — bloquear nesse ponto não faz sentido semântico.\n- **C**: Incorreta. Inverte os papéis: PreToolUse roda *antes*, não depois; PostToolUse roda *depois*, não antes.\n- **D**: Incorreta. Ambos podem, sim, dar feedback ao Claude (por exemplo, retornando mensagens de erro ou modificando outputs). O PreToolUse pode gerar um erro que interrompe o fluxo (feedback direto), e o PostToolUse pode processar o resultado e influenciar respostas futuras.','\n',char(10)),replace('Imagine que você está jogando um jogo no computador e o personagem vai usar uma "ferramenta mágica" (tipo uma pá para cavar um buraco).\n\n- **PreToolUse** é como um segurança que fica **antes** da pá ser usada. Ele verifica: "Você tem permissão para cavar aqui?" Se não tiver, ele **bloqueia** e não deixa a pá ser usada.\n- **PostToolUse** é como um ajudante que aparece **depois** que a pá já cavou. Ele não pode bloquear (já cavou!), mas pode limpar a sujeira, colocar uma placa ou até chamar outro ajudante para continuar o trabalho.\n\nResumindo:\n- O segurança (PreToolUse) aparece **antes** e pode **impedir**.\n- O ajudante (PostToolUse) aparece **depois** e **não pode impedir**, mas pode fazer outras coisas.\n\nA resposta certa é a **B** porque ela explica direitinho quem faz o quê!','\n',char(10)));
INSERT INTO cards VALUES('admin','card_1783092987238_mt6mg7my2',269,'Where do you define a project hook that should be shared with the team?',replace('Where do you define a project hook that should be shared with the team?\n\nWhere do you define a project hook that should be shared with the team?\n[Resposta correta: .claude/settings.json é o escopo de projeto compartilhado com o time. ~/.claude/settings.json é global de máquina; settings.local.json é pessoal/não commitado; CLAUDE.md não define hooks.]\n\n[ ] A - ~/.claude/settings.json\n[ ] B - .claude/settings.json\n[ ] C - .claude/settings.local.json\n[ ] D - CLAUDE.md','\n',char(10)),'B - .claude/settings.json','["Domain_3::Claude_Code_Configuration_Workflows", "Scenario_2::Code_Generation_Claude_Code"]','New',0,2.5,0,1783092987238,1783727246750,1783203558653,replace('**Tradução da pergunta e alternativas para português do Brasil:**\n\nPergunta: Onde você define um hook de projeto que deve ser compartilhado com o time?\n\nAlternativas:\n[ ] A - ~/.claude/settings.json\n[ ] B - .claude/settings.json\n[ ] C - .claude/settings.local.json\n[ ] D - CLAUDE.md','\n',char(10)),replace('**Explicação didática para um adulto tech lead:**\n\nA pergunta trata de onde configurar um **project hook** (gancho de projeto) no ecossistema Claude (provavelmente Claude Code ou CLI da Anthropic) de forma que ele seja **compartilhado com o time** via versionamento.\n\n- **Alternativa correta: B - .claude/settings.json**\n\n  O arquivo `.claude/settings.json` está dentro do diretório do projeto (`.claude/` na raiz). Por ser um arquivo versionado (committado no repositório), todos os membros do time que clonarem o projeto terão acesso a essa configuração. É o escopo de **projeto** propriamente dito, ideal para hooks, prompts personalizados ou configurações que devem valer para toda a equipe.\n\n- **Alternativa A - ~/.claude/settings.json** (errada)\n\n  O `~` (home do usuário) indica escopo **global/máquina**, ou seja, é uma configuração pessoal do desenvolvedor. Não é compartilhada com o time, pois cada máquina tem seu próprio `~/.claude/settings.json`. Inclusive, conforme a própria dica na resposta, é dito "global de máquina".\n\n- **Alternativa C - .claude/settings.local.json** (errada)\n\n  O sufixo `.local` geralmente indica um arquivo que **não deve ser commitado** (está no `.gitignore`). Ele serve para sobrescrever configurações localmente sem afetar o repositório. Portanto, não é compartilhado com o time. A própria descrição indica "pessoal/não commitado".\n\n- **Alternativa D - CLAUDE.md** (errada)\n\n  O arquivo `CLAUDE.md` (ou `CLAUDE.md` na raiz do projeto) é um arquivo de instruções/personalização de comportamento do Claude, mas **não define hooks**. Ele pode conter regras de estilo, contexto do projeto, etc., mas o local para definir hooks é o `settings.json`.\n\n**Resumo técnico:** O escopo correto para compartilhar hooks com o time é o escopo de **projeto** (`.claude/settings.json`), que fica dentro do repositório e é versionado com o código.','\n',char(10)),replace('Imagine que você e seus amigos estão jogando um jogo de LEGO em grupo. Para que todos montem da mesma forma, vocês colocam as instruções dentro da caixa do LEGO que todo mundo vai usar. Essa caixa é como o arquivo `.claude/settings.json` — ele fica dentro da pasta do projeto, e todo mundo do time tem acesso a ele.\n\nAgora, se você deixar as instruções no seu quarto (que é tipo a pasta `~/.claude/` no seu computador), só você vê, certo? Seus amigos não saberiam como montar.\n\nO arquivo `settings.local.json` seria como um bilhete secreto só seu, que você não mostra pros outros. E o `CLAUDE.md` é como um caderno de regras do jogo, mas não é onde se colocam os "hooks" (que são como gatilhos ou lembretes automáticos). Então o lugar certo para todo mundo ver e usar é o **`.claude/settings.json`**.','\n',char(10)));
INSERT INTO cards VALUES('admin','card_1783092987258_xpsk21s8v',270,'What is the matcher field for in a hook''s configuration?',replace('What is the matcher field for in a hook''s configuration?\n\nWhat is the matcher field for in a hook''s configuration?\n[Resposta correta: O matcher especifica quais tools disparam o hook, aceitando padrões como Write|Edit ou *. As demais descrevem exit code, caminho ou controle de usuário, não a função do matcher.]\n\n[ ] A - It defines the success exit code\n[ ] B - It specifies which tool types trigger the hook (e.g. Read, Write|Edit, or *)\n[ ] C - It defines the absolute path of the script\n[ ] D - It restricts which users can run the hook','\n',char(10)),'[ ] B - It specifies which tool types trigger the hook (e.g. Read, Write|Edit, or *)','["Domain_3::Claude_Code_Configuration_Workflows", "Scenario_2::Code_Generation_Claude_Code"]','New',0,2.5,0,1783092987258,1783727249735,1783203558653,replace('Tradução para português do Brasil:\n\nQual é a finalidade do campo matcher na configuração de um hook?\n\n[ ] A - Ele define o código de saída de sucesso\n[ ] B - Ele especifica quais tipos de ferramentas (tools) disparam o hook (ex.: Read, Write|Edit ou *)\n[ ] C - Ele define o caminho absoluto do script\n[ ] D - Ele restringe quais usuários podem executar o hook','\n',char(10)),replace('Explicação didática para um adulto tech lead:\n\nO campo **matcher** em um hook (como os do sistema de hooks do Claude Code ou ferramentas similares) tem como função exclusiva determinar **quais tipos de tool calls** devem acionar a execução daquele hook.\n\n- **Alternativa A (incorreta):** O código de saída (exit code) bem-sucedido é tipicamente definido em outra parte da configuração, por exemplo, em campos como `success_exit_codes`, `expected_exit_code` ou algo equivalente. O matcher não tem relação com isso.\n\n- **Alternativa B (correta):** É exatamente essa a função do matcher. Ele aceita padrões como `Read`, `Write|Edit`, ou o curinga `*` para definir quais operações de ferramenta (tools) disparam o hook. Por exemplo, um hook configurado com `matcher: "Write|Edit"` será executado sempre que o agente chamar uma ferramenta de escrita ou edição.\n\n- **Alternativa C (incorreta):** O caminho absoluto do script é definido em um campo como `script_path`, `command` ou `path`, e não no matcher. O matcher lida com padrões de trigger, não com localização de arquivos.\n\n- **Alternativa D (incorreta):** Restrições de usuário são gerenciadas por campos como `allowed_users`, `user_restrictions` ou mecanismos de permissão do sistema operacional, não pelo matcher.\n\nPortanto, o campo **matcher** é utilizado exclusivamente para definir quais tipos de chamadas de ferramenta ativam o hook.','\n',char(10)),replace('Imagine que você tem um robô assistente que pode usar várias ferramentas: uma ferramenta de leitura (como um livro), uma ferramenta de escrita (como um caderno), e uma ferramenta de edição (como uma borracha).\n\nO **matcher** é como uma "regra do jogo" que diz: "Esse gancho (hook) só vai funcionar quando o robô usar QUAL ferramenta?".\n\nSe você colocar no matcher "Write|Edit", o gancho vai ser ativado APENAS quando o robô escrever ou editar alguma coisa. Se você colocar "*", significa "qualquer ferramenta".\n\nAs outras opções estão erradas porque:\n- A letra A fala sobre código de sucesso — isso é sobre "deu certo ou errado", não sobre qual ferramenta usar.\n- A letra C fala sobre o caminho do arquivo — isso é sobre ONDE está o script, não QUANDO ele deve rodar.\n- A letra D fala sobre quem pode usar — isso é sobre USUÁRIOS, não sobre ferramentas.\n\nEntão o matcher é simplesmente um "filtro" que escolhe quais ferramentas vão fazer o gancho funcionar!','\n',char(10)));
INSERT INTO cards VALUES('admin','card_1783092987307_r6fvy6rhu',271,'How does a hook receive the tool call data and communicate the decision?',replace('How does a hook receive the tool call data and communicate the decision?\n\nHow does a hook receive the tool call data and communicate the decision?\n[Resposta correta: O hook recebe um JSON pelo stdin e devolve a decisão pelo exit code. As demais inventam mecanismos de entrada/saída que não são os descritos.]\n\n[ ] A - It receives via command-line arguments and responds by file\n[ ] B - It receives a JSON via stdin and communicates the decision via exit code\n[ ] C - It receives by environment variable and responds by stdout only\n[ ] D - It receives via HTTP API and responds with an HTTP status code','\n',char(10)),'[ ] B - It receives a JSON via stdin and communicates the decision via exit code','["Domain_3::Claude_Code_Configuration_Workflows", "Scenario_2::Code_Generation_Claude_Code"]','New',0,2.5,0,1783092987307,1783727252744,1783203558653,replace('**Tradução para português do Brasil:**\n\n**Pergunta:** Como um hook recebe os dados da chamada de ferramenta (tool call) e comunica a decisão?\n\n**Alternativas:**\n[ ] A - Recebe via argumentos de linha de comando e responde por arquivo\n[ ] B - Recebe um JSON via stdin e comunica a decisão via código de saída (exit code)\n[ ] C - Recebe por variável de ambiente e responde apenas via stdout\n[ ] D - Recebe via API HTTP e responde com um código de status HTTP','\n',char(10)),replace('**Explicação para um adulto (tech lead):**\n\nNo contexto de hooks para ferramentas (tool calls), o padrão mais comum e adequado para integração de scripts externos é a comunicação via **stdin** (entrada padrão) para receber dados e **exit code** (código de retorno) para sinalizar a decisão. Isso ocorre porque:\n\n1. **Por que a alternativa B está correta:** O hook é tipicamente um subprocesso executado pelo sistema. O sistema envia os dados da chamada da ferramenta (tool call) como um JSON pelo stdin, uma vez que essa é uma forma universal e simples de passar dados estruturados para um processo filho. A decisão (aceitar, recusar, modificar, etc.) é comunicada pelo exit code, que é um mecanismo de retorno leve e padronizado (0 para sucesso/aceite, códigos diferentes para diferentes decisões). Essa abordagem evita a complexidade de soquetes, arquivos temporários ou parsing de variáveis de ambiente.\n\n2. **Por que as demais alternativas estão incorretas:**\n   - **Alternativa A (argumentos de linha de comando):** Argumentos de linha de comando têm limitações severas de tamanho e não são adequados para payloads JSON potencialmente grandes ou complexos. Além disso, responder "por arquivo" exige gerenciamento de arquivos temporários, permissões e limpeza, o que é frágil e não escalável.\n   - **Alternativa C (variável de ambiente):** Variáveis de ambiente também têm limites de tamanho e não foram projetadas para transportar dados dinâmicos e estruturados entre processos. Responder "apenas por stdout" misturaria saída de log/depuração com a resposta da decisão, tornando o parsing ambíguo e propenso a erros.\n   - **Alternativa D (API HTTP):** Expor um hook via API HTTP adicionaria latência de rede, complexidade de servidor web, necessidade de gerenciamento de portas/endpoints e problemas de segurança (firewall, autenticação). É excessivamente complexo para a comunicação simples entre um processo pai e um filho no mesmo host.\n\nPortanto, o design minimalista e eficiente de stdin para entrada e exit code para saída é a abordagem canônica e tecnicamente superior para hooks de tool calls.','\n',char(10)),'Imagine que você tem um robô ajudante (o sistema) que quer pedir ajuda a outro robô (o hook). O robô principal escreve um bilhete em formato JSON (uma linguagem secreta que os robôs entendem) e passa esse bilhete pela "portinha de entrada" (stdin). O outro robô lê o bilhete, pensa na resposta, e em vez de escrever um novo bilhete, ele simplesmente acende uma luz verde (código de saída 0) se a resposta for "sim" ou uma luz vermelha (outro código) se for "não". É assim que eles se comunicam: um passa o papel pela fresta e o outro pisca uma luz para responder. As outras formas seriam mais complicadas: falar pelo megafone (argumentos de linha de comando) — que não dá para passar bilhetes longos; escrever em um quadro branco (variável de ambiente) — que tem espaço limitado; ou usar um telefone (API HTTP) — que precisa de fios e número de telefone, muito complicado para uma conversa simples entre dois robôs na mesma sala!');
INSERT INTO cards VALUES('admin','card_1783092987326_2h7zgv151',272,'In a PreToolUse hook, what do exit code 0 and exit code 2 do?',replace('In a PreToolUse hook, what do exit code 0 and exit code 2 do?\n\nIn a PreToolUse hook, what do exit code 0 and exit code 2 do?\n[Resposta correta: Exit 0 permite; exit 2 bloqueia e manda o texto de stderr ao Claude como feedback. A A inverte; a C ignora o bloqueio; a D troca os papéis e os canais.]\n\n[ ] A - 0 blocks; 2 allows\n[ ] B - 0 allows the tool call; 2 blocks and sends the stderr as feedback to Claude\n[ ] C - Both allow; the difference is only in logging\n[ ] D - 2 allows and sends stdout to the user; 0 blocks silently','\n',char(10)),'[ ] B - 0 permite a chamada de ferramenta; 2 bloqueia e envia o stderr como feedback para o Claude','["Domain_3::Claude_Code_Configuration_Workflows", "Domain_4::Prompt_Engineering_Structured_Output", "Scenario_2::Code_Generation_Claude_Code"]','New',0,2.5,0,1783092987326,1783727255959,1783203558653,replace('**Tradução para português do Brasil:**\n\nPergunta: Em um hook PreToolUse, o que fazem os códigos de saída 0 e 2?\n\n[ ] A - 0 bloqueia; 2 permite\n[ ] B - 0 permite a chamada de ferramenta; 2 bloqueia e envia o stderr como feedback para o Claude\n[ ] C - Ambos permitem; a diferença está apenas no logging\n[ ] D - 2 permite e envia stdout para o usuário; 0 bloqueia silenciosamente','\n',char(10)),replace('**Explicação para um adulto tech lead:**\n\nEm um PreToolUse hook (comum em frameworks como o Anthropic Claude API ou sistemas de agentes), você pode interceptar uma chamada de ferramenta antes dela ser executada e decidir o que fazer com base no código de saída do seu script/hook.\n\n- **Exit code 0**: significa "sucesso" — o hook permite que a chamada de ferramenta prossiga normalmente. É o comportamento padrão de aprovação.\n- **Exit code 2**: é um código especial usado para "bloquear com feedback". O hook rejeita a chamada da ferramenta, mas envia o conteúdo do **stderr** do seu script de volta ao Claude (ou ao modelo) como uma mensagem de feedback. Isso permite que o modelo entenda *por que* a ferramenta foi bloqueada e, potencialmente, corrija a ação.\n\nAnalisando as alternativas incorretas:\n- **A**: Inverte os papéis — afirma que exit 0 bloqueia (falso) e exit 2 permite (falso).\n- **C**: Afirma que ambos permitem — incorreto, pois exit 2 bloqueia explicitamente.\n- **D**: Confunde os canais — exit 2 não envia stdout para o usuário, e exit 0 não bloqueia silenciosamente.\n\nPortanto, a alternativa **B** é a correta.','\n',char(10)),replace('Imagine que você tem um robô assistente (Claude) que quer usar uma ferramenta, como uma calculadora. Antes de deixar ele usar, tem um "fiscal" (o PreToolUse hook) que verifica se está tudo certo.\n\n- Se o fiscal **"bate o carimbo com 0"** (exit code 0), ele diz: "Tudo ok, pode usar a ferramenta!"\n- Se o fiscal **"bate o carimbo com 2"** (exit code 2), ele diz: "Não pode usar!", **e ainda manda um bilhete** explicando o motivo (o que estava escrito no stderr). Assim, o Claude lê o bilhete e tenta de novo de forma diferente.\n\nAs outras opções são como trocar os carimbos ou fingir que o bloqueio não aconteceu — o que não é o jeito correto de funcionar.','\n',char(10)));
INSERT INTO cards VALUES('admin','card_1783092987344_cv9exk3h7',273,'What is the correct sequence to build a hook?',replace('What is the correct sequence to build a hook?\n\nWhat is the correct sequence to build a hook?\n[Resposta correta: A ordem é: escolher o evento, definir o matcher, escrever o comando que lê o JSON do stdin e, se preciso, dar feedback via exit code. As demais descrevem MCP ou skills, não hooks.]\n\n[ ] A - Write the command, choose the exit code, then define the event\n[ ] B - Choose Pre/PostToolUse, define the matcher, write the command that reads stdin, give feedback via exit code\n[ ] C - Register via claude mcp add and define permissions\n[ ] D - Create a SKILL.md with allowed-tools and invoke by slash command','\n',char(10)),'B - Choose Pre/PostToolUse, define the matcher, write the command that reads stdin, give feedback via exit code','["Domain_3::Claude_Code_Configuration_Workflows", "Scenario_2::Code_Generation_Claude_Code"]','New',0,2.5,0,1783092987344,1783727259379,1783203558653,replace('**Tradução para português do Brasil:**\n\nQual é a sequência correta para construir um hook?\n\n[ ] A - Escrever o comando, escolher o código de saída (exit code), então definir o evento\n[ ] B - Escolher Pre/PostToolUse, definir o matcher, escrever o comando que lê o stdin, fornecer feedback via código de saída (exit code)\n[ ] C - Registrar via "claude mcp add" e definir permissões\n[ ] D - Criar um arquivo SKILL.md com allowed-tools e invocar por comando de barra (/)','\n',char(10)),replace('**Explicação didática para adulto (tech lead):**\n\nA alternativa correta é a **B**, pois descreve a sequência canônica para construir um hook no ecossistema Claude Code (antigo Claude CLI). Hooks são scripts que interceptam eventos específicos no ciclo de vida de uma interação com o agente, como antes ou depois do uso de uma ferramenta (Pre/PostToolUse).\n\nA ordem correta é:\n\n1. **Escolher o evento (Pre/PostToolUse)** – Define *quando* o hook será disparado. Hooks sempre estão associados a eventos no ciclo de uso de ferramentas.\n2. **Definir o matcher** – Um filtro que especifica *qual* ferramenta (ou tipo de ferramenta) deve disparar o hook. Pode ser um nome exato, um padrão glob, ou expressão regular.\n3. **Escrever o comando que lê o JSON do stdin** – O hook recebe dados estruturados via entrada padrão (stdin) no formato JSON. O script precisa ser capaz de interpretar esse input para tomar decisões.\n4. **Dar feedback via exit code** – Códigos de saída (0 para sucesso/permitir, não-zero para falha/bloquear) são o mecanismo de retorno para o agente Claude. Isso permite controlar o fluxo da execução.\n\n**Análise das alternativas incorretas:**\n\n- **A** – A ordem está incorreta. Você não escreve o comando antes de escolher o evento; o evento é o ponto de partida conceitual. Além disso, o exit code não é escolhido antes de tudo — ele é uma consequência da lógica do script.\n- **C** – Descreve o fluxo de registro de um MCP server (Model Context Protocol), não de um hook. "claude mcp add" é um comando para adicionar servidores MCP, e hooks não são registrados dessa forma.\n- **D** – Descreve a mecânica de **skills** (no Claude Code), que são instruções baseadas em arquivos SKILL.md com permissões e comandos de barra (/). Isso não tem relação com a construção de hooks, que operam em nível de eventos de ferramentas.','\n',char(10)),replace('Imagine que você está construindo um robô assistente que usa ferramentas (como uma calculadora ou um bloco de notas). Um "hook" é como um sensor que faz algo especial quando o robô vai usar uma ferramenta — por exemplo, pedir permissão ou registrar o que foi feito.\n\nA ordem certa para construir esse sensor é:\n\n1. **Escolher quando ele vai funcionar** — Antes ou depois do robô usar a ferramenta? (Isso é o Pre/PostToolUse)\n2. **Definir qual ferramenta ativa o sensor** — Só a calculadora? Qualquer ferramenta? (Isso é o matcher)\n3. **Escrever o programa que lê as informações** — O robô manda um bilhete em JSON (um formato de texto organizado) explicando o que vai fazer. O sensor precisa ler esse bilhete.\n4. **Responder com um sinal** — O sensor dá um "joinha" (código 0) se está tudo bem, ou um "pare" (código diferente de zero) se algo está errado.\n\nAs outras opções explicam coisas diferentes:\n- **Opção A** — Mistura a ordem, começando pelo fim.\n- **Opção C** — Fala de como conectar um servidor externo (MCP), que é outro assunto.\n- **Opção D** — Fala de "skills", que são como receitas prontas para o robô seguir, não sensores de ferramentas.','\n',char(10)));
INSERT INTO cards VALUES('admin','card_1783092987371_ws3mpmfvf',274,'To block Claude from reading .',replace('To block Claude from reading .\n\nTo block Claude from reading .env files via a hook, which configuration do you use?\n[Resposta correta: É um PreToolUse com matcher Read que inspeciona file_path e, ao encontrar .env, escreve em stderr e faz exit(2) para bloquear. PostToolUse não bloqueia; exit 0 sempre permite; skill não é o mecanismo desse cenário.]\n\n[ ] A - PostToolUse with matcher Read, exit 2\n[ ] B - PreToolUse with matcher Read that checks tool_input.file_path; if it contains .env, write to stderr and exit(2)\n[ ] C - PreToolUse with matcher * and exit 0 always\n[ ] D - A skill with disallowed-tools listing Read','\n',char(10)),'B - PreToolUse with matcher Read that checks tool_input.file_path; if it contains .env, write to stderr and exit(2)','["Domain_3::Claude_Code_Configuration_Workflows", "Domain_2::Tool_Design_MCP_Integration", "Scenario_2::Code_Generation_Claude_Code"]','New',0,2.5,0,1783092987371,1783727262499,1783203558653,replace('**Tradução para português do Brasil:**\n\nPara bloquear que Claude leia arquivos .env por meio de um hook, qual configuração você utiliza?\n\n[ ] A - PostToolUse com matcher Read, exit 2\n[ ] B - PreToolUse com matcher Read que verifica tool_input.file_path; se contiver .env, escreve em stderr e faz exit(2)\n[ ] C - PreToolUse com matcher * e exit 0 sempre\n[ ] D - Uma skill com disallowed-tools listando Read','\n',char(10)),replace('**Explicação para adulto (tech lead):**\n\nA resposta correta é a alternativa **B**.\n\nVamos analisar cada uma:\n\n- **Alternativa B (correta):** O hook do tipo `PreToolUse` é executado *antes* da ferramenta ser chamada. Isso é essencial para *bloquear* a ação. O `matcher Read` indica que a regra se aplica apenas à ferramenta de leitura (Read). Dentro do hook, verificamos `tool_input.file_path` — se ele contiver `.env`, escrevemos uma mensagem de erro em stderr e chamamos `exit(2)`. O código de saída 2 (ou diferente de zero) sinaliza falha, impedindo que o Read seja executado. Essa é a abordagem correta para "bloquear" preventivamente.\n\n- **Alternativa A (incorreta):** `PostToolUse` é executado *depois* que a ferramenta já rodou. Mesmo que faça exit(2), o dano já ocorreu — Claude já leu o arquivo. Portanto, não bloqueia, apenas reporta ou reage após o fato.\n\n- **Alternativa C (incorreta):** `PreToolUse` com `matcher *` e `exit 0` sempre. Exit 0 significa sucesso, ou seja, permite que a ferramenta prossiga. Isso não bloqueia nada. Além disso, matcher "*" aplicaria a regra a *todas* as ferramentas, mas o exit 0 não impede execução alguma.\n\n- **Alternativa D (incorreta):** Skills definem permissões de alto nível (quais ferramentas um usuário pode usar), mas não são hooks que inspecionam argumentos específicos (como o caminho do arquivo). A lista `disallowed-tools` impede o uso completo da ferramenta Read, não permite uma verificação condicional baseada no conteúdo de `file_path`.','\n',char(10)),replace('Imagine que você tem um robô chamado Claude que pode ler arquivos do seu computador. Você não quer que ele leia um arquivo secreto chamado ".env" (que pode ter senhas).\n\nPara impedir isso, você precisa de uma "regra" que seja verificada **antes** de Claude ler o arquivo. É como um porteiro que olha o nome do arquivo e, se for ".env", diz "Pare! Não pode entrar!" e barra a passagem.\n\n- A alternativa **B** é a certa porque coloca o porteiro na entrada (PreToolUse = antes de usar a ferramenta), ele só olha para a ferramenta de leitura (matcher Read), verifica o nome do arquivo, e se for .env, ele grita "Proibido!" (escreve no stderr) e bate a porta (exit 2 - que significa "não permitido").\n\n- A alternativa **A** está errada porque coloca o porteiro depois que o robô já leu o arquivo (PostToolUse). De nada adianta barrar depois, o segredo já foi visto!\n\n- A alternativa **C** está errada porque o porteiro diz "Pode passar!" para todo mundo (exit 0 = sucesso). Não bloqueia ninguém.\n\n- A alternativa **D** está errada porque é como tirar o robô inteiro de circulação (proibir a ferramenta Read completamente), em vez de apenas impedir a leitura do arquivo .env específico.\n\nEntão a resposta certa é a **B**!','\n',char(10)));
INSERT INTO cards VALUES('admin','card_1783092987388_84ezbn8jc',275,'Why does a hook that only checks Read not fully protect the .',replace('Why does a hook that only checks Read not fully protect the .\n\nWhy does a hook that only checks Read not fully protect the .env, and what is the more robust alternative?\n[Resposta correta: Como Grep e Bash não enviam file_path, um hook de Read não cobre grep nem cat .env; regras permissions.deny (ex.: Read(**/.env)) dão cobertura uniforme. As demais erram a causa ou negam a necessidade de proteção.]\n\n[ ] A - Because hooks cannot read stdin; use a subagent\n[ ] B - Because each tool has a different input (Grep uses pattern, Bash uses command), so the file_path check does not catch grep or cat; use permissions.deny\n[ ] C - Because the Read matcher does not exist; use matcher *\n[ ] D - Because .env is ignored by default; no protection is needed','\n',char(10)),'B - Because each tool has a different input (Grep uses pattern, Bash uses command), so the file_path check does not catch grep or cat; use permissions.deny','["Domain_2::Tool_Design_MCP_Integration", "Domain_5::Context_Management_Reliability", "Scenario_4::Developer_Productivity"]','New',0,2.5,0,1783092987388,1783727265890,1783203558653,replace('**Tradução para português do Brasil:**\n\n**Pergunta:** Por que um hook que verifica apenas Read não protege completamente o arquivo .env, e qual é a alternativa mais robusta?\n\n[ ] A - Porque hooks não conseguem ler stdin; use um subagente\n[ ] B - Porque cada ferramenta tem uma entrada diferente (Grep usa pattern, Bash usa command), então a verificação de file_path não pega grep ou cat; use permissions.deny\n[ ] C - Porque o matcher Read não existe; use matcher *\n[ ] D - Porque .env é ignorado por padrão; nenhuma proteção é necessária','\n',char(10)),replace('**Explicação didática para adulto tech lead:**\n\nA pergunta aborda um ponto sutil sobre o sistema de permissões e hooks em agentes de IA (como o Assistants API ou frameworks similares). O hook "Read" normalmente verifica o parâmetro `file_path` nas chamadas de ferramentas. O problema é que ferramentas como `Grep` e `Bash` não recebem `file_path` como parâmetro — o Grep recebe um `pattern` (e internamente pode ler arquivos), e o Bash recebe um `command` (string de shell). Portanto, um hook que só examina `file_path` jamais detectará um `grep .env` ou `cat .env` executado via Bash, porque esses comandos não passam por um parâmetro `file_path`.\n\n**Alternativa correta (B):** Ela identifica precisamente essa limitação (cada tool tem parâmetros diferentes) e propõe a solução correta: usar `permissions.deny` com regras como `Read(**/.env)` — que funcionam no nível do sistema de permissões, independentemente de qual ferramenta está sendo usada, bloqueando qualquer tentativa de acessar o arquivo.\n\n**Análise das alternativas incorretas:**\n\n- **A:** É falsa. Hooks podem sim interceptar ferramentas, e o problema não é sobre stdin. Subagente não resolve a questão fundamental.\n- **C:** É falsa. O matcher Read existe sim; o problema não é a existência do matcher, mas sim seu escopo limitado a `file_path`.\n- **D:** É falsa e perigosa. .env **não** é ignorado por padrão; ele contém segredos (senhas, tokens) e precisa de proteção explícita.','\n',char(10)),replace('**Explicação para criança de 10 anos:**\n\nImagine que você tem um cofre (o arquivo .env) com seus segredos. Você coloca um segurança na porta do cofre que só verifica se alguém está tentando abrir a porta (o hook Read). Mas o problema é que algumas pessoas malvadas podem chegar pelo telhado ou por um túnel — elas não usam a porta! O Grep e o Bash são assim: eles não "abrem a porta" do arquivo, eles dão um jeito de ler o conteúdo por outros meios.\n\nA alternativa correta (letra B) diz: coloque um alarme que protege o cofre inteiro, não só a porta. Esse alarme é o `permissions.deny`, que bloqueia qualquer tentativa de acessar o arquivo .env, não importa como a pessoa tente.\n\nAs outras respostas estão erradas porque:\n- A: Diz que o segurança não consegue ouvir o que chega pelo correio (stdin) — mas isso não é o problema.\n- C: Diz que o segurança não existe — mas ele existe, só não é bom o suficiente.\n- D: Diz que o cofre não precisa de proteção — isso é muito perigoso! O .env tem senhas e segredos importantes.','\n',char(10)));
INSERT INTO cards VALUES('admin','card_1783092987410_ora6g5mhc',276,'You want file protection that applies equally to Read, Grep and Bash.',replace('You want file protection that applies equally to Read, Grep and Bash.\n\nYou want file protection that applies equally to Read, Grep and Bash. What do you use?\n[Resposta correta: permissions.deny aplica-se de forma uniforme a todas as tools, sem precisar de um matcher por tool. Hook de Read não cobre Grep/Bash; PostToolUse não bloqueia; prosa no CLAUDE.md não tem enforcement.]\n\n[ ] A - A PreToolUse hook with matcher Read\n[ ] B - permissions.deny rules, which apply uniformly to all tools\n[ ] C - A PostToolUse hook with matcher *\n[ ] D - A prose instruction in the CLAUDE.md','\n',char(10)),'B - permissions.deny rules, which apply uniformly to all tools','["Domain_3::Claude_Code_Configuration_Workflows", "Domain_5::Context_Management_Reliability", "Scenario_2::Code_Generation_Claude_Code"]','New',0,2.5,0,1783092987410,1783727269055,1783203558653,replace('**Tradução para português do Brasil:**\n\nVocê quer proteção de arquivos que se aplique igualmente ao Read, Grep e Bash.\n\nO que você usa?\n\n[ ] A - Um hook PreToolUse com matcher Read\n[ ] B - Regras de permissions.deny, que se aplicam uniformemente a todas as tools\n[ ] C - Um hook PostToolUse com matcher *\n[ ] D - Uma instrução em prosa no CLAUDE.md','\n',char(10)),replace('**Explicação didática para um adulto tech lead:**\n\nA pergunta trata de um cenário onde você deseja uma política de proteção de arquivos que funcione de forma consistente entre as ferramentas Read, Grep e Bash — ou seja, independentemente de qual tool o modelo utilize para acessar um arquivo, a restrição deve ser aplicada.\n\n- **Alternativa A (PreToolUse hook com matcher Read):** Esta abordagem só ativaria o hook antes da execução da tool Read. Grep e Bash não seriam cobertos por esse matcher, deixando brechas de segurança. Um hook com matcher restrito a uma tool específica não atende ao requisito de "aplicar-se igualmente" a todas as três.\n\n- **Alternativa B (permissions.deny):** Correto. As regras de `permissions.deny` são definidas no nível de configuração do projeto e se aplicam globalmente a todas as tool calls (Read, Grep, Bash, Edit, etc.). Elas funcionam como uma camada de política centralizada que o modelo não pode contornar. Ao listar um arquivo ou diretório em `permissions.deny`, o acesso é bloqueado de forma consistente em qualquer tool que tente tocá-lo.\n\n- **Alternativa C (PostToolUse hook com matcher *):** Um hook PostToolUse executa *após* a tool já ter sido chamada. Ele não bloqueia nada; serve para logging, auditoria ou reações a eventos, mas não para prevenir o acesso. Mesmo com matcher `*`, ele não impede que um arquivo seja lido — apenas permite reagir depois que o acesso já ocorreu.\n\n- **Alternativa D (instrução em prosa no CLAUDE.md):** Instruções textuais em CLAUDE.md são *guidelines* sem enforcement. O modelo pode ignorá-las ou interpretá-las incorretamente. Não há garantia de que uma prosa seja respeitada em todas as tool calls, especialmente em casos de jailbreak ou alucinação. Portanto, não oferece proteção confiável e uniforme.\n\n**Resumo técnico:** `permissions.deny` é a única opção que oferece uma política de segurança mandatória e transversal a todas as ferramentas, sem depender de matchers específicos ou de compliance voluntária do modelo.','\n',char(10)),replace('**Explicação para uma criança de 10 anos:**\n\nImagine que você tem três amigos: o Li (que lê arquivos), o Grep (que procura palavras nos arquivos) e o Bash (que mexe nos arquivos). Você quer garantir que nenhum deles entre no seu quarto secreto.\n\n- Se você colocar um segurança na porta só para o Li (alternativa A), o Grep e o Bash ainda podem entrar — não resolve.\n- Se você escrever num bilhete "por favor, não entrem" (alternativa D), eles podem ignorar ou esquecer.\n- Se você colocar o segurança depois que eles já entraram (alternativa C), já era — o estrago está feito.\n- Agora, se você colocar uma fechadura na porta do quarto (alternativa B), ela funciona para qualquer um dos três amigos. Não importa quem tenta abrir — a porta está trancada para todos.\n\nÉ por isso que as regras de `permissions.deny` são a melhor escolha: elas são como uma fechadura que funciona para todas as ferramentas ao mesmo tempo.','\n',char(10)));
INSERT INTO cards VALUES('admin','card_1783092987432_kg36afvap',277,'Why are absolute paths recommended in hook scripts, and what is the trade-off?',replace('Why are absolute paths recommended in hook scripts, and what is the trade-off?\n\nWhy are absolute paths recommended in hook scripts, and what is the trade-off?\n[Resposta correta: Caminhos absolutos mitigam path interception e binary planting, mas dificultam compartilhar o settings.json (o caminho varia por máquina). As demais erram o motivo de segurança ou a existência do trade-off.]\n\n[ ] A - To improve read performance; with no downside\n[ ] B - To mitigate path interception and binary planting; the trade-off is that it makes sharing settings.json across machines harder\n[ ] C - Because relative paths are not supported on Windows\n[ ] D - To reduce the hook''s token consumption','\n',char(10)),'[ ] B - To mitigate path interception and binary planting; the trade-off is that it makes sharing settings.json across machines harder','["Domain_3::Claude_Code_Configuration_Workflows", "Domain_4::Prompt_Engineering_Structured_Output", "Scenario_2::Code_Generation_Claude_Code"]','New',0,2.5,0,1783092987432,1783727272287,1783203558653,replace('**Tradução para português do Brasil:**\n\nPor que caminhos absolutos são recomendados em scripts de hook, e qual é o trade-off?\n\n[ ] A - Para melhorar a performance de leitura; sem desvantagens.\n[ ] B - Para mitigar path interception e binary planting; o trade-off é que isso dificulta o compartilhamento do settings.json entre diferentes máquinas.\n[ ] C - Porque caminhos relativos não são suportados no Windows.\n[ ] D - Para reduzir o consumo de token do hook.','\n',char(10)),replace('**Explicação didática para um adulto tech lead:**\n\nO cenário típico aqui é o uso de hooks (como hooks do Git, hooks de linters/pre-commit, ou hooks de ferramentas como o Lefthook, Husky, etc.) que referenciam executáveis ou scripts.\n\n**Alternativa correta: B**\n\nCaminhos absolutos são recomendados porque eliminam a ambiguidade de qual executável será invocado. Quando um caminho relativo (ou apenas o nome do binário, resolvido via PATH) é usado, um atacante que consiga modificar o PATH (path interception) ou plantar um binário malicioso em um diretório anterior na resolução (binary planting) pode fazer com que o hook execute código arbitrário. Ao usar um caminho absoluto, você fixa exatamente qual binário será executado, ignorando completamente as variáveis de ambiente e a ordem de resolução.\n\nO trade-off é que o caminho absoluto depende da estrutura de diretórios da máquina onde o repositório foi clonado/configurado. Se você tiver um settings.json (ou arquivo de configuração similar) versionado e que referencie esse caminho absoluto, cada desenvolvedor precisará ajustá-lo para sua própria máquina, dificultando o compartilhamento e a portabilidade do arquivo.\n\n**Análise das alternativas incorretas:**\n\n- **A**: Caminhos absolutos não têm impacto significativo em performance de leitura (a diferença é irrelevante). Além disso, a afirmativa "sem desvantagens" é falsa — existe o trade-off claro de portabilidade, conforme explicado.\n- **C**: Absolute e relative paths são suportados em todos os sistemas operacionais modernos, incluindo Windows (desde que se respeite a sintaxe correta, como barras invertidas ou o prefixo `C:\`). A afirmação é factualmente incorreta.\n- **D**: "Token consumption" não é um conceito relevante na discussão de segurança e portabilidade de hooks. Essa parece uma alternativa fictícia ou confusa, provavelmente inserida como distrator sem fundamento técnico real no contexto.','\n',char(10)),replace('Imagine que você tem um brinquedo muito legal e quer mostrar para seu amigo como brincar com ele. Você pode dizer: "Pega o brinquedo que está em cima da mesa" — mas se a mesa estiver em outro lugar, seu amigo vai se confundir. Isso é como um caminho relativo: ele só funciona se tudo estiver no mesmo lugar.\n\nAgora, se você disser: "Pega o brinquedo que está no quarto do Pedro, na estante azul, na segunda prateleira" — é um caminho absoluto. Não tem erro, seu amigo vai achar direto, mesmo que tudo esteja bagunçado. Mas o problema é que, se seu amigo levar essa instrução para a casa dele, ele não vai achar o brinquedo, porque a casa dele é diferente.\n\nEntão, usar caminhos absolutos é mais seguro (ninguém vai trocar seu brinquedo por um falso), mas difícil de compartilhar com outras pessoas. As outras opções estão erradas porque ou dizem que é mais rápido (não é), ou dizem que Windows não entende caminhos relativos (entende sim), ou falam de uma coisa chamada "token" que não tem nada a ver com isso.','\n',char(10)));
INSERT INTO cards VALUES('admin','card_1783092987451_7sgxxh2q3',278,'How do you share hook settings across machines while keeping absolute paths?',replace('How do you share hook settings across machines while keeping absolute paths?\n\nHow do you share hook settings across machines while keeping absolute paths?\n[Resposta correta: Um settings.example.json com $PWD e um script de setup gera o settings.local.json com o caminho absoluto local. Commitar caminhos fixos não funciona em outras máquinas; caminhos relativos perdem a proteção; CLAUDE_HEADLESS não existe.]\n\n[ ] A - Commit the settings.json with fixed absolute paths from your machine\n[ ] B - Use settings.example.json with a $PWD placeholder and an init script that generates the local settings.local.json\n[ ] C - Use relative paths, giving up security\n[ ] D - Set the CLAUDE_HEADLESS variable to resolve the paths','\n',char(10)),'B - Use settings.example.json with a $PWD placeholder and an init script that generates the local settings.local.json','["Domain_3::Claude_Code_Configuration_Workflows", "Scenario_2::Code_Generation_Claude_Code"]','New',0,2.5,0,1783092987451,1783727275308,1783203558653,replace('---\n\n## Tradução (pt-BR)\n\n**Pergunta:** Como compartilhar configurações de hook entre máquinas mantendo caminhos absolutos?\n\n**Alternativas:**\n\n[ ] A - Commitar o settings.json com caminhos absolutos fixos da sua máquina\n[ ] B - Usar um settings.example.json com um placeholder $PWD e um script de inicialização que gera o settings.local.json local\n[ ] C - Usar caminhos relativos, abrindo mão da segurança\n[ ] D - Definir a variável CLAUDE_HEADLESS para resolver os caminhos','\n',char(10)),replace('## Explicação para um adulto (tech lead)\n\nO problema central é: você precisa compartilhar hooks do Claude (como regras de lint, automações, etc.) em um repositório versionado (ex: git), mas esses hooks frequentemente precisam referenciar caminhos absolutos no sistema de arquivos. Como fazer isso sem quebrar em outras máquinas?\n\n### Por que B é a resposta correta\n\nA alternativa **B** resolve o problema com um padrão clássico e elegante: **arquivo de exemplo + script de setup local**. O `settings.example.json` contém placeholders como `$PWD` que são substituídos dinamicamente por um script de init (ex: `setup.sh` ou `npm init`). Esse script gera um `settings.local.json` com os caminhos absolutos corretos para aquela máquina. Como o `settings.local.json` fica no `.gitignore`, cada desenvolvedor tem seu arquivo ajustado localmente, mas todos partem do mesmo exemplo versionado.\n\n### Por que as demais estão erradas\n\n- **A**: Commitar caminhos absolutos fixos quebra em qualquer outra máquina — a estrutura de diretórios, nomes de usuário, unidades de disco etc. são diferentes. É o erro mais básico.\n- **C**: Caminhos relativos podem funcionar em alguns cenários, mas eles reduzem a segurança, pois um hook malicioso poderia subir diretórios (ex: `../../..`) e atingir áreas sensíveis do sistema. Além disso, nem todos os hooks suportam caminhos relativos de forma confiável.\n- **D**: `CLAUDE_HEADLESS` não é uma variável real da plataforma Claude/Anthropic. É uma invenção para confundir. Não existe tal mecanismo de resolução de caminhos.','\n',char(10)),replace('Imagina que você tem uma receita de bolo que você quer compartilhar com seus amigos. A receita diz "use o leite que está na geladeira da sua casa". Mas a geladeira do seu amigo é diferente, e o leite está em outro lugar! Se você escrever o endereço exato da sua casa na receita, o amigo não vai achar o leite.\n\nEntão o que fazer? Você pode escrever uma receita que diz: "pegue o leite que está no lugar onde você guarda leite". E, junto com a receita, manda um bilhete dizendo: "antes de fazer o bolo, anote aqui onde fica o leite na SUA casa". Cada amigo preenche o bilhete com o caminho certo para ele.\n\nÉ isso que a opção **B** faz: ela cria um arquivo de exemplo (a receita) e um script que pergunta para o computador "onde você está agora?" e completa o endereço certinho. Assim, todo mundo usa a mesma receita, mas cada computador preenche o caminho correto sozinho.\n\nAs outras opções são ruins porque:\n\n- **A**: é como escrever o endereço da sua casa na receita e passar adiante — ninguém vai achar.\n- **C**: é tentar achar o leite sem saber onde fica, o que pode fazer você se perder e mexer em coisas que não deveria.\n- **D**: é uma opção inventada, não existe de verdade.','\n',char(10)));
INSERT INTO cards VALUES('admin','card_1783092987469_1jahozya8',279,'Which of the options is NOT a valid hook event?',replace('Which of the options is NOT a valid hook event?\n\nWhich of the options is NOT a valid hook event?\n[Resposta correta: PreMerge não é um evento de hook. SessionStart, UserPromptSubmit e PreCompact estão entre os eventos válidos (junto de Notification, Stop, SubagentStop e SessionEnd).]\n\n[ ] A - SessionStart\n[ ] B - UserPromptSubmit\n[ ] C - PreCompact\n[ ] D - PreMerge','\n',char(10)),'[ ] D - PreMerge','["Domain_3::Claude_Code_Configuration_Workflows", "Scenario_2::Code_Generation_Claude_Code"]','New',0,2.5,0,1783092987469,1783727278328,1783203558653,replace('**Tradução fiel para pt-BR:**\n\nQual das opções NÃO é um evento de hook válido?\n\n[ ] A - SessionStart  \n[ ] B - UserPromptSubmit  \n[ ] C - PreCompact  \n[ ] D - PreMerge','\n',char(10)),replace('**Explicação didática para adulto (tech lead):**\n\nA pergunta trata de eventos de hook — pontos de extensão em um sistema que permitem executar lógica personalizada em momentos específicos do ciclo de vida de uma aplicação (neste contexto, provavelmente uma plataforma de agentes/LLM).\n\n- **SessionStart**: Evento disparado quando uma sessão é iniciada. É um hook válido, comum para inicialização de estado.\n- **UserPromptSubmit**: Evento disparado quando o usuário submete um prompt. É válido e amplamente utilizado para interceptação e pré-processamento de entradas.\n- **PreCompact**: Evento que ocorre antes de uma operação de compactação (ex.: compactação de histórico de conversas). É válido em sistemas que gerenciam memória de longo prazo.\n- **PreMerge**: Não é um evento de hook reconhecido na maioria das plataformas de agentes. O termo "merge" pode sugerir mesclagem de branches ou dados, mas **PreMerge** não consta como hook padrão em sistemas como OpenAI Agents SDK, LangChain, AutoGen, ou similares. Portanto, esta é a alternativa inválida.\n\n**Resumo:** SessionStart, UserPromptSubmit e PreCompact são eventos de hook documentados e válidos. PreMerge é fictício ou não faz parte do conjunto padrão de hooks.','\n',char(10)),replace('**Explicação para criança de 10 anos:**\n\nImagine que você está jogando um videogame que tem "gatilhos" especiais que acontecem em momentos importantes do jogo. Por exemplo:\n\n- **SessionStart**: quando você começa uma nova partida.\n- **UserPromptSubmit**: quando você digita um comando e aperta "OK".\n- **PreCompact**: quando o jogo vai guardar seu progresso e limpar a memória.\n\nEsses são gatilhos que realmente existem no jogo. Agora, **PreMerge** é um nome inventado — parece uma mistura de palavras, mas não é um gatilho de verdade. É como se alguém dissesse que existe um evento "AntesDeMisturar", mas isso não faz parte do jogo. Por isso, **PreMerge** é a opção que NÃO é um evento de hook válido.','\n',char(10)));
INSERT INTO cards VALUES('admin','card_1783092987502_0xa60iyov',280,'In which situations does the Notification event trigger a hook?',replace('In which situations does the Notification event trigger a hook?\n\nIn which situations does the Notification event trigger a hook?\n[Resposta correta: Notification dispara quando o Claude envia uma notificação: pedido de permissão de tool ou ociosidade de 60 segundos. As demais descrevem gatilhos que não correspondem a esse evento.]\n\n[ ] A - Only when a tool call fails with an error\n[ ] B - When Claude needs permission for a tool, or after being idle for 60 seconds\n[ ] C - On every message sent by the user\n[ ] D - Whenever the CLAUDE.md is read','\n',char(10)),'B - When Claude needs permission for a tool, or after being idle for 60 seconds','["Domain_3::Claude_Code_Configuration_Workflows", "Scenario_2::Code_Generation_Claude_Code"]','New',0,2.5,0,1783092987502,1783727281456,1783203558653,replace('Tradução:\nEm quais situações o evento Notification dispara um hook?\n\n[ ] A - Apenas quando uma chamada de ferramenta (tool) falha com um erro\n[ ] B - Quando Claude precisa de permissão para uma ferramenta, ou após ficar ocioso por 60 segundos\n[ ] C - Em toda mensagem enviada pelo usuário\n[ ] D - Sempre que o CLAUDE.md é lido','\n',char(10)),replace('Explicação para um adulto tech lead:\n\nO evento "Notification" no contexto do Claude (provavelmente referindo-se ao sistema de hooks do Claude Code ou API) é disparado especificamente em duas situações:\n\n1. **Quando Claude precisa de permissão para executar uma ferramenta** — isso ocorre quando uma ferramenta (tool) requer aprovação explícita do usuário antes de ser executada. O hook de notificação é acionado para alertar o sistema (ou o usuário) sobre essa necessidade de autorização.\n\n2. **Após 60 segundos de ociosidade** — se Claude ficar inativo por 60 segundos, um evento de notificação é disparado, provavelmente para permitir que o sistema tome alguma ação (como perguntar se o usuário ainda está presente ou liberar recursos).\n\n**Análise das alternativas incorretas:**\n\n- **Alternativa A** ("Apenas quando uma chamada de ferramenta falha com um erro"): Incorreta. Uma falha de tool call geraria um evento de erro, não uma notificação. O evento Notification não está relacionado a falhas.\n\n- **Alternativa C** ("Em toda mensagem enviada pelo usuário"): Incorreta. Mensagens de usuário disparam eventos de mensagem (message), não eventos de notificação. São eventos distintos.\n\n- **Alternativa D** ("Sempre que o CLAUDE.md é lido"): Incorreta. A leitura do CLAUDE.md é um evento interno de configuração/inicialização, não um evento de notificação.','\n',char(10)),replace('Explicação para uma criança de 10 anos:\n\nImagina que o Claude é um robô assistente. O "evento Notification" é como um despertador ou um sinal sonoro que o robô usa para avisar você sobre duas coisas importantes:\n\n1. **"Preciso de permissão!"** — Quando o Claude quer usar uma ferramenta (como acessar um arquivo ou enviar um email) e precisa que você diga "pode" ou "não pode".\n\n2. **"Estou esperando..."** — Se você não fala nada com o Claude por 60 segundos (1 minuto), ele dispara um aviso para dizer "ei, ainda está aí?".\n\nAgora vamos ver por que as outras opções estão erradas:\n\n- **Opção A** diz que é "só quando uma ferramenta quebra". Não é verdade! Se a ferramenta der erro, isso é um "evento de erro", não uma notificação. São coisas diferentes.\n\n- **Opção C** diz que é "toda vez que você manda uma mensagem". Também não! Quando você envia uma mensagem, é um "evento de mensagem", não uma notificação.\n\n- **Opção D** diz que é "quando o CLAUDE.md é lido". Isso é como o robô lendo o manual de instruções dele, o que acontece no começo. Não é uma notificação.\n\nEntão a resposta certa é a **letra B**: o Notification acontece quando o Claude precisa de permissão para usar uma ferramenta OU quando fica 60 segundos sem fazer nada.','\n',char(10)));
INSERT INTO cards VALUES('admin','card_1783092987544_0o5cwm5jz',281,'Structurally, what defines an Agent Skill?',replace('Structurally, what defines an Agent Skill?\n\nStructurally, what defines an Agent Skill?\n[Resposta correta: Um Agent Skill é uma pasta com SKILL.md, cujo frontmatter tem name e description e cujo corpo traz as instruções. A A erra o nome do arquivo e o local; C e D descrevem outras features.]\n\n[ ] A - A skill.md file at the root of the skills directory\n[ ] B - A folder containing a SKILL.md, with frontmatter (name, description) and the instructions below\n[ ] C - An entry in settings.json with the skill field\n[ ] D - A command registered via claude mcp add','\n',char(10)),'B - A folder containing a SKILL.md, with frontmatter (name, description) and the instructions below','["Domain_3::Claude_Code_Configuration_Workflows", "Scenario_2::Code_Generation_Claude_Code"]','New',0,2.5,0,1783092987544,1783727284895,1783203558653,replace('Tradução para português do Brasil:\n\n**Pergunta:** Estruturalmente, o que define um Agent Skill?\n\n[ ] A - Um arquivo skill.md na raiz do diretório de skills\n[ ] B - Uma pasta contendo um SKILL.md, com frontmatter (nome, descrição) e as instruções abaixo\n[ ] C - Uma entrada no settings.json com o campo skill\n[ ] D - Um comando registrado via claude mcp add','\n',char(10)),replace('Explicação didática para adulto (tech lead):\n\nA resposta correta é a **alternativa B**.\n\nUm Agent Skill, no ecossistema Claude Code (e ferramentas similares), é definido estruturalmente como um *diretório* (pasta) que contém um arquivo chamado `SKILL.md`. Esse arquivo possui duas partes fundamentais:\n\n1. **Frontmatter (metadados YAML):** contém obrigatoriamente os campos `name` (nome do skill) e `description` (descrição do que ele faz). Esses metadados são usados pelo sistema para indexar, listar e "descobrir" o skill.\n2. **Corpo (body):** abaixo do frontmatter, as instruções propriamente ditas (o prompt/instruções que definem o comportamento do skill).\n\nPor que as demais alternativas estão incorretas?\n\n- **A** - Erra ao mencionar "skill.md" (minúsculo, em vez de SKILL.md maiúsculo) e ao dizer que o arquivo fica "na raiz do diretório de skills". Na verdade, é uma *pasta* contendo o SKILL.md, não um arquivo solto.\n- **C** - Descreve uma configuração via settings.json com campo "skill". Skills não são definidos por uma entrada em settings.json; são definidos estruturalmente por pastas e arquivos SKILL.md. Settings.json pode referenciar skills, mas não os define.\n- **D** - Descreve um comando registrado via `claude mcp add`. Isso se refere ao MCP (Model Context Protocol) e à adição de ferramentas/servidores MCP, não à definição estrutural de um Agent Skill. São conceitos diferentes.','\n',char(10)),replace('Explicação para criança de 10 anos:\n\nImagine que você tem um caderno de receitas. Cada receita precisa de uma página com o nome da receita e uma explicação de como fazer.\n\nUm Agent Skill é como uma dessas receitas. A alternativa B diz que o Skill é uma pasta (como uma gaveta) que tem um arquivo chamado SKILL.md (como uma ficha de receita). Nessa ficha, na parte de cima, escrevemos o nome e o que o Skill faz (frontmatter). Embaixo, escrevemos as instruções de como ele funciona.\n\nAs outras opções estão erradas assim:\n- A: diz que é só um arquivo jogado na pasta principal, mas não é assim que funciona.\n- C: diz que é uma anotação num arquivo de configuração, mas isso não define o Skill.\n- D: fala de um comando de computador, que é outra coisa totalmente diferente.\n\nEntão, a resposta certa é a **B**!','\n',char(10)));
INSERT INTO cards VALUES('admin','card_1783092987561_rylxuhne0',282,'Why does the stdin format make writing hooks challenging?',replace('Why does the stdin format make writing hooks challenging?\n\nWhy does the stdin format make writing hooks challenging?\n[Resposta correta: A estrutura do stdin varia por tipo de hook e, em Pre/PostToolUse, o tool_input muda conforme a tool chamada. As demais afirmações sobre o formato são incorretas.]\n\n[ ] A - The stdin is always binary and needs manual decoding\n[ ] B - The input changes according to the hook type and, in Pre/PostToolUse, the tool_input still varies according to the tool\n[ ] C - The stdin only accepts plain text, never JSON\n[ ] D - The format is fixed and identical for all hooks, which is confusing','\n',char(10)),'B - The input changes according to the hook type and, in Pre/PostToolUse, the tool_input still varies according to the tool','["Domain_3::Claude_Code_Configuration_Workflows", "Domain_4::Prompt_Engineering_Structured_Output", "Scenario_2::Code_Generation_Claude_Code"]','New',0,2.5,0,1783092987561,1783727288308,1783203558653,replace('**Tradução para português do Brasil:**\n\nPor que o formato stdin torna a escrita de hooks desafiadora?\n\n[ ] A - O stdin é sempre binário e precisa de decodificação manual\n[ ] B - A entrada varia conforme o tipo de hook e, em Pre/PostToolUse, o tool_input ainda varia de acordo com a tool\n[ ] C - O stdin aceita apenas texto puro, nunca JSON\n[ ] D - O formato é fixo e idêntico para todos os hooks, o que é confuso','\n',char(10)),replace('**Explicação didática para adulto (tech lead):**\n\nA alternativa **B** é a correta. O desafio de escrever hooks usando stdin reside no fato de que o formato da entrada não é uniforme — ele muda **por tipo de hook**. Por exemplo, hooks como `PreUpload` e `PostUpload` têm estruturas de entrada diferentes entre si. Além disso, dentro do tipo `Pre/PostToolUse`, o campo `tool_input` varia conforme a **ferramenta específica** que está sendo chamada (ex.: uma tool de busca tem parâmetros diferentes de uma tool de cálculo). Isso significa que o desenvolvedor precisa:\n\n- Conhecer o schema específico de cada hook type;\n- Lidar com a variabilidade de `tool_input` dentro de hooks do tipo tool_use;\n- Tratar a entrada de forma dinâmica, sem poder assumir um formato fixo.\n\nAs demais alternativas estão incorretas pelos seguintes motivos:\n\n- **A**: Falsa. O stdin não é binário; ele geralmente recebe dados textuais (JSON). Não há "decodificação manual" envolvida.\n- **C**: Falsa. O stdin aceita JSON perfeitamente — na verdade, a maioria dos hooks utiliza JSON como formato de entrada.\n- **D**: Falsa. O formato não é fixo nem idêntico; justamente o contrário: ele varia, e essa variação é a fonte da dificuldade.','\n',char(10)),replace('Imagine que você tem vários tipos de brinquedos, e cada um vem com um manual diferente. Um é um quebra-cabeça, outro um carrinho de montar. Se você tentar usar o manual do quebra-cabeça para montar o carrinho, não vai funcionar!\n\nEscrever hooks (que são como "ajudantes" de um programa) é parecido: o stdin (um jeito de receber informações) muda de formato dependendo do tipo de hook. E, dentro de um tipo específico, o conteúdo ainda muda conforme a ferramenta usada. Isso complica porque o programador precisa saber qual "manual" usar a cada momento.\n\nAs outras opções estão erradas porque:\n- A: Não é "binário" (coisa de computador em 0s e 1s) — é texto normal.\n- C: Aceita sim JSON (um formato organizado de dados), não só texto simples.\n- D: Não é fixo e igual para todos — se fosse, seria fácil, mas justamente muda o tempo todo.','\n',char(10)));
INSERT INTO cards VALUES('admin','card_1783092987577_vvefgp4ot',283,'Which technique helps discover the real structure of a hook''s input?',replace('Which technique helps discover the real structure of a hook''s input?\n\nWhich technique helps discover the real structure of a hook''s input?\n[Resposta correta: Um hook helper com matcher * e jq . gravando em arquivo mostra exatamente os dados que chegam pelo stdin. As demais não capturam a estrutura real do input do hook.]\n\n[ ] A - Run claude --debug and read the CLAUDE.md\n[ ] B - Create a helper hook with matcher * and a command like jq . > post-log.json to write the input to a file\n[ ] C - Consult the CLAUDE_HEADLESS variable\n[ ] D - Add @input to the CLAUDE.md','\n',char(10)),'B - Create a helper hook with matcher * and a command like jq . > post-log.json to write the input to a file','["Domain_3::Claude_Code_Configuration_Workflows", "Domain_2::Tool_Design_MCP_Integration", "Scenario_2::Code_Generation_Claude_Code"]','New',0,2.5,0,1783092987577,1783727291620,1783203558653,replace('**Tradução para português do Brasil:**\n\n**Pergunta:** Qual técnica ajuda a descobrir a estrutura real da entrada (input) de um hook?\n\n**Alternativas:**\n\n[ ] A - Executar claude --debug e ler o CLAUDE.md\n[ ] B - Criar um hook auxiliar com matcher * e um comando como jq . > post-log.json para gravar a entrada em um arquivo\n[ ] C - Consultar a variável CLAUDE_HEADLESS\n[ ] D - Adicionar @input ao CLAUDE.md','\n',char(10)),replace('**Explicação para um adulto tech lead:**\n\nA resposta correta é a **alternativa B**.\n\n**Por que a B está correta:**\n\nQuando você está desenvolvendo hooks para o Claude Code (ou qualquer sistema baseado em hooks), muitas vezes você precisa entender exatamente qual é a estrutura dos dados que estão sendo passados para o hook via stdin. Criar um hook auxiliar com um matcher universal (`*` — que captura todos os eventos) e um comando como `jq . > post-log.json` faz exatamente isso: ele recebe o payload completo do hook (em JSON) e o escreve em um arquivo de log. Isso permite que você inspecione a estrutura real, campos disponíveis, tipos de dados, etc. É uma técnica de debugging extremamente útil e direta.\n\n**Por que as demais estão erradas:**\n\n- **Alternativa A** — `claude --debug` pode fornecer informações de depuração, mas o `CLAUDE.md` é um arquivo de configuração/memória do Claude, não um dump dos dados de entrada do hook. A alternativa não explica como capturar a estrutura do input.\n\n- **Alternativa C** — `CLAUDE_HEADLESS` é uma variável de ambiente que provavelmente indica se o Claude está rodando em modo headless (sem interface gráfica). Ela não tem relação com a inspeção da estrutura de dados de um hook.\n\n- **Alternativa D** — Adicionar `@input` ao `CLAUDE.md` não é uma funcionalidade real ou documentada para inspeção de hooks. O `CLAUDE.md` não processa anotações mágicas para revelar estruturas de dados de hooks.','\n',char(10)),replace('Imagine que você tem uma caixa mágica que recebe presentes (dados), mas você não sabe o que tem dentro. A técnica certa é criar um "espião" que anota tudo que chega dentro da caixa.\n\nA alternativa B diz: crie um hook ajudante que use um "matcher *" (que é como dizer "espione tudo") e um comando que escreva tudo que chega em um arquivo. Assim, você pode abrir o arquivo depois e ver exatamente o que estava dentro — é como filmar o que entra na caixa para assistir depois.\n\nAs outras opções não funcionam porque:\n- A: é como perguntar para o próprio brinquedo o que ele recebeu — ele não sabe.\n- C: é uma variável de ambiente que não mostra o conteúdo do hook.\n- D: é como escrever um bilhete na parede e esperar que ele se revele — não faz sentido.','\n',char(10)));
INSERT INTO cards VALUES('admin','card_1783092987594_apviluo60',284,'How does Claude decide whether to apply a skill to a request?',replace('How does Claude decide whether to apply a skill to a request?\n\nHow does Claude decide whether to apply a skill to a request?\n[Resposta correta: O Claude compara semanticamente a requisição com a description de cada skill e ativa as que casam. As demais descrevem comportamentos que não correspondem ao matching por description.]\n\n[ ] A - It applies all available skills on every request\n[ ] B - It compares the request semantically against each skill''s description and activates the ones that match\n[ ] C - It applies in alphabetical order of the directories\n[ ] D - It only applies when the skill is referenced with @','\n',char(10)),'[ ] B - It compares the request semantically against each skill''s description and activates the ones that match','["Domain_3::Claude_Code_Configuration_Workflows", "Scenario_2::Code_Generation_Claude_Code"]','New',0,2.5,0,1783092987594,1783727294724,1783203558653,replace('**Tradução da pergunta e alternativas:**\n\n**Pergunta:** Como o Claude decide se deve aplicar uma skill a uma requisição?\n\n**Alternativas:**\n\n[ ] A - Ele aplica todas as skills disponíveis em todas as requisições\n\n[ ] B - Ele compara semanticamente a requisição com a descrição de cada skill e ativa as que correspondem\n\n[ ] C - Ele aplica em ordem alfabética dos diretórios\n\n[ ] D - Ele só aplica quando a skill é referenciada com @','\n',char(10)),replace('**Explicação didática para adulto (tech lead):**\n\n**Resposta correta: B**\n\nO Claude, ao receber uma requisição, realiza um processo de *semantic matching* entre o conteúdo da requisição do usuário e a `description` definida em cada skill. Esse matching é baseado em similaridade semântica (não lexical exata), permitindo que a skill seja ativada mesmo que o usuário use sinônimos ou paráfrases.\n\n**Por que as demais estão incorretas:**\n\n- **A** - Se todas as skills fossem aplicadas em todas as requisições, haveria conflitos de instruções, consumo desnecessário de tokens e possíveis comportamentos contraditórios. O sistema foi projetado para ser seletivo.\n\n- **C** - A ordem alfabética dos diretórios não é critério de seleção. A organização em diretórios é apenas estrutural/namespacing, não funcional para matching.\n\n- **D** - A anotação `@` é uma forma de referenciar skills em ferramentas como o GitHub Copilot ou agents, mas não é o mecanismo padrão de ativação no core do Claude. O matching por description é o mecanismo principal.','\n',char(10)),replace('**Explicação para uma criança de 10 anos:**\n\nImagina que o Claude é um robô assistente que tem vários "livrinhos de instruções" — cada livrinho é uma skill. Um livrinho ensina a fazer bolo, outro ensina a somar números, outro ensina a desenhar.\n\nQuando você pede algo para o Claude, ele lê o seu pedido e pensa: "Qual desses livrinhos combina com o que a criança está pedindo?"\n\nSe você pede "me ajuda a fazer um bolo de chocolate", o Claude compara o seu pedido com a descrição de cada livrinho. O livrinho de culinária tem a descrição "ensina receitas de doces e bolos" — isso combina! Então ele ativa esse livrinho. O livrinho de matemática não combina, então ele não usa.\n\nA alternativa B diz exatamente isso: ele **compara o sentido do seu pedido com a descrição de cada skill** e ativa só as que fazem sentido.\n\nAs outras alternativas estão erradas porque:\n- A: usar todos os livrinhos ao mesmo tempo seria uma bagunça!\n- C: a ordem do nome dos livrinhos não importa.\n- D: ele não precisa que você grite o nome do livrinho com @ — ele entende pelo sentido do que você fala.','\n',char(10)));
INSERT INTO cards VALUES('admin','card_1783092987611_wibvzzr2d',285,'You want a rule to apply in all conversations of the project (e.',replace('You want a rule to apply in all conversations of the project (e.\n\nYou want a rule to apply in all conversations of the project (e.g. always TypeScript strict). Where do you put it?\n[Resposta correta: CLAUDE.md é always-on, ideal para algo que deve valer sempre. Skills carregam sob demanda; hook é event-driven; comando exige invocação, nenhum garante regra sempre-ativa.]\n\n[ ] A - In a skill, since it loads on demand\n[ ] B - In the CLAUDE.md, since it is loaded in every conversation\n[ ] C - In a PostToolUse hook\n[ ] D - In .claude/commands/, invoked by slash','\n',char(10)),'B - In the CLAUDE.md, since it is loaded in every conversation','["Domain_3::Claude_Code_Configuration_Workflows", "Domain_5::Context_Management_Reliability", "Scenario_2::Code_Generation_Claude_Code"]','New',0,2.5,0,1783092987612,1783727298002,1783203558653,replace('**Tradução para português do Brasil:**\n\nVocê quer que uma regra se aplique em todas as conversas do projeto (ex.: sempre usar TypeScript strict). Onde você a coloca?\n\n[ ] A - Em uma skill, pois ela carrega sob demanda\n[ ] B - No CLAUDE.md, pois ele é carregado em todas as conversas\n[ ] C - Em um hook PostToolUse\n[ ] D - Em .claude/commands/, invocado por barra','\n',char(10)),replace('**Explicação didática para um adulto tech lead:**\n\nA pergunta trata de onde configurar uma regra global — algo como "sempre usar TypeScript strict" — para que seja aplicada consistentemente em **todas as conversas** de um projeto no ambiente Claude (seja Claude Desktop, Claude Code ou similar).\n\n- **Alternativa A (Skill):** Incorreta. Skills são como "plugins" ou "habilidades" que podem ser carregadas sob demanda, geralmente ativadas quando o contexto ou a tarefa específica as exige. Elas não são acionadas automaticamente em toda conversa; cabe ao usuário ou ao sistema carregá-las conforme necessário. Portanto, não garantem que a regra esteja presente em 100% das conversas.\n\n- **Alternativa B (CLAUDE.md):** Correta. O arquivo `CLAUDE.md` (ou `CLAUDE.md` na raiz do projeto) é um arquivo de configuração/projeto que é lido e processado no início de **toda conversa** que envolve aquele diretório. Ele funciona como uma "constituição" do projeto, definindo regras, preferências e diretrizes que valem sempre. É o lugar ideal para regras permanentes como "TypeScript strict deve ser habilitado". É "always-on" por design.\n\n- **Alternativa C (PostToolUse hook):** Incorreta. Hooks como `PostToolUse` são eventos disparados **após** o uso de uma ferramenta (tool). Eles são acionados por eventos específicos, não são carregados automaticamente em toda conversa. Servem para reações a ações, não para regras permanentes. Além disso, um hook precisa ser configurado e nem toda conversa necessariamente passa por ele.\n\n- **Alternativa D (.claude/commands/):** Incorreta. Comandos em `.claude/commands/` são acionados via barra (slash commands), como `/meu-comando`. Eles exigem **invocação explícita** pelo usuário. Não há garantia de que o usuário se lembre de digitar o comando toda vez. Portanto, não servem para uma regra que deve valer sempre, sem depender de ação manual.\n\n**Conclusão:** O `CLAUDE.md` é o único mecanismo que garante aplicação automática e consistente da regra em todas as conversas do projeto. As demais alternativas dependem de carga sob demanda, eventos específicos ou invocação explícita.','\n',char(10)),replace('Imagine que você tem um caderno de regras para um jogo. Você quer que uma regra — tipo "sempre usar lápis azul" — valha para TODAS as partidas que você jogar.\n\n- Se você colocar a regra em um **"poder especial"** (skill), ele só funciona quando você lembra de ativá-lo. Nem toda partida vai ter o poder ligado. ❌\n- Se você colocar a regra na **primeira página do caderno** (CLAUDE.md), toda vez que você abre o caderno ela já está lá, valendo para o jogo inteiro. ✅\n- Se você colocar a regra em um **alarme que toca depois de você fazer algo** (hook), ele só aparece depois de uma ação específica. Não funciona desde o começo. ❌\n- Se você colocar a regra em um **comando secreto** que você precisa falar em voz alta (slash command), você precisa lembrar de dizer o comando toda vez. Se esquecer, a regra não vale. ❌\n\nEntão, a melhor opção é colocar a regra no **CLAUDE.md**, porque ele está sempre ligado, como a primeira página do caderno de regras que você lê antes de qualquer partida!','\n',char(10)));
INSERT INTO cards VALUES('admin','card_1783092987629_yfyhecvk1',286,'You repeat an instruction (e.',replace('You repeat an instruction (e.\n\nYou repeat an instruction (e.g. PR review format) only when doing that specific task. Which tool do you use?\n[Resposta correta: Uma skill carrega sob demanda quando a requisição casa, sem poluir as outras conversas. CLAUDE.md ficaria sempre carregado; hook é por evento; regra por glob é por caminho de arquivo.]\n\n[ ] A - CLAUDE.md, to stay always loaded\n[ ] B - A skill, which loads on demand when the request matches\n[ ] C - A SessionStart hook\n[ ] D - A rule in .claude/rules/ by glob','\n',char(10)),'B - A skill, which loads on demand when the request matches','["Domain_3::Claude_Code_Configuration_Workflows", "Scenario_2::Code_Generation_Claude_Code"]','New',0,2.5,0,1783092987629,1783727300961,1783203558653,replace('**Tradução para Português do Brasil:**\n\nVocê repete uma instrução (ex.: formato de revisão de PR) somente quando está fazendo aquela tarefa específica. Qual ferramenta você usa?\n\n[ ] A - CLAUDE.md, para ficar sempre carregado\n[ ] B - Uma skill, que carrega sob demanda quando a requisição corresponde\n[ ] C - Um hook SessionStart\n[ ] D - Uma regra em .claude/rules/ por glob','\n',char(10)),replace('**Explicação para adulto (tech lead):**\n\nA pergunta trata de um cenário específico: você tem uma instrução que deve ser aplicada apenas quando você está realizando uma determinada tarefa (no exemplo, revisar um PR). Você não quer que essa instrução polua ou influencie conversas que não têm relação com aquela tarefa.\n\n**Alternativa correta: B - Uma skill.**\n\nSkills são artefatos que carregam instruções, prompts ou ferramentas sob demanda. Elas são ativadas apenas quando o contexto da conversa corresponde ao gatilho definido para aquela skill. Isso significa que você pode ter uma skill específica para "revisão de PR" que só será carregada quando você estiver de fato revisando um PR, sem interferir em outras conversas.\n\n**Por que as demais estão incorretas:**\n\n- **A - CLAUDE.md**: O arquivo CLAUDE.md fica sempre carregado em todas as conversas. Ele é útil para instruções globais e persistentes, mas justamente por estar sempre presente, ele "polui" conversas onde aquela instrução não é relevante. O enunciado diz explicitamente "sem poluir as outras conversas", o que descarta o CLAUDE.md.\n\n- **C - Um hook SessionStart**: Hooks são executados com base em eventos (no caso, o início de uma sessão). Embora possam ser usados para carregar instruções condicionalmente, eles são acionados por eventos, não por correspondência de conteúdo/requisição. Eles não são a ferramenta projetada para o cenário descrito de "carregar sob demanda quando a requisição casa".\n\n- **D - Uma regra em .claude/rules/ por glob**: Regras por glob são aplicadas com base no caminho do arquivo sendo trabalhado. Elas são úteis para aplicar instruções específicas a determinados tipos de arquivo ou diretórios, mas não são acionadas por "requisição" ou conteúdo de conversa. O escopo delas é o sistema de arquivos, não o contexto da conversa.','\n',char(10)),replace('Imagine que você tem várias tarefas para fazer: lição de casa, arrumar o quarto, ajudar na cozinha. Para arrumar o quarto, você precisa de uma lista de instruções (como "dobrar as roupas", "guardar os brinquedos"). Você só quer ver essa lista quando estiver arrumando o quarto, certo? Não adianta nada ver a lista da cozinha enquanto você está no quarto, isso só atrapalha!\n\nÉ a mesma coisa com o assistente de IA. Se ele tem uma instrução especial só para revisar código (como revisar um PR), ele só deve usar essa instrução quando estiver fazendo essa tarefa.\n\nA resposta certa é a **letra B - Uma skill (uma "habilidade")**. É como se fosse um livro de regras que só abre quando você precisa dele. As outras opções:\n- A (CLAUDE.md) é como uma regra que fica o tempo todo, atrapalhando quando não precisa.\n- C (hook) é como um alarme que toca quando algo acontece, mas não é o melhor para escolher a instrução certa na hora certa.\n- D (regra por glob) é como uma regra que depende do nome do arquivo, não do que você está fazendo.\n\nEntão, a melhor ferramenta para "usar uma instrução só quando estiver fazendo aquela tarefa" é a **skill**!','\n',char(10)));
INSERT INTO cards VALUES('admin','card_1783092987646_meu5v736q',287,'Why do skills not fill the context window like the CLAUDE.',replace('Why do skills not fill the context window like the CLAUDE.\n\nWhy do skills not fill the context window like the CLAUDE.md?\n[Resposta correta: Só name e description ficam carregados até a skill ser ativada, quando o SKILL.md completo entra no contexto. A A é falsa (skills entram no contexto quando ativadas); a C contraria o comportamento do CLAUDE.md; a D é inventada.]\n\n[ ] A - Because skills never enter the context, they only run scripts\n[ ] B - Because initially only name and description are loaded; the full SKILL.md enters only when the skill is activated\n[ ] C - Because the CLAUDE.md also only loads on demand\n[ ] D - Because skills are stored on an external server','\n',char(10)),'B - Because initially only name and description are loaded; the full SKILL.md enters only when the skill is activated','["Domain_3::Claude_Code_Configuration_Workflows", "Domain_5::Context_Management_Reliability", "Scenario_2::Code_Generation_Claude_Code"]','New',0,2.5,0,1783092987646,1783727304511,1783203558653,replace('**Tradução para português do Brasil:**\n\n**Pergunta:** Por que as skills (habilidades) não preenchem a janela de contexto como o CLAUDE.md?\n\n**Alternativas:**\n\n[ ] A - Porque as skills nunca entram no contexto, elas apenas executam scripts\n[ ] B - Porque inicialmente apenas nome e descrição são carregados; o SKILL.md completo entra apenas quando a skill é ativada\n[ ] C - Porque o CLAUDE.md também só carrega sob demanda\n[ ] D - Porque as skills são armazenadas em um servidor externo','\n',char(10)),replace('**Explicação para um adulto (tech lead):**\n\nA pergunta aborda um detalhe importante de arquitetura de sistemas de IA conversacional com suporte a plugins/skills: o gerenciamento eficiente da janela de contexto.\n\nA alternativa **B** é a correta. A arquitetura funciona com um mecanismo de carregamento sob demanda ("lazy loading"). Inicialmente, apenas os metadados essenciais da skill (nome e descrição) são injetados no prompt. Isso serve como um índice ou sumário, permitindo que o modelo saiba que aquela skill existe e para que serve, sem consumir tokens preciosos com seu conteúdo completo. Apenas quando o modelo decide ativar a skill (por exemplo, o usuário faz uma pergunta que corresponde à descrição dela), o conteúdo integral do arquivo SKILL.md é carregado na janela de contexto. Esse design é análogo a um sistema de páginas de memória virtual: você mantém apenas a tabela de páginas (name/description) carregada, e faz o page fault (ativação da skill) para trazer a página (SKILL.md completo) para a memória principal (contexto).\n\n**Análise das alternativas incorretas:**\n\n- **A:** É falsa. Skills podem sim entrar no contexto quando ativadas. A afirmação de que "nunca entram no contexto" contradiz o propósito delas, que é justamente fornecer instruções ou dados para o modelo utilizar durante a conversa.\n\n- **C:** É uma afirmação incorreta. O CLAUDE.md (geralmente um arquivo de instruções/base de conhecimento do projeto) se comporta de forma oposta: ele é carregado **integralmente** no início da conversa, ocupando a janela de contexto desde o primeiro turno. Dizer que ele "também só carrega sob demanda" contraria o comportamento real e o motivo da pergunta (que contrasta skills com CLAUDE.md).\n\n- **D:** É uma afirmação inventada e sem fundamento. A localização física do armazenamento (servidor externo vs. local) não tem relação com a política de carregamento na janela de contexto. A pergunta é sobre *quando* e *como* o conteúdo é carregado, não *onde* ele está armazenado.','\n',char(10)),replace('**Explicação para uma criança de 10 anos:**\n\nImagina que você tem uma mochila (a "janela de contexto") que só cabe uma quantidade limitada de coisas. Dentro dessa mochila, você tem um caderno chamado CLAUDE.md, que você coloca inteiro na mochila desde o começo do dia.\n\nAgora, você também tem vários outros livros de receitas, que são as "skills". Se você colocasse todos os livros de receitas inteiros na mochila, ela ia ficar cheia e não caberia mais nada! Por isso, você só coloca na mochila uma etiqueta com o nome do livro e uma frase dizendo o que tem nele (por exemplo: "Livro de receitas de bolo"). Só quando você realmente quer fazer um bolo é que você tira o livro inteiro da estante e coloca na mochila.\n\nA alternativa errada A diz que os livros de receita nunca entram na mochila - mas isso não é verdade, eles entram quando você precisa deles! A C diz que o caderno CLAUDE.md também só é pego na hora, mas não é: ele já vem na mochila desde o início. A D diz que é porque os livros estão guardados em outra casa - mas o problema não é onde eles estão, e sim como você decide o que colocar na mochila.','\n',char(10)));
INSERT INTO cards VALUES('admin','card_1783092987662_7itsez5ya',288,'What is the difference in trigger between a skill and a slash command?',replace('What is the difference in trigger between a skill and a slash command?\n\nWhat is the difference in trigger between a skill and a slash command?\n[Resposta correta: Slash commands precisam ser digitados; skills ativam automaticamente e também podem ser chamadas por /skill-name. A A e a D erram os gatilhos; a C nega a invocação manual da skill.]\n\n[ ] A - Both require explicit typed invocation\n[ ] B - Slash commands require explicit invocation; skills activate automatically (and can also be invoked via /skill-name)\n[ ] C - Skills only activate automatically and can never be invoked manually\n[ ] D - Slash commands activate automatically and skills require typing','\n',char(10)),'B - Slash commands require explicit invocation; skills activate automatically (and can also be invoked via /skill-name)','["Domain_3::Claude_Code_Configuration_Workflows", "Scenario_2::Code_Generation_Claude_Code"]','New',0,2.5,0,1783092987662,1783727307304,1783203558653,replace('**Tradução para português do Brasil:**\n\nQual é a diferença no gatilho (ou "disparo") entre uma skill e um slash command?\n\n[ ] A - Ambos exigem invocação explícita digitada\n[ ] B - Slash commands exigem invocação explícita; skills ativam automaticamente (e também podem ser invocadas via /skill-name)\n[ ] C - Skills ativam apenas automaticamente e nunca podem ser invocadas manualmente\n[ ] D - Slash commands ativam automaticamente e skills exigem digitação','\n',char(10)),replace('**Explicação para um adulto tech lead:**\n\nA diferença fundamental entre skills e slash commands está no mecanismo de disparo (trigger).\n\n- **Slash commands** são comandos que exigem que o usuário os digite explicitamente (ex.: `/help`, `/deploy`). Não há ativação automática — o usuário precisa intencionalmente invocá-los.\n- **Skills**, por outro lado, são projetadas para ativação automática. Elas são tipicamente acionadas por eventos ou condições específicas (como o padrão de uma mensagem, mudança de estado, etc.). Além disso, muitas plataformas permitem que skills também sejam invocadas manualmente através de um prefixo como `/skill-name`, oferecendo um fallback para invocação explícita.\n\n**Análise das alternativas:**\n\n- **A - Incorreta:** Afirma que ambos exigem digitação explícita, o que é falso para skills (que têm ativação automática).\n- **B - Correta:** Descreve com precisão a diferença: slash commands exigem invocação explícita, skills ativam automaticamente mas também podem ser chamadas via `/skill-name`.\n- **C - Incorreta:** Diz que skills nunca podem ser invocadas manualmente, o que é falso — muitas implementações permitem invocação manual via `/skill-name`.\n- **D - Incorreta:** Inverte a relação, afirmando que slash commands ativam automaticamente e skills exigem digitação, o que é o oposto do comportamento real.','\n',char(10)),replace('**Explicação para uma criança de 10 anos:**\n\nImagine que você tem dois tipos de ajudantes:\n\n1. **Slash command** é como um amigo que só faz algo se você chamar pelo nome. Você precisa digitar o comando (como `/ajuda`) para ele agir.\n2. **Skill** é como um robô inteligente que já fica de olho no que acontece e age sozinho quando percebe que é necessário. Mas, se você quiser, também pode chamá-lo pelo nome (como `/skill-nome`) para pedir ajuda.\n\nA alternativa **B** está certa porque diz que:\n- Slash commands: você precisa chamar.\n- Skills: agem sozinhas, mas você também pode chamar se quiser.\n\nAs outras estão erradas porque misturam tudo ou dizem o contrário do que realmente acontece!','\n',char(10)));
INSERT INTO cards VALUES('admin','card_1783092987679_2m8t2afe7',289,'Where are personal skills stored and what is their scope?',replace('Where are personal skills stored and what is their scope?\n\nWhere are personal skills stored and what is their scope?\n[Resposta correta: Skills pessoais ficam em ~/.claude/skills e acompanham o usuário em todos os projetos. .claude/skills é escopo de projeto; workflows e settings.local.json não guardam skills.]\n\n[ ] A - In the repository''s .claude/skills, shared with the team\n[ ] B - In ~/.claude/skills, following you across all projects\n[ ] C - In .github/workflows, applied via Actions\n[ ] D - In settings.local.json, per project','\n',char(10)),'B - In ~/.claude/skills, following you across all projects','["Domain_3::Claude_Code_Configuration_Workflows", "Scenario_2::Code_Generation_Claude_Code"]','New',0,2.5,0,1783092987679,1783727310387,1783203558653,replace('**Tradução para português do Brasil:**\n\nOnde as skills pessoais são armazenadas e qual é seu escopo?\n\n[ ] A - No .claude/skills do repositório, compartilhado com a equipe\n[ ] B - Em ~/.claude/skills, acompanhando você em todos os projetos\n[ ] C - Em .github/workflows, aplicado via Actions\n[ ] D - Em settings.local.json, por projeto','\n',char(10)),replace('**Explicação para um adulto (tech lead):**\n\nA pergunta trata do mecanismo de "personal skills" no ecossistema Claude (provavelmente Claude Code ou ferramenta similar da Anthropic). A resposta correta é a **alternativa B**.\n\n**Por que B está correta:**  \nSkills pessoais são armazenadas no diretório home do usuário (`~/.claude/skills`) e têm escopo global — ou seja, estão disponíveis em qualquer projeto que você abrir no Claude. Esse comportamento é análogo a arquivos de configuração global como `~/.gitconfig` ou `~/.bashrc`: são seus, não do projeto. Isso permite que você defina instruções, preferências ou comportamentos padrão que deseja que o Claude siga independentemente do contexto do projeto.\n\n**Por que as demais estão incorretas:**\n\n- **A** (`repository''s .claude/skills`): Esse caminho (`<repo>/.claude/skills`) é justamente o oposto — trata-se de skills com **escopo de projeto** (shared with the team). Skills pessoais não ficam no repositório; se ficassem, seriam versionadas e compartilhadas com toda a equipe via Git, o que vai contra o conceito de "pessoal".\n\n- **C** (`.github/workflows`): Workflows do GitHub Actions são para automação de CI/CD (build, testes, deploy). Não têm relação alguma com armazenamento de skills. É uma distração técnica.\n\n- **D** (`settings.local.json`): Embora `settings.local.json` (provavelmente dentro de `.claude/`) contenha configurações locais do projeto, ele não armazena skills. Além disso, o enunciado da resposta correta já antecipa: "workflows e settings.local.json não guardam skills".\n\n**Resumo técnico:**  \n- **Skills pessoais** → `~/.claude/skills` → escopo: global (todos os projetos)  \n- **Skills de projeto** → `<repo>/.claude/skills` → escopo: projeto (compartilhado via Git)  \n- **Config local** → `<repo>/.claude/settings.local.json` → escopo: projeto (ignorado pelo Git)  \n- **Workflows** → `.github/workflows/*.yml` → CI/CD, sem relação com skills','\n',char(10)),replace('Imagine que você tem uma mochila mágica que vai com você para qualquer lugar. Dentro dessa mochila, você guarda seus cadernos com as suas anotações pessoais — coisas que só você usa, como seu jeito preferido de resolver problemas. Essa mochila é a pasta `~/.claude/skills`. Onde quer que você vá (qualquer projeto), suas anotações pessoais estão lá.\n\nAgora, seus amigos também têm uma pasta de projeto, dentro da casa do projeto (`<repo>/.claude/skills`). Essa pasta é para coisas que todo mundo do time usa. Se você guardasse algo só seu ali, todo mundo veria — e não é legal porque é pessoal.\n\nEntão, a alternativa B está certa: skills pessoais ficam na sua mochila global (`~/.claude/skills`) e te acompanham em todos os projetos. As outras alternativas estão erradas:\n- A diz que fica no repositório, mas aí todo mundo vê (não é pessoal).\n- C fala de workflows, que são tipo robôs que fazem tarefas automáticas — não guardam anotações.\n- D fala de settings.local.json, que é só um bloquinho de configurações, não guarda skills.','\n',char(10)));
INSERT INTO cards VALUES('admin','card_1783092987697_pv08g9w8f',290,'Where are project skills stored and how are they shared?',replace('Where are project skills stored and how are they shared?\n\nWhere are project skills stored and how are they shared?\n[Resposta correta: Skills de projeto ficam em .claude/skills, versionadas, e quem clona o repo as recebe automaticamente. ~/.claude/skills é pessoal; marketplace é para distribuição ampla; CLAUDE.md não guarda skills.]\n\n[ ] A - In ~/.claude/skills, following each user\n[ ] B - In .claude/skills at the repo root, versioned and received by whoever clones\n[ ] C - In a plugin marketplace only\n[ ] D - In the CLAUDE.md, as text','\n',char(10)),'B - In .claude/skills at the repo root, versioned and received by whoever clones','["Domain_3::Claude_Code_Configuration_Workflows", "Scenario_2::Code_Generation_Claude_Code"]','New',0,2.5,0,1783092987697,1783727313396,1783203558653,replace('**Tradução para português do Brasil:**\n\n**Pergunta:** Onde as skills de projeto são armazenadas e como são compartilhadas?\n\n[ ] A - Em ~/.claude/skills, seguindo cada usuário\n[ ] B - Em .claude/skills na raiz do repositório, versionadas e recebidas por quem clonar\n[ ] C - Apenas em um marketplace de plugins\n[ ] D - No CLAUDE.md, como texto','\n',char(10)),replace('**Explicação para um adulto (tech lead):**\n\n**Resposta correta: B**\n\nSkills de projeto ficam no diretório **`.claude/skills`** na raiz do repositório. Esse diretório é versionado (commitado) junto com o código, portanto qualquer pessoa que clonar o repositório recebe automaticamente essas skills. Isso garante que todo o time tenha acesso às mesmas instruções e comportamentos do Claude para aquele projeto específico.\n\n**Por que as demais estão erradas:**\n\n- **A** (`~/.claude/skills`): Esse caminho se refere ao diretório *pessoal* do usuário no sistema. Skills ali são pessoais e não são compartilhadas automaticamente com o time. Não é o local adequado para skills de projeto que precisam ser distribuídas.\n\n- **C** (marketplace de plugins): O marketplace é um mecanismo para distribuição ampla de skills, mas não é o único nem o principal para skills de projeto. Skills locais e versionadas no repositório independem de marketplace.\n\n- **D** (`CLAUDE.md`): O arquivo CLAUDE.md armazena configurações e instruções em texto para o Claude, mas **não guarda skills**. Skills são artefatos binários ou estruturados que ficam no diretório `.claude/skills`, não no CLAUDE.md.','\n',char(10)),replace('Imagine que você está montando um castelo de Lego com seus amigos e cada um tem um manual de instruções diferente. Se cada um seguir seu próprio manual, o castelo fica todo torto!\n\nAgora pensa assim: as "skills" são como receitas mágicas que ensinam o Claude (um robô ajudante) a fazer as coisas do jeito certo para o projeto.\n\n- **Resposta B** é como colocar a receita dentro da caixa do Lego. Quando alguém pega a caixa (clona o repositório), já leva a receita junto. Todo mundo usa a mesma! ✅\n\n- **Resposta A** seria cada amigo guardar a receita no bolso. Só ele tem, ninguém mais vê. ❌\n\n- **Resposta C** seria a receita estar só numa lojinha especial. Você teria que ir até lá comprar. Não dá para todo mundo do time ver fácil. ❌\n\n- **Resposta D** seria você tentar escrever a receita em um post-it grudado na tampa da caixa. Mas a receita verdadeira é grande e complicada, não cabe num post-it. O CLAUDE.md é só um bilhete rápido, não guarda as skills de verdade. ❌\n\nEntão a resposta certa é a **B**: as skills ficam guardadinhas na pasta `.claude/skills` dentro do projeto. Assim quem baixa o projeto já ganha as skills de presente! 🎁','\n',char(10)));
INSERT INTO cards VALUES('admin','card_1783092987739_4h2f52kq8',291,'A code pattern that the whole team must follow in the repo should become a skill of which type?',replace('A code pattern that the whole team must follow in the repo should become a skill of which type?\n\nA code pattern that the whole team must follow in the repo should become a skill of which type?\n[Resposta correta: Skill de projeto (.claude/skills) é versionada e compartilhada com o time. Pessoal ficaria só com você; enterprise vai além do time (organização inteira); README é documentação humana, não instrução para o Claude.]\n\n[ ] A - Personal, in ~/.claude/skills\n[ ] B - Project, in .claude/skills, versioned with the code\n[ ] C - Enterprise, imposed by the entire organization\n[ ] D - None, it should go only in the README','\n',char(10)),'B - Project, in .claude/skills, versioned with the code','["Domain_3::Claude_Code_Configuration_Workflows", "Scenario_2::Code_Generation_Claude_Code"]','New',0,2.5,0,1783092987739,1783727316730,1783203558653,replace('**Tradução para português do Brasil:**\n\nPergunta: Um padrão de código que todo o time deve seguir no repositório deve se tornar uma skill de qual tipo?\n\nAlternativas:\n[ ] A - Pessoal, em ~/.claude/skills\n[ ] B - De projeto, em .claude/skills, versionada com o código\n[ ] C - Corporativa, imposta por toda a organização\n[ ] D - Nenhuma, deve ir apenas no README','\n',char(10)),replace('**Explicação para um adulto tech lead:**\n\nA pergunta trata de onde armazenar skills do Claude — instruções padronizadas que guiam o comportamento do assistente no contexto de um repositório. O cenário descreve um padrão de código que **todo o time** deve seguir. Isso implica que a skill precisa ser versionada, compartilhada e aplicada automaticamente a todos os membros do time que trabalham naquele repositório.\n\n**Alternativa correta: B — Project, in .claude/skills, versioned with the code**\n\nSkills de projeto ficam no diretório `.claude/skills` dentro do próprio repositório. Como estão versionadas com o código, qualquer pessoa que clonar o repositório terá acesso a elas. Isso garante que o time inteiro siga o mesmo padrão, sem depender de configurações individuais. Além disso, o Claude as carrega automaticamente ao ser utilizado no contexto daquele projeto.\n\n**Por que as demais estão incorretas:**\n\n- **A (Pessoal, em ~/.claude/skills):** Skills pessoais ficam apenas na máquina do usuário. Não são compartilhadas com o time. Não atendem ao requisito de "todo o time deve seguir".\n\n- **C (Corporativa/Enterprise):** Skills enterprise são aplicadas a uma organização inteira, o que vai além do escopo de um único time ou repositório. Além disso, geralmente exigem configuração administrativa centralizada e não são versionadas diretamente com o código do projeto.\n\n- **D (Nenhuma, deve ir apenas no README):** README é documentação voltada para leitura humana. Não é uma instrução interpretável pelo Claude. Colocar padrões apenas no README não garante que o Claude siga as regras durante a interação com o código.','\n',char(10)),replace('Imagine que você tem um caderno de regras para fazer um trabalho em grupo com seus amigos. Se cada um tiver suas próprias regras guardadas em casa, ninguém vai saber o que os outros estão fazendo. A melhor ideia é colocar as regras dentro do próprio caderno do trabalho, assim todo mundo vê e segue as mesmas coisas.\n\nAqui é a mesma ideia: o time de programação tem um padrão que todos devem seguir. Colocar esse padrão numa pasta chamada `.claude/skills`, que fica dentro do próprio projeto (como se estivesse no caderno do trabalho), é o melhor jeito, porque todo mundo que pegar o projeto vai ter acesso às regras.\n\nAs outras opções não funcionam bem:\n- Guardar no computador de cada um (pessoal) → só a pessoa vê.\n- Colocar para a empresa inteira (corporativa) → é regra demais, vale para todo mundo, não só para o time.\n- Colocar só no README (um arquivo de instruções) → o README é para pessoas lerem, não para o robô Claude entender e seguir sozinho.','\n',char(10)));
INSERT INTO cards VALUES('admin','card_1783092987757_h4t38tdb8',292,'Which sign indicates that something should become a skill?',replace('Which sign indicates that something should become a skill?\n\nWhich sign indicates that something should become a skill?\n[Resposta correta: Repetir a mesma explicação ao Claude é o sinal de que há uma skill a ser escrita. As demais indicam necessidade de MCP, refatoração do CLAUDE.md ou hook, não skill.]\n\n[ ] A - When the task requires an external tool via MCP\n[ ] B - When you find yourself explaining the same thing to Claude repeatedly\n[ ] C - When the CLAUDE.md grows larger than 500 lines\n[ ] D - When a hook needs to block a tool','\n',char(10)),'B - When you find yourself explaining the same thing to Claude repeatedly','["Domain_3::Claude_Code_Configuration_Workflows", "Domain_4::Prompt_Engineering_Structured_Output", "Scenario_2::Code_Generation_Claude_Code"]','New',0,2.5,0,1783092987757,1783727320051,1783203558653,replace('**Tradução:**\n\nQual sinal indica que algo deve se tornar uma skill?\n\n[ ] A - Quando a tarefa requer uma ferramenta externa via MCP\n[ ] B - Quando você se pega explicando a mesma coisa para o Claude repetidamente\n[ ] C - Quando o CLAUDE.md fica maior que 500 linhas\n[ ] D - Quando um hook precisa bloquear uma ferramenta','\n',char(10)),replace('**Explicação para adulto (tech lead):**\n\nA resposta correta é a **alternativa B**.\n\nSkills no ecossistema Claude (especialmente no contexto do Claude Code) são blocos de instruções reutilizáveis que encapsulam conhecimento ou procedimentos específicos que você ensina ao Claude. O sinal clássico de que algo merece virar uma skill é a **repetição**: se você está sempre explicando o mesmo padrão, convenção, regra de negócio ou fluxo de trabalho para o Claude, isso significa que esse conhecimento deveria ser externalizado em uma skill.\n\n**Análise das demais alternativas:**\n\n- **A (ferramenta externa via MCP):** MCP (Model Context Protocol) é um mecanismo para integrar ferramentas externas ao ecossistema Claude. Se uma tarefa requer uma ferramenta externa, você deve criar ou configurar um MCP server, não uma skill. São conceitos distintos: MCP lida com integração de sistemas; skill lida com instruções e conhecimento reutilizável.\n\n- **C (CLAUDE.md maior que 500 linhas):** Embora um CLAUDE.md muito grande seja um sinal de que algo precisa ser reorganizado (possivelmente extraindo partes para skills), o gatilho direto não é o tamanho do arquivo. O CLAUDE.md serve para instruções gerais e persistentes sobre o projeto; skills são mais específicas e modulares. O sintoma real é a repetição, não uma métrica arbitrária de linhas.\n\n- **D (hook precisa bloquear uma ferramenta):** Hooks são scripts que executam em eventos do ciclo de vida do Claude Code (pré-execução, pós-execução etc.). Se um hook precisa bloquear uma ferramenta, isso é um caso de configuração de hook ou permissão, não uma skill. Skills não são usadas para controle de acesso ou bloqueio de comandos.\n\n**Resumo técnico:** A pergunta testa o entendimento do propósito de skills no ecossistema Claude Code. Skills existem para capturar e reutilizar conhecimento que você ensina repetidamente ao Claude. O padrão "explicar a mesma coisa várias vezes" é o indicador mais forte e direto de que uma skill é necessária.','\n',char(10)),replace('Imagine que você tem um amigo robô, o Claude, que ajuda você a fazer lições de casa. Toda vez que você pede para ele arrumar seu quarto, você precisa explicar de novo: "Primeiro guarde os livros na estante, depois dobre as roupas, depois jogue o lixo fora". Isso é chato, né?\n\nA alternativa B diz: "Quando você percebe que está explicando a mesma coisa para o Claude repetidamente". É exatamente isso! Se você vive repetindo as mesmas instruções, significa que você deveria **ensinar ele de uma vez por todas**, criando uma "skill" — que é como um atalho ou uma receita pronta.\n\nAs outras opções estão erradas porque:\n- **A** é sobre usar ferramentas externas (tipo um aspirador de pó especial), não sobre ensinar.\n- **C** é sobre o arquivo de instruções ter ficado muito grande — isso pode ser um problema, mas não é o principal sinal de que você precisa de uma skill.\n- **D** é sobre impedir que o Claude use alguma ferramenta, que é outra história.\n\nEntão, a resposta certa é a **B**: o sinal é a repetição!','\n',char(10)));
INSERT INTO cards VALUES('admin','card_1783092987776_mhlkz07hg',293,'What are the two parts of a SKILL.',replace('What are the two parts of a SKILL.\n\nWhat are the two parts of a SKILL.md?\n[Resposta correta: O SKILL.md tem o frontmatter (name, description) e, abaixo, as instruções seguidas quando a skill é ativada. As demais descrevem estruturas que não correspondem ao arquivo.]\n\n[ ] A - A JSON header and a YAML body\n[ ] B - The frontmatter (name, description) and, below the dashes, the task instructions\n[ ] C - A block of scripts and a block of permissions\n[ ] D - An imports section and an exports section','\n',char(10)),'B - The frontmatter (name, description) and, below the dashes, the task instructions','["Domain_3::Claude_Code_Configuration_Workflows", "Domain_4::Prompt_Engineering_Structured_Output", "Scenario_2::Code_Generation_Claude_Code"]','New',0,2.5,0,1783092987776,1783727323287,1783203558653,replace('Tradução:\n\nPergunta: Quais são as duas partes de um SKILL?\n\nQuais são as duas partes de um SKILL.md?\n\n[ ] A - Um cabeçalho JSON e um corpo YAML\n[ ] B - O frontmatter (nome, descrição) e, abaixo dos traços, as instruções da tarefa\n[ ] C - Um bloco de scripts e um bloco de permissões\n[ ] D - Uma seção de imports e uma seção de exports','\n',char(10)),replace('Explicação para adulto tech lead:\n\nA pergunta aborda a estrutura do arquivo **SKILL.md**, um conceito comum em plataformas como o GitHub Copilot (Custom Skills) ou assistentes de IA que seguem um formato padronizado para definir habilidades.\n\nA alternativa **B** está correta porque descreve exatamente o formato esperado de um SKILL.md:\n\n- **Frontmatter (metadados)**: um bloco delimitado por `---` no início do arquivo, contendo campos como `name` (nome da skill) e `description` (descrição do propósito da skill), geralmente em YAML.\n- **Instruções da tarefa**: após o segundo `---` (ou após o frontmatter), o restante do arquivo contém as instruções que serão executadas quando a skill for ativada, normalmente escritas em linguagem natural ou em um formato específico da plataforma, como YAML ou Markdown com diretivas.\n\nAs demais alternativas estão incorretas:\n\n- **A**: SKILL.md não utiliza cabeçalho JSON; o frontmatter é tipicamente YAML, e não há um "corpo YAML" separado. A estrutura é frontmatter + body, não JSON + YAML.\n- **C**: Não há separação explícita entre "script" e "permissões" como partes constituintes do SKILL.md. Permissões podem aparecer no frontmatter como metadados, mas não como uma parte estrutural independente.\n- **D**: SKILL.md não possui seções de imports/exports. Isso é próprio de módulos de linguagens de programação (JavaScript, Python, etc.), não do arquivo de definição de skill.','\n',char(10)),replace('Imagine que você está escrevendo uma receita para um robô ajudante. O SKILL.md é como um papel que ensina o robô a fazer algo novo.\n\nEsse papel tem duas partes importantes:\n\n1. **O nome e a descrição** (igual o título de uma receita e o que ela faz): fica no começo, entre dois traços (---).\n2. **As instruções** (igual os passos da receita): vêm depois dos traços.\n\nA resposta certa é a **B** porque é exatamente isso: primeiro o nome e a descrição, e depois os passos da tarefa.\n\nAs outras respostas estão erradas:\n- **A** mistura JSON com YAML, mas a gente só usa YAML no começo, não JSON.\n- **C** fala de "bloco de scripts e permissões", mas não é assim que o SKILL.md organiza as coisas.\n- **D** fala de "imports e exports", que é coisa de programação de verdade, não de um arquivo de instruções para robô.','\n',char(10)));
INSERT INTO cards VALUES('admin','card_1783092987792_sgo4lzywy',294,'What is the relationship between the skill''s directory name and the name field?',replace('What is the relationship between the skill''s directory name and the name field?\n\nWhat is the relationship between the skill''s directory name and the name field?\n[Resposta correta: O diretório define o comando (/nome), o campo name faz default ao diretório e serve de label, e recomenda-se que coincidam. As demais invertem a relação ou negam a recomendação.]\n\n[ ] A - They are independent and never relate\n[ ] B - The directory name determines the command (/name) and name (defaults to the directory) is the label; they are recommended to match\n[ ] C - The name field determines the directory name automatically\n[ ] D - The command always comes from the name field, ignoring the directory','\n',char(10)),'[ ] B - The directory name determines the command (/name) and name (defaults to the directory) is the label; they are recommended to match','["Domain_3::Claude_Code_Configuration_Workflows", "Scenario_2::Code_Generation_Claude_Code"]','New',0,2.5,0,1783092987792,1783727326439,1783203558653,replace('**Tradução para português do Brasil:**\n\n*Pergunta:* Qual é a relação entre o nome do diretório do skill e o campo name?\n\n*Alternativas:*\n[ ] A - Eles são independentes e nunca se relacionam\n[ ] B - O nome do diretório determina o comando (/nome) e o campo name (que por padrão é o diretório) é o label; recomenda-se que coincidam\n[ ] C - O campo name determina automaticamente o nome do diretório\n[ ] D - O comando sempre vem do campo name, ignorando o diretório','\n',char(10)),replace('**Explicação para adulto (tech lead):**\n\nA alternativa **B** está correta. Em sistemas como a Alexia Skills Kit ou plataformas que usam pastas de skills, o **nome do diretório** (ex: `minha-skill`) é utilizado para definir o comando de invocação (ex: `/minha-skill`). O campo `name` no manifesto (ex: `skill.json` ou `manifest.yml`) serve como rótulo de exibição, mas seu valor padrão é herdado do nome do diretório se não for especificado. A recomendação de boas práticas é manter ambos iguais para evitar confusão e bugs de roteamento.\n\nPor que as demais estão erradas:\n- **A**: Incorreta porque eles se relacionam (o diretório dita o comando e o name default).\n- **C**: Incorreta porque o fluxo é o oposto: o diretório pode influenciar o name default, não o contrário.\n- **D**: Incorreta porque o comando é derivado do diretório, não do campo name.','\n',char(10)),replace('**Explicação para criança de 10 anos:**\n\nImagina que você tem uma pasta no seu computador chamada "meu-jogo". Dentro dessa pasta, tem um arquivo que diz qual é o nome do seu jogo. Se você não colocar um nome especial, o computador usa o nome da pasta como nome do jogo. E quando alguém quer jogar seu jogo, digita "/meu-jogo". Então, o nome da pasta vira o comando e também o nome padrão. É por isso que a gente sempre tenta deixar os dois iguais: o nome da pasta e o nome do jogo. A alternativa certa é a **B**.','\n',char(10)));
INSERT INTO cards VALUES('admin','card_1783092987810_2nn2zu7d6',295,'What does Claude load from each skill at initialization?',replace('What does Claude load from each skill at initialization?\n\nWhat does Claude load from each skill at initialization?\n[Resposta correta: Na inicialização carregam-se só name e description; o SKILL.md completo entra quando a skill é invocada. A A contraria o carregamento sob demanda; C e D estão incorretas.]\n\n[ ] A - The full SKILL.md of all skills\n[ ] B - Only the name and the description of each skill\n[ ] C - Only the scripts of the skill''s directory\n[ ] D - Nothing, skills only load on restart','\n',char(10)),'B - Only the name and the description of each skill','["Domain_1::Agentic_Architecture_Orchestration", "Domain_3::Claude_Code_Configuration_Workflows", "Scenario_4::Developer_Productivity"]','New',0,2.5,0,1783092987810,1783727329978,1783203558653,replace('Tradução:\n\n**O que o Claude carrega de cada skill na inicialização?**\n\n[ ] A - O SKILL.md completo de todas as skills\n[ ] B - Apenas o nome e a descrição de cada skill\n[ ] C - Apenas os scripts do diretório da skill\n[ ] D - Nada, skills são carregadas apenas na reinicialização','\n',char(10)),replace('Explicação para adulto tech lead:\n\nNa arquitetura do Claude (especificamente no contexto do projeto Anthropic, como o uso de skills no Claude Code ou sistemas similares), o comportamento de inicialização segue um princípio de **carregamento sob demanda (lazy loading)** para otimizar performance e uso de tokens de contexto.\n\n**Alternativa correta (B):** Durante a inicialização, o sistema carrega apenas metadados essenciais de cada skill — especificamente o `name` (nome) e `description` (descrição). Isso permite que o Claude saiba quais skills estão disponíveis e qual é o propósito de cada uma, sem consumir recursos desnecessários. A descrição é usada para que o modelo possa decidir, durante uma conversa, se deve ou não invocar determinada skill. O conteúdo completo do `SKILL.md` (que pode conter instruções detalhadas, exemplos, configurações, etc.) só é carregado quando a skill é efetivamente invocada.\n\n**Por que as demais estão erradas:**\n\n- **A (O SKILL.md completo de todas as skills):** Isso violaria o princípio de carregamento sob demanda. Carregar o conteúdo completo de todas as skills na inicialização consumiria muitos tokens de contexto desnecessariamente, especialmente em projetos com muitas skills. Além disso, muitas skills podem nunca ser usadas durante uma sessão, tornando esse carregamento ineficiente.\n\n- **C (Apenas os scripts do diretório da skill):** Os scripts (código executável) associados a uma skill também seguem a abordagem de carregamento sob demanda. Carregar todos os scripts na inicialização seria igualmente ineficiente. Além disso, o `SKILL.md` pode conter instruções de uso e contexto que não são scripts, mas que são fundamentais para o funcionamento correto da skill.\n\n- **D (Nada, skills são carregadas apenas na reinicialização):** Essa alternativa é duplamente incorreta. Primeiro, algo é sim carregado (name e description). Segundo, skills não requerem reinicialização para serem carregadas; elas são carregadas sob demanda durante a execução normal da sessão.','\n',char(10)),replace('Imagine que você tem uma caixa de ferramentas cheia de brinquedos diferentes, cada um com seu manual de instruções (esse manual é o "SKILL.md").\n\nNa inicialização (quando o sistema "acorda"), o Claude não abre todos os manuais de uma vez — isso daria muito trabalho e ocuparia espaço! Em vez disso, ele só dá uma olhadinha no nome de cada brinquedo (ex: "Carrinho Azul") e lê uma frase curta dizendo para que ele serve (ex: "Serve para andar rápido").\n\nQuando você realmente quer brincar com o carrinho azul, aí sim o Claude pega o manual completo e lê todas as instruções.\n\nA alternativa A estaria errada porque seria como querer ler todos os manuais de todos os brinquedos ao mesmo tempo, o que é cansativo e desnecessário. A C está errada porque os "scripts" seriam as peças do brinquedo, que também só são abertas quando você vai usar. E a D está errada porque o sistema não precisa reiniciar o computador inteiro só para pegar um brinquedo novo — ele pega na hora que precisa!','\n',char(10)));
INSERT INTO cards VALUES('admin','card_1783092987828_u5l5bmmld',296,'When does the full content of the SKILL.',replace('When does the full content of the SKILL.\n\nWhen does the full content of the SKILL.md enter the context?\n[Resposta correta: O SKILL.md completo entra quando a skill é invocada, por matching ou /skill-name. Na inicialização há só name e description; /compact e @ no CLAUDE.md não disparam o carregamento.]\n\n[ ] A - As soon as Claude Code starts the session\n[ ] B - When the skill is invoked (matching with the description or /skill-name)\n[ ] C - Only when running /compact\n[ ] D - Only if the CLAUDE.md references the skill with @','\n',char(10)),'[ ] B - When the skill is invoked (matching with the description or /skill-name)','["Domain_3::Claude_Code_Configuration_Workflows", "Domain_5::Context_Management_Reliability", "Scenario_2::Code_Generation_Claude_Code"]','New',0,2.5,0,1783092987828,1783727333321,1783203558653,replace('**Tradução para português do Brasil:**\n\nQuando o conteúdo completo do SKILL.md entra no contexto?\n[Resposta correta: O SKILL.md completo entra quando a skill é invocada, por matching ou /skill-name. Na inicialização há só name e description; /compact e @ no CLAUDE.md não disparam o carregamento.]\n\n[ ] A - Assim que o Claude Code inicia a sessão\n[ ] B - Quando a skill é invocada (correspondência com a descrição ou /skill-name)\n[ ] C - Apenas ao executar /compact\n[ ] D - Apenas se o CLAUDE.md referenciar a skill com @','\n',char(10)),replace('**Explicação para um adulto tech lead:**\n\nA alternativa correta é a **B**. O ciclo de vida de uma skill no Claude Code segue uma estratégia de carregamento tardio (lazy loading) otimizada para eficiência de contexto.\n\n- **Alternativa B (correta):** O conteúdo completo do SKILL.md só é inserido no contexto no momento em que a skill é efetivamente invocada, seja por correspondência automática com a descrição da skill durante a interação, seja pelo uso explícito do comando `/skill-name`. Isso evita poluir o contexto com instruções desnecessárias antes da ativação.\n\n- **Alternativa A (incorreta):** Na inicialização, apenas o `name` e a `description` da skill são carregados — uma estratégia de metadados que permite matching sem consumir tokens preciosos com o conteúdo integral. Carregar o SKILL.md completo logo no início da sessão seria antieconômico, especialmente em sessões longas com múltiplas skills disponíveis.\n\n- **Alternativa C (incorreta):** O comando `/compact` é uma ferramenta de gerenciamento de contexto que resume ou reorganiza o histórico, mas não tem relação com o carregamento de skills. Ele não dispara a inclusão do SKILL.md.\n\n- **Alternativa D (incorreta):** A referência `@skill-name` no CLAUDE.md é um mecanismo de ativação de skill, mas não carrega automaticamente o conteúdo completo. A skill precisa ser invocada (via matching ou `/skill-name`) para que o SKILL.md completo entre no contexto. A menção `@` apenas sinaliza disponibilidade ou preferência, não o carregamento integral.\n\n**Resumo técnico:** O design segue o princípio de carregamento sob demanda (on-demand loading), onde apenas metadados são pré-carregados e o conteúdo completo é injetado na janela de contexto apenas quando a skill é ativada, otimizando o uso de tokens e a eficiência da sessão.','\n',char(10)),replace('**Explicação para uma criança de 10 anos:**\n\nImagina que o SKILL.md é como um livro de regras de um jogo. Quando você começa a jogar (inicia a sessão), você só vê o nome do jogo e uma descrição bem curtinha na capa do livro — não o livro inteiro.\n\nA alternativa **B** está certa: o livro completo só é aberto e lido quando você realmente decide jogar aquele jogo, seja porque o computador percebeu que você está falando sobre ele (matching) ou porque você escreveu o nome do jogo no chat (/skill-name).\n\nAs outras estão erradas:\n\n- **A:** Se o livro inteiro fosse aberto desde o início, seria como carregar todos os livros da sua estante na mochila ao mesmo tempo — pesado e desnecessário!\n- **C:** O /compact é como apertar um botão para arrumar seu quarto (organizar o histórico), não tem nada a ver com abrir um livro de regras novo.\n- **D:** Colocar @nome-do-jogo no CLAUDE.md é como deixar um bilhete lembrando que você tem aquele jogo, mas só isso não faz o livro abrir sozinho — você precisa pegar o livro e ler (invocar a skill).\n\nEntão, resumindo: o livro de regras completo só aparece quando você realmente for jogar aquele jogo!','\n',char(10)));
INSERT INTO cards VALUES('admin','card_1783092987846_3vp7o7ozp',297,'What is the priority order in case of a name conflict between skills?',replace('What is the priority order in case of a name conflict between skills?\n\nWhat is the priority order in case of a name conflict between skills?\n[Resposta correta: A ordem é Enterprise > Personal > Project, e plugins usam namespace próprio, ficando fora da hierarquia. As demais invertem a ordem ou colocam plugins na disputa.]\n\n[ ] A - Project > Personal > Enterprise\n[ ] B - Enterprise > Personal > Project, with plugins outside the hierarchy (their own namespace)\n[ ] C - Personal > Enterprise > Project\n[ ] D - Plugins > Enterprise > Personal > Project','\n',char(10)),'B - Enterprise > Personal > Project, with plugins outside the hierarchy (their own namespace)','["Domain_3::Claude_Code_Configuration_Workflows", "Scenario_2::Code_Generation_Claude_Code"]','New',0,2.5,0,1783092987846,1783727336416,1783203558653,replace('**Tradução para português do Brasil:**\n\n**Pergunta:** Qual é a ordem de prioridade em caso de conflito de nomes entre skills?\n\n**Alternativas:**\n[ ] A - Projeto > Pessoal > Enterprise\n[ ] B - Enterprise > Pessoal > Projeto, com plugins fora da hierarquia (namespace próprio)\n[ ] C - Pessoal > Enterprise > Projeto\n[ ] D - Plugins > Enterprise > Pessoal > Projeto','\n',char(10)),replace('**Explicação didática para um adulto tech lead:**\n\nA pergunta trata da resolução de conflitos de nomenclatura em um ecossistema de skills (habilidades ou módulos) que podem ser definidos em diferentes escopos: Enterprise (corporativo/organizacional), Personal (pessoal/usuário) e Project (projeto específico). Além disso, há a figura dos plugins, que possuem um mecanismo de isolamento próprio.\n\nA alternativa correta é a **B**, que estabelece a hierarquia **Enterprise > Personal > Project**, com plugins fora dessa hierarquia, em um namespace separado.\n\n**Por que a B está correta:**\n\n1. **Enterprise (maior prioridade):** Regras, skills ou configurações definidas no nível corporativo devem prevalecer sobre qualquer outro escopo, pois representam políticas e padrões obrigatórios da organização. É o nível mais abrangente e, portanto, o de maior autoridade.\n\n2. **Personal (prioridade intermediária):** Configurações pessoais do usuário vêm em segundo lugar. O usuário pode personalizar sua experiência, mas sem sobrescrever políticas corporativas mandatórias.\n\n3. **Project (menor prioridade):** Definições no nível do projeto são as mais específicas, mas também as de menor escopo. Elas são sobrescritas tanto por configurações pessoais quanto corporativas.\n\n4. **Plugins fora da hierarquia:** Plugins operam em um namespace próprio, o que significa que seus nomes não competem diretamente com skills nos outros três níveis. Isso é um design deliberado para evitar conflitos e permitir que plugins coexistam sem risco de sobrescrita acidental.\n\n**Por que as demais alternativas estão erradas:**\n\n- **Alternativa A (Project > Personal > Enterprise):** Inverte completamente a hierarquia. Colocar Project como maior prioridade faria com que configurações de um único projeto pudessem sobrescrever políticas corporativas, o que é indesejável em qualquer sistema minimamente bem arquitetado. Seria um pesadelo de governança.\n\n- **Alternativa C (Personal > Enterprise > Project):** Coloca Personal acima de Enterprise. Isso permitiria que um usuário comum sobrescrevesse políticas corporativas obrigatórias, o que quebra qualquer modelo de governança e conformidade. Embora Project fique corretamente como menor prioridade, a inversão entre Personal e Enterprise é grave.\n\n- **Alternativa D (Plugins > Enterprise > Personal > Project):** Insere plugins dentro da hierarquia e, pior, no topo dela. Isso viola o princípio de que plugins devem ter namespace isolado. Colocar plugins como maior prioridade significa que qualquer plugin instalado poderia sobrescrever skills corporativas, pessoais e de projeto, o que é um risco de segurança e estabilidade enorme. Além disso, quebra o contrato de isolamento que plugins normalmente devem respeitar.','\n',char(10)),replace('Imagina que você tem três tipos de regras para organizar seus brinquedos:\n\n1. **Regras da Empresa (Enterprise)** - São as regras dos seus pais, valem para todo mundo em casa.\n2. **Regras Pessoais (Personal)** - São suas regras, do seu quarto.\n3. **Regras do Projeto (Project)** - São regras para uma brincadeira específica, tipo "hoje só brincamos de carrinho".\n\nAgora, se houver uma briga entre essas regras (por exemplo, a regra da empresa diz "não pode comer doce antes do jantar", mas a regra do projeto diz "pode comer doce na brincadeira"), quem ganha? A regra mais importante: a da empresa (Enterprise) ganha da pessoal, que ganha da do projeto.\n\nE os plugins? Eles são como convidados especiais que trazem seus próprios brinquedos. Eles não brigam com as regras porque usam brinquedos com nomes diferentes, num cantinho separado. Eles não entram na disputa!\n\nA alternativa B diz exatamente isso: Enterprise manda em todo mundo, depois vem o Pessoal, depois o Projeto, e os plugins ficam de fora, num espaço próprio. É a resposta certa!\n\nAs outras opções estão erradas porque:\n- **A** coloca o Projeto como chefe, mas o Projeto é só uma brincadeirinha, não pode mandar nos pais!\n- **C** coloca você (Pessoal) acima dos pais (Enterprise), mas não é assim que funciona.\n- **D** coloca os convidados (plugins) como chefões, mas eles nem deveriam estar na disputa!','\n',char(10)));
INSERT INTO cards VALUES('admin','card_1783092987864_xm4nfrjib',298,'There is an enterprise skill code-review and you create a personal one with the same name.',replace('There is an enterprise skill code-review and you create a personal one with the same name.\n\nThere is an enterprise skill code-review and you create a personal one with the same name. Which one wins and what do you do?\n[Resposta correta: A enterprise tem prioridade máxima, então vence; a solução é renomear a sua para um nome distinto. A A e a D erram a hierarquia; a C ignora o conflito de nomes.]\n\n[ ] A - The personal one wins; nothing to do\n[ ] B - The enterprise one wins; rename yours to something distinct (e.g. backend-review)\n[ ] C - Both run together with no conflict\n[ ] D - The project one wins over both','\n',char(10)),'B - The enterprise one wins; rename yours to something distinct (e.g. backend-review)','["Domain_3::Claude_Code_Configuration_Workflows", "Scenario_2::Code_Generation_Claude_Code"]','New',0,2.5,0,1783092987864,1783727339319,1783203558653,replace('**Tradução para português do Brasil:**\n\nExiste uma skill corporativa chamada "code-review" e você cria uma skill pessoal com o mesmo nome. Qual delas prevalece e o que você deve fazer?\n\n[ ] A - A pessoal vence; nada a fazer\n[ ] B - A corporativa vence; renomeie a sua para algo distinto (ex.: backend-review)\n[ ] C - Ambas rodam juntas sem conflito\n[ ] D - A do projeto vence ambas','\n',char(10)),replace('**Explicação para um adulto tech lead:**\n\nEm sistemas de skill management (como no GitHub Copilot Extensions ou plataformas similares), as skills corporativas (enterprise) têm prioridade máxima sobre skills pessoais ou de projeto. Isso ocorre porque as skills corporativas são definidas centralmente pela organização para garantir padrões, políticas de segurança, compliance e consistência em toda a empresa.\n\nQuando há conflito de nomes (mesmo nome para skill corporativa e pessoal), a corporativa sempre prevalece. A skill pessoal é ignorada ou sobrescrita, nunca executada em paralelo. Portanto, manter uma skill pessoal com nome idêntico é inútil — ela nunca será invocada.\n\nA ação correta é renomear sua skill pessoal para um nome único e descritivo (ex.: "backend-review" em vez de "code-review"), eliminando a ambiguidade. Isso permite que ambas coexistam sem conflito: a corporativa continua sendo usada quando o nome genérico "code-review" é referenciado, e a sua skill pessoal pode ser chamada pelo nome específico.\n\n**Análise das alternativas incorretas:**\n\n- **A (A pessoal vence):** Errada. A hierarquia padrão é enterprise > project > personal, não o contrário.\n- **C (Ambas rodam juntas):** Errada. Conflito de nomes causa sobrescrita, não execução paralela. O sistema não mescla ou junta comportamentos.\n- **D (A do projeto vence ambas):** Errada. A skill corporativa (enterprise) tem prioridade máxima; a de projeto fica abaixo dela na hierarquia.','\n',char(10)),replace('Imagine que sua escola tem uma regra geral chamada "Hora do Estudo" que vale para todo mundo. Você decide criar sua própria "Hora do Estudo" só para você, com as mesmas palavras. Mas a regra da escola é mais forte — então a sua versão não funciona, porque a da escola sempre ganha.\n\nO que fazer? Simples: dar um nome diferente para a sua regra pessoal, tipo "Hora do Estudo de Matemática". Assim, as duas podem existir sem confusão!\n\nAs outras respostas estão erradas porque:\n- Dizer que a sua vence não é verdade — a da escola é mais forte.\n- Dizer que as duas funcionam juntas também não — só uma pode valer quando têm o mesmo nome.\n- Dizer que a do projeto vence as duas também está errado — a da escola ainda ganha de todas.','\n',char(10)));
INSERT INTO cards VALUES('admin','card_1783092987883_j92u6egb5',299,'How does the priority hierarchy let the organization impose standards without preventing customization?',replace('How does the priority hierarchy let the organization impose standards without preventing customization?\n\nHow does the priority hierarchy let the organization impose standards without preventing customization?\n[Resposta correta: Enterprise garante o padrão por prioridade máxima, e o usuário mantém customização usando skills pessoais de nomes distintos. A A e a C erram a hierarquia; a D ignora o mecanismo de skills.]\n\n[ ] A - Enterprise blocks any personal skill\n[ ] B - Enterprise skills (maximum priority) guarantee the standard, and users customize with personal skills of distinct names\n[ ] C - Project skills always override enterprise\n[ ] D - Standards can only be imposed via hooks','\n',char(10)),'[ ] B - Enterprise skills (maximum priority) guarantee the standard, and users customize with personal skills of distinct names','["Domain_3::Claude_Code_Configuration_Workflows", "Domain_2::Tool_Design_MCP_Integration", "Scenario_2::Code_Generation_Claude_Code"]','New',0,2.5,0,1783092987883,1783727342782,1783203558653,replace('**Tradução para português do Brasil:**\n\n**Pergunta:** Como a hierarquia de prioridades permite que a organização imponha padrões sem impedir a customização?\n\n**Alternativas:**\n\n[ ] A - Enterprise bloqueia qualquer skill pessoal\n[ ] B - Skills Enterprise (prioridade máxima) garantem o padrão, e os usuários customizam com skills pessoais de nomes distintos\n[ ] C - Skills de projeto sempre sobrescrevem as Enterprise\n[ ] D - Padrões só podem ser impostos via hooks','\n',char(10)),replace('**Explicação técnica para um adulto (tech lead):**\n\nA questão aborda o mecanismo de **priority hierarchy** (hierarquia de prioridades) em um sistema de automação/computação em nuvem (provavelmente relacionado a um framework de gerenciamento de configuração ou execução de tarefas). O objetivo é conciliar dois requisitos aparentemente conflitantes: a organização precisa garantir que certos padrões sejam seguidos (ex.: compliance, segurança, conformidade), mas os times ou usuários individuais precisam de liberdade para customizar comportamentos específicos.\n\n**Por que a alternativa B é a correta?**\n\n- **Enterprise skills (prioridade máxima)** significa que as definições impostas pela organização têm precedência sobre quaisquer outras. Isso garante que o padrão seja aplicado de forma incontornável.\n- **Customização com skills pessoais de nomes distintos** significa que usuários ou projetos podem criar suas próprias skills (scripts, automações, configurações) desde que não conflitem com os nomes das skills Enterprise. Como têm nomes diferentes, não há conflito de prioridade — cada skill é executada em seu próprio contexto. Assim, a organização mantém o padrão (skills Enterprise) sem bloquear que os usuários criem soluções próprias (skills pessoais).\n\n**Por que as demais estão erradas:**\n\n- **Alternativa A** ("Enterprise bloqueia qualquer skill pessoal"): Isso impediria totalmente a customização, contradizendo o objetivo descrito na pergunta ("sem impedir customização"). A hierarquia de prioridades não precisa bloquear skills pessoais; ela apenas estabelece que, em caso de conflito, a Enterprise vence. Mas se os nomes forem distintos, ambos coexistem.\n- **Alternativa C** ("Skills de projeto sempre sobrescrevem as Enterprise"): Isso inverte a hierarquia. Se skills de projeto pudessem sobrescrever as Enterprise, a organização perderia o controle sobre os padrões. A pergunta deixa claro que a organização quer *impor* padrões, o que exige prioridade máxima para as regras Enterprise.\n- **Alternativa D** ("Padrões só podem ser impostos via hooks"): É uma afirmação incorreta e restritiva. Hooks são um mecanismo possível, mas a hierarquia de prioridades em si (skills com diferentes níveis de prioridade) já é o mecanismo que permite impor padrões, sem depender exclusivamente de hooks. Além disso, hooks geralmente são usados para extensão ou interceptação, não como o único meio de imposição de padrões.','\n',char(10)),replace('**Explicação para uma criança de 10 anos:**\n\nImagine que você está jogando um jogo de criar personagens. A escola (organização) decide que todo personagem precisa ter um uniforme azul (padrão). Mas você pode escolher o chapéu, a mochila e os sapatos do seu personagem (customização).\n\nA alternativa B é a resposta certa porque funciona assim:\n- A escola diz: "O uniforme azul é obrigatório — ninguém pode mudar isso." (isso é a skill Enterprise com prioridade máxima)\n- Mas você pode escolher um chapéu legal, uma mochila diferente e tênis coloridos, desde que não troquem o uniforme azul. (isso são skills pessoais com nomes diferentes)\n\nAs outras alternativas estão erradas porque:\n- A: Se a escola bloqueasse *tudo* que você quisesse fazer, você não poderia personalizar nada — chato!\n- C: Se os alunos pudessem mudar o uniforme azul, a escola perderia o padrão — bagunça!\n- D: Dizer que só dá para impor padrão de um jeito específico (hooks) é mentira, dá para fazer de outras formas também.\n\nEntão, resumindo: a escola garante o padrão (uniforme azul) com regras que ninguém pode quebrar, mas você pode personalizar o resto. Todo mundo feliz! 😊','\n',char(10)));
INSERT INTO cards VALUES('admin','card_1783092987903_bgb4q9xh0',300,'Which action with skills requires restarting Claude Code?',replace('Which action with skills requires restarting Claude Code?\n\nWhich action with skills requires restarting Claude Code?\n[Resposta correta: Só criar um diretório top-level de skills inexistente exige restart para passar a ser monitorado. Editar, remover e criar skills dentro de diretórios já monitorados entram em vigor via live change detection.]\n\n[ ] A - Editing the SKILL.md of an existing skill\n[ ] B - Deleting a skill''s directory\n[ ] C - Creating a top-level skills directory that did not exist when the session started\n[ ] D - Creating a new skill inside an already-monitored directory','\n',char(10)),'C - Creating a top-level skills directory that did not exist when the session started','["Domain_3::Claude_Code_Configuration_Workflows", "Domain_5::Context_Management_Reliability", "Scenario_2::Code_Generation_Claude_Code"]','New',0,2.5,0,1783092987903,1783727346085,1783203558653,replace('**Tradução para português do Brasil:**\n\nPergunta: "Qual ação relacionada a skills exige reinicialização do Claude Code?"\n\nAlternativas:\n[ ] A - Editar o SKILL.md de uma skill existente\n[ ] B - Excluir o diretório de uma skill\n[ ] C - Criar um diretório top-level de skills que não existia quando a sessão foi iniciada\n[ ] D - Criar uma nova skill dentro de um diretório já monitorado','\n',char(10)),replace('**Explicação para adulto (tech lead):**\n\nO Claude Code possui um mecanismo de "live change detection" que monitora alterações em diretórios de skills já reconhecidos pela sessão. Isso significa que edições, remoções e criações de skills dentro de diretórios que já estão no radar do Claude Code são detectadas em tempo real, sem necessidade de restart.\n\nA única exceção — e portanto a resposta correta — é a criação de um diretório top-level de skills que **não existia** quando a sessão foi iniciada. O motivo é técnico: o sistema de monitoramento de arquivos (file watcher) é configurado no momento da inicialização da sessão e só "escuta" diretórios que já existiam naquele instante. Um diretório top-level novo, criado posteriormente, não está na lista de diretórios monitorados e, portanto, o Claude Code não saberá que ele existe até que a sessão seja reiniciada.\n\nAnálise das alternativas incorretas:\n- **A (Editar SKILL.md):** Incorreta. A live change detection captura modificações em arquivos dentro de diretórios já monitorados.\n- **B (Excluir diretório de skill):** Incorreta. A remoção é detectada dinamicamente, sem necessidade de restart.\n- **D (Criar skill dentro de diretório já monitorado):** Incorreta. O diretório pai já está sendo observado pelo file watcher, então a nova skill é descoberta automaticamente.','\n',char(10)),replace('Imagine que o Claude Code é como um segurança que, no começo do seu turno, anota todos os armários (diretórios) que existem na sala. Durante o turno, ele fica de olho nesses armários: se alguém colocar uma caixa nova dentro, trocar a etiqueta ou tirar uma caixa, ele percebe na hora.\n\nAgora, se você trouxer um armário novinho que não estava na sala quando ele chegou, ele não vai saber que esse armário existe — porque ele não estava na lista inicial. Para ele começar a vigiar esse armário novo, você precisa pedir pra ele recomeçar o turno (reiniciar o Claude Code).\n\nÉ exatamente isso que a alternativa C diz: criar uma pasta de skills completamente nova (um "armário" que não existia) exige restart. Já editar, apagar ou criar skills dentro de pastas que já existiam (alternativas A, B e D) funciona sem restart, porque o segurança já está de olho nelas.','\n',char(10)));
INSERT INTO cards VALUES('admin','card_1783092987946_le4o8dn68',301,'Regarding skills, when is it mandatory to restart Claude Code?',replace('Regarding skills, when is it mandatory to restart Claude Code?\n\nRegarding skills, when is it mandatory to restart Claude Code?\n[Resposta correta: O restart só é necessário ao criar um diretório top-level de skills que não existia no início da sessão. Edições e remoções entram automaticamente, e o item D exagera ao dizer "nunca".]\n\n[ ] A - Whenever any SKILL.md is edited\n[ ] B - Only when creating a top-level skills directory that did not exist when the session started\n[ ] C - Whenever a skill is removed\n[ ] D - Never, all changes are automatic','\n',char(10)),'B - Only when creating a top-level skills directory that did not exist when the session started','["Domain_3::Claude_Code_Configuration_Workflows", "Scenario_2::Code_Generation_Claude_Code"]','New',0,2.5,0,1783092987946,1783727349120,1783203558653,replace('**Tradução para português do Brasil:**\n\n**Pergunta:** Em relação às skills, quando é obrigatório reiniciar o Claude Code?\n\n**Alternativas:**\n[ ] A - Sempre que qualquer SKILL.md for editado\n[ ] B - Apenas ao criar um diretório top-level de skills que não existia quando a sessão foi iniciada\n[ ] C - Sempre que uma skill for removida\n[ ] D - Nunca, todas as alterações são automáticas','\n',char(10)),replace('**Explicação para um adulto tech lead:**\n\nO Claude Code gerencia skills como artefatos carregados em memória no início de uma sessão. O comportamento esperado é:\n\n- **Alternativa B (correta):** O restart é obrigatório apenas quando um novo diretório top-level de skills é criado durante a sessão. Isso ocorre porque o Claude Code não monitora dinamicamente a criação de novos diretórios de skills — ele só descobre skills nos diretórios que existiam no momento da inicialização. Criar um novo diretório de skills exige um restart para que o sistema o reconheça e carregue seu conteúdo.\n\n- **Alternativa A (incorreta):** Edições em arquivos SKILL.md existentes são detectadas automaticamente, sem necessidade de restart. O Claude Code possui mecanismos de hot-reload ou reavaliação sob demanda para mudanças em skills já carregadas.\n\n- **Alternativa C (incorreta):** Remoções de skills também são refletidas automaticamente. O sistema reconhece a ausência do arquivo ou diretório e ajusta o estado interno sem intervenção manual.\n\n- **Alternativa D (incorreta):** Afirmar que "nunca" é necessário restart é um exagero. Embora a maioria das mudanças seja automática, a criação de um novo diretório top-level de skills é uma exceção que exige reinicialização, conforme explicado acima.','\n',char(10)),replace('**Explicação para uma criança de 10 anos:**\n\nImagine que o Claude Code é como seu videogame favorito. As "skills" são como fases ou personagens novos que você pode adicionar ao jogo.\n\n- Se você **editar** um personagem que já existe (mudar a cor da roupa dele), o jogo percebe na hora — sem precisar reiniciar.\n- Se você **apagar** um personagem, o jogo também nota na hora.\n- Mas se você **criar uma pasta nova de personagens** (um diretório top-level de skills), é como instalar um novo disco de jogo — você precisa reiniciar o console para o jogo reconhecer que tem conteúdo novo.\n\nEntão a resposta certa é a **B**: você só precisa reiniciar quando cria uma pasta de skills nova que não existia quando você começou a jogar.','\n',char(10)));
INSERT INTO cards VALUES('admin','card_1783092987964_1zdxe4l51',302,'Why prefer descriptive names (frontend-review) over generic ones (review) for skills?',replace('Why prefer descriptive names (frontend-review) over generic ones (review) for skills?\n\nWhy prefer descriptive names (frontend-review) over generic ones (review) for skills?\n[Resposta correta: Nomes descritivos evitam colisões de prioridade e ajudam o matching correto. As demais inventam regras de carregamento, de tamanho de name ou de bloqueio.]\n\n[ ] A - Because longer names load faster\n[ ] B - To avoid priority conflicts with same-named skills and help Claude choose the right skill\n[ ] C - Because the name field requires at least two words\n[ ] D - Because generic ones are blocked by the validator','\n',char(10)),'B - To avoid priority conflicts with same-named skills and help Claude choose the right skill','["Domain_2::Tool_Design_MCP_Integration", "Domain_1::Agentic_Architecture_Orchestration", "Scenario_4::Developer_Productivity"]','New',0,2.5,0,1783092987964,1783727352447,1783203558653,replace('**Tradução para português do Brasil:**\n\nPor que preferir nomes descritivos (frontend-review) em vez de genéricos (review) para skills?\n\n[ ] A - Porque nomes mais longos carregam mais rápido\n[ ] B - Para evitar conflitos de prioridade com skills de mesmo nome e ajudar o Claude a escolher a skill correta\n[ ] C - Porque o campo de nome exige pelo menos duas palavras\n[ ] D - Porque nomes genéricos são bloqueados pelo validador','\n',char(10)),replace('**Explicação didática para um adulto (tech lead):**\n\nA alternativa **B** é a correta. Em sistemas multiagente ou ambientes onde múltiplas skills são registradas, nomes descritivos como "frontend-review" eliminam ambiguidades. Se duas skills com o mesmo nome genérico "review" existirem (ex.: uma para frontend e outra para backend), o mecanismo de resolução de prioridade ou roteamento pode falhar, pois o nome é a chave de identificação para matching. Nomes descritivos funcionam como namespaces reduzidos: eles carregam semântica de domínio, evitam colisões e tornam o processo de seleção determinístico.\n\n- **A** está errada: nomes mais longos tendem a ocupar mais bytes e não há ganho de performance de carregamento associado ao tamanho do nome da skill.\n- **C** está errada: não há regra geral que exija duas palavras no campo de nome de skill; isso é uma invenção.\n- **D** está errada: validadores não bloqueiam nomes genéricos por padrão; o problema é de desambiguação, não de validação sintática.','\n',char(10)),'Imagine que você tem dois brinquedos: um carrinho azul e um carrinho vermelho. Se você guardar os dois na caixa e escrever só "carrinho" nela, fica confuso — você não sabe qual é qual. Agora, se escrever "carrinho azul" e "carrinho vermelho", fica fácil de encontrar. Com as skills do Claude é a mesma coisa: se você colocar o nome "review", pode ser difícil saber qual é a certa quando existir mais de uma. Usar "frontend-review" ou "backend-review" deixa tudo claro e evita que o Claude se confunda.');
INSERT INTO cards VALUES('admin','card_1783092987981_rw1c6wxbu',303,'About the fields of a skill''s frontmatter, which statement is correct?',replace('About the fields of a skill''s frontmatter, which statement is correct?\n\nAbout the fields of a skill''s frontmatter, which statement is correct?\n[Resposta correta: Tecnicamente todos os campos são opcionais, sendo description o recomendado (com fallback para o primeiro parágrafo). As demais tratam campos opcionais como obrigatórios.]\n\n[ ] A - name and description are both mandatory\n[ ] B - Technically all are optional; description is the recommended one (without it, the first paragraph of the markdown is used)\n[ ] C - allowed-tools is mandatory for any skill\n[ ] D - The entire frontmatter is mandatory, otherwise the skill does not load','\n',char(10)),'B - Technically all are optional; description is the recommended one (without it, the first paragraph of the markdown is used)','["Domain_3::Claude_Code_Configuration_Workflows", "Scenario_2::Code_Generation_Claude_Code"]','New',0,2.5,0,1783092987981,1783727355556,1783203558653,replace('**Tradução da pergunta e alternativas para português do Brasil:**\n\n**Pergunta:** Sobre os campos do frontmatter de uma skill, qual afirmação está correta?\n\n[ ] A - name e description são ambos obrigatórios\n[ ] B - Tecnicamente todos são opcionais; description é o recomendado (sem ele, o primeiro parágrafo do markdown é usado)\n[ ] C - allowed-tools é obrigatório para qualquer skill\n[ ] D - Todo o frontmatter é obrigatório, caso contrário a skill não carrega','\n',char(10)),replace('**Explicação para adulto (tech lead):**\n\nA alternativa **B** está correta porque, na implementação do Open WebUI (e em muitos sistemas similares baseados em frontmatter YAML para skills), não há exigência de que qualquer campo específico seja preenchido para que a skill seja carregada e funcione. O frontmatter é puramente informativo/configuracional. O campo `description` é o único que possui um mecanismo de fallback: se estiver ausente, o sistema utiliza o primeiro parágrafo do conteúdo Markdown da skill como descrição. Isso torna o campo altamente recomendado, mas não obrigatório.\n\n**Análise das demais alternativas:**\n\n- **A** (name e description são ambos obrigatórios): Incorreta. Embora seja uma boa prática fornecer ambos, tecnicamente nenhum campo é obrigatório. A skill carrega mesmo sem eles, utilizando nome do arquivo ou fallbacks.\n- **C** (allowed-tools é obrigatório para qualquer skill): Incorreta. `allowed-tools` (ou `permitted_tools`, dependendo da implementação) é um campo opcional, utilizado apenas quando se deseja restringir quais ferramentas a skill pode chamar. Se ausente, normalmente a skill tem acesso a todas as ferramentas disponíveis (ou nenhuma, conforme a política do sistema).\n- **D** (Todo o frontmatter é obrigatório, caso contrário a skill não carrega): Incorreta. O frontmatter inteiro é opcional. Uma skill pode existir sem qualquer frontmatter e ainda assim ser carregada, utilizando o nome do arquivo e o conteúdo bruto como fallback.','\n',char(10)),replace('**Explicação para criança de 10 anos:**\n\nImagine que você está montando uma ficha de um personagem de jogo. No topo da ficha, tem um espaço para escrever o nome, a descrição e algumas regras especiais. Agora, pense que você *pode* preencher esses campos, mas não é obrigatório. Se você não escrever a descrição, o jogo vai pegar a primeira frase do texto que você escreveu embaixo e usar ela. É assim que funciona o frontmatter de uma skill!\n\nA resposta certa é a **B**: nenhum campo é obrigatório, mas é bom colocar a descrição — senão o sistema usa o primeiro parágrafo do texto.\n\nAs outras opções estão erradas porque:\n- A letra **A** diz que nome e descrição são obrigatórios — mas não são, você pode deixar em branco.\n- A letra **C** diz que "allowed-tools" (as ferramentas permitidas) é obrigatório — mas é opcional, só serve se você quiser controlar quais ferramentas a skill pode usar.\n- A letra **D** fala que tudo tem que ser preenchido, senão a skill não carrega — mentira! A skill funciona mesmo sem nada no frontmatter.','\n',char(10)));
INSERT INTO cards VALUES('admin','card_1783092987999_4udasxgtq',304,'What are the restrictions of a skill''s name field?',replace('What are the restrictions of a skill''s name field?\n\nWhat are the restrictions of a skill''s name field?\n[Resposta correta: O name aceita só minúsculas, números e hifens, com no máximo 64 caracteres. A A confunde com o limite de description; C e D erram os caracteres e o limite.]\n\n[ ] A - Any character, up to 1,024 characters\n[ ] B - Only lowercase letters, numbers and hyphens; maximum of 64 characters\n[ ] C - Uppercase letters and spaces allowed, no length limit\n[ ] D - Only numbers, up to 32 characters','\n',char(10)),'B - Only lowercase letters, numbers and hyphens; maximum of 64 characters','["ForaDosDominios", "ForaDoCenario"]','New',0,2.5,0,1783092987999,1783727358981,1783203558653,replace('**Tradução para português do Brasil:**\n\nPergunta: "Quais são as restrições do campo ''name'' de uma skill?"\n\nAlternativas:\n[ ] A - Qualquer caractere, até 1.024 caracteres\n[ ] B - Apenas letras minúsculas, números e hifens; máximo de 64 caracteres\n[ ] C - Letras maiúsculas e espaços permitidos, sem limite de comprimento\n[ ] D - Apenas números, até 32 caracteres','\n',char(10)),replace('**Explicação didática para um adulto (tech lead):**\n\nA alternativa correta é a **B**. O campo `name` de uma skill (por exemplo, em plataformas como Alexa Skills Kit da Amazon) possui restrições bem definidas para garantir consistência, identificação única e compatibilidade com sistemas de roteamento e indexação. Ele aceita **apenas letras minúsculas (a-z), números (0-9) e hifens (-)**, com um limite máximo de **64 caracteres**.\n\n- **Alternativa A** está incorreta porque o limite de 1.024 caracteres é típico do campo `description`, não do `name`. Além disso, caracteres especiais e maiúsculas não são permitidos no nome.\n- **Alternativa C** está incorreta pois letras maiúsculas e espaços não são aceitos no `name`, e há sim um limite de comprimento (64 caracteres).\n- **Alternativa D** está incorreta porque o campo não é restrito apenas a números, e o limite não é de 32 caracteres, mas sim de 64.\n\nPortanto, a única alternativa que reflete corretamente as regras de nomenclatura de skills é a **B**.','\n',char(10)),replace('Imagine que você está criando um nome para um personagem de um jogo. Esse nome não pode ser qualquer coisa, senão o computador pode se confundir. O nome de uma "skill" (que é como um "poder" ou "comando" que um assistente virtual entende) funciona assim:\n\n- Só pode usar **letras minúsculas** (a, b, c...), **números** (0, 1, 2...) e **hifens** (-).\n- O nome não pode ser maior que **64 letras ou números** (tipo um nome médio de pessoa).\n\nA resposta certa é a **B** porque diz exatamente isso. As outras opções estão erradas: uma diz que pode qualquer letra (não pode maiúscula), outra diz que não tem limite de tamanho (tem sim!), e outra diz que só pode número (pode letra também).','\n',char(10)));
INSERT INTO cards VALUES('admin','card_1783092988016_4vhoh004m',305,'About a skill''s description field, which statement is correct?',replace('About a skill''s description field, which statement is correct?\n\nAbout a skill''s description field, which statement is correct?\n[Resposta correta: A description vai até 1.024 caracteres e é o campo mais importante, pois orienta o matching (com description + when_to_use somando até 1.536 no listing). A A confunde com o name; C e D negam seu papel no matching.]\n\n[ ] A - Maximum of 64 characters, used only as a label\n[ ] B - Maximum of 1,024 characters; it is the most important because Claude uses it for skill matching\n[ ] C - It has no limit and does not influence matching\n[ ] D - It is only used when invoked by /skill-name','\n',char(10)),'[ ] B - Maximum of 1,024 characters; it is the most important because Claude uses it for skill matching','["ForaDosDominios", "ForaDoCenario"]','New',0,2.5,0,1783092988016,1783727362811,1783203558653,replace('**Tradução fiel para português do Brasil:**\n\nSobre o campo de descrição de uma skill, qual afirmação está correta?\n\n[ ] A - Máximo de 64 caracteres, usado apenas como rótulo\n[ ] B - Máximo de 1.024 caracteres; é o mais importante porque o Claude o utiliza para correspondência de skills (skill matching)\n[ ] C - Não tem limite e não influencia a correspondência (matching)\n[ ] D - É usado apenas quando invocado por /skill-name','\n',char(10)),replace('**Explicação didática para um adulto tech lead:**\n\nA alternativa **B** é a correta. O campo `description` de uma skill aceita até **1.024 caracteres** e é considerado o campo mais relevante para o mecanismo de *skill matching* do Claude. Isso significa que, quando o modelo precisa decidir qual skill ativar para responder a uma solicitação do usuário, ele analisa principalmente esse campo para entender o propósito e o escopo da skill.\n\n- **Por que B está correta:** O limite documentado é de fato 1.024 caracteres para a `description`, e ela — juntamente com o campo `when_to_use` (que soma até 1.536 caracteres no total do *listing*) — orienta diretamente o matching. Sem uma descrição clara e bem escrita, o Claude pode não associar corretamente a skill ao contexto apropriado.\n\n- **Por que A está errada:** O limite de 64 caracteres e a função de "apenas rótulo" se aplicam ao campo `name` da skill, não à `description`. A alternativa A confunde os dois campos.\n\n- **Por que C está errada:** A `description` certamente tem limite (1.024 caracteres) e, mais importante, **influencia sim** o matching. Negar isso é ignorar o propósito central do campo.\n\n- **Por que D está errada:** A descrição não é "usada apenas quando invocada por /skill-name". O campo é lido e processado durante o matching automático do Claude, independentemente de como a skill é invocada.','\n',char(10)),replace('Imagine que cada skill (que é como um "superpoder" do Claude) tem uma ficha de apresentação. Nessa ficha, o campo mais importante é a "descrição" — é ali que a gente explica para o Claude: "Essa skill serve para fazer isso aqui!". O limite é de 1.024 caracteres, e o Claude lê essa descrição para saber quando usar o superpoder certo.\n\n- A opção A está errada porque confunde a descrição com o "nome" da skill (que é tipo um apelido curto).\n- A opção C está errada porque a descrição tem limite e sim, ajuda o Claude a decidir qual skill usar.\n- A opção D está errada porque a descrição é lida pelo Claude automaticamente, não só quando a skill é chamada pelo nome.','\n',char(10)));
INSERT INTO cards VALUES('admin','card_1783092988036_llbopskyl',306,'What is progressive disclosure in skills?',replace('What is progressive disclosure in skills?\n\nWhat is progressive disclosure in skills?\n[Resposta correta: Progressive disclosure mantém o essencial no SKILL.md e move a referência detalhada para arquivos lidos sob demanda, poupando contexto. A A contraria a ideia; C e D descrevem outras coisas.]\n\n[ ] A - Loading all reference material at initialization\n[ ] B - Keeping the essentials in the SKILL.md and putting detailed reference in separate files, read only when needed\n[ ] C - Splitting the skill into several slash commands\n[ ] D - Compacting the SKILL.md automatically each session','\n',char(10)),'B - Keeping the essentials in the SKILL.md and putting detailed reference in separate files, read only when needed','["Domain_3::Claude_Code_Configuration_Workflows", "Scenario_2::Code_Generation_Claude_Code"]','New',0,2.5,0,1783092988036,1783727365852,1783203558653,replace('**Tradução para português do Brasil:**\n\n**Pergunta:** O que é "progressive disclosure" (revelação progressiva) em Skills?\n\n**Alternativas:**\n[ ] A - Carregar todo o material de referência na inicialização\n[ ] B - Manter o essencial no SKILL.md e colocar a referência detalhada em arquivos separados, lidos apenas quando necessário\n[ ] C - Dividir a skill em vários comandos de barra (/slash commands)\n[ ] D - Compactar automaticamente o SKILL.md a cada sessão','\n',char(10)),replace('**Explicação para adulto (tech lead):**\n\n"Progressive disclosure" é um princípio de design de interação que consiste em apresentar apenas as informações necessárias para a tarefa imediata, revelando detalhes adicionais conforme a demanda do usuário. Aplicado ao contexto de Skills (especialmente em assistentes como o Claude, no qual o arquivo SKILL.md define o comportamento central), a técnica funciona assim:\n\n- **Resposta correta (B):** O SKILL.md contém apenas o essencial — o propósito, as regras de comportamento e a estrutura de alto nível da Skill. As documentações extensas, tabelas, códigos de exemplo, glossários ou listas de API são colocadas em arquivos separados (ex.: `reference/*.md`, `examples/*.md`, `api-specs/*.md`). Esses arquivos não são carregados no contexto do modelo a menos que o usuário ou a própria Skill explicitamente os solicite. Isso poupa tokens de contexto, reduz ruído e evita que informações desnecessárias "gastem" a janela de contexto disponível.\n\n- **Por que A está errada:** Carregar todo o material de referência na inicialização é o oposto da revelação progressiva. Isso sobrecarrega o contexto logo de início, consome tokens preciosos e pode degradar a qualidade da resposta por excesso de informação irrelevante para a conversa corrente.\n\n- **Por que C está errada:** Dividir a skill em vários comandos de barra é uma estratégia de organização da interface — útil para separar funcionalidades, mas não é, por si só, revelação progressiva. Não há relação direta com carregamento seletivo de conteúdo.\n\n- **Por que D está errada:** Compactar automaticamente o SKILL.md a cada sessão (por exemplo, removendo comentários, quebras de linha ou resumindo conteúdo) é uma técnica de compressão ou redução de tamanho, não de revelação progressiva. A revelação progressiva não compacta o conteúdo; ela o organiza em camadas de profundidade.\n\n**Conclusão técnica:** A alternativa B descreve precisamente a aplicação do princípio *progressive disclosure* no contexto de Skills de assistentes de IA: manter a superfície enxuta e revelar detalhes sob demanda.','\n',char(10)),replace('Imagine que você tem uma mochila cheia de livros. Se você colocar todos os livros na mochila de uma vez, ela fica pesada e difícil de carregar. Em vez disso, você coloca só o caderno do dia — o básico — e deixa os livros maiores na estante. Quando precisar de um deles, você vai até a estante e pega. Isso é "revelação progressiva".\n\nEm uma Skill (um programinha que ajuda o assistente a se comportar de um jeito especial), a gente faz a mesma coisa: coloca no arquivo principal (SKILL.md) só o mais importante — como se fosse um resumo do que a Skill faz. Os detalhes enormes, como listas, regras ou exemplos compridos, ficam em outros arquivos "na estante". O assistente só vai ler esses arquivos se alguém pedir ou se for realmente necessário.\n\nAs outras alternativas estão erradas porque:\n- **A** (carregar tudo de uma vez) é como colocar a mochila cheia de todos os livros — pesado demais.\n- **C** (dividir em vários comandos) é como ter vários botões diferentes no controle remoto, não tem a ver com revelar informações aos poucos.\n- **D** (compactar automaticamente) é como apertar o texto para ele ficar menor, mas não é a mesma coisa que deixar os detalhes escondidos para só mostrar quando precisar.\n\nEntão a resposta certa é a **B**: manter o essencial no SKILL.md e colocar a referência detalhada em arquivos separados, lidos só quando necessário.','\n',char(10)));
INSERT INTO cards VALUES('admin','card_1783092988054_shwrplzte',307,'What does the allowed-tools field do in a skill?',replace('What does the allowed-tools field do in a skill?\n\nWhat does the allowed-tools field do in a skill?\n[Resposta correta: allowed-tools pré-aprova as ferramentas listadas (evita o prompt), mas não restringe: as demais seguem as regras normais de permissão. A A é a pegadinha (allowed-tools não restringe); C descreve disallowed-tools; D é inventado.]\n\n[ ] A - It restricts access only to the listed tools, blocking the rest\n[ ] B - It pre-approves the listed tools while the skill is active, without restricting the others\n[ ] C - It lists the tools that should be blocked\n[ ] D - It defines which users can invoke the skill','\n',char(10)),'[ ] B - It pre-approves the listed tools while the skill is active, without restricting the others','["Domain_3::Claude_Code_Configuration_Workflows", "Domain_2::Tool_Design_MCP_Integration", "Scenario_2::Code_Generation_Claude_Code"]','New',0,2.5,0,1783092988054,1783727369130,1783203558653,replace('**Tradução para português do Brasil:**\n\nO que o campo allowed-tools faz em uma skill?\n\n[ ] A - Restringe o acesso apenas às ferramentas listadas, bloqueando as demais\n[ ] B - Pré-aprova as ferramentas listadas enquanto a skill está ativa, sem restringir as outras\n[ ] C - Lista as ferramentas que devem ser bloqueadas\n[ ] D - Define quais usuários podem invocar a skill','\n',char(10)),replace('**Explicação didática para um adulto tech lead:**\n\nO campo `allowed-tools` em uma skill (no contexto de plataformas de agentes de IA, como Amazon Bedrock Agents ou similares) serve para **pré-aprovar** determinadas ferramentas, evitando que o modelo precise pedir permissão ao usuário (via prompt) para utilizá-las. Isso otimiza a experiência, reduzindo interrupções desnecessárias.\n\nA alternativa **B** está correta porque descreve exatamente esse comportamento: as ferramentas listadas em `allowed-tools` são pré-aprovadas automaticamente enquanto a skill estiver ativa, mas as demais ferramentas **não são bloqueadas** — elas continuam seguindo as regras normais de permissão (que podem incluir solicitação de confirmação via prompt ou outras políticas de acesso).\n\nAnalisando as demais alternativas:\n\n- **A (incorreta):** Esta é a "pegadinha". O `allowed-tools` **não restringe** o uso apenas às ferramentas listadas. Ele apenas pré-aprova as listadas, mas as outras ainda podem ser usadas mediante aprovação normal. Confundir "pré-aprovação" com "restrição" é um erro comum.\n\n- **C (incorreta):** Esta descrição corresponde ao campo `disallowed-tools` (ou similar), que explicita quais ferramentas devem ser bloqueadas. O `allowed-tools` faz o oposto: ele lista o que é permitido sem necessidade de aprovação adicional, não o que é proibido.\n\n- **D (incorreta):** Controle de quais usuários podem invocar uma skill é tipicamente feito por mecanismos de autenticação/autorização (IAM, RBAC, etc.), não pelo campo `allowed-tools`. Esta alternativa é completamente inventada e não corresponde à função do campo.','\n',char(10)),replace('**Explicação para uma criança de 10 anos:**\n\nImagina que você tem uma caixa cheia de brinquedos. Alguns brinquedos você pode pegar sem pedir permissão para ninguém — eles estão na "lista de brinquedos liberados". Outros brinquedos você só pode pegar depois de perguntar para um adulto.\n\nO `allowed-tools` é como essa "lista de brinquedos liberados" para um robô inteligente. Quando a skill (que é como um "modo de brincadeira" do robô) está ativa, os brinquedos (ferramentas) que estão nessa lista podem ser usados sem pedir autorização. Os outros brinquedos ainda podem ser usados, mas o robô precisa perguntar antes.\n\nA resposta **B** está certa porque o robô pode usar as ferramentas da lista sem incomodar ninguém, mas ele não fica PROIBIDO de usar as outras — ele só precisa de permissão, como sempre.\n\nA resposta **A** seria como dizer que o robô só pode brincar com os brinquedos da lista e não pode tocar nos outros, o que não é verdade. A resposta **C** seria o contrário: uma lista de brinquedos PROIBIDOS. E a resposta **D** seria sobre quem pode ligar o robô, não sobre as ferramentas que ele usa.','\n',char(10)));
INSERT INTO cards VALUES('admin','card_1783092988073_dawdp9irz',308,'What happens if allowed-tools is omitted in the frontmatter?',replace('What happens if allowed-tools is omitted in the frontmatter?\n\nWhat happens if allowed-tools is omitted in the frontmatter?\n[Resposta correta: Sem allowed-tools, nada é pré-aprovado e o modelo normal de permissões continua valendo. Omitir não impede o carregamento (A), não bloqueia tudo (C) nem pré-aprova tudo (D).]\n\n[ ] A - The skill does not load\n[ ] B - Nothing is pre-approved; Claude follows the normal permission model and asks for confirmation when needed\n[ ] C - All tools are blocked\n[ ] D - All tools are pre-approved by default','\n',char(10)),'B - Nothing is pre-approved; Claude follows the normal permission model and asks for confirmation when needed','["Domain_3::Claude_Code_Configuration_Workflows", "Domain_2::Tool_Design_MCP_Integration", "Scenario_2::Code_Generation_Claude_Code"]','New',0,2.5,0,1783092988073,1783727372440,1783203558653,replace('**Tradução para português do Brasil:**\n\n**Pergunta:** O que acontece se "allowed-tools" for omitido no frontmatter?\n\n**Alternativas:**\n[ ] A - A skill não carrega\n[ ] B - Nada é pré-aprovado; Claude segue o modelo normal de permissões e pede confirmação quando necessário\n[ ] C - Todas as ferramentas são bloqueadas\n[ ] D - Todas as ferramentas são pré-aprovadas por padrão','\n',char(10)),replace('**Explicação para um adulto tech lead:**\n\nO campo `allowed-tools` no frontmatter de uma skill no Claude for Desktop (ou em configurações similares do ecossistema Claude) é um mecanismo opcional de **pré-aprovação** de chamadas de ferramentas. Quando você omite esse campo, nenhuma ferramenta é pré-aprovada automaticamente. O comportamento padrão do modelo de permissões do Claude permanece ativo, ou seja:\n\n- O Claude **pode solicitar** a execução de ferramentas normalmente.\n- Entretanto, o **usuário final** será consultado (através de um diálogo de confirmação) antes de qualquer chamada de ferramenta ser efetivamente executada — a menos que configurações globais de permissão já estejam definidas de outra forma.\n\n**Análise das alternativas:**\n\n- **A: "A skill não carrega"** — Incorreto. A omissão de `allowed-tools` não impede que a skill seja carregada. A skill carrega normalmente; apenas não há uma lista de ferramentas pré-aprovadas. Omitir não causa falha de carregamento.\n- **B: "Nada é pré-aprovado; Claude segue o modelo normal de permissões e pede confirmação quando necessário"** — Correto. Essa é a descrição exata do comportamento. Sem uma lista de `allowed-tools`, cada chamada de ferramenta é tratada pelo mecanismo padrão de permissão, que geralmente exige confirmação explícita do usuário.\n- **C: "Todas as ferramentas são bloqueadas"** — Incorreto. Omitir `allowed-tools` não bloqueia todas as ferramentas. Ele apenas não as pré-aprova. O Claude ainda pode solicitar o uso de ferramentas, mas dependerá da aprovação do usuário no momento da execução. Não há um bloqueio geral.\n- **D: "Todas as ferramentas são pré-aprovadas por padrão"** — Incorreto. Essa seria a consequência de uma política de permissão permissiva, mas não é o comportamento padrão ao omitir `allowed-tools`. A omissão significa "não pré-aprovar nada", e não "pré-aprovar tudo".','\n',char(10)),replace('**Explicação para uma criança de 10 anos:**\n\nImagine que você tem um jogo onde seu amigo robô (o Claude) pode usar ferramentas como "abrir porta", "desenhar" ou "fazer barulho". \n\nO "allowed-tools" é como uma lista de **permissões** que você dá ao robô: "Pode usar essas ferramentas sem me perguntar toda hora."\n\nSe você **não** fizer essa lista (omitir o allowed-tools), o que acontece?\n\n- O robô ainda funciona normal (não quebra).\n- O robô ainda pode tentar usar as ferramentas.\n- Mas, antes de usar qualquer ferramenta, ele vai perguntar: "Posso usar essa ferramenta?" e você precisa dizer "sim" ou "não".\n\nEntão, a resposta certa é a **letra B**: nada é liberado automaticamente, e o robô (Claude) segue o jeito normal de pedir permissão.\n\nAs outras opções estão erradas porque:\n- **A**: O robô não para de funcionar (a skill carrega sim).\n- **C**: Não é que todas as ferramentas são proibidas — elas podem ser usadas, mas com sua permissão.\n- **D**: Também não é que todas são liberadas sem perguntar — isso seria o contrário!','\n',char(10)));
INSERT INTO cards VALUES('admin','card_1783092988089_mwunx7ns3',309,'What is the practical size rule for the SKILL.',replace('What is the practical size rule for the SKILL.\n\nWhat is the practical size rule for the SKILL.md?\n[Resposta correta: A recomendação é manter o SKILL.md abaixo de ~500 linhas e, se passar, dividir em arquivos de referência. As demais confundem com limites de outros campos ou negam a recomendação.]\n\n[ ] A - Keep below ~64 lines\n[ ] B - Keep below ~500 lines; if it exceeds that, split into reference files\n[ ] C - Keep below ~1,024 characters\n[ ] D - There is no recommended limit','\n',char(10)),'[ ] B - Keep below ~500 lines; if it exceeds that, split into reference files','["Domain_3::Claude_Code_Configuration_Workflows", "Scenario_2::Code_Generation_Claude_Code"]','New',0,2.5,0,1783092988089,1783727375794,1783203558653,replace('**Tradução da pergunta e alternativas para Português do Brasil:**\n\n**Pergunta:** Qual é a regra prática de tamanho para o SKILL.md?\n\n**Alternativas:**\n\n[ ] A - Manter abaixo de ~64 linhas\n[ ] B - Manter abaixo de ~500 linhas; se exceder, dividir em arquivos de referência\n[ ] C - Manter abaixo de ~1.024 caracteres\n[ ] D - Não há limite recomendado','\n',char(10)),replace('**Explicação para um adulto tech lead:**\n\nA alternativa **B** é a correta porque reflete a recomendação oficial documentada nas práticas de design de instruções para modelos de IA (como no padrão proposto por Anthropic e seguido por boas práticas de engenharia de prompt). O SKILL.md é um arquivo de habilidade que descreve como um agente ou assistente deve executar uma tarefa específica. A recomendação prática é mantê-lo conciso — idealmente abaixo de ~500 linhas — para garantir que o modelo consiga processar e seguir as instruções sem perda de contexto ou degradação de desempenho. Caso o conteúdo ultrapasse esse limite, a orientação é modularizar: dividir o SKILL em múltiplos arquivos de referência (por exemplo, separando lógica, exemplos, validações) e invocá-los conforme necessário, mantendo o SKILL.md principal enxuto.\n\n**Análise das alternativas incorretas:**\n\n- **Alternativa A** (~64 linhas): Esse número é muito restritivo e não condiz com a recomendação prática. 64 linhas pode ser um limite citado em outros contextos (ex.: tamanho de respostas curtas ou campos de descrição resumida), mas não se aplica ao SKILL.md. Seria inviável para habilidades minimamente complexas.\n- **Alternativa C** (~1.024 caracteres): Confunde limite de caracteres com limite de linhas. Além disso, 1.024 caracteres é extremamente pequeno para um SKILL.md — menos que um parágrafo médio. Essa métrica parece vir de campos de formulário ou restrições de sistemas legados, não de boas práticas de design de habilidades.\n- **Alternativa D** (nenhum limite): Negar a existência de um limite prático vai contra a recomendação explícita. Embora não haja um limite técnico rígido, a orientação pragmática existe justamente para evitar problemas de processamento e manutenção. Dizer que "não há limite" é desinformação.','\n',char(10)),replace('Imagine que o SKILL.md é como um manual de instruções para um robô ajudante. Se o manual for muito grande, o robô pode ficar confuso ou demorar muito para ler tudo. Por isso, a recomendação é escrever um manual que não ultrapasse umas 500 linhas — mais ou menos umas 10 páginas de caderno. Se o manual precisar ser maior que isso, a gente divide ele em vários livretos menores, cada um falando de uma parte específica. Assim o robô entende direitinho e não se perde.\n\nAs outras opções estão erradas:\n- A de 64 linhas seria um manual tão pequeno que mal daria para explicar uma receita de bolo.\n- A de 1.024 caracteres é o tamanho de um tweet grande — impossível explicar uma tarefa completa.\n- A que diz que não tem limite estaria errada porque, na prática, todo mundo sabe que manual gigante confunde até robô.','\n',char(10)));
INSERT INTO cards VALUES('admin','card_1783092988107_u15ui53j4',310,'You want an onboarding skill that only reads the code, without modifying anything.',replace('You want an onboarding skill that only reads the code, without modifying anything.\n\nYou want an onboarding skill that only reads the code, without modifying anything. How do you configure it?\n[Resposta correta: Para restringir escrita, use disallowed-tools (ou deny em /permissions); allowed-tools só pré-aprova, não bloqueia. A A cai na pegadinha do allowed-tools; C e D não impedem edição.]\n\n[ ] A - List Read in allowed-tools, which blocks Edit and Write\n[ ] B - Use disallowed-tools listing Edit, Write, MultiEdit, or deny rules in /permissions\n[ ] C - Omit the frontmatter to disable writing\n[ ] D - Set user-invocable: false','\n',char(10)),'B - Use disallowed-tools listing Edit, Write, MultiEdit, or deny rules in /permissions','["Domain_3::Claude_Code_Configuration_Workflows", "Domain_2::Tool_Design_MCP_Integration", "Scenario_2::Code_Generation_Claude_Code"]','New',0,2.5,0,1783092988107,1783727379142,1783203558653,replace('**Tradução:**\n\n> Você quer uma skill de integração que apenas leia o código, sem modificar nada. Como você a configura?\n>\n> [ ] A - Listar "Read" em allowed-tools, o que bloqueia Edit e Write\n> [ ] B - Usar disallowed-tools listando Edit, Write, MultiEdit, ou regras de negação em /permissions\n> [ ] C - Omitir o frontmatter para desabilitar a escrita\n> [ ] D - Definir user-invocable: false','\n',char(10)),replace('**Explicação para um adulto tech lead:**\n\nO objetivo é criar uma skill que tenha permissão **somente de leitura** no código, ou seja, que **não possa modificar arquivos**.\n\nVamos analisar cada alternativa:\n\n- **Alternativa B (correta):** Esta é a abordagem correta. O sistema de permissões de ferramentas (tools) em plataformas como Cursor, Windsurf, Copilot ou similares geralmente funciona com uma lista de negação explícita. Usar `disallowed-tools` (ou regras de `deny` em `/permissions`) para bloquear explicitamente ferramentas de edição/escrita (`Edit`, `Write`, `MultiEdit`) é a maneira mais segura e semanticamente correta de garantir que a skill nunca irá modificar o código. A lista de negação é avaliada e impede o uso das ferramentas listadas.\n\n- **Alternativa A (incorreta):** Esta é uma pegadinha clássica. `allowed-tools` é uma **lista de permissões** (whitelist). Ela define quais ferramentas estão *pré-aprovadas* para uso, mas **não bloqueia** ferramentas que não estão na lista. Em muitos sistemas, o comportamento padrão é que ferramentas não listadas no `allowed-tools` podem ser solicitadas, mas exigem aprovação do usuário (ou do sistema) no momento do uso. Portanto, ela não impede a edição de forma eficaz; apenas torna a edição um passo extra.\n\n- **Alternativa C (incorreta):** O frontmatter (metadados no início do arquivo de configuração da skill) geralmente contém instruções de descrição, modelo, ou configurações de comportamento, mas omiti-lo **não** desabilita funcionalidades de escrita. A skill ainda pode invocar ferramentas de edição. Remover o frontmatter apenas torna o arquivo de configuração potencialmente inválido ou sem contexto, mas não é um mecanismo de segurança para controle de acesso.\n\n- **Alternativa D (incorreta):** A opção `user-invocable: false` (ou similar) determina se a skill pode ser chamada diretamente pelo usuário, e não o que ela pode fazer. Uma skill pode ser não-invocável pelo usuário, mas ainda assim ser ativada por outros processos (como agentes automáticos) e ter permissões de escrita. Isso não resolve o problema de restringir a skill a apenas leitura.\n\n**Conclusão:** A alternativa B é a única que implementa uma restrição efetiva de escrita através do mecanismo de negação explícita de ferramentas de modificação.','\n',char(10)),replace('Imagine que você tem um robô assistente. Você quer que ele só *olhe* para o seu dever de casa, mas nunca *escreva* nada nele, certo?\n\n- **Alternativa B (correta):** É como dar uma ordem clara para o robô: "Você está proibido de usar caneta, lápis ou pincel." Listar as ferramentas proibidas é a forma mais direta de garantir que ele não vai rabiscar nada.\n\n- **Alternativa A (incorreta):** É como fazer uma lista do que ele *pode* usar (só os olhos). Mas se a lista não disser que ele não pode usar caneta, ele pode pegar uma e perguntar "Posso?". A pessoa pode esquecer e falar "Pode". Então não é seguro.\n\n- **Alternativa C (incorreta):** É como tirar a capa do caderno de instruções do robô. Isso não impede ele de pegar uma caneta se ele quiser.\n\n- **Alternativa D (incorreta):** É como dizer para o robô "você não pode ser ligado pelo botão". Mas ele ainda pode ser ligado por controle remoto e sair escrevendo. Isso não resolve o problema.\n\n**Resumindo:** Para ter certeza que o robô só vai olhar, o melhor é falar exatamente o que ele está proibido de usar: a caneta.','\n',char(10)));
INSERT INTO cards VALUES('admin','card_1783092988153_aaiqx99qp',311,'According to the open standard, how do you organize the directory of a complex skill?',replace('According to the open standard, how do you organize the directory of a complex skill?\n\nAccording to the open standard, how do you organize the directory of a complex skill?\n[Resposta correta: O open standard sugere scripts/, references/ e assets/ para separar código, documentação e dados. A A ignora a organização; C e D descrevem estruturas de projeto ou de hooks, não de skill.]\n\n[ ] A - Everything in a single SKILL.md, without subdirectories\n[ ] B - scripts/ for executable code, references/ for documentation and assets/ for images/templates/data\n[ ] C - src/, dist/ and node_modules/\n[ ] D - One directory per hook event','\n',char(10)),'B - scripts/ for executable code, references/ for documentation and assets/ for images/templates/data','["Domain_3::Claude_Code_Configuration_Workflows", "Domain_2::Tool_Design_MCP_Integration", "Scenario_2::Code_Generation_Claude_Code"]','New',0,2.5,0,1783092988153,1783727383199,1783203558653,replace('**Tradução fiel para português do Brasil:**\n\n**Pergunta:** De acordo com o padrão aberto, como você organiza o diretório de uma skill complexa?\n\n**Alternativas:**\n\n[ ] A - Tudo em um único SKILL.md, sem subdiretórios\n[ ] B - scripts/ para código executável, references/ para documentação e assets/ para imagens/modelos/dados\n[ ] C - src/, dist/ e node_modules/\n[ ] D - Um diretório por evento de hook','\n',char(10)),replace('**Explicação didática para um adulto tech lead:**\n\nA pergunta se refere à organização de diretórios de skills no contexto de um padrão aberto, como o definido pelo Open Skills Standard (ou similar, como o modelo de skills da OWASP ou do ecossistema de agentes autônomos). O objetivo é estruturar skills complexas de forma modular, legível e reutilizável.\n\n**Alternativa correta: B**\n\nA alternativa B reflete exatamente a recomendação do padrão aberto para skills complexas. O uso de subdiretórios como `scripts/` (código executável), `references/` (documentação, como arquivos de especificação, guias) e `assets/` (dados estáticos, imagens, templates) promove a separação de preocupações (Separation of Concerns). Essa estrutura facilita a manutenção, a colaboração e a validação automatizada por ferramentas que consomem skills. É uma abordagem madura para engenharia de software aplicada a skills.\n\n**Por que as demais estão incorretas:**\n\n- **Alternativa A ("Tudo em um único SKILL.md, sem subdiretórios")**: Ignora completamente a necessidade de organização modular. Em skills complexas, um único arquivo torna o código monolítico, difícil de manter, versionar e testar. O padrão aberto recomenda justamente o oposto: modularização.\n\n- **Alternativa C ("src/, dist/ e node_modules/")**: Essa estrutura é típica de projetos Node.js ou de aplicações web, mas não corresponde ao padrão aberto para skills. Embora `src/` e `dist/` sejam comuns em compilação/transpilação, o padrão de skills não utiliza esses diretórios como convenção principal. Além disso, `node_modules/` é um artefato de gerenciamento de dependências, não uma estrutura de skill.\n\n- **Alternativa D ("Um diretório por evento de hook")**: Essa estrutura seria apropriada para organizar hooks ou handlers de eventos específicos (ex.: `on_new_message/`, `on_click/`), mas não é a recomendação do padrão aberto para organizar uma skill completa. Ela confunde a organização de skills com a organização de hooks, que são um conceito diferente.','\n',char(10)),replace('Imagine que você tem um projeto de escola muito grande. Em vez de colocar tudo numa pasta só bagunçada, o padrão aberto ensina a criar pastas organizadas: uma para os "comandos" (scripts/), outra para as "explicações" (references/) e outra para as "figuras e dados" (assets/). A alternativa B é a certa porque faz isso.\n\nAs outras opções estão erradas: a A coloca tudo amontoado, a C usa pastas de programação de computadores que não são para isso, e a D organiza por eventos, que é outro tipo de coisa.','\n',char(10)));
INSERT INTO cards VALUES('admin','card_1783092988171_ud1ffxg12',312,'You need a consistent and reliable operation (e.',replace('You need a consistent and reliable operation (e.\n\nYou need a consistent and reliable operation (e.g. environment validation). A script or a model-generated instruction?\n[Resposta correta: Um script testado é mais confiável que instrução gerada e roda sem carregar seu conteúdo no contexto. Instrução gerada é probabilística; CLAUDE.md e hook não substituem o script confiável nesse cenário.]\n\n[ ] A - A generated instruction, since it is more flexible\n[ ] B - A script in the skill''s directory, more reliable as tested code and that runs without loading its content into the context\n[ ] C - An entry in the CLAUDE.md describing the step by step\n[ ] D - A PreToolUse hook generating the result on the fly','\n',char(10)),'B - A script in the skill''s directory, more reliable as tested code and that runs without loading its content into the context','["Domain_3::Claude_Code_Configuration_Workflows", "Domain_5::Context_Management_Reliability", "Scenario_4::Developer_Productivity"]','New',0,2.5,0,1783092988171,1783727386674,1783203558653,replace('**Tradução para português do Brasil:**\n\nVocê precisa de uma operação consistente e confiável (ex.: validação de ambiente). Um script ou uma instrução gerada por modelo?\n\n[ ] A - Uma instrução gerada, pois é mais flexível\n[ ] B - Um script no diretório da skill, mais confiável por ser código testado e que roda sem carregar seu conteúdo no contexto\n[ ] C - Uma entrada no CLAUDE.md descrevendo o passo a passo\n[ ] D - Um hook PreToolUse gerando o resultado na hora','\n',char(10)),replace('**Explicação técnica para um adulto tech lead:**\n\nA pergunta aborda um dilema comum em sistemas que combinam código determinístico com modelos de linguagem: como garantir execução consistente e confiável de operações críticas (como validação de ambiente).\n\nA alternativa **B** é a correta porque:\n\n1. **Determinismo vs. Probabilismo**: Um script é código executável testado, que produz o mesmo resultado para as mesmas entradas (determinístico). Uma instrução gerada por modelo (alternativa A) é probabilística — o modelo pode alucinar, omitir passos ou interpretar incorretamente o comando, levando a inconsistências.\n\n2. **Contexto limitado**: Scripts executam sem consumir tokens do contexto do modelo. Instruções ou hooks gerados por IA ocupam espaço precioso na janela de contexto e podem degradar a performance do modelo para outras tarefas.\n\n3. **Testabilidade**: Scripts podem ser versionados, testados unitariamente e integrados em pipelines de CI/CD. Instruções em CLAUDE.md (alternativa C) ou hooks (alternativa D) dependem de interpretação do modelo, o que introduz variabilidade e dificulta testes automatizados.\n\n**Por que as demais estão erradas:**\n\n- **A (Instrução gerada)**: Embora flexível, é probabilística e não-garantida. Para operações que exigem consistência (como validação de ambiente antes de um deploy), confiar em um modelo de linguagem é arriscado.\n\n- **C (Entrada no CLAUDE.md)**: Documentação descritiva depende que o modelo leia, interprete e execute corretamente o passo a passo. Não há garantia de execução fiel, e o conteúdo precisa ser carregado no contexto.\n\n- **D (Hook PreToolUse)**: Hooks gerados na hora sofrem do mesmo problema das instruções geradas — são probabilísticos. Além disso, hooks tendem a ser executados antes de ferramentas, mas ainda dependem de geração do modelo, introduzindo latência e incerteza.\n\n**Resumo**: Para operações que exigem confiabilidade, consistência e baixo custo de contexto, um script testado é sempre superior a qualquer abordagem baseada em geração de linguagem natural.','\n',char(10)),replace('**Explicação para uma criança de 10 anos:**\n\nImagine que você precisa fazer uma tarefa toda vez que usa o computador, como verificar se seu jogo favorito está atualizado. Você tem duas opções:\n\n1. **Um robô que você já programou** com passos certinhos — ele sempre faz exatamente a mesma coisa, sem erros. É como uma receita de bolo que já funcionou muitas vezes.\n2. **Pedir para um amigo inventar as instruções na hora** — ele pode esquecer algo, se confundir ou inventar um passo errado.\n\nA pergunta é: o que é melhor para uma tarefa que precisa dar certo sempre?\n\nA resposta certa é a **B**: usar um script (um programinha) que já foi testado e funciona. É como o robô programado. Ele é confiável porque:\n- Sempre faz igual\n- Não ocupa espaço da memória do seu amigo (o "contexto" do computador)\n- Já foi testado antes\n\nAs outras opções são como pedir para alguém inventar na hora (opção A), escrever num post-it e esperar que a pessoa leia certo (opção C), ou pedir para um robô mal treinado fazer na hora (opção D). Nenhuma é tão confiável quanto um programinha testado!','\n',char(10)));
INSERT INTO cards VALUES('admin','card_1783092988189_b1lwcfuud',313,'Why do scripts save context and what instruction do you give in the SKILL.',replace('Why do scripts save context and what instruction do you give in the SKILL.\n\nWhy do scripts save context and what instruction do you give in the SKILL.md?\n[Resposta correta: O script roda sem carregar o conteúdo no contexto, então instrua o Claude a rodá-lo, não a lê-lo (só a saída gasta tokens). A A inverte a instrução; a C ignora o custo da saída; a D contraria a economia de contexto.]\n\n[ ] A - Because Claude reads the whole script into the context before running; instruct it to read it first\n[ ] B - Because the script runs without loading its content into the context (only the output consumes tokens); instruct Claude to run it, not to read it\n[ ] C - Because scripts do not consume tokens at any stage\n[ ] D - Because the SKILL.md should contain all the script code inline','\n',char(10)),'B - Because the script runs without loading its content into the context (only the output consumes tokens); instruct Claude to run it, not to read it','["Domain_3::Claude_Code_Configuration_Workflows", "Domain_5::Context_Management_Reliability", "Scenario_2::Code_Generation_Claude_Code"]','New',0,2.5,0,1783092988189,1783727389856,1783203558653,replace('**Tradução para português do Brasil:**\n\n**Pergunta:** Por que os scripts salvam contexto e qual instrução você dá no SKILL.md?\n\n[ ] A - Porque o Claude lê o script inteiro no contexto antes de executar; instrua-o a lê-lo primeiro  \n[ ] B - Porque o script roda sem carregar seu conteúdo no contexto (apenas a saída consome tokens); instrua o Claude a executá-lo, não a lê-lo  \n[ ] C - Porque scripts não consomem tokens em nenhum estágio  \n[ ] D - Porque o SKILL.md deve conter todo o código do script inline','\n',char(10)),replace('**Explicação para um adulto (tech lead):**\n\n**Resposta correta: B**\n\nO mecanismo central aqui é a economia de tokens no contexto. Quando você salva um script separado (ex.: via Artifacts ou MCP), o conteúdo do script **não é carregado no contexto de diálogo** — apenas a saída da execução do script é que gasta tokens. Isso é crucial para projetos de longa duração ou com scripts complexos, pois o custo de manter todo o código-fonte no contexto seria proibitivo.\n\nPortanto, a instrução correta no `SKILL.md` (ou arquivo de skill) deve ser algo como: *"Execute o script X, não leia seu conteúdo"*. Isso direciona o modelo a apenas chamar o script e processar sua saída, sem desperdiçar tokens com o código-fonte.\n\n**Análise das alternativas incorretas:**\n\n- **A** — Afirma o oposto do que realmente acontece. O Claude **não** carrega o script inteiro no contexto antes de executar. Se instruíssemos o modelo a "ler primeiro", estaríamos justamente fazendo o que queremos evitar: carregar o script no contexto e queimar tokens desnecessariamente.\n\n- **C** — Enganosa. Scripts **não consomem tokens enquanto estão salvos externamente**, mas a saída da execução **consome sim** tokens. A alternativa sugere que "não consomem tokens em nenhum estágio", o que é falso — a saída sempre gasta tokens, e o objetivo é minimizar esse gasto.\n\n- **D** — Incorreta e contraditória com a premissa de economia de contexto. Colocar todo o código inline no SKILL.md aumentaria drasticamente o consumo de tokens, exatamente o oposto do que se deseja.','\n',char(10)),replace('**Explicação para uma criança de 10 anos:**\n\nImagina que você tem um livro de receitas (o SKILL.md) e uma receita muito longa (o script). Se você copiar a receita inteira dentro do livro, o livro fica enorme e pesado. Mas se você colocar a receita em um papel separado e só disser "vai lá e faz a receita", o livro continua leve e fácil de carregar.\n\nÉ a mesma coisa com o Claude! Se você mandar ele ler o script inteiro, gasta muitos "tokens" (que são como moedas de energia). Mas se você mandar ele **executar** o script sem ler ele todo, só o resultado (a saída) gasta algumas moedinhas. Muito mais econômico!\n\n**Por que as outras opções estão erradas?**  \n- A: Diz pra ler o script primeiro — isso gastaria moedas à toa.  \n- C: Diz que scripts não gastam moedas nunca — mas o resultado do script gasta sim.  \n- D: Diz pra colocar o código inteiro no livro — isso deixaria o livro pesadíssimo!','\n',char(10)));
INSERT INTO cards VALUES('admin','card_1783092988207_t9clle1ii',314,'An architecture guide is only relevant for some questions.',replace('An architecture guide is only relevant for some questions.\n\nAn architecture guide is only relevant for some questions. How do you avoid loading it always?\n[Resposta correta: Linkar o arquivo no SKILL.md com instrução de quando carregá-lo faz o Claude lê-lo só quando o tópico casa. As demais fariam o conteúdo carregar sempre ou em toda requisição.]\n\n[ ] A - Put it entirely in the CLAUDE.md\n[ ] B - Link it in the SKILL.md with a clear instruction of when to load it, so Claude only reads it when the request matches\n[ ] C - Copy it into the main SKILL.md\n[ ] D - Reference it with @ in the CLAUDE.md','\n',char(10)),'B - Link it in the SKILL.md with a clear instruction of when to load it, so Claude only reads it when the request matches','["Domain_3::Claude_Code_Configuration_Workflows", "Domain_5::Context_Management_Reliability", "Scenario_2::Code_Generation_Claude_Code"]','New',0,2.5,0,1783092988207,1783727393245,1783203558653,replace('**Tradução para português do Brasil:**\n\nPergunta: Um guia de arquitetura só é relevante para algumas perguntas. Como evitar carregá-lo sempre?\n\n[ ] A - Colocá-lo inteiramente no CLAUDE.md\n[ ] B - Linká-lo no SKILL.md com uma instrução clara de quando carregá-lo, para que Claude o leia apenas quando a requisição corresponder\n[ ] C - Copiá-lo para o SKILL.md principal\n[ ] D - Referenciá-lo com @ no CLAUDE.md','\n',char(10)),replace('**Explicação para adulto (tech lead):**\n\nA resposta correta é a **alternativa B**.\n\nO problema central aqui é sobre eficiência no uso de contexto e tokens. Um "guia de arquitetura" é um documento extenso que descreve decisões arquiteturais, padrões e restrições do projeto. Na maioria das interações com Claude (ou qualquer LLM em um ambiente de desenvolvimento como Cursor, Copilot, etc.), esse guia simplesmente não é necessário — por exemplo, perguntas sobre lógica de negócio simples ou correção de bugs pontuais não exigem conhecimento arquitetural profundo.\n\n**Por que a B é a melhor abordagem:**\n- SKILL.md (ou arquivos similares de contexto/prompt) é tipicamente carregado como instrução base para o modelo.\n- Ao *linkar* o guia dentro desse arquivo com uma instrução condicional explícita (ex.: "Carregue este documento apenas quando a pergunta envolver decisões de arquitetura, como escolha de padrões, estrutura de microsserviços, etc."), você delega ao modelo a decisão de quando consumir aquele conteúdo.\n- Isso reduz drasticamente o consumo de tokens em requisições onde o guia é irrelevante, mantendo a capacidade de acessá-lo quando necessário.\n\n**Por que as demais estão erradas:**\n\n- **A** (Colocar inteiramente no CLAUDE.md): CLAUDE.md (ou equivalente) é geralmente carregado em *todas* as requisições como contexto fixo. Isso faria o guia inteiro ser consumido sempre, exatamente o oposto do desejado.\n\n- **C** (Copiar para o SKILL.md principal): Mesmo problema da A. SKILL.md é carregado como instrução base, então todo o conteúdo do guia seria injetado em todas as interações, desperdiçando tokens e potencialmente diluindo instruções mais relevantes.\n\n- **D** (Referenciar com @ no CLAUDE.md): A anotação `@` geralmente indica inclusão inline ou referência de arquivo que é resolvida e carregada no momento da leitura do arquivo. Dependendo da implementação, isso pode resultar no mesmo problema de carregamento sempre, ou no mínimo não oferece a mesma flexibilidade condicional que um link com instrução explícita no SKILL.md.','\n',char(10)),replace('**Explicação para criança de 10 anos:**\n\nImagine que você tem um livro gigante de regras de um jogo de tabuleiro. Mas você só precisa dele quando vai jogar um jogo novo, não quando vai apenas organizar as peças na caixa.\n\nSe você colocar o livro inteiro na sua mochila todos os dias (alternativas A, C e D), você carrega peso extra desnecessário. A melhor ideia (alternativa B) é deixar o livro na estante e colocar um bilhete na sua mochila dizendo: "Pegue o livro só quando for jogar um jogo novo". Assim, você só carrega o peso quando realmente precisa.\n\nNo nosso caso, Claude (o assistente) é como a pessoa que carrega a mochila. Se a gente colocar o guia de arquitetura (o livro de regras) em todo lugar, ele vai ler aquilo em toda conversa, mesmo quando não precisa. Mas se a gente colocar uma instrução esperta no SKILL.md (o bilhete), Claude só vai ler o guia quando a pergunta for sobre arquitetura. Economiza energia e atenção!','\n',char(10)));
INSERT INTO cards VALUES('admin','card_1783092988224_sjc0y8nc2',315,'What is the fundamental loading difference between CLAUDE.',replace('What is the fundamental loading difference between CLAUDE.\n\nWhat is the fundamental loading difference between CLAUDE.md and skills?\n[Resposta correta: CLAUDE.md é always-on e skills carregam sob demanda pelo matching da description. As demais invertem ou negam esse comportamento.]\n\n[ ] A - Both load on demand\n[ ] B - CLAUDE.md loads in every conversation (always-on); skills load on demand when the request matches\n[ ] C - CLAUDE.md loads on demand; skills load always\n[ ] D - Neither is loaded automatically','\n',char(10)),'B - CLAUDE.md loads in every conversation (always-on); skills load on demand when the request matches','["Domain_3::Claude_Code_Configuration_Workflows", "Scenario_2::Code_Generation_Claude_Code"]','New',0,2.5,0,1783092988224,1783727396120,1783203558653,replace('**Tradução para Português do Brasil:**\n\nQual é a diferença fundamental de carregamento entre CLAUDE.md e skills?\n\n[ ] A - Ambos carregam sob demanda\n[ ] B - CLAUDE.md carrega em todas as conversas (sempre ativo); skills carregam sob demanda quando a solicitação corresponde\n[ ] C - CLAUDE.md carrega sob demanda; skills carregam sempre\n[ ] D - Nenhum dos dois é carregado automaticamente','\n',char(10)),replace('**Explicação para um adulto tech lead:**\n\nO comportamento esperado de um sistema que utiliza tanto um arquivo de configuração global (CLAUDE.md) quanto habilidades modulares (skills) segue uma lógica de carregamento bem definida para otimizar recursos e garantir previsibilidade.\n\n- **Alternativa correta: B**. O CLAUDE.md funciona como um arquivo de configuração de sistema que deve estar disponível em todas as sessões para garantir que diretrizes, regras de comportamento e contexto global estejam sempre presentes. As skills, por outro lado, são carregadas sob demanda com base em matching de descrição, evitando overhead desnecessário e permitindo um ecossistema escalável de funcionalidades.\n\n- **Alternativa A**: Incorreta porque nega o carregamento always-on do CLAUDE.md, que é essencial para manter consistência entre conversas.\n\n- **Alternativa C**: Incorreta porque inverte o comportamento: o CLAUDE.md não pode ser carregado sob demanda, pois isso comprometeria diretrizes obrigatórias; e skills não podem ficar always-on sem critério, pois isso inflaria o contexto desnecessariamente.\n\n- **Alternativa D**: Incorreta porque nega o carregamento automático do CLAUDE.md, que ocorre sim em toda conversa.\n\nPortanto, a diferença fundamental é que CLAUDE.md é always-on (carregado em toda conversa), enquanto skills seguem um modelo de carregamento sob demanda baseado em matching semântico.','\n',char(10)),replace('**Explicação para uma criança de 10 anos:**\n\nImagine que você tem uma mochila especial para ir à escola.\n\n- O **CLAUDE.md** é como o seu caderno de regras da sala. Ele fica sempre com você, em todas as aulas, o dia inteiro. Você não precisa pedir para ele aparecer — ele já está lá.\n- As **skills** são como brinquedos ou jogos que você só pega quando precisa. Se você vai jogar futebol na educação física, você pega a bola. Se vai desenhar, pega os lápis de cor. Eles não ficam todos na sua mesa o tempo todo, só quando a atividade combina com eles.\n\nA alternativa **B** é a certa porque diz exatamente isso: o CLAUDE.md está sempre ligado (como o caderno de regras), e as skills só aparecem quando a "descrição" delas combina com o que você está fazendo (como pegar a bola só na hora do futebol). As outras alternativas trocam essa lógica ou dizem que nada carrega, o que não é verdade.','\n',char(10)));
INSERT INTO cards VALUES('admin','card_1783092988242_b6mk74e01',316,'A restriction should always apply, like "never modify the database schema".',replace('A restriction should always apply, like "never modify the database schema".\n\nA restriction should always apply, like "never modify the database schema". Where do you put it?\n[Resposta correta: Constraints sempre-ativas vão no CLAUDE.md, que carrega em toda conversa. Skill carrega sob demanda, comando exige invocação e Notification é um evento, nenhum garante a regra sempre presente.]\n\n[ ] A - In a skill, which loads on demand\n[ ] B - In the CLAUDE.md, since it is an always-active constraint of the project\n[ ] C - In .claude/commands/, by slash\n[ ] D - In a Notification hook','\n',char(10)),'B - In the CLAUDE.md, since it is an always-active constraint of the project','["Domain_3::Claude_Code_Configuration_Workflows", "Domain_4::Prompt_Engineering_Structured_Output", "Scenario_2::Code_Generation_Claude_Code"]','New',0,2.5,0,1783092988242,1783727399722,1783203558653,replace('**Tradução para português do Brasil:**\n\n**Pergunta:** Uma restrição deve sempre ser aplicada, como "nunca modificar o esquema do banco de dados". Onde você a coloca?\n\n[ ] A - Em uma skill, que carrega sob demanda  \n[ ] B - No CLAUDE.md, já que é uma restrição sempre ativa do projeto  \n[ ] C - Em .claude/commands/, via barra (slash)  \n[ ] D - Em um hook de Notificação','\n',char(10)),replace('**Explicação para um adulto tech lead:**\n\nA pergunta aborda o *design de sistema de regras persistentes* no ecossistema Claude (ou assistentes similares). O requisito é claro: a restrição deve ser **sempre aplicada**, ou seja, estar presente em **todas as interações**, sem necessidade de invocação explícita.\n\n- **Alternativa correta (B):** O `CLAUDE.md` é o arquivo de configuração de projeto que é carregado automaticamente no *contexto de sistema* (system prompt) de toda conversa. Seu conteúdo age como uma diretriz permanente, exatamente como uma restrição de projeto que não pode ser esquecida. É o equivalente a colocar uma regra no `prompt` base do assistente. Qualquer restrição colocada ali será "sempre-ativa" porque o arquivo é lido a cada novo turno de conversa.\n\n- **Alternativa A (incorreta):** Skills são acionadas sob demanda, via invocação explícita ou matching de intenção. Se a restrição precisa valer *sempre*, depender de carregamento sob demanda é frágil — o desenvolvedor pode esquecer de ativar a skill, ou a skill pode não ser invocada no contexto correto.\n\n- **Alternativa C (incorreta):** Comandos em `.claude/commands/` são atalhos acionados por `/comando`. Eles são úteis para ações rápidas, mas não se aplicam automaticamente. Uma restrição crítica não pode depender de digitação manual de um comando.\n\n- **Alternativa D (incorreta):** Hooks de notificação disparam eventos específicos (ex.: ao iniciar conversa, ao receber upload). Embora possam aplicar regras em momentos pontuais, não garantem que a restrição estará ativa *durante toda a conversa*, a menos que o hook reescreva o contexto a cada mensagem — o que não é o propósito do mecanismo.\n\n**Conclusão técnica:** Para regras que devem ser invariantes (ex.: "nunca alterar schema de banco", "sempre usar HTTPS", "jamais expor credenciais"), o único local que garante vigência contínua e automática é o arquivo de configuração de projeto que alimenta o *system prompt* — no caso, o `CLAUDE.md`.','\n',char(10)),replace('Imagine que você tem um robô assistente que te ajuda a fazer lição de casa. Você quer que ele **sempre** lembre de uma regra importante, tipo "nunca rabiscar o livro da biblioteca". Onde você escreve essa regra?\n\n- **Opção A (Skill):** Seria como dar um comando de voz para o robô: "Lembre disso!". Mas se você esquecer de falar, ele não vai lembrar sozinho.\n- **Opção B (CLAUDE.md - correta):** É como escrever a regra num post-it gigante e colar na testa do robô. Ele vai ler aquilo **toda hora**, sem precisar que você lembre ele.\n- **Opção C (Comando /):** É como ter um botão mágico que você precisa apertar toda vez que quer que a regra valha. Se você não apertar, a regra não vale.\n- **Opção D (Notificação):** É como um alarme que toca só em certos momentos. Mas entre um alarme e outro, o robô pode fazer o que não devia.\n\n**Resposta certa:** CLAUDE.md, porque a regra fica ligada o tempo todo, igual um aviso que o robô nunca tira da frente dos olhos.','\n',char(10)));
INSERT INTO cards VALUES('admin','card_1783092988262_3xo0ziwwn',317,'An expertise is only relevant sometimes (e.',replace('An expertise is only relevant sometimes (e.\n\nAn expertise is only relevant sometimes (e.g. a review checklist). Skill or CLAUDE.md?\n[Resposta correta: Conhecimento eventual deve virar skill, para não poluir o contexto sempre. CLAUDE.md ficaria sempre carregado; hook é por evento; regra por glob é por caminho de arquivo, não por tarefa.]\n\n[ ] A - CLAUDE.md, to ensure it is always available\n[ ] B - Skill, since it is only occasionally relevant and would pollute the context if always loaded\n[ ] C - A PostToolUse hook\n[ ] D - A rule by glob in .claude/rules/','\n',char(10)),'B - Skill, since it is only occasionally relevant and would pollute the context if always loaded','["Domain_3::Claude_Code_Configuration_Workflows", "Domain_5::Context_Management_Reliability", "Scenario_2::Code_Generation_Claude_Code"]','New',0,2.5,0,1783092988262,1783727402682,1783203558653,replace('**Tradução da pergunta e alternativas:**\n\n**Pergunta:** Uma expertise é relevante apenas às vezes (ex.: uma checklist de revisão). Skill ou CLAUDE.md?\n\n**Alternativas:**\n[ ] A - CLAUDE.md, para garantir que esteja sempre disponível\n[ ] B - Skill, já que é relevante apenas ocasionalmente e poluiria o contexto se carregada sempre\n[ ] C - Um hook PostToolUse\n[ ] D - Uma regra por glob em .claude/rules/','\n',char(10)),replace('**Explicação para um adulto tech lead:**\n\nA questão aborda o design de sistemas de contexto para assistentes de IA (como Claude) em projetos de software, especificamente onde armazenar conhecimento que é relevante apenas em momentos específicos.\n\n**Análise da resposta correta (Alternativa B):**\n\nA alternativa B está correta porque **Skills** são mecanismos projetados exatamente para conhecimento de uso pontual. Elas não são carregadas no contexto permanentemente — são ativadas sob demanda, quando o assunto ou tarefa específica é identificada. Isso evita desperdício de tokens e mantém o foco do assistente no que é relevante para o momento.\n\n**Por que as demais alternativas estão incorretas:**\n\n- **A (CLAUDE.md):** Este arquivo é carregado **sempre** no início de cada conversa. Colocar uma checklist de revisão (que só é útil em momentos específicos) aqui significa poluir o contexto de todas as interações, mesmo quando o conhecimento é irrelevante. Isso é antieconômico e prejudica a performance do modelo.\n\n- **C (PostToolUse hook):** Hooks são mecanismos de automação baseados em eventos (disparados após o uso de uma ferramenta). Eles não são o local apropriado para armazenar conhecimento declarativo como uma checklist. Servem para gatilhos comportamentais, não para dados de contexto.\n\n- **D (Regra por glob em .claude/rules/):** Regras por glob são associadas a **caminhos de arquivo** (ex.: `*.py` ou `tests/`). Elas são acionadas quando o assistente interage com arquivos que correspondem ao padrão. Uma checklist de revisão não está vinculada a um padrão de arquivo específico, mas sim a uma **tarefa ou atividade** (ex.: "vou fazer code review agora"). Portanto, não se encaixa nesse mecanismo.','\n',char(10)),replace('**Explicação para uma criança de 10 anos:**\n\nImagina que você tem uma mochila (o "contexto" do robô) e precisa colocar coisas úteis dentro dela.\n\n- Se você colocar **todas** as suas coisas na mochila o tempo todo, ela fica pesada e difícil de carregar.\n- A **CLAUDE.md** é como um caderno que fica **sempre** na mochila. Só deve ter coisas que você usa o tempo todo.\n- Uma **Skill** é como um brinquedo ou ferramenta que você só pega quando precisa. Por exemplo: uma lupa para olhar detalhes. Você não precisa carregá-la o tempo todo — só quando for examinar algo.\n\nA pergunta diz que a expertise (como uma lista de conferência para revisar um trabalho) é usada **só de vez em quando**. Então não faz sentido deixar isso sempre na mochila (CLAUDE.md) — isso seria como carregar um casaco pesado no verão!\n\nA resposta certa é guardar isso como uma **Skill** (alternativa B), porque você só pega quando precisa, e assim a mochila fica leve e organizada.','\n',char(10)));
INSERT INTO cards VALUES('admin','card_1783092988280_lll8vtqy3',318,'What is the difference in triggering between hooks and skills?',replace('What is the difference in triggering between hooks and skills?\n\nWhat is the difference in triggering between hooks and skills?\n[Resposta correta: Hooks disparam por eventos (event-driven); skills ativam pelo que se pede (request-driven). A A, C e D trocam ou uniformizam indevidamente os gatilhos.]\n\n[ ] A - Both are request-driven\n[ ] B - Hooks are event-driven (e.g. before tool calls); skills are request-driven (activate by what you ask)\n[ ] C - Hooks are request-driven; skills are event-driven\n[ ] D - Both trigger only by manual invocation','\n',char(10)),'B - Hooks are event-driven (e.g. before tool calls); skills are request-driven (activate by what you ask)','["Domain_3::Claude_Code_Configuration_Workflows", "Domain_4::Prompt_Engineering_Structured_Output", "Scenario_2::Code_Generation_Claude_Code"]','New',0,2.5,0,1783092988280,1783727406165,1783203558653,replace('**Tradução para português do Brasil:**\n\n**Pergunta:** Qual é a diferença no acionamento entre hooks e skills?\n\n**Alternativas:**\n[ ] A - Ambos são orientados a requisição (request-driven)\n[ ] B - Hooks são orientados a eventos (event-driven), por exemplo, antes de chamadas de ferramentas; skills são orientados a requisição (request-driven), ativam pelo que você pede\n[ ] C - Hooks são orientados a requisição; skills são orientados a eventos\n[ ] D - Ambos acionam apenas por invocação manual','\n',char(10)),replace('**Explicação para um adulto tech lead:**\n\nA alternativa **B** é a correta porque descreve precisamente a diferença arquitetônica fundamental entre hooks e skills em sistemas e frameworks de IA (como o Agentes de IA, LangChain, ou plataformas de automação).\n\n**Por que B está correta:**\n- **Hooks** são mecanismos de **event-driven** (orientados a eventos). Eles são registrados para "escutar" eventos específicos no ciclo de vida de uma execução — como "antes de chamar uma ferramenta", "após a conclusão de um passo", "quando um erro ocorre", etc. Eles não são invocados diretamente pelo usuário, mas sim acionados automaticamente quando o evento associado ocorre.\n- **Skills** (ou "habilidades" / ferramentas) são **request-driven** (orientados a requisição). Elas são ativadas sob demanda, tipicamente quando o usuário faz uma pergunta ou solicitação que o modelo identifica como sendo melhor resolvida por aquela skill específica. O modelo decide qual skill chamar com base no contexto da requisição.\n\n**Por que as demais estão erradas:**\n- **A (Ambos são request-driven):** Incorreta porque hooks não são acionados por requisição direta do usuário, mas sim por eventos internos do sistema.\n- **C (Hooks são request-driven; skills são event-driven):** Incorreta porque inverte a definição — hooks são event-driven e skills são request-driven.\n- **D (Ambos acionam apenas por invocação manual):** Incorreta porque hooks disparam automaticamente por eventos (não manualmente), e skills podem ser ativadas automaticamente pelo modelo conforme a necessidade da requisição, sem invocação manual explícita.\n\nPortanto, B reflete corretamente a distinção: hooks reagem a eventos; skills respondem a requisições.','\n',char(10)),replace('**Explicação para uma criança de 10 anos:**\n\nImagina que você está em um jogo de videogame.\n\n**Hooks** são como **armadilhas automáticas**: você não precisa apertar nada. Quando você pisa em um lugar (o "evento" acontece), a armadilha dispara sozinha. Por exemplo: "quando você pegar uma moeda, o jogo toca um som". O som toca automaticamente porque você pegou a moeda — você não pediu para tocar.\n\n**Skills** são como **poderes especiais** do seu personagem: eles só funcionam quando você **pede** ou quando você **precisa** deles. Por exemplo: você aperta um botão para usar o "soco especial" ou o jogo vê que você precisa pular um buraco e ativa o poder de superpulo. Eles só acontecem porque você pediu ou porque a situação pediu.\n\n**Resumindo:**\n- **Hook**: dispara sozinho quando algo acontece (como uma armadilha).\n- **Skill**: só ativa quando você pede ou quando precisa (como um poder especial).\n\nÉ por isso que a resposta certa é a **B**! 😊','\n',char(10)));
INSERT INTO cards VALUES('admin','card_1783092988298_zi5n7wi2z',319,'You want to run a linter every time a file is saved.',replace('You want to run a linter every time a file is saved.\n\nYou want to run a linter every time a file is saved. Hook or skill?\n[Resposta correta: Rodar algo a cada evento (save) é caso de hook (event-driven). Skill e slash command dependem do pedido/invocação; regra por glob aplica convenções, não executa a cada save.]\n\n[ ] A - Skill, activated by description matching\n[ ] B - Hook, since it is a per-event operation (on each save)\n[ ] C - Slash command, invoked manually after saving\n[ ] D - A rule in .claude/rules/ with glob','\n',char(10)),'B - Hook, since it is a per-event operation (on each save)','["Domain_3::Claude_Code_Configuration_Workflows", "Domain_5::Context_Management_Reliability", "Scenario_4::Developer_Productivity"]','New',0,2.5,0,1783092988298,1783727409902,1783203558653,replace('**Tradução para português do Brasil:**\n\nVocê quer executar um linter toda vez que um arquivo é salvo. Hook ou skill?\n\n[ ] A - Skill, ativado por correspondência de descrição\n[ ] B - Hook, já que é uma operação por evento (a cada salvamento)\n[ ] C - Slash command, invocado manualmente após salvar\n[ ] D - Uma regra em .claude/rules/ com glob','\n',char(10)),replace('**Explicação técnica para um adulto tech lead:**\n\nO cenário é claro: queremos executar um liner automaticamente **sempre que um arquivo é salvo**. Isso é um comportamento reativo a um evento (event-driven), não uma ação iniciada pelo usuário sob demanda. Vamos analisar cada alternativa:\n\n- **B (correta): Hook** — Hooks são mecanismos projetados justamente para reagir a eventos do ciclo de vida de arquivos ou ações do editor/IDE, como "ao salvar", "ao abrir", "ao fechar". O Hook é acionado automaticamente pelo evento, sem necessidade de invocação explícita do usuário. É a escolha ideal e semanticamente correta para o problema.\n\n- **A (incorreta): Skill** — Skills são normalmente ativados por matching de descrição (texto/intenção) em assistentes conversacionais ou por comandos explícitos. Embora possam executar ações, não são orientados a evento de save; eles dependem de um pedido do usuário (ex.: "roda o linter"). Não se encaixa no requisito "toda vez que salva".\n\n- **C (incorreta): Slash command** — Um slash command exige invocação manual do usuário (ex.: digitar /lint). O requisito pede execução automática a cada save, o que contraria a natureza explícita e manual de um slash command.\n\n- **D (incorreta): Regra em .claude/rules/ com glob** — Regras com glob definem convenções, configurações ou comportamentos esperados para arquivos que correspondem a um padrão (ex.: "sempre que abrir um .ts, usar tabs"). Não servem para executar um linter a cada save de forma imperativa; são declarativas e de configuração de ambiente, não de execução contínua baseada em evento.','\n',char(10)),replace('Imagine que você tem um robô ajudante que verifica se seu dever de casa está bonito (é o "linter"). Você quer que ele faça essa verificação **toda vez que você termina de escrever e salva seu arquivo**.\n\nAgora, vamos ver as opções:\n\n- **A - Skill** — Isso seria como ensinar o robô a fazer a verificação **só quando você pedir** "Ei, robô, verifica meu dever!". Não é automático.\n\n- **B - Hook (correta)** — Isso é como colocar um sensor na gaveta onde você guarda o dever. **Toda vez que você fecha a gaveta (salva o arquivo), o sensor avisa o robô para verificar**. O robô age sozinho, sem você precisar pedir. É a melhor opção!\n\n- **C - Slash command** — Isso seria como ter que digitar um comando especial no computador sempre que quiser verificar. Bem chato, né? Você teria que lembrar de fazer isso depois de salvar.\n\n- **D - Regra em .claude/rules/ com glob** — Isso é como colocar um cartaz na parede dizendo "aqui sempre usamos lápis azul". É uma regra, mas não faz o robô agir sozinho toda vez que você salva.\n\n**Resposta certa: B - Hook, porque ele age sozinho cada vez que você salva o arquivo!**','\n',char(10)));
INSERT INTO cards VALUES('admin','card_1783092988318_i8nznkils',320,'In a complete setup, which feature covers "automatic per-event operations"?',replace('In a complete setup, which feature covers "automatic per-event operations"?\n\nIn a complete setup, which feature covers "automatic per-event operations"?\n[Resposta correta: Hooks cobrem operações automáticas por evento. CLAUDE.md é para padrões sempre-ativos; Skills para expertise por tarefa sob demanda; MCP servers para integrações externas.]\n\n[ ] A - CLAUDE.md\n[ ] B - Skills\n[ ] C - Hooks\n[ ] D - MCP servers','\n',char(10)),'C - Hooks','["Domain_3::Claude_Code_Configuration_Workflows", "Scenario_2::Code_Generation_Claude_Code"]','New',0,2.5,0,1783092988318,1783727413050,1783203558653,replace('**Tradução para português do Brasil:**\n\nPergunta: Em uma configuração completa, qual funcionalidade cobre "operações automáticas por evento"?\n\nAlternativas:\n[ ] A - CLAUDE.md\n[ ] B - Skills\n[ ] C - Hooks\n[ ] D - MCP servers','\n',char(10)),replace('**Explicação para adulto (tech lead):**\n\nA pergunta trata de um tópico relevante em sistemas de automação e agentes de IA, especificamente no ecossistema Claude (ou similar). O conceito de "operações automáticas por evento" se refere a ações que são disparadas automaticamente em resposta à ocorrência de eventos específicos durante o ciclo de vida de uma interação ou execução de tarefa.\n\n**Alternativa correta: C - Hooks**\n\nHooks (ganchos) são mecanismos de extensão que permitem executar código ou ações customizadas em pontos específicos do ciclo de vida de um sistema. No contexto de agentes de IA como Claude, hooks são projetados exatamente para isso: reagir a eventos (ex: início de sessão, fim de execução, erro, etc.) com operações automáticas. É o equivalente ao padrão de "event-driven programming" ou "lifecycle callbacks" em frameworks como React (useEffect, componentDidMount), Git hooks (pre-commit, post-merge) ou CI/CD pipelines (webhooks).\n\n**Por que as demais estão erradas:**\n\n- **A - CLAUDE.md**: Este arquivo de configuração define padrões de comportamento "sempre ativos" (always-on), ou seja, regras que valem para toda e qualquer interação, independentemente de eventos. É uma configuração declarativa de contexto global, não um gatilho reativo a eventos. Pense como um "global config" ou "system prompt fixo", não como um event handler.\n\n- **B - Skills**: Representam conhecimento ou expertise especializada que pode ser invocada sob demanda para tarefas específicas. É como um módulo de domínio — está disponível para uso quando necessário, mas não é acionado automaticamente por eventos. A metáfora correta seria "biblioteca de funções" ou "plugin de domínio", não um "event listener".\n\n- **D - MCP servers**: O Model Context Protocol (MCP) servers são integrações externas que permitem ao modelo acessar ferramentas, dados ou serviços fora do seu ambiente. São conectores para o mundo exterior (APIs, bancos de dados, etc.), mas não são o mecanismo responsável por operações automáticas baseadas em eventos. Seriam como "adapters" ou "gateways" de integração, não "event handlers".\n\n**Resumo técnico:** Hooks são o padrão correto de "event-driven automation" aqui, enquanto CLAUDE.md (config global), Skills (expertise sob demanda) e MCP servers (integração externa) têm finalidades distintas e não se confundem com o conceito de operações automáticas por evento.','\n',char(10)),replace('**Explicação para criança de 10 anos:**\n\nVamos pensar em uma casa inteligente. A pergunta é: qual parte da casa faz coisas automaticamente quando algo acontece?\n\nImagine que você tem um robô ajudante em casa. Esse robô pode ser programado de várias formas:\n\n- **CLAUDE.md** é como um quadro de regras fixas na parede: "Sempre guarde os brinquedos depois de usar" — isso vale o tempo todo, não importa o que aconteça.\n\n- **Skills** são como livros de receitas ou manuais: você pode pedir "me ajuda a fazer um bolo" e ele usa o livro de receitas. Só funciona quando você pede.\n\n- **MCP servers** são como tomadas elétricas ou conexões com a internet: permitem o robô se conectar a outros aparelhos, como uma lâmpada ou um aspirador de pó.\n\n- **Hooks** (ganchos) são como sensores especiais: "QUANDO a porta abrir, ACENDA a luz" ou "QUANDO você terminar de limpar, AVISE no celular". Eles ficam esperando um evento acontecer e aí fazem algo automaticamente!\n\nEntão, "operações automáticas por evento" significa: coisas que acontecem sozinhas quando um evento ocorre. Isso é exatamente o que os **Hooks** fazem. Eles são como "se... então..." automáticos: "SE isso acontecer, ENTÃO faça aquilo".\n\nResposta correta: **C - Hooks**!','\n',char(10)));
INSERT INTO cards VALUES('admin','card_1783092988363_gyu1olne6',321,'What does the .',replace('What does the .\n\nWhat does the .claude directory contain and how is it shared?\n[Resposta correta: O .claude reúne agents, hooks, skills e settings, versionados e compartilhados via Git. As demais reduzem indevidamente o conteúdo ou o meio de compartilhamento.]\n\n[ ] A - Only skills, distributed via marketplace\n[ ] B - Agents, hooks, skills and settings, versioned and shared via Git\n[ ] C - Only the CLAUDE.md, sent by email\n[ ] D - Only the MCP credentials, outside version control','\n',char(10)),'B - Agents, hooks, skills and settings, versioned and shared via Git','["Domain_3::Claude_Code_Configuration_Workflows", "Scenario_2::Code_Generation_Claude_Code"]','New',0,2.5,0,1783092988363,1783727416071,1783203558653,replace('**Tradução para português do Brasil:**\n\n**Pergunta:** O que o diretório .claude contém e como ele é compartilhado?\n\n[ ] A - Apenas skills, distribuídas via marketplace\n[ ] B - Agents, hooks, skills e settings, versionados e compartilhados via Git\n[ ] C - Apenas o CLAUDE.md, enviado por email\n[ ] D - Apenas as credenciais MCP, fora do controle de versão','\n',char(10)),replace('**Explicação para um adulto tech lead:**\n\nO diretório `.claude` é um repositório central de configuração e extensibilidade para projetos que utilizam o Claude como assistente de desenvolvimento. A alternativa correta é a **B**.\n\n**Por que a B está correta:**\n\nO `.claude` armazena **agents** (definições de agentes especializados), **hooks** (scripts de automação disparados por eventos do ciclo de desenvolvimento), **skills** (capacidades modulares que estendem as funcionalidades do Claude) e **settings** (configurações do ambiente de trabalho). Todo esse conteúdo é versionado dentro do próprio repositório Git do projeto, o que garante rastreabilidade, colaboração e reprodutibilidade entre membros da equipe. Compartilhar via Git é a abordagem padrão em engenharia de software para manter consistência e histórico de mudanças.\n\n**Por que as demais estão erradas:**\n\n- **A** — Reduz o escopo apenas a "skills" e sugere um "marketplace" como meio de distribuição. O `.claude` não se limita a skills nem depende de marketplace; ele é versionado localmente no projeto e compartilhado via Git com toda a estrutura de agents, hooks e settings.\n- **C** — Afirma que contém apenas o arquivo `CLAUDE.md` e que é compartilhado por email. Isso é incorreto: o `CLAUDE.md` pode existir dentro do `.claude` ou na raiz, mas o diretório tem um propósito muito mais amplo. Compartilhar por email viola boas práticas de versionamento e colaboração.\n- **D** — Limita o conteúdo a "credenciais MCP" e afirma que está fora do controle de versão. Credenciais sensíveis geralmente não devem ser versionadas, mas o `.claude` não se resume a credenciais — ele contém configurações e extensões que *devem* ser versionadas para funcionar corretamente em diferentes ambientes de desenvolvimento.','\n',char(10)),replace('**Explicação para uma criança de 10 anos:**\n\nImagine que o `.claude` é como uma "caixa de ferramentas secreta" que o ajudante de programação (Claude) usa para trabalhar melhor no seu projeto. Dentro dessa caixa tem:\n\n- **Agents**: "ajudantes especiais" que fazem tarefas diferentes.\n- **Hooks**: "lembretes automáticos" que disparam ações quando algo acontece.\n- **Skills**: "superpoderes" que o Claude pode aprender para fazer coisas novas.\n- **Settings**: as "regras do jogo" para o projeto.\n\nAgora, como essa caixa é compartilhada entre as pessoas do time? Não é por email (muito chato e fácil de perder) nem por marketplace (lojinha de aplicativos). É usando o **Git**, que é como um "álbum de figurinhas mágico" onde todo mundo vê as mesmas figurinhas e sabe quem colocou o quê e quando.\n\nA resposta certa é a **B** porque ela descreve direitinho o que tem dentro da caixa e como ela é compartilhada. As outras respostas erram porque:\n\n- **A** diz que só tem "skills" — mas tem muito mais coisas!\n- **C** diz que só tem um arquivo e que é enviado por email — isso não funciona bem, pois todos precisam da mesma versão.\n- **D** diz que só tem senhas e não usa Git — senhas não devem ficar no Git (por segurança), mas a caixa tem muito mais que só senhas.','\n',char(10)));
INSERT INTO cards VALUES('admin','card_1783092988383_codm8gbyl',322,'What is the design principle when choosing among the customization features?',replace('What is the design principle when choosing among the customization features?\n\nWhat is the design principle when choosing among the customization features?\n[Resposta correta: O princípio é combinar as features conforme a especialidade de cada uma, sem forçar tudo em uma. As demais defendem concentrar tudo em uma única feature, o oposto do recomendado.]\n\n[ ] A - Concentrate everything in skills, since they are the most flexible\n[ ] B - Each feature has its specialty; combine them instead of forcing everything into one\n[ ] C - Use only CLAUDE.md to simplify\n[ ] D - Always prefer hooks, since they are deterministic','\n',char(10)),'B - Each feature has its specialty; combine them instead of forcing everything into one','["Domain_3::Claude_Code_Configuration_Workflows", "Scenario_2::Code_Generation_Claude_Code"]','New',0,2.5,0,1783092988383,1783727418803,1783203558653,replace('**Tradução para português do Brasil:**\n\nQual é o princípio de design ao escolher entre os recursos de customização?\n\n[ ] A - Concentre tudo em skills, já que são as mais flexíveis\n[ ] B - Cada recurso tem sua especialidade; combine-os em vez de forçar tudo em um só\n[ ] C - Use apenas CLAUDE.md para simplificar\n[ ] D - Sempre prefira hooks, já que são determinísticos','\n',char(10)),replace('**Explicação para um adulto (tech lead):**\n\nA resposta correta é a **alternativa B**.\n\nO princípio de design correto para escolher entre os recursos de customização é entender que cada recurso (como skills, hooks, CLAUDE.md, etc.) foi projetado com uma finalidade específica e possui pontos fortes distintos. A abordagem recomendada não é eleger um único recurso como "superior" e concentrar tudo nele, mas sim combinar os recursos de forma inteligente, aproveitando a especialidade de cada um para resolver o problema da maneira mais adequada.\n\n**Por que as demais estão erradas:**\n\n- **Alternativa A ("Concentre tudo em skills")**: Incorreta porque skills, embora flexíveis, não são a melhor escolha para todos os cenários. Forçar tudo em skills ignora que hooks podem ser mais adequados para comportamentos determinísticos e que o CLAUDE.md pode ser melhor para configurações de projeto. O princípio não é "centralizar em um", mas "usar o melhor para cada caso".\n\n- **Alternativa C ("Use apenas CLAUDE.md")**: Incorreta porque CLAUDE.md é um ótimo recurso para configurações globais e instruções persistentes, mas não substitui a necessidade de hooks para lógica procedural ou skills para comportamentos complexos. Simplificar demais pode levar a um design inadequado.\n\n- **Alternativa D ("Sempre prefira hooks")**: Incorreta porque hooks são determinísticos e previsíveis, mas não são a ferramenta certa para tudo. Skills oferecem mais flexibilidade e podem ser mais adequadas quando se precisa de comportamentos adaptáveis ou acesso a ferramentas externas. O determinismo não é o único critério de escolha.','\n',char(10)),replace('Imagine que você tem uma caixa de ferramentas com vários tipos de ferramentas: um martelo, uma chave de fenda, um alicate e uma fita métrica. Cada ferramenta serve para uma coisa diferente.\n\nO princípio de design é como escolher qual ferramenta usar. Você não vai usar o martelo para apertar um parafuso, certo? Também não vai usar só a chave de fenda para construir uma casa inteira.\n\nA resposta certa (alternativa B) diz que cada ferramenta (ou "recurso") tem sua especialidade. O legal é combinar elas! Use o martelo para pregar, a chave de fenda para apertar parafusos, o alicate para segurar coisas. Assim o trabalho fica bem feito.\n\nAs outras alternativas estão erradas porque querem usar uma única ferramenta para tudo: \n- A alternativa A quer usar só o martelo (skill) \n- A alternativa C quer usar só a fita métrica (CLAUDE.md) \n- A alternativa D quer usar só a chave de fenda (hooks)\n\nMas a melhor ideia é usar cada uma no que ela é boa e combiná-las quando necessário!','\n',char(10)));
INSERT INTO cards VALUES('admin','card_1783092988404_ugik0vh8j',323,'What is the simplest method to share skills with the team?',replace('What is the simplest method to share skills with the team?\n\nWhat is the simplest method to share skills with the team?\n[Resposta correta: Commitar em .claude/skills faz quem clona receber as skills automaticamente e updates no próximo pull. Marketplace é para distribuição ampla; CLAUDE.md não guarda skills; e-mail exige instalação manual.]\n\n[ ] A - Publish in a plugin marketplace\n[ ] B - Commit the skills in .claude/skills in the repository; whoever clones receives them automatically\n[ ] C - Paste the skills into the CLAUDE.md\n[ ] D - Send the files by email for manual installation','\n',char(10)),'[ ] B - Commit the skills in .claude/skills in the repository; whoever clones receives them automatically','["Domain_3::Claude_Code_Configuration_Workflows", "Domain_2::Tool_Design_MCP_Integration", "Scenario_2::Code_Generation_Claude_Code"]','New',0,2.5,0,1783092988404,1783727422370,1783203558653,replace('**Tradução para português do Brasil:**\n\nQual é o método mais simples para compartilhar habilidades (skills) com o time?\n\n[ ] A - Publicar em um marketplace de plugins\n[ ] B - Commitar as skills em .claude/skills no repositório; quem clona as recebe automaticamente\n[ ] C - Colar as skills no CLAUDE.md\n[ ] D - Enviar os arquivos por email para instalação manual','\n',char(10)),replace('**Explicação para um adulto (tech lead):**\n\nA pergunta busca o método mais simples e eficiente para compartilhar skills (configurações de comportamento do Claude) com a equipe de desenvolvimento. Vamos analisar cada alternativa:\n\n**Alternativa B (correta):** Ao commitar os arquivos de skill no diretório `.claude/skills` dentro do repositório do projeto, qualquer pessoa que clonar o repositório terá automaticamente acesso a essas skills. Quando houver atualizações, basta fazer um `git pull` para sincronizar as novas versões. Isso aproveita o fluxo de trabalho já existente da equipe (Git), não exige ações manuais adicionais, e garante versionamento e rastreabilidade. É o método mais simples e alinhado com boas práticas de DevOps.\n\n**Alternativa A (incorreta):** Publicar em um marketplace de plugins é um método válido para distribuição ampla e pública, mas não é o "mais simples" para compartilhamento interno com o time. Envolve processo de publicação, aprovação e descoberta externa, o que adiciona complexidade desnecessária para um contexto de equipe.\n\n**Alternativa C (incorreta):** O arquivo `CLAUDE.md` é utilizado para configurações de contexto e instruções do projeto, mas não é o local apropriado para armazenar skills. Skills têm estrutura e propósito diferentes; colocá-las no CLAUDE.md misturaria responsabilidades e poderia causar conflitos ou má interpretação pelo Claude.\n\n**Alternativa D (incorreta):** Enviar arquivos por email é trabalhoso, propenso a erros, não escala, não tem versionamento, e exige que cada membro faça instalação manual individualmente. É o método menos eficiente dentre as opções.','\n',char(10)),replace('Imagine que você e seus amigos estão desenhando um mapa do tesouro juntos. Vocês têm um caderno especial onde todo mundo coloca seus desenhos.\n\nSe um amigo desenhar algo legal, o jeito mais fácil de todo mundo ter esse desenho é colocar a folha no caderno compartilhado. Quando alguém pegar o caderno, já vai ver o desenho novo automaticamente!\n\nA alternativa B é a melhor porque funciona igual: em vez de mandar o desenho por email (alternativa D), publicar num site (alternativa A) ou tentar escrever no meio de outra coisa (alternativa C), você simplesmente coloca o arquivo na pasta certa dentro do projeto. Quando alguém baixar o projeto (como pegar o caderno), já vai ter as skills na hora. E se você atualizar, a pessoa só precisa "puxar" a novidade — sem esforço extra!','\n',char(10)));
INSERT INTO cards VALUES('admin','card_1783092988422_94wufup8z',324,'You want to distribute skills to the community or across multiple repos, beyond your immediate team.',replace('You want to distribute skills to the community or across multiple repos, beyond your immediate team.\n\nYou want to distribute skills to the community or across multiple repos, beyond your immediate team. Which method?\n[Resposta correta: Para distribuição ampla, plugins via marketplace deixam outros descobrirem e instalarem. Commitar em um repo atende só o time; ~/.claude/skills é pessoal; @ no CLAUDE.md não distribui skills.]\n\n[ ] A - Commit in .claude/skills of a specific repo\n[ ] B - Plugins distributed via marketplace, which others discover and install\n[ ] C - Put them in each user''s ~/.claude/skills manually\n[ ] D - Reference the skills in the CLAUDE.md with @','\n',char(10)),'B - Plugins distributed via marketplace, which others discover and install','["Domain_3::Claude_Code_Configuration_Workflows", "Domain_2::Tool_Design_MCP_Integration", "Scenario_2::Code_Generation_Claude_Code"]','New',0,2.5,0,1783092988422,1783727425717,1783203558653,replace('**Tradução para pt-BR:**\n\nVocê deseja distribuir skills para a comunidade ou através de múltiplos repositórios, além do seu time imediato. Qual método?\n\n[ ] A - Commitar em .claude/skills de um repositório específico\n[ ] B - Plugins distribuídos via marketplace, que outros descobrem e instalam\n[ ] C - Colocá-los manualmente no ~/.claude/skills de cada usuário\n[ ] D - Referenciar as skills no CLAUDE.md com @','\n',char(10)),replace('**Explicação para um adulto tech lead:**\n\nA pergunta trata do cenário de distribuição de skills (configurações, instruções ou automações do Claude) para além do seu time imediato — ou seja, para a comunidade ou múltiplos repositórios. O objetivo é um método que permita descoberta e instalação por terceiros.\n\n- **Alternativa B (correta):** Plugins distribuídos via marketplace são a abordagem adequada para distribuição ampla. Um marketplace (como o do Claude ou da Anthropic) oferece um catálogo centralizado onde outros desenvolvedores podem descobrir, avaliar e instalar o plugin com facilidade. Isso resolve os problemas de descoberta (o recurso é indexado e buscável), manutenção (versão única e atualizações centralizadas) e instalação (simplificada para o usuário final). É o equivalente a publicar uma biblioteca no npm ou PyPI.\n\n- **Alternativa A (incorreta):** Commitar skills em `.claude/skills` de um repositório específico limita a distribuição a quem tem acesso àquele repositório e faz parte daquele time. Não atende ao requisito de "comunidade" ou "múltiplos repositórios".\n\n- **Alternativa C (incorreta):** Colocar manualmente em `~/.claude/skills` de cada usuário é totalmente inviável para distribuição ampla. Exige intervenção manual, sem padronização, sem versionamento e sem canal de descoberta. É um método puramente local e pessoal.\n\n- **Alternativa D (incorreta):** Referenciar skills no CLAUDE.md com `@` pode ser útil para documentar dependências dentro de um time, mas não distribui as skills em si. O `@` apenas referencia algo que já deveria estar disponível localmente; não há mecanismo de descoberta ou instalação para a comunidade.\n\nPortanto, a resposta correta é a B.','\n',char(10)),replace('Imagine que você criou um "joguinho" ou "regra" especial para o Claude, o robô assistente, e quer que todo mundo possa usar — não só seus amigos da escola.\n\n**Opção B (a certa):** Você coloca seu "joguinhos" em uma lojinha (marketplace). Assim, qualquer pessoa no mundo pode entrar na loja, ver o que você fez e baixar para usar. Todo mundo descobre sozinho!\n\n**Opção A (errada):** Você guarda o joguinho só na pasta do seu grupo de trabalho. Quem não é do grupo não vê nem consegue usar.\n\n**Opção C (errada):** Você tem que ir na casa de cada pessoa, pegar o computador dela e colocar o joguinho lá dentro. Muito trabalhoso, e ninguém descobre sozinho.\n\n**Opção D (errada):** Você escreve um bilhete falando "tem um joguinho aqui, olha o @", mas o joguinho não está com o bilhete — a pessoa precisa já ter ele no computador. Não adianta para distribuir.\n\nEntão, a maneira mágica de todo mundo encontrar e instalar é: **colocar na lojinha (marketplace)!**','\n',char(10)));
INSERT INTO cards VALUES('admin','card_1783092988441_077npzpdn',325,'What does the strictKnownMarketplaces field control in managed settings?',replace('What does the strictKnownMarketplaces field control in managed settings?\n\nWhat does the strictKnownMarketplaces field control in managed settings?\n[Resposta correta: strictKnownMarketplaces restringe as fontes/marketplaces aprovadas para instalação de plugins. As demais descrevem prioridade de skills, limites de description ou allowed-tools.]\n\n[ ] A - Which skills have priority in case of conflict\n[ ] B - Where plugins can be installed from, restricting the approved sources/marketplaces\n[ ] C - The character limit of skills'' description\n[ ] D - Which tools are pre-approved in the skills','\n',char(10)),'B - Where plugins can be installed from, restricting the approved sources/marketplaces','["ForaDosDominios", "ForaDoCenario"]','New',0,2.5,0,1783092988441,1783727429289,1783203558653,replace('**Tradução para português do Brasil:**\n\nO que o campo strictKnownMarketplaces controla nas configurações gerenciadas?\n\n[ ] A - Quais skills têm prioridade em caso de conflito\n[ ] B - De onde os plugins podem ser instalados, restringindo as fontes/marketplaces aprovados\n[ ] C - O limite de caracteres da descrição das skills\n[ ] D - Quais ferramentas são pré-aprovadas nas skills','\n',char(10)),replace('**Explicação didática para um adulto tech lead:**\n\nO campo `strictKnownMarketplaces` é uma configuração de managed settings (políticas gerenciadas) utilizada em plataformas como Alexa ou assistentes virtuais corporativos para controlar a proveniência de plugins ou skills.\n\n**Alternativa correta (B):** strictKnownMarketplaces restringe as fontes ou marketplaces aprovados para instalação de plugins. Isso significa que, quando ativado, apenas plugins provenientes de marketplaces considerados "conhecidos" ou "confiáveis" (definidos na política) podem ser instalados, bloqueando fontes não autorizadas. É um mecanismo de segurança e governança para evitar a instalação de plugins de fontes não verificadas.\n\n**Análise das alternativas incorretas:**\n\n- **A (Quais skills têm prioridade em caso de conflito):** Isso descreve um campo de priorização ou resolução de conflitos entre skills, algo como `skillPriority` ou `conflictResolution`, não relacionado a marketplaces ou fontes de plugins.\n\n- **C (O limite de caracteres da descrição das skills):** Refere-se a um campo que define o tamanho máximo permitido para descrições de skills (ex.: `descriptionMaxLength`). Não tem relação com a origem de instalação de plugins.\n\n- **D (Quais ferramentas são pré-aprovadas nas skills):** Descreve um campo de whitelist de ferramentas ou APIs permitidas dentro de skills (ex.: `allowedTools`). Não é sobre de onde plugins podem ser baixados.','\n',char(10)),replace('Imagine que a casa inteligente do seu chefe é como um celular. Você pode baixar aplicativos (plugins) para fazer coisas legais, como ligar a TV ou tocar música. Mas, se você baixar de qualquer lugar da internet, pode ser perigoso — pode vir um vírus!\n\nO campo `strictKnownMarketplaces` é como um "filtro de segurança" que o chefe da tecnologia (o administrador) coloca. Ele diz: "Só pode baixar plugins dessas lojas oficiais que eu confio, tipo a loja oficial da Amazon ou da Google. Nada de baixar de sites estranhos!".\n\nEntão, essa configuração serve para controlar de onde os plugins podem ser instalados, permitindo só fontes seguras. As outras opções falam sobre coisas diferentes: qual skill ganha quando duas brigam (A), o tamanho da letra da descrição (C) e quais ferramentas já estão liberadas para uso (D). A resposta certa é a B.','\n',char(10)));
INSERT INTO cards VALUES('admin','card_1783092988461_aqofi4kx4',326,'Security standards that MUST be consistent across the whole organization.',replace('Security standards that MUST be consistent across the whole organization.\n\nSecurity standards that MUST be consistent across the whole organization. Which deploy method?\n[Resposta correta: A palavra "devem" aponta para enterprise managed settings, cujas skills têm prioridade máxima e sobrepõem personal e project. Skills de projeto ou pessoais não garantem consistência organizacional; hook por máquina não é gerenciado centralmente.]\n\n[ ] A - Project skills in each repository\n[ ] B - Enterprise managed settings, with maximum-priority enterprise skills overriding personal and project\n[ ] C - Personal skills in ~/.claude/skills\n[ ] D - A SessionStart hook on each machine','\n',char(10)),'B - Enterprise managed settings, with maximum-priority enterprise skills overriding personal and project','["Domain_3::Claude_Code_Configuration_Workflows", "Domain_5::Context_Management_Reliability", "Scenario_2::Code_Generation_Claude_Code"]','New',0,2.5,0,1783092988461,1783727432894,1783203558653,replace('**Tradução para português do Brasil:**\n\nPadrões de segurança que DEVEM ser consistentes em toda a organização.\n\nPadrões de segurança que DEVEM ser consistentes em toda a organização. Qual método de implantação?\n\n[ ] A - Skills de projeto em cada repositório\n[ ] B - Configurações gerenciadas pela empresa (Enterprise managed settings), com skills empresariais de prioridade máxima substituindo skills pessoais e de projeto\n[ ] C - Skills pessoais em ~/.claude/skills\n[ ] D - Um hook SessionStart em cada máquina','\n',char(10)),replace('**Explicação técnica (para adulto tech lead):**\n\nA palavra-chave aqui é "DEVEM" (MUST em maiúsculo, indicando um requisito obrigatório segundo a RFC 2119). O problema é: como garantir que padrões de segurança sejam aplicados uniformemente em toda a organização, sem exceções?\n\n**Alternativa correta (B):** Enterprise managed settings com skills de prioridade máxima. Esta é a única abordagem que permite definir políticas centralizadas que **sobrescrevem** qualquer configuração local (pessoal ou de projeto). A hierarquia de prioridade (enterprise > project > personal) garante que nem um desenvolvedor individual, nem um time específico, possa burlar ou desabilitar os padrões de segurança estabelecidos pela organização. Isso é essencial para compliance, auditoria e governança.\n\n**Alternativa A (Project skills):** Skills definidas por repositório são específicas de cada projeto e não garantem consistência entre diferentes equipes ou áreas da organização. Cada repositório pode ter suas próprias skills, sem coordenação central. Além disso, um time pode simplesmente esquecer ou optar por não incluir determinadas skills de segurança.\n\n**Alternativa C (Personal skills):** Skills pessoais são definidas em ~/.claude/skills, ou seja, são individuais e voluntárias. Não há mecanismo que force um desenvolvedor a adotá-las. Zero garantia de consistência organizacional.\n\n**Alternativa D (SessionStart hook por máquina):** Hooks são scripts executados em uma máquina local. Embora possam aplicar configurações, não há gerenciamento centralizado — cada máquina precisa ser configurada individualmente. Não é escalável nem auditável, e não há garantia de que todos os colaboradores estejam rodando o mesmo hook. Um hook pode ser modificado ou removido localmente sem supervisão.','\n',char(10)),replace('Imagine que sua escola tem regras de segurança, como "não correr no corredor" e "usar capacete na bicicleta". Essas regras valem para todo mundo, em todas as salas, o tempo todo. Não pode ter uma sala onde vale e outra onde não vale, senão não é seguro.\n\nA pergunta é: como garantir que todo mundo siga as mesmas regras de segurança na empresa?\n\nA resposta B é como ter a diretora da escola (a empresa) dizendo: "Essas regras são as mais importantes e valem para todos, não importa o que o professor da sua sala ou você mesmo queira fazer." As outras respostas são como deixar cada sala criar suas próprias regras (A), cada aluno fazer o que quiser (C), ou colocar um bilhete em cada carteira, mas cada um pode ignorar ou jogar fora (D).\n\nPor isso a B é a correta: só ela garante que todo mundo siga as mesmas regras de segurança.','\n',char(10)));
INSERT INTO cards VALUES('admin','card_1783092988479_pejisujcn',327,'What is the first step when debugging a problematic skill?',replace('What is the first step when debugging a problematic skill?\n\nWhat is the first step when debugging a problematic skill?\n[Resposta correta: O validator (verifier) é o primeiro passo, pegando problemas estruturais antes de perder tempo. Reinstalar, aumentar effort ou editar o CLAUDE.md não diagnosticam a estrutura da skill.]\n\n[ ] A - Reinstall Claude Code\n[ ] B - Run the skills validator, which catches structural problems (invalid frontmatter, file name, YAML)\n[ ] C - Increase the effort level\n[ ] D - Edit the CLAUDE.md to force the skill','\n',char(10)),'B - Run the skills validator, which catches structural problems (invalid frontmatter, file name, YAML)','["Domain_3::Claude_Code_Configuration_Workflows", "Domain_4::Prompt_Engineering_Structured_Output", "Scenario_2::Code_Generation_Claude_Code"]','New',0,2.5,0,1783092988479,1783727436439,1783203558653,replace('Tradução da pergunta e alternativas:\n\n**Pergunta:** Qual é o primeiro passo ao depurar uma skill problemática?\n\n[ ] A - Reinstalar o Claude Code\n[ ] B - Executar o validador de skills, que captura problemas estruturais (frontmatter inválido, nome de arquivo, YAML)\n[ ] C - Aumentar o nível de effort\n[ ] D - Editar o CLAUDE.md para forçar a skill','\n',char(10)),replace('Explicação para adulto tech lead:\n\nA resposta correta é a **alternativa B**.\n\nQuando uma skill não está funcionando conforme o esperado, o primeiro passo deve ser sempre verificar se há problemas estruturais. O validador de skills é a ferramenta mais adequada para isso, pois ele analisa rapidamente:\n\n- **Frontmatter inválido**: metadados da skill (como `---` no início do arquivo) que podem estar mal formatados.\n- **Nome de arquivo**: convenções de nomenclatura que precisam ser seguidas para que a skill seja reconhecida.\n- **YAML malformado**: erros de sintaxe no YAML que impedem o parsing correto das configurações da skill.\n\n**Por que as demais alternativas estão incorretas:**\n\n- **A (Reinstalar o Claude Code)**: É uma ação drástica e desnecessária como primeiro passo. Reinstalar não diagnostica a causa raiz do problema. Pode até resolver um problema de instalação corrompida, mas isso é raro e não deve ser a primeira suspeita.\n\n- **C (Aumentar o nível de effort)**: Aumentar o "esforço" pode mudar o comportamento do modelo, mas não corrige erros estruturais na definição da skill. Se a skill tem YAML inválido ou frontmatter incorreto, aumentar effort não vai fazer mágica — o arquivo continua quebrado.\n\n- **D (Editar o CLAUDE.md para forçar a skill)**: Editar o CLAUDE.md é uma ação reativa com baixa probabilidade de sucesso se o problema for estrutural. O CLAUDE.md não substitui a validação da skill. É como tentar consertar o motor do carro ajustando o ar-condicionado.\n\nA abordagem correta de debugging segue o princípio de "isolar a causa raiz". Primeiro, valide a estrutura (alternativa B). Só depois de confirmar que a estrutura está correta é que faz sentido investigar outras causas.','\n',char(10)),replace('Imagine que você montou um robô de brinquedo, mas ele não funciona. O que você faz primeiro?\n\nVocê não sai comprando um robô novo (alternativa A - reinstalar), nem aperta botões aleatórios (alternativa C - aumentar esforço), nem tenta enfiar um papel diferente nele (alternativa D - editar CLAUDE.md).\n\nA primeira coisa a fazer é **verificar se você montou o robô direito**! Isso é o que o validador de skills faz (alternativa B). Ele olha as peças da skill pra ver se:\n\n- As instruções estão escritas no lugar certo (frontmatter)\n- O nome do arquivo está certo\n- Não tem nenhum errinho de digitação no "idioma" que o computador entende (YAML)\n\nÉ como conferir se você encaixou todas as peças do Lego antes de reclamar que o castelo não parece com a foto da caixa. Primeiro verifique se a montagem está correta!','\n',char(10)));
INSERT INTO cards VALUES('admin','card_1783092988498_vvsb95wwj',328,'The skill does not appear in the list.',replace('The skill does not appear in the list.\n\nThe skill does not appear in the list. Which structural requirements do you check?\n[Resposta correta: O SKILL.md precisa estar em um diretório nomeado e ter o nome exato SKILL.md. A A viola justamente esses requisitos; não existe campo enabled nem comando claude skill add nesse contexto.]\n\n[ ] A - Whether the file is named skill.md at the root of skills\n[ ] B - Whether the SKILL.md is inside a named directory and whether the name is exactly SKILL.md (SKILL uppercase, md lowercase)\n[ ] C - Whether there is an enabled: true field in the frontmatter\n[ ] D - Whether the skill was registered with claude skill add','\n',char(10)),'B - Whether the SKILL.md is inside a named directory and whether the name is exactly SKILL.md (SKILL uppercase, md lowercase)','["Domain_3::Claude_Code_Configuration_Workflows", "Scenario_2::Code_Generation_Claude_Code"]','New',0,2.5,0,1783092988498,1783727439874,1783203558653,replace('**Tradução:**\n\nA habilidade não aparece na lista.\n\nA habilidade não aparece na lista. Quais requisitos estruturais você verifica?\n\n[ ] A - Se o arquivo está nomeado como skill.md na raiz de skills\n[ ] B - Se o SKILL.md está dentro de um diretório nomeado e se o nome é exatamente SKILL.md (SKILL maiúsculo, md minúsculo)\n[ ] C - Se existe um campo enabled: true no frontmatter\n[ ] D - Se a habilidade foi registrada com claude skill add','\n',char(10)),replace('**Explicação para adulto (tech lead):**\n\nA pergunta trata de um problema de descoberta: uma skill (habilidade) que deveria ser carregada não aparece na lista disponível. A resposta correta é a **alternativa B**, porque os requisitos estruturais fundamentais para que uma skill seja reconhecida pelo sistema são:\n\n1. O arquivo SKILL.md deve estar **dentro de um diretório nomeado** (ou seja, não pode estar solto na raiz).\n2. O nome do arquivo deve ser **exatamente SKILL.md** — com "SKILL" em letras maiúsculas e "md" em letras minúsculas.\n\n**Por que as demais estão erradas:**\n\n- **Alternativa A** ("skill.md na raiz de skills"): errada por dois motivos. Primeiro, o arquivo precisa estar dentro de um subdiretório, não na raiz. Segundo, o nome deve ser "SKILL.md" (maiúsculo), não "skill.md" (minúsculo). A pergunta original deixa claro que a alternativa A viola justamente esses requisitos.\n- **Alternativa C** ("enabled: true no frontmatter"): não existe campo `enabled` no frontmatter de um SKILL.md. Esse não é um requisito estrutural válido para o reconhecimento da skill.\n- **Alternativa D** ("registrada com claude skill add"): não existe comando `claude skill add` nesse contexto. O reconhecimento de skills é feito pela estrutura de diretórios e arquivos, não por registro manual via comando.\n\nPortanto, ao debuggar por que uma skill não aparece, o primeiro check deve ser estrutural: o arquivo está no local e com o nome corretos?','\n',char(10)),replace('**Explicação para criança de 10 anos:**\n\nImagina que você tem uma caixa de brinquedos. Dentro dela, você coloca várias caixinhas menores, cada uma com o nome de um brinquedo. Dentro de cada caixinha menor, tem um papel dizendo como o brinquedo funciona.\n\nAgora, a pergunta é: por que um brinquedo não aparece na sua lista?\n\nA resposta certa é a **letra B**: porque o papel com as instruções (o SKILL.md) precisa estar dentro de uma caixinha com nome (um diretório nomeado) e o nome do papel tem que ser exatamente "SKILL.md" — com SKILL em letra maiúscula e md em minúscula.\n\nAs outras opções estão erradas porque:\n\n- **Letra A**: está errada porque o papel não pode estar jogado no fundo da caixa grande (na raiz), tem que estar dentro de uma caixinha menor.\n- **Letra C**: está errada porque não existe um negócio de "ligado/desligado" no papel. Isso não é algo que a gente usa aqui.\n- **Letra D**: está errada porque não existe um comando mágico "claude skill add" para registrar o brinquedo. O jeito certo é só colocar o papel na caixinha certa.\n\nEntão, se um brinquedo não aparece, a primeira coisa é verificar se o papel está na caixinha certa e com o nome certinho!','\n',char(10)));
INSERT INTO cards VALUES('admin','card_1783092988517_wdfdhhi98',329,'Which command helps you see skill loading errors?',replace('Which command helps you see skill loading errors?\n\nWhich command helps you see skill loading errors?\n[Resposta correta: claude --debug mostra mensagens de carregamento e /doctor verifica overflow do budget de descriptions. A A inventa a flag; C é registro de MCP; /compact resume contexto.]\n\n[ ] A - claude --verbose-skills\n[ ] B - claude --debug (looking for the skill name); /doctor helps with the descriptions budget overflow\n[ ] C - claude mcp add debug\n[ ] D - /compact','\n',char(10)),'B - claude --debug (looking for the skill name); /doctor helps with the descriptions budget overflow','["Domain_3::Claude_Code_Configuration_Workflows", "Domain_4::Prompt_Engineering_Structured_Output", "Scenario_2::Code_Generation_Claude_Code"]','New',0,2.5,0,1783092988517,1783727443438,1783203558653,replace('**Tradução para português do Brasil:**\n\nQual comando ajuda você a ver erros de carregamento de skills?\n\n[ ] A - claude --verbose-skills\n[ ] B - claude --debug (procurando pelo nome da skill); /doctor ajuda com o overflow do budget de descriptions\n[ ] C - claude mcp add debug\n[ ] D - /compact','\n',char(10)),replace('**Explicação didática para um adulto tech lead:**\n\nA alternativa B está correta. No ecossistema Claude, o comando `claude --debug` exibe mensagens detalhadas de carregamento, incluindo erros específicos de skills. Além disso, o comando `/doctor` é um utilitário que verifica problemas como estouro (overflow) do budget de descriptions, que é um limite de tamanho para descrições de skills. Juntas, essas ferramentas permitem diagnosticar falhas de carregamento.\n\nAnálise das alternativas incorretas:\n\n- **Alternativa A (`claude --verbose-skills`)**: Esta flag não existe na CLI do Claude. É uma invenção. Não há um comando `--verbose-skills` reconhecido.\n\n- **Alternativa C (`claude mcp add debug`)**: O comando `mcp add` é utilizado para registrar ferramentas MCP (Model Context Protocol) no Claude, não para depuração de erros de carregamento de skills. A semântica está errada.\n\n- **Alternativa D (`/compact`)**: O comando `/compact` resume o contexto da conversa, compactando o histórico para economizar tokens. Não tem relação com diagnóstico de erros de carregamento de skills.','\n',char(10)),replace('Imagine que você tem um jogo de videogame e, de vez em quando, algumas fases não carregam direito. Para descobrir o que deu errado, você usa uma "ferramenta de detetive". \n\nNo Claude, o comando `claude --debug` é como ligar o "modo detetive" — ele mostra tudo que está acontecendo quando o sistema tenta carregar as skills (que são como "poderes" ou "habilidades" do Claude). Se algo der erro, aparece na tela!\n\nE o comando `/doctor` é como levar o sistema ao "médico": ele verifica se as descrições das skills não estão muito grandes (o que chamam de "overflow do budget", que é quando a descrição estoura o limite de tamanho).\n\nAs outras opções estão erradas:\n- A opção A (`claude --verbose-skills`) é um nome de comando inventado, não existe no Claude.\n- A opção C (`claude mcp add debug`) seria como tentar adicionar uma peça nova ao jogo, não resolver erro de carregamento.\n- A opção D (`/compact`) é como apertar um botão que "enrola" a conversa para economizar espaço, não ajuda a achar erros.','\n',char(10)));
INSERT INTO cards VALUES('admin','card_1783092988537_hdyv38due',330,'Your personal skill is being ignored.',replace('Your personal skill is being ignored.\n\nYour personal skill is being ignored. What is the likely cause and the options?\n[Resposta correta: Uma skill enterprise de mesmo nome tem prioridade maior; renomear a sua (mais fácil) ou falar com o admin resolve. As demais atribuem a causa a corrupção, effort ou CLAUDE.md, não ao conflito de prioridade.]\n\n[ ] A - The SKILL.md is corrupted; recreate it\n[ ] B - An enterprise skill of the same name has higher priority; rename yours or talk to the admin\n[ ] C - The effort level is low; increase it\n[ ] D - The CLAUDE.md is overriding the skill','\n',char(10)),'[ ] B - An enterprise skill of the same name has higher priority; rename yours or talk to the admin','["Domain_3::Claude_Code_Configuration_Workflows", "Scenario_2::Code_Generation_Claude_Code"]','New',0,2.5,0,1783092988537,1783727446516,1783203558653,replace('**Tradução:**\n\nSua skill pessoal está sendo ignorada. Qual é a causa provável e quais são as opções?\n\n[ ] A - O SKILL.md está corrompido; recrie-o\n[ ] B - Uma skill enterprise de mesmo nome tem prioridade maior; renomeie a sua ou fale com o administrador\n[ ] C - O nível de effort está baixo; aumente-o\n[ ] D - O CLAUDE.md está sobrescrevendo a skill','\n',char(10)),replace('**Explicação para adulto tech lead:**\n\nA pergunta aborda um cenário comum em sistemas que permitem a sobreposição de configurações (como skills pessoais vs. skills corporativas/enterprise). O mecanismo de resolução de conflitos segue uma hierarquia de precedência: normalmente, configurações globais/enterprise têm prioridade sobre configurações locais/pessoais.\n\n**Alternativa correta: B**\n\nA letra B descreve exatamente o problema de conflito de nomenclatura com prioridade. Quando uma skill enterprise possui o mesmo nome que sua skill pessoal, o sistema dá prioridade à enterprise. As soluções propostas são práticas: (1) renomear sua skill pessoal para um nome único (solução mais rápida e de baixo risco) ou (2) contactar o administrador para resolver o conflito (necessário se você não tiver permissão para renomear ou se a skill enterprise precisar ser ajustada).\n\n**Análise das alternativas incorretas:**\n\n- **A (SKILL.md corrompido):** Corrupção de arquivo poderia causar falha no carregamento, mas não explica o cenário de "ignorada" — uma skill corrompida provavelmente geraria erro explícito ou comportamento imprevisível, não um silencioso desrespeito à skill.\n\n- **C (effort baixo):** O conceito de "effort" (esforço) não é uma configuração que determina prioridade de skills. Ele pode influenciar comportamento do modelo (ex.: profundidade de raciocínio), mas não faz uma skill ser ignorada em favor de outra.\n\n- **D (CLAUDE.md sobrescrevendo):** O CLAUDE.md é um arquivo de configuração do projeto, mas não tem o comportamento de "sobrescrever" skills. Ele pode fornecer instruções contextuais, porém o mecanismo de prioridade entre skills pessoais e enterprise é independente do CLAUDE.md.','\n',char(10)),replace('Imagine que você tem um desenho seu na geladeira (sua skill pessoal), mas sua escola colocou um desenho igualzinho na parede da entrada (skill enterprise). Quando as pessoas olham, elas veem o da escola primeiro, porque ele está num lugar mais importante. Seu desenho não está estragado nem é feio — ele simplesmente está sendo "ignorado" porque o da escola tem prioridade.\n\nPara resolver, você pode: (a) fazer um desenho diferente, com um nome novo (mais fácil), ou (b) pedir para um adulto (admin) arrumar isso.\n\nAs outras opções estão erradas porque:\n- A: Seu desenho não está rasgado (corrompido).\n- C: Não adianta caprichar mais (aumentar effort) — o problema não é capricho, é que tem dois iguais.\n- D: O mural da sala de aula (CLAUDE.md) não apaga seu desenho da geladeira.','\n',char(10)));
INSERT INTO cards VALUES('admin','card_1783092988582_9a6ic9fc3',331,'You installed a plugin but its skills do not appear.',replace('You installed a plugin but its skills do not appear.\n\nYou installed a plugin but its skills do not appear. What do you do?\n[Resposta correta: Limpar o cache, reiniciar e reinstalar resolve, e o validator diagnostica estrutura errada persistente. Renomear não é o problema aqui; mover manualmente ou usar @ no CLAUDE.md não é o procedimento indicado.]\n\n[ ] A - Rename the plugin''s skills to avoid conflict\n[ ] B - Clear the cache, restart and reinstall; if it persists, check the plugin''s structure with the validator\n[ ] C - Move them manually to ~/.claude/skills\n[ ] D - Add the plugin to the CLAUDE.md with @','\n',char(10)),'B - Clear the cache, restart and reinstall; if it persists, check the plugin''s structure with the validator','["Domain_3::Claude_Code_Configuration_Workflows", "Domain_2::Tool_Design_MCP_Integration", "Scenario_2::Code_Generation_Claude_Code"]','New',0,2.5,0,1783092988582,1783727450066,1783203558653,replace('**Tradução:**\n\nVocê instalou um plugin, mas suas skills não aparecem. O que você faz?\n\n[ ] A - Renomear as skills do plugin para evitar conflito\n[ ] B - Limpar o cache, reiniciar e reinstalar; se persistir, verificar a estrutura do plugin com o validator\n[ ] C - Movê-las manualmente para ~/.claude/skills\n[ ] D - Adicionar o plugin ao CLAUDE.md com @','\n',char(10)),replace('**Explicação para um adulto tech lead:**\n\nA pergunta trata de um cenário onde um plugin foi instalado, mas suas skills (habilidades) não são reconhecidas ou aparecem no sistema. Vamos analisar cada alternativa:\n\n- **Alternativa A (Renomear as skills):** Renomear skills não resolve o problema de descoberta ou carregamento. Se o plugin foi instalado corretamente, o nome das skills não deveria causar conflito a ponto de ocultá-las. Essa é uma ação superficial que não ataca a causa raiz.\n\n- **Alternativa B (Correta):** Esta é a abordagem sistemática e recomendada. Limpar o cache remove possíveis dados corrompidos ou inconsistentes que impedem o carregamento. Reiniciar o processo garante que todas as configurações sejam recarregadas do zero. Reinstalar assegura que todos os arquivos estejam no lugar correto. Se o problema persistir, o validator é a ferramenta apropriada para diagnosticar problemas estruturais no plugin (como pastas ausentes, metadados incorretos ou hierarquia errada). Essa sequência cobre tanto problemas transitórios quanto estruturais.\n\n- **Alternativa C (Mover manualmente para ~/.claude/skills):** Mover arquivos manualmente não é o procedimento indicado para plugins instalados. O diretório de skills pode não ser o local correto para o plugin inteiro, e isso pode quebrar a integridade da instalação. A instalação adequada deve gerenciar esses caminhos automaticamente.\n\n- **Alternativa D (Adicionar ao CLAUDE.md com @):** Adicionar uma entrada no CLAUDE.md com @ não é um mecanismo de instalação ou ativação de plugins. Isso pode ser usado para referenciar contextos, mas não para resolver problemas de skills não carregadas. É uma ação irrelevante para o problema.\n\n**Conclusão:** A alternativa B é a mais robusta e alinhada com boas práticas de troubleshooting: ações de baixo risco e alto impacto (cache, reinício, reinstalação) seguidas de diagnóstico especializado (validator) para casos persistentes.','\n',char(10)),replace('Imagine que você baixou um joguinho novo no tablet, mas os personagens não aparecem. O que fazer?\n\nSe você só mudar o nome dos personagens (alternativa A), isso não resolve, porque o problema não é o nome.\n\nA melhor ideia (alternativa B) é: primeiro, limpar a memória do tablet (cache), desligar e ligar de novo, e se ainda assim não funcionar, reinstalar o jogo. Se mesmo assim os personagens não aparecerem, aí você pede ajuda para uma ferramenta especial (validator) que descobre se o jogo foi montado do jeito certo.\n\nMover os arquivos para outra pasta (alternativa C) bagunça tudo, porque não é assim que se faz.\n\nE escrever o nome do jogo num papel mágico (alternativa D) não faz aparecer os personagens.\n\nEntão, a resposta certa é a **B**: limpar, reiniciar, reinstalar e, se precisar, usar o validator.','\n',char(10)));
INSERT INTO cards VALUES('admin','card_1783092988602_u1a9bzlji',332,'The skill''s script fails at runtime due to permissions.',replace('The skill''s script fails at runtime due to permissions.\n\nThe skill''s script fails at runtime due to permissions. How do you resolve it?\n[Resposta correta: chmod +x nos scripts resolve a falha por permissão. Instalar pacotes é para dependência faltando; --debug diagnostica carregamento; renomear é para conflito de prioridade.]\n\n[ ] A - Install missing external packages\n[ ] B - Grant execute permission with chmod +x on the referenced scripts\n[ ] C - Run claude --debug\n[ ] D - Rename the skill to something distinct','\n',char(10)),'B - Grant execute permission with chmod +x on the referenced scripts','["Domain_3::Claude_Code_Configuration_Workflows", "Scenario_2::Code_Generation_Claude_Code"]','New',0,2.5,0,1783092988602,1783727453440,1783203558653,replace('**Tradução:**\n\nA execução do script da skill falha em tempo de execução devido a permissões.\n\nComo você resolve isso?\n\n[ ] A - Instalar pacotes externos faltando\n[ ] B - Conceder permissão de execução com chmod +x nos scripts referenciados\n[ ] C - Executar claude --debug\n[ ] D - Renomear a skill para algo distinto','\n',char(10)),replace('**Explicação para um adulto tech lead:**\n\nO problema relatado é claro: o script falha em tempo de execução **especificamente por causa de permissões**. Isso indica que o sistema operacional está impedindo a execução do script porque ele não possui a flag de permissão de execução (execute permission) definida.\n\n**Alternativa correta: B - chmod +x**\n\n- O comando `chmod +x` (change mode + execute) adiciona a permissão de execução ao arquivo de script. No Linux/Unix, todo arquivo precisa ter a permissão `x` para ser executado diretamente. Sem ela, o kernel nega a tentativa de execução, gerando o erro "Permission denied". Esta é a correção direta e específica para o problema descrito.\n\n**Por que as demais estão erradas:**\n\n- **A (Instalar pacotes externos):** Resolve problemas de dependências faltando (ex.: módulos Python não instalados, bibliotecas ausentes). O erro seria algo como "ModuleNotFoundError" ou "command not found", não um erro de permissão.\n\n- **C (claude --debug):** A flag `--debug` é usada para diagnosticar problemas de carregamento de configuração, como conflitos de arquivos YAML, variáveis de ambiente ou caminhos incorretos. Ela pode revelar o erro de permissão, mas não o corrige. É uma ferramenta de diagnóstico, não de resolução.\n\n- **D (Renomear a skill):** Renomear a skill resolveria um conflito de prioridade ou nome duplicado entre skills, mas não tem relação alguma com permissões de arquivo em tempo de execução.','\n',char(10)),replace('Imagine que você tem um videogame e baixa um jogo novo. Quando você tenta abrir o jogo, o videogame diz: "Não posso abrir isso!". O motivo é que o jogo está "trancado" e ninguém deu permissão para ele ser executado.\n\n- A opção **B (chmod +x)** é como dar um "passe livre" para o jogo. Você está dizendo ao computador: "Pode deixar esse arquivo ser executado, está liberado!". É a única coisa que resolve o problema de permissão.\n\n- A opção **A (instalar pacotes)** seria como tentar consertar o jogo baixando peças novas, mas o problema não é que faltam peças — o problema é que o jogo está trancado.\n\n- A opção **C (--debug)** é como ligar para a assistência técnica para entender o que está errado. Eles podem descobrir que o jogo está trancado, mas ainda assim precisam destrancar ele. Não resolve sozinho.\n\n- A opção **D (renomear a skill)** é como mudar o nome do jogo na prateleira. Isso não faz o jogo abrir magicamente.\n\nEntão, a resposta certa é a **B**: dar permissão de execução com `chmod +x`.','\n',char(10)));
INSERT INTO cards VALUES('admin','card_1783092988622_y7dcus8jv',333,'The skill loads but fails at runtime due to a missing dependency.',replace('The skill loads but fails at runtime due to a missing dependency.\n\nThe skill loads but fails at runtime due to a missing dependency. How do you resolve it?\n[Resposta correta: Instalar os pacotes e registrar as dependências na description resolve o erro por dependência faltando. O validator pega problemas estruturais, não de runtime; chmod resolve permissão; limpar cache é para skills que não aparecem.]\n\n[ ] A - Run the validator again until it passes\n[ ] B - Install the required external packages and document the dependencies in the skill''s description\n[ ] C - chmod +x the scripts\n[ ] D - Clear the cache and restart','\n',char(10)),'B - Install the required external packages and document the dependencies in the skill''s description','["Domain_2::Tool_Design_MCP_Integration", "Domain_5::Context_Management_Reliability", "Scenario_1::Customer_Support_Agent"]','New',0,2.5,0,1783092988622,1783727456933,1783203558653,replace('**Tradução fiel para pt-BR:**\n\nA habilidade carrega, mas falha em tempo de execução devido a uma dependência ausente. Como você resolve isso?\n\n[ ] A - Executar o validador novamente até que ele passe\n[ ] B - Instalar os pacotes externos necessários e documentar as dependências na descrição da habilidade\n[ ] C - chmod +x nos scripts\n[ ] D - Limpar o cache e reiniciar','\n',char(10)),replace('**Explicação técnica para adulto tech lead:**\n\nO problema descrito é clássico: a skill (habilidade) é carregada pelo sistema sem erros de sintaxe ou estrutura — isso significa que o validador não encontrou problemas no manifesto ou nos arquivos. Porém, ao ser executada, ela falha porque tenta importar ou utilizar um pacote/biblioteca que não está disponível no ambiente de runtime. Isso é um erro de dependência ausente.\n\nA alternativa **B** é a correta porque aborda diretamente a causa raiz: é preciso instalar os pacotes externos necessários no ambiente onde a skill será executada (seja via requirements.txt, package.json, ou similar) e documentar essas dependências na descrição da skill. Documentar na descrição é uma boa prática que permite que outros desenvolvedores ou sistemas de deploy saibam quais dependências são necessárias antes da execução.\n\n**Análise das alternativas incorretas:**\n\n- **A (Executar o validador novamente):** O validador geralmente checa estrutura, sintaxe, conformidade com schemas, etc. Se a skill já carregou, o validador passou. Erro de runtime por dependência faltando não é capturado por validadores estáticos. Repeti-lo não resolverá o problema.\n\n- **C (chmod +x nos scripts):** Alterar permissões de execução só é relevante se o erro for de permissão ("Permission denied"). O enunciado diz explicitamente que o erro é por "missing dependency", não por falta de permissão de execução. chmod +x não instala pacotes.\n\n- **D (Limpar o cache e reiniciar):** Limpar cache resolve problemas onde uma versão antiga ou corrompida da skill está sendo usada. Se a skill carrega mas falha em runtime por dependência, o cache não é o culpado. Reiniciar também não fará o pacote mágico aparecer.','\n',char(10)),replace('Imagine que você tem um jogo de videogame que abre, mas quando você tenta jogar, ele dá erro porque está faltando uma peça importante, tipo um controle ou um cabo de energia.\n\nA alternativa B diz: "Instalar os pacotes externos necessários e documentar as dependências na descrição da habilidade." Isso é como pegar o controle que estava faltando e ainda escrever na caixa do jogo: "Precisa de controle para jogar!". Assim, todo mundo sabe o que precisa ter antes de tentar jogar.\n\nAs outras opções não funcionam:\n- A - Rodar o validador de novo é como apertar o botão "OK" no erro repetidas vezes — não resolve, porque o problema não é o jogo estar quebrado, é a peça que falta.\n- C - chmod +x é como tentar dar um jeito no arquivo do jogo, mas não coloca a peça que falta.\n- D - Limpar o cache e reiniciar é como desligar o videogame e ligar de novo — se a peça não estava lá, continua não estando.\n\nEntão a resposta certa é a **B**.','\n',char(10)));
INSERT INTO cards VALUES('admin','card_1783092988641_nosbnhpik',334,'What is the rule about path separators in skills to avoid a runtime error?',replace('What is the rule about path separators in skills to avoid a runtime error?\n\nWhat is the rule about path separators in skills to avoid a runtime error?\n[Resposta correta: A regra é usar barras normais (/) em todo lugar, inclusive no Windows. As demais introduzem contrabarras ou deixam a escolha ambígua, o que causa o erro.]\n\n[ ] A - Use backslashes (\) on Windows and slashes (/) elsewhere\n[ ] B - Use normal slashes (/) everywhere, even on Windows\n[ ] C - Always use absolute paths with backslashes\n[ ] D - Let Claude choose the separator automatically','\n',char(10)),'[ ] B - Use normal slashes (/) everywhere, even on Windows','["Domain_2::Tool_Design_MCP_Integration", "Domain_5::Context_Management_Reliability", "Scenario_4::Developer_Productivity"]','New',0,2.5,0,1783092988641,1783727460703,1783203558653,replace('**Tradução para português do Brasil:**\n\nPergunta: Qual é a regra sobre separadores de caminho em skills para evitar um erro em tempo de execução?\n\n[ ] A - Use barras invertidas (\) no Windows e barras normais (/) em outros lugares\n[ ] B - Use barras normais (/) em todo lugar, inclusive no Windows\n[ ] C - Sempre use caminhos absolutos com barras invertidas\n[ ] D - Deixe o Claude escolher o separador automaticamente','\n',char(10)),replace('**Explicação para adulto (tech lead):**\n\nEm ambientes de execução de skills (como em plataformas de agentes de IA ou sistemas de automação), o uso inconsistente de separadores de caminho pode gerar erros de runtime, especialmente quando o código precisa ser cross-platform.\n\n- **Alternativa B (correta):** A recomendação padrão em plataformas modernas (como em skills para Claude, ferramentas de automação, e muitas linguagens como Python e JavaScript) é usar sempre barras normais (`/`). Mesmo no Windows, a grande maioria das bibliotecas modernas — como `pathlib` em Python ou `fs` no Node.js — normaliza automaticamente barras normais para o separador correto do sistema operacional. Isso garante portabilidade e elimina erros de parsing.\n\n- **Alternativa A (errada):** Embora pareça intuitivo usar `\` no Windows, isso frequentemente quebra em contextos onde o separador é interpretado como caractere de escape (ex.: em strings JSON, YAML, ou argumentos de shell). Além disso, aumenta a complexidade lógica e a chance de erro.\n\n- **Alternativa C (errada):** Usar caminhos absolutos com barras invertidas é ainda mais específico para Windows e falha em outros sistemas. Caminhos absolutos também reduzem portabilidade.\n\n- **Alternativa D (errada):** Delegar a decisão ao Claude (ou a qualquer sistema automatizado sem controle explícito) pode levar a comportamentos imprevisíveis. A regra deve ser explícita e determinística.','\n',char(10)),replace('Imagine que você está escrevendo o endereço de uma casa. Se você escrever de um jeito diferente cada vez, o carteiro pode se perder e não entregar a carta.\n\nA regra é simples: use sempre **barras normais (/)**, como nas barras do teclado que inclinam para a direita. Funciona em qualquer computador, seja Windows, Mac ou Linux.\n\n- Quem usa barra invertida (\) igual no Windows, pode causar confusão porque alguns programas pensam que é outra coisa.\n- Quem usa caminhos enormes e fixos, pode quebrar em outros computadores.\n- E deixar o computador adivinhar sozinho também é arriscado.\n\nEntão, para não dar erro: **sempre use / em todo lugar**.','\n',char(10)));
INSERT INTO cards VALUES('admin','card_1783092988660_8ut5wqhdg',335,'The skill "does not trigger" when it should.',replace('The skill "does not trigger" when it should.\n\nThe skill "does not trigger" when it should. What is the indicated fix?\n[Resposta correta: "Não dispara" se corrige melhorando a description e adicionando frases de gatilho. Checar caminho/nome/YAML é para "não carrega"; descriptions distintas resolvem "skill errada usada"; chmod é para permissão de script.]\n\n[ ] A - Check the path, the file name and the YAML syntax\n[ ] B - Improve the description and add trigger phrases\n[ ] C - Make the descriptions more distinct from each other\n[ ] D - chmod +x the scripts','\n',char(10)),'B - Improve the description and add trigger phrases','["Domain_3::Claude_Code_Configuration_Workflows", "Domain_4::Prompt_Engineering_Structured_Output", "Scenario_2::Code_Generation_Claude_Code"]','New',0,2.5,0,1783092988660,1783727464344,1783203558653,replace('**Tradução para português do Brasil:**\n\nA habilidade "não dispara" quando deveria disparar. Qual é a correção indicada?\n\n[ ] A - Verificar o caminho, o nome do arquivo e a sintaxe YAML\n[ ] B - Melhorar a descrição e adicionar frases de gatilho\n[ ] C - Tornar as descrições mais distintas entre si\n[ ] D - Dar permissão de execução (chmod +x) aos scripts','\n',char(10)),replace('**Explicação didática para um adulto tech lead:**\n\nO problema descrito é que a skill *não dispara* quando deveria — ou seja, o mecanismo de invocação da skill está falhando em reconhecê-la no momento apropriado. Em sistemas de assistentes de voz ou de comandos (como Alexa, Google Assistant ou frameworks como Mycroft, Alexa Skills Kit, etc.), o disparo de uma skill depende fundamentalmente de dois elementos: a **descrição** da skill (que ajuda a identificar seu propósito) e as **frases de gatilho** (utterances ou invoke names), que são os padrões de fala que ativam a skill.\n\nA alternativa **B** é a correta porque ataca diretamente a causa raiz do "não dispara": se a skill não está sendo ativada, é provável que as frases de gatilho estejam ausentes, genéricas demais ou conflitantes, ou que a descrição não esteja clara o suficiente para o sistema associar corretamente a intenção do usuário à skill.\n\nAnálise das demais alternativas:\n\n- **Alternativa A (Verificar caminho, nome do arquivo e sintaxe YAML):** Essa abordagem é indicada quando a skill **não carrega** (falha na inicialização ou no deploy), e não quando ela carrega mas não dispara. Um erro de sintaxe YAML ou de path geralmente impede que o sistema sequer reconheça a skill como válida, resultando em erro de build ou de registro, não em falha de disparo em tempo de execução.\n\n- **Alternativa C (Tornar as descrições mais distintas):** Essa correção é voltada para o problema oposto — quando a **skill errada** é usada no lugar da correta (ambiguidade entre skills similares). Se o sistema está confundindo duas skills, descrições mais distintas resolvem. Mas não é o caso de "não disparar", e sim de "disparar a skill errada".\n\n- **Alternativa D (Dar permissão de execução aos scripts):** Isso é um problema de permissão de sistema operacional. Se o script não tem permissão de execução (chmod +x), a skill pode falhar ao executar, mas o sintoma seria um erro de runtime ou "skill não executou", e não "skill não disparou". O disparo (trigger) é anterior à execução.\n\nPortanto, para o sintoma específico "não dispara", a correção indicada é melhorar a descrição e adicionar frases de gatilho.','\n',char(10)),replace('Imagine que você tem um robô que só faz alguma coisa quando você fala palavras mágicas certas.\n\nSe o robô não está fazendo nada quando você fala, é porque ele não está entendendo que você quer que ele ajude. Para consertar isso, você precisa ensinar ao robô quais palavras usar para chamá-lo. É como dar a ele um "nome secreto" e explicar melhor o que ele faz.\n\n- A opção A (verificar o caminho, nome e sintaxe) seria como checar se o brinquedo está montado direitinho. Isso ajuda se ele não liga, mas não se ele liga e não escuta você.\n- A opção C (deixar as descrições mais diferentes) serve quando você tem dois robôs parecidos e um deles faz a coisa errada. Não é o nosso caso.\n- A opção D (dar permissão) é tipo destravar um botão. Serve se o robô não consegue se mexer, mas não se ele não te ouve.\n\nEntão, a resposta certa é a **B**: melhorar a descrição e adicionar frases de gatilho — ou seja, ensinar melhor o robô a te ouvir e entender quando você está falando com ele.','\n',char(10)));
INSERT INTO cards VALUES('admin','card_1783092988681_d1p9pxf13',336,'Custom slash commands/skills that need to be shared with the whole team via the repository should go where?',replace('Custom slash commands/skills that need to be shared with the whole team via the repository should go where?\n\nCustom slash commands/skills that need to be shared with the whole team via the repository should go where?\n[Resposta correta: O escopo de projeto (.claude/commands/ ou .claude/skills/) é versionado e chega a todos via Git. ~/.claude/ é para comandos pessoais não compartilhados; CLAUDE.md é contexto, não define comandos; settings.local.json não é commitado.]\n\n[ ] A - In ~/.claude/commands, user scope\n[ ] B - In the project directory (.claude/commands/ or .claude/skills/), versioned and available to whoever clones\n[ ] C - In the project''s CLAUDE.md, as text\n[ ] D - In the project''s settings.local.json','\n',char(10)),'B - In the project directory (.claude/commands/ or .claude/skills/), versioned and available to whoever clones','["Domain_3::Claude_Code_Configuration_Workflows", "Scenario_2::Code_Generation_Claude_Code"]','New',0,2.5,0,1783092988681,1783727467436,1783203558653,replace('**Tradução para pt-BR:**\n\nComandos/skills personalizados que precisam ser compartilhados com todo o time via repositório devem ir para onde?\n\n[ ] A - Em ~/.claude/commands, escopo do usuário\n[ ] B - No diretório do projeto (.claude/commands/ ou .claude/skills/), versionado e disponível para quem clonar\n[ ] C - No CLAUDE.md do projeto, como texto\n[ ] D - No settings.local.json do projeto','\n',char(10)),replace('**Explicação para adulto tech lead:**\n\nA alternativa correta é a **B**. Vamos entender o racional:\n\n- **Alternativa B (correta):** O diretório `.claude/commands/` (ou `.claude/skills/`) dentro do repositório do projeto é a localização padrão para definir comandos e skills que fazem parte do escopo do projeto. Como está dentro do repositório, ele é versionado pelo Git, o que significa que qualquer pessoa que clone o projeto terá acesso a esses comandos/skills automaticamente. Isso garante consistência e compartilhamento em todo o time.\n\n- **Alternativa A (incorreta):** `~/.claude/commands/` refere-se ao escopo do usuário local (máquina do desenvolvedor). Esse diretório **não** é versionado nem compartilhado via repositório, sendo adequado apenas para comandos pessoais que não devem ser expostos ao time.\n\n- **Alternativa C (incorreta):** O `CLAUDE.md` é um arquivo de contexto/instruções para o Claude, mas não suporta definição de comandos ou skills. Ele serve para fornecer diretrizes, regras de negócio ou preferências de projeto como texto livre, não para registrar comandos executáveis.\n\n- **Alternativa D (incorreta):** `settings.local.json` é um arquivo de configuração local do projeto (geralmente ignorado pelo `.gitignore`). Ele não é commitado e, portanto, não é adequado para compartilhar comandos ou skills com o time. Além disso, seu propósito é armazenar ajustes de ambiente local, não definições funcionais de comandos.\n\n**Resumo técnico:** Para compartilhar comandos/skills com o time via repositório, use o escopo de projeto (`<repo>/.claude/commands/` ou `<repo>/.claude/skills/`). Escopos de usuário (`~/.claude/`) são para uso pessoal; arquivos de contexto ou configuração local não servem para esse propósito.','\n',char(10)),replace('Imagine que você e seus amigos estão montando um quebra-cabeça gigante. Se você criar uma regra especial para ajudar todo mundo a montar o quebra-cabeça mais rápido, onde você deve colocar essa regra?\n\n- **Colocar na sua gaveta secreta em casa (opção A)** — só você vê, ninguém mais aprende. Não adianta!\n- **Colocar numa folha dentro da caixa do quebra-cabeça (opção B)** — todo mundo que pegar a caixa vai ver a regra. É a melhor ideia!\n- **Escrever a regra na parede da sala (opção C)** — as pessoas podem ler, mas não é um lugar certo para guardar regras de jogo.\n- **Guardar num papel que você joga fora depois (opção D)** — ninguém vai ver essa regra porque o papel some.\n\nA resposta certa é a **B**: colocar dentro da pasta do projeto (`.claude/commands/` ou `.claude/skills/`), porque assim todo mundo que baixar o projeto vai ter esses comandos automaticamente!','\n',char(10)));
INSERT INTO cards VALUES('admin','card_1783092988700_eqxc4m29o',337,'When do you use Plan Mode instead of direct execution?',replace('When do you use Plan Mode instead of direct execution?\n\nWhen do you use Plan Mode instead of direct execution?\n[Resposta correta: Plan Mode é para tarefas complexas, de larga escala ou com decisões arquiteturais, onde trade-offs surgem na exploração. Execução direta cobre tarefas simples e bem definidas, então A e D estão erradas; testes não são o critério (C).]\n\n[ ] A - On any task, even simple and well-defined ones\n[ ] B - When the task is complex, large-scale, with multiple valid approaches or architectural decisions\n[ ] C - Only when you need to run tests\n[ ] D - Only for one-line tasks','\n',char(10)),'[ ] B - When the task is complex, large-scale, with multiple valid approaches or architectural decisions','["Domain_3::Claude_Code_Configuration_Workflows", "Domain_4::Prompt_Engineering_Structured_Output", "Scenario_2::Code_Generation_Claude_Code"]','New',0,2.5,0,1783092988700,1783727470906,1783203558653,replace('**Tradução para português do Brasil:**\n\n**Pergunta:** Quando você usa o Modo Plano (Plan Mode) em vez da execução direta?\n\n**Alternativas:**\n[ ] A - Em qualquer tarefa, mesmo as simples e bem definidas\n[ ] B - Quando a tarefa é complexa, de larga escala, com múltiplas abordagens válidas ou decisões arquiteturais\n[ ] C - Apenas quando você precisa executar testes\n[ ] D - Apenas para tarefas de uma linha','\n',char(10)),replace('**Explicação para um adulto tech lead:**\n\nA pergunta aborda um conceito de fluxo de trabalho em sistemas de IA assistiva (como o modo "Plan" vs. "Act" em ferramentas como Cursor, Windsurf, ou assistentes de codificação). O Modo Plano é projetado para cenários que exigem análise, exploração de alternativas e tomada de decisão antes de qualquer ação concreta.\n\n**Alternativa correta (B):** Esta é a resposta certa porque o Plan Mode é utilizado exatamente quando a tarefa apresenta complexidade — seja por seu escopo amplo, múltiplas soluções viáveis, ou necessidade de decisões arquiteturais que envolvem trade-offs. Nesse modo, o assistente pode explorar o código, o contexto do projeto, levantar opções e apresentar uma estratégia antes de executar qualquer alteração. Isso evita retrabalho e alinha a equipe quanto à direção a ser seguida.\n\n**Por que as demais estão erradas:**\n- **Alternativa A ("qualquer tarefa"):** Errada porque usar Plan Mode para tarefas simples e bem definidas (como corrigir um typo ou ajustar uma variável) seria ineficiente e burocrático. Execução direta é mais adequada nesses casos.\n- **Alternativa C ("apenas quando precisa executar testes"):** Errada porque a execução de testes não é o gatilho para o Plan Mode. Testes podem ser parte de uma tarefa complexa, mas não são o critério definidor. Além disso, você pode executar testes tanto no Plan Mode quanto na execução direta — o modo não é definido por isso.\n- **Alternativa D ("apenas para tarefas de uma linha"):** Errada pelo oposto da A. Tarefas de uma linha são tipicamente simples e bem definidas, sendo candidatas ideais para execução direta, não para planejamento.','\n',char(10)),replace('**Explicação para uma criança de 10 anos:**\n\nImagina que você tem duas maneiras de fazer um dever de casa: uma é "pensar primeiro, depois fazer" e a outra é "já ir fazendo". A pergunta é: quando você usa o jeito "pensar primeiro" (Plan Mode) em vez do "já ir fazendo" (execução direta)?\n\n**Resposta certa (B):** Você usa o "pensar primeiro" quando a tarefa é bem difícil, grande ou tem várias formas de resolver. Por exemplo: se você precisa construir uma maquete de uma cidade inteira, você primeiro desenha, mede, escolhe os materiais — isso é planejar. Se você for fazer direto sem pensar, pode acabar tendo que refazer tudo depois.\n\n**Por que as outras estão erradas?**\n- **A ("qualquer tarefa")** — Errada! Se a tarefa for fácil, como escrever seu nome, não precisa planejar, é só fazer.\n- **C ("só quando precisa testar")** — Errada! Testar é diferente de planejar. Você pode testar coisas depois de fazer, mas o planejamento é sobre decidir *como* fazer antes de começar.\n- **D ("só para tarefas de uma linha")** — Errada! Tarefas de uma linha são as mais fáceis, tipo apagar um risco no desenho. Isso você faz na hora, sem precisar planejar nada.','\n',char(10)));
INSERT INTO cards VALUES('admin','card_1783092988720_fvsyhtwf8',338,'How do you apply conventions to files by type/path (e.',replace('How do you apply conventions to files by type/path (e.\n\nHow do you apply conventions to files by type/path (e.g. test files scattered across the codebase)?\n[Resposta correta: Regras em .claude/rules/ com glob patterns aplicam convenções de forma automática e determinística por caminho, independente de diretório. CLAUDE.md é vinculado a diretório; skill exige invocação; nenhum resolve regras condicionais por caminho como o glob.]\n\n[ ] A - Put the conventions in the root directory''s CLAUDE.md\n[ ] B - Create files in .claude/rules/ with YAML frontmatter and glob patterns, applied according to the path\n[ ] C - Create a skill invoked by slash command\n[ ] D - Create a PostToolUse hook per file type','\n',char(10)),'B - Create files in .claude/rules/ with YAML frontmatter and glob patterns, applied according to the path','["Domain_3::Claude_Code_Configuration_Workflows", "Scenario_2::Code_Generation_Claude_Code"]','New',0,2.5,0,1783092988720,1783727474373,1783203558653,replace('**Tradução da pergunta e alternativas:**\n\n**Pergunta:** Como aplicar convenções a arquivos por tipo/caminho (ex.: arquivos de teste espalhados pela base de código)?\n\n**Alternativas:**\n\n[ ] A - Colocar as convenções no CLAUDE.md do diretório raiz\n[ ] B - Criar arquivos em .claude/rules/ com frontmatter YAML e padrões glob, aplicados de acordo com o caminho\n[ ] C - Criar uma skill invocada por comando de barra (/)\n[ ] D - Criar um hook PostToolUse por tipo de arquivo','\n',char(10)),replace('**Explicação para um adulto tech lead:**\n\nA resposta correta é a **alternativa B**.\n\nO problema central é: como aplicar convenções (regras de comportamento, estilo, validação) de forma automática e determinística a arquivos específicos baseando-se em seu tipo ou caminho, sem depender de invocação manual ou de estrutura de diretórios?\n\nVamos analisar cada alternativa:\n\n**A - Colocar as convenções no CLAUDE.md do diretório raiz** → Incorreto. O CLAUDE.md é um arquivo de configuração vinculado ao diretório onde ele está localizado. Ele não possui mecanismo de glob patterns para filtrar arquivos por tipo ou caminho. Ele aplica regras globalmente ao projeto ou a um subdiretório específico, sem granularidade por padrão de caminho.\n\n**B - Criar arquivos em .claude/rules/ com frontmatter YAML e glob patterns** → Correto. O diretório `.claude/rules/` permite criar arquivos com metadados (YAML frontmatter) que definem padrões glob. Esses padrões determinam a quais caminhos/arquivos as regras se aplicam. O sistema aplica as regras automaticamente ao processar arquivos que correspondem aos globs, sem necessidade de invocação manual ou hooks. É a solução nativa, escalável e determinística para o problema.\n\n**C - Criar uma skill invocada por slash command** → Incorreto. Skills exigem invocação explícita pelo usuário (via comando de barra). Isso não resolve o problema de aplicar convenções automaticamente com base no tipo/caminho do arquivo. É uma abordagem reativa, não proativa.\n\n**D - Criar um PostToolUse hook por tipo de arquivo** → Incorreto. Hooks (como PostToolUse) são mecanismos de extensão para executar código após o uso de uma ferramenta, mas não foram projetados para aplicar convenções baseadas em caminho/tipo de arquivo de forma nativa e determinística. Seria uma gambiarra comparado à solução em B.\n\nPortanto, a alternativa B é a única que resolve o problema de forma nativa, automática e por padrão de caminho.','\n',char(10)),replace('**Explicação para uma criança de 10 anos:**\n\nImagine que você tem uma mochila cheia de deveres de casa espalhados. Alguns são de matemática, outros de português. Você quer que cada tipo de dever seja corrigido de um jeito diferente automaticamente.\n\nA alternativa **B** é como arrumar a mochila com etiquetas mágicas: você cria pastinhas especiais (`.claude/rules/`) e escreve regras com "etiquetas" (YAML) que dizem: "tudo que tiver ''teste'' no nome deve seguir essa regra". O computador lê essas etiquetas e aplica as regras sozinho, sem ninguém precisar pedir.\n\nAs outras opções não funcionam tão bem:\n- **A** é como colocar uma regra única na capa da mochila — vale para tudo, não dá para separar por matéria.\n- **C** é como ter um amigo que só ajuda se você chamar pelo nome — não funciona sozinho.\n- **D** é como tentar arrumar a mochila depois que já pegou o dever — é confuso e dá mais trabalho.\n\nEntão a opção **B** é a mais esperta porque as regras são aplicadas sozinhas, de acordo com o tipo de arquivo!','\n',char(10)));
INSERT INTO cards VALUES('admin','card_1783092988741_i193png5s',339,'How do you run a verbose skill without polluting the main conversation, preserving full capability?',replace('How do you run a verbose skill without polluting the main conversation, preserving full capability?\n\nHow do you run a verbose skill without polluting the main conversation, preserving full capability?\n[Resposta correta: context: fork executa a skill em subagente isolado, e a saída não retorna à conversa. O prefixo ! ainda envia a saída do bash ao contexto; /compact comprime e perde capacidade; rodar em sequência ainda polui o contexto.]\n\n[ ] A - Use the ! prefix to run via bash\n[ ] B - Add context: fork to the skill''s frontmatter, isolating the execution in a subagent\n[ ] C - Run /compact after the skill\n[ ] D - Run the skills in sequence to dilute the output','\n',char(10)),'B - Add context: fork to the skill''s frontmatter, isolating the execution in a subagent','["Domain_3::Claude_Code_Configuration_Workflows", "Domain_5::Context_Management_Reliability", "Scenario_2::Code_Generation_Claude_Code"]','New',0,2.5,0,1783092988741,1783727477822,1783203558653,replace('**Tradução para português do Brasil:**\n\nPergunta: "Como executar uma skill verbosa sem poluir a conversa principal, preservando toda a capacidade?"\n\nAlternativas:\n[ ] A - Use o prefixo ! para executar via bash\n[ ] B - Adicione context: fork ao frontmatter da skill, isolando a execução em um subagente\n[ ] C - Execute /compact após a skill\n[ ] D - Execute as skills em sequência para diluir a saída','\n',char(10)),replace('**Explicação para um adulto tech lead:**\n\nA resposta correta é a alternativa **B**.\n\n- **Alternativa B (correta):** Ao adicionar `context: fork` no frontmatter da skill, você instrui o sistema a executar aquela skill em um subagente isolado. Isso significa que o contexto principal da conversa não é afetado pelas saídas intermediárias ou pelo processamento interno da skill. No entanto, a skill mantém toda a sua capacidade funcional — ela ainda pode acessar ferramentas, ler arquivos, executar comandos bash etc. — mas o "ruído" gerado por ela não retorna para o chat principal. É a abordagem ideal para skills que produzem muita saída (verbosas) mas cujo resultado final não precisa poluir o contexto da conversa.\n\n- **Alternativa A (incorreta):** O prefixo `!` de fato executa um comando bash, mas a saída do bash *retorna ao contexto da conversa*. Ou seja, se a skill for verbosa, toda essa verbosidade vai poluir o contexto principal. Além disso, o `!` não isola a skill em um subagente; ele apenas redireciona a execução para o shell.\n\n- **Alternativa C (incorreta):** O comando `/compact` comprime o histórico da conversa, mas isso é uma ação *post-hoc* (depois que o estrago já foi feito) e, mais importante, a compressão *perde capacidade* — informações podem ser perdidas ou simplificadas demais. O objetivo da pergunta é "preservar toda a capacidade", o que vai contra a ideia de compactar.\n\n- **Alternativa D (incorreta):** Executar skills em sequência apenas soma os tokens de todas elas no contexto. Isso não isola a verbosidade de nenhuma skill específica; pelo contrário, pode até piorar a poluição, pois o contexto acumula a saída de múltiplas skills.','\n',char(10)),replace('Imagine que você está desenhando em uma folha de papel, mas tem um amigo que gosta de rabiscar sem parar. Se ele rabiscar na sua folha, vai sujar seu desenho. \n\nA pergunta é: como deixar seu amigo rabiscar à vontade sem sujar a sua folha?\n\n- Se você usar o **!** (alternativa A), é como se o amigo rabiscasse bem na sua folha e você visse tudo.\n- Se você usar o **/compact** (alternativa C), é como se você amassasse a folha depois para tentar esconder os rabiscos, mas aí o desenho fica todo amassado e perde detalhes.\n- Se você colocar as skills em sequência (alternativa D), é como se vários amigos rabiscassem um após o outro — sua folha fica cada vez mais suja.\n\nA melhor ideia é a **alternativa B**: dar ao seu amigo uma folha separada (um "subagente") para ele rabiscar à vontade. Assim, sua folha principal continua limpa, e ele pode desenhar o quanto quiser sem atrapalhar você!','\n',char(10)));
INSERT INTO cards VALUES('admin','card_1783092988762_t1bvfsbbe',340,'How do you avoid example context (e.',replace('How do you avoid example context (e.\n\nHow do you avoid example context (e.g. example endpoints) being loaded when it is not needed?\n[Resposta correta: Uma skill invocada sob demanda carrega o material só quando chamada. CLAUDE.md carrega sempre; regra por caminho carrega para qualquer tarefa naquele diretório; @ no CLAUDE.md inclui em toda requisição.]\n\n[ ] A - Put it in the CLAUDE.md, which loads always\n[ ] B - Create a skill that references the material and is invoked on demand via slash command\n[ ] C - Create a path-based rule in .claude/rules/\n[ ] D - Reference it with @ in the CLAUDE.md','\n',char(10)),'B - Create a skill that references the material and is invoked on demand via slash command','["Domain_3::Claude_Code_Configuration_Workflows", "Domain_5::Context_Management_Reliability", "Scenario_2::Code_Generation_Claude_Code"]','New',0,2.5,0,1783092988762,1783727480948,1783203558653,replace('**Tradução para português do Brasil:**\n\nPergunta: Como evitar que o contexto de exemplo (ex.: endpoints de exemplo) seja carregado quando não for necessário?\n\nAlternativas:\n[ ] A - Colocar no CLAUDE.md, que carrega sempre\n[ ] B - Criar uma skill que referencie o material e seja invocada sob demanda via comando de barra\n[ ] C - Criar uma regra baseada em caminho em .claude/rules/\n[ ] D - Referenciar com @ no CLAUDE.md','\n',char(10)),replace('**Explicação didática para um adulto tech lead:**\n\nA pergunta aborda um problema comum de eficiência: como evitar que materiais de exemplo (como endpoints de API fictícios, payloads de amostra, etc.) sejam injetados no contexto do assistente (Claude) quando não são relevantes para a tarefa atual.\n\nA alternativa correta é a **B**. Skills são uma funcionalidade do Claude que permite agrupar instruções e referências que podem ser ativadas sob demanda por meio de um comando de barra (slash command), como `/skill-exemplos-api`. Isso significa que o material de exemplo só entra no contexto quando você explicitamente invoca a skill, evitando poluição desnecessária do contexto e desperdício de tokens.\n\nVamos analisar por que as outras alternativas estão erradas:\n\n**A - Colocar no CLAUDE.md, que carrega sempre:** O CLAUDE.md é um arquivo de configuração que é carregado em *todas* as conversas. Se você colocar exemplos volumosos lá, eles ocuparão tokens e espaço no contexto mesmo quando não forem necessários, exatamente o oposto do que se deseja.\n\n**C - Criar uma regra baseada em caminho em .claude/rules/:** Regras baseadas em caminho (path-based rules) são ativadas automaticamente quando você está trabalhando em um diretório específico. Se você criar uma regra para "qualquer tarefa naquele diretório", os exemplos serão carregados sempre que você estiver naquele diretório, mesmo que a tarefa atual não precise deles. Isso resolve parcialmente (apenas para aquele diretório), mas não é uma ativação verdadeiramente sob demanda.\n\n**D - Referenciar com @ no CLAUDE.md:** O uso de `@` no CLAUDE.md para incluir referências faz com que esse material seja carregado em *toda requisição*, já que o CLAUDE.md é processado globalmente. Novamente, isso vai contra o objetivo de carregar exemplos apenas quando necessário.\n\nPortanto, a skill sob demanda é a abordagem mais enxuta e eficiente para o cenário descrito.','\n',char(10)),replace('Imagine que você tem uma mochila para ir à escola. Se você colocar todos os seus brinquedos dentro da mochila todos os dias, ela ficará pesada e você vai se cansar à toa. O ideal é levar só o que você vai usar naquele dia.\n\nA pergunta é sobre como fazer o computador (o Claude) não carregar exemplos grandes o tempo todo, mas só quando a gente realmente precisa deles.\n\nA resposta certa é a **B**: criar uma "skill" (como se fosse um atalho mágico) que você só usa quando quer. Você digita um comando especial (como `/exemplos`) e só aí os exemplos aparecem. É como guardar os brinquedos num armário e pegá-los só na hora de brincar.\n\nAs outras opções são ruins porque:\n- **A** e **D**: colocam os exemplos num lugar que carrega SEMPRE, igual levar o brinquedo na mochila todos os dias mesmo sem usar.\n- **C**: carrega os exemplos sempre que você mexe em uma pasta específica, mesmo que não precise. É como levar o brinquedo pra escola toda vez que você vai à aula de matemática, mesmo que seja dia de só usar lápis e caderno.\n\nEntão, a melhor ideia é ter um "comando especial" que só traz os exemplos quando você pede. 😊','\n',char(10)));
INSERT INTO cards VALUES('admin','card_1783092988815_xfztmz8o3',341,'There are several integration options (webhooks, bot tokens, Apps) with different architectural implications.',replace('There are several integration options (webhooks, bot tokens, Apps) with different architectural implications.\n\nThere are several integration options (webhooks, bot tokens, Apps) with different architectural implications. What do you do?\n[Resposta correta: Plan Mode explora as opções e trade-offs (autenticação, erros, capacidades futuras) e recomenda antes de implementar. Assumir e começar scaffolding (A) ou implementar direto (C) ignora as decisões arquiteturais; criar skills (D) não decide a arquitetura.]\n\n[ ] A - Assume the most common option and start scaffolding\n[ ] B - Use Plan Mode to explore the options and trade-offs and recommend before implementing\n[ ] C - Increase the effort level and implement directly\n[ ] D - Create a skill for each option','\n',char(10)),'B - Use Plan Mode to explore the options and trade-offs and recommend before implementing','["Domain_3::Claude_Code_Configuration_Workflows", "Domain_1::Agentic_Architecture_Orchestration", "Scenario_2::Code_Generation_Claude_Code"]','New',0,2.5,0,1783092988815,1783727484321,1783203558653,replace('**Tradução para Português do Brasil:**\n\nExistem várias opções de integração (webhooks, tokens de bot, Apps) com diferentes implicações arquiteturais. O que você faz?\n\n[ ] A - Assume a opção mais comum e começa a fazer o scaffolding\n[ ] B - Usa o Plan Mode para explorar as opções e trade-offs (autenticação, erros, capacidades futuras) e recomendar antes de implementar\n[ ] C - Aumenta o nível de esforço e implementa diretamente\n[ ] D - Cria uma skill para cada opção','\n',char(10)),replace('**Explicação para um adulto tech lead:**\n\nA pergunta aborda um dilema comum em arquitetura de software: como lidar com múltiplas alternativas de integração que têm implicações arquiteturais distintas (autenticação, tratamento de erros, escalabilidade, capacidades futuras). A resposta correta é a **alternativa B**.\n\n**Por que B é a resposta correta:**\n- Seguir um fluxo de *deliberate design* ou *Plan Mode* (modo de planejamento) é a abordagem mais madura e profissional. Antes de escrever qualquer linha de código, devemos entender os trade-offs de cada opção: como cada uma lida com autenticação (OAuth vs. tokens estáticos vs. webhooks com segredos compartilhados), como cada uma lida com falhas (retry vs. idempotência vs. filas), e quais capacidades futuras (eventos assíncronos, Rate limiting, escopos de permissão) cada uma suporta.\n- Tomar essa decisão arquitetural com base em análise, e não em palpite, evita retrabalho, dívida técnica e retrabalho caro. É uma prática de *Architecture Decision Record (ADR)*.\n\n**Por que as demais alternativas estão erradas:**\n\n- **Alternativa A ("Assume a opção mais comum e começa o scaffolding"):** Erro de presunção. "Mais comum" não significa "mais adequada". O contexto do sistema (se é um SaaS multi-tenant, um sistema legado, uma plataforma serverless) pode tornar a opção mais comum uma péssima escolha. Começar scaffolding (estrutura inicial de código) sem uma decisão arquitetural informada amarra o projeto a uma direção que pode ser difícil de mudar depois.\n\n- **Alternativa C ("Aumenta o nível de esforço e implementa diretamente"):** Erro de atitude. "Aumentar o esforço" não resolve o problema de falta de clareza arquitetural. Implementar diretamente, sem análise, é o equivalente a "codificar primeiro, pensar depois". O resultado é quase sempre retrabalho, refatoração e desperdício de tempo e dinheiro.\n\n- **Alternativa D ("Cria uma skill para cada opção"):** Erro de abordagem. Criar skills (habilidades/implementações separadas) para cada opção é uma forma de evitar a decisão arquitetural, postergando o custo. Isso multiplica o esforço de desenvolvimento, manutenção e teste. Em vez de decidir, você mantém todas as opções vivas, o que aumenta a complexidade e o custo total de propriedade (TCO). Não é uma estratégia sustentável.\n\n**Conclusão técnica:** A abordagem correta é planejar, documentar as decisões (ADRs), explorar os trade-offs e só então implementar.','\n',char(10)),replace('**Explicação para uma criança de 10 anos:**\n\nImagine que você quer construir uma casa na árvore. Você tem várias ideias de como fazer: usar escada de corda, escada de madeira, ou um tobogã. Cada jeito tem coisas boas e ruins.\n\nA alternativa B é a certa porque, antes de começar a construir, você para e pensa: "Qual é o melhor jeito? Qual é mais seguro? Qual vai durar mais?" Depois que você pensar bem, você decide e constrói.\n\nAs outras alternativas são erradas porque:\n- A (começar a construir sem pensar direito) — você pode escolher a pior opção e ter que refazer tudo depois.\n- C (fazer tudo de uma vez, na pressa) — você pode fazer uma bagunça e ter que desmontar tudo.\n- D (fazer um pouco de cada jeito) — você gasta muito tempo e material, e no final não termina nada direito.\n\nA melhor ideia é parar, pensar, planejar e depois construir. Isso evita retrabalho e dor de cabeça!','\n',char(10)));
INSERT INTO cards VALUES('admin','card_1783092988836_gtxc06sdk',342,'A team guideline is not reaching all the developers.',replace('A team guideline is not reaching all the developers.\n\nA team guideline is not reaching all the developers. What is the likely cause and the fix?\n[Resposta correta: Arquivos de usuário (~/.claude/CLAUDE.md) só afetam aquele dev; mover para o nível de projeto faz a diretriz chegar a todos. Não há cache persistente (A e D erram isso), e não é preciso escalar para enterprise (C).]\n\n[ ] A - The CLAUDE.md persistent cache is out of date; clear the cache\n[ ] B - The guideline is in the ~/.claude/CLAUDE.md (user level) of whoever wrote it; move it to the project''s .claude/CLAUDE.md\n[ ] C - The guideline needs to become an enterprise skill\n[ ] D - The CLAUDE.md is only read on the first session; recreate the file','\n',char(10)),'B - The guideline is in the ~/.claude/CLAUDE.md (user level) of whoever wrote it; move it to the project''s .claude/CLAUDE.md','["Domain_3::Claude_Code_Configuration_Workflows", "Domain_5::Context_Management_Reliability", "Scenario_2::Code_Generation_Claude_Code"]','New',0,2.5,0,1783092988836,1783727487996,1783203558653,replace('**Tradução para português do Brasil:**\n\n**Pergunta:** Uma diretriz da equipe não está alcançando todos os desenvolvedores. Qual é a causa provável e a correção?\n\n[ ] A - O cache persistente do CLAUDE.md está desatualizado; limpe o cache\n[ ] B - A diretriz está no ~/.claude/CLAUDE.md (nível do usuário) de quem a escreveu; mova-a para o .claude/CLAUDE.md do projeto\n[ ] C - A diretriz precisa se tornar uma skill empresarial (enterprise)\n[ ] D - O CLAUDE.md é lido apenas na primeira sessão; recrie o arquivo','\n',char(10)),replace('**Explicação para um adulto tech lead:**\n\nO Claude Code suporta diferentes níveis de configuração via arquivos CLAUDE.md. Existem três níveis principais:\n\n1. **Nível de usuário** (`~/.claude/CLAUDE.md`): Afeta apenas o desenvolvedor que possui esse arquivo em seu diretório home. Cada desenvolvedor tem seu próprio ambiente e esse arquivo não é compartilhado.\n2. **Nível de projeto** (`.claude/CLAUDE.md` no diretório raiz do projeto): Esse arquivo fica versionado no repositório e é compartilhado por todos os desenvolvedores que clonam o projeto.\n3. **Nível global** (via `claude.json` ou enterprise): Pode ser usado para aplicar configurações em toda a organização.\n\nO cenário descrito é típico: um desenvolvedor criou uma diretriz da equipe em seu próprio arquivo de usuário (`~/.claude/CLAUDE.md`). Como cada desenvolvedor tem seu próprio diretório home, apenas a pessoa que escreveu a diretriz a vê aplicada. Os demais desenvolvedores não têm esse arquivo ou têm versões diferentes.\n\n**Por que a alternativa B é a correta:** Mover a diretriz do nível de usuário para o nível de projeto (`.claude/CLAUDE.md`) faz com que ela seja versionada no repositório e aplicada automaticamente a todos os desenvolvedores que trabalham naquele projeto.\n\n**Por que as demais estão erradas:**\n- **A**: Não existe "cache persistente" do CLAUDE.md que precise ser limpo. O arquivo é lido a cada interação relevante, não há um mecanismo de cache que cause o problema descrito.\n- **C**: Transformar em "enterprise skill" é um conceito diferente e desnecessário para esse problema. Skills são funcionalidades mais complexas (como ferramentas personalizadas ou integrações). O problema é simplesmente de escopo/localização do arquivo.\n- **D**: O CLAUDE.md não é lido apenas na primeira sessão. Ele é reavaliado conforme necessário. Recriar o arquivo não resolveria o problema de alcance para todos os desenvolvedores.','\n',char(10)),replace('**Explicação para uma criança de 10 anos:**\n\nImagine que sua professora pediu para todo mundo da turma seguir uma regra, como "entregar a lição até sexta-feira". Só que, em vez de escrever essa regra no quadro da sala para todo mundo ver, ela escreveu num bilhete e colocou dentro do armário dela. Quem veria esse bilhete? Só ela!\n\nÉ exatamente isso que acontece quando alguém coloca a diretriz no arquivo `~/.claude/CLAUDE.md`. O "~" significa a "pastinha pessoal" de cada desenvolvedor no computador. Então, se o João escreveu uma regra lá, só o João vê. A Maria, o Pedro e os outros não sabem dessa regra.\n\nA alternativa B diz: "Pare de guardar a regra na pastinha pessoal de uma pessoa. Coloque a regra na pastinha do projeto, que todo mundo que trabalha no projeto pode ver." É como pegar o bilhete do armário da professora e escrever a regra no quadro negro da sala de aula. Agora sim, todo mundo vê!\n\nAs outras alternativas estão erradas porque:\n- A e D falam de "cache" e "recriar o arquivo" — é como pensar que o problema é que o bilhete está desbotado e precisa ser reescrito. Não adianta, porque o bilhete ainda está no armário da professora!\n- C fala de "skill empresarial" — seria como montar um sistema de som super chique para anunciar a regra, quando na verdade é só colocar a regra no quadro mesmo. Muito complicado e desnecessário.','\n',char(10)));
INSERT INTO cards VALUES('admin','card_1783092988855_wad3dijnp',343,'How do you organize a large set of project instructions in a modular and maintainable way?',replace('How do you organize a large set of project instructions in a modular and maintainable way?\n\nHow do you organize a large set of project instructions in a modular and maintainable way?\n[Resposta correta: Arquivos por tópico em .claude/rules/ dão modularidade e manutenção. Um CLAUDE.md gigante não é modular; README é documentação humana, não instrução para o Claude; hooks são por evento, não organizam diretrizes.]\n\n[ ] A - Put everything in a single giant CLAUDE.md\n[ ] B - Create separate markdown files by topic in .claude/rules/ (e.g. testing.md, api-conventions.md)\n[ ] C - Distribute the instructions across several README.md files in the repo\n[ ] D - Create one hook per instruction topic','\n',char(10)),'B - Create separate markdown files by topic in .claude/rules/ (e.g. testing.md, api-conventions.md)','["Domain_3::Claude_Code_Configuration_Workflows", "Scenario_2::Code_Generation_Claude_Code"]','New',0,2.5,0,1783092988855,1783727491248,1783203558653,replace('**Tradução para português do Brasil:**\n\n**Pergunta:** Como organizar um grande conjunto de instruções de projeto de forma modular e sustentável?\n\n[ ] A - Colocar tudo em um único CLAUDE.md gigante\n[ ] B - Criar arquivos markdown separados por tópico em .claude/rules/ (ex: testing.md, api-conventions.md)\n[ ] C - Distribuir as instruções por vários arquivos README.md no repositório\n[ ] D - Criar um hook por tópico de instrução','\n',char(10)),replace('**Explicação para adulto (tech lead):**\n\nA alternativa **B** é a correta. A abordagem recomendada pelo ecossistema Claude (e por boas práticas de engenharia de software) é usar o diretório `.claude/rules/` para armazenar arquivos markdown organizados por tópico. Isso oferece:\n\n**Por que B está correta:**\n- **Modularidade:** Cada arquivo cobre um domínio específico (testes, convenções de API, estilo de código, etc.), facilitando a localização e edição de regras sem afetar outras áreas.\n- **Manutenção:** Permite adicionar, remover ou modificar instruções de forma isolada, sem risco de conflitos ou de "poluir" um arquivo monolítico.\n- **Descoberta:** O Claude automaticamente carrega e considera todos os arquivos dentro de `.claude/rules/`, aplicando as regras conforme o contexto da conversa.\n- **Versionamento:** Cada arquivo pode ser versionado independentemente, permitindo revisões e histórico granular.\n\n**Análise das alternativas incorretas:**\n\n- **A (um único CLAUDE.md gigante):** Viola o princípio da responsabilidade única. Um arquivo monolítico dificulta a localização de instruções específicas, aumenta o risco de conflitos de edição, e torna a manutenção um pesadelo à medida que o projeto cresce. Não há separação de concerns.\n\n- **C (vários README.md):** README.md é um padrão do GitHub para documentação voltada a seres humanos (desenvolvedores, usuários). Não é interpretado pelo Claude como instruções de projeto. Além disso, READMEs são tipicamente voltados para entendimento do repositório como um todo, não para regras de comportamento da IA.\n\n- **D (um hook por tópico):** Hooks (`claude.hooks.*`) são scripts executados em eventos específicos (pré-início, pós-resposta, etc.), e não um mecanismo para organizar diretrizes de projeto. Eles servem para automação de tarefas, não para definir regras de estilo ou convenções. Usar hooks para isso seria um desvio de finalidade e traria complexidade desnecessária.','\n',char(10)),replace('**Explicação para criança de 10 anos:**\n\nImagine que você tem uma mochila gigante para guardar todas as regras do seu projeto de ciências. Você pode:\n\n- **Opção A:** Jogar tudo amassado num único caderno. Quando precisar achar algo, vai ter que revirar tudo. Uma bagunça!\n- **Opção B (a certa!):** Usar várias pastinhas separadas: uma para "regras dos testes", outra para "regras do desenho", outra para "regras da programação". Assim, quando você precisar de uma regra, é só abrir a pastinha certa. Fica fácil de arrumar e de achar.\n- **Opção C:** Colocar as instruções nos rótulos da mochila. Só que os rótulos são para os seus colegas lerem, não para você seguir. Não funciona.\n- **Opção D:** Usar alarmes no celular para lembrar de cada regra. Mas alarme é para lembrar de horário, não para organizar regras. Fica confuso.\n\nA resposta **B** é a melhor porque separa as regras em arquivos diferentes por assunto, igual organizar seu material escolar em pastas coloridas: cada coisa no seu lugar!','\n',char(10)));
INSERT INTO cards VALUES('admin','card_1783092988876_pe1gf3tac',344,'How do you deterministically normalize tool results (including third-party ones) in the Agent SDK?',replace('How do you deterministically normalize tool results (including third-party ones) in the Agent SDK?\n\nHow do you deterministically normalize tool results (including third-party ones) in the Agent SDK?\n[Resposta correta: Um hook PostToolUse é ponto único, determinístico e uniforme para normalizar resultados. Depender do LLM é probabilístico (A); modificar cada ferramenta é inconsistente (C); uma ferramenta extra dobra chamadas e depende de comportamento não confiável (D).]\n\n[ ] A - Instruct the LLM to normalize each result in the prompt\n[ ] B - Use a PostToolUse hook to intercept and transform the results before the agent''s processing\n[ ] C - Modify the code of each tool individually\n[ ] D - Ask for an extra tool that does the normalization on each call','\n',char(10)),'[ ] B - Use a PostToolUse hook to intercept and transform the results before the agent''s processing','["Domain_2::Tool_Design_MCP_Integration", "Domain_5::Context_Management_Reliability", "Scenario_1::Customer_Support_Agent"]','New',0,2.5,0,1783092988876,1783727494810,1783203558653,replace('**Tradução para português do Brasil:**\n\n**Pergunta:** Como você normaliza deterministicamente os resultados das ferramentas (incluindo as de terceiros) no Agent SDK?\n\n**Alternativas:**\n[ ] A - Instruir o LLM a normalizar cada resultado no prompt\n[ ] B - Usar um hook PostToolUse para interceptar e transformar os resultados antes do processamento do agente\n[ ] C - Modificar o código de cada ferramenta individualmente\n[ ] D - Pedir uma ferramenta extra que faça a normalização em cada chamada','\n',char(10)),replace('**Explicação para adulto (tech lead):**\n\nA alternativa **B** é a correta porque oferece um ponto único e determinístico de interceptação e transformação de resultados de ferramentas. No Agent SDK, hooks como `PostToolUse` são mecanismos de middleware que permitem manipular a saída de qualquer ferramenta após sua execução, mas antes que o resultado seja entregue ao loop principal do agente. Isso garante que a normalização seja aplicada de forma consistente e previsível, independentemente de qual ferramenta foi chamada (seja ela própria ou de terceiros).\n\n**Por que as outras estão erradas:**\n\n- **A (Instruir o LLM no prompt):** É uma abordagem probabilística. O LLM pode ou não seguir a instrução corretamente, e seu comportamento não é determinístico. Além disso, você depende da capacidade de interpretação do modelo, o que introduz variabilidade e possíveis falhas.\n\n- **C (Modificar cada ferramenta individualmente):** Extremamente inconsistente e de difícil manutenção. Para ferramentas de terceiros, você pode nem ter acesso ao código-fonte. Mesmo que tivesse, modificar cada uma delas cria um pesadelo de manutenção e aumenta a superfície de bugs.\n\n- **D (Criar uma ferramenta extra):** Isso dobra o número de chamadas (uma para a ferramenta original e outra para a de normalização), aumenta latência e custo, e ainda depende de o LLM decidir chamar essa ferramenta extra corretamente — novamente, um comportamento não determinístico e não confiável.\n\nPortanto, a abordagem com `PostToolUse` é a mais elegante, determinística e escalável.','\n',char(10)),replace('**Explicação para criança de 10 anos:**\n\nImagine que você tem várias máquinas de brinquedo que produzem resultados diferentes. Algumas dão bolinhas azuis, outras dão bolinhas vermelhas, e algumas até dão quadrados! Você quer que todas elas deem só bolinhas verdes.\n\n- **Alternativa A:** Você pede para um robô esperto (o LLM) arrumar isso. Mas o robô às vezes esquece ou faz do jeito dele — não é garantido.\n- **Alternativa B (a certa):** Você coloca uma "caixinha mágica" na saída de cada máquina. Tudo que sai delas passa pela caixinha, que transforma em bolinha verde. Funciona sempre, do mesmo jeito.\n- **Alternativa C:** Você tenta abrir cada máquina e consertar por dentro. Mas algumas máquinas são de outros países e você não pode mexer!\n- **Alternativa D:** Você pede para uma máquina extra arrumar o resultado das outras. Mas aí você precisa ligar duas máquinas para cada brinquedo — demora mais e pode dar errado se a máquina extra não funcionar direito.\n\nA **caixinha mágica (PostToolUse)** é a melhor porque funciona sempre igual e você não precisa mexer em cada brinquedo separadamente.','\n',char(10)));
INSERT INTO cards VALUES('admin','card_1783092988898_48s46ozm7',345,'Which combination of frontmatter features handles missing arguments, context leakage and tool control?',replace('Which combination of frontmatter features handles missing arguments, context leakage and tool control?\n\nWhich combination of frontmatter features handles missing arguments, context leakage and tool control?\n[Resposta correta: argument-hint sugere parâmetros, context: fork isola a execução e allowed-tools controla ferramentas, tudo com enforcement determinístico. Instruções em prosa (C) são prompt sem enforcement; as demais opções listam campos que não resolvem esses três problemas.]\n\n[ ] A - name, description and paths\n[ ] B - argument-hint, context: fork and allowed-tools\n[ ] C - Prose instructions in the body of the SKILL.md asking for each behavior\n[ ] D - disable-model-invocation, model and user-invocable','\n',char(10)),'B - argument-hint, context: fork and allowed-tools','["Domain_3::Claude_Code_Configuration_Workflows", "Scenario_2::Code_Generation_Claude_Code"]','New',0,2.5,0,1783092988898,1783727497857,1783203558653,replace('**Tradução para português do Brasil:**\n\n**Pergunta:** Qual combinação de recursos de frontmatter lida com argumentos ausentes, vazamento de contexto e controle de ferramentas?\n\n**Alternativas:**\n[ ] A - name, description and paths\n[ ] B - argument-hint, context: fork and allowed-tools\n[ ] C - Instruções em prosa no corpo do SKILL.md pedindo cada comportamento\n[ ] D - disable-model-invocation, model and user-invocable','\n',char(10)),replace('**Explicação didática para um adulto tech lead:**\n\nA pergunta aborda três problemas críticos em sistemas de agentes/LLMs: (1) garantir que argumentos obrigatórios sejam fornecidos (missing arguments), (2) evitar que contexto de uma execução vaze para outra (context leakage) e (3) restringir quais ferramentas o modelo pode invocar (tool control).\n\nA alternativa **B** é a correta porque cada um dos três recursos de frontmatter ataca diretamente um desses problemas de forma determinística:\n\n- **argument-hint**: Sugere parâmetros ao modelo, reduzindo a chance de argumentos ausentes. É um mecanismo de "hint" (dica) que orienta o modelo a preencher corretamente os parâmetros necessários, funcionando como um lembrete estruturado no frontmatter.\n- **context: fork**: Isola a execução criando um fork de contexto, o que impede que informações de uma execução anterior vazem para a atual. Isso resolve o problema de context leakage ao garantir que cada execução comece com um contexto limpo e separado.\n- **allowed-tools**: Define explicitamente quais ferramentas o modelo pode utilizar, controlando o acesso a funcionalidades. Isso resolve o problema de tool control ao restringir o conjunto de ferramentas disponíveis.\n\nA questão menciona que tudo isso opera com "enforcement determinístico", ou seja, são mecanismos de frontmatter que garantem comportamento previsível e forçado, não dependendo de o modelo "seguir instruções".\n\n**Por que as demais alternativas estão incorretas:**\n\n- **A (name, description and paths)**: Esses campos são metadados básicos (nome, descrição e caminhos). Nenhum deles resolve missing arguments, context leakage ou tool control. Name e description são apenas informativos; paths define caminhos de arquivos, sem qualquer relação com os três problemas.\n- **C (Instruções em prosa no corpo do SKILL.md)**: Instruções em linguagem natural (prosa) dependem da capacidade do modelo de segui-las, o que não é determinístico. Modelos podem ignorar, interpretar mal ou esquecer instruções, especialmente em cenários complexos. Não há enforcement — é apenas um prompt, não um controle programático.\n- **D (disable-model-invocation, model and user-invocable)**: disable-model-invocation desativa a invocação pelo modelo, mas não resolve missing arguments ou context leakage. "model" e "user-invocable" são configurações de permissão de invocação, não tratam dos três problemas listados.','\n',char(10)),replace('**Explicação para uma criança de 10 anos:**\n\nImagine que você está montando um robô que segue suas instruções. Às vezes, o robô pode fazer três coisas erradas: (1) esquecer de pedir algo que você precisa dar pra ele (argumentos faltando), (2) misturar o que você pediu hoje com o que pediu ontem (vazamento de contexto), e (3) usar ferramentas que você não quer que ele use (controle de ferramentas).\n\nA resposta certa é a **B** porque cada item dessa opção resolve um desses problemas:\n\n- **argument-hint** é como um lembrete que você coloca no robô para ele não esquecer de pedir o que precisa.\n- **context: fork** é como dar uma folha de papel nova para o robô cada vez que você pede algo, assim ele não confunde com o que escreveu antes.\n- **allowed-tools** é como dizer pro robô: "você só pode usar esses brinquedos aqui, os outros estão proibidos".\n\nAs outras opções não funcionam porque:\n- **A**: Só dá nome e descreve o robô, não resolve nenhum problema.\n- **C**: Pedir educadamente no manual do robô não garante que ele vai obedecer — ele pode esquecer ou fazer do jeito dele.\n- **D**: Fala sobre quem pode ligar o robô, mas não resolve os três problemas.\n\nEntão a melhor escolha é a **B**, que tem uma ferramentinha pra cada problema!','\n',char(10)));
INSERT INTO cards VALUES('admin','card_1783092988920_r6hkd5iei',346,'When do you use CLAUDE.',replace('When do you use CLAUDE.\n\nWhen do you use CLAUDE.md versus Skills to organize instructions?\n[Resposta correta: CLAUDE.md cobre padrões universais (always-on) e Skills cobrem workflows específicos sob demanda. Mover tudo para Skills faz os padrões universais deixarem de ser aplicados (A); C inverte os papéis; regras por caminho são para convenções por tipo de arquivo, não por workflow (D).]\n\n[ ] A - Move everything to Skills, which are more flexible\n[ ] B - CLAUDE.md for universal standards (always loaded); Skills for specific workflows, loaded on demand\n[ ] C - CLAUDE.md for specific workflows; Skills for universal standards\n[ ] D - Use path-based rules for both cases','\n',char(10)),'B - CLAUDE.md for universal standards (always loaded); Skills for specific workflows, loaded on demand','["Domain_3::Claude_Code_Configuration_Workflows", "Scenario_2::Code_Generation_Claude_Code"]','New',0,2.5,0,1783092988920,1783727500803,1783203558653,replace('**Tradução:**\n\nQuando você usa CLAUDE.md versus Skills para organizar instruções?\n\n[ ] A - Mover tudo para Skills, que são mais flexíveis\n[ ] B - CLAUDE.md para padrões universais (sempre carregados); Skills para workflows específicos, carregados sob demanda\n[ ] C - CLAUDE.md para workflows específicos; Skills para padrões universais\n[ ] D - Usar regras baseadas em caminho para ambos os casos','\n',char(10)),replace('**Explicação para Tech Lead:**\n\nA alternativa correta é a **B**. Eis a análise detalhada:\n\n**Por que B está correta:** O CLAUDE.md é projetado para conter instruções e padrões que devem ser aplicados universalmente em todas as interações com o Claude — ele é "always-on", ou seja, carregado sempre que o contexto é iniciado. Já Skills são módulos de instruções que podem ser ativados sob demanda para workflows específicos, não sobrecarregando o contexto desnecessariamente. Essa separação de responsabilidades é o design pattern correto.\n\n**Por que as demais estão incorretas:**\n- **A** está errada porque mover tudo para Skills faz com que os padrões universais deixem de ser aplicados automaticamente. Skills só são carregadas quando explicitamente invocadas, então regras que deveriam valer para toda interação (como formatação de código, convenções de nomenclatura, etc.) seriam perdidas.\n- **C** inverte os papéis: CLAUDE.md não é para workflows específicos (para isso existem Skills), e Skills não são para padrões universais (isso é papel do CLAUDE.md).\n- **D** está errada porque regras por caminho (path-based rules) são utilizadas para definir convenções específicas por tipo de arquivo ou diretório (ex: "para arquivos .py, use snake_case"), não para organizar workflows.','\n',char(10)),replace('**Explicação para criança de 10 anos:**\n\nImagina que você tem um baú de brinquedos e uma mochila.\n\nO **CLAUDE.md** é como o **baú de brinquedos** — dentro dele você guarda os brinquedos que você usa **todo santo dia**, como seu carrinho favorito ou a bola. Eles estão sempre ali, prontos para brincar.\n\nJá os **Skills** são como a **mochila** que você prepara só quando vai a um lugar especial, como ir à casa do amigo para jogar videogame. Você coloca na mochila só o que precisa para aquela ocasião.\n\n**Alternativa certa (B):** CLAUDE.md guarda as regras que valem **sempre** (como "escove os dentes todo dia"), e Skills guardam as instruções para **tarefas específicas** (como "passo a passo para fazer um castelo de areia").\n\n**Por que as outras estão erradas:**\n- **A:** Colocar tudo na mochila (Skills) faria você esquecer as regras importantes do dia a dia.\n- **C:** Trocar as coisas de lugar — colocar regras do dia a dia na mochila e regras especiais no baú — não faz sentido.\n- **D:** Usar "regras por caminho" é como organizar brinquedos por cor, não serve para organizar workflows.','\n',char(10)));
INSERT INTO cards VALUES('admin','card_1783092988944_5ixvp8tvg',347,'A personal skill has the same name as a project skill.',replace('A personal skill has the same name as a project skill.\n\nA personal skill has the same name as a project skill. What happens?\n[Resposta correta: A skill de projeto tem precedência sobre a pessoal; renomear a sua (ex.: /my-commit) resolve. A A inverte a precedência; não existe lógica condicional por usuário (C) nem campo override (D) no frontmatter.]\n\n[ ] A - The personal one (~/.claude/skills/) always wins\n[ ] B - The project one (.claude/skills/) has precedence; to use yours, rename it (e.g. /my-commit)\n[ ] C - Both run together via per-user conditional logic in the frontmatter\n[ ] D - An override: true field is needed in the personal one''s frontmatter','\n',char(10)),'[ ] B - The project one (.claude/skills/) has precedence; to use yours, rename it (e.g. /my-commit)','["Domain_3::Claude_Code_Configuration_Workflows", "Scenario_2::Code_Generation_Claude_Code"]','New',0,2.5,0,1783092988944,1783727503850,1783203558653,replace('**Tradução para português do Brasil:**\n\nUma skill pessoal tem o mesmo nome que uma skill de projeto.\n\nUma skill pessoal tem o mesmo nome que uma skill de projeto. O que acontece?\n\n[ ] A - A pessoal (~/.claude/skills/) sempre vence\n[ ] B - A do projeto (.claude/skills/) tem precedência; para usar a sua, renomeie-a (ex.: /my-commit)\n[ ] C - Ambas executam juntas por meio de lógica condicional por usuário no frontmatter\n[ ] D - Um campo override: true é necessário no frontmatter da skill pessoal','\n',char(10)),replace('**Explicação para adulto tech lead:**\n\nO cenário descreve um conflito de nomenclatura entre uma skill definida globalmente (na pasta pessoal `~/.claude/skills/`) e uma skill definida no escopo do projeto (em `.claude/skills/`). O comportamento esperado — e documentado — é que a skill do projeto **tem precedência** sobre a skill pessoal de mesmo nome. Isso significa que, quando ambas existem com o mesmo identificador, o sistema utilizará a versão do projeto, ignorando a versão pessoal.\n\n**Por que B é a correta:**\n- A letra B descreve exatamente o comportamento: a skill do projeto prevalece, e a solução para usar a versão pessoal é renomeá-la (ex.: `/my-commit` em vez de `/commit`), evitando o conflito.\n\n**Por que as demais estão erradas:**\n- **A** está incorreta porque inverte a precedência: a skill pessoal não "sempre vence"; na verdade, a do projeto é quem tem prioridade.\n- **C** está incorreta porque não existe "lógica condicional por usuário" no frontmatter que faça ambas executarem juntas quando os nomes coincidem. O comportamento é de substituição (override), não de execução paralela.\n- **D** está incorreta porque não há um campo `override: true` no frontmatter da skill pessoal para forçar sua precedência. O mecanismo de resolução de conflitos é baseado em escopo (projeto > pessoal), não em flag explícita.','\n',char(10)),'Imagine que você tem duas pastas de figurinhas: uma sua, em casa, e outra na sala de aula, que a professora organizou. Se você colocar uma figurinha com o nome "cachorro" na sua pasta e a professora colocar uma figurinha com o mesmo nome "cachorro" na pasta da sala, quem manda é a figurinha da sala de aula. A da sala é mais importante porque é do projeto da turma. Se você quiser usar a sua figurinha, é só dar um nome diferente para ela, tipo "meu-cachorro". É exatamente isso que acontece com as skills do Claude: a do projeto ganha da sua pessoal, e para usar a sua, você precisa renomeá-la.');
INSERT INTO cards VALUES('admin','card_1783092988966_82ylbr3u6',348,'You need to integrate Claude with dozens of GitHub endpoints.',replace('You need to integrate Claude with dozens of GitHub endpoints.\n\nYou need to integrate Claude with dozens of GitHub endpoints. Why use an MCP server instead of defining each tool manually?\n[Resposta correta: O ganho é não precisar autorar e manter schema e função de cada capability. A inverte o papel do MCP. C inventa uma conversão de protocolo inexistente. D é falso, a autenticação continua necessária.]\n\n[ ] A - Because the MCP server runs Claude locally, dispensing with the API.\n[ ] B - Because the MCP server already ships the tools ready, avoiding writing and maintaining schema plus function for each capability.\n[ ] C - Because MCP automatically converts REST APIs into GraphQL.\n[ ] D - Because MCP eliminates the need for authentication on GitHub.','\n',char(10)),'B - Because the MCP server already ships the tools ready, avoiding writing and maintaining schema plus function for each capability.','["Domain_2::Tool_Design_MCP_Integration", "Scenario_4::Developer_Productivity"]','New',0,2.5,0,1783092988966,1783727507267,1783203558653,replace('**Tradução para português do Brasil:**\n\nVocê precisa integrar o Claude com dezenas de endpoints do GitHub.\n\nPor que usar um servidor MCP em vez de definir cada ferramenta manualmente?\n\n[ ] A - Porque o servidor MCP executa o Claude localmente, dispensando a API.\n[ ] B - Porque o servidor MCP já entrega as ferramentas prontas, evitando a necessidade de escrever e manter o schema e a função para cada capacidade.\n[ ] C - Porque o MCP converte automaticamente REST APIs em GraphQL.\n[ ] D - Porque o MCP elimina a necessidade de autenticação no GitHub.','\n',char(10)),replace('**Explicação para um adulto tech lead:**\n\nA pergunta aborda o valor prático do protocolo MCP (Model Context Protocol) em um cenário de integração com múltiplos endpoints do GitHub. O MCP é um padrão aberto que permite que modelos de linguagem (como o Claude) se conectem a ferramentas e fontes de dados externas de forma padronizada, sem exigir que cada integração seja codificada manualmente.\n\n**Alternativa correta: B**\n\nA alternativa B está correta porque captura exatamente a proposta central do MCP: em vez de o desenvolvedor precisar criar manualmente um schema (definição dos parâmetros, tipos, descrições) e uma função (implementação da lógica) para cada um dos dezenas de endpoints do GitHub, ele pode simplesmente usar um servidor MCP que já expõe essas ferramentas. O servidor MCP pré-configurado (como o `@modelcontextprotocol/server-github`) já contém as definições e implementações para operações comuns (criar issues, listar repositórios, fazer buscas, etc.). O ganho é produtividade e redução de erros, eliminando o trabalho repetitivo de "autoração" (criação manual) de schemas e funções para cada capability.\n\n**Análise das alternativas incorretas:**\n\n**A - Porque o servidor MCP executa o Claude localmente, dispensando a API.**\nIncorreto. O MCP não "executa o Claude localmente". O Claude continua sendo acessado via API (seja via Anthropic API ou execução local via Claude Desktop). O MCP é um protocolo de comunicação entre o modelo (onde quer que ele esteja rodando) e ferramentas externas. A alternativa inverte o papel do MCP: ele não substitui a API do Claude, mas sim padroniza a conexão com ferramentas.\n\n**C - Porque o MCP converte automaticamente REST APIs em GraphQL.**\nIncorreto. O MCP não faz conversão de protocolos. Ele é um protocolo próprio (baseado em JSON-RPC) para expor ferramentas a modelos de linguagem. Não há nenhuma conversão automática de REST para GraphQL envolvida. Essa alternativa inventa uma funcionalidade inexistente.\n\n**D - Porque o MCP elimina a necessidade de autenticação no GitHub.**\nIncorreto. O MCP não elimina requisitos de autenticação. O servidor MCP para GitHub ainda precisa de um token de acesso (GitHub Personal Access Token) configurado pelo usuário para fazer chamadas autenticadas à API do GitHub. O MCP padroniza como as ferramentas são expostas, mas não ignora a segurança ou autenticação dos serviços subjacentes.','\n',char(10)),replace('Imagine que você quer ensinar um robô (o Claude) a fazer várias coisas no GitHub, como criar issues, ver repositórios, buscar código, etc. São dezenas de tarefas diferentes!\n\nSe você fosse fazer isso manualmente, teria que escrever uma "receita" (schema) e uma "função" para cada tarefa — seria um trabalho enorme e chato, igual ter que explicar passo a passo como fazer cada coisinha.\n\nAgora, o MCP é como uma caixa de ferramentas já pronta. Alguém já colocou lá dentro todas as ferramentas necessárias para mexer no GitHub. Você só precisa pegar a ferramenta certa e usar. Não precisa fabricar cada ferramenta do zero!\n\nÉ por isso que a resposta certa é a B: o servidor MCP já entrega as ferramentas prontas, então você não precisa escrever e manter o schema e a função de cada capacidade.\n\nAs outras opções estão erradas porque:\n- A diz que o MCP faz o Claude rodar localmente sem API — isso não é verdade, o Claude ainda precisa da API.\n- C diz que o MCP transforma REST em GraphQL — isso não existe, o MCP não faz essa conversão.\n- D diz que o MCP acaba com a autenticação do GitHub — mentira, você ainda precisa de senha/token para acessar o GitHub.','\n',char(10)));
INSERT INTO cards VALUES('admin','card_1783092988986_m2pifqwsi',349,'A cloud company wants to make it easy for agents to use its APIs.',replace('A cloud company wants to make it easy for agents to use its APIs.\n\nA cloud company wants to make it easy for agents to use its APIs. Who can author the corresponding MCP server?\n[Resposta correta: Qualquer pessoa pode autorar um MCP server, e é comum o provedor do serviço publicar o oficial. A centraliza indevidamente na Anthropic. B restringe demais. D inventa uma exigência de certificação.]\n\n[ ] A - Only Anthropic, which controls all MCP servers.\n[ ] B - Only the end customer who consumes the service.\n[ ] C - Anyone; often the provider itself publishes an official implementation.\n[ ] D - Only someone who holds an official MCP certification.','\n',char(10)),'[ ] C - Anyone; often the provider itself publishes an official implementation.','["Domain_2::Tool_Design_MCP_Integration", "Scenario_1::Customer_Support_Agent"]','New',0,2.5,0,1783092988986,1783727512369,1783203558653,replace('**Tradução para português do Brasil:**\n\nUma empresa de cloud quer facilitar o uso de suas APIs por agentes. Quem pode criar o servidor MCP correspondente?\n\n[ ] A - Apenas a Anthropic, que controla todos os servidores MCP.\n[ ] B - Apenas o cliente final que consome o serviço.\n[ ] C - Qualquer pessoa; frequentemente o próprio provedor publica uma implementação oficial.\n[ ] D - Apenas alguém que possua uma certificação oficial MCP.','\n',char(10)),replace('**Explicação para um adulto tech lead:**\n\nO MCP (Model Context Protocol) é um protocolo aberto, especificado pela Anthropic, mas que qualquer pessoa ou organização pode implementar. Não há controle centralizado, nem exigência de certificação. A resposta correta é a C.\n\n- **Alternativa A (incorreta):** A Anthropic é a criadora do protocolo, mas não controla nem restringe quem pode criar servidores MCP. O protocolo é aberto.\n- **Alternativa B (incorreta):** Restringe desnecessariamente a autoria ao cliente final. Qualquer pessoa, incluindo terceiros ou o próprio provedor da API, pode criar um servidor MCP.\n- **Alternativa C (correta):** Reflete com precisão a natureza aberta do MCP. É comum que o próprio provedor do serviço publique uma implementação oficial, mas nada impede que terceiros (inclusive a comunidade) criem suas próprias implementações.\n- **Alternativa D (incorreta):** Não existe uma certificação oficial MCP. O protocolo é aberto e não exige certificação para implementação.','\n',char(10)),replace('Imagine que você tem um brinquedo muito legal e quer ensinar seus amigos a brincar com ele. O MCP é como um manual de instruções que qualquer pessoa pode usar para ensinar programas de computador (agentes) a usar as ferramentas de uma empresa.\n\nA pergunta é: quem pode escrever esse manual de instruções?\n\n- **Alternativa A** diz que só a empresa que inventou o manual (Anthropic) pode escrever. Mas não é verdade! O manual é aberto, qualquer um pode criar o seu.\n- **Alternativa B** diz que só quem compra o brinquedo pode escrever o manual. Também não! Qualquer pessoa interessada pode fazer.\n- **Alternativa C** (a correta) diz que qualquer um pode escrever o manual, mas geralmente quem faz o brinquedo (o provedor do serviço) escreve o manual oficial. É como se a fábrica do brinquedo fizesse um manual, mas seus amigos também poderiam criar o deles.\n- **Alternativa D** diz que você precisa de um diploma especial para escrever o manual. Isso não existe! Qualquer um pode tentar criar um.\n\nEntão a resposta certa é a **C**: qualquer pessoa pode criar um servidor MCP, assim como qualquer um pode escrever um manual de instruções para um brinquedo.','\n',char(10)));
INSERT INTO cards VALUES('admin','card_1783092989007_bobl09phy',350,'An architect describes MCP to the team.',replace('An architect describes MCP to the team.\n\nAn architect describes MCP to the team. Which definition is correct at the architecture level?\n[Resposta correta: O MCP é uma camada de comunicação que desloca a carga de definição e execução para servidores especializados. B confunde MCP com tool use (são complementares). C reduz o MCP a armazenamento de prompts. D descreve exatamente o trabalho manual que o MCP evita.]\n\n[ ] A - A communication layer that provides context and tools to Claude, shifting the definition and execution of tools from your server to specialized MCP servers.\n[ ] B - A framework that replaces tool use, making Claude call APIs without needing tools.\n[ ] C - A file format for storing prompts locally on the developer''s machine.\n[ ] D - A library that forces you to write schema and function for each capability manually.','\n',char(10)),'A - A communication layer that provides context and tools to Claude, shifting the definition and execution of tools from your server to specialized MCP servers.','["Domain_2::Tool_Design_MCP_Integration", "Domain_1::Agentic_Architecture_Orchestration", "Scenario_4::Developer_Productivity"]','New',0,2.5,0,1783092989007,1783727516330,1783203558653,replace('**Tradução para português do Brasil:**\n\nUm arquiteto descreve o MCP para a equipe. Qual definição está correta no nível de arquitetura?\n\n[ ] A - Uma camada de comunicação que fornece contexto e ferramentas para o Claude, deslocando a definição e execução de ferramentas do seu servidor para servidores MCP especializados.\n[ ] B - Um framework que substitui o uso de ferramentas (tool use), fazendo o Claude chamar APIs sem precisar de ferramentas.\n[ ] C - Um formato de arquivo para armazenar prompts localmente na máquina do desenvolvedor.\n[ ] D - Uma biblioteca que força você a escrever schema e função para cada capacidade manualmente.','\n',char(10)),replace('**Explicação didática para adulto tech lead:**\n\nA alternativa A está correta porque descreve precisamente o papel arquitetural do Model Context Protocol (MCP). O MCP é um protocolo aberto que atua como uma camada de comunicação padronizada entre modelos de linguagem (como Claude) e fontes externas de contexto e ferramentas. No nível de arquitetura, ele funciona como um middleware que desacopla o modelo dos servidores que fornecem capacidades especializadas. Em vez de cada desenvolvedor implementar manualmente a lógica de integração entre o LLM e ferramentas externas, o MCP estabelece um padrão onde servidores MCP especializados são responsáveis por expor recursos (contexto) e ferramentas, e o cliente MCP (dentro do aplicativo host, como o Claude Desktop) gerencia a comunicação. Isso desloca a carga de definição e execução para esses servidores, promovendo modularidade, reuso e interoperabilidade.\n\n**Análise das alternativas incorretas:**\n\n- **Alternativa B**: Confunde MCP com tool use. MCP e tool use são complementares, não substitutos. Tool use (function calling) é uma capacidade do modelo de invocar funções; MCP é o protocolo que orquestra como essas ferramentas são descobertas, acessadas e executadas por servidores externos. Um não substitui o outro — o MCP é a infraestrutura que padroniza o tool use.\n\n- **Alternativa C**: Reduz o MCP a um mero formato de arquivo para armazenamento de prompts, o que é uma visão extremamente limitada e incorreta. MCP é um protocolo de comunicação completo que gerencia descoberta de recursos, execução de ferramentas e fornecimento de contexto, não apenas persistência local de prompts.\n\n- **Alternativa D**: Descreve exatamente o trabalho manual que o MCP foi projetado para evitar. Sem o MCP, o desenvolvedor precisaria escrever schemas e funções manualmente para cada capacidade. O MCP automatiza esse processo, padronizando a interface e eliminando a necessidade de implementação manual repetitiva.','\n',char(10)),replace('**Explicação para criança de 10 anos:**\n\nImagine que você tem um robô assistente (o Claude) e vários amigos especialistas em diferentes assuntos. Um amigo sabe desenhar, outro sabe calcular contas difíceis, outro sabe tocar música.\n\nO MCP é como um sistema de walkie-talkies que conecta o robô a esses amigos. Quando o robô precisa de um desenho, ele não precisa saber desenhar — ele simplesmente usa o walkie-talkie para chamar o amigo especialista em desenho, que faz o trabalho e manda o resultado de volta.\n\nA alternativa A está certa porque descreve exatamente isso: o MCP é uma "camada de comunicação" (o walkie-talkie) que passa o trabalho de fazer as coisas (definir e executar ferramentas) para "servidores especializados" (os amigos especialistas).\n\nAs outras opções estão erradas porque:\n- A B diz que o MCP substitui as ferramentas, mas não é verdade — ele organiza como as ferramentas são usadas, não as substitui.\n- A C diz que o MCP é só um arquivo para guardar instruções, mas ele é muito mais que isso.\n- A D diz que o MCP te obriga a escrever tudo manualmente, mas na verdade ele faz o contrário: ele evita que você tenha que escrever tudo na mão!','\n',char(10)));
INSERT INTO cards VALUES('admin','card_1783092989059_hugz683w8',351,'What is the role of the MCP client in the architecture?',replace('What is the role of the MCP client in the architecture?\n\nWhat is the role of the MCP client in the architecture?\n[Resposta correta: O client é a ponte que abstrai protocolo e mensagens. A é papel do MCP server, que faz a chamada externa. C é responsabilidade do server ao expor tools. D não descreve o client.]\n\n[ ] A - Directly execute the external API and return the result to the user.\n[ ] B - Be the communication bridge between your server and the MCP servers, handling message exchange and the protocol.\n[ ] C - Define the schemas of the tools that will be exposed to Claude.\n[ ] D - Store the resources on disk for offline access.','\n',char(10)),'[ ] B - Be the communication bridge between your server and the MCP servers, handling message exchange and the protocol.','["Domain_2::Tool_Design_MCP_Integration", "Domain_1::Agentic_Architecture_Orchestration", "Scenario_1::Customer_Support_Agent"]','New',0,2.5,0,1783092989059,1783727520594,1783203558653,replace('**Tradução para português do Brasil:**\n\nPergunta: Qual é o papel do cliente MCP na arquitetura?\n\n[ ] A - Executar diretamente a API externa e retornar o resultado para o usuário.\n[ ] B - Ser a ponte de comunicação entre o seu servidor e os servidores MCP, lidando com a troca de mensagens e o protocolo.\n[ ] C - Definir os esquemas das ferramentas (tools) que serão expostas ao Claude.\n[ ] D - Armazenar os recursos em disco para acesso offline.','\n',char(10)),replace('**Explicação para um adulto tech lead:**\n\nNa arquitetura MCP (Model Context Protocol), o cliente MCP atua como um intermediário que abstrai os detalhes de transporte e protocolo entre o servidor da aplicação (seu servidor) e os servidores MCP que fornecem ferramentas, recursos e prompts. Ele gerencia a conexão (por stdio ou SSE), serializa/deserializa mensagens no formato JSON-RPC e garante que as requisições e respostas fluam corretamente entre as partes.\n\n**Por que B é a correta?** A alternativa B descreve exatamente essa função: o cliente MCP é a ponte que cuida da troca de mensagens e da implementação do protocolo, permitindo que o servidor da aplicação não precise lidar diretamente com esses detalhes de baixo nível.\n\n**Por que as demais estão erradas:**\n\n- **A** está incorreta porque executar diretamente chamadas a APIs externas é responsabilidade do **MCP server** (ou, mais especificamente, dos handlers de tools implementados no server), não do cliente. O cliente apenas envia a solicitação e recebe o resultado.\n\n- **C** está incorreta porque a definição dos schemas das tools (como parâmetros de entrada) é responsabilidade do **MCP server**, que declara as tools que expõe. O cliente consome esses schemas para saber como invocar as tools, mas não os define.\n\n- **D** está incorreta porque o armazenamento de recursos em disco para acesso offline não é uma função intrínseca do cliente MCP. Recursos (resources) são expostos pelo MCP server, e o cliente pode acessá-los, mas a persistência em disco depende de implementação específica da aplicação, não sendo um papel definido do cliente na arquitetura.','\n',char(10)),replace('Imagine que você tem dois amigos que falam línguas diferentes: um fala português e o outro fala inglês. Você precisa ser o "tradutor" entre eles, explicando o que cada um disse de um jeito que o outro entenda. O cliente MCP é exatamente esse tradutor — ele fica no meio, recebe as mensagens de um lado, traduz para o formato certo e entrega para o outro lado. Assim, seu servidor (que é tipo você) não precisa se preocupar em aprender a língua de cada servidor MCP que ele quiser conversar; o cliente faz esse trabalho chato de tradução e troca de mensagens para você.\n\nAs outras opções estão erradas:\n- **A** - Quem chama APIs externas é o servidor MCP, não o cliente. O cliente só pede e recebe.\n- **C** - Quem define "o quê" as ferramentas fazem e "como" usá-las é o servidor MCP. O cliente aprende essas regras, mas não as cria.\n- **D** - Guardar coisas no disco para usar sem internet não é trabalho do cliente. Essa função depende de como a aplicação foi feita, não faz parte do papel principal dele.','\n',char(10)));
INSERT INTO cards VALUES('admin','card_1783092989079_kkplmxbbq',352,'Saying that MCP is "transport agnostic" means that:',replace('Saying that MCP is "transport agnostic" means that:\n\nSaying that MCP is "transport agnostic" means that:\n[Resposta correta: Transport agnostic quer dizer flexibilidade de transporte, com stdio local sendo o caso comum. A assume HTTP como único. B ignora o cenário local via stdio. D descreve uma automação que não existe.]\n\n[ ] A - Communication only works via HTTP between different machines.\n[ ] B - Client and server always run on separate remote servers.\n[ ] C - Client and server can communicate through different methods (stdio, HTTP, WebSockets), with stdin/stdout on the same machine being the most common.\n[ ] D - The protocol chooses the transport on its own without the developer being able to configure it.','\n',char(10)),'C - Client and server can communicate through different methods (stdio, HTTP, WebSockets), with stdin/stdout on the same machine being the most common.','["Domain_2::Tool_Design_MCP_Integration", "Scenario_4::Developer_Productivity"]','New',0,2.5,0,1783092989079,1783727524246,1783203558653,replace('**Tradução para português do Brasil:**\n\nDizer que o MCP é "transport agnostic" significa que:\n\n[ ] A - A comunicação só funciona via HTTP entre máquinas diferentes.\n[ ] B - O cliente e o servidor sempre rodam em servidores remotos separados.\n[ ] C - O cliente e o servidor podem se comunicar através de diferentes métodos (stdio, HTTP, WebSockets), sendo o stdin/stdout na mesma máquina o mais comum.\n[ ] D - O protocolo escolhe o transporte por conta própria, sem que o desenvolvedor consiga configurá-lo.','\n',char(10)),replace('**Explicação didática para um adulto tech lead:**\n\nO termo "transport agnostic" significa que o MCP (Model Context Protocol) não depende de um único mecanismo de transporte para que cliente e servidor troquem mensagens. Em vez disso, ele abstrai a camada de transporte, permitindo que diferentes implementações sejam usadas conforme o cenário.\n\nA alternativa **C** está correta porque descreve exatamente isso: o MCP suporta múltiplos transportes (stdio, HTTP, WebSockets) e aponta corretamente que o caso mais comum e padrão é a comunicação via stdin/stdout entre processos rodando na mesma máquina — ideal para integração local com agentes, ferramentas de linha de comando e IDEs.\n\n**Análise das alternativas incorretas:**\n\n- **A** está errada porque afirma que a comunicação funciona *apenas* via HTTP entre máquinas diferentes. Isso contradiz o princípio de "transport agnostic", que por definição não restringe o transporte a HTTP, e ignora o cenário local via stdio.\n\n- **B** está errada porque diz que cliente e servidor *sempre* rodam em servidores remotos separados. Na prática, o caso mais comum (stdio) é justamente o oposto: ambos rodam na mesma máquina. Transport agnostic inclui tanto ambientes locais quanto remotos.\n\n- **D** está errada porque descreve uma automação que não existe. O MCP não escolhe o transporte automaticamente; o desenvolvedor é quem configura qual transporte será utilizado. "Agnostic" significa que o protocolo *suporta* múltiplos transportes, não que ele os *decida* sozinho.','\n',char(10)),replace('Imagine que você tem dois amigos que precisam conversar. Um está no mesmo quarto que você e o outro está em outra cidade.\n\n"Transport agnostic" é como dizer que vocês podem usar qualquer jeito de conversar: falar pessoalmente (stdio), ligar pelo telefone (HTTP) ou fazer uma videochamada (WebSockets). O importante é que a conversa acontece, não importa o método.\n\nA alternativa **C** está certa porque diz isso: o cliente e o servidor podem conversar de vários jeitos diferentes, mas o jeito mais comum é os dois estarem no mesmo computador, conversando pela "portinha" padrão do terminal (stdin/stdout).\n\nAs outras opções estão erradas porque:\n- A) Diz que só dá pra conversar por telefone (HTTP), mas não é verdade — dá pra conversar pessoalmente também.\n- B) Diz que os dois amigos estão sempre em lugares diferentes, mas eles podem estar no mesmo lugar.\n- D) Diz que o próprio sistema escolhe o jeito de conversar sem você poder mudar, mas na verdade você é quem escolhe o método.','\n',char(10)));
INSERT INTO cards VALUES('admin','card_1783092989100_tu9pqcp8a',353,'Which message pairs cover tool discovery and execution in MCP?',replace('Which message pairs cover tool discovery and execution in MCP?\n\nWhich message pairs cover tool discovery and execution in MCP?\n[Resposta correta: ListTools descobre e CallTool executa. B inverte os papéis dos dois pares. C mistura mensagem de resource com tool. D inventa nomes que não existem no protocolo.]\n\n[ ] A - ListToolsRequest/ListToolsResult to discover and CallToolRequest/CallToolResult to execute.\n[ ] B - CallToolRequest/CallToolResult to discover and ListToolsRequest/ListToolsResult to execute.\n[ ] C - ReadResourceRequest to discover and CallToolRequest to execute.\n[ ] D - GetToolsRequest to discover and RunToolRequest to execute.','\n',char(10)),'A - ListToolsRequest/ListToolsResult to discover and CallToolRequest/CallToolResult to execute.','["Domain_2::Tool_Design_MCP_Integration", "Domain_4::Prompt_Engineering_Structured_Output", "Scenario_4::Developer_Productivity"]','New',0,2.5,0,1783092989100,1783727528086,1783203558653,replace('**Tradução para Português do Brasil:**\n\nQual par de mensagens cobre a descoberta e execução de ferramentas no MCP?\n\n[ ] A - ListToolsRequest/ListToolsResult para descobrir e CallToolRequest/CallToolResult para executar.\n[ ] B - CallToolRequest/CallToolResult para descobrir e ListToolsRequest/ListToolsResult para executar.\n[ ] C - ReadResourceRequest para descobrir e CallToolRequest para executar.\n[ ] D - GetToolsRequest para descobrir e RunToolRequest para executar.','\n',char(10)),replace('**Explicação para adulto (Tech Lead):**\n\nO Model Context Protocol (MCP) define mensagens específicas para cada operação. O padrão de design segue o modelo "Request/Result" (ou Request/Response) típico de protocolos como JSON-RPC.\n\n**Resposta correta: A**\n\n- **ListToolsRequest / ListToolsResult**: Este é o par de mensagens responsável pela **descoberta** de ferramentas. Ao enviar um `ListToolsRequest`, o servidor responde com um `ListToolsResult` contendo a lista de ferramentas disponíveis, seus nomes, descrições e schemas de parâmetros.\n- **CallToolRequest / CallToolResult**: Este é o par de mensagens responsável pela **execução** de uma ferramenta específica. Ao enviar um `CallToolRequest` com o nome da ferramenta e seus argumentos, o servidor processa a chamada e retorna um `CallToolResult` com o resultado da execução.\n\n**Análise das alternativas incorretas:**\n\n- **B**: Inverte os papéis. `CallToolRequest/CallToolResult` é para executar, não para descobrir. `ListToolsRequest/ListToolsResult` é para descobrir, não para executar.\n- **C**: Mistura conceitos. `ReadResourceRequest` é um par de mensagens utilizado para **recursos** (resources) no MCP, não para ferramentas. Ferramentas (tools) e recursos (resources) são conceitos distintos no protocolo.\n- **D**: Inventa nomes que não existem no protocolo MCP. Não há mensagens chamadas `GetToolsRequest` ou `RunToolRequest` na especificação oficial do MCP. Os nomes corretos são `ListToolsRequest` e `CallToolRequest`.','\n',char(10)),replace('**Explicação para criança de 10 anos:**\n\nImagine que você está em uma loja de brinquedos com um robô ajudante.\n\n- **Descobrir ferramentas** é como pedir para o robô te mostrar uma lista de todos os brinquedos que ele tem guardados. No MCP, isso é feito com **ListToolsRequest/ListToolsResult**.\n- **Executar a ferramenta** é como você pedir para o robô pegar um brinquedo específico e brincar com ele. No MCP, isso é feito com **CallToolRequest/CallToolResult**.\n\nA letra **A** é a certa porque ela usa os nomes certos para cada tarefa: um para descobrir (ListTools) e outro para executar (CallTool).\n\nAs outras opções estão erradas porque:\n- **B**: Troca as funções — pede para o robô brincar com o brinquedo antes de saber quais brinquedos existem!\n- **C**: Mistura coisas diferentes — pede algo que não é um brinquedo (recurso) para descobrir ferramentas.\n- **D**: Usa nomes inventados que não existem no manual do robô.','\n',char(10)));
INSERT INTO cards VALUES('admin','card_1783092989120_v9h67h4kg',354,'In the flow for "What repositories do I have?',replace('In the flow for "What repositories do I have?\n\nIn the flow for "What repositories do I have?", at what moment is GitHub actually called?\n[Resposta correta: A chamada externa ocorre no CallToolRequest, quando o server aciona o GitHub. A confunde descoberta com execução. B trata tool_use como se já trouxesse dados. D nega a chamada externa.]\n\n[ ] A - At the ListToolsRequest, before Claude sees the question.\n[ ] B - When Claude responds with tool_use, which already contains the GitHub response.\n[ ] C - After the CallToolRequest, when the MCP server executes the tool and calls GitHub, returning CallToolResult.\n[ ] D - Only in the final response, formulated by Claude without an external call.','\n',char(10)),'C - After the CallToolRequest, when the MCP server executes the tool and calls GitHub, returning CallToolResult.','["Domain_2::Tool_Design_MCP_Integration", "Domain_5::Context_Management_Reliability", "Scenario_4::Developer_Productivity"]','New',0,2.5,0,1783092989120,1783727531804,1783203558653,replace('## Tradução para português\n\nNo fluxo de "Quais repositórios eu tenho?", em que momento o GitHub é realmente chamado?\n\n[ ] A - No ListToolsRequest, antes de Claude ver a pergunta.\n[ ] B - Quando Claude responde com tool_use, que já contém a resposta do GitHub.\n[ ] C - Após o CallToolRequest, quando o servidor MCP executa a ferramenta e chama o GitHub, retornando CallToolResult.\n[ ] D - Apenas na resposta final, formulada por Claude sem uma chamada externa.','\n',char(10)),replace('## Explicação para um adulto (tech lead)\n\nVamos analisar o fluxo MCP (Model Context Protocol) para uma requisição que envolve ferramentas externas:\n\n1. **ListToolsRequest** (A - incorreta): É o momento de **descoberta**. O cliente pergunta ao servidor MCP "quais ferramentas você disponibiliza?". O servidor responde com a lista de ferramentas disponíveis (ex: `get_repositories`, `create_issue`, etc.). Neste ponto, **nenhuma chamada ao GitHub é feita**, apenas se informa que existe uma ferramenta que pode consultar repositórios. Claude sequer viu a pergunta do usuário ainda.\n\n2. **Claude decide usar a ferramenta** → resposta com `tool_use` (B - incorreta): Claude analisa a pergunta do usuário, identifica que precisa da ferramenta `get_repositories` e gera uma resposta contendo um bloco `tool_use` com os parâmetros necessários. Este `tool_use` **não contém a resposta do GitHub** — ele contém apenas a **intenção** de chamar a ferramenta, como se fosse um "rascunho" da chamada. É um equívoco achar que os dados já estão aqui.\n\n3. **CallToolRequest** → execução → **CallToolResult** (C - correta): O cliente MCP (ex: Claude Desktop) recebe o `tool_use` e envia um `CallToolRequest` para o servidor MCP. É o servidor quem **realmente executa a chamada ao GitHub**, faz a requisição HTTP GET para a API do GitHub, obtém a lista de repositórios, e empacota tudo em um `CallToolResult` que é devolvido ao cliente. **Este é o único momento em que o GitHub é efetivamente contactado.**\n\n4. **Resposta final** (D - incorreta): Claude recebe o `CallToolResult`, interpreta os dados e formula a resposta final em linguagem natural. Mas os dados vieram de uma chamada externa real; negar que a chamada ocorreu é factualmente errado.\n\n**Resumo técnico**: O fluxo é `ListTools (descoberta) → tool_use (intenção) → CallTool (execução real) → CallToolResult (dados) → resposta final (formatação)`. A chamada externa ao GitHub acontece exclusivamente na etapa 3.','\n',char(10)),replace('## Explicação para uma criança de 10 anos\n\nImagina que você tem um assistente mágico (Claude) e um ajudante (o servidor MCP) que pode buscar informações na internet.\n\n**O que acontece em cada etapa?**\n\nA - **"Que ferramentas você tem?"** - O assistente pergunta ao ajudante quais ferramentas ele possui. O ajudante responde: "Eu tenho uma ferramenta que consulta o GitHub". O GitHub **ainda não foi chamado**. É como olhar a caixa de ferramentas antes de usar qualquer uma.\n\nB - **"Preciso dessa ferramenta aqui"** - O assistente decide que vai usar a ferramenta de consulta ao GitHub. Ele escreve num papel: "Usar ferramenta: get_repositories". Esse papel **não tem a resposta ainda**, é só um lembrete do que precisa ser feito. É como dizer "vou ligar para o Pedro" - você ainda não ligou, só disse que vai ligar.\n\nC - **"Hora de chamar o GitHub!"** - O ajudante pega o papel, faz a ligação para o GitHub de verdade, pergunta "quais repositórios existem?", recebe a resposta e entrega para o assistente. ✅ **É AQUI que o GitHub é chamado de verdade!**\n\nD - **"Montando a resposta bonita"** - O assistente pega os dados que o ajudante trouxe e escreve uma resposta legal para você. Mas se o ajudante não tivesse chamado o GitHub, não teria dados nenhuns!\n\n**Resumindo**: É igual a encomendar uma pizza. Você primeiro vê o cardápio (ListTools), depois decide pedir (tool_use), aí a pizzaria realmente faz a pizza (CallToolRequest → GitHub), e finalmente você recebe e come a pizza (resposta final). O GitHub é chamado na hora de fazer a pizza, não antes!','\n',char(10)));
INSERT INTO cards VALUES('admin','card_1783092989142_sdscxc80v',355,'You want to expose a capability that only reads data, with no side effect.',replace('You want to expose a capability that only reads data, with no side effect.\n\nYou want to expose a capability that only reads data, with no side effect. What should you use?\n[Resposta correta: Resource é para buscar dados sem efeito colateral, como um GET. A ignora a distinção tool versus resource. C confunde leitura de dados com workflow de prompt. D é falso, resources também retornam dados.]\n\n[ ] A - Tool, since every MCP capability is a tool.\n[ ] B - Resource, analogous to an HTTP GET handler that only reads information.\n[ ] C - Prompt, because reading data is always a user workflow.\n[ ] D - Tool, because only tools can return data to Claude.','\n',char(10)),'B - Resource, analogous to an HTTP GET handler that only reads information.','["Domain_2::Tool_Design_MCP_Integration", "Scenario_1::Customer_Support_Agent"]','New',0,2.5,0,1783092989142,1783727536082,1783203558653,replace('**Tradução para português do Brasil:**\n\nVocê quer expor uma capacidade que apenas lê dados, sem efeito colateral. O que você deve usar?\n\n[ ] A - Tool, já que toda capacidade do MCP é uma tool.\n[ ] B - Resource, análogo a um handler HTTP GET que apenas lê informações.\n[ ] C - Prompt, porque ler dados é sempre um workflow do usuário.\n[ ] D - Tool, porque apenas tools podem retornar dados para o Claude.','\n',char(10)),replace('**Explicação para um adulto tech lead:**\n\nA pergunta trata do Model Context Protocol (MCP) e como expor capacidades de forma semanticamente correta. No MCP, existem três conceitos principais: **tools**, **resources** e **prompts**, cada um com um propósito distinto.\n\n- **Resource** é a abstração correta para operações de leitura de dados sem efeitos colaterais, análoga a um GET em REST. Resources expõem dados do servidor para o cliente (como Claude), e são idealmente *side-effect-free* — ou seja, apenas consultam informações sem modificar estado.\n\n- **Tool**, por outro lado, é semanticamente associada a ações que podem ter efeitos colaterais (criar, atualizar, deletar), equivalentes a POST, PUT, PATCH ou DELETE. Embora tecnicamente uma tool também possa ser implementada como read-only, isso viola a intenção semântica do protocolo.\n\n- **Prompt** é um mecanismo para composição de workflows ou templates de interação, não para exposição de dados crus.\n\n**Análise das alternativas:**\n\n- **A (Tool - incorreta):** Afirma que toda capacidade MCP é uma tool, o que é falso. MCP distingue claramente tools, resources e prompts como primitivas diferentes, cada uma com semântica própria. Ignorar essa distinção leva a um design pobre da interface.\n\n- **B (Resource - correta):** É a resposta correta. Resources são especificamente desenhados para expor dados sem efeitos colaterais, usando um modelo de identificação URI e métodos de leitura pura.\n\n- **C (Prompt - incorreta):** Confunde leitura de dados com workflow de prompt. Prompts são templates para estruturar conversas ou ações, não para expor dados brutos.\n\n- **D (Tool - incorreta):** A afirmação de que "apenas tools podem retornar dados para Claude" é falsa. Resources também retornam dados, e são o mecanismo primário para isso. Tools retornam resultados de ações, que podem ou não incluir dados, mas seu propósito principal não é simplesmente "retornar dados".','\n',char(10)),replace('**Explicação para uma criança de 10 anos:**\n\nImagine que você tem um baú de brinquedos e precisa de alguém para pegar um brinquedo sem bagunçar nada.\n\n- **Resource (Recurso)** é como um amigo que só OLHA dentro do baú e te conta o que tem lá. Ele não mexe em nada, só observa e te dá a informação. É a escolha certa para "só ler dados".\n\n- **Tool (Ferramenta)** é como um amigo que pode PEGAR os brinquedos, TROCAR de lugar, ou até GUARDAR coisas novas. Ele pode fazer bagunça (efeito colateral).\n\n- **Prompt (Instrução/Prompt)** é como uma receita de bolo que te ensina o passo a passo para fazer alguma coisa. Não é para só olhar os dados, é para seguir um plano.\n\nEntão, se você só quer olhar os dados sem mudar nada, que nem um GET no site (quando você abre uma página para ver informações), você usa um **Resource**!\n\nA alternativa A está errada porque acha que tudo no MCP é tool, mas não é. A C confunde ler dados com seguir um roteiro. A D está errada porque tools não são as únicas que retornam dados — resources também retornam!','\n',char(10)));
INSERT INTO cards VALUES('admin','card_1783092989162_04i6ehvnt',356,'Which description correctly differentiates the two types of resource?',replace('Which description correctly differentiates the two types of resource?\n\nWhich description correctly differentiates the two types of resource?\n[Resposta correta: Direct tem URI fixa e templated tem parâmetro na URI. A inverte as duas definições. C nega a existência do parâmetro no templated. D inventa uma distinção de leitura versus escrita que não existe.]\n\n[ ] A - Direct resource uses a URI with a parameter and templated resource uses a fixed URI.\n[ ] B - Direct resource uses a fixed URI (docs://documents) and templated resource uses a URI with a parameter (docs://documents/{doc_id}).\n[ ] C - Both always use fixed URIs, changing only the mime_type.\n[ ] D - Direct resource is for writing and templated resource is for reading.','\n',char(10)),'[ ] B - Direct resource uses a fixed URI (docs://documents) and templated resource uses a URI with a parameter (docs://documents/{doc_id}).','["ForaDosDominios", "ForaDoCenario"]','New',0,2.5,0,1783092989162,1783727539703,1783203558653,replace('**Tradução:**\n\nQual descrição diferencia corretamente os dois tipos de recurso?\n\n[ ] A - Recurso direto usa uma URI com parâmetro e recurso template usa uma URI fixa.\n[ ] B - Recurso direto usa uma URI fixa (docs://documents) e recurso template usa uma URI com parâmetro (docs://documents/{doc_id}).\n[ ] C - Ambos sempre usam URIs fixas, mudando apenas o mime_type.\n[ ] D - Recurso direto é para escrita e recurso template é para leitura.','\n',char(10)),replace('**Explicação para adulto (tech lead):**\n\nA pergunta trata da diferenciação entre **recursos diretos (direct)** e **recursos templated (templated)** no contexto de APIs ou protocolos de comunicação, muito provavelmente relacionados ao padrão **JSON:API** ou a especificações RESTful que utilizam URIs para identificar recursos.\n\n- **Alternativa B (correta):** Define precisamente que um recurso direto possui uma URI fixa (ex.: `docs://documents`), enquanto um recurso templated utiliza uma URI com um parâmetro (ex.: `docs://documents/{doc_id}`). Essa é a distinção clássica: recursos diretos apontam para um conjunto ou entidade específica sem necessidade de substituição de parâmetros; recursos templated exigem que um ou mais parâmetros sejam preenchidos para resolver a URI completa. A alternativa inclusive exemplifica com `{doc_id}`, que é a notação padrão para placeholders em URI templates (conforme RFC 6570).\n\n- **Alternativa A (incorreta):** Inverte as definições. Afirma que o recurso direto tem parâmetro na URI e o templated tem URI fixa, o que é o oposto do conceito correto.\n\n- **Alternativa C (incorreta):** Nega a existência de parâmetros em ambos, afirmando que ambos usam URIs fixas e diferem apenas pelo mime_type. Isso é falso, pois a principal característica do recurso templated é exatamente a presença de parâmetros na URI.\n\n- **Alternativa D (incorreta):** Inventa uma distinção baseada em permissões de leitura vs. escrita, que não é inerente aos conceitos de direct vs. templated. Ambos os tipos podem ser usados tanto para leitura quanto para escrita, dependendo do método HTTP empregado.\n\nPortanto, a alternativa B é a única que descreve corretamente a diferença fundamental entre os dois tipos de recurso.','\n',char(10)),replace('**Explicação para criança de 10 anos:**\n\nImagine que você tem um endereço para chegar na sua casa. Um **recurso direto** é como o endereço completo da sua casa: "Rua das Flores, 123". Você já pode ir direto, sem precisar mudar nada.\n\nJá um **recurso templated** é como um endereço que tem um espaço em branco para ser preenchido: "Rua das Flores, {número da casa}". Você precisa colocar o número certo para saber onde ir. O `{doc_id}` no exemplo é esse espaço em branco — você precisa preencher com o ID do documento.\n\nA alternativa **B** é a correta porque diz exatamente isso: o recurso direto tem um endereço fixo (URI fixa) e o recurso templated tem um endereço com um espaço para preencher (parâmetro na URI).\n\nAs outras alternativas estão erradas porque:\n- **A** troca tudo (fala que o direto é que tem o espaço em branco).\n- **C** diz que nenhum dos dois tem espaço em branco, o que não é verdade para o templated.\n- **D** inventa uma história de que um é só para escrever e outro só para ler, mas isso não tem nada a ver com a diferença entre eles.','\n',char(10)));
INSERT INTO cards VALUES('admin','card_1783092989183_lvgy6s7e0',357,'What is the purpose of the mime_type parameter when defining a resource?',replace('What is the purpose of the mime_type parameter when defining a resource?\n\nWhat is the purpose of the mime_type parameter when defining a resource?\n[Resposta correta: O mime_type sinaliza o tipo de dado retornado. A é falso, o SDK Python serializa automaticamente. B confunde mime_type com transporte. D não tem relação com autenticação.]\n\n[ ] A - Force the client to manually convert the object to JSON.\n[ ] B - Define the transport (stdio or HTTP) used by the resource.\n[ ] C - Give the client a hint of the type of data returned, such as application/json or text/plain.\n[ ] D - Authenticate the client with the MCP server.','\n',char(10)),'C - Give the client a hint of the type of data returned, such as application/json or text/plain.','["Domain_2::Tool_Design_MCP_Integration", "Domain_4::Prompt_Engineering_Structured_Output", "Scenario_6::Structured_Data_Extraction"]','New',0,2.5,0,1783092989183,1783727543935,1783203558653,replace('**Tradução**\n\nQual é o propósito do parâmetro mime_type ao definir um recurso?\n\n[ ] A - Forçar o cliente a converter manualmente o objeto para JSON.\n[ ] B - Definir o transporte (stdio ou HTTP) usado pelo recurso.\n[ ] C - Dar ao cliente uma dica do tipo de dado retornado, como application/json ou text/plain.\n[ ] D - Autenticar o cliente com o servidor MCP.','\n',char(10)),replace('**Explicação para um adulto tech lead**\n\nO parâmetro `mime_type` em recursos (resources) no contexto do Model Context Protocol (MCP) serve exclusivamente para indicar ao cliente qual é o formato (media type) do conteúdo que será retornado por aquele recurso. É uma metadado descritivo,类似 ao cabeçalho `Content-Type` do HTTP.\n\nVamos analisar cada alternativa:\n\n- **Alternativa A (incorreta):** afirma que o `mime_type` força o cliente a fazer conversão manual para JSON. Isso é falso. No MCP, o SDK Python (e outros) já serializam automaticamente objetos Python para JSON quando o `mime_type` é `application/json`. O parâmetro não força nada; ele apenas declara o formato esperado.\n\n- **Alternativa B (incorreta):** confunde `mime_type` com mecanismo de transporte. O transporte (stdio ou HTTP) é definido em outra camada da configuração do servidor MCP, não no recurso. O `mime_type` não tem qualquer relação com o protocolo de comunicação subjacente.\n\n- **Alternativa C (correta):** descreve exatamente a função do `mime_type`: fornecer uma dica ao cliente sobre o tipo de dado retornado. Por exemplo, `application/json` indica que o conteúdo será JSON, `text/plain` indica texto simples, `image/png` indica uma imagem PNG, etc. O cliente pode usar essa informação para decidir como processar ou exibir o conteúdo.\n\n- **Alternativa D (incorreta):** não tem relação com autenticação. Autenticação é tratada por mecanismos como tokens, cabeçalhos de autorização, ou esquemas de segurança definidos na camada de transporte, não no `mime_type` de um recurso.\n\nPortanto, a resposta correta é a letra C.','\n',char(10)),replace('Imagine que você tem uma caixa de presentes, mas ela está fechada. Você não sabe se dentro tem um brinquedo, um livro ou uma roupa. O `mime_type` é como um adesivo colado na caixa que diz: "Atenção! Dentro tem um livro" ou "Dentro tem um brinquedo". Ele não abre a caixa por você, mas dá uma dica do que esperar.\n\nNo computador, quando um programa (cliente) pede uma informação para outro programa (servidor), o `mime_type` avisa: "O que vou te mandar é do tipo `application/json` (que são dados organizados) ou `text/plain` (que é texto simples)". Assim, o cliente já sabe como ler e mostrar aquela informação.\n\nAs outras respostas estão erradas porque:\n- A: o `mime_type` não obriga ninguém a fazer nada, só dá uma dica.\n- B: o `mime_type` não decide se a conversa entre os programas vai ser por "correio" (HTTP) ou por "telefone" (stdio).\n- D: o `mime_type` não serve para saber se o cliente "é de confiança" (autenticação). Isso é outra história.\n\nEntão, a resposta certa é a letra C, porque o `mime_type` é exatamente um "aviso" do tipo de dado que vai chegar.','\n',char(10)));
INSERT INTO cards VALUES('admin','card_1783092989203_q33nvpxlm',358,'The user types @document_name to autocomplete and inject the content into the prompt.',replace('The user types @document_name to autocomplete and inject the content into the prompt.\n\nThe user types @document_name to autocomplete and inject the content into the prompt. Which primitive covers this case?\n[Resposta correta: Autocomplete e injeção de conteúdo são casos de resources (direct para listar, templated para buscar). A trata leitura de dados como tool. B confunde com prompts. D força tools onde resources são o primitivo adequado.]\n\n[ ] A - Tools, since Claude needs to execute an action to fetch the file.\n[ ] B - Prompts, because it is the user who triggers the reference.\n[ ] C - Resources: a direct one lists the documents (autocomplete) and a templated one fetches the content to inject into the prompt.\n[ ] D - A combination of two separate tools, one to list and another to read.','\n',char(10)),'C - Resources: a direct one lists the documents (autocomplete) and a templated one fetches the content to inject into the prompt.','["Domain_2::Tool_Design_MCP_Integration", "Domain_4::Prompt_Engineering_Structured_Output", "Scenario_4::Developer_Productivity"]','New',0,2.5,0,1783092989203,1783727547746,1783203558653,replace('**Tradução para português do Brasil:**\n\nO usuário digita @nome_do_documento para autocompletar e injetar o conteúdo no prompt. Qual primitiva cobre esse caso?\n\n[ ] A - Tools, já que Claude precisa executar uma ação para buscar o arquivo.\n[ ] B - Prompts, porque é o usuário que dispara a referência.\n[ ] C - Resources: um direto lista os documentos (autocomplete) e um templated busca o conteúdo para injetar no prompt.\n[ ] D - Uma combinação de duas tools separadas, uma para listar e outra para ler.','\n',char(10)),replace('**Explicação didática para um adulto tech lead:**\n\nA pergunta aborda o protocolo MCP (Model Context Protocol) e qual primitiva é a mais adequada para modelar o comportamento de autocomplete e injeção de conteúdo via `@document_name`.\n\n**Por que C é a resposta correta:**\n\nResources no MCP são o primitivo projetado especificamente para expor dados e conteúdo do lado do servidor para o modelo. Eles vêm em duas variações:\n- **Resources diretos (static)**: usados para listar ou expor conjuntos de dados conhecidos — neste caso, a lista de nomes de documentos disponíveis para autocomplete.\n- **Resources templated**: usam URIs com parâmetros (ex: `document://{id}`) para buscar um recurso específico sob demanda — neste caso, buscar o conteúdo de um documento específico e injetá-lo no prompt.\n\nResources são o primitivo correto porque representam **dados** (não ações), e o fluxo descrito é essencialmente: o usuário seleciona um recurso de uma lista (autocomplete), e o conteúdo desse recurso é recuperado e injetado.\n\n**Análise das alternativas incorretas:**\n\n- **A (Tools)**: Tools são usadas para executar ações, efeitos colaterais ou operações computacionais. Embora tecnicamente uma tool pudesse "buscar" o arquivo, o uso de tools para leitura de dados que poderiam ser resources é considerado um anti-pattern no MCP. Resources são o primitivo adequado para dados, tools para ações.\n\n- **B (Prompts)**: Prompts no MCP são templates reutilizáveis de mensagens (combinações de user/system messages). Não têm relação com recuperação de dados. A confusão pode vir do fato de o usuário iniciar a ação, mas isso não faz do recurso um prompt.\n\n- **D (Combinação de duas tools)**: Similar a A, mas dobrando o erro. Modelar listagem e leitura como duas tools separadas ignora que resources já oferecem nativamente listagem (via `resources/list`) e leitura (via `resources/read` e URIs templated). Forçar tools onde resources servem perfeitamente viola a semântica do protocolo.','\n',char(10)),replace('Imagina que você tem uma pasta com vários desenhos. Quando você digita "@" e o começo do nome de um desenho, o computador mostra uma lista de desenhos para você escolher (isso é o autocomplete). Depois que você escolhe, ele pega o desenho e coloca na sua tela.\n\nA pergunta é: qual "tipo de coisa" no computador é melhor para fazer isso?\n\nA opção C diz que é um "Resource" (recurso). Um "Resource" é como uma estante de livros: tem uma lista com os nomes de todos os livros (para você escolher) e, quando você pede um livro específico, ele busca esse livro para você ler. É exatamente o que acontece quando você digita @documento: primeiro aparece a lista para você escolher (autocomplete), e depois ele pega o conteúdo do documento e coloca no seu texto.\n\nAs outras opções estão erradas:\n- A e D falam em usar "Tools" (ferramentas), que são mais para fazer ações, como apagar ou desenhar algo. Mas aqui a gente só quer **pegar** um desenho que já existe, não fazer uma ação.\n- B fala em "Prompts", que são como instruções ou mensagens prontas. Não tem nada a ver com pegar arquivos.\n\nEntão a resposta certa é a C: Resources!','\n',char(10)));
INSERT INTO cards VALUES('admin','card_1783092989224_y15i3lo26',359,'Why would an MCP server expose ready-made prompts?',replace('Why would an MCP server expose ready-made prompts?\n\nWhy would an MCP server expose ready-made prompts?\n[Resposta correta: Prompts são instruções testadas que aumentam consistência e qualidade. A confunde prompts com tool use. C mistura prompts com resources. D não tem relação com credenciais.]\n\n[ ] A - Because prompts are the only way for Claude to call tools.\n[ ] B - Because they are pre-built and tested instructions, producing more consistent results than improvised prompts.\n[ ] C - Because prompts replace resources in fetching data.\n[ ] D - Because prompts store the server''s authentication credentials.','\n',char(10)),'B - Because they are pre-built and tested instructions, producing more consistent results than improvised prompts.','["Domain_2::Tool_Design_MCP_Integration", "Domain_4::Prompt_Engineering_Structured_Output", "Scenario_2::Code_Generation_Claude_Code"]','New',0,2.5,0,1783092989224,1783727551975,1783203558653,replace('**Tradução para Português do Brasil:**\n\nPor que um servidor MCP exporia prompts prontos?\n\n[ ] A - Porque prompts são a única forma de Claude chamar ferramentas (tools).\n[ ] B - Porque são instruções pré-construídas e testadas, produzindo resultados mais consistentes do que prompts improvisados.\n[ ] C - Porque prompts substituem recursos (resources) na busca de dados.\n[ ] D - Porque prompts armazenam as credenciais de autenticação do servidor.','\n',char(10)),replace('**Explicação para um adulto tech lead:**\n\nA alternativa **B** é a correta. No contexto do Model Context Protocol (MCP), prompts são templates ou instruções pré-definidas e testadas que um servidor MCP expõe para clientes (como o Claude). O objetivo é padronizar interações comuns, garantindo consistência, previsibilidade e qualidade nas respostas do modelo, evitando que o usuário precise improvisar instruções toda vez.\n\n**Análise das alternativas incorretas:**\n\n- **Alternativa A** — Incorreta. No MCP, tools (ferramentas) e prompts são conceitos diferentes. Ferramentas permitem que o modelo execute ações (como chamar APIs ou funções), enquanto prompts são instruções de entrada. Uma ferramenta pode ser invocada sem que um prompt pré-definido seja utilizado. Portanto, prompts não são o único mecanismo para chamar tools.\n  \n- **Alternativa C** — Incorreta. Resources (recursos) no MCP representam dados que podem ser consultados (como arquivos, bancos de dados ou endpoints). Prompts não substituem resources; eles são instruções para o modelo, enquanto resources fornecem conteúdo a ser processado. São conceitos ortogonais e complementares.\n\n- **Alternativa D** — Incorreta. Credenciais de autenticação nunca devem ser armazenadas em prompts, que são instruções compartilhadas entre cliente e servidor. Isso seria uma violação grave de segurança. Credenciais são gerenciadas por mecanismos de autenticação específicos, não por prompts.','\n',char(10)),replace('Imagine que você tem um jogo de videogame e, em vez de você criar comandos do zero toda vez, o jogo já vem com comandos especiais prontos que funcionam super bem. Esses comandos foram testados por quem fez o jogo para garantir que tudo saia como esperado.\n\nÉ a mesma ideia com o MCP: o servidor oferece "prompts prontos" — que são como receitas de bolo já testadas. Assim, quando você pede algo, o resultado sai sempre certinho, sem precisar inventar a receita toda vez.\n\nAs outras opções estão erradas:\n- A (sobre chamar ferramentas) — Não é verdade, porque dá para chamar ferramentas de outros jeitos, não só com prompts.\n- C (sobre substituir dados) — Prompts não substituem informações; eles são instruções, como um manual.\n- D (sobre senhas) — Colocar senhas em prompts seria muito perigoso e não é para isso que servem.','\n',char(10)));
INSERT INTO cards VALUES('admin','card_1783092989244_pggqi4o2d',360,'What is the typical return value of an MCP prompt?',replace('What is the typical return value of an MCP prompt?\n\nWhat is the typical return value of an MCP prompt?\n[Resposta correta: Um prompt retorna uma lista de mensagens prontas para envio ao Claude. A confunde com resposta do modelo. B descreve o retorno de uma definição de tool. D confunde prompt com resource.]\n\n[ ] A - A single string already formatted as Claude''s final response.\n[ ] B - A JSON schema describing the parameters of a tool.\n[ ] C - A list of messages (e.g., base.UserMessage) that the client can send directly to Claude.\n[ ] D - A resource URI to be read later.','\n',char(10)),'[ ] C - A list of messages (e.g., base.UserMessage) that the client can send directly to Claude.','["Domain_2::Tool_Design_MCP_Integration", "Domain_4::Prompt_Engineering_Structured_Output", "Scenario_4::Developer_Productivity"]','New',0,2.5,0,1783092989244,1783727555560,1783203558653,replace('**Tradução para português do Brasil:**\n\nQual é o valor de retorno típico de um prompt MCP?\n\n[ ] A - Uma única string já formatada como a resposta final do Claude.\n[ ] B - Um schema JSON descrevendo os parâmetros de uma tool.\n[ ] C - Uma lista de mensagens (ex.: base.UserMessage) que o cliente pode enviar diretamente ao Claude.\n[ ] D - Uma URI de recurso para ser lida posteriormente.','\n',char(10)),replace('**Explicação didática para um adulto tech lead:**\n\nNo contexto do Model Context Protocol (MCP), um "prompt" é uma template reutilizável que gera uma sequência de mensagens estruturadas para serem enviadas a um modelo de linguagem (como o Claude). O retorno típico de uma definição de prompt no MCP é uma lista de mensagens — objetos como `UserMessage`, `AssistantMessage` etc. — prontas para serem consumidas pelo cliente. \n\nVamos analisar cada alternativa:\n\n- **Alternativa C (correta):** "Uma lista de mensagens (ex.: base.UserMessage) que o cliente pode enviar diretamente ao Claude." — Esta é a definição correta. No MCP, um prompt server implementa um `Prompt` que, quando invocado, retorna uma lista de `PromptMessage` (geralmente contendo `role` e `content`). Essa lista é exatamente o que o cliente vai enviar como input para o LLM, sem necessidade de transformação adicional.\n\n- **Alternativa A:** "Uma única string já formatada como a resposta final do Claude." — Isso descreveria o *output* do modelo, não o *input* gerado pelo prompt. Um prompt MCP gera mensagens de entrada (o que será enviado ao modelo), não a resposta final. Além disso, não é uma única string, mas sim uma lista estruturada de mensagens.\n\n- **Alternativa B:** "Um schema JSON descrevendo os parâmetros de uma tool." — Isso descreve o retorno de uma definição de *tool* (ou *function*) no MCP, não de um prompt. Tools definem schemas de parâmetros que o modelo pode invocar; prompts definem mensagens pré-formatadas. São conceitos diferentes.\n\n- **Alternativa D:** "Uma URI de recurso para ser lida posteriormente." — Isso descreve o retorno de uma *resource* no MCP, não de um prompt. Resources fornecem dados via URI (como arquivos, banco de dados etc.), enquanto prompts geram mensagens para o LLM.\n\nPortanto, a resposta correta é a alternativa C.','\n',char(10)),replace('Imagine que você quer pedir ajuda para o Claude (um robô inteligente). Um "prompt" no MCP é como um **modelo de carta** já prontinho. Quando você usa esse modelo, ele não devolve a resposta do robô — ele devolve uma **lista de perguntas e instruções** que você pode mandar direto para o robô responder.\n\nAs opções:\n- A: diz que o prompt devolve a resposta final do robô – errado! O prompt devolve o que você vai *perguntar*, não a resposta.\n- B: diz que devolve um esquema de ferramenta – isso é de outra coisa (tool), não do prompt.\n- C: diz que devolve uma lista de mensagens prontinhas para enviar ao Claude – **correto!** É exatamente isso.\n- D: diz que devolve um endereço (URI) de recurso – isso é de outra coisa (resource), não do prompt.\n\nEntão a resposta certa é a **C**: o prompt dá uma lista de mensagens já organizadas para você mandar direto para o Claude.','\n',char(10)));
INSERT INTO cards VALUES('admin','card_1783092989299_npysqg6o9',361,'How does FastMCP (Python SDK) reduce the work of defining a tool?',replace('How does FastMCP (Python SDK) reduce the work of defining a tool?\n\nHow does FastMCP (Python SDK) reduce the work of defining a tool?\n[Resposta correta: O SDK usa decorator e type hints para gerar o schema, com Field do Pydantic nas descrições. A é o trabalho manual que o SDK evita. C ignora o papel dos type hints. D confunde tool com resource.]\n\n[ ] A - It requires you to write the JSON schema by hand for each parameter.\n[ ] B - It uses decorators (@mcp.tool) and type hints to generate the JSON schema automatically, with Pydantic''s Field describing the parameters.\n[ ] C - It generates the schema only at runtime, without type hints.\n[ ] D - It converts the function into a templated resource.','\n',char(10)),'B - It uses decorators (@mcp.tool) and type hints to generate the JSON schema automatically, with Pydantic''s Field describing the parameters.','["Domain_2::Tool_Design_MCP_Integration", "Domain_4::Prompt_Engineering_Structured_Output", "Scenario_2::Code_Generation_Claude_Code"]','New',0,2.5,0,1783092989299,1783727559312,1783203558653,replace('**Tradução para português do Brasil:**\n\n**Pergunta:** Como o FastMCP (SDK Python) reduz o trabalho de definir uma ferramenta (tool)?\n\n[ ] A - Ele exige que você escreva o schema JSON manualmente para cada parâmetro.\n[ ] B - Ele usa decorators (@mcp.tool) e type hints para gerar o schema JSON automaticamente, com o Field do Pydantic descrevendo os parâmetros.\n[ ] C - Ele gera o schema apenas em tempo de execução, sem type hints.\n[ ] D - Ele converte a função em um resource (recurso) baseado em template.','\n',char(10)),replace('**Explicação para um adulto tech lead:**\n\nO FastMCP (Python SDK) reduz significativamente o trabalho de definição de ferramentas ao automatizar a geração do JSON Schema a partir do código Python. Isso é feito através de duas abordagens principais:\n\n1. **Decorators (`@mcp.tool`)**: O desenvolvedor simplesmente anota uma função Python com esse decorator, e o SDK a registra automaticamente como uma ferramenta MCP. Não é necessário implementar interfaces abstratas, classes base ou arquivos de configuração separados.\n\n2. **Type hints + Pydantic**: O SDK inspeciona as anotações de tipo (type hints) dos parâmetros da função e, com a ajuda do Pydantic, gera automaticamente o JSON Schema correspondente. Se o desenvolvedor usar `Field(description="...")` do Pydantic, essas descrições são incorporadas ao schema, enriquecendo a documentação da ferramenta para o cliente MCP.\n\n**Análise das alternativas:**\n\n- **Alternativa A (INCORRETA):** Afirma que o SDK exige escrever o JSON Schema manualmente. Isso é justamente o oposto do que o FastMCP faz — o objetivo principal do SDK é eliminar esse trabalho manual.\n\n- **Alternativa B (CORRETA):** Descreve precisamente o mecanismo: decorators + type hints + Pydantic Field para geração automática de schema.\n\n- **Alternativa C (INCORRETA):** Diz que o schema é gerado apenas em runtime *sem* type hints. Na verdade, os type hints são essenciais para a geração do schema no FastMCP. Sem eles, o SDK não teria informação suficiente para construir o schema automaticamente.\n\n- **Alternativa D (INCORRETA):** Confunde o conceito de "tool" com "resource". No MCP, tools são funções executáveis (com action/effect), enquanto resources são fontes de dados (com URI template). O FastMCP trata tools e resources como primitivas distintas, não convertendo uma na outra.','\n',char(10)),replace('**Explicação para uma criança de 10 anos:**\n\nImagine que você precisa ensinar um robô a fazer contas de matemática. Normalmente, você teria que escrever um manual super complicado explicando cada detalhe da conta. Mas o FastMCP é como um assistente mágico que entende o que você quer fazer só de olhar como você escreveu a função.\n\nSe você escrever uma função assim:\n```python\n@mcp.tool\ndef somar(a: int, b: int) -> int:\n    return a + b\n```\n\nO FastMCP automaticamente descobre que a ferramenta se chama "somar", que ela precisa de dois números inteiros (a e b) e que vai devolver outro número inteiro. Ele mesmo cria o "manual" (o schema) para o robô entender como usar essa ferramenta.\n\nÉ como se você pudesse falar "faz um sanduíche" e a pessoa já soubesse que precisa de pão, queijo e presunto, sem você ter que explicar cada ingrediente. O FastMCP faz esse trabalho chato de criar a ficha técnica sozinho!\n\n**Resumindo: a alternativa B está certa** porque o FastMCP usa esses truques legais (decorators e type hints) para fazer o trabalho pesado pra você.','\n',char(10)));
INSERT INTO cards VALUES('admin','card_1783092989321_fy61khjz3',362,'In Claude Code, what is the purpose of adding an MCP server like Playwright?',replace('In Claude Code, what is the purpose of adding an MCP server like Playwright?\n\nIn Claude Code, what is the purpose of adding an MCP server like Playwright?\n[Resposta correta: MCP servers acrescentam novas tools e capabilities, como o controle de browser via Playwright. A confunde com armazenamento de histórico. C não tem relação com escolha de modelo. D é o oposto do que MCP faz.]\n\n[ ] A - To store Claude Code''s conversation history.\n[ ] B - To provide Claude with new tools and capabilities it would not normally have, such as controlling a browser.\n[ ] C - To swap the language model used by Claude Code.\n[ ] D - To disable Claude Code''s native tools.','\n',char(10)),'B - To provide Claude with new tools and capabilities it would not normally have, such as controlling a browser.','["Domain_3::Claude_Code_Configuration_Workflows", "Domain_2::Tool_Design_MCP_Integration", "Scenario_2::Code_Generation_Claude_Code"]','New',0,2.5,0,1783092989321,1783727562746,1783203558653,replace('**Tradução para português do Brasil:**\n\nNo Claude Code, qual é o propósito de adicionar um servidor MCP como o Playwright?\n\n[ ] A - Armazenar o histórico de conversas do Claude Code.\n[ ] B - Fornecer ao Claude novas ferramentas e capacidades que ele normalmente não teria, como controlar um navegador.\n[ ] C - Trocar o modelo de linguagem usado pelo Claude Code.\n[ ] D - Desabilitar as ferramentas nativas do Claude Code.','\n',char(10)),replace('**Explicação didática para um adulto tech lead:**\n\nA alternativa **B** está correta. O MCP (Model Context Protocol) é um padrão aberto que permite que modelos de linguagem como o Claude se integrem com sistemas externos. Ao adicionar um servidor MCP como o Playwright, você está estendendo as capacidades do Claude — ele ganha acesso a ferramentas que permitem, por exemplo, controlar um navegador, navegar por páginas web, clicar em elementos, extrair informações, etc. Essas não são capacidades nativas do Claude; elas são expostas através do protocolo MCP.\n\nVamos às incorretas:\n\n- **A**: MCP servers não têm relação com armazenamento de histórico. O histórico de conversas é gerenciado internamente pelo Claude Code.\n- **C**: A escolha do modelo de linguagem (como qual versão do Claude está sendo usada) é uma configuração separada do Claude Code, não relacionada à adição de servidores MCP.\n- **D**: Adicionar um servidor MCP é justamente o oposto de desabilitar ferramentas — ele adiciona novas ferramentas ao Claude, em vez de remover as existentes.','\n',char(10)),replace('Imagine que o Claude é um robô que só sabe conversar. Se você colocar um "MCP server" como o Playwright, é como dar uma mão nova para o robô — agora ele consegue controlar um navegador de internet, abrir sites e clicar em coisas. Antes ele não conseguia fazer isso.\n\n- A alternativa A está errada porque não tem nada a ver com guardar o histórico da conversa.\n- A alternativa C está errada porque não é para trocar o "cérebro" (o modelo de IA) do Claude.\n- A alternativa D está errada porque adicionar ferramentas novas não desabilita as que já existem — é o contrário!\n\nResumindo: a resposta certa é a **B**, porque o MCP server dá novas habilidades para o Claude, como controlar um navegador.','\n',char(10)));
INSERT INTO cards VALUES('admin','card_1783092989341_c0708qznr',363,'What are the three components that an MCP server can expose?',replace('What are the three components that an MCP server can expose?\n\nWhat are the three components that an MCP server can expose?\n[Resposta correta: Os três primitivos expostos são Tools, Prompts e Resources. B inclui client e session, que não são expostos pelo server. C e D misturam conceitos de transporte, schema e autenticação que não são os três componentes.]\n\n[ ] A - Tools, Prompts and Resources.\n[ ] B - Tools, Clients and Sessions.\n[ ] C - Prompts, Transports and Schemas.\n[ ] D - Resources, Tokens and Handlers.','\n',char(10)),'[ ] A - Tools, Prompts and Resources.','["Domain_2::Tool_Design_MCP_Integration", "ForaDoCenario"]','New',0,2.5,0,1783092989341,1783727566067,1783203558653,replace('**Tradução para pt-BR:**\n\nPergunta: "Quais são os três componentes que um servidor MCP pode expor?"\n\nAlternativas:\n[ ] A - Tools, Prompts e Resources.\n[ ] B - Tools, Clients e Sessions.\n[ ] C - Prompts, Transports e Schemas.\n[ ] D - Resources, Tokens e Handlers.','\n',char(10)),replace('**Explicação para um adulto tech lead:**\n\nNo contexto do **Model Context Protocol (MCP)**, um servidor expõe três primitivos fundamentais que permitem que clientes (como LLMs ou aplicações) interajam com capacidades e dados externos. Esses três componentes são:\n\n1. **Tools (Ferramentas)** – São funções invocáveis pelo cliente, geralmente para executar ações no mundo externo (ex.: consultar uma API, escrever em um banco de dados, enviar um e-mail). Tools têm descrições e schemas de entrada/saída, permitindo que o modelo decida quando e como chamá-las.\n\n2. **Prompts (Modelos de Prompt)** – São templates de mensagens pré-definidos que o servidor disponibiliza. Eles facilitam a construção de interações padronizadas, como um prompt de "boas-vindas" ou "resumo", que podem ser reutilizados pelo cliente.\n\n3. **Resources (Recursos)** – São fontes de dados estáticas ou dinâmicas (ex.: arquivos, endpoints de API, bancos de dados) que o servidor expõe para leitura. Recursos possuem um URI e podem ser consultados pelo cliente para obter informações contextuais.\n\n**Por que a alternativa A é a correta:** Ela lista exatamente os três primitivos definidos na especificação do MCP.\n\n**Análise das alternativas incorretas:**\n\n- **Alternativa B (Tools, Clients e Sessions):** "Clients" e "Sessions" não são componentes que um servidor expõe; são conceitos de infraestrutura da comunicação. O servidor não expõe clientes nem gerencia sessões como primitivos expostos.\n\n- **Alternativa C (Prompts, Transports e Schemas):** "Transports" são mecanismos de comunicação (como stdio ou SSE) entre cliente e servidor, não são componentes expostos. "Schemas" (como JSON Schema) são usados internamente para descrever parâmetros de tools ou resources, mas não são um primitivo exposto por si só.\n\n- **Alternativa D (Resources, Tokens e Handlers):** "Tokens" são unidades de texto para modelos de linguagem, não são componentes expostos por um servidor MCP. "Handlers" são funções internas de tratamento de requisições, não primitivos expostos ao cliente.','\n',char(10)),replace('**Explicação para uma criança de 10 anos:**\n\nImagine que o servidor MCP é como uma caixa de ferramentas mágica que um robô inteligente (o cliente) pode usar para fazer coisas legais. Essa caixa de ferramentas tem três tipos de coisas que ela pode mostrar para o robô:\n\n1. **Ferramentas (Tools)** – São como brinquedos que o robô pode pegar e usar para fazer alguma ação, como desenhar ou ligar uma luz.\n2. **Modelos de Prompt (Prompts)** – São como receitas prontas que o robô pode seguir para conversar de um jeito especial, tipo um roteiro de história.\n3. **Recursos (Resources)** – São como livros ou informações que o robô pode ler para aprender algo novo.\n\nA alternativa A lista essas três coisas certinhas!\n\nAs outras alternativas estão erradas porque misturam nomes de outras partes. Por exemplo:\n- **Alternativa B** fala de "clientes" e "sessões" – mas isso são apelidos das pessoas que usam a caixa, não são peças dentro dela.\n- **Alternativa C** fala de "transporte" e "esquemas" – transporte é o caminhão que leva a caixa, e esquemas são as instruções escritas, não são os brinquedos que saem da caixa.\n- **Alternativa D** fala de "tokens" e "handlers" – tokens são pedacinhos de palavras, e handlers são os botões internos da caixa, não são o que ela mostra por fora.\n\nEntão a resposta certa é a **alternativa A**!','\n',char(10)));
INSERT INTO cards VALUES('admin','card_1783092989362_gp2tbdgo3',364,'Which command adds the Playwright MCP server to Claude Code?',replace('Which command adds the Playwright MCP server to Claude Code?\n\nWhich command adds the Playwright MCP server to Claude Code?\n[Resposta correta: O comando é claude mcp add playwright npx @playwright/mcp@latest, executado no terminal fora do Claude Code. A inventa um slash command inexistente. C não é o mecanismo de registro do MCP. D apenas instala o browser, não o server MCP.]\n\n[ ] A - Inside Claude Code, type /mcp install playwright.\n[ ] B - In the terminal, claude mcp add playwright npx @playwright/mcp@latest.\n[ ] C - Directly edit the project''s package.json file.\n[ ] D - Run npx playwright install inside Claude Code.','\n',char(10)),'B - In the terminal, claude mcp add playwright npx @playwright/mcp@latest.','["Domain_3::Claude_Code_Configuration_Workflows", "Domain_2::Tool_Design_MCP_Integration", "Scenario_2::Code_Generation_Claude_Code"]','New',0,2.5,0,1783092989362,1783727569734,1783203558653,replace('**Tradução para português do Brasil:**\n\nPergunta: Qual comando adiciona o servidor MCP do Playwright ao Claude Code?\n\n[ ] A - Dentro do Claude Code, digite /mcp install playwright.\n[ ] B - No terminal, execute claude mcp add playwright npx @playwright/mcp@latest.\n[ ] C - Edite diretamente o arquivo package.json do projeto.\n[ ] D - Execute npx playwright install dentro do Claude Code.','\n',char(10)),replace('**Explicação para um adulto tech lead:**\n\nO MCP (Model Context Protocol) é o protocolo que permite que assistentes como Claude Code se comuniquem com ferramentas externas (servidores MCP). Para adicionar um servidor MCP ao Claude Code, o mecanismo correto é registrar o servidor através da CLI do Claude, fora do ambiente interativo do Claude Code.\n\n**Alternativa correta (B):** O comando `claude mcp add playwright npx @playwright/mcp@latest` é executado no terminal do sistema operacional (fora do Claude Code). Ele utiliza a CLI nativa do Claude (`claude mcp add`) para registrar o servidor MCP do Playwright. O argumento `npx @playwright/mcp@latest` especifica como o servidor deve ser iniciado (via npx, usando o pacote oficial mais recente). Este comando adiciona a configuração ao arquivo de configuração do Claude (como `~/.claude/settings.json`), permitindo que o Claude Code invoque as ferramentas do Playwright (navegador, páginas, etc.) durante as interações.\n\n**Alternativa A - Incorreta:** `/mcp install playwright` não é um comando válido no Claude Code. O Claude Code não possui um sistema de slash commands para gerenciamento de servidores MCP internamente.\n\n**Alternativa C - Incorreta:** O arquivo `package.json` de um projeto JavaScript/TypeScript gerencia dependências do projeto, não o registro de servidores MCP para o Claude Code. A configuração de servidores MCP é feita em arquivos de configuração específicos do Claude (como `claude.json` ou `settings.json`), não no `package.json`.\n\n**Alternativa D - Incorreta:** O comando `npx playwright install` baixa os navegadores necessários para o Playwright (Chromium, Firefox, WebKit), mas não registra o servidor MCP. Sem o registro via `claude mcp add`, o Claude Code não saberá como invocar ou se comunicar com o Playwright como ferramenta MCP.','\n',char(10)),replace('Imagine que o Claude Code é um robô assistente e o Playwright é uma ferramenta que permite ao robô controlar um navegador de internet. Para o robô conseguir usar essa ferramenta, alguém precisa apresentá-los formalmente — é como um "matchmaker" (aquele que apresenta duas pessoas).\n\nO comando `claude mcp add playwright npx @playwright/mcp@latest` é como dizer: "Ei, robô Claude, conheça o Playwright! Sempre que você precisar dele, use este endereço aqui."\n\nVocê precisa digitar isso no terminal do computador (aquela janela preta de comandos), não dentro da conversa com o Claude.\n\nAs outras opções estão erradas:\n- Opção A: É como tentar apresentar as pessoas usando uma palavra mágica que não existe.\n- Opção C: É como tentar colocar o endereço do Playwright na lista de convidados de uma festa errada.\n- Opção D: É como comprar um brinquedo novo, mas esquecer de apresentá-lo ao robô. O brinquedo está lá, mas o robô não sabe que pode usá-lo.','\n',char(10)));
INSERT INTO cards VALUES('admin','card_1783092989384_v4e7ybrc1',365,'How do you avoid repeated permission prompts for the tools of an MCP server in local use?',replace('How do you avoid repeated permission prompts for the tools of an MCP server in local use?\n\nHow do you avoid repeated permission prompts for the tools of an MCP server in local use?\n[Resposta correta: A entrada vai no array allow de .claude/settings.local.json com o prefixo mcp__ (dois underscores). A erra o número de underscores. B descreve o caso do GitHub Actions, não o local. D é inseguro e não é o mecanismo indicado.]\n\n[ ] A - Add "mcp_playwright" with one underscore to the allow array.\n[ ] B - List each tool individually in allowed_tools in the workflow.\n[ ] C - In .claude/settings.local.json, add "mcp__playwright" with two underscores to the permissions allow array.\n[ ] D - Completely disable Claude Code''s permission system.','\n',char(10)),'C - In .claude/settings.local.json, add "mcp__playwright" with two underscores to the permissions allow array.','["Domain_2::Tool_Design_MCP_Integration", "Domain_3::Claude_Code_Configuration_Workflows", "Scenario_4::Developer_Productivity"]','New',0,2.5,0,1783092989384,1783727573263,1783203558653,replace('**Tradução para pt-BR:**\n\n**Pergunta:** Como evitar solicitações de permissão repetidas para as ferramentas de um servidor MCP em uso local?\n\n**Alternativas:**\n\n[ ] A - Adicionar "mcp_playwright" com um underscore ao array allow.\n[ ] B - Listar cada ferramenta individualmente em allowed_tools no workflow.\n[ ] C - Em .claude/settings.local.json, adicionar "mcp__playwright" com dois underscores ao array de permissões allow.\n[ ] D - Desabilitar completamente o sistema de permissões do Claude Code.','\n',char(10)),replace('**Explicação para Adulto (Tech Lead):**\n\n**Resposta Correta: C**\n\nA alternativa C descreve corretamente o mecanismo oficial para evitar prompts repetidos de permissão para ferramentas MCP em ambiente local. O arquivo `.claude/settings.local.json` é o local apropriado para configurações locais que não devem ser versionadas (geralmente incluído no `.gitignore`). A chave de permissão segue o padrão `mcp__<server-name>`, com **dois underscores** separando o prefixo `mcp` do nome do servidor MCP. Ao adicionar essa string ao array `allow` dentro de `permissions`, o Claude Code autoriza automaticamente todas as ferramentas daquele servidor MCP sem solicitar confirmação a cada uso.\n\n**Por que as demais estão erradas:**\n\n- **A:** O prefixo correto usa **dois underscores** (`mcp__`), não um. Com um underscore apenas (`mcp_`), o sistema não reconhece a entrada como uma permissão para um servidor MCP, tornando a configuração ineficaz.\n- **B:** Esta alternativa descreve o comportamento para **GitHub Actions** (CI/CD), onde é necessário listar ferramentas individualmente em `allowed_tools` no workflow YAML. Não se aplica ao uso local interativo.\n- **D:** Desabilitar completamente o sistema de permissões remove toda a camada de segurança, expondo o ambiente a execução não monitorada de ferramentas. É uma prática insegura e não recomendada, além de não ser o mecanismo adequado para resolver o problema específico de prompts repetidos.\n\n**Resumo técnico:** O caminho correto é configurar `~/.claude/settings.local.json` (ou `.claude/settings.local.json` no projeto) com a estrutura:\n\n```json\n{\n  "permissions": {\n    "allow": ["mcp__playwright"]\n  }\n}\n```\n\nIsso concede permissão automática a todas as ferramentas do servidor MCP `playwright`.','\n',char(10)),replace('**Explicação para Criança de 10 anos:**\n\nImagine que você tem um robô assistente (o Claude Code) que pode usar várias ferramentas, como uma "caixa de ferramentas mágica" chamada MCP. Toda vez que o robô quer pegar uma ferramenta dessa caixa, ele pede permissão para você: "Posso usar o martelo? Posso usar a chave de fenda?" — isso é chato quando você já disse que pode usar todas!\n\nA alternativa C é a resposta certa porque ensina você a criar um "passe livre" para a caixa de ferramentas inteira. Você escreve num arquivo de configuração (como se fosse um bilhete com regras) o nome da caixa com **dois tracinhos** (`mcp__playwright`). Assim, o robô sabe que pode usar qualquer ferramenta dessa caixa sem precisar perguntar toda hora.\n\nAs outras opções estão erradas porque:\n- **A** usa só um tracinho — é como escrever o nome da caixa errado, e o robô não entende.\n- **B** serve para outro tipo de uso (em nuvem, não no seu computador).\n- **D** é tipo desligar o sistema de segurança inteiro — perigoso! Alguém poderia usar ferramentas sem você saber.','\n',char(10)));
INSERT INTO cards VALUES('admin','card_1783092989405_13wcnaa8o',366,'You want Claude to inspect the actual visual result of components and refine the generation prompt.',replace('You want Claude to inspect the actual visual result of components and refine the generation prompt.\n\nYou want Claude to inspect the actual visual result of components and refine the generation prompt. Which MCP server should you use?\n[Resposta correta: O Playwright permite observar o output visual renderizado, não só o código. A lê código, não o visual. C e D atuam sobre dados e APIs, não sobre a renderização visual do componente.]\n\n[ ] A - A filesystem MCP, which only reads the code files.\n[ ] B - Playwright MCP, which opens the browser, navigates to the app and inspects the rendered visual style.\n[ ] C - A database MCP, to query the state of the components.\n[ ] D - An API testing MCP, which only validates HTTP responses.','\n',char(10)),'[ ] B - Playwright MCP, which opens the browser, navigates to the app and inspects the rendered visual style.','["Domain_2::Tool_Design_MCP_Integration", "Domain_4::Prompt_Engineering_Structured_Output", "Scenario_2::Code_Generation_Claude_Code"]','New',0,2.5,0,1783092989405,1783727576978,1783203558653,replace('**Tradução para português do Brasil:**\n\nVocê quer que o Claude inspecione o resultado visual real dos componentes e refine o prompt de geração.\n\nVocê quer que o Claude inspecione o resultado visual real dos componentes e refine o prompt de geração. Qual servidor MCP você deve usar?\n\n[ ] A - Um MCP de filesystem, que apenas lê os arquivos de código.\n[ ] B - Playwright MCP, que abre o navegador, navega até o aplicativo e inspeciona o estilo visual renderizado.\n[ ] C - Um MCP de banco de dados, para consultar o estado dos componentes.\n[ ] D - Um MCP de teste de API, que apenas valida respostas HTTP.','\n',char(10)),replace('**Explicação para um adulto tech lead:**\n\nO requisito principal é **inspecionar o resultado visual real dos componentes**. Isso significa que não basta olhar o código-fonte; é necessário ver o que o navegador efetivamente renderizou — layout, cores, fontes, posicionamento, responsividade, etc.\n\n- **Alternativa B (Playwright MCP) — Correta**: O Playwright é uma ferramenta de automação de navegador que permite abrir uma página, interagir com ela e, crucialmente, **inspecionar o estado visual renderizado no DOM**, incluindo estilos computados, posições, tamanhos e propriedades visuais. Com ele, é possível capturar screenshots, avaliar se um componente está visível, verificar cores e fontes aplicadas, etc. Isso atende exatamente ao objetivo de inspecionar o "resultado visual real".\n\n- **Alternativa A (Filesystem MCP) — Incorreta**: Um MCP de sistema de arquivos permite ler, escrever e listar arquivos. Embora seja útil para inspecionar código-fonte (JSX, CSS, etc.), ele **não executa o código nem renderiza visualmente nada**. Você só vê o texto dos arquivos, não o resultado renderizado no navegador.\n\n- **Alternativa C (Database MCP) — Incorreta**: Um MCP de banco de dados permite consultar e manipular dados armazenados. O estado de componentes pode até estar refletido no banco, mas isso é uma representação indireta e abstrata, **não o output visual renderizado**. Não há inspeção visual alguma.\n\n- **Alternativa D (API Testing MCP) — Incorreta**: Um MCP de teste de API focado em validação de respostas HTTP só consegue verificar headers, status codes e corpos de resposta. Isso é totalmente inadequado para inspecionar a renderização visual de componentes de interface.\n\n**Conclusão**: Para inspecionar o resultado visual real, você precisa de uma ferramenta que interaja com o navegador renderizado — o Playwright MCP é a escolha correta.','\n',char(10)),replace('Imagine que você desenhou um robô num papel (o código) e quer ver se ele ficou bonito de verdade depois de pronto (o visual renderizado).\n\n- Se você **só olhar o papel com as instruções de como desenhar** (alternativa A), você nunca vai ver o robô de verdade. É como ler a receita do bolo sem fazer o bolo.\n- Se você **olhar o bolo pronto no forno** (alternativa B — Playwright), aí sim você vê o resultado real: cor, forma, tamanho, se está bonito ou precisa de mais enfeites.\n- Se você **olhar a lista de ingredientes que sobraram na geladeira** (alternativa C — banco de dados), você não vê o bolo, só os ingredientes.\n- Se você **testar se o forno liga e desliga** (alternativa D — API), você não vê o bolo, só vê se o forno funciona.\n\nEntão, para ver o visual real do componente, você precisa do **Playwright MCP**, que abre o navegador, carrega a página e mostra como ela ficou de verdade.','\n',char(10)));
INSERT INTO cards VALUES('admin','card_1783092989427_g70c485ur',367,'Why does the MCP permissions configuration in GitHub Actions differ from local use?',replace('Why does the MCP permissions configuration in GitHub Actions differ from local use?\n\nWhy does the MCP permissions configuration in GitHub Actions differ from local use?\n[Resposta correta: Em GitHub Actions cada tool precisa ser listada individualmente em allowed_tools. A descreve o atalho local, que não existe em Actions. C e D são falsos sobre o comportamento em Actions.]\n\n[ ] A - Because in Actions it is enough to use the mcp__playwright prefix to allow everything.\n[ ] B - Because in Actions there is no shortcut: each tool must be listed individually in allowed_tools, e.g., mcp__playwright__browser_click.\n[ ] C - Because in Actions permissions are always granted automatically.\n[ ] D - Because in Actions Claude does not use MCP servers.','\n',char(10)),'B - Because in Actions there is no shortcut: each tool must be listed individually in allowed_tools, e.g., mcp__playwright__browser_click.','["Domain_3::Claude_Code_Configuration_Workflows", "Domain_2::Tool_Design_MCP_Integration", "Scenario_5::Claude_Code_CI_CD"]','New',0,2.5,0,1783092989427,1783727580536,1783203558653,replace('Tradução:\n\n**Por que a configuração de permissões MCP no GitHub Actions difere do uso local?**\n\n[ ] A - Porque no Actions é suficiente usar o prefixo mcp__playwright para permitir tudo.\n[ ] B - Porque no Actions não existe atalho: cada tool precisa ser listada individualmente em allowed_tools, ex.: mcp__playwright__browser_click.\n[ ] C - Porque no Actions as permissões são sempre concedidas automaticamente.\n[ ] D - Porque no Actions o Claude não utiliza servidores MCP.','\n',char(10)),replace('Explicação para adulto (tech lead):\n\nA resposta correta é a **alternativa B**.\n\nNo ambiente local, o Claude Desktop permite o uso de curingas (wildcards) no arquivo de configuração `mcp_servers.json` para liberar todas as tools de um servidor MCP de uma só vez. Por exemplo, configurar `"allowed_tools": ["mcp__playwright__*"]` ou até mesmo omitir a lista funciona como um atalho para autorizar tudo que pertence àquele servidor.\n\nNo **GitHub Actions**, esse atalho **não existe**. Cada tool deve ser explicitamente listada na configuração — sem suporte a wildcards. Isso significa que, se você tiver um servidor MCP com dezenas de tools, precisará enumerar cada uma individualmente em `allowed_tools`, como `mcp__playwright__browser_click`, `mcp__playwright__browser_type`, etc.\n\n**Por que as outras alternativas estão erradas:**\n\n- **Alternativa A**: Incorreta. Usar apenas `mcp__playwright` como prefixo não é suficiente no Actions. O comportamento exigido é a listagem individual, não um prefixo genérico.\n- **Alternativa C**: Incorreta. As permissões não são concedidas automaticamente. Pelo contrário, o Actions exige configuração explícita — e mais rigorosa — justamente por ser um ambiente de execução automatizada com riscos de segurança elevados.\n- **Alternativa D**: Incorreta. O Claude **utiliza** servidores MCP no Actions normalmente. O que muda é apenas o mecanismo de declaração de permissões, não a arquitetura de integração com MCP.','\n',char(10)),replace('Imagine que você tem uma caixa de ferramentas cheia de ferramentas diferentes — martelo, chave de fenda, alicate, etc.\n\nNo seu quarto (uso local), você pode dizer "pode usar qualquer ferramenta do grupo ''Playwright''" e pronto. É um atalho.\n\nJá na escola (GitHub Actions), o professor não aceita atalhos. Você precisa dizer exatamente quais ferramentas quer usar, uma por uma: "posso usar o martelo do grupo Playwright", "posso usar a chave de fenda do grupo Playwright". Não pode falar "todas as ferramentas do Playwright".\n\nPor isso a resposta certa é a **B**: no Actions, você não consegue usar atalhos — tem que listar cada ferramentinha pelo nome completo.','\n',char(10)));
INSERT INTO cards VALUES('admin','card_1783092989448_lv55r2t2s',368,'Besides browser control, what capabilities does the MCP ecosystem cover?',replace('Besides browser control, what capabilities does the MCP ecosystem cover?\n\nBesides browser control, what capabilities does the MCP ecosystem cover?\n[Resposta correta: O ecossistema cobre banco de dados, API, filesystem, nuvem e automação de dev tools. A nega as integrações externas. B e D restringem o ecossistema a uma única categoria.]\n\n[ ] A - Only text generation, with no external integrations.\n[ ] B - Only local filesystem operations.\n[ ] C - Database, API testing/monitoring, filesystem, cloud services and automation of development tools.\n[ ] D - Exclusively browser control via Playwright.','\n',char(10)),'C - Database, API testing/monitoring, filesystem, cloud services and automation of development tools.','["Domain_2::Tool_Design_MCP_Integration", "Domain_4::Prompt_Engineering_Structured_Output", "Scenario_4::Developer_Productivity"]','New',0,2.5,0,1783092989448,1783727583843,1783203558653,replace('**Tradução para português do Brasil:**\n\n**Pergunta:** Além do controle de navegador, quais capacidades o ecossistema MCP cobre?\n\n[ ] A - Apenas geração de texto, sem integrações externas.\n[ ] B - Apenas operações no sistema de arquivos local.\n[ ] C - Banco de dados, teste/monitoramento de API, sistema de arquivos, serviços em nuvem e automação de ferramentas de desenvolvimento.\n[ ] D - Exclusivamente controle de navegador via Playwright.','\n',char(10)),replace('**Explicação para adulto (tech lead):**\n\nA resposta correta é a alternativa **C**.\n\nO MCP (Model Context Protocol) é um protocolo aberto que padroniza a comunicação entre modelos de linguagem (LLMs) e fontes externas de dados e ferramentas. Ele foi projetado justamente para **ampliar as capacidades dos modelos** para além da geração de texto pura, conectando-os a sistemas reais.\n\nVamos analisar cada alternativa:\n\n- **Alternativa A ("Apenas geração de texto, sem integrações externas"):** Está INCORRETA. O MCP existe exatamente para o oposto: prover integrações externas. Sem elas, o modelo fica limitado ao conhecimento de treinamento e não consegue interagir com dados dinâmicos ou executar ações no mundo real.\n\n- **Alternativa B ("Apenas operações no sistema de arquivos local"):** Está INCORRETA. Embora operações de filesystem sejam uma das capacidades do MCP, o ecossistema não se limita a isso. Reduzir o MCP a filesystem é ignorar integrações com bancos de dados, APIs, cloud e dev tools.\n\n- **Alternativa C ("Banco de dados, API, filesystem, nuvem e automação de dev tools"):** CORRETA. Essa alternativa abrange corretamente os principais domínios de integração que o MCP suporta: consultas a bancos de dados (SQL/NoSQL), chamadas a APIs REST ou GraphQL (incluindo testing/monitoring), operações em sistema de arquivos, interação com serviços em nuvem (AWS, GCP, Azure) e automação de ferramentas de desenvolvimento (Git, CI/CD, linters, etc.).\n\n- **Alternativa D ("Exclusivamente controle de navegador via Playwright"):** Está INCORRETA. Controle de navegador é apenas uma das capacidades, e o enunciado já menciona "além do browser control", indicando que existem outras capacidades. Esta alternativa nega a existência das demais integrações.\n\n**Resumo para o tech lead:** O MCP não é um padrão para uma única categoria de ferramenta — é um framework de integração genérico que cobre múltiplos domínios. Escolher C é a única opção que reflete a amplitude real do ecossistema.','\n',char(10)),replace('**Explicação para uma criança de 10 anos:**\n\nPensa no MCP como se fosse um "cabo mágico" que conecta o cérebro do computador (o modelo de linguagem) com várias ferramentas que ele pode usar.\n\nO computador já sabe controlar o navegador (como abrir sites). Mas com o MCP, ele pode fazer muito mais!\n\nA resposta certa é a **letra C**, porque ela lista várias coisas legais que o MCP permite fazer:\n- Mexer em **banco de dados** (como organizar uma lista de filmes)\n- Testar e monitorar **APIs** (que são como "mensageiros" entre programas)\n- Trabalhar com **arquivos** do computador (como criar, ler e salvar documentos)\n- Usar serviços na **nuvem** (como o Google Drive ou o iCloud)\n- Automatizar **ferramentas de desenvolvedor** (como ajudar a programar mais rápido)\n\nAs outras alternativas estão erradas porque:\n- **A** diz que ele só gera texto, mas esquece que ele pode se conectar com coisas de fora.\n- **B** diz que ele só mexe em arquivos, mas ele faz muito mais.\n- **D** diz que ele só controla o navegador, mas a pergunta já disse que é *além* disso.\n\nOu seja: o MCP é como um canivete suíço digital — não serve só pra uma coisa, mas pra muitas!','\n',char(10)));
INSERT INTO cards VALUES('admin','card_1783092989468_eize0cus2',369,'Integrating Claude with a large service like GitHub, which production problem does MCP mitigate?',replace('Integrating Claude with a large service like GitHub, which production problem does MCP mitigate?\n\nIntegrating Claude with a large service like GitHub, which production problem does MCP mitigate?\n[Resposta correta: O MCP desloca a carga de definir e manter muitas tools para um server dedicado. A, C e D descrevem benefícios que o MCP não promete (latência, tratamento de erro e consumo de tokens).]\n\n[ ] A - It eliminates network latency on all calls.\n[ ] B - It transfers the burden of writing, testing and maintaining many tool schemas and functions to a dedicated MCP server.\n[ ] C - It removes the need to handle errors from API calls.\n[ ] D - It makes Claude run without consuming tokens.','\n',char(10)),'B - It transfers the burden of writing, testing and maintaining many tool schemas and functions to a dedicated MCP server.','["Domain_2::Tool_Design_MCP_Integration", "Domain_1::Agentic_Architecture_Orchestration", "Scenario_4::Developer_Productivity"]','New',0,2.5,0,1783092989468,1783727587410,1783203558653,replace('**Tradução para português do Brasil:**\n\nPergunta: "Integrando Claude com um serviço de grande porte como o GitHub, qual problema de produção o MCP resolve?"\n\nAlternativas:\n[ ] A - Elimina a latência de rede em todas as chamadas.\n[ ] B - Transfere a carga de escrever, testar e manter muitos schemas de tools e funções para um servidor MCP dedicado.\n[ ] C - Remove a necessidade de tratar erros de chamadas de API.\n[ ] D - Faz com que o Claude execute sem consumir tokens.','\n',char(10)),replace('**Explicação didática para um adulto tech lead:**\n\nO MCP (Model Context Protocol) é um protocolo aberto que padroniza a comunicação entre modelos de linguagem (como o Claude) e fontes externas de dados ou ferramentas (tools). Quando integramos um LLM a um serviço extenso como o GitHub, o número de endpoints, schemas, parâmetros e lógicas de negócio cresce rapidamente. Cada tool precisa ser definida com um schema JSON preciso, testada e mantida conforme a API do serviço evolui.\n\n**Alternativa correta: B**\n\nO principal problema de produção que o MCP mitiga é justamente a complexidade de gerenciar dezenas ou centenas de definições de tools diretamente no cliente (ex: no código que chama o Claude). Com o MCP, essas definições são delegadas a um **servidor MCP dedicado**, que expõe as tools de forma padronizada. Isso centraliza a lógica de definição, versionamento, testes e manutenção. O cliente (Claude) simplesmente descobre as tools disponíveis via o protocolo, sem precisar saber os detalhes internos de cada integração.\n\n**Por que as demais alternativas estão incorretas:**\n\n- **A** — O MCP não elimina latência de rede. Na verdade, ele adiciona uma camada extra de comunicação entre o cliente e o servidor MCP, o que pode até aumentar levemente a latência. A latência de rede continua existindo nas chamadas às APIs do serviço (ex: GitHub). O MCP é sobre organização e padronização, não sobre performance de rede.\n\n- **C** — O MCP não remove a necessidade de tratar erros. Pelo contrário, o servidor MCP ainda precisa lidar com erros de API, timeouts, rate limits, etc. O protocolo define como erros são reportados, mas não elimina a responsabilidade de tratá-los. O cliente também continua precisando lidar com falhas na comunicação com o servidor MCP.\n\n- **D** — O MCP não faz o modelo executar sem consumir tokens. Cada chamada ao Claude consome tokens de entrada (prompt + tools definitions) e saída (resposta). Embora o MCP possa reduzir o número de tokens necessários para descrever tools (já que elas são descobertas pelo protocolo em vez de embutidas no prompt), o consumo de tokens não é eliminado — ele apenas pode ser otimizado indiretamente.','\n',char(10)),replace('Imagine que você tem um amigo robô muito inteligente chamado Claude. Você quer que ele ajude você a usar o GitHub, que é como um baú enorme cheio de códigos e ferramentas.\n\nSem o MCP, você teria que escrever em um papel gigante todas as instruções de como usar cada ferramenta do GitHub — como criar um repositório, fazer um commit, listar issues... e toda vez que algo mudasse no GitHub, você teria que reescrever tudo. É um trabalhão!\n\nCom o MCP, é como se você tivesse um assistente separado, um "servidor MCP", que é o especialista em GitHub. Esse assistente cuida de todas as instruções complicadas. Quando o Claude precisa de algo, ele pergunta para esse assistente: "Qual ferramenta você tem para criar um repositório?" O assistente responde e o Claude usa. Se o GitHub mudar, só o assistente precisa atualizar as instruções — o Claude nem precisa se preocupar.\n\nEntão a resposta certa é a **letra B**: o MCP resolve o problema de ter que escrever, testar e manter um monte de instruções complicadas para cada ferramenta. Em vez disso, um servidor dedicado cuida disso tudo!\n\nAs outras opções estão erradas porque:\n- **A** — Não adianta fingir que o problema de demora da internet desaparece. A internet continua existindo.\n- **C** — Erros ainda acontecem (tipo quando o GitHub está fora do ar), e alguém precisa tratá-los.\n- **D** — O Claude sempre gasta "energia" (tokens) para pensar e responder. Não tem como escapar disso.','\n',char(10)));
INSERT INTO cards VALUES('admin','card_1783092989490_z4i0f4gso',370,'Which sentence correctly summarizes MCP at the architecture level?',replace('Which sentence correctly summarizes MCP at the architecture level?\n\nWhich sentence correctly summarizes MCP at the architecture level?\n[Resposta correta: É uma camada de comunicação que desloca definição e execução para servers especializados. A confunde MCP com tool use. C reduz a armazenamento. D restringe indevidamente o transporte.]\n\n[ ] A - A replacement for tool use that dispenses with any tool call.\n[ ] B - A communication layer that provides context and tools to Claude without your own integration code, shifting definition and execution to specialized MCP servers.\n[ ] C - A database that stores Claude''s responses.\n[ ] D - A protocol that only works via HTTP between clouds.','\n',char(10)),'B - A communication layer that provides context and tools to Claude without your own integration code, shifting definition and execution to specialized MCP servers.','["Domain_2::Tool_Design_MCP_Integration", "Scenario_4::Developer_Productivity"]','New',0,2.5,0,1783092989490,1783727591134,1783203558653,replace('**Tradução para português do Brasil:**\n\n**Pergunta:** Qual frase resume corretamente o MCP no nível de arquitetura?\n\n[ ] A - Uma substituição para tool use que dispensa qualquer chamada de ferramenta.\n[ ] B - Uma camada de comunicação que fornece contexto e ferramentas para Claude sem exigir seu próprio código de integração, deslocando definição e execução para servidores MCP especializados.\n[ ] C - Um banco de dados que armazena as respostas do Claude.\n[ ] D - Um protocolo que funciona apenas via HTTP entre nuvens.','\n',char(10)),replace('**Explicação para um adulto (tech lead):**\n\n**Resposta correta: Alternativa B**\n\nO MCP (Model Context Protocol) é, essencialmente, um protocolo de camada de comunicação que padroniza a forma como modelos de linguagem (como o Claude) interagem com fontes externas de dados, ferramentas e contexto. A alternativa B captura corretamente os dois aspectos fundamentais do MCP no nível arquitetural:\n\n1. **É uma camada de comunicação** — não substitui o mecanismo de tool use, mas o organiza de forma padronizada. O MCP define um "caminho" (ou pipeline) onde o modelo pode solicitar tools definidas em servidores remotos ou locais, sem que o desenvolvedor precise escrever código de integração customizado para cada fonte.\n\n2. **Desloca definição e execução para servidores especializados** — em vez de o cliente (ex.: Claude Desktop) conter toda a lógica de como cada ferramenta funciona, cada MCP server é responsável por implementar e expor suas próprias ferramentas e recursos. O modelo simplesmente recebe a lista de ferramentas disponíveis via MCP e as invoca conforme necessário.\n\n**Análise das alternativas incorretas:**\n\n- **Alternativa A** — "Uma substituição para tool use que dispensa qualquer chamada de ferramenta." Isso está errado porque MCP não substitui tool use; ele *padroniza* como o tool use acontece. O MCP ainda exige chamadas de ferramenta (tool calls), mas organiza o fluxo de forma consistente entre diferentes servidores. Quem confunde MCP com "substituto de tool use" está perdendo de vista que MCP é um protocolo de comunicação, não um mecanismo diferente de invocação.\n\n- **Alternativa C** — "Um banco de dados que armazena as respostas do Claude." Isso é um equívoco completo. MCP não é um armazenamento persistente; é um protocolo para troca de mensagens e contexto entre o modelo e servidores externos. Pode-se usar um banco de dados como parte de um MCP server, mas o protocolo em si não é um banco de dados.\n\n- **Alternativa D** — "Um protocolo que funciona apenas via HTTP entre nuvens." O MCP foi projetado para ser flexível quanto ao transporte: ele pode rodar via stdio (comunicação local por entrada/saída padrão) ou via SSE (Server-Sent Events) sobre HTTP, e não está restrito apenas a ambientes cloud. A alternativa D impõe uma restrição artificial que não existe no design do MCP.','\n',char(10)),replace('**Explicação para uma criança de 10 anos:**\n\nImagine que você está brincando de "detetive" com o Claude, um robô muito inteligente. Às vezes o Claude precisa de ajuda para resolver um mistério — ele precisa olhar num livro ou usar uma calculadora.\n\nO MCP é como um **telefone especial** que permite o Claude falar com vários ajudantes (os "servidores MCP") sem que você precise ensinar o Claude a usar cada telefone diferente. Cada ajudante já sabe fazer uma coisa específica: um sabe calcular, outro sabe procurar em livros, outro sabe desenhar.\n\nA alternativa **B** está certa porque diz que o MCP é esse "telefone" (camada de comunicação) que **leva contexto e ferramentas para o Claude** sem você precisar escrever código novo para cada ajudante. E o mais legal: a "definição e execução" — ou seja, quem sabe fazer cada tarefa — está nos ajudantes especializados, não no Claude.\n\n**Por que as outras estão erradas?**\n\n- **A** diz que MCP substitui o "tool use" (uso de ferramentas) e não precisa mais chamar ferramentas. Isso é falso! O MCP ainda usa ferramentas, só organiza melhor como elas são chamadas.\n\n- **C** diz que MCP é um banco de dados que guarda respostas do Claude. Não é! MCP não guarda nada, ele só ajuda o Claude a se comunicar com outros programas.\n\n- **D** diz que MCP funciona só via HTTP entre nuvens (internet). Mas MCP também funciona localmente, no seu computador, sem precisar de internet!','\n',char(10)));
INSERT INTO cards VALUES('admin','card_1783092989542_vpjre7ha2',371,'What does an MCP Server expose in a standardized way?',replace('What does an MCP Server expose in a standardized way?\n\nWhat does an MCP Server expose in a standardized way?\n[Resposta correta: O server expõe tools, prompts e resources de forma padronizada. A omite prompts e resources. C e D não são o que o server expõe.]\n\n[ ] A - Only tools, never prompts or resources.\n[ ] B - Tools, prompts and resources that give access to data or functionality of an external service.\n[ ] C - The language model and its weights.\n[ ] D - The end user''s authentication credentials.','\n',char(10)),'B - Tools, prompts and resources that give access to data or functionality of an external service.','["Domain_2::Tool_Design_MCP_Integration", "Scenario_1::Customer_Support_Agent"]','New',0,2.5,0,1783092989542,1783727595217,1783203558653,replace('**Tradução:**\n\nO que um Servidor MCP expõe de forma padronizada?\n\n[ ] A - Apenas ferramentas (tools), nunca prompts ou recursos (resources).\n[ ] B - Ferramentas (tools), prompts e recursos (resources) que fornecem acesso a dados ou funcionalidades de um serviço externo.\n[ ] C - O modelo de linguagem e seus pesos.\n[ ] D - As credenciais de autenticação do usuário final.','\n',char(10)),replace('**Explicação para Adulto (Tech Lead):**\n\nNo contexto do Model Context Protocol (MCP), o servidor (MCP Server) é responsável por expor capacidades e dados de forma padronizada para que clientes MCP (como agents, IDEs ou aplicações) possam interagir com eles de maneira consistente.\n\nA resposta correta é a **B**.\n\n- **Resposta correta (B)**: O MCP Server expõe três tipos de primitivas padronizadas: **tools** (ferramentas - operações que o modelo pode executar, como chamadas de API), **prompts** (modelos de mensagens pré-definidos que orientam o comportamento do modelo) e **resources** (recursos - dados ou conteúdo que podem ser lidos, como arquivos, registros de banco de dados ou resultados de queries). Essas primitivas permitem que o servidor forneça acesso a dados e funcionalidades de serviços externos de maneira segura e estruturada.\n\n- **Alternativa A (incorreta)**: Afirma que o servidor expõe apenas tools. Isso é falso, pois o MCP define explicitamente três primitivas (tools, prompts e resources) que o servidor pode expor.\n\n- **Alternativa C (incorreta)**: O MCP Server não expõe o modelo de linguagem nem seus pesos. O modelo de linguagem é tipicamente executado no cliente (ex: um LLM local ou remoto) e consome as primitivas expostas pelo servidor. Servir modelos e seus pesos está fora do escopo do MCP.\n\n- **Alternativa D (incorreta)**: Credenciais de autenticação do usuário final jamais devem ser expostas por um servidor MCP. Na verdade, o protocolo define mecanismos de segurança e autenticação separados (como transporte com autenticação) para proteger essas informações, e não como algo que o servidor expõe como recurso.','\n',char(10)),replace('Vamos imaginar que o MCP Server é como uma "caixa mágica" que se conecta a serviços da internet, como um banco de dados ou uma API de clima.\n\nPergunta: O que essa caixa mágica mostra para o lado de fora de um jeito que todo mundo entende?\n\nResposta correta: **Ela mostra ferramentas (coisas que você pode fazer), prompts (mensagens prontas para ajudar) e recursos (dados ou informações) de um serviço externo.**\n\nPor que as outras estão erradas?\n\n- **A**: Diz que a caixa só mostra ferramentas, mas ela também mostra prompts e recursos. É como dizer que uma caixa de ferramentas só tem martelo, mas ela também tem chave de fenda e alicate.\n- **C**: Diz que a caixa mostra o "cérebro" do robô (o modelo de linguagem e seus pesos). Não é verdade! O cérebro do robô fica em outro lugar, a caixa só ajuda o robô a se conectar com serviços de fora.\n- **D**: Diz que a caixa mostra as senhas do usuário. Isso é um perigo! A caixa nunca deve mostrar senhas, elas ficam guardadas em segredo.\n\nEntão, a caixa mágica (MCP Server) expõe ferramentas, prompts e recursos para conectar o robô a serviços externos.','\n',char(10)));
INSERT INTO cards VALUES('admin','card_1783092989562_893u2m7hc',372,'Which definition correctly separates MCP Client and MCP Server?',replace('Which definition correctly separates MCP Client and MCP Server?\n\nWhich definition correctly separates MCP Client and MCP Server?\n[Resposta correta: O Client consome e o Server expõe de forma padronizada. A inverte os papéis. B nega a distinção. D troca onde cada componente reside.]\n\n[ ] A - The Client is the interface to the external service and the Server consumes the tools.\n[ ] B - Client and Server are the same component with different names.\n[ ] C - The Client is the component of your application that consumes tools, prompts and resources; the Server is the specialized interface that exposes them in a standardized way.\n[ ] D - The Server runs in the application and the Client runs in the external service.','\n',char(10)),'C - The Client is the component of your application that consumes tools, prompts and resources; the Server is the specialized interface that exposes them in a standardized way.','["Domain_2::Tool_Design_MCP_Integration", "Scenario_4::Developer_Productivity"]','New',0,2.5,0,1783092989562,1783727598656,1783203558653,replace('**Tradução para português do Brasil:**\n\nQual definição separa corretamente MCP Client e MCP Server?\n\n[ ] A - O Client é a interface para o serviço externo e o Server consome as ferramentas.\n[ ] B - Client e Server são o mesmo componente com nomes diferentes.\n[ ] C - O Client é o componente da sua aplicação que consome ferramentas, prompts e recursos; o Server é a interface especializada que os expõe de forma padronizada.\n[ ] D - O Server roda na aplicação e o Client roda no serviço externo.','\n',char(10)),replace('**Explicação técnica para um adulto tech lead:**\n\nNo contexto do Model Context Protocol (MCP), temos uma arquitetura cliente-servidor bem definida:\n\n- **Alternativa correta (C)**: Reflete exatamente o papel de cada parte no MCP. O **Client** (cliente MCP) é o componente que roda dentro da aplicação do usuário (ex: um editor de código, um IDE, um agente de IA) e é responsável por **consumir** os recursos expostos — como ferramentas (tools), prompts e recursos (resources). O **Server** (servidor MCP) é um processo separado que **expõe** esses recursos de forma padronizada através do protocolo. O Server pode, por exemplo, expor ferramentas para acessar uma API externa, um banco de dados ou qualquer serviço. O Client descobre o que o Server oferece e faz chamadas a ele.\n\n- **Alternativa A (incorreta)**: Inverte os papéis. Ela diz que o Client é a interface para o serviço externo e que o Server consome as ferramentas. Na verdade, é o Server que atua como interface especializada (ponte) para o serviço externo, e o Client é quem consome. Portanto, há uma inversão completa das responsabilidades.\n\n- **Alternativa B (incorreta)**: Nega a distinção entre Client e Server, afirmando que são o mesmo componente com nomes diferentes. Isso é falso: no MCP, Client e Server são processos distintos com responsabilidades diferentes. O Client inicia a conexão, descobre capacidades e faz requisições; o Server atende a essas requisições expondo seus recursos.\n\n- **Alternativa D (incorreta)**: Troca onde cada componente reside. Afirma que o Server roda na aplicação e o Client roda no serviço externo. Na realidade, o Client roda na aplicação (ex: dentro do editor de código ou agente) e o Server é um processo separado que pode rodar localmente ou remotamente, atuando como ponte para serviços externos. A localização está invertida.\n\nPortanto, a definição que separa corretamente os papéis é a alternativa C.','\n',char(10)),replace('Imagine que você tem um restaurante (a sua aplicação). O **Client** é o garçom que fica na sua mesa e **consome** a comida — ele pede os pratos, as bebidas e a sobremesa. O **Server** é a cozinha, que **prepara e entrega** os pratos de um jeito padronizado (em pratos bonitos, com talheres certinhos). O garçom nunca cozinha, e a cozinha nunca vai até a mesa do cliente. Cada um tem seu trabalho.\n\nA alternativa C diz isso certinho: o Client (garçom) consome e o Server (cozinha) expõe os recursos de forma padronizada.\n\nA alternativa A está errada porque troca os papéis — colocou o Client como cozinha e o Server como garçom.\nA alternativa B está errada porque diz que o garçom e a cozinha são a mesma coisa, mas não são.\nA alternativa D está errada porque diz que a cozinha fica na mesa do cliente e o garçom fica na cozinha — tudo trocado!\n\nEntão a resposta certa é a C, que explica direitinho quem faz o quê.','\n',char(10)));
INSERT INTO cards VALUES('admin','card_1783092989583_0scw12ykk',373,'A cloud provider wants agents to use its APIs easily.',replace('A cloud provider wants agents to use its APIs easily.\n\nA cloud provider wants agents to use its APIs easily. Which MCP pattern applies?\n[Resposta correta: O provedor publica um MCP Server oficial com as tools prontas. A troca server por client. C e D contrariam o fato de que o provedor pode e costuma autorar o próprio server.]\n\n[ ] A - The provider publishes an official MCP Client that each agent must incorporate.\n[ ] B - The provider publishes an official MCP Server with the tools of its services already defined.\n[ ] C - The provider delegates the creation of the server to Anthropic.\n[ ] D - The provider forces each client to write its own server from scratch.','\n',char(10)),'B - The provider publishes an official MCP Server with the tools of its services already defined.','["Domain_2::Tool_Design_MCP_Integration", "Scenario_1::Customer_Support_Agent"]','New',0,2.5,0,1783092989583,1783727602341,1783203558653,replace('**[TRADUÇÃO]**\n\nUm provedor de nuvem quer que agentes usem suas APIs facilmente. Qual padrão MCP se aplica?\n\n[ ] A - O provedor publica um Cliente MCP oficial que cada agente deve incorporar.\n[ ] B - O provedor publica um Servidor MCP oficial com as ferramentas de seus serviços já definidas.\n[ ] C - O provedor delega a criação do servidor para a Anthropic.\n[ ] D - O provedor força cada cliente a escrever seu próprio servidor do zero.','\n',char(10)),replace('**[EXPLICAÇÃO PARA ADULTO TECH LEAD]**\n\n**Resposta correta: B**\n\nNo contexto do Model Context Protocol (MCP), o padrão de arquitetura mais adequado para um provedor de nuvem que deseja expor suas APIs facilmente para agentes de IA é que o próprio provedor publique um **Servidor MCP oficial**. Isso segue o princípio de design do MCP, onde:\n\n- **Quem conhece melhor a API** é o provedor do serviço (nuvem). Ele tem domínio sobre a semântica, autenticação, rate limiting, versões e documentação dos endpoints.\n- **O servidor MCP** expõe tools (ferramentas) que os agentes (clientes MCP) podem invocar. O cliente MCP descobre e chama as tools expostas pelo servidor — não o contrário.\n- **O provedor publica o servidor** e o disponibiliza (ex.: via npm, Docker, ou URL pública). Cada agente ou aplicação cliente apenas se conecta a esse servidor.\n\n**Análise das alternativas incorretas:**\n\n- **Alternativa A**: Inverte os papéis. O cliente MCP é quem consome as tools; não faz sentido o provedor publicar um cliente que cada agente "incorpore". Cada agente pode ter seu próprio cliente MCP (ex.: SDKs como o `@modelcontextprotocol/sdk`), e eles se conectam ao servidor do provedor.\n- **Alternativa C**: A Anthropic criou o protocolo MCP, mas não é responsável por implementar servidores MCP de terceiros. Delegar a criação a ela seria antieconômico, cria gargalo e contraria a natureza descentralizada e aberta do protocolo.\n- **Alternativa D**: Forçar cada cliente a escrever seu próprio servidor do zero derrota o propósito do MCP, que é justamente padronizar e reduzir o trabalho de integração. Seria um desperdício de esforço e altamente propenso a erros e inconsistências.','\n',char(10)),replace('**[EXPLICAÇÃO PARA CRIANÇA DE 10 ANOS]**\n\nImagine que a nuvem é uma grande loja de brinquedos, e os agentes (programas de computador) são crianças que querem brincar com os brinquedos dessa loja.\n\nA loja quer que as crianças consigam brincar facilmente. Para isso, ela monta um **balcão de brinquedos** pronto, com todos os brinquedos organizados e instruções de como usar cada um. Esse balcão é o "Servidor MCP". As crianças só precisam chegar e pegar o que querem — elas não precisam construir o balcão nem os brinquedos.\n\nA alternativa B diz exatamente isso: o provedor da nuvem (a loja) cria o servidor (o balcão) com todas as ferramentas prontas. As outras opções não fazem sentido:\n\n- **A** seria tipo a loja obrigar cada criança a construir sua própria lojinha dentro de casa — trabalhoso e desnecessário.\n- **C** seria a loja pedir para outra empresa fazer o balcão, sendo que a loja conhece melhor seus próprios brinquedos.\n- **D** seria cada criança ter que construir o balcão do zero, o que é muito mais difícil e demorado.\n\nEntão a resposta certa é a **B**: o provedor publica o servidor MCP oficial, e as crianças (agentes) só usam ele.','\n',char(10)));
INSERT INTO cards VALUES('admin','card_1783092989604_gnqwc6ytc',374,'What is the practical difference between using MCP and calling the API directly?',replace('What is the practical difference between using MCP and calling the API directly?\n\nWhat is the practical difference between using MCP and calling the API directly?\n[Resposta correta: Com MCP as definições já vêm prontas, poupando o trabalho de autoria. A inverte a situação. B nega a economia de implementação. D inventa uma restrição de protocolo.]\n\n[ ] A - With MCP you author all schemas manually and with the direct API they come ready.\n[ ] B - There is no difference, both require the same implementation work.\n[ ] C - With MCP the schemas and functions come ready; calling the API directly, you author all the tool definitions.\n[ ] D - MCP only works with GraphQL APIs and the direct call only with REST.','\n',char(10)),'C - With MCP the schemas and functions come ready; calling the API directly, you author all the tool definitions.','["Domain_2::Tool_Design_MCP_Integration", "Domain_4::Prompt_Engineering_Structured_Output", "ForaDoCenario"]','New',0,2.5,0,1783092989604,1783727606129,1783203558653,replace('**Tradução para português do Brasil:**\n\nQual é a diferença prática entre usar MCP e chamar a API diretamente?\n\n[ ] A - Com MCP você cria todos os schemas manualmente e com a API direta eles vêm prontos.\n[ ] B - Não há diferença, ambos exigem o mesmo trabalho de implementação.\n[ ] C - Com MCP os schemas e funções vêm prontos; chamando a API diretamente, você cria todas as definições das ferramentas.\n[ ] D - MCP funciona apenas com APIs GraphQL e a chamada direta apenas com REST.','\n',char(10)),replace('**Explicação para um adulto tech lead:**\n\nMCP (Model Context Protocol) é um protocolo padronizado que permite que modelos de linguagem (LLMs) descubram e interajam com ferramentas (tools) de forma dinâmica. Quando você usa MCP, o servidor expõe schemas, funções e definições de ferramentas já estruturadas seguindo o protocolo. O cliente MCP (ex.: um agente LLM) consome essas definições prontas — ele sabe exatamente quais parâmetros passar, quais endpoints ou operações estão disponíveis, etc., sem precisar que o desenvolvedor escreva manualmente cada definição de tool.\n\nJá ao chamar a API diretamente (seja REST, GraphQL, gRPC ou qualquer outro protocolo), o desenvolvedor precisa "autorar" manualmente todas as definições das ferramentas: criar schemas JSON, descrever endpoints, especificar parâmetros, tipos de retorno, autenticação, etc. Não há um mecanismo padronizado de descoberta e integração automática como no MCP.\n\n**Análise das alternativas:**\n\n- **Alternativa A (incorreta):** Ela inverte a situação. Na verdade, com MCP os schemas vêm prontos (o servidor MCP os expõe); com API direta você que cria tudo manualmente.\n- **Alternativa B (incorreta):** Há diferença sim. MCP reduz significativamente o trabalho de implementação ao fornecer um contrato padronizado e descoberta automática de ferramentas.\n- **Alternativa C (correta):** Descreve precisamente a diferença prática: MCP oferece schemas e funções prontos (o desenvolvedor consome definições já expostas pelo servidor MCP), enquanto na chamada direta à API o desenvolvedor precisa escrever manualmente todas as definições de tool.\n- **Alternativa D (incorreta):** MCP não é restrito a GraphQL, nem a chamada direta a REST. MCP é um protocolo agnóstico de transporte — pode usar HTTP/JSON, WebSockets, stdio, etc. A chamada direta à API pode usar qualquer estilo de arquitetura (REST, GraphQL, SOAP, RPC). A alternativa inventa uma restrição que não existe.','\n',char(10)),replace('Imagine que você está montando um robô de brinquedo. Se você comprar um kit MCP, ele já vem com as peças certas e um manual explicando como tudo se encaixa — você só precisa conectar. Agora, se você chama a API diretamente, é como se você tivesse que desenhar cada peça do zero, escrever as instruções e montar tudo sozinho. Dá muito mais trabalho!\n\nA alternativa C está certa porque ela diz que com MCP os schemas (que são como as "instruções" do que o robô pode fazer) já vêm prontos, e quando você chama a API diretamente, você precisa escrever todas essas instruções manualmente.\n\nAs outras opções estão erradas: a A diz o contrário do que é verdade, a B fala que não tem diferença (mas tem, sim!), e a D inventa uma história de que MCP só funciona com um tipo de API e chamada direta com outro — isso não é verdade.','\n',char(10)));
INSERT INTO cards VALUES('admin','card_1783092989627_y38fdqkd9',375,'Why is it incorrect to state that MCP and tool use are synonyms?',replace('Why is it incorrect to state that MCP and tool use are synonyms?\n\nWhy is it incorrect to state that MCP and tool use are synonyms?\n[Resposta correta: MCP entrega a implementação pronta e o tool use é o mecanismo de chamada, sendo os dois complementares. A e C tratam MCP como substituto do tool use. D confunde tool use com resources.]\n\n[ ] A - Because tool use does not exist when MCP is used.\n[ ] B - Because MCP provides the schemas and functions already implemented, while tool use is how Claude calls those tools; they are complementary.\n[ ] C - Because MCP completely replaces tool use in production.\n[ ] D - Because tool use is only a subset of resources.','\n',char(10)),'[ ] B - Because MCP provides the schemas and functions already implemented, while tool use is how Claude calls those tools; they are complementary.','["Domain_2::Tool_Design_MCP_Integration", "Domain_4::Prompt_Engineering_Structured_Output", "ForaDoCenario"]','New',0,2.5,0,1783092989627,1783727609295,1783203558653,replace('**Tradução para português do Brasil:**\n\nPor que é incorreto afirmar que MCP e tool use são sinônimos?\n\n[ ] A - Porque tool use não existe quando MCP é usado.\n[ ] B - Porque o MCP fornece os schemas e funções já implementados, enquanto tool use é como Claude chama essas ferramentas; eles são complementares.\n[ ] C - Porque o MCP substitui completamente o tool use em produção.\n[ ] D - Porque tool use é apenas um subconjunto de resources.','\n',char(10)),replace('**Explicação para adulto (tech lead):**\n\nA alternativa correta é a **B**. Vamos analisar tecnicamente:\n\n- **MCP (Model Context Protocol)** é um protocolo padronizado que define como um servidor expõe ferramentas (tools), recursos (resources) e prompts para o cliente (ex: Claude Desktop). Ele entrega a *implementação pronta*: schemas JSON, funções executáveis, etc.\n\n- **Tool use** é o mecanismo interno do modelo (Claude) para *invocar* essas ferramentas. Quando o modelo decide que precisa de uma ferramenta, ele gera uma chamada de função (function calling) — isso é tool use.\n\nEles **não são sinônimos** porque atuam em camadas diferentes da arquitetura: MCP é o *provedor/definição* das ferramentas; tool use é o *mecanismo de chamada* pelo modelo. São complementares: MCP disponibiliza, tool use consome.\n\n**Análise das alternativas incorretas:**\n\n- **A** — Falsa. Tool use continua existindo mesmo com MCP; é como Claude chama as ferramentas expostas via MCP.\n- **C** — Falsa. MCP não substitui tool use; ele apenas padroniza a exposição das ferramentas. O mecanismo de chamada (tool use) ainda é necessário.\n- **D** — Falsa. Tool use não é um subconjunto de resources. Resources são dados/arquivos expostos via MCP, enquanto tool use é o mecanismo de invocação de funções. São conceitos distintos.','\n',char(10)),replace('Imagine que você tem um controle de videogame cheio de botões. \n\n- **MCP** é como o manual que explica o que cada botão faz — ele mostra as funções prontas para usar.\n- **Tool use** é você apertar os botões para o personagem do jogo agir.\n\nEles não são a mesma coisa! Um é o manual (MCP) e o outro é apertar os botões (tool use). Os dois são necessários juntos, não um substituindo o outro.\n\nAs respostas erradas dizem coisas como "tool use não existe quando MCP é usado" (claro que existe, você ainda precisa apertar os botões!) ou "MCP substitui tool use" (não, um precisa do outro). E uma resposta confunde tool use com "resources", que são outros tipos de informação que o MCP pode dar, como arquivos ou dados.','\n',char(10)));
INSERT INTO cards VALUES('admin','card_1783092989649_vca7fna88',376,'What is the most common transport setup in MCP?',replace('What is the most common transport setup in MCP?\n\nWhat is the most common transport setup in MCP?\n[Resposta correta: O setup mais comum é client e server na mesma máquina via stdio. A e B assumem transportes de rede como padrão, quando são apenas opções. D descreve um mecanismo que não é o comum.]\n\n[ ] A - HTTP between distinct machines in different clouds.\n[ ] B - WebSockets mandatory for any communication.\n[ ] C - Client and server on the same machine via standard input/output (stdio).\n[ ] D - A message queue managed externally.','\n',char(10)),'C - Client and server on the same machine via standard input/output (stdio).','["Domain_2::Tool_Design_MCP_Integration", "Scenario_4::Developer_Productivity"]','New',0,2.5,0,1783092989649,1783727612843,1783203558653,replace('**Tradução para português do Brasil:**\n\nPergunta: Qual é a configuração de transporte mais comum no MCP?\n\nAlternativas:\n[ ] A - HTTP entre máquinas distintas em nuvens diferentes.\n[ ] B - WebSockets obrigatório para qualquer comunicação.\n[ ] C - Cliente e servidor na mesma máquina via entrada/saída padrão (stdio).\n[ ] D - Uma fila de mensagens gerenciada externamente.','\n',char(10)),replace('**Explicação didática para um adulto tech lead:**\n\nNo **Model Context Protocol (MCP)**, o transporte define como cliente e servidor se comunicam. A resposta correta é a **alternativa C**.\n\n**Por que C está correta?**\nO setup mais comum no MCP é ter o cliente e o servidor executando no mesmo processo ou na mesma máquina, comunicando-se via **standard input/output (stdio)**. Isso ocorre porque o MCP foi projetado inicialmente para ser leve e de baixa latência, ideal para integrações locais — por exemplo, um editor de código (cliente) se comunicando com um servidor MCP que oferece ferramentas de análise de código. O stdio oferece simplicidade, sem necessidade de configuração de rede, descoberta de serviços ou gerenciamento de conexões.\n\n**Por que as demais estão erradas:**\n- **A (HTTP entre máquinas distintas):** Embora o MCP possa, em teoria, ser usado sobre HTTP, essa não é a configuração mais comum. Além disso, HTTP entre máquinas distintas exige configuração de rede, autenticação, latência maior, o que não é o cenário típico.\n- **B (WebSockets obrigatório):** WebSockets são um transporte possível, mas não obrigatório. O MCP não exige WebSockets; na verdade, o transporte mais comum (stdio) nem usa WebSockets. A alternativa B sugere obrigatoriedade, o que é incorreto.\n- **D (Fila de mensagens gerenciada externamente):** Filas de mensagens (como RabbitMQ, Kafka) não são o transporte padrão do MCP. Elas adicionariam complexidade desnecessária para o caso de uso típico (comunicação local entre processos). O MCP não define fila externa como transporte comum.','\n',char(10)),replace('Imagine que você tem dois amiguinhos: um é o **cliente** (que pede coisas) e o outro é o **servidor** (que responde). No MCP, a forma mais comum deles conversarem é estando na **mesma casa**, usando um **canudo** (stdio) para se falar — um sopra a mensagem e o outro escuta.\n\nA letra **C** está certa porque é assim que geralmente funciona: os dois estão juntinhos, sem precisar de internet ou coisas complicadas.\n\nAs outras opções estão erradas porque:\n- **A** diz que eles se falam pela internet, em nuvens diferentes — isso é possível, mas não é o mais comum.\n- **B** diz que eles são obrigados a usar um tipo especial de ligação chamada WebSocket — mas não, eles podem usar o canudo mesmo.\n- **D** diz que eles usam uma "fila" tipo mercadinho onde alguém entrega os recados — isso existe, mas não é o jeito mais comum deles se falarem no MCP.','\n',char(10)));
INSERT INTO cards VALUES('admin','card_1783092989670_lbg347ien',377,'Which messages does the client use to discover a server''s tools?',replace('Which messages does the client use to discover a server''s tools?\n\nWhich messages does the client use to discover a server''s tools?\n[Resposta correta: ListToolsRequest/Result descobre as tools disponíveis. A executa uma tool, não descobre. C é para resources. D trata da inicialização, não da descoberta de tools.]\n\n[ ] A - CallToolRequest / CallToolResult.\n[ ] B - ListToolsRequest / ListToolsResult.\n[ ] C - ReadResourceRequest / ReadResourceResult.\n[ ] D - InitializeRequest / InitializeResult.','\n',char(10)),'B - ListToolsRequest / ListToolsResult.','["Domain_2::Tool_Design_MCP_Integration", "Domain_4::Prompt_Engineering_Structured_Output", "Scenario_6::Structured_Data_Extraction"]','New',0,2.5,0,1783092989670,1783727616818,1783203558653,replace('**TRADUÇÃO (pt-BR):**\n\nQuais mensagens o cliente usa para descobrir as ferramentas (tools) de um servidor?\n\n[ ] A - CallToolRequest / CallToolResult.\n[ ] B - ListToolsRequest / ListToolsResult.\n[ ] C - ReadResourceRequest / ReadResourceResult.\n[ ] D - InitializeRequest / InitializeResult.','\n',char(10)),replace('**EXPLICAÇÃO PARA UM TECH LEAD (adulto):**\n\nA pergunta trata do mecanismo de descoberta de ferramentas (tool discovery) no protocolo MCP (Model Context Protocol). No MCP, o cliente precisa primeiro saber quais ferramentas o servidor disponibiliza antes de poder invocá-las. O par de mensagens responsável por essa descoberta é **ListToolsRequest / ListToolsResult**.\n\n- **Alternativa A (CallToolRequest / CallToolResult):** Este par é usado para *executar* uma ferramenta específica, não para descobri-la. Pressupõe que o cliente já sabe o nome e os parâmetros da ferramenta. Portanto, está incorreta para o propósito de descoberta.\n\n- **Alternativa B (ListToolsRequest / ListToolsResult):** Correta. O cliente envia um `ListToolsRequest` para o servidor, que responde com um `ListToolsResult` contendo a lista de ferramentas disponíveis (nome, descrição, esquema de entrada, etc.). É o equivalente funcional a um "endpoint de descoberta" ou "introspection" no contexto MCP.\n\n- **Alternativa C (ReadResourceRequest / ReadResourceResult):** Este par pertence ao sistema de *recursos* (resources) do MCP, que lida com dados estáticos ou dinâmicos (como arquivos, conteúdo de banco de dados, etc.). Não tem relação com a descoberta de ferramentas.\n\n- **Alternativa D (InitializeRequest / InitializeResult):** Esta mensagem faz parte do handshake inicial de conexão entre cliente e servidor. Embora seja a primeira troca de mensagens, seu propósito é negociar versão do protocolo, capacidades (capabilities) e autenticação — e não listar ferramentas específicas. A descoberta de fato das ferramentas ocorre em um momento posterior, via ListTools.\n\nPortanto, a resposta correta é a **alternativa B**.','\n',char(10)),replace('Imagine que você tem um robô assistente (o servidor) que pode fazer várias coisas: desenhar, calcular, traduzir textos. Mas você, que é o cliente, não sabe o que ele sabe fazer. Para descobrir, você precisa perguntar: "Quais são suas ferramentas?" — e o robô te responde com uma lista.\n\nÉ exatamente isso que o **ListToolsRequest** faz: você pergunta "quais ferramentas você tem?" e o servidor responde com **ListToolsResult** ("aqui estão elas!"). As outras alternativas são para outras coisas:\n\n- **A** é para pedir para o robô *usar* uma ferramenta (executar), não para descobrir quais existem.\n- **C** é para pedir informações ou arquivos (como ler um livro), não para descobrir ferramentas.\n- **D** é para o "oi, tudo bem?" inicial entre você e o robô, para ver se vocês se entendem.\n\nEntão, a resposta certa é a **letra B**, porque é assim que o cliente descobre quais ferramentas o servidor oferece.','\n',char(10)));
INSERT INTO cards VALUES('admin','card_1783092989692_74lkg0kiw',378,'Which messages execute a specific tool with arguments?',replace('Which messages execute a specific tool with arguments?\n\nWhich messages execute a specific tool with arguments?\n[Resposta correta: CallToolRequest/Result executa a tool com os argumentos. A apenas lista as tools. C é para resources. D usa nomes inexistentes no protocolo.]\n\n[ ] A - ListToolsRequest / ListToolsResult.\n[ ] B - CallToolRequest / CallToolResult.\n[ ] C - ReadResourceRequest / ReadResourceResult.\n[ ] D - RunToolRequest / RunToolResult.','\n',char(10)),'B - CallToolRequest / CallToolResult.','["Domain_2::Tool_Design_MCP_Integration", "ForaDoCenario"]','New',0,2.5,0,1783092989692,1783727620329,1783203558653,replace('**Tradução da pergunta e alternativas para português do Brasil:**\n\n**Pergunta:** Quais mensagens executam uma ferramenta específica com argumentos?\n\n[ ] A - ListToolsRequest / ListToolsResult.\n[ ] B - CallToolRequest / CallToolResult.\n[ ] C - ReadResourceRequest / ReadResourceResult.\n[ ] D - RunToolRequest / RunToolResult.','\n',char(10)),replace('**Explicação didática para um adulto tech lead:**\n\nA pergunta se insere no contexto do protocolo MCP (Model Context Protocol), que define um conjunto padronizado de mensagens para comunicação entre clientes (como LLMs) e servidores que expõem ferramentas, recursos e prompts.\n\nNo MCP, a execução de uma ferramenta com argumentos específicos é feita através do par **CallToolRequest** (enviado pelo cliente) e **CallToolResult** (resposta do servidor). O `CallToolRequest` contém o nome da ferramenta a ser chamada e um objeto `arguments` com os parâmetros necessários. O `CallToolResult` retorna o resultado da execução, que pode incluir conteúdo textual, imagens, ou outros tipos de dados, além de indicadores de erro ou sucesso.\n\nAnalisando as alternativas incorretas:\n\n- **Alternativa A (ListToolsRequest / ListToolsResult):** Este par é usado para *listar* as ferramentas disponíveis no servidor, não para executá-las. O `ListToolsRequest` retorna um array com a descrição de cada ferramenta (nome, schema de entrada, etc.), mas não invoca nenhuma delas com argumentos.\n\n- **Alternativa C (ReadResourceRequest / ReadResourceResult):** Este par pertence ao domínio de *recursos* (resources) do MCP, não de ferramentas (tools). Recursos são conteúdos estáticos ou dinâmicos que podem ser lidos (como arquivos, URIs, etc.), mas não são executáveis com argumentos como ferramentas.\n\n- **Alternativa D (RunToolRequest / RunToolResult):** Estes nomes não existem no protocolo MCP. O protocolo padroniza exatamente "CallToolRequest" e "CallToolResult" como os tipos de mensagens para chamada de ferramentas. "RunTool" é uma nomenclatura inventada que não corresponde à especificação oficial.\n\nPortanto, a resposta correta é a alternativa B.','\n',char(10)),replace('Imagine que você tem um robô que pode fazer várias coisas, como desenhar, somar números ou contar piadas. Para o robô fazer alguma coisa, você precisa pedir de um jeito certo.\n\nPergunta: "Quais mensagens fazem uma ferramenta específica funcionar com argumentos?"\n\nAs alternativas são nomes de "pedidos" e "respostas" que o robô entende.\n\n- A: "ListToolsRequest" é como se você pedisse: "Me mostre a lista de tudo que você sabe fazer." O robô só mostra a lista, não faz nada.\n- B: "CallToolRequest" é como se você dissesse: "Robô, faça a ferramenta ''somar'' com os números 2 e 3!" Aí o robô executa a soma e responde com "CallToolResult". É o único que realmente executa uma ferramenta.\n- C: "ReadResourceRequest" é como se você pedisse para o robô ler um livro ou um arquivo. Ele não executa ferramentas, só lê coisas prontas.\n- D: "RunToolRequest" parece um nome inventado, como se você chamasse o robô de "Rex" em vez de "Robô". O robô não entende esse nome.\n\nEntão, a resposta certa é a B, porque só ela é o pedido certo para fazer o robô executar uma ferramenta de verdade com os argumentos que você der.','\n',char(10)));
INSERT INTO cards VALUES('admin','card_1783092989714_6qs2lu2mu',379,'What is the core responsibility of the MCP Client?',replace('What is the core responsibility of the MCP Client?\n\nWhat is the core responsibility of the MCP Client?\n[Resposta correta: O client é a ponte que abstrai protocolo e mensagens. A é responsabilidade do server. C não é o papel do client. D contorna o server, o que não corresponde ao fluxo real.]\n\n[ ] A - Implement the logic of the tools that will be executed.\n[ ] B - Serve as the bridge between your server and the MCP servers, abstracting protocol and message exchange.\n[ ] C - Store the resources in permanent cache.\n[ ] D - Directly call the external service, dispensing with the server.','\n',char(10)),'[ ] B - Serve as the bridge between your server and the MCP servers, abstracting protocol and message exchange.','["ForaDosDominios", "ForaDoCenario"]','New',0,2.5,0,1783092989714,1783727623544,1783203558653,replace('**Tradução para português do Brasil:**\n\nQual é a responsabilidade principal do Cliente MCP?\n\n[ ] A - Implementar a lógica das ferramentas que serão executadas.\n[ ] B - Servir como a ponte entre o seu servidor e os servidores MCP, abstraindo o protocolo e a troca de mensagens.\n[ ] C - Armazenar os recursos em cache permanente.\n[ ] D - Chamar diretamente o serviço externo, dispensando o servidor.','\n',char(10)),replace('**Explicação didática para um adulto tech lead:**\n\nNo contexto do **Model Context Protocol (MCP)**, o cliente MCP (MCP Client) tem um papel arquitetural bem definido. Ele atua como uma **camada de abstração** que gerencia a comunicação entre sua aplicação (ou "seu servidor", no sentido de servidor da aplicação host) e os servidores MCP que expõem ferramentas, recursos e prompts.\n\nVamos analisar cada alternativa:\n\n- **✅ B - Serve as the bridge between your server and the MCP servers, abstracting protocol and message exchange.**  \n  **Correta.** O MCP Client é responsável por estabelecer e gerenciar a conexão (transporte), serializar/desserializar mensagens no formato do protocolo (JSON-RPC), gerenciar solicitações e respostas, e expor uma interface limpa para a camada superior da aplicação. Ele isola o desenvolvedor dos detalhes de baixo nível do protocolo, como handshake, negotiação de capabilities, lifecycle das sessões, etc. Sem ele, o desenvolvedor teria que implementar manualmente toda a comunicação com cada servidor MCP.\n\n- **❌ A - Implement the logic of the tools that will be executed.**  \n  **Incorreta.** A lógica de negócio e implementação das ferramentas (tools) é responsabilidade do **servidor MCP (MCP Server)**. O cliente apenas descobre, invoca e gerencia as chamadas às ferramentas, mas não contém a implementação delas. Confundiria os papéis: o server provê os recursos; o client consome.\n\n- **❌ C - Store the resources in permanent cache.**  \n  **Incorreta.** Embora o MCP Client possa implementar estratégias de cache para evitar requisições desnecessárias (como cache de listagem de recursos), o armazenamento permanente de recursos não é sua responsabilidade principal. Recursos são dados expostos pelo servidor MCP e podem ser cacheados temporariamente, mas "permanent cache" sugere persistência indefinida, o que foge ao escopo do cliente. Além disso, a responsabilidade core é a abstração da comunicação, não o gerenciamento de cache.\n\n- **❌ D - Directly call the external service, dispensing with the server.**  \n  **Incorreta.** Isso quebraria completamente a arquitetura do MCP. O cliente MCP não chama serviços externos diretamente; ele sempre passa pelo servidor MCP, que é quem sabe como acessar os sistemas externos (APIs, bancos de dados, etc.). "Dispensar o servidor" viola o padrão de design do protocolo, onde o servidor é o provedor dos recursos e o cliente é o consumidor. Chamadas diretas sem intermédio do servidor fogem completamente ao fluxo definido.','\n',char(10)),replace('**Explicação para uma criança de 10 anos:**\n\nImagina que você quer brincar com um boneco que está dentro de uma caixa fechada. Você não pode pegar o boneco diretamente porque a caixa é muito complicada de abrir. Então, você tem um amigo que sabe exatamente como abrir a caixa e pegar o boneco para você.\n\nNo MCP, o **MCP Client** é esse amigo! Ele é a "ponte" entre você (seu programa) e a caixa (o servidor MCP). O trabalho dele é conversar com a caixa usando uma "língua secreta" (o protocolo) para pedir as coisas que você quer (ferramentas, informações) e trazer de volta para você de um jeito fácil de entender.\n\nAs outras opções estão erradas porque:\n- **A** - Quem inventa os brinquedos e sabe como eles funcionam é o servidor, não o cliente.\n- **C** - Guardar os brinquedos para sempre não é trabalho do cliente; ele só busca e entrega.\n- **D** - O cliente não pode pular a caixa e ir direto buscar o boneco; ele precisa do amigo que sabe abrir a caixa (o servidor).\n\nEntão, a resposta certa é a **B**: o cliente MCP serve como a ponte entre você e os servidores MCP, cuidando de toda a conversa complicada para você.','\n',char(10)));
INSERT INTO cards VALUES('admin','card_1783092989736_juulmn7un',380,'What is the correct order of discovery and execution when answering "what repositories do I have?',replace('What is the correct order of discovery and execution when answering "what repositories do I have?\n\nWhat is the correct order of discovery and execution when answering "what repositories do I have?"\n[Resposta correta: A ordem é descobrir (ListTools) e então executar (CallTool), com o Claude no meio decidindo. A inverte a sequência. C ignora a descoberta e execução. D trata os dois pares como simultâneos, o que não corresponde ao fluxo.]\n\n[ ] A - CallToolRequest first, then ListToolsRequest to confirm.\n[ ] B - ListToolsRequest/Result, sending query and tools to Claude, decision to call the tool, CallToolRequest/Result, return to Claude and final response.\n[ ] C - Claude responds directly without discovering or executing tools.\n[ ] D - CallToolRequest and ListToolsRequest happen simultaneously before anything is sent to Claude.','\n',char(10)),'B - ListToolsRequest/Result, sending query and tools to Claude, decision to call the tool, CallToolRequest/Result, return to Claude and final response.','["Domain_2::Tool_Design_MCP_Integration", "Domain_4::Prompt_Engineering_Structured_Output", "Scenario_4::Developer_Productivity"]','New',0,2.5,0,1783092989736,1783727627130,1783203558653,replace('**Tradução para português do Brasil:**\n\nPergunta: Qual é a ordem correta de descoberta e execução ao responder "quais repositórios eu tenho?"\n\n[ ] A - CallToolRequest primeiro, depois ListToolsRequest para confirmar.\n[ ] B - ListToolsRequest/Result, envio da consulta e ferramentas para o Claude, decisão de chamar a ferramenta, CallToolRequest/Result, retorno ao Claude e resposta final.\n[ ] C - Claude responde diretamente sem descobrir ou executar ferramentas.\n[ ] D - CallToolRequest e ListToolsRequest acontecem simultaneamente antes que qualquer coisa seja enviada ao Claude.','\n',char(10)),replace('**Explicação para um adulto tech lead:**\n\nO fluxo correto do protocolo MCP (Model Context Protocol) segue uma sequência bem definida: primeiro ocorre a **descoberta** das ferramentas disponíveis (ListToolsRequest/Result), depois o sistema envia a consulta do usuário juntamente com a descrição das ferramentas para o modelo Claude. O Claude então **decide** se deve chamar alguma ferramenta e, se sim, qual. A partir dessa decisão, o sistema executa a ferramenta escolhida (CallToolRequest/Result). O resultado retorna ao Claude para processamento, que então gera a resposta final para o usuário.\n\n**Análise das alternativas incorretas:**\n\n- **Alternativa A**: Inverte a ordem ao sugerir que primeiro se executa uma ferramenta (CallToolRequest) e depois se descobre o que está disponível (ListToolsRequest). Isso é logicamente impossível — como executar algo sem antes saber o que existe? O servidor de ferramentas precisa ser consultado primeiro para informar quais ferramentas estão disponíveis, seus nomes, descrições e esquemas de parâmetros.\n\n- **Alternativa C**: Ignora completamente o processo de descoberta e execução. Para responder "quais repositórios eu tenho", o Claude não pode simplesmente inventar a resposta — ele precisa primeiro descobrir que existe uma ferramenta como "list_repositories", entender como usá-la e então efetivamente chamá-la para obter os dados reais.\n\n- **Alternativa D**: Trata ListToolsRequest e CallToolRequest como eventos simultâneos, o que não faz sentido no protocolo. A descoberta (ListTools) é pré-requisito para a execução (CallTool), pois o cliente precisa saber quais ferramentas estão disponíveis e seus parâmetros antes de poder invocá-las.','\n',char(10)),replace('Imagine que você quer saber quantos brinquedos tem no seu quarto, mas está escuro e você não lembra onde tudo está.\n\nPrimeiro, você acende a luz e olha ao redor para ver o que tem disponível — isso é o **ListTools** (descobrir as ferramentas). Depois, você pensa: "Hum, preciso de uma ferramenta para me ajudar... uma lanterna, talvez?" — isso é o **Claude decidindo** qual ferramenta usar. Então você pega a lanterna e acende (isso é o **CallTool** — executar a ferramenta). Com a luz, você consegue ver e contar todos os seus brinquedos. Finalmente, você volta e conta para alguém quantos brinquedos você tem — essa é a **resposta final**.\n\nA alternativa B faz exatamente isso na ordem certa: descobre primeiro, decide, executa e depois responde. As outras opções estão erradas porque:\n- A quer pegar a ferramenta antes de saber o que existe.\n- C quer responder sem usar nenhuma ferramenta (impossível se você não sabe a resposta).\n- D quer fazer tudo ao mesmo tempo, mas você precisa descobrir antes de usar!','\n',char(10)));
INSERT INTO cards VALUES('admin','card_1783092989776_0l7uolqp6',381,'In the MCP flow, who makes the call to the external API (e.',replace('In the MCP flow, who makes the call to the external API (e.\n\nIn the MCP flow, who makes the call to the external API (e.g., GitHub)?\n[Resposta correta: O server faz a chamada externa após receber o CallToolRequest. A atribui isso ao client. B trata tool_use como se executasse a chamada. D não corresponde ao fluxo automatizado.]\n\n[ ] A - The MCP Client, directly, without involving the server.\n[ ] B - Claude itself, when generating the tool_use.\n[ ] C - The MCP Server, triggered by a CallToolRequest from the client, returning CallToolResult.\n[ ] D - The end user, manually.','\n',char(10)),'C - The MCP Server, triggered by a CallToolRequest from the client, returning CallToolResult.','["Domain_2::Tool_Design_MCP_Integration", "Scenario_2::Code_Generation_Claude_Code"]','New',0,2.5,0,1783092989776,1783727630627,1783203558653,replace('**Tradução para português do Brasil:**\n\nNo fluxo MCP, quem faz a chamada para a API externa (ex.: GitHub)?\n\n[ ] A - O MCP Client, diretamente, sem envolver o servidor.\n[ ] B - O próprio Claude, ao gerar o tool_use.\n[ ] C - O MCP Server, acionado por um CallToolRequest vindo do cliente, retornando CallToolResult.\n[ ] D - O usuário final, manualmente.','\n',char(10)),replace('**Explicação didática para um adulto tech lead:**\n\nNo protocolo MCP (Model Context Protocol), o fluxo de execução de uma ferramenta (tool) segue uma arquitetura bem definida de cliente-servidor:\n\n1. **Cliente (MCP Client)** é quem inicia a conversa com o modelo de linguagem (ex.: Claude) e gerencia o ciclo de vida das requisições. Quando o modelo responde com um `tool_use`, o cliente interpreta essa resposta e envia uma requisição formal ao servidor MCP na forma de um **`CallToolRequest`**.\n\n2. **Servidor (MCP Server)** é o componente responsável por implementar a lógica real da ferramenta. Ao receber o `CallToolRequest`, o servidor executa a ação solicitada — que pode incluir chamar uma API externa como a do GitHub, acessar um banco de dados, executar um script, etc. Após a execução, o servidor retorna um **`CallToolResult`** ao cliente.\n\nPortanto, **a alternativa C está correta**: o servidor MCP é quem efetivamente faz a chamada à API externa, após ser acionado pelo `CallToolRequest` vindo do cliente.\n\n**Análise das alternativas incorretas:**\n\n- **Alternativa A (O MCP Client, diretamente, sem envolver o servidor):** Incorreta porque o cliente MCP não possui, por definição, a implementação das ferramentas. Ele atua como orquestrador, roteando requisições para o servidor apropriado. Se o cliente chamasse a API diretamente, quebraria a separação de responsabilidades do protocolo.\n\n- **Alternativa B (O próprio Claude, ao gerar o tool_use):** Incorreta porque Claude (ou qualquer modelo de linguagem) apenas *decide* usar uma ferramenta e gera a intenção (`tool_use`). O modelo não executa chamadas de rede ou APIs externas — isso é delegado ao servidor MCP.\n\n- **Alternativa D (O usuário final, manualmente):** Incorreta porque o fluxo MCP é automatizado. O usuário final interage com o cliente (ex.: um chat), mas não faz chamadas manuais à API. O objetivo do MCP é justamente abstrair essa complexidade.','\n',char(10)),replace('Imagine que você quer pedir informações sobre um repositório no GitHub. Você (usuário) fala com um assistente inteligente (Claude). Claude entende seu pedido e decide que precisa consultar o GitHub. Mas Claude não sabe fazer isso sozinho — ele é só um cérebro que pensa, não um computador que acessa a internet.\n\nEntão Claude pede ajuda para um "ajudante especial" chamado **MCP Server**. Esse ajudante é como um funcionário que tem a chave e sabe exatamente como falar com o GitHub. O cliente MCP (quem organiza a conversa) avisa o ajudante: "Ei, faz essa chamada para o GitHub!". O ajudante então liga para o GitHub, busca a informação e devolve o resultado para o cliente, que mostra para Claude, que responde para você.\n\n**Resumindo:** quem realmente faz a ligação para o GitHub é o **MCP Server** (o ajudante), não o Claude, nem o cliente, nem você. É como num restaurante: você pede a comida (usuário), o garçom anota (cliente), o cozinheiro prepara (servidor) — e o cozinheiro é quem realmente faz o prato!','\n',char(10)));
INSERT INTO cards VALUES('admin','card_1783092989799_ucqb001mv',382,'You want to test the tools of an MCP server without assembling an entire application.',replace('You want to test the tools of an MCP server without assembling an entire application.\n\nYou want to test the tools of an MCP server without assembling an entire application. What should you use?\n[Resposta correta: O MCP Inspector permite testar as tools sem uma aplicação completa. A e D adicionam trabalho que o Inspector evita. C não é a ferramenta de teste indicada para iterar em tools isoladas.]\n\n[ ] A - A separate unit test script for each tool.\n[ ] B - The Python SDK''s MCP Inspector, started with mcp dev mcp_server.py and accessible via a local URL in the browser.\n[ ] C - Claude Code itself in production mode.\n[ ] D - A complete MCP Client written from scratch.','\n',char(10)),'B - The Python SDK''s MCP Inspector, started with mcp dev mcp_server.py and accessible via a local URL in the browser.','["Domain_2::Tool_Design_MCP_Integration", "Domain_4::Prompt_Engineering_Structured_Output", "Scenario_4::Developer_Productivity"]','New',0,2.5,0,1783092989799,1783727634003,1783203558653,replace('**Tradução para português do Brasil:**\n\nVocê quer testar as ferramentas (tools) de um servidor MCP sem montar uma aplicação completa. O que você deve usar?\n\n[ ] A - Um script de teste unitário separado para cada ferramenta.\n[ ] B - O MCP Inspector do Python SDK, iniciado com mcp dev mcp_server.py e acessível via URL local no navegador.\n[ ] C - O próprio Claude Code em modo de produção.\n[ ] D - Um Cliente MCP completo escrito do zero.','\n',char(10)),replace('**Explicação técnica para um adulto tech lead:**\n\nA pergunta trata especificamente de como testar as *tools* de um servidor MCP (Model Context Protocol) de forma rápida, sem a necessidade de montar uma aplicação cliente completa.\n\n**Resposta correta: Alternativa B**\n\nO **MCP Inspector** é uma ferramenta oficial fornecida pelo SDK do Python (e também disponível em outros SDKS) que permite inspecionar e testar interativamente um servidor MCP. Ao executar `mcp dev mcp_server.py`, um servidor de desenvolvimento é iniciado juntamente com uma interface web (acessível via navegador) que lista todas as ferramentas, recursos e prompts expostos pelo servidor. Você pode chamar as ferramentas individualmente, ver os parâmetros esperados, observar as respostas e depurar o comportamento sem escrever uma única linha de código cliente. É a abordagem ideal para iteração e depuração rápida.\n\n**Por que as demais alternativas estão erradas:**\n\n- **Alternativa A (Script de teste unitário separado para cada ferramenta):** Embora seja possível e, em alguns contextos, desejável ter testes unitários, essa abordagem exige que você escreva, mantenha e execute scripts manualmente para cada ferramenta. Isso adiciona trabalho significativo de configuração e codificação, justamente o que o MCP Inspector foi projetado para evitar. Não é a ferramenta mais adequada para um teste exploratório rápido.\n\n- **Alternativa C (Claude Code em modo de produção):** Claude Code em modo de produção não é uma ferramenta de teste para servidores MCP. Ele é um assistente de codificação que consome ferramentas MCP, mas não foi projetado para depurar ou testar isoladamente as ferramentas de um servidor. Usá-lo para esse fim seria ineficiente e inadequado.\n\n- **Alternativa D (Um Cliente MCP completo escrito do zero):** Essa é a abordagem mais trabalhosa de todas. Escrever um cliente MCP completo do zero para testar ferramentas é totalmente desnecessário quando existem ferramentas como o MCP Inspector. Isso viola o princípio de "não repetir a si mesmo" (DRY) e adiciona uma enorme sobrecarga de desenvolvimento e manutenção.\n\n**Conclusão:** O MCP Inspector é a ferramenta certa para testar tools de forma interativa e isolada, sem a necessidade de construir uma aplicação completa.','\n',char(10)),replace('Imagine que você construiu um brinquedo novo que tem vários botões e alavancas (as "ferramentas" ou "tools"). Você quer testar se cada botão e alavanca funciona direitinho antes de montar o brinquedo inteiro. \n\nO **MCP Inspector** é como uma "caixa de testes" mágica. Você coloca seu brinquedo dentro dessa caixa, e ela mostra todos os botões e alavancas na tela do computador. Você pode clicar em cada um, ver o que ele faz, e descobrir se está funcionando — tudo sem precisar montar o brinquedo completo!\n\nAs outras opções seriam mais trabalhosas:\n- **A** seria como testar cada botão escrevendo uma instrução diferente para cada um — dá muito trabalho!\n- **C** seria como tentar usar o brinquedo já montado e pronto para saber se os botões funcionam — não é o jeito certo de testar.\n- **D** seria como construir um segundo brinquedo inteiro só para testar as peças do primeiro — muito cansativo e desnecessário!\n\nEntão, a resposta certa é a **B**: usar o MCP Inspector, que é a ferramenta feita especialmente para testar as peças do seu servidor MCP sem precisar montar tudo.','\n',char(10)));
INSERT INTO cards VALUES('admin','card_1783092989820_2bg98hcy9',383,'When opening the MCP Inspector, what is the first step before listing or testing tools?',replace('When opening the MCP Inspector, what is the first step before listing or testing tools?\n\nWhen opening the MCP Inspector, what is the first step before listing or testing tools?\n[Resposta correta: É preciso clicar em Connect para inicializar o server antes de listar tools. A, C e D descrevem passos de outros contextos, não o primeiro passo dentro do Inspector.]\n\n[ ] A - Write the JSON schema of the tools manually.\n[ ] B - Click "Connect" to initialize the server, changing the status from "Disconnected" to "Connected".\n[ ] C - Add the server to the project''s .mcp.json.\n[ ] D - Authenticate via ${GITHUB_TOKEN}.','\n',char(10)),'[ ] B - Click "Connect" to initialize the server, changing the status from "Disconnected" to "Connected".','["Domain_2::Tool_Design_MCP_Integration", "Scenario_2::Code_Generation_Claude_Code"]','New',0,2.5,0,1783092989820,1783727637580,1783203558653,replace('**Tradução para português do Brasil:**\n\nAo abrir o MCP Inspector, qual é o primeiro passo antes de listar ou testar ferramentas?\n\n[ ] A - Escrever o schema JSON das ferramentas manualmente.\n[ ] B - Clicar em "Connect" para inicializar o servidor, mudando o status de "Disconnected" para "Connected".\n[ ] C - Adicionar o servidor ao arquivo .mcp.json do projeto.\n[ ] D - Autenticar via ${GITHUB_TOKEN}.','\n',char(10)),replace('**Explicação para um adulto tech lead:**\n\nO MCP Inspector é uma ferramenta de desenvolvimento que permite inspecionar, listar e testar ferramentas (tools) expostas por um servidor MCP (Model Context Protocol). Quando você abre o Inspector pela primeira vez, ele inicia no estado "Disconnected" — ou seja, não há uma conexão ativa com nenhum servidor MCP. Sem essa conexão estabelecida, o Inspector não tem como consultar o servidor para descobrir quais ferramentas estão disponíveis, seus schemas ou parâmetros.\n\nPortanto, o primeiro passo obrigatório é clicar no botão "Connect". Essa ação dispara o handshake do protocolo MCP, estabelece o canal de comunicação entre o Inspector e o servidor e atualiza o status visual para "Connected". Uma vez conectado, o Inspector pode enviar requisições como `tools/list` para listar as ferramentas ou `tools/call` para testá-las.\n\nAnalisando as alternativas incorretas:\n\n- **A (Escrever o schema JSON manualmente):** Totalmente desnecessário. O MCP Inspector descobre os schemas automaticamente via o método `tools/list` do protocolo. Escrever schemas manualmente seria um retrabalho propenso a erros e não faz parte do fluxo de uso da ferramenta.\n\n- **C (Adicionar o servidor ao .mcp.json):** Essa ação faz parte da configuração inicial do servidor MCP no ambiente de desenvolvimento (por exemplo, VS Code ou IDE), não dentro do MCP Inspector. O .mcp.json é um arquivo de configuração usado para registrar servidores MCP no seu editor, mas o Inspector já está apontando para um servidor específico no momento em que é aberto. Esse passo é anterior à abertura do Inspector, não posterior.\n\n- **D (Autenticar via token do GitHub):** Embora alguns servidores MCP exijam autenticação (como o servidor GitHub MCP), autenticação não é o primeiro passo universal. Além disso, a autenticação geralmente ocorre após a conexão ser estabelecida, ou como parte dos parâmetros de inicialização, e não antes de conectar. O Inspector gerencia autenticação de forma diferente dependendo do servidor, mas o Connect vem primeiro.','\n',char(10)),replace('Imagine que o MCP Inspector é como um controle remoto que ainda não está ligado na TV. Antes de você poder ver os canais (as ferramentas) ou testar se eles funcionam, você precisa primeiro apertar o botão "Ligar" para conectar o controle à TV.\n\nA opção B é exatamente isso: clicar em "Connect" é como apertar o botão "Ligar". Depois que você conecta, o Inspector muda de "Desconectado" para "Conectado", e só aí ele consegue conversar com o servidor para listar as ferramentas disponíveis.\n\nAs outras opções estão erradas porque:\n- A - É como tentar adivinhar os canais de TV em vez de deixar a TV mostrar quais existem.\n- C - É como configurar o controle antes de comprá-lo — isso já deveria ter sido feito antes.\n- D - É como mostrar sua carteirinha da escola antes mesmo de ligar o aparelho — não faz sentido fazer isso primeiro.','\n',char(10)));
INSERT INTO cards VALUES('admin','card_1783092989841_t5430uxg3',384,'How does the MCP Inspector help validate workflows that depend on state?',replace('How does the MCP Inspector help validate workflows that depend on state?\n\nHow does the MCP Inspector help validate workflows that depend on state?\n[Resposta correta: O Inspector preserva estado entre chamadas, viabilizando testes sequenciais. A reiniciaria o estado, contrariando o objetivo. C e D negam a capacidade de testar mudanças de estado em sequência.]\n\n[ ] A - It restarts the server on each call, ensuring total isolation.\n[ ] B - It keeps the server state between calls, allowing tools to be tested in sequence, such as editing a doc and then reading to confirm persistence.\n[ ] C - It executes all tools in parallel with no defined order.\n[ ] D - It prevents any state change during the tests.','\n',char(10)),'[ ] B - It keeps the server state between calls, allowing tools to be tested in sequence, such as editing a doc and then reading to confirm persistence.','["Domain_2::Tool_Design_MCP_Integration", "Domain_5::Context_Management_Reliability", "Scenario_4::Developer_Productivity"]','New',0,2.5,0,1783092989841,1783727640996,1783203558653,replace('**TRADUÇÃO PARA PORTUGUÊS DO BRASIL**\n\nPergunta: Como o MCP Inspector ajuda a validar workflows que dependem de estado?\n\nAlternativas:\n\n[ ] A - Ele reinicia o servidor a cada chamada, garantindo isolamento total.\n[ ] B - Ele mantém o estado do servidor entre as chamadas, permitindo que ferramentas sejam testadas em sequência, como editar um documento e depois ler para confirmar a persistência.\n[ ] C - Ele executa todas as ferramentas em paralelo, sem ordem definida.\n[ ] D - Ele impede qualquer mudança de estado durante os testes.','\n',char(10)),replace('**EXPLICAÇÃO PARA UM ADULTO TECH LEAD**\n\nO MCP (Model Context Protocol) Inspector é uma ferramenta de depuração e validação que permite testar interações com servidores MCP de forma interativa. A pergunta aborda como ele lida com workflows que dependem de estado — ou seja, cenários onde uma operação subsequente depende do resultado ou efeito colateral de uma operação anterior.\n\n**Resposta correta: B**\n\nA alternativa B está correta porque o Inspector preserva o estado do servidor entre chamadas sucessivas. Isso é fundamental para testar sequências de operações que simulam fluxos reais de uso. Por exemplo, ao testar um servidor de arquivos, você pode:\n1. Chamar uma ferramenta `create_document` para criar um documento com certo conteúdo.\n2. Em seguida, chamar `read_document` para ler o mesmo documento e verificar se o conteúdo foi persistido corretamente.\n\nSe o estado fosse reiniciado entre as chamadas, esse tipo de teste sequencial seria impossível. A capacidade de manter o estado é o que viabiliza a validação de workflows com dependência de estado.\n\n**Análise das alternativas incorretas:**\n\n- **Alternativa A** ("Reinicia o servidor a cada chamada"): Isso é justamente o oposto do que o Inspector faz. Se o servidor fosse reiniciado a cada chamada, qualquer estado criado pela primeira chamada seria perdido, impossibilitando testes que dependem de mutações sequenciais. Embora o isolamento total seja útil em alguns cenários (como testes unitários puros), ele inviabiliza a validação de workflows com estado.\n\n- **Alternativa C** ("Executa todas as ferramentas em paralelo, sem ordem definida"): O Inspector não executa automaticamente todas as ferramentas em paralelo. Ele é uma ferramenta interativa que espera o usuário fazer chamadas individuais ou sequenciais. Mesmo que houvesse suporte a execução paralela, isso não ajudaria a validar workflows com dependência de estado — pelo contrário, a falta de ordem definida quebraria qualquer fluxo sequencial.\n\n- **Alternativa D** ("Impede qualquer mudança de estado durante os testes"): Essa alternativa contradiz completamente a proposta do Inspector. Se o estado não pudesse ser alterado, não seria possível testar operações de mutação (como criar, atualizar ou deletar recursos). O Inspector justamente permite que você faça chamadas que modificam o estado e depois verifique os efeitos dessas modificações.\n\nPortanto, a alternativa B descreve precisamente o mecanismo que torna o Inspector útil para validar workflows dependentes de estado.','\n',char(10)),replace('**EXPLICAÇÃO PARA UMA CRIANÇA DE 10 ANOS**\n\nImagine que você está brincando de "detetive" com um amigo. Você dá uma pista para ele, e ele precisa lembrar dessa pista para resolver o próximo enigma. Se a cada pista ele esquecesse tudo e começasse do zero, nunca conseguiria resolver o caso, certo?\n\nO MCP Inspector é como um caderno de anotações do detetive. Ele permite que você faça uma coisa (como escrever algo em um documento) e depois verifique se aquilo ainda está lá (como ler o documento para conferir). Isso é muito útil para testar se um programa está funcionando direito quando uma tarefa depende do que foi feito antes.\n\nA alternativa **B** está certa porque o Inspector **guarda na memória** o que foi feito entre uma tarefa e outra, como se fosse o caderno do detetive que nunca é apagado.\n\nAs outras alternativas estão erradas porque:\n- **A** diz que ele apaga tudo a cada tarefa — isso atrapalharia, pois você perderia o que já havia feito.\n- **C** diz que ele faz tudo ao mesmo tempo e sem ordem — mas algumas tarefas precisam ser feitas uma depois da outra.\n- **D** diz que ele não deixa você mudar nada — mas aí não daria para testar se as mudanças funcionam!\n\nEntão, a resposta certa é a **B**: o Inspector guarda as informações entre uma tarefa e outra, permitindo testar sequências completas.','\n',char(10)));
INSERT INTO cards VALUES('admin','card_1783092989862_6fy8jct31',385,'What is the role of the MCP Inspector in development?',replace('What is the role of the MCP Inspector in development?\n\nWhat is the role of the MCP Inspector in development?\n[Resposta correta: O Inspector oferece feedback loop imediato para iterar, testar erros e debugar. A confunde ferramenta de dev com produção. B e D atribuem ao Inspector papéis que não são os seus.]\n\n[ ] A - Replace the MCP server in production.\n[ ] B - Serve as the official MCP Client for end users.\n[ ] C - Iterate quickly on tools, test edge cases and errors, verify interactions and state, and debug in real time without separate test scripts.\n[ ] D - Automatically generate the MCP server code.','\n',char(10)),'C - Iterate quickly on tools, test edge cases and errors, verify interactions and state, and debug in real time without separate test scripts.','["Domain_2::Tool_Design_MCP_Integration", "Domain_5::Context_Management_Reliability", "Scenario_4::Developer_Productivity"]','New',0,2.5,0,1783092989862,1783727644387,1783203558653,replace('**Tradução para português do Brasil:**\n\nQual é o papel do MCP Inspector no desenvolvimento?\n\n[ ] A - Substituir o servidor MCP em produção.\n[ ] B - Servir como o Cliente MCP oficial para usuários finais.\n[ ] C - Iterar rapidamente sobre ferramentas, testar casos de borda e erros, verificar interações e estado, e depurar em tempo real sem scripts de teste separados.\n[ ] D - Gerar automaticamente o código do servidor MCP.','\n',char(10)),replace('**Explicação para um adulto (tech lead):**\n\nO MCP Inspector é uma ferramenta de desenvolvimento voltada para depuração e iteração rápida de servidores MCP (Model Context Protocol). A alternativa C descreve com precisão seu propósito: permitir que o desenvolvedor teste ferramentas, simule casos de borda, verifique o estado das interações e depure em tempo real, eliminando a necessidade de scripts de teste manuais ou separados.\n\n- **Alternativa A** está incorreta porque o Inspector não substitui o servidor em produção. Ele é uma ferramenta de desenvolvimento/debug, não um substituto de runtime.\n- **Alternativa B** está incorreta porque o Inspector não é um cliente MCP para usuários finais. Ele é uma interface de desenvolvedor para inspecionar e depurar o servidor.\n- **Alternativa D** está incorreta porque o Inspector não gera código automaticamente. Ele auxilia na validação e depuração, mas a implementação do servidor é feita separadamente pelo desenvolvedor.\n\nPortanto, a resposta correta é a **alternativa C**.','\n',char(10)),replace('Imagine que você está construindo um robô. O MCP Inspector é como um "modo de teste" que permite você ver como o robô está funcionando, testar se ele acerta os movimentos, ver se algo dá errado e consertar na hora, sem precisar escrever um monte de instruções separadas.\n\nA alternativa errada A diz que ele substitui o robô na hora de funcionar de verdade — não é isso, ele só ajuda a testar.\nA B diz que ele é o controle que as pessoas usam para mexer no robô — também não, é só para programadores.\nA D diz que ele cria o robô sozinho — também não, o programador é quem constrói.\n\nA única certa é a C, que fala que ele serve para testar rapidinho, ver erros e consertar tudo em tempo real.','\n',char(10)));
INSERT INTO cards VALUES('admin','card_1783092989883_u78cy3a53',386,'In a real project, do you normally implement the MCP client, the server, or both?',replace('In a real project, do you normally implement the MCP client, the server, or both?\n\nIn a real project, do you normally implement the MCP client, the server, or both?\n[Resposta correta: No mundo real implementa-se tipicamente um dos dois; ambos juntos é didático. A trata implementar ambos como obrigatório. C nega a implementação. D exclui indevidamente o server.]\n\n[ ] A - Always both, since one does not work without the other in the same code.\n[ ] B - Usually only one of the two; implementing both is usually just for teaching purposes.\n[ ] C - Never either, since everything is generated automatically.\n[ ] D - Only the client, never the server.','\n',char(10)),'B - Usually only one of the two; implementing both is usually just for teaching purposes.','["Domain_2::Tool_Design_MCP_Integration", "Scenario_4::Developer_Productivity"]','New',0,2.5,0,1783092989883,1783727647506,1783203558653,replace('**Tradução para português do Brasil:**\n\n**Pergunta:** Em um projeto real, você normalmente implementa o cliente MCP, o servidor, ou ambos?\n\n[ ] A - Sempre ambos, já que um não funciona sem o outro no mesmo código.\n[ ] B - Normalmente apenas um dos dois; implementar ambos geralmente é só para fins didáticos.\n[ ] C - Nunca nenhum dos dois, já que tudo é gerado automaticamente.\n[ ] D - Apenas o cliente, nunca o servidor.','\n',char(10)),replace('**Explicação didática para um adulto tech lead:**\n\nA alternativa correta é a **B**.\n\nNo mundo real, quando você adota o Model Context Protocol (MCP), você tipicamente implementa **apenas um dos lados** — ou você é um *cliente* MCP (ex.: uma aplicação como Claude Desktop, um plugin de IDE, ou uma ferramenta que consome recursos de servidores MCP) ou você é um *servidor* MCP (ex.: um serviço que expõe ferramentas, recursos ou prompts para clientes MCP). Raramente você implementa ambos no mesmo projeto de produção, a menos que o projeto seja um middleware ou um proxy, o que é incomum.\n\n**Por que as demais estão erradas:**\n\n- **Alternativa A ("Sempre ambos")** — Esta afirmação é falsa. Embora para testar um servidor MCP você precise de um cliente (e vice-versa), isso não significa que você implementa ambos no mesmo código em produção. Um time que desenvolve um servidor MCP usa clientes existentes (como o Claude Desktop) para testar, mas não implementa o cliente do zero. A alternativa trata como obrigatório o que é apenas circunstancial em cenários de teste ou aprendizado.\n\n- **Alternativa C ("Nunca nenhum dos dois")** — Isso não é verdade. MCP é um protocolo ativo e em produção. Projetos reais implementam servidores MCP (ex.: expor APIs internas como ferramentas para LLMs) ou clientes MCP (ex.: integração em IDEs). A afirmação de que "tudo é gerado automaticamente" é incorreta — não há geração automática universal; você escreve código explícito para implementar o protocolo.\n\n- **Alternativa D ("Apenas o cliente, nunca o servidor")** — Excludente demais. Existem muitos projetos reais que implementam servidores MCP, como bridges para bancos de dados, APIs externas, sistemas de arquivos, etc. Dizer que "nunca" se implementa o servidor é factualmente incorreto.\n\n**Conclusão técnica:** Em produção, você escolhe um lado da arquitetura cliente-servidor MCP para implementar. Implementar ambos no mesmo código é uma prática didática ou de prototipação, não o padrão em projetos reais.','\n',char(10)),replace('Imagine que o MCP é como um videogame online. Você pode ser o **jogador** (cliente) ou pode ser o **criador do jogo** (servidor). Normalmente, você é um ou outro, não os dois ao mesmo tempo.\n\n- A opção **B** diz: "Normalmente você é só um deles; fazer os dois é só para aprender." — Isso é verdade! Na vida real, você ou joga ou cria o jogo.\n- A opção **A** diz: "Você sempre tem que fazer os dois." — Mentira! Você não precisa criar o jogo para jogar, nem precisa jogar para criar.\n- A opção **C** diz: "Nunca faz nenhum, porque tudo é feito sozinho." — Também mentira! Alguém precisa fazer o jogo ou o jogador.\n- A opção **D** diz: "Só o jogador, nunca o criador." — Errado de novo! Muita gente cria jogos (servidores MCP) de verdade.\n\nEntão a resposta certa é a **B**: você normalmente faz só um lado — ou o cliente, ou o servidor.','\n',char(10)));
INSERT INTO cards VALUES('admin','card_1783092989906_zayjl09zz',387,'What are the two main components of an MCP client?',replace('What are the two main components of an MCP client?\n\nWhat are the two main components of an MCP client?\n[Resposta correta: São a classe custom MCP Client e o Client Session do SDK. A inclui o server, que não é componente do client. C e D listam elementos que não são os dois componentes do client.]\n\n[ ] A - The MCP Server and the Client Session.\n[ ] B - The MCP Client (custom class) and the Client Session (the actual connection to the server, from the Python SDK).\n[ ] C - The Transport and the Schema Generator.\n[ ] D - The Inspector and the Resource Template.','\n',char(10)),'B - The MCP Client (custom class) and the Client Session (the actual connection to the server, from the Python SDK).','["Domain_2::Tool_Design_MCP_Integration", "ForaDoCenario"]','New',0,2.5,0,1783092989906,1783727650724,1783203558653,replace('**Tradução para português do Brasil:**\n\n**Pergunta:** Quais são os dois componentes principais de um cliente MCP?\n\n**Alternativas:**\n\n[ ] A - O Servidor MCP e a Sessão do Cliente.\n[ ] B - O Cliente MCP (classe personalizada) e a Sessão do Cliente (a conexão real com o servidor, do Python SDK).\n[ ] C - O Transporte e o Gerador de Esquemas.\n[ ] D - O Inspetor e o Modelo de Recurso.','\n',char(10)),replace('**Explicação para um adulto tech lead:**\n\nNo contexto do Model Context Protocol (MCP), um cliente é composto por dois elementos fundamentais:\n\n1. **A classe MCP Client (custom class)** – é a implementação personalizada que encapsula a lógica de negócio da aplicação cliente. Ela é responsável por orquestrar as chamadas, gerenciar estado e integrar-se ao resto do sistema.\n\n2. **A Client Session (do Python SDK)** – é a abstração de conexão fornecida pelo SDK oficial do MCP. Ela gerencia o ciclo de vida da comunicação com o servidor, incluindo o estabelecimento da conexão, o envio de requisições e o recebimento de respostas, além do handshake de capabilities.\n\n**Por que a alternativa B está correta:**\nA combinação de uma classe cliente customizada com a sessão gerenciada pelo SDK é exatamente o que a documentação do MCP define como os dois componentes principais de qualquer cliente MCP. A classe customizada fornece a interface de alto nível para a aplicação, enquanto a Client Session lida com os detalhes de baixo nível do protocolo.\n\n**Por que as demais estão erradas:**\n\n- **Alternativa A (MCP Server + Client Session):** Incorreta porque o servidor MCP não é um componente do cliente. Servidor e cliente são entidades distintas que se comunicam via protocolo. A inclusão do servidor como componente do cliente é um erro conceitual grave.\n\n- **Alternativa C (Transport + Schema Generator):** Incorreta porque, embora o Transport seja uma camada importante do protocolo (responsável pela comunicação física, como Stdio ou SSE), ele não é um dos "dois componentes principais" de um cliente MCP. O Schema Generator não é um componente padrão do MCP.\n\n- **Alternativa D (Inspector + Resource Template):** Incorreta porque o Inspector é uma ferramenta de depuração/inspeção, não um componente do cliente. Resource Template é um conceito relacionado a recursos do servidor, não ao cliente.','\n',char(10)),replace('**Explicação para uma criança de 10 anos:**\n\nImagine que um cliente MCP é como um videogame que se conecta a um servidor de jogos online. \n\nO cliente MCP tem duas partes principais:\n\n1. **A classe personalizada do cliente MCP** – é como o controle do videogame que você usa. Cada jogo pode ter um controle diferente, com botões especiais. É a parte que você (o programador) cria para fazer o que você precisa.\n\n2. **A Sessão do Cliente** – é como o cabo ou o Wi-Fi que conecta seu videogame ao servidor. Sem ele, não dá para jogar online. Essa parte vem pronta do SDK (um kit de ferramentas) do MCP.\n\n**Por que a alternativa B é a certa?**\nPorque junta essas duas coisas: o "controle" que você cria (a classe personalizada) e o "cabo de conexão" que vem com o kit (a Sessão do Cliente).\n\n**Por que as outras estão erradas?**\n\n- A alternativa A diz que o servidor é parte do cliente. Isso é como dizer que a televisão é parte do controle remoto. Não faz sentido! O servidor é outra coisa, separada.\n\n- A alternativa C fala de "Transporte" e "Gerador de Esquemas". Transporte é como o tipo de cabo usado, mas não é uma das duas partes principais. Gerador de Esquemas nem existe no MCP.\n\n- A alternativa D fala de "Inspetor" (uma ferramenta para dar uma olhada no sistema) e "Modelo de Recurso" (algo do servidor). Nenhum dos dois é parte do cliente.','\n',char(10)));
INSERT INTO cards VALUES('admin','card_1783092989948_r2uh8dl06',388,'Why wrap the Client Session in a custom class?',replace('Why wrap the Client Session in a custom class?\n\nWhy wrap the Client Session in a custom class?\n[Resposta correta: A classe cuida do gerenciamento e cleanup de recursos da sessão. A confunde com geração de schema. C e D não têm relação com o motivo de encapsular a sessão.]\n\n[ ] A - To generate the JSON schema of the tools automatically.\n[ ] B - Because the session requires careful resource management, and the class handles the cleanup of connections when they end.\n[ ] C - To allow communication only via HTTP.\n[ ] D - To store Claude''s responses in cache.','\n',char(10)),'B - Because the session requires careful resource management, and the class handles the cleanup of connections when they end.','["Domain_2::Tool_Design_MCP_Integration", "Domain_5::Context_Management_Reliability", "Scenario_1::Customer_Support_Agent"]','New',0,2.5,0,1783092989948,1783727654569,1783203558653,replace('**Tradução para português do Brasil:**\n\n**Por que encapsular a Client Session em uma classe personalizada?**\n\n[ ] A - Para gerar o schema JSON das ferramentas automaticamente.\n[ ] B - Porque a sessão exige um gerenciamento cuidadoso de recursos, e a classe cuida da limpeza (cleanup) das conexões quando elas terminam.\n[ ] C - Para permitir a comunicação apenas via HTTP.\n[ ] D - Para armazenar as respostas de Claude em cache.','\n',char(10)),replace('**Explicação didática para um adulto tech lead:**\n\nA alternativa **B** é a correta porque encapsular a `Client Session` (geralmente referindo-se à sessão HTTP de bibliotecas como `aiohttp` ou `httpx`) em uma classe personalizada tem como objetivo principal gerenciar o ciclo de vida dos recursos de forma adequada.\n\n**Por que a B está correta:**\n- Sessões HTTP gerenciam conexões, pools de conexão, timeouts e cookies. Se não forem fechadas explicitamente, podem vazar file descriptors ou manter conexões abertas indefinidamente.\n- Ao encapsular em uma classe, podemos usar patterns como `context manager` (`__aenter__` e `__aexit__`) ou `dispose` para garantir que `session.close()` (ou equivalente) seja chamado, mesmo em caso de exceções.\n- Isso promove responsabilidade única, testabilidade e reuso do código.\n\n**Análise das alternativas incorretas:**\n\n**A - Para gerar o schema JSON das ferramentas automaticamente.**\n- Gerar schemas JSON é uma funcionalidade de parsing/validação, não uma responsabilidade de gerenciamento de sessão. Confundir esses papéis viola o princípio da separação de responsabilidades.\n\n**C - Para permitir a comunicação apenas via HTTP.**\n- Uma sessão não "permite" comunicação apenas via HTTP; a própria biblioteca já faz isso. Além disso, restringir a apenas HTTP não é um motivo para encapsular — pelo contrário, encapsular geralmente visa abstrair a complexidade, não limitar o protocolo.\n\n**D - Para armazenar as respostas de Claude em cache.**\n- Cache de respostas é uma preocupação de camada de aplicação, resolvida com decorators, dicionários ou bibliotecas como `cachetools`. Encapsular a sessão não tem relação direta com caching; são conceitos ortogonais. Uma classe de sessão bem desenhada pode *suportar* caching, mas esse não é o motivo principal do encapsulamento.','\n',char(10)),replace('Imagine que você tem uma mangueira de jardim para regar as plantas. Depois de usar, você precisa fechar a torneira e guardar a mangueira direitinho, senão ela pode estragar ou inundar tudo. \n\nEncapsular a Client Session em uma classe personalizada é como criar uma "caixa inteligente" que guarda a mangueira. Essa caixa sabe que, quando você terminar de usar, ela precisa fechar a torneira e guardar tudo no lugar certo, mesmo que você esqueça. Assim, nada vaza e nada quebra!\n\nAs outras opções estão erradas porque:\n- A opção A fala de fazer um "mapa" automático das ferramentas, que é outra coisa.\n- A opção C fala de usar só HTTP, mas a sessão já faz isso, não precisa de uma classe especial só para isso.\n- A opção D fala de guardar as respostas do Claude, que é como tirar uma foto do que ele disse — legal, mas não é o motivo de usar a "caixa inteligente" para a mangueira.','\n',char(10)));
INSERT INTO cards VALUES('admin','card_1783092989969_r358subbb',389,'You need to expose read-only data, analogous to an HTTP GET.',replace('You need to expose read-only data, analogous to an HTTP GET.\n\nYou need to expose read-only data, analogous to an HTTP GET. Which MCP primitive should you use?\n[Resposta correta: Resources são o primitivo para buscar informação sem executar ações. A força tools onde resources se aplicam. B confunde com prompts. D não é um primitivo de exposição de dados.]\n\n[ ] A - Tools, since only they return data to Claude.\n[ ] B - Prompts, because reading data is a user workflow.\n[ ] C - Resources, ideal for fetching information rather than executing actions.\n[ ] D - Client Session, which reads the data directly.','\n',char(10)),'C - Resources, ideal for fetching information rather than executing actions.','["Domain_2::Tool_Design_MCP_Integration", "Scenario_4::Developer_Productivity"]','New',0,2.5,0,1783092989969,1783727657850,1783203558653,replace('**Tradução para português do Brasil:**\n\nVocê precisa expor dados somente leitura, análogo a um HTTP GET. Qual primitiva MCP você deve usar?\n\n[ ] A - Tools, pois apenas elas retornam dados para o Claude.\n[ ] B - Prompts, porque ler dados é um fluxo de trabalho do usuário.\n[ ] C - Resources, ideal para buscar informação em vez de executar ações.\n[ ] D - Client Session, que lê os dados diretamente.','\n',char(10)),replace('**Explicação técnica para um adulto tech lead:**\n\nA pergunta aborda o Model Context Protocol (MCP) e seus primitivos. O cenário é claro: expor dados *read-only*, algo semanticamente equivalente a um endpoint HTTP GET. Vamos analisar cada alternativa:\n\n- **Alternativa C (correta):** No MCP, `Resources` são o primitivo projetado exatamente para isso. Eles representam dados estáticos ou semiestáticos que o servidor disponibiliza para leitura pelo cliente (ex.: Claude Desktop). Assim como um GET não modifica o estado do servidor, Resources não executam ações nem causam efeitos colaterais. Eles são a abstração ideal para expor conteúdo como arquivos, documentos, schemas, logs, etc.\n\n- **Alternativa A (incorreta):** A afirmação de que "apenas tools retornam dados" é falsa. `Tools` são primitivos voltados para *execução de ações* (análogo a POST, PUT, DELETE), podendo receber parâmetros do modelo e retornar resultados. Embora tools também possam retornar dados, seu propósito principal é a execução de operações, não a exposição passiva de dados. Usar tools para dados read-only seria um abuso conceitual e arquitetural.\n\n- **Alternativa B (incorreta):** `Prompts` são templates reutilizáveis que auxiliam na construção de mensagens para o modelo. Não são um mecanismo de exposição de dados, mas sim de interação estruturada com o LLM. Confundir promps com recursos de leitura de dados é um erro comum de quem está começando com MCP.\n\n- **Alternativa D (incorreta):** `Client Session` não é um primitivo de exposição de dados do MCP. Session refere-se à conexão estabelecida entre cliente e servidor, gerenciando o ciclo de vida e o transporte das mensagens. Não é uma abstração para expor dados, e sim para gerenciar o canal de comunicação.\n\n**Resumo técnico:** Resources são o equivalente MCP para GET requests. Use-os quando quiser que o cliente leia informações sem provocar mutação de estado no servidor.','\n',char(10)),replace('**Explicação para uma criança de 10 anos:**\n\nImagine que você tem uma caixa cheia de figurinhas e seu amigo quer ver quais são.\n\n- **Resources (Resposta correta):** É como abrir a caixa e mostrar as figurinhas para seu amigo olhar. Ele só olha, não mexe nem tira nada. É só leitura, como dar uma olhadinha.\n\n- **Tools (Alternativa A errada):** Seria como dar uma ferramenta para seu amigo colar as figurinhas em um álbum. Ele está fazendo uma ação, não só olhando.\n\n- **Prompts (Alternativa B errada):** Seria como dar um roteiro para seu amigo dizer frases prontas sobre as figurinhas. Não tem a ver com mostrar as figurinhas em si.\n\n- **Client Session (Alternativa D errada):** Seria o próprio combinado de vocês dois de se encontrar e conversar. Não é o que vocês estão mostrando um ao outro.\n\nEntão, para só mostrar os dados sem fazer nada, igual a dar uma olhada nas figurinhas, usamos Resources!','\n',char(10)));
INSERT INTO cards VALUES('admin','card_1783092989991_tkb69o9jy',390,'Which two essential functions does an MCP client implement?',replace('Which two essential functions does an MCP client implement?\n\nWhich two essential functions does an MCP client implement?\n[Resposta correta: list_tools obtém as tools e call_tool as executa. A cita métodos de conexão, não os essenciais de tools. C trata de resources. D repete a mesma função sem incluir a execução.]\n\n[ ] A - connect() and disconnect(), only to manage the connection.\n[ ] B - list_tools(), which gets the server''s tools, and call_tool(), which executes a tool with Claude''s arguments.\n[ ] C - read_resource() and write_resource(), for data.\n[ ] D - list_tools() and list_tools(), one to discover and another to execute.','\n',char(10)),'B - list_tools(), which gets the server''s tools, and call_tool(), which executes a tool with Claude''s arguments.','["Domain_2::Tool_Design_MCP_Integration", "ForaDoCenario"]','New',0,2.5,0,1783092989991,1783727661064,1783203558653,replace('**Tradução para Português do Brasil:**\n\n**Pergunta:** Quais são as duas funções essenciais que um cliente MCP implementa?\n\n[ ] A - connect() e disconnect(), apenas para gerenciar a conexão.\n[ ] B - list_tools(), que obtém as ferramentas do servidor, e call_tool(), que executa uma ferramenta com os argumentos do Claude.\n[ ] C - read_resource() e write_resource(), para dados.\n[ ] D - list_tools() e list_tools(), uma para descobrir e outra para executar.','\n',char(10)),replace('**Explicação para um adulto (tech lead):**\n\nNo contexto do Model Context Protocol (MCP), um cliente MCP tem duas responsabilidades fundamentais relacionadas ao ciclo de vida das ferramentas (tools) expostas por um servidor MCP:\n\n1. **Descoberta (list_tools):** O cliente precisa saber quais ferramentas estão disponíveis no servidor. A função `list_tools()` consulta o servidor e retorna um inventário de todas as ferramentas que podem ser invocadas, incluindo seus nomes, descrições e esquemas de parâmetros. Isso é essencial para que o modelo de linguagem (como o Claude) saiba quais capacidades estão à sua disposição e como usá-las.\n\n2. **Execução (call_tool):** Uma vez que o modelo decide qual ferramenta usar e com quais argumentos, o cliente precisa invocá-la. A função `call_tool()` envia uma requisição ao servidor para executar a ferramenta específica com os parâmetros fornecidos pelo modelo e retorna o resultado.\n\n**Análise das alternativas incorretas:**\n\n- **A (connect/disconnect):** Gerenciar conexão é um aspecto infraestrutural, não uma "função essencial" do cliente MCP no sentido semântico do protocolo. A pergunta pede as funções que definem o propósito do cliente, não os métodos de transporte.\n\n- **C (read_resource/write_resource):** Essas funções pertencem ao domínio de **recursos** (resources), não de **ferramentas** (tools). Embora o MCP também lide com recursos, a pergunta é especificamente sobre as funções essenciais de um cliente MCP — e estas são list_tools e call_tool, que tratam do mecanismo de ferramentas.\n\n- **D (list_tools/list_tools repetido):** Além de ter um erro conceitual (listar duas vezes a mesma função), a descrição "uma para descobrir e outra para executar" está correta na intenção, mas erra ao nomear ambas como `list_tools()`. A função de execução é `call_tool()`, não uma segunda `list_tools()`.','\n',char(10)),replace('Imagine que o MCP é como um assistente que pode usar ferramentas especiais. O cliente MCP é como o "controle remoto" desse assistente. Esse controle precisa fazer duas coisas principais:\n\n1. **Ver o que tem disponível (list_tools):** É como abrir a gaveta de ferramentas para ver quais ferramentas estão lá — chave de fenda, martelo, alicate.\n2. **Usar a ferramenta escolhida (call_tool):** Depois que você decide qual ferramenta usar, você pega ela e executa o serviço — como usar a chave de fenda para apertar um parafuso.\n\nA alternativa B é a correta porque junta esses dois passos: descobrir as ferramentas (list_tools) e executar a ferramenta escolhida com os comandos certos (call_tool).\n\nAs outras opções estão erradas:\n- **A** fala só de conectar e desconectar, que é o básico, mas não é o que o cliente faz de importante.\n- **C** confunde ferramentas com recursos (ler e escrever dados), que é outra coisa.\n- **D** repete o nome da mesma função duas vezes, como se você pudesse abrir a gaveta duas vezes e isso magicamente usasse a ferramenta — não funciona assim!','\n',char(10)));
INSERT INTO cards VALUES('admin','card_1783092990044_4lhdavk9s',391,'Which message pattern does a Resource follow in MCP?',replace('Which message pattern does a Resource follow in MCP?\n\nWhich message pattern does a Resource follow in MCP?\n[Resposta correta: Resources usam ReadResourceRequest com URI e ReadResourceResult com os dados. A é o padrão de tools. C descreve um modelo assíncrono que não é o dos resources. D é descoberta de tools, não leitura de resource.]\n\n[ ] A - CallToolRequest with arguments and CallToolResult with the result.\n[ ] B - Request-response: ReadResourceRequest with a URI and ReadResourceResult with the data.\n[ ] C - Publishing to an asynchronous queue with no direct response.\n[ ] D - ListToolsRequest followed by ListToolsResult.','\n',char(10)),'B - Request-response: ReadResourceRequest with a URI and ReadResourceResult with the data.','["Domain_2::Tool_Design_MCP_Integration", "Domain_4::Prompt_Engineering_Structured_Output", "Scenario_6::Structured_Data_Extraction"]','New',0,2.5,0,1783092990044,1783727665244,1783203558653,replace('**Tradução para português do Brasil:**\n\nQual padrão de mensagem um Resource segue no MCP?\n\n[ ] A - CallToolRequest com argumentos e CallToolResult com o resultado.\n[ ] B - Requisição-resposta: ReadResourceRequest com um URI e ReadResourceResult com os dados.\n[ ] C - Publicação em uma fila assíncrona sem resposta direta.\n[ ] D - ListToolsRequest seguido de ListToolsResult.','\n',char(10)),replace('**Explicação didática para um adulto tech lead:**\n\nNo MCP (Model Context Protocol), um *Resource* representa dados estáticos ou semiestáticos que podem ser consultados pelo cliente. O padrão de comunicação usado por Resources é o clássico **request-response síncrono**: o cliente envia um `ReadResourceRequest` contendo um URI que identifica o recurso desejado, e o servidor responde com um `ReadResourceResult` contendo os dados (como texto ou blob).\n\n**Por que a B é a correta?**\n- Resources seguem exatamente esse padrão: requisição contendo um URI → resposta contendo os dados. É a forma mais direta e alinhada com a especificação do MCP.\n\n**Por que as demais estão incorretas?**\n- **A**: `CallToolRequest`/`CallToolResult` é o padrão de **Tools** (ferramentas), que aceitam argumentos e retornam resultados de uma ação, não de um recurso.\n- **C**: Publicação assíncrona em fila sem resposta direta descreve um padrão orientado a eventos (como notificações), não o mecanismo de leitura de Resources.\n- **D**: `ListToolsRequest`/`ListToolsResult` é usado para **descoberta de ferramentas**, não para leitura de recursos.','\n',char(10)),replace('Imagine que você tem uma estante de livros. Quando você quer ler um livro, você pede para alguém pegar o livro pelo título (é o "ReadResourceRequest" com o URI) e a pessoa te entrega o livro com a história dentro (é o "ReadResourceResult").\n\n- A opção A seria tipo pedir para uma ferramenta fazer alguma coisa, como um martelo bater em um prego. Não é pedir um livro.\n- A opção C seria como jogar um bilhete dentro de uma garrafa e jogar no mar, sem saber se alguém vai responder. Não funciona para pegar um livro.\n- A opção D seria como perguntar "quais ferramentas você tem?" antes de usar uma. Não é pedir o livro em si.\n\nEntão a resposta certa é a **B**, porque é o jeito certo de pedir um recurso (um livro) e receber ele de volta.','\n',char(10)));
INSERT INTO cards VALUES('admin','card_1783092990066_hgvlt9mn6',392,'Which criterion distinguishes Direct from Templated Resource?',replace('Which criterion distinguishes Direct from Templated Resource?\n\nWhich criterion distinguishes Direct from Templated Resource?\n[Resposta correta: Direct é URI estática sem parâmetros e Templated tem parâmetros parseados como kwargs. A inverte as definições. B inventa distinção de leitura versus escrita. D nega a URI estática do direct.]\n\n[ ] A - Direct uses parameters in the URI and Templated uses a fixed URI.\n[ ] B - Direct is for writing and Templated for reading.\n[ ] C - Direct uses a static URI with no parameters; Templated uses a URI with parameters that the SDK parses and passes as kwargs to the function.\n[ ] D - Both use a dynamic URI, changing only the mime_type.','\n',char(10)),'C - Direct uses a static URI with no parameters; Templated uses a URI with parameters that the SDK parses and passes as kwargs to the function.','["ForaDosDominios", "ForaDoCenario"]','New',0,2.5,0,1783092990066,1783727668538,1783203558653,replace('**Tradução para português do Brasil:**\n\nQual critério distingue Direct de Templated Resource?\n\n[ ] A - Direct usa parâmetros na URI e Templated usa uma URI fixa.\n[ ] B - Direct é para escrita e Templated para leitura.\n[ ] C - Direct usa uma URI estática sem parâmetros; Templated usa uma URI com parâmetros que o SDK interpreta e passa como kwargs para a função.\n[ ] D - Ambos usam uma URI dinâmica, mudando apenas o mime_type.','\n',char(10)),replace('**Explicação para um adulto tech lead:**\n\nA alternativa **C** é a correta. No contexto de SDKs que geram clientes a partir de especificações OpenAPI / REST, o conceito de "Direct Resource" versus "Templated Resource" se refere estritamente à forma como a URI do endpoint é tratada:\n\n- **Direct Resource**: a URI é fixa e estática (ex.: `/api/users`), sem parâmetros de path. Toda a chamada utiliza exatamente aquela URI.\n- **Templated Resource**: a URI contém placeholders/parâmetros (ex.: `/api/users/{user_id}`). O SDK interpreta esses placeholders durante a chamada, substitui pelos valores fornecidos e os passa como argumentos nomeados (kwargs) para a função gerada.\n\n**Por que as demais estão erradas:**\n- **A** inverte os conceitos: Direct não usa parâmetros na URI; Templated sim.\n- **B** inventa uma distinção de leitura vs. escrita que não existe nesse contexto. Ambos os tipos podem ser usados tanto para leitura quanto para escrita, dependendo do método HTTP.\n- **D** afirma que ambos usam URI dinâmica, o que é falso: Direct usa URI estática. A menção a mime_type é irrelevante para o critério de distinção.','\n',char(10)),replace('Imagine que você quer acessar uma página na internet. A **Direct Resource** é como um link fixo, por exemplo: "www.exemplo.com/brinquedos". Esse link nunca muda.\n\nJá a **Templated Resource** é como um link que tem um espaço em branco para você preencher, tipo "www.exemplo.com/usuario/___". Você coloca o nome do usuário no lugar do traço e o link se completa.\n\nA alternativa **C** diz exatamente isso: o Direct tem link fixo (sem "espaços em branco") e o Templated tem link com parâmetros (com "espaços em branco" que o sistema preenche).\n\nAs outras opções estão erradas: A troca tudo, B inventa uma história de leitura e escrita que não tem nada a ver, e D fala que ambos são variáveis, o que não é verdade para o Direct.','\n',char(10)));
INSERT INTO cards VALUES('admin','card_1783092990088_uv7olbgrh',393,'What is the role of the mime_type when defining a resource?',replace('What is the role of the mime_type when defining a resource?\n\nWhat is the role of the mime_type when defining a resource?\n[Resposta correta: O mime_type informa o tipo de dado para o client saber parsear. A confunde com transporte. C não tem relação com autenticação. D é falso, a serialização é automática.]\n\n[ ] A - Define the transport used between client and server.\n[ ] B - Give the client a hint of the type of data returned (application/json, text/plain, application/pdf) so it knows how to parse it.\n[ ] C - Authenticate the resource with GitHub.\n[ ] D - Force the developer to serialize the object manually.','\n',char(10)),'B - Give the client a hint of the type of data returned (application/json, text/plain, application/pdf) so it knows how to parse it.','["ForaDosDominios", "ForaDoCenario"]','New',0,2.5,0,1783092990088,1783727671828,1783203558653,replace('Tradução para português do Brasil:\n\n**Pergunta:** Qual é o papel do mime_type ao definir um recurso?\n\n**Alternativas:**\n[ ] A - Define o transporte usado entre cliente e servidor.\n[ ] B - Dá ao cliente uma dica do tipo de dado retornado (application/json, text/plain, application/pdf) para que ele saiba como interpretá-lo.\n[ ] C - Autentica o recurso com o GitHub.\n[ ] D - Força o desenvolvedor a serializar o objeto manualmente.','\n',char(10)),replace('Explicação didática para adulto tech lead:\n\nO **mime_type** (também conhecido como **media type**) é um mecanismo padronizado (definido pela IANA) que indica a natureza e o formato de um documento ou recurso transmitido via HTTP ou outros protocolos. Quando você define um recurso em uma API REST, especificar o `mime_type` correto no cabeçalho `Content-Type` (para requisições) ou `Accept` (para respostas) é fundamental para a negociação de conteúdo entre cliente e servidor.\n\n**Por que a alternativa B é a correta:**  \nO servidor informa ao cliente qual o formato dos dados retornados (ex.: `application/json`, `text/plain`, `application/pdf`). Com essa informação, o cliente sabe como interpretar (parsear) a resposta — por exemplo, chamar `JSON.parse()` no JavaScript se for `application/json`, ou exibir um PDF nativamente se for `application/pdf`.\n\n**Análise das alternativas incorretas:**\n\n- **A: "Define o transporte usado entre cliente e servidor."** — Isso é falso. O transporte (TCP, HTTP, etc.) é uma camada inferior, definida pelo protocolo de comunicação, não pelo mime_type. O mime_type opera na camada de apresentação, indicando o formato do conteúdo transportado, não o transporte em si.\n\n- **C: "Autentica o recurso com o GitHub."** — Absurdo. Autenticação é feita por mecanismos como tokens (OAuth, JWT), chaves de API ou Basic Auth, geralmente transmitidos no cabeçalho `Authorization`. O mime_type não tem absolutamente nenhuma relação com autenticação.\n\n- **D: "Força o desenvolvedor a serializar o objeto manualmente."** — Falso. Frameworks modernos (Spring, Django REST, Rails, etc.) serializam automaticamente objetos para o formato indicado pelo mime_type (JSON, XML, etc.). O desenvolvedor não é forçado a fazer isso manualmente; pelo contrário, o mime_type permite que a serialização seja automatizada.','\n',char(10)),replace('Imagine que você está enviando uma carta para um amigo. Dentro do envelope, você pode colocar um desenho, uma foto ou uma lista de compras. Na parte de fora do envelope, você escreve o que tem lá dentro — por exemplo: "Aqui tem um desenho" ou "Aqui tem uma foto". Isso ajuda seu amigo a saber como olhar o que você mandou.\n\nO **mime_type** é exatamente isso: uma etiqueta que o servidor coloca nos dados que ele envia para o seu computador (o cliente). Essa etiqueta diz: "Essa informação é do tipo JSON" ou "Isso é um PDF" ou "Isso é um texto simples". Assim, o programa do seu computador sabe como abrir e entender aqueles dados.\n\nA alternativa **B** está certa porque explica direitinho essa função: dar uma dica para o cliente de qual é o tipo do dado, para ele saber como interpretar.\n\nA alternativa **A** está errada porque mime_type não tem nada a ver com o meio de transporte (se é carro, avião, bicicleta...). O transporte aqui é o protocolo HTTP, e o mime_type só fala sobre o formato do conteúdo.\n\nA alternativa **C** está errada porque autenticação é como mostrar um crachá ou uma senha para provar quem você é. O mime_type não faz isso.\n\nA alternativa **D** está errada porque, na verdade, os programas modernos convertem os dados automaticamente para o formato certo. Você não precisa fazer isso manualmente.','\n',char(10)));
INSERT INTO cards VALUES('admin','card_1783092990109_foof6z2lh',394,'To implement @document_name that injects content into the prompt, why prefer resources over tools?',replace('To implement @document_name that injects content into the prompt, why prefer resources over tools?\n\nTo implement @document_name that injects content into the prompt, why prefer resources over tools?\n[Resposta correta: O resource injeta contexto direto no prompt, poupando chamadas de tool extras. A é falso sobre tools. C confunde controle (resources são controlados pela aplicação). D inventa uma diferença de autenticação.]\n\n[ ] A - Because tools cannot return text to Claude.\n[ ] B - Because the resource injects the content directly into the prompt as initial context, avoiding extra tool calls and generating immediate responses.\n[ ] C - Because resources are executed by the model automatically.\n[ ] D - Because tools require authentication and resources do not.','\n',char(10)),'B - Because the resource injects the content directly into the prompt as initial context, avoiding extra tool calls and generating immediate responses.','["Domain_2::Tool_Design_MCP_Integration", "Domain_4::Prompt_Engineering_Structured_Output", "Scenario_4::Developer_Productivity"]','New',0,2.5,0,1783092990109,1783727675907,1783203558653,replace('**Tradução para português do Brasil:**\n\nPergunta: Para implementar @document_name que injeta conteúdo no prompt, por que preferir resources em vez de tools?\n\nAlternativas:\n[ ] A - Porque tools não podem retornar texto para o Claude.\n[ ] B - Porque o resource injeta o conteúdo diretamente no prompt como contexto inicial, evitando chamadas extras de tool e gerando respostas imediatas.\n[ ] C - Porque resources são executados pelo modelo automaticamente.\n[ ] D - Porque tools exigem autenticação e resources não.','\n',char(10)),replace('**Explicação técnica para um adulto tech lead:**\n\nA alternativa correta é a B.\n\n**Por que B está correta:**\nResources (no contexto do Model Context Protocol / MCP) são projetados para fornecer dados estáticos ou semi-estáticos que são inseridos diretamente no contexto do prompt antes mesmo de o modelo começar a gerar a resposta. Isso significa que, quando você usa `@document_name`, o conteúdo do resource já está disponível como parte do prompt inicial, sem que o modelo precise fazer uma chamada de tool (function call) para buscá-lo. Isso elimina o round-trip adicional de uma tool call → retorno da tool → continuação da resposta, resultando em respostas mais rápidas e com menor latência.\n\n**Por que as demais estão incorretas:**\n\n- **A**: Falso. Tools podem sim retornar texto para Claude. Na verdade, o retorno de uma tool é exatamente o texto/estrutura que o modelo recebe para continuar a resposta. A afirmação é factualmente incorreta.\n\n- **C**: Falso. Resources não são executados pelo modelo automaticamente. Resources são disponibilizados pelo servidor (aplicação) e injetados no prompt pelo host/cliente. O modelo não "executa" resources; ele apenas recebe o conteúdo no contexto. Já tools são sim invocadas pelo modelo (via function calling). A afirmação troca os papeis: tools são executadas pelo modelo (através de chamadas), enquanto resources são gerenciados pela aplicação.\n\n- **D**: Falso. Não há uma regra geral de que tools exigem autenticação e resources não. Tanto resources quanto tools podem ou não exigir autenticação, dependendo da implementação do servidor MCP. A alternativa inventa uma diferença que não é intrínseca ao protocolo.','\n',char(10)),replace('Imagine que você está fazendo uma pergunta para um amigo super inteligente (o Claude). Você pode dar a ele um "lembrete" escrito (que é o resource) ou pedir para ele ir buscar uma informação em outro lugar (que é a tool).\n\nO resource é como colocar um papel colado na testa do seu amigo com a informação importante. Ele já vê aquilo na hora, sem precisar fazer nada extra, e responde rapidinho.\n\nA tool é como pedir: "Amigo, vai na estante pegar o livro tal, abre na página tal, e me diz o que está escrito". Ele precisa parar o que está fazendo, ir buscar, voltar, e só depois responder. Isso gasta mais tempo.\n\nEntão, quando você quer que o Claude já saiba do documento (@document_name) desde o começo, é melhor usar resource (o papel colado) do que tool (ir buscar), porque é mais rápido e direto!\n\nAs outras alternativas estão erradas porque:\n- A diz que tools não podem devolver texto, mas elas podem sim!\n- C diz que resources são executados pelo modelo automaticamente, mas na verdade quem coloca o resource no prompt é o sistema, não o modelo.\n- D diz que tools precisam de senha e resources não, mas isso não é verdade — os dois podem ou não precisar, depende de como foram feitos.','\n',char(10)));
INSERT INTO cards VALUES('admin','card_1783092990130_gl4mta1wk',395,'When returning data from a resource in the Python SDK, do you need to convert the object to JSON manually?',replace('When returning data from a resource in the Python SDK, do you need to convert the object to JSON manually?\n\nWhen returning data from a resource in the Python SDK, do you need to convert the object to JSON manually?\n[Resposta correta: O SDK serializa automaticamente, bastando retornar a estrutura. A e C impõem uma conversão manual desnecessária. D nega que resources retornem dados estruturados.]\n\n[ ] A - Yes, always calling json.dumps before returning.\n[ ] B - No, the Python SDK serializes the return value automatically; just return the data structure.\n[ ] C - Yes, but only for mime_type text/plain.\n[ ] D - No, because resources do not return structured data.','\n',char(10)),'B - No, the Python SDK serializes the return value automatically; just return the data structure.','["Domain_2::Tool_Design_MCP_Integration", "Domain_4::Prompt_Engineering_Structured_Output", "Scenario_4::Developer_Productivity"]','New',0,2.5,0,1783092990130,1783727679771,1783203558653,replace('**Tradução para português do Brasil:**\n\n**Pergunta:** Ao retornar dados de um resource no Python SDK, é necessário converter o objeto para JSON manualmente?\n\n[ ] A - Sim, sempre chamando json.dumps antes de retornar.\n[ ] B - Não, o Python SDK serializa o valor de retorno automaticamente; basta retornar a estrutura de dados.\n[ ] C - Sim, mas apenas para mime_type text/plain.\n[ ] D - Não, porque resources não retornam dados estruturados.','\n',char(10)),replace('**Explicação para um adulto tech lead:**\n\nA alternativa correta é a **B**.\n\nNo Python SDK de frameworks como o Google API Python Client ou o SDK do Django REST Framework, os resources (ou views) que retornam dados são automaticamente serializados para JSON pelo próprio framework. O desenvolvedor não precisa chamar `json.dumps()` explicitamente — basta retornar um dicionário, lista, ou qualquer estrutura de dados serializável, e o SDK cuida da conversão, definindo também os headers de Content-Type corretamente.\n\n**Por que as demais estão erradas:**\n\n- **Alternativa A:** Está incorreta porque, na maioria dos SDKs modernos, chamar `json.dumps()` manualmente é desnecessário e pode até causar dupla serialização (string dentro de string). O SDK já faz isso automaticamente.\n- **Alternativa C:** Também incorreta. A serialização automática independe do mime_type; mesmo para text/plain o SDK não exige conversão manual. Além disso, a afirmação de que "só para text/plain" não faz sentido no contexto de serialização JSON.\n- **Alternativa D:** Incorreta. Resources retornam dados estruturados sim (dicionários, listas, modelos serializados). Negar isso é um erro conceitual.','\n',char(10)),replace('**Explicação para uma criança de 10 anos:**\n\nImagine que você tem uma caixa de brinquedos e quer mostrar para alguém o que tem dentro dela. Em vez de você mesmo tirar cada brinquedo e organizar, você entrega a caixa para um robô que faz isso por você.\n\nNo Python SDK, é a mesma coisa: você não precisa organizar os dados manualmente (chamando `json.dumps`). Basta entregar os dados para o SDK, e ele mesmo os transforma no formato certo (JSON) automaticamente.\n\nAs outras opções estão erradas:\n- A diz que você sempre precisa fazer manualmente — não precisa, o robô faz.\n- C diz que só precisa fazer manualmente para um tipo específico — errado, o robô faz para tudo.\n- D diz que os resources não retornam dados organizados — mas eles retornam sim, como uma lista de brinquedos!','\n',char(10)));
INSERT INTO cards VALUES('admin','card_1783092990149_07zb2hvzz',396,'In the client, how do you decide how to process the content returned by a resource?',replace('In the client, how do you decide how to process the content returned by a resource?\n\nIn the client, how do you decide how to process the content returned by a resource?\n[Resposta correta: A decisão se baseia no mimeType do conteúdo. A ignora tipos não-JSON. C usa um critério irrelevante. D adiciona uma chamada desnecessária.]\n\n[ ] A - Always parse as JSON, regardless of the type.\n[ ] B - By checking the mimeType: if "application/json", parse as JSON; otherwise, return the raw text.\n[ ] C - By consulting the payload size in bytes.\n[ ] D - By executing an additional tool to infer the format.','\n',char(10)),'B - By checking the mimeType: if "application/json", parse as JSON; otherwise, return the raw text.','["Domain_2::Tool_Design_MCP_Integration", "Domain_4::Prompt_Engineering_Structured_Output", "Scenario_4::Developer_Productivity"]','New',0,2.5,0,1783092990149,1783727683671,1783203558653,replace('**Tradução para português do Brasil:**\n\nPergunta: No cliente, como você decide como processar o conteúdo retornado por um resource?\n\n[ ] A - Sempre fazer o parse como JSON, independentemente do tipo.\n[ ] B - Verificando o mimeType: se for "application/json", fazer o parse como JSON; caso contrário, retornar o texto bruto.\n[ ] C - Consultando o tamanho do payload em bytes.\n[ ] D - Executando uma ferramenta adicional para inferir o formato.','\n',char(10)),replace('**Explicação para um adulto tech lead:**\n\nA alternativa correta é a **B**. A decisão de como processar o conteúdo retornado por um resource deve ser baseada no **mimeType** (ou Content-Type) presente no cabeçalho da resposta HTTP. Esse é o padrão universal na web: o servidor informa qual é o formato do conteúdo, e o cliente respeita essa informação.\n\n- **Alternativa A** está incorreta porque assumir que tudo é JSON é frágil e quebradiço. Recursos podem retornar HTML, XML, texto plano, imagens, etc. Tentar fazer parse de JSON em um conteúdo que não é JSON resultará em erro de parse ou em comportamento imprevisível.\n- **Alternativa C** está incorreta porque o tamanho do payload não tem relação alguma com o formato do conteúdo. Um JSON pode ser pequeno ou enorme; o mesmo vale para texto plano ou XML. Tamanho não é um indicador confiável de tipo.\n- **Alternativa D** está incorreta porque executar uma ferramenta adicional para inferir o formato é desnecessário e ineficiente. O servidor já informa o formato através do cabeçalho Content-Type. Adicionar uma etapa extra de inferência (como tentar detectar se o conteúdo parece JSON, XML, etc.) aumenta a latência, introduz complexidade e pode levar a falsos positivos.\n\nPortanto, a abordagem correta e mais eficiente é: **verificar o mimeType** e, se for "application/json", fazer o parse como JSON; caso contrário, retornar o conteúdo como texto bruto (ou tratá-lo conforme o tipo apropriado).','\n',char(10)),replace('Imagina que você pede algo para um amigo, e ele te entrega uma caixa. Na caixa, tem um selinho dizendo o que tem dentro: se está escrito "brinquedo", você sabe que é um brinquedo; se está escrito "livro", você sabe que é um livro.\n\nNo computador, é parecido. Quando um programa (cliente) pede informações para um servidor, o servidor responde com um conteúdo e coloca uma "etiqueta" chamada **mimeType** dizendo o que é aquilo. Se a etiqueta diz "application/json", quer dizer que o conteúdo é um JSON (um formato de dados organizado). Se diz outra coisa, é um texto normal ou outro formato.\n\nA melhor forma de decidir o que fazer com o conteúdo é **olhar essa etiqueta (mimeType)**. As outras opções estão erradas porque:\n- Achar que é sempre JSON é como achar que toda caixa tem brinquedo — pode ter um ovo de galinha dentro!\n- Olhar o tamanho da caixa não diz o que tem dentro.\n- Chamar outra pessoa para adivinhar o que tem dentro é perda de tempo, porque a etiqueta já diz tudo.\n\nEntão: **veja o mimeType** — se for "application/json", trate como JSON; senão, use o texto como veio.','\n',char(10)));
INSERT INTO cards VALUES('admin','card_1783092990170_wcpnfsza5',397,'How do the two types of resource appear in the MCP Inspector?',replace('How do the two types of resource appear in the MCP Inspector?\n\nHow do the two types of resource appear in the MCP Inspector?\n[Resposta correta: O Inspector separa "Resources" (direct) de "Resource Templates" (templated, que exigem parâmetros). A mistura resources com tools. C omite os templated. D coloca resources na seção errada.]\n\n[ ] A - All together in a single list called "Tools".\n[ ] B - In separate sections: "Resources" for the direct/static ones and "Resource Templates" for the templated ones, which ask for parameter values.\n[ ] C - Only the direct ones appear; the templated ones are not displayed.\n[ ] D - Both appear in the "Prompts" section.','\n',char(10)),'[ ] B - In separate sections: "Resources" for the direct/static ones and "Resource Templates" for the templated ones, which ask for parameter values.','["Domain_2::Tool_Design_MCP_Integration", "Domain_5::Context_Management_Reliability", "Scenario_4::Developer_Productivity"]','New',0,2.5,0,1783092990170,1783727687887,1783203558653,replace('**Tradução:**\n\n> Como os dois tipos de recurso aparecem no MCP Inspector?\n> \n> [ ] A - Todos juntos em uma única lista chamada "Tools".\n> [ ] B - Em seções separadas: "Resources" para os diretos/estáticos e "Resource Templates" para os modelados (templated), que solicitam valores de parâmetros.\n> [ ] C - Apenas os diretos aparecem; os modelados não são exibidos.\n> [ ] D - Ambos aparecem na seção "Prompts".','\n',char(10)),replace('**Explicação para um adulto (tech lead):**\n\nNo MCP (Model Context Protocol), o Inspector é a ferramenta de interface que permite ao desenvolvedor visualizar e testar os recursos expostos por um servidor MCP. Esses recursos se dividem em dois tipos fundamentais:\n\n1. **Resources (diretos/estáticos):** São URIs fixas e imutáveis, que retornam sempre o mesmo conteúdo (ex.: `file:///logs/app.log`). O Inspector os lista em uma seção chamada "Resources".\n2. **Resource Templates (templated):** São URIs com parâmetros dinâmicos, representadas por placeholders como `{param}` (ex.: `file:///logs/{service}.log`). O Inspector os lista em uma seção separada chamada "Resource Templates" e, ao selecioná-los, exibe campos para o desenvolvedor preencher os valores dos parâmetros antes de fazer a requisição.\n\n**Análise das alternativas:**\n\n- **Alternativa A (incorreta):** Mistura os conceitos de resources com tools. Tools são uma abstração completamente diferente no MCP (ações executáveis, como chamadas de função). Resources não aparecem na lista "Tools".\n- **Alternativa B (correta):** Descreve exatamente o comportamento do Inspector: duas seções separadas para os dois tipos, com os templates exigindo parâmetros.\n- **Alternativa C (incorreta):** O Inspector exibe **ambos** os tipos. Os templated aparecem, mas dependem de parâmetros para serem resolvidos.\n- **Alternativa D (incorreta):** "Prompts" é outra categoria no MCP (templates de mensagens pré-definidas), não onde resources são exibidos.','\n',char(10)),replace('Imagine que o MCP Inspector é como uma caixa de ferramentas. Dentro dela, existem dois tipos de "papéis" que o computador pode ler:\n\n1. **Papéis prontos (Resources):** São papéis que já estão escritos e não mudam. Você pode pegar e ler na hora.\n2. **Papéis para preencher (Resource Templates):** São papéis que têm espaços em branco. Você precisa escrever algo nesses espaços (como o nome de um serviço) para poder ler.\n\nNo MCP Inspector, esses dois tipos aparecem em **gavetas separadas**: uma chamada "Resources" para os papéis prontos, e outra chamada "Resource Templates" para os que precisam ser preenchidos.\n\nAs outras respostas estão erradas porque:\n- **A** diz que tudo aparece junto em "Tools" — mas "Tools" é outra coisa (são como "ferramentas" que fazem ações).\n- **C** diz que os papéis para preencher não aparecem — mas eles aparecem sim!\n- **D** diz que ambos estão em "Prompts" — mas "Prompts" é uma gaveta diferente para mensagens prontas.','\n',char(10)));
INSERT INTO cards VALUES('admin','card_1783092990191_39of179m2',398,'Who controls each of the three MCP primitives?',replace('Who controls each of the three MCP primitives?\n\nWho controls each of the three MCP primitives?\n[Resposta correta: Tools são controladas pelo modelo, Resources pela aplicação e Prompts pelo usuário. A e D embaralham os controladores. C atribui tudo ao modelo, ignorando as camadas distintas.]\n\n[ ] A - Tools by the user, Resources by the model, Prompts by the application.\n[ ] B - Tools by the model/Claude, Resources by the application and Prompts by the user.\n[ ] C - All three are controlled by the model.\n[ ] D - Tools by the application, Resources by the user, Prompts by the model.','\n',char(10)),'B - Tools by the model/Claude, Resources by the application and Prompts by the user.','["ForaDosDominios", "ForaDoCenario"]','New',0,2.5,0,1783092990191,1783727691356,1783203558653,replace('**Tradução para Português do Brasil:**\n\nPergunta: Quem controla cada um dos três primitivos do MCP?\n\n[ ] A - Tools pela usuário, Resources pelo modelo, Prompts pela aplicação.\n[ ] B - Tools pelo modelo/Claude, Resources pela aplicação e Prompts pelo usuário.\n[ ] C - Todos os três são controlados pelo modelo.\n[ ] D - Tools pela aplicação, Resources pelo usuário, Prompts pelo modelo.','\n',char(10)),replace('**Explicação para um adulto tech lead:**\n\nNo contexto do Model Context Protocol (MCP), os três primitivos fundamentais são Tools, Resources e Prompts, cada um com um controlador distinto baseado na arquitetura do protocolo:\n\n- **Tools** (Ferramentas) são controladas pelo modelo (Claude ou qualquer modelo que implemente o MCP). O modelo decide quando e como invocar ferramentas para estender suas capacidades (ex.: executar código, buscar dados externos). O modelo as expõe ao host.\n\n- **Resources** (Recursos) são controlados pela aplicação (o "host" ou cliente MCP). A aplicação gerencia quais recursos (arquivos, bancos de dados, APIs) estão disponíveis e os disponibiliza para o modelo acessar de forma controlada.\n\n- **Prompts** (Instruções/Prompts) são controlados pelo usuário. O usuário fornece prompts dinâmicos ou templates que guiam o comportamento do modelo, seja diretamente ou através de templates predefinidos que o usuário escolhe ativar.\n\n**Análise das alternativas incorretas:**\n\n- **A** está errada pois inverte os controladores: Tools não são controladas pelo usuário (o usuário pode sugerir, mas quem invoca é o modelo), Resources não são controladas pelo modelo (o modelo consome, não gerencia), e Prompts não são controlados pela aplicação (a aplicação pode hospedar templates, mas o controle final do prompt ativo é do usuário).\n\n- **C** está errada pois centraliza todo o controle no modelo, ignorando que Resources são gerenciados pela aplicação (por questões de segurança e escopo) e Prompts são dirigidos pelo usuário.\n\n- **D** está errada pois mais uma vez troca os papéis: Tools não são controladas pela aplicação (o modelo as invoca), Resources não são controlados pelo usuário (a aplicação os gerencia), e Prompts não são controlados pelo modelo (o usuário os fornece).\n\nPortanto, a alternativa **B** reflete corretamente a separação de responsabilidades no MCP.','\n',char(10)),replace('**Explicação para uma criança de 10 anos:**\n\nImagine que você tem um jogo de RPG onde três personagens trabalham juntos: o **Mestre do Jogo (o modelo)**, o **Jogador (a aplicação)** e você, o **Criador da Aventura (o usuário)**.\n\nCada um controla uma "ferramenta mágica" diferente:\n\n1. **Tools (Ferramentas)** — quem controla é o Mestre do Jogo (o modelo). Ele decide quando usar poderes especiais, como "calcular algo muito rápido" ou "pesquisar um livro mágico". O mestre é quem aperta o botão.\n\n2. **Resources (Recursos)** — quem controla é o Jogador (a aplicação). Ele é o dono do baú de tesouros. Ele decide quais mapas, livros ou itens estão disponíveis para o mestre usar. O mestre só pode pegar o que o jogador colocar no baú.\n\n3. **Prompts (Instruções)** — quem controla é você, o Criador da Aventura (o usuário). Você escreve a história, dá as dicas e diz "agora, aja como um herói gentil" ou "responda como um sábio". O mestre e o jogador seguem o que você mandou.\n\n**Por que as outras respostas estão erradas?**\n- A opção A disse que o usuário controla as ferramentas — mas é o mestre quem as usa.\n- A opção C disse que o mestre controla tudo — mas o baú de recursos é do jogador, e as instruções são suas.\n- A opção D embaralhou tudo de novo, colocando cada um no lugar errado.\n\nA única que acertou foi a **B**: mestre controla ferramentas, jogador controla recursos, e você controla as instruções.','\n',char(10)));
INSERT INTO cards VALUES('admin','card_1783092990213_h0dyp869g',399,'You want to give Claude a capability that it decides on its own when to invoke, such as executing JavaScript.',replace('You want to give Claude a capability that it decides on its own when to invoke, such as executing JavaScript.\n\nYou want to give Claude a capability that it decides on its own when to invoke, such as executing JavaScript. Which primitive should you use?\n[Resposta correta: Tools são controladas pelo modelo, que decide quando invocá-las. A e B têm outros controladores (aplicação e usuário). D não é um primitivo.]\n\n[ ] A - Resources, controlled by the application.\n[ ] B - Prompts, controlled by the user.\n[ ] C - Tools, controlled by the model, since it is Claude that decides when to call them.\n[ ] D - Client Session, which invokes the capability automatically.','\n',char(10)),'C - Tools, controlled by the model, since it is Claude that decides when to call them.','["Domain_2::Tool_Design_MCP_Integration", "Domain_1::Agentic_Architecture_Orchestration", "Scenario_4::Developer_Productivity"]','New',0,2.5,0,1783092990213,1783727695418,1783203558653,replace('**Tradução:**\n\nVocê quer dar a Claude uma capacidade que ele decida por conta própria quando invocar, como executar JavaScript.\n\nQual primitivo você deve usar?\n\n[ ] A - Resources, controlados pela aplicação.\n[ ] B - Prompts, controlados pelo usuário.\n[ ] C - Tools, controladas pelo modelo, já que é Claude quem decide quando chamá-las.\n[ ] D - Client Session, que invoca a capacidade automaticamente.','\n',char(10)),replace('**Explicação para adulto tech lead:**\n\nA pergunta aborda o conceito de **primitivos do protocolo MCP (Model Context Protocol)** e quem detém o controle sobre sua execução.\n\n- **Alternativa C (correta):** Tools são o primitivo projetado exatamente para este cenário. No MCP, tools são expostas ao modelo (Claude) e é o modelo quem decide, autonomamente, quando invocá-las com base no contexto da conversa. Isso é ideal para ações como executar JavaScript, fazer chamadas de API, calcular algo, etc. — o modelo analisa a necessidade e invoca a tool por conta própria.\n\n- **Alternativa A (incorreta):** Resources são controlados pela aplicação (cliente), não pelo modelo. O cliente decide quando e quais resources expor. O modelo apenas os lê, mas não decide ativamente quando invocá-los. Não se encaixa no requisito de "Claude decide quando invocar".\n\n- **Alternativa B (incorreta):** Prompts são templates controlados pelo usuário (ou pela aplicação cliente). O modelo pode preenchê-los, mas quem decide quando e quais prompts usar é o usuário, não o modelo. Portanto, não atende ao requisito.\n\n- **Alternativa D (incorreta):** Client Session não é um primitivo do MCP. É um conceito de gerenciamento de conexão/estado, não uma capability que o modelo invoca. Além disso, a descrição de "invoca automaticamente" sugere um comportamento automático do cliente, não uma decisão autônoma do modelo.','\n',char(10)),replace('Imagina que você tem um robô ajudante chamado Claude. Você quer que ele tenha ferramentas especiais, como uma calculadora que ele mesmo decide quando usar.\n\n- **Tools (ferramentas):** São como brinquedos que o robô pode pegar quando quiser. Se ele vê uma conta difícil, ele mesmo decide: "Ah, vou usar minha calculadora!" — É a opção certa porque o robô decide sozinho.\n\n- **Resources (recursos):** São como livros que só a sua mãe pode pegar da estante e mostrar para você. O robô não pode pegar sozinho.\n\n- **Prompts:** São como receitas de bolo que você dá para o robô seguir. Você decide a receita, não o robô.\n\n- **Client Session:** Isso não é uma ferramenta de verdade, é mais como se fosse o "liga/desliga" do robô. Não serve para ele decidir fazer algo.\n\nEntão, a resposta certa é a **C**, porque as Tools deixam o próprio Claude decidir quando usar, exatamente como você queria!','\n',char(10)));
INSERT INTO cards VALUES('admin','card_1783092990233_smtjrcpfp',400,'The application needs to fetch data to populate an autocomplete in the UI or inject context into the prompt.',replace('The application needs to fetch data to populate an autocomplete in the UI or inject context into the prompt.\n\nThe application needs to fetch data to populate an autocomplete in the UI or inject context into the prompt. Which primitive should you use?\n[Resposta correta: Resources são controlados pela aplicação, ideais para popular UI ou injetar contexto. A e B têm controladores diferentes. D força uma combinação desnecessária.]\n\n[ ] A - Tools, controlled by the model.\n[ ] B - Prompts, controlled by the user.\n[ ] C - Resources, controlled by the application, which decides when to fetch and how to use (UI or context), as in the "Add from Google Drive" integration.\n[ ] D - A tool and a prompt combined.','\n',char(10)),'[ ] C - Resources, controlled by the application, which decides when to fetch and how to use (UI or context), as in the "Add from Google Drive" integration.','["Domain_2::Tool_Design_MCP_Integration", "Domain_4::Prompt_Engineering_Structured_Output", "Scenario_4::Developer_Productivity"]','New',0,2.5,0,1783092990233,1783727699740,1783203558653,replace('**Tradução para português do Brasil:**\n\nA aplicação precisa buscar dados para popular um autocomplete na interface ou injetar contexto no prompt.\n\nQual primitiva você deve usar?\n\n[ ] A - Tools, controladas pelo modelo.\n[ ] B - Prompts, controlados pelo usuário.\n[ ] C - Resources, controlados pela aplicação, que decide quando buscar e como usar (UI ou contexto), como na integração "Adicionar do Google Drive".\n[ ] D - Uma tool e um prompt combinados.','\n',char(10)),replace('**Explicação para um adulto (tech lead):**\n\nA pergunta aborda a escolha da primitiva correta em um sistema de agentes/LLM (como o protocolo MCP - Model Context Protocol) para o cenário em que a aplicação precisa buscar dados externos de forma proativa, seja para preencher um componente de UI (ex.: autocomplete) ou para enriquecer o contexto enviado ao modelo.\n\n**Análise das alternativas:**\n\n- **Alternativa C (correta):** Resources são a primitiva adequada quando a aplicação (cliente) detém o controle sobre quando e como os dados são buscados. Diferente de Tools (que são invocadas pelo modelo) e Prompts (gerenciados pelo usuário), Resources permitem que a aplicação decida: "agora vou buscar os dados do Google Drive para exibir na UI" ou "vou buscar este documento e injetá-lo como contexto no prompt". O exemplo clássico é a integração "Add from Google Drive" — a aplicação busca a lista de arquivos, exibe para o usuário escolher, e então injeta o conteúdo selecionado no prompt. Isso é um Resource.\n\n- **Alternativa A (errada):** Tools são controladas pelo modelo. O modelo decide quando invocar uma ferramenta. No cenário descrito, a aplicação precisa ter o controle sobre a busca (ex.: popular autocomplete antes mesmo de o modelo ser chamado). Se usássemos uma Tool, o modelo precisaria decidir chamá-la, o que não faz sentido para popular UI ou injetar contexto de forma determinística pela aplicação.\n\n- **Alternativa B (errada):** Prompts são templates ou mensagens definidas pelo usuário/desenvolvedor para guiar o comportamento do modelo. Eles não são um mecanismo de busca de dados. Um prompt não "busca" dados de uma fonte externa; ele apenas fornece instruções. Portanto, não atende ao requisito de fetch de dados.\n\n- **Alternativa D (errada):** Combinar Tool e Prompt seria uma abordagem híbrida desnecessária e que viola a separação de responsabilidades. Se a aplicação precisa controlar a busca, usar uma Tool (controlada pelo modelo) combinada com um Prompt não resolve o problema de controle pela aplicação. Além disso, adiciona complexidade sem benefício claro, forçando uma combinação artificial.\n\n**Conclusão:** A alternativa C é a única que descreve corretamente a primitiva onde a aplicação mantém o controle sobre a busca e o uso dos dados, atendendo exatamente ao cenário de popular UI ou injetar contexto.','\n',char(10)),replace('Imagine que você está montando um quebra-cabeça e precisa de peças que estão em outra sala.\n\n- **Tools** são como um robô que decide sozinho quando ir buscar as peças. Você não pode controlar quando ele vai.\n- **Prompts** são como instruções escritas que você dá para alguém, mas elas não buscam nada — só dizem o que fazer.\n- **Resources** são como você mesmo indo até a sala, pegando as peças que quer e trazendo para sua mesa. Você decide o momento certo e como usar as peças (colocar na sua estante de UI ou misturar com outras peças no quebra-cabeça do prompt).\n\nO exemplo do "Adicionar do Google Drive" é exatamente isso: a aplicação (você) busca a lista de arquivos, mostra para o usuário escolher um, e depois coloca esse arquivo no prompt. Quem manda é a aplicação, não o modelo nem o usuário.\n\nPor isso a resposta certa é a **C**.','\n',char(10)));
INSERT INTO cards VALUES('admin','card_1783092990285_g2snpu5qs',401,'You want pre-defined workflows that the user triggers via button, menu or slash command.',replace('You want pre-defined workflows that the user triggers via button, menu or slash command.\n\nYou want pre-defined workflows that the user triggers via button, menu or slash command. Which primitive should you use?\n[Resposta correta: Prompts são controlados pelo usuário, que aciona o workflow predefinido. A e B atribuem o controle ao modelo e à aplicação. D não é um primitivo.]\n\n[ ] A - Tools, since Claude decides when to run.\n[ ] B - Resources, since the application decides when to fetch.\n[ ] C - Prompts, controlled by the user, who decides when to run the predefined workflow.\n[ ] D - Client Session, which triggers the workflow.','\n',char(10)),'C - Prompts, controlled by the user, who decides when to run the predefined workflow.','["Domain_3::Claude_Code_Configuration_Workflows", "Domain_2::Tool_Design_MCP_Integration", "Scenario_2::Code_Generation_Claude_Code"]','New',0,2.5,0,1783092990285,1783727703399,1783203558653,replace('**Tradução para português do Brasil:**\n\nVocê deseja ter workflows predefinidos que o usuário aciona via botão, menu ou comando de barra. Qual primitiva você deve usar?\n\n[ ] A - Tools, pois Claude decide quando executar.\n[ ] B - Resources, pois a aplicação decide quando buscar.\n[ ] C - Prompts, controlados pelo usuário, que decide quando executar o workflow predefinido.\n[ ] D - Sessão do Cliente, que aciona o workflow.','\n',char(10)),replace('**Explicação para adulto tech lead:**\n\nA pergunta trata de primitivas no contexto do protocolo MCP (Model Context Protocol). O cenário descreve a necessidade de workflows predefinidos que sejam *iniciados pelo usuário* manualmente (via botão, menu ou slash command), e não pelo modelo de IA ou pela aplicação automaticamente.\n\n- **Alternativa C (correta):** Prompts são a primitiva correta porque representam workflows ou templates predefinidos que o *usuário* escolhe ativar explicitamente. No MCP, prompts funcionam como receitas ou comandos que o usuário dispara quando deseja. É exatamente o caso de uso descrito: o usuário clica em um botão ou digita um comando e o workflow é executado sob seu controle.\n\n- **Alternativa A (incorreta):** Tools são primitivas que o *modelo* (Claude) decide quando invocar, não o usuário. O modelo avalia o contexto e decide se precisa de uma ferramenta. Isso tira o controle do usuário, contradizendo o requisito.\n\n- **Alternativa B (incorreta):** Resources são dados ou conteúdos expostos que a *aplicação* (ou o cliente MCP) decide quando buscar. Novamente, o controle não está nas mãos do usuário para disparar workflows.\n\n- **Alternativa D (incorreta):** "Client Session" não é uma primitiva no MCP. O termo correto para uma sessão de cliente no MCP é "Client Session" como conceito de conexão, mas não é uma primitiva que define workflows acionáveis pelo usuário. É um termo genérico de infraestrutura de comunicação.','\n',char(10)),replace('Imagine que você tem um robô que pode fazer várias tarefas, como contar uma história ou desenhar um cachorro. Você quer que o robô só faça essas tarefas quando VOCÊ mandar, apertando um botão ou escrevendo um comando.\n\n- **Prompts** são como receitas prontas que você guarda para o robô. Você é quem decide: "Agora quero a receita da história" e clica no botão. O robô obedece porque você mandou. ✅\n\n- **Tools** são ferramentas que o robô decide usar sozinho, quando ele acha que precisa. Se você não gosta disso, não serve para o que você quer. ❌\n\n- **Resources** são como livros ou arquivos que o programa busca para você, mas quem decide buscar é o aplicativo, não você apertando um botão. ❌\n\n- **Client Session** é só o nome da "conversa" entre seu computador e o robô, não é uma receita de tarefa. ❌\n\nEntão, a resposta certa é **Prompts**, porque é a única que deixa VOCÊ no controle, apertando o botão quando quiser!','\n',char(10)));
INSERT INTO cards VALUES('admin','card_1783092990306_4bmrmg08v',402,'Which decision mapping between MCP primitives is correct?',replace('Which decision mapping between MCP primitives is correct?\n\nWhich decision mapping between MCP primitives is correct?\n[Resposta correta: Tools para nova capacidade, Resources para dados na app e Prompts para workflows do usuário. A e D embaralham o mapeamento. C ignora a distinção entre os primitivos.]\n\n[ ] A - New capability for Claude (Resources); data for the app (Prompts); user workflows (Tools).\n[ ] B - New capability for Claude (Tools); data for the app, UI/context (Resources); user-triggered workflows (Prompts).\n[ ] C - All cases (Tools).\n[ ] D - New capability for Claude (Prompts); data for the app (Tools); user workflows (Resources).','\n',char(10)),'[ ] B - New capability for Claude (Tools); data for the app, UI/context (Resources); user-triggered workflows (Prompts).','["Domain_2::Tool_Design_MCP_Integration", "Domain_4::Prompt_Engineering_Structured_Output", "Scenario_4::Developer_Productivity"]','New',0,2.5,0,1783092990306,1783727706926,1783203558653,replace('Tradução para português do Brasil:\n\n**Pergunta:** Qual mapeamento de decisão entre primitivos MCP está correto?\n\n**Alternativas:**\n[ ] A - Nova capacidade para o Claude (Resources); dados para o aplicativo (Prompts); fluxos de trabalho do usuário (Tools).\n[ ] B - Nova capacidade para o Claude (Tools); dados para o aplicativo, UI/contexto (Resources); fluxos de trabalho acionados pelo usuário (Prompts).\n[ ] C - Todos os casos (Tools).\n[ ] D - Nova capacidade para o Claude (Prompts); dados para o aplicativo (Tools); fluxos de trabalho do usuário (Resources).','\n',char(10)),replace('Explicação para um adulto tech lead:\n\nNo **Model Context Protocol (MCP)**, existem três primitivos principais — Tools, Resources e Prompts — cada um com um propósito distinto e complementar.\n\n- **Tools** são funções executáveis que o modelo pode invocar para realizar ações ou estender suas capacidades. Elas representam **novas capacidades para o Claude**, permitindo que ele interaja com APIs, execute código, busque dados externos sob demanda, etc.\n- **Resources** são dados ou conteúdos que o servidor expõe para o cliente (a app). Eles podem ser carregados no contexto da conversa para fornecer informações estáticas ou dinâmicas (como documentos, arquivos, estados de UI). Representam **dados para o aplicativo**.\n- **Prompts** são templates de mensagens pré-formatadas que guiam o comportamento do modelo em fluxos de trabalho específicos, acionados pelo usuário. Servem para estruturar interações recorrentes.\n\nA **alternativa B** reflete exatamente esse mapeamento:\n- Tools → nova capacidade para o Claude (✔️)\n- Resources → dados para a app, UI/contexto (✔️)\n- Prompts → fluxos de trabalho acionados pelo usuário (✔️)\n\n**Por que as demais estão erradas:**\n\n- **A**: Inverte completamente os papéis — associa Resources a "nova capacidade" (quando na verdade Resources fornecem dados contextuais) e Prompts a "dados para o app" (quando Prompts são templates de workflow).\n- **C**: Ignora a distinção fundamental entre os primitivos, sugerindo que todos os casos são resolvidos com Tools. Isso não condiz com a arquitetura do MCP, que utiliza cada primitivo para um propósito específico.\n- **D**: Também embaralha o mapeamento — coloca Prompts como "nova capacidade" (deveria ser Tools), Tools como "dados para o app" (deveria ser Resources) e Resources como "fluxos de trabalho" (deveria ser Prompts).','\n',char(10)),replace('Imagine que o Claude é um amigo robô que vive dentro de um aplicativo. Para ele funcionar bem, existem três tipos de "coisas" que o ajudam:\n\n1. **Tools (Ferramentas)** — São como brinquedos novos que o Claude ganha. Ele pode usar um martelo de brinquedo para bater, uma pá para cavar... cada ferramenta dá a ele uma habilidade nova. É uma **nova capacidade** para o Claude.\n\n2. **Resources (Recursos)** — São como o caderno de desenho e os lápis de cor que estão sobre a mesa. Eles **contêm dados e informações** que o Claude pode ver para entender o que está acontecendo no aplicativo.\n\n3. **Prompts (Instruções)** — São como receitas de bolo prontas. O usuário (você!) pode pedir: "Claude, siga a receita do bolo de chocolate". O Claude já sabe o passo a passo porque a receita está pronta. Isso ajuda em **fluxos de trabalho que você mesmo aciona**.\n\nA alternativa **B** acertou tudinho: ferramentas dão novas capacidades, recursos fornecem dados para o app, e instruções prontas ajudam nos trabalhos que você pede.\n\nAs outras alternativas misturam tudo — é como se alguém dissesse que a pá (ferramenta) serve para desenhar (recurso), ou que o caderno (recurso) serve para dar novas capacidades. Não faz sentido!','\n',char(10)));
INSERT INTO cards VALUES('admin','card_1783092990328_wir9zcjyt',403,'Who does each MCP primitive serve?',replace('Who does each MCP primitive serve?\n\nWho does each MCP primitive serve?\n[Resposta correta: Tools servem o modelo, Resources a aplicação e Prompts os usuários. A e D trocam os destinatários. C uniformiza indevidamente tudo no modelo.]\n\n[ ] A - Tools serve the user, Resources serve the model, Prompts serve the application.\n[ ] B - Tools serve the model, Resources serve the application, Prompts serve the users.\n[ ] C - All serve the model.\n[ ] D - Tools serve the application, Resources serve the users, Prompts serve the model.','\n',char(10)),'B - Tools serve the model, Resources serve the application, Prompts serve the users.','["Domain_2::Tool_Design_MCP_Integration", "ForaDoCenario"]','New',0,2.5,0,1783092990328,1783727710587,1783203558653,replace('**Tradução para português do Brasil:**\n\nA quem cada primitiva do MCP serve?\n\n[ ] A - Tools servem o usuário, Resources servem o modelo, Prompts servem a aplicação.\n[ ] B - Tools servem o modelo, Resources servem a aplicação, Prompts servem os usuários.\n[ ] C - Todas servem o modelo.\n[ ] D - Tools servem a aplicação, Resources servem os usuários, Prompts servem o modelo.','\n',char(10)),replace('**Explicação didática para um adulto tech lead:**\n\nNo contexto do Model Context Protocol (MCP), as primitives (ferramentas, recursos e prompts) têm destinatários distintos e bem definidos na arquitetura:\n\n- **Tools (Ferramentas):** São expostas pelo servidor MCP para serem **invocadas pelo modelo de linguagem (LLM)**. O modelo decide quando chamá-las para executar ações como buscar dados externos, realizar cálculos ou interagir com sistemas. Portanto, servem **ao modelo**.\n\n- **Resources (Recursos):** São dados estáticos ou dinâmicos que o servidor disponibiliza para a **aplicação cliente** consumir e enviar ao modelo conforme necessário. Funcionam como uma camada de dados estruturados (ex.: arquivos, banco de dados, APIs) que a aplicação gerencia e alimenta ao modelo. Servem **à aplicação**.\n\n- **Prompts (Instruções/modelos de prompt):** São templates de mensagens ou instruções pré-definidas que auxiliam os **usuários finais** a interagir de forma mais eficiente com o modelo. São curados por desenvolvedores para orientar o comportamento do modelo, mas seu público-alvo são os usuários que os selecionam ou acionam.\n\n**Análise das alternativas incorretas:**\n- **A:** Inverte os destinatários de Tools e Resources, e erra em Prompts.\n- **C:** Uniformiza tudo no modelo, ignorando que Resources são gerenciados pela aplicação e Prompts são voltados aos usuários.\n- **D:** Troca completamente os papéis, atribuindo Tools à aplicação, Resources aos usuários e Prompts ao modelo.','\n',char(10)),replace('Imagine que o MCP é como uma lanchonete com três tipos de itens:\n\n1. **Ferramentas (Tools)** são como as máquinas de refrigerante na cozinha — quem usa são os robôs (o modelo de linguagem) para preparar as coisas.\n2. **Recursos (Resources)** são como os ingredientes no estoque — quem cuida deles é o gerente (a aplicação) para abastecer os robôs.\n3. **Prompts** são como os cardápios prontos — eles ajudam os clientes (os usuários) a escolher o que pedir.\n\nA alternativa B é a correta porque acerta quem usa cada coisa: ferramentas são para o robô, recursos são para o gerente e cardápios são para os clientes. As outras alternativas trocam tudo ou dizem que todo mundo serve só o robô, o que não faz sentido nessa história.','\n',char(10)));
INSERT INTO cards VALUES('admin','card_1783092990350_zqh2mt9gk',404,'What is the difference between MCP servers and skills?',replace('What is the difference between MCP servers and skills?\n\nWhat is the difference between MCP servers and skills?\n[Resposta correta: MCP servers dão ferramentas e integrações; skills dão conhecimento para a conversa, sendo categorias distintas. A nega a diferença. B inverte os papéis. D trata skills como substituto universal.]\n\n[ ] A - They are the same thing with different names.\n[ ] B - MCP servers provide knowledge for the conversation and skills provide external tools.\n[ ] C - MCP servers provide external tools and integrations, while skills provide knowledge for the conversation; they are different categories.\n[ ] D - Skills replace MCP servers in any scenario.','\n',char(10)),'[ ] C - MCP servers provide external tools and integrations, while skills provide knowledge for the conversation; they are different categories.','["Domain_2::Tool_Design_MCP_Integration", "ForaDoCenario"]','New',0,2.5,0,1783092990350,1783727713988,1783203558653,replace('**Tradução da pergunta e alternativas para português do Brasil:**\n\n**Pergunta:** Qual é a diferença entre servidores MCP e skills?\n\n[ ] A - São a mesma coisa com nomes diferentes.\n[ ] B - Servidores MCP fornecem conhecimento para a conversa e skills fornecem ferramentas externas.\n[ ] C - Servidores MCP fornecem ferramentas externas e integrações, enquanto skills fornecem conhecimento para a conversa; são categorias diferentes.\n[ ] D - Skills substituem servidores MCP em qualquer cenário.','\n',char(10)),replace('**Explicação didática para um adulto tech lead:**\n\n**Alternativa correta: C**\n\nA alternativa C descreve precisamente a distinção arquitetural entre MCP servers e skills em plataformas de agentes de IA. MCP (Model Context Protocol) servers são componentes que expõem ferramentas externas, APIs e integrações — ou seja, capacidade de *ação* (ex.: buscar dados em um banco, chamar uma API externa, executar código). Skills, por outro lado, encapsulam *conhecimento* contextual ou instruções que orientam o comportamento do modelo durante a conversa (ex.: "você é um assistente de suporte técnico nível 2").\n\n**Por que as demais alternativas estão erradas:**\n\n- **A** está incorreta porque nega a existência de qualquer diferença. Na prática, MCP servers e skills têm papéis distintos e complementares — um é sobre ferramentas/ações, o outro sobre contexto/conhecimento.\n\n- **B** inverte os papéis: MCP servers não fornecem "conhecimento para a conversa" (esse é o papel das skills), e skills não fornecem "ferramentas externas" (esse é o papel dos MCP servers).\n\n- **D** é incorreta porque skills não substituem MCP servers. Eles operam em camadas diferentes da arquitetura e um não torna o outro obsoleto. Em cenários que exigem integrações externas, MCP servers são necessários; skills não cobrem essa funcionalidade.','\n',char(10)),replace('**Explicação para uma criança de 10 anos:**\n\nImagine que você tem um robô assistente. \n\n- Os **MCP servers** são como as **ferramentas** que o robô pode usar: uma calculadora, um binóculo para ver coisas longe, ou um telefone para ligar para alguém. Eles ajudam o robô a *fazer coisas*.\n- As **skills** são como as **instruções ou conhecimentos** que você ensina para o robô: "Quando alguém pedir ajuda, responda com educação" ou "Você sabe tudo sobre dinossauros". Elas ajudam o robô a *saber como se comportar e o que dizer*.\n\nA alternativa **C** está certa porque diz exatamente isso: MCP servers dão ferramentas externas e skills dão conhecimento para a conversa.\n\nAs outras estão erradas porque:\n- **A** diz que são a mesma coisa — mas não são, uma é ferramenta e outra é conhecimento.\n- **B** troca os papéis, como se a ferramenta desse conhecimento e o conhecimento desse ferramentas.\n- **D** diz que skills podem substituir MCP servers sempre — mas não podem, porque se o robô precisar de uma calculadora, só ensinar boas maneiras não vai resolver!','\n',char(10)));
INSERT INTO cards VALUES('admin','card_1783092990371_tz1u4mbh7',405,'How do you share the configuration of an MCP server with the team while keeping individual credentials?',replace('How do you share the configuration of an MCP server with the team while keeping individual credentials?\n\nHow do you share the configuration of an MCP server with the team while keeping individual credentials?\n[Resposta correta: O padrão é .mcp.json de projeto com variáveis de ambiente e documentação no README, dando fonte única sem expor credenciais. A comita credencial real, o que é inseguro. B faz a config divergir entre devs. D comita placeholder, o que a orientação diz para nunca fazer.]\n\n[ ] A - Commit a .mcp.json with the real token embedded for everyone to use.\n[ ] B - Each dev creates their own per-user config, with no shared file.\n[ ] C - Use a project-scoped .mcp.json expanding environment variables (e.g., ${GITHUB_TOKEN}) and document the variable in the README.\n[ ] D - Put a token placeholder in the .mcp.json and commit it to guide the team.','\n',char(10)),'[ ] C - Use a project-scoped .mcp.json expanding environment variables (e.g., ${GITHUB_TOKEN}) and document the variable in the README.','["Domain_2::Tool_Design_MCP_Integration", "Domain_3::Claude_Code_Configuration_Workflows", "Scenario_4::Developer_Productivity"]','New',0,2.5,0,1783092990371,1783727717622,1783203558653,replace('**Tradução para português do Brasil:**\n\nComo você compartilha a configuração de um servidor MCP com a equipe mantendo credenciais individuais?\n\n[ ] A - Fazer commit de um .mcp.json com o token real embutido para todos usarem.\n[ ] B - Cada desenvolvedor cria sua própria configuração por usuário, sem nenhum arquivo compartilhado.\n[ ] C - Usar um .mcp.json com escopo de projeto que expande variáveis de ambiente (ex.: ${GITHUB_TOKEN}) e documentar a variável no README.\n[ ] D - Colocar um placeholder de token no .mcp.json e fazer commit para guiar a equipe.','\n',char(10)),replace('**Explicação didática para um adulto tech lead:**\n\nO problema central aqui é como balancear compartilhamento de configuração com segurança de credenciais. Vamos analisar cada alternativa:\n\n**Alternativa C (Correta):** Esta é a abordagem recomendada. O arquivo `.mcp.json` com escopo de projeto é versionado e compartilhado com toda a equipe, mas as credenciais sensíveis (tokens, senhas, chaves de API) são referenciadas via variáveis de ambiente (ex.: `${GITHUB_TOKEN}`). O desenvolvedor define essas variáveis localmente (no shell, `.env.local`, ou gerenciador de segredos). Documentar a variável no README garante que novos membros saibam quais variáveis precisam configurar. Isso proporciona: (1) fonte única de verdade para a estrutura da configuração; (2) segurança, pois credenciais não vão para o repositório; (3) flexibilidade para cada dev usar suas próprias credenciais.\n\n**Alternativa A (Incorreta):** Comitar um token real é uma violação grave de segurança. Qualquer pessoa com acesso ao repositório (incluindo fornecedores, ex-funcionários, ou até atacantes em caso de vazamento) teria acesso à credencial. Além disso, se o token for rotacionado, todo o time precisa atualizar o arquivo. É a antítese de boas práticas de segurança.\n\n**Alternativa B (Incorreta):** Cada desenvolvedor criar sua própria configuração per-user significa que não há um arquivo compartilhado. Isso leva à duplicação de esforço, inconsistências entre ambientes (cada um pode ter configurações ligeiramente diferentes), e dificuldade de onboarding — novos membros precisam descobrir como configurar do zero, sem referência.\n\n**Alternativa D (Incorreta):** Colocar um placeholder parece útil, mas a orientação oficial do MCP recomenda explicitamente *nunca* comitar placeholders. Placeholders podem ser interpretados erroneamente como valores reais, esquecidos em commits, ou pior, substituídos por valores reais e commitados acidentalmente. A documentação no README é a forma correta de comunicar o que precisa ser configurado.','\n',char(10)),replace('Imagine que sua equipe tem um controle remoto mágico (o servidor MCP) que todo mundo precisa usar. Esse controle precisa de uma senha especial (o token) para funcionar.\n\n- **Opção A:** Escrever a senha num papel e colar na parede do escritório. Perigoso! Qualquer visitante vê.\n- **Opção B:** Cada pessoa inventa seu próprio controle do zero. Caos! Cada um faz de um jeito diferente.\n- **Opção C (A certa!):** Todo mundo usa o mesmo modelo de controle (arquivo compartilhado), mas cada pessoa guarda sua senha num cadeado pessoal (variável de ambiente). No manual (README), está explicado qual senha cada um precisa ter. Assim, o controle é igual para todos, mas a senha de cada um é secreta.\n- **Opção D:** Escrever "SENHA_AQUI" no papel e pendurar na parede. Alguém pode esquecer de trocar e deixar a senha de verdade exposta.\n\nA opção C é a melhor porque todo mundo segue o mesmo roteiro, mas ninguém corre o risco de ter a senha roubada!','\n',char(10)));
INSERT INTO cards VALUES('admin','card_1783092990393_mfa768id1',406,'An application generates EventBridge JSON rules and the user needs the raw JSON to copy, but Claude always wraps the output in markdown with explanatory text.',replace('An application generates EventBridge JSON rules and the user needs the raw JSON to copy, but Claude always wraps the output in markdown with explanatory text.\n\nAn application generates EventBridge JSON rules and the user needs the raw JSON to copy, but Claude always wraps the output in markdown with explanatory text. Which approach reliably delivers the clean JSON?\n[Resposta correta: O prefill com "```json" mais a stop sequence "```" força Claude a produzir apenas o conteúdo e encerrar ao fechar o bloco. Instruções em prosa (B) não garantem a supressão do markdown, temperature (C) controla aleatoriedade e não formato, e few-shot (D) é mais custoso e menos determinístico que a combinação prefill mais stop sequence.]\n\n[ ] A - Prefix the assistant message with "```json" and set stop_sequences=["```"], making Claude complete only the JSON and stop when it tries to close the block.\n[ ] B - Add the instruction "do not use markdown and do not explain anything" to the user message.\n[ ] C - Increase the temperature to reduce the verbosity of the explanation.\n[ ] D - Ask for few-shot examples of other JSONs until the model learns not to comment.','\n',char(10)),'A - Prefix the assistant message with "```json" and set stop_sequences=["```"], making Claude complete only the JSON and stop when it tries to close the block.','["Domain_4::Prompt_Engineering_Structured_Output", "Domain_2::Tool_Design_MCP_Integration", "Scenario_2::Code_Generation_Claude_Code"]','New',0,2.5,0,1783092990393,1783727721486,1783203558653,replace('**Tradução para português do Brasil:**\n\n**Pergunta:** Um aplicativo gera regras JSON do EventBridge e o usuário precisa do JSON bruto para copiar, mas Claude sempre envolve a saída em markdown com texto explicativo. Qual abordagem entrega o JSON limpo de forma confiável?\n\n**Alternativas:**\n\n[ ] A - Adicionar o prefixo "```json" à mensagem do assistente e definir stop_sequences=["```"], fazendo com que Claude complete apenas o JSON e pare quando tentar fechar o bloco.\n\n[ ] B - Adicionar a instrução "não use markdown e não explique nada" à mensagem do usuário.\n\n[ ] C - Aumentar a temperatura para reduzir a verbosidade da explicação.\n\n[ ] D - Pedir exemplos few-shot de outros JSONs até que o modelo aprenda a não comentar.','\n',char(10)),replace('**Explicação para um adulto tech lead:**\012\012A alternativa **A** é a resposta correta porque utiliza dois mecanismos complementares da API da Anthropic que garantem controle preciso sobre a saída:\012\0121. **Prefill ("```json"):** Ao pré-preenchecer o início da resposta do assistente com o marcador de bloco de código JSON, você "guia" o modelo para continuar a partir dali, produzindo conteúdo JSON válido dentro do bloco markdown. Isso é mais forte do que uma instrução no prompt, pois é parte da própria sequência de saída esperada.\012\0122. **Stop sequence ("```"):** Ao definir a sequência de parada como "```", Claude interrompe a geração imediatamente após fechar o bloco de código, eliminando qualquer texto explicativo posterior que ele poderia adicionar.\012\012Juntos, esses mecanismos garantem que a saída seja exatamente: ```json\n{...}\n``` — e nada mais.\012\012**Análise das alternativas incorretas:**\012\012- **B:** Instruções em prosa no prompt são apenas sugestões. Claude pode ignorá-las parcialmente ou interpretá-las de forma flexível. Embora ajude, não há garantia determinística de supressão de markdown ou comentários.\012\012- **C:** A temperatura controla a aleatoriedade da distribuição de probabilidade da próxima palavra, não o formato estrutural da saída. Temperatura baixa torna o modelo mais determinístico; temperatura alta aumenta a criatividade e, portanto, a probabilidade de *mais* texto explicativo, não menos.\012\012- **D:** Few-shot é útil para aprendizado de padrões, mas é mais caro (consome mais tokens de entrada), menos determinístico (o modelo pode ainda assim adicionar variações) e não oferece o controle rígido de parada que a stop sequence proporciona. A combinação prefill + stop sequence é mais eficiente e confiável.','\012',char(10)),replace('**Explicação para uma criança de 10 anos:**\n\nImagine que você tem um robô que desenha. Você quer que ele desenhe apenas um círculo, mas ele sempre escreve "Esse é um lindo círculo!" em volta. \n\nA alternativa **A** é como colocar o lápis já apontado no papel começando o círculo e dizer ao robô: "PARE de desenhar assim que terminar o círculo". Assim, ele não tem como escrever nada extra!\n\n- A opção **B** é só pedir educadamente "não escreva nada além do círculo". Às vezes ele obedece, às vezes não.\n- A opção **C** é dizer para ele desenhar mais devagar ou mais rápido — isso não muda o fato de que ele ainda quer escrever explicações.\n- A opção **D** é mostrar vários exemplos de círculos sem texto esperando que ele aprenda sozinho. Pode funcionar, mas gasta mais tempo e papel.\n\nA opção **A** é a mais esperta porque usa comandos diretos que o robô é obrigado a seguir, sem depender de "boas maneiras" ou tentativa e erro!','\n',char(10)));
INSERT INTO cards VALUES('admin','card_1783092990415_a0gf6y581',407,'What is the mechanism by which the prefill with "```json" combined with the stop sequence "```" results in JSON without comments?',replace('What is the mechanism by which the prefill with "```json" combined with the stop sequence "```" results in JSON without comments?\n\nWhat is the mechanism by which the prefill with "```json" combined with the stop sequence "```" results in JSON without comments?\n[Resposta correta: O prefill coloca Claude no meio de um bloco de código, então ele só continua com o conteúdo, e a stop sequence corta a geração no fechamento. A stop sequence não apaga texto posterior (A), o prefill não faz validação de schema (C) e a user message isolada não garante ausência de explicação (D).]\n\n[ ] A - The stop sequence deletes the generated markdown after the response ends.\n[ ] B - The prefilled assistant message makes Claude continue from inside a block that has already started, generating only the JSON, and the stop sequence ends the generation when it tries to close the block.\n[ ] C - The prefill instructs the model to validate the JSON schema before responding.\n[ ] D - The user message alone is enough to prevent any explanation.','\n',char(10)),'[ ] B - The prefilled assistant message makes Claude continue from inside a block that has already started, generating only the JSON, and the stop sequence ends the generation when it tries to close the block.','["Domain_4::Prompt_Engineering_Structured_Output", "Scenario_6::Structured_Data_Extraction"]','New',0,2.5,0,1783092990415,1783727724635,1783203558653,replace('**Tradução para português do Brasil:**\n\nQual é o mecanismo pelo qual o preenchimento com "```json" combinado com a sequência de parada "```" resulta em JSON sem comentários?\n\n[ ] A - A sequência de parada deleta o markdown gerado após o fim da resposta.\n[ ] B - A mensagem de assistente pré-preenchida faz com que Claude continue de dentro de um bloco que já foi iniciado, gerando apenas o JSON, e a sequência de parada encerra a geração quando ele tenta fechar o bloco.\n[ ] C - O preenchimento instrui o modelo a validar o schema JSON antes de responder.\n[ ] D - A mensagem do usuário, isoladamente, é suficiente para evitar qualquer explicação.','\n',char(10)),replace('**Explicação didática para um adulto tech lead:**\n\nA alternativa **B** está correta. O mecanismo funciona da seguinte forma:\n\nAo pré-preenchirmos a mensagem do assistente com "```json", estamos inserindo Claude *dentro* de um bloco de código JSON já aberto. O modelo, por sua natureza autocompletiva, simplesmente dá continuidade ao que já está ali — ou seja, ele gera o conteúdo JSON propriamente dito, sem adicionar textos explicativos, porque o contexto já o colocou em modo "bloco de código".\n\nQuando o modelo tenta fechar o bloco escrevendo "```", a stop sequence configurada (também "```") é acionada e interrompe a geração imediatamente. Isso significa que o fechamento do bloco nunca é de fato escrito na saída final; a geração para no exato momento em que começaria a escrevê-lo.\n\n**Por que as demais alternativas estão erradas:**\n\n- **A**: A stop sequence não "deleta" nada. Ela interrompe a geração antes que o texto seja produzido. Não há pós-processamento de exclusão.\n- **C**: O prefill não ativa nenhuma validação de schema. É puramente um artefato de como a geração de texto autocompletiva funciona, não uma instrução metalinguística para o modelo.\n- **D**: A mensagem do usuário sozinha não é suficiente; modelos de linguagem frequentemente adicionam explicações, introduções ou formatação extra. É a combinação do prefill + stop sequence que garante a saída limpa.','\n',char(10)),replace('**Explicação para uma criança de 10 anos:**\n\nImagina que você está escrevendo uma redação e o professor começa a frase para você: "O gato ...". Você só precisa continuar a frase, certo? Não vai começar explicando o que é um gato, porque a frase já começou!\n\nÉ a mesma coisa com o Claude. Quando a gente coloca "```json" no início da resposta, é como se a gente já tivesse começado a escrever um bloco de código. O Claude só continua de onde parou, escrevendo o JSON.\n\nAí a gente diz para ele: "Pare quando você tentar fechar o bloco com ```". Então, quando ele vai escrever o ``` para fechar, a gente aperta o "pause" e ele para. O resultado é um JSON limpinho, sem textos extras nem explicações.\n\nAs outras opções estão erradas porque:\n- **A**: A parada não apaga nada depois — ela só impede que o texto seja escrito.\n- **C**: O Claude não está "validando" o JSON, ele só está continuando o que já estava escrito.\n- **D**: Só a mensagem do usuário não adianta, porque o Claude poderia responder com explicações antes do JSON.','\n',char(10)));
INSERT INTO cards VALUES('admin','card_1783092990441_vgldsdw56',408,'For which types of output is the prefill plus stop sequence technique appropriate?',replace('For which types of output is the prefill plus stop sequence technique appropriate?\n\nFor which types of output is the prefill plus stop sequence technique appropriate?\n[Resposta correta: A técnica serve para qualquer conteúdo formatado onde se quer só o conteúdo sem explicações, incluindo Python, bullets e CSV. Ela não é exclusiva de JSON (A), não se destina a texto explicativo longo (B) e não depende de extended thinking (D), que inclusive é incompatível com prefilling.]\n\n[ ] A - Only for JSON, since it depends on the curly-brace syntax.\n[ ] B - Only for long natural-language responses that need context.\n[ ] C - For any structured content without comments, such as Python snippets, bulleted lists or CSV.\n[ ] D - Only when extended thinking is enabled.','\n',char(10)),'C - For any structured content without comments, such as Python snippets, bulleted lists or CSV.','["Domain_4::Prompt_Engineering_Structured_Output", "Scenario_6::Structured_Data_Extraction"]','New',0,2.5,0,1783092990441,1783727727812,1783203558653,replace('**Tradução para português do Brasil:**\n\nPara quais tipos de saída a técnica de prefill mais stop sequence é apropriada?\n\n[ ] A - Apenas para JSON, já que depende da sintaxe de chaves.\n[ ] B - Apenas para respostas longas em linguagem natural que precisam de contexto.\n[ ] C - Para qualquer conteúdo estruturado sem comentários, como trechos de Python, listas com marcadores ou CSV.\n[ ] D - Apenas quando o extended thinking está habilitado.','\n',char(10)),replace('**Explicação didática para um adulto tech lead:**\012\012A técnica de *prefill plus stop sequence* consiste em pré-popular ("preencher") o início da resposta do modelo e, em seguida, definir uma *stop sequence* (sequência de parada) que interrompe a geração assim que um determinado marcador é atingido. Isso é útil para extrair apenas o conteúdo desejado, sem que o modelo adicione explicações, introduções ou rodeios.\012\012**Análise da alternativa correta (C):**\012A técnica funciona para **qualquer conteúdo estruturado que se queira obter sem comentários adicionais**. Exemplos incluem:\012- **Trechos de código Python**: você preenche o início (ex.: `def funcao():`) e usa uma stop sequence (ex.: `\n\n`) para parar após o bloco de código desejado.\012- **Listas com marcadores (bullets)**: você preenche o primeiro item e usa a quebra de linha dupla como parada.\012- **CSV**: você preenche o cabeçalho e usa uma stop sequence para capturar apenas as linhas de dados.\012\012Não há restrição a um formato específico; o requisito é que o conteúdo seja **estruturado** e que se deseje **excluir comentários ou explicações** que o modelo naturalmente tenderia a adicionar.\012\012**Análise das alternativas incorretas:**\012\012- **Alternativa A**: Incorreta. Embora JSON seja um caso de uso comum (devido à sintaxe previsível com chaves), a técnica não se limita a JSON. Ela funciona para qualquer formato onde se possa prever um início e um ponto de parada claro.\012\012- **Alternativa B**: Incorreta. Para respostas longas em linguagem natural, o prefill mais stop sequence é contraproducente. O objetivo da técnica é justamente **suprimir** o texto explicativo e obter apenas o conteúdo "cru". Em respostas narrativas longas, queremos justamente o oposto — que o modelo complete naturalmente com contexto e explicações.\012\012- **Alternativa D**: Incorreta. Extended thinking (raciocínio estendido) é um modo onde o modelo "pensa" antes de responder, gerando um chain-of-thought interno. Na verdade, o prefill costuma ser **incompatível** com extended thinking, pois o modelo pode ignorar o prefill ou produzir saídas inconsistentes quando nesse modo. A técnica independe do extended thinking.','\012',char(10)),replace('Imagine que você está brincando de completar frases. A técnica de "prefill mais stop sequence" é como dar um empurrãozinho para o computador começar a escrever e depois falar "PARE!" bem na hora certa.\n\n**Explicação simples:**\n\nSe você quer que o computador escreva só uma lista de compras, sem ele ficar enrolando e dizendo "Aqui está sua lista..." ou "Espero que ajude...", você pode:\n1. Começar escrevendo o primeiro item: "Leite"\n2. Pedir para ele parar quando pular uma linha\n\nPronto! Ele vai escrever só os itens da lista, sem conversa fiada.\n\n**Qual alternativa está certa?** A letra **C**. Porque essa técnica serve para vários tipos de conteúdo organizado, como:\n- Códigos de computador (Python)\n- Listas com bolinhas\n- Tabelas simples (CSV)\n\nNão serve só para JSON (alternativa A), não é para textos longos com explicação (alternativa B), e não precisa de um modo especial de pensar do computador (alternativa D).\n\nEntão, resumo: essa técnica é para quando você quer que o computador vá direto ao ponto, sem rodeios!','\n',char(10)));
INSERT INTO cards VALUES('admin','card_1783092990465_9fg7i24ub',409,'What is the main benefit of using XML tags in prompts?',replace('What is the main benefit of using XML tags in prompts?\n\nWhat is the main benefit of using XML tags in prompts?\n[Resposta correta: As XML tags funcionam como delimitadores que separam instruções de dados e identificam seções, especialmente com muito conteúdo interpolado. Elas não reduzem tokens (A), não obrigam a saída a ser XML (C) e não têm relação com extended thinking (D).]\n\n[ ] A - Reducing the token consumption of the prompt.\n[ ] B - Creating clear delimiters that help Claude distinguish instructions from data and know which section each piece of text belongs to.\n[ ] C - Forcing the model output to always come in XML format.\n[ ] D - Automatically activating extended thinking mode.','\n',char(10)),'B - Creating clear delimiters that help Claude distinguish instructions from data and know which section each piece of text belongs to.','["Domain_4::Prompt_Engineering_Structured_Output", "ForaDoCenario"]','New',0,2.5,0,1783092990465,1783727731267,1783203558653,replace('**Tradução para português do Brasil:**\n\nPergunta: Qual é o principal benefício de usar tags XML em prompts?\n\n[ ] A - Reduzir o consumo de tokens do prompt.\n[ ] B - Criar delimitadores claros que ajudam o Claude a distinguir instruções de dados e saber a qual seção cada parte do texto pertence.\n[ ] C - Forçar a saída do modelo a sempre vir em formato XML.\n[ ] D - Ativar automaticamente o modo de pensamento estendido (extended thinking).','\n',char(10)),replace('**Explicação para um adulto tech lead:**\n\nA alternativa correta é a **B**.\n\nTags XML (como `<instrucao>`, `<dados>`, `<exemplo>`, etc.) funcionam como **delimitadores semânticos** no prompt. Elas organizam a estrutura do texto de forma que o modelo consiga identificar claramente onde começa e termina cada seção. Isso é especialmente útil em prompts complexos, com muito conteúdo interpolado (mistura de instruções, exemplos, dados de entrada, contexto), pois reduz a ambiguidade e melhora a aderência do modelo ao que se espera de cada parte.\n\nPor que as demais estão incorretas:\n\n- **Alternativa A (Reduzir o consumo de tokens):** Incorreta. Tags XML, na verdade, **adicionam** tokens ao prompt (cada tag consome tokens de abertura e fechamento). Elas não reduzem o consumo; o benefício é estrutural, não econômico.\n\n- **Alternativa C (Forçar a saída em XML):** Incorreta. Tags XML no prompt são uma técnica de formatação da entrada. Elas não obrigam o modelo a gerar saída em XML. O formato da saída deve ser especificado separadamente nas instruções, se desejado.\n\n- **Alternativa D (Ativar automaticamente o extended thinking):** Incorreta. O modo extended thinking (raciocínio estendido) é um recurso independente, ativado por parâmetros específicos da API ou configuração do modelo, não pelo uso de tags XML no conteúdo do prompt.','\n',char(10)),replace('Imagine que você está escrevendo uma carta para um amigo e quer separar bem as partes: o que é um pedido, o que é uma informação e o que é um exemplo. Se você misturar tudo, seu amigo pode se confundir.\n\nAs tags XML funcionam como **caixinhas organizadas** dentro do texto. Você coloca uma etiqueta no começo (tipo `<pedido>`) e outra no final (`</pedido>`) para mostrar onde cada coisa começa e termina. Assim, o Claude (o modelo de IA) entende direitinho o que é instrução, o que é dado e o que é exemplo, sem se embaralhar.\n\n- A opção A está errada porque as tags não diminuem a quantidade de "palavras" que o modelo precisa ler — na verdade, elas até aumentam um pouquinho.\n- A opção C está errada porque as tags não obrigam o modelo a responder sempre no formato XML. Elas só servem para organizar a entrada.\n- A opção D está errada porque as tags não ativam nenhum modo especial de pensar. O modo de pensar mais profundamente é outra coisa, ligado por botões diferentes.\n\nResumindo: a resposta certa é a **B**, porque as tags XML são como etiquetas organizadoras que ajudam o Claude a não se confundir.','\n',char(10)));
INSERT INTO cards VALUES('admin','card_1783092990489_yacqgc1b7',410,'In which situation does using XML tags bring the most value?',replace('In which situation does using XML tags bring the most value?\n\nIn which situation does using XML tags bring the most value?\n[Resposta correta: As tags ajudam mais quando há muito contexto, mistura de tipos de conteúdo e várias variáveis interpoladas. Em prompts curtos e simples o ganho é mínimo (A), elas não afetam criatividade (B) e não dependem de stop sequences (D).]\n\n[ ] A - In short single-sentence prompts with no interpolated data.\n[ ] B - When you want the response to be more creative.\n[ ] C - When including a lot of context, mixing content types and interpolating multiple variables in complex prompts.\n[ ] D - Only when stop sequences are used.','\n',char(10)),'[ ] C - When including a lot of context, mixing content types and interpolating multiple variables in complex prompts.','["Domain_4::Prompt_Engineering_Structured_Output", "ForaDoCenario"]','New',0,2.5,0,1783092990489,1783727734357,1783203558653,replace('**Tradução para português do Brasil:**\n\nEm qual situação o uso de tags XML traz mais valor?\n\n[ ] A - Em prompts curtos de uma única frase, sem dados interpolados.\n[ ] B - Quando você deseja que a resposta seja mais criativa.\n[ ] C - Ao incluir muito contexto, misturar tipos de conteúdo e interpolar múltiplas variáveis em prompts complexos.\n[ ] D - Apenas quando sequências de parada (stop sequences) são usadas.','\n',char(10)),replace('**Explicação didática para um adulto tech lead:**\n\nA alternativa correta é a **C**.\n\n**Por que a C está correta:**\nTags XML (como `<context>`, `<instruction>`, `<data>`, `<example>`, etc.) são uma técnica poderosa de engenharia de prompt para estruturar e delimitar diferentes partes de uma entrada complexa. Em prompts que contêm:\n- **Muito contexto**: grandes blocos de informação que precisam ser interpretados corretamente;\n- **Mistura de tipos de conteúdo**: como instruções, dados estruturados, exemplos e formatação de saída;\n- **Múltiplas variáveis interpoladas**: valores dinâmicos inseridos em diferentes partes do prompt;\n\n...as tags XML ajudam o modelo a entender a semântica de cada seção, reduzindo ambiguidades e melhorando a precisão da resposta. É uma forma de "namespacing" textual que organiza o prompt de maneira hierárquica e clara.\n\n**Por que as demais estão erradas:**\n- **A**: Em prompts curtos e simples, o valor das tags é mínimo. Não há complexidade o suficiente para justificar a sobrecarga sintática. Na verdade, tags podem atrapalhar mais do que ajudar nesse cenário.\n- **B**: Criatividade não é afetada por tags XML. Tags são um mecanismo estrutural, não um parâmetro de estímulo criativo (como temperatura ou top-p).\n- **D**: Stop sequences são um recurso de controle de geração (quando parar de gerar tokens). Não têm relação com a utilidade de tags XML. Tags são usadas na entrada (prompt), não na configuração de saída.','\n',char(10)),replace('Vamos imaginar que você está escrevendo uma carta para um amigo. Se a carta for curta, tipo "Vamos jogar bola amanhã?", não precisa de muita organização, né? Agora, se você quiser contar uma história longa, com vários personagens, lugares diferentes e até incluir um desenho, fica mais fácil se você separar cada parte com títulos, como "Personagens:", "Lugares:", "História:".\n\nAs tags XML funcionam como esses títulos. Elas ajudam o computador a entender qual parte do texto é uma instrução, qual parte é um exemplo e qual parte é um dado importante.\n\nEntão, a resposta certa é a letra **C**: as tags XML ajudam mais quando o prompt (o texto que você dá para o computador) é grande, tem vários tipos de informação misturados e precisa de organização. Nas outras situações:\n- **A**: Prompt curto não precisa de tags, é como a cartinha simples.\n- **B**: As tags não deixam a resposta mais criativa, elas só organizam a informação.\n- **D**: "Stop sequences" são uma coisa totalmente diferente (é tipo falar "para aqui" na hora da resposta), não tem nada a ver com as tags.','\n',char(10)));
INSERT INTO cards VALUES('admin','card_1783092990552_p8lchuj4l',411,'When is it preferable to use multi-shot instead of one-shot prompting?',replace('When is it preferable to use multi-shot instead of one-shot prompting?\n\nWhen is it preferable to use multi-shot instead of one-shot prompting?\n[Resposta correta: Multi-shot é indicado para cobrir múltiplos edge cases e diferentes formatos válidos de resposta. Ele aumenta tokens em vez de reduzir (A), não é necessário quando um exemplo basta (B) e não tem relação com temperature (D).]\n\n[ ] A - When you want to reduce the number of tokens in the prompt as much as possible.\n[ ] B - When a single example already covers all the cases.\n[ ] C - When you need to cover several edge cases or show different types of valid response.\n[ ] D - When the goal is to increase the temperature of the response.','\n',char(10)),'[ ] C - When you need to cover several edge cases or show different types of valid response.','["Domain_4::Prompt_Engineering_Structured_Output", "Scenario_6::Structured_Data_Extraction"]','New',0,2.5,0,1783092990552,1783727737520,1783203558653,replace('**Tradução para português do Brasil:**\n\nQuando é preferível usar multi-shot em vez de one-shot prompting?\n\n[ ] A - Quando você deseja reduzir ao máximo o número de tokens no prompt.\n[ ] B - Quando um único exemplo já cobre todos os casos.\n[ ] C - Quando você precisa cobrir vários edge cases ou mostrar diferentes tipos de resposta válida.\n[ ] D - Quando o objetivo é aumentar a temperatura da resposta.','\n',char(10)),replace('**Explicação didática para um adulto tech lead:**\n\nA pergunta aborda a escolha entre técnicas de prompting: one-shot (um único exemplo) vs. multi-shot (múltiplos exemplos) no contexto de LLMs. Vamos analisar cada alternativa.\n\n**Resposta correta: C**\n\nO multi-shot prompting é a abordagem ideal quando o domínio do problema apresenta múltiplos cenários de borda (edge cases) ou diferentes formatos/semânticas de resposta que são todos considerados válidos. Ao fornecer vários exemplos, você condiciona o modelo a generalizar corretamente para toda a variedade de entradas possíveis, reduzindo a ambiguidade e aumentando a precisão. Um único exemplo (one-shot) pode levar o modelo a superajustar (overfit) aquele padrão específico, falhando em casos que fogem do exemplo mostrado.\n\n**Análise dos erros:**\n\n- **A (Reduzir tokens):** Esta alternativa está errada porque multi-shot, por definição, adiciona mais exemplos ao prompt, o que *aumenta* o número de tokens, não reduz. Se o objetivo é minimizar tokens, usa-se zero-shot ou one-shot.\n\n- **B (Um exemplo já cobre tudo):** Se um único exemplo já é suficiente para cobrir todos os casos, não há necessidade de multi-shot. O one-shot já resolveria. Usar multi-shot aqui seria redundante e custoso (mais tokens, maior latência).\n\n- **D (Aumentar temperature):** Temperature é um hiperparâmetro de amostragem que controla a aleatoriedade da saída (quanto maior, mais criativa/aleatória). Não há relação causal entre escolher multi-shot e alterar temperature. São conceitos ortogonais: um diz respeito à estrutura do prompt, o outro à decodificação da resposta.','\n',char(10)),replace('**Explicação para uma criança de 10 anos:**\n\nImagine que você está aprendendo a desenhar animais.\n\n- **One-shot** é quando a professora mostra UM desenho de cachorro e pede para você desenhar qualquer animal. Você pode até desenhar um gato ou um pássaro, mas talvez só saiba desenhar cachorro porque foi o único exemplo que viu.\n\n- **Multi-shot** é quando a professora mostra vários desenhos: um cachorro, um gato, um pássaro e um peixe. Assim você entende que pode desenhar animais diferentes, e não fica preso a um só.\n\nA alternativa C diz: "Quando você precisa cobrir vários casos diferentes ou mostrar diferentes tipos de resposta válida." É exatamente isso! Se você só mostra um exemplo, o modelo (ou a criança) pode achar que só existe um jeito certo de responder. Mostrando vários exemplos, ele aprende a lidar com situações diferentes.\n\nAs outras opções estão erradas porque:\n- **A** diz que multi-shot serve para reduzir tokens (palavras no prompt). Na verdade, multi-shot COLOCA MAIS palavras, então não reduz nada.\n- **B** diz para usar multi-shot quando um exemplo já basta. Ora, se um já basta, pra que usar vários? É desperdício.\n- **D** fala em aumentar a temperatura. Temperatura é um ajuste que faz o modelo responder de jeitos mais criativos ou mais certinhos, e não tem nada a ver com usar um ou muitos exemplos.','\n',char(10)));
INSERT INTO cards VALUES('admin','card_1783092990574_37ovbtzbh',412,'What is the recommended good practice when naming XML tags in a prompt?',replace('What is the recommended good practice when naming XML tags in a prompt?\n\nWhat is the recommended good practice when naming XML tags in a prompt?\n[Resposta correta: Nomes específicos e descritivos ajudam Claude a entender o propósito de cada seção. Nomes genéricos (A), aleatórios (C) ou numéricos (D) não comunicam a função da seção e reduzem a clareza.]\n\n[ ] A - Always use generic, short names like <a> or <x> to save tokens.\n[ ] B - Use specific, descriptive names like <sales_records>, <my_code> or <docs>.\n[ ] C - Use random names so as not to induce biases in the model.\n[ ] D - Use only numeric tags like <1> and <2>.','\n',char(10)),'B - Use specific, descriptive names like <sales_records>, <my_code> or <docs>.','["Domain_4::Prompt_Engineering_Structured_Output", "ForaDoCenario"]','New',0,2.5,0,1783092990574,1783727740731,1783203558653,replace('**Tradução para português do Brasil:**\n\n**Pergunta:** Qual é a boa prática recomendada ao nomear tags XML em um prompt?\n\n[ ] A - Sempre usar nomes genéricos e curtos como `<a>` ou `<x>` para economizar tokens.\n[ ] B - Usar nomes específicos e descritivos como `<sales_records>`, `<my_code>` ou `<docs>`.\n[ ] C - Usar nomes aleatórios para não induzir vieses no modelo.\n[ ] D - Usar apenas tags numéricas como `<1>` e `<2>`.','\n',char(10)),replace('**Explicação didática para um adulto tech lead:**\n\nA alternativa **B** é a correta. Quando estruturamos prompts com tags XML (ou delimitadores similares), o objetivo é comunicar claramente ao modelo a função de cada seção do conteúdo. Nomes como `<sales_records>`, `<my_code>` ou `<docs>` funcionam como *semantic hints* — eles carregam significado que ajuda o modelo a inferir o propósito, o formato esperado e o contexto daquela seção.\n\n**Por que as demais estão erradas:**\n\n- **Alternativa A (nomes genéricos como `<a>` ou `<x>`)**: Embora economizem alguns tokens, o custo de tokens de nomes descritivos é marginal comparado ao ganho de clareza. Nomes genéricos não comunicam propósito e podem confundir o modelo sobre qual dado deve estar ali. A economia de tokens não justifica a perda de precisão semântica.\n\n- **Alternativa C (nomes aleatórios)**: Nomes aleatórios não eliminam vieses — apenas removem qualquer sinal semântico útil. O modelo não é "enviesado" por nomes descritivos; pelo contrário, é guiado corretamente. Aleatoriedade introduz ruído desnecessário na comunicação.\n\n- **Alternativa D (tags numéricas)**: Tags como `<1>` e `<2>` são tão genéricas quanto as da alternativa A e não fornecem contexto algum. O modelo precisa "adivinhar" o que cada número representa, o que reduz a confiabilidade e a precisão do output.\n\n**Conclusão:** Nomes descritivos são uma forma de *prompt engineering* que melhora a aderência do modelo à estrutura desejada, sem custo significativo de tokens.','\n',char(10)),replace('Imagine que você precisa organizar seu quarto. Você tem uma caixa para brinquedos, outra para livros e outra para roupas. Se você escrever "Caixa 1", "Caixa 2" e "Caixa 3" nas caixas, quando quiser achar um brinquedo, vai ter que abrir todas até encontrar. Agora, se você escrever "Brinquedos", "Livros" e "Roupas", fica muito mais fácil encontrar o que procura!\n\nA mesma coisa acontece quando a gente dá instruções para o Claude. Se a gente usa nomes como `<vendas>` ou `<codigo>`, o Claude entende rapidinho o que vai em cada parte. Se a gente usa nomes estranhos como `<a>` ou `<1>`, ele fica confuso e pode misturar tudo.\n\nEntão, a melhor escolha é a **letra B**: usar nomes que explicam o que cada parte significa, igual colocar etiquetas bonitas nas caixas do seu quarto!','\n',char(10)));
INSERT INTO cards VALUES('admin','card_1783092990596_kl45vhj1s',413,'A sentiment classifier gets sarcastic comments wrong, labeling them as positive.',replace('A sentiment classifier gets sarcastic comments wrong, labeling them as positive.\n\nA sentiment classifier gets sarcastic comments wrong, labeling them as positive. Which prompt technique best solves the problem?\n[Resposta correta: Exemplos que mostram como tratar o caso difícil, com o sarcasmo rotulado e explicado, ensinam o padrão desejado. Aumentar temperature (B) não corrige a lógica de classificação, repetir a instrução (C) não adiciona sinal novo e trocar o modelo (D) não endereça a falta de exemplos do caso de borda.]\n\n[ ] A - Add few-shot examples with a sarcastic case labeled as "Negative" and context explaining why it should be treated that way.\n[ ] B - Increase the temperature so the model considers more interpretations.\n[ ] C - Repeat the phrase "detect sarcasm correctly" several times in the instruction.\n[ ] D - Swap the model for a larger one without changing the prompt.','\n',char(10)),'A - Add few-shot examples with a sarcastic case labeled as "Negative" and context explaining why it should be treated that way.','["Domain_4::Prompt_Engineering_Structured_Output", "Scenario_6::Structured_Data_Extraction"]','New',0,2.5,0,1783092990596,1783727744125,1783203558653,replace('**Tradução para português do Brasil:**\n\nUm classificador de sentimentos erra comentários sarcásticos, rotulando-os como positivos. Qual técnica de prompt resolve melhor o problema?\n\n[ ] A - Adicionar exemplos few-shot com um caso sarcástico rotulado como "Negativo" e contexto explicando por que deve ser tratado dessa forma.\n[ ] B - Aumentar a temperatura para que o modelo considere mais interpretações.\n[ ] C - Repetir a frase "detecte sarcasmo corretamente" várias vezes na instrução.\n[ ] D - Trocar o modelo por um maior sem alterar o prompt.','\n',char(10)),replace('**Explicação para adulto (tech lead):**\n\nO problema central é que o classificador de sentimentos está sendo "enganado" pelo sarcasmo — uma afirmação que parece positiva na superfície, mas carrega intenção negativa. Modelos de linguagem, por padrão, tendem a interpretar o texto literalmente se não receberem instruções ou exemplos que explicitem o tratamento de casos ambíguos.\n\n**Alternativa A (correta):** Few-shot learning é a técnica mais direta e eficaz para ensinar ao modelo um padrão de borda (edge case). Ao fornecer um exemplo explícito de sarcasmo rotulado como "Negative" e, idealmente, com uma breve explicação do raciocínio, você está condicionando o modelo a generalizar aquele comportamento para novos casos similares. Isso atua diretamente na causa raiz: a falta de representação do caso de borda no prompt.\n\n**Alternativa B (incorreta):** A temperatura controla a aleatoriedade da amostragem (nível de criatividade/risco nas respostas). Aumentá-la não corrige a lógica de classificação — apenas faz o modelo "chutar" mais variações, o que pode piorar a precisão em vez de resolvê-la.\n\n**Alternativa C (incorreta):** Repetir a instrução não adiciona informação nova ao modelo. O prompt continua semanticamente o mesmo; repetições não criam exemplos concretos nem ensinam o padrão desejado. O modelo já "ouviu" a instrução na primeira menção.\n\n**Alternativa D (incorreta):** Trocar para um modelo maior pode, eventualmente, melhorar o desempenho geral, mas não endereça a necessidade específica de ensinar o caso de borda do sarcasmo. Sem exemplos ou instruções adequadas no prompt, o modelo maior continuará cometendo o mesmo erro. É uma abordagem indireta e ineficiente comparada ao few-shot direcionado.','\n',char(10)),replace('Imagine que você tem um robô que lê frases e diz se elas são "felizes" ou "tristes". Mas tem um problema: quando alguém fala uma coisa zuando (sarcasmo), tipo "Nossa, que dia maravilhoso!" num dia chuvoso, o robô acha que é feliz, mas na verdade é triste.\n\nA melhor maneira de consertar isso é dar um exemplo para o robô, mostrando: "Olha, quando alguém fala isso zuando, na verdade é triste, entendeu?" É como ensinar uma criança: mostrar um exemplo prático funciona muito melhor do que só repetir a regra várias vezes.\n\nAs outras opções não funcionam bem:\n- Aumentar a "temperatura" do robô seria como deixá-lo mais bagunceiro e criativo — isso só piora, porque ele vai chutar mais ainda.\n- Ficar repetindo "detecte sarcasmo" sem mostrar um exemplo é como mandar a criança "prestar atenção" sem explicar no que.\n- Pegar um robô maior e mais potente, mas sem ensinar o exemplo, é como comprar um computador novo e esperar que ele mágicamente entenda sarcasmo — não funciona.\n\nEntão a resposta certa é a letra **A**: mostrar um exemplo prático de sarcasmo e explicar por que ele é negativo.','\n',char(10)));
INSERT INTO cards VALUES('admin','card_1783092990617_h7extegjm',414,'What is a good source of examples to include in a few-shot prompt?',replace('What is a good source of examples to include in a few-shot prompt?\n\nWhat is a good source of examples to include in a few-shot prompt?\n[Resposta correta: Os pares de maior pontuação nas avaliações demonstram o output perfeito para o seu caso específico. Exemplos aleatórios (A) não têm qualidade garantida, os de menor nota (C) ensinam o padrão errado e exemplos genéricos (D) não refletem o caso de uso real.]\n\n[ ] A - Generate random examples without going through any evaluation.\n[ ] B - Use the input/output pairs with the highest score in the evaluations, since they show the ideal output for the case.\n[ ] C - Use the pairs that got the lowest scores so the model learns from mistakes.\n[ ] D - Copy generic examples from the documentation, unrelated to the use case.','\n',char(10)),'B - Use the input/output pairs with the highest score in the evaluations, since they show the ideal output for the case.','["Domain_4::Prompt_Engineering_Structured_Output", "ForaDoCenario"]','New',0,2.5,0,1783092990617,1783727747541,1783203558653,replace('**Tradução para português do Brasil:**\n\nPergunta: Qual é uma boa fonte de exemplos para incluir em um prompt de few-shot?\n\n[ ] A - Gerar exemplos aleatórios sem passar por nenhuma avaliação.\n[ ] B - Usar os pares de entrada/saída com a maior pontuação nas avaliações, pois eles mostram o output ideal para o caso.\n[ ] C - Usar os pares que obtiveram as menores pontuações para que o modelo aprenda com os erros.\n[ ] D - Copiar exemplos genéricos da documentação, não relacionados ao caso de uso.','\n',char(10)),replace('**Explicação para adulto tech lead:**\n\nA técnica de few-shot prompting consiste em fornecer ao modelo alguns exemplos de entrada e saída desejada dentro do próprio prompt, para que ele entenda o padrão esperado e generalize a partir dali. A eficácia do few-shot depende diretamente da qualidade e representatividade dos exemplos fornecidos.\n\n**Alternativa correta: B**\n\nA alternativa B está correta porque pares de entrada/saída com as maiores pontuações em avaliações representam o "gold standard" do comportamento esperado. Eles foram validados como exemplos de alta qualidade, mostrando exatamente o tipo de output que queremos que o modelo reproduza. Incluir esses exemplos no prompt fornece ao modelo uma referência clara e precisa do que constitui uma resposta bem-sucedida.\n\n**Por que as demais estão incorretas:**\n\n- **A (Gerar exemplos aleatórios sem avaliação):** Exemplos aleatórios podem conter ruído, inconsistências, erros ou simplesmente não representar o padrão desejado. Sem avaliação, não há garantia de qualidade, o que pode levar o modelo a aprender padrões incorretos ou irrelevantes.\n\n- **C (Usar pares com as menores pontuações):** Esta alternativa é contra-intuitiva. Embora aprender com erros seja útil em contextos de fine-tuning ou aprendizado supervisionado clássico (onde o modelo pode corrigir seus pesos), no few-shot prompting estamos apenas dando exemplos no contexto. Apresentar exemplos ruins ensina ao modelo o padrão errado de resposta, prejudicando a performance.\n\n- **D (Copiar exemplos genéricos da documentação):** Exemplos genéricos e não relacionados ao caso de uso falham em contextualizar o modelo para a tarefa específica. Few-shot funciona melhor quando os exemplos são representativos do domínio e do formato desejado. Exemplos genéricos podem até confundir o modelo, pois não refletem as nuances do seu problema particular.','\n',char(10)),replace('**Explicação para criança de 10 anos:**\n\nImagina que você tem um robô que precisa aprender a desenhar cachorros. Você pode dar alguns exemplos de desenhos para ele copiar. Qual seria a melhor escolha?\n\n- **Opção B (a resposta certa):** Mostrar os melhores desenhos de cachorro que existem! Se você mostrar desenhos lindos, o robô vai tentar fazer algo parecido e vai sair bonito.\n\n- **Opção A (errada):** Pegar qualquer desenho aleatório. Pode ser um rabisco feio sem querer, e o robô vai achar que desenhar assim está certo.\n\n- **Opção C (errada):** Mostrar os piores desenhos, cheios de erros. Você estaria ensinando o robô a errar também!\n\n- **Opção D (errada):** Mostrar desenhos de gatos, carros ou flores. O robô vai ficar confuso porque você pediu para ele desenhar cachorros, mas só mostrou outras coisas.\n\n**Resumo:** Para ensinar bem, sempre mostre os melhores exemplos do que você quer que o robô faça!','\n',char(10)));
INSERT INTO cards VALUES('admin','card_1783092990638_sj1r377y7',415,'What are the two types of guidelines used to make a prompt more specific?',replace('What are the two types of guidelines used to make a prompt more specific?\n\nWhat are the two types of guidelines used to make a prompt more specific?\n[Resposta correta: Os dois tipos são Output Quality Guidelines (qualidades da saída) e Process Steps (passos de raciocínio antes da resposta). Stop sequences e prefill (B) controlam formato de saída, one/multi-shot (C) são estratégias de exemplos e temperature/effort (D) são parâmetros de geração, não guidelines de especificidade.]\n\n[ ] A - Output Quality Guidelines and Process Steps.\n[ ] B - Stop sequences and prefill.\n[ ] C - One-shot and multi-shot.\n[ ] D - Temperature and effort.','\n',char(10)),'A - Output Quality Guidelines and Process Steps.','["Domain_4::Prompt_Engineering_Structured_Output", "ForaDoCenario"]','New',0,2.5,0,1783092990638,1783727750622,1783203558653,replace('**Tradução para português do Brasil:**\n\nPergunta: Quais são os dois tipos de diretrizes usadas para tornar um prompt mais específico?\n\n[ ] A - Output Quality Guidelines (Diretrizes de Qualidade da Saída) e Process Steps (Passos de Processo).\n[ ] B - Stop sequences (sequências de parada) e prefill (preenchimento).\n[ ] C - One-shot (um exemplo) e multi-shot (vários exemplos).\n[ ] D - Temperature (temperatura) e effort (esforço).','\n',char(10)),replace('**Explicação para um adulto tech lead:**\n\nA pergunta trata de técnicas de engenharia de prompt para aumentar a especificidade das respostas de modelos de linguagem (LLMs). A alternativa A está correta porque "Output Quality Guidelines" e "Process Steps" são, de fato, duas categorias estabelecidas de diretrizes que instruem o modelo a produzir respostas mais precisas e alinhadas ao que se deseja.\n\n- **Output Quality Guidelines:** São instruções que definem critérios de qualidade para a saída, como "seja conciso", "use linguagem técnica", "responda em formato JSON", "evite opiniões pessoais". Elas moldam o estilo, a estrutura e o nível de detalhe da resposta.\n- **Process Steps:** São instruções que definem uma sequência de raciocínio ou etapas que o modelo deve seguir antes de produzir a resposta final, como "primeiro, analise o problema, depois liste as opções e, por fim, escolha a melhor". Isso força o modelo a decompor o problema, aumentando a confiabilidade e a especificidade da saída.\n\nAnálise das alternativas incorretas:\n\n- **B - Stop sequences and prefill:** Embora sejam técnicas úteis para controlar o formato e o início da resposta (ex.: forçar o modelo a começar com "Resposta:" ou parar em um token específico), elas não são "guidelines" (diretrizes) que tornam o prompt mais específico. São mecanismos de controle de tokenização e geração, não instruções semânticas para o conteúdo.\n- **C - One-shot and multi-shot:** São estratégias de few-shot learning, onde se fornecem exemplos no prompt. Elas melhoram a qualidade da resposta, mas não são "dois tipos de guidelines" — são abordagens de exemplificação, e não diretrizes explícitas sobre qualidade da saída ou processo.\n- **D - Temperature and effort:** Temperature é um parâmetro de amostragem que controla a criatividade vs. determinismo; effort (às vezes referido como "effort level" em alguns APIs) é um parâmetro que influencia o quanto o modelo "tenta" raciocinar. Ambos são hiperparâmetros de configuração do modelo, e não diretrizes escritas no prompt para torná-lo mais específico.\n\nPortanto, a resposta correta é a alternativa A.','\n',char(10)),replace('Imagine que você está pedindo ajuda para um robô que responde perguntas. Para ele entender direitinho o que você quer, você precisa dar "instruções especiais". Essas instruções são de dois tipos:\n\n1. **Diretrizes de Qualidade da Saída:** É como dizer "me responda com palavras fáceis" ou "escreva a resposta em forma de lista". Você está dizendo COMO você quer a resposta.\n2. **Passos de Processo:** É como dizer "primeiro pense em todas as ideias, depois escolha a melhor e só então me responda". Você está dizendo QUAL RACIOCÍNIO o robô deve fazer antes de falar a resposta final.\n\nAs outras opções estão erradas porque:\n- **B (sequências de parada e preenchimento):** São truques para fazer o robô começar ou parar de falar em momentos certos, mas não são "instruções" para ele pensar melhor.\n- **C (um exemplo e vários exemplos):** É quando você mostra exemplos para o robô copiar, mas não são os dois tipos principais de instrução.\n- **D (temperatura e esforço):** São botões de ajuste do robô (como "mais criativo" ou "mais caprichado"), e não instruções escritas no pedido.\n\nEntão, a resposta certa é a letra A: Output Quality Guidelines e Process Steps!','\n',char(10)));
INSERT INTO cards VALUES('admin','card_1783092990660_4xr760436',416,'Why might providing only the input/output pair not be enough in an example?',replace('Why might providing only the input/output pair not be enough in an example?\n\nWhy might providing only the input/output pair not be enough in an example?\n[Resposta correta: Adicionar contexto explicando por que o output é bom ajuda Claude a captar os critérios de qualidade. O modelo não exige JSON (A), numeração não é requisito (C) e a questão não é consumo de tokens (D).]\n\n[ ] A - Because the model ignores any example that is not in JSON.\n[ ] B - Because explaining why that output is good helps Claude understand what makes the response high quality.\n[ ] C - Because examples always need to be numbered to work.\n[ ] D - Because a single pair consumes too many tokens.','\n',char(10)),'B - Because explaining why that output is good helps Claude understand what makes the response high quality.','["Domain_4::Prompt_Engineering_Structured_Output", "ForaDoCenario"]','New',0,2.5,0,1783092990660,1783727754031,1783203558653,replace('**Tradução para português do Brasil:**\n\n**Pergunta:** Por que pode não ser suficiente fornecer apenas o par entrada/saída em um exemplo?\n\n**[ ] A - Porque o modelo ignora qualquer exemplo que não esteja em JSON.**\n**[ ] B - Porque explicar por que a saída é boa ajuda o Claude a entender o que torna a resposta de alta qualidade.**\n**[ ] C - Porque os exemplos sempre precisam ser numerados para funcionar.**\n**[ ] D - Porque um único par consome muitos tokens.**','\n',char(10)),replace('**Explicação didática para um adulto tech lead:**\n\nA alternativa B é a correta. Ao fornecer exemplos (few-shot prompting) para modelos como Claude, incluir apenas o par input/output é útil, mas limitado. O que realmente potencializa a eficácia do exemplo é adicionar uma explicação ou raciocínio que justifique *por que* aquela saída é considerada boa. Isso ajuda o modelo a inferir os critérios de qualidade, o tom, o estilo e as regras implícitas que você espera ver nas respostas. Sem essa contextualização, o modelo pode focar apenas no padrão superficial, sem captar os aspectos qualitativos desejados.\n\n**Análise das alternativas incorretas:**\n\n- **Alternativa A (incorreta):** É uma afirmação falsa. Modelos como Claude podem processar exemplos em diversos formatos (texto livre, Markdown, etc.). JSON não é um requisito obrigatório para que exemplos sejam considerados ou processados.\n\n- **Alternativa C (incorreta):** Não há exigência de que exemplos sejam numerados. Eles podem ser apresentados de várias formas (listas, parágrafos, diálogos). A numeração é irrelevante para a eficácia do aprendizado few-shot.\n\n- **Alternativa D (incorreta):** A questão do consumo de tokens não é o ponto central. Um único par input/output geralmente consome poucos tokens. O problema não é a quantidade de tokens, mas a falta de informação semântica que explique o "porquê" da qualidade da resposta.','\n',char(10)),replace('Imagine que você está ensinando um amigo a desenhar. Se você mostrar só o desenho final (a saída) e a foto que ele copiou (a entrada), seu amigo pode não entender *por que* aquele desenho ficou bonito — talvez ele não perceba que você caprichou nos olhos ou usou cores vibrantes de propósito.\n\nAgora, se você explicar: "Olha, eu pintei o céu de azul claro porque queria passar tranquilidade, e fiz os olhos bem grandes para dar um ar simpático" — aí seu amigo entende *o que* faz o desenho ser bom e pode caprichar nessas partes também.\n\nÉ a mesma coisa com o Claude. Se você só der um exemplo de pergunta e resposta, ele pode até copiar o formato, mas não vai saber quais detalhes são importantes. Explicar por que a resposta é boa é como dar um "mapa do tesouro" para o modelo entender o que você realmente quer!','\n',char(10)));
INSERT INTO cards VALUES('admin','card_1783092990683_9o7451tkv',417,'Which description corresponds to the iterative prompt engineering cycle?',replace('Which description corresponds to the iterative prompt engineering cycle?\n\nWhich description corresponds to the iterative prompt engineering cycle?\n[Resposta correta: O ciclo envolve definir objetivo, escrever, avaliar, aplicar técnicas e re-avaliar iterativamente, com melhora mensurável a cada passo. Usar sem avaliação (A) contraria o ciclo, mexer na temperature (C) e trocar de modelo (D) não são os passos do processo iterativo de engenharia de prompt.]\n\n[ ] A - Write a prompt only once and use it in production without evaluation.\n[ ] B - Define the goal, write the initial prompt, evaluate against criteria, apply techniques and re-evaluate, repeating the last two steps until performance is satisfactory.\n[ ] C - Increase the temperature each round until the output changes.\n[ ] D - Swap the model repeatedly until one of them works.','\n',char(10)),'B - Define the goal, write the initial prompt, evaluate against criteria, apply techniques and re-evaluate, repeating the last two steps until performance is satisfactory.','["Domain_4::Prompt_Engineering_Structured_Output", "ForaDoCenario"]','New',0,2.5,0,1783092990683,1783727757353,1783203558653,replace('**Tradução para português do Brasil:**\n\nQual descrição corresponde ao ciclo iterativo de engenharia de prompt?\n\n[ ] A - Escrever um prompt apenas uma vez e usá-lo em produção sem avaliação.\n[ ] B - Definir o objetivo, escrever o prompt inicial, avaliar segundo critérios, aplicar técnicas e reavaliar, repetindo as duas últimas etapas até que o desempenho seja satisfatório.\n[ ] C - Aumentar a temperatura a cada rodada até que a saída mude.\n[ ] D - Trocar o modelo repetidamente até que um deles funcione.','\n',char(10)),replace('**Explicação didática para adulto tech lead:**\n\nA alternativa **B** é a correta porque descreve precisamente o ciclo de *iterative prompt engineering*, uma prática consolidada em LLMOps e desenvolvimento de software baseado em IA generativa. O processo é análogo a um loop de feedback controlado: define-se um objetivo mensurável (ex.: precisão, formato de saída, aderência a restrições), escreve-se um prompt candidato, avalia-se seu desempenho contra critérios objetivos, aplicam-se técnicas de refinamento (como *chain-of-thought*, *few-shot*, formatação estruturada, instruções negativas) e reavalia-se. O ciclo se repete até que as métricas atinjam o limiar de aceitação.\n\nPor que as demais estão erradas:\n\n- **A** está incorreta porque o prompt engineering é intrinsecamente iterativo. Escrever um prompt único e colocá-lo em produção sem avaliação contraria o princípio básico de que prompts são hiperparâmetros que precisam ser testados e ajustados. Não há garantia de que o prompt inicial será robusto para variações de entrada.\n- **C** está errada pois aumentar a temperatura não é um passo do ciclo de engenharia de prompt, mas sim um ajuste de parâmetro de inferência que controla a aleatoriedade da saída. Embora possa ser parte da experimentação, não representa o ciclo iterativo de refinamento do prompt em si.\n- **D** está errada porque trocar de modelo não é o foco do *prompt engineering* iterativo. O ciclo pressupõe melhoria do prompt dentro de um mesmo modelo (ou arquitetura). Trocar de modelo pode ser uma estratégia, mas não descreve o processo iterativo de engenharia de prompt.','\n',char(10)),replace('**Explicação para uma criança de 10 anos:**\n\nImagine que você está ensinando um robô amigo a fazer um desenho. Você não acerta de primeira, né? Você pede, vê o que ele desenha, pensa "ah, faltou cor" e aí fala de novo: "agora com cores". Depois vê que ele usou a cor errada e fala "use lápis azul". Você vai ajustando o pedido até o desenho ficar do jeito que você queria. Isso é um ciclo: pedir, ver o resultado, melhorar o pedido, pedir de novo. A alternativa B explica exatamente isso: primeiro você define o que quer, escreve o prompt (o pedido), vê se está bom, aplica técnicas para melhorar e repete até ficar legal.\n\nAs outras opções estão erradas:\n- A: achar que o primeiro pedido já serve, sem nem olhar o resultado. Pode sair tudo errado!\n- C: aumentar a temperatura é como deixar o robô mais "doidinho" nas respostas. Não é assim que se melhora o pedido.\n- D: ficar trocando de robô toda hora também não resolve — o importante é ensinar melhor o mesmo robô.','\n',char(10)));
INSERT INTO cards VALUES('admin','card_1783092990706_llmqhq1tl',418,'What is the recommendation about the first line of a prompt?',replace('What is the recommendation about the first line of a prompt?\n\nWhat is the recommendation about the first line of a prompt?\n[Resposta correta: A primeira linha é a mais importante e deve declarar a tarefa de forma direta e clara, como instrução. Perguntas vagas (A) enfraquecem o pedido, exemplos não precedem a instrução principal (B) e stop sequences são parâmetros da API, não conteúdo da primeira linha (D).]\n\n[ ] A - It should be an open and vague question to give the model freedom.\n[ ] B - It should contain all the few-shot examples before any instruction.\n[ ] C - It should lead with a direct, clear statement of the task, in simple language and as an instruction, not as a vague question.\n[ ] D - It should bring the list of stop sequences to be used.','\n',char(10)),'C - It should lead with a direct, clear statement of the task, in simple language and as an instruction, not as a vague question.','["ForaDosDominios", "ForaDoCenario"]','New',0,2.5,0,1783092990706,1783727760243,1783203558653,replace('**Tradução para português do Brasil:**\n\n**Pergunta:** Qual é a recomendação sobre a primeira linha de um prompt?\n\n[ ] A - Deve ser uma pergunta aberta e vaga para dar liberdade ao modelo.\n[ ] B - Deve conter todos os exemplos de few-shot antes de qualquer instrução.\n[ ] C - Deve começar com uma declaração direta e clara da tarefa, em linguagem simples e como uma instrução, não como uma pergunta vaga.\n[ ] D - Deve trazer a lista de stop sequences a serem utilizadas.','\n',char(10)),replace('**Explicação para um adulto tech lead:**\n\nA resposta correta é a alternativa **C**.\n\nA primeira linha de um prompt é o ponto de contato mais crítico para definir o comportamento do modelo. A recomendação consolidada em engenharia de prompt (best practices da OpenAI, Anthropic, Google e demais provedores) é que o prompt seja **direto, claro e imperativo** desde o início. Isso porque modelos de linguagem (especialmente os instrucionais) são otimizados para seguir comandos explícitos. Quando a primeira linha é uma instrução clara — "Traduza o seguinte texto para português:" — o modelo entende imediatamente o contexto e o formato esperado, reduzindo a chance de interpretações ambíguas ou respostas fora do escopo.\n\nPor que as demais estão incorretas:\n\n- **Alternativa A (pergunta vaga/aberta):** Perguntas vagas como "O que você acha sobre..." tendem a gerar respostas genéricas, prolixas ou com baixo foco. Embora em alguns cenários criativos isso seja desejável, como recomendação geral para a *primeira linha* de um prompt, é contraproducente. O modelo precisa de direção clara, não de ambiguidade.\n- **Alternativa B (exemplos few-shot antes da instrução):** A ordem mais eficaz geralmente é: instrução primeiro, depois exemplos. Colocar exemplos antes da instrução pode confundir o modelo sobre qual é o padrão esperado (ele pode "aprender" o formato sem saber qual a tarefa). A boa prática é declarar a tarefa e então fornecer exemplos que ilustrem a instrução.\n- **Alternativa D (lista de stop sequences):** Stop sequences são parâmetros de configuração da API, não conteúdo textual do prompt. Elas podem ser definidas nos parâmetros da chamada à API (como no parâmetro `stop` da OpenAI ou `stop_sequences` da Anthropic), mas não fazem sentido como conteúdo da primeira linha do prompt. Colocá-las no texto do prompt seria ineficaz e confuso.','\n',char(10)),replace('Imagine que você está pedindo ajuda a um robô inteligente. Se você falar: "O que você acha de fazer alguma coisa?", o robô fica confuso. É melhor falar logo de cara: "Robô, faça isso para mim: traduza esta frase." Assim ele entende direitinho o que você quer.\n\nA alternativa **C** diz exatamente isso: a primeira linha do prompt (que é o pedido que você escreve) deve ser uma instrução bem clara e direta, como "Faça isso", em vez de uma pergunta confusa como "O que você acha disso?".\n\nAs outras opções não são boas:\n- A: fazer uma pergunta vaga deixa o robô perdido.\n- B: colocar exemplos antes da instrução é como mostrar o resultado antes de explicar o que você quer — o robô pode não entender.\n- D: falar de "stop sequences" (que são comandos técnicos para parar a resposta) não faz sentido na primeira linha do seu pedido, isso é coisa de programador, não de conversa.','\n',char(10)));
INSERT INTO cards VALUES('admin','card_1783092990729_ixrmwbxrm',419,'When is it appropriate to consider using extended thinking?',replace('When is it appropriate to consider using extended thinking?\n\nWhen is it appropriate to consider using extended thinking?\n[Resposta correta: Extended thinking é indicado para tarefas complexas quando o prompting padrão falha. Não é necessário em toda tarefa (A), tende a aumentar custo em vez de reduzir (B) e é incompatível com message prefilling (D).]\n\n[ ] A - Always, on any task, to guarantee longer responses.\n[ ] B - Only when you want to reduce the cost per token.\n[ ] C - When standard prompting is not giving good results on hard, complex tasks.\n[ ] D - Only together with message prefilling.','\n',char(10)),'C - When standard prompting is not giving good results on hard, complex tasks.','["Domain_4::Prompt_Engineering_Structured_Output", "Domain_5::Context_Management_Reliability", "ForaDoCenario"]','New',0,2.5,0,1783092990729,1783727763686,1783203558653,replace('Tradução:\n\n**Pergunta:** Quando é apropriado considerar o uso de *extended thinking* (raciocínio estendido)?\n\n[ ] A - Sempre, em qualquer tarefa, para garantir respostas mais longas.\n[ ] B - Apenas quando você deseja reduzir o custo por token.\n[ ] C - Quando o prompting padrão não está gerando bons resultados em tarefas difíceis e complexas.\n[ ] D - Apenas em conjunto com *message prefilling* (preenchimento prévio de mensagens).','\n',char(10)),replace('**Explicação para um adulto tech lead:**\n\nA alternativa correta é a **C**. O *extended thinking* (ou raciocínio estendido) é um modo de operação no qual o modelo dedica mais tempo e recursos computacionais para "pensar" antes de responder, gerando cadeias de raciocínio internas mais longas. Isso é particularmente útil para problemas complexos — como raciocínio matemático avançado, lógica multi-etapas, planejamento ou análise profunda — onde o prompting padrão (single-shot ou few-shot sem raciocínio explícito) tende a falhar.\n\n**Análise das alternativas incorretas:**\n\n- **A (Sempre, em qualquer tarefa):** Incorreta. Usar *extended thinking* indiscriminadamente é ineficiente e antieconômico. Para tarefas simples (ex.: extração de dados, sumarização básica, perguntas factuais diretas), o prompting padrão é suficiente e mais rápido. Ativar o raciocínio estendido para tudo aumentaria latência e custos sem benefício tangível.\n\n- **B (Apenas quando você deseja reduzir o custo por token):** Incorreta. O *extended thinking* tende a *aumentar* o custo por token, e não reduzi-lo. Isso porque o modelo gera tokens de raciocínio interno (que são cobrados como tokens de saída, dependendo da API) antes de produzir a resposta final. A redução de custo não é uma motivação para usar esse modo; pelo contrário, é uma desvantagem a ser ponderada.\n\n- **D (Apenas em conjunto com *message prefilling*):** Incorreta. *Message prefilling* (preencher parte da resposta do modelo antes dele gerar) e *extended thinking* são duas funcionalidades distintas, e em muitas implementações elas são mutuamente exclusivas ou conflitantes. O *extended thinking* exige que o modelo construa seu raciocínio internamente do zero; pré-preenchimento rompe esse fluxo. Portanto, eles não são compatíveis e certamente não há obrigatoriedade de uso conjunto.','\n',char(10)),replace('Imagine que você tem um robô que responde perguntas. Para perguntas fáceis, tipo "quanto é 2+2?", o robô responde na hora. Mas para perguntas difíceis, tipo "se eu tenho 5 maçãs, dou 2 para um amigo, ganho 3 da minha avó, e depois como 1, quantas sobraram?", o robô pode errar se responder rápido demais.\n\nO "extended thinking" é como pedir para o robô "pensar mais devagar" — ele vai escrever um rascunho mental antes de dar a resposta final. Isso é ótimo para problemas cabeludos!\n\nEntão:\n- ❌ Usar isso **sempre** (alternativa A) seria bobagem, como pensar muito para responder "2+2".\n- ❌ Usar isso **para gastar menos dinheiro** (alternativa B) também não faz sentido, porque pensar mais gasta mais energia (e mais dinheiro).\n- ✅ A opção certa (C) é: **use quando as respostas normais não estão funcionando bem em tarefas bem difíceis**.\n- ❌ E a opção D diz que só pode usar junto com outra coisa chamada "message prefilling", mas isso não é verdade — eles são coisas diferentes e geralmente não funcionam juntos.\n\nResumindo: pense mais quando o problema for mais difícil e a resposta simples não estiver dando certo!','\n',char(10)));
INSERT INTO cards VALUES('admin','card_1783092990751_c5kj54e5w',420,'Which features are incompatible with extended thinking?',replace('Which features are incompatible with extended thinking?\n\nWhich features are incompatible with extended thinking?\n[Resposta correta: Message pre-filling e temperature estão entre os recursos incompatíveis com extended thinking. XML tags e few-shot (A), stop sequences e system prompt (C) e guidelines de especificidade (D) não estão na lista de incompatibilidades citada.]\n\n[ ] A - XML tags and few-shot examples.\n[ ] B - Message pre-filling and temperature.\n[ ] C - Stop sequences and system prompt.\n[ ] D - Output Quality Guidelines and Process Steps.','\n',char(10)),'B - Message pre-filling and temperature.','["Domain_4::Prompt_Engineering_Structured_Output", "ForaDoCenario"]','New',0,2.5,0,1783092990751,1783727767137,1783203558653,replace('**Tradução para português do Brasil:**\n\n**Pergunta:** Quais recursos são incompatíveis com o pensamento estendido (extended thinking)?\n\n**Alternativas:**\n[ ] A - Tags XML e exemplos few-shot.\n[ ] B - Preenchimento de mensagem (message pre-filling) e temperatura (temperature).\n[ ] C - Sequências de parada (stop sequences) e prompt de sistema (system prompt).\n[ ] D - Diretrizes de qualidade de saída e etapas de processo.','\n',char(10)),replace('**Explicação para um adulto tech lead:**\n\nO "extended thinking" é um modo de operação de modelos de linguagem (como o Claude) que permite raciocínio mais profundo e prolongado antes de gerar uma resposta, útil para problemas complexos de matemática, física, programação, etc. No entanto, alguns recursos de configuração padrão da API são incompatíveis com esse modo.\n\nA alternativa correta é a **B - Message pre-filling and temperature**.\n\n- **Message pre-filling** (preenchimento de mensagem) é o recurso que permite pré-popular parte da resposta do assistente (ex.: definir o início da resposta). Isso é incompatível com extended thinking porque o modelo precisa de controle total sobre o fluxo do raciocínio interno. Se você pré-preenche parte da resposta, interfere no processo de pensamento estendido.\n\n- **Temperature** controla a aleatoriedade da saída (valores > 0 tornam a resposta mais criativa). No extended thinking, a temperatura é fixada em 0 (ou próxima disso) para garantir que o raciocínio seja determinístico e focado, já que a criatividade extra poderia introduzir inconsistências lógicas em cadeias longas de raciocínio.\n\n**Análise das alternativas incorretas:**\n\n- **A - XML tags and few-shot examples:** Tags XML (como usar tags <thinking> no prompt) são perfeitamente compatíveis — na verdade, são recomendadas para estruturar prompts. Exemplos few-shot também funcionam normalmente; você pode fornecer exemplos de raciocínio para guiar o modelo.\n\n- **C - Stop sequences and system prompt:** System prompt é plenamente compatível (e até recomendado para definir o contexto). Stop sequences (sequências que interrompem a geração) também funcionam, embora seu uso exija cuidado para não cortar o raciocínio no meio.\n\n- **D - Output Quality Guidelines and Process Steps:** Diretrizes de qualidade de saída são perfeitamente aceitáveis. Etapas de processo (como instruções passo a passo) são, na verdade, o coração do extended thinking: você pode pedir que o modelo pense passo a passo.\n\nPortanto, a única alternativa que lista **exclusivamente** recursos incompatíveis documentados é a B.','\n',char(10)),replace('**Explicação para uma criança de 10 anos:**\n\nImagine que você está resolvendo um problema muito difícil de matemática, daqueles que você precisa pensar bastante antes de responder.\n\nO "extended thinking" é como quando seu professor diz: "Pense com calma, pode demorar o tempo que precisar para achar a resposta certa".\n\nAgora, existem algumas ferramentas que atrapalham esse "pensar com calma":\n\n1. **Preenchimento de mensagem** - É como se alguém já começasse a escrever a resposta para você. Se você está pensando, não quer que ninguém coloque palavras na sua boca, certo?\n\n2. **Temperatura** - Isso controla se você vai ser mais "criativo" ou mais "certinho" nas respostas. Quando você precisa pensar em algo bem difícil, o melhor é ser bem certinho e não inventar coisas. Por isso, no "pensamento estendido", a criatividade fica desligada.\n\nAs outras alternativas estão erradas porque:\n- **Tags XML e exemplos** - São como dicas que ajudam você a pensar melhor.\n- **Prompt de sistema e sequências de parada** - O prompt de sistema é como as instruções do professor (super útil!), e as sequências de parada são como um alarme para parar de pensar — também não atrapalham.\n- **Diretrizes de qualidade e etapas** - São regras para fazer o trabalho bem feito, e seguir passos é exatamente o que você faz quando pensa com calma!\n\nEntão a resposta certa é a **B**: Preenchimento de mensagem e temperatura são os recursos que não funcionam com o pensamento estendido.','\n',char(10)));
INSERT INTO cards VALUES('admin','card_1783092990807_s7q87p82v',421,'What is the function of the "signature" in extended thinking responses?',replace('What is the function of the "signature" in extended thinking responses?\n\nWhat is the function of the "signature" in extended thinking responses?\n[Resposta correta: O signature é um token criptográfico que assegura a integridade do texto do thinking, evitando adulteração que levaria a direções inseguras. Ele não indica effort (A), não comprime conteúdo (C) e não autentica o usuário (D).]\n\n[ ] A - To indicate the effort level chosen in the session.\n[ ] B - To be a cryptographic token that guarantees the thinking text was not modified, preventing tampering with the reasoning.\n[ ] C - To compress the thinking text to save tokens.\n[ ] D - To authenticate the user who sent the prompt.','\n',char(10)),'[ ] B - To be a cryptographic token that guarantees the thinking text was not modified, preventing tampering with the reasoning.','["ForaDosDominios", "ForaDoCenario"]','New',0,2.5,0,1783092990807,1783727770252,1783203558653,replace('**Tradução para português do Brasil:**\n\n**Pergunta:** Qual é a função da "assinatura" (signature) em respostas de pensamento estendido (extended thinking)?\n\n[ ] A - Indicar o nível de esforço escolhido na sessão.\n[ ] B - Ser um token criptográfico que garante que o texto do pensamento não foi modificado, evitando adulteração do raciocínio.\n[ ] C - Comprimir o texto do pensamento para economizar tokens.\n[ ] D - Autenticar o usuário que enviou o prompt.','\n',char(10)),replace('**Explicação técnica para um adulto tech lead:**\n\nA alternativa **B** é a correta. Em sistemas de "extended thinking" (como os disponíveis em modelos de raciocínio estendido de LLMs), o componente chamado "signature" (assinatura) funciona como um **token criptográfico** — geralmente um HMAC (Hash-based Message Authentication Code) ou uma assinatura digital assimétrica — que é gerado a partir do conteúdo do bloco de pensamento (thinking text). Esse token é anexado à resposta para permitir que o sistema consumidor (seja um gateway, um auditor ou o próprio modelo em uma etapa posterior) **verifique a integridade** do texto de raciocínio.\n\n**Por que as demais estão incorretas:**\n\n- **A (indicar nível de esforço):** O nível de esforço (effort) é um parâmetro de configuração, geralmente enviado no prompt ou definido na sessão, e não é função de uma assinatura criptográfica. A assinatura não carrega metadados sobre esforço.\n\n- **C (comprimir o texto):** Assinaturas não têm função de compressão; elas são hashes ou blocos criptográficos de tamanho fixo (e geralmente muito pequenos comparados ao texto). Compressão é feita por algoritmos como gzip ou tokenização eficiente, não por assinaturas.\n\n- **D (autenticar o usuário):** A assinatura no thinking text autentica a **integridade do conteúdo** (prova que o texto não foi alterado após a geração), e não a identidade do usuário que enviou o prompt. Autenticação de usuário é feita por tokens de sessão, JWT, OAuth, etc.\n\nPortanto, a função principal é **garantia de integridade e não-repúdio do raciocínio intermediário**, protegendo contra adulteração maliciosa que poderia levar o modelo a direções inseguras ou inconsistentes.','\n',char(10)),replace('**Explicação para uma criança de 10 anos:**\n\nImagina que você escreveu uma redação super legal na escola, mas seu amigo malvado quer apagar algumas palavras para fazer você parecer bobo. Para evitar isso, você coloca um **carrimbo secreto** no final do texto. Esse carimbo só você sabe fazer. Se alguém mexer no texto, o carimbo "quebra" e todo mundo percebe que foi alterado.\n\nA "assinatura" (signature) no pensamento estendido do computador funciona assim: é um **código secreto** que prova que ninguém mexeu no raciocínio do computador depois que ele foi gerado. As outras opções estão erradas porque:\n\n- **A** diz que mostra o "esforço" — mas o carimbo não mostra o quanto você estudou; ele só protege o texto.\n- **C** diz que é para "encolher o texto" — mas o carimbo não encolhe nada, ele só prova que está tudo certinho.\n- **D** diz que é para saber "quem escreveu" — mas na verdade é para saber se o texto foi **mexido** depois, não quem escreveu.\n\nEntão a resposta certa é a **B**: a assinatura é como um cadeado digital que impede que ninguém altere o raciocínio do computador sem que todo mundo perceba.','\n',char(10)));
INSERT INTO cards VALUES('admin','card_1783092990830_66qcc97fn',422,'What characterizes a "redacted thinking" block?',replace('What characterizes a "redacted thinking" block?\n\nWhat characterizes a "redacted thinking" block?\n[Resposta correta: Redacted thinking é raciocínio sinalizado pela segurança interna, vem criptografado e pode ser reenviado sem perda de contexto. Ele não é apagado de forma permanente (A), não é tradução (C) e não se refere ao prompt do usuário (D).]\n\n[ ] A - A permanently deleted thinking block that can no longer be used.\n[ ] B - Reasoning content flagged by the internal security systems, encrypted, that can still be resent to Claude in future conversations without losing context.\n[ ] C - The thinking text translated into another language for security.\n[ ] D - The part of the user''s prompt that was censored before processing.','\n',char(10)),'B - Reasoning content flagged by the internal security systems, encrypted, that can still be resent to Claude in future conversations without losing context.','["ForaDosDominios", "ForaDoCenario"]','New',0,2.5,0,1783092990830,1783727773176,1783203558653,replace('**Tradução para português do Brasil:**\n\nPergunta: O que caracteriza um bloco de "redacted thinking"?\n\n[ ] A - Um bloco de pensamento permanentemente apagado que não pode mais ser utilizado.\n[ ] B - Conteúdo de raciocínio sinalizado pelos sistemas de segurança internos, criptografado, que ainda pode ser reenviado ao Claude em conversas futuras sem perder contexto.\n[ ] C - O texto do pensamento traduzido para outro idioma por motivos de segurança.\n[ ] D - A parte do prompt do usuário que foi censurada antes do processamento.','\n',char(10)),replace('**Explicação para um adulto tech lead:**\n\nA alternativa B é a correta. O "redacted thinking" é um mecanismo de segurança implementado nos modelos Claude. Quando o sistema de segurança interno detecta que um bloco de raciocínio (thinking) contém conteúdo sensível ou que viola políticas, ele não simplesmente o descarta. Em vez disso, ele o **criptografa** e o substitui por um marcador do tipo "redacted thinking block". Esse bloco criptografado pode ser posteriormente reenviado para o modelo em conversas futuras sem perda de contexto, pois o modelo consegue "descriptografá-lo" internamente quando necessário — desde que o contexto de segurança permita.\n\n**Por que as demais estão erradas:**\n\n- **Alternativa A (incorreta):** O bloco não é permanentemente apagado. Ele é criptografado, não deletado. O modelo ainda pode reutilizar o contexto daquele pensamento em interações futuras, o que prova que não há remoção permanente.\n  \n- **Alternativa C (incorreta):** Não se trata de tradução para outro idioma. O "redacted" se refere à ocultação/redação do conteúdo por segurança, não a uma transformação linguística. Não há mudança de língua envolvida.\n\n- **Alternativa D (incorreta):** O "redacted thinking" refere-se ao bloco de raciocínio *do modelo*, não ao prompt do usuário. É o pensamento interno do Claude que foi sinalizado, e não uma censura aplicada ao input do usuário antes do processamento.','\n',char(10)),replace('Imagine que você está resolvendo um problema de matemática no caderno e, de repente, escreve algo que não deveria — tipo a resposta de um teste secreto. Em vez de rasgar a página e jogar fora (o que perderia todo o seu raciocínio), você coloca aquele pedaço dentro de um cofre trancado. Depois, quando precisar lembrar o que pensou, você pode abrir o cofre de novo.\n\nO "redacted thinking" é mais ou menos isso: é um pedaço do pensamento do Claude que o sistema de segurança achou que deveria esconder. Mas, em vez de apagar para sempre, ele guarda esse pensamento num "cofre" (criptografado). Assim, se o Claude precisar usar aquele pensamento de novo em outra conversa, ele consegue abrir o cofre e continuar de onde parou, sem perder o contexto.\n\n**Por que as outras opções estão erradas?**\n- A opção A diz que é apagado para sempre — não é, ele fica guardado no cofre.\n- A opção C diz que é uma tradução para outro idioma — nada a ver, não é sobre traduzir, é sobre esconder.\n- A opção D diz que é parte do que o usuário escreveu que foi censurada — na verdade, é o pensamento do próprio Claude que foi escondido, não o que você escreveu para ele.','\n',char(10)));
INSERT INTO cards VALUES('admin','card_1783092990855_srg0f3h7w',423,'Which sequence describes the typical prompt evaluation workflow?',replace('Which sequence describes the typical prompt evaluation workflow?\n\nWhich sequence describes the typical prompt evaluation workflow?\n[Resposta correta: O workflow é rascunhar, criar dataset, rodar, avaliar com grader e iterar comparando ao baseline. Ir direto para produção (B) pula a avaliação, e as opções C e D descrevem técnicas de formatação e geração, não o workflow de avaliação.]\n\n[ ] A - Draft the prompt, create an evaluation dataset, run it over each case, pass the output through a grader and change the prompt comparing against the baseline.\n[ ] B - Write the prompt and send it straight to production.\n[ ] C - Create few-shot examples, increase the temperature and measure tokens.\n[ ] D - Define stop sequences, prefix the assistant message and measure latency.','\n',char(10)),'A - Draft the prompt, create an evaluation dataset, run it over each case, pass the output through a grader and change the prompt comparing against the baseline.','["ForaDosDominios", "ForaDoCenario"]','New',0,2.5,0,1783092990855,1783727776520,1783203558653,replace('**Tradução para português do Brasil:**\n\n**Pergunta:** Qual sequência descreve o fluxo de trabalho típico de avaliação de prompts?\n\n[ ] A - Rascunhar o prompt, criar um dataset de avaliação, executá-lo em cada caso, passar a saída por um avaliador (grader) e alterar o prompt comparando com a linha de base (baseline).\n[ ] B - Escrever o prompt e enviá-lo diretamente para produção.\n[ ] C - Criar exemplos few-shot, aumentar a temperatura e medir tokens.\n[ ] D - Definir sequências de parada (stop sequences), prefixar a mensagem do assistente e medir latência.','\n',char(10)),replace('**Explicação para um adulto tech lead:**\n\nA alternativa **A** descreve corretamente o fluxo de trabalho iterativo e estruturado de avaliação de prompts em engenharia de prompt, amplamente adotado em práticas de LLMOps (Large Language Model Operations). O processo começa com um rascunho inicial do prompt, seguido pela criação de um dataset de avaliação com entradas-representativas e saídas esperadas (ground truth). Em seguida, executa-se o prompt sobre cada caso do dataset, e as saídas geradas são submetidas a um "grader" (um avaliador automatizado ou humano) que as compara contra um baseline — geralmente a versão anterior do prompt ou um desempenho mínimo aceitável. Com base nessa avaliação, o prompt é ajustado e o ciclo se repete até que se atinja a qualidade desejada.\n\nAs demais alternativas estão incorretas pelos seguintes motivos:\n\n- **B** - Ignora completamente qualquer etapa de validação, teste ou iteração. Enviar um prompt diretamente para produção sem avaliação é uma prática arriscada e negligente, especialmente em aplicações que exigem confiabilidade, segurança e aderência a requisitos de negócio. Não há garantia de que o prompt se comporte conforme o esperado em diferentes entradas ou cenários de borda.\n\n- **C** - Descreve técnicas específicas de construção de prompt (few-shot) e parâmetros de configuração (temperatura, contagem de tokens), mas não representa um fluxo de avaliação. "Criar exemplos few-shot" e "aumentar a temperatura" são decisões de design ou tuning, não etapas de um workflow de avaliação. Medir tokens pode ser uma métrica, mas está fora do contexto de um ciclo avaliativo completo.\n\n- **D** - Similarmente, descreve configurações de formatação de saída (stop sequences, prefixo de mensagem) e medição de latência. Embora latência seja uma métrica relevante em produção, o trecho não descreve um workflow de avaliação de qualidade do prompt, apenas aspectos operacionais. Faltam os elementos centrais: dataset de avaliação, comparador (grader) e iteração por comparação com baseline.','\n',char(10)),replace('Imagine que você está criando uma receita de bolo. Você não vai fazer o bolo e servir direto, certo? Primeiro você pensa na receita (rascunha o prompt), depois testa com alguns ingredientes diferentes (cria um dataset de avaliação), faz o bolo (roda o prompt), prova (passa por um avaliador/grader) e compara com uma receita que você já sabe que ficou boa (baseline). Se não ficou bom, você muda alguma coisa e testa de novo até acertar. É isso que a alternativa A explica!\n\nAgora, as outras opções não fazem sentido para um fluxo de avaliação:\n- **B** - Seria tipo fazer a receita e servir o bolo sem nem provar! Pode dar muito errado.\n- **C** - É como falar "coloque mais açúcar, aumente a temperatura do forno e meça o tamanho do bolo". Isso são truques de cozinha, e não o passo a passo de como testar e melhorar a receita.\n- **D** - É como definir "o forno desliga sozinho depois de 30 minutos" e "coloque a massa na forma". Também são só instruções avulsas, e não o processo completo de testar e comparar para deixar o bolo perfeito.','\n',char(10)));
INSERT INTO cards VALUES('admin','card_1783092990882_s1jvh0v4g',424,'What is the difference between /effort and the ultrathink keyword in controlling reasoning?',replace('What is the difference between /effort and the ultrathink keyword in controlling reasoning?\n\nWhat is the difference between /effort and the ultrathink keyword in controlling reasoning?\n[Resposta correta: /effort define o nível da sessão (low rápido e barato até max mais longo) e ultrathink adiciona raciocínio extra só naquele turno sem alterar o effort da sessão. Eles não são idênticos (A), os papéis não são invertidos (C) e não dependem de prefilling (D).]\n\n[ ] A - /effort and ultrathink do exactly the same thing and are interchangeable.\n[ ] B - /effort sets the session reasoning level (low to max), while ultrathink signals extra reasoning only on that turn, without changing the session effort.\n[ ] C - ultrathink changes the effort permanently and /effort lasts only for one turn.\n[ ] D - Both only work when message prefilling is active.','\n',char(10)),'[ ] B - /effort sets the session reasoning level (low to max), while ultrathink signals extra reasoning only on that turn, without changing the session effort.','["Domain_3::Claude_Code_Configuration_Workflows", "Scenario_2::Code_Generation_Claude_Code"]','New',0,2.5,0,1783092990882,1783727779430,1783203558653,replace('**Tradução para português do Brasil:**\n\nQual é a diferença entre /effort e a palavra-chave ultrathink no controle de raciocínio?\n\n[ ] A - /effort e ultrathink fazem exatamente a mesma coisa e são intercambiáveis.\n[ ] B - /effort define o nível de raciocínio da sessão (low até max), enquanto ultrathink sinaliza raciocínio extra apenas naquele turno, sem alterar o effort da sessão.\n[ ] C - ultrathink altera o effort permanentemente e /effort dura apenas um turno.\n[ ] D - Ambos só funcionam quando o preenchimento de mensagem (message prefilling) está ativo.','\n',char(10)),replace('**Explicação para um adulto tech lead:**\n\nA alternativa **B** é a correta porque descreve com precisão a arquitetura de dois mecanismos distintos para controle de raciocínio em modelos de linguagem:\n\n- **/effort**: é um parâmetro que define o nível de raciocínio **global da sessão**. Quando você define effort como "low", o modelo deve responder com raciocínio mínimo (mais rápido e barato). Em "max", o modelo emprega raciocínio prolongado (mais lento e caro). Esse ajuste persiste ao longo de toda a sessão até ser explicitamente alterado.\n\n- **ultrathink**: é uma palavra-chave ou sinalizador de uso **local/temporário**. Quando incluída em um turno específico, instrui o modelo a aplicar raciocínio extra apenas naquela interação, sem modificar a configuração de effort da sessão. Ou seja, é um "boost" pontual.\n\n**Por que as demais estão erradas:**\n- **A**: Incorreta porque os dois mecanismos têm escopos e comportamentos diferentes (um é global, outro é local).\n- **C**: Incorreta porque inverte os papéis — ultrathink não altera effort permanentemente, e /effort não dura apenas um turno.\n- **D**: Incorreta porque ambos funcionam independentemente de message prefilling.','\n',char(10)),replace('**Explicação para uma criança de 10 anos:**\n\nImagine que você está jogando um videogame onde um robô ajudante responde suas perguntas.\n\n- **/effort** é como um botão de "dificuldade" que você escolhe no início: se colocar "fácil" (low), o robô responde rápido e simples. Se colocar "difícil" (max), ele pensa mais e demora mais. Esse botão continua valendo para todas as perguntas que você fizer.\n\n- **ultrathink** é como apertar um botão turbo só para UMA pergunta. Mesmo que o jogo esteja no modo "fácil", você pode pedir para o robô pensar mais naquela pergunta específica, sem mudar o modo do jogo inteiro.\n\n**Por que as outras opções estão erradas:**\n- **A**: Dizer que são a mesma coisa é como dizer que apertar um botão turbo uma vez é igual a mudar a dificuldade do jogo inteiro — não é!\n- **C**: Dizer que o turbo muda a dificuldade pra sempre e que o botão de dificuldade só vale um turno é o contrário do que realmente acontece.\n- **D**: Dizer que os dois só funcionam com uma "mágica especial" (prefilling) não é verdade — eles funcionam sozinhos.','\n',char(10)));
INSERT INTO cards VALUES('admin','card_1783092990906_nv5ymmlrw',425,'What should an eval dataset be made of?',replace('What should an eval dataset be made of?\n\nWhat should an eval dataset be made of?\n[Resposta correta: Um eval dataset contém inputs representativos dos pedidos reais de produção, interpolados no template. Ele não é só outputs (A), não deve conter apenas casos improváveis (C) e não é o código da aplicação (D).]\n\n[ ] A - Only the expected outputs, without the inputs.\n[ ] B - Example inputs that represent the types of requests the prompt will handle in production, interpolated into the prompt template.\n[ ] C - Only extreme cases that never appear in production.\n[ ] D - The source code of the application that calls the model.','\n',char(10)),'B - Example inputs that represent the types of requests the prompt will handle in production, interpolated into the prompt template.','["Domain_4::Prompt_Engineering_Structured_Output", "ForaDoCenario"]','New',0,2.5,0,1783092990906,1783727782700,1783203558653,replace('**Tradução para português do Brasil:**\n\n**Pergunta:** Do que um conjunto de dados de avaliação (eval dataset) deve ser composto?\n\n[ ] A - Apenas as saídas esperadas, sem as entradas.\n[ ] B - Exemplos de entradas que representam os tipos de solicitações que o prompt lidará em produção, interpolados no template do prompt.\n[ ] C - Apenas casos extremos que nunca aparecem em produção.\n[ ] D - O código-fonte da aplicação que chama o modelo.','\n',char(10)),replace('**Explicação didática para um adulto (tech lead):**\n\nUm **eval dataset** (conjunto de dados de avaliação) tem como objetivo medir a qualidade e o comportamento de um modelo de linguagem (LLM) ou de um sistema baseado em prompt. Para que essa medição seja útil e representativa, o dataset precisa refletir aquilo que o sistema encontrará no mundo real.\n\n**Alternativa correta: B**\n\nA alternativa B está correta porque um eval dataset deve conter **exemplos de inputs (entradas)** que sejam representativos dos pedidos reais que o sistema receberá em produção, **interpolados no template do prompt**. Isso significa que você pega o mesmo template de prompt que será usado em produção e preenche suas variáveis com dados de entrada reais ou simulados. Isso permite testar se o modelo se comporta corretamente com os mesmos tipos de variação de entrada que ele enfrentará.\n\n**Por que as demais estão erradas:**\n\n- **A (Apenas saídas esperadas, sem entradas):** Um eval dataset precisa conter tanto entradas quanto saídas esperadas (ground truth) para que possamos comparar a saída gerada pelo modelo com o resultado desejado. Somente com outputs não é possível realizar a avaliação, pois não há como saber qual entrada gerou aquela saída.\n\n- **C (Apenas casos extremos que nunca aparecem em produção):** Embora seja desejável incluir alguns casos extremos (edge cases) ou raros para testar limites, um dataset composto exclusivamente por casos improváveis não representa a distribuição real dos dados e pode levar a uma avaliação enviesada. O foco deve ser em entradas representativas da produção, complementadas por alguns casos de borda.\n\n- **D (Código-fonte da aplicação):** O eval dataset é um conjunto de dados usado para testar o comportamento do modelo/prompt, não o código da aplicação. O código-fonte diz respeito à lógica de engenharia de software (como chamar a API, tratar erros, etc.), mas não serve como entrada para avaliação da qualidade das respostas do modelo.','\n',char(10)),replace('Vamos imaginar que você está treinando um amigo robô para responder perguntas sobre animais. Para saber se ele está aprendendo direitinho, você precisa testá-lo.\n\n**O que é um "eval dataset"?** É como uma lista de perguntas que você vai fazer para o robô para ver se ele responde certo.\n\nA resposta **B** está certa: você deve pegar **perguntas de verdade** que as pessoas costumam fazer (como "Qual o som do gato?" ou "O que o cachorro come?") e colocar no formato que o robô entende. Assim você testa com coisas que realmente vão aparecer no dia a dia.\n\nAs outras opções estão erradas porque:\n\n- **A:** Se você só tiver as respostas certas, mas não as perguntas, como vai saber o que perguntar ao robô? Não faz sentido.\n- **C:** Só testar com coisas muito estranhas e raras (como "O que o unicórnio come?") não ajuda a saber se o robô vai bem nas perguntas normais que as pessoas fazem.\n- **D:** O código do aplicativo é como as "regras do jogo" que fazem o robô funcionar, mas não são as perguntas que você vai fazer a ele.\n\nEntão, lembre-se: para testar seu robô, use perguntas parecidas com as que ele vai receber de verdade!','\n',char(10)));
INSERT INTO cards VALUES('admin','card_1783092990929_ygk3ruccy',426,'Which two questions should a good skill description answer?',replace('Which two questions should a good skill description answer?\n\nWhich two questions should a good skill description answer?\n[Resposta correta: A description deve responder o que a skill faz e quando usá-la. Custo e autoria (A), linguagem e tokens (B) e parâmetros de modelo (D) não são o que a description precisa comunicar para o disparo correto.]\n\n[ ] A - How much the skill costs and who created it.\n[ ] B - In which language the skill was written and how many tokens it consumes.\n[ ] C - What the skill does and when Claude should use it.\n[ ] D - Which model to use and which temperature to apply.','\n',char(10)),'C - What the skill does and when Claude should use it.','["Domain_3::Claude_Code_Configuration_Workflows", "Domain_4::Prompt_Engineering_Structured_Output", "Scenario_2::Code_Generation_Claude_Code"]','New',0,2.5,0,1783092990929,1783727786218,1783203558653,replace('---\n\n**Tradução para português do Brasil:**\n\nQuais duas perguntas uma boa descrição de skill deve responder?\n\n[ ] A - Quanto a skill custa e quem a criou.\n[ ] B - Em qual linguagem a skill foi escrita e quantos tokens ela consome.\n[ ] C - O que a skill faz e quando Claude deve usá-la.\n[ ] D - Qual modelo usar e qual temperatura aplicar.','\n',char(10)),replace('**Explicação técnica para um adulto tech lead:**\n\nUma skill description (descrição de skill) é um metadado essencial no ecossistema de agentes baseados em LLMs como o Claude. Ela funciona como um "sinal" para o modelo decidir **quando** invocar aquela skill. O modelo lê as descrições disponíveis e escolhe a skill mais adequada para a tarefa em questão. Portanto, a descrição precisa responder a duas perguntas fundamentais:\n\n- **O que a skill faz?** (propósito, funcionalidade, ação que será executada)\n- **Quando usar?** (contexto de ativação, gatilho, situação ideal para invocação)\n\n**Análise das alternativas incorretas:**\n\n- **A (Custo e autoria):** Irrelevante para o mecanismo de disparo. O modelo não seleciona skills com base em custo financeiro ou quem a escreveu.\n- **B (Linguagem e tokens):** Detalhes de implementação, não de propósito. O modelo não precisa saber a linguagem de programação usada ou a contagem de tokens para decidir se a skill é aplicável.\n- **D (Modelo e temperatura):** Parâmetros de configuração do LLM, não informações de descrição funcional. A seleção de skill é baseada em semântica da tarefa, não em hiperparâmetros.','\n',char(10)),replace('Imagine que você tem uma caixa de ferramentas cheia de brinquedos diferentes. Cada brinquedo vem com uma etiqueta explicando para que serve. Uma boa etiqueta responde duas perguntas: "O que isso faz?" (ex.: "isso faz desenhos") e "Quando usar?" (ex.: "use quando quiser pintar"). Assim você sabe qual brinquedo pegar na hora certa!\n\nSe a etiqueta dissesse "quanto custou" ou "quem fez", isso não ajudaria a saber para que serve o brinquedo. A resposta certa é a **letra C**: a descrição deve dizer **o que a skill faz** e **quando o Claude (o robô) deve usá-la**.','\n',char(10)));
INSERT INTO cards VALUES('admin','card_1783092990951_fqvolytig',427,'A skill does not trigger when it should.',replace('A skill does not trigger when it should.\n\nA skill does not trigger when it should. What is the indicated adjustment?\n[Resposta correta: O ajuste é enriquecer a description com palavras-chave e frases de gatilho alinhadas ao modo como os pedidos são feitos, pois o matching é semântico. Mexer no código interno (B), no effort (C) ou reduzir exemplos (D) não afeta o disparo da skill.]\n\n[ ] A - Add to the description more keywords and trigger phrases that match how you actually phrase your requests.\n[ ] B - Rewrite the skill''s internal code so it runs faster.\n[ ] C - Increase the session effort so the model looks for more skills.\n[ ] D - Reduce the number of examples in the main prompt.','\n',char(10)),'[ ] A - Add to the description more keywords and trigger phrases that match how you actually phrase your requests.','["Domain_2::Tool_Design_MCP_Integration", "Domain_1::Agentic_Architecture_Orchestration", "Scenario_1::Customer_Support_Agent"]','New',0,2.5,0,1783092990951,1783727789999,1783203558653,replace('Tradução para português do Brasil:\n\n**Pergunta:** Uma skill não dispara quando deveria. Qual é o ajuste indicado?\n\n[ ] A - Adicionar à descrição mais palavras-chave e frases de gatilho que correspondam à forma como você realmente formula seus pedidos.\n[ ] B - Reescrever o código interno da skill para que ela seja executada mais rapidamente.\n[ ] C - Aumentar o effort da sessão para que o modelo procure por mais skills.\n[ ] D - Reduzir o número de exemplos no prompt principal.','\n',char(10)),replace('Explicação para um adulto tech lead:\n\nO problema descrito é clássico em sistemas baseados em LLM que utilizam roteamento de skills/intents: a skill não está sendo selecionada quando deveria. Isso geralmente ocorre por um desalinhamento semântico entre a descrição da skill e a forma como os usuários formulam seus pedidos.\n\n**Resposta correta: Alternativa A**\n\nA alternativa A está correta porque, em sistemas de matching semântico (como embeddings + similaridade de cosseno ou classificadores de intenção), o mecanismo de disparo depende da correspondência entre a representação textual da skill (sua descrição) e a consulta do usuário. Quanto mais alinhadas estiverem as palavras-chave e frases de gatilho na descrição com os padrões reais de fala dos usuários, maior a chance de matching. É uma questão de cobertura lexical e semântica — essencialmente, estamos melhorando o recall do sistema de roteamento.\n\n**Por que as demais alternativas estão erradas:**\n\n**Alternativa B** — Reescrever o código interno para executar mais rápido não resolve o problema de a skill não ser selecionada. Velocidade de execução é um problema de performance (latência), não de acurácia de roteamento. A skill pode estar extremamente rápida, mas se não for sequer invocada, isso é irrelevante.\n\n**Alternativa C** — Aumentar o "session effort" (um conceito que aparece em algumas plataformas como parâmetro de quão "agressivamente" o modelo busca skills) não é uma abordagem estrutural. Isso pode aumentar falsos positivos (disparar skills que não deveriam) e introduzir instabilidade, além de não tratar a causa raiz — a descrição mal alinhada.\n\n**Alternativa D** — Reduzir o número de exemplos no prompt principal pode, na verdade, piorar o problema. Exemplos bem escritos ajudam o modelo a entender o comportamento esperado. A menos que haja overfitting ou ruído, reduzir exemplos tende a reduzir a precisão do comportamento da skill, não a melhorar seu disparo.','\n',char(10)),replace('Imagine que você tem uma caixa mágica que guarda várias "ajudas" (skills) que você criou. Cada ajuda tem uma etiqueta na caixa explicando para que ela serve. Quando você pede algo, a caixa mágica olha a sua frase e tenta encontrar a ajuda certa comparando com as etiquetas.\n\nSe a sua ajuda não está aparecendo quando você pede, é porque a etiqueta (a descrição) não combina direito com o que você fala. Por exemplo, se você criou uma ajuda para desenhar gatos, mas na etiqueta escreveu "auxiliar de formas geométricas", a caixa mágica nunca vai achar que "faz um gato pra mim" combina com essa etiqueta!\n\nA alternativa A diz: "escreva na etiqueta palavras e frases que combinem com o jeito que você realmente pede as coisas". Isso é o certo! É como trocar a etiqueta confusa por uma que diga "faz desenhos de animais, especialmente gatos".\n\nAs outras opções estão erradas porque:\n- B (mexer no código para rodar mais rápido) não adianta — a ajuda pode ser super rápida, mas se a caixa mágica nem a encontra, não serve de nada.\n- C (aumentar a "força" da caixa mágica para procurar mais) é como chutar: pode fazer a caixa achar ajudas erradas.\n- D (tirar exemplos) é o contrário do que ajuda — menos exemplos deixam a caixa mágica mais confusa, não mais esperta.','\n',char(10)));
INSERT INTO cards VALUES('admin','card_1783092990974_9gxpq3www',428,'A skill exists and passes validation, but Claude does not use it when expected.',replace('A skill exists and passes validation, but Claude does not use it when expected.\n\nA skill exists and passes validation, but Claude does not use it when expected. What is the most likely cause and fix?\n[Resposta correta: Se a skill valida mas não é usada, a causa quase sempre é a description, corrigida com frases de gatilho alinhadas aos pedidos reais. A lógica interna passou na validação (A), o tamanho do modelo não é o gargalo (B) e o effort não controla seleção de skill (D).]\n\n[ ] A - The skill is poorly implemented; rewrite its logic.\n[ ] B - The model is too small; swap it for a larger one.\n[ ] C - The cause is almost always the description; fix it by adding trigger phrases that match how you phrase your requests, since the matching is semantic.\n[ ] D - The effort is low; increase it to max.','\n',char(10)),'C - The cause is almost always the description; fix it by adding trigger phrases that match how you phrase your requests, since the matching is semantic.','["Domain_2::Tool_Design_MCP_Integration", "Domain_4::Prompt_Engineering_Structured_Output", "Scenario_1::Customer_Support_Agent"]','New',0,2.5,0,1783092990974,1783727793442,1783203558653,replace('**Tradução para português do Brasil:**\n\nUma skill existe e passa na validação, mas o Claude não a utiliza quando esperado. Qual é a causa mais provável e a correção?\n\n[ ] A - A skill é mal implementada; reescreva sua lógica.\n[ ] B - O modelo é muito pequeno; troque por um maior.\n[ ] C - A causa é quase sempre a description; corrija adicionando frases de gatilho que correspondam a como você formula seus pedidos, já que a correspondência é semântica.\n[ ] D - O effort está baixo; aumente ao máximo.','\n',char(10)),replace('**Explicação para um adulto tech lead:**\n\nNo ecossistema de skills do Claude (seja no Console da Anthropic ou via API), o mecanismo de seleção de skills funciona por **matching semântico** entre a descrição da skill e o prompt do usuário. Quando uma skill passa na validação (ou seja, seu código JSON/YAML é sintaticamente correto e a lógica interna não quebra), mas não é invocada, o gargalo quase nunca está na implementação interna — está na **description**.\n\n- **Alternativa A (incorreta):** A validação já passou, o que indica que a lógica da skill (passos, ferramentas, condições) está estruturalmente correta. Reescrever a lógica não resolveria o problema de *discoverability*.\n- **Alternativa B (incorreta):** O tamanho do modelo (Claude 3 Haiku vs Sonnet vs Opus) não afeta o mecanismo de seleção de skills. A seleção é feita por um classificador semântico independente do modelo de geração.\n- **Alternativa C (correta):** A descrição é o principal campo usado pelo sistema de matching para decidir se uma skill é relevante. Se a descrição usa termos genéricos ou diferentes dos que você usa nos prompts, o matching semântico falha. A correção é alinhar a descrição — adicionar sinônimos, exemplos, "frases de gatilho" que reflitam como o usuário realmente pede aquela funcionalidade.\n- **Alternativa D (incorreta):** O parâmetro `skill_effort` (0 a 1) controla o quão agressivamente o modelo tenta *usar* uma skill já selecionada, mas não controla a *seleção* inicial da skill. Aumentá-lo não fará a skill ser escolhida se ela nem entrou no radar.\n\n**Correção prática:** Edite o campo `description` da skill para incluir variações naturais do que um usuário diria ao solicitar aquela funcionalidade. Exemplo: se a skill é "traduzir textos", a descrição pode conter "tradução, traduzir, translate, converter idioma, mudar para inglês, versão em português". Quanto mais próxima da linguagem real dos usuários, maior a taxa de acerto do matching.','\n',char(10)),replace('**Explicação para uma criança de 10 anos:**\n\nImagine que você tem uma caixa de ferramentas mágica. Dentro dela, você colocou uma ferramenta especial chamada "Skill". Essa Skill funciona direitinho — você testou e ela faz o que deveria fazer. Mas, quando você pede algo para o robô Claude, ele simplesmente não pega essa ferramenta! Por quê?\n\nÉ como se a sua ferramenta tivesse uma etiqueta com o nome "Apagador" escrito, mas você sempre pede "Pode limpar o quadro?". O robô olha a etiqueta, não vê a palavra "limpar" e acha que não é aquela ferramenta que você quer.\n\nO problema não é a ferramenta em si (ela funciona!), nem o robô ser pequeno ou grande demais. O problema é a **etiqueta (description)** . A solução é escrever na etiqueta todas as palavras que você usa quando pede aquela ajuda. Se você pede "limpar", "apagar", "tirar sujeira", "deixar branco de novo" — coloca tudo na etiqueta! Assim, quando você falar, o robô vai reconhecer e pegar a ferramenta certa.','\n',char(10)));
INSERT INTO cards VALUES('admin','card_1783092990998_ycaaw1qn3',429,'What is the robust way to test whether a skill''s description triggers correctly?',replace('What is the robust way to test whether a skill''s description triggers correctly?\n\nWhat is the robust way to test whether a skill''s description triggers correctly?\n[Resposta correta: Testar múltiplas variações de frase revela quais formulações não disparam, e as palavras-chave dessas devem entrar na description. Testar só uma frase (A) não cobre a variedade real, a validação de sintaxe (C) não garante disparo e a latência (D) não mede disparo.]\n\n[ ] A - Test only one exact phrase and assume the rest will work.\n[ ] B - Test phrase variations that express the same request and, if any does not trigger, add those keywords to the description.\n[ ] C - Check whether the skill passes syntax validation.\n[ ] D - Measure the skill''s response time in production.','\n',char(10)),'[ ] B - Test phrase variations that express the same request and, if any does not trigger, add those keywords to the description.','["Domain_2::Tool_Design_MCP_Integration", "Domain_4::Prompt_Engineering_Structured_Output", "Domain_1::Agentic_Architecture_Orchestration", "Scenario_1::Customer_Support_Agent"]','New',0,2.5,0,1783092990998,1783727797093,1783203558653,replace('**Tradução para português do Brasil:**\n\nPergunta: Qual é a maneira robusta de testar se a descrição de uma skill é acionada corretamente?\n\n[ ] A - Testar apenas uma frase exata e presumir que o resto funcionará.\n[ ] B - Testar variações de frase que expressam a mesma solicitação e, se alguma não disparar, adicionar essas palavras-chave à descrição.\n[ ] C - Verificar se a skill passa na validação de sintaxe.\n[ ] D - Medir o tempo de resposta da skill em produção.','\n',char(10)),replace('**Explicação didática para um adulto tech lead:**\n\nA resposta correta é a **alternativa B**.\n\nEm sistemas de processamento de linguagem natural (NLU) aplicados a skills ou intents, a "description" (descrição) de uma skill é um campo semântico usado pelo modelo para entender quando aquela skill deve ser acionada. Diferentemente de um matching exato por regex ou string literal, o modelo infere intenções a partir de paráfrases e variações linguísticas. Portanto, para garantir que o acionamento ocorra de forma robusta, a estratégia adequada é **testar múltiplas variações de frases que semanticamente representam a mesma solicitação**.\n\nSe uma frase variante não dispara a skill, isso indica que a descrição atual não cobre aquele espectro semântico. A ação corretiva é enriquecer a descrição com as palavras-chave ou expressões ausentes, ampliando a cobertura do modelo. Essa abordagem é iterativa e empiricamente orientada.\n\n**Análise detalhada das alternativas incorretas:**\n\n- **Alternativa A ("testar apenas uma frase exata e presumir que o resto funcionará"):** Totalmente insuficiente. Em NLU, a variação linguística é imensa — sinônimos, ordenações diferentes, termos coloquiais, etc. Testar apenas uma frase não garante generalização alguma. É um anti-padrão.\n\n- **Alternativa C ("verificar se a skill passa na validação de sintaxe"):** A validação de sintaxe verifica apenas se o código ou a configuração da skill está estruturalmente correta (ex.: JSON bem formado, campos obrigatórios preenchidos). Isso não tem relação com o correto acionamento semântico da skill. Uma skill pode passar em toda validação sintática e simplesmente nunca ser acionada porque a descrição não corresponde às frases dos usuários.\n\n- **Alternativa D ("medir o tempo de resposta da skill em produção"):** Latência e acionamento são métricas ortogonais. Uma skill pode ter baixíssima latência (resposta rápida) mas nunca ser invocada pela descrição inadequada, ou ser invocada incorretamente para inputs errados. Medir tempo de resposta não avalia a correção do matching semântico.\n\nPortanto, a única alternativa que testa diretamente a capacidade de a descrição capturar corretamente a intenção do usuário em múltiplos cenários é a **B**.','\n',char(10)),replace('Imagine que você ensina um robô a te ajudar com lição de casa. Você escreve na "descrição" dele: "ajuda com matemática". Mas quando você fala "Me ajuda com essa conta?", o robô não responde. Isso porque ele só aprendeu a frase exata "ajuda com matemática".\n\nA forma correta de testar é experimentar várias frases que significam a mesma coisa, como:\n- "Pode me ajudar com essa equação?"\n- "Como resolvo esse problema de matemática?"\n- "Preciso de ajuda com números."\n\nSe alguma dessas frases não fizer o robô responder, você deve adicionar as palavras importantes (como "equação", "problema", "números") na descrição dele. Assim, o robô aprende melhor e entende mais jeitos de pedir a mesma coisa.\n\nAs outras opções são ruins porque:\n- Testar só uma frase (A) é como achar que o robô entende tudo depois de ouvir uma palavra.\n- Verificar se o "código" do robô está certo (C) não garante que ele entenda o que você fala.\n- Medir a velocidade da resposta (D) não diz se ele entendeu ou não a pergunta.\n\nA melhor forma é sempre testar com várias frases diferentes e ir ensinando ao robô as palavras que estão faltando. É assim que a gente faz um sistema realmente esperto!','\n',char(10)));
INSERT INTO cards VALUES('admin','card_1783092991020_y9cldbvf6',430,'Claude uses the wrong skill or gets confused between similar skills.',replace('Claude uses the wrong skill or gets confused between similar skills.\n\nClaude uses the wrong skill or gets confused between similar skills. What is the cause and fix?\n[Resposta correta: Confusão entre skills vem de descriptions parecidas demais, resolvida tornando-as mais distintas e específicas. Remover skills (B) elimina funcionalidade sem resolver a causa, o effort (C) não influencia isso e renomear com números (D) não distingue o propósito semântico.]\n\n[ ] A - The descriptions are too similar; make them more distinct and specific to avoid conflicts.\n[ ] B - There are too many skills installed; remove half of them.\n[ ] C - The effort is too high; reduce it to low.\n[ ] D - The skills need to be renamed with sequential numbers.','\n',char(10)),'[ ] A - The descriptions are too similar; make them more distinct and specific to avoid conflicts.','["Domain_2::Tool_Design_MCP_Integration", "Domain_4::Prompt_Engineering_Structured_Output", "Scenario_1::Customer_Support_Agent"]','New',0,2.5,0,1783092991020,1783727800816,1783203558653,replace('TRADUÇÃO PARA PORTUGUÊS (BR):\n\nPergunta: "Claude usa a skill errada ou fica confuso entre skills similares. Qual é a causa e a correção?"\n\nAlternativas:\n[ ] A - As descrições são muito parecidas; torne-as mais distintas e específicas para evitar conflitos.\n[ ] B - Há muitas skills instaladas; remova metade delas.\n[ ] C - O esforço (effort) está muito alto; reduza-o para baixo.\n[ ] D - As skills precisam ser renomeadas com números sequenciais.','\n',char(10)),replace('EXPLICAÇÃO PARA UM ADULTO TECH LEAD:\n\nA resposta correta é a alternativa A.\n\n**Por que A está correta:**\nO problema central descrito é que Claude está confundindo skills porque as descrições são semanticamente próximas. O mecanismo de seleção de skills do Claude se baseia principalmente na *descrição* da skill para decidir qual invocar. Se duas skills têm descrições como "processa pedidos de reembolso" e "processa pedidos de devolução", o modelo pode não conseguir diferenciá-las com clareza. A correção adequada é tornar as descrições mais distintas e específicas, incluindo palavras-chave exclusivas, exemplos de quando usar cada uma, e contextos de ativação bem definidos. Isso reduz a ambiguidade na hora da seleção.\n\n**Por que as demais estão erradas:**\n\n- **B (remover metade das skills):** Isso é uma abordagem paliativa. Reduzir a quantidade de skills pode diminuir a probabilidade de conflito, mas não resolve a causa raiz, que é a similaridade das descrições. Além disso, você pode perder funcionalidades importantes. O correto é refinar as descrições existentes, não simplesmente deletar skills.\n\n- **C (reduzir o effort):** O parâmetro *effort* (esforço) controla o quão "cuidadoso" o modelo é ao processar uma skill já selecionada, não influencia a *seleção* entre skills. O esforço não tem relação com o problema de confusão entre skills similares. Reduzi-lo não ajudaria em nada e ainda poderia prejudicar a qualidade da execução.\n\n- **D (renomear com números sequenciais):** Números sequenciais (skill_1, skill_2...) não carregam informação semântica alguma. O Claude precisa de descrições textuais ricas para entender *quando* usar cada skill. Numerar apenas torna a seleção ainda mais difícil, pois remove todo o contexto semântico.\n\n**Resumo técnico:** A causa é ambigüidade semântica nas descrições. A correção é aumentar a especificidade e o contraste entre as descrições de cada skill.','\n',char(10)),replace('EXPLICAÇÃO PARA UMA CRIANÇA DE 10 ANOS:\n\nImagine que você tem dois amigos que se chamam João. Um João adora futebol e o outro João adora videogame. Se você disser "João, vem aqui!", os dois podem ficar confusos e não saber quem você está chamando. O problema é que os nomes são iguais!\n\nCom o Claude e as skills (que são como "habilidades" ou "tarefas" que ele pode fazer), acontece a mesma coisa. Se duas skills têm descrições muito parecidas, o Claude não sabe qual escolher.\n\nA alternativa A diz: "As descrições são muito parecidas; torne-as mais distintas e específicas para evitar conflitos." Isso é como dar apelidos diferentes para cada João: "João Futebol" e "João Videogame". Assim, quando você chamar "João Futebol!", só um deles vai aparecer. Essa é a solução certa!\n\nAs outras opções estão erradas:\n\n- B (remover skills): seria como dizer "ai, tem João demais, vamos mandar um embora". Mas você não precisa perder um amigo! Basta dar nomes diferentes.\n\n- C (mudar o effort): effort é como a "força" que o Claude usa para fazer a tarefa. Isso não tem nada a ver com escolher qual skill usar.\n\n- D (numerar as skills): seria como chamar os Joãos de "João 1" e "João 2". Isso ainda não ajuda, porque você não sabe qual é qual. É melhor usar nomes que lembrem o que cada um faz!\n\nEntão, a resposta certa é a A: deixar as descrições mais diferentes e específicas, para o Claude não se confundir.\n','\n',char(10)));
INSERT INTO cards VALUES('admin','card_1783092991076_rz6gnzgiz',431,'In which situation should an agent escalate to a human instead of resolving autonomously?',replace('In which situation should an agent escalate to a human instead of resolving autonomously?\n\nIn which situation should an agent escalate to a human instead of resolving autonomously?\n[Resposta correta: A escalada correta ocorre diante de uma lacuna genuína de política que exige julgamento humano, com critérios explícitos definidos no prompt. Escalar por sentimento do cliente (A), por confiança autorreportada mal calibrada (B) ou por especulação sobre intenção futura (D) são exatamente as pegadinhas a evitar.]\n\n[ ] A - When the customer seems angry or dissatisfied in the tone of the message.\n[ ] B - When the model itself reports low confidence in the answer.\n[ ] C - When there is a genuine policy gap (the policy is silent on the case) that requires human judgment.\n[ ] D - When the agent speculates that the customer may have a problematic future intent.','\n',char(10)),'C - When there is a genuine policy gap (the policy is silent on the case) that requires human judgment.','["Domain_4::Prompt_Engineering_Structured_Output", "Domain_1::Agentic_Architecture_Orchestration", "Scenario_1::Customer_Support_Agent"]','New',0,2.5,0,1783092991077,1783727804035,1783203558653,replace('**Tradução para português do Brasil:**\n\n**Pergunta:** Em qual situação um agente deve escalar para um humano em vez de resolver de forma autônoma?\n\n[ ] A - Quando o cliente parece irritado ou insatisfeito no tom da mensagem.\n[ ] B - Quando o próprio modelo relata baixa confiança na resposta.\n[ ] C - Quando há uma lacuna genuína de política (a política é omissa sobre o caso) que exige julgamento humano.\n[ ] D - Quando o agente especula que o cliente pode ter uma intenção futura problemática.','\n',char(10)),replace('**Explicação para um adulto (tech lead):**\n\nA resposta correta é a **alternativa C**.\n\n**Por que C é a resposta correta:**\n\nA escalada para um humano deve ser um mecanismo controlado e previsível, acionado somente quando o sistema autônomo (agente) encontra um cenário para o qual não há política definida — ou seja, uma "lacuna genuína de política". Nesses casos, não há regra programada ou instrução no prompt que permita ao agente decidir, e por isso o julgamento humano é necessário. Essa abordagem evita que o agente tome decisões arbitrárias ou inseguras fora do escopo de sua autoridade. Além disso, critérios explícitos para escalada devem estar definidos no prompt do sistema, garantindo rastreabilidade e consistência.\n\n**Análise das alternativas incorretas:**\n\n- **Alternativa A (cliente irritado/insatisfeito):** Escalar apenas com base no tom emocional do cliente introduz subjetividade e pode gerar sobrecarga desnecessária no time humano. Agentes bem projetados devem ser capazes de lidar com clientes insatisfeitos dentro da política, usando técnicas de comunicação empática, sem precisar escalar. A menos que a política explicitamente determine escalada para abuso ou ameaça, o tom negativo por si só não é um gatilho válido.\n\n- **Alternativa B (baixa confiança do modelo):** A confiança reportada por um modelo de linguagem (LLM) é uma métrica interna e frequentemente mal calibrada — o modelo pode estar confiante e errado, ou inseguro e correto. Basear escalada nesse sinal leva a falsos positivos e negativos, comprometendo a confiabilidade do sistema. A decisão de escalar deve ser orientada por regras de negócio, não por autoavaliação do modelo.\n\n- **Alternativa D (especulação sobre intenção futura):** Especular sobre o que o cliente *pode* fazer no futuro é altamente subjetivo, propenso a vieses e sem base factual. Agentes devem operar com base em informações concretas e políticas explícitas, não em adivinhações. Escalar por intenção futura presumida abre margem para erros graves e decisões discriminatórias.\n\n**Conclusão técnica:** A escalada correta ocorre diante de uma lacuna genuína de política que exige julgamento humano, com critérios explícitos definidos no prompt. Escalar por sentimento do cliente (A), por confiança autorreportada mal calibrada (B) ou por especulação sobre intenção futura (D) são exatamente as pegadinhas a evitar.','\n',char(10)),replace('Imagine que você é um robô que ajuda a responder dúvidas de clientes em uma loja. Você tem um manual de regras (a "política") que diz o que fazer em cada situação.\n\n- Se o cliente está bravo, você não precisa chamar um humano — você mesmo pode tentar acalmar a pessoa, pedir desculpas e resolver.\n- Se você está inseguro sobre a resposta, também não é motivo para chamar um humano — você pode dar a melhor resposta que sabe ou pedir mais informações.\n- Se você fica imaginando "será que esse cliente vai fazer algo ruim no futuro?", também não deve chamar um humano, porque isso é só um palpite, não um fato.\n\nA única hora certa de chamar um humano é quando **o manual (a política) não diz nada sobre aquele caso**. Por exemplo, se o cliente pede algo que não está escrito em lugar nenhum no manual, aí sim você precisa de um humano para decidir, porque você não tem regra para seguir. É como quando você está jogando um jogo e aparece uma situação que não está nas regras — você precisa perguntar para um adulto.','\n',char(10)));
INSERT INTO cards VALUES('admin','card_1783092991099_xetdz1k8s',432,'An agent gets tool selection right on single-concern requests, but errs on multiple-concern ones.',replace('An agent gets tool selection right on single-concern requests, but errs on multiple-concern ones.\n\nAn agent gets tool selection right on single-concern requests, but errs on multiple-concern ones. What is the first approach?\n[Resposta correta: A alta precisão em casos simples mostra que o agente entende as ferramentas e só precisa de orientação no padrão multi-preocupação, obtida com few-shot. Reescrever descrições (A) ou construir roteador (B) é desnecessário quando o entendimento das ferramentas já está correto, e trocar o modelo (D) não é indicado.]\n\n[ ] A - Rewrite the descriptions of all tools from scratch.\n[ ] B - Build a dedicated router for complex requests.\n[ ] C - Add few-shot examples demonstrating the reasoning and correct sequence for the multi-concern pattern.\n[ ] D - Swap the model for a larger one.','\n',char(10)),'C - Add few-shot examples demonstrating the reasoning and correct sequence for the multi-concern pattern.','["Domain_2::Tool_Design_MCP_Integration", "Domain_4::Prompt_Engineering_Structured_Output", "Scenario_1::Customer_Support_Agent"]','New',0,2.5,0,1783092991099,1783727807671,1783203558653,replace('**Tradução para português do Brasil:**\n\nUm agente acerta na seleção de ferramentas em requisições de preocupação única, mas erra em requisições de múltiplas preocupações. Qual é a primeira abordagem?\n\n[ ] A - Reescrever as descrições de todas as ferramentas do zero.\n[ ] B - Construir um roteador dedicado para requisições complexas.\n[ ] C - Adicionar exemplos few-shot demonstrando o raciocínio e a sequência correta para o padrão de múltiplas preocupações.\n[ ] D - Trocar o modelo por um maior.','\n',char(10)),replace('**Explicação didática para adulto tech lead:**\n\nO cenário descreve um agente que já demonstra alta competência em casos simples (preocupação única), mas falha em cenários mais complexos que exigem a combinação ou sequenciamento de múltiplas ferramentas. Isso indica que o problema **não** está no entendimento individual das ferramentas nem no modelo em si, mas sim na **capacidade de planejamento e raciocínio sequencial** quando múltiplas preocupações estão presentes.\n\nVamos analisar cada alternativa:\n\n**C - Adicionar exemplos few-shot demonstrando o raciocínio e a sequência correta para o padrão de múltiplas preocupações. (CORRETA)**\nA abordagem mais parcimoniosa e eficaz é fornecer ao modelo exemplos explícitos (few-shot) que demonstrem o passo a passo para lidar com requisições que envolvem múltiplas preocupações. Como o agente já entende as ferramentas individualmente (acerta em casos simples), ele só precisa aprender o *padrão de composição* — e few-shots bem elaborados cumprem exatamente esse papel, guiando o raciocínio sem exigir reescrita de código ou troca de modelo.\n\n**A - Reescrever as descrições de todas as ferramentas do zero. (INCORRETA)**\nReescrever descrições seria justificável se o agente estivesse escolhendo ferramentas erradas mesmo em casos simples. O enunciado diz que ele *acerta* em requisições de preocupação única, o que comprova que as descrições atuais são suficientes. Reescrever tudo seria retrabalho desnecessário e não resolveria o problema central que é a orquestração entre múltiplas ferramentas.\n\n**B - Construir um roteador dedicado para requisições complexas. (INCORRETA)**\nConstruir um roteador externo é uma solução arquitetural mais pesada e complexa, que introduz um novo componente de software com custos de manutenção e latência. O problema ainda está na camada de prompt/inteligência do agente, não na arquitetura. Antes de mudar a arquitetura, deve-se tentar intervenções mais leves como engenharia de prompt (few-shot).\n\n**D - Trocar o modelo por um maior. (INCORRETA)**\nModelos maiores são mais caros e lentos, e não há evidência de que o modelo atual seja incapaz de entender o padrão multi-preocupação — ele só precisa ser *guiado* para isso. A falha é de *prompting/raciocínio induzido*, não de capacidade bruta do modelo. Trocar o modelo seria um tiro de canhão para matar uma formiga, além de não ser a "primeira abordagem" recomendada.\n\nConclusão: A abordagem mais leve, direta e eficaz como *primeiro passo* é a engenharia de prompt via few-shot, que ataca diretamente a causa raiz: a falta de exemplos de como raciocinar sobre múltiplas preocupações encadeadas.','\n',char(10)),replace('Imagina que você tem um robô ajudante que sabe usar ferramentas como martelo, chave de fenda e tesoura.\n\nQuando você pede algo simples, tipo "martela esse prego", ele acerta sempre. Mas quando você pede algo mais complicado, tipo "primeiro martela o prego, depois corta o barbante com a tesoura e parafusa a dobradiça", ele se atrapalha e faz a ordem errada ou usa a ferramenta errada.\n\nO que fazer primeiro?\n\nA opção C é a melhor: dar exemplos pra ele. Mostrar uns 2 ou 3 probleminhas parecidos com a resposta certa, tipo:\n"Se pedirem ''martela o prego e corta o barbante'', você primeiro pega o martelo, martela o prego, depois pega a tesoura e corta o barbante. Entendeu?"\n\nAí o robô aprende o *jeito certo de pensar* quando tem várias tarefas. É muito mais fácil do que reescrever o manual inteiro das ferramentas (opção A), construir um robô separado só pra decidir o que fazer (opção B), ou trocar o robô por um maior e mais caro (opção D). Como ele já entende as ferramentas uma por uma, é só ensinar a sequência certa com exemplos!','\n',char(10)));
INSERT INTO cards VALUES('admin','card_1783092991123_e2gg5cx3d',433,'Why is providing the existing content in the context the reliable way to avoid duplication, such as duplicate tests?',replace('Why is providing the existing content in the context the reliable way to avoid duplication, such as duplicate tests?\n\nWhy is providing the existing content in the context the reliable way to avoid duplication, such as duplicate tests?\n[Resposta correta: O LLM só raciocina sobre o que está em seu contexto, então ver o conteúdo existente é o que permite evitar duplicatas. O matching por palavra-chave é frágil e perde equivalências semânticas (A), reduzir a saída não trata duplicação (C) e o modelo não memoriza o repositório entre execuções (D).]\n\n[ ] A - Because keyword matching detects all duplicates robustly.\n[ ] B - Because the LLM only reasons over what is in its context; without seeing what already exists, there is no way to avoid duplicates.\n[ ] C - Because reducing the amount of output eliminates duplicates.\n[ ] D - Because the model memorizes the repository between runs.','\n',char(10)),'B - Because the LLM only reasons over what is in its context; without seeing what already exists, there is no way to avoid duplicates.','["Domain_5::Context_Management_Reliability", "Domain_4::Prompt_Engineering_Structured_Output", "Scenario_4::Developer_Productivity"]','New',0,2.5,0,1783092991123,1783727811145,1783203558653,replace('**Tradução para português do Brasil:**\n\n**Pergunta:** Por que fornecer o conteúdo existente no contexto é a forma confiável de evitar duplicação, como testes duplicados?\n\n**Alternativas:**\n\n[ ] A - Porque a correspondência por palavra-chave detecta todas as duplicatas de forma robusta.\n[ ] B - Porque o LLM só raciocina sobre o que está em seu contexto; sem ver o que já existe, não há como evitar duplicatas.\n[ ] C - Porque reduzir a quantidade de saída elimina duplicatas.\n[ ] D - Porque o modelo memoriza o repositório entre execuções.','\n',char(10)),replace('**Explicação para um adulto (tech lead):**\n\n**Resposta correta: Alternativa B**\n\nA alternativa B está correta porque reflete o funcionamento fundamental dos Large Language Models (LLMs). Estes modelos possuem uma **janela de contexto** (context window) que define o escopo de informações disponíveis para o raciocínio em uma determinada chamada. O LLM não possui memória persistente entre execuções — cada chamada é estatisticamente independente. Portanto, a única maneira de o modelo "saber" o que já existe no repositório (como testes já escritos) é fornecendo esse conteúdo explicitamente dentro do contexto da requisição. Sem esse conteúdo no contexto, o modelo simplesmente não tem como inferir ou deduzir se algo é duplicado, pois ele não "lembra" de execuções anteriores.\n\n**Análise das alternativas incorretas:**\n\n- **Alternativa A (Keyword matching):** Incorreta. Correspondência por palavra-chave (keyword matching) é uma abordagem frágil e superficial. Ela falha em capturar equivalências semânticas, ou seja, dois testes que testam a mesma funcionalidade mas usam palavras diferentes (ex.: "calcular soma" vs. "adicionar números") não seriam detectados como duplicatas. Além disso, um LLM não executa keyword matching internamente — ele opera por representações densas (embeddings) e predição de tokens.\n\n- **Alternativa C (Reduzir a saída):** Incorreta. Reduzir a quantidade de saída (output) não trata duplicação. Um modelo pode gerar pouca saída e ainda assim produzir conteúdo duplicado. A quantidade de saída é um parâmetro de geração (como max_tokens), não uma estratégia para evitar duplicatas. A causa raiz da duplicação é a falta de conhecimento do que já existe, não o volume do que é gerado.\n\n- **Alternativa D (Memorização do repositório):** Incorreta. LLMs não memorizam repositórios entre execuções. Cada sessão ou chamada de API é stateless a menos que o estado seja gerenciado externamente (via histórico de conversa no contexto). O modelo não possui persistência inerente de informações entre chamadas distintas. Mesmo com fine-tuning, o modelo não "grava" conteúdos específicos de um repositório entre runs.','\n',char(10)),replace('**Explicação para uma criança de 10 anos:**\n\nImagine que você tem um robô que ajuda a criar lições de casa. Esse robô só consegue pensar naquilo que você mostra para ele na hora. Se você não mostrar quais lições já foram feitas, ele pode criar uma lição igual a outra que já existe, porque ele simplesmente não sabe que ela já foi feita!\n\nÉ como se você estivesse desenhando e um amigo seu também estivesse desenhando em outra sala, sem ver o que você fez. Vocês podem acabar desenhando a mesma coisa, certo?\n\nAgora, se vocês desenharem lado a lado, um vendo o desenho do outro, fica muito mais fácil não repetir o mesmo desenho.\n\nÉ exatamente isso que a alternativa B explica: o robô (LLM) só consegue pensar naquilo que está na "cabeça" dele no momento (o contexto). Se a gente mostrar para ele o que já existe, ele consegue evitar criar coisa repetida. As outras opções estão erradas porque:\n\n- **A:** Diz que procurar palavras iguais resolve tudo, mas isso não funciona. Duas receitas de bolo podem usar palavras diferentes e ainda serem a mesma receita!\n- **C:** Diz que escrever menos evita repetição, mas escrever pouco não impede de escrever algo repetido.\n- **D:** Diz que o robô guarda tudo na memória, mas ele não guarda nada entre uma tarefa e outra — ele esquece tudo depois que termina!','\n',char(10)));
INSERT INTO cards VALUES('admin','card_1783092991150_5xw7yzzs7',434,'An agent confuses similar tools.',replace('An agent confuses similar tools.\n\nAn agent confuses similar tools. What is the first step, low effort and high impact?\n[Resposta correta: A descrição é o principal sinal de seleção de ferramenta, então melhorá-la é o primeiro passo de baixo esforço e alto impacto. Camada de roteamento (A), consolidação (C) e few-shot (D) são medidas mais custosas que só devem ser consideradas depois de resolver a descrição.]\n\n[ ] A - Build a dedicated routing layer to choose the tool.\n[ ] B - Improve the tool descriptions with input formats, examples, edge cases and when to use each one.\n[ ] C - Consolidate the similar tools into a single one.\n[ ] D - Add many few-shot examples before any other change.','\n',char(10)),'B - Improve the tool descriptions with input formats, examples, edge cases and when to use each one.','["Domain_2::Tool_Design_MCP_Integration", "Domain_4::Prompt_Engineering_Structured_Output", "Scenario_4::Developer_Productivity"]','New',0,2.5,0,1783092991150,1783727814724,1783203558653,replace('Tradução para português do Brasil:\n\n**Um agente confunde ferramentas similares.**\nPergunta: Um agente confunde ferramentas similares. Qual é o primeiro passo, de baixo esforço e alto impacto?\n\n[ ] A - Construir uma camada de roteamento dedicada para escolher a ferramenta.\n[ ] B - Melhorar as descrições das ferramentas com formatos de entrada, exemplos, casos extremos e quando usar cada uma.\n[ ] C - Consolidar as ferramentas similares em uma única.\n[ ] D - Adicionar muitos exemplos few-shot antes de qualquer outra mudança.','\n',char(10)),replace('Explicação para adulto (tech lead):\n\nO problema central é que o agente está confundindo ferramentas porque não consegue diferenciá-las adequadamente. Em sistemas de agentes (como aqueles baseados em LLMs), a seleção de ferramentas depende quase inteiramente das descrições fornecidas no "tool schema" ou "tool definition". O modelo usa essas descrições para decidir qual ferramenta invocar.\n\n**Por que B é a resposta correta:**\n\nMelhorar as descrições das ferramentas é a ação de **menor esforço** e **maior impacto** porque:\n- Não requer mudanças arquiteturais (diferente de A e C).\n- Não requer coleta ou geração de dados adicionais (diferente de D).\n- Ataca diretamente a causa raiz: se as descrições são ambíguas, o modelo não tem informação suficiente para decidir corretamente.\n- Adicionar detalhes como formatos de entrada esperados, exemplos concretos, casos extremos e orientações de uso (ex: "use esta ferramenta quando X, use a outra quando Y") reduz drasticamente a ambiguidade.\n\n**Análise das alternativas incorretas:**\n\n- **A (Camada de roteamento):** Construir uma camada de roteamento dedicada é uma solução de **altíssimo esforço** (requer desenvolvimento, testes, manutenção) e só faz sentido depois que as descrições já estiverem otimizadas. É overengineering prematuro.\n\n- **C (Consolidar ferramentas):** Consolidar ferramentas similares pode resolver o sintoma (o agente não confunde porque só existe uma), mas perde a especialização que cada ferramenta provavelmente oferece. Além disso, requer refatoração de código e possíveis mudanças em chamadas existentes. É um passo de médio/alto esforço que pode ser desnecessário se as descrições forem boas.\n\n- **D (Adicionar few-shot examples):** Few-shot é útil, mas adicionar exemplos antes de melhorar as descrições é colocar a carroça na frente dos bois. Descrições são o mecanismo primário de seleção; few-shot é um complemento. Além disso, coletar/gerar bons exemplos tem custo e pode introduzir viés. Deve ser feito após a otimização das descrições.\n\n**Conclusão:** Siga o princípio de Pareto: a descrição é o principal sinal de seleção de ferramenta. Melhorá-la é o passo de menor esforço com maior retorno. As outras alternativas são medidas mais custosas que só devem ser consideradas depois de resolver a qualidade das descrições.','\n',char(10)),replace('Imagine que você tem duas caixas de brinquedos muito parecidas: uma tem peças de LEGO e a outra tem peças de encaixar. Se você escrever só "caixa de peças" nas duas, você vai sempre abrir a caixa errada!\n\nAqui, o "agente" é como um robô que precisa escolher a ferramenta certa para cada tarefa. Ele está confundindo as ferramentas porque as instruções (descrições) são ruins.\n\nA melhor ideia, que não dá quase nenhum trabalho mas resolve o problema, é **melhorar as descrições** (alternativa B). É como colocar etiquetas bem escritas: "Caixa com peças de LEGO - use para montar casinhas" e "Caixa com peças de encaixe - use para montar carrinhos". Assim o robô nunca mais erra!\n\nAs outras opções dão muito mais trabalho:\n- A - Criar um "vigia" especial para escolher a caixa (dá trabalho programar isso).\n- C - Juntar as duas caixas em uma só (mas aí perde a graça de cada brinquedo).\n- D - Fazer muitos desenhos de exemplo antes de arrumar as etiquetas (é mais fácil primeiro arrumar as etiquetas, né?).\n\nEntão, primeiro arrume as etiquetas (descrições), depois pense nas outras soluções se ainda precisar!','\n',char(10)));
INSERT INTO cards VALUES('admin','card_1783092991175_mpey40zfu',435,'An agent consistently selects the wrong tool.',replace('An agent consistently selects the wrong tool.\n\nAn agent consistently selects the wrong tool. What is the first diagnostic step?\n[Resposta correta: A descrição é o principal input de decisão do modelo, então revisá-la para distinguir propósito e quando usar cada ferramenta é o primeiro passo. Enumerar todos os padrões (A), criar classificador (B) ou remover funcionalidade (D) são abordagens a evitar.]\n\n[ ] A - Enumerate all possible usage patterns in the prompt.\n[ ] B - Build a separate classifier to choose the tool.\n[ ] C - Review the tool descriptions to ensure they clearly distinguish the purpose of each one and when to use them.\n[ ] D - Remove the least-used tool to reduce options.','\n',char(10)),'C - Review the tool descriptions to ensure they clearly distinguish the purpose of each one and when to use them.','["Domain_2::Tool_Design_MCP_Integration", "Domain_4::Prompt_Engineering_Structured_Output", "Scenario_1::Customer_Support_Agent"]','New',0,2.5,0,1783092991175,1783727818301,1783203558653,replace('**Tradução para português (Brasil):**\n\nUm agente consistentemente seleciona a ferramenta errada.\n\nQual é o primeiro passo de diagnóstico?\n\n[ ] A - Enumerar todos os padrões de uso possíveis no prompt.\n[ ] B - Construir um classificador separado para escolher a ferramenta.\n[ ] C - Revisar as descrições das ferramentas para garantir que elas distinguem claramente o propósito de cada uma e quando usá-las.\n[ ] D - Remover a ferramenta menos usada para reduzir as opções.','\n',char(10)),replace('**Explicação para um adulto tech lead:**\n\nA resposta correta é a **alternativa C**.\n\nQuando um agente baseado em LLM consistentemente escolhe a ferramenta errada, o problema geralmente está na **qualidade das descrições das ferramentas**. Em sistemas de agentes, as descrições das ferramentas são o principal mecanismo de instrução que orienta o modelo sobre qual ferramenta invocar em cada contexto. O modelo não "entende" o código da ferramenta; ele toma decisões com base no texto da descrição, nos nomes e nos parâmetros expostos. Portanto, o primeiro passo de diagnóstico é sempre revisar se as descrições são suficientemente distintas e informativas para diferenciar os propósitos e cenários de uso.\n\n**Por que as demais alternativas estão incorretas:**\n\n- **Alternativa A (Enumerar todos os padrões de uso no prompt):** Embora possa ser útil em alguns cenários, enumerar todos os padrões de uso possíveis no prompt tende a ser ineficiente, polui o contexto com informações extensas e não endereça a causa raiz. O problema não é falta de exemplos, mas sim ambiguidade nas descrições.\n\n- **Alternativa B (Construir um classificador separado):** Construir um classificador adicional para decidir qual ferramenta usar adiciona complexidade desnecessária ao sistema e desvia do problema central. O LLM já deveria ser capaz de realizar essa escolha se as descrições forem claras. Criar um componente extra é uma solução muito pesada para o primeiro passo de diagnóstico.\n\n- **Alternativa D (Remover a ferramenta menos usada):** Remover funcionalidades reduz a capacidade do agente e pode mascarar o problema, mas não o resolve. O correto é primeiro entender se o erro é de descrição, de implementação ou de design de ferramentas, antes de eliminar opções.','\n',char(10)),replace('**Explicação para uma criança de 10 anos:**\n\nImagine que você tem vários controles remotos em casa: um para a TV, um para o videogame e um para o som. Mas você sempre pega o controle do videogame quando quer ligar a TV. O que está errado?\n\nIsso é o que acontece com o agente (um robô que escolhe ferramentas). Ele sempre pega a ferramenta errada.\n\nA primeira coisa a fazer é olhar as descrições de cada ferramenta — tipo as etiquetas nos controles. Se a etiqueta do controle do videogame estiver escrito "Liga a TV", o robô vai ficar confuso! Então, a melhor ideia é **arrumar as etiquetas (as descrições)** para que cada ferramenta explique direitinho para que serve e quando usar.\n\nAs outras opções seriam:\n- A: Listar todos os usos possíveis (mas isso é como escrever um livro enorme de instruções — bagunça tudo).\n- B: Criar outro robô só para escolher a ferramenta (muito complicado e desnecessário).\n- D: Jogar fora o controle menos usado (assim a gente perde um controle que pode ser útil depois).\n\nEntão, a resposta certa é a **C**: revisar as descrições para que fique bem claro o que cada ferramenta faz e quando usar cada uma.','\n',char(10)));
INSERT INTO cards VALUES('admin','card_1783092991199_l12z2mswt',436,'In which situation is the cause of wrong tool selection in the prompt, and not in the tool description?',replace('In which situation is the cause of wrong tool selection in the prompt, and not in the tool description?\n\nIn which situation is the cause of wrong tool selection in the prompt, and not in the tool description?\n[Resposta correta: Um padrão sistemático ligado a uma palavra-chave, com acerto na ausência dela, aponta para lógica keyword-sensitive no system prompt. Erro aleatório (A) não indica roteamento por termo, descrições parecidas (C) apontam para a descrição e não o prompt, e o acerto sem o termo descarta limitação do modelo (D).]\n\n[ ] A - When the error occurs completely at random, unrelated to the text of the request.\n[ ] B - When there is a systematic pattern triggered by a specific keyword and the model gets it right in the absence of that term, indicating keyword-sensitive logic in the system prompt.\n[ ] C - When the tool descriptions are too similar to each other.\n[ ] D - When the model is too small for the task.','\n',char(10)),'[ ] B - When there is a systematic pattern triggered by a specific keyword and the model gets it right in the absence of that term, indicating keyword-sensitive logic in the system prompt.','["Domain_4::Prompt_Engineering_Structured_Output", "Domain_2::Tool_Design_MCP_Integration", "Scenario_1::Customer_Support_Agent"]','New',0,2.5,0,1783092991199,1783727821747,1783203558653,replace('**Tradução para português do Brasil:**\n\nEm qual situação a causa da seleção incorreta da ferramenta está no prompt, e não na descrição da ferramenta?\n\n[ ] A - Quando o erro ocorre de forma completamente aleatória, sem relação com o texto da solicitação.\n[ ] B - Quando há um padrão sistemático acionado por uma palavra-chave específica e o modelo acerta na ausência desse termo, indicando uma lógica sensível a palavras-chave no system prompt.\n[ ] C - Quando as descrições das ferramentas são muito parecidas entre si.\n[ ] D - Quando o modelo é muito pequeno para a tarefa.','\n',char(10)),replace('**Explicação didática para um adulto tech lead:**\n\nA pergunta investiga a **origem do erro** na seleção de ferramentas: o problema está no **prompt** (instrução do sistema) ou na **descrição da ferramenta**?\n\n- **Alternativa B (correta):** Se o modelo sistematicamente escolhe a ferramenta errada quando uma palavra-chave específica está presente, mas acerta quando essa palavra está ausente, isso é uma evidência forte de que o *system prompt* contém uma regra ou condicional que mapeia a palavra-chave para a ferramenta errada. Esse comportamento sistemático (não aleatório) e dependente de um termo específico aponta claramente para o prompt como causa raiz. A descrição da ferramenta pode estar perfeitamente correta, mas o prompt está "sequestrando" a decisão com uma regra mal formulada.\n\n- **Alternativa A (incorreta):** Erro aleatório, sem padrão ou relação com o texto, sugere problemas de instabilidade do modelo, amostragem (temperature/top-p) ou ruído computacional, não um viés induzido pelo prompt.\n\n- **Alternativa C (incorreta):** Quando descrições de ferramentas são muito similares, o modelo naturalmente tem dificuldade de distinguir qual usar. Nesse caso, o problema está na qualidade/redação das descrições, não no prompt.\n\n- **Alternativa D (incorreta):** Um modelo pequeno pode carecer de capacidade de raciocínio ou compreensão para escolher a ferramenta adequada, mas isso é uma limitação do modelo, não do prompt. Além disso, a alternativa diz "acerta sem o termo" — essa condição não se aplica aqui.','\n',char(10)),replace('Imagine que você tem um robô que precisa escolher qual brinquedo pegar: uma bola ou um carrinho. Você escreve instruções para ele.\n\nA alternativa B é como se o robô, toda vez que ouve a palavra "vermelho", pegasse a bola, mesmo quando você queria o carrinho. Mas se você não falar "vermelho", ele acerta sempre. Isso significa que o problema está nas **instruções que você escreveu** (no prompt), não na descrição dos brinquedos. Você colocou uma regra escondida que confunde o robô.\n\nAs outras opções seriam: o robô errar sem motivo (A), os brinquedos terem descrições muito parecidas (C), ou o robô ser muito bobinho para entender (D). Nenhuma delas coloca a culpa nas instruções — a culpa é de outra coisa.','\n',char(10)));
INSERT INTO cards VALUES('admin','card_1783092991222_v7eke06tg',437,'An agent has a systematic performance drop (78% vs 93%) whenever a specific term appears, even with good tool descriptions.',replace('An agent has a systematic performance drop (78% vs 93%) whenever a specific term appears, even with good tool descriptions.\n\nAn agent has a systematic performance drop (78% vs 93%) whenever a specific term appears, even with good tool descriptions. What is the cause?\n[Resposta correta: A queda sistemática ligada a um termo específico indica lógica explícita keyword-sensitive no system prompt. As descrições não são a causa quando o desempenho é bom sem o termo (A), o acerto na ausência do termo descarta limitação do modelo (B) e o padrão é sistemático, não aleatório como seria com temperature alta (D).]\n\n[ ] A - The tool descriptions are ambiguous despite seeming good.\n[ ] B - The model is limited and cannot handle this type of request.\n[ ] C - The system prompt contains keyword-sensitive instructions creating unintended routing.\n[ ] D - The temperature is too high and generates random variation.','\n',char(10)),'C - The system prompt contains keyword-sensitive instructions creating unintended routing.','["Domain_4::Prompt_Engineering_Structured_Output", "Domain_1::Agentic_Architecture_Orchestration", "Scenario_1::Customer_Support_Agent"]','New',0,2.5,0,1783092991222,1783727825465,1783203558653,replace('**Tradução para português do Brasil:**\n\n**Pergunta:** Um agente tem uma queda sistemática de desempenho (78% vs 93%) sempre que um termo específico aparece, mesmo com boas descrições de ferramentas. Qual é a causa?\n\n**Alternativas:**\n\n[ ] A - As descrições das ferramentas são ambíguas, apesar de parecerem boas.\n[ ] B - O modelo é limitado e não consegue lidar com esse tipo de solicitação.\n[ ] C - O prompt do sistema contém instruções sensíveis a palavras-chave, criando um roteamento não intencional.\n[ ] D - A temperatura está muito alta e gera variação aleatória.','\n',char(10)),replace('**Explicação para um adulto tech lead:**\n\nA queda de desempenho é **sistemática** (78% vs 93%) e está **estritamente ligada à presença de um termo específico**. Isso é um padrão clássico de **vazamento de lógica condicional no system prompt**.\n\n- **Alternativa C (correta):** É a única que explica um comportamento determinístico e condicionado a um gatilho léxico. Se o system prompt contém algo como "se o usuário mencionar ''X'', faça Y", o agente desvia seu comportamento sempre que o termo aparece, causando a queda consistente. As tool descriptions podem estar perfeitas, mas a lógica embutida no prompt sobrescreve o comportamento esperado.\n\n- **Alternativa A (incorreta):** Se as descrições fossem ambíguas, a queda seria generalizada ou apareceria em outras situações. O fato de o desempenho ser de 93% na *ausência* do termo mostra que as descrições funcionam bem — o problema é acionado exclusivamente pela presença do termo.\n\n- **Alternativa B (incorreta):** Um modelo limitado apresentaria baixo desempenho em todas as variações da tarefa, não apenas quando um termo específico aparece. A diferença de 15 pontos percentuais entre as duas condições prova que o modelo é capaz de executar a tarefa corretamente (93% de acerto na condição sem o termo).\n\n- **Alternativa D (incorreta):** Temperature alta causa variação aleatória e ruído — os resultados seriam imprevisíveis e inconsistentes, não uma queda *sistemática* e correlacionada a um termo específico. O padrão observado é determinístico, não estocástico.','\n',char(10)),replace('**Explicação para uma criança de 10 anos:**\n\nImagina que você tem um robô que responde perguntas. Na maioria das vezes ele acerta 93 de cada 100 perguntas — muito bem! Mas, de repente, quando alguém fala a palavra "abacaxi", ele só acerta 78 de cada 100. Isso acontece sempre que a palavra aparece, e não por acaso.\n\nPor que isso acontece?\n\n- A resposta certa (C) diz que o problema está nas instruções que deram para o robô. Alguém escreveu uma regra do tipo: "Se a pessoa falar ''abacaxi'', faça isso diferente". Essa regra especial atrapalha o robô, mesmo que ele seja bom no resto.\n\n- As outras respostas não fazem sentido porque:\n  - (A) Se as descrições das tarefas fossem confusas, o robô erraria sempre, não só quando aparece "abacaxi".\n  - (B) Se o robô fosse limitado, ele iria mal em tudo, mas ele vai bem na maioria das vezes.\n  - (D) Se fosse culpa da "temperatura" (uma configuração que deixa o robô mais criativo), os erros seriam aleatórios, e não sempre que a palavra aparece.\n\nEntão, o culpado é uma regra escondida nas instruções que o robô recebeu!','\n',char(10)));
INSERT INTO cards VALUES('admin','card_1783092991245_atfh1c0i5',438,'Prose descriptions keep being interpreted ambiguously and have already failed.',replace('Prose descriptions keep being interpreted ambiguously and have already failed.\n\nProse descriptions keep being interpreted ambiguously and have already failed. Which technique is most effective?\n[Resposta correta: Exemplos concretos de entrada-saída contornam a ambiguidade linguística ao mostrar exatamente o resultado esperado. Repetir prosa que já falhou (A) não adiciona clareza, validar só a estrutura (C) não resolve a lógica da transformação e aumentar effort (D) não trata a ambiguidade da instrução.]\n\n[ ] A - Rewrite the same prose description with different words.\n[ ] B - Provide 2-3 concrete input-output examples showing the expected transformation.\n[ ] C - Add only a validation of the output structure.\n[ ] D - Increase the session effort so the model reasons more.','\n',char(10)),'B - Provide 2-3 concrete input-output examples showing the expected transformation.','["Domain_4::Prompt_Engineering_Structured_Output", "Domain_5::Context_Management_Reliability", "Scenario_6::Structured_Data_Extraction"]','New',0,2.5,0,1783092991245,1783727829241,1783203558653,replace('**Tradução:**\n\nDescrições em prosa continuam sendo interpretadas de forma ambígua e já falharam.\n\nDescrições em prosa continuam sendo interpretadas de forma ambígua e já falharam. Qual técnica é mais eficaz?\n\n[ ] A - Reescrever a mesma descrição em prosa com palavras diferentes.\n[ ] B - Fornecer 2-3 exemplos concretos de entrada-saída mostrando a transformação esperada.\n[ ] C - Adicionar apenas uma validação da estrutura de saída.\n[ ] D - Aumentar o esforço (effort) da sessão para que o modelo raciocine mais.','\n',char(10)),replace('**Explicação para um adulto tech lead:**\n\n**Resposta correta: B**\n\n**Por que B é a melhor escolha:**\n\nQuando instruções em linguagem natural (prosa) falham devido à ambiguidade intrínseca da linguagem, a técnica mais eficaz é fornecer exemplos concretos de input-output (few-shot learning ou in-context learning). Exemplos concretos eliminam a ambiguidade ao demonstrar exatamente o que se espera, em vez de depender de uma descrição abstrata que pode ser interpretada de múltiplas formas. Isso é particularmente eficaz em modelos de linguagem, que se beneficiam de padrões explícitos.\n\n**Análise das alternativas incorretas:**\n\n- **A (Reescrever a prosa com palavras diferentes):** Se a descrição original já falhou por ambiguidade, simplesmente reescrevê-la com sinônimos ou reestruturação sintática não resolve o problema fundamental — a linguagem natural continuará sujeita a interpretações divergentes. É apenas "mais do mesmo" sem endereçar a causa raiz.\n\n- **C (Adicionar apenas validação da estrutura de saída):** Validar a estrutura (ex.: "a saída deve ser um JSON") não resolve ambiguidades sobre a lógica da transformação — o *que* deve ser feito com os dados. Estrutura é sobre formato; o problema é sobre semântica e lógica de negócio.\n\n- **D (Aumentar o esforço/effort da sessão):** Aumentar o parâmetro de "effort" ou número de tokens de raciocínio pode ajudar em tarefas complexas, mas não trata ambiguidade semântica na instrução. Se o modelo não entendeu o que fazer, mais raciocínio sobre uma instrução ambígua só levará a respostas mais elaboradamente erradas.','\n',char(10)),replace('**Explicação para uma criança de 10 anos:**\n\nImagine que você pede para um amigo desenhar um gato, mas só fala "desenha um gato". Seu amigo desenha um gato bravo, mas você queria um gato dormindo. A descrição em palavras foi ambígua — deu pra entender de dois jeitos diferentes.\n\nAgora, se você mostrar uma foto de um gato dormindo e disser "desenha igual a isso", fica muito mais fácil, né? É exatamente isso que a opção B faz: ao invés de só descrever com palavras (que podem ser confusas), você mostra exemplos prontos.\n\nAs outras opções não funcionam tão bem:\n- **A:** É como repetir "desenha um gato" com palavras diferentes, tipo "faz um desenho de um felino". O problema continua o mesmo.\n- **C:** É como dizer "o desenho tem que ser no papel quadriculado" — ajuda no formato, mas não no que desenhar.\n- **D:** É como mandar seu amigo pensar mais antes de desenhar. Mas pensar mais numa instrução confusa não resolve — ele vai continuar sem saber se é gato bravo ou dormindo.\n\nEntão, a melhor ideia é sempre dar exemplos prontos de como você quer o resultado!','\n',char(10)));
INSERT INTO cards VALUES('admin','card_1783092991268_3proa5rub',439,'How can you improve the completeness of responses whose gap varies a lot from case to case?',replace('How can you improve the completeness of responses whose gap varies a lot from case to case?\n\nHow can you improve the completeness of responses whose gap varies a lot from case to case?\n[Resposta correta: Um passo de autocrítica (padrão evaluator-optimizer) faz o agente avaliar o rascunho contra critérios antes de responder, tratando lacunas variáveis. Few-shot serve a padrões consistentes, não lacunas altamente variáveis (A), trocar o modelo não resolve gap estrutural (B) e pedir confirmação ao cliente transfere o ônus (D).]\n\n[ ] A - Add few-shot examples covering every possible variation.\n[ ] B - Swap the model for a larger one.\n[ ] C - Add a self-critique step in which the agent evaluates its own draft against criteria before responding.\n[ ] D - Ask the customer to confirm whether the response turned out complete.','\n',char(10)),'C - Add a self-critique step in which the agent evaluates its own draft against criteria before responding.','["Domain_1::Agentic_Architecture_Orchestration", "Domain_4::Prompt_Engineering_Structured_Output", "Domain_5::Context_Management_Reliability", "Scenario_1::Customer_Support_Agent"]','New',0,2.5,0,1783092991268,1783727832823,1783203558653,replace('**Tradução para português do Brasil:**\n\nPergunta: Como você pode melhorar a completude de respostas cuja lacuna varia muito de caso para caso?\n\n[ ] A - Adicionar exemplos few-shot cobrindo todas as variações possíveis.\n[ ] B - Trocar o modelo por um maior.\n[ ] C - Adicionar um passo de autocrítica no qual o agente avalia seu próprio rascunho contra critérios antes de responder.\n[ ] D - Pedir ao cliente que confirme se a resposta foi completa.','\n',char(10)),replace('**Explicação didática para um adulto tech lead:**\n\nA pergunta aborda um problema comum em sistemas de agentes de IA: como garantir que respostas geradas sejam completas quando o conhecimento necessário ou o "gap" de informação varia significativamente a cada chamada — ora o agente precisa de um detalhe técnico profundo, ora de um contexto histórico, ora de um dado numérico específico.\n\n**Alternativa correta: C**\n\nAdicionar um passo de autocrítica (padrão evaluator-optimizer) é a abordagem mais adequada porque:\n\n- O agente gera um rascunho e, em seguida, avalia esse rascunho contra um conjunto de critérios predefinidos (ex.: "contém dado numérico?", "explica o conceito X?", "inclui fonte?").\n- Esse passo é dinâmico e adaptável a cada caso: os critérios são fixos, mas o que o agente avalia no rascunho varia conforme o conteúdo gerado e a lacuna identificada.\n- Permite que o próprio agente detecte omissões e realize iterações de refinamento antes de entregar a resposta final.\n- É escalável para gaps altamente variáveis, pois não depende de exemplos pré-catalogados nem de intervenção externa.\n\n**Por que as demais estão incorretas:**\n\n- **A (Few-shot covering all variations):** Few-shot learning funciona bem para padrões consistentes e repetitivos. Tentar cobrir "todas as variações possíveis" é impraticável em cenários com alta variabilidade — o espaço de possibilidades é grande demais, o custo de construção dos exemplos é proibitivo, e o modelo pode sofrer com overfitting ou confusão diante de exemplos contraditórios.\n\n- **B (Trocar por um modelo maior):** Um modelo maior pode ter mais capacidade paramétrica, mas isso não resolve um gap estrutural de completude. A lacuna não é de capacidade bruta de geração, mas de processo: o modelo precisa verificar se cobriu todos os aspectos necessários para aquele caso específico. Um modelo maior pode até alucinar mais confiantemente respostas incompletas.\n\n- **D (Pedir confirmação ao cliente):** Isso apenas transfere o ônus da verificação de completude para o usuário, o que degrade a experiência do produto. Em contexto enterprise, espera-se que o sistema faça o trabalho pesado de garantir qualidade, não que o cliente atue como validador manual a cada interação.\n\n**Resumo técnico:** O padrão evaluator-optimizer com autocrítica é a solução arquitetural correta para variabilidade de gaps porque implementa um loop de verificação interno, adaptativo e sem dependência de dados externos ou intervenção humana.','\n',char(10)),replace('Imagine que você tem um robô que ajuda a responder perguntas, mas toda pergunta é diferente — uma pergunta é sobre dinossauros, outra é sobre receita de bolo, outra é sobre regras de futebol. O robôt nem sempre lembra de dar a resposta completa.\n\nA melhor ideia é ensinar o robô a "dar uma revisada" no que ele mesmo escreveu antes de responder. Tipo quando você faz um dever de casa e, antes de entregar, lê de novo para ver se não esqueceu de nada. O robô faz a mesma coisa: ele escreve a resposta, depois olha para ela e confere: "Será que eu falei o nome do dinossauro? Dei a receita certinha? Expliquei a regra direitinho?" Se faltou algo, ele ajusta antes de mostrar para você.\n\nAs outras ideias não funcionam tão bem:\n- Colocar exemplos prontos de tudo que pode ser perguntado daria um trabalho imenso e ainda assim teria perguntas novas que os exemplos não cobrem.\n- Trocar o robô por um maior não resolve, porque o problema não é ele ser fraco — é que ele não para pra verificar.\n- Perguntar para o cliente se a resposta está boa é como você perguntar pro seu professor se a sua lição está certa — o trabalho de conferir acaba sendo do professor, não seu. O melhor é o robô já entregar algo bem feito.','\n',char(10)));
INSERT INTO cards VALUES('admin','card_1783092991293_x2uj1w68f',440,'How can you reduce false positives from a detector by clearly defining the target, instead of using examples or filters?',replace('How can you reduce false positives from a detector by clearly defining the target, instead of using examples or filters?\n\nHow can you reduce false positives from a detector by clearly defining the target, instead of using examples or filters?\n[Resposta correta: Critérios explícitos do que constitui um problema generalizam para casos novos. Few-shot só captura padrões parecidos com os mostrados (A), filtros tratam o sintoma sem definir o alvo (B) e reduzir a sensibilidade geral (D) não define o que deve ser sinalizado e pode causar falsos negativos.]\n\n[ ] A - Add more few-shot examples of the cases that produced false positives.\n[ ] B - Apply post-processing filters to remove the unwanted flags.\n[ ] C - Specify explicit criteria for what constitutes a problem, such as flagging a comment only when the claimed behavior contradicts the actual behavior of the code.\n[ ] D - Reduce the detector''s overall sensitivity by flagging fewer things.','\n',char(10)),'C - Specify explicit criteria for what constitutes a problem, such as flagging a comment only when the claimed behavior contradicts the actual behavior of the code.','["Domain_4::Prompt_Engineering_Structured_Output", "Scenario_5::Claude_Code_CI_CD"]','New',0,2.5,0,1783092991293,1783727836185,1783203558653,replace('## Tradução (Português - BR)\n\n**Pergunta:** Como você pode reduzir falsos positivos de um detector definindo claramente o alvo, em vez de usar exemplos ou filtros?\n\n[ ] A - Adicionar mais exemplos few-shot dos casos que produziram falsos positivos.\n[ ] B - Aplicar filtros de pós-processamento para remover as sinalizações indesejadas.\n[ ] C - Especificar critérios explícitos para o que constitui um problema, como sinalizar um comentário apenas quando o comportamento alegado contradiz o comportamento real do código.\n[ ] D - Reduzir a sensibilidade geral do detector, sinalizando menos coisas.','\n',char(10)),replace('## Explicação para um Adulto (Tech Lead)\n\nA pergunta aborda um conceito fundamental em sistemas de detecção e classificação: a diferença entre **definir o alvo de forma explícita e generalizável** versus **abordagens baseadas em exemplos ou heurísticas corretivas**. A resposta correta é a alternativa **C**.\n\n**Por que C está correta:**\n\nDefinir critérios explícitos (regras baseadas em lógica formal) ataca a **causa raiz** do problema de falsos positivos. Critérios como "flaggar um comentário apenas quando o comportamento alegado contradiz o comportamento real do código" estabelecem uma fronteira de decisão que:\n\n- É semanticamente precisa e auditável.\n- Generaliza para casos não vistos durante o desenvolvimento, pois codifica a intenção do detector, não padrões superficiais.\n- Permite debugging e refinamento lógico (se um falso positivo ocorre, ajusta-se a regra, não se adicionam exemplos).\n\n**Por que as demais estão erradas:**\n\n- **A (Adicionar mais exemplos few-shot):** Few-shot learning ou exemplos adicionais apenas expandem o conjunto de padrões que o detector reconhece. Isso pode reduzir falsos positivos nos casos específicos adicionados, mas não resolve a indefinição do alvo. O detector continua inferindo o critério a partir de similaridade superficial com os exemplos, sem compreender a regra subjacente. A generalização permanece frágil.\n\n- **B (Aplicar filtros de pós-processamento):** Filtros tratam o **sintoma** (o falso positivo já ocorreu) sem redefinir o alvo. É uma abordagem reativa e ad hoc. Cada filtro novo pode introduzir novos falsos negativos e o sistema se torna uma pilha de correções, sem uma definição coerente do que deve ou não ser sinalizado.\n\n- **D (Reduzir a sensibilidade geral):** Isso é o oposto de "definir claramente o alvo". Você está tornando o detector mais conservador às cegas, sem critério. Isso reduz falsos positivos às custas de aumentar falsos negativos. É uma solução de força bruta que não resolve o problema de especificação — o detector continua sem saber o que *realmente* importa sinalizar.\n\n**Em resumo:** C é a única alternativa que atende diretamente ao comando "definir claramente o alvo" (clear definition of the target), enquanto as demais são abordagens indiretas, paliativas ou de compromisso.','\n',char(10)),replace('Imagine que você tem um robô que deve avisar quando alguém conta uma mentira sobre o que um programa de computador faz.\n\n**Jeito ruim 1 (Alternativa A):** Você mostra vários exemplos de mentiras para o robô. "Essa aqui é mentira, essa aqui também..." Mas o robô só decora os exemplos que você mostrou. Se aparecer uma mentira diferente, ele pode não perceber.\n\n**Jeito ruim 2 (Alternativa B):** Depois que o robô já avisou errado várias vezes, você coloca filtros para tentar consertar. "Se for isso, não avise". Mas você não está ensinando o robô a pensar, só tapando buracos.\n\n**Jeito ruim 3 (Alternativa D):** Você deixa o robô mais "preguiçoso", avisando menos coisas. Assim ele erra menos, mas também perde muitas mentiras de verdade.\n\n**Jeito certo (Alternativa C - a resposta correta):** Você ensina uma regra clara para o robô: "Só avise se o que a pessoa disse sobre o programa for o contrário do que o programa realmente faz." Agora o robô entende o *critério* e consegue identificar qualquer mentira nova, mesmo que nunca tenha visto aquela mentira antes. É como ensinar a regra do jogo, em vez de mostrar apenas algumas jogadas.','\n',char(10)));
INSERT INTO cards VALUES('admin','card_1783092991352_an0653zrl',441,'A team enables the Pull Request Action in its repository.',replace('A team enables the Pull Request Action in its repository.\n\nA team enables the Pull Request Action in its repository. What behavior is automatically expected on each pull request that is created?\n[Resposta correta: A Pull Request Action revisa as mudanças, analisa o impacto e posta um relatório no PR. Ela não faz merge automático (A), não se limita a rodar testes (C) e publica o retorno no próprio PR, não por email (D).]\n\n[ ] A - Automatically merges the PR if no conflict is detected.\n[ ] B - Reviews the proposed changes, analyzes the impact and posts a detailed report on the PR.\n[ ] C - Only runs the test suite and fails the PR in case of failure.\n[ ] D - Notifies the author by email without publishing anything on the PR itself.','\n',char(10)),'B - Reviews the proposed changes, analyzes the impact and posts a detailed report on the PR.','["Domain_4::Prompt_Engineering_Structured_Output", "Domain_3::Claude_Code_Configuration_Workflows", "Scenario_5::Claude_Code_CI_CD"]','New',0,2.5,0,1783092991352,1783727839647,1783203558653,replace('**Tradução para português do Brasil:**\n\nUma equipe habilita a Pull Request Action em seu repositório. Qual comportamento é automaticamente esperado em cada pull request que é criado?\n\n[ ] A - Faz merge automático do PR se nenhum conflito for detectado.\n[ ] B - Revisa as mudanças propostas, analisa o impacto e publica um relatório detalhado no PR.\n[ ] C - Apenas executa a suíte de testes e reprova o PR em caso de falha.\n[ ] D - Notifica o autor por e-mail sem publicar nada no próprio PR.','\n',char(10)),replace('**Explicação para adulto (tech lead):**\n\nA Pull Request Action é um recurso de automação que visa fornecer *feedback* contextual diretamente no fluxo de revisão. A alternativa **B** está correta porque descreve com precisão o comportamento esperado: a ação analisa as alterações propostas, avalia o impacto (por exemplo, detectando possíveis problemas de segurança, estilo, ou regras de negócio) e então posta um relatório diretamente no PR, onde revisores e autores podem visualizá-lo.\n\nVamos analisar por que as demais alternativas estão incorretas:\n\n- **A (Fazer merge automático):** Embora algumas ferramentas de CI possam realizar merge automático sob certas condições (ex.: GitHub Auto-Merge), esse não é o comportamento padrão ou esperado de uma Pull Request Action. A ação é voltada para análise e revisão, não para conclusão do fluxo. Além disso, um merge automático sem validação humana completa representaria um risco de governança em projetos sérios.\n\n- **C (Apenas executar testes):** Executar a suíte de testes é geralmente responsabilidade de um pipeline de CI/CD separado (ex.: GitHub Actions configurado para testes). A Pull Request Action vai além disso, oferecendo uma análise mais rica (ex.: verificação de boas práticas, análise estática, cobertura de código) e não se limita a "passar/falhar" com base em testes.\n\n- **D (Notificar por e-mail):** Notificações por e-mail podem existir como um canal secundário, mas o comportamento principal e esperado de uma Pull Request Action é fornecer feedback visível e rastreável dentro do próprio PR, no ecossistema onde o time já está colaborando. Publicar apenas por e-mail iria contra o princípio de transparência e rastreabilidade no desenvolvimento moderno.\n\nPortanto, a resposta **B** é a única que descreve o escopo completo e esperado de uma Pull Request Action.','\n',char(10)),replace('**Explicação para uma criança de 10 anos:**\n\nImagina que você e seus amigos estão escrevendo uma história em grupo. Cada um pode sugerir mudanças — isso é um "pull request". A **Pull Request Action** é como um robô assistente que lê as sugestões que você fez, pensa se elas são boas ou podem causar problemas, e depois escreve um bilhete bem explicado dentro do próprio projeto, dizendo o que achou, para que todos vejam.\n\n- A opção **A** (fazer merge automático) seria como se esse robô juntasse sua sugestão na história sem ninguém olhar direito — isso não é seguro!\n- A opção **C** (só rodar testes) seria como se o robô só verificasse se as palavras estão escritas certo, mas não lesse o conteúdo da história.\n- A opção **D** (avisar por e-mail) seria como se o robô mandasse um recado só pra você, escondido, em vez de escrever no mural onde todo mundo pode ver.\n\nA melhor opção é a **B**: o robô lê suas mudanças, pensa no impacto e escreve um relatório bem bonito ali mesmo no projeto, para todos os amigos verem e discutirem.','\n',char(10)));
INSERT INTO cards VALUES('admin','card_1783092991375_a9h2swjsh',442,'When is it preferable to use few-shot examples instead of refining instructions to obtain a consistent output format?',replace('When is it preferable to use few-shot examples instead of refining instructions to obtain a consistent output format?\n\nWhen is it preferable to use few-shot examples instead of refining instructions to obtain a consistent output format?\n[Resposta correta: Few-shot é preferível depois que o refinamento de instruções já falhou, pois 3-4 exemplos do formato exato são seguidos com mais confiabilidade que instruções abstratas. Não é uma escolha automática antes de tentar instruções (A), few-shot aumenta tokens (C) e mais contexto explicativo não corrige variabilidade de formato (D).]\n\n[ ] A - Always, even before trying to refine the instructions.\n[ ] B - When refining the instructions has already failed; 3-4 examples showing the exact format are followed more reliably than abstract instructions.\n[ ] C - When you want to reduce the number of tokens in the prompt.\n[ ] D - When it is enough to add more explanatory context to the prompt.','\n',char(10)),'B - When refining the instructions has already failed; 3-4 examples showing the exact format are followed more reliably than abstract instructions.','["Domain_4::Prompt_Engineering_Structured_Output", "Scenario_6::Structured_Data_Extraction"]','New',0,2.5,0,1783092991375,1783727842622,1783203558653,replace('**Tradução para português do Brasil:**\n\n**Pergunta:** Quando é preferível usar exemplos few-shot em vez de refinar instruções para obter um formato de saída consistente?\n\n[ ] A - Sempre, mesmo antes de tentar refinar as instruções.\n[ ] B - Quando refinar as instruções já falhou; de 3 a 4 exemplos mostrando o formato exato são seguidos com mais confiabilidade do que instruções abstratas.\n[ ] C - Quando você deseja reduzir o número de tokens no prompt.\n[ ] D - Quando é suficiente adicionar mais contexto explicativo ao prompt.','\n',char(10)),replace('**Explicação para um adulto tech lead:**\n\nA alternativa B está correta. Few-shot learning (fornecer poucos exemplos no prompt) é uma técnica poderosa, mas tem um custo em tokens e complexidade. A abordagem mais enxuta e eficiente é sempre começar refinando as instruções textuais (zero-shot), pois isso não consome tokens extras com exemplos e geralmente é suficiente para modelos de linguagem modernos.\n\n- **A está errada** porque few-shot não deve ser a primeira escolha. Instruções bem escritas (zero-shot) são mais econômicas e frequentemente suficientes. Few-shot só se justifica quando as instruções falham consistentemente.\n\n- **B está correta** porque few-shot é uma técnica de "último recurso" quando instruções abstratas não produzem o formato desejado. Modelos de linguagem são muito bons em imitar padrões explícitos — 3 a 4 exemplos concretos do formato exato de saída têm mais poder de "fixar" o comportamento do que descrições abstratas como "responda no formato JSON com campos X, Y, Z".\n\n- **C está errada** porque few-shot aumenta o consumo de tokens — cada exemplo adiciona tokens ao prompt. Se o objetivo é reduzir tokens, a escolha é zero-shot com instruções enxutas, não few-shot.\n\n- **D está errada** porque adicionar mais contexto explicativo é justamente refinar as instruções (abordagem zero-shot), não few-shot. O problema apontado é que contexto explicativo adicional nem sempre resolve variabilidade de formato — o modelo pode interpretar mal instruções longas ou abstratas, enquanto exemplos concretos são mais determinísticos.','\n',char(10)),replace('**Explicação para uma criança de 10 anos:**\n\nImagine que você está ensinando um robô a desenhar casas. Você pode tentar explicar com palavras: "Desenhe um quadrado com um triângulo em cima". Mas às vezes o robô faz um círculo com um triângulo do lado — não entendeu direito.\n\nAgora, se você mostrar 3 ou 4 desenhos de casas prontos e disser "faz igual a esses", o robô copia direitinho!\n\nMas mostrar desenhos extras gasta mais papel (no computador, gasta mais "tokens"). Então, primeiro você tenta só com palavras. Se não funcionar, aí você mostra os exemplos. É por isso que a resposta B é a certa: usar exemplos só depois que tentar explicar com palavras já falhou!','\n',char(10)));
INSERT INTO cards VALUES('admin','card_1783092991397_jv1lb9ny0',443,'Claude changes the signature of a function but leaves call sites outdated, producing type errors.',replace('Claude changes the signature of a function but leaves call sites outdated, producing type errors.\n\nClaude changes the signature of a function but leaves call sites outdated, producing type errors. Which configuration fixes this immediately?\n[Resposta correta: O padrão é um PostToolUse hook rodando o type checker (ex: tsc --noEmit) após cada edição e devolvendo os erros ao Claude na hora. PreToolUse (A) roda antes da edição e não vê o resultado; rodar só no fim (C) perde o feedback imediato; reverter (D) não corrige os outros arquivos.]\n\n[ ] A - A PreToolUse hook that blocks the edit before it happens.\n[ ] B - A PostToolUse hook that runs the type checker after each edit, captures the errors and returns them to Claude to fix.\n[ ] C - A hook that runs the type checker only at the end of the session, aggregating all the errors.\n[ ] D - A hook that automatically reverts any edit with a type error.','\n',char(10)),'B - A PostToolUse hook that runs the type checker after each edit, captures the errors and returns them to Claude to fix.','["Domain_3::Claude_Code_Configuration_Workflows", "Domain_4::Prompt_Engineering_Structured_Output", "Domain_5::Context_Management_Reliability", "Scenario_2::Code_Generation_Claude_Code"]','New',0,2.5,0,1783092991397,1783727846184,1783203558653,replace('TRADUÇÃO:\n\nClaude altera a assinatura de uma função, mas deixa os locais de chamada desatualizados, gerando erros de tipo. Qual configuração corrige isso imediatamente?\n\n[ ] A - Um hook PreToolUse que bloqueia a edição antes que ela aconteça.\n[ ] B - Um hook PostToolUse que executa o type checker após cada edição, captura os erros e os devolve para Claude corrigir.\n[ ] C - Um hook que executa o type checker apenas no final da sessão, agregando todos os erros.\n[ ] D - Um hook que reverte automaticamente qualquer edição com erro de tipo.','\n',char(10)),replace('EXPLICAÇÃO PARA TECH LEAD:\n\nA resposta correta é a alternativa B.\n\nO problema descrito é um cenário clássico de edição incoerente: Claude modifica a assinatura de uma função mas não atualiza os pontos de chamada (call sites), resultando em type errors. A configuração que resolve isso imediatamente precisa detectar o erro logo após a edição e dar feedback para que Claude corrija os arquivos afetados.\n\nPor que a B é a resposta correta:\n- Um hook PostToolUse (executado após o uso da ferramenta de edição) que roda o type checker (ex: tsc --noEmit) captura os erros de tipo imediatamente após a edição.\n- Os erros capturados são retornados a Claude, que pode então usar essas informações para corrigir os call sites desatualizados — seja na mesma chamada ou na iteração seguinte.\n- Isso estabelece um ciclo rápido de "editar → verificar → corrigir", que é exatamente o que se precisa para manter a coerência do código.\n\nPor que as demais alternativas estão erradas:\n- A (PreToolUse): roda antes da edição, então não consegue detectar os erros gerados pela mudança de assinatura, pois a mudança ainda não ocorreu.\n- C (type checker apenas no final): o feedback é tardio — os erros só são descobertos no fim da sessão, perdendo a chance de correção imediata e iterativa.\n- D (reverter automaticamente): além de ser uma abordagem destrutiva (descarta a edição inteira em vez de corrigir os call sites), não ensina Claude a consertar os outros arquivos; a função continuaria com a assinatura antiga.','\n',char(10)),replace('EXPLICAÇÃO PARA CRIANÇA DE 10 ANOS:\n\nImagine que você está arrumando seu quarto. Você decide mudar a estante de lugar (é a "assinatura da função"). Mas esqueceu de mover os brinquedos que estavam nela para o novo lugar (são os "call sites desatualizados"). Agora tudo está bagunçado!\n\nA pergunta quer saber qual é a melhor forma de consertar isso na hora.\n\n- Alternativa A: seria como verificar se a estante está no lugar certo ANTES de mudá-la. Não faz sentido, né? O erro acontece depois da mudança.\n- Alternativa B (correta!): é como pedir para alguém olhar o quarto logo depois que você moveu a estante e gritar: "Ei, os brinquedos estão no chão, coloca eles na estante nova!" Assim você arruma na hora.\n- Alternativa C: seria esperar o dia inteiro para arrumar a bagunça só no final. Aí o quarto fica bagunçado o dia todo!\n- Alternativa D: seria simplesmente devolver a estante para o lugar antigo em vez de arrumar os brinquedos. Isso não resolve o problema de verdade — você desiste da mudança em vez de aprender a fazer direito.\n\nA melhor ideia é a B: depois de fazer a mudança, verificar se deu tudo certo e, se algo estiver errado, corrigir na hora!','\n',char(10)));
INSERT INTO cards VALUES('admin','card_1783092991419_gtewc9vcx',444,'In a project using an untyped language, you want the same benefit as the type checking hook.',replace('In a project using an untyped language, you want the same benefit as the type checking hook.\n\nIn a project using an untyped language, you want the same benefit as the type checking hook. What is the equivalent approach?\n[Resposta correta: Sem compilador ou type checker, o equivalente é usar testes automatizados para capturar regressões e devolver o feedback ao Claude. Forçar tipos estáticos (B) foge da linguagem escolhida; desativar hooks (C) abre mão do benefício; um linter de estilo (D) verifica formatação, não a correção funcional que os testes cobrem.]\n\n[ ] A - Implement similar functionality using automated tests in place of the type checker.\n[ ] B - Force the adoption of static type annotations in the untyped language.\n[ ] C - Disable hooks, since type checking does not apply to untyped languages.\n[ ] D - Run a style linter as a direct replacement for the type checker.','\n',char(10)),'A - Implement similar functionality using automated tests in place of the type checker.','["Domain_4::Prompt_Engineering_Structured_Output", "Domain_5::Context_Management_Reliability", "Scenario_5::Claude_Code_CI_CD"]','New',0,2.5,0,1783092991419,1783727849447,1783203558653,replace('**Tradução para português do Brasil:**\n\nEm um projeto usando uma linguagem não tipada, você deseja obter o mesmo benefício do hook de type checking.\n\nQual é a abordagem equivalente?\n\n[ ] A - Implementar funcionalidade similar usando testes automatizados no lugar do type checker.\n[ ] B - Forçar a adoção de anotações de tipo estáticas na linguagem não tipada.\n[ ] C - Desabilitar hooks, já que type checking não se aplica a linguagens não tipadas.\n[ ] D - Executar um linter de estilo como substituto direto do type checker.','\n',char(10)),replace('**Explicação para adulto (tech lead):**\n\nA alternativa **A** é a correta. Em linguagens não tipadas (ex.: JavaScript puro, Python sem type hints, Ruby, PHP), não há um compilador ou type checker para capturar erros de tipo e inconsistências de interface em tempo de desenvolvimento. O hook de type checking, presente em linguagens tipadas (ex.: TypeScript, Java, Rust), atua como uma barreira de segurança que previne que código com violações de tipo seja commitado.\n\nA abordagem equivalente mais pragmática é usar **testes automatizados** (unitários, de integração, funcionais) como substituto funcional. Os testes verificam comportamentos esperados, detectam regressões e validam contratos entre componentes — funções análogas à verificação de tipos, mas em tempo de execução. Além disso, podem ser integrados como hooks de pré-commit ou pré-push, devolvendo feedback rápido ao desenvolvedor (ex.: Claude, ou qualquer outro agente/desenvolvedor).\n\n**Por que as outras alternativas estão erradas:**\n\n- **B** - Forçar anotações de tipo estáticas em uma linguagem que não as suporta nativamente (ou as ignora em runtime) é contornar a decisão de projeto. Mesmo que Python aceite type hints, eles não são verificados em runtime sem ferramentas externas (mypy, Pyright). Isso muda a dinâmica da stack e pode não ser viável em projetos legados ou equipes que deliberadamente escolheram uma linguagem dinâmica.\n\n- **C** - Desabilitar hooks simplesmente remove qualquer verificação automatizada, o oposto do objetivo. O benefício do type checking é justamente ter uma camada de segurança; desabilitá-la deixa o projeto vulnerável a erros que poderiam ser capturados precocemente.\n\n- **D** - Linters de estilo (ESLint, RuboCop, etc.) verificam problemas de formatação, convenções de código, possíveis bugs sintáticos e más práticas, mas **não** verificam correção funcional, contratos de interface ou tipos de dados. São complementares, não substitutos diretos de type checking.','\n',char(10)),replace('Imagine que você está montando um quebra-cabeça. Em algumas linguagens de programação, existe um "fiscal" que confere se cada peça se encaixa direitinho antes de você colocar no lugar. Esse fiscal é o **type checker**.\n\nAgora, se você está usando uma linguagem que **não tem** esse fiscal (uma linguagem "não tipada"), você precisa de outra forma de garantir que as peças se encaixam. A melhor maneira é **testar** o quebra-cabeça: você monta, dá uma olhada geral, mexe nas peças e vê se está tudo certinho. Isso é o **teste automatizado**.\n\n- A opção **A** é a certa: criar testes no lugar do fiscal.\n- A opção **B** seria forçar um fiscal onde ele não existe — é como tentar usar uma régua para medir algo que não tem medida certa.\n- A opção **C** é desistir e não verificar nada — aí o quebra-cabeça pode ficar todo errado.\n- A opção **D** é verificar só a cor das peças, e não se elas encaixam direito. Ajuda, mas não resolve o problema principal.','\n',char(10)));
INSERT INTO cards VALUES('admin','card_1783092991442_5i5dzrbjq',445,'When adopting a hook that launches a separate instance of Claude for review, what are the trade-offs and the recommendation?',replace('When adopting a hook that launches a separate instance of Claude for review, what are the trade-offs and the recommendation?\n\nWhen adopting a hook that launches a separate instance of Claude for review, what are the trade-offs and the recommendation?\n[Resposta correta: O benefício é codebase mais limpo com menos duplicação, e o custo é tempo e uso de API extras por edição, mitigado ao monitorar somente diretórios críticos. A instância separada consome API adicional (contra B e D), e o objetivo é mais qualidade e menos duplicação, não velocidade (C).]\n\n[ ] A - Benefit of a cleaner codebase, with the cost of extra time and API, recommending monitoring only critical directories.\n[ ] B - No relevant cost, since the extra instance reuses the same API session.\n[ ] C - Benefit of speed, with the cost of lower quality due to automatic review.\n[ ] D - Cost only of storage, with no impact on time or API calls.','\n',char(10)),'A - Benefit of a cleaner codebase, with the cost of extra time and API, recommending monitoring only critical directories.','["Domain_3::Claude_Code_Configuration_Workflows", "Domain_5::Context_Management_Reliability", "Scenario_2::Code_Generation_Claude_Code"]','New',0,2.5,0,1783092991442,1783727852805,1783203558653,replace('**Tradução para Português do Brasil:**\n\n**Pergunta:** Ao adotar um hook que lança uma instância separada do Claude para revisão, quais são os trade-offs e a recomendação?\n\n[ ] A - Benefício de um codebase mais limpo, com o custo de tempo extra e uso de API, recomendando monitorar apenas diretórios críticos.\n[ ] B - Nenhum custo relevante, já que a instância extra reutiliza a mesma sessão de API.\n[ ] C - Benefício de velocidade, com o custo de qualidade inferior devido à revisão automática.\n[ ] D - Custo apenas de armazenamento, sem impacto no tempo ou chamadas de API.','\n',char(10)),replace('**Explicação Didática para Adulto (Tech Lead):**\n\n**Resposta Correta: A**\n\n**Por que A está correta:**\nAo adotar um hook que dispara uma instância separada do Claude para revisar código (por exemplo, em um pipeline de CI/CD ou em um git hook como pre-commit), o principal benefício é a qualidade do código resultante. Uma instância dedicada de revisão pode analisar o código de forma independente, sugerir refatorações, detectar duplicações e inconsistências que um desenvolvedor humano ou uma revisão superficial poderiam perder. O custo é real: cada revisão consome tokens de API (custo financeiro) e adiciona latência ao fluxo de trabalho (tempo extra por commit/push). A recomendação prática de monitorar apenas diretórios críticos é sensata — você concentra o recurso onde ele agrega mais valor (ex: diretórios de lógica de negócio core) e evita sobrecarregar diretórios de baixo risco (ex: assets, configs, testes gerados).\n\n**Por que B está errada:**\nA afirmação de que "não há custo relevante porque a instância extra reutiliza a mesma sessão de API" é tecnicamente incorreta. Cada chamada de API ao Claude — mesmo que na mesma sessão ou contexto — consome tokens de entrada e saída, que são cobrados por uso. Além disso, o hook lança uma *nova* instância (um novo contexto de conversa), o que implica em custo de API completo, não reutilização de sessão anterior. Não existe o conceito de "sessão compartilhada gratuita" entre instâncias separadas.\n\n**Por que C está errada:**\nO benefício não é velocidade. Na verdade, adicionar uma etapa de revisão por IA *aumenta* o tempo total do ciclo (é um custo, não um benefício). Quanto à qualidade, a premissa de que revisão automática gera "qualidade inferior" contradiz o propósito do hook. Embora revisões automáticas possam ter falsos positivos ou sugestões imperfeitas, o objetivo é justamente melhorar a qualidade, não reduzi-la. Esta alternativa inverte os trade-offs.\n\n**Por que D está errada:**\nO custo não é "apenas de armazenamento". Revisões por IA envolvem processamento computacional e chamadas de API, que têm custo financeiro e de tempo (latência). Armazenamento é irrelevante aqui, a menos que você esteja persistindo logs de revisão, mas mesmo assim o custo principal não é de armazenamento.','\n',char(10)),replace('**Explicação para uma criança de 10 anos:**\n\nImagina que você escreveu uma redação na escola e, antes de entregar, pede para um amigo muito inteligente ler e dar sugestões para melhorar. Esse amigo é o Claude.\n\nA alternativa **A** diz o seguinte: pedir ajuda do amigo (Claude) deixa seu texto mais bonito e sem erros (codebase mais limpo), mas isso gasta tempo e energia do amigo (custa dinheiro de API). A dica é: só peça ajuda para as partes mais importantes do texto (diretórios críticos), não para tudo. Isso é o mais sensato!\n\nA **B** está errada porque acha que o amigo não gasta energia para ajudar — mas ele sempre gasta, sim.\n\nA **C** está errada porque diz que você termina mais rápido (velocidade), mas na verdade pedir ajuda demora mais. E também diz que a qualidade fica pior, sendo que o objetivo é justamente melhorar.\n\nA **D** está errada porque acha que o único gasto é guardar o papel (armazenamento), mas o gasto mesmo é o esforço do amigo (tempo e dinheiro de API).\n\n**Resumo:** A alternativa **A** é a correta porque descreve direitinho o que acontece: seu código fica mais limpo, mas gasta tempo e dinheiro, então é melhor usar a revisão só no que é mais importante.','\n',char(10)));
INSERT INTO cards VALUES('admin','card_1783092991465_zc8aw9aqv',446,'In a large project, Claude creates duplicate queries instead of reusing the existing ones.',replace('In a large project, Claude creates duplicate queries instead of reusing the existing ones.\n\nIn a large project, Claude creates duplicate queries instead of reusing the existing ones. Which hook pattern mitigates this?\n[Resposta correta: O padrão lança uma segunda instância do Claude Code (via Agent SDK) para revisar as mudanças, detectar queries similares e dar feedback para remover a duplicata. Matching por regex (A) é frágil e não entende similaridade semântica; apagar tudo (C) é destrutivo; despejar o diretório inteiro no contexto (D) não é o mecanismo descrito e não gera o feedback de revisão.]\n\n[ ] A - A hook that does pattern matching by regex on query names to block duplicates.\n[ ] B - A hook that, when modifying files in ./queries, launches a second instance of Claude Code to review the changes and detect similar queries.\n[ ] C - A hook that automatically deletes any new query added in ./queries.\n[ ] D - A hook that includes the entire ./queries directory in the context of each edit.','\n',char(10)),'B - A hook that, when modifying files in ./queries, launches a second instance of Claude Code to review the changes and detect similar queries.','["Domain_3::Claude_Code_Configuration_Workflows", "Domain_4::Prompt_Engineering_Structured_Output", "Scenario_2::Code_Generation_Claude_Code"]','New',0,2.5,0,1783092991465,1783727856443,1783203558653,replace('**Tradução para Português do Brasil:**\n\nPERGUNTA: Em um projeto grande, o Claude cria queries duplicadas em vez de reutilizar as existentes. Qual padrão de hook mitiga esse problema?\n\n[ ] A - Um hook que faz correspondência de padrões por regex nos nomes das queries para bloquear duplicatas.\n[ ] B - Um hook que, ao modificar arquivos em ./queries, lança uma segunda instância do Claude Code para revisar as alterações e detectar queries similares.\n[ ] C - Um hook que automaticamente deleta qualquer nova query adicionada em ./queries.\n[ ] D - Um hook que inclui o diretório inteiro ./queries no contexto de cada edição.','\n',char(10)),replace('**Explicação para Adulto (Tech Lead):**\n\nO problema central é a **duplicação de queries** em um projeto grande. Isso ocorre tipicamente porque o Claude (ou o desenvolvedor) não tem visibilidade completa do que já existe no repositório de queries e, em vez de reutilizar, cria algo novo, gerando inconsistência e débito técnico.\n\n**Resposta correta: Alternativa B**\n\nO padrão descrito em B é o mais robusto porque:\n1. **Utiliza uma segunda instância do Claude Code (via Agent SDK)** para atuar como um "revisor" das mudanças. Essa abordagem tira proveito da capacidade do modelo de entender **similaridade semântica** entre queries — algo que vai muito além de simples correspondência textual.\n2. O hook é acionado **no momento da modificação** (quando arquivos em ./queries são alterados), o que é um ponto de intervenção ideal: não antes (que impediria a criação), nem depois (quando o dano já estaria consolidado).\n3. O feedback gerado é **revisão e recomendação** — ou seja, o hook atua de forma inteligente, sugerindo a remoção da duplicata em vez de simplesmente bloqueá-la ou destruí-la. Isso é colaborativo e preserva a produtividade.\n\n**Por que as demais estão erradas:**\n\n- **Alternativa A (regex):** Correspondência por regex em nomes de queries é frágil porque (a) nomes podem ser diferentes mesmo que as queries sejam semanticamente idênticas, e (b) regex não entende similaridade semântica — duas queries podem fazer a mesma coisa com nomes completamente diferentes. Além disso, "bloquear" é uma abordagem punitiva, não pedagógica.\n\n- **Alternativa C (deletar automaticamente):** É uma abordagem excessivamente agressiva e destrutiva. Deletar automaticamente qualquer nova query adicionada impede o trabalho legítimo de criação. Pode haver casos em que uma nova query é realmente necessária (ex.: requisitos que mudaram). Não há inteligência na decisão.\n\n- **Alternativa D (incluir diretório inteiro no contexto):** Embora incluir o diretório ./queries no contexto possa ajudar a evitar duplicação ao dar mais visibilidade ao modelo, isso não é um "mecanismo de revisão" nem gera feedback. É apenas uma estratégia de engenharia de prompt que pode ajudar a reduzir o problema, mas não o resolve de forma confiável. Além disso, em projetos grandes, incluir todo o diretório no contexto pode estourar limites de tokens e degradar a performance.','\n',char(10)),replace('Imagine que você tem uma caixa de blocos de montar. Você já tem um bloco azul que encaixa perfeitamente no que você quer fazer, mas às vezes você esquece e pega um bloco novo igualzinho, criando bagunça.\n\nA pergunta é: o que fazer para não criar blocos repetidos?\n\n- Se a gente tentasse adivinhar só pelo nome do bloco (alternativa A), poderia errar — dois blocos com nomes diferentes podem servir para a mesma coisa!\n- Se a gente simplesmente jogasse fora todo bloco novo (alternativa C), a gente nunca poderia criar nada novo, mesmo quando precisasse.\n- Se a gente colocasse a caixa inteira de blocos na mesa (alternativa D), ajudaria um pouco, mas não teria ninguém para nos avisar quando estamos pegando um repetido.\n\nA melhor ideia (alternativa B) é: quando alguém colocar um bloco novo na caixa, chamar um amigo esperto para dar uma olhada. Esse amigo compara o bloco novo com todos os outros que já estão na caixa. Se ele perceber que o bloco novo é igual a um que já existe, ele avisa: "Ei, você já tem um bloco assim! Que tal usar aquele em vez de criar outro?" Isso resolve o problema sem estragar nada e ainda ensina a não repetir.','\n',char(10)));
INSERT INTO cards VALUES('admin','card_1783092991487_0bmy68ruk',447,'You want automatic AI review but need to control cost and latency.',replace('You want automatic AI review but need to control cost and latency.\n\nYou want automatic AI review but need to control cost and latency. Where should you apply the separate instance hook?\n[Resposta correta: Para controlar custo e latência, aplica-se o hook apenas em diretórios de alto valor onde a consistência importa (ex: ./queries). Monitorar o projeto inteiro (A) maximiza o overhead; restringir a config e docs (C) ignora o código crítico onde a duplicação ocorre; amostragem aleatória (D) não garante cobertura dos pontos importantes.]\n\n[ ] A - On the entire project, to ensure maximum coverage.\n[ ] B - Only in high-value directories where consistency matters, such as ./queries.\n[ ] C - Only in configuration and documentation files.\n[ ] D - Randomly on part of the files, to sample the changes.','\n',char(10)),'B - Only in high-value directories where consistency matters, such as ./queries.','["Domain_3::Claude_Code_Configuration_Workflows", "Domain_5::Context_Management_Reliability", "Scenario_5::Claude_Code_CI_CD"]','New',0,2.5,0,1783092991487,1783727859860,1783203558653,replace('**Tradução para português do Brasil:**\n\nVocê deseja revisão automática de IA, mas precisa controlar custo e latência.\n\nOnde você deve aplicar o hook de instância separada?\n\n[ ] A - Em todo o projeto, para garantir a cobertura máxima.\n[ ] B - Apenas em diretórios de alto valor onde a consistência é importante, como ./queries.\n[ ] C - Apenas em arquivos de configuração e documentação.\n[ ] D - Aleatoriamente em parte dos arquivos, para amostrar as alterações.','\n',char(10)),replace('**Explicação Técnica (para um tech lead):**\n\n**Resposta correta: B**\n\nA questão aborda um problema clássico de engenharia de plataforma: otimizar o trade-off entre qualidade (revisão automática) e recursos computacionais (custo e latência). O "separate instance hook" aqui se refere a um ponto de extensão onde uma instância de serviço de IA é disparada para revisar mudanças.\n\n**Análise detalhada:**\n\n**Alternativa B (correta):** Aplicar o hook seletivamente em diretórios de alto valor — como `./queries`, que tipicamente contém lógica de consulta a banco de dados, onde inconsistências e duplicações causam impacto significativo em produção — é a abordagem mais eficiente. Você concentra o recurso computacional onde o retorno sobre o investimento (ROI) é maior. Isso mantém a latência baixa (menos chamadas de IA) e o custo controlado (menos tokens processados), sem abrir mão da revisão nos pontos críticos.\n\n**Alternativa A (errada):** Aplicar o hook em todo o projeto maximiza a cobertura, mas também maximiza o overhead. Cada commit ou PR dispararia uma chamada de IA para cada arquivo alterado, independentemente da criticidade. Isso aumenta tanto custo (consumo de tokens) quanto latência (tempo de espera pela revisão completa), contrariando diretamente o requisito de controlar ambos.\n\n**Alternativa C (errada):** Restringir o hook apenas a arquivos de configuração e documentação ignora completamente o código-fonte — justamente onde a duplicação lógica e inconsistências algorítmicas mais ocorrem. É um falso positivo de economia: você gasta pouco, mas também revisa pouco, anulando o propósito da revisão automática de IA.\n\n**Alternativa D (errada):** Amostragem aleatória introduz imprevisibilidade. Você nunca garante que os arquivos críticos (como `./queries`) serão revisados. Além disso, a ausência de consistência na cobertura torna impossível estabelecer uma linha de base de qualidade. É uma estratégia estatisticamente frágil e não atende a requisitos de governança de código.','\n',char(10)),replace('Imagine que você tem uma professora de IA que pode revisar seu dever de casa para ver se está tudo certinho. Mas chamar a professora toda hora custa dinheiro e demora.\n\nA pergunta é: onde você coloca a "campainha" que chama a professora?\n\n- Se você chamar a professora para VER TUDO (alternativa A), ela vai cansar, gastar muito dinheiro e demorar horrores.\n- Se você chamar só para ver os arquivos de CONFIGURAÇÃO e INSTRUÇÕES (alternativa C), ela vai ignorar o mais importante: o código em si, onde estão os erros de verdade.\n- Se você chamar ALEATORIAMENTE (alternativa D), é como jogar dados: às vezes ela revisa o arquivo mais importante, às vezes não. Não dá para confiar.\n- Agora, se você chamar a professora só para revisar as PARTES MAIS IMPORTANTES, como a pasta `./queries` (alternativa B), que tem as perguntas que o sistema faz ao banco de dados, você gasta pouco dinheiro, não demora muito e ainda garante que o que é crítico está certo.\n\nÉ como escolher: melhor revisar a redação que vale nota 10 do que gastar tempo revisando a lista de material escolar. A alternativa B é a mais esperta!','\n',char(10)));
INSERT INTO cards VALUES('admin','card_1783092991510_gksmfoyzg',448,'You need to enforce standards in delegated work without relying on prompts, with separate frontend and backend reviewers.',replace('You need to enforce standards in delegated work without relying on prompts, with separate frontend and backend reviewers.\n\nYou need to enforce standards in delegated work without relying on prompts, with separate frontend and backend reviewers. Which pattern meets this need?\n[Resposta correta: O padrão usa subagents customizados distintos, cada um com suas próprias skills no frontmatter (reviewer frontend vs backend), garantindo isolamento e expertise específica. Um subagent genérico (A) ou um prompt longo (D) dependem de prompts, exatamente o que se quer evitar; um hook (C) não fornece o isolamento por expertise dos subagents.]\n\n[ ] A - A single generic subagent that receives instructions for frontend and backend in the prompt.\n[ ] B - Distinct custom subagents, each with its own skills in the skills field of the frontmatter.\n[ ] C - A shared PostToolUse hook that decides the type of review at runtime.\n[ ] D - A long system prompt that describes all the frontend and backend rules.','\n',char(10)),'B - Distinct custom subagents, each with its own skills in the skills field of the frontmatter.','["Domain_1::Agentic_Architecture_Orchestration", "Domain_2::Tool_Design_MCP_Integration", "Scenario_3::Multi_Agent_Research"]','New',0,2.5,0,1783092991510,1783727863190,1783203558653,replace('**Tradução para português do Brasil:**\n\nVocê precisa aplicar padrões em trabalho delegado sem depender de prompts, com revisores separados de frontend e backend. Qual padrão atende a essa necessidade?\n\n[ ] A - Um único subagente genérico que recebe instruções para frontend e backend no prompt.\n[ ] B - Subagentes customizados distintos, cada um com suas próprias habilidades no campo "skills" do frontmatter.\n[ ] C - Um hook PostToolUse compartilhado que decide o tipo de revisão em tempo de execução.\n[ ] D - Um prompt de sistema longo que descreve todas as regras de frontend e backend.','\n',char(10)),replace('**Explicação para um adulto tech lead:**\n\nO requisito central é claro: aplicar padrões em trabalho delegado **sem depender de prompts**, com **revisores separados** (frontend e backend). Vamos analisar cada alternativa:\n\n**Alternativa A (incorreta):** Um único subagente genérico que recebe instruções no prompt. Isso viola frontalmente o requisito "sem depender de prompts", pois toda a lógica de diferenciação entre frontend e backend estaria no prompt. Além disso, um único agente não oferece isolamento de responsabilidades — ele precisaria decidir o que revisar baseado em instruções textuais, o que é frágil e não escalável.\n\n**Alternativa B (correta):** Subagentes customizados distintos, cada um com suas próprias skills declaradas no frontmatter. Este padrão atende perfeitamente: não depende de prompts (as skills são declarativas, no frontmatter/YAML), oferece isolamento total (cada subagente é especialista em seu domínio), e separa claramente as responsabilidades (frontend reviewer vs backend reviewer). É a abordagem mais modular, testável e aderente ao princípio da separação de preocupações.\n\n**Alternativa C (incorreta):** Um hook PostToolUse compartilhado. Hooks são mecanismos de middleware que executam lógica em momentos específicos do ciclo de vida de um agente. Embora úteis para cross-cutting concerns, um hook compartilhado não fornece o isolamento por expertise que a questão exige. Você ainda precisaria de lógica condicional (provavelmente baseada em prompts ou regras implícitas) para decidir qual tipo de revisão aplicar, além de não haver separação clara entre revisores.\n\n**Alternativa D (incorreta):** Um prompt de sistema longo que descreve todas as regras. Novamente, viola o requisito "sem depender de prompts". Um prompt monolítico para todas as regras de frontend e backend é difícil de manter, propenso a conflitos de instruções e não oferece isolamento — um único agente tentaria aplicar tudo, gerando confusão e potencialmente misturando padrões de frontend com backend.\n\n**Conclusão:** A alternativa B é a única que resolve o problema sem usar prompts, com isolamento real entre os revisores, cada um especializado em seu domínio através de skills declarativas no frontmatter.','\n',char(10)),replace('Imagine que você tem um trabalho em grupo na escola. Você precisa que duas pessoas revisem o trabalho: uma para verificar se os desenhos estão bonitos (frontend) e outra para verificar se as contas de matemática estão certas (backend).\n\nAgora, você não quer dar instruções escritas para eles (sem prompts). Você quer que cada um já saiba o que fazer por si mesmo.\n\n**Opção A:** Ter uma única pessoa que faz tudo, mas você precisa dar instruções no papel para ela saber o que fazer. Isso não funciona porque você não quer depender de instruções escritas.\n\n**Opção B (a certa!):** Ter duas pessoas diferentes: uma que é especialista em desenhos e outra que é especialista em matemática. Cada uma já tem suas habilidades próprias (skills) e sabe exatamente o que fazer sem precisar de instruções. É como ter um amigo que adora desenhar e outro que é craque em contas — cada um já sabe sua parte!\n\n**Opção C:** Usar um "supervisor" que decide na hora quem vai revisar o quê. Mas esse supervisor precisaria de instruções para decidir, e você quer evitar isso.\n\n**Opção D:** Escrever um manual gigante com todas as regras de desenhos e de matemática para uma única pessoa seguir. Mas aí você está dependendo de instruções escritas (prompts), o que você não quer.\n\nEntão a escolha B é a melhor porque cada revisor já nasce sabendo sua especialidade, sem precisar de instruções extras!','\n',char(10)));
INSERT INTO cards VALUES('admin','card_1783092991533_27d7vvbk4',449,'What is the main value of sharing a PR review skill through a repository, beyond individual use?',replace('What is the main value of sharing a PR review skill through a repository, beyond individual use?\n\nWhat is the main value of sharing a PR review skill through a repository, beyond individual use?\n[Resposta correta: Compartilhar a skill via repositório padroniza o code review em todo o time e cria uma experiência consistente na organização, não só para quem a criou. Não se trata de cache ou custo de API (A), não elimina configuração de hooks (C) e o objetivo é justamente ampliar o uso além do autor, não restringir a ele (D).]\n\n[ ] A - Reduces the API cost per review by reusing cache across users.\n[ ] B - Standardizes code review across the whole team and creates a consistent experience in the organization.\n[ ] C - Eliminates the need for any hook configuration in the repository.\n[ ] D - Ensures that only the skill author keeps control over the reviews.','\n',char(10)),'[ ] B - Standardizes code review across the whole team and creates a consistent experience in the organization.','["Domain_3::Claude_Code_Configuration_Workflows", "Domain_4::Prompt_Engineering_Structured_Output", "Scenario_5::Claude_Code_CI_CD"]','New',0,2.5,0,1783092991533,1783727866399,1783203558653,replace('**Tradução para português do Brasil:**\n\n**Pergunta:** Qual é o principal valor de compartilhar uma habilidade (skill) de revisão de PR através de um repositório, além do uso individual?\n\n**Alternativas:**\n[ ] A - Reduz o custo de API por revisão ao reutilizar cache entre usuários.\n[ ] B - Padroniza a revisão de código em todo o time e cria uma experiência consistente na organização.\n[ ] C - Elimina a necessidade de qualquer configuração de hook no repositório.\n[ ] D - Garante que apenas o autor da skill mantenha o controle sobre as revisões.','\n',char(10)),replace('**Explicação para um adulto (tech lead):**\n\nA alternativa **B** é a correta. O valor central de compartilhar uma skill de code review via repositório é promover a **padronização e consistência** em todo o time. Quando uma skill é compartilhada através de um repositório (como um repositório de ações ou workflows compartilhados no GitHub), todos os membros da equipe podem utilizar as mesmas regras, heurísticas e automações de revisão. Isso elimina a variabilidade de critérios entre revisores, reduz ruídos em PRs, acelera o onboarding de novos desenvolvedores e garante que a qualidade do código seja avaliada sob os mesmos padrões organizacionais.\n\n**Análise das alternativas incorretas:**\n\n- **A:** O compartilhamento de skill não tem como objetivo principal reduzir custos de API via cache. Embora possa haver ganhos indiretos de desempenho, esse não é o propósito fundamental. A afirmativa confunde mecanismo com valor de negócio.\n\n- **C:** Compartilhar uma skill não elimina a necessidade de configuração de hooks no repositório. Hooks (como pre-commit) são configurações locais/de repositório que podem coexistir com skills compartilhadas, mas uma coisa não substitui a outra.\n\n- **D:** Essa alternativa contradiz o próprio conceito de compartilhamento. Se o objetivo é "compartilhar", não faz sentido restringir o uso ao autor. A proposta de uma skill via repositório é justamente ampliar o alcance e permitir que outros colaborem e usem a skill, não centralizar o controle.','\n',char(10)),replace('Imagine que você e seus amigos estão jogando um jogo de tabuleiro, mas cada um tem uma regra diferente para contar os pontos. Um acha que vale 10, outro acha que vale 5, e ninguém se entende. Agora, se vocês colocarem as regras em um papel que todos podem ver e seguir, todo mundo vai contar os pontos do mesmo jeito — fica mais justo e ninguém briga.\n\nA skill de revisão de PR é como esse papel de regras. Quando você compartilha ela em um repositório (que é tipo uma pasta do projeto), todo o time passa a revisar o código do mesmo jeito. Isso é bom porque:\n- Todo mundo sabe o que procurar.\n- Ninguém faz "do jeito dele".\n- O trabalho fica mais organizado.\n\nAs outras opções estão erradas porque:\n- **A** fala de economia de dinheiro (cache), mas não é essa a ideia principal.\n- **C** diz que você não precisa mais configurar hooks (pequenos programas que rodam antes de salvar), mas isso ainda pode ser necessário.\n- **D** diz que só o criador da skill pode usar, mas compartilhar é justamente para que todos possam usar!','\n',char(10)));
INSERT INTO cards VALUES('admin','card_1783092991557_sueof7ryt',450,'A developer defines a tool passing only name and description, but Claude cannot assemble the arguments correctly.',replace('A developer defines a tool passing only name and description, but Claude cannot assemble the arguments correctly.\n\nA developer defines a tool passing only name and description, but Claude cannot assemble the arguments correctly. What is missing from the specification?\n[Resposta correta: A especificação completa exige name, description e input_schema; sem o input_schema Claude não sabe a estrutura dos argumentos. max_uses pertence à web search tool, is_error e tool_use_id pertencem ao bloco tool_result, não à definição da tool.]\n\n[ ] A - The max_uses field\n[ ] B - The input_schema with the JSON Schema of the arguments\n[ ] C - The is_error field\n[ ] D - The tool_use_id field','\n',char(10)),'B - The input_schema with the JSON Schema of the arguments','["Domain_2::Tool_Design_MCP_Integration", "Domain_4::Prompt_Engineering_Structured_Output", "Scenario_4::Developer_Productivity"]','New',0,2.5,0,1783092991557,1783727869878,1783203558653,replace('**Tradução para português do Brasil:**\n\n**Pergunta:** Um desenvolvedor define uma ferramenta passando apenas nome e descrição, mas Claude não consegue montar os argumentos corretamente. O que está faltando na especificação?\n\n**Alternativas:**\n[ ] A - O campo max_uses\n[ ] B - O input_schema com o JSON Schema dos argumentos\n[ ] C - O campo is_error\n[ ] D - O campo tool_use_id','\n',char(10)),replace('**Explicação para um adulto tech lead:**\n\nPara que Claude (ou qualquer modelo) possa invocar uma ferramenta corretamente, a definição da ferramenta precisa conter três elementos obrigatórios: `name`, `description` e `input_schema`. O `input_schema` utiliza o padrão JSON Schema para descrever a estrutura, os tipos e as restrições dos parâmetros que a ferramenta espera receber. Sem ele, Claude não tem como saber quais argumentos devem ser gerados, seus tipos (string, number, object, array, etc.), quais são obrigatórios ou opcionais, e qual a estrutura esperada. Isso torna impossível para o modelo "montar os argumentos corretamente", conforme descrito no enunciado.\n\n**Análise das alternativas incorretas:**\n- **A (max_uses):** Este campo não faz parte da definição da ferramenta em si. Ele é um parâmetro opcional usado em configurações de *tool use* para limitar o número de chamadas da ferramenta (por exemplo, em web search tools), mas não é obrigatório nem resolve o problema de montagem dos argumentos.\n- **C (is_error):** Este campo pertence ao bloco `tool_result` (a resposta que é retornada após a execução da ferramenta), não à definição da ferramenta. Ele indica se a execução resultou em erro.\n- **D (tool_use_id):** Este campo também faz parte do bloco `tool_result` e serve para associar a resposta a uma chamada específica (`tool_use`), permitindo que o modelo relacione o resultado à invocação correta. Não é parte da definição da ferramenta.\n\nPortanto, a única alternativa que preenche a lacuna na especificação para que Claude consiga montar os argumentos corretamente é o `input_schema`.','\n',char(10)),replace('Imagine que você pede para um robô ajudante fazer um sanduíche. Você diz: "O nome do sanduíche é X" e "a descrição é delicioso". Mas o robô não sabe quais ingredientes usar, nem a quantidade, nem a ordem! O que falta é uma "receita" (input_schema) que explique direitinho: pão, queijo, presunto, em que ordem montar, etc. Sem essa receita, o robô erra tudo.\n\nAs outras opções são como dizer "use no máximo 3 ingredientes" (max_uses), "deu certo ou errado?" (is_error), ou "qual o número do pedido?" (tool_use_id) — isso ajuda depois, mas não diz como montar o sanduíche. O que realmente está faltando é a receita completa (input_schema).','\n',char(10)));
INSERT INTO cards VALUES('admin','card_1783092991621_757928fp7',451,'When reviewing a tool''s description, which element below is considered a mandatory good practice besides explaining what the tool does?',replace('When reviewing a tool''s description, which element below is considered a mandatory good practice besides explaining what the tool does?\n\nWhen reviewing a tool''s description, which element below is considered a mandatory good practice besides explaining what the tool does?\n[Resposta correta: A boa prática pede 3-4 frases, quando usar, o que retorna e descrição de cada argumento. C erra ao omitir a descrição dos argumentos e D erra ao tirar da description o critério de quando usar, que é justamente o que Claude lê para decidir.]\n\n[ ] A - Limiting the description to a single short sentence to save tokens\n[ ] B - Describing when Claude should use the tool, what it returns and each argument\n[ ] C - Listing only the argument names without a description\n[ ] D - Leaving the usage guidance only in the system prompt and not in the description','\n',char(10)),'B - Describing when Claude should use the tool, what it returns and each argument','["Domain_2::Tool_Design_MCP_Integration", "Domain_4::Prompt_Engineering_Structured_Output", "Scenario_4::Developer_Productivity"]','New',0,2.5,0,1783092991621,1783727873273,1783203558653,replace('**Tradução para português do Brasil:**\n\nAo revisar a descrição de uma ferramenta, qual elemento abaixo é considerado uma boa prática obrigatória além de explicar o que a ferramenta faz?\n\n[ ] A - Limitar a descrição a uma única frase curta para economizar tokens\n[ ] B - Descrever quando Claude deve usar a ferramenta, o que ela retorna e cada argumento\n[ ] C - Listar apenas os nomes dos argumentos sem uma descrição\n[ ] D - Deixar a orientação de uso apenas no system prompt e não na descrição','\n',char(10)),replace('**Explicação para adulto (tech lead):**\n\nA alternativa correta é a **B**.\n\nAo descrever uma ferramenta (tool) para um modelo como o Claude, seguir boas práticas na descrição é essencial para que o modelo entenda corretamente quando e como invocá-la. A boa prática recomendada é que a descrição contenha de 3 a 4 frases cobrindo:\n- Quando usar a ferramenta (critério de ativação);\n- O que ela retorna;\n- A descrição de cada argumento.\n\n**Análise das alternativas incorretas:**\n\n- **A**: Limitar a descrição a uma única frase curta para economizar tokens não é uma boa prática, pois uma descrição muito enxuta pode carecer de contexto necessário para o modelo decidir corretamente quando usar a ferramenta.\n- **C**: Listar apenas os nomes dos argumentos sem descrição é insuficiente, pois o modelo precisa entender o significado e o propósito de cada argumento para preenchê-los adequadamente.\n- **D**: Deixar a orientação de uso apenas no system prompt e não na description é problemático, pois o Claude lê a descrição da ferramenta para decidir quando utilizá-la. Se o critério de uso não estiver na descrição, o modelo pode não ter a informação necessária no momento da decisão.','\n',char(10)),'Imagine que você está ensinando um robô a usar uma caixa de ferramentas. Se você colocar uma etiqueta na caixa dizendo só "martelo", o robô pode não saber quando usar o martelo — se é para pregar um prego, quebrar uma parede ou abrir uma noz. A melhor maneira é escrever na etiqueta: "Use este martelo quando precisar pregar algo. Ele devolve o barulho que faz. Os argumentos são: ''prego'' (tamanho do prego) e ''força'' (quão forte bater)." Assim, a alternativa **B** é a certa porque diz que devemos explicar quando usar, o que a ferramenta devolve e o que cada parte significa.');
INSERT INTO cards VALUES('admin','card_1783092991646_0dfdwe43d',452,'How is the assistant message characterized when Claude decides to call a tool?',replace('How is the assistant message characterized when Claude decides to call a tool?\n\nHow is the assistant message characterized when Claude decides to call a tool?\n[Resposta correta: Quando usa uma tool, a assistant message traz múltiplos blocos (por exemplo texto e tool_use), diferente da resposta de bloco único. A user message com tool_result é a etapa seguinte de devolução do resultado, não a decisão de usar a tool.]\n\n[ ] A - A user message containing the tool_result block\n[ ] B - An assistant message with a single text block\n[ ] C - An assistant message with multiple blocks in the content, such as text plus tool_use\n[ ] D - A system message with the tool schema','\n',char(10)),'C - An assistant message with multiple blocks in the content, such as text plus tool_use','["Domain_4::Prompt_Engineering_Structured_Output", "ForaDoCenario"]','New',0,2.5,0,1783092991646,1783727876706,1783203558653,replace('**Tradução para português do Brasil:**\n\n**Pergunta:** Como é caracterizada a mensagem do assistente quando Claude decide chamar uma ferramenta (tool)?\n\n[ ] A - Uma mensagem de usuário contendo o bloco tool_result\n[ ] B - Uma mensagem do assistente com um único bloco de texto\n[X] C - Uma mensagem do assistente com múltiplos blocos no conteúdo, como texto mais tool_use\n[ ] D - Uma mensagem de sistema com o schema da ferramenta','\n',char(10)),replace('**Explicação didática para um adulto tech lead:**\n\nA resposta correta é a alternativa **C**.\n\nQuando Claude (ou qualquer modelo da família Anthropic que suporte tool use) decide invocar uma ferramenta, a mensagem retornada pelo assistente não é uma resposta textual simples. Em vez disso, a API estrutura a mensagem com um array de blocos no campo `content`, onde cada bloco possui um tipo específico.\n\n**Por que C está correta:**\n\nNo protocolo de tool use da Anthropic, quando o modelo decide chamar uma ferramenta, a mensagem do assistente contém:\n\n- Um ou mais blocos do tipo `text` (a explicação ou raciocínio do modelo sobre por que está chamando a ferramenta)\n- Um ou mais blocos do tipo `tool_use` (com `id`, `name` e `input` — os parâmetros que serão passados para a ferramenta)\n\nExemplo típico da estrutura:\n\n```json\n{\n  "role": "assistant",\n  "content": [\n    { "type": "text", "text": "Vou buscar a cotação atual..." },\n    { \n      "type": "tool_use",\n      "id": "toolu_abc123",\n      "name": "get_stock_price",\n      "input": { "symbol": "AAPL" }\n    }\n  ]\n}\n```\n\nEssa estrutura de múltiplos blocos é justamente a característica que distingue uma resposta normal de texto de uma resposta que inclui uma chamada de ferramenta.\n\n**Por que as demais estão erradas:**\n\n- **A** (user message com tool_result): Esta mensagem é enviada *pelo usuário (ou sistema)* para devolver o resultado da execução da ferramenta de volta ao modelo. Não é a mensagem que caracteriza a *decisão* de chamar a ferramenta, mas sim a *resposta* após a execução. O fluxo correto é: assistant com tool_use → user com tool_result → assistant com resposta final.\n\n- **B** (assistant message com único bloco de texto): Isso descreve uma resposta normal do assistente, sem chamada de ferramenta. Quando Claude decide usar uma tool, a mensagem sempre conterá ao menos um bloco `tool_use`, tornando-a multi-bloco.\n\n- **D** (system message com o schema da ferramenta): A mensagem de sistema pode conter a definição das ferramentas disponíveis (tool schema), mas isso é parte da configuração inicial enviada pelo usuário, não a resposta do assistente decidindo usar uma ferramenta.','\n',char(10)),replace('**Explicação para uma criança de 10 anos:**\n\nImagina que você está conversando com um robô inteligente, o Claude. Esse robô pode usar ferramentas especiais, como uma calculadora ou um dicionário, para te ajudar melhor.\n\nQuando o Claude **decide** que precisa usar uma ferramenta, a mensagem dele não é só um textão comum. É como se ele dissesse: "Vou buscar essa informação pra você!" e, ao mesmo tempo, já estivesse com a mão estendida pegando a ferramenta.\n\nA resposta dele vem em **várias partes** (vários blocos):\n1. Um bloco com texto explicando o que ele vai fazer.\n2. Outro bloco dizendo qual ferramenta ele quer usar e como usar.\n\nÉ como se fosse uma resposta em dois pedaços: a fala e a ação.\n\n**Por que as outras opções estão erradas?**\n\n- **Opção A** (mensagem do usuário com resultado da ferramenta): Isso é quando VOCÊ (ou o sistema) devolve pro Claude o resultado que a ferramenta deu. Não é a hora em que ele decide usar a ferramenta, é depois que a ferramenta já foi usada.\n\n- **Opção B** (mensagem com um único bloco de texto): Isso é uma resposta normal, quando o Claude só conversa, sem usar nenhuma ferramenta. Não tem a parte da "ação".\n\n- **Opção D** (mensagem do sistema com a descrição das ferramentas): Isso é quando alguém explica pro Claude quais ferramentas existem e como funcionam. É como mostrar o manual de instruções, não o momento em que ele decide usar uma.\n\n**Resumindo:** Quando Claude decide usar uma ferramenta, a mensagem dele tem **vários blocos** (texto + a chamada da ferramenta). É a opção **C**!','\n',char(10)));
INSERT INTO cards VALUES('admin','card_1783092991674_72z8zkd9u',453,'A technically correct tool is almost never called by Claude.',replace('A technically correct tool is almost never called by Claude.\n\nA technically correct tool is almost never called by Claude. What is the most likely cause according to the tool design criteria?\n[Resposta correta: A description é o que Claude lê para decidir quando e como chamar a tool, então uma description ruim gera uso incorreto ou ausência de uso. As demais opções tratam de detalhes técnicos que não explicam a não utilização motivada por documentação fraca.]\n\n[ ] A - The input_schema uses numeric types instead of strings\n[ ] B - The description is the documentation Claude reads and, being poor, causes incorrect use or no use at all\n[ ] C - The tool was not registered as built-in\n[ ] D - fine_grained tool calling is not enabled','\n',char(10)),'B - The description is the documentation Claude reads and, being poor, causes incorrect use or no use at all','["Domain_2::Tool_Design_MCP_Integration", "Domain_4::Prompt_Engineering_Structured_Output", "Scenario_1::Customer_Support_Agent"]','New',0,2.5,0,1783092991674,1783727880131,1783203558653,replace('**Tradução:**\n\n> Uma ferramenta tecnicamente correta quase nunca é chamada pelo Claude. Qual é a causa mais provável de acordo com os critérios de design de ferramentas?\n> \n> [ ] A - O input_schema usa tipos numéricos em vez de strings\n> [ ] B - A descrição é a documentação que o Claude lê e, sendo ruim, causa uso incorreto ou nenhum uso\n> [ ] C - A ferramenta não foi registrada como embutida (built-in)\n> [ ] D - O fine-grained tool calling não está habilitado','\n',char(10)),replace('**Explicação para adulto (tech lead):**\n\nA resposta correta é a **alternativa B**.\n\nO Claude (e modelos de linguagem em geral) não "enxergam" as funções como um sistema de tipos ou como código compilado. O que o modelo lê é a **descrição textual** da ferramenta. A descrição é o principal artefato de documentação que orienta o modelo sobre *quando* e *como* usar a ferramenta. Se a descrição for ambígua, genérica ou não capturar claramente o propósito e os cenários de uso, o modelo simplesmente não terá informação suficiente para decidir invocá-la — mesmo que a implementação técnica (schema, tipos, lógica) esteja perfeita.\n\n**Por que as demais alternativas estão incorretas:**\n\n- **A** (tipos numéricos vs. strings): O schema de entrada aceita tanto tipos numéricos quanto strings. O Claude consegue converter valores adequadamente. Isso não impede o uso da ferramenta.\n- **C** (registro como built-in): O conceito de "built-in" se aplica a ferramentas internas do sistema (como calculadora ou busca). Ferramentas customizadas são registradas via API — não há exigência de serem "built-in" para funcionar.\n- **D** (fine-grained tool calling): Esse é um recurso avançado que permite controle mais granular sobre *quando* uma ferramenta é chamada, mas não é um pré-requisito para que ela seja chamada. Sua ausência não impede invocações.\n\n**Conclusão:** A causa raiz mais provável é uma descrição mal escrita. Invista tempo em redigir descrições claras, com exemplos de uso e critérios objetivos de quando a ferramenta deve ser acionada.','\n',char(10)),replace('Imagine que você tem um robô chamado Claude e dá a ele uma caixa de ferramentas. Uma das ferramentas é um martelo super legal, mas você escreveu no manual: "É uma coisa de metal". O robô não sabe se aquilo serve para pregar pregos, quebrar nozes ou abrir portas. Resultado: ele nunca usa o martelo, mesmo ele sendo perfeitamente bom.\n\nO problema não é o martelo (a ferramenta), mas sim o manual (a descrição) que não explica direito para que ele serve. É por isso que a resposta certa é a **letra B**: a descrição é o que o Claude lê para saber quando chamar a ferramenta, e se ela for ruim, ele não vai usar ou vai usar errado.','\n',char(10)));
INSERT INTO cards VALUES('admin','card_1783092991703_khu20kenl',454,'When returning a tool''s result to Claude, which field ensures pairing with the original call?',replace('When returning a tool''s result to Claude, which field ensures pairing with the original call?\n\nWhen returning a tool''s result to Claude, which field ensures pairing with the original call?\n[Resposta correta: O bloco tool_result vai em uma user message e usa tool_use_id para casar com o id do tool_use correspondente, além de content e is_error. name e input_schema pertencem à definição da tool e max_uses é da web search tool.]\n\n[ ] A - name, equal to the one in the tool definition\n[ ] B - tool_use_id, which must match the id of the corresponding tool_use block\n[ ] C - input_schema, repeated in the tool_result\n[ ] D - max_uses, indicating how many times the tool was called','\n',char(10)),'B - tool_use_id, which must match the id of the corresponding tool_use block','["Domain_2::Tool_Design_MCP_Integration", "Domain_4::Prompt_Engineering_Structured_Output", "Scenario_1::Customer_Support_Agent"]','New',0,2.5,0,1783092991703,1783727883665,1783203558653,replace('**Tradução para português do Brasil:**\n\nPergunta: Ao retornar o resultado de uma ferramenta para o Claude, qual campo garante o pareamento com a chamada original?\n\n[Resposta correta: O bloco tool_result vai em uma user message e usa tool_use_id para casar com o id do tool_use correspondente, além de content e is_error. name e input_schema pertencem à definição da tool e max_uses é da web search tool.]\n\n[ ] A - name, igual ao da definição da ferramenta\n[ ] B - tool_use_id, que deve corresponder ao id do bloco tool_use correspondente\n[ ] C - input_schema, repetido no tool_result\n[ ] D - max_uses, indicando quantas vezes a ferramenta foi chamada','\n',char(10)),replace('**Explicação para um adulto (tech lead):**\n\nA pergunta aborda o mecanismo de emparelhamento (pareamento) entre uma chamada de ferramenta e seu respectivo resultado no protocolo de uso de ferramentas do Claude (function calling).\n\n**Resposta correta: Alternativa B - tool_use_id**\n\nNo protocolo de tool use da Anthropic, quando o Claude faz uma chamada de ferramenta, ele gera um bloco `tool_use` contendo um campo `id` único (ex: "toolu_12345"). Quando o sistema retorna o resultado dessa chamada, ele deve enviar um bloco `tool_result` dentro de uma mensagem do usuário (user message). O campo `tool_use_id` no `tool_result` é justamente o identificador que referencia o `id` do `tool_use` original, estabelecendo o vínculo entre a chamada e o resultado. Sem esse pareamento correto, a API não consegue associar qual resultado pertence a qual chamada de ferramenta, especialmente em cenários com múltiplas chamadas paralelas ou sequenciais.\n\n**Análise das alternativas incorretas:**\n\n- **Alternativa A (name)**: O campo `name` está presente na definição da ferramenta (tool definition) e também no bloco `tool_use` para indicar qual ferramenta está sendo chamada. Porém, ele não serve para parear a resposta com a chamada original — duas chamadas para a mesma ferramenta teriam o mesmo `name`, causando ambiguidade.\n\n- **Alternativa C (input_schema)**: `input_schema` é um campo da definição da ferramenta (tool definition) que descreve o esquema JSON dos parâmetros de entrada. Não é utilizado no `tool_result` e não participa do pareamento.\n\n- **Alternativa D (max_uses)**: `max_uses` é um parâmetro específico da ferramenta de busca web (web search tool) que limita o número de chamadas consecutivas. Não tem relação com o pareamento chamada-resposta no protocolo geral de tool use.','\n',char(10)),replace('Imagine que você pede ajuda para duas pessoas diferentes ao mesmo tempo. Você escreve um bilhete para cada uma. Para saber qual resposta veio de qual pessoa, você coloca um número diferente em cada bilhete: "Pedido 1" e "Pedido 2". Quando a resposta chega, você olha o número para saber de qual pedido aquela resposta veio.\n\nNo computador, o Claude (o assistente) faz algo parecido. Quando ele chama uma ferramenta (como uma calculadora), ele cria um "bilhete" com um número único chamado `id`. Quando a ferramenta devolve a resposta, ela precisa colocar esse mesmo número no campo `tool_use_id`, assim o Claude sabe: "Ah, essa resposta é daquela chamada que fiz com o número tal!"\n\nAs outras opções não funcionam para isso:\n- Opção A: Usar o `name` (nome) seria como duas pessoas terem o mesmo nome — você não saberia qual resposta é de qual.\n- Opção C: `input_schema` é como a "receita" de como fazer a pergunta, não serve para identificar a resposta.\n- Opção D: `max_uses` é como um limite de quantas vezes você pode pedir algo, não tem nada a ver com juntar pergunta e resposta.\n\nPor isso a resposta correta é a letra B!','\n',char(10)));
INSERT INTO cards VALUES('admin','card_1783092991729_t9y08qhc0',455,'In the follow-up that sends the tool_result, the developer omits the tool schema to save tokens.',replace('In the follow-up that sends the tool_result, the developer omits the tool schema to save tokens.\n\nIn the follow-up that sends the tool_result, the developer omits the tool schema to save tokens. What is the problem?\n[Resposta correta: Mesmo sem esperar nova chamada, o schema deve ser reenviado para Claude interpretar as referências à tool já presentes no histórico. A opção A representa exatamente a pegadinha a ser evitada e as demais confundem com outros campos ou recursos.]\n\n[ ] A - No problem, the schema is only needed on the first call\n[ ] B - Claude still needs the schema to understand the references to the tool in the conversation history\n[ ] C - The tool_result is rejected due to a missing is_error\n[ ] D - The schema is only needed when using fine_grained tool calling','\n',char(10)),'[ ] B - Claude ainda precisa do schema para entender as referências à ferramenta no histórico da conversa','["Domain_2::Tool_Design_MCP_Integration", "Domain_5::Context_Management_Reliability", "Scenario_1::Customer_Support_Agent"]','New',0,2.5,0,1783092991729,1783727886987,1783203558653,replace('**Tradução para português do Brasil:**\n\n*Pergunta:* No follow-up que envia o tool_result, o desenvolvedor omite o schema da ferramenta para economizar tokens. Qual é o problema?\n\n*Alternativas:*\n[ ] A - Não tem problema, o schema só é necessário na primeira chamada\n[ ] B - Claude ainda precisa do schema para entender as referências à ferramenta no histórico da conversa\n[ ] C - O tool_result é rejeitado devido à ausência de is_error\n[ ] D - O schema só é necessário quando se usa fine_grained tool calling','\n',char(10)),replace('**Explicação para adulto tech lead:**\n\nA alternativa correta é a **B**.\n\nO problema central está na forma como o Claude (e modelos de linguagem em geral) processam o contexto da conversa. O schema de uma ferramenta não é apenas um "contrato" para a primeira chamada; ele serve como definição semântica que o modelo precisa ter disponível sempre que houver referências àquela ferramenta no histórico. \n\nQuando o desenvolvedor envia um `tool_result` em um follow-up sem incluir novamente o schema da ferramenta, o Claude pode não conseguir relacionar corretamente o resultado recebido à definição original da ferramenta. Isso ocorre porque o modelo precisa do schema para:\n1. Entender quais parâmetros foram usados e seus tipos esperados\n2. Saber o propósito e a descrição da ferramenta\n3. Manter a coerência das chamadas de ferramenta ao longo da conversa\n\n**Análise das alternativas incorretas:**\n\n- **A**: É exatamente a "pegadinha" mencionada na questão. O schema não é necessário apenas na primeira chamada; ele precisa estar presente sempre que a ferramenta for referenciada no histórico.\n  \n- **C**: Confunde `is_error` (campo opcional que indica se houve erro) com a necessidade do schema. A ausência de `is_error` não causa rejeição do `tool_result`; esse campo serve apenas para sinalizar falhas na execução.\n\n- **D**: `fine_grained_tool_calling` é um recurso específico para controle refinado de chamadas de ferramenta, mas não elimina a necessidade do schema nos follow-ups. A necessidade do schema independe do modo de chamada.','\n',char(10)),replace('Imagine que você pediu ajuda para um amigo montar um Lego. Na primeira vez, você mostrou a foto da estante (o "schema") para ele saber como é o brinquedo. Depois que ele te entrega uma peça (o "tool_result"), você joga a foto fora para economizar espaço. Mas aí você não lembra mais onde aquela peça encaixa! O problema é que seu amigo (o Claude) ainda precisa da foto para entender o que está acontecendo. \n\nA alternativa correta é a **B**: o Claude ainda precisa do schema (a "foto da estante") para entender as referências à ferramenta no histórico, mesmo depois da primeira chamada. A opção A é uma pegadinha — pensar que dá pra jogar fora depois do primeiro uso. A opção C confunde com outro detalhe (o "is_error", que é como avisar se a peça veio quebrada). A opção D também está errada, porque precisa do schema em qualquer situação.','\n',char(10)));
INSERT INTO cards VALUES('admin','card_1783092991755_371u7dldz',456,'What technically happens when enabling fine_grained=True in tool calling?',replace('What technically happens when enabling fine_grained=True in tool calling?\n\nWhat technically happens when enabling fine_grained=True in tool calling?\n[Resposta correta: O fine-grained tool calling desabilita a validação de JSON da API e entrega os chunks conforme são gerados, sem o buffering entre chaves de topo. A opção A inverte o comportamento, C confunde com o reenvio de schema e D confunde com max_uses.]\n\n[ ] A - The API starts validating the JSON more strictly before delivering it\n[ ] B - The API-side JSON validation is disabled and chunks are delivered as soon as they are generated\n[ ] C - The tool schema is no longer needed\n[ ] D - The number of tool calls becomes automatically limited','\n',char(10)),'B - The API-side JSON validation is disabled and chunks are delivered as soon as they are generated','["Domain_5::Context_Management_Reliability", "ForaDoCenario"]','New',0,2.5,0,1783092991755,1783727890425,1783203558653,replace('**Tradução para português do Brasil:**\n\n**Pergunta:** O que acontece tecnicamente ao habilitar fine_grained=True na chamada de ferramentas (tool calling)?\n\n[ ] A - A API começa a validar o JSON de forma mais rigorosa antes de entregá-lo\n[ ] B - A validação de JSON do lado da API é desabilitada e os chunks são entregues assim que são gerados\n[ ] C - O schema da ferramenta não é mais necessário\n[ ] D - O número de chamadas de ferramenta se torna automaticamente limitado','\n',char(10)),replace('**Explicação técnica (para um adulto tech lead):**\n\nA opção correta é a **B**.\n\nQuando você habilita `fine_grained=True` no contexto de tool calling (comum em APIs de modelos de linguagem que suportam streaming, como a Anthropic), o comportamento padrão de "buffering" — no qual a API acumula tokens de JSON até que um bloco completo e válido de nível superior (ex.: uma ferramenta inteira) esteja pronto — é desabilitado. Em vez disso, a API desativa a validação sintática de JSON no lado servidor e passa a entregar os chunks de tokens conforme eles são gerados pelo modelo, em tempo real.\n\nIsso significa que o cliente recebe fragmentos parciais e possivelmente inválidos de JSON (por exemplo, um nome de ferramenta incompleto ou argumentos truncados) e assume a responsabilidade de reconstruir e validar o JSON por conta própria. O benefício é uma latência menor (os dados chegam mais rápido, sem esperar o fim de uma ferramenta), mas o custo é maior complexidade no cliente, que precisa lidar com parsing incremental.\n\nAs demais alternativas estão incorretas:\n- **A** está errada porque a validação não se torna mais rigorosa — pelo contrário, ela é desabilitada.\n- **C** está errada porque o schema da ferramenta continua sendo necessário para que o cliente saiba como interpretar os dados recebidos.\n- **D** está errada porque `fine_grained` não tem relação com limitar o número de chamadas; isso seria controlado por parâmetros como `max_tokens` ou lógica de aplicação.','\n',char(10)),replace('**Explicação para uma criança de 10 anos:**\n\nImagine que você está desenhando um robô, mas em vez de esperar o desenho inteiro ficar pronto para te mostrar, eu vou te mostrando cada pedaço assim que eu desenho — primeiro a cabeça, depois o braço, e assim por diante. Normalmente, o computador espera o desenho completo e bonito antes de te entregar. Quando a gente liga o "fine_grained=True", o computador para de esperar e vai te mandando os pedaços na hora que eles saem, mesmo que estejam meio bagunçados. Você que precisa juntar tudo depois.\n\nÉ como ligar o modo "entrega rápida" da ferramenta: chega mais rápido, mas você tem que montar o quebra-cabeça sozinho.\n\nAs outras opções estão erradas porque:\n- A: diz que ele verifica mais ainda o desenho, mas na verdade ele para de verificar.\n- C: diz que você não precisa mais do molde do robô, mas você ainda precisa saber como ele é.\n- D: diz que o robô só pode desenhar um número limitado de vezes, mas não tem nada a ver com isso.','\n',char(10)));
INSERT INTO cards VALUES('admin','card_1783092991780_4svvqe8md',457,'For most applications, which tool calling behavior is recommended?',replace('For most applications, which tool calling behavior is recommended?\n\nFor most applications, which tool calling behavior is recommended?\n[Resposta correta: O padrão com validação atende a maioria dos apps; fine-grained só se justifica quando é preciso mostrar progresso em tempo real, processar resultados parciais ou o buffering prejudica a UX e há disposição para tratar JSON inválido. As demais generalizam o uso de fine-grained ou fogem do tema.]\n\n[ ] A - Always fine-grained, because it is faster\n[ ] B - The default behavior with JSON validation\n[ ] C - Fine-grained only when the schema is complex\n[ ] D - Disable tools and use only text','\n',char(10)),'B - The default behavior with JSON validation','["ForaDosDominios", "ForaDoCenario"]','New',0,2.5,0,1783092991780,1783727893806,1783203558653,replace('**Tradução para português do Brasil:**\n\n**Pergunta:** Para a maioria das aplicações, qual comportamento de chamada de ferramenta é recomendado?\n\n[ ] A - Sempre fine-grained, porque é mais rápido\n[ ] B - O comportamento padrão com validação JSON\n[ ] C - Fine-grained apenas quando o esquema é complexo\n[ ] D - Desabilitar ferramentas e usar apenas texto','\n',char(10)),replace('**Explicação para um adulto (tech lead):**\n\nA alternativa correta é a **B**: "O comportamento padrão com validação JSON".\n\n**Por que a B é a resposta correta?**\n\nO comportamento padrão (default behavior) com validação JSON é o mais recomendado para a maioria das aplicações porque ele oferece um equilíbrio ideal entre confiabilidade, simplicidade e desempenho. A validação JSON garante que as chamadas de ferramenta estejam sintaticamente corretas antes de serem executadas, evitando falhas inesperadas no fluxo da aplicação. O modo padrão também lida com o buffering de chamadas, enviando as requisições de forma otimizada, o que reduz a latência geral. Para a grande maioria dos casos de uso — como chatbots, automação de tarefas, integrações com APIs — esse comportamento é suficiente e mais robusto.\n\n**Análise das alternativas incorretas:**\n\n- **A - Sempre fine-grained, porque é mais rápido:** Incorreta. O modo *fine-grained* (granularidade fina) não é necessariamente mais rápido; ele tende a ser mais verboso e pode aumentar a latência, pois cada token relacionado a chamada de ferramenta é transmitido individualmente. Ele só se justifica em cenários específicos, como streaming em tempo real onde o usuário precisa ver o progresso das chamadas. Generalizar seu uso para todas as aplicações é uma recomendação inadequada.\n\n- **C - Fine-grained apenas quando o esquema é complexo:** Incorreta. A complexidade do schema não é o critério determinante para usar *fine-grained*. O que define a necessidade de *fine-grained* são requisitos de UX, como exibir progresso em tempo real, processar resultados parciais ou situações onde o buffering prejudica a experiência do usuário. Um schema complexo pode ser perfeitamente atendido pelo comportamento padrão com validação JSON.\n\n- **D - Desabilitar ferramentas e usar apenas texto:** Incorreta. Esta alternativa foge completamente do tema, que é sobre qual *comportamento de chamada de ferramenta* é recomendado. Desabilitar ferramentas é o oposto de utilizar a funcionalidade de tool calling. Para aplicações que precisam de chamadas de ferramenta, essa opção não faz sentido.','\n',char(10)),replace('Imagine que você tem um assistente que pode pedir ajuda para outras "ferramentas" (como uma calculadora, um dicionário ou um relógio) para responder suas perguntas.\n\nExistem diferentes jeitos de pedir essa ajuda:\n\n1. **Jeito "fine-grained"** (grão fino) - É como se o assistente fosse explicando cada passo bem devagar: "Vou... usar... a... calculadora... agora... 2... mais... 2... é... 4". Isso demora mais e é mais cansativo de ouvir.\n\n2. **Jeito padrão com validação** - O assistente junta tudo que precisa num pedido completo: "Calculadora: 2 + 2 = 4" e só mostra o resultado. É mais rápido e organizado.\n\n3. **Desabilitar as ferramentas** - É como dizer pro assistente: "Você não pode usar calculadora, nem dicionário, nem nada. Só use seu próprio conhecimento!"\n\nPara a maioria das coisas que a gente faz no dia a dia, o **jeito padrão com validação** é o melhor! Ele é como um amigo que pensa antes de falar, verifica se a informação está certa (validação) e só depois te responde. Assim você não precisa esperar cada palavra ser dita e ainda tem a garantia de que a resposta está correta.\n\nOs outros jeitos só são legais em situações especiais, como quando você quer ver o passo a passo de um cálculo bem complicado acontecendo bem devagarinho.','\n',char(10)));
INSERT INTO cards VALUES('admin','card_1783092991806_ahl9xt8pp',458,'Which set of capabilities does the built-in text editor tool offer Claude?',replace('Which set of capabilities does the built-in text editor tool offer Claude?\n\nWhich set of capabilities does the built-in text editor tool offer Claude?\n[Resposta correta: A text editor tool permite ver conteúdo e faixas de linhas, substituir e inserir texto, criar arquivos e desfazer edições recentes. A opção A limita indevidamente à leitura, C descreve a web search tool e D extrapola para execução de comandos, que não é a função dessa tool.]\n\n[ ] A - Only reading files, without writing\n[ ] B - Viewing files and directories, replacing and inserting text, creating files and undoing edits\n[ ] C - Running web searches on allowed domains\n[ ] D - Running arbitrary terminal commands on the host','\n',char(10)),'B - Viewing files and directories, replacing and inserting text, creating files and undoing edits','["Domain_2::Tool_Design_MCP_Integration", "Domain_1::Agentic_Architecture_Orchestration", "Scenario_4::Developer_Productivity"]','New',0,2.5,0,1783092991806,1783727897139,1783203558653,replace('**Tradução para português do Brasil:**\n\n**Pergunta:** Qual conjunto de capacidades a ferramenta de edição de texto embutida oferece ao Claude?\n\n[ ] A - Apenas leitura de arquivos, sem escrita\n[ ] B - Visualizar arquivos e diretórios, substituir e inserir texto, criar arquivos e desfazer edições recentes\n[ ] C - Executar buscas na web em domínios permitidos\n[ ] D - Executar comandos arbitrários de terminal no host','\n',char(10)),replace('**Explicação para adulto (tech lead):**\n\nA resposta correta é a **alternativa B**. Vamos analisar cada opção:\n\n- **Alternativa B (correta):** A ferramenta de edição de texto embutida (text editor tool) do Claude foi projetada especificamente para manipulação de arquivos de texto. Ela oferece um conjunto de operações que inclui: visualização de conteúdo de arquivos e listagem de diretórios, substituição de trechos de texto, inserção de novo conteúdo, criação de novos arquivos e um mecanismo de rollback (undo) para edições recentes. Isso permite que o Claude leia e modifique arquivos no ambiente de trabalho sem precisar de ferramentas externas.\n\n- **Alternativa A (incorreta):** Afirma que a ferramenta é somente leitura (read-only). Isso é falso, pois a text editor tool tem capacidades de escrita — ela pode criar, modificar e reverter alterações em arquivos. Reduzir a ferramenta a um visualizador ignora sua funcionalidade principal.\n\n- **Alternativa C (incorreta):** Descreve a *web search tool*, não a text editor tool. A ferramenta de busca na web é outra tool independente no ecossistema do Claude, usada para consultar domínios autorizados. A text editor tool não realiza buscas web.\n\n- **Alternativa D (incorreta):** Refere-se a uma ferramenta de execução de comandos de terminal (geralmente a sandbox ou bash tool), que permite rodar comandos arbitrários no ambiente do host. A text editor tool não executa comandos de shell; ela opera exclusivamente sobre o conteúdo textual de arquivos.','\n',char(10)),replace('**Explicação para uma criança de 10 anos:**\n\nImagine que o Claude é um robô que pode ajudar a escrever e arrumar textos no computador. A ferramenta de edição de texto que ele tem dentro dele é como um "caderno mágico". Com esse caderno, Claude pode:\n\n- **Ver** o que está escrito nos arquivos (como abrir um livro e ler).\n- **Olhar** a lista de pastas e arquivos (como ver o índice do caderno).\n- **Tirar** partes do texto e **colocar** um texto novo no lugar (como apagar um desenho e fazer outro melhor).\n- **Criar** arquivos novos (como pegar uma folha em branco e começar a escrever).\n- **Desfazer** as mudanças que fez (como apertar "voltar" num videogame).\n\nA resposta certa é a **letra B**, porque ela descreve tudinho que o caderno mágico faz.\n\nAs outras estão erradas:\n- **A** diz que ele só pode ler, mas ele também pode escrever — então está errada.\n- **C** fala de fazer buscas na internet, mas isso é outra ferramenta, não o editor de texto.\n- **D** fala de dar comandos para o computador, como ligar e desligar coisas — o editor de texto não faz isso, ele só mexe em textos.','\n',char(10)));
INSERT INTO cards VALUES('admin','card_1783092991830_z0f64qn7a',459,'What is the main tradeoff assumed when using fine-grained tool calling?',replace('What is the main tradeoff assumed when using fine-grained tool calling?\n\nWhat is the main tradeoff assumed when using fine-grained tool calling?\n[Resposta correta: Como a validação de JSON é desabilitada, o código passa a receber JSON parcial ou inválido, incluindo valores não terminados que não casam com o schema. A opção A inverte o benefício de menor buffering, C contradiz o próprio caso de uso e D confunde com a web search tool.]\n\n[ ] A - An increase in buffering time between chunks\n[ ] B - The code needs to handle invalid or partial JSON, such as unterminated strings\n[ ] C - The loss of the ability to show progress in real time\n[ ] D - The need to enable the tool in the organization console','\n',char(10)),'[ ] B - The code needs to handle invalid or partial JSON, such as unterminated strings','["Domain_4::Prompt_Engineering_Structured_Output", "Domain_2::Tool_Design_MCP_Integration", "Scenario_2::Code_Generation_Claude_Code"]','New',0,2.5,0,1783092991830,1783727900668,1783203558653,replace('**Tradução para português do Brasil:**\n\n**Pergunta:** Qual é o principal tradeoff assumido ao usar fine-grained tool calling?\n\n**Alternativas:**\n\n[ ] A - Um aumento no tempo de buffering entre chunks\n[ ] B - O código precisa lidar com JSON inválido ou parcial, como strings não terminadas\n[ ] C - A perda da capacidade de mostrar progresso em tempo real\n[ ] D - A necessidade de habilitar a ferramenta no console da organização','\n',char(10)),replace('**Explicação para um adulto tech lead:**\n\nO fine-grained tool calling é uma técnica que permite que um modelo de linguagem invoque ferramentas em pequenos pedaços (chunks) de saída, em vez de esperar a geração completa de uma chamada de ferramenta. Isso reduz a latência percebida e permite streaming mais responsivo.\n\nO principal tradeoff está na alternativa **B**: como os tokens são transmitidos em tempo real, o código cliente pode receber fragmentos de JSON que ainda não estão completos ou que, isoladamente, são sintaticamente inválidos (por exemplo, uma string que ainda não foi fechada com aspas, chaves ou colchetes não balanceados, etc.). Isso exige que o desenvolvedor implemente lógica para acumular, validar e tratar esses fragmentos, lidando com estados parciais e possíveis erros de parsing.\n\n**Análise das alternativas incorretas:**\n\n- **A (Aumento no buffering):** É o oposto do objetivo. O fine-grained tool calling reduz o buffering — em vez de aguardar a saída completa, os tokens são enviados assim que disponíveis. Portanto, o buffering diminui, não aumenta.\n- **C (Perda de progresso em tempo real):** Também é o inverso. A motivação principal do streaming chunk-level é justamente permitir que o usuário veja o progresso em tempo real, sem ter que esperar a conclusão total. Logo, a capacidade de exibir progresso é mantida ou melhorada.\n- **D (Habilitar no console):** Trata-se de uma configuração operacional, não de um tradeoff técnico intrínseco ao paradigma de fine-grained tool calling. Habilitação no console pode ser um pré-requisito, mas não é um tradeoff arquitetural.','\n',char(10)),replace('**Explicação para uma criança de 10 anos:**\n\nImagine que você está montando um quebra-cabeça e, em vez de esperar ele ficar pronto para ver a figura, você vai recebendo as peças uma por uma enquanto elas são encaixadas. Isso é legal porque você vê o progresso, mas cada peça sozinha é só um pedaço sem sentido — pode até parecer que está errada!\n\nA pergunta quer saber qual é o "preço" que a gente paga por usar essa forma de funcionamento. A resposta certa é a **B**: o programador precisa cuidar de pedaços de JSON (que é um formato de organizar informações) que chegam pela metade ou bagunçados. É como receber uma frase cortada no meio: "O gato sub" — você sabe que falta "iu no telhado", mas, sozinho, está incompleto.\n\nAs outras opções estão erradas:\n- A diz que demora mais para enviar os pedaços, mas na verdade é o contrário: envia mais rápido.\n- C diz que você não consegue ver o andamento, mas a ideia é justamente você ver em tempo real!\n- D fala de ligar uma ferramenta num painel de configuração, que é outra coisa completamente diferente.','\n',char(10)));
INSERT INTO cards VALUES('admin','card_1783092991857_31z9n4as2',460,'The text editor tool already has its schema expanded internally by Claude.',replace('The text editor tool already has its schema expanded internally by Claude.\n\nThe text editor tool already has its schema expanded internally by Claude. What does the developer still need to provide?\n[Resposta correta: Embora Claude expanda o schema a partir de um schema pequeno com type e name, o desenvolvedor ainda precisa escrever a implementação que executa as operações. A opção A ignora o schema embutido, C confunde com a web search tool e D erra ao equiparar à web search, que Claude executa sozinho.]\n\n[ ] A - The complete JSON Schema of the arguments, written by hand\n[ ] B - The real implementation, that is, the function that executes the operations\n[ ] C - The allowed_domains field to restrict access to files\n[ ] D - Nothing, since the tool is fully automatic like web search','\n',char(10)),'B - The real implementation, that is, the function that executes the operations','["Domain_2::Tool_Design_MCP_Integration", "Scenario_4::Developer_Productivity"]','New',0,2.5,0,1783092991857,1783727903979,1783203558653,replace('**Tradução para português do Brasil:**\n\nA ferramenta de editor de texto já teve seu schema expandido internamente pelo Claude. O que o desenvolvedor ainda precisa fornecer?\n\n[ ] A - O schema JSON completo dos argumentos, escrito manualmente  \n[ ] B - A implementação real, ou seja, a função que executa as operações  \n[ ] C - O campo allowed_domains para restringir o acesso a arquivos  \n[ ] D - Nada, já que a ferramenta é totalmente automática como a pesquisa na web','\n',char(10)),replace('**Explicação didática para um adulto tech lead:**\n\nA questão trata do mecanismo de extensão de ferramentas (tools) no ecossistema Claude. Quando usamos o conceito de "schema expansion", o Claude (ou o modelo de linguagem) é capaz de inferir e expandir internamente o schema JSON de argumentos a partir de uma definição minimalista — por exemplo, contendo apenas `type` e `name`. Isso reduz o trabalho manual de escrever schemas complexos.\n\nNo entanto, o schema é apenas a *especificação* da interface da ferramenta. O desenvolvedor ainda precisa fornecer a **implementação concreta** — o código que será executado quando o modelo decidir invocar a ferramenta. Para o text editor tool, isso significa escrever a lógica que realmente lê, escreve ou modifica arquivos.\n\n**Análise das alternativas:**\n\n- **Alternativa A (incorreta):** O schema já é expandido automaticamente pelo Claude, então o desenvolvedor não precisa escrevê-lo manualmente. A expansão do schema é exatamente o benefício anunciado.\n\n- **Alternativa B (correta):** Embora Claude expanda o schema, ele não pode executar o código por conta própria no ambiente do desenvolvedor. A implementação real (a função que executa as operações de arquivo) precisa ser fornecida pelo desenvolvedor.\n\n- **Alternativa C (incorreta):** O campo `allowed_domains` é específico da ferramenta de pesquisa na web (web search tool), não do editor de texto. Não faz sentido restringir "domínios" para operações de arquivo.\n\n- **Alternativa D (incorreta):** A ferramenta de editor de texto não é totalmente automática como a web search, porque a web search é uma ferramenta que Claude pode executar sozinho (consultando sua própria API). Já o editor de texto depende de uma implementação fornecida pelo desenvolvedor para interagir com o sistema de arquivos local."','\n',char(10)),replace('Imagine que você pediu para um amigo muito inteligente arrumar seu quarto. Ele sabe exatamente como deve ser o quarto arrumado (esse é o "schema" que o Claude entende sozinho). Mas ele não pode pegar nos seus brinquedos e livros porque não está aí de verdade — ele só pode te dar as instruções.\n\nVocê, que está no quarto, é quem precisa realmente pegar os brinquedos e colocar no lugar certo. É isso que o desenvolvedor precisa fazer: escrever o código que realmente executa as ações, como abrir arquivos ou escrever texto. O Claude sabe o que precisa ser feito, mas quem faz acontecer de verdade é o programador!','\n',char(10)));
INSERT INTO cards VALUES('admin','card_1783092991919_7q7wav15u',461,'What is the purpose of the max_uses field in the web search tool?',replace('What is the purpose of the max_uses field in the web search tool?\n\nWhat is the purpose of the max_uses field in the web search tool?\n[Resposta correta: max_uses limita a quantidade de buscas que Claude pode realizar, mesmo com follow-ups, evitando chamadas excessivas; a busca é executada automaticamente por Claude. As demais confundem com allowed_domains, tamanho de resultado ou renderização na UI.]\n\n[ ] A - Define how many domains can be searched\n[ ] B - Limit how many searches Claude can perform, avoiding excessive calls\n[ ] C - Specify the maximum size of the returned result\n[ ] D - Determine how many results appear in the UI','\n',char(10)),'[ ] B - Limit how many searches Claude can perform, avoiding excessive calls','["Domain_2::Tool_Design_MCP_Integration", "Domain_5::Context_Management_Reliability", "Scenario_1::Customer_Support_Agent"]','New',0,2.5,0,1783092991919,1783727907702,1783203558653,replace('**Tradução para Português do Brasil:**\n\n**Pergunta:** Qual é a finalidade do campo max_uses na ferramenta de busca web?\n\n[Resposta correta: max_uses limita a quantidade de buscas que Claude pode realizar, mesmo com follow-ups, evitando chamadas excessivas; a busca é executada automaticamente por Claude. As demais confundem com allowed_domains, tamanho de resultado ou renderização na UI.]\n\n[ ] A - Define quantos domínios podem ser pesquisados\n[ ] B - Limita quantas buscas Claude pode realizar, evitando chamadas excessivas\n[ ] C - Especifica o tamanho máximo do resultado retornado\n[ ] D - Determina quantos resultados aparecem na interface do usuário','\n',char(10)),replace('**Explicação Didática para um Adulto Tech Lead:**\n\nO campo **max_uses** é um parâmetro de configuração presente em ferramentas (tools) no ecossistema da Anthropic, utilizado para controlar o número máximo de invocações que o modelo (Claude) pode fazer daquela ferramenta durante uma conversa ou execução. No contexto específico de uma ferramenta de busca web (web search tool), max_uses serve para limitar quantas chamadas de busca o Claude pode disparar, mesmo que ele tente fazer isso em respostas subsequentes (follow-ups).\n\n**Análise das alternativas:**\n\n- **Alternativa B (correta):** "Limita quantas buscas Claude pode realizar, evitando chamadas excessivas" — Esta é a descrição precisa. O max_uses é um limitador de invocações da ferramenta. Ele protege contra loops de busca ou consumo excessivo de API/quota, garantindo que Claude não execute mais do que o número especificado de buscas, independentemente de quantas interações o usuário faça.\n\n- **Alternativa A (incorreta):** "Define quantos domínios podem ser pesquisados" — Isso confunde max_uses com allowed_domains (ou domains), que é um parâmetro diferente usado para restringir a quais domínios a busca pode ser direcionada. max_uses não tem relação com escopo de domínios.\n\n- **Alternativa C (incorreta):** "Especifica o tamanho máximo do resultado retornado" — O tamanho máximo do resultado retornado (em termos de número de caracteres, tokens ou páginas) é controlado por outros parâmetros, como max_tokens ou configurações de truncamento de resultado, não por max_uses.\n\n- **Alternativa D (incorreta):** "Determina quantos resultados aparecem na interface do usuário" — A quantidade de resultados exibidos na UI é tipicamente controlada por parâmetros como num_results, top_k, ou similar. max_uses não tem a ver com renderização ou exibição de resultados.','\n',char(10)),replace('Imagine que o Claude é um ajudante que pode fazer pesquisas na internet para você. O campo **max_uses** é como um limite de quantas vezes ele pode apertar o botão de "pesquisar". Por exemplo, se você colocar max_uses = 3, ele só pode fazer 3 buscas, mesmo que você peça para ele pesquisar de novo depois. Isso é para ele não gastar todas as pesquisas de uma vez, igual quando seus pais dizem "só pode brincar no tablet por 30 minutos".\n\nAs outras opções estão erradas porque:\n- A opção A fala de quantos sites diferentes ele pode pesquisar, mas isso é outro ajuste.\n- A opção C fala do tamanho do resultado (tipo quantas palavras), mas não é isso.\n- A opção D fala de quantos resultados aparecem na tela, mas também não é a função do max_uses.','\n',char(10)));
INSERT INTO cards VALUES('admin','card_1783092991943_0cedweyjy',462,'You want Claude to answer medical questions using only sources like nih.',replace('You want Claude to answer medical questions using only sources like nih.\n\nYou want Claude to answer medical questions using only sources like nih.gov and PubMed. Which field of the web search tool should you apply?\n[Resposta correta: allowed_domains restringe as buscas a domínios específicos, garantindo informação baseada em evidências. max_uses só limita a quantidade de buscas, is_error trata erros de tool_result e input_schema define argumentos, nenhum deles restringe fontes.]\n\n[ ] A - max_uses, limiting the number of searches to trusted sources\n[ ] B - allowed_domains, restricting the searches to specific domains\n[ ] C - is_error, marking blog results as an error\n[ ] D - input_schema, filtering by content type','\n',char(10)),'B - allowed_domains, restricting the searches to specific domains','["Domain_2::Tool_Design_MCP_Integration", "Domain_4::Prompt_Engineering_Structured_Output", "Scenario_1::Customer_Support_Agent"]','New',0,2.5,0,1783092991943,1783727911456,1783203558653,replace('**Tradução para português do Brasil:**\n\nVocê quer que o Claude responda a perguntas médicas usando apenas fontes como nih.gov e PubMed. Qual campo da ferramenta de busca na web você deve aplicar?\n\n[ ] A - max_uses, limitando o número de buscas a fontes confiáveis\n[ ] B - allowed_domains, restringindo as buscas a domínios específicos\n[ ] C - is_error, marcando resultados de blogs como erro\n[ ] D - input_schema, filtrando por tipo de conteúdo','\n',char(10)),replace('**Explicação didática para um adulto tech lead:**\n\nA resposta correta é a alternativa **B - allowed_domains**.\n\nO campo `allowed_domains` em uma ferramenta de busca na web (web_search tool) é especificamente projetado para restringir as buscas a um ou mais domínios. Quando você configura `allowed_domains: ["nih.gov", "pubmed.ncbi.nlm.nih.gov"]`, o mecanismo de busca retornará apenas resultados que pertençam a esses domínios, funcionando como uma whitelist. Isso é exatamente o que o cenário exige: garantir que Claude apenas consulte fontes autorizadas e baseadas em evidências científicas.\n\nAnalisando as alternativas incorretas:\n\n- **A - max_uses**: Este parâmetro define um limite máximo de quantas vezes a ferramenta pode ser chamada dentro de um contexto (ex.: no máximo 3 chamadas de busca). Ele não filtra *quais* fontes são retornadas, apenas quantas buscas podem ser feitas. Um modelo poderia usar todas as suas chamadas permitidas e ainda assim acessar sites não confiáveis como blogs ou Wikipedia.\n\n- **C - is_error**: Este campo é utilizado para sinalizar que um resultado de ferramenta (tool_result) conteve um erro. Ele não é um parâmetro de configuração prévia da ferramenta de busca, mas sim um campo de retorno/status. Marcar resultados de blogs como erro não é uma funcionalidade disponível nem faria sentido como parâmetro de configuração — você não pode "pré-marcar" resultados como erro antes da consulta acontecer.\n\n- **D - input_schema**: Este campo define o esquema dos argumentos de entrada da ferramenta (os parâmetros que ela aceita). Ele é usado para descrever a interface da ferramenta para o modelo, mas não serve para filtrar domínios ou tipos de conteúdo durante a execução da busca. É um metadado de definição, não um filtro de execução.','\n',char(10)),replace('Imagine que você tem uma tarefa de pesquisa na escola e só pode usar livros da biblioteca da sua sala, não pode pegar livros de qualquer lugar. \n\nO `allowed_domains` é como um bilhete que você dá para o Claude falando: "Só pode pegar informações dos sites nih.gov e PubMed, e de mais nenhum lugar!". Assim ele só vai buscar nesses lugares confiáveis, como se fosse buscar só nos livros certos da biblioteca.\n\nAs outras opções não funcionam para isso:\n- `max_uses` seria como falar "você só pode fazer 3 pesquisas" — mas ele poderia pesquisar em sites não confiáveis nessas 3 vezes.\n- `is_error` é tipo um alerta que aparece quando algo dá errado, não serve para escolher os lugares da pesquisa.\n- `input_schema` é como a lista do que você precisa preencher num formulário, não serve para filtrar sites.\n\nEntão a resposta certa é a **B - allowed_domains**, porque é a única que realmente diz para o Claude: "só busque nesses sites específicos".','\n',char(10)));
INSERT INTO cards VALUES('admin','card_1783092991968_vw3jzmbm9',463,'Before using the web search tool in production, which organizational prerequisite must be met?',replace('Before using the web search tool in production, which organizational prerequisite must be met?\n\nBefore using the web search tool in production, which organizational prerequisite must be met?\n[Resposta correta: A organização precisa habilitar a Web Search tool no console de settings antes do uso. allowed_domains é configuração da chamada, fine_grained é recurso não relacionado e a busca não é implementada pelo desenvolvedor.]\n\n[ ] A - Define allowed_domains for all users\n[ ] B - Enable the Web Search tool in the organization settings console\n[ ] C - Enable fine_grained tool calling\n[ ] D - Manually implement the search function','\n',char(10)),'B - Enable the Web Search tool in the organization settings console','["Domain_2::Tool_Design_MCP_Integration", "Domain_4::Prompt_Engineering_Structured_Output", "Scenario_1::Customer_Support_Agent"]','New',0,2.5,0,1783092991968,1783727914735,1783203558653,replace('**Tradução para português do Brasil:**\n\n**Pergunta:** Antes de usar a ferramenta de busca na web em produção, qual pré-requisito organizacional deve ser atendido?\n\n[ ] A - Definir allowed_domains para todos os usuários\n[ ] B - Ativar a ferramenta Web Search no console de configurações da organização\n[ ] C - Ativar chamada de ferramenta com fine_grained (granularidade fina)\n[ ] D - Implementar manualmente a função de busca','\n',char(10)),replace('**Explicação didática para um adulto tech lead:**\n\nA alternativa **B** é a correta porque o uso da ferramenta de busca web em produção exige uma autorização explícita em nível organizacional. A plataforma (como OpenAI, Azure OpenAI, etc.) disponibiliza um console de configurações da organização onde administradores podem habilitar ou desabilitar recursos. A Web Search tool precisa ser ativada nesse console antes que qualquer aplicação ou usuário possa utilizá-la em ambiente produtivo. Isso é um requisito de governança e segurança: a organização deve optar por expor seus dados a serviços externos de busca.\n\n**Análise das alternativas incorretas:**\n\n- **A (Definir allowed_domains para todos os usuários):** allowed_domains é um parâmetro que pode ser passado na chamada da ferramenta para restringir os domínios pesquisados, mas não é um pré-requisito organizacional. Você pode usar a ferramenta sem definir allowed_domains; aliás, defini-lo para "todos os usuários" não é um conceito que faça sentido como configuração global obrigatória.\n\n- **C (Ativar chamada de ferramenta com fine_grained):** fine_grained (granularidade fina) é um recurso relacionado a como o modelo chama ferramentas — controlando quais argumentos são gerados, paralelismo, etc. É uma otimização técnica, não um pré-requisito organizacional para usar web search.\n\n- **D (Implementar manualmente a função de busca):** Se a organização optou por usar a Web Search tool da plataforma, a implementação da busca já é fornecida pelo serviço. Implementar manualmente seria substituir a ferramenta por uma solução própria, o que não é um pré-requisito para usar a ferramenta pronta — é uma alternativa diferente.','\n',char(10)),replace('Vamos imaginar que você quer usar um novo brinquedo que precisa de internet, como um assistente de voz que pesquisa coisas na web. Antes de você poder usar esse brinquedo, seus pais precisam liberar o acesso no roteador ou no tablet, certo?\n\nA pergunta é: o que a empresa (como se fosse a família) precisa fazer antes de usar a ferramenta de busca na internet?\n\nA resposta certa é a letra **B**: Ativar a ferramenta de busca no painel de configurações da organização. É como ligar um interruptor geral lá no sistema. Sem isso, ninguém consegue usar.\n\nAs outras opções estão erradas:\n- **A**: Definir allowed_domains seria como dizer "só pode pesquisar em sites de animais". Isso é uma regra a mais, mas não é o primeiro passo. Você pode usar a busca sem essa regra.\n- **C**: Fine_grained é algo técnico chato que não precisa estar ligado para a busca funcionar.\n- **D**: Implementar manualmente seria construir sua própria ferramenta de busca do zero — isso dá muito trabalho e não é necessário, porque a ferramenta já vem pronta para usar.','\n',char(10)));
INSERT INTO cards VALUES('admin','card_1783092991994_kftbvhdzm',464,'Which rendering approach gives transparency about the sources used by the web search?',replace('Which rendering approach gives transparency about the sources used by the web search?\n\nWhich rendering approach gives transparency about the sources used by the web search?\n[Resposta correta: A renderização recomendada mostra o texto como conteúdo normal, os resultados como lista de fontes no topo e citações inline com domínio, título, URL e trecho, garantindo transparência. As demais omitem referências ou dados que compõem a citação completa.]\n\n[ ] A - Show only the final text, without references\n[ ] B - Display a list of sources at the top and inline citations with domain, title, URL and snippet\n[ ] C - Hide the URLs to avoid cluttering the interface\n[ ] D - Present only the domain of each source','\n',char(10)),'B - Display a list of sources at the top and inline citations with domain, title, URL and snippet','["Domain_4::Prompt_Engineering_Structured_Output", "Scenario_3::Multi_Agent_Research"]','New',0,2.5,0,1783092991994,1783727918059,1783203558653,replace('**Tradução para português do Brasil:**\n\n**Qual abordagem de renderização oferece transparência sobre as fontes utilizadas pela pesquisa na web?**\n\n[ ] A - Mostrar apenas o texto final, sem referências\n[ ] B - Exibir uma lista de fontes no topo e citações inline com domínio, título, URL e trecho\n[ ] C - Ocultar as URLs para evitar poluir a interface\n[ ] D - Apresentar apenas o domínio de cada fonte','\n',char(10)),replace('**Explicação para um adulto tech lead:**\n\nA pergunta trata de um requisito fundamental em sistemas de busca integrados a assistentes de IA: a **transparência na atribuição de fontes**. Em aplicações reais (ex.: search-augmented generation, RAG), o usuário precisa saber de onde vieram as informações para verificar credibilidade, evitar plágio e permitir aprofundamento.\n\n**Alternativa correta: B**\n\nA opção B descreve uma abordagem completa de renderização: lista de fontes no topo (sumário) + citações inline contendo domínio, título, URL e trecho. Isso resolve dois problemas simultaneamente:\n1. **Contextualização inline**: ao ler o texto gerado, o usuário vê a âncora da fonte imediatamente ao lado da afirmação.\n2. **Referência consolidada**: a lista no topo funciona como índice, permitindo visão panorâmica de todas as fontes utilizadas.\n\nEssa combinação atende ao princípio de *verificabilidade* (traceability) — o usuário pode clicar e ir direto ao trecho original, conferindo fidelidade entre a resposta gerada e a fonte.\n\n**Por que as demais estão incorretas:**\n\n- **A (mostrar apenas o texto final, sem referências)**: Viola o requisito de transparência. Sem referências, o usuário não tem como verificar a veracidade ou origem da informação, o que quebra a confiança no sistema.\n\n- **C (ocultar URLs para evitar poluir a interface)**: Embora a preocupação com poluição visual seja legítima, ocultar completamente as URLs sacrifica a transparência. A alternativa B já resolve isso ao exibir as URLs de forma estruturada (lista no topo + inline), o que é mais informativo e não menos limpo que esconder tudo.\n\n- **D (apresentar apenas o domínio)**: É insuficiente. Saber apenas o domínio (ex.: "wikipedia.org") não permite localizar o trecho exato usado. Faltam título, URL completa e snippet — elementos essenciais para verificação direta.','\n',char(10)),replace('Imagine que você fez uma pesquisa na internet para o dever de casa. A resposta que o computador te deu veio de vários sites diferentes.\n\n- **Opção A**: O computador simplesmente escreve a resposta e não te conta de onde tirou aquilo. Você não pode conferir se está certo.\n- **Opção B (a resposta certa)**: O computador mostra no topo uma lista dos sites que usou e, no meio do texto, coloca pequenas marquinhas com o nome do site, o título da página, o endereço e um pedacinho do que foi copiado. Assim você pode clicar e ver se é verdade.\n- **Opção C**: O computador esconde os endereços dos sites porque acha que vai poluir a tela. Mas aí você não sabe onde foi buscar a informação.\n- **Opção D**: O computador só mostra o nome grande do site (tipo "Wikipédia"), mas não mostra o endereço completo nem o trecho usado. Você não consegue achar o lugar exato.\n\nA opção B é a melhor porque é **transparente**: ela mostra tudo que você precisa para conferir se a resposta é confiável, igual a um professor que diz "olha, eu tirei isso daqui, pode ver".','\n',char(10)));
INSERT INTO cards VALUES('admin','card_1783092992019_5hlvr798f',465,'The model responds "ReadFile: main.',replace('The model responds "ReadFile: main.\n\nThe model responds "ReadFile: main.go". What is the next step executed by the coding assistant?\n[Resposta correta: O assistant lê o arquivo de fato, devolve o conteúdo ao modelo e só então o modelo gera a resposta final baseada nesse conteúdo. As demais pulam a execução real da ação ou transferem a leitura para o usuário.]\n\n[ ] A - It immediately returns the final response to the user without opening the file\n[ ] B - It actually reads the file and sends the content back to the model, which then generates the final response\n[ ] C - It asks the user to paste the file content\n[ ] D - It ignores the request and keeps generating text','\n',char(10)),'[ ] B - It actually reads the file and sends the content back to the model, which then generates the final response','["Domain_2::Tool_Design_MCP_Integration", "Domain_5::Context_Management_Reliability", "Scenario_4::Developer_Productivity"]','New',0,2.5,0,1783092992019,1783727921461,1783203558653,replace('**Tradução da Pergunta e Alternativas:**\n\nO modelo responde "ReadFile: main.\n\nO modelo responde "ReadFile: main.go". Qual é o próximo passo executado pelo assistente de codificação?\n\n[ ] A - Ele imediatamente retorna a resposta final para o usuário sem abrir o arquivo\n[ ] B - Ele de fato lê o arquivo e envia o conteúdo de volta para o modelo, que então gera a resposta final\n[ ] C - Ele pede que o usuário cole o conteúdo do arquivo\n[ ] D - Ele ignora a solicitação e continua gerando texto','\n',char(10)),replace('**Explicação para um Adulto (Tech Lead):**\n\nA resposta do modelo "ReadFile: main.go" é uma **chamada de ferramenta** (tool call). Em arquiteturas de agentes de IA, quando um modelo precisa executar uma ação concreta (como ler um arquivo), ele não faz isso diretamente — ele emite um comando estruturado indicando qual ferramenta deve ser invocada e com quais parâmetros. O runtime (ou middleware) do agente intercepta essa chamada, executa a ação real (no caso, a leitura do arquivo `main.go`), captura o resultado (o conteúdo do arquivo) e o retorna ao modelo como um novo turno de contexto. Somente de posse desse conteúdo o modelo pode formular a resposta final para o usuário.\n\n**Análise das alternativas:**\n\n- **Alternativa A (Errada):** Pular a execução real da ferramenta quebraria o fluxo de trabalho. O modelo ficaria sem os dados necessários para responder, tornando a resposta vazia ou incoerente. O propósito da chamada de ferramenta é justamente obter informações externas.\n- **Alternativa B (Correta):** Descreve precisamente o ciclo tool call → execução → retorno do resultado → geração da resposta final. É o comportamento esperado em qualquer framework de agentes bem implementado (LangChain, AutoGPT, OpenAI Function Calling, etc.).\n- **Alternativa C (Errada):** Transferir a responsabilidade para o usuário seria uma má experiência (UX) e quebraria a automação. O agente tem a capacidade de executar a leitura; perguntar ao usuário seria um retrocesso desnecessário.\n- **Alternativa D (Errada):** Ignorar a chamada de ferramenta anularia o propósito da interação. Se o modelo não agir sobre suas próprias solicitações de leitura de arquivo, o sistema não consegue cumprir tarefas que exigem acesso a dados externos.','\n',char(10)),replace('Imagine que você é um assistente robô e seu amigo humano pede: "Robô, leia o arquivo main.go para mim". Você responde: "Vou ler o arquivo main.go". Agora, o que você faz?\n\nA opção certa é a **B**: você realmente abre o arquivo, lê o que está escrito, e só depois conta para o seu amigo o que estava lá. É como quando sua mãe pede para você pegar um livro na estante: você primeiro vai até lá, pega o livro, e depois mostra para ela o que tem dentro. Você não pode simplesmente inventar o que está escrito (alternativa A ou D) nem pedir para ela mesma pegar o livro (alternativa C). O legal do robô é que ele faz o trabalho sozinho!\n\n**Resumindo:** O robô disse que vai ler — então ele lê de verdade e DEPOIS responde.','\n',char(10)));
INSERT INTO cards VALUES('admin','card_1783092992046_21181tkfa',466,'Why does a pure language model not read files on its own and how does tool use solve this?',replace('Why does a pure language model not read files on its own and how does tool use solve this?\n\nWhy does a pure language model not read files on its own and how does tool use solve this?\n[Resposta correta: Um language model puro apenas processa e retorna texto; o tool use injeta instruções para o modelo pedir ações, o sistema executa a ação real e devolve o resultado ao modelo. As demais partem da premissa falsa de que o modelo já lê arquivos ou atribuem a causa a rede e memória.]\n\n[ ] A - It reads files, but needs network permission; tool use only authenticates\n[ ] B - LMs only process text; tool use teaches the model to request actions, executes them and returns the result\n[ ] C - LMs do not read because they lack memory; tool use increases the context\n[ ] D - LMs read files, but tool use only improves the formatting of the response','\n',char(10)),'B - LMs only process text; tool use teaches the model to request actions, executes them and returns the result','["Domain_2::Tool_Design_MCP_Integration", "Domain_1::Agentic_Architecture_Orchestration", "Scenario_4::Developer_Productivity"]','New',0,2.5,0,1783092992046,1783727924677,1783203558653,replace('**Tradução para o português (Brasil):**\n\nPor que um modelo de linguagem puro não lê arquivos por conta própria e como o uso de ferramentas (tool use) resolve isso?\n\n[ ] A - Ele lê arquivos, mas precisa de permissão de rede; o uso de ferramentas apenas autentica.\n[ ] B - Modelos de linguagem apenas processam texto; o uso de ferramentas ensina o modelo a solicitar ações, executa-as e retorna o resultado.\n[ ] C - Modelos de linguagem não leem porque não têm memória; o uso de ferramentas aumenta o contexto.\n[ ] D - Modelos de linguagem leem arquivos, mas o uso de ferramentas apenas melhora a formatação da resposta.','\n',char(10)),replace('**Explicação didática para um adulto tech lead:**\n\nA alternativa correta é a B.\n\nUm modelo de linguagem puro (LLM) é, por definição, um sistema que recebe uma sequência de tokens textuais como entrada e produz uma sequência de tokens textuais como saída. O modelo não tem capacidade de fazer chamadas de sistema, acessar o sistema de arquivos do SO, executar HTTP requests ou interagir com qualquer recurso externo. Tudo o que ele "sabe" está contido nos pesos da rede neural, treinados a partir de grandes corpora de texto.\n\nO problema fundamental, portanto, é que o modelo não pode, por si só, ler um arquivo do disco, consultar uma API ou executar um comando SQL. Ele não "sabe" que existe um arquivo; ele apenas gera texto que *parece* ser uma resposta sobre um arquivo, mas sem acesso real.\n\nO "tool use" (uso de ferramentas) resolve isso ao criar um protocolo de duas camadas:\n\n1. O modelo é instruído (via system prompt e fine-tuning) a gerar, em vez de texto comum, uma requisição estruturada — por exemplo, uma string JSON indicando "quero chamar a função read_file com o parâmetro caminho=''dados.csv''".\n2. Um orquestrador (código externo ao modelo) intercepta essa saída, interpreta a requisição, executa a função real (no SO, na rede, etc.) e alimenta o resultado de volta ao modelo como parte do contexto.\n\nAssim, o modelo não "lê" o arquivo; ele solicita que alguém leia, e o resultado é colocado no prompt para ele processar. Isso resolve a limitação sem modificar a arquitetura do LLM.\n\n**Análise das alternativas incorretas:**\n\n- **A** — Falsa. O modelo puro *não* lê arquivos, independentemente de permissão de rede. O problema não é de permissão, e sim de arquitetura: o modelo não tem capacidade de executar I/O.\n- **C** — Falsa. A ausência de leitura de arquivos não se deve a falta de memória (contexto limitado). Mesmo com contexto infinito, o modelo continuaria sem conseguir acessar o sistema de arquivos. Tool use pode aumentar o contexto indiretamente, mas essa não é a razão de existir.\n- **D** — Falsa. Modelos de linguagem puros não leem arquivos. Tool use não é apenas sobre formatação; é sobre permitir que o modelo interaja com o mundo externo de forma factual, e não sobre estética de resposta.','\n',char(10)),replace('**Explicação para uma criança de 10 anos:**\n\nImagine que você tem um amigo muito inteligente que sabe responder muitas perguntas, mas ele está em uma sala fechada sem janelas e sem portas. Ele só ouve o que você fala e só pode falar de volta. Ele não consegue pegar um livro, abrir um site ou olhar para fora — ele só sabe o que já aprendeu antes.\n\nUm modelo de linguagem puro é exatamente assim: ele só recebe texto e só devolve texto. Ele não consegue "ler" um arquivo do seu computador porque ele não tem braços para pegar o arquivo.\n\nO "uso de ferramentas" (tool use) é como dar a ele um telefone mágico. Agora, quando ele precisa de uma informação que está em um arquivo, ele pode falar no telefone: "Por favor, leia o arquivo para mim!". Do outro lado, um robô (o sistema) ouve o pedido, vai até o arquivo, lê e conta o resultado para o modelo. O modelo, então, usa essa informação para responder você.\n\nEntão o modelo não lê o arquivo diretamente — ele pede ajuda a um "assistente" que lê para ele. É por isso que a resposta certa é a B: modelos de linguagem só processam texto, e o uso de ferramentas ensina o modelo a pedir ações, que são executadas por outro programa, e o resultado volta para ele.','\n',char(10)));
INSERT INTO cards VALUES('admin','card_1783092992072_6ggrrrfuc',467,'Which architecture benefit stems from Claude''s strength in tool use?',replace('Which architecture benefit stems from Claude''s strength in tool use?\n\nWhich architecture benefit stems from Claude''s strength in tool use?\n[Resposta correta: A força em tool use permite tarefas mais difíceis combinando tools, torna a plataforma extensível e melhora a segurança ao navegar o codebase sem indexação, geralmente sem enviar o codebase inteiro para fora. A opção C exagera a garantia (o texto diz "geralmente"), A e D confundem com outros temas.]\n\n[ ] A - It eliminates the need to write descriptions in the tools\n[ ] B - It is an extensible platform that combines and uses novel tools and navigates the codebase without indexing\n[ ] C - It guarantees that no data ever leaves the local machine in any scenario\n[ ] D - It removes the need for JSON validation on all calls','\n',char(10)),'[ ] B - It is an extensible platform that combines and uses novel tools and navigates the codebase without indexing','["Domain_2::Tool_Design_MCP_Integration", "Scenario_4::Developer_Productivity"]','New',0,2.5,0,1783092992072,1783727927864,1783203558653,replace('**Tradução para português do Brasil:**\n\nQual benefício de arquitetura decorre da força de Claude no uso de ferramentas (tool use)?\n\n[ ] A - Elimina a necessidade de escrever descrições nas ferramentas\n[ ] B - É uma plataforma extensível que combina e utiliza ferramentas novas e navega pelo codebase sem indexação\n[ ] C - Garante que nenhum dado jamais saia da máquina local em qualquer cenário\n[ ] D - Elimina a necessidade de validação JSON em todas as chamadas','\n',char(10)),replace('**Explicação didática para um adulto tech lead:**\n\nA pergunta aborda um conceito importante sobre a arquitetura de sistemas com LLMs: qual benefício arquitetural decorre especificamente da capacidade de Claude em usar ferramentas (tool use).\n\n**Alternativa correta: B**\n\nClaude''s strength in tool use allows it to be used as an extensible platform. O raciocínio é:\n\n1. **Combinação de ferramentas**: Claude pode orquestrar múltiplas ferramentas em sequência ou paralelamente para resolver tarefas complexas, agindo como um "cérebro" que decide qual ferramenta chamar e em qual ordem.\n\n2. **Extensibilidade**: Novas ferramentas podem ser adicionadas à plataforma sem necessidade de re-treinar o modelo — basta definir a ferramenta com uma descrição clara e Claude aprenderá a usá-la durante a interação.\n\n3. **Navegação no codebase sem indexação**: Diferente de abordagens tradicionais que exigem indexação prévia do código (como RAG com chunks), Claude pode navegar pelo codebase usando ferramentas como "read_file", "list_directory", "grep_search", etc., acessando arquivos sob demanda, sem precisar de um índice pré-construído.\n\n4. **Segurança de dados**: Essa abordagem geralmente não envia o codebase inteiro para fora da máquina local, pois Claude solicita apenas os arquivos específicos de que precisa, reduzindo a superfície de exposição de dados.\n\n**Por que as demais alternativas estão incorretas:**\n\n❌ **A** - "Elimina a necessidade de escrever descrições nas ferramentas": Isso é falso. Na verdade, a qualidade das descrições das ferramentas é crucial para que Claude saiba quando e como usá-las corretamente. Descrições bem escritas são um requisito fundamental, não algo eliminado.\n\n❌ **C** - "Garante que nenhum dado jamais saia da máquina local em qualquer cenário": Isso é uma afirmação absoluta e enganosa. O texto de referência diz "geralmente sem enviar o codebase inteiro para fora", o que é diferente de uma garantia absoluta. Depende da implementação e configuração específica. A palavra "garante" e "em qualquer cenário" tornam essa afirmação incorreta como benefício geral.\n\n❌ **D** - "Elimina a necessidade de validação JSON em todas as chamadas": Falso. As chamadas de ferramentas geralmente usam JSON para passar parâmetros, e a validação continua sendo necessária para garantir que os parâmetros estejam no formato correto. A validação JSON é uma prática de engenharia independente do tool use.','\n',char(10)),replace('Imagine que o Claude é como um super-herói que pode usar ferramentas diferentes para resolver problemas, igual um personagem de videogame que pode usar chave de fenda, martelo e computador.\n\nA pergunta quer saber: qual é a vantagem legal que o Claude ganha por ser tão bom em usar ferramentas?\n\nA resposta certa é a **B**: Claude vira uma "plataforma extensível" — isso é como um brinquedo que você pode ir adicionando peças novas. Ele pode combinar várias ferramentas para fazer coisas difíceis, e consegue andar pelo código do computador (o "codebase") sem precisar de um mapa gigante (indexação). É como se ele pudesse abrir gavetas uma por uma para procurar o que precisa, em vez de espalhar tudo no chão de uma vez.\n\nAs outras opções estão erradas porque:\n\n**A** - Não é verdade que ele não precisa de descrições. As descrições são super importantes, igual manual de instruções!\n\n**C** - Diz que "nenhum dado jamais sai do computador", mas isso não é garantido. Às vezes alguns dados podem sair, não é 100% seguro sempre.\n\n**D** - Diz que não precisa mais validar JSON, mas isso é como dizer que não precisa mais conferir se a peça do quebra-cabeça encaixa direito. Ainda precisa!','\n',char(10)));
INSERT INTO cards VALUES('admin','card_1783092992100_vjx8okie1',468,'In the Agent SDK, how do you limit the tools that Claude can use in a query() call?',replace('In the Agent SDK, how do you limit the tools that Claude can use in a query() call?\n\nIn the Agent SDK, how do you limit the tools that Claude can use in a query() call?\n[Resposta correta: Passar options.allowedTools restringe as tools disponíveis, equivalente à flag --allowedTools do CLI. Remover input_schema quebraria a definição, max_uses é da web search e fine_grained não controla disponibilidade de tools.]\n\n[ ] A - By removing the input_schema from the unwanted tools\n[ ] B - By passing options.allowedTools, for example { allowedTools: ["Read", "Glob"] }\n[ ] C - By setting max_uses to zero for each tool\n[ ] D - By disabling fine_grained tool calling','\n',char(10)),'B - By passing options.allowedTools, for example { allowedTools: ["Read", "Glob"] }','["Domain_2::Tool_Design_MCP_Integration", "Domain_1::Agentic_Architecture_Orchestration", "Scenario_4::Developer_Productivity"]','New',0,2.5,0,1783092992100,1783727931648,1783203558653,replace('**Tradução:**\n\nPergunta: "No Agent SDK, como você limita as ferramentas (tools) que o Claude pode usar em uma chamada query()?"\n\nAlternativas:\n[ ] A - Removendo o input_schema das ferramentas indesejadas\n[ ] B - Passando options.allowedTools, por exemplo { allowedTools: ["Read", "Glob"] }\n[ ] C - Definindo max_uses como zero para cada ferramenta\n[ ] D - Desabilitando a chamada de ferramenta refinada (fine_grained tool calling)','\n',char(10)),replace('**Explicação para um adulto tech lead:**\n\nA alternativa **B** é a correta porque o Agent SDK (provavelmente o SDK da Anthropic para interagir com Claude) expõe explicitamente a opção `allowedTools` no objeto `options` do método `query()`. Essa opção permite listar exatamente quais ferramentas o Claude pode invocar durante a execução, funcionando de forma análoga à flag `--allowedTools` na interface de linha de comando (CLI). É a maneira direta e documentada de restringir o conjunto de ferramentas disponíveis.\n\n**Por que as demais estão erradas:**\n\n- **A**: Remover o `input_schema` de uma definição de ferramenta (tool definition) quebra a validação da própria ferramenta. O SDK utiliza o `input_schema` (normalmente em JSON Schema) para validar os parâmetros que o Claude envia. Sem ele, a ferramenta não pode ser chamada corretamente e, em vez de simplesmente ficar indisponível, pode causar erros de execução ou falhas na serialização. É um approach invasivo e não recomendado.\n\n- **C**: `max_uses` é um parâmetro que, quando existe, está associado a ferramentas de busca na web (web search) para limitar quantas vezes aquela ferramenta específica pode ser usada em uma conversa. Não é um mecanismo geral para desabilitar ferramentas — definir como zero pode simplesmente ignorar o limite ou causar comportamento indefinido, não sendo a forma correta de remover a ferramenta do conjunto disponível.\n\n- **D**: "Fine-grained tool calling" (chamada de ferramenta refinada) é um recurso que permite ao modelo decidir quais ferramentas chamar de forma mais granular ou com maior controle sobre parâmetros. Desabilitar isso não impede que ferramentas sejam chamadas; apenas remove o refinamento no controle, possivelmente fazendo o modelo voltar a um comportamento mais básico. Não é um mecanismo de filtragem de quais ferramentas estão disponíveis.','\n',char(10)),replace('**Explicação para uma criança de 10 anos:**\n\nImagina que o Claude é um robô ajudante que pode usar várias ferramentas, como uma "Lupa" (para ler arquivos) e um "Globo" (para olhar o mundo todo). Quando você pede ajuda para ele com o comando `query()`, você pode dizer: "Pode usar só a Lupa e o Globo, nada mais!". Para fazer isso, você usa o `options.allowedTools`, que é como dar uma lista do que ele pode pegar na caixa de ferramentas.\n\nSe você tentar esconder as outras ferramentas tirando as instruções de uso delas (a opção A), o robô fica confuso e não sabe como usar nenhuma. Se você tentar dizer "use zero vezes" (opção C), isso não funciona para todas as ferramentas — é como tentar calçar uma luva no pé. E desligar o "modo refinado" (opção D) é como tirar o ajuste fino do robô, mas ele ainda pode pegar qualquer ferramenta. \n\nEntão, o jeito certo é simplesmente falar na lista: "Robô, use só essas ferramentas aqui: { allowedTools: [''Read'', ''Glob''] }" — isso funciona direitinho!\n\n**Resposta correta: B**','\n',char(10)));
INSERT INTO cards VALUES('admin','card_1783092992126_hzk5im4qi',469,'You want to create tools for an MCP server in Python without writing JSON schema manually.',replace('You want to create tools for an MCP server in Python without writing JSON schema manually.\n\nYou want to create tools for an MCP server in Python without writing JSON schema manually. What does the official SDK offer?\n[Resposta correta: O SDK permite definir tools com o decorator @mcp.tool usando type hints e Field do Pydantic, gerando o schema correto automaticamente. As demais inventam um gerador externo, confundem com web search ou negam o recurso do SDK.]\n\n[ ] A - An external schema generator that runs before the deploy\n[ ] B - @mcp.tool decorators with type hints and Pydantic''s Field, generating the schema automatically\n[ ] C - An allowed_domains field that dispenses with the schema\n[ ] D - Writing the schema by hand remains mandatory','\n',char(10)),'[ ] B - @mcp.tool decorators with type hints and Pydantic''s Field, generating the schema automatically','["Domain_2::Tool_Design_MCP_Integration", "Domain_4::Prompt_Engineering_Structured_Output", "Scenario_4::Developer_Productivity"]','New',0,2.5,0,1783092992126,1783727934952,1783203558653,replace('**Tradução para português do Brasil:**\n\nVocê quer criar ferramentas para um servidor MCP em Python sem escrever JSON schema manualmente. O que o SDK oficial oferece?\n\n[ ] A - Um gerador de schema externo que roda antes do deploy\n[ ] B - Decoradores @mcp.tool com type hints e Field do Pydantic, gerando o schema automaticamente\n[ ] C - Um campo allowed_domains que dispensa o schema\n[ ] D - Escrever o schema manualmente continua obrigatório','\n',char(10)),replace('**Explicação para adulto tech lead:**\n\nA alternativa correta é a B.\n\nO SDK oficial do MCP (Model Context Protocol) para Python oferece uma abordagem elegante e Pythonica para definição de ferramentas (tools). Através do decorador `@mcp.tool`, você pode anotar funções que serão expostas como ferramentas. O que elimina a necessidade de escrever JSON schema manualmente é o uso combinado de:\n\n- **Type hints**: os parâmetros da função já trazem informação de tipo (str, int, list, etc.).\n- **Pydantic''s Field**: para validações mais ricas, descrições, valores padrão, etc.\n- O SDK, em tempo de execução, inspeciona a assinatura da função e gera automaticamente o JSON Schema correspondente, que será usado pelo protocolo MCP.\n\n**Por que as demais estão erradas:**\n\n- **Alternativa A**: Não há um "gerador externo que roda antes do deploy". O schema é gerado dinamicamente pelo SDK, não em uma etapa externa de build/deploy.\n- **Alternativa C**: O campo `allowed_domains` não existe no contexto de definição de tools do MCP. Isso parece uma confusão com alguma configuração de segurança ou web scraping, não com geração de schema.\n- **Alternativa D**: É justamente o contrário. O SDK foi projetado para que você NÃO precise escrever schema manualmente. Essa alternativa nega o recurso central oferecido.','\n',char(10)),replace('Imagine que você está ensinando o computador a fazer várias tarefas, como somar números ou buscar informações. Para isso, você precisa explicar direitinho que tipo de informação cada tarefa precisa receber (texto, número, lista...).\n\nAntigamente, você teria que escrever essa explicação em um "idioma" complicado chamado JSON Schema, cheio de chaves e colchetes, e qualquer errinho podia quebrar tudo.\n\nAgora, o SDK do MCP (um kit de ferramentas para programadores) oferece um jeito muito mais fácil: você escreve a tarefa como uma função normal de Python, coloca um "carimbo mágico" chamado `@mcp.tool` em cima dela, e usa type hints (coisinhas que já dizem se é texto, número, etc.). Pronto! O computador descobre sozinho qual é o esquema e faz tudo automaticamente. É como ter um robô que organiza seu quarto sem você precisar dar instruções super detalhadas — ele já sabe onde cada coisa vai.\n\nA resposta certa é a **B**: você usa `@mcp.tool` com dicas de tipo e o Pydantic Field, e o schema é gerado sozinho. As outras opções ou inventam ferramentas externas (A), falam de "domínios permitidos" que não têm nada a ver (C), ou dizem que você ainda precisa escrever tudo na mão, o que não é verdade (D).','\n',char(10)));
INSERT INTO cards VALUES('admin','card_1783092992169_53r43d9ao',470,'Which line correctly initializes an MCP server with FastMCP in the Python SDK?',replace('Which line correctly initializes an MCP server with FastMCP in the Python SDK?\n\nWhich line correctly initializes an MCP server with FastMCP in the Python SDK?\n[Resposta correta: A inicialização usa from mcp.server.fastmcp import FastMCP seguido de mcp = FastMCP("DocumentMCP", log_level="ERROR"). As demais usam métodos inexistentes ou misturam parâmetros de outras tools.]\n\n[ ] A - mcp = MCP.start("DocumentMCP")\n[ ] B - from mcp.server.fastmcp import FastMCP and then mcp = FastMCP("DocumentMCP", log_level="ERROR")\n[ ] C - mcp = FastMCP.connect(allowed_domains=["nih.gov"])\n[ ] D - import fastmcp and then fastmcp.run()','\n',char(10)),'B - from mcp.server.fastmcp import FastMCP and then mcp = FastMCP("DocumentMCP", log_level="ERROR")','["Domain_2::Tool_Design_MCP_Integration", "Scenario_4::Developer_Productivity"]','New',0,2.5,0,1783092992169,1783727938223,1783203558653,replace('**Tradução para português do Brasil:**\n\nQual linha inicializa corretamente um servidor MCP com FastMCP no SDK Python?\n\n[ ] A - mcp = MCP.start("DocumentMCP")\n[ ] B - from mcp.server.fastmcp import FastMCP e em seguida mcp = FastMCP("DocumentMCP", log_level="ERROR")\n[ ] C - mcp = FastMCP.connect(allowed_domains=["nih.gov"])\n[ ] D - import fastmcp e em seguida fastmcp.run()','\n',char(10)),replace('**Explicação para adulto tech lead:**\n\n**Resposta correta: B**\n\nA biblioteca MCP (Model Context Protocol) da Anthropic fornece, em seu SDK Python, o módulo `mcp.server.fastmcp`, que expõe a classe `FastMCP`. A maneira correta de instanciar um servidor FastMCP é importar essa classe e criar uma instância passando o nome do servidor (primeiro argumento obrigatório) e opcionalmente parâmetros como `log_level`.\n\n**Análise das alternativas incorretas:**\n\n- **A - `mcp = MCP.start("DocumentMCP")`** — Incorreta pois `MCP` é uma classe de mais baixo nível no SDK (não FastMCP). Além disso, `start()` é um método de instância ou classe que não existe para esse propósito de inicialização direta. Não há um construtor ou factory method `start` que retorne um servidor FastMCP configurado.\n\n- **C - `mcp = FastMCP.connect(allowed_domains=["nih.gov"])`** — Incorreta pois `FastMCP` não possui um método de classe ou instância chamado `connect()`. Os parâmetros `allowed_domains` também não fazem parte da API de inicialização do `FastMCP` — eles pertencem, no máximo, a configurações de segurança de ferramentas específicas, não à criação do servidor. O correto é usar o construtor `FastMCP(...)`.\n\n- **D - `import fastmcp` e em seguida `fastmcp.run()`** — Incorreta pois o módulo não se chama simplesmente `fastmcp`, e sim `mcp.server.fastmcp`. Além disso, `run()` não existe como função autônoma no módulo — o método correto para rodar o servidor é chamado em uma instância de `FastMCP`, algo como `mcp.run()`.\n\n**Resumo técnico:** A letra B reflete exatamente a documentação oficial: `from mcp.server.fastmcp import FastMCP` seguido de `mcp = FastMCP("NomeDoServidor", log_level="ERROR")`.','\n',char(10)),replace('**Explicação para uma criança de 10 anos:**\n\nImagine que você quer criar um robô mensageiro (o servidor MCP) que ajuda outros programas a conversarem entre si. O "FastMCP" é como um kit de montagem para fazer esse robô.\n\nA forma certa de começar é:\n\n1. Pegar a peça certa da caixa de ferramentas: `from mcp.server.fastmcp import FastMCP`\n2. Montar o robô com um nome e algumas instruções: `mcp = FastMCP("DocumentMCP", log_level="ERROR")`\n\nAs outras opções estão erradas porque:\n\n- A opção A tenta ligar o robô antes mesmo de montá-lo (`MCP.start` não funciona assim).\n- A opção C tenta usar um comando de "conectar" que não existe no manual do FastMCP (`FastMCP.connect` não é um método real).\n- A opção D tenta importar a caixa inteira (`import fastmcp`) em vez de pegar só a peça necessária, e depois tenta dar `fastmcp.run()` como se a caixa inteira fosse o robô — mas não é.\n\nEntão, a resposta certa é a **B**, porque segue o manual de instruções direitinho!','\n',char(10)));
INSERT INTO cards VALUES('admin','card_1783092992257_5em3rjj7l',471,'What is Pydantic''s Field for when defining parameters of an MCP tool?',replace('What is Pydantic''s Field for when defining parameters of an MCP tool?\n\nWhat is Pydantic''s Field for when defining parameters of an MCP tool?\n[Resposta correta: Field, por exemplo Field(description=...), fornece a descrição de cada argumento para Claude entender o que o parâmetro espera. As demais atribuem a Field funções de autenticação, limite de uso ou registro de tool, que não são suas.]\n\n[ ] A - Validating the authentication token of the MCP server\n[ ] B - Providing the description of each argument, helping Claude understand what the parameter expects\n[ ] C - Limiting how many times the parameter can be used\n[ ] D - Replacing the @mcp.tool decorator','\n',char(10)),'B - Providing the description of each argument, helping Claude understand what the parameter expects','["Domain_2::Tool_Design_MCP_Integration", "Scenario_4::Developer_Productivity"]','New',0,2.5,0,1783092992257,1783727941503,1783203558653,replace('**Tradução para português do Brasil:**\n\n**Pergunta:** Para que serve o Field do Pydantic ao definir parâmetros de uma ferramenta MCP?\n\n**Alternativas:**\n[ ] A - Validar o token de autenticação do servidor MCP\n[ ] B - Fornecer a descrição de cada argumento, ajudando o Claude a entender o que o parâmetro espera\n[ ] C - Limitar quantas vezes o parâmetro pode ser usado\n[ ] D - Substituir o decorador @mcp.tool','\n',char(10)),replace('**Explicação para um adulto tech lead:**\n\nO Pydantic é uma biblioteca de validação de dados baseada em type hints do Python. O `Field` é uma função do Pydantic que permite enriquecer a definição de campos de modelos com metadados adicionais, como `description`, `default`, `alias`, `gt`, `lt`, `max_length`, entre outros.\n\nNo contexto de MCP (Model Context Protocol), as ferramentas (tools) expõem funcionalidades para o modelo de linguagem (Claude) invocar. Quando você define uma ferramenta MCP (via `@mcp.tool` ou similar), os parâmetros da função Python são convertidos em um schema JSON que o modelo interpreta. O `Field(description=...)` é usado nesses parâmetros para fornecer uma descrição semântica clara do que cada parâmetro representa, qual formato espera, etc. Essa descrição é incluída no schema do tool e enviada ao modelo, que a utiliza para entender como preencher corretamente os argumentos durante a chamada.\n\n**Análise das alternativas:**\n\n- **A - Validar o token de autenticação do servidor MCP**: Incorreto. O `Field` do Pydantic não tem qualquer relação com autenticação. Tokens de autenticação são gerenciados por mecanismos como headers HTTP, OAuth, chaves de API, etc., e não fazem parte do escopo de definição de schemas de parâmetros.\n\n- **B - Fornecer a descrição de cada argumento, ajudando o Claude a entender o que o parâmetro espera**: Correto. Esta é a finalidade principal do `Field(description=...)` ao definir parâmetros de tools MCP. A descrição é utilizada pelo modelo para compreender o propósito e as regras de cada parâmetro.\n\n- **C - Limitar quantas vezes o parâmetro pode ser usado**: Incorreto. O `Field` pode definir constraints como valores mínimos/máximos (ex.: `gt`, `lt`), tamanho de strings (`min_length`, `max_length`), etc., mas não controla frequência de uso ou rate limiting. Limitar quantidade de uso de um parâmetro ou de uma tool é responsabilidade de uma camada de aplicação externa (middleware, gateway API, etc.).\n\n- **D - Substituir o decorador @mcp.tool**: Incorreto. O `@mcp.tool` é o decorador que registra uma função como uma ferramenta MCP, expondo-a ao modelo. O `Field` é usado dentro da assinatura da função para enriquecer a definição de cada parâmetro individual. São conceitos complementares, não substitutos.','\n',char(10)),replace('Imagine que você está ensinando um robô inteligente a usar suas ferramentas. Uma dessas ferramentas é um "pesquisador de receitas". Quando você diz ao robô como usar essa ferramenta, você precisa explicar direitinho o que cada "botão" (parâmetro) faz.\n\nO `Field` do Pydantic é como um **rótulo ou etiqueta** que você coloca em cada botão para o robô entender. Por exemplo, se a ferramenta precisa de um ingrediente, você escreve: `Field(description="O nome do ingrediente que você quer usar na receita")`. Assim, o robô sabe que ali deve colocar "farinha", "açúcar", etc.\n\nAs outras alternativas estão erradas porque:\n- **A** - O `Field` não é usado para verificar se o robô tem permissão (senha) para usar a ferramenta. Isso é outra coisa.\n- **C** - O `Field` não controla quantas vezes você pode usar um botão. Isso seria como um limite de "só pode usar 3 vezes por dia", que não é função dele.\n- **D** - O `Field` não substitui o "@mcp.tool". O "@mcp.tool" é o que transforma uma função comum em uma ferramenta que o robô pode usar. O `Field` só ajuda a descrever os botões dessa ferramenta.\n\nEntão, resposta certa: **B** - O `Field` serve para dar uma descrição de cada argumento, ajudando o robô (Claude) a entender o que cada parâmetro espera.','\n',char(10)));
INSERT INTO cards VALUES('admin','card_1783092992286_1v7r22pvy',472,'In the @mcp.',replace('In the @mcp.\n\nIn the @mcp.tool decorator, what is the function of the name and description fields?\n[Resposta correta: name é o identificador da tool e description explica o que ela faz, orientando Claude sobre quando chamá-la. As demais trocam as funções dos campos ou os confundem com tipo de retorno, schema e max_uses.]\n\n[ ] A - name defines the return type and description defines the arguments\n[ ] B - name is the tool identifier and description explains what it does, helping Claude decide when to call it\n[ ] C - Both are optional and ignored by the SDK\n[ ] D - name limits the number of uses and description defines the schema','\n',char(10)),'B - name is the tool identifier and description explains what it does, helping Claude decide when to call it','["Domain_2::Tool_Design_MCP_Integration", "Scenario_1::Customer_Support_Agent"]','New',0,2.5,0,1783092992286,1783727944846,1783203558653,replace('**Tradução para português do Brasil:**\n\nNo decorador @mcp.tool, qual é a função dos campos name e description?\n\n[ ] A - name define o tipo de retorno e description define os argumentos\n[ ] B - name é o identificador da tool e description explica o que ela faz, ajudando Claude a decidir quando chamá-la\n[ ] C - Ambos são opcionais e ignorados pelo SDK\n[ ] D - name limita o número de usos e description define o schema','\n',char(10)),replace('**Explicação técnica:**\n\nNo MCP (Model Context Protocol), o decorador `@mcp.tool` é usado para registrar ferramentas que o modelo de linguagem (Claude) pode invocar. Os campos `name` e `description` têm papéis específicos e fundamentais:\n\n- **`name`**: Define o identificador único da ferramenta. É usado internamente pelo protocolo para referenciar a tool e pelo modelo para invocá-la. Deve ser único no contexto do servidor MCP.\n\n- **`description`**: Fornece uma explicação semântica sobre o propósito e comportamento da ferramenta. O modelo (Claude) utiliza essa descrição para entender **quando** e **por que** chamar a tool, com base no contexto da conversa. Sem uma descrição clara, o modelo pode não identificar corretamente a oportunidade de uso.\n\n**Análise das alternativas:**\n\n- **Alternativa A (Incorreta)**: O tipo de retorno é definido pela tipagem da função Python, não pelo campo `name`. Os argumentos são definidos pelos parâmetros da função, não pelo `description`.\n\n- **Alternativa B (Correta)**: Descreve precisamente as funções de cada campo. O `name` é o identificador da tool, e o `description` orienta o modelo sobre quando utilizá-la.\n\n- **Alternativa C (Incorreta)**: Ambos os campos são obrigatórios ou, no mínimo, essenciais para o funcionamento adequado. O `name` é obrigatório para identificar a tool; o `description` é altamente recomendado para que o modelo saiba quando usar a ferramenta. Ignorá-los quebraria a funcionalidade.\n\n- **Alternativa D (Incorreta)**: O número de usos não é controlado pelo campo `name` — isso seria uma configuração de rate limiting ou permissões, fora do decorador. O schema dos argumentos é inferido automaticamente dos parâmetros da função, não definido pelo `description`.','\n',char(10)),replace('Imagine que você tem um robô ajudante chamado Claude. Você pode dar a ele algumas ferramentas especiais, como uma calculadora ou um dicionário.\n\nQuando você ensina uma ferramenta nova para o Claude, você precisa dizer duas coisas importantes:\n1. **O nome da ferramenta** (`name`) — tipo "calculadora" ou "dicionário". É assim que o Claude sabe qual ferramenta você está dando a ele.\n2. **O que ela faz** (`description`) — tipo "essa calculadora soma e multiplica números" ou "esse dicionário mostra o significado das palavras". É assim que o Claude sabe quando ele deve usar cada ferramenta.\n\nSe você só desse o nome, o Claude não saberia para que serve. Se só desse a descrição, ele não saberia como chamar a ferramenta.\n\nPor isso a resposta correta é a letra B: o **name** é como o apelido da ferramenta (identificador) e o **description** explica o que ela faz, ajudando o Claude a decidir quando usá-la.\n\nAs outras respostas estão erradas porque:\n- A: O nome não define o tipo de resposta, e a descrição não define os argumentos.\n- C: Os dois campos são importantes, não podem ser ignorados.\n- D: O nome não controla quantas vezes você pode usar a ferramenta, e a descrição não define o esquema dos dados.','\n',char(10)));
INSERT INTO cards VALUES('admin','card_1783092992315_cmrohl11t',473,'How should a Python MCP tool signal an error, for example when the doc_id does not exist?',replace('How should a Python MCP tool signal an error, for example when the doc_id does not exist?\n\nHow should a Python MCP tool signal an error, for example when the doc_id does not exist?\n[Resposta correta: O tratamento de erro se integra naturalmente via exceptions Python, como levantar ValueError quando o doc_id não existe. Retornar string vazia esconde o erro, is_error é campo do tool_result e não do decorator, e a web search é irrelevante ao caso.]\n\n[ ] A - By returning an empty string\n[ ] B - By raising a Python exception, such as ValueError\n[ ] C - By setting is_error directly in the decorator\n[ ] D - By calling the web search tool to look up the doc_id','\n',char(10)),'B - By raising a Python exception, such as ValueError','["Domain_2::Tool_Design_MCP_Integration", "Domain_4::Prompt_Engineering_Structured_Output", "Scenario_6::Structured_Data_Extraction"]','New',0,2.5,0,1783092992315,1783727949452,1783203558653,replace('**Tradução para português do Brasil:**\n\n**Pergunta:** Como uma ferramenta MCP em Python deve sinalizar um erro, por exemplo, quando o doc_id não existe?\n\n**Alternativas:**\n[ ] A - Retornando uma string vazia\n[ ] B - Levantando uma exceção Python, como ValueError\n[ ] C - Definindo is_error diretamente no decorador\n[ ] D - Chamando a ferramenta de busca na web para localizar o doc_id','\n',char(10)),replace('**Explicação didática para um adulto tech lead:**\n\nNo contexto do Model Context Protocol (MCP), ferramentas implementadas em Python devem sinalizar erros utilizando o mecanismo nativo de exceções da linguagem. A alternativa **B** é a correta porque:\n\n1. **Mecanismo idiomático Python**: Levantar exceções como `ValueError` é a forma padrão e esperada de indicar falhas em Python. O framework MCP captura essas exceções e as traduz para o formato de erro adequado no protocolo.\n\n2. **Por que as outras estão erradas:**\n   - **A (string vazia)**: Retornar uma string vazia é ambíguo — não diferencia entre "documento não encontrado" e "documento existe mas está vazio". Isso esconde o erro e pode levar a comportamentos inesperados no cliente.\n   - **C (is_error no decorador)**: `is_error` é um campo opcional presente no `tool_result`, não no decorador da ferramenta. Ele é preenchido automaticamente pelo runtime MCP quando uma exceção é levantada, não devendo ser configurado manualmente no nível do decorator.\n   - **D (chamar busca web)**: Redirecionar para outra ferramenta para tratar um erro local é uma abordagem incorreta e ineficiente. A responsabilidade de sinalizar o erro é da própria ferramenta, não de uma ferramenta externa.','\n',char(10)),replace('**Explicação para uma criança de 10 anos:**\n\nImagine que você tem uma caixa de brinquedos e alguém te pede: "Me dá o brinquedo que está na etiqueta ''ABC''." Se essa etiqueta não existe na sua caixa, o que você faz?\n\n- Você **não** deve entregar uma caixa vazia (isso é como retornar uma string vazia — a pessoa fica sem saber se o brinquedo não existe ou se você esqueceu de colocar algo).\n- Você **não** deve sair perguntando para outras pessoas se elas têm esse brinquedo (isso é como chamar outra ferramenta).\n- O melhor é **avisar claramente**: "Essa etiqueta não existe na minha caixa!" Em Python, a gente faz isso levantando a mão e dizendo "ValueError: doc_id não encontrado". Assim quem pediu sabe exatamente o que aconteceu.\n\nEntão a resposta certa é a **B**: levantar uma exceção, que é o jeito do Python dizer "Ops, deu erro aqui!"','\n',char(10)));
INSERT INTO cards VALUES('admin','card_1783092992354_53m77p7kh',474,'Which set of benefits characterizes the use of SDK decorators instead of manual JSON schema?',replace('Which set of benefits characterizes the use of SDK decorators instead of manual JSON schema?\n\nWhich set of benefits characterizes the use of SDK decorators instead of manual JSON schema?\n[Resposta correta: Os decorators eliminam o JSON manual, usam type hints para validação, descrições para orientar Claude, exceptions Python para erros e registram a tool automaticamente. As demais contradizem esses pontos ao exigir schema ou registro manual.]\n\n[ ] A - Manual schema mandatory, but with fewer lines\n[ ] B - No manual JSON, validation by type hints, clear descriptions, errors via exceptions and automatic registration by the decorator\n[ ] C - Validation only at runtime without type hints\n[ ] D - Manual registration of each tool in a configuration file','\n',char(10)),'B - No manual JSON, validation by type hints, clear descriptions, errors via exceptions and automatic registration by the decorator','["Domain_2::Tool_Design_MCP_Integration", "Domain_4::Prompt_Engineering_Structured_Output", "Scenario_4::Developer_Productivity"]','New',0,2.5,0,1783092992354,1783727952549,1783203558653,NULL,replace('**Tradução da Pergunta:**  \nQual conjunto de benefícios caracteriza o uso de decorators do SDK em vez do JSON schema manual?\n\n**Tradução das Alternativas:**  \n[ ] A - Schema manual obrigatório, mas com menos linhas  \n[ ] B - Sem JSON manual, validação por type hints, descrições claras, erros via exceções e registro automático pelo decorator  \n[ ] C - Validação apenas em tempo de execução, sem type hints  \n[ ] D - Registro manual de cada tool em um arquivo de configuração  \n\n---  \n\n**Explicação para um adulto tech lead:**\n\nA alternativa correta é a **B**.\n\nA pergunta trata da diferença entre usar decorators do SDK (como `@tool` do Anthropic SDK ou decorators similares em frameworks como LangChain, LlamaIndex, etc.) versus escrever manualmente schemas JSON para definir ferramentas (tools) que serão expostas a modelos de linguagem como o Claude.\n\n**Por que a B é a correta:**  \nOs decorators oferecem exatamente os benefícios listados:  \n1. **Eliminação do JSON manual** — o desenvolvedor não precisa escrever o schema JSON bruto; o decorator gera o schema automaticamente a partir da assinatura da função.  \n2. **Validação por type hints** — os tipos Python (str, int, list, etc.) são usados para inferir o tipo dos parâmetros no schema, garantindo consistência entre o código e a definição da tool.  \n3. **Descrições claras** — docstrings e anotações (ex.: `Annotated[str, "descrição"]`) são utilizadas para gerar as descrições dos parâmetros no schema.  \n4. **Erros via exceções** — em vez de retornar strings de erro que precisam ser tratadas manualmente no schema, o código pode lançar exceções Python que são capturadas e tratadas adequadamente.  \n5. **Registro automático** — o decorator registra a tool em uma lista ou estrutura interna, eliminando a necessidade de mantê-la em um arquivo de configuração separado.\n\n**Por que as demais estão erradas:**  \n- **A** — afirma que o schema manual é obrigatório. Isso é falso, pois o decorator gera o schema automaticamente.  \n- **C** — diz que a validação ocorre apenas em tempo de execução e sem type hints. Na verdade, os decorators permitem validação estática (pelo interpretador Python) e uso de type hints.  \n- **D** — afirma que é necessário registrar cada tool manualmente em um arquivo de configuração. Isso contradiz justamente um dos principais benefícios dos decorators: o registro automático.','\n',char(10)),replace('Imagine que você tem que ensinar um robô a fazer várias tarefas, como somar números ou buscar informações. Você pode escrever as instruções em uma linguagem complicada (JSON manual) ou usar uma "etiqueta mágica" (decorator) que já faz quase tudo sozinho.\n\nA alternativa **B** está certa porque diz que, usando a etiqueta mágica:  \n- Você não precisa escrever instruções complicadas (sem JSON manual).  \n- O robô entende os tipos de dados automaticamente (validação por type hints).  \n- Você pode dar descrições claras do que cada coisa faz.  \n- Se algo der errado, o robô avisa com um "sinal de erro" (exceções).  \n- A etiqueta mágica já cadastra a tarefa sozinha, sem você precisar anotar em nenhum lugar.\n\nAs outras opções estão erradas porque:  \n- A diz que você ainda precisa escrever as instruções complicadas.  \n- C diz que o robô só descobre os tipos quando está executando a tarefa, e sem ajuda visual.  \n- D diz que você tem que anotar cada tarefa em um caderninho separado, o que dá mais trabalho.','\n',char(10)));
INSERT INTO cards VALUES('admin','card_1783092992384_el2qu8wgp',475,'A flow requires verifying identity before processing a refund, with financial risk if the order fails.',replace('A flow requires verifying identity before processing a refund, with financial risk if the order fails.\n\nA flow requires verifying identity before processing a refund, with financial risk if the order fails. Which approach guarantees the sequence?\n[Resposta correta: Quando erros têm consequências financeiras ou legais, o controle de ordem é problema de orquestração e deve usar código determinístico, não a conformidade probabilística do LLM. Prompt e few-shot não garantem a ordem, e remover a ferramenta impede o próprio reembolso, tratando disponibilidade em vez de orquestração.]\n\n[ ] A - Instruct the order in the system prompt and trust the model''s compliance\n[ ] B - Use programmatic enforcement with deterministic code to control the orchestration\n[ ] C - Remove the refund tool from the allowedTools list\n[ ] D - Add few-shot examples showing the correct order','\n',char(10)),'[ ] B - Use programmatic enforcement with deterministic code to control the orchestration','["Domain_1::Agentic_Architecture_Orchestration", "Domain_2::Tool_Design_MCP_Integration", "Domain_5::Context_Management_Reliability", "Scenario_1::Customer_Support_Agent"]','New',0,2.5,0,1783092992384,1783727956133,1783203558653,replace('**Tradução para português do Brasil:**\n\n**Pergunta:** Um fluxo exige verificar a identidade antes de processar um reembolso, com risco financeiro se o pedido falhar. Qual abordagem garante a sequência?\n\n[ ] A - Instruir a ordem no prompt do sistema e confiar na conformidade do modelo\n[ ] B - Usar imposição programática com código determinístico para controlar a orquestração\n[ ] C - Remover a ferramenta de reembolso da lista de allowedTools\n[ ] D - Adicionar exemplos few-shot mostrando a ordem correta','\n',char(10)),replace('**Explicação técnica para um adulto tech lead:**\n\n**Alternativa correta: B**\n\nA questão trata de um problema clássico de orquestração em sistemas que utilizam LLMs (Large Language Models). Quando há risco financeiro ou legal envolvido, não se pode confiar no comportamento probabilístico de um modelo de linguagem para garantir a sequência correta de operações.\n\n**Por que B é a resposta correta:**\n- Código determinístico (programmatic enforcement) garante que a verificação de identidade ocorra antes do reembolso de forma imperativa e incondicional.\n- O LLM é utilizado apenas para tarefas onde sua natureza probabilística é aceitável (ex.: interpretação de linguagem natural), mas a orquestração fica a cargo de um controlador tradicional (código).\n- Isso segue o princípio de separação de responsabilidades: lógica de negócio crítica não deve depender da "boa vontade" do modelo.\n\n**Por que as demais estão erradas:**\n\n- **A (Instruir no prompt do sistema e confiar na conformidade):** É ingênuo confiar que o modelo sempre seguirá instruções de ordem, especialmente em cenários complexos ou com prompts adversários. LLMs são probabilísticos — mesmo com 99% de acerto, 1% de falha em operações financeiras pode ser inaceitável.\n\n- **C (Remover a ferramenta de reembolso da lista):** Isso quebra o fluxo por completo — se a ferramenta não está disponível, o reembolso jamais será processado. Resolve o problema de ordem matando a funcionalidade, o que não é uma solução válida. Além disso, confunde problema de orquestração com problema de disponibilidade.\n\n- **D (Adicionar exemplos few-shot):** Few-shot pode melhorar a aderência, mas ainda é uma abordagem probabilística. O modelo pode ignorar os exemplos em certos contextos, e não há garantia formal de que a sequência será respeitada.\n\n**Conclusão técnica:** Em cenários com consequências financeiras ou legais, a orquestração deve ser feita com código determinístico, não com conformidade probabilística do LLM.','\n',char(10)),replace('**Explicação para uma criança de 10 anos:**\n\nImagina que você tem um robô que ajuda a devolver brinquedos na loja. A regra é: primeiro você tem que mostrar seu cartão da loja (verificar identidade), e só depois o robô pode devolver o dinheiro.\n\nSe a gente só *pedir* para o robô fazer isso na ordem certa, ele pode errar às vezes — tipo, ele pode devolver o dinheiro antes de verificar o cartão, e aí a loja perde dinheiro!\n\nA melhor maneira de garantir que ele faça tudo certinho é **programar o robô com uma regra dura**: primeiro ele É OBRIGADO a verificar o cartão, e SÓ DEPOIS ele pode devolver o dinheiro. É como colocar uma fechadura que só abre depois que você passar o cartão. Não tem como errar!\n\nAs outras opções são:\n- **A)** Só pedir educadamente no manual — o robô pode desobedecer.\n- **C)** Tirar o botão de devolver dinheiro — aí nunca devolve, o que não resolve.\n- **D)** Mostrar exemplos de como fazer — o robô ainda pode se confundir.\n\nEntão a resposta certa é a **B**: usar um código que obriga a ordem certa, sem chance de erro!','\n',char(10)));
INSERT INTO cards VALUES('admin','card_1783092992418_65hfdpw0s',476,'Which technique improves the model''s tool selection in ambiguous and edge cases?',replace('Which technique improves the model''s tool selection in ambiguous and edge cases?\n\nWhich technique improves the model''s tool selection in ambiguous and edge cases?\n[Resposta correta: De 4 a 6 exemplos focados em cenários ambíguos, mostrando por que uma ferramenta foi escolhida sobre alternativas plausíveis, superam regras declarativas para decisões nuançadas. Regras declarativas rendem menos, casos não ambíguos não ajudam e reduzir ferramentas não é o que trata a ambiguidade.]\n\n[ ] A - Writing a list of declarative rules covering every possible case\n[ ] B - Adding 4-6 examples of ambiguous scenarios with the comparative reasoning of the choice\n[ ] C - Including many examples of unambiguous and easy cases\n[ ] D - Reducing the number of available tools to the minimum','\n',char(10)),'[ ] B - Adding 4-6 examples of ambiguous scenarios with the comparative reasoning of the choice','["Domain_4::Prompt_Engineering_Structured_Output", "ForaDoCenario"]','New',0,2.5,0,1783092992418,1783727959718,1783203558653,replace('**Tradução para Português do Brasil:**\n\n**Pergunta:** Qual técnica melhora a seleção de ferramentas pelo modelo em casos ambíguos e de borda?\n\n[ ] A - Escrever uma lista de regras declarativas cobrindo todos os casos possíveis\n[ ] B - Adicionar de 4 a 6 exemplos de cenários ambíguos com o raciocínio comparativo da escolha\n[ ] C - Incluir muitos exemplos de casos não ambíguos e fáceis\n[ ] D - Reduzir o número de ferramentas disponíveis ao mínimo','\n',char(10)),replace('**Explicação para um adulto (tech lead):**\n\nA pergunta trata de como melhorar a capacidade de um modelo de linguagem (LLM) de escolher a ferramenta correta quando o contexto é ambíguo ou quando estamos em situações de borda (edge cases), onde múltiplas ferramentas poderiam parecer aplicáveis.\n\n**Resposta correta: Alternativa B**\n\nA alternativa B é a mais eficaz porque, em vez de tentar listar exaustivamente todas as situações possíveis (o que é impraticável), ela utiliza *few-shot prompting* com exemplos criteriosamente selecionados. Ao fornecer de 4 a 6 exemplos que explicitam o *raciocínio comparativo* — ou seja, "por que a ferramenta X foi escolhida em vez da ferramenta Y, mesmo que ambas parecessem plausíveis" —, o modelo aprende a aplicar um *chain-of-thought* ou um julgamento ponderado. Esse tipo de exemplificação é muito mais rica semanticamente do que regras abstratas, pois mostra ao modelo o *processo de decisão* em zonas cinzentas.\n\n**Por que as demais estão erradas:**\n\n- **Alternativa A:** Regras declarativas são frágeis para ambiguidades porque tentam capturar nuances do mundo real em instruções rígidas. A complexidade combinatória de "cobrir todos os casos possíveis" é inviável, e o modelo pode falhar em situações não previstas. Além disso, LLMs generalizam melhor a partir de exemplos do que de instruções declarativas (conforme evidenciado em pesquisas de *in-context learning*).\n- **Alternativa C:** Exemplos não ambíguos e fáceis não ensinam o modelo a lidar com a ambiguidade. Eles reforçam padrões óbvios, mas não fornecem o *contraste* necessário para que o modelo aprenda a discernir entre opções concorrentes em casos incertos.\n- **Alternativa D:** Reduzir o número de ferramentas é uma solução de design/arquitetura que pode simplificar o problema, mas não "melhora a seleção" propriamente dita — ela apenas evita o problema. Em cenários reais, muitas vezes não podemos eliminar ferramentas legítimas; a ambiguidade persiste e precisa ser tratada no nível do raciocínio do modelo, não na eliminação de opções.','\n',char(10)),replace('**Explicação para uma criança de 10 anos:**\n\nImagine que você tem uma caixa de ferramentas com um martelo, uma chave de fenda e um alicate. Se alguém pedir para você "apertar um parafuso", fica fácil: você pega a chave de fenda. Mas e se a pessoa disser "preciso juntar essas duas peças de madeira"? Pode ser martelo (pregos) ou chave de fenda (parafusos) — é uma situação *ambígua*.\n\nA pergunta é: o que ajuda você a escolher a ferramenta certa nessas horas difíceis?\n\n- **Alternativa B é a melhor:** Se alguém te der 4 ou 6 exemplos de situações confusas como essa, e explicar **por que** escolheu uma ferramenta no lugar da outra ("aqui usei o martelo porque a madeira estava rachando com parafusos"), você aprende a pensar igual. Isso é muito mais útil do que decorar regras.\n\n- **Alternativa A (regras para tudo):** Não dá para escrever uma regra para cada situação possível — seriam milhões de regras! E ainda assim algumas escapariam.\n\n- **Alternativa C (exemplos fáceis):** Se você só treinar com exemplos fáceis ("apertar parafuso → chave de fenda"), você nunca aprende a resolver os casos difíceis e confusos.\n\n- **Alternativa D (menos ferramentas):** Se você jogar fora o martelo e o alicate e ficar só com a chave de fenda, você até escolhe mais rápido, mas não consegue fazer tudo o que precisa. O problema não é a quantidade de ferramentas, mas sim saber escolher entre elas quando várias parecem servir.\n\nEntão, para melhorar a escolha em casos ambíguos, o melhor é ter exemplos que mostram **como pensar** na hora da dúvida. 😊','\n',char(10)));
INSERT INTO cards VALUES('admin','card_1783092992446_qwxsc0fbs',477,'When distributing tools among agents following least privilege, what is the correct strategy?',replace('When distributing tools among agents following least privilege, what is the correct strategy?\n\nWhen distributing tools among agents following least privilege, what is the correct strategy?\n[Resposta correta: Cada agente recebe apenas a ferramenta de escopo reduzido do seu caso comum, com casos complexos resolvidos por coordenação, pois super-provisionar degrada a tarefa principal. A opção A super-provisiona, C recai no caching especulativo desaconselhado e D remove a capacidade necessária.]\n\n[ ] A - Give all agents the full set of tools for maximum flexibility\n[ ] B - Give each agent only the narrow-scope tool for its common case, handling complex cases through coordination\n[ ] C - Provision extra tools via speculative caching anticipating future needs\n[ ] D - Leave each agent without tools and solve everything through the prompt','\n',char(10)),'[ ] B - Give each agent only the narrow-scope tool for its common case, handling complex cases through coordination','["Domain_1::Agentic_Architecture_Orchestration", "Domain_2::Tool_Design_MCP_Integration", "Scenario_1::Customer_Support_Agent"]','New',0,2.5,0,1783092992446,1783727963205,1783203558653,replace('**Tradução para português do Brasil:**\n\n**Pergunta:** Ao distribuir ferramentas entre agentes seguindo o princípio do menor privilégio, qual é a estratégia correta?\n\n[ ] A - Dar a todos os agentes o conjunto completo de ferramentas para máxima flexibilidade\n[ ] B - Dar a cada agente apenas a ferramenta de escopo reduzido para seu caso comum, lidando com casos complexos através de coordenação\n[ ] C - Provisionar ferramentas extras via caching especulativo antecipando necessidades futuras\n[ ] D - Deixar cada agente sem ferramentas e resolver tudo através do prompt','\n',char(10)),replace('**Explicação didática para um adulto tech lead (com análise das alternativas):**\n\nO princípio do **menor privilégio (least privilege)** estabelece que uma entidade deve ter acesso apenas aos recursos estritamente necessários para executar sua função. No contexto de agentes com ferramentas, isso significa que cada agente deve receber exclusivamente as ferramentas que precisa para realizar seu caso de uso mais comum.\n\n**Resposta correta: B**\n\nA alternativa B está alinhada com o conceito de *segurança por design* e *arquitetura orientada a princípios*. Cada agente opera com o menor conjunto possível de ferramentas, e quando um caso complexo exige mais recursos, isso é resolvido por coordenação entre agentes (por exemplo, um agente orquestrador delegando a outro agente especializado). Isso reduz a superfície de ataque, minimiza riscos de uso indevido e mantém cada agente focado em sua tarefa principal.\n\n**Análise das alternativas incorretas:**\n\n- **A (super-provisionamento):** Dar o conjunto completo de ferramentas a todos os agentes viola o princípio do menor privilégio. Agentes não precisam de ferramentas que nunca utilizarão, e o excesso de opções pode levar a erros, segurança fragilizada e degradação da tarefa principal (o agente "se distrai" com ferramentas irrelevantes).\n\n- **C (caching especulativo):** Provisionar ferramentas extras "por precaução" (speculative caching) é uma abordagem antagônica ao menor privilégio. Antecipar necessidades futuras sem evidência concreta adiciona complexidade, risco e sobrecarga desnecessária, sendo desaconselhada em arquiteturas que seguem o princípio.\n\n- **D (ausência total de ferramentas):** Deixar agentes sem ferramentas os torna incapazes de executar qualquer ação prática. Um agente que depende exclusivamente do prompt para tudo perde a capacidade de interagir com o ambiente, sistemas externos ou executar tarefas concretas, tornando-se inútil para a maioria dos cenários reais.','\n',char(10)),replace('Imagine que você tem uma caixa de ferramentas cheia de coisas: martelo, chave de fenda, tesoura, alicate, furadeira. Agora, você precisa distribuir essas ferramentas para vários amigos, cada um com uma tarefa diferente.\n\nO princípio do "menor privilégio" é como dizer: "Cada amigo só leva o que realmente vai usar". Se o João só vai pendurar um quadro, ele leva apenas o martelo. Se a Maria só vai apertar um parafuso, ela leva só a chave de fenda. Se aparecer um problema mais complicado, eles podem se ajudar — o João chama a Maria, e cada um usa a ferramenta certa na hora certa.\n\n- Se você der todas as ferramentas para todo mundo (alternativa A), os amigos podem se atrapalhar, perder ferramentas ou até se machucar com o que não sabem usar.\n- Se você der ferramentas extras "só por precaução" (alternativa C), é como dar uma furadeira para o João que só vai pendurar um quadro — ele não precisa, e pode acabar fazendo besteira.\n- Se você não der ferramenta nenhuma (alternativa D), os amigos não conseguem fazer nada! Só conversando não se pendura quadro nem aperta parafuso.\n\nA melhor ideia (alternativa B) é dar a cada um só a ferramenta que ele precisa para o trabalho dele. Se surgir algo mais complicado, eles se organizam e resolvem juntos. Assim, tudo funciona direitinho, sem bagunça e sem perigo.','\n',char(10)));
INSERT INTO cards VALUES('admin','card_1783092992476_s0xz26hul',478,'A search returns multiple customer matches.',replace('A search returns multiple customer matches.\n\nA search returns multiple customer matches. What is the correct conduct before acting?\n[Resposta correta: O usuário tem conhecimento definitivo da própria identidade, então Claude deve pedir um identificador adicional antes de qualquer ação específica do cliente. Limiares de confiança são mal calibrados, esconder a ambiguidade remove a capacidade de tratar o caso e encerrar a conversa não resolve o pedido.]\n\n[ ] A - Automatically choose the match with the highest confidence score\n[ ] B - Ask the user for an additional identifier, such as email, phone or order number\n[ ] C - Hide the ambiguity from Claude and proceed with the first match\n[ ] D - Interrupt the service and end the conversation','\n',char(10)),'[ ] B - Ask the user for an additional identifier, such as email, phone or order number','["Domain_2::Tool_Design_MCP_Integration", "Domain_1::Agentic_Architecture_Orchestration", "Scenario_1::Customer_Support_Agent"]','New',0,2.5,0,1783092992476,1783727966975,1783203558653,replace('## Tradução (pt-BR)\n\n**Pergunta:** Uma busca retorna múltiplos clientes correspondentes. Qual é a conduta correta antes de agir?\n\n- [ ] A - Escolher automaticamente a correspondência com maior pontuação de confiança\n- [ ] B - Pedir ao usuário um identificador adicional, como e-mail, telefone ou número do pedido\n- [ ] C - Ocultar a ambiguidade de Claude e prosseguir com a primeira correspondência\n- [ ] D - Interromper o serviço e encerrar a conversa','\n',char(10)),replace('## Explicação Didática para Adulto (Tech Lead)\n\n**Resposta correta: B**\n\nQuando um sistema de busca retorna múltiplos matches para um mesmo cliente, estamos diante de uma ambiguidade que precisa ser resolvida antes de qualquer ação. A conduta correta é solicitar ao usuário um identificador adicional (e-mail, telefone, número do pedido, CPF etc.) para desambiguar e garantir que a ação será aplicada ao cliente certo.\n\n### Por que a B é a melhor escolha?\n\n- **Princípio de segurança e precisão:** Em sistemas que lidam com dados sensíveis ou ações transacionais (como alterar cadastro, emitir nota fiscal, consultar histórico), agir com base em um match ambíguo pode causar vazamento de informações, retrabalho ou danos ao cliente.\n- **Delegação correta da decisão:** O usuário humano tem conhecimento definitivo sobre sua própria identidade. O sistema deve reconhecer seus limites e delegar a desambiguação a quem possui a informação correta.\n- **Melhor UX:** Pedir um dado adicional é rápido, não-frustrante e resolve o problema de forma cooperativa.\n\n### Análise das alternativas incorretas\n\n**A - Escolher automaticamente a correspondência com maior pontuação de confiança**\n- **Erro:** Limiares de confiança (confidence scores) são mal calibrados e não substituem a certeza do usuário. Escolher automaticamente pode levar a ações no cliente errado, violando privacidade e causando erros operacionais. É uma falsa sensação de segurança.\n\n**C - Ocultar a ambiguidade de Claude e prosseguir com a primeira correspondência**\n- **Erro:** Esconder a ambiguidade do sistema remove a capacidade de tratar o caso adequadamente. O modelo não consegue tomar uma decisão informada se a ambiguidade for mascarada. Isso também quebra a confiabilidade do sistema.\n\n**D - Interromper o serviço e encerrar a conversa**\n- **Erro:** Abortar o atendimento sem tentar resolver o problema é uma experiência frustrante e não resolve o pedido do usuário. A abordagem correta é engajar o usuário para desfazer o impasse, não desistir.','\n',char(10)),replace('## Explicação para Criança de 10 Anos\n\nImagine que você está em uma sorveteria e diz "quero um sorvete de chocolate". O atendente olha e vê vários potes de chocolate diferentes — um com calda, outro com granulado, outro bem cremoso. Ele não sabe qual você quer!\n\nQual a melhor atitude?\n\n**Opção B (a correta):** O atendente pergunta: "Qual deles? O que tem calda, granulado ou o cremoso?" — assim ele descobre exatamente qual você quer. Isso é educado e resolve o problema.\n\n**As outras opções são ruins porque:**\n\n- **Opção A:** Ele simplesmente escolhe um aleatório, mesmo sem saber se é o que você quer. Pode ser que você ganhe um sorvete sem calda, quando queria com calda. Não é legal!\n- **Opção C:** Ele finge que não viu os outros potes e te dá o primeiro que apareceu. Mentira não é bom, e você pode ficar insatisfeito.\n- **Opção D:** Ele diz "não sei qual é, então vou embora" e te deixa sem sorvete. Isso seria muito chato, né?\n\n**Resumo:** Quando não temos certeza, o melhor é perguntar para quem sabe a resposta certa — no caso, o próprio usuário!','\n',char(10)));
INSERT INTO cards VALUES('admin','card_1783092992528_iryfywllw',479,'You want to prevent a tool from accessing arbitrary URLs.',replace('You want to prevent a tool from accessing arbitrary URLs.\n\nYou want to prevent a tool from accessing arbitrary URLs. Which design approach is the most robust?\n[Resposta correta: Constranger a capacidade na própria interface da ferramenta torna o comportamento indesejado impossível, atacando a causa. Instruções no prompt não fazem enforcement confiável, blocklists são incompletas e exigem manutenção, e revisar depois não impede o acesso.]\n\n[ ] A - Add instructions in the prompt forbidding external URLs\n[ ] B - Restrict the capability in the tool interface, replacing fetch_url with load_document that validates formats\n[ ] C - Keep a blocklist of forbidden domains and update it periodically\n[ ] D - Log the calls and review improper accesses afterwards','\n',char(10)),'B - Restrict the capability in the tool interface, replacing fetch_url with load_document that validates formats','["Domain_2::Tool_Design_MCP_Integration", "Domain_4::Prompt_Engineering_Structured_Output", "Scenario_6::Structured_Data_Extraction"]','New',0,2.5,0,1783092992528,1783727970628,1783203558653,replace('**Tradução para português do Brasil:**\n\nVocê quer evitar que uma ferramenta acesse URLs arbitrárias. Qual abordagem de design é a mais robusta?\n\n[ ] A - Adicionar instruções no prompt proibindo URLs externas\n[ ] B - Restringir a capacidade na própria interface da ferramenta, substituindo fetch_url por load_document que valida formatos\n[ ] C - Manter uma blocklist de domínios proibidos e atualizá-la periodicamente\n[ ] D - Registrar as chamadas e revisar acessos inadequados depois','\n',char(10)),replace('**Explicação para um adulto tech lead:**\n\nA alternativa correta é a **B**.\n\nEla segue o princípio de segurança conhecido como "secure by design" ou "defense in depth", atacando a causa raiz do problema. Ao limitar a própria interface da ferramenta (substituindo `fetch_url` por `load_document` que valida formatos), você torna o comportamento indesejado *impossível de acontecer*. Não há como a ferramenta acessar URLs arbitrárias se ela não possui essa capacidade. Isso é um controle preventivo, não reativo.\n\nAnálise das alternativas incorretas:\n\n- **A (Instruções no prompt):** Prompt instructions são orientações, não enforcement confiável. Um adversário (ou até mesmo um comportamento imprevisto do modelo) pode ignorar, jailbreak ou manipular as instruções. Não há garantia técnica de que serão seguidas. É um controle frágil e facilmente contornável.\n\n- **C (Blocklist de domínios):** Blocklists são inerentemente incompletas (só cobrem o que você já conhece) e exigem manutenção constante. URLs arbitrárias incluem domínios novos, subdomínios, IPs diretos, serviços de encurtamento, etc. É uma abordagem reativa e de longo prazo insustentável.\n\n- **D (Log e revisão posterior):** Isso é um controle *detectivo*, não *preventivo*. O acesso indesejado já ocorreu antes de ser revisado. Depende de monitoramento humano, escala mal e não impede o problema — apenas registra que ele aconteceu.\n\n**Conclusão:** A única abordagem que elimina o problema pela raiz é restringir a capacidade no nível da interface (B). As demais confiam em controles falhos, reativos ou incompletos.','\n',char(10)),replace('Imagine que você tem um robô que pode buscar qualquer coisa na internet, mas você não quer que ele entre em sites perigosos.\n\n**Alternativa A:** Você diz para o robô: "Não entre em sites perigosos, hein!" — mas ele pode esquecer ou desobedecer. Só falar não adianta muito.\n\n**Alternativa B (a melhor!):** Você tira do robô a capacidade de acessar sites aleatórios. Em vez disso, você dá a ele um livro de receitas já aprovado, e ele só pode ler desse livro. Assim, ele simplesmente não consegue entrar em sites proibidos. É a solução mais segura!\n\n**Alternativa C:** Você faz uma lista de sites proibidos e mostra para o robô. Mas sempre aparecem sites novos que não estavam na lista, e o robô pode acessá-los. A lista nunca é completa.\n\n**Alternativa D:** Você deixa o robô acessar qualquer site, mas depois você olha o histórico para ver o que ele fez. Só que o estrago já foi feito — o acesso ao site perigoso já aconteceu.\n\nResumindo: a melhor forma de evitar que algo ruim aconteça é fazer com que seja **impossível** de acontecer, não só pedir ou fiscalizar depois.','\n',char(10)));
INSERT INTO cards VALUES('admin','card_1783092992553_6ogntvxpu',480,'A review tool generates many false positives and the devs are losing confidence.',replace('A review tool generates many false positives and the devs are losing confidence.\n\nA review tool generates many false positives and the devs are losing confidence. Which action reduces the noise while preserving what works?\n[Resposta correta: Desabilitar temporariamente as categorias de alto FP (estilo, naming, documentação) e rodar só as de alta precisão (segurança, correção, performance) reduz o ruído sem degradar o que funciona. Desligar tudo perde o valor bom, baixar a sensibilidade por igual degrada categorias boas e ignorar os FPs transfere o ônus ao dev enquanto a confiança erode.]\n\n[ ] A - Turn off the entire tool until all prompts are rewritten\n[ ] B - Temporarily disable the high FP categories and run only the high-precision ones while improving the prompts\n[ ] C - Lower the sensitivity of all categories equally\n[ ] D - Keep everything on and ask the devs to ignore the false positives','\n',char(10)),'B - Temporarily disable the high FP categories and run only the high-precision ones while improving the prompts','["Domain_4::Prompt_Engineering_Structured_Output", "Domain_3::Claude_Code_Configuration_Workflows", "Scenario_5::Claude_Code_CI_CD"]','New',0,2.5,0,1783092992553,1783727974103,1783203558653,replace('**Tradução da pergunta:** Uma ferramenta de revisão gera muitos falsos positivos e os desenvolvedores estão perdendo a confiança.\n\nQual ação reduz o ruído enquanto preserva o que funciona?\n\n[ ] A - Desligar a ferramenta inteira até que todos os prompts sejam reescritos\n[ ] B - Desabilitar temporariamente as categorias de alto FP e rodar apenas as de alta precisão enquanto melhora os prompts\n[ ] C - Reduzir a sensibilidade de todas as categorias igualmente\n[ ] D - Manter tudo ligado e pedir para os desenvolvedores ignorarem os falsos positivos','\n',char(10)),replace('**Explicação para um adulto tech lead:**\n\nA questão central é como lidar com uma ferramenta de revisão automatizada (code review, lint, análise estática, etc.) que está gerando excesso de falsos positivos, levando à perda de confiança dos desenvolvedores — um problema sério, pois ferramentas com alta taxa de FP tendem a ser ignoradas ou desativadas por completo.\n\nA alternativa correta é a **B**. Essa abordagem é cirúrgica: ao desabilitar temporariamente apenas as categorias que mais geram falsos positivos (ex.: estilo, naming, documentação) e manter ativas as de alta precisão (ex.: segurança, correção, performance), reduz-se drasticamente o ruído sem perder os alertas de maior valor. Ao mesmo tempo, o esforço de melhoria contínua dos prompts é mantido, atacando a causa raiz dos FPs.\n\nAnálise das alternativas incorretas:\n\n- **A (Desligar tudo):** É uma reação extrema e contraproducente. Joga fora o valor que a ferramenta entrega nas categorias de alta precisão. Enquanto os prompts são reescritos (o que pode levar semanas), a equipe fica sem nenhum tipo de revisão automatizada.\n\n- **C (Reduzir sensibilidade geral):** Reduzir a sensibilidade de forma uniforme é uma medida cega. Afeta igualmente categorias de alta e baixa qualidade. Você reduz FP das categorias ruins, mas também reduz a capacidade de encontrar problemas reais nas boas. Pior: se as categorias de alta precisão já têm baixo FP, reduzir ainda mais a sensibilidade só gera falsos negativos.\n\n- **D (Manter tudo e ignorar):** Essa é a pior de todas. Ignorar falsos positivos não resolve o problema de confiança; na verdade, agrava. Os desenvolvedores passam a tratar TODOS os alertas como ruído (inclusive os verdadeiros positivos), e a ferramenta se torna inútil. É o caminho mais rápido para o "alert fatigue" e o completo descrédito da ferramenta.\n\nPortanto, **B** é a única opção que equilibra a redução imediata de ruído com a preservação dos benefícios e a melhoria contínua.','\n',char(10)),replace('Imagine que você tem uma caixa de brinquedos que faz sons para te ajudar a arrumar o quarto. Quando você coloca um lápis no lugar certo, ela diz "Muito bem!". Mas, de vez em quando, ela também apita sem motivo, tipo quando você só encosta no lápis. Isso é chato e você para de confiar nela.\n\nA pergunta é: o que fazer para diminuir os apitos falsos sem estragar os apitos bons?\n\n- **Opção A:** Desligar a caixa completamente até arrumar todos os botões. Mas aí você perde todos os "muito bem" também.\n- **Opção B (a certa):** Desligar só os sensores que mais apitam sem motivo (como o sensor de "arrumou bonitinho") e deixar ligados os que são quase sempre certeiros (como "tirou o lápis do chão"). Enquanto isso, você vai arrumando os sensores ruins.\n- **Opção C:** Deixar todos os sensores mais fracos, inclusive os bons. Aí eles quase nunca apitam, nem quando deveriam.\n- **Opção D:** Deixar tudo como está e pedir pra você fingir que não ouve os apitos falsos. Só que você fica cada vez mais bravo e para de prestar atenção em qualquer som.\n\nA melhor saída é a **B**: calar a boca dos sensores encrenqueiros por um tempo, manter os confiáveis trabalhando, e ir consertando os problemas. Assim a caixa continua útil e você volta a confiar nela.','\n',char(10)));
INSERT INTO cards VALUES('admin','card_1783092992612_cl2fp5vel',481,'Your CI pipeline includes two code review modes: a pre-merge-commit hook that blocks PR merging until complete, and "deep analysis" that runs overnight, polls for batch completion, then posts detailed suggestions.',replace('Your CI pipeline includes two code review modes: a pre-merge-commit hook that blocks PR merging until complete, and "deep analysis" that runs overnight, polls for batch completion, then posts detailed suggestions.\n\nYour CI pipeline includes two code review modes: a pre-merge-commit hook that blocks PR merging until complete, and "deep analysis" that runs overnight, polls for batch completion, then posts detailed suggestions. Which mode should use batch processing?\nO que a pergunta pede: which mode should use batch → qual modo deve usar batch (escolha o que tolera atraso).\n\nA pegadinha: blocks PR merging until complete (precisa ser rápido) vs runs overnight, polls for batch completion (já descreve o comportamento de batch).\n\nRaciocínio: O hook pré-merge bloqueia o merge e precisa ser rápido → síncrono. A deep analysis roda à noite e já faz polling — o caso clássico de batch (lento, mas 50% mais barato). C .\n\n[ ] A - Both modes\n[ ] B - Pre-merge-commit hook only\n[ ] C - Deep analysis only\n[ ] D - Neither mode','\n',char(10)),'C - Deep analysis only','["Domain_4::Prompt_Engineering_Structured_Output", "Domain_5::Context_Management_Reliability", "Scenario_5::Claude_Code_CI_CD"]','New',0,2.5,0,1783092992612,1783727977518,1783203558653,replace('**Tradução para português do Brasil:**\n\nSua esteira de CI inclui dois modos de revisão de código: um hook pre-merge-commit que bloqueia o merge do PR até ser concluído, e uma "análise aprofundada" que roda durante a noite, faz polling pela conclusão do lote e então publica sugestões detalhadas. Qual modo deve usar processamento em lote (batch)?\n\n[ ] A - Ambos os modos\n[ ] B - Apenas o hook pre-merge-commit\n[ ] C - Apenas a análise aprofundada\n[ ] D - Nenhum dos modos','\n',char(10)),replace('**Explicação didática para um adulto tech lead:**\n\nA pergunta testa o entendimento de quando o processamento em lote (batch) é adequado versus quando ele não é.\n\n**Análise da resposta correta (C - Deep analysis only):**\n\nO processamento em lote é caracterizado por maior latência (não é instantâneo), maior eficiência de custo (tipicamente 50% mais barato que processamento sob demanda) e é projetado para cargas de trabalho que toleram atraso. A descrição da "deep analysis" já entrega a pista: ela roda overnight (tolerância a atraso) e faz polling pelo resultado (comportamento típico de jobs assíncronos/batch). É o cenário ideal para batch processing.\n\n**Por que as demais alternativas estão erradas:**\n\n- **A (Ambos os modos):** O hook pre-merge-commit bloqueia o merge até ser concluído - isso exige resposta rápida e síncrona. Submeter um hook de bloqueio a processamento batch destruiria a experiência do desenvolvedor, pois ninguém esperaria horas para um PR ser mesclado.\n\n- **B (Apenas o hook pre-merge-commit):** É o oposto do que se deseja. Um hook que bloqueia merge precisa ser rápido (segundos, não horas) para não emperrar o fluxo de trabalho. Batch é lento por definição.\n\n- **D (Nenhum dos modos):** Ignora que a análise aprofundada já descreve exatamente o comportamento de um job batch: execução noturna, polling, posting assíncrono de resultados.','\n',char(10)),replace('Imagine que você tem duas tarefas:\n\n1. **Tarefa rápida:** Você precisa verificar se a lição de casa está certa ANTES de entregar ao professor. Se demorar, você fica preso e não consegue passar para a próxima matéria. Essa tarefa precisa ser resolvida na hora.\n\n2. **Tarefa devagar:** Você tem que ler um livro gigante e fazer um resumo. Pode fazer isso durante a noite, enquanto dorme. Não tem pressa - você pode começar, ir dormir, e no dia seguinte ver o resultado.\n\nAgora, qual dessas tarefas pode usar o processamento em lote (batch)? Batch é como colocar várias tarefas num "pacote" e processar tudo de uma vez, o que demora mais, mas é mais barato.\n\nA **Tarefa 1** (o hook pre-merge) é a lição que precisa ser verificada na hora - não dá para esperar. Já a **Tarefa 2** (deep analysis) é o livro que você pode ler durante a noite - pode esperar.\n\nEntão a resposta certa é: **só a análise aprofundada (deep analysis)** deve usar batch, porque ela já foi feita para rodar devagar, durante a noite. O hook pré-merge precisa ser rápido, então não pode ser batch.','\n',char(10)));
INSERT INTO cards VALUES('admin','card_1783092992639_al053ldyh',482,'Production logs reveal that the agent misinterprets data from your MCP tools: Unix timestamps from get_customer , ISO 8601 dates from lookup_order , and numeric status codes (1=pending, 2=shipped).',replace('Production logs reveal that the agent misinterprets data from your MCP tools: Unix timestamps from get_customer , ISO 8601 dates from lookup_order , and numeric status codes (1=pending, 2=shipped).\n\nProduction logs reveal that the agent misinterprets data from your MCP tools: Unix timestamps from get_customer , ISO 8601 dates from lookup_order , and numeric status codes (1=pending, 2=shipped). Some tools are third-party MCP servers you cannot modify. What''s the most maintainable approach to normalize data formats?\nO que a pergunta pede: most maintainable approach → "a abordagem mais sustentável ". Querem a solução mais limpa e durável, não um remendo rápido.\n\nA pegadinha: third-party MCP servers you cannot modify → servidores de terceiros que você não pode modificar . Essa é a pegadinha: qualquer opção que dependa só de alterar essas ferramentas é impossível.\n\nRaciocínio: A restrição proíbe modificar ferramentas de terceiros, mas não proíbe criar wrappers em volta delas. Corrija as que você controla e envolva as que não pode. A (hook) é frágil e dependente de infraestrutura. C joga a responsabilidade no prompt — pouco confiável. D depende de o agente lembrar de chamar a ferramenta toda vez. B resolve na fonte sem violar a regra.\n\n[ ] A - Use a PostToolUse hook to intercept tool results and apply formatting transformations before agent processing\n[ ] B - Modify tools you control to return human-readable formats; create wrapper tools for third-party tools\n[ ] C - Add detailed format documentation to your system prompt explaining each tool''s data conventions\n[ ] D - Create a normalize_data tool that the agent calls after each data retrieval to transform values','\n',char(10)),'[ ] B - Modify tools you control to return human-readable formats; create wrapper tools for third-party tools','["Domain_2::Tool_Design_MCP_Integration", "Domain_1::Agentic_Architecture_Orchestration", "Scenario_1::Customer_Support_Agent"]','New',0,2.5,0,1783092992639,1783727981087,1783203558653,replace('**Tradução para português do Brasil:**\n\nOs logs de produção revelam que o agente interpreta incorretamente os dados das suas ferramentas MCP: timestamps Unix do get_customer, datas ISO 8601 do lookup_order e códigos de status numéricos (1=pending, 2=shipped). Algumas ferramentas são servidores MCP de terceiros que você não pode modificar. Qual é a abordagem mais sustentável para normalizar os formatos dos dados?\n\n[ ] A - Usar um hook PostToolUse para interceptar os resultados das ferramentas e aplicar transformações de formatação antes do processamento pelo agente\n[ ] B - Modificar as ferramentas que você controla para retornar formatos legíveis por humanos; criar ferramentas wrapper para ferramentas de terceiros\n[ ] C - Adicionar documentação detalhada de formato ao seu prompt de sistema explicando as convenções de dados de cada ferramenta\n[ ] D - Criar uma ferramenta normalize_data que o agente chama após cada recuperação de dados para transformar os valores','\n',char(10)),replace('**Explicação para adulto tech lead:**\n\nA restrição crítica do problema é: "Some tools are third-party MCP servers you cannot modify." Isso elimina qualquer abordagem que dependa exclusivamente de alterar essas ferramentas — mas não proíbe criar wrappers em volta delas.\n\n**Por que B é a resposta correta:**\n\nA alternativa B segue o princípio de "corrigir na fonte sempre que possível". Para as ferramentas que você controla, você modifica diretamente a saída para usar formatos padronizados e legíveis (ex.: timestamp → data ISO 8601 ou string datetime). Para as ferramentas de terceiros (que você não pode modificar), você cria wrapper tools — ou seja, ferramentas MCP que encapsulam a chamada original, recebem os dados brutos, aplicam a normalização e retornam o resultado padronizado.\n\nEssa abordagem é a mais sustentável porque:\n- **Centraliza a lógica de normalização** em uma camada de adaptação, em vez de espalhá-la por prompts, hooks ou chamadas manuais.\n- **Não depende de comportamento do agente** — o agente simplesmente chama o wrapper e recebe dados já normalizados, sem precisar "lembrar" de transformar nada.\n- **É resiliente a mudanças upstream** — se uma ferramenta de terceiro mudar seu formato, você só precisa ajustar o wrapper, não o prompt ou a lógica do agente.\n- **Respeita a restrição de não modificar ferramentas de terceiros**, contornando-a elegantemente com o padrão Adapter/Wrapper.\n\n**Por que as demais estão erradas:**\n\n- **A (hook PostToolUse):** Hooks são frágeis e dependentes de infraestrutura específica. Eles introduzem lógica de transformação em um ponto cego do pipeline (entre a ferramenta e o agente), o que dificulta debugging, versionamento e testes. Além disso, hooks podem não estar disponíveis em todas as plataformas MCP ou podem ser desabilitados em atualizações. É uma solução acoplada e de difícil manutenção.\n\n- **C (documentação no prompt de sistema):** Depender de o agente interpretar corretamente documentação em texto livre é extremamente frágil. LLMs são notórios por ignorar ou interpretar mal instruções em prompts longos, especialmente quando os formatos são variados (Unix timestamp, ISO 8601, códigos numéricos). Isso coloca a responsabilidade no comportamento do modelo, que é probabilístico e não determinístico. Não é sustentável.\n\n- **D (ferramenta normalize_data chamada manualmente):** Essa abordagem exige que o agente "lembre" de chamar normalize_data após cada consulta. Isso depende de prompting confiável e consistente, o que é frágil. Se o agente pular a chamada em qualquer cenário (por alucinação, por instrução ambígua ou por otimização de tokens), os dados chegarão sem normalização. Além disso, adiciona latência e complexidade desnecessárias — toda chamada de ferramenta tem custo e tempo. É um workaround, não uma solução arquitetural.','\n',char(10)),replace('Imagine que você tem um cachorro que só entende comandos em português, e um amigo seu tem um cachorro que só entende comandos em inglês. Vocês querem que os dois cachorros brinquem juntos seguindo as mesmas regras.\n\nVocê pode treinar seu próprio cachorro (que você controla) para entender português. Mas o cachorro do seu amigo (de terceiros) você não pode mexer — não pode entrar na casa dele para treinar o cachorro dele.\n\nO que você faz? Você cria um "tradutor" (um wrapper) para o cachorro do seu amigo. Você ensina o tradutor a ouvir o comando em português, traduzir para inglês, dar o comando pro cachorro do amigo, pegar a resposta em inglês e traduzir de volta para português. Assim, os dois cachorros passam a "falar a mesma língua" sem você precisar invadir a casa de ninguém.\n\nÉ exatamente isso que a opção B faz: arruma as ferramentas que você pode arrumar e coloca um "tradutor" (wrapper) nas ferramentas de terceiros. As outras opções são ruins porque: a opção A é como colocar um filtro mágico que pode quebrar do nada; a opção C é como escrever um bilhete enorme e torcer pro cachorro ler — e cachorro não lê; a opção D é como dar um apito pro cachorro e esperar que ele lembre de usar toda vez que precisar se comunicar.','\n',char(10)));
INSERT INTO cards VALUES('admin','card_1783092992664_7ucwl3io7',483,'Your CI/CD system performs three types of Claude-powered analysis: (1) quick style checks on each PR that block merging until complete, (2) comprehensive security audits run weekly, and (3) test case generation triggered nightly.',replace('Your CI/CD system performs three types of Claude-powered analysis: (1) quick style checks on each PR that block merging until complete, (2) comprehensive security audits run weekly, and (3) test case generation triggered nightly.\n\nYour CI/CD system performs three types of Claude-powered analysis: (1) quick style checks on each PR that block merging until complete, (2) comprehensive security audits run weekly, and (3) test case generation triggered nightly. The Message Batches API offers 50% cost savings but can take up to 24 hours to process. Which combination correctly matches each task to its API approach?\nO que a pergunta pede: which combination correctly matches each task → associe cada tarefa à abordagem certa (não uma regra única para tudo).\n\nA pegadinha: block merging until complete = precisa ser rápido → síncrono. weekly e nightly podem esperar → batch.\n\nRaciocínio: Só os style checks bloqueiam o merge , então precisam de resposta imediata → síncrono. A auditoria semanal e a geração noturna toleram o atraso de 24h, então ambas ganham os 50% de economia do batch . D é a única que casa cada tarefa pela sua tolerância a atraso. B erra ao manter a geração noturna em síncrono — ela pode esperar.\n\n[ ] A - Use the Message Batches API for all three tasks to maximize the 50% cost savings, and poll for batch completion.\n[ ] B - Use synchronous calls for PR style checks and nightly test generation; use Message Batches API only for weekly security audits.\n[ ] C - Use synchronous calls for all three tasks for consistent response times, and rely on prompt caching to reduce costs.\n[ ] D - Use synchronous calls for PR style checks; use the Message Batches API for weekly security audits and nightly test generation.','\n',char(10)),'D - Use synchronous calls for PR style checks; use the Message Batches API for weekly security audits and nightly test generation.','["Domain_5::Context_Management_Reliability", "Domain_4::Prompt_Engineering_Structured_Output", "Scenario_5::Claude_Code_CI_CD"]','New',0,2.5,0,1783092992664,1783727984386,1783203558653,replace('**Tradução para Português do Brasil:**\n\nSeu sistema de CI/CD realiza três tipos de análise baseadas em Claude: (1) verificações rápidas de estilo em cada PR que bloqueiam o merge até serem concluídas, (2) auditorias abrangentes de segurança executadas semanalmente e (3) geração de casos de teste acionada diariamente. A API de Message Batches oferece 50% de economia de custos, mas pode levar até 24 horas para processar. Qual combinação associa corretamente cada tarefa à sua abordagem de API?\n\n[ ] A - Usar a API de Message Batches para todas as três tarefas para maximizar a economia de 50% e consultar periodicamente a conclusão dos lotes.\n[ ] B - Usar chamadas síncronas para verificações de estilo de PR e geração noturna de testes; usar a API de Message Batches apenas para auditorias semanais de segurança.\n[ ] C - Usar chamadas síncronas para todas as três tarefas para tempos de resposta consistentes e contar com o prompt caching para reduzir custos.\n[ ] D - Usar chamadas síncronas para verificações de estilo de PR; usar a API de Message Batches para auditorias semanais de segurança e geração noturna de testes.','\n',char(10)),replace('**Explicação para um Tech Lead:**\n\nA pergunta testa a capacidade de alinhar requisitos de latência com características de cada abordagem de API. Vamos analisar cada alternativa:\n\n**Alternativa correta: D**\n\n- **Style checks (síncrono/calls síncronas):** A descrição diz que eles "block merging until complete" — ou seja, o merge depende da conclusão da análise. Isso exige resposta imediata/em tempo real. Chamadas síncronas (API padrão) são a escolha correta.\n- **Auditorias semanais (Message Batches):** Não há urgência — é executada semanalmente, tolera latência de horas/dias. O lote oferece 50% de economia, ideal.\n- **Geração noturna de testes (Message Batches):** Executada à noite, o resultado só será usado no dia seguinte. Tolerância total ao atraso de até 24h. O lote é a abordagem correta e econômica.\n\n**Por que as demais estão erradas:**\n\n- **A:** Colocar tudo em batch ignora que os style checks bloqueiam o merge. Se o batch leva até 24h, o merge ficaria travado por um dia inteiro — inviável para um fluxo de desenvolvimento ágil.\n- **B:** Coloca a geração noturna de testes como síncrona. Isso desperdiça economia de 50% desnecessariamente, já que a tarefa não tem urgência e poderia usar batch sem prejuízo.\n- **C:** Coloca tudo como síncrono. Perde completamente o benefício de 50% de economia das duas tarefas que toleram atraso, usando mais recursos sem necessidade. Prompt caching é útil, mas não substitui a economia estrutural do batch.\n\n**Conclusão:** O princípio é simples: tarefas que bloqueiam o fluxo (síncronas, urgentes) → chamadas síncronas. Tarefas assíncronas, programadas, sem urgência → Message Batches. A alternativa D é a única que respeita essa lógica para cada tarefa individualmente.','\n',char(10)),replace('Imagine que você tem três tarefas em casa:\n\n1. **Verificar estilo do PR:** É como quando você está montando um Lego e alguém precisa verificar se a peça encaixa certinho *antes* de você colocar a próxima. Se demorar, você não consegue continuar. Precisa ser rápido! → **Chamada síncrona** (resposta na hora).\n\n2. **Auditoria de segurança semanal:** É como limpar seu quarto uma vez por semana. Não precisa ser feito agora, pode ser no sábado de manhã. Dá para esperar. → **Message Batches** (mais barato, pode demorar).\n\n3. **Gerar testes à noite:** É como preparar a mochila da escola na noite anterior. Você só vai usar no dia seguinte, então não precisa ser feito na hora. Pode esperar. → **Message Batches** (econômico, atraso não é problema).\n\nA alternativa D acerta: faz rápido o que precisa ser rápido (style check) e deixa pra depois o que pode esperar (auditoria e testes noturnos), economizando 50% no que não tem pressa.\n\nAs outras opções ou atrasam tudo (A), ou perdem dinheiro fazendo rápido algo que poderia esperar (B e C).','\n',char(10)));
INSERT INTO cards VALUES('admin','card_1783092992689_zb6r58mxs',484,'Analysis shows false positive rates vary: security/correctness 8%, performance 18%, style/naming 52%, documentation 48%.',replace('Analysis shows false positive rates vary: security/correctness 8%, performance 18%, style/naming 52%, documentation 48%.\n\nAnalysis shows false positive rates vary: security/correctness 8%, performance 18%, style/naming 52%, documentation 48%. Developers are dismissing findings without review because "half are wrong." The high false positive categories are undermining confidence in the accurate ones. What approach best restores developer trust while improving the system?\nO que a pergunta pede: best restores developer trust while improving the system → restrição dupla: recuperar a confiança E melhorar o sistema.\n\nA pegadinha: As categorias ruidosas (style 52%, docs 48%) estão contaminando a confiança nas precisas (security 8%) agora .\n\nRaciocínio: A confiança está desabando agora por causa das categorias ruidosas. Desligá-las temporariamente restaura a confiança imediata (as restantes têm 8–18%, aceitável) enquanto você corrige os prompts. A só adiciona trabalho de leitura. C é lento demais — a confiança já está caindo. D degrada as boas categorias junto com as ruins. B ataca a causa preservando o que funciona.\n\n[ ] A - Keep all categories but display a confidence score with each finding.\n[ ] B - Temporarily disable high false positive categories (style, naming, documentation) and run only high-precision categories while improving prompts.\n[ ] C - Keep all categories enabled while adding few-shot examples to improve accuracy over the coming weeks.\n[ ] D - Apply a uniform strictness reduction across all categories to bring the overall false positive rate down.','\n',char(10)),'[ ] B - Temporarily disable high false positive categories (style, naming, documentation) and run only high-precision categories while improving prompts.','["Domain_4::Prompt_Engineering_Structured_Output", "Domain_5::Context_Management_Reliability", "Scenario_5::Claude_Code_CI_CD"]','New',0,2.5,0,1783092992689,1783727987882,1783203558653,replace('**Tradução para português do Brasil:**\n\nA análise mostra que as taxas de falso positivo variam: segurança/corretude 8%, desempenho 18%, estilo/nomenclatura 52%, documentação 48%.\n\nOs desenvolvedores estão descartando os achados sem revisão porque "metade está errada". As categorias com alta taxa de falso positivo estão prejudicando a confiança nas categorias precisas. Qual abordagem melhor recupera a confiança dos desenvolvedores enquanto melhora o sistema?\n\n[ ] A - Manter todas as categorias, mas exibir uma pontuação de confiança para cada achado.\n[ ] B - Desabilitar temporariamente as categorias com alta taxa de falso positivo (estilo, nomenclatura, documentação) e executar apenas as categorias de alta precisão enquanto melhora os prompts.\n[ ] C - Manter todas as categorias habilitadas enquanto adiciona exemplos few-shot para melhorar a precisão ao longo das próximas semanas.\n[ ] D - Aplicar uma redução uniforme de rigor em todas as categorias para reduzir a taxa geral de falso positivo.','\n',char(10)),replace('**Explicação didática para um adulto tech lead:**\n\nO cenário descreve um problema clássico de "sinal vs. ruído" em sistemas de análise estática ou revisão automatizada. Temos quatro categorias com taxas de falso positivo muito diferentes:\n\n- Segurança/Corretude: 8% (excelente, 92% de precisão)\n- Desempenho: 18% (bom, 82% de precisão)\n- Estilo/Nomenclatura: 52% (ruim, apenas 48% de precisão)\n- Documentação: 48% (ruim, apenas 52% de precisão)\n\nO problema não é apenas que existem falsos positivos — é que as categorias ruidosas (estilo e documentação) estão **contaminando a percepção geral** do sistema. Os desenvolvedores, ao verem que "metade está errada", param de revisar *qualquer* achado, incluindo os de segurança (8% de falso positivo), que são extremamente valiosos.\n\nVamos analisar as alternativas:\n\n**Alternativa A (Exibir pontuação de confiança):** Embora pareça razoável, adiciona complexidade cognitiva. O desenvolvedor já está frustrado e tendencioso a ignorar tudo. Uma pontuação de confiança não resolve a raiz do problema: as categorias ruidosas continuam poluindo a fila de revisões. O desenvolvedor ainda precisa gastar tempo filtrando manualmente. Além disso, se ele já está descartando tudo, não vai parar para ler pontuações de confiança.\n\n**Alternativa B (Correta):** Desabilitar temporariamente as categorias de alto falso positivo ataca o problema de forma cirúrgica:\n- **Restaura a confiança imediatamente**: as categorias restantes têm 8-18% de falso positivo (82-92% de precisão), o que é aceitável e dá credibilidade ao sistema.\n- **Melhora o sistema**: ao desabilitar temporariamente, você ganha tempo para revisar e melhorar os prompts dessas categorias sem pressão.\n- **Quebra o viés de "metade está errada"**: remove o ruído que estava contaminando a percepção.\n- **É uma medida reversível**: uma vez que os prompts estejam melhores, você reativa as categorias.\n\n**Alternativa C (Adicionar few-shot examples ao longo de semanas):** É a abordagem correta a longo prazo para *melhorar* o sistema, mas é lenta demais para *recuperar a confiança* agora. A confiança já está caindo — esperar "semanas" vai agravar o problema. Os desenvolvedores vão continuar ignorando todos os achados nesse período, incluindo alertas críticos de segurança.\n\n**Alternativa D (Redução uniforme de rigor):** É a pior abordagem. Reduzir o rigor uniformemente significa que você vai diminuir a sensibilidade das categorias *boas* (segurança e desempenho) para nivelar por baixo. Isso pode introduzir falsos negativos perigosos — alertas de segurança que deixam de ser disparados. Você estaria sacrificando a precisão das categorias críticas para acomodar as ruidosas, o que é contraproducente.\n\n**Conclusão:** A alternativa B é a única que atende simultaneamente aos dois requisitos da pergunta: (1) restaurar a confiança dos desenvolvedores de forma imediata e (2) melhorar o sistema a longo prazo, ao permitir o refinamento dos prompts problemáticos sem pressa.','\n',char(10)),replace('Imagine que você tem uma caixa de ferramentas com 4 ferramentas diferentes. Duas delas (Martelo e Chave de Fenda) funcionam muito bem — erram só de vez em quando. Mas duas outras (Tesoura e Cola) estão estragadas e erram METADE das vezes.\n\nO problema é que, quando alguém vê que "metade das ferramentas está errada", para de usar a caixa inteira, inclusive as ferramentas boas!\n\nA melhor solução é:\n1. Guardar as ferramentas estragadas (Tesoura e Cola) temporariamente.\n2. Continuar usando as ferramentas boas (Martelo e Chave de Fenda).\n3. Enquanto isso, consertar as ferramentas estragadas.\n\nDepois que as ferramentas estragadas estiverem consertadas, você coloca todas de volta na caixa.\n\nAs outras opções não funcionam tão bem porque:\n- A opção A (colocar um adesivo de "confiança" em cada ferramenta) não resolve — a pessoa ainda vai ter que testar cada uma.\n- A opção C (consertar tudo mas continuar usando as estragadas enquanto isso) faz com que as pessoas continuem desconfiando.\n- A opção D (deixar TODAS as ferramentas menos precisas) é a pior — você estraga as ferramentas boas junto com as ruins!','\n',char(10)));
INSERT INTO cards VALUES('admin','card_1783092992715_0rfx9nefa',485,'Subtle issues only surface when a different team member reviews the PR.',replace('Subtle issues only surface when a different team member reviews the PR.\n\nSubtle issues only surface when a different team member reviews the PR. Claude''s reasoning during generation shows it considered these cases but concluded its approach was correct. Which approach directly addresses the root cause of this self-review limitation?\nO que a pergunta pede: directly addresses the root cause of this self-review limitation → atacar a raiz da limitação de autorrevisão , não o sintoma.\n\nA pegadinha: O problema aparece quando outra pessoa revisa. A raiz é que o gerador não consegue revisar a si mesmo com isenção.\n\nRaciocínio: A raiz é o viés da autorrevisão: o mesmo raciocínio que escreveu o código não enxerga os próprios pontos cegos. B e D ainda são o mesmo modelo se revisando — não quebram o viés. C ajuda mas não ataca a raiz. A replica o que funcionou na vida real: um revisor independente que não vê o raciocínio original.\n\n[ ] A - Have a second, independent Claude instance review the changes without seeing the generator''s reasoning.\n[ ] B - Enable extended thinking for the generation pass, allowing more thorough deliberation.\n[ ] C - Include comprehensive tests and documentation in the prompt context during generation.\n[ ] D - Add explicit self-review instructions to the generation prompt, asking Claude to critique its own output.','\n',char(10)),'A - Have a second, independent Claude instance review the changes without seeing the generator''s reasoning.','["Domain_4::Prompt_Engineering_Structured_Output", "Scenario_5::Claude_Code_CI_CD"]','New',0,2.5,0,1783092992715,1783727991213,1783203558653,replace('**Tradução para português do Brasil:**\n\nProblemas sutis só aparecem quando um membro diferente da equipe revisa o PR.\n\nProblemas sutis só aparecem quando um membro diferente da equipe revisa o PR. O raciocínio de Claude durante a geração mostra que ele considerou esses casos, mas concluiu que sua abordagem estava correta. Qual abordagem ataca diretamente a causa raiz dessa limitação de autorrevisão?\n\n[ ] A - Fazer uma segunda instância independente do Claude revisar as alterações sem ver o raciocínio do gerador.\n[ ] B - Habilitar pensamento estendido (extended thinking) na passagem de geração, permitindo uma deliberação mais aprofundada.\n[ ] C - Incluir testes abrangentes e documentação no contexto do prompt durante a geração.\n[ ] D - Adicionar instruções explícitas de autorrevisão ao prompt de geração, pedindo que Claude critique sua própria saída.','\n',char(10)),replace('**Explicação para um adulto tech lead:**\n\nA pergunta descreve um fenômeno bem conhecido em engenharia de software: o viés do autor. Quando você mesmo escreve o código, seu cérebro já percorreu aquele caminho lógico e tende a "pular" os mesmos atalhos mentais que usou na escrita, não enxergando pontos cegos. O problema se manifesta quando outra pessoa revisa e encontra issues sutis que o autor não viu.\n\nO enunciado diz explicitamente: "Claude''s reasoning during generation shows it considered these cases but concluded its approach was correct." Ou seja, Claude considerou os cenários alternativos durante a geração, mas concluiu que sua abordagem estava correta — exatamente o mesmo viés de autorrevisão que um ser humano teria.\n\n**Por que A é a resposta correta:**\n\nA alternativa A propõe uma segunda instância independente do Claude que:\n1. Não tem acesso ao raciocínio original (evita contaminação cognitiva)\n2. Faz uma revisão verdadeiramente cega e imparcial\n3. Mimetiza o processo de code review humano, onde um revisor externo traz um olhar fresco\n\nIsso ataca a **causa raiz**: o viés de confirmação inerente a quem revisa o próprio trabalho. Ao introduzir uma segunda instância que não sabe qual foi o raciocínio do gerador, elimina-se o viés de ancoragem e viés de confirmação.\n\n**Análise das alternativas incorretas:**\n\n- **B** (extended thinking) — É como dar mais tempo para a mesma pessoa revisar o código que ela mesma escreveu. Mais deliberação não resolve o viés de confirmação; na verdade, pode reforçá-lo ao permitir que a pessoa construa racionalizações mais elaboradas para justificar suas decisões originais.\n\n- **C** (incluir testes e documentação) — É uma boa prática, mas não resolve o problema fundamental. Ter mais contexto não elimina o viés de autorrevisão. É como dar mais livros de referência para alguém que está convencido de que sua resposta está correta — a pessoa tenderá a buscar confirmação nos livros, não refutação.\n\n- **D** (instruções explícitas de autorrevisão) — É pedir que o mesmo modelo critique sua própria saída. O enunciado já deixa claro que Claude considerou os casos durante a geração e concluiu que estava certo. Instruções explícitas não quebram o viés intrínseco — o modelo continuará preso ao mesmo raciocínio que o levou à conclusão original. É como pedir para um advogado julgar o próprio caso.','\n',char(10)),replace('**Explicação para uma criança de 10 anos:**\n\nImagina que você desenhou um cachorro. Quando você termina, você acha que o desenho está perfeito. Mas aí seu amigo olha e diz: "Olha, você pintou o rabo do cachorro de azul, mas cachorro tem rabo marrom!" Você só percebeu o erro quando outra pessoa viu, porque quando você mesmo olha, seu cérebro já está acostumado com o desenho e não enxerga os errinhos.\n\nO problema é o mesmo aqui com o robô Claude. Quando ele gera um código e depois revisa ele mesmo, ele também não enxerga os próprios erros, porque já está "viciado" no raciocínio que usou para criar o código.\n\nAs opções:\n\n**A (a certa)** — Pegar um outro Claude que não viu o raciocínio original, como seu amigo que olha seu desenho sem saber que você pintou o rabo de azul. Esse outro robô vai olhar com olhos novos e achar os erros que o primeiro não viu.\n\n**B** — Dar mais tempo para o mesmo Claude pensar — isso não adianta, porque ele vai continuar pensando igual, só que por mais tempo.\n\n**C** — Colocar mais informações no prompt — é como dar dicionários para quem já acha que acertou tudo. A pessoa vai procurar nos dicionários só o que confirma que ela está certa.\n\n**D** — Pedir para o mesmo Claude se criticar — isso não funciona, porque ele já pensou sobre o assunto durante a criação e decidiu que estava certo. É como pedir para você mesmo encontrar erros no seu próprio desenho — você não consegue, porque seu olho já se acostumou.','\n',char(10)));
INSERT INTO cards VALUES('admin','card_1783092992740_3anae9b21',486,'The current prompt tells Claude to "check that comments are accurate and up-to-date.',replace('The current prompt tells Claude to "check that comments are accurate and up-to-date.\n\nThe current prompt tells Claude to "check that comments are accurate and up-to-date." Findings flag acceptable patterns (TODO markers) while missing comments that describe behavior the code no longer implements. What change addresses the root cause of this inconsistent analysis?\nO que a pergunta pede: addresses the root cause of this inconsistent analysis → a raiz da inconsistência.\n\nA pegadinha: A instrução atual ("accurate and up-to-date") é vaga . Critério vago → análise inconsistente.\n\nRaciocínio: A raiz é o critério vago. Defini-lo com precisão ( sinalizar só quando o comentário contradiz o código ) elimina tanto os falsos positivos (TODOs) quanto os falsos negativos. B trata um sintoma. C adiciona dado mas não cria um critério claro. D ajuda, mas A vai direto à raiz.\n\n[ ] A - Specify explicit criteria: flag comments only when their claimed behavior contradicts actual code behavior.\n[ ] B - Filter out TODO, FIXME, and descriptive comment patterns before analysis.\n[ ] C - Include git blame data so Claude can identify comments that predate recent modifications.\n[ ] D - Add few-shot examples of misleading comments to help the model recognize similar patterns.','\n',char(10)),'A - Specify explicit criteria: flag comments only when their claimed behavior contradicts actual code behavior.','["Domain_4::Prompt_Engineering_Structured_Output", "Domain_1::Agentic_Architecture_Orchestration", "Scenario_5::Claude_Code_CI_CD"]','New',0,2.5,0,1783092992740,1783727994302,1783203558653,replace('**Tradução para português do Brasil:**\n\nO prompt atual diz ao Claude para "verificar se os comentários são precisos e atualizados." Os resultados sinalizam padrões aceitáveis (marcadores TODO) enquanto perdem comentários que descrevem comportamento que o código não implementa mais. Qual mudança resolve a causa raiz dessa análise inconsistente?\n\n[ ] A - Especificar critérios explícitos: sinalizar comentários apenas quando o comportamento descrito contradiz o comportamento real do código.\n[ ] B - Filtrar padrões de TODO, FIXME e comentários descritivos antes da análise.\n[ ] C - Incluir dados de git blame para que o Claude possa identificar comentários anteriores a modificações recentes.\n[ ] D - Adicionar exemplos few-shot de comentários enganosos para ajudar o modelo a reconhecer padrões semelhantes.','\n',char(10)),replace('**Explicação para um adulto tech lead:**\n\nA raiz do problema é que o critério "accurate and up-to-date" é vago e subjetivo. Com um critério impreciso, o modelo não tem uma âncora consistente para decidir o que sinalizar — ele acaba sendo excessivamente permissivo (ignorando comentários obsoletos que descrevem comportamento que não existe mais) e excessivamente restritivo (sinalizando TODOs, que por definição são marcadores legítimos de trabalho pendente, não de imprecisão).\n\nA alternativa A resolve a causa raiz porque **substitui um critério vago por um critério objetivo e verificável**: a contradição entre o que o comentário *afirma* e o que o código *executa*. Isso torna a análise determinística — tanto o modelo quanto um revisor humano podem verificar a mesma coisa. Com "contradição" como gatilho, TODOs não são sinalizados (a menos que descrevam algo já implementado de forma diferente), e comentários desatualizados são pegos porque descrevem um comportamento que o código não tem.\n\nAnálise das demais alternativas:\n\n- **B (Filtrar TODOs, FIXMEs etc.):** Trata um sintoma (os falsos positivos), mas não resolve o falso negativo. Comentários obsoletos que não são marcadores TODO continuarão sendo perdidos porque o critério vago permanece. É uma solução paliativa.\n\n- **C (Incluir git blame):** Adiciona contexto histórico útil, mas não define o que constitui um comentário "impreciso". Git blame pode dizer *quando* um comentário foi escrito, mas não se ele contradiz o código hoje. Ajuda, mas não é a causa raiz.\n\n- **D (Adicionar exemplos few-shot):** Melhora o reconhecimento de padrões pelo modelo, mas ainda opera sobre um critério vago. Exemplos podem reduzir a inconsistência superficial, mas sem uma definição clara do que é "preciso e atualizado", o modelo continuará aplicando seu próprio julgamento subjetivo em casos fora dos exemplos.','\n',char(10)),replace('Vamos pensar em um jogo de "caça aos erros" nos comentários do código. A instrução atual diz: "veja se os comentários estão certinhos e atualizados". O problema é que essa instrução é muito parecida com dizer "desenhe um animal bonito" — cada pessoa vai desenhar uma coisa diferente, e ninguém sabe se acertou ou errou.\n\nO que acontece? O programa marca TODOs (que são anotações de coisas para fazer depois e estão perfeitamente corretas) como se fossem problema. Ao mesmo tempo, ele NÃO percebe quando um comentário diz "essa função soma dois números" mas na verdade o código agora está subtraindo — isso é um comentário mentiroso!\n\nA alternativa A resolve o problema de verdade porque troca uma regra confusa por uma regra muito clara: **só reclame do comentário se ele disser uma coisa e o código fizer outra diferente**. É como dizer: "só reclame se a legenda da foto não combinar com a foto". Agora todo mundo sabe exatamente o que fazer!\n\nAs outras opções são como colocar curativos em lugares diferentes, mas sem tratar a ferida principal. Filtrar TODOs (B) resolve um pouco, mas ainda perde os comentários mentirosos. Olhar o histórico do git (C) ajuda a saber quando o comentário foi escrito, mas não diz se ele está errado. Dar exemplos (D) é legal, mas ainda deixa a regra confusa para situações diferentes dos exemplos.','\n',char(10)));
INSERT INTO cards VALUES('admin','card_1783092992767_slouhc4jm',487,'After an initial review generates 12 findings, a developer pushes new commits.',replace('After an initial review generates 12 findings, a developer pushes new commits.\n\nAfter an initial review generates 12 findings, a developer pushes new commits. The review runs again and produces 8 findings — but 5 duplicate earlier comments on code already fixed. What''s the most effective way to eliminate this redundant feedback while maintaining thorough analysis?\nO que a pergunta pede: eliminate redundant feedback while maintaining thorough analysis → restrição dupla: eliminar redundância MAS manter a análise completa.\n\nA pegadinha: while maintaining thorough analysis elimina qualquer opção que reduza o que é analisado.\n\nRaciocínio: A solução precisa atender às duas metades. A (só o último push) perde a análise completa de interações com arquivos antigos. C pula commits intermediários (perde cobertura). D é frágil (correspondência exata de texto falha fácil). B dá ao Claude a memória dos achados anteriores para ele mesmo filtrar, mantendo a análise completa.\n\n[ ] A - Restrict the review scope to only files modified in the most recent push.\n[ ] B - Include prior review findings in context, instructing Claude to only report new or still-unaddressed issues.\n[ ] C - Run reviews only on initial PR creation and final pre-merge state, skipping intermediate commits.\n[ ] D - Add a post-processing filter that removes findings matching previous file paths and descriptions.','\n',char(10)),'B - Include prior review findings in context, instructing Claude to only report new or still-unaddressed issues.','["Domain_4::Prompt_Engineering_Structured_Output", "Domain_5::Context_Management_Reliability", "Scenario_5::Claude_Code_CI_CD"]','New',0,2.5,0,1783092992767,1783727998040,1783203558653,replace('**Tradução para português do Brasil:**\n\nPergunta: Após uma revisão inicial gerar 12 achados, um desenvolvedor envia novos commits. A revisão é executada novamente e produz 8 achados — mas 5 duplicam comentários anteriores sobre código já corrigido. Qual é a maneira mais eficaz de eliminar esse feedback redundante mantendo uma análise minuciosa?\n\n[ ] A - Restringir o escopo da revisão apenas aos arquivos modificados no commit mais recente.\n[ ] B - Incluir os achados da revisão anterior no contexto, instruindo o Claude a relatar apenas problemas novos ou ainda não resolvidos.\n[ ] C - Executar revisões apenas na criação inicial do PR e no estado final antes do merge, pulando commits intermediários.\n[ ] D - Adicionar um filtro de pós-processamento que remove achados que correspondam a caminhos de arquivos e descrições anteriores.','\n',char(10)),replace('**Explicação didática para um adulto tech lead:**\n\nA pergunta impõe uma restrição dupla: (1) eliminar feedback redundante E (2) manter uma análise minuciosa (thorough analysis). Qualquer alternativa que viole um desses dois requisitos está automaticamente descartada.\n\n**Análise detalhada das alternativas:**\n\n**Alternativa B (correta):** É a única que atende simultaneamente aos dois requisitos. Ao incluir os achados da revisão anterior no contexto (como mensagem de sistema ou no prompt), o Claude tem consciência do que já foi reportado. Com a instrução explícita de "relatar apenas problemas novos ou ainda não resolvidos", o modelo pode comparar o estado atual do código com os achados anteriores e decidir inteligentemente se um problema persiste ou foi corrigido. Isso elimina a redundância sem reduzir o escopo da análise — o Claude ainda examina todos os arquivos e interações, mas simplesmente não repete o que já foi dito sobre problemas que já não existem mais. É uma abordagem baseada em contexto e inteligência, não em filtragem mecânica ou redução de escopo.\n\n**Alternativa A (incorreta):** Restringir o escopo da revisão apenas aos arquivos do último commit viola "manter análise minuciosa". Um novo commit pode introduzir mudanças que interagem com arquivos não modificados no mesmo push. Além disso, problemas em arquivos não tocados no último push — mas que ainda existem — deixariam de ser reportados. A análise se torna parcial e potencialmente cega para regressões ou problemas latentes.\n\n**Alternativa C (incorreta):** Pular commits intermediários também viola a análise minuciosa. O propósito de revisar commits intermediários é justamente detectar problemas cedo, antes que o código evolua e se torne mais difícil de corrigir. Se você só revisa no início e no final, perde a oportunidade de feedback contínuo e ágil. Além disso, o problema apresentado (redundância em recomitação) não é resolvido — na verdade, ele é apenas evitado ao não revisar, o que não é a mesma coisa que "eliminar feedback redundante mantendo análise".\n\n**Alternativa D (incorreta):** Um filtro de pós-processamento baseado em correspondência exata de caminho de arquivo + descrição é frágil. Pequenas variações na redagem do achado (ex: "linha 42: variável não utilizada" vs "variável declarada mas nunca usada na linha 42") fariam o filtro não detectar a duplicata. Além disso, se um problema for genuinamente diferente mas compartilhar o mesmo arquivo e descrição similar, ele seria incorretamente filtrado. Por fim, isso não resolve o problema de "manter análise minuciosa" — o filtro age cegamente após a análise, potencialmente removendo achados válidos.\n\n**Conclusão:** A alternativa B é a única que emprega inteligência contextual (o próprio modelo decide com base nos achados anteriores), respeitando tanto a eliminação de redundância quanto a manutenção de uma análise completa e minuciosa.','\n',char(10)),replace('Imagina que você é um professor corrigindo a redação de um aluno. Na primeira vez, você encontra 12 erros e anota todos. O aluno corrige alguns e te entrega de novo. Agora você encontra 8 erros, mas 5 deles são os mesmos que você já tinha anotado antes — só que o aluno já corrigiu aquilo! Você não quer perder tempo repetindo os mesmos comentários, mas também não quer deixar de revisar o texto com atenção.\n\nQual a melhor solução?\n\n**Opção A:** Só olhar as partes que o aluno mudou. Ruim! Porque a parte que não mudou pode ter erros que você ainda não viu ou que continuam errados.\n\n**Opção B (a certa):** Você pega a lista de erros que achou da primeira vez e, ao corrigir de novo, fala pra você mesmo: "só vou marcar o que é NOVO ou o que continua errado". Assim você não repete os que já foram corrigidos, mas não deixa de olhar o texto inteiro.\n\n**Opção C:** Só corrigir na primeira e na última versão, pulando as versões do meio. Isso não resolve o problema — você só está evitando revisar, não está sendo esperto.\n\n**Opção D:** Usar um robô que apaga comentários iguais. Mas se o erro novo for parecido com um antigo, o robô pode apagar ele sem querer! Além disso, se o comentário estiver escrito com palavras diferentes, o robô não percebe que é o mesmo erro.\n\nEntão a resposta certa é a **B**: usar a lista de erros antigos como "lembrete" para só falar dos problemas novos ou que ainda não foram arrumados. É o jeito mais inteligente e completo!','\n',char(10)));
INSERT INTO cards VALUES('admin','card_1783092992796_vlfq5tpdv',488,'The code review works iteratively: Claude analyzes a file, then may request related files via tool calling before final feedback.',replace('The code review works iteratively: Claude analyzes a file, then may request related files via tool calling before final feedback.\n\nThe code review works iteratively: Claude analyzes a file, then may request related files via tool calling before final feedback. You''re evaluating batch processing. What is the primary technical constraint?\nO que a pergunta pede: primary technical constraint → a principal limitação técnica (o que tecnicamente impede ), não um mero inconveniente.\n\nA pegadinha: O fluxo é iterativo com tool calling (chama ferramenta → recebe → continua).\n\nRaciocínio: A pergunta pede a limitação técnica . O batch é assíncrono e não permite o loop interativo de tool-use no meio do processamento. C descreve uma desvantagem de latência, mas o otherwise function admite que o fluxo funcionaria — logo não é o que impede tecnicamente. A é a barreira real.\n\n[ ] A - The asynchronous model prevents executing tools mid-request and returning results for Claude to continue analysis.\n[ ] B - Batch processing lacks request correlation identifiers for matching outputs to inputs.\n[ ] C - Batch latency of up to 24 hours is too slow for PR feedback, though the workflow could otherwise function.\n[ ] D - The batch API doesn''t support tool definitions in request parameters.','\n',char(10)),'A - The asynchronous model prevents executing tools mid-request and returning results for Claude to continue analysis.','["Domain_3::Claude_Code_Configuration_Workflows", "Domain_5::Context_Management_Reliability", "Scenario_2::Code_Generation_Claude_Code"]','New',0,2.5,0,1783092992796,1783728001961,1783203558653,replace('TRADUÇÃO:\n\nO code review funciona iterativamente: Claude analisa um arquivo e então pode solicitar arquivos relacionados via tool calling antes do feedback final.\n\nVocê está avaliando processamento em lote (batch). Qual é a principal limitação técnica?\n\n[ ] A - O modelo assíncrono impede a execução de ferramentas (tools) no meio da requisição e o retorno dos resultados para que Claude continue a análise.\n[ ] B - O processamento em lote não possui identificadores de correlação de requisição para corresponder saídas a entradas.\n[ ] C - A latência do lote, de até 24 horas, é muito lenta para feedback de PR, embora o fluxo pudesse funcionar de outra forma.\n[ ] D - A API batch não suporta definições de ferramentas nos parâmetros da requisição.','\n',char(10)),replace('EXPLICAÇÃO PARA ADULTO TECH LEAD:\n\nA questão descreve um fluxo de code review que é inerentemente iterativo: Claude analisa um arquivo e, durante a mesma sessão, pode solicitar arquivos relacionados via tool calling para então continuar a análise e produzir um feedback final. Este é um loop síncrono e sequencial.\n\nA pergunta pede a **principal limitação técnica** — o que tecnicamente *impede* o funcionamento, e não um simples inconveniente.\n\n**Alternativa correta: A**\n\nO modelo de batch processing é assíncrono por definição. Você submete um conjunto de requisições e, posteriormente, consulta os resultados. Não há como, no meio do processamento de uma dessas requisições, fazer uma chamada de ferramenta, aguardar o retorno e continuar a análise. O fluxo iterativo com tool calling exige comunicação bidirecional em tempo real (request-response dentro da mesma sessão), o que o batch não suporta. Esta é a barreira técnica fundamental.\n\n**Por que as demais estão incorretas:**\n\n- **B** — Embora correlação de requisições seja uma consideração válida em sistemas distribuídos, não é a principal limitação técnica para o cenário descrito. Mesmo com identificadores perfeitos, o fluxo iterativo com tool calling ainda não funcionaria.\n\n- **C** — A latência é um problema operacional, não uma limitação técnica. O próprio texto da alternativa diz "though the workflow could otherwise function" (embora o fluxo pudesse funcionar de outra forma). Isso confirma que não é o que impede tecnicamente — é apenas uma questão de desempenho.\n\n- **D** — Esta afirmação é factualmente incorreta. A API batch da Anthropic (e de outros provedores) permite sim definir tools nos parâmetros da requisição batch. O problema não é a falta de suporte a tool definitions, mas sim a impossibilidade de executá-las iterativamente durante o processamento.','\n',char(10)),replace('Imagine que você está fazendo um trabalho de casa e precisa consultar seu irmão mais velho para tirar dúvidas. Você pergunta uma coisa, ele responde, e então você pergunta outra baseado na resposta que ele deu — é uma conversa de vai e vem.\n\nAgora pense no processamento em lote como enviar várias perguntas por escrito para seu irmão e só receber as respostas no dia seguinte. Se você precisar de uma informação extra que só descobriu depois de ler a primeira resposta, azar! Você não pode perguntar de novo porque já mandou tudo de uma vez.\n\nO fluxo de code review com ferramentas é como uma conversa: o programa analisa um arquivo, percebe que precisa de mais informações, usa uma ferramenta para buscar, recebe o resultado e continua pensando. No processamento em lote, isso não funciona porque ele não consegue "pedir mais informações" no meio do caminho. Essa é a verdadeira limitação técnica — o resto são só problemas chatos, mas que daria para dar um jeito.','\n',char(10)));
INSERT INTO cards VALUES('admin','card_1783092992823_c5h3mbxku',489,'Reviews identify valid issues but feedback isn''t actionable ("complex ticket allocation logic" without saying what to change).',replace('Reviews identify valid issues but feedback isn''t actionable ("complex ticket allocation logic" without saying what to change).\n\nReviews identify valid issues but feedback isn''t actionable ("complex ticket allocation logic" without saying what to change). Adding "always include specific fix suggestions" still produces inconsistent output. What prompting technique would most reliably produce consistently actionable feedback?\nO que a pergunta pede: most reliably produce consistently actionable feedback → consistência + feedback acionável.\n\nA pegadinha: Instruções explícitas já foram tentadas e falharam → a solução tem que ser outra técnica.\n\nRaciocínio: O enunciado diz que instruções explícitas já falharam — isso elimina C ("mais do mesmo"). Few-shot examples mostram em vez de descrever — a forma mais confiável de fixar um formato. A não resolve o formato; B é mais complexo que o necessário. D .\n\n[ ] A - Expand the context window to include more of the surrounding codebase.\n[ ] B - Implement a two-pass approach: one prompt identifies issues, a second generates fixes.\n[ ] C - Further refine the instructions with more explicit requirements for each part of the feedback.\n[ ] D - Add 3-4 few-shot examples showing the exact format: issue identified, code location, specific fix.','\n',char(10)),'[ ] D - Add 3-4 few-shot examples showing the exact format: issue identified, code location, specific fix.','["Domain_4::Prompt_Engineering_Structured_Output", "Domain_1::Agentic_Architecture_Orchestration", "Scenario_5::Claude_Code_CI_CD"]','New',0,2.5,0,1783092992823,1783728005649,1783203558653,replace('**Tradução para português do Brasil:**\n\nAs revisões identificam problemas válidos, mas o feedback não é acionável ("lógica de alocação de tickets complexa" sem dizer o que mudar).\n\nAs revisões identificam problemas válidos, mas o feedback não é acionável ("lógica de alocação de tickets complexa" sem dizer o que mudar). Adicionar "sempre inclua sugestões de correção específicas" ainda produz saída inconsistente. Qual técnica de prompt produziria o feedback acionável de forma mais consistente?\n\n[ ] A - Expandir a janela de contexto para incluir mais partes da base de código.\n[ ] B - Implementar uma abordagem de duas etapas: um prompt identifica problemas, um segundo gera correções.\n[ ] C - Refinar ainda mais as instruções com requisitos mais explícitos para cada parte do feedback.\n[ ] D - Adicionar 3-4 exemplos few-shot mostrando o formato exato: problema identificado, localização no código, correção específica.','\n',char(10)),replace('**Explicação didática para adulto tech lead:**\n\nO problema central é que instruções explícitas por si só falharam em produzir consistência ("adicionar ''sempre inclua sugestões de correção específicas'' ainda produz saída inconsistente"). Isso indica que o modelo precisa de algo além de comandos textuais para fixar o formato desejado.\n\n**Alternativa correta: D - Few-shot examples.**\n\nFew-shot learning é a técnica mais confiável para impor consistência de formato porque demonstra, ao invés de apenas descrever, o comportamento esperado. Modelos de linguagem são intrinsecamente melhores em imitar padrões vistos em exemplos do que em seguir instruções abstratas sobre formatação. Com 3-4 exemplos concretos mostrando "issue identificada → localização no código → correção específica", o modelo aprende por analogia o padrão exato de saída.\n\n**Por que as outras estão erradas:**\n\n- **A (expandir contexto):** Aumentar a janela de contexto não resolve o problema de formato de saída. O modelo pode ter até mais distrações com código adicional, mas continuará produzindo feedback genérico se não houver um padrão a ser seguido.\n\n- **B (two-pass):** Essa abordagem adiciona complexidade operacional e latência sem garantir consistência. O segundo prompt ainda sofreria do mesmo problema — sem exemplos concretos, ele pode gerar correções genéricas ou mal formatadas. Além disso, o enunciado pede uma técnica de *prompt*, não uma mudança arquitetural no pipeline.\n\n- **C (refinar instruções):** Isso já foi tentado e falhou, conforme o próprio enunciado. Instruções mais detalhadas ainda dependem da capacidade do modelo de interpretar e seguir comandos abstratos, o que é inerentemente menos confiável do que exemplos concretos.\n\n**Conclusão:** Few-shot examples são a técnica padrão-ouro para forçar consistência de formato em saídas de LLMs, especialmente quando instruções textuais já se mostraram insuficientes.','\n',char(10)),replace('Imagina que você está ensinando um robô a dar sugestões de melhoria para um dever de casa. Se você só falar "dê sugestões específicas", o robô pode ainda dar respostas vagas como "melhore isso". Mas se você mostrar 3 ou 4 exemplos prontos, tipo "aqui: ''trocar a cor do botão de azul para verde''", o robô aprende copiando esse jeito de responder.\n\nÉ a mesma lógica aqui: mostrar exemplos (few-shot) funciona melhor do que só dar ordens mais complicadas. As outras opções são como aumentar o texto que o robô pode ler (não ajuda), fazer o robô passar por duas etapas (mais trabalho, mesmo problema) ou dar ordens ainda mais detalhadas (já tentaram e não funcionou).','\n',char(10)));
INSERT INTO cards VALUES('admin','card_1783092992854_e8o4rsfq9',490,'Your CI runs the Claude Code CLI ( --print mode) with CLAUDE.',replace('Your CI runs the Claude Code CLI ( --print mode) with CLAUDE.\n\nYour CI runs the Claude Code CLI ( --print mode) with CLAUDE.md. Reviews are insightful but produce narrative paragraphs that must be manually copied into PR comments. You want to auto-post each finding as a separate inline comment, requiring structured data (file path, line, severity, fix). What''s the most effective approach?\nO que a pergunta pede: most effective approach para obter dados estruturados que possam ser postados automaticamente.\n\nA pegadinha: Postagem automática exige estrutura garantida — um formato de texto que o modelo "tenta" seguir não basta.\n\nRaciocínio: Para automação confiável, a estrutura garantida por flags nativas ( --output-format json com schema) é a mais robusta. A e B dependem de o modelo seguir um formato textual (frágil). C adiciona um passo extra e ainda parseia texto. D usa o recurso feito exatamente para isso.\n\n[ ] A - Add a "Review Output Format" section to CLAUDE.md with examples of structured findings.\n[ ] B - Include formatting instructions in the prompt requiring a parseable template like [FILE:path] [LINE:n] [SEVERITY:level].\n[ ] C - Keep the narrative format but add a summarization step that generates a structured JSON summary.\n[ ] D - Use CLI flags --output-format json and --json-schema to enforce structured findings, then parse and post via the GitHub API.','\n',char(10)),'D - Use CLI flags --output-format json and --json-schema to enforce structured findings, then parse and post via the GitHub API.','["Domain_4::Prompt_Engineering_Structured_Output", "Domain_3::Claude_Code_Configuration_Workflows", "Scenario_5::Claude_Code_CI_CD"]','New',0,2.5,0,1783092992854,1783728009409,1783203558653,replace('**Tradução para Português (Brasil):**\n\nSeu CI executa o Claude Code CLI (modo --print) com o CLAUDE.md. As revisões são perspicazes, mas produzem parágrafos narrativos que precisam ser copiados manualmente para os comentários do PR. Você quer publicar automaticamente cada descoberta como um comentário inline separado, exigindo dados estruturados (caminho do arquivo, linha, gravidade, correção). Qual é a abordagem mais eficaz?\n\n[ ] A - Adicionar uma seção "Formato de Saída da Revisão" ao CLAUDE.md com exemplos de descobertas estruturadas.\n[ ] B - Incluir instruções de formatação no prompt exigindo um modelo parseável como [FILE:path] [LINE:n] [SEVERITY:level].\n[ ] C - Manter o formato narrativo, mas adicionar uma etapa de sumarização que gera um resumo JSON estruturado.\n[ ] D - Usar as flags da CLI --output-format json e --json-schema para impor descobertas estruturadas, depois analisar e publicar via API do GitHub.','\n',char(10)),replace('**Explicação Didática para Adulto (Tech Lead):**\n\nO problema central aqui é a **confiabilidade da estrutura de dados** para automação. Quando você precisa que um sistema (CI) consuma a saída de outro sistema (Claude Code) e execute ações automatizadas (postar comentários inline no GitHub), você não pode depender de formatação "sugerida" ou "negociada" — você precisa de uma **garantia contratual** sobre a estrutura.\n\nVamos analisar cada alternativa:\n\n- **Alternativa A (Seção no CLAUDE.md):** Você está pedindo para o modelo seguir um formato descrito em um arquivo de configuração (CLAUDE.md). Isso é frágil porque o modelo pode desviar, interpretar ambiguamente ou simplesmente ignorar a seção em certos contextos. Não há enforcement — é uma sugestão, não um contrato.\n\n- **Alternativa B (Instruções no prompt com template):** Similar à A, mas no prompt. Modelos de linguagem são bons em seguir instruções, mas não são determinísticos. Um template textual como `[FILE:x] [LINE:y]` pode ser mal formatado, ter espaçamento inconsistente, ou sofrer de "alucinação" de estrutura. Parsear texto livre é sempre uma fonte de bugs.\n\n- **Alternativa C (Manter narrativo + sumarização):** Isso adiciona complexidade (um passo extra de processamento) e ainda depende de um parser de texto para extrair o JSON do resumo. Você está essencialmente terceirizando o problema de parsing para outro componente, sem resolver a causa raiz.\n\n- **Alternativa D (Flags nativas --output-format json e --json-schema):** Esta é a abordagem correta porque utiliza um mecanismo **nativo da ferramenta** para garantir a estrutura. Flags como `--output-format json` instruem o Claude Code a produzir saída estritamente em JSON, e `--json-schema` permite definir o schema exato (com campos como `file_path`, `line`, `severity`, `fix`). Isso cria um **contrato formal** — o modelo é forçado pelo próprio CLI a respeitar a estrutura, e qualquer desvio resulta em erro de validação. A saída é deterministicamente parseável por qualquer script (Python, jq, etc.) sem necessidade de expressões regulares frágeis.\n\n**Resumo:** Para automação confiável, prefira **enforcement nativo da ferramenta** (alternativa D) em vez de convenção textual (A, B) ou processamento adicional (C).','\n',char(10)),replace('**Explicação para uma criança de 10 anos:**\n\nImagina que você pediu para seu amigo escrever uma lista de coisas que ele achou legais no seu dever de casa. Mas ele escreve tudo em parágrafos grandes, e você precisa copiar cada ideia em um post-it diferente para colocar no mural. Dá trabalho, né?\n\nAgora, se você desse a ele um papel com espaços prontinhos: "Arquivo: ____", "Linha: ____", "Gravidade: ____", "Correção: ____", ele preencheria certinho e você só precisaria colar cada papel no mural.\n\nAlgumas opções são como pedir para ele "tentar" escrever bonitinho — mas ele pode esquecer ou errar. A melhor opção (letra D) é como dar a ele um **formulário obrigatório** que o computador já entende, sem chance de erro. É a mais esperta porque resolve o problema de uma vez, sem depender de sorte!','\n',char(10)));
INSERT INTO cards VALUES('admin','card_1783092992930_39pln6wxs',491,'Your review shows inconsistent severity ratings — similar issues like null pointer risks get "critical" in some PRs but "medium" in others.',replace('Your review shows inconsistent severity ratings — similar issues like null pointer risks get "critical" in some PRs but "medium" in others.\n\nYour review shows inconsistent severity ratings — similar issues like null pointer risks get "critical" in some PRs but "medium" in others. What''s the most effective way to improve severity consistency?\nO que a pergunta pede: most effective way to improve severity consistency → consistência nas notas de gravidade.\n\nA pegadinha: O mesmo problema recebe notas diferentes → falta uma âncora estável.\n\nRaciocínio: A inconsistência vem da falta de âncoras objetivas. Critérios explícitos com exemplos de código por nível dão referência estável entre PRs. B torna tudo relativo (o mesmo bug muda de nota conforme o PR — piora a consistência). C é uma lista estática que perde nuance. D exige trabalho manual. A .\n\n[ ] A - Include explicit severity criteria in your prompt with concrete code examples for each level.\n[ ] B - Ask Claude to rate severity relative to other issues in the same PR.\n[ ] C - Add a CLAUDE.md listing issue types and default severities to reference.\n[ ] D - Request Claude include its reasoning for each severity, then calibrate manually.','\n',char(10)),'A - Include explicit severity criteria in your prompt with concrete code examples for each level.','["Domain_4::Prompt_Engineering_Structured_Output", "Scenario_5::Claude_Code_CI_CD"]','New',0,2.5,0,1783092992930,1783728013167,1783203558653,replace('**Tradução para Português do Brasil:**\n\nSua revisão mostra classificações de gravidade inconsistentes — problemas semelhantes, como riscos de ponteiro nulo, recebem "crítico" em alguns PRs e "médio" em outros. Qual é a maneira mais eficaz de melhorar a consistência das classificações de gravidade?\n\n[ ] A - Incluir critérios explícitos de gravidade no seu prompt com exemplos concretos de código para cada nível.\n[ ] B - Pedir ao Claude para classificar a gravidade em relação a outros problemas no mesmo PR.\n[ ] C - Adicionar um arquivo CLAUDE.md listando tipos de problema e gravidades padrão para referência.\n[ ] D - Solicitar que o Claude inclua sua justificativa para cada gravidade e então calibrar manualmente.','\n',char(10)),replace('**Explicação para um adulto (Tech Lead):**\n\nO problema central é a falta de **âncoras objetivas e estáveis**. Quando você não define critérios claros, o modelo (Claude) acaba interpretando gravidade de forma subjetiva, variando conforme o contexto de cada PR.\n\n**Por que a alternativa A é a correta?**\n\nFornecer critérios explícitos com exemplos concretos de código para cada nível de severidade cria uma **régua fixa e universal**. O modelo passa a ter referências tangíveis: "ponteiro nulo sem validação em produção = crítico; ponteiro nulo em código morto ou inacessível = médio". Isso elimina a ambiguidade e padroniza a classificação entre diferentes PRs, pois o critério é absoluto, não relativo.\n\n**Por que as demais estão erradas:**\n\n- **B (classificar em relação a outros problemas no mesmo PR):** Essa abordagem torna a gravidade **relativa** — o mesmo bug pode ser classificado como "crítico" em um PR cheio de problemas triviais e "médio" em um PR com poucos problemas graves. Isso *introduz* ainda mais inconsistência entre PRs, exatamente o oposto do que se deseja.\n\n- **C (arquivo CLAUDE.md listando tipos e gravidades):** Embora pareça útil, uma lista estática sem exemplos de código é muito genérica. "Null pointer — Critical" não ajuda o modelo a distinguir quando um null pointer é crítico vs. quando é médio. Sem exemplos contextualizados, a interpretação continua subjetiva.\n\n- **D (justificativa + calibração manual):** Isso depende de trabalho humano intensivo (revisar e calibrar manualmente cada saída), o que não escala e não resolve a causa raiz — a falta de critérios objetivos. É uma abordagem reativa e custosa, não preventiva.\n\n**Resumo técnico:** A alternativa A ataca a causa raiz (falta de definições objetivas), enquanto B, C e D tratam sintomas ou introduzem novas fontes de variabilidade.','\n',char(10)),replace('**Explicação para uma criança de 10 anos:**\n\nImagine que você e seus amigos têm que dar notas para desenhos. Um desenho com um erro feio (como um rabisco no meio) ganha "nota 0" de um amigo, mas "nota 7" de outro. Isso é confuso, né?\n\nO problema da pergunta é parecido: a IA (Claude) está dando notas diferentes para erros iguais em programas de computador.\n\n**A melhor solução (alternativa A)** é criar uma "cola" com exemplos bem específicos:\n- "Se o erro é desse tipo A → nota 10 (crítico)"\n- "Se o erro é desse tipo B → nota 5 (médio)"\n\nCom exemplos de código de verdade, a IA sempre sabe qual nota dar, não importa em qual programa ela está olhando. É como ter um gabarito oficial!\n\n**Por que as outras opções não são tão boas:**\n\n- **B** seria comparar o desenho só com os outros desenhos da mesma pilha. Num dia de desenhos feios, um desenho meio feio parece bonito. Noutro dia de desenhos lindos, ele parece horrível. A nota muda! Isso não resolve o problema.\n\n- **C** é ter uma lista dizendo "erro de matemática = nota baixa", mas sem explicar quando é erro besta ou erro grave. Fica confuso ainda.\n\n- **D** é fazer a IA explicar por que deu cada nota, e você ter que conferir tudo manualmente. Dá muito trabalho e cansa!\n\n**Então a resposta certa é a A:** dar exemplos concretos de código para cada nível de gravidade, como um gabarito que funciona sempre!','\n',char(10)));
INSERT INTO cards VALUES('admin','card_1783092992961_s5932zd58',492,'A PR modifies 14 files.',replace('A PR modifies 14 files.\n\nA PR modifies 14 files. Your single-pass review is inconsistent: detailed for some files, superficial for others, bugs missed, and contradictory feedback (flagging a pattern in one file, approving identical code elsewhere). How should you restructure the review?\nO que a pergunta pede: how should you restructure the review → como reestruturar.\n\nA pegadinha: O problema é a passagem única sobre 14 arquivos (atenção diluída, contradições).\n\nRaciocínio: A raiz é a atenção diluída numa só passagem. Dividir em análise por arquivo (qualidade local consistente) + uma passagem de integração resolve tanto a superficialidade quanto as contradições. A só aumenta o contexto (não garante atenção uniforme). C é caro e não corrige contradições de raiz. D empurra o problema para o desenvolvedor. B .\n\n[ ] A - Switch to a larger-context model to give all 14 files attention in one pass.\n[ ] B - Split into focused passes: analyze each file individually, then a separate integration-focused pass examining cross-file data flow.\n[ ] C - Run three independent passes and only flag issues appearing in at least two.\n[ ] D - Require developers to split large PRs into 3-4 file submissions.','\n',char(10)),'B - Split into focused passes: analyze each file individually, then a separate integration-focused pass examining cross-file data flow.','["Domain_4::Prompt_Engineering_Structured_Output", "Domain_5::Context_Management_Reliability", "Scenario_5::Claude_Code_CI_CD"]','New',0,2.5,0,1783092992961,1783728016752,1783203558653,replace('**Tradução para português do Brasil:**\n\n> Um PR modifica 14 arquivos. Sua revisão em uma única passada é inconsistente: detalhada para alguns arquivos, superficial para outros, bugs foram perdidos e feedback contraditório foi dado (apontando um padrão em um arquivo e aprovando código idêntico em outro). Como você deve reestruturar a revisão?\n>\n> [ ] A – Mudar para um modelo de contexto maior para dar atenção a todos os 14 arquivos em uma única passada.\n> [ ] B – Dividir em passadas focadas: analisar cada arquivo individualmente e, em seguida, uma passada separada focada em integração, examinando o fluxo de dados entre arquivos.\n> [ ] C – Executar três passadas independentes e sinalizar apenas problemas que aparecerem em pelo menos duas delas.\n> [ ] D – Exigir que os desenvolvedores dividam PRs grandes em submissões de 3 a 4 arquivos.','\n',char(10)),replace('**Explicação didática para um adulto tech lead:**\n\nO problema central descrito é a **atenção diluída em uma única passada** sobre 14 arquivos. Isso leva a três sintomas clássicos: inconsistência de profundidade (uns arquivos recebem análise detalhada, outros superficial), bugs não detectados (por falta de foco) e contradições (aprova código idêntico em lugares diferentes porque o revisor não consegue manter o contexto completo na cabeça).\n\nA alternativa **B** resolve a raiz do problema ao quebrar a revisão em duas etapas com **propósitos distintos**:\n\n1. **Passada por arquivo (análise local):** Cada arquivo é examinado isoladamente com foco total. Isso garante consistência local: mesmos padrões são tratados da mesma forma dentro de cada arquivo. A atenção não é dividida entre 14 contextos simultaneamente.\n\n2. **Passada de integração (análise global):** Após a análise local, uma segunda passada examina exclusivamente o fluxo de dados entre arquivos, chamadas de função, contratos de interface e consistência entre módulos. Isso elimina as contradições entre arquivos e detecta bugs de integração.\n\n**Por que as demais alternativas estão erradas:**\n\n- **A (modelo de contexto maior):** Aumentar o contexto não garante atenção uniforme — o problema não é capacidade de processamento, mas sim a **natureza humana** (ou mesmo de LLMs) de ter desempenho inconsistente em tarefas longas. Um modelo maior ainda fará uma única passada, sujeito aos mesmos problemas de fadiga e distribuição desigual de atenção.\n\n- **C (três passadas independentes):** É caro (3x o esforço) e não resolve contradições de raiz — três passadas independentes podem produzir três conjuntos diferentes de contradições. A regra de "2 de 3" filtra ruído, mas não garante consistência local ou global. Além disso, bugs sutis podem aparecer em apenas uma passada e ser descartados.\n\n- **D (exigir PRs menores):** Isso apenas empurra o problema para o desenvolvedor, sem ensinar o revisor a fazer revisões melhores. PRs grandes às vezes são inevitáveis (refatorações, mudanças de API). O revisor precisa de uma estratégia, não de uma restrição externa. Além disso, PRs de 3-4 arquivos ainda podem ter contradições entre si se forem dependentes.','\n',char(10)),replace('Imagine que você tem que revisar o dever de casa de 14 colegas ao mesmo tempo. Se você tentar ler tudo de uma vez, vai se cansar, vai reparar bem nos detalhes de alguns, vai passar batido em erros de outros e ainda pode falar "isso está ótimo!" para um e "isso está errado!" para outro que fez a mesma coisa.\n\nA alternativa certa (B) é como fazer a revisão em duas rodadas:\n\n1. **Primeiro**, você lê o dever de cada colega um por um, com calma, prestando atenção só naquele. Assim você trata todo mundo igual e não se confunde.\n\n2. **Depois**, você dá uma olhada em como os deveres se conectam — por exemplo, se a resposta de um depende do cálculo do outro. Isso evita contradições.\n\nAs outras opções são piores:\n\n- **A** (usar uma lupa maior) não adianta — você ainda vai ler tudo de uma vez e continuar cansado.\n- **C** (ler três vezes e marcar só o que aparecer duas vezes) dá muito mais trabalho e pode fazer você ignorar erros que apareceram só uma vez.\n- **D** (pedir para os colegas entregarem menos páginas de cada vez) só empurra o problema para eles, sem te ajudar a revisar melhor.','\n',char(10)));
INSERT INTO cards VALUES('admin','card_1783092992994_lp82puhq7',493,'Claude suggests 10 test cases but 6 duplicate scenarios already covered in the existing test suite.',replace('Claude suggests 10 test cases but 6 duplicate scenarios already covered in the existing test suite.\n\nClaude suggests 10 test cases but 6 duplicate scenarios already covered in the existing test suite. What change would most effectively reduce duplicate suggestions?\nO que a pergunta pede: most effectively reduce duplicate suggestions → reduzir duplicatas.\n\nA pegadinha: O Claude não enxerga o que já existe → falta o contexto dos testes atuais.\n\nRaciocínio: A causa é simples: o Claude não vê os testes atuais. Dar esse contexto resolve na raiz. B é frágil (correspondência por nome falha). C só corta o volume (mesma proporção de duplicatas). D muda o foco mas ainda pode duplicar edge cases. A .\n\n[ ] A - Include the existing test file in the context so Claude can see what''s already covered.\n[ ] B - Post-process to filter suggestions whose names match existing test names.\n[ ] C - Reduce requested suggestions from 10 to 5.\n[ ] D - Instruct Claude to focus only on edge cases and error conditions.','\n',char(10)),'A - Include the existing test file in the context so Claude can see what''s already covered.','["Domain_5::Context_Management_Reliability", "Domain_4::Prompt_Engineering_Structured_Output", "Scenario_5::Claude_Code_CI_CD"]','New',0,2.5,0,1783092992994,1783728020210,1783203558653,replace('**Tradução**\n\nClaude sugere 10 casos de teste, mas 6 cenários duplicados já estão cobertos no conjunto de testes existente.\n\nClaude sugere 10 casos de teste, mas 6 cenários duplicados já estão cobertos no conjunto de testes existente. Qual mudança reduziria mais efetivamente as sugestões duplicadas?\n\n[ ] A - Incluir o arquivo de testes existente no contexto para que o Claude possa enxergar o que já está coberto.\n[ ] B - Aplicar pós-processamento para filtrar sugestões cujos nomes coincidam com nomes de testes existentes.\n[ ] C - Reduzir o número de sugestões solicitadas de 10 para 5.\n[ ] D - Instruir o Claude a focar apenas em casos extremos (edge cases) e condições de erro.','\n',char(10)),replace('**Explicação para adulto tech lead**\n\nA causa raiz do problema é clara: o Claude está gerando sugestões sem conhecer os testes que já existem. Ele não tem visibilidade do que já foi coberto, então naturalmente propõe cenários que já estão implementados. A abordagem mais eficaz é eliminar essa cegueira contextual.\n\nAnalisando cada alternativa:\n\n**A - Correta.** Incluir o arquivo de testes existente no contexto (via system prompt ou na mensagem do usuário) resolve o problema na fonte. O Claude passa a ter conhecimento do estado atual da suíte de testes e pode comparar, inferir cobertura e evitar sugerir algo já implementado. É uma solução preventiva e estrutural.\n\n**B - Incorreta.** Pós-processamento por correspondência de nomes é frágil e superficial. Nomes de testes podem ser diferentes mesmo testando o mesmo cenário (ex: "test_login_invalid_password" vs "test_login_wrong_credentials"), e nomes iguais podem ter implementações diferentes. Além disso, isso trata o sintoma, não a causa.\n\n**C - Incorreta.** Reduzir de 10 para 5 apenas diminui o volume absoluto de duplicatas, mas mantém a mesma proporção — se 60% eram duplicatas (6 de 10), com 5 pedidos provavelmente teríamos 3 duplicatas. O problema persiste.\n\n**D - Incorreta.** Focar em edge cases e erros pode até evitar algumas duplicatas de cenários felizes, mas o Claude continuará sem saber quais edge cases já existem. Ele pode muito bem sugerir um edge case que já está testado. A falta de contexto continua sendo o problema.','\n',char(10)),replace('Imagine que você pediu para um amigo desenhar 10 dinossauros diferentes. Só que você já tem 6 desenhos de dinossauros na sua pasta, mas seu amigo não viu essa pasta. Então ele desenha 10 dinossauros, e 6 deles são exatamente iguais aos que você já tinha! Que perda de tempo, né?\n\nA melhor solução é: mostrar a pasta com os desenhos que você já tem para o seu amigo ANTES dele começar a desenhar. Assim ele sabe o que já existe e não vai repetir.\n\nAs outras soluções são:\n- Tentar adivinhar pelos nomes dos desenhos (mas nomes diferentes podem ser do mesmo dinossauro!)\n- Pedir só 5 desenhos (aí ele repete menos, mas ainda repete)\n- Pedir para ele desenhar só dinossauros estranhos (mas ele continua sem saber quais você já tem)\n\nA opção A é a mais esperta: mostrar o que já existe para evitar repetição desde o começo.','\n',char(10)));
INSERT INTO cards VALUES('admin','card_1783092993025_spdbia6i1',494,'Your pipeline runs claude "Analyze this pull request.',replace('Your pipeline runs claude "Analyze this pull request.\n\nYour pipeline runs claude "Analyze this pull request..." but the job hangs indefinitely, waiting for interactive input. What''s the correct approach to run Claude Code in an automated pipeline?\nO que a pergunta pede: correct approach to run Claude Code in an automated pipeline → rodar de forma não interativa.\n\nA pegadinha: hangs... waiting for interactive input = trava esperando entrada interativa.\n\nRaciocínio: O modo não interativo (print/headless) é ativado pela flag -p (ou --print ), que faz o Claude Code executar e sair sem prompt interativo. --batch , CLAUDE_HEADLESS e o redirecionamento de stdin não são o mecanismo oficial. B .\n\n[ ] A - Add the --batch flag.\n[ ] B - Add the -p flag: claude -p "Analyze this pull request..."\n[ ] C - Redirect stdin from /dev/null.\n[ ] D - Set CLAUDE_HEADLESS=true before running.','\n',char(10)),'[ ] B - Add the -p flag: claude -p "Analyze this pull request..."','["Domain_3::Claude_Code_Configuration_Workflows", "Domain_5::Context_Management_Reliability", "Scenario_5::Claude_Code_CI_CD"]','New',0,2.5,0,1783092993025,1783728024039,1783203558653,replace('**Tradução para português do Brasil:**\n\nSeu pipeline executa o Claude: "Analise este pull request..." mas o job trava indefinidamente, esperando entrada interativa. Qual é a abordagem correta para executar o Claude Code em um pipeline automatizado?\n\n[ ] A - Adicionar a flag --batch.\n[ ] B - Adicionar a flag -p: claude -p "Analise este pull request..."\n[ ] C - Redirecionar o stdin para /dev/null.\n[ ] D - Definir CLAUDE_HEADLESS=true antes de executar.','\n',char(10)),replace('**Explicação didática para um adulto tech lead:**\n\nO problema central é que, por padrão, o Claude Code entra em modo interativo (REPL), aguardando comandos do usuário via stdin. Em um pipeline CI/CD, não há um operador humano para fornecer essa entrada — por isso o processo "hang" (fica travado).\n\nVamos analisar cada alternativa:\n\n**Alternativa A — --batch:** Esta flag não existe oficialmente no Claude Code. O termo "batch" pode remeter a outros sistemas (como OpenAI batch API), mas não é um mecanismo suportado pelo CLI do Claude Code. Logo, é uma alternativa incorreta.\n\n**Alternativa B — -p (ou --print):** Esta é a abordagem correta e documentada. A flag `-p` recebe uma string de prompt como argumento, fazendo com que o Claude Code execute o prompt, produza a saída e encerre imediatamente, sem entrar no modo interativo. É exatamente o que se precisa para um pipeline automatizado: execução única e não interativa.\n\n**Alternativa C — Redirecionar stdin de /dev/null:** Embora pareça lógico (já que o problema é esperar por stdin), isso não desativa o modo interativo. O Claude Code ainda tentará inicializar o loop de Leitura-Avaliação-Impressão (REPL) e, ao detectar stdin fechado, pode simplesmente falhar ou se comportar de forma indefinida — não é o mecanismo oficial para execução não interativa.\n\n**Alternativa D — CLAUDE_HEADLESS=true:** Essa variável de ambiente existe, mas seu propósito é controlar a renderização de componentes rich (como tabelas, markdown formatado etc.) em ambientes sem terminal. Ela não desativa o modo interativo. O processo ainda tentará entrar no REPL e aguardar entrada, mesmo com o cabeçalho "headless" ativado.\n\n**Conclusão:** A única maneira garantida de executar Claude Code em modo não interativo em um pipeline é usar a flag `-p` (ou `--print`) para fornecer o prompt diretamente na linha de comando. O comportamento está documentado oficialmente.','\n',char(10)),replace('Imagine que você tem um robô chamado Claude. Normalmente, você fala com ele, ele responde, e depois fica esperando você falar de novo. Ele fica "ouvindo" o tempo todo.\n\nAgora imagine que você coloca esse robô dentro de uma máquina automática (o "pipeline"). A máquina diz: "Claude, analise este código!" Mas o Claude termina de analisar e fica esperando... esperando... esperando você falar mais alguma coisa. Só que ninguém vai falar! Então ele trava.\n\nA solução é usar um comando especial. Em vez de chamar o Claude e deixar ele esperando, você usa a **flag -p** (de "print" ou "prompt"). Funciona assim: você já dá a instrução junto com o chamado, tipo "Claude, faça isso E SÓ ISSO, depois pare."\n\nAs outras opções são como tentar:\n- Tampar os ouvidos do robô (redirecionar stdin) — ele ainda fica esperando, mesmo sem ouvir nada.\n- Colocar um "modo silencioso" (CLAUDE_HEADLESS) — ele fica quietinho, mas ainda esperando.\n- Usar um comando que não existe (--batch) — é como pedir para o robô voar; ele não sabe fazer isso.\n\nEntão a resposta certa é a **B**: usar a flag `-p` com a instrução. Assim o Claude faz o trabalho e para na hora, sem ficar esperando.','\n',char(10)));
INSERT INTO cards VALUES('admin','card_1783092993066_pvi0avl5q',495,'Reviews average 15 findings with 40% false positives.',replace('Reviews average 15 findings with 40% false positives.\n\nReviews average 15 findings with 40% false positives. The bottleneck is investigation time: devs must click each finding to read reasoning before deciding. CLAUDE.md already has comprehensive rules, and stakeholders rejected any approach that filters findings before review. What change best addresses the investigation time bottleneck?\nO que a pergunta pede: best addresses the investigation time bottleneck → reduzir o tempo de investigação.\n\nA pegadinha: stakeholders rejected any approach that filters → NÃO pode filtrar antes da revisão. Isso mata A e D na hora.\n\nRaciocínio: A restrição proíbe filtrar (mata A e D ). O gargalo é ter que clicar para ler o raciocínio. Trazer raciocínio + confiança inline elimina o clique sem remover nenhum achado. C reorganiza mas não corta o tempo de leitura por achado. B .\n\n[ ] A - Surface only high-confidence findings, filtering out uncertain flags before devs see them.\n[ ] B - Require Claude to include its reasoning and confidence assessment inline with each finding.\n[ ] C - Categorize findings as "blocking" vs "suggestions" with tiered review requirements.\n[ ] D - Add a post-processor that suppresses findings matching historical false-positive signatures.','\n',char(10)),'[ ] B - Require Claude to include its reasoning and confidence assessment inline with each finding.','["Domain_4::Prompt_Engineering_Structured_Output", "Domain_2::Tool_Design_MCP_Integration", "Scenario_5::Claude_Code_CI_CD"]','New',0,2.5,0,1783092993066,1783728027910,1783203558653,replace('**Tradução fiel para pt-BR:**\n\nAs revisões têm, em média, 15 achados, com 40% de falsos positivos.\n\nO gargalo é o tempo de investigação: os devs precisam clicar em cada achado para ler o raciocínio antes de decidir. O arquivo CLAUDE.md já possui regras abrangentes, e as partes interessadas rejeitaram qualquer abordagem que filtre os achados antes da revisão. Qual mudança melhor resolve o gargalo do tempo de investigação?\n\n[ ] A - Exibir apenas achados de alta confiança, filtrando alertas incertos antes que os devs os vejam.\n[ ] B - Exigir que o Claude inclua seu raciocínio e avaliação de confiança inline com cada achado.\n[ ] C - Categorizar os achados como "impeditivos" vs "sugestões" com requisitos de revisão em níveis.\n[ ] D - Adicionar um pós-processador que suprime achados que correspondam a assinaturas históricas de falsos positivos.','\n',char(10)),replace('**Explicação didática para um adulto tech lead:**\n\nO problema central é claro: o gargalo é o *tempo de investigação* — cada desenvolvedor precisa clicar em cada um dos 15 achados para ler o raciocínio por trás da decisão da ferramenta. Isso é um problema de *custo de acesso à informação*: a informação necessária para decidir (o raciocínio) está atrás de um clique.\n\nA restrição crucial: "stakeholders rejected any approach that filters findings before review." Isso elimina imediatamente as alternativas **A** e **D**, pois ambas envolvem filtragem prévia (uma por confiança, outra por assinaturas históricas). A alternativa **C** reorganiza os achados em categorias, mas não elimina a necessidade de clicar e ler cada um — o desenvolvedor ainda precisa investigar tanto os "impeditivos" quanto as "sugestões" para tomar uma decisão informada. A categorização pode até aumentar a carga cognitiva, pois agora há uma decisão adicional sobre em qual nível cada achado se encaixa.\n\nA alternativa **B** ataca diretamente o gargalo: ao trazer o raciocínio e a confiança *inline* (ou seja, já visível sem clique), eliminamos o custo de acesso. O desenvolvedor pode escanear visualmente os 15 achados, ver imediatamente por que cada um foi levantado e com qual nível de confiança, e decidir rapidamente. Isso reduz o tempo por achado de "clique + leitura" para "leitura direta", um ganho de eficiência substancial sem filtrar absolutamente nada. É a única alternativa que respeita a restrição imposta pelos stakeholders e resolve a causa raiz do gargalo.\n\n**Explicação para uma criança de 10 anos:**\n\nImagina que você tem 15 bilhetes na sua mesa, e para saber o que cada um diz, você precisa abrir um envelope para ler. Isso demora muito, certo? O problema é que os programadores estão perdendo tempo abrindo cada envelope. Algumas pessoas queriam jogar alguns bilhetes fora sem nem abrir, mas os chefes não deixaram.\n\nA melhor ideia é escrever o que cada bilhete diz *do lado de fora do envelope*. Assim, você lê tudo rapidinho sem precisar abrir nada. É isso que a opção B faz: mostra o raciocínio e a confiança de cada achado logo de cara, sem precisar clicar. As outras opções ou jogam bilhetes fora (o que não pode) ou só organizam os envelopes de outro jeito, mas você ainda precisa abrir todos.','\n',char(10)),replace('Imagina que você tem 15 bilhetes na sua mesa, e para saber o que cada um diz, você precisa abrir um envelope para ler. Isso demora muito, certo? O problema é que os programadores estão perdendo tempo abrindo cada envelope. Algumas pessoas queriam jogar alguns bilhetes fora sem nem abrir, mas os chefes não deixaram.\n\nA melhor ideia é escrever o que cada bilhete diz *do lado de fora do envelope*. Assim, você lê tudo rapidinho sem precisar abrir nada. É isso que a opção B faz: mostra o raciocínio e a confiança de cada achado logo de cara, sem precisar clicar. As outras opções ou jogam bilhetes fora (o que não pode) ou só organizam os envelopes de outro jeito, mas você ainda precisa abrir todos.','\n',char(10)));
INSERT INTO cards VALUES('admin','card_1783092993106_wcvhx7xpm',496,'Two workflows: (1) a blocking pre-merge check that must complete before merging, (2) a technical debt report generated overnight.',replace('Two workflows: (1) a blocking pre-merge check that must complete before merging, (2) a technical debt report generated overnight.\n\nTwo workflows: (1) a blocking pre-merge check that must complete before merging, (2) a technical debt report generated overnight. Your manager proposes switching both to Batch for 50% savings. How should you evaluate this proposal?\nO que a pergunta pede: how should you evaluate this proposal → avaliar criticamente, não aceitar de olhos fechados.\n\nA pegadinha: blocking... must complete before merging (síncrono) vs overnight (pode esperar).\n\nRaciocínio: O pre-merge bloqueia o merge → não pode esperar 24h → síncrono. O relatório noturno tolera latência → batch (50% off). A é a divisão correta. C e D forçam batch no fluxo bloqueante (inviável); B abre mão da economia onde ela é possível.\n\n[ ] A - Use batch for the technical debt reports only; keep real-time for pre-merge checks.\n[ ] B - Keep real-time for both to avoid ordering issues.\n[ ] C - Switch both to batch with a timeout fallback to real-time.\n[ ] D - Switch both to batch with status polling.','\n',char(10)),'[ ] A - Use batch for the technical debt reports only; keep real-time for pre-merge checks.','["Domain_3::Claude_Code_Configuration_Workflows", "Domain_5::Context_Management_Reliability", "Domain_4::Prompt_Engineering_Structured_Output", "Scenario_5::Claude_Code_CI_CD"]','New',0,2.5,0,1783092993106,1783728031677,1783203558653,replace('**Tradução para português do Brasil:**\n\nDois fluxos de trabalho: (1) uma verificação bloqueante de pré-merge que deve ser concluída antes do merge; (2) um relatório de dívida técnica gerado durante a noite.\n\nSeu gerente propõe migrar ambos para o sistema Batch para economizar 50%. Como você deve avaliar essa proposta?\n\n[ ] A - Use batch apenas para os relatórios de dívida técnica; mantenha tempo real para as verificações de pré-merge.\n[ ] B - Mantenha tempo real para ambos para evitar problemas de ordenação.\n[ ] C - Migre ambos para batch com um fallback de timeout para tempo real.\n[ ] D - Migre ambos para batch com polling de status.','\n',char(10)),replace('**Explicação para um adulto (tech lead):**\n\nA proposta do gerente está tratando dois workloads com características diametralmente opostas como se fossem intercambiáveis, e isso é o erro central.\n\n**Por que A é a resposta correta:**\n\n- O **pre-merge check** é um workload **síncrono e bloqueante**: o desenvolvedor não consegue fazer merge do PR até que essa verificação passe. O tempo de resposta impacta diretamente o ciclo de desenvolvimento. Batch, por definição, introduz latência não-determinística (pode levar minutos ou horas para ser processado), o que quebraria o fluxo de CI/CD — ninguém vai esperar 24h para dar merge em um hotfix.\n- O **relatório de dívida técnica noturno** é um workload **assíncrono e tolerante a latência**: não há um ser humano esperando o resultado. Ele pode ser processado em lote durante a madrugada sem qualquer impacto na produtividade do time. Aplicar Batch aqui é a escolha ótima, obtendo os 50% de economia sem nenhum custo.\n\nA estratégia correta é tratar cada workload de acordo com seus requisitos não-funcionais: **o que é síncrono e crítico para o throughput do time fica em tempo real; o que é assíncrono e pode esperar vai para batch.**\n\n**Análise das alternativas incorretas:**\n\n- **B** — "Manter tempo real em ambos para evitar problemas de ordenação." É uma posição conservadora demais. Não existe problema de ordenação relevante em um relatório noturno — ele é um job único e atômico. Ao manter ambos em tempo real, você simplesmente abre mão da economia de 50% onde ela seria perfeitamente viável. É irracional do ponto de vista financeiro.\n- **C** — "Migrar ambos para batch com fallback de timeout para tempo real." O problema aqui é que o *fallback* só seria acionado após o timeout, mas o timeout já teria frustrado o desenvolvedor. No melhor dos casos, você adiciona complexidade desnecessária (lógica de fallback, monitoramento, estado compartilhado) e no pior caso, o merge do desenvolvedor leva 30 minutos porque o batch falhou e caiu no fallback. Você está tentando consertar um erro de design com um patch frágil.\n- **D** — "Migrar ambos para batch com polling de status." Polling não resolve a latência — você continua com o mesmo problema: o desenvolvedor não consegue mergear até que o batch processe. Polling é uma técnica para *consultar* o status, não para *acelerar* o processamento. Você teria a pior experiência de usuário (polling constante) com o pior tempo de resposta (batch). O pior dos dois mundos.','\n',char(10)),replace('**Explicação para uma criança de 10 anos:**\n\nImagina que você tem duas tarefas:\n\n1. **Verificar se o dever de casa está certo** — você precisa fazer isso *antes* de entregar para a professora. Se demorar, você fica travado e não consegue entregar. Isso é urgente!\n2. **Organizar a estante de livros** — você pode fazer isso à noite, antes de dormir. Não tem pressa. Pode até fazer tudo de uma vez.\n\nSeu chefe (gerente) disse: "Vamos fazer as duas coisas devagar (batch) para economizar dinheiro."\n\nMas se você fizer a verificação do dever de casa devagar, você vai ficar esperando e não vai conseguir entregar o trabalho! Você vai ficar bravo.\n\nA resposta certa (A) diz: "Faz a organização da estante devagar (batch) porque não tem pressa, mas deixa a verificação do dever de casa rápida (tempo real)."\n\nAs outras opções são ruins porque:\n- **B** — Faz as duas coisas rápidas, mas aí você gasta mais dinheiro sem precisar (a estante podia ser devagar).\n- **C** — Tenta fazer as duas coisas devagar, mas com um "despertador" para voltar ao rápido se demorar. Só que você já vai ter perdido tempo esperando.\n- **D** — Faz as duas coisas devagar e fica olhando o relógio a cada 5 segundos perguntando "já terminou? já terminou?". Não adianta, continua demorando!\n\nEntão a escolha inteligente é: **cada coisa no seu tempo. O que é urgente faz rápido; o que pode esperar, faz devagar e economiza.**','\n',char(10)));
INSERT INTO cards VALUES('admin','card_1783092993153_146til16d',497,'The document analysis subagent frequently fails on PDFs (corrupted sections, password-protected, library timeouts).',replace('The document analysis subagent frequently fails on PDFs (corrupted sections, password-protected, library timeouts).\n\nThe document analysis subagent frequently fails on PDFs (corrupted sections, password-protected, library timeouts). Currently any exception terminates the subagent and returns an error to the coordinator, causing excessive coordinator involvement in routine error handling. What''s the most effective architectural improvement?\nO que a pergunta pede: most effective architectural improvement → melhoria de arquitetura.\n\nA pegadinha: O coordenador é sobrecarregado com erros rotineiros → o subagente deveria tratar localmente o que consegue.\n\nRaciocínio: A causa é o coordenador envolvido em erros rotineiros. Dar ao subagente autonomia para resolver o transitório localmente, propagando só o irresolúvel (com contexto) reduz a sobrecarga mantendo a visibilidade. B mascara falhas como sucesso (perigoso). C joga o trabalho para o coordenador. D adiciona complexidade desnecessária. A .\n\n[ ] A - Have the subagent do local recovery for transient failures and only propagate errors it can''t resolve, including what was attempted and partial results.\n[ ] B - Have the subagent always return success with errors in metadata; the coordinator filters during synthesis.\n[ ] C - Have the coordinator validate all documents before dispatching.\n[ ] D - Create a dedicated error-handling agent monitoring all failures via a shared queue.','\n',char(10)),'A - Have the subagent do local recovery for transient failures and only propagate errors it can''t resolve, including what was attempted and partial results.','["Domain_1::Agentic_Architecture_Orchestration", "Domain_5::Context_Management_Reliability", "Scenario_3::Multi_Agent_Research"]','New',0,2.5,0,1783092993153,1783728035387,1783203558653,replace('**Tradução para português do Brasil:**\n\nO subagente de análise de documentos falha frequentemente em PDFs (seções corrompidas, protegidos por senha, timeouts de bibliotecas).\n\nAtualmente, qualquer exceção encerra o subagente e retorna um erro ao coordenador, causando envolvimento excessivo do coordenador em tratamento de erros rotineiros. Qual é a melhoria arquitetural mais eficaz?\n\n[ ] A - Fazer com que o subagente realize recuperação local para falhas transitórias e propague apenas os erros que não consegue resolver, incluindo o que foi tentado e resultados parciais.\n[ ] B - Fazer com que o subagente sempre retorne sucesso com erros nos metadados; o coordenador filtra durante a síntese.\n[ ] C - Fazer com que o coordenador valide todos os documentos antes de despachá-los.\n[ ] D - Criar um agente dedicado de tratamento de erros monitorando todas as falhas por meio de uma fila compartilhada.','\n',char(10)),replace('**Explicação para adulto tech lead:**\n\nO problema central é que o coordenador está sendo sobrecarregado com erros rotineiros e recuperáveis (PDF corrompido, timeout de biblioteca) que o subagente poderia tentar resolver sozinho. A abordagem correta (alternativa **A**) segue o princípio de **resiliência local e fail-fast controlado**: o subagente tenta recuperação local (re-tentar, baixar novamente, tentar biblioteca alternativa) e só escala para o coordenador o que é realmente irresolúvel. Isso reduz o acoplamento e o ruído no fluxo de orquestração.\n\n- **Alternativa A (correta):** Dá autonomia ao subagente para lidar com falhas conhecidas, preservando o coordenador para decisões excepcionais. Inclui resultado parcial e tentativas, o que é útil para debug e decisão.\n- **Alternativa B (incorreta):** Mascarar falha como sucesso viola o princípio da veracidade e pode corromper o resultado final, já que o coordenador pode não detectar corretamente erros ocultos em metadados.\n- **Alternativa C (incorreta):** Joga a responsabilidade de validação para o coordenador, que não é especialista em documentos, além de adicionar latência e acoplar ainda mais o fluxo.\n- **Alternativa D (incorreta):** Cria um agente extra que adiciona complexidade e latência sem resolver a causa raiz — o subagente ainda falharia da mesma forma e teria que se comunicar com outro agente.\n\n**Conclusão:** A alternativa A é a melhor porque trata erros na camada correta (local), reduzindo a carga do coordenador sem esconder falhas reais.','\n',char(10)),replace('Imagine que você tem um robô que analisa lições de casa (PDFs). Às vezes, a lição está com uma folha amassada ou manchada. O problema é que, quando isso acontece, o robô para tudo e chama o chefe (coordenador) para resolver. O chefe fica cansado de ter que resolver esses probleminhas toda hora.\n\nA melhor solução é ensinar o robô a tentar resolver sozinho: passar a folha novamente na máquina, tentar ler de outro jeito. Se ele conseguir, ótimo! Se não conseguir mesmo, aí sim ele chama o chefe e explica o que tentou e o que conseguiu fazer até onde deu.\n\nAs outras opções são piores:\n- A opção B seria o robô falar "deu certo!" mesmo com erro, escondendo o problema — isso é enganar o chefe.\n- A opção C seria o chefe ter que revisar todas as lições antes de entregar para o robô, mas ele não entende de lição, só de organizar.\n- A opção D seria criar um segundo robô só para cuidar dos erros, mas o primeiro robô continuaria travando do mesmo jeito.\n\nEntão, a melhor ideia é a A: ensinar o robô a se virar sozinho com os probleminhas comuns.','\n',char(10)));
INSERT INTO cards VALUES('admin','card_1783092993200_ltgalzwom',498,'The web search subagent queries three categories: academic databases returned 15 papers, industry reports returned "0 results found", patent databases returned "Connection timeout.',replace('The web search subagent queries three categories: academic databases returned 15 papers, industry reports returned "0 results found", patent databases returned "Connection timeout.\n\nThe web search subagent queries three categories: academic databases returned 15 papers, industry reports returned "0 results found", patent databases returned "Connection timeout." When designing error propagation, what approach enables the best recovery decisions?\nO que a pergunta pede: enables the best recovery decisions → melhores decisões de recuperação.\n\nA pegadinha: 0 results é um resultado válido (a busca funcionou, não achou nada); timeout é uma falha de acesso (vale repetir). Tratar igual é o erro.\n\nRaciocínio: A boa recuperação depende de diferenciar "não achei nada" (não adianta repetir) de "não consegui acessar" (vale repetir). B preserva essa distinção. A esconde numa métrica; D trata coisas distintas como iguais; C tira a decisão do coordenador. B .\n\n[ ] A - Aggregate outcomes into a single success-rate metric (e.g., "67% coverage").\n[ ] B - Distinguish access failures (timeout) needing retry from valid empty results ("0 results") representing successful queries.\n[ ] C - Have the subagent retry transient failures internally and report only persistent errors.\n[ ] D - Report both the timeout and "0 results" as failures.','\n',char(10)),'B - Distinguish access failures (timeout) needing retry from valid empty results ("0 results") representing successful queries.','["Domain_1::Agentic_Architecture_Orchestration", "Domain_2::Tool_Design_MCP_Integration", "Domain_5::Context_Management_Reliability", "Scenario_3::Multi_Agent_Research"]','New',0,2.5,0,1783092993200,1783728039194,1783203558653,replace('**Tradução para português do Brasil:**\n\nO subagente de busca na web consulta três categorias: bases acadêmicas retornaram 15 artigos, relatórios da indústria retornaram "0 resultados encontrados", bases de patentes retornaram "Tempo limite de conexão excedido". Ao projetar a propagação de erros, qual abordagem possibilita as melhores decisões de recuperação?\n\n[ ] A - Agregar os resultados em uma única métrica de taxa de sucesso (ex.: "cobertura de 67%").\n[ ] B - Distinguir falhas de acesso (timeout) que precisam de repetição de resultados vazios válidos ("0 resultados") que representam consultas bem-sucedidas.\n[ ] C - Fazer o subagente repetir falhas transitórias internamente e relatar apenas erros persistentes.\n[ ] D - Relatar tanto o timeout quanto "0 resultados" como falhas.','\n',char(10)),replace('**Explicação para um adulto tech lead:**\n\nA questão aborda um problema clássico de resiliência e observabilidade em sistemas distribuídos: como propagar erros de forma que o orquestrador (coordenador) tome decisões inteligentes de recuperação.\n\n**Análise das alternativas:**\n\n- **Alternativa B (correta):** Diferencia semanticamente os resultados. "0 resultados" em relatórios da indústria **não é uma falha** — a consulta executou com sucesso, simplesmente não havia dados. Já "Connection timeout" é uma **falha de acesso** — o serviço não respondeu, e a ação correta é tentar novamente (retry). Ao preservar essa distinção, o coordenador pode optar por repetir apenas onde faz sentido, sem desperdiçar recursos repetindo consultas que já deram certo (mas retornaram vazio). Essa é a abordagem mais alinhada com padrões como *Result Type* (success vs. failure vs. empty) e *Error Boundaries*.\n\n- **Alternativa A:** Agregar em uma métrica única (ex.: "2 de 3 sucesso") perde granularidade. O coordenador não sabe se o "fracasso" veio de um resultado vazio (que não precisa de retry) ou de um timeout (que precisa). Isso leva a decisões subótimas — ou repete tudo desnecessariamente, ou ignora falhas reais.\n\n- **Alternativa C:** Embora pareça elegante, a "repetição interna cega" pode mascarar problemas. Um subagente que repete timeouts infinitamente esgota recursos e atrasa a resposta. Além disso, o subagente não tem contexto global para decidir quantas repetições são adequadas — essa decisão deveria estar no coordenador. Viola o princípio de *fail-fast* e *circuit breaker*.\n\n- **Alternativa D:** Tratar "0 resultados" como falha é conceitualmente errado. Um resultado vazio é uma resposta perfeitamente válida de uma consulta bem-sucedida. Classificá-lo como erro distorce métricas de saúde do sistema e pode disparar alarmes falsos ou loops de retry infinitos.\n\n**Melhores práticas relacionadas:**\n- *Domain-driven error types* (Erros de domínio vs. erros técnicos)\n- *Result pattern* (Monads como `Result<T, E>` em Rust ou `Either` em Scala)\n- *Observability*: métricas separadas para "empty results" e "timeouts"\n- *Resilience4j / Polly*: Decidir retry com base no tipo de exceção','\n',char(10)),replace('**Explicação para uma criança de 10 anos:**\n\nImagine que você é o chefe de três amigos que foram pesquisar coisas para um trabalho da escola:\n\n- **Amigo 1 (acadêmico):** Voltou com 15 livros. Ótimo!\n- **Amigo 2 (relatórios):** Voltou e disse "não achei nada". Ele procurou direitinho, mas realmente não tinha nada.\n- **Amigo 3 (patentes):** Nem conseguiu entrar na biblioteca. O portão estava trancado (timeout).\n\nAgora, você precisa decidir se manda alguém tentar de novo.\n\n**Qual é a melhor forma de contar o que aconteceu?**\n\nA alternativa **B** é a certa porque ela diz: "O Amigo 2 não precisa repetir — ele fez o trabalho dele certinho, só não tinha nada para achar. Já o Amigo 3 precisa tentar de novo, porque o problema foi que ele não conseguiu entrar."\n\nAs outras opções são piores porque:\n- **A** (juntar tudo num número só): Você diria "67% de sucesso". Mas não saberia quem repetir.\n- **C** (deixar cada amigo repetir sozinho): O Amigo 3 ficaria tentando abrir o portão para sempre, sem você saber.\n- **D** (falar que os dois estão errados): Você mandaria o Amigo 2 repetir a busca mesmo ele já tendo feito certo. Perda de tempo!\n\n**Resumo:** É importante saber a DIFERENÇA entre "não achei nada" (tudo OK) e "não consegui tentar" (precisa repetir).','\n',char(10)));
INSERT INTO cards VALUES('admin','card_1783092993245_y37jbvc48',499,'When aggregated results total ~75K tokens, the synthesis agent reliably cites the first 15K and final 10K but omits findings in the middle 50K — even when relevant.',replace('When aggregated results total ~75K tokens, the synthesis agent reliably cites the first 15K and final 10K but omits findings in the middle 50K — even when relevant.\n\nWhen aggregated results total ~75K tokens, the synthesis agent reliably cites the first 15K and final 10K but omits findings in the middle 50K — even when relevant. How should you restructure the aggregated input?\nO que a pergunta pede: how should you restructure the aggregated input → reorganizar a entrada.\n\nA pegadinha: É o efeito "lost in the middle" (primazia/recência) — o modelo lembra do começo e do fim, esquece o meio.\n\nRaciocínio: A informação crítica está enterrada no meio. Um resumo dos achados-chave no início (posição de primazia) + cabeçalhos de seção navegáveis garante que o essencial não se perca. A perde detalhe. C só ajuda parcialmente. D só redistribui o problema. B .\n\n[ ] A - Summarize all outputs to under 20K tokens before aggregation.\n[ ] B - Place a key findings summary at the beginning and organize details with explicit section headers.\n[ ] C - Stream results incrementally, processing web search first.\n[ ] D - Rotate which subagent''s results appear first across tasks.','\n',char(10)),'B - Place a key findings summary at the beginning and organize details with explicit section headers.','["Domain_1::Agentic_Architecture_Orchestration", "Domain_5::Context_Management_Reliability", "Domain_4::Prompt_Engineering_Structured_Output", "Scenario_3::Multi_Agent_Research"]','New',0,2.5,0,1783092993245,1783728043299,1783203558653,replace('**Tradução para português do Brasil:**\n\nPergunta: "Quando os resultados agregados totalizam ~75K tokens, o agente de síntese cita de forma confiável os primeiros 15K e os últimos 10K, mas omite descobertas nos 50K do meio — mesmo quando relevantes. Como você deve reestruturar a entrada agregada?"\n\nAlternativas:\n[ ] A - Resumir todas as saídas para menos de 20K tokens antes da agregação.\n[ ] B - Colocar um resumo das descobertas principais no início e organizar os detalhes com cabeçalhos de seção explícitos.\n[ ] C - Transmitir os resultados de forma incremental, processando a pesquisa na web primeiro.\n[ ] D - Rotacionar qual subagente tem seus resultados apresentados primeiro entre as tarefas.','\n',char(10)),replace('**Explicação para adulto tech lead:**\n\nO problema descrito é o clássico efeito "lost in the middle" (perdido no meio), um fenômeno bem documentado em modelos de linguagem de grande porte (LLMs). Quando a entrada é muito longa (~75K tokens), o modelo tende a reter melhor as informações no início (primazia) e no final (recência) da janela de contexto, enquanto o conteúdo intermediário sofre degradação significativa na recuperação.\n\nVamos analisar cada alternativa:\n\n**Alternativa B (correta):** Colocar um resumo executivo das descobertas-chave logo no início da entrada explora o efeito de primazia — o modelo processa e retém essa informação crítica primeiro. Em seguida, organizar o restante com cabeçalhos de seção explícitos (ex: "## Seção 1: Análise de Mercado", "## Seção 2: Resultados Técnicos") oferece uma estrutura semântica navegável. Isso é eficaz porque: (a) o conteúdo essencial está numa posição de alta retenção, (b) os cabeçalhos funcionam como âncoras que ajudam o modelo a segmentar e recuperar informações específicas mesmo em posições intermediárias, e (c) não há perda de informação bruta.\n\n**Alternativa A (incorreta):** Resumir para menos de 20K tokens resolveria o problema ao reduzir drasticamente a entrada, mas com um custo alto — perda irreversível de detalhes e granularidade. Você joga fora ~73% do conteúdo original. Em cenários onde o detalhamento é importante (análise de logs, revisão de múltiplas fontes), isso é inaceitável. Além disso, a compressão em si (sumarização) pode introduzir viés ou omitir informações que o resumo não considerou relevantes.\n\n**Alternativa C (incorreta):** Processar incrementalmente, começando pela pesquisa web, não resolve o problema estrutural. O modelo ainda receberá ~75K tokens; apenas a ordenação parcial muda. A pesquisa web sendo processada primeiro pode, na verdade, piorar a situação se os resultados dela forem longos e empurrarem outros conteúdos para o "meio" da janela. Stream não mitiga o viés posicional do modelo.\n\n**Alternativa D (incorreta):** Rotacionar qual subagente aparece primeiro apenas redistribui o problema. Em algumas tarefas, o subagente A será lembrado; em outras, o subagente B. Mas em todas as tarefas, alguém será prejudicado pelo "lost in the middle". Não há garantia de que a informação mais relevante estará na posição favorecida. É uma solução paliativa que não trata a causa raiz.\n\nPortanto, a abordagem mais robusta é estruturar a entrada com um resumo de achados no início (aproveitando primazia) + cabeçalhos de seção (melhorando a navegabilidade atencional do modelo), mantendo todos os dados disponíveis sem perda.','\n',char(10)),replace('Imagine que você tem uma história muito, muito longa para contar para seu amigo. Seu amigo presta atenção no começo da história (porque é novo e interessante), presta atenção no final (porque a história está terminando), mas no meio ele começa a bocejar e esquece o que você falou. Isso é o que acontece com o computador quando damos a ele ~75 mil palavras — ele lembra do início e do fim, mas esquece o "meião".\n\nA alternativa B resolve isso assim: primeiro, você conta para o seu amigo um "resumão" de tudo que vai acontecer na história — assim ele já sabe o que é importante. Depois, você vai contando os detalhes, mas coloca "títulos" para cada parte, tipo "Capítulo 1: O Tesouro Escondido", "Capítulo 2: A Floresta Mágica". Esses títulos ajudam seu amigo (e o computador!) a saber onde cada coisa está, mesmo no meio da história.\n\nAs outras opções não são tão boas:\n- A seria como contar a história inteira em 3 frases — você perde todos os detalhes legais.\n- C seria como começar contando só uma parte da história primeiro — ainda vai ter um meio grande e chato.\n- D seria como trocar a ordem das partes da história a cada vez que você conta — sempre alguém vai ficar de fora.\n\nA melhor ideia é ter um resumo no começo e usar títulos para organizar — assim ninguém esquece nada!','\n',char(10)));
INSERT INTO cards VALUES('admin','card_1783092993289_5v8h7bylj',500,'A colleague suggests the document analysis agent send output directly to synthesis instead of routing through the coordinator.',replace('A colleague suggests the document analysis agent send output directly to synthesis instead of routing through the coordinator.\n\nA colleague suggests the document analysis agent send output directly to synthesis instead of routing through the coordinator. What is the main advantage of keeping the coordinator as the central hub?\nO que a pergunta pede: main advantage of keeping the coordinator as the central hub → a vantagem do hub central.\n\nRaciocínio: O valor do hub é controle e observabilidade : ver tudo, padronizar o tratamento de erros e controlar o fluxo de informação. A é um detalhe que outros desenhos também fariam; B é falso (o hub adiciona um salto, não reduz latência); D é tecnicamente impreciso. C .\n\n[ ] A - It enables automatic retry logic that direct calls can''t support.\n[ ] B - It batches requests, reducing API calls and latency.\n[ ] C - It can observe all interactions, handle errors consistently, and decide what information each subagent receives.\n[ ] D - Subagents have isolated memory, and direct communication needs complex serialization only the coordinator can do.','\n',char(10)),'[ ] C - It can observe all interactions, handle errors consistently, and decide what information each subagent receives.','["Domain_1::Agentic_Architecture_Orchestration", "Scenario_3::Multi_Agent_Research"]','New',0,2.5,0,1783092993289,1783728047072,1783203558653,replace('**Tradução para português do Brasil:**\n\nUm colega sugere que o agente de análise de documentos envie a saída diretamente para a síntese, em vez de rotear pelo coordenador.\n\nUm colega sugere que o agente de análise de documentos envie a saída diretamente para a síntese, em vez de rotear pelo coordenador. Qual é a principal vantagem de manter o coordenador como hub central?\n\n[ ] A - Ele permite lógica de retry automática que chamadas diretas não suportam.\n[ ] B - Ele agrupa requisições, reduzindo chamadas de API e latência.\n[ ] C - Ele pode observar todas as interações, tratar erros de forma consistente e decidir quais informações cada subagente recebe.\n[ ] D - Subagentes têm memória isolada, e a comunicação direta precisa de serialização complexa que apenas o coordenador pode fazer.','\n',char(10)),replace('**Explicação para um adulto tech lead:**\n\nA alternativa **C** está correta porque captura o valor arquitetural fundamental de um hub central (orquestrador) em sistemas multi-agentes. Manter o coordenador como hub central oferece três benefícios críticos:\n\n1. **Observabilidade total** — Todas as mensagens passam por um único ponto, permitindo logging, tracing e monitoramento centralizados. Em produção, isso é essencial para depuração, auditoria e análise de comportamento do sistema.\n\n2. **Tratamento consistente de erros** — O hub pode implementar políticas uniformes de retry, fallback, timeout e compensação. Se um subagente falha, o coordenador decide se tenta novamente, ignora ou aborta o fluxo — sem que cada agente precise implementar sua própria lógica.\n\n3. **Controle de informações** — O coordenador pode filtrar, transformar ou enriquecer dados antes de repassá-los, garantindo que cada subagente receba apenas o necessário (princípio do menor privilégio) e evitando vazamento de contexto irrelevante.\n\n**Por que as demais estão incorretas:**\n\n- **A —** Retry automático não é exclusivo de um hub central. Chamadas diretas entre agentes também podem implementar retry. A afirmação "chamadas diretas não suportam" é tecnicamente falsa.\n- **B —** O hub central adiciona um hop extra na comunicação, o que tende a *aumentar* a latência, não reduzi-la. Agrupamento de requisições (batching) pode ser feito em qualquer ponto, e o hub geralmente não reduz chamadas de API — ele as gerencia.\n- **D —** O coordenador não é o único capaz de lidar com serialização. Qualquer agente pode serializar/desserializar dados. A afirmação de que "apenas o coordenador pode fazer" é incorreta. Além disso, memória isolada de subagentes é um detalhe de implementação, não uma vantagem do hub central.','\n',char(10)),replace('Imagine que seus amigos estão montando um castelo de Lego. Cada amigo tem uma tarefa: um separa as peças vermelhas, outro monta as torres, outro coloca os bonecos.\n\nSe cada amigo ficar passando peças diretamente para o outro, ninguém sabe quem está fazendo o quê. Pode dar confusão: alguém recebe peça errada, alguém esquece de passar algo importante, e se um amigo errar, ninguém percebe.\n\nAgora imagine que tem um "coordenador" — um amigo que fica no meio. Ele recebe tudo de todo mundo, olha se está certo, decide o que cada um precisa receber e, se alguém errar, ele avisa e ajuda a consertar. Esse amigo coordenador consegue ver tudo que está acontecendo, e por isso a brincadeira funciona melhor.\n\nÉ isso que a alternativa C explica: o coordenador consegue ver todas as conversas, cuidar dos erros de forma justa para todo mundo e decidir qual informação cada agente (cada amigo) precisa receber. É a melhor resposta porque mostra exatamente por que ter alguém no centro ajuda o time todo.\n\nAs outras alternativas estão erradas porque:\n- A — qualquer amigo pode tentar de novo se errar, não precisa ser o coordenador.\n- B — na verdade, passar por um amigo no meio pode demorar um pouquinho mais, não acelera.\n- D — qualquer um pode ler e escrever mensagens, não só o coordenador.','\n',char(10)));
INSERT INTO cards VALUES('admin','card_1783092993442_iizev43z6',501,'When verification is needed, the synthesis agent returns control to the coordinator, which invokes web search, then re-invokes synthesis.',replace('When verification is needed, the synthesis agent returns control to the coordinator, which invokes web search, then re-invokes synthesis.\n\nWhen verification is needed, the synthesis agent returns control to the coordinator, which invokes web search, then re-invokes synthesis. This adds 2-3 round trips and increases latency by 40%. 85% are simple fact-checks; 15% require deeper investigation. What''s the most effective approach to reduce overhead while maintaining system reliability?\nO que a pergunta pede: reduce overhead while maintaining reliability → restrição dupla.\n\nA pegadinha: 85% simples vs 15% complexas → trate os dois grupos de formas diferentes .\n\nRaciocínio: A resposta certa atende às duas metades: reduz overhead (85% resolvidos localmente) E mantém confiabilidade (15% complexos seguem o caminho controlado). B dá poder demais ao agente (perde controle/confiabilidade); A não reduz a latência percebida; D é especulativo. C é o equilíbrio exato.\n\n[ ] A - Accumulate all verification needs and batch them to the coordinator at the end.\n[ ] B - Give the synthesis agent all web search tools to handle any verification directly.\n[ ] C - Give the synthesis agent a scoped verify_fact tool for simple lookups, while complex ones still delegate via the coordinator.\n[ ] D - Have the web search agent cache extra context anticipating verifications.','\n',char(10)),'C - Give the synthesis agent a scoped verify_fact tool for simple lookups, while complex ones still delegate via the coordinator.','["Domain_1::Agentic_Architecture_Orchestration", "Domain_2::Tool_Design_MCP_Integration", "Domain_4::Prompt_Engineering_Structured_Output", "Scenario_3::Multi_Agent_Research"]','New',0,2.5,0,1783092993442,1783728051191,1783203558653,replace('**Tradução para Português do Brasil:**\n\nQuando a verificação é necessária, o agente de síntese retorna o controle ao coordenador, que invoca a pesquisa na web e, em seguida, re-invoca a síntese.\n\nIsso adiciona de 2 a 3 viagens de ida e volta e aumenta a latência em 40%. 85% são verificações simples de fatos; 15% exigem investigação mais profunda. Qual é a abordagem mais eficaz para reduzir a sobrecarga (overhead) enquanto se mantém a confiabilidade do sistema?\n\n[ ] A - Acumular todas as necessidades de verificação e enviá-las em lote ao coordenador no final.\n[ ] B - Dar ao agente de síntese todas as ferramentas de pesquisa na web para lidar diretamente com qualquer verificação.\n[ ] C - Dar ao agente de síntese uma ferramenta de verificação de fatos com escopo definido (scoped verify_fact) para consultas simples, enquanto as complexas ainda delegam via coordenador.\n[ ] D - Fazer com que o agente de pesquisa na web armazene em cache contexto extra, antecipando verificações.','\n',char(10)),replace('**Explicação para um adulto tech lead:**\n\nO problema central é de arquitetura de sistemas baseados em agentes de IA: o gargalo atual é que *toda* verificação — mesmo as triviais — passa pelo coordenador, que faz uma chamada de web search e depois re-invoca a síntese. Isso gera um overhead fixo de 2-3 round trips por verificação, algo aceitável para os 15% de consultas complexas, mas altamente ineficiente para os 85% que são simples fact-checks.\n\nA análise das alternativas:\n\n- **Alternativa A (Acumular e enviar em lote):** Pode reduzir o número de viagens do coordenador, mas não reduz a latência percebida pelo usuário, que precisará esperar até o final para ter qualquer verificação feita. Além disso, acúmulos de verificações simples continuariam causando espera desnecessária. Viola o requisito de *reduzir overhead* sem ganho real em experiência.\n\n- **Alternativa B (Dar ao agente de síntese todas as ferramentas de web search):** Isso elimina o coordenador da jogada, mas quebra a restrição de *manter a confiabilidade*. Agora um agente com escopo genérico tem acesso irrestrito a fontes externas, sem governança centralizada (logging, aprovação de chamadas caras, rate limiting, etc.). Além disso, 15% dos casos que exigem investigação mais criteriosa perderiam a validação controlada do coordenador. É over-engineering que sacrifica controle.\n\n- **Alternativa C (Ferramenta scoped verify_fact para simples, delegando as complexas ao coordenador):** Atende perfeitamente à restrição dupla. Para os 85% de verificações simples (ex.: "qual a capital da França?"), o agente de síntese recebe uma ferramenta leve, de escopo limitado — por exemplo, uma função que consulta uma API de fact-checking rápida ou uma cache local de conhecimento validado. Isso corta drasticamente a latência para a maioria dos casos. Para os 15% que exigem investigação mais profunda (ex.: "qual foi o impacto da política X na economia Y em um contexto controverso?"), o caminho controlado via coordenador é preservado, mantendo a confiabilidade.\n\n- **Alternativa D (Cache de contexto extra pelo agente de web search):** Especulativo e frágil. Pré-cachear "contexto extra" antecipando verificações é um palpite sobre o que pode ser verificado, o que raramente é eficaz em sistemas reais. A sobrecarga de armazenamento e a baixa taxa de acerto típica tornam essa abordagem pouco prática. Além disso, ainda exige que o coordenador seja invocado para as verificações que não estiverem em cache.\n\nPortanto, a alternativa **C** é a mais equilibrada: segmenta o problema por tipo de carga (estratégia de "fast path" vs. "slow path"), otimizando o caso comum sem comprometer a qualidade do caso raro.','\n',char(10)),replace('Imagine que você tem uma professora (o coordenador) que ajuda você a verificar informações na internet. Toda vez que você precisa checar algo, você tem que andar até a mesa dela, esperar ela olhar no computador, e depois voltar. Isso demora muito!\n\n85% das suas perguntas são super rápidas, tipo "qual a capital do Brasil?". Mas 15% são difíceis, tipo "explique como funciona a economia da Argentina".\n\nAgora, pense nas opções:\n\n- **A:** Você guarda todas as perguntas para fazer no final da aula. Mas aí você fica esperando o tempo todo pra saber a resposta.\n- **B:** Você ganha o computador da professora e faz tudo sozinho. Mas você pode se atrapalhar ou acessar sites não confiáveis.\n- **C:** Você ganha um "dicionário rápido" que responde perguntas fáceis na hora (85% dos casos). Quando a pergunta é difícil, aí você vai até a professora (15% dos casos). É o melhor dos dois mundos!\n- **D:** Você tenta adivinhar quais perguntas a professora vai responder e anota antes. Mas você pode chutar errado e perder tempo.\n\nA melhor escolha é a letra **C**: dar uma ferramenta rápida para as perguntas simples, mas continuar pedindo ajuda para as complicadas. Assim, você acelera a maioria das respostas sem perder a qualidade das respostas difíceis.','\n',char(10)));
INSERT INTO cards VALUES('admin','card_1783092993472_ysxdcy4iz',502,'Two credible sources conflict: a government report says 40% growth, an industry analysis says 12%.',replace('Two credible sources conflict: a government report says 40% growth, an industry analysis says 12%.\n\nTwo credible sources conflict: a government report says 40% growth, an industry analysis says 12%. Both seem legitimate and the discrepancy affects conclusions. What''s the most effective way for the document analysis agent to handle this?\nO que a pergunta pede: most effective way to handle this → como tratar o conflito.\n\nA pegadinha: O agente de análise não deve decidir a verdade sozinho nem esconder o conflito.\n\nRaciocínio: Preserve a informação completa e transparente: registre os dois valores, marque o conflito claramente e passe a decisão para quem tem visão global (coordenador). A interrompe o trabalho sem necessidade; B esconde o conflito numa escolha unilateral; C omite a sinalização (a síntese pode nem perceber). D .\n\n[ ] A - Halt and escalate to the coordinator immediately before continuing.\n[ ] B - Apply credibility heuristics, pick one value, complete with a footnote.\n[ ] C - Include both without flagging them as conflicting, letting synthesis decide.\n[ ] D - Complete the analysis with both figures included, explicitly annotate the conflict with source attribution, and let the coordinator reconcile before synthesis.','\n',char(10)),'[ ] D - Complete the analysis with both figures included, explicitly annotate the conflict with source attribution, and let the coordinator reconcile before synthesis.','["Domain_1::Agentic_Architecture_Orchestration", "Domain_4::Prompt_Engineering_Structured_Output", "Domain_5::Context_Management_Reliability", "Scenario_3::Multi_Agent_Research"]','New',0,2.5,0,1783092993472,1783728058312,1783203558653,replace('**Tradução para português do Brasil:**\n\nDuas fontes confiáveis entram em conflito: um relatório governamental indica crescimento de 40%, enquanto uma análise do setor aponta 12%. Ambas parecem legítimas e a discrepância afeta as conclusões. Qual é a forma mais eficaz de o agente de análise de documentos lidar com essa situação?\n\n[ ] A - Parar e escalar imediatamente para o coordenador antes de continuar.\n[ ] B - Aplicar heurísticas de credibilidade, escolher um dos valores e finalizar com uma nota de rodapé.\n[ ] C - Incluir ambos sem sinalizá-los como conflitantes, deixando que a síntese decida.\n[ ] D - Concluir a análise com ambos os números incluídos, anotar explicitamente o conflito com a atribuição das fontes e deixar que o coordenador reconcilie antes da síntese.','\n',char(10)),replace('**Explicação didática para adulto (tech lead):**\n\nA alternativa **D** é a mais eficaz porque adota uma abordagem **transparente, rastreável e que preserva a decisão no nível correto da hierarquia**. O agente de análise de documentos deve ser um processador fiel de informações, não um árbitro de verdades conflitantes. Ao incluir ambos os valores, anotar explicitamente o conflito com atribuição clara às fontes e delegar a reconciliação ao coordenador (que tem visão de contexto, objetivos de negócio e critérios de qualidade), o agente cumpre seu papel sem introduzir viés ou interromper o fluxo prematuramente.\n\n**Por que as demais estão erradas:**\n- **A** — Interromper o pipeline de análise sem necessidade. O conflito não é uma falha catastrófica que exija parada imediata; é um dado relevante que deve ser processado e sinalizado. Parar o trabalho quebra a eficiência e sobrecarrega o coordenador com algo que poderia ser tratado de forma assíncrona.\n- **B** — Aplicar heurísticas de credibilidade e escolher unilateralmente um valor introduz viés do agente e perde informação crítica. A nota de rodapé é insuficiente porque não força a reconciliação nem alerta adequadamente quem vai consumir o dado. O agente não tem contexto para decidir qual fonte é "mais correta".\n- **C** — Incluir ambos sem sinalização explícita de conflito é uma omissão perigosa. A etapa de síntese pode não detectar a discrepância e gerar conclusões inconsistentes ou contraditórias, comprometendo a qualidade do resultado final.','\n',char(10)),replace('Imagine que você está juntando informações para um trabalho da escola. Duas fontes diferentes (um livro do governo e uma revista do mercado) dão números diferentes sobre o crescimento de alguma coisa: um diz 40%, outro diz 12%. Os dois parecem certos, mas não podem estar certos ao mesmo tempo. O que você faz?\n\nA melhor saída é a **D**: você anota os dois números no seu trabalho, escreve bem clarinho "esses dois não batem, vem de fontes diferentes" e deixa que seu professor (que é o coordenador) decida qual usar. Assim, você não esconde nada, não inventa uma resposta e mostra que foi esperto ao perceber o problema.\n\nAs outras opções são piores porque:\n- **A** — Parar tudo e chamar o professor na hora atrapalha seu trabalho e você poderia seguir adiante com outras partes.\n- **B** — Escolher um número sozinho, fingindo que o outro não existe, é trapacear — você não tem como saber qual é o certo.\n- **C** — Colocar os dois números no trabalho sem avisar que eles são diferentes faz o leitor achar que está tudo certo, e pode dar problema no final.','\n',char(10)));
INSERT INTO cards VALUES('admin','card_1783092993499_xl4tkscxg',503,'Combined outputs total 155K tokens (web search 85K with page content, document analysis 70K with reasoning chains), but synthesis performs optimally under 50K.',replace('Combined outputs total 155K tokens (web search 85K with page content, document analysis 70K with reasoning chains), but synthesis performs optimally under 50K.\n\nCombined outputs total 155K tokens (web search 85K with page content, document analysis 70K with reasoning chains), but synthesis performs optimally under 50K. What''s the most effective solution?\nO que a pergunta pede: most effective solution para caber sob 50K.\n\nA pegadinha: O excesso vem de conteúdo verboso (page content + reasoning chains), não da quantidade de fatos.\n\nRaciocínio: A raiz é a verbosidade. Fazer os agentes a montante emitirem só o essencial estruturado ataca a causa e melhora a qualidade. A complica o fluxo; C adiciona infraestrutura pesada; D adiciona um agente extra (e pode perder fidelidade). B corrige na fonte.\n\n[ ] A - Process findings in sequential batches, maintaining running state.\n[ ] B - Modify upstream agents to return structured data (key facts, citations, relevance) instead of verbose content and reasoning.\n[ ] C - Store findings in a vector database and give synthesis retrieval tools.\n[ ] D - Add an intermediate summarization agent before synthesis.','\n',char(10)),'[ ] B - Modify upstream agents to return structured data (key facts, citations, relevance) instead of verbose content and reasoning.','["Domain_2::Tool_Design_MCP_Integration", "Domain_4::Prompt_Engineering_Structured_Output", "Domain_1::Agentic_Architecture_Orchestration", "Scenario_3::Multi_Agent_Research"]','New',0,2.5,0,1783092993500,1783728065552,1783203558653,replace('**Tradução para Português do Brasil:**\n\nSaídas combinadas totalizam 155 mil tokens (pesquisa na web com 85 mil tokens de conteúdo de página, análise de documentos com 70 mil tokens de cadeias de raciocínio), mas a síntese tem desempenho ideal abaixo de 50 mil tokens. Qual é a solução mais eficaz?\n\n[ ] A - Processar os resultados em lotes sequenciais, mantendo estado em execução.\n[ ] B - Modificar os agentes upstream para retornar dados estruturados (fatos-chave, citações, relevância) em vez de conteúdo verboso e raciocínio.\n[ ] C - Armazenar os resultados em um banco vetorial e dar à síntese ferramentas de recuperação.\n[ ] D - Adicionar um agente de sumarização intermediário antes da síntese.','\n',char(10)),replace('**Explicação para Adulto (Tech Lead):**\n\n**Análise do Problema:**\nO problema central é que o pipeline está gerando 155K tokens brutos (85K de páginas web + 70K de cadeias de raciocínio dos agentes de análise), mas o módulo de síntese opera de forma ótima sob 50K. Não se trata de falta de informação relevante, mas de **excesso de verbosidade** — conteúdo bruto de páginas e cadeias de raciocínio explícitas que inflam artificialmente o volume de tokens.\n\n**Alternativa Correta: B**\nModificar os agentes upstream para retornar apenas dados estruturados (fatos, citações, relevância) ataca a **causa raiz**: a verbosidade na fonte. Ao invés de emitir parágrafos verbosos e cadeias de raciocínio completas, cada agente passa a retornar um payload enxuto e padronizado (ex.: `[{fact: "X", citation: "url", relevance: 0.95}, ...]`). Isso reduz drasticamente a contagem de tokens sem perder informação semântica — pelo contrário, melhora a qualidade ao eliminar ruído.\n\n**Análise das demais alternativas:**\n\n- **A (Processar em lotes sequenciais):** Isso apenas gerencia o estado do pipeline, mas não resolve o volume de tokens. Você ainda teria que passar 155K tokens pelo processo, apenas fragmentado. O problema de estouro de limite do sintetizador persistiria.\n\n- **C (Banco vetorial + ferramentas de retrieval):** Adiciona infraestrutura pesada (embedding, indexação, consulta) e complexidade operacional. Embora possa funcionar, é uma solução indireta que trata o sintoma (muito dado) com uma camada extra de tecnologia, quando o problema é mais simples: os agentes upstream produzem conteúdo inflado.\n\n- **D (Agente sumarizador intermediário):** Introduz latência, custo de tokens extra (o próprio sumarizador consome tokens para ler e resumir) e risco de perda de fidelidade na sumarização. É uma gambiarra que adiciona complexidade sem resolver a causa raiz — e o sumarizador pode consumir uma parte significativa dos 155K tokens só para processá-los.\n\n**Conclusão:**\nB é a solução mais eficaz porque modifica o **comportamento na origem**, reduzindo a verbosidade antes mesmo de chegar ao sintetizador. É uma abordagem de "design do sistema" (structured output dos agentes), que traz ganhos de eficiência, qualidade e simplicidade.','\n',char(10)),replace('**Explicação para Criança de 10 Anos**\n\nImagina que você pediu para seus amigos pesquisarem sobre dinossauros. Cada amigo volta e conta uma história enorme e cheia de detalhes (como eles pensaram, todas as palavras que leram, etc.). No final, você tem um monte de papel cheio de informação — mas você só precisa de uma folha para fazer o resumo final.\n\nO que a gente quer é que, em vez de cada amigo contar uma história gigante, eles tragam só os **pontos principais**: "T-rex tinha dentes grandes", "Vivia na América do Norte", "Comia carne" — e de onde tiraram isso. Assim o papel fica pequeno e organizado.\n\nA opção **B** é exatamente isso: ensinar os "agentes" (os ajudantes que pesquisam) a entregar só o essencial, em vez de textos enormes. É a melhor ideia porque resolve o problema logo no começo, sem precisar complicar com guardar coisas em lugares especiais (C), ler aos poucos (A) ou pedir para outra pessoa resumir (D — que daria mais trabalho ainda!).','\n',char(10)));
INSERT INTO cards VALUES('admin','card_1783092993527_axlru424d',504,'Requests to "analyze the quarterly report I uploaded" route to the web search agent 45% of the time.',replace('Requests to "analyze the quarterly report I uploaded" route to the web search agent 45% of the time.\n\nRequests to "analyze the quarterly report I uploaded" route to the web search agent 45% of the time. The web search agent has analyze_content ("analyzes content and extracts key information"); the document agent has analyze_document ("analyzes documents and extracts key information"). How should you address this misrouting?\nO que a pergunta pede: how should you address this misrouting → corrigir o encaminhamento errado.\n\nA pegadinha: As duas descrições são quase idênticas → o coordenador não distingue. A raiz é a ambiguidade da ferramenta de web search.\n\nRaciocínio: A causa é a colisão de descrições. Diferenciar a ferramenta ambígua na fonte (nome + descrição que deixa claro que é conteúdo web ) elimina a sobreposição. C corrige só um lado (a de web continua atraindo "analyze"); B e D adicionam camadas sem remover a ambiguidade de raiz. A .\n\n[ ] A - Rename the web tool to extract_web_results and redescribe it as "processes information retrieved from web searches and URLs."\n[ ] B - Add a pre-routing classifier.\n[ ] C - Expand only the document tool''s description, leaving the web tool unchanged.\n[ ] D - Add few-shot routing examples to the coordinator''s prompt.','\n',char(10)),'A - Rename the web tool to extract_web_results and redescribe it as "processes information retrieved from web searches and URLs."','["Domain_1::Agentic_Architecture_Orchestration", "Domain_2::Tool_Design_MCP_Integration", "Domain_4::Prompt_Engineering_Structured_Output", "Scenario_3::Multi_Agent_Research"]','New',0,2.5,0,1783092993527,1783728073016,1783203558653,replace('TRADUÇÃO:\n\nPergunta: Requisições para "analisar o relatório trimestral que enviei" são encaminhadas para o agente de busca web 45% das vezes.\n\nO agente de busca web tem analyze_content ("analisa conteúdo e extrai informações-chave"); o agente de documentos tem analyze_document ("analisa documentos e extrai informações-chave"). Como você deve resolver esse encaminhamento incorreto?\n\nAlternativas:\n[ ] A - Renomear a ferramenta web para extract_web_results e redesccrevê-la como "processa informações recuperadas de buscas web e URLs."\n[ ] B - Adicionar um classificador de pré-roteamento.\n[ ] C - Expandir apenas a descrição da ferramenta de documento, deixando a ferramenta web inalterada.\n[ ] D - Adicionar exemplos de roteamento few-shot ao prompt do coordenador.','\n',char(10)),replace('EXPLICAÇÃO PARA ADULTO TECH LEAD:\n\nO problema central é um **mau roteamento (misrouting)** causado por **ambiguidade semântica entre as descrições das ferramentas**. O coordenador (agente de roteamento) decide qual agente executar com base nos nomes e descrições das ferramentas disponíveis. Quando duas descrições são quase idênticas — "analyzes content and extracts key information" vs. "analyzes documents and extracts key information" — o coordenador não tem informação suficiente para distinguir adequadamente os casos. O resultado é que 45% das requisições sobre "analyze the quarterly report" (que deveriam ir para o agente de documentos) acabam no agente de busca web.\n\n**Análise das alternativas:**\n\n- **A (Correta):** Renomear a ferramenta web para `extract_web_results` e ajustar sua descrição para "processes information retrieved from web searches and URLs." Isso **elimina a ambiguidade na fonte**: o nome agora deixa claro que se trata de conteúdo web (não documentos genéricos), e a descrição especifica explicitamente o domínio de atuação (resultados de busca e URLs). O coordenador consegue distinguir claramente: se veio de uma busca web ou URL → web tool; se é um documento enviado → document tool. É a solução mais direta e de menor custo.\n\n- **B (Incorreta):** Adicionar um classificador de pré-roteamento resolve o sintoma (filtrar antes), mas não ataca a causa raiz (descrições ambíguas). É uma **solução mais complexa e cara** (requer treinar/manter um modelo adicional) que ainda pode falhar se o classificador não for perfeito. Além disso, adiciona latência e complexidade operacional desnecessárias.\n\n- **C (Incorreta):** Expandir apenas a descrição da ferramenta de documento mantém a ferramenta web com descrição genérica. Isso **não resolve a ambiguidade** — a ferramenta web continua atraindo requisições que mencionam "analyze", "content" e "key information", justamente os termos da requisição do usuário. O problema persiste porque a colisão semântica continua existindo.\n\n- **D (Incorreta):** Adicionar exemplos few-shot ao prompt do coordenador pode melhorar o roteamento em alguns casos, mas **não elimina a raiz do problema**. Few-shot examples são heurísticos e podem falhar em edge cases. A descrição ambígua continua sendo a fonte primária de confusão para o modelo. É um paliativo, não uma correção estrutural.\n\n**Conclusão técnica:** A melhor prática em design de sistemas de agentes é garantir que **nomes e descrições de ferramentas sejam semanticamente distintos e não sobreponíveis**. A alternativa A aplica exatamente esse princípio.','\n',char(10)),replace('EXPLICAÇÃO PARA CRIANÇA DE 10 ANOS:\n\nImagina que você tem dois amigos robôs:\n- O Robô Web, que sabe procurar coisas na internet.\n- O Robô Documento, que sabe ler papéis e arquivos.\n\nVocê dá um comando: "Analise o relatório trimestral que eu enviei." Mas os dois robôs têm etiquetas quase iguais nas suas portas! As etiquetas dizem mais ou menos a mesma coisa: "analisa conteúdo" e "analisa documentos". Então, o chefe dos robôs (o coordenador) fica confuso e manda o comando para o robô errado 45% das vezes — igual a jogar uma moeda e dar cara.\n\n**O que fazer?**\n\nA melhor ideia (alternativa A) é **mudar a plaquinha** do Robô Web para algo bem diferente, tipo: "extract_web_results — só serve para pegar informações de sites e links da internet." Assim, o coordenador entende clarinho: "Ah, isso é de site → mando pro Robô Web. Isso é um documento que a pessoa mandou → mando pro Robô Documento." Fim da confusão!\n\nAs outras opções:\n- B: Colocar um porteiro extra para decidir. Dá mais trabalho e não resolve a confusão das plaquinhas.\n- C: Só mudar a plaquinha de um robô, deixando o outro com a plaquinha genérica. A confusão continua!\n- D: Dar exemplos para o coordenador ("quando for relatório, manda pra lá"). Isso até ajuda um pouco, mas ainda pode errar porque a plaquinha confusa continua lá.\n\n**Resumo:** O problema é que as duas plaquinhas são parecidas. A solução é tornar uma delas bem diferente e específica. É como colocar um adesivo enorme escrito "SÓ PARA INTERNET" no Robô Web!','\n',char(10)));
INSERT INTO cards VALUES('admin','card_1783092993556_v58m2k1lc',505,'The web search and document analysis agents both investigate the same subtopics, doubling token usage without increasing coverage.',replace('The web search and document analysis agents both investigate the same subtopics, doubling token usage without increasing coverage.\n\nThe web search and document analysis agents both investigate the same subtopics, doubling token usage without increasing coverage. What''s the most effective way to address this?\nO que a pergunta pede: most effective way to address a sobreposição de trabalho.\n\nA pegadinha: O trabalho deveria ser dividido antes da delegação.\n\nRaciocínio: A forma mais eficaz previne a sobreposição na origem: o coordenador divide o espaço antes de delegar. A é reativa e complexa (coordenação em tempo real); B desperdiça o paralelismo; D deixa o desperdício acontecer e só limpa depois. C evita o custo em vez de remediar.\n\n[ ] A - Shared state where agents log their focus to avoid duplication dynamically.\n[ ] B - Sequential execution: document analysis runs after web search, using its findings as context.\n[ ] C - Have the coordinator partition the research space before delegation, assigning distinct subtopics/sources to each agent.\n[ ] D - Let both finish in parallel, then have the coordinator deduplicate afterward.','\n',char(10)),'[ ] C - Have the coordinator partition the research space before delegation, assigning distinct subtopics/sources to each agent.','["Domain_1::Agentic_Architecture_Orchestration", "Domain_2::Tool_Design_MCP_Integration", "Scenario_3::Multi_Agent_Research"]','New',0,2.5,0,1783092993556,1783728079568,1783203558653,replace('**Tradução para português do Brasil:**\n\nOs agentes de busca na web e de análise de documentos investigam os mesmos subtópicos, dobrando o uso de tokens sem aumentar a cobertura.\n\nQual é a forma mais eficaz de resolver isso?\n\n[ ] A - Estado compartilhado onde os agentes registram seu foco para evitar duplicação dinamicamente.\n[ ] B - Execução sequencial: a análise de documentos é executada após a busca na web, usando seus resultados como contexto.\n[ ] C - O coordenador particiona o espaço de pesquisa antes da delegação, atribuindo subtópicos/fontes distintas para cada agente.\n[ ] D - Deixar ambos terminarem em paralelo e, em seguida, o coordenador deduplicar posteriormente.','\n',char(10)),replace('**Explicação para um adulto Tech Lead:**\n\nA questão descreve um problema clássico de orquestração em sistemas multiagente (LLM): dois agentes independentes recebem o mesmo escopo de trabalho e acabam produzindo resultados redundantes, desperdiçando tokens (custo computacional) e tempo de processamento, sem ganho real de cobertura informacional.\n\nVamos analisar as alternativas:\n\n- **Alternativa A (Estado compartilhado com registro dinâmico):** Propõe uma abordagem reativa, onde os agentes consultam um estado central para saber o que já está sendo investigado e ajustam seu foco em tempo real. Embora funcione em teoria, introduz complexidade significativa: necessidade de sincronização, latência adicional para consultas/atualizações, risco de condições de corrida (race conditions), e ainda assim consumo extra de tokens com as chamadas de coordenação. É uma solução corretiva, não preventiva.\n\n- **Alternativa B (Execução sequencial):** Elimina o paralelismo, o que pode até resolver a duplicação, mas sacrifica drasticamente a performance. Em pipelines de pesquisa, o paralelismo é justamente um dos principais benefícios de usar múltiplos agentes. Além disso, forçar a análise de documentos a depender dos resultados da web search pode introduzir viés e limitar descobertas independentes. É jogar o bebê fora junto com a água do banho.\n\n- **Alternativa C (Particionamento pelo coordenador ANTES da delegação):** Esta é a abordagem mais eficaz porque ataca a causa raiz: a falta de definição de escopo no momento da delegação. Ao invés de remediar a duplicação depois ou coordenar em tempo real, o coordenador — que tem visão holística do objetivo — divide o "espaço de pesquisa" (subtópicos, fontes, períodos, domínios) em partições exclusivas e as atribui a cada agente. Isso elimina a sobreposição na origem, maximiza a cobertura total (soma das partes = todo), reduz o consumo de tokens ao mínimo necessário, preserva o paralelismo e mantém a arquitetura simples. É o princípio de "separação de concerns" aplicado à orquestração de agentes.\n\n- **Alternativa D (Paralelismo total + deduplicação posterior):** É o pior cenário em termos de eficiência. Dobra o consumo de tokens (já que ambos investigam tudo), gera trabalho duplicado, e ainda exige um passo adicional de deduplicação que também consome tokens e tempo de processamento. É aceitável apenas em protótipos rápidos onde simplicidade de implementação é priorizada sobre custo, mas definitivamente não é a forma mais Eficaz de "address this".\n\n**Conclusão:** A alternativa C é a mais eficaz porque é preventiva, preserva paralelismo, reduz custo, simplifica a arquitetura e resolve o problema na raiz.','\n',char(10)),replace('**Explicação para uma criança de 10 anos:**\n\nImagina que você e seu amigo precisam pesquisar sobre "animais da Amazônia" para um trabalho da escola.\n\n- Se os dois pegarem o mesmo livro sobre ariranhas e começarem a ler as mesmas páginas, vocês vão perder tempo e energia lendo a mesma coisa duas vezes. Fizeram trabalho dobrado, mas descobriram as mesmas coisas. Não foi eficiente, né?\n\nAgora vamos ver as opções:\n\n1. **Opção A:** Vocês combinam de ir gritando um para o outro "já li isso!" enquanto leem. Isso atrapalha, gasta energia e ainda corre o risco de um não ouvir o outro.\n\n2. **Opção B:** Um espera o outro terminar de ler TUDO para depois começar. Isso demora horrores! Perde a vantagem de serem dois.\n\n3. **Opção C (a melhor!):** Antes de começar, o professor (que é tipo o coordenador) divide o assunto: "Você pesquisa sobre ariranhas e seu amigo pesquisa sobre onças-pintadas". Pronto! Cada um foca no seu, não tem duplicação, e no final vocês juntam tudo. Descobrem mais coisas, gastam menos energia e terminam rápido.\n\n4. **Opção D:** Os dois leem tudo dobrado, gastam energia à toa, e depois o professor tem que catar o que é repetido e jogar fora. Muito desperdício!\n\nEntão a opção C é a mais esperta: **dividir o trabalho antes de começar**, para que cada um faça uma parte diferente. Assim não tem duplicação e o trabalho rende muito mais!','\n',char(10)));
INSERT INTO cards VALUES('admin','card_1783092993584_trkbzmvtu',506,'The web search subagent returns results for only 3 of 5 categories (2 timed out).',replace('The web search subagent returns results for only 3 of 5 categories (2 timed out).\n\nThe web search subagent returns results for only 3 of 5 categories (2 timed out). Document analysis succeeded. The synthesis subagent must produce a summary from this mixed-quality input. What''s the most effective error propagation strategy?\nO que a pergunta pede: most effective error propagation strategy → como propagar o estado de erro.\n\nA pegadinha: A síntese deve ser transparente sobre o que faltou — não esconder, nem travar tudo.\n\nRaciocínio: A melhor propagação é transparente e útil : produz a síntese possível e marca explicitamente onde há lacunas. B esconde as falhas (perigoso); C/D travam o fluxo por dados parcialmente úteis. A entrega valor e sinaliza a incerteza.\n\n[ ] A - Structure the synthesis output with coverage annotations indicating which findings are well-supported vs which areas have gaps from unavailable sources.\n[ ] B - Proceed using only the successful sources, without indicating what was unavailable.\n[ ] C - Have synthesis ask the coordinator to retry the timed-out sources with longer timeouts first.\n[ ] D - Have synthesis return an error for incomplete data, triggering a full retry or failure.','\n',char(10)),'A - Structure the synthesis output with coverage annotations indicating which findings are well-supported vs which areas have gaps from unavailable sources.','["Domain_1::Agentic_Architecture_Orchestration", "Domain_4::Prompt_Engineering_Structured_Output", "Domain_5::Context_Management_Reliability", "Scenario_3::Multi_Agent_Research"]','New',0,2.5,0,1783092993584,1783728086301,1783203558653,replace('## Tradução (Português-BR)\n\n**Pergunta:** O subagente de busca web retorna resultados para apenas 3 de 5 categorias (2 expiraram por tempo limite). A análise de documentos foi bem-sucedida. O subagente de síntese deve produzir um resumo a partir dessa entrada de qualidade mista. Qual é a estratégia de propagação de erros mais eficaz?\n\n[ ] A - Estruturar a saída da síntese com anotações de cobertura, indicando quais descobertas são bem fundamentadas versus quais áreas têm lacunas devido a fontes indisponíveis.\n[ ] B - Prosseguir usando apenas as fontes bem-sucedidas, sem indicar o que estava indisponível.\n[ ] C - Fazer com que a síntese peça ao coordenador para repetir as fontes que expiraram com timeouts maiores primeiro.\n[ ] D - Fazer com que a síntese retorne um erro por dados incompletos, acionando uma nova tentativa completa ou falha.','\n',char(10)),replace('## Explicação Didática para um Adulto (Tech Lead)\n\nA questão aborda um cenário clássico em sistemas multiagentes: **como lidar com dados parciais em um pipeline de síntese**. Vamos analisar cada alternativa:\n\n### Por que **A** é a resposta correta?\n\nA alternativa **A** implementa o que chamamos de **propagação transparente com anotação de confiança**. Ela reconhece que:\n- Dados parciais ainda têm valor significativo (3 de 5 categorias + análise de documentos OK).\n- O consumidor do resumo precisa saber **onde confiar** e **onde desconfiar** do resultado.\n- A estratégia não esconde o problema nem trava o fluxo — ela **enriquece a saída com metadados de cobertura**.\n\nIsso é especialmente importante em sistemas onde:\n- O resumo será usado para tomada de decisão (o decisor precisa saber se faltou informação).\n- O custo de retry é alto (repetir tudo poderia ser pior do que entregar parcial com aviso).\n- A transparência é um requisito não-funcional (auditabilidade, rastreabilidade).\n\n### Por que as demais estão erradas?\n\n- **B (usar só fontes bem-sucedidas, sem indicar falhas)**: Esta é uma **propagação silenciosa de perda de informação**. O consumidor do resumo não saberá que 2 das 5 categorias estão faltando. Isso pode levar a decisões incorretas com base em dados incompletos, sem qualquer sinalização. É o pior cenário: dados parciais apresentados como completos.\n\n- **C (pedir retry com timeouts maiores)**: Embora pareça razoável, esta estratégia **delega a decisão para o coordenador de forma inadequada**. A síntese não deveria ditar política de timeout — isso é responsabilidade do orquestrador/coordenador. Além disso, não há garantia de que aumentar o timeout resolverá o problema (as fontes podem simplesmente estar fora do ar). A abordagem também ignora o fato de que a análise de documentos foi bem-sucedida e pode gerar valor imediato.\n\n- **D (retornar erro e abortar)**: Esta é uma **propagação catastrófica**. Jogar fora 3 categorias bem-sucedidas + análise de documentos porque 2 categorias falharam é um desperdício. Em sistemas reais, dados parciais com anotação de incerteza são preferíveis a "tudo ou nada". Essa abordagem só faz sentido se a completude for um requisito **absolutamente crítico** — o que geralmente não é o caso em tarefas de síntese exploratória.\n\n### Conclusão técnica\n\nA melhor estratégia de propagação de erros em pipelines de síntese com qualidade mista é: **entregar o melhor resultado possível, mas sinalizar explicitamente suas limitações**. Isso mantém o fluxo, agrega valor imediato e preserva a capacidade do consumidor de julgar a confiabilidade do resultado.','\n',char(10)),replace('Imagine que você pediu para um amigo pesquisar 5 coisas diferentes para um trabalho de escola. Ele conseguiu achar informação de 3 coisas, mas 2 ele não encontrou porque o site estava muito lento. Você precisa escrever um resumo do que ele descobriu.\n\nA melhor coisa a fazer é: **escrever o resumo com o que você tem, mas avisar no texto quais partes estão incompletas**. Por exemplo: "Sobre as comidas típicas, eu descobri isso... [MAS não consegui informação sobre as danças típicas porque o site não abriu]."\n\nIsso é melhor do que:\n- Fingir que as 2 coisas que faltam não existem (engana quem lê).\n- Pedir para ele tentar de novo e deixar todo mundo esperando.\n- Desistir de tudo e não fazer resumo nenhum, perdendo o trabalho que já foi feito.\n\nEntão, a resposta certa é a **A**, porque você entrega o que conseguiu, mas avisa educadamente onde estão as falhas.','\n',char(10)));
INSERT INTO cards VALUES('admin','card_1783092993611_wdy9aix3b',507,'Both agents have completed and returned findings to the coordinator.',replace('Both agents have completed and returned findings to the coordinator.\n\nBoth agents have completed and returned findings to the coordinator. What is the appropriate next step for producing an integrated research output?\nO que a pergunta pede: appropriate next step for producing an integrated output → próximo passo para integrar.\n\nRaciocínio: A integração é função do agente de síntese , alimentado pelo coordenador. A quebra o papel dos agentes; B concatena sem integrar (não é síntese); D rompe a arquitetura de hub. C .\n\n[ ] A - The document agent requests the web results and merges them internally.\n[ ] B - The coordinator concatenates the raw outputs and returns them as the final result.\n[ ] C - The coordinator passes both sets of findings to the synthesis agent for unified integration.\n[ ] D - Each agent sends findings directly to the report agent, bypassing the coordinator.','\n',char(10)),'C - The coordinator passes both sets of findings to the synthesis agent for unified integration.','["Domain_1::Agentic_Architecture_Orchestration", "Domain_4::Prompt_Engineering_Structured_Output", "Scenario_3::Multi_Agent_Research"]','New',0,2.5,0,1783092993611,1783728093327,1783203558653,replace('**Tradução para português do Brasil:**\n\nAmbos os agentes concluíram e retornaram suas descobertas ao coordenador. Qual é o próximo passo adequado para produzir um resultado de pesquisa integrado?\n\n[ ] A - O agente de documento solicita os resultados da web e os mescla internamente.\n[ ] B - O coordenador concatena as saídas brutas e as retorna como resultado final.\n[ ] C - O coordenador passa ambos os conjuntos de descobertas para o agente de síntese para integração unificada.\n[ ] D - Cada agente envia descobertas diretamente ao agente de relatório, ignorando o coordenador.','\n',char(10)),replace('**Explicação para um adulto tech lead:**\n\nA pergunta descreve um cenário típico de arquitetura multi-agente, onde dois agentes especializados (provavelmente um agente de busca na web e um agente de documento, ou similares) já concluíram seu trabalho e reportaram seus resultados a um agente coordenador central (hub). O desafio agora é produzir um "resultado de pesquisa integrado" — ou seja, uma resposta coerente que una as descobertas de ambos os agentes de forma sinérgica, não apenas justaposta.\n\nVamos analisar as alternativas:\n\n- **Alternativa A**: "O agente de documento solicita os resultados da web e os mescla internamente." Isso quebra o padrão arquitetural estabelecido. O agente de documento não deveria buscar resultados da web diretamente, pois isso o transformaria em um agente híbrido e viola a separação de responsabilidades (cada agente tem um escopo definido). Além disso, o coordenador já recebeu as descobertas de ambos os agentes; fazer um agente buscar novamente os dados do outro é ineficiente e desnecessário.\n\n- **Alternativa B**: "O coordenador concatena as saídas brutas e as retorna como resultado final." Concatenar textualmente as saídas brutas não é "integrar", é apenas justapor. O resultado seria uma colagem sem coesão, possivelmente com informações redundantes, contradições não resolvidas e formatação inconsistente. Uma verdadeira integração exige análise cruzada, deduplicação, síntese e reorganização do conteúdo em um fluxo lógico e coerente.\n\n- **Alternativa C**: "O coordenador passa ambos os conjuntos de descobertas para o agente de síntese para integração unificada." Esta é a abordagem correta. Em arquiteturas multi-agente bem projetadas, o agente coordenador (hub) orquestra o fluxo, mas não necessariamente executa todas as tarefas. A síntese — que é uma tarefa cognitivamente complexa de unificação e sumarização — é delegada a um agente especializado (o agente de síntese). O coordenador coleta, valida e repassa os dados; o agente de síntese processa e produz o output integrado. Isso respeita o princípio de responsabilidade única e mantém a escalabilidade do sistema.\n\n- **Alternativa D**: "Cada agente envia descobertas diretamente ao agente de relatório, ignorando o coordenador." Isso rompe a arquitetura de hub-and-spoke (estrela), que é a premissa do cenário (o enunciado afirma que ambos os agentes já retornaram ao coordenador). Ignorar o coordenador introduz acoplamento direto entre agentes, dificulta a governança centralizada (controle de fluxo, logging, validação) e torna o sistema mais frágil e menos manutenível.\n\nPortanto, a resposta correta é a **alternativa C**, pois mantém a integridade arquitetural, respeita a especialização dos agentes e produz um resultado genuinamente integrado.','\n',char(10)),replace('Imagine que você e seu amigo estão fazendo uma pesquisa para um trabalho da escola. Você ficou responsável por procurar informações sobre dinossauros e seu amigo ficou responsável por procurar informações sobre fósseis. Vocês dois terminaram e entregaram suas anotações para a coordenadora do grupo, que é a responsável por organizar tudo.\n\nO que a coordenadora deve fazer para criar um trabalho que junte as duas pesquisas?\n\n- Opção A: Pedir para você pegar as anotações do seu amigo e tentar juntar tudo sozinho. Isso não é legal porque cada um já fez sua parte; não faz sentido você refazer o trabalho do outro.\n\n- Opção B: A coordenadora simplesmente grampeia as folhas de vocês dois e entrega assim mesmo. Isso não é um trabalho integrado — ficariam partes soltas, repetindo informações, sem uma história contínua.\n\n- Opção C: A coordenadora pega as anotações de vocês dois e entrega para uma pessoa especialista em juntar informações (o "agente de síntese"). Essa pessoa lê tudo, organiza, tira o que está repetido e escreve um texto único e bonito que conta a história completa dos dinossauros e fósseis. Essa é a melhor escolha!\n\n- Opção D: Cada um de vocês ignora a coordenadora e entrega as anotações direto para quem vai digitar o trabalho. Isso bagunça tudo porque a coordenadora não sabe mais o que está acontecendo e pode gerar confusão.\n\nA opção C é a correta porque usa a pessoa certa (o especialista em juntar informações) para criar um resultado final organizado e completo, sem bagunçar as funções de cada um.','\n',char(10)));
INSERT INTO cards VALUES('admin','card_1783092993638_ab8vlrunr',508,'You gave the document analysis agent a general fetch_url tool.',replace('You gave the document analysis agent a general fetch_url tool.\n\nYou gave the document analysis agent a general fetch_url tool. It now frequently fetches search engine result pages to do ad-hoc searches — behavior that should route through the web search agent. What''s the most effective fix?\nO que a pergunta pede: most effective fix → correção mais eficaz.\n\nA pegadinha: A ferramenta genérica demais permite o abuso. A correção limpa restringe a capacidade por design.\n\nRaciocínio: A correção mais robusta troca a ferramenta ampla por uma de escopo restrito ( load_document que valida o formato), eliminando o abuso por design (menor privilégio). A é frágil (lista de domínios nunca completa); B depende do modelo obedecer. C . (Obs.: D também é um design defensável; em provas da Anthropic, a preferência costuma ser a ferramenta de escopo apertado.)\n\n[ ] A - Filter/block fetch_url calls to known search-engine domains.\n[ ] B - Add prompt instructions to use fetch_url only for document URLs.\n[ ] C - Replace fetch_url with a load_document tool that validates URLs point to document formats.\n[ ] D - Remove fetch_url from the document agent and route all URL loading through the coordinator to the web search agent.','\n',char(10)),'[ ] C - Replace fetch_url with a load_document tool that validates URLs point to document formats.','["Domain_2::Tool_Design_MCP_Integration", "Domain_1::Agentic_Architecture_Orchestration", "Scenario_3::Multi_Agent_Research"]','New',0,2.5,0,1783092993638,1783728100167,1783203558653,replace('**Tradução para português do Brasil:**\n\nVocê deu ao agente de análise de documentos uma ferramenta genérica fetch_url.\n\nAgora, ele frequentemente acessa páginas de resultados de mecanismos de busca para fazer pesquisas ad-hoc — comportamento que deveria passar pelo agente de busca web. Qual é a correção mais eficaz?\n\n[ ] A - Filtrar/bloquear chamadas fetch_url para domínios conhecidos de mecanismos de busca.\n[ ] B - Adicionar instruções no prompt para usar fetch_url apenas para URLs de documentos.\n[ ] C - Substituir fetch_url por uma ferramenta load_document que valide se as URLs apontam para formatos de documento.\n[ ] D - Remover fetch_url do agente de documentos e direcionar todo carregamento de URL através do coordenador para o agente de busca web.','\n',char(10)),replace('**Explicação didática para um adulto tech lead:**\n\nO problema central é que a ferramenta fetch_url é **genérica demais** — ela permite que o agente acesse qualquer URL, incluindo páginas de busca que deveriam ser tratadas por outro agente especializado. Isso viola o princípio de **menor privilégio** (least privilege) e quebra a separação de responsabilidades entre os agentes.\n\n**Análise das alternativas:**\n\n- **A (Filtrar/bloquear domínios de busca):** É uma abordagem reativa e frágil. Manter uma lista de bloqueio de domínios de mecanismos de busca é uma corrida de gato e rato — novos domínios, subdomínios ou variações podem surgir, e a lista nunca estará completa. Além disso, não resolve o problema de o agente usar a ferramenta para outros fins inadequados.\n\n- **B (Adicionar instruções no prompt):** Depende inteiramente da obediência do modelo a instruções textuais. Modelos de linguagem não são deterministas e podem ignorar instruções, especialmente se interpretarem que a ação alternativa é mais útil para o usuário. É a abordagem mais frágil e menos confiável.\n\n- **C (Substituir por load_document que valida formato):** Esta é a correção mais eficaz porque ataca a causa raiz — a ferramenta é muito poderosa para o que o agente deveria fazer. Ao substituir por uma ferramenta de escopo estreito que **valida ativamente** se a URL aponta para formatos de documento (PDF, DOCX, TXT, etc.), eliminamos o abuso **por design**. O agente simplesmente não consegue acessar páginas de busca porque a ferramenta rejeitaria tais URLs. Isso implementa o princípio de menor privilégio de forma robusta.\n\n- **D (Remover fetch_url e rotear via coordenador):** Também é uma solução defensável do ponto de vista arquitetural — força o roteamento correto através do coordenador. No entanto, adiciona complexidade (a latência de uma chamada extra ao coordenador) e pode introduzir um gargalo. Em provas da Anthropic e na filosofia de design de agentes, a preferência costuma ser por ferramentas de escopo apertado (C) em vez de roteamento indireto, por ser mais direto e menos acoplado.\n\n**Conclusão:** A alternativa C é a mais eficaz porque resolve o problema na raiz — restringindo a **capacidade** da ferramenta em vez de tentar controlar o **comportamento** do modelo ou depender de listas externas.','\n',char(10)),replace('Imagine que você tem um brinquedo que faz tudo: pode virar carrinho, foguete, robô... Mas você só quer que ele seja um carrinho para brincar na pista. O problema é que ele fica virando foguete e saindo voando para outros lugares!\n\nA melhor solução não é ficar falando "não vira foguete" toda hora (porque ele pode esquecer), nem colocar uma cerca imaginária (porque ele pode pular). A melhor solução é trocar esse brinquedo que faz tudo por um **carrinho de verdade** — que só sabe andar na pista e não tem como virar foguete.\n\nFoi o que a opção C fez: trocou a ferramenta "pega qualquer URL" por uma ferramenta "só pega documentos". Assim, o agente nem consegue mais acessar páginas de busca, mesmo que tentasse. Problema resolvido de verdade!','\n',char(10)));
INSERT INTO cards VALUES('admin','card_1783092993667_cvm8ospdl',509,'The web search subagent times out.',replace('The web search subagent times out.\n\nThe web search subagent times out. Which error propagation approach best enables intelligent recovery?\nO que a pergunta pede: best enables intelligent recovery → melhor recuperação inteligente.\n\nA pegadinha: Recuperação inteligente exige contexto estruturado e rico , não um status genérico.\n\nRaciocínio: Recuperação inteligente precisa de informação suficiente para o coordenador decidir (retry? fonte alternativa? seguir sem?). B esconde o contexto num status genérico; C mascara falha como sucesso (perigoso); D mata o fluxo inteiro. A .\n\n[ ] A - Return structured error context to the coordinator: failure type, attempted query, partial results, and alternative approaches.\n[ ] B - Retry with exponential backoff internally, returning a generic "search unavailable" only after all retries.\n[ ] C - Catch the timeout and return an empty result set marked as successful.\n[ ] D - Propagate the exception to a top-level handler that terminates the whole workflow.','\n',char(10)),'[ ] A - Return structured error context to the coordinator: failure type, attempted query, partial results, and alternative approaches.','["Domain_1::Agentic_Architecture_Orchestration", "Domain_5::Context_Management_Reliability", "Scenario_3::Multi_Agent_Research"]','New',0,2.5,0,1783092993667,1783728106346,1783203558653,replace('**Tradução para Português (Brasil):**\n\n**Pergunta:** O subagente de busca web expira (timeout).\n\n**Alternativas:**\n\n[ ] A - Retornar contexto de erro estruturado para o coordenador: tipo de falha, consulta tentada, resultados parciais e abordagens alternativas.\n\n[ ] B - Repetir com backoff exponencial internamente, retornando um genérico "busca indisponível" somente após todas as tentativas.\n\n[ ] C - Capturar o timeout e retornar um conjunto de resultados vazio marcado como bem-sucedido.\n\n[ ] D - Propagar a exceção para um manipulador de nível superior que encerra todo o fluxo de trabalho.','\n',char(10)),replace('**Explicação para Adulto (Tech Lead):**\n\n**Alternativa correta: A**\n\nA pergunta pede a abordagem que **melhor possibilita uma recuperação inteligente** diante de um timeout no subagente de busca web. "Recuperação inteligente" significa que o coordenador (orquestrador) deve ter informação suficiente para tomar uma decisão consciente sobre como prosseguir: tentar novamente, consultar uma fonte alternativa, usar resultados parciais, ou ignorar a falha e seguir em frente.\n\n**Por que A está correta:**\n- Retornar um contexto de erro **estruturado e rico** (tipo da falha, consulta original, resultados parciais, sugestões de alternativas) é o pré-requisito para que o coordenador possa decidir o melhor curso de ação.\n- É a abordagem que preserva o máximo de informação no ponto de falha, permitindo que a lógica de orquestração tome decisões adaptativas e contextuais — a essência da "recuperação inteligente".\n\n**Por que as demais estão incorretas:**\n\n**B -** O backoff exponencial interno é uma estratégia válida de resiliência, mas **esconde o contexto** do coordenador ao retornar apenas um status genérico "search unavailable". Sem saber o tipo de falha, a consulta que falhou ou se houve resultados parciais, o coordenador não pode tomar decisões informadas. A recuperação se torna cega e limitada a um simples "tentar de novo depois".\n\n**C -** Retornar um resultado vazio **mascarado como sucesso** é perigoso. Isso viola o princípio de transparência: o coordenador acredita que a busca ocorreu normalmente e que simplesmente não havia resultados, quando na verdade houve um timeout. Isso pode levar a conclusões incorretas e decisões de negócio equivocadas. Não é recuperação inteligente — é ocultação de falha.\n\n**D -** Propagar a exceção para um manipulador global que **encerra todo o fluxo** é a antítese da recuperação inteligente. Isso torna o sistema frágil: um timeout em um subagente de busca derruba todo o workflow. Em sistemas complexos, o ideal é isolar falhas e permitir que partes do sistema continuem funcionando.\n\n**Conclusão:** Apenas a alternativa A fornece informações suficientes para que o coordenador possa tomar uma decisão contextualizada e adaptativa, que é o que define uma recuperação inteligente.','\n',char(10)),replace('**Explicação para Criança de 10 anos:**\n\nImagine que você pediu para um amigo procurar um livro na biblioteca, mas ele demorou tanto que o tempo acabou (timeout). Agora você precisa decidir o que fazer.\n\n**A alternativa certa é a A.** Ela diz que seu amigo volta e te conta: "Não consegui achar porque o tempo acabou, eu estava procurando ''Harry Potter'', achei esses 2 livros no meio do caminho, e talvez você possa tentar na estante ao lado." Assim você pode decidir: tentar de novo, pedir ajuda para outra pessoa, ou ficar com o que ele já achou.\n\n**Por que as outras são ruins?**\n\n**B -** Seu amigo fica tentando sozinho várias vezes e, depois de muito tempo, só diz "Não achei, desculpa". Você não sabe o que aconteceu nem se ele achou alguma coisa no caminho.\n\n**C -** Seu amigo volta com as mãos vazias e finge que deu tudo certo, dizendo "É, não tinha nenhum livro interessante mesmo". Você vai acreditar que não existe nenhum livro, mas na verdade ele nem terminou de procurar!\n\n**D -** Seu amigo grita "DEU ERRO!" e aí todo mundo para. A brincadeira acaba por causa de um único livro que não foi encontrado.\n\nA melhor forma de resolver problemas é ter bastante informação para tomar uma boa decisão - é isso que a alternativa A faz!','\n',char(10)));
INSERT INTO cards VALUES('admin','card_1783092993695_0kko2thl6',510,'The document analysis subagent encounters a corrupted PDF it cannot parse.',replace('The document analysis subagent encounters a corrupted PDF it cannot parse.\n\nThe document analysis subagent encounters a corrupted PDF it cannot parse. What is the most effective way to handle this failure?\nO que a pergunta pede: most effective way to handle this failure → tratar a falha.\n\nA pegadinha: Uma falha pontual num documento não deve travar tudo nem ser escondida.\n\nRaciocínio: Erro pontual deve subir com contexto para o coordenador decidir (pular? alternativa?). B é desproporcional (mata tudo); C esconde a perda de dados; D é inútil aqui — corrupção não é transitória, repetir não resolve. A .\n\n[ ] A - Return the error with context to the coordinator, letting it decide how to proceed.\n[ ] B - Throw an exception that terminates the entire workflow.\n[ ] C - Silently skip the corrupted document and continue.\n[ ] D - Retry parsing three times with exponential backoff before reporting failure.','\n',char(10)),'[ ] A - Return the error with context to the coordinator, letting it decide how to proceed.','["Domain_1::Agentic_Architecture_Orchestration", "Domain_5::Context_Management_Reliability", "Scenario_3::Multi_Agent_Research"]','New',0,2.5,0,1783092993695,1783728112904,1783203558653,replace('**Tradução para português do Brasil:**\n\nO subagente de análise de documentos encontra um PDF corrompido que não consegue analisar.\n\nQual é a maneira mais eficaz de lidar com essa falha?\n\n[ ] A - Retornar o erro com contexto para o coordenador, permitindo que ele decida como prosseguir.\n[ ] B - Lançar uma exceção que encerra todo o fluxo de trabalho.\n[ ] C - Pular silenciosamente o documento corrompido e continuar.\n[ ] D - Tentar analisar novamente três vezes com backoff exponencial antes de reportar a falha.','\n',char(10)),replace('**Explicação didática para um adulto tech lead:**\n\nA questão trata de resiliência e tratamento de falhas em arquiteturas de agentes/microsserviços, onde um subagente especializado (análise de documentos) encontra um erro recuperável ou semi-recuperável (PDF corrompido). O cenário é clássico em pipelines de processamento de documentos: um arquivo veio corrompido, mas isso não significa que todo o workflow deve falhar.\n\n**Alternativa correta: A**\n\nRetornar o erro **com contexto** para o coordenador é a abordagem mais alinhada com boas práticas de arquitetura orientada a agentes e design tolerante a falhas. O subagente não deve tomar decisões de negócio (pular ou abortar tudo) — ele deve reportar o problema com informações suficientes (nome do arquivo, tipo de corrupção, stack trace, etc.) para que o coordenador, que tem visão全局 do processo, decida a ação correta. Isso respeita o princípio da responsabilidade única e mantém a orquestração centralizada.\n\n**Por que as demais estão erradas:**\n\n**B - Lançar uma exceção que encerra todo o fluxo de trabalho.**  \nÉ desproporcional e antagônica à resiliência. Um único documento corrompido não justifica abortar todo o pipeline, especialmente se houver dezenas, centenas ou milhares de outros documentos válidos. Isso viola o princípio de "fail gracefully" e pode causar perda massiva de processamento.\n\n**C - Pular silenciosamente o documento corrompido e continuar.**  \nAqui o erro é omitir a falha. "Silenciosamente" significa que nenhum log, alerta ou notificação é gerado. Isso compromete a rastreabilidade (audit trail) e a capacidade de detectar problemas no pipeline. O usuário ou operador nunca saberá que um documento foi ignorado, podendo levar a decisões erradas baseadas em dados incompletos.\n\n**D - Tentar analisar novamente três vezes com backoff exponencial antes de reportar a falha.**  \nEmbora backoff exponencial seja uma boa estratégia para falhas transitórias (ex.: timeout de rede, serviço temporariamente indisponível), corrupção de PDF é uma falha **permanente** — não há quantidade de retentativas que vá magicamente consertar um arquivo binário corrompido. Repetir três vezes só consome tempo e recursos computacionais à toa, para no final ainda precisar reportar a falha. É ineficaz e atrasa o processamento dos demais documentos.','\n',char(10)),replace('Imagine que você é um ajudante em uma fábrica de doces. Sua tarefa é ler as caixas que chegam e ver se estão boas. De repente, você pega uma caixa que está toda amassada e não consegue abrir de jeito nenhum.\n\nO que você faz?\n\n- Opção A: Você avisa o chefe e mostra a caixa amassada. Ele decide se joga fora ou tenta abrir de outro jeito. ✓ MELHOR — O chefe tem a visão geral e sabe o que fazer.\n- Opção B: Você grita "CAIXA ESTRAGADA!" e Para TUDO na fábrica. Todo mundo para de trabalhar por causa de uma única caixa. ✗ É exagero!\n- Opção C: Você joga a caixa no lixo em segredo e continua como se nada tivesse acontecido. ✗ Mentiroso! O chefe precisa saber que uma caixa veio estragada.\n- Opção D: Você fica tentando abrir a caixa amassada três vezes, mesmo sabendo que ela está estragada. ✗ Perda de tempo! Tentar de novo não vai consertar o amassado.\n\nA melhor resposta é a **A**: avisar o coordenador (o "chefe") com todos os detalhes para ele decidir. Assim, você faz seu trabalho direito, não para tudo, e não esconde o problema.','\n',char(10)));
INSERT INTO cards VALUES('admin','card_1783092993791_mtyi2tfke',511,'You create an /explore-alternatives skill to brainstorm approaches.',replace('You create an /explore-alternatives skill to brainstorm approaches.\n\nYou create an /explore-alternatives skill to brainstorm approaches. After running it, Claude''s subsequent responses are influenced by the exploration — referencing abandoned approaches. What''s the most effective way to configure this skill?\nO que a pergunta pede: most effective way to configure this skill → como configurar a skill.\n\nA pegadinha: O contexto exploratório vaza para o trabalho seguinte → é preciso isolar o contexto.\n\nRaciocínio: A raiz é a contaminação do contexto principal. context: fork roda a exploração em contexto isolado , descartado depois — exatamente o comportamento desejado. A depende de disciplina manual; C é sobre executar comandos, não isolar contexto; D só muda o escopo (pessoal vs projeto), não isola. B .\n\n[ ] A - Split into /explore-start and /explore-end to demarcate context.\n[ ] B - Add context: fork to the skill''s frontmatter.\n[ ] C - Use the ! prefix to run the logic as a bash subprocess.\n[ ] D - Create the skill in ~/.claude/skills/ instead of .claude/skills/.','\n',char(10)),'[ ] B - Add context: fork to the skill''s frontmatter.','["Domain_3::Claude_Code_Configuration_Workflows", "Domain_5::Context_Management_Reliability", "Scenario_2::Code_Generation_Claude_Code"]','New',0,2.5,0,1783092993791,1783728116343,1783203558653,replace('**Tradução para português do Brasil:**\n\nVocê cria uma skill /explore-alternatives para fazer brainstorming de abordagens.\n\nVocê cria uma skill /explore-alternatives para fazer brainstorming de abordagens. Depois de executá-la, as respostas subsequentes de Claude são influenciadas pela exploração — referenciando abordagens abandonadas. Qual é a forma mais eficaz de configurar esta skill?\n\n[ ] A - Dividir em /explore-start e /explore-end para demarcar o contexto.\n[ ] B - Adicionar context: fork ao frontmatter da skill.\n[ ] C - Usar o prefixo ! para executar a lógica como um subprocesso bash.\n[ ] D - Criar a skill em ~/.claude/skills/ em vez de .claude/skills/.','\n',char(10)),replace('**Explicação didática para um adulto tech lead:**\n\nO problema central é que o contexto exploratório (ideias abandonadas, caminhos descartados) está "vazando" para a conversa principal, poluindo o raciocínio de Claude em interações posteriores. Isso é um problema clássico de **isolamento de contexto**.\n\nVamos analisar cada alternativa:\n\n**Alternativa B (correta):** `context: fork` é um mecanismo que instrui Claude a executar a skill em um contexto completamente separado (um "fork"), como uma ramificação temporária. Após a execução, esse contexto é descartado, e apenas o resultado final (não o processo de pensamento) retorna ao contexto principal. Isso resolve exatamente o problema de contaminação, pois isola totalmente o brainstorming exploratório.\n\n**Alternativa A (incorreta):** Dividir em /explore-start e /explore-end seria uma abordagem puramente manual, dependendo da disciplina do usuário para demarcar o início e fim do contexto exploratório. Não há garantia de isolamento real — Claude ainda pode manter referências ao contexto anterior entre os comandos. É frágil e não resolve o problema estruturalmente.\n\n**Alternativa C (incorreta):** O prefixo `!` executa comandos como subprocessos bash no sistema operacional, não na lógica da skill. Isso não tem relação com o isolamento de contexto da conversa; é sobre execução de comandos shell.\n\n**Alternativa D (incorreta):** A localização da skill (`~/.claude/skills/` — escopo global/pessoal vs `.claude/skills/` — escopo do projeto) afeta apenas onde a skill está disponível, não como seu contexto é gerenciado durante a execução. Muda o escopo de acesso, mas não resolve o vazamento de contexto.','\n',char(10)),replace('**Explicação para uma criança de 10 anos:**\n\nImagine que você tem um caderno onde faz sua lição de casa. Você também tem uma folha de rascunho separada onde rabisca ideias, faz contas e testa coisas.\n\nO problema aqui é parecido: quando você usa a skill de "explorar alternativas", é como se você estivesse rabiscando ideias no mesmo caderno da lição de casa. Depois, quando você continua a lição, fica vendo os rabiscos e se confunde — você ainda pensa nas ideias que já descartou!\n\nA alternativa B resolve isso dizendo: "Use uma folha de rascunho separada!" — o `context: fork` faz a skill funcionar em um "caderno à parte". Depois que ela termina, esse caderno é jogado fora e só o resultado final (a melhor ideia) volta para o seu caderno principal. Assim, a bagunça dos rascunhos não atrapalha o resto do seu trabalho.\n\nAs outras opções não funcionam porque:\n- A: É como dizer "desenhe uma linha no caderno separando os rascunhos" — você ainda vê os rabiscos.\n- C: É sobre usar um computador diferente, mas não tem nada a ver com separar os pensamentos.\n- D: É sobre guardar o caderno em gavetas diferentes. A gaveta não muda o que está escrito dentro.','\n',char(10)));
INSERT INTO cards VALUES('admin','card_1783092993819_70rkhnx8k',512,'Each subagent completes successfully, but the final reports cover only visual arts, missing music, writing, and film.',replace('Each subagent completes successfully, but the final reports cover only visual arts, missing music, writing, and film.\n\nEach subagent completes successfully, but the final reports cover only visual arts, missing music, writing, and film. The coordinator decomposed the topic into "AI in digital art creation," "AI in graphic design," and "AI in photography." What is the most likely root cause?\nO que a pergunta pede: most likely root cause → a causa raiz, não o sintoma.\n\nA pegadinha: Cada subagente teve sucesso . A raiz está em como o tema foi dividido no começo.\n\nRaciocínio: Como cada subagente teve sucesso , o erro não está na execução, mas na divisão inicial: o coordenador só criou subtópicos visuais. Tudo a jusante herdou a limitação. A e B culpam a execução (que funcionou); D mitigaria mas não é a raiz. C é a origem.\n\n[ ] A - The web search agent''s queries aren''t comprehensive enough and need expanding.\n[ ] B - The document agent filters out non-visual sources due to restrictive relevance criteria.\n[ ] C - The coordinator''s task decomposition is too narrow, producing subtasks that don''t cover all relevant domains.\n[ ] D - The synthesis agent lacks instructions for identifying coverage gaps.','\n',char(10)),'[ ] C - The coordinator''s task decomposition is too narrow, producing subtasks that don''t cover all relevant domains.','["Domain_1::Agentic_Architecture_Orchestration", "Domain_4::Prompt_Engineering_Structured_Output", "Scenario_3::Multi_Agent_Research"]','New',0,2.5,0,1783092993819,1783728119649,1783203558653,replace('**Tradução para português do Brasil:**\n\nCada subagente é concluído com sucesso, mas os relatórios finais cobrem apenas artes visuais, deixando de fora música, escrita e cinema. O coordenador decompôs o tópico em "IA na criação de arte digital", "IA no design gráfico" e "IA na fotografia". Qual é a causa raiz mais provável?\n\n[ ] A - As consultas do agente de busca na web não são abrangentes o suficiente e precisam ser expandidas.\n[ ] B - O agente de documentos filtra fontes não visuais devido a critérios de relevância restritivos.\n[ ] C - A decomposição de tarefas do coordenador é muito estreita, produzindo subtarefas que não cobrem todos os domínios relevantes.\n[ ] D - O agente de síntese não tem instruções para identificar lacunas de cobertura.','\n',char(10)),replace('**Explicação didática para um adulto (tech lead):**\n\nPara um tech lead, o cenário é clássico em sistemas multiagentes: cada subagente reporta sucesso individual, mas o resultado final é incompleto. Isso aponta para um problema estrutural no *design* da orquestração, não na execução.\n\n- **Alternativa C (correta):** O coordenador definiu os subtópicos como "IA na criação de arte digital", "IA no design gráfico" e "IA na fotografia". Todos são estritamente visuais. Música, escrita e cinema jamais seriam abordados porque não há subtarefa que os contemple. A falha está no *task decomposition* — a árvore de quebra do problema já nasceu truncada. Qualquer execução downstream, por mais perfeita que seja, herdará esse viés.\n\n- **Alternativa A (incorreta):** Sugere que o agente de busca tem consultas insuficientes. Porém, se o agente de busca fosse o problema, ele falharia em *alguns* subtópicos visuais ou traria resultados incompletos. O enunciado diz que *todos* os subagentes completaram com sucesso, e o resultado só cobre artes visuais. O agente de busca pode estar perfeitamente configurado dentro dos subtópicos que recebeu.\n\n- **Alternativa B (incorreta):** Atribui a culpa ao filtro de relevância do agente de documentos. Mas se o filtro bloqueasse fontes não visuais, ele estaria agindo corretamente dada a diretiva recebida (os subtópicos são visuais). Além disso, o problema é sistêmico (ausência de domínios inteiros), não um falso positivo ou negativo em relevância.\n\n- **Alternativa D (incorreta):** O agente de síntese não ter instruções para detectar lacunas é uma *falta de mitigação*, não a *causa raiz*. Mesmo que ele tivesse essa instrução, ele não teria como gerar conteúdo sobre música ou cinema — as subtarefas não forneceram dados sobre esses temas. A raiz é anterior: a decomposição inicial jamais incluiu não visuais.\n\n**Conclusão:** A causa raiz é C. É um problema de *scope definition* na fase de planejamento. Em engenharia de sistemas multiagentes, a decomposição de tarefas (task decomposition) determina os limites do que pode ser alcançado. Se a decomposição é enviesada, todo o pipeline herdará o viés.','\n',char(10)),replace('Vamos imaginar que você precisa fazer uma pesquisa sobre "Esportes" para a escola. Você divide o trabalho com seus amigos: um fica com "Futebol", outro com "Basquete" e outro com "Vôlei". Todo mundo faz direitinho e entrega a parte. Mas, no final, o trabalho só fala de esportes com bola! Cadê a natação? Cadê a corrida? O problema não foi que seus amigos não souberam pesquisar — eles pesquisaram bem, mas dentro do que foi pedido. O problema foi que você, coordenador, só escolheu esportes com bola. Se tivesse incluído "Natação" ou "Atletismo" na lista, o trabalho teria ficado completo.\n\nAqui é a mesma coisa. O coordenador pediu só coisas de artes visuais (arte digital, design gráfico e fotografia). Os subagentes fizeram tudo certo, mas música, escrita e cinema ficaram de fora porque ninguém pediu para pesquisar sobre eles. A causa do problema não é que os subagentes erraram — é que a divisão do trabalho já estava incompleta desde o começo.\n\nA alternativa C diz exatamente isso: o coordenador dividiu o tema de um jeito muito restrito, deixando de fora áreas importantes. As outras opções (A, B e D) culpam os subagentes, mas eles só seguiram as ordens que receberam.','\n',char(10)));
INSERT INTO cards VALUES('admin','card_1783092993847_9le5tbe04',513,'Three developers report Claude follows the "always include comprehensive error handling" guideline, but a fourth (new) developer reports it isn''t followed.',replace('Three developers report Claude follows the "always include comprehensive error handling" guideline, but a fourth (new) developer reports it isn''t followed.\n\nThree developers report Claude follows the "always include comprehensive error handling" guideline, but a fourth (new) developer reports it isn''t followed. All four are in the same repo with the latest code. What''s the most likely cause and fix?\nO que a pergunta pede: most likely cause and fix → a causa e a correção.\n\nA pegadinha: Funciona para os veteranos, não para o novato → a regra está numa config pessoal , não no projeto .\n\nRaciocínio: Padrão clássico: a regra está nas configs pessoais dos veteranos, então o novato nunca a recebe. A correção é mover para o nível de projeto (versionado), onde todos herdam. A inverte a lógica; C e D descrevem mecanismos que não funcionam assim. B .\n\n[ ] A - The new dev''s ~/.claude/CLAUDE.md has conflicting instructions; remove them.\n[ ] B - The guideline lives in the original devs'' ~/.claude/CLAUDE.md (user-level), not the project''s .claude/CLAUDE.md. Move it to the project file so everyone gets it.\n[ ] C - Claude caches CLAUDE.md; clear the cache.\n[ ] D - Claude builds per-user preference models; the new dev must repeat the requirement until learned.','\n',char(10)),'[ ] B - The guideline lives in the original devs'' ~/.claude/CLAUDE.md (user-level), not the project''s .claude/CLAUDE.md. Move it to the project file so everyone gets it.','["Domain_3::Claude_Code_Configuration_Workflows", "Domain_5::Context_Management_Reliability", "Scenario_2::Code_Generation_Claude_Code"]','New',0,2.5,0,1783092993847,1783728123085,1783203558653,replace('**Tradução para português do Brasil:**\n\nTrês desenvolvedores reportam que o Claude segue a diretriz "sempre incluir tratamento de erros abrangente", mas um quarto (novo) desenvolvedor reporta que ela não é seguida. Todos os quatro estão no mesmo repositório com o código mais recente. Qual é a causa mais provável e a correção?\n\n[ ] A - O arquivo ~/.claude/CLAUDE.md do novo dev tem instruções conflitantes; remova-as.\n[ ] B - A diretriz está no ~/.claude/CLAUDE.md dos desenvolvedores originais (nível do usuário), e não no .claude/CLAUDE.md do projeto. Mova-a para o arquivo do projeto para que todos a recebam.\n[ ] C - O Claude armazena em cache o CLAUDE.md; limpe o cache.\n[ ] D - O Claude constrói modelos de preferência por usuário; o novo dev deve repetir a exigência até que seja aprendida.','\n',char(10)),replace('**Explicação para adulto (tech lead):**\n\nO cenário descreve um problema clássico de configuração: os três desenvolvedores veteranos observam o comportamento esperado, mas o novato não. Como todos estão no mesmo repositório com o código mais recente, a diferença não está no código-fonte, e sim no ambiente de cada um.\n\nNo Claude, existem dois níveis de arquivos de instruções (CLAUDE.md):\n- **Nível de projeto**: `.claude/CLAUDE.md` (versionado, dentro do repositório) — todos que clonam o repositório o recebem.\n- **Nível de usuário**: `~/.claude/CLAUDE.md` (no diretório home do usuário) — é pessoal e não é compartilhado via versionamento.\n\nA alternativa **B** é a correta porque descreve exatamente esse padrão: a diretriz foi colocada no `~/.claude/CLAUDE.md` dos desenvolvedores originais (nível de usuário). Como esse arquivo não está no repositório, o novo desenvolvedor nunca o recebeu. A correção é mover a diretriz para o `.claude/CLAUDE.md` do projeto, que é versionado e, portanto, herdado por todos.\n\n**Por que as outras alternativas estão erradas:**\n\n- **A**: Assume que o novato tem um arquivo conflitante no `~/.claude/CLAUDE.md`. Mas se ele é novo e nunca configurou nada, é improvável que tenha instruções conflitantes. Além disso, se houvesse conflito, a solução ainda seria centralizar no projeto, não simplesmente remover o arquivo pessoal.\n\n- **C**: O cache do CLAUDE.md não é um mecanismo conhecido/documentado que cause esse tipo de discrepância entre desenvolvedores. Cache afetaria o mesmo usuário entre sessões, não usuários diferentes. E mesmo que existisse, não explicaria por que apenas o novato não vê a regra.\n\n- **D**: Claude não constrói "modelos de preferência por usuário" que aprendem com repetição para diretrizes explícitas em CLAUDE.md. Isso é ficção técnica. Diretrizes são seguidas com base nos arquivos de instrução presentes, não por aprendizado incremental entre sessões.\n\n**Resumo:** O problema é de escopo de configuração (usuário vs. projeto). A correção é versionar a diretriz no repositório.','\n',char(10)),replace('Imagine que três amigos têm um caderno de regras em casa, e eles seguem uma regra: "sempre coloque capacete antes de andar de bicicleta". Um quarto amigo chega novo no grupo, e ninguém deu o caderno de regras para ele. Então ele nunca coloca o capacete. O problema não é que ele seja desobediente — é que a regra estava escrita no caderno pessoal de cada um, e não no caderno oficial do grupo que todos compartilham.\n\nA solução é simples: pegar essa regra e escrever no caderno do grupo (que fica dentro da pasta do projeto). Assim, qualquer pessoa nova que entrar no grupo já vai receber o caderno com todas as regras e saberá que precisa usar capacete.\n\nAs outras opções não fazem sentido:\n- A: Diz que o menino novo tem um caderno diferente em casa, mas ele acabou de chegar, nem tem caderno ainda.\n- C: Diz que a culpa é da memória do computador, mas isso não explica por que só o novato não sabe da regra.\n- D: Diz que o amigo novo precisa repetir "capacete, capacete, capacete" até o computador aprender, mas regras não funcionam assim — você escreve uma vez e pronto.','\n',char(10)));
INSERT INTO cards VALUES('admin','card_1783092993876_pdjtp1wso',514,'A /commit skill exists at .',replace('A /commit skill exists at .\n\nA /commit skill exists at .claude/skills/commit/SKILL.md . One developer wants to customize it personally without affecting teammates. What should you recommend?\nO que a pergunta pede: what should you recommend para customizar sem afetar os colegas .\n\nA pegadinha: without affecting teammates → mudança pessoal , não no projeto.\n\nRaciocínio: Uma skill pessoal de mesmo nome em ~/.claude/skills/ tem precedência sobre a do projeto para aquele usuário, sem tocar no repositório compartilhado. D funcionaria mas cria um comando diferente (perde a ergonomia de /commit ); B inventa uma flag; C polui a skill do time. A . (D é aceitável se você quer um comando paralelo, mas a pergunta pede customizar o /commit .)\n\n[ ] A - Create a personal version at ~/.claude/skills/commit/SKILL.md with the same name.\n[ ] B - Set override: true in the personal skill''s frontmatter.\n[ ] C - Add username-based conditional logic to the project skill.\n[ ] D - Create a personal version in ~/.claude/skills/ with a different name like /my-commit.','\n',char(10)),'A - Create a personal version at ~/.claude/skills/commit/SKILL.md with the same name.','["Domain_3::Claude_Code_Configuration_Workflows", "Scenario_2::Code_Generation_Claude_Code"]','New',0,2.5,0,1783092993876,1783728126478,1783203558653,replace('**Tradução para português do Brasil:**\n\nUma skill `/commit` existe em `.claude/skills/commit/SKILL.md`. Um desenvolvedor deseja personalizá-la individualmente sem afetar os colegas. O que você deve recomendar?\n\n[ ] A - Criar uma versão pessoal em `~/.claude/skills/commit/SKILL.md` com o mesmo nome.\n[ ] B - Definir `override: true` no frontmatter da skill pessoal.\n[ ] C - Adicionar lógica condicional baseada em nome de usuário na skill do projeto.\n[ ] D - Criar uma versão pessoal em `~/.claude/skills/` com um nome diferente, como `/my-commit`.','\n',char(10)),replace('**Explicação didática para um adulto tech lead:**\n\nA pergunta testa o conhecimento sobre o mecanismo de precedência de skills no Claude Code. A documentação oficial estabelece que skills definidas no diretório do usuário (`~/.claude/skills/`) sobrescrevem skills de mesmo nome definidas no projeto (`.claude/skills/`). Isso permite personalização local sem modificar o repositório compartilhado.\n\n**Alternativa correta: A**\n\n- **Por que é a melhor escolha:** Ao criar `~/.claude/skills/commit/SKILL.md` com o mesmo nome `/commit`, o Claude Code dará prioridade à versão pessoal sobre a do projeto, mas apenas para aquele usuário específico. Os colegas continuarão usando a versão original do projeto. É zero impacto no repositório compartilhado, nenhum arquivo de projeto é alterado, e o comando `/commit` continua funcionando normalmente para todos.\n\n**Por que as demais estão erradas:**\n\n- **B (`override: true`):** Esta flag não existe no formato de frontmatter de skills do Claude Code. É uma invenção. Mesmo que existisse, a documentação não suporta esse mecanismo. A precedência é resolvida por caminho (diretório do usuário vs. diretório do projeto), não por uma flag declarativa.\n- **C (lógica condicional):** Modificar a skill do projeto (`./claude/skills/commit/SKILL.md`) adicionando condicionais baseadas em usuário afeta diretamente o arquivo compartilhado no repositório. Isso exigiria commit, code review, e impactaria todos os desenvolvedores. Além disso, polui a skill com lógica que não pertence ao fluxo padrão do time.\n- **D (nome diferente):** Embora criar `~/.claude/skills/my-commit/SKILL.md` funcione como um comando personalizado, ele não customiza o `/commit` existente — cria um comando *novo* e *paralelo* (`/my-commit`). O desenvolvedor precisaria lembrar de usar `/my-commit` em vez de `/commit`, o que quebra a ergonomia e o propósito declarado da pergunta: "customizar o `/commit`". É uma solução funcional, mas não atende ao requisito específico.','\n',char(10)),replace('Imagine que na sua escola tem uma regra geral para fazer lição de casa, escrita num quadro na sala de aula. Todo mundo segue essa regra. Mas você quer fazer a lição de um jeito que funciona melhor para você, sem bagunçar o quadro dos outros.\n\n**Alternativa A (a resposta certa):** Você escreve a SUA regra num papel e guarda na sua mochila. Como o seu papel está mais perto de você do que o quadro da sala, quando você for fazer a lição, você olha primeiro para o seu papel. Seus colegas continuam olhando o quadro da sala. Todo mundo feliz!\n\n**Alternativa B:** Você inventa uma palavra mágica "override: true" e escreve no seu papel. Mas essa palavra mágica não existe de verdade — ninguém ensinou isso na escola. Não funciona.\n\n**Alternativa C:** Você pega um pincel e escreve sua regra personalizada NO QUADRO da sala, mas coloca "só para o João". Agora todo mundo vê seu rabisco no quadro, e quando a professora for dar aula, vai ter que explicar por que tem duas regras. Isso confunde a turma toda e mexe no quadro que é de todo mundo.\n\n**Alternativa D:** Você cria um papel na sua mochila chamado "minha-lição-especial" em vez de "lição-de-casa". Funciona, mas quando a professora pedir "façam a lição de casa!", você vai ter que lembrar de olhar o "minha-lição-especial" — não é a mesma coisa, e você pode se confundir.\n\nResumindo: a melhor forma de personalizar algo só para você, sem atrapalhar ninguém, é criar a sua própria versão no SEU cantinho com o MESMO nome. Assim, quando você chamar, o seu computador usa a sua versão, e quando seus amigos chamarem, usam a versão do time.','\n',char(10)));
INSERT INTO cards VALUES('admin','card_1783092993905_c0uhb44q3',515,'A /migration skill accepts a name via $ARGUMENTS .',replace('A /migration skill accepts a name via $ARGUMENTS .\n\nA /migration skill accepts a name via $ARGUMENTS . Three issues: (1) devs invoke without arguments → poorly-named files, (2) it incorporates schema details from unrelated earlier conversations, (3) a dev triggered destructive cleanup due to broad tool access. Which configuration addresses all three?\nO que a pergunta pede: configuration approach addresses all three issues → uma config que resolve os três .\n\nA pegadinha: Mapeie cada problema a uma config: (1) falta argumento → argument-hint ; (2) contexto vazando → context: fork ; (3) acesso amplo → allowed-tools .\n\nRaciocínio: Só A usa os três mecanismos configuráveis que casam 1:1 com os três problemas. B tenta resolver tudo por instrução (frágil — depende do modelo obedecer); C e D resolvem partes mas não os três com mecanismos nativos. A .\n\n[ ] A - Add argument-hint frontmatter to prompt for parameters, use context: fork to isolate execution, and restrict allowed-tools to file writes.\n[ ] B - Add validation instructions in SKILL.md to check $ARGUMENTS, ignore prior context, and list forbidden operations.\n[ ] C - Use positional $1/$2, reference schema via @ syntax, and add a description warning about destructive ops.\n[ ] D - Split into /migration-create and /migration-apply, request a name if missing, and use different allowed-tools scopes.','\n',char(10)),'A - Add argument-hint frontmatter to prompt for parameters, use context: fork to isolate execution, and restrict allowed-tools to file writes.','["Domain_3::Claude_Code_Configuration_Workflows", "Domain_2::Tool_Design_MCP_Integration", "Domain_5::Context_Management_Reliability", "Scenario_2::Code_Generation_Claude_Code"]','New',0,2.5,0,1783092993905,1783728130045,1783203558653,replace('**Tradução para português do Brasil:**\n\nUm skill `/migration` aceita um nome via `$ARGUMENTS`.\n\nTrês problemas: (1) devs invocam sem argumentos → arquivos com nomes mal definidos, (2) ele incorpora detalhes de esquema de conversas anteriores não relacionadas, (3) um dev acionou uma limpeza destrutiva devido ao amplo acesso a ferramentas.\n\nQual configuração resolve todos os três?\n\n[ ] A - Adicionar frontmatter argument-hint para solicitar parâmetros, usar context: fork para isolar a execução e restringir allowed-tools apenas a escritas de arquivo.\n[ ] B - Adicionar instruções de validação no SKILL.md para verificar $ARGUMENTS, ignorar contexto anterior e listar operações proibidas.\n[ ] C - Usar $1/$2 posicional, referenciar esquema via sintaxe @ e adicionar uma descrição de aviso sobre operações destrutivas.\n[ ] D - Dividir em /migration-create e /migration-apply, solicitar um nome se ausente e usar diferentes escopos de allowed-tools.','\n',char(10)),replace('**Explicação didática para um adulto tech lead:**\n\nO cenário descreve três problemas clássicos de segurança e usabilidade em um skill de chat/agente:\n\n1. **Falta de argumento obrigatório** → devs chamam o skill sem fornecer o `$ARGUMENTS` esperado, resultando em arquivos com nomes genéricos ou corrompidos.\n2. **Vazamento de contexto entre conversas** → o skill está "vazando" informações de esquemas de conversas anteriores que não têm relação com a atual, poluindo a execução.\n3. **Acesso excessivo a ferramentas** → o skill tem permissão para ferramentas destrutivas (ex.: deletar arquivos, executar comandos arbitrários), permitindo que um dev acione acidentalmente uma limpeza.\n\nA alternativa **A** é a correta porque emprega **três mecanismos de configuração nativos** que mapeiam diretamente 1:1 para cada problema:\n\n| Problema | Mecanismo | Como resolve |\n|---|---|---|\n| (1) Falta de argumento | `argument-hint` (frontmatter) | Força o sistema a solicitar o parâmetro antes da execução, evitando invocações sem argumento. |\n| (2) Vazamento de contexto | `context: fork` | Isola a execução em um contexto limpo (fork), sem herdar mensagens anteriores da conversa. |\n| (3) Acesso amplo | `allowed-tools` restrito | Limita o skill a apenas operações de escrita em arquivo, removendo ferramentas destrutivas. |\n\n**Por que as demais estão erradas:**\n\n- **B** tenta resolver tudo via **instruções textuais** no SKILL.md (validação manual, ignorar contexto, listar operações proibidas). Isso é frágil porque depende que o modelo de linguagem obedeça corretamente — não há garantia de que o modelo não "esquecerá" ou ignorará as instruções. Mecanismos de configuração (como `allowed-tools`) são enforcement, não sugestão.\n\n- **C** usa `$1/$2` posicional (não resolve o problema de argumento faltante — se o dev não passar, continua quebrando), referência esquema via `@` syntax (não isola contexto — apenas referencia, não limpa) e uma descrição de aviso (não remove o acesso destrutivo). Não há enforcement real.\n\n- **D** é uma abordagem de redesign (dividir em dois skills). Embora melhore a situação, não resolve o problema de vazamento de contexto (não menciona `context: fork` ou equivalente) e depende de lógica condicional para solicitar nome, o que ainda permite execução parcial sem validação rígida.\n\nPortanto, apenas **A** utiliza mecanismos de configuração que **forçam** o comportamento desejado em nível de plataforma, não dependendo da obediência do modelo.','\n',char(10)),replace('Imagine que você tem um robô ajudante que cria nomes para arquivos de migração. Três coisas estão dando errado:\n\n1. As pessoas chamam o robô sem dizer qual nome usar, aí ele cria arquivos com nomes estranhos.\n2. O robô "se lembra" de conversas antigas e mistura informações de outros projetos no seu trabalho atual.\n3. O robô tem uma "arma muito forte" (pode apagar arquivos inteiros), e alguém sem querer apertou o gatilho.\n\nA melhor solução (alternativa **A**) é como dar três regras claras para o robô:\n\n- **Regra 1**: "Só trabalhe se a pessoa disser o nome primeiro" → isso resolve o problema dos nomes feios.\n- **Regra 2**: "Esqueça tudo que aconteceu antes, comece do zero a cada tarefa" → isso resolve o problema de misturar conversas antigas.\n- **Regra 3**: "Você só pode escrever em arquivos, nada de apagar ou usar ferramentas perigosas" → isso resolve o problema de alguém causar estrago.\n\nAs outras opções são como dar um "conselho" em vez de uma "regra" — o robô pode ou não seguir. A opção A coloca regras de verdade que o robô é obrigado a cumprir.','\n',char(10)));
INSERT INTO cards VALUES('admin','card_1783092993933_3snf8guw8',516,'You must restructure a monolith into microservices — changes across dozens of files, decisions about service boundaries and dependencies.',replace('You must restructure a monolith into microservices — changes across dozens of files, decisions about service boundaries and dependencies.\n\nYou must restructure a monolith into microservices — changes across dozens of files, decisions about service boundaries and dependencies. Which approach should you take?\nO que a pergunta pede: which approach should you take para uma tarefa grande e arquitetural .\n\nA pegadinha: Decisões de design antes de codar → modo de planejamento.\n\nRaciocínio: Tarefa ampla, com decisões de arquitetura e dependências entremeadas → plan mode primeiro (explorar, mapear, projetar) evita retrabalho caro. A e C arriscam decisões ruins de fronteira; B presume que você já tem o design pronto (não tem). D .\n\n[ ] A - Direct execution, making changes incrementally so the boundaries reveal themselves.\n[ ] B - Direct execution with comprehensive upfront instructions detailing each service.\n[ ] C - Direct execution, switching to plan mode only if unexpected complexity appears.\n[ ] D - Enter plan mode to explore the codebase, understand dependencies, and design the approach before making changes.','\n',char(10)),'D - Enter plan mode to explore the codebase, understand dependencies, and design the approach before making changes.','["Domain_3::Claude_Code_Configuration_Workflows", "Domain_4::Prompt_Engineering_Structured_Output", "Domain_5::Context_Management_Reliability", "Scenario_2::Code_Generation_Claude_Code"]','New',0,2.5,0,1783092993933,1783728133781,1783203558653,replace('## Tradução para português do Brasil\n\n**Pergunta:**\nVocê precisa reestruturar um monólito em microsserviços — mudanças em dezenas de arquivos, decisões sobre limites de serviços e dependências. Qual abordagem você deve adotar?\n\n[ ] A - Execução direta, fazendo mudanças incrementais para que os limites se revelem por si próprios.\n[ ] B - Execução direta com instruções abrangentes definidas antecipadamente, detalhando cada serviço.\n[ ] C - Execução direta, mudando para o modo de planejamento apenas se uma complexidade inesperada aparecer.\n[ ] D - Entrar em modo de planejamento para explorar o código-fonte, entender as dependências e projetar a abordagem antes de fazer as mudanças.','\n',char(10)),replace('## Explicação para um adulto (tech lead)\n\n### Contexto do problema\n\nA pergunta trata de uma mudança arquitetural de grande escala: transformar um monólito em microsserviços. Isso envolve dezenas de arquivos, decisões críticas sobre fronteiras entre serviços (service boundaries) e gerenciamento de dependências. É um trabalho de alta complexidade e alto risco, onde erros de design iniciais podem gerar retrabalho massivo.\n\n### Análise das alternativas\n\n**Alternativa D (correta) — "Entrar em modo de planejamento para explorar o código-fonte, entender as dependências e projetar a abordagem antes de fazer as mudanças."**\n\nEsta é a abordagem correta porque:\n- Reconhece que a tarefa envolve decisões arquiteturais que não podem (e não devem) ser tomadas no meio da execução.\n- O "plano" aqui não significa documentação burocrática, mas sim uma exploração estruturada do código existente para mapear dependências, identificar acoplamentos e definir quais domínios fazem sentido como serviços independentes.\n- Reduz o risco de retrabalho: um erro na definição de fronteiras de serviço (por exemplo, separar incorretamente entidades fortemente acopladas) pode custar semanas ou meses de refatoração.\n- Ferramentas como análise estática de dependências, DDD (Domain-Driven Design) e event storming são aplicadas tipicamente nessa fase.\n\n**Alternativa A — "Execução direta, fazendo mudanças incrementais para que os limites se revelem por si próprios."**\n\n- Problemática porque assume que os limites "emergirão" naturalmente. Na prática, sem uma visão prévia, você pode acabar com boundaries mal desenhados que exigem reestruturações dolorosas depois.\n- Mudanças incrementais funcionam bem para refatorações contínuas (ex.: melhorar coesão interna), mas não para uma transformação arquitetural onde as decisões de fronteira são interdependentes.\n\n**Alternativa B — "Execução direta com instruções abrangentes definidas antecipadamente, detalhando cada serviço."**\n\n- O problema aqui é que essas "instruções abrangentes" exigem o entendimento prévio do código, que é exatamente o que o modo de planejamento fornece. A alternativa B pula a etapa de exploração e assume que o design já está completo — o que raramente é verdade para um monólito legado.\n- Na prática, você não consegue detalhar cada serviço sem primeiro explorar e entender as dependências reais.\n\n**Alternativa C — "Execução direta, mudando para o modo de planejamento apenas se uma complexidade inesperada aparecer."**\n\n- Essa abordagem reativa é arriscada porque a complexidade "inesperada" geralmente aparece tarde demais, quando retrabalho já foi feito. É mais caro corrigir um boundary mal definido depois de implementado do que planejar antes.\n- O modo de planejamento não é uma "penalidade" para complexidade — é uma ferramenta preventiva.\n\n### Por que a D é a melhor escolha\n\nEm engenharia de software, decisões arquiteturais de alto impacto (como decomposição de monólitos) se beneficiam de uma fase de exploração e design antes da execução. O "plan mode" no contexto de ferramentas como Claude (codebase) ou IDEs oferece exatamente isso: capacidade de navegar, ler arquivos, entender o grafo de dependências e só então executar mudanças com confiança. É uma aplicação do princípio "medir duas vezes, cortar uma".','\n',char(10)),replace('## Explicação para uma criança de 10 anos\n\nImagina que você tem um castelo de Lego gigante — uma fortaleza enorme com muitas salas, torres e pontes. Agora alguém pede: "Quero que você separe esse castelão em vários castelos menores, cada um com seu próprio time de bonequinhos."\n\nVocê tem duas opções:\n\n1. Sair quebrando tudo e ir separando as peças tentando adivinhar o que vai em cada castelinho novo.\n2. **Primeiro dar uma volta no castelão, olhar cada sala, ver quais portas conectam uma parte à outra, entender como os bonequinhos andam entre as salas, e só DEPOIS começar a separar.**\n\nQual opção é mais esperta? A segunda, claro! Se você sair separando sem planejar, pode colocar a cozinha em um castelinho e o fogão em outro — aí ninguém come!\n\nNo mundo dos programas de computador, é a mesma coisa. Um monólito é como esse castelão gigante. Virar ele em microsserviços (os castelinhos) é difícil. Se a gente sair mexendo sem entender direito como as partes se conectam, pode fazer uma bagunça enorme e ter que refazer tudo de novo.\n\nPor isso a resposta certa é: **primeiro explorar e planejar, depois executar**. É como desenhar um mapa do tesouro antes de sair cavando buracos no quintal!','\n',char(10)));
INSERT INTO cards VALUES('admin','card_1783092993960_h672odiju',517,'After two iterations describing requirements in prose, the output structure still doesn''t match — fields nested differently, timestamps wrong.',replace('After two iterations describing requirements in prose, the output structure still doesn''t match — fields nested differently, timestamps wrong.\n\nAfter two iterations describing requirements in prose, the output structure still doesn''t match — fields nested differently, timestamps wrong. Claude interprets prose differently each time. What''s the most effective approach for the next iteration?\nO que a pergunta pede: most effective approach for the next iteration → o próximo passo mais eficaz.\n\nA pegadinha: A prosa já falhou duas vezes → mostre exemplos concretos em vez de descrever.\n\nRaciocínio: A prosa (descrição) já falhou repetidamente — mais prosa precisa ( D ) é "mais do mesmo". Exemplos concretos de entrada-saída são a forma mais confiável de comunicar a estrutura exata (few-shot). A valida mas não comunica a intenção; C é diagnóstico, não solução. B .\n\n[ ] A - Write a JSON schema and validate output against it each iteration.\n[ ] B - Provide 2-3 concrete input-output examples showing the expected transformation.\n[ ] C - Ask Claude to explain its current interpretation to find where it diverges.\n[ ] D - Rewrite requirements with greater technical precision (field mappings, nesting rules, timestamp format).','\n',char(10)),'B - Provide 2-3 concrete input-output examples showing the expected transformation.','["Domain_4::Prompt_Engineering_Structured_Output", "Domain_2::Tool_Design_MCP_Integration", "Scenario_6::Structured_Data_Extraction"]','New',0,2.5,0,1783092993960,1783728137397,1783203558653,replace('**Tradução para português do Brasil:**\n\n**Pergunta:**\nApós duas iterações descrevendo requisitos em prosa, a estrutura da saída ainda não corresponde — campos aninhados de forma diferente, carimbos de data/hora errados.\nClaude interpreta a prosa de forma diferente a cada vez. Qual é a abordagem mais eficaz para a próxima iteração?\n\n**Alternativas:**\n[ ] A - Escrever um esquema JSON e validar a saída contra ele a cada iteração.\n[ ] B - Fornecer 2-3 exemplos concretos de entrada-saída mostrando a transformação esperada.\n[ ] C - Pedir ao Claude que explique sua interpretação atual para identificar onde há divergência.\n[ ] D - Reescrever os requisitos com maior precisão técnica (mapeamentos de campos, regras de aninhamento, formato de carimbo de data/hora).','\n',char(10)),replace('**Explicação para adulto (tech lead):**\n\n**Por que B é a resposta correta:**\nO problema central é que descrições em linguagem natural (prosa) são inerentemente ambíguas. Claude — assim como qualquer modelo de linguagem — pode interpretar a mesma descrição de formas diferentes a cada execução, especialmente quando lidamos com estruturas de dados complexas como aninhamento de campos e formatos específicos de timestamp. A abordagem mais eficaz é fornecer **exemplos concretos de entrada-saída (few-shot learning)**. Isso elimina a ambiguidade ao mostrar diretamente o padrão esperado, permitindo que o modelo generalize a partir do exemplo, em vez de interpretar regras abstratas.\n\n**Por que as demais estão erradas:**\n- **A (Esquema JSON):** Validar a saída contra um esquema detecta o erro, mas não corrige a geração. Você ainda precisará iterar para ajustar a saída, e o esquema por si só não comunica *como* a transformação deve ocorrer — apenas o formato final. É uma ferramenta de verificação, não de especificação.\n- **C (Explicar interpretação):** Pode ajudar a diagnosticar onde a divergência ocorre, mas é uma etapa de diagnóstico, não de solução. Você consumirá mais uma iteração apenas para entender o problema, sem avançar na correção.\n- **D (Reescrita precisa):** É tentador, mas "mais do mesmo" que já falhou duas vezes. A prosa, por mais precisa que seja, ainda é interpretada pelo modelo linguisticamente; o erro não é de falta de precisão, mas de limitação fundamental da comunicação em linguagem natural para estruturas rígidas. Exemplos concretos são mais eficazes que descrições mais longas.','\n',char(10)),replace('Imagine que você está tentando ensinar um amigo a desenhar um círculo vermelho. Primeiro, você diz: "Desenhe um círculo vermelho". Ele desenha um quadrado azul. Você diz de novo: "É um círculo, e vermelho!". Ele desenha um círculo rosa. Percebeu? Falar não está funcionando!\n\nAgora, em vez de falar, você pega um papel e mostra: "Olha, VEJA: aqui está um desenho de um círculo vermelho. Faça IGUAL a este." Pronto! Seu amigo consegue copiar o exemplo.\n\nÉ a mesma coisa com o Claude. Em vez de ficar descrevendo com palavras (que ele entende diferente cada vez), o melhor é dar **exemplos prontos** mostrando como a entrada vira a saída. Assim ele copia o exemplo e acerta de primeira.\n\nAs outras opções seriam:\n- A: Dar uma régua para medir depois que ele desenhar — ajuda a ver o erro, mas não ensina a desenhar certo.\n- C: Perguntar "o que você entendeu?" — aí ele explica o quadrado azul, mas você perde tempo só descobrindo o erro.\n- D: Falar com palavras mais complicadas — mas ele já não estava entendendo as palavras simples, falar mais difícil não vai ajudar!','\n',char(10)));
INSERT INTO cards VALUES('admin','card_1783092993989_auzg4h8n6',518,'Your CLAUDE.',replace('Your CLAUDE.\n\nYour CLAUDE.md exceeds 500 lines mixing TypeScript conventions, testing, API patterns, deployment. Developers struggle to locate/update sections. What approach does Claude Code support for organizing project instructions into focused modules?\nO que a pergunta pede: what approach does Claude Code support for organizing... into focused modules → recurso suportado para modularizar.\n\nRaciocínio: O Claude Code suporta modularização via .claude/rules/ com arquivos focados por tópico. A é sobre herança hierárquica (não modularização por tema); C não é como o Claude carrega instruções; D não é um recurso real. B .\n\n[ ] A - Multiple CLAUDE.md files at different tree levels, each overriding the parent.\n[ ] B - Separate markdown files in .claude/rules/, each covering one topic (testing.md, api-conventions.md).\n[ ] C - Split into README.md files in subdirectories, loaded automatically as instructions.\n[ ] D - A .claude/config.yaml mapping file patterns to sections within CLAUDE.md.','\n',char(10)),'[ ] B - Separate markdown files in .claude/rules/, each covering one topic (testing.md, api-conventions.md).','["Domain_3::Claude_Code_Configuration_Workflows", "Domain_4::Prompt_Engineering_Structured_Output", "Scenario_2::Code_Generation_Claude_Code"]','New',0,2.5,0,1783092993989,1783728140711,1783203558653,replace('**Tradução para português do Brasil:**\n\nSeu CLAUDE.md excede 500 linhas, misturando convenções TypeScript, testes, padrões de API e deploy. Os desenvolvedores têm dificuldade para localizar/atualizar seções. Qual abordagem o Claude Code suporta para organizar instruções do projeto em módulos focados?\n\n[ ] A - Múltiplos arquivos CLAUDE.md em diferentes níveis da árvore de diretórios, cada um sobrescrevendo o pai.\n[ ] B - Arquivos markdown separados em .claude/rules/, cada um cobrindo um tópico (testing.md, api-conventions.md).\n[ ] C - Dividir em arquivos README.md em subdiretórios, carregados automaticamente como instruções.\n[ ] D - Um arquivo .claude/config.yaml que mapeia padrões de arquivo para seções dentro do CLAUDE.md.','\n',char(10)),replace('**Explicação para adulto tech lead:**\n\nA pergunta trata de como o Claude Code (ferramenta da Anthropic para desenvolvimento assistido via terminal) gerencia instruções de projeto quando o arquivo `CLAUDE.md` fica grande demais para ser prático.\n\nA alternativa **B** é a correta. O Claude Code oferece suporte nativo ao diretório `.claude/rules/`, onde você pode colocar múltiplos arquivos markdown, cada um dedicado a um tópico específico (ex.: `testing.md`, `api-conventions.md`, `typescript-style.md`). Todos esses arquivos são carregados e concatenados como contexto de instruções, sem que um sobrescreva o outro — eles são simplesmente combinados. Isso resolve o problema de um monolito de 500+ linhas, permitindo que cada time mantenha seu próprio arquivo de regras sem colisão.\n\nPor que as demais estão erradas:\n\n- **A**: É uma funcionalidade que **não existe** no Claude Code. O Claude Code não suporta "herança" hierárquica de múltiplos arquivos `CLAUDE.md` onde um sobrescreve outro. Existe um conceito de cascata com `CLAUDE.md` em subdiretórios para escopo, mas não é um mecanismo de sobrescrita por tópico como descrito — e certamente não resolve modularização temática.\n\n- **C**: O Claude Code **não carrega** `README.md` como instruções de projeto automaticamente. READMEs são para documentação humana; o Claude Code ignora `README.md` a menos que explicitamente referenciado. Essa alternativa confunde documentação de projeto com instruções de agente.\n\n- **D**: Não existe nenhum recurso chamado `.claude/config.yaml` para mapear padrões de arquivo a seções do `CLAUDE.md`. O Claude Code usa `CLAUDE.md` diretamente e, para modularização, usa `.claude/rules/`. Essa alternativa é inventada.\n\n**Resumo técnico:** Use `.claude/rules/` com arquivos markdown temáticos para modularizar instruções. Cada arquivo é carregado e adicionado ao contexto. Simples, escalável e suportado nativamente.','\n',char(10)),replace('Imagine que você tem um caderno gigante de 500 páginas com regras de como fazer lição de casa, brincar, arrumar o quarto e cozinhar — tudo misturado. Fica difícil achar o que você precisa, né?\n\nO Claude Code (um robô que ajuda programadores) resolve esse problema assim: em vez de um caderno gigante, você pode criar VÁRIOS caderninhos menores, cada um com um assunto só. Um caderninho só para regras de testes, outro só para regras de TypeScript, outro só para regras de API. Esses caderninhos ficam guardados numa pasta chamada `.claude/rules/`.\n\nEntão a resposta certa é a **B**: criar arquivos separados dentro de `.claude/rules/`, cada um falando de um tópico diferente.\n\nAs outras opções estão erradas porque:\n- A: Não existe esse negócio de vários CLAUDE.md que um anula o outro.\n- C: README.md é como a "capa" do projeto, o robô não lê isso automaticamente.\n- D: Não existe esse arquivo mágico `.claude/config.yaml` que o robô entenda para esse propósito.','\n',char(10)));
INSERT INTO cards VALUES('admin','card_1783092994019_139sft5hd',519,'Adding error handling across 120 files in three phases: (1) discovery, (2) collaborative design, (3) implementation.',replace('Adding error handling across 120 files in three phases: (1) discovery, (2) collaborative design, (3) implementation.\n\nAdding error handling across 120 files in three phases: (1) discovery, (2) collaborative design, (3) implementation. In Phase 1 Claude generates verbose output that fills the context window before discovery finishes. What''s the most effective approach to complete this while maintaining implementation consistency?\nO que a pergunta pede: most effective approach... while maintaining consistency → restrição dupla (terminar a descoberta + manter consistência).\n\nA pegadinha: A Fase 1 é verbosa e enche o contexto → isole a verbosidade num subagente.\n\nRaciocínio: A descoberta verbosa deve rodar isolada (subagente Explore) , devolvendo só um resumo ao contexto principal, que fica limpo para o design e a implementação consistentes. A e B fragmentam o estado (risco à consistência); C só adia o estouro de contexto. D .\n\n[ ] A - Headless mode with --continue, passing explicit summaries between batches.\n[ ] B - Define the pattern in CLAUDE.md, process files in batches across sessions, relying on the shared file.\n[ ] C - Continue all phases in the main conversation, using /compact periodically.\n[ ] D - Use the Explore subagent for Phase 1 to isolate verbose output and return a summary, then continue Phases 2-3 in the main conversation.','\n',char(10)),'D - Use the Explore subagent for Phase 1 to isolate verbose output and return a summary, then continue Phases 2-3 in the main conversation.','["Domain_1::Agentic_Architecture_Orchestration", "Domain_5::Context_Management_Reliability", "Scenario_4::Developer_Productivity"]','New',0,2.5,0,1783092994019,1783728144166,1783203558653,replace('**Tradução para Português do Brasil:**\n\nAdicionando tratamento de erros em 120 arquivos em três fases: (1) descoberta, (2) design colaborativo, (3) implementação.\n\nAdicionando tratamento de erros em 120 arquivos em três fases: (1) descoberta, (2) design colaborativo, (3) implementação. Na Fase 1, o Claude gera uma saída verbosa que preenche a janela de contexto antes que a descoberta termine. Qual é a abordagem mais eficaz para concluir isso mantendo a consistência da implementação?\n\n[ ] A - Modo headless com --continue, passando resumos explícitos entre os lotes.\n[ ] B - Definir o padrão no CLAUDE.md, processar arquivos em lotes entre sessões, confiando no arquivo compartilhado.\n[ ] C - Continuar todas as fases na conversa principal, usando /compact periodicamente.\n[ ] D - Usar o subagente Explore para a Fase 1, isolando a saída verbosa e retornando um resumo, depois continuar as Fases 2-3 na conversa principal.','\n',char(10)),replace('**Explicação para Adulto (Tech Lead):**\n\nO problema central é que a Fase 1 (descoberta) é inerentemente verbosa — analisar 120 arquivos para mapear pontos de falha, fluxos existentes e onde inserir tratamento de erros gera uma quantidade massiva de texto. Essa verbosidade compete diretamente com a janela de contexto limitada do modelo. Se todo esse conteúdo bruto ocupar o contexto principal, não sobra espaço para as fases seguintes (design e implementação), que exigem contexto limpo para tomar decisões consistentes.\n\n**Análise das alternativas:**\n\n- **A (Headless mode com --continue e resumos entre lotes):** Fragmenta o problema em lotes, mas exige que o estado seja passado manualmente via resumos entre execuções. O risco é duplo: (1) resumos podem perder detalhes críticos para consistência; (2) cada execução headless não tem visão do todo, aumentando a chance de decisões inconsistentes entre lotes.\n\n- **B (Definir padrão no CLAUDE.md e processar em lotes entre sessões):** Similar à A, mas ainda mais frágil. Depender de um arquivo de configuração compartilhado (CLAUDE.md) para manter consistência entre sessões é arriscado porque (1) o arquivo é estático e não captura nuances descobertas durante a análise; (2) cada sessão começa "fria", sem memória do que já foi decidido, levando a decisões inconsistentes.\n\n- **C (Continuar tudo na conversa principal com /compact):** /compact ajuda a condensar o histórico, mas não resolve o problema fundamental: o conteúdo verboso da Fase 1 já está ocupando espaço e, mesmo compactado, a compressão pode perder informações críticas. Além disso, o modelo ainda precisa "carregar" todo aquele contexto para as fases seguintes, o que degrada a qualidade da implementação.\n\n- **D (Subagente Explore na Fase 1, retornando resumo):** Esta é a abordagem correta porque resolve o problema de isolamento de contexto. O subagente Explore é uma instância separada do modelo que processa a Fase 1 com sua própria janela de contexto, gerando todo o output verboso necessário sem contaminar o contexto principal. Ao final, ele retorna APENAS um resumo estruturado (padrões encontrados, decisões de design, exceções mapeadas) para o contexto principal. Com o contexto limpo, as Fases 2 (design colaborativo — que pode envolver discussão com o usuário) e 3 (implementação) rodam no contexto principal com máxima capacidade de raciocínio, garantindo consistência porque o resumo da Fase 1 é conciso o suficiente para ser mantido na memória de trabalho do modelo durante todo o processo.','\n',char(10)),replace('Imagina que você tem que organizar 120 brinquedos em 3 etapas: primeiro olhar cada brinquedo e ver o que precisa ser arrumado (descoberta), depois decidir juntos como arrumar (design), e finalmente arrumar tudo (implementação). O problema é que na primeira etapa, você descreve cada brinquedo com tantos detalhes que ocupa todo o papel que você tem para anotar, e não sobra espaço para as próximas etapas.\n\nAs opções A e B seriam como tentar arrumar em partes separadas, usando bilhetinhos para lembrar o que fazer, mas correndo o risco de arrumar cada parte de um jeito diferente. A opção C seria tentar continuar no mesmo papel, amassando e escrevendo bem pequeno — mas ainda assim fica confuso.\n\nA opção D é a mais esperta: chame um amigo (o subagente Explore) para fazer só a primeira etapa sozinho, usando o papel dele. Quando ele terminar, ele te entrega um resumo bem curtinho só com as informações mais importantes. Aí você fica com seu papel limpo e cheio de espaço para fazer as próximas etapas com calma e sem bagunça, garantindo que tudo fique arrumado do mesmo jeito.','\n',char(10)));
INSERT INTO cards VALUES('admin','card_1783092994048_ircczutqu',520,'Including 2-3 exemplar endpoint implementations improves consistency for new endpoints — but this context is only useful for creating new endpoints, not bug fixes or reviews.',replace('Including 2-3 exemplar endpoint implementations improves consistency for new endpoints — but this context is only useful for creating new endpoints, not bug fixes or reviews.\n\nIncluding 2-3 exemplar endpoint implementations improves consistency for new endpoints — but this context is only useful for creating new endpoints, not bug fixes or reviews. What''s the most efficient configuration approach?\nO que a pergunta pede: most efficient configuration → eficiente = carregar o contexto só quando necessário.\n\nA pegadinha: Útil só para criar endpoints → carregar sob demanda , não sempre.\n\nRaciocínio: "Eficiente" + "só um caso" = carregar sob demanda . Uma skill invocada quando se cria endpoint traz o contexto só nessa hora. A polui todo contexto (ineficiente); C é trabalho manual repetitivo; D ativa para qualquer trabalho na API (inclui bug fixes/reviews, onde o contexto é inútil). B . (D é tentadora, mas ativa amplo demais.)\n\n[ ] A - Put the exemplars in CLAUDE.md (always available).\n[ ] B - Create a skill referencing the exemplars with pattern instructions, invoked on-demand via slash command.\n[ ] C - Copy the exemplars manually into each generation request.\n[ ] D - Path-specific rules in .claude/rules/api/ that activate when working in the API directory.','\n',char(10)),'B - Create a skill referencing the exemplars with pattern instructions, invoked on-demand via slash command.','["Domain_3::Claude_Code_Configuration_Workflows", "Domain_5::Context_Management_Reliability", "Domain_4::Prompt_Engineering_Structured_Output", "Scenario_2::Code_Generation_Claude_Code"]','New',0,2.5,0,1783092994048,1783728147705,1783203558653,replace('**Tradução para português do Brasil:**\n\nIncluir 2-3 implementações de endpoints como exemplares melhora a consistência para novos endpoints — mas esse contexto só é útil para criar novos endpoints, não para corrigir bugs ou fazer revisões. Qual é a abordagem de configuração mais eficiente?\n\n[ ] A - Colocar os exemplares no CLAUDE.md (sempre disponível).\n[ ] B - Criar uma skill referenciando os exemplares com instruções de padrão, invocada sob demanda via comando de barra (/).\n[ ] C - Copiar os exemplares manualmente em cada solicitação de geração.\n[ ] D - Regras específicas de diretório em .claude/rules/api/ que são ativadas ao trabalhar no diretório da API.','\n',char(10)),replace('**Explicação para adulto (tech lead):**\n\nA pergunta destaca um ponto importante: o contexto dos exemplares é **útil apenas para criação de novos endpoints**, não para bugs ou code reviews. A palavra-chave é **eficiência** — carregar esse contexto apenas quando necessário, sem poluir o contexto geral do assistente.\n\n**Alternativa correta: B** — Criar uma skill com os exemplares e instruções de padrão, invocada sob demanda via slash command. Isso é eficiente porque:\n\n- O contexto só é carregado quando o desenvolvedor explicitamente invoca a skill (ex: `/new-endpoint`).\n- Não polui o contexto de conversas sobre bugs, revisões ou outros tópicos onde os exemplares seriam irrelevantes.\n- Mantém a consistência sem overhead desnecessário.\n\n**Por que as demais estão erradas:**\n\n- **A (CLAUDE.md):** O conteúdo fica "sempre disponível", consumindo tokens do contexto permanentemente, mesmo quando o trabalho é sobre bugs ou revisões. É ineficiente.\n- **C (cópia manual):** Altamente ineficiente em termos de trabalho manual. Força o desenvolvedor a copiar e colar os exemplares repetidamente, o que é propenso a erros e inconsistências.\n- **D (path-specific rules em .claude/rules/api/):** Embora pareça inteligente, essas regras são ativadas **sempre que o usuário trabalha no diretório da API** — independentemente de estar criando um novo endpoint ou corrigindo um bug. Para bugs e revisões, o contexto dos exemplares é inútil, consumindo tokens e poluindo o contexto desnecessariamente. A alternativa B é mais granular e eficiente.','\n',char(10)),replace('**Explicação para criança de 10 anos:**\n\nImagina que você tem um "caderno de receitas" com as 3 melhores receitas de bolo. Esse caderno só ajuda quando você vai FAZER um bolo novo. Se você está apenas corrigindo um bolo que já fez (queimou um pouco) ou olhando a receita de outra pessoa, o caderno não serve para nada.\n\nA pergunta é: qual o jeito mais esperto de guardar esse caderno?\n\n- Colocar ele sempre na sua mochila (opção A) — toda hora você carrega ele, mesmo quando está fazendo lição de matemática. Pesa!\n- Criar um "atalho mágico" no seu celular que só abre o caderno quando você pede (opção B) — você só pega o caderno quando realmente vai fazer um bolo. ✅ **Essa é a melhor!**\n- Ficar copiando as receitas à mão toda vez que for fazer um bolo (opção C) — dá um trabalho enorme repetir tudo.\n- Deixar o caderno na gaveta da cozinha e pegar ele sempre que você entra na cozinha (opção D) — mas às vezes você entra na cozinha só para beber água, não para fazer bolo. Aí você pega o caderno sem precisar.\n\nA opção B é a mais eficiente porque você só usa o "atalho" quando realmente precisa criar um endpoint novo, sem desperdiçar espaço ou esforço.','\n',char(10)));
INSERT INTO cards VALUES('admin','card_1783092994122_ik5vgqt4r',521,'You must add Slack notifications.',replace('You must add Slack notifications.\n\nYou must add Slack notifications. Existing channels (email, SMS, push) have clear patterns. But Slack offers different integration methods (webhooks, bot tokens, Apps) with different capabilities. The ticket says "add Slack support" without specifying which method. How should you approach this task?\nO que a pergunta pede: how should you approach this task → como abordar.\n\nA pegadinha: O requisito é ambíguo (não especifica o método) e a escolha tem implicações arquiteturais → planeje antes.\n\nRaciocínio: Requisito ambíguo + escolha com impacto arquitetural = plan mode para levantar as opções e recomendar antes de codar. A , C e D tomam uma decisão técnica importante prematuramente (sem saber se delivery tracking será necessário). B .\n\n[ ] A - Direct execution using incoming webhooks to match the one-way pattern.\n[ ] B - Enter plan mode to explore the options and their architectural implications, then recommend before implementing.\n[ ] C - Direct execution using the bot token approach for delivery confirmation.\n[ ] D - Direct execution to scaffold the Slack class, deferring the method decision.','\n',char(10)),'[ ] B - Enter plan mode to explore the options and their architectural implications, then recommend before implementing.','["Domain_3::Claude_Code_Configuration_Workflows", "Domain_4::Prompt_Engineering_Structured_Output", "Domain_2::Tool_Design_MCP_Integration", "Scenario_2::Code_Generation_Claude_Code"]','New',0,2.5,0,1783092994122,1783728150962,1783203558653,replace('**Tradução para português do Brasil (fiel ao original):**\n\nVocê deve adicionar notificações do Slack. Os canais existentes (e-mail, SMS, push) têm padrões claros. Mas o Slack oferece diferentes métodos de integração (webhooks, tokens de bot, Apps) com diferentes capacidades. O ticket diz "adicionar suporte ao Slack" sem especificar qual método. Como você deve abordar esta tarefa?\n\n[ ] A - Execução direta usando webhooks de entrada para corresponder ao padrão unidirecional.\n[ ] B - Entrar em modo de plano para explorar as opções e suas implicações arquiteturais, depois recomendar antes de implementar.\n[ ] C - Execução direta usando a abordagem de token de bot para confirmação de entrega.\n[ ] D - Execução direta para estruturar a classe Slack, adiando a decisão do método.','\n',char(10)),replace('**Explicação didática para um adulto tech lead:**\n\nO problema central aqui é um requisito ambíguo com implicações arquiteturais significativas. O ticket diz apenas "adicione suporte ao Slack", mas o Slack oferece múltiplos mecanismos de integração (Incoming Webhooks, Slack Bot Tokens, Slack Apps com granularidade de permissões), cada um com capacidades, limites e modelos de manutenção radicalmente diferentes.\n\n**Por que B é a resposta correta:**\n\nA alternativa B propõe iniciar com um "plan mode" — levantar as opções disponíveis, analisar as implicações arquiteturais de cada uma (ex.: webhooks são unidirecionais e simples, mas não permitem ler mensagens ou confirmar delivery; bot tokens permitem interação bidirecional e confirmação, mas exigem gerenciamento de OAuth e escopos; Slack Apps oferecem o máximo de flexibilidade com custo de setup maior) e só então recomendar uma abordagem antes de escrever código. Isso está alinhado com práticas sólidas de engenharia: entender o domínio e as restrições antes de implementar. É a abordagem que evita retrabalho e escolhas arquiteturais equivocadas.\n\n**Por que as demais estão erradas:**\n\n- **A** assume prematuramente que webhooks são a escolha certa só porque os canais existentes seguem um padrão unidirecional. Ignora que o requisito pode evoluir para incluir delivery tracking, leitura de canais, ou interatividade. É uma decisão técnica tomada sem informação suficiente.\n\n- **C** também pula para uma escolha específica (bot token), assumindo que confirmação de entrega é necessária. Se o requisito for apenas notificação unidirecional simples, isso adiciona complexidade desnecessária (gerenciamento de tokens, OAuth, rate limits de bots).\n\n- **D** sugere adiar a decisão implementando uma estrutura genérica. Isso parece pragmático, mas na prática leva a uma abstração prematura — você acaba criando uma classe Slack sem saber qual comportamento concreto ela precisa suportar, o que pode resultar em design genérico demais ou ter que ser refatorado logo em seguida.','\n',char(10)),replace('Imagine que você precisa instalar uma campainha nova em casa. Sua mãe pediu: "quero uma campainha que toque na cozinha". Só que existem vários tipos: uma campainha que só faz "ding-dong", uma que toca música, uma que acende uma luz junto, e até uma que manda uma mensagem no celular. Cada uma precisa de ferramentas e fios diferentes.\n\nSe você já sair furando paredes para instalar a campainha mais simples (webhooks), pode ser que sua mãe queira a que toca música, e você vai ter que desfazer tudo. Se você instalar a mais complicada (bot token), pode gastar dinheiro e tempo à toa se ela só queria o "ding-dong" básico.\n\nA melhor ideia (alternativa B) é primeiro perguntar: "Mãe, você quer que a campainha só faça barulho, ou também quer que acenda uma luz? E se a gente não estiver em casa, tem que avisar no celular?" Só depois de entender direitinho o que ela precisa, você escolhe a campainha certa e instala de uma vez só, sem ter que refazer o serviço depois.','\n',char(10)));
INSERT INTO cards VALUES('admin','card_1783092994150_h796hpvsc',522,'Your CLAUDE.',replace('Your CLAUDE.\n\nYour CLAUDE.md (400+ lines) has coding standards, testing, a PR review checklist, deployment, migrations. You want coding/testing always applied, but PR/deployment/migration guidance only during those tasks. What''s the most effective restructuring approach?\nO que a pergunta pede: most effective restructuring → reestruturar.\n\nA pegadinha: sempre (universais) vs só ao executar essas tarefas (específicos de tarefa).\n\nRaciocínio: A divisão pedida é sempre vs sob demanda por tarefa . Universais ficam no CLAUDE.md (sempre carregados); fluxos de tarefa viram Skills acionadas quando necessário. B é por tipo de arquivo (não por tarefa); C mantém tudo sempre carregado; D tira até o que deveria ser sempre aplicado. A .\n\n[ ] A - Keep universal standards in CLAUDE.md and create Skills for task-specific workflows (PR, deploy, migrations) with trigger keywords.\n[ ] B - Split into .claude/rules/ with path-specific glob patterns per file type.\n[ ] C - Keep all content in CLAUDE.md using @import to organize into files.\n[ ] D - Move all guidance into Skills, keeping only a brief project description in CLAUDE.md.','\n',char(10)),'A - Keep universal standards in CLAUDE.md and create Skills for task-specific workflows (PR, deploy, migrations) with trigger keywords.','["Domain_3::Claude_Code_Configuration_Workflows", "Scenario_2::Code_Generation_Claude_Code"]','New',0,2.5,0,1783092994150,1783728153966,1783203558653,replace('**Tradução (pt-BR):**\n\nSeu CLAUDE.md (400+ linhas) contém padrões de codificação, testes, um checklist de revisão de PR, deploy e migrações. Você quer que os padrões de codificação/testes sejam sempre aplicados, mas as orientações de PR/deploy/migração apenas durante essas tarefas específicas. Qual é a abordagem de reestruturação mais eficaz?\n\n[ ] A - Manter os padrões universais no CLAUDE.md e criar Skills para fluxos de trabalho específicos de tarefa (PR, deploy, migrações) com palavras-chave de ativação.\n[ ] B - Dividir em .claude/rules/ com padrões glob específicos por tipo de arquivo.\n[ ] C - Manter todo o conteúdo no CLAUDE.md usando @import para organizar em arquivos.\n[ ] D - Mover todas as orientações para Skills, mantendo apenas uma breve descrição do projeto no CLAUDE.md.','\n',char(10)),replace('**Explicação didática para adulto (tech lead):**\n\nA questão trata da arquitetura de conhecimento do assistente Claude em um projeto. CLAUDE.md é carregado **sempre** em todo contexto. Já Skills (instruções customizadas) são carregadas **sob demanda**, tipicamente ativadas por palavras-chave ou comandos específicos.\n\nO problema apresentado é de granularidade e eficiência: 400+ linhas sendo carregadas integralmente em toda interação, quando parte desse conteúdo só é relevante em momentos específicos (revisão de PR, deploy, migrations). Isso consome tokens de contexto desnecessariamente e pode diluir a atenção do modelo.\n\n**Por que A é a alternativa correta:**\n\n- Separa o que é **sempre relevante** (padrões de codificação, testes) — fica no CLAUDE.md, carregado em todo prompt.\n- Isola o que é **relevante apenas em contextos específicos** (checklist de PR, procedimentos de deploy, migrations) — vira Skills com palavras-chave de gatilho (ex.: "PR review", "deploy", "migrate").\n- Respeita o princípio de **carga sob demanda**: só consome tokens e atenção quando necessário.\n- Mantém o CLAUDE.md enxuto e focado, evitando poluição cognitiva.\n\n**Por que as demais estão erradas:**\n\n- **B** — Dividir por tipo de arquivo (.claude/rules/ com globs path-specific) não resolve o problema. A segmentação por tipo de arquivo é ortogonal à segmentação por tarefa. Um mesmo arquivo .py pode ser editado tanto em tarefas de codificação (que exigem padrões de teste) quanto em tarefas de deploy (que não exigem). Além disso, regras baseadas em glob continuam sendo carregadas sempre que o arquivo correspondente é mencionado, não resolvendo a questão do carregamento sob demanda por tarefa.\n\n- **C** — Manter tudo no CLAUDE.md usando @import só organiza arquiteturalmente, mas não resolve o problema de carregamento. O conteúdo continua sendo carregado integralmente em toda interação, independentemente da tarefa. Organização não é o mesmo que segmentação de carga.\n\n- **D** — Mover tudo para Skills e deixar apenas uma descrição breve no CLAUDE.md é o oposto do desejado. Você perderia a aplicação **sempre ativa** dos padrões de codificação e testes. Skills exigem gatilho explícito; se não houver palavra-chave, o modelo não terá os padrões de codificação disponíveis, mesmo em tarefas rotineiras de desenvolvimento.','\n',char(10)),replace('Imagine que você tem uma mochila bem pesada (o CLAUDE.md) que você leva para a escola todos os dias. Dentro dela, tem coisas que você usa o tempo todo, como seu estojo e caderno (padrões de codificação e testes). Mas também tem coisas que você só usa em dias especiais, como o tênis de Educação Física ou a fantasia de Halloween (instruções de PR, deploy e migrações). Carregar tudo junto todos os dias cansa e atrapalha!\n\nA alternativa A é a mais esperta: você deixa na mochila só o que usa todo dia (estojo e caderno no CLAUDE.md). O tênis de Educação Física e a fantasia de Halloween você guarda em um armário na escola (Skills) e só pega quando for usar (quando alguém falar "vamos fazer deploy!" ou "hora de revisar o PR").\n\nAs outras opções não são tão boas:\n- A B organiza por tipo de objeto (canetas juntas, lápis juntos), mas isso não resolve o problema de carregar peso desnecessário.\n- A C organiza melhor dentro da mochila, mas você continua carregando tudo.\n- A D tira até o estojo e caderno da mochila! Aí você fica sem eles quando precisa.\n','\n',char(10)));
INSERT INTO cards VALUES('admin','card_1783092994181_m5sg30vim',523,'An /analyze-codebase skill performs comprehensive analysis (dependency scanning, coverage, quality metrics).',replace('An /analyze-codebase skill performs comprehensive analysis (dependency scanning, coverage, quality metrics).\n\nAn /analyze-codebase skill performs comprehensive analysis (dependency scanning, coverage, quality metrics). After running it, Claude becomes less responsive and loses track of the original task. What''s the most effective way to address this while preserving full analysis capability?\nO que a pergunta pede: most effective way... while preserving full analysis capability → restrição dupla.\n\nA pegadinha: A saída da análise entope o contexto principal → isole-a num subagente.\n\nRaciocínio: A causa é o contexto principal entupido pela análise volumosa. context: fork isola a execução, preservando toda a capacidade de análise sem poluir a sessão. A muda o modelo (não resolve o entupimento); B perde detalhe (não preserva análise completa); C fragmenta sem resolver o acúmulo. D .\n\n[ ] A - Add model: haiku to the frontmatter for a faster model.\n[ ] B - Compress all outputs into a brief summary before displaying.\n[ ] C - Split into three smaller skills that each generate less output.\n[ ] D - Add context: fork to run the analysis in an isolated sub-agent context.','\n',char(10)),'D - Add context: fork to run the analysis in an isolated sub-agent context.','["Domain_3::Claude_Code_Configuration_Workflows", "Domain_5::Context_Management_Reliability", "Scenario_2::Code_Generation_Claude_Code"]','New',0,2.5,0,1783092994181,1783728157233,1783203558653,replace('**Tradução para pt-BR:**\n\nUma habilidade /analyze-codebase realiza uma análise abrangente (verificação de dependências, cobertura, métricas de qualidade). Após executá-la, Claude fica menos responsivo e perde o rumo da tarefa original. Qual é a maneira mais eficaz de resolver isso enquanto preserva a capacidade total de análise?\n\n[ ] A - Adicionar model: haiku ao frontmatter para usar um modelo mais rápido.\n[ ] B - Comprimir todas as saídas em um breve resumo antes de exibir.\n[ ] C - Dividir em três habilidades menores que gerem menos saída cada uma.\n[ ] D - Adicionar context: fork para executar a análise em um contexto de subagente isolado.','\n',char(10)),replace('**Explicação para adulto (tech lead):**\n\nO problema central é que a saída volumosa da análise de código está consumindo o contexto principal da sessão, fazendo com que Claude perca a capacidade de manter a tarefa original — um clássico problema de estouro de janela de contexto ou degradação de desempenho por excesso de tokens.\n\n**Alternativa correta: D — context: fork**\n\nA diretiva `context: fork` cria um subagente isolado que executa a análise em seu próprio contexto, separado da conversa principal. Isso é a abordagem arquiteturalmente correta porque:\n\n- **Preserva a capacidade total de análise**: o subagente tem acesso irrestrito às ferramentas e pode gerar toda a saída necessária sem se preocupar com limite de contexto.\n- **Isola o impacto no contexto principal**: o fork retorna apenas um resultado resumido ou referência, sem entupir a sessão principal com megabytes de dependências, cobertura e métricas.\n- **Escalabilidade**: segue o padrão de design de sistemas multiagentes, onde tarefas pesadas são delegadas a agentes efêmeros.\n\n**Por que as outras estão erradas:**\n\n- **A — model: haiku**: Trocar o modelo não resolve o problema fundamental. O Haiku também tem limites de contexto e, sendo um modelo menor, pode *piorar* a capacidade de análise complexa. A causa raiz não é velocidade, é volume de dados.\n- **B — Comprimir saídas**: Isso exige pós-processamento e perde detalhes. A restrição é clara: "preserving full analysis capability". Compressão descarta informação — portanto, viola o requisito. Além disso, o estrago já está feito: Claude já gastou tokens para gerar a saída completa antes de comprimi-la.\n- **C — Dividir em três skills**: Fragmentar a análise não reduz o volume total de saída — apenas a distribui. O acúmulo de contexto ainda ocorre, possivelmente de forma ainda mais fragmentada e difícil de gerenciar. Não ataca a causa raiz, apenas redistribui o problema.','\n',char(10)),replace('Imagine que você tem uma mochila (o contexto do Claude) e precisa colocar um relatório enorme de dever de casa (a análise de código) dentro dela. Se você colocar esse relatório enorme, a mochila fica tão cheia que você não consegue nem pegar o restante do material da escola (a tarefa original).\n\nA opção D é a melhor porque funciona como criar uma "mochilinha extra" (um subagente) só para o relatório enorme. O relatório fica lá, completinho, sem atrapalhar o que você já estava fazendo na mochila principal. Você não perde nada da análise e ainda consegue continuar sua tarefa original de boa.\n\nAs outras opções são ruins porque:\n- A (trocar de modelo) é como trocar de mochila pra uma menor — não resolve, só piora.\n- B (resumir o relatório) joga informações importantes fora — aí você perde detalhes.\n- C (dividir em três partes) ainda enche a mochila, só que com três papéis menores em vez de um grande. O problema continua.','\n',char(10)));
INSERT INTO cards VALUES('admin','card_1783092994211_d64v9av3b',524,'Distinct areas have different conventions (React functional+hooks, API async/await, DB repository pattern).',replace('Distinct areas have different conventions (React functional+hooks, API async/await, DB repository pattern).\n\nDistinct areas have different conventions (React functional+hooks, API async/await, DB repository pattern). Test files are spread alongside code (Button.test.tsx next to Button.tsx), and you want all tests to follow the same conventions regardless of location. Most maintainable way to apply correct conventions automatically?\nO que a pergunta pede: most maintainable way... automatically apply correct conventions → aplicar automaticamente, por caminho/tipo de arquivo.\n\nA pegadinha: As convenções dependem do tipo de arquivo , e os testes seguem regra própria onde quer que estejam → globs.\n\nRaciocínio: A aplicação automática por tipo/caminho de arquivo (incluindo testes espalhados, via glob *.test.* ) é exatamente o que .claude/rules/ com globs faz. A depende de inferência (não confiável); B não cobre testes espalhados de forma uniforme; D exige invocação manual (não é automático). C .\n\n[ ] A - Consolidate all conventions in the root CLAUDE.md under headers, relying on inference.\n[ ] B - Place a CLAUDE.md in each subdirectory.\n[ ] C - Create rule files in .claude/rules/ with YAML frontmatter specifying glob patterns to apply conventions by file path.\n[ ] D - Create skills per code type with conventions in their SKILL.md.','\n',char(10)),'C - Create rule files in .claude/rules/ with YAML frontmatter specifying glob patterns to apply conventions by file path.','["Domain_3::Claude_Code_Configuration_Workflows", "Domain_4::Prompt_Engineering_Structured_Output", "Scenario_2::Code_Generation_Claude_Code"]','New',0,2.5,0,1783092994211,1783728160448,1783203558653,replace('**Tradução para português do Brasil:**\n\nÁreas distintas têm convenções diferentes (React funcional+hooks, API async/await, padrão repositório de banco de dados). Os arquivos de teste estão espalhados junto ao código (Button.test.tsx ao lado de Button.tsx), e você quer que todos os testes sigam as mesmas convenções independentemente da localização. Qual a forma mais sustentável de aplicar as convenções corretas automaticamente?\n\n[ ] A - Consolidar todas as convenções no CLAUDE.md raiz sob cabeçalhos, confiando em inferência.\n[ ] B - Colocar um CLAUDE.md em cada subdiretório.\n[ ] C - Criar arquivos de regra em .claude/rules/ com frontmatter YAML especificando padrões glob para aplicar convenções por caminho de arquivo.\n[ ] D - Criar skills por tipo de código com as convenções no respectivo SKILL.md.','\n',char(10)),replace('**Explicação para um adulto tech lead:**\n\nA pergunta descreve um cenário típico de codebase poliglota: diferentes áreas do projeto (React, API, DB) seguem convenções distintas, e os testes — que podem estar em qualquer lugar — devem seguir uma convenção uniforme. O desafio é aplicar as regras certas automaticamente, sem depender de ação manual nem de inferência frágil.\n\n**Alternativa correta: C**\n\nO mecanismo `.claude/rules/` com frontmatter YAML e glob patterns foi projetado exatamente para isso. Cada arquivo de regra pode declarar algo como:\n\n```yaml\n---\nglobs: "**/*.test.*"\n---\n# Regras para testes: usar describe/it, mocks padronizados, etc.\n```\n\nIsso permite que:\n- Regras específicas para React components sejam aplicadas apenas a arquivos `.tsx` dentro de `components/`.\n- Regras para testes sejam aplicadas a qualquer arquivo que corresponda a `*.test.*`, independentemente de onde ele esteja na árvore de diretórios.\n- Regras para API sejam aplicadas a `routes/**/*.ts`.\n- O mecanismo de glob resolution do Claude (ou da ferramenta) combina os padrões de forma eficiente e determinística.\n\n**Por que as demais estão erradas:**\n\n**A** - Consolidar tudo no CLAUDE.md raiz e "confiar em inferência" é frágil. Inferência de contexto por LLM não é determinística; o modelo pode aplicar a convenção errada dependendo de nuances no prompt ou no histórico. Não é "automático" de forma confiável — você depende do julgamento do modelo.\n\n**B** - Colocar um CLAUDE.md em cada subdiretório até parece razoável, mas quebra com testes espalhados. Um teste `Button.test.tsx` pode estar no mesmo diretório que `Button.tsx`, mas tecnicamente ele "herda" as regras do diretório de componentes — quando na verdade deveria seguir as regras de teste. Além disso, isso duplica configuração e é difícil de manter conforme o projeto cresce.\n\n**D** - Skills são invocadas *manualmente* ou por seleção explícita do usuário, não são aplicadas automaticamente por padrão de caminho de arquivo. A pergunta pede especificamente "apply correct conventions automatically" — skills não atendem a esse requisito de automatismo.\n\n**Conclusão:** A alternativa C resolve o problema de forma declarativa, determinística e escalável, usando globs para mapear convenções a padrões de caminho — inclusive capturando arquivos de teste espalhados.','\n',char(10)),replace('Imagine que você tem uma fábrica de brinquedos. Cada tipo de brinquedo (carrinho, boneca, quebra-cabeça) tem um jeito diferente de ser montado. Mas todos os brinquedos passam por um controle de qualidade que segue as mesmas regras, não importa onde eles estão na fábrica.\n\nAgora, você quer ensinar o robô da fábrica a montar cada brinquedo do jeito certo, sem você precisar ficar lembrando ele toda hora.\n\nSe você escrever tudo num único papel e pedir para o robô "adivinhar" o que fazer (alternativa A), ele pode errar — robôs não são bons em adivinhar.\n\nSe você colocar um papel em cada sala da fábrica (alternativa B), o robô vai seguir a regra da sala, mas um brinquedo que vai para o controle de qualidade vai seguir a regra da sala de montagem, não a regra do controle de qualidade.\n\nSe você criar "habilidades" que o robô só usa se você mandar (alternativa D), ele nunca vai fazer automaticamente.\n\nA melhor ideia (alternativa C) é ter uma pastinha de regras mágicas, onde cada regra tem um "padrão" (um jeito de reconhecer o brinquedo). Por exemplo: "se o nome do arquivo tiver ''.test.'' no meio, use as regras de teste". Assim, não importa onde o arquivo de teste está — na sala dos carrinhos, das bonecas ou dos quebra-cabeças — o robô sempre vai aplicar as regras certas de teste. É automático e não erra!','\n',char(10)));
INSERT INTO cards VALUES('admin','card_1783092994241_w2rxzogpp',525,'You want a GitHub MCP server for the team.',replace('You want a GitHub MCP server for the team.\n\nYou want a GitHub MCP server for the team. Each of six developers has their own personal access token. You want consistent tooling without committing credentials. What''s the most effective configuration approach?\nO que a pergunta pede: most effective configuration... without committing credentials → consistência sem versionar segredos.\n\nA pegadinha: without committing credentials elimina qualquer opção que fixe tokens no repositório.\n\nRaciocínio: Um .mcp.json versionado dá tooling consistente ao time; a expansão ${GITHUB_TOKEN} mantém o segredo fora do versionamento (cada dev provê sua variável). B perde a consistência (cada um configura do seu jeito); C é complexidade desnecessária; D mistura placeholder versionado com override (frágil). A .\n\n[ ] A - Add the server to a project-scoped .mcp.json with environment variable expansion (${GITHUB_TOKEN}) for auth, and document the variable in the README.\n[ ] B - Each developer configures the server in user scope with claude mcp add --scope user.\n[ ] C - Create a wrapper that reads tokens from .env and proxies to the GitHub API.\n[ ] D - Configure project scope with a placeholder token, then have developers override locally.','\n',char(10)),'[ ] A - Add the server to a project-scoped .mcp.json with environment variable expansion (${GITHUB_TOKEN}) for auth, and document the variable in the README.','["Domain_2::Tool_Design_MCP_Integration", "Domain_3::Claude_Code_Configuration_Workflows", "Scenario_4::Developer_Productivity"]','New',0,2.5,0,1783092994241,1783728163697,1783203558653,replace('**Tradução para pt-BR:**\n\nPergunta: "Você quer um servidor MCP do GitHub para o time. Cada um dos seis desenvolvedores tem seu próprio token de acesso pessoal. Você quer ferramentas consistentes sem versionar credenciais. Qual é a abordagem de configuração mais eficaz?"\n\n[ ] A - Adicionar o servidor a um .mcp.json com escopo de projeto com expansão de variável de ambiente (${GITHUB_TOKEN}) para autenticação, e documentar a variável no README.\n[ ] B - Cada desenvolvedor configura o servidor no escopo do usuário com claude mcp add --scope user.\n[ ] C - Criar um wrapper que lê tokens de um .env e faz proxy para a API do GitHub.\n[ ] D - Configurar escopo do projeto com um token placeholder, e então os desenvolvedores sobrescrevem localmente.','\n',char(10)),replace('**Explicação para adulto (tech lead):**\n\n**Alternativa correta: A**\n\nA opção A é a mais eficaz porque resolve os dois requisitos simultaneamente: (1) consistência de tooling entre os 6 desenvolvedores e (2) não versionamento de credenciais.\n\nO arquivo `.mcp.json` com escopo de projeto (project-scoped) fica versionado no repositório, garantindo que todos os desenvolvedores usem exatamente a mesma configuração de servidor MCP — mesmas ferramentas, mesmos nomes de comandos, mesma estrutura. Isso elimina divergências de configuração que gerariam "funfa na minha máquina".\n\nA expansão de variável de ambiente `${GITHUB_TOKEN}` mantém o segredo fora do repositório. Cada desenvolvedor define sua própria variável de ambiente `GITHUB_TOKEN` com seu PAT pessoal (via shell rc, .env.local ignorado pelo git, ou gerenciador de segredos). O token nunca toca o repositório. Documentar no README informa o time sobre a variável necessária, fechando o ciclo.\n\n**Por que as outras estão erradas:**\n\n❌ **B** — "Cada desenvolvedor configura no escopo do usuário." Isso quebra a consistência. Cada um pode configurar parâmetros diferentes, versões diferentes, ou até esquecer de configurar. Não há um único arquivo versionado garantindo que todos usam o mesmo server. Além disso, não há trilha de auditoria via código revisado.\n\n❌ **C** — "Wrapper que lê .env e faz proxy." É excesso de complexidade. Você estaria introduzindo uma camada intermediária (um processo proxy) que precisa ser mantida, testada e documentada. O MCP server já suporta expansão de variável de ambiente nativamente; não há necessidade de reinventar a roda com um proxy customizado. Mais código = mais superfície de falha.\n\n❌ **D** — "Placeholder token + override local." O placeholder token versionado no `.mcp.json` é um anti-padrão de segurança. Mesmo sendo placeholder, há risco de um token real vazar acidentalmente no commit. Além disso, o mecanismo de override local é frágil: cada desenvolvedor precisa lembrar de sobrescrever, e ferramentas de CI podem acidentalmente usar o placeholder. É uma abordagem propensa a erro.','\n',char(10)),replace('Imagine que você e seus 5 amigos vão jogar um videogame online. Cada um tem sua própria senha para entrar no jogo. Vocês querem jogar com as mesmas regras (mesmo mapa, mesmas armas, mesma dificuldade), mas ninguém pode escrever a senha num papel que fica colado na parede da sala — porque qualquer visitante poderia ver.\n\nA opção A é a melhor: vocês combinam as regras do jogo num caderno que todos podem ver e copiar (o .mcp.json versionado). Mas, em vez de escrever a senha no caderno, vocês escrevem "use a senha que está no seu bolso" (${GITHUB_TOKEN}). Cada um guarda a própria senha no bolso (variável de ambiente). Assim, todo mundo joga com as mesmas regras, mas ninguém vê a senha do outro.\n\nAs outras opções são piores:\n\n- Opção B: cada um inventa as próprias regras do jogo do seu jeito. Vira bagunça.\n- Opção C: você cria um robô complicado que lê a senha de um cofre e conecta no jogo. Dá muito trabalho e pode quebrar.\n- Opção D: você escreve "batata" como senha no caderno (placeholder) e pede pra cada amigo lembrar de trocar pela senha verdadeira. Alguém vai esquecer e o jogo não funciona.','\n',char(10)));
INSERT INTO cards VALUES('admin','card_1783092994275_wr8d8foe2',526,'You want a /review slash command available to every developer when they clone/pull the repo.',replace('You want a /review slash command available to every developer when they clone/pull the repo.\n\nYou want a /review slash command available to every developer when they clone/pull the repo. Where should you create this command file?\nO que a pergunta pede: where should you create o comando para que todos recebam ao clonar → versionado no projeto.\n\nA pegadinha: available to every developer when they clone/pull → tem que viver no projeto versionado.\n\nRaciocínio: Para que todos recebam o comando ao clonar, ele precisa estar versionado no projeto : .claude/commands/ . C é pessoal (não compartilha); A e D não são onde comandos vivem. B .\n\n[ ] A - In a .claude/config.json with a commands array.\n[ ] B - In the .claude/commands/ directory in the project repository.\n[ ] C - In ~/.claude/commands/ in each developer''s home directory.\n[ ] D - In the CLAUDE.md at the project root.','\n',char(10)),'B - In the .claude/commands/ directory in the project repository.','["Domain_3::Claude_Code_Configuration_Workflows", "Domain_2::Tool_Design_MCP_Integration", "Scenario_2::Code_Generation_Claude_Code"]','New',0,2.5,0,1783092994275,1783728166936,1783203558653,replace('**Tradução para português do Brasil:**\n\nVocê quer um comando slash /review disponível para todos os desenvolvedores quando eles clonarem/fizerem pull do repositório.\n\nOnde você deve criar este arquivo de comando?\n\n[ ] A - Em um .claude/config.json com um array de comandos.\n[ ] B - No diretório .claude/commands/ no repositório do projeto.\n[ ] C - Em ~/.claude/commands/ no diretório home de cada desenvolvedor.\n[ ] D - No CLAUDE.md na raiz do projeto.','\n',char(10)),replace('**Explicação técnica para um adulto Tech Lead:**\n\nA pergunta tem um requisito fundamental: o comando /review deve estar **disponível para todos os desenvolvedores assim que clonarem ou fizerem pull do repositório**. Isso significa que ele precisa estar **versionado no controle de versão (git)** e fazer parte do projeto, não da máquina local de cada desenvolvedor.\n\n- **Alternativa B (correta):** O diretório `.claude/commands/` na raiz do repositório é o local padrão onde comandos slash customizados e compartilhados via versionamento são definidos. Qualquer arquivo (ex.: `review.json` ou `review.md`) colocado ali é automaticamente reconhecido pelo Claude Code como um comando slash disponível. Como esse diretório fica dentro do projeto e é versionado pelo git, todos os desenvolvedores recebem o comando ao clonar ou fazer pull.\n\n- **Alternativa A (incorreta):** O `.claude/config.json` pode conter configurações gerais, mas comandos slash customizados não são definidos dentro de um "commands array" neste arquivo. O mecanismo padrão do Claude Code para comandos compartilhados é via arquivos no diretório `.claude/commands/`.\n\n- **Alternativa C (incorreta):** `~/.claude/commands/` é o diretório **local/pessoal** do desenvolvedor. Arquivos colocados ali são visíveis apenas para aquele desenvolvedor específico e **não são versionados**. Portanto, não atende ao requisito de estar disponível para todos ao clonar o repositório.\n\n- **Alternativa D (incorreta):** O `CLAUDE.md` é um arquivo de instruções/contexto para o Claude (como um prompt de sistema), não um local para definir comandos slash. Ele pode mencionar o comando, mas não o implementa de fato.\n\n**Resumo:** A resposta correta é B, pois somente o diretório `.claude/commands/` versionado no repositório garante distribuição automática a todos os desenvolvedores.','\n',char(10)),replace('**Explicação para uma criança de 10 anos:**\n\nImagina que você e seus amigos estão fazendo um trabalho em grupo na escola. Vocês criaram uma "regra secreta" (o comando /review) que todo mundo precisa usar.\n\nSe você colocar essa regra dentro da **pasta do trabalho** (que está no pendrive que todos copiam), quando alguém pegar uma cópia do trabalho, já vai ter a regra junto. É isso que a opção B faz: coloca o comando dentro da pasta do projeto que fica salva no git (como se fosse um pendrive mágico que todo mundo compartilha).\n\nAgora, se você colocar a regra na **sua gaveta pessoal em casa** (opção C), só você vai ter acesso a ela — seus amigos não vão saber da regra quando pegarem o trabalho.\n\nA opção A é como se você tentasse colocar a regra dentro de um manual de instruções que não aceita esse tipo de anotação. E a opção D é como escrever a regra num post-it colado na parede — até dá pra ver, mas não funciona como um comando de verdade.\n\n**Então a resposta certa é a B** porque é o único lugar que faz o comando viajar junto com o projeto para todo mundo que baixar ele!','\n',char(10)));
INSERT INTO cards VALUES('admin','card_1783092994311_i74vdbqek',527,'Single-concern requests: 94% accuracy.',replace('Single-concern requests: 94% accuracy.\n\nSingle-concern requests: 94% accuracy. Multi-concern messages ("refund order #1234 and update shipping for #5678"): tool selection drops to 58% — the agent addresses one concern or mixes parameters. Most effective approach to improve reliability for multi-concern requests?\nO que a pergunta pede: most effective approach to improve reliability for multi-concern requests → confiabilidade em pedidos com múltiplas demandas .\n\nA pegadinha: O agente se confunde quando várias demandas vêm juntas → decompor em pedidos individuais.\n\nRaciocínio: A raiz é a sobrecarga de processar várias demandas de uma vez. Decompor explicitamente em pedidos individuais antes de processar é o mais confiável e escalável. C (few-shot) ajuda mas é menos robusto que a decomposição estrutural; B reduz a clareza; D só remedia depois do erro. A . (C é defensável em provas que priorizam few-shot, mas a decomposição é estruturalmente mais forte.)\n\n[ ] A - A preprocessing layer that decomposes multi-concern messages into individual requests, processes each, then combines results.\n[ ] B - Consolidate related tools into fewer, general-purpose tools.\n[ ] C - Add few-shot examples demonstrating reasoning and tool sequence for multi-concern requests.\n[ ] D - Response validation that detects incomplete responses and re-prompts.','\n',char(10)),'A - A preprocessing layer that decomposes multi-concern messages into individual requests, processes each, then combines results.','["Domain_2::Tool_Design_MCP_Integration", "Domain_4::Prompt_Engineering_Structured_Output", "Domain_5::Context_Management_Reliability", "Scenario_1::Customer_Support_Agent"]','New',0,2.5,0,1783092994311,1783728170707,1783203558653,replace('**Tradução para português do Brasil:**\n\n**Pergunta:** Requisições de uma única demanda: 94% de precisão. Mensagens com múltiplas demandas ("reembolse o pedido #1234 e atualize o envio do #5678"): a seleção de ferramentas cai para 58% — o agente atende uma demanda ou mistura os parâmetros. Qual é a abordagem mais eficaz para melhorar a confiabilidade em requisições com múltiplas demandas?\n\n[ ] A - Uma camada de pré-processamento que decompõe mensagens com múltiplas demandas em requisições individuais, processa cada uma e depois combina os resultados.\n[ ] B - Consolidar ferramentas relacionadas em menos ferramentas de propósito geral.\n[ ] C - Adicionar exemplos few-shot demonstrando o raciocínio e a sequência de ferramentas para requisições com múltiplas demandas.\n[ ] D - Validação de resposta que detecta respostas incompletas e reenvia o prompt.','\n',char(10)),replace('**Explicação para um adulto tech lead:**\n\nA alternativa correta é a **A**.\n\nO problema central é claro: quando o agente recebe múltiplas demandas em uma única mensagem, a taxa de acerto na seleção de ferramentas cai de 94% para 58%. Isso indica que o modelo tem dificuldade em processar paralelamente intenções distintas e associar corretamente os parâmetros de cada uma.\n\n**Por que A é a melhor resposta:**\n\nA alternativa A propõe uma **decomposição estrutural explícita** do problema. Em vez de forçar o modelo a resolver o problema complexo de uma vez, criamos uma camada de pré-processamento que:\n1. Identifica quantas demandas existem na mensagem.\n2. Separa cada demanda em uma requisição individual e independente.\n3. Processa cada requisição isoladamente (onde o agente tem 94% de precisão).\n4. Combina os resultados de forma consistente.\n\nEssa abordagem ataca a **causa raiz** do problema: a sobrecarga cognitiva do modelo ao lidar com múltiplas intenções simultâneas. Ao reduzir o problema a subproblemas que o modelo já resolve bem, ganhamos robustez, escalabilidade e rastreabilidade. É um padrão arquitetural conhecido como "dividir para conquistar" (divide and conquer) e é particularmente eficaz em sistemas de agentes autônomos.\n\n**Por que as demais alternativas são inferiores:**\n\n- **C (few-shot examples):** Embora seja uma abordagem válida e possa trazer melhorias, ela depende do modelo generalizar corretamente a partir dos exemplos. O few-shot melhora o comportamento, mas não elimina a fragilidade inerente do modelo ao processar múltiplas intenções. É uma solução mais frágil e menos previsível que a decomposição estrutural. Em alguns contextos de prova, C poderia ser considerado, mas a alternativa A é estruturalmente mais forte e confiável.\n\n- **B (consolidar ferramentas):** Unificar ferramentas de propósito geral reduz a granularidade do sistema, o que pode até piorar o problema ao criar ferramentas mais complexas e ambíguas. Em vez de ajudar o modelo a distinguir demandas, torna a separação mais difícil.\n\n- **D (validação de resposta):** Essa abordagem é **reativa**, não **preventiva**. Ela só detecta o erro depois que ele acontece e tenta corrigi-lo com um novo prompt. Isso aumenta latência, custo computacional e ainda pode falhar na segunda tentativa. É um remendo, não uma solução de engenharia sólida.','\n',char(10)),replace('Imagine que você tem um amigo que é muito bom em fazer uma coisa de cada vez. Se você pede "me passa o lápis", ele acerta 94% das vezes. Mas se você pede "me passa o lápis e aponta o meu caderno", ele erra muito porque fica confuso com dois pedidos ao mesmo tempo.\n\nA melhor forma de ajudar seu amigo é: antes de dar o pedido complicado para ele, você separa em dois pedidos simples. Primeiro você pede "me passa o lápis", ele faz isso. Depois você pede "aponta o meu caderno", ele faz isso também. Assim ele não se confunde!\n\nÉ exatamente isso que a alternativa A faz: ela pega uma mensagem difícil com vários pedidos, separa em pedidos menores e mais fáceis, resolve cada um separadamente e junta tudo no final. As outras opções ou tentam ensinar seu amigo a lidar com a confusão (o que não funciona tão bem), ou só percebem o erro depois que ele já aconteceu.','\n',char(10)));
INSERT INTO cards VALUES('admin','card_1783092994345_s9zaknm71',528,'The agent sometimes selects get_customer when lookup_order would be better, especially for ambiguous requests ("help with my recent purchase").',replace('The agent sometimes selects get_customer when lookup_order would be better, especially for ambiguous requests ("help with my recent purchase").\n\nThe agent sometimes selects get_customer when lookup_order would be better, especially for ambiguous requests ("help with my recent purchase"). You''ll add few-shot examples. Which approach most effectively addresses this?\nO que a pergunta pede: which approach... most effectively (dado que você vai usar few-shot).\n\nA pegadinha: O problema está nos casos ambíguos → os exemplos devem cobrir a ambiguidade, com raciocínio.\n\nRaciocínio: As falhas estão em casos ambíguos , então os exemplos devem mirar essa ambiguidade e mostrar o raciocínio da escolha. C ensina o que o agente já acerta (casos claros); A não é few-shot (a pergunta fixou few-shot); B (agrupar) é mais fraco que mostrar o contraste com raciocínio. D .\n\n[ ] A - "Use when"/"do not use when" guidelines in each tool description.\n[ ] B - Examples grouped by tool — all get_customer, then all lookup_order.\n[ ] C - 10-15 examples of clear, unambiguous requests for each tool''s typical use.\n[ ] D - 4-6 examples targeting ambiguous scenarios, each showing reasoning for why one tool was chosen over plausible alternatives.','\n',char(10)),'[ ] D - 4-6 examples targeting ambiguous scenarios, each showing reasoning for why one tool was chosen over plausible alternatives.','["Domain_4::Prompt_Engineering_Structured_Output", "Domain_2::Tool_Design_MCP_Integration", "Scenario_1::Customer_Support_Agent"]','New',0,2.5,0,1783092994345,1783728174319,1783203558653,replace('**Tradução para português do Brasil:**\n\nO agente às vezes seleciona get_customer quando lookup_order seria melhor, especialmente em solicitações ambíguas ("ajuda com minha compra recente").\n\nO agente às vezes seleciona get_customer quando lookup_order seria melhor, especialmente em solicitações ambíguas ("ajuda com minha compra recente"). Você adicionará exemplos few-shot. Qual abordagem resolve isso de forma mais eficaz?\n\n[ ] A - Diretrizes "use quando"/"não use quando" na descrição de cada ferramenta.\n[ ] B - Exemplos agrupados por ferramenta — todos os get_customer, depois todos os lookup_order.\n[ ] C - 10-15 exemplos de solicitações claras e não ambíguas para cada uso típico de ferramenta.\n[ ] D - 4-6 exemplos visando cenários ambíguos, cada um mostrando o raciocínio de por que uma ferramenta foi escolhida em vez de alternativas plausíveis.','\n',char(10)),replace('**Explicação para um adulto tech lead:**\n\nO problema central é que o agente erra justamente nos casos ambíguos — aqueles em que a solicitação do usuário poderia, à primeira vista, justificar tanto get_customer quanto lookup_order (ex.: "preciso de ajuda com minha compra recente"). A pergunta já estabelece que você usará **few-shot examples** (exemplos no prompt), então alternativas que não são few-shot (como a A, que são guidelines embutidas nas descrições das tools) estão fora de escopo.\n\n**Análise das alternativas:**\n\n- **A** — Embora "use when"/"do not use when" seja uma boa prática de documentação, não é few-shot learning. A pergunta fixa que a abordagem será com exemplos few-shot, logo essa alternativa não atende ao requisito.\n\n- **B** — Agrupar exemplos por ferramenta (todos os get_customer, depois todos os lookup_order) organiza o prompt, mas não ataca a raiz do problema. Exemplos agrupados por ferramenta não ensinam o agente a *discriminar* entre elas em casos limítrofes. O agente continuará sem um bom padrão de decisão para ambiguidades.\n\n- **C** — Muitos exemplos (10-15) de casos claros e não ambíguos reforçam o que o agente *já* acerta, mas não corrigem a falha específica. O erro ocorre justamente onde os casos *não* são claros. Exemplos óbvios não treinam o modelo para a zona de dúvida.\n\n- **D** (correta) — Esta é a abordagem mais eficaz porque:\n  1. Foca nos **cenários ambíguos**, que são exatamente onde o erro acontece.\n  2. Usa **poucos exemplos (4-6)**, o que é suficiente e mantém o prompt enxuto.\n  3. Cada exemplo inclui o **raciocínio** da escolha ("por que lookup_order foi escolhido em vez de get_customer"). Isso é chain-of-thought aplicado a few-shot: o modelo não só vê o par input→output, mas aprende o *processo de decisão*.\n  4. Ensina o contraste: mostrar por que uma alternativa plausível foi rejeitada é mais informativo do que apenas mostrar o acerto.\n\n**Resumo técnico:** O erro é de *discriminação* em casos de fronteira. Few-shot com raciocínio contrastivo (alternativa D) é a técnica mais direta e eficiente para resolver esse tipo de problema.','\n',char(10)),replace('Imagine que você tem um robô que ajuda a organizar sua casa. Ele às vezes confunde guardar brinquedos com guardar roupas quando você fala "arrume minhas coisas". A pergunta diz: você vai dar exemplos para o robô aprender. Qual jeito é melhor?\n\n- **Alternativa A** — Colocar um aviso na parede dizendo "guarde brinquedos aqui, roupas ali". Não é um exemplo, é uma instrução. A pergunta já disse que você vai dar exemplos, então essa opção não serve.\n\n- **Alternativa B** — Mostrar primeiro 10 exemplos de como guardar brinquedos e depois 10 de como guardar roupas. O robô aprende cada coisa separada, mas ainda não sabe escolher quando você diz algo confuso tipo "arrume minhas coisas".\n\n- **Alternativa C** — Dar 15 exemplos fáceis e óbvios, como guardar uma bola no cesto de brinquedos ou uma camiseta no armário. O robô já sabe fazer isso! O problema é quando a frase é confusa, não quando é clara.\n\n- **Alternativa D (correta)** — Dar 4 a 6 exemplos de frases confusas, como "arrume minhas coisas", e explicar: "Aqui eu escolhi guardar brinquedos porque a pessoa estava perto do cesto de brinquedos, e não do armário". Assim o robô aprende a *pensar* antes de escolher, entendendo por que uma opção é melhor que a outra.\n\nÉ como ensinar alguém a cozinhar: mostrar receitas fáceis não ajuda quando a pessoa erra justamente nas receitas mais complicadas. O melhor é mostrar os casos difíceis e explicar o raciocínio.','\n',char(10)));
INSERT INTO cards VALUES('admin','card_1783092994381_m1ns1e5h1',529,'In 12% of cases, the agent skips get_customer and calls lookup_order using only the stated name, sometimes causing misidentified accounts and wrong refunds.',replace('In 12% of cases, the agent skips get_customer and calls lookup_order using only the stated name, sometimes causing misidentified accounts and wrong refunds.\n\nIn 12% of cases, the agent skips get_customer and calls lookup_order using only the stated name, sometimes causing misidentified accounts and wrong refunds. What change would most effectively address this reliability issue?\nO que a pergunta pede: most effectively address this reliability issue → garantir confiabilidade (verificação obrigatória).\n\nA pegadinha: Consequência grave (reembolsos errados) → precisa de uma garantia programática , não só instrução.\n\nRaciocínio: Quando o erro causa dano financeiro, a garantia tem que ser estrutural, não persuasiva . Um bloqueio programático impede a ação sem verificação — 100% confiável. B e C reduzem mas não garantem (o modelo pode falhar nos 12%); A é mais indireto. D é a salvaguarda determinística.\n\n[ ] A - A routing classifier that enables only the appropriate tool subset per request.\n[ ] B - Strengthen the system prompt: get_customer verification is mandatory before order operations.\n[ ] C - Few-shot examples showing the agent always calling get_customer first.\n[ ] D - A programmatic prerequisite that blocks lookup_order and process_refund until get_customer returns a verified ID.','\n',char(10)),'D - A programmatic prerequisite that blocks lookup_order and process_refund until get_customer returns a verified ID.','["Domain_2::Tool_Design_MCP_Integration", "Domain_5::Context_Management_Reliability", "Domain_4::Prompt_Engineering_Structured_Output", "Scenario_1::Customer_Support_Agent"]','New',0,2.5,0,1783092994381,1783728178396,1783203558653,replace('**Tradução para Português (Brasil):**\n\nEm 12% dos casos, o agente ignora o get_customer e chama o lookup_order usando apenas o nome informado, causando, às vezes, contas mal identificadas e reembolsos indevidos. Qual mudança seria mais eficaz para resolver esse problema de confiabilidade?\n\n[ ] A - Um classificador de roteamento que habilita apenas o subconjunto de ferramentas apropriado por requisição.\n[ ] B - Reforçar o prompt do sistema: a verificação do get_customer é obrigatória antes de operações de pedido.\n[ ] C - Exemplos few-shot mostrando o agente sempre chamando get_customer primeiro.\n[ ] D - Uma pré-condição programática que bloqueia lookup_order e process_refund até que get_customer retorne um ID verificado.','\n',char(10)),replace('**Explicação para um adulto tech lead:**\n\nO problema descrito é um clássico de confiabilidade em sistemas de agentes de IA: o modelo, em uma parcela não desprezível dos casos (12%), toma um atalho e pula uma etapa crítica de verificação (get_customer). Isso resulta em identificação incorreta de contas e reembolsos errados — um erro com consequências financeiras diretas.\n\nVamos analisar cada alternativa sob a ótica de garantia de confiabilidade:\n\n**Alternativa A - Classificador de roteamento:** Essa abordagem tenta resolver o problema indiretamente, limitando quais ferramentas estão disponíveis em cada contexto. Porém, o problema não é de excesso de ferramentas disponíveis, mas sim de o agente optar por não usar a ferramenta correta. Um classificador de roteamento pode até piorar a situação se classificar errado, e não garante que o get_customer será chamado antes das operações de pedido.\n\n**Alternativa B - Reforçar o prompt do sistema:** Essa é uma solução "soft" — depende do modelo seguir instruções corretamente. O dado do problema mostra que o modelo já falha em 12% dos casos. Reforçar a instrução pode reduzir a taxa de erro, mas não a elimina. É uma melhoria, não uma solução definitiva. O modelo ainda pode "alucinar" ou ignorar a instrução.\n\n**Alternativa C - Exemplos few-shot:** Similar à alternativa B, é uma abordagem baseada em persuasão do modelo. Exemplos podem ajudar, mas não garantem comportamento determinístico. O modelo pode generalizar incorretamente ou simplesmente não seguir o padrão dos exemplos em 12% dos casos.\n\n**Alternativa D - Pré-condição programática (CORRETA):** Esta é a única alternativa que introduz uma **garantia determinística**. Em vez de pedir para o modelo fazer a coisa certa, você *impede programaticamente* que ele faça a coisa errada. Lookup_order e process_refund simplesmente não executam até que get_customer tenha retornado um ID verificado. Isso transforma um comportamento desejável (chamar get_customer primeiro) em uma **restrição inescapável do sistema**.\n\nPara um tech lead: pense nisso como aplicar o princípio de "fail-fast" e "defense in depth". Em sistemas críticos (especialmente envolvendo dinheiro), você nunca deve confiar apenas em boas intenções ou instruções. Você coloca **guard rails** no nível de infraestrutura. É a diferença entre ter uma placa "pare" e instalar um semáforo com sensor — um depende do motorista seguir a regra, o outro torna a violação impossível.\n\n**Análise das alternativas incorretas:**\n\n- **A** está errada porque ataca um problema diferente (roteamento de ferramentas) e não endereça a raiz: o agente ignorar uma etapa de verificação.\n- **B** está errada porque é uma solução probabilística para um problema que exige garantia determinística. Em sistemas financeiros, "achar que resolve" não é suficiente.\n- **C** está errada pela mesma razão de B — exemplos não substituem uma garantia de execução obrigatória de um passo crítico.\n- **D** está correta porque a única maneira de ter 100% de confiabilidade é tornar a violação da regra programaticamente impossível.','\n',char(10)),replace('Imagina que você tem um robô que ajuda a devolver brinquedos na loja. Mas, 12 em cada 100 vezes, o robô não pergunta "qual é o seu nome completo?" e já vai procurar o pedido. Aí ele pode confundir você com outra pessoa e dar o dinheiro para a pessoa errada. Isso é um problema sério!\n\nAgora, vamos ver as soluções:\n\n**A** - Colocar um guarda na porta que decide quais ferramentas o robô pode usar. Mas o problema não é esse — o robô já tem todas as ferramentas, só não está usando a certa.\n\n**B** - Falar mais alto para o robô: "LEMBRE-SE: sempre pergunte o nome completo primeiro!". Mas o robô já ouviu isso e ainda assim erra 12% das vezes. Só falar mais alto não resolve.\n\n**C** - Mostrar vários exemplos para o robô: "Olha, aqui o João primeiro perguntou o nome, depois olhou o pedido." Mesma coisa — o robô pode ver os exemplos e ainda errar.\n\n**D** - Aqui é diferente: você coloca uma **fechadura** na máquina de procurar pedidos. Ela só abre se o robô primeiro perguntar o nome completo e confirmar quem é a pessoa. O robô não consegue pular essa etapa — é impossível! Se ele tentar, a máquina simplesmente não funciona.\n\nÉ como um videogame que não deixa você passar de fase até pegar a chave secreta. Não adianta o robô querer passar sem a chave — a porta nem abre!\n\nEntão a resposta certa é a **D**, porque é a única que **garante** que o robô nunca vai pular a etapa de verificação, mesmo que ele tente.','\n',char(10)));
INSERT INTO cards VALUES('admin','card_1783092994428_6eosu1a82',530,'Complex cases (billing disputes, multi-order returns) have 15% lower CSAT even when technically correct.',replace('Complex cases (billing disputes, multi-order returns) have 15% lower CSAT even when technically correct.\n\nComplex cases (billing disputes, multi-order returns) have 15% lower CSAT even when technically correct. The agent gives accurate resolutions but inconsistently explains reasoning — sometimes omitting policy, timelines, or next steps. Gaps vary by case. Improve quality without adding human review. Most effective?\nO que a pergunta pede: most effective... without adding human review → melhorar a qualidade sem revisão humana.\n\nA pegadinha: As lacunas variam caso a caso (política, prazo, próximos passos) → o agente precisa autoavaliar a completude .\n\nRaciocínio: Como as lacunas variam , exemplos fixos ( C ) não cobrem todas. Um passo de autocrítica de completude se adapta a cada caso, sem revisão humana. A só troca o modelo (não garante completude); D transfere o esforço ao cliente. B . (C é defensável, mas a variabilidade das lacunas favorece a autoavaliação adaptativa.)\n\n[ ] A - Raise the model tier from Haiku to Sonnet for complex cases.\n[ ] B - Add a self-critique step where the agent evaluates its draft for completeness (addresses the concern, includes context, anticipates follow-ups).\n[ ] C - Few-shot examples showing complete explanations for five common complex case types.\n[ ] D - A confirmation step asking "Does this fully address your concern?" before closing.','\n',char(10)),'B - Add a self-critique step where the agent evaluates its draft for completeness (addresses the concern, includes context, anticipates follow-ups).','["Domain_4::Prompt_Engineering_Structured_Output", "Domain_1::Agentic_Architecture_Orchestration", "Scenario_1::Customer_Support_Agent"]','New',0,2.5,0,1783092994428,1783728182077,1783203558653,replace('**Tradução para português do Brasil:**\n\nCasos complexos (disputas de cobrança, devoluções com múltiplos itens) têm 15% menos CSAT mesmo quando tecnicamente corretos.\n\nO agente fornece resoluções precisas, mas explica o raciocínio de forma inconsistente — às vezes omitindo política, prazos ou próximos passos. As lacunas variam conforme o caso. Melhorar a qualidade sem adicionar revisão humana. Qual é o mais eficaz?\n\n[ ] A - Elevar o nível do modelo de Haiku para Sonnet em casos complexos.\n[ ] B - Adicionar uma etapa de autocrítica onde o agente avalia seu rascunho quanto à completude (aborda a preocupação, inclui contexto, antecipa desdobramentos).\n[ ] C - Exemplos few-shot mostrando explicações completas para cinco tipos comuns de casos complexos.\n[ ] D - Uma etapa de confirmação perguntando "Isso aborda totalmente sua preocupação?" antes de finalizar.','\n',char(10)),replace('**Explicação para adulto tech lead:**\n\nO problema central é que o agente entrega resoluções tecnicamente corretas, mas as explicações são inconsistentes — ora falta a política, ora falta o prazo, ora falta o próximo passo. A variabilidade das lacunas é o ponto crítico: não há um padrão fixo de omissão.\n\nVamos analisar cada alternativa:\n\n**A - Elevar o modelo de Haiku para Sonnet** → Trocar o modelo subjacente pode melhorar a qualidade geral da linguagem, mas não resolve o problema específico de *completude da explicação*. Um modelo mais potente ainda pode omitir informações se não houver um mecanismo que o oriente a verificar se cobriu todos os elementos necessários. É uma solução indireta e cara, sem garantia de endereçar a causa raiz.\n\n**B - Etapa de autocrítica de completude (Correta)** → Esta abordagem ataca diretamente a causa raiz: como as lacunas variam caso a caso, precisamos de um mecanismo adaptativo. O agente gera o rascunho e depois o avalia contra um checklist implícito de completude (abordou a preocupação? incluiu contexto? antecipou perguntas de acompanhamento?). Isso funciona sem revisão humana porque é o próprio modelo fazendo autoavaliação — uma técnica consolidada (conhecida como "self-critique" ou "self-reflection" em LLMs). É escalável, adaptável a cada caso e não adiciona latência humana.\n\n**C - Exemplos few-shot para 5 tipos comuns** → Embora útil, esta abordagem pressupõe que as lacunas se encaixam em 5 categorias pré-definidas. O enunciado diz explicitamente que as "gaps vary by case". Casos fora desses 5 tipos (ou variações sutis dentro deles) continuarão com problemas. É uma melhoria parcial, não resolve a variabilidade.\n\n**D - Etapa de confirmação "Isso aborda sua preocupação?"** → Esta alternativa não melhora a qualidade da resposta do agente; ela transfere a responsabilidade para o cliente. Além disso, clientes em casos complexos (já frustrados com disputas de cobrança) podem não ter conhecimento para avaliar se a resposta é completa. Um cliente pode confirmar e depois se sentir enganado ao descobrir que faltou informação. Isso pode piorar o CSAT, não melhorar.\n\n**Conclusão:** A autocrítica (B) é uma forma de *garantia de qualidade programática* sem revisão humana, atacando diretamente a inconsistência na completude das explicações.','\n',char(10)),replace('Imagine que você está ajudando seus amigos a resolver problemas. Você sempre dá a resposta certa, mas às vezes esquece de explicar algumas coisas importantes, como "você tem 7 dias para trocar" ou "o próximo passo é falar com o gerente". Como seus amigos não sabem desses detalhes, eles ficam confusos e nem sempre ficam felizes com sua ajuda, mesmo você estando certo.\n\nAgora, qual é a melhor forma de melhorar sem pedir para outra pessoa revisar tudo?\n\n- **Opção A:** Usar um computador mais potente. Isso é como trocar seu lápis por um computador — pode ajudar um pouco, mas não resolve o esquecimento.\n- **Opção B (correta):** Antes de entregar a resposta, você relê e se pergunta: "Eu expliquei tudo? Falei sobre o prazo? Falei o que fazer depois?" Isso se chama autocrítica e funciona para qualquer tipo de problema, porque você mesmo verifica se está completo.\n- **Opção C:** Mostrar 5 exemplos prontos. Mas os problemas podem ser diferentes desses exemplos, então você ainda pode esquecer coisas em problemas novos.\n- **Opção D:** Perguntar ao amigo "Entendeu?" antes de terminar. Mas seu amigo não sabe o que deveria ter sido explicado, então ele pode dizer "sim" e depois descobrir que faltou algo.\n\nA melhor ideia é a opção B: ensinar o agente a revisar o próprio trabalho, verificando se explicou tudo direitinho antes de entregar. Assim ele melhora sozinho, sem precisar de outra pessoa!','\n',char(10)));
INSERT INTO cards VALUES('admin','card_1783092994495_1ev9u4m3q',531,'After get_customer and lookup_order, the agent faces uncertainty.',replace('After get_customer and lookup_order, the agent faces uncertainty.\n\nAfter get_customer and lookup_order, the agent faces uncertainty. Which situation is the most appropriate trigger for escalate_to_human?\nO que a pergunta pede: most appropriate trigger for escalate_to_human → quando escalar é certo.\n\nA pegadinha: Escalar é certo quando há uma lacuna de política que o agente não pode resolver — não por medo da reação do cliente.\n\nRaciocínio: A escalada cabe numa lacuna real de política que exige julgamento humano. Em B a política não cobre concorrentes (genuinamente ambíguo). A , C , D são resolvíveis pelo próprio agente (informar a janela de cancelamento, tratar as duas demandas, apresentar o rastreamento com tato). B .\n\n[ ] A - Cancel an order shipped yesterday, delivery tomorrow — escalate because the customer might change their mind.\n[ ] B - A competitor price match; policy allows adjustments for your own site within 14 days but is silent on competitors. Escalate for policy interpretation.\n[ ] C - A message mentions a billing question and a return — escalate so a human coordinates both.\n[ ] D - Customer claims non-delivery but tracking shows delivered and signed — escalate because contradicting them might harm the relationship.','\n',char(10)),'[ ] B - A competitor price match; policy allows adjustments for your own site within 14 days but is silent on competitors. Escalate for policy interpretation.','["Domain_1::Agentic_Architecture_Orchestration", "Domain_4::Prompt_Engineering_Structured_Output", "Domain_2::Tool_Design_MCP_Integration", "Scenario_1::Customer_Support_Agent"]','New',0,2.5,0,1783092994495,1783728185969,1783203558653,replace('**Tradução para português do Brasil**\n\nPergunta: Após get_customer e lookup_order, o agente enfrenta incerteza. Qual situação é o gatilho mais adequado para escalate_to_human?\n\nAlternativas:\n[ ] A - Cancelar um pedido enviado ontem, com entrega prevista para amanhã — escalar porque o cliente pode mudar de ideia.\n[ ] B - Um pedido de equiparação de preço de concorrente; a política permite ajustes para o próprio site dentro de 14 dias, mas é omissa em relação a concorrentes. Escalar para interpretação de política.\n[ ] C - Uma mensagem menciona uma dúvida sobre faturamento e uma devolução — escalar para que um humano coordene ambas.\n[ ] D - Cliente alega não recebimento, mas o rastreamento mostra entregue e assinado — escalar porque contradizê-lo pode prejudicar o relacionamento.','\n',char(10)),replace('**Explicação didática para um adulto tech lead**\n\nA pergunta testa a capacidade de discernir quando um agente de IA deve escalar um caso para um humano. O princípio fundamental é: **escalar é apropriado quando há uma lacuna de política que o agente não tem autoridade ou informação para resolver**, não quando a decisão poderia ser tomada pelo próprio agente com base nas regras existentes.\n\n**Alternativa correta: B**\n\nNa alternativa B, a política cobre ajustes de preço para o *próprio site* em até 14 dias, mas é **omissa** quanto a concorrentes. Isso cria um cenário de ambiguidade legítima de política — o agente não tem uma regra clara para seguir. Essa é a definição clássica de um caso que requer julgamento humano: um humano (supervisor, gerente de política) precisa interpretar a intenção da política, decidir se uma exceção se aplica ou definir um novo precedente. O agente não tem meios de resolver sozinho.\n\n**Por que as demais estão incorretas:**\n\n- **Alternativa A**: O agente pode perfeitamente informar o cliente sobre a política de cancelamento — por exemplo, "pedidos já enviados não podem ser cancelados, mas você pode recusar o recebimento ou devolver após a entrega". A *possibilidade* de o cliente mudar de ideia não é um motivo para escalar; o agente lida com a explicação dentro da política existente.\n\n- **Alternativa C**: Um agente bem projetado consegue lidar com múltiplos tópicos em uma única interação. Não há nada que exija coordenação humana. O agente pode consultar billing e retornos separadamente e consolidar a resposta. Escalar por "coordenação" seria um falso positivo — o agente deve ser capaz de gerenciar o contexto da conversa.\n\n- **Alternativa D**: Embora a situação seja delicada, o agente pode seguir um fluxo pré-definido: confirmar o endereço, sugerir verificação com vizinhos, iniciar um processo de disputa com a transportadora, etc. Escalar *apenas* por medo de prejudicar o relacionamento não é tecnicamente justificado. Agentes podem e devem ser treinados para lidar com conversas difíceis com empatia. A escalada aqui poderia até ser contraproducente, atrasando a resolução.\n\n**Conclusão técnica:** O gatilho correto para escalada é a *ambiguidade de política*, não o desconforto do agente ou a complexidade percebida da interação.','\n',char(10)),replace('Imagine que você é um robô ajudante em uma loja. Você tem um manual de regras para seguir. \n\nA alternativa B diz que um cliente pede para pagar o mesmo preço de uma loja concorrente, mas o manual da sua loja só fala em igualar preços da *própria* loja. Ele não diz nada sobre concorrentes! Isso é como uma "lacuna no manual". Você não pode inventar uma regra, então precisa chamar seu chefe (um humano) para decidir. Essa é a hora certa de pedir ajuda.\n\nNas outras opções:\n- A: O cliente quer cancelar um pedido que já foi enviado. Seu manual diz o que fazer nesse caso: explicar que não pode cancelar, mas pode devolver depois. Você não precisa do chefe.\n- C: O cliente tem duas perguntas (faturamento e devolução). Seu robô consegue responder às duas sozinho — é só olhar no sistema.\n- D: O cliente diz que não recebeu, mas o sistema mostra que foi entregue. Mesmo sendo chato dar essa notícia, seu manual tem um passo a passo: confirmar endereço, sugerir perguntar aos vizinhos, etc. Você não escala só porque a notícia é ruim.\n\nEntão: **escalar é para quando falta regra no manual, não para quando a tarefa é difícil ou chata.**','\n',char(10)));
INSERT INTO cards VALUES('admin','card_1783092994533_ox6o9gxrp',532,'The agent calls get_customer when users ask about orders ("check my order #12345") instead of lookup_order .',replace('The agent calls get_customer when users ask about orders ("check my order #12345") instead of lookup_order .\n\nThe agent calls get_customer when users ask about orders ("check my order #12345") instead of lookup_order . Both have minimal descriptions and accept similar identifier formats. What''s the most effective first step to improve tool selection reliability?\nO que a pergunta pede: most effective first step → o primeiro passo (comece pelo mais básico).\n\nA pegadinha: Descrições mínimas e formatos parecidos → a raiz é a descrição pobre.\n\nRaciocínio: O primeiro passo é sempre o mais fundamental e barato: corrigir as descrições pobres (a causa direta). Few-shot ( B ) é o passo seguinte se ainda persistir; C muda a arquitetura (drástico); D adiciona infraestrutura. A . (Compare com a Q48, onde a pergunta já fixava few-shot.)\n\n[ ] A - Expand each description with input formats, example queries, edge cases, and boundaries explaining when to use one vs the other.\n[ ] B - Add 5-8 few-shot examples routing order queries to lookup_order.\n[ ] C - Consolidate both into a single lookup_entity tool.\n[ ] D - A routing layer that parses input and pre-selects by keywords.','\n',char(10)),'[ ] A - Expand each description with input formats, example queries, edge cases, and boundaries explaining when to use one vs the other.','["Domain_2::Tool_Design_MCP_Integration", "Domain_4::Prompt_Engineering_Structured_Output", "Scenario_1::Customer_Support_Agent"]','New',0,2.5,0,1783092994533,1783728189347,1783203558653,NULL,NULL,NULL);
INSERT INTO cards VALUES('admin','card_1783092994573_nbo8ko2qr',533,'When customers include "account", the agent calls get_customer first 78% of the time; without "account", it calls lookup_order first 93%.',replace('When customers include "account", the agent calls get_customer first 78% of the time; without "account", it calls lookup_order first 93%.\n\nWhen customers include "account", the agent calls get_customer first 78% of the time; without "account", it calls lookup_order first 93%. The tool descriptions are well-written and unambiguous. What is the most likely root cause?\nO que a pergunta pede: most likely root cause → a causa raiz.\n\nA pegadinha: tool descriptions are well-written and unambiguous → o problema não é a descrição. É a associação aprendida da palavra "account".\n\nRaciocínio: O enunciado afirma que as descrições são boas e inequívocas — isso elimina C (e enfraquece soluções de descrição). O viés vem da associação aprendida no pré-treino entre "account" e "customer". B presume instruções keyword-sensitive não mencionadas; D é desproporcional. A .\n\n[ ] A - The model''s base training creates associations between "account" and customer operations that override the descriptions.\n[ ] B - The system prompt has keyword-sensitive instructions.\n[ ] C - The descriptions need negative examples.\n[ ] D - The model needs fine-tuning on multi-concept messages.','\n',char(10)),'[ ] A - The model''s base training creates associations between "account" and customer operations that override the descriptions.','["Domain_1::Agentic_Architecture_Orchestration", "Domain_2::Tool_Design_MCP_Integration", "Domain_4::Prompt_Engineering_Structured_Output", "Scenario_1::Customer_Support_Agent"]','New',0,2.5,0,1783092994573,1783728192658,1783203558653,NULL,NULL,NULL);
INSERT INTO cards VALUES('admin','card_1783092994607_py8qct3hj',534,'get_customer returns all matches when searching by name.',replace('get_customer returns all matches when searching by name.\n\nget_customer returns all matches when searching by name. Claude currently picks the most recent order when multiple results return, but 15% of multi-match cases proceed with the wrong customer. How should you address this?\nO que a pergunta pede: how should you address this → corrigir a escolha errada em multi-match.\n\nA pegadinha: Adivinhar (pegar o mais recente) é arriscado → peça um identificador adicional antes de agir.\n\nRaciocínio: Quando a identificação errada causa dano (conta errada, reembolso errado), o certo é desambiguar pedindo mais um dado antes de agir. A esconde a ambiguidade num ranking (pode errar silenciosamente); B continua adivinhando; D ainda prossegue automaticamente acima de um limiar arbitrário. C elimina o palpite.\n\n[ ] A - Modify get_customer to return only the single best match by ranking.\n[ ] B - Few-shot using conversational context to infer the right customer without asking.\n[ ] C - Instruct Claude to ask for an additional identifier (email, phone, order #) when multiple matches return, before any customer-specific action.\n[ ] D - A confidence score that proceeds above 85% and prompts below.','\n',char(10)),'[ ] C - Instruct Claude to ask for an additional identifier (email, phone, order #) when multiple matches return, before any customer-specific action.','["Domain_2::Tool_Design_MCP_Integration", "Domain_4::Prompt_Engineering_Structured_Output", "Scenario_1::Customer_Support_Agent"]','New',0,2.5,0,1783092994607,1783728196067,1783203558653,NULL,NULL,NULL);
INSERT INTO cards VALUES('admin','card_1783092994640_168vqtprt',535,'The agent achieves 55% first-contact resolution (target 80%).',replace('The agent achieves 55% first-contact resolution (target 80%).\n\nThe agent achieves 55% first-contact resolution (target 80%). It escalates straightforward cases (standard damage replacements with photo evidence) while attempting complex situations needing policy exceptions. Most effective way to improve escalation calibration?\nO que a pergunta pede: most effective way to improve escalation calibration → calibrar quando escalar.\n\nA pegadinha: O agente escala o fácil e tenta o difícil — invertido . Precisa de critérios claros + exemplos.\n\nRaciocínio: A calibração errada vem da falta de critérios claros de quando escalar. Defini-los explicitamente com exemplos dos dois lados corrige diretamente o comportamento invertido. B usa confiança como proxy (impreciso); C é pesado (treinar modelo); D escala por emoção, não por adequação ao caso. A .\n\n[ ] A - Add explicit escalation criteria to the system prompt with few-shot examples of when to escalate vs resolve.\n[ ] B - Self-report a confidence score (1-10) and route below a threshold.\n[ ] C - A separate classifier trained on historical tickets.\n[ ] D - Sentiment analysis that escalates when frustration exceeds a threshold.','\n',char(10)),'[ ] A - Add explicit escalation criteria to the system prompt with few-shot examples of when to escalate vs resolve.','["Domain_4::Prompt_Engineering_Structured_Output", "Domain_1::Agentic_Architecture_Orchestration", "Scenario_1::Customer_Support_Agent"]','New',0,2.5,0,1783092994640,1783728199276,1783203558653,NULL,NULL,NULL);
INSERT INTO cards VALUES('admin','card_1783092994675_isfmpdxf9',536,'Progressive summarization at 70% capacity.',replace('Progressive summarization at 70% capacity.\n\nProgressive summarization at 70% capacity. Customers reference specific amounts ("the 15% discount I mentioned") but the agent gives wrong values — details stated 20+ turns ago got condensed into "discussed promotional pricing." Most effective fix?\nO que a pergunta pede: most effective fix → corrigir a perda de valores específicos.\n\nA pegadinha: Dados transacionais (valores, datas, números) não podem virar resumo vago → extraia para um bloco persistente.\n\nRaciocínio: A correção robusta separa os fatos críticos da sumarização : um bloco "case facts" sempre presente garante que valores nunca se percam, por mais antigos que sejam. C melhora mas ainda depende da sumarização não falhar; A só adia; D é mais complexo e reativo. B .\n\n[ ] A - Raise the summarization threshold from 70% to 85%.\n[ ] B - Extract transactional facts (amounts, dates, order numbers) into a persistent "case facts" block included in every prompt, outside the summarized history.\n[ ] C - Revise the summarization prompt to preserve all numbers, percentages, and dates verbatim.\n[ ] D - Store full history externally and retrieve when the agent detects phrases like "as I mentioned."','\n',char(10)),'[ ] B - Extract transactional facts (amounts, dates, order numbers) into a persistent "case facts" block included in every prompt, outside the summarized history.','["Domain_5::Context_Management_Reliability", "Domain_1::Agentic_Architecture_Orchestration", "Scenario_1::Customer_Support_Agent"]','New',0,2.5,0,1783092994675,1783728203072,1783203558653,NULL,NULL,NULL);
INSERT INTO cards VALUES('admin','card_1783092994709_1mralnt16',537,'The agent averages 4+ API round-trips per resolution.',replace('The agent averages 4+ API round-trips per resolution.\n\nThe agent averages 4+ API round-trips per resolution. Claude requests get_customer and lookup_order in separate sequential turns even when both are needed upfront. Most effective way to reduce round-trips?\nO que a pergunta pede: most effective way to reduce round-trips → reduzir idas e voltas.\n\nA pegadinha: As duas ferramentas são frequentemente necessárias juntas → permita chamadas paralelas numa só rodada.\n\nRaciocínio: O Claude suporta múltiplas chamadas de ferramenta na mesma rodada (parallel tool use). Instruí-lo a agrupar quando ambas são necessárias upfront reduz as idas e voltas direto, sem nova infraestrutura. A desperdiça chamadas (executa o que pode não ser preciso); B cria ferramentas rígidas por combinação; D não muda o comportamento de batching. C . (B é defensável para uma combinação muito comum, mas C é mais geral.)\n\n[ ] A - Speculative execution that auto-calls likely tools alongside any request, returning all results.\n[ ] B - Composite tools like get_customer_with_orders bundling common combinations.\n[ ] C - Prompt Claude to batch tool requests per turn, returning all results together before the next call.\n[ ] D - Increase max_tokens so Claude can plan ahead.','\n',char(10)),'[ ] C - Prompt Claude to batch tool requests per turn, returning all results together before the next call.','["Domain_2::Tool_Design_MCP_Integration", "Domain_4::Prompt_Engineering_Structured_Output", "Scenario_1::Customer_Support_Agent"]','New',0,2.5,0,1783092994709,1783728206450,1783203558653,NULL,NULL,NULL);
INSERT INTO cards VALUES('admin','card_1783092994746_a3f7h9pq3',538,'The agent frequently calls get_customer for order-status questions, though lookup_order would be more appropriate.',replace('The agent frequently calls get_customer for order-status questions, though lookup_order would be more appropriate.\n\nThe agent frequently calls get_customer for order-status questions, though lookup_order would be more appropriate. What should you examine first?\nO que a pergunta pede: what should you examine first → o primeiro lugar a investigar.\n\nA pegadinha: Problema de seleção de ferramenta → o primeiro suspeito é sempre a descrição das ferramentas.\n\nRaciocínio: O primeiro passo no diagnóstico de má seleção de ferramenta é checar se as descrições separam claramente os propósitos. É o mais barato e a causa mais comum. A , C , D são intervenções posteriores e mais pesadas. B .\n\n[ ] A - Implement a pre-processing classifier that routes order queries to lookup_order.\n[ ] B - Review tool descriptions to ensure they clearly distinguish each tool''s purpose.\n[ ] C - Add few-shot examples covering every order-related query pattern.\n[ ] D - Reduce the number of tools to simplify selection.','\n',char(10)),'[ ] B - Review tool descriptions to ensure they clearly distinguish each tool''s purpose.','["Domain_2::Tool_Design_MCP_Integration", "Domain_4::Prompt_Engineering_Structured_Output", "Scenario_1::Customer_Support_Agent"]','New',0,2.5,0,1783092994746,1783728209893,1783203558653,NULL,NULL,NULL);
INSERT INTO cards VALUES('admin','card_1783092994781_e1xje3cgi',539,'Simple requests ("refund order #1234"): 91% resolution in 3-4 tool calls.',replace('Simple requests ("refund order #1234"): 91% resolution in 3-4 tool calls.\n\nSimple requests ("refund order #1234"): 91% resolution in 3-4 tool calls. Complex requests ("charged twice, discount didn''t apply, want to cancel"): 12+ calls, only 54%, investigating concerns sequentially and gathering redundant customer data. Most effective change?\nO que a pergunta pede: most effective change to improve complex request handling → lidar melhor com pedidos complexos.\n\nA pegadinha: Investiga sequencialmente e repete a coleta de dados → decomponha e investigue em paralelo com contexto compartilhado .\n\nRaciocínio: Os dois sintomas (sequencial + dados redundantes) somem com decomposição + paralelismo + contexto compartilhado : cada demanda é tratada em paralelo e os dados do cliente são buscados uma vez e reutilizados. B mantém o sequencial; C ajuda marginalmente; D esconde a complexidade numa ferramenta-canivete (e não adiciona paralelismo). A .\n\n[ ] A - Decompose the request into distinct concerns, investigate each in parallel using shared customer context, then synthesize a resolution.\n[ ] B - Verification gates between steps, checkpointing after each concern.\n[ ] C - Few-shot examples of ideal tool sequences for multi-part billing scenarios.\n[ ] D - Consolidate get_customer, lookup_order, and billing lookups into one investigate_issue tool.','\n',char(10)),'[ ] A - Decompose the request into distinct concerns, investigate each in parallel using shared customer context, then synthesize a resolution.','["Domain_1::Agentic_Architecture_Orchestration", "Domain_2::Tool_Design_MCP_Integration", "Domain_4::Prompt_Engineering_Structured_Output", "Scenario_1::Customer_Support_Agent"]','New',0,2.5,0,1783092994781,1783728213718,1783203558653,NULL,NULL,NULL);
INSERT INTO cards VALUES('admin','card_1783092994815_3bhaufqiv',540,'Implementing the agentic loop.',replace('Implementing the agentic loop.\n\nImplementing the agentic loop. After each API call, you decide whether to continue (execute tools, call again) or stop (present the final response). What determines this decision?\nO que a pergunta pede: what determines this decision → o que decide continuar ou parar.\n\nA pegadinha: Decisão determinística → ler o campo stop_reason da resposta (fato técnico, não heurística de texto).\n\nRaciocínio: O loop agêntico é controlado deterministicamente pelo stop_reason : tool_use significa que o Claude quer executar ferramentas (continue); end_turn significa que terminou (pare). A é um guard-rail útil mas não a lógica central; B é frágil (parsing de linguagem natural); D é incorreto (há texto junto com tool_use). C .\n\n[ ] A - A max iteration count (e.g., 10) — stop when reached, regardless of whether Claude needs more work.\n[ ] B - Parse the response text for phrases like "I''ve completed" or "Is there anything else?".\n[ ] C - Check the stop_reason field: continue when it equals "tool_use", stop when it equals "end_turn".\n[ ] D - Check whether the response includes any assistant text — if so, end the loop.','\n',char(10)),'[ ] C - Check the stop_reason field: continue when it equals "tool_use", stop when it equals "end_turn".','["Domain_1::Agentic_Architecture_Orchestration", "ForaDoCenario"]','New',0,2.5,0,1783092994815,1783728217025,1783203558653,NULL,NULL,NULL);
INSERT INTO cards VALUES('test_user','test_scenario_1_1',1,'O que é o Claude Agent SDK?','Qual é a principal funcionalidade do Claude Agent SDK?','O Claude Agent SDK permite construir agentes inteligentes que usam o Claude como modelo de linguagem para resolver tarefas complexas.','["Scenario_1::Customer_Support_Agent", "Domain_1::Agentic_Architecture_Orchestration"]','New',0,2.5,0,1783717125834,1783717125834,1783717125834,NULL,NULL,NULL);
INSERT INTO cards VALUES('test_user','test_scenario_1_2',2,'Como usar MCP customizadas em agentes?','Quais são as principais ferramentas MCP customizadas utilizadas em um agente de suporte ao cliente?','As principais ferramentas incluem: get_customer (obter dados do cliente), lookup_order (buscar pedidos), process_refund (processar devoluções) e escalate_to_human (escalar para humano).','["Scenario_1::Customer_Support_Agent", "Domain_2::Tool_Use_MCP"]','New',0,2.5,0,1783717125834,1783717125834,1783717125834,NULL,NULL,NULL);
INSERT INTO cards VALUES('admin','scenario_1_card_admin_1',501,'O que é o Claude Agent SDK?','Qual é a principal funcionalidade do Claude Agent SDK?','O Claude Agent SDK permite construir agentes inteligentes que usam o Claude como modelo de linguagem para resolver tarefas complexas.','["ForaDosDominios", "ForaDoCenario"]','New',0,2.5,0,1783717316417,1783728054543,1783717316418,NULL,NULL,NULL);
