INSERT INTO cards VALUES('admin','scenario_2_card_admin_1',503,'O que é Claude Code?','Como o Claude Code acelera o desenvolvimento de software?','O Claude Code é um assistente integrado que ajuda com geração de código, refatoração, debugging e documentação usando slash commands customizados.','["Domain_3::Claude_Code_Configuration_Workflows", "Scenario_2::Code_Generation_Claude_Code"]','New',0,2.5,0,1783717610424,1783728068817,1783717610424,NULL,NULL,NULL);
INSERT INTO cards VALUES('admin','scenario_2_card_admin_2',504,'Plan mode vs execução direta','Qual é a diferença entre Plan mode e execução direta no Claude Code?','Plan mode permite desenhar a solução arquitetural antes de implementar, enquanto execução direta implementa as mudanças imediatamente.','["Domain_3::Claude_Code_Configuration_Workflows", "Scenario_2::Code_Generation_Claude_Code"]','New',0,2.5,0,1783717610424,1783728076126,1783717610424,NULL,NULL,NULL);
