PRAGMA foreign_keys=OFF;
BEGIN TRANSACTION;
CREATE TABLE cards (
	user_id VARCHAR NOT NULL, 
	id VARCHAR NOT NULL, 
	seq INTEGER, 
	title VARCHAR NOT NULL, 
	question VARCHAR NOT NULL, 
	answer VARCHAR NOT NULL, 
	tags VARCHAR NOT NULL, 
	state VARCHAR NOT NULL, 
	interval INTEGER NOT NULL, 
	"easeFactor" FLOAT NOT NULL, 
	repetitions INTEGER NOT NULL, 
	"createdAt" INTEGER NOT NULL, 
	"updatedAt" INTEGER NOT NULL, 
	"nextReviewDate" INTEGER NOT NULL, 
	traducao VARCHAR, 
	explanation VARCHAR, 
	"tenYearOld" VARCHAR, 
	PRIMARY KEY (user_id, id)
);
CREATE TABLE card_options (
	user_id VARCHAR NOT NULL, 
	"cardId" VARCHAR NOT NULL, 
	"optionId" VARCHAR NOT NULL, 
	text VARCHAR NOT NULL, 
	"isCorrect" BOOLEAN NOT NULL, 
	"optionOrder" INTEGER NOT NULL, 
	PRIMARY KEY (user_id, "cardId", "optionId")
);
CREATE TABLE attempts (
	user_id VARCHAR NOT NULL, 
	"cardId" VARCHAR NOT NULL, 
	"attemptId" VARCHAR NOT NULL, 
	timestamp INTEGER NOT NULL, 
	quality INTEGER NOT NULL, 
	"elapsedTime" INTEGER NOT NULL, 
	"wasCorrect" BOOLEAN NOT NULL, 
	"userAnswer" VARCHAR, 
	"easeFactorBefore" FLOAT NOT NULL, 
	"easeFactorAfter" FLOAT NOT NULL, 
	"intervalBefore" INTEGER NOT NULL, 
	"intervalAfter" INTEGER NOT NULL, 
	PRIMARY KEY (user_id, "cardId", "attemptId")
);
CREATE TABLE jornadas (
	user_id VARCHAR NOT NULL, 
	id VARCHAR NOT NULL, 
	nome VARCHAR NOT NULL, 
	ativa BOOLEAN NOT NULL, 
	ordem INTEGER NOT NULL, 
	"createdAt" INTEGER NOT NULL, 
	"updatedAt" INTEGER NOT NULL, "pontosTentativas" INTEGER DEFAULT 3, 
	PRIMARY KEY (user_id, id)
);
CREATE TABLE jornada_perguntas (
	user_id VARCHAR NOT NULL, 
	"jornadaId" VARCHAR NOT NULL, 
	"cardId" VARCHAR NOT NULL, 
	ordem INTEGER NOT NULL, 
	PRIMARY KEY (user_id, "jornadaId", "cardId")
);
CREATE TABLE jornada_progresso (
	user_id VARCHAR NOT NULL, 
	"jornadaId" VARCHAR NOT NULL, 
	status VARCHAR NOT NULL, 
	"bestErrors" INTEGER, 
	"completedAt" INTEGER, 
	"currentQuestionIndex" INTEGER NOT NULL, 
	"currentErrors" INTEGER NOT NULL, 
	"currentLives" INTEGER NOT NULL, 
	"lastActiveAt" INTEGER, 
	"bestTime" INTEGER, 
	PRIMARY KEY (user_id, "jornadaId")
);
CREATE TABLE learn_stats (
	user_id VARCHAR NOT NULL, 
	"totalXp" INTEGER NOT NULL, 
	PRIMARY KEY (user_id)
);
CREATE TABLE app_config (
	user_id VARCHAR NOT NULL, 
	chave VARCHAR NOT NULL, 
	valor VARCHAR NOT NULL, 
	PRIMARY KEY (user_id, chave)
);
CREATE TABLE users (
	id INTEGER NOT NULL, 
	email VARCHAR NOT NULL, 
	password VARCHAR NOT NULL, 
	is_active BOOLEAN NOT NULL, 
	created_at DATETIME NOT NULL, 
	updated_at DATETIME NOT NULL, 
	PRIMARY KEY (id)
);
CREATE INDEX ix_cards_seq ON cards (seq);
CREATE INDEX ix_cards_user_id ON cards (user_id);
CREATE INDEX ix_card_options_user_id ON card_options (user_id);
CREATE INDEX ix_attempts_user_id ON attempts (user_id);
CREATE INDEX ix_jornadas_user_id ON jornadas (user_id);
CREATE INDEX ix_jornada_perguntas_user_id ON jornada_perguntas (user_id);
CREATE INDEX ix_jornada_progresso_user_id ON jornada_progresso (user_id);
CREATE INDEX ix_app_config_user_id ON app_config (user_id);
CREATE UNIQUE INDEX ix_users_email ON users (email);
COMMIT;
